import{x as e}from"./GlobalSearch-C-_tpIUt.js";var t=JSON.parse(`[{"id":"shou-zhu-dai-tu","simplified":"守株待兔","traditional":"守株待兔","pinyinOverride":null,"literalMeaning":"to guard a tree stump, waiting for a hare","figurativeMeaning":"to rigidly stick to one lucky method and expect it to keep working, instead of adapting to changing circumstances; to rely on a lucky fluke rather than making an effort","englishEquivalents":["to wait for the ship to come in","to bank on lightning striking twice"],"shortGloss":"to rely on a lucky fluke instead of effort, expecting it to repeat","characters":[{"char":"守","meaning":"to guard; to watch over; to keep watch at"},{"char":"株","meaning":"a stump of a tree (a felled or cut-off trunk still rooted in the ground)"},{"char":"待","meaning":"to wait for; to await"},{"char":"兔","meaning":"hare; rabbit"}],"origin":{"period":"Warring States period (475–221 BCE)","sourceText":"《韩非子·五蠹》","sourceTextEnglish":"Han Feizi (韩非子), chapter \\"Wu Du\\" (五蠹, \\"The Five Vermin\\")","originalExcerpt":"宋人有耕田者。田中有株，兔走触株，折颈而死。因释其耒而守株，冀复得兔。兔不可复得，而身为宋国笑。今欲以先王之政，治当世之民，皆守株之类也。","storyEnglish":"A farmer in the state of Song was working his field when a hare, running past, crashed headlong into a tree stump and broke its neck. The farmer abandoned his plough, sat down by the stump, and waited every day after, hoping another hare would come and meet the same end. It never happened again, and he became a laughing stock throughout the state of Song. Han Feizi uses the story to close a political argument: trying to govern the people of the present age with the methods of the ancient kings, he says, is exactly the same folly as guarding the stump.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate"],"structure":"verb-object + verb-object","register":"literary, but very widely understood and used in ordinary speech","connotation":"negative","commonMistakes":"Specifically describes waiting for a one-off stroke of luck to repeat itself. It is not a general synonym for laziness or inaction, and shouldn't be used for someone who simply isn't making an effort at all (with no lucky precedent they're hoping to repeat).","canStandAlone":false},"examples":[{"simplified":"市场变化这么快，你不能守株待兔，得主动去找客户。","traditional":"市場變化這麼快，你不能守株待兔，得主動去找客戶。","english":"The market changes so fast. You can't just sit around waiting for another lucky break, you need to go find clients yourself.","source":"spoken"},{"simplified":"他去年靠一次投机赚了钱，现在守株待兔，天天等着同样的机会再次出现。","traditional":"他去年靠一次投機賺了錢，現在守株待兔，天天等著同樣的機會再次出現。","english":"He made money once last year through a speculative bet, and now he just sits around every day waiting for the same opportunity to come again.","source":"written"}],"synonyms":["刻舟求剑"],"antonyms":["随机应变"],"confusedWith":[]},{"id":"hua-she-tian-zu","simplified":"画蛇添足","literalMeaning":"draw a snake and add feet","figurativeMeaning":"to ruin something by adding unnecessary details","englishEquivalents":["gild the lily","over-embellish","overdo it"],"shortGloss":"ruin by adding unnecessary details","characters":[{"char":"画","meaning":"draw"},{"char":"蛇","meaning":"snake"},{"char":"添","meaning":"add"},{"char":"足","meaning":"feet"}],"origin":{"period":"Warring States period (475–221 BCE)","sourceText":"《战国策·齐策二》","sourceTextEnglish":"Strategies of the Warring States, Strategies of Qi II","originalExcerpt":"楚有祠者，赐其舍人卮酒。舍人相谓曰：“数人饮之不足，一人饮之有余，请画地为蛇，先成者饮酒。”一人蛇先成，引酒且饮之，乃左手持卮，右手画蛇曰：“吾能为之足。”未成，一人之蛇成，夺其卮曰：“蛇固无足，子安能为之足乎？”遂饮其酒。","storyEnglish":"In the state of Chu during the Warring States period, a nobleman offered a cup of wine as a prize to his servants. They decided that whoever could draw a snake on the ground the fastest would win the wine. One servant finished his drawing quickly and, confident of his victory, decided to add feet to his snake. While he was doing this, another servant finished his snake and claimed the wine, pointing out that snakes do not have feet. The first servant lost the prize because he unnecessarily embellished his drawing.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"literary, but very widely understood and used in ordinary speech","connotation":"negative","commonMistakes":"Learners often confuse this idiom with simply making a mistake, but it specifically refers to adding unnecessary elements that spoil the whole. It is not used for general errors.","canStandAlone":false},"examples":[{"simplified":"他在报告中画蛇添足，结果反而让人感到困惑。","english":"He over-embellished the report, which ended up confusing people.","traditional":"他在報告中畫蛇添足，結果反而讓人感到困惑。"},{"simplified":"设计已经很完美了，不要画蛇添足。","english":"The design is already perfect, don't ruin it by adding unnecessary details.","traditional":"設計已經很完美了，不要畫蛇添足。"}],"synonyms":["多此一举"],"antonyms":["画龙点睛"],"confusedWith":[{"id":"多此一举","note":"Both involve unnecessary actions, but 画蛇添足 implies ruining something, while 多此一举 is more about redundancy."}],"traditional":"畫蛇添足","pinyinOverride":null},{"id":"hua-long-dian-jing","simplified":"画龙点睛","literalMeaning":"paint dragon dot eyes","figurativeMeaning":"to add the finishing touch; to bring something to life with a small but crucial detail","englishEquivalents":["add the finishing touch","bring to life","the icing on the cake"],"shortGloss":"add the finishing touch","characters":[{"char":"画","meaning":"to paint"},{"char":"龙","meaning":"dragon"},{"char":"点","meaning":"to dot"},{"char":"睛","meaning":"eyes"}],"origin":{"period":"Southern and Northern Dynasties (420–589)","sourceText":"《历代名画记》","sourceTextEnglish":"Record of Famous Paintings of All Dynasties","originalExcerpt":"张僧繇画龙不点睛，点之即飞去。","storyEnglish":"The idiom originates from a story about the famous painter Zhang Sengyou during the Southern and Northern Dynasties. He painted dragons on a temple wall but left the eyes blank. When asked why, he explained that adding the eyes would bring the dragons to life, and they would fly away. To prove his point, he painted the eyes, and the dragons indeed flew off the wall, leaving the onlookers amazed.","historicalFigures":["Zhang Sengyou"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"literary, but very widely understood and used in ordinary speech","connotation":"positive","commonMistakes":"Learners often confuse this idiom with simply 'painting a dragon' without understanding the emphasis on the crucial final detail. It specifically refers to the importance of a small addition that completes or perfects something.","canStandAlone":false},"examples":[{"simplified":"这篇文章已经很好了，加上这个结尾就更是画龙点睛。","english":"This article is already very good, but adding this conclusion is the finishing touch.","traditional":"這篇文章已經很好了，加上這個結尾就更是畫龍點睛。"},{"simplified":"设计师在最后一刻画龙点睛，使整个作品焕然一新。","english":"The designer added the finishing touch at the last moment, making the entire work look brand new.","traditional":"設計師在最後一刻畫龍點睛，使整個作品煥然一新。"}],"synonyms":["锦上添花"],"antonyms":[],"confusedWith":[{"id":"画蛇添足","note":"While 画龙点睛 refers to a crucial addition, 画蛇添足 means adding something unnecessary that ruins the whole."}],"traditional":"畫龍點睛","pinyinOverride":null},{"id":"yu-gong-yi-shan","simplified":"愚公移山","literalMeaning":"the foolish old man moves mountains","figurativeMeaning":"perseverance and determination can overcome great obstacles","englishEquivalents":["Where there's a will, there's a way","Perseverance conquers all"],"shortGloss":"perseverance overcomes obstacles","characters":[{"char":"愚","meaning":"foolish"},{"char":"公","meaning":"old man"},{"char":"移","meaning":"move"},{"char":"山","meaning":"mountain"}],"origin":{"period":"Warring States period (475–221 BCE)","sourceText":"《列子·汤问》","sourceTextEnglish":"Liezi, Questions of Tang","originalExcerpt":"愚公者，年且九十，面山而居，惡其阻也，將率子孫荷擔者三夫，鑿石而出之。","storyEnglish":"The story tells of an old man named Yu Gong who, despite being nearly ninety, decided to remove the mountains blocking his village's access to the outside world. He, along with his family, began to dig up the mountains. When a wise man mocked him for his foolishness, Yu Gong replied that while he might die, his descendants would continue the work, and eventually, the mountains would be moved. This determination impressed the gods, who sent divine beings to help him move the mountains.","historicalFigures":["Yu Gong"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["subject","predicate","object"],"structure":"subject-predicate","register":"literary, but very widely understood and used in ordinary speech","connotation":"positive","commonMistakes":"Learners might confuse this idiom with expressions that imply foolishness without the element of perseverance. It's important to understand that the idiom praises determination, not the literal foolishness of the old man.","canStandAlone":true},"examples":[{"simplified":"只要有愚公移山的精神，我们就能克服任何困难。","english":"As long as we have the spirit of Yu Gong moving mountains, we can overcome any difficulty.","traditional":"只要有愚公移山的精神，我們就能克服任何困難。"},{"simplified":"他用愚公移山的毅力完成了这项艰巨的任务。","english":"He completed the daunting task with the perseverance of Yu Gong moving mountains.","traditional":"他用愚公移山的毅力完成了這項艱鉅的任務。"}],"synonyms":["锲而不舍","坚持不懈"],"antonyms":["半途而废"],"confusedWith":[{"id":"愚不可及","note":"愚不可及 means 'extremely foolish', focusing on foolishness without the positive connotation of perseverance."}],"traditional":"愚公移山","pinyinOverride":null},{"id":"shui-di-shi-chuan","simplified":"水滴石穿","literalMeaning":"water drop stone penetrate","figurativeMeaning":"persistent effort can overcome any difficulty","englishEquivalents":["Constant dripping wears away the stone","Perseverance prevails"],"shortGloss":"perseverance overcomes obstacles","characters":[{"char":"水","meaning":"water"},{"char":"滴","meaning":"drop"},{"char":"石","meaning":"stone"},{"char":"穿","meaning":"penetrate"}],"origin":{"period":"Song Dynasty (960–1279)","sourceText":"《宋·罗大经·鹤林玉露》","sourceTextEnglish":"Song Dynasty, Luo Dajing, 'Helin Yulu'","originalExcerpt":"滴水穿石，非一日之功。","storyEnglish":"The idiom comes from the observation that even a small, soft drop of water can eventually penetrate a hard stone if it drips continuously over time. This illustrates the power of persistence and patience in overcoming obstacles.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["subject","predicate","object"],"structure":"subject-predicate","register":"commonly used in both formal and informal contexts","connotation":"positive","commonMistakes":"Learners might confuse this idiom with others that involve water or stones but do not convey perseverance, such as '井底之蛙'. It's important to remember the focus on persistence.","canStandAlone":true},"examples":[{"simplified":"他每天坚持学习，终于考上了理想的大学，真是水滴石穿。","english":"He studied diligently every day and finally got into his dream university; truly, perseverance pays off.","traditional":"他每天堅持學習，終於考上了理想的大學，真是水滴石穿。"},{"simplified":"水滴石穿，只要你不放弃，总会成功。","english":"Perseverance overcomes all obstacles; as long as you don't give up, you will succeed.","traditional":"水滴石穿，只要你不放棄，總會成功。"}],"synonyms":["锲而不舍","持之以恒"],"antonyms":["半途而废"],"confusedWith":[{"id":"井底之蛙","note":"This idiom refers to someone with a limited perspective, not perseverance."}],"traditional":"水滴石穿","pinyinOverride":null},{"id":"yan-er-dao-ling","simplified":"掩耳盗铃","literalMeaning":"cover ears to steal a bell","figurativeMeaning":"to deceive oneself; to ignore the obvious","englishEquivalents":["bury one's head in the sand","turn a blind eye"],"shortGloss":"deceive oneself; ignore the obvious","characters":[{"char":"掩","meaning":"cover"},{"char":"耳","meaning":"ears"},{"char":"盗","meaning":"steal"},{"char":"铃","meaning":"bell"}],"origin":{"period":"Warring States period (475–221 BCE)","sourceText":"《吕氏春秋·自知》","sourceTextEnglish":"The Annals of Lü Buwei, Self-Knowledge","originalExcerpt":"有盗钟者，欲负而走，掩其耳，曰：“我无闻也。”","storyEnglish":"In the Warring States period, a man wanted to steal a large bell. Realizing the bell would make noise, he covered his own ears, thinking this would prevent others from hearing it. This story illustrates the folly of self-deception and ignoring reality.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"literary, but widely understood and used in ordinary speech","connotation":"negative","commonMistakes":"Learners often confuse this idiom with similar ones like 掩耳盗铃 and 自欺欺人. While both involve self-deception, 掩耳盗铃 emphasizes ignoring obvious facts, while 自欺欺人 focuses on lying to oneself.","canStandAlone":false},"examples":[{"simplified":"他明知道自己错了，却还在掩耳盗铃。","english":"He knows he's wrong, yet he still deceives himself.","traditional":"他明知道自己錯了，卻還在掩耳盜鈴。"},{"simplified":"面对问题，我们不能掩耳盗铃，而应该积极解决。","english":"When facing problems, we shouldn't ignore them, but actively solve them.","traditional":"面對問題，我們不能掩耳盜鈴，而應該積極解決。"}],"synonyms":["自欺欺人"],"antonyms":[],"confusedWith":[{"id":"自欺欺人","note":"自欺欺人 means to deceive oneself and others, while 掩耳盗铃 focuses on ignoring obvious truths."}],"traditional":"掩耳盜鈴","pinyinOverride":null},{"id":"shi-quan-shi-mei","simplified":"十全十美","literalMeaning":"ten complete, ten beautiful","figurativeMeaning":"perfect in every way; flawless","englishEquivalents":["perfect","flawless","ideal"],"shortGloss":"perfect in every way","characters":[{"char":"十","meaning":"ten"},{"char":"全","meaning":"complete; whole"},{"char":"十","meaning":"ten"},{"char":"美","meaning":"beautiful; perfect"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '十全十美' is believed to have originated from the idea of achieving perfection in all aspects. The number ten is often used in Chinese culture to signify completeness and perfection. This idiom is used to describe something or someone that is flawless and without any shortcomings.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"coordinate","register":"common in both written and spoken Chinese","connotation":"positive","commonMistakes":"Learners might use this idiom to describe something that is merely good or satisfactory, but it should be reserved for situations where something is truly flawless. It is often confused with '完美无缺' which also means perfect but emphasizes the absence of defects.","canStandAlone":false},"examples":[{"simplified":"她的演出真是十全十美，令人难以忘怀。","english":"Her performance was truly perfect, leaving a lasting impression.","traditional":"她的演出真是十全十美，令人難以忘懷。"},{"simplified":"这次旅行安排得十全十美，大家都很满意。","english":"The trip was perfectly arranged, and everyone was very satisfied.","traditional":"這次旅行安排得十全十美，大家都很滿意。"}],"synonyms":["完美无缺","无懈可击"],"antonyms":["瑕不掩瑜"],"confusedWith":[{"id":"完美无缺","note":"Both mean perfect, but '完美无缺' emphasizes the absence of defects."}],"traditional":"十全十美","pinyinOverride":null},{"id":"chen-yu-luo-yan","simplified":"沉鱼落雁","literalMeaning":"fish sink, geese fall","figurativeMeaning":"extremely beautiful; so beautiful that even fish and birds are captivated","englishEquivalents":["drop-dead gorgeous","breathtaking beauty"],"shortGloss":"breathtaking beauty","characters":[{"char":"沉","meaning":"sink"},{"char":"鱼","meaning":"fish"},{"char":"落","meaning":"fall"},{"char":"雁","meaning":"geese"}],"origin":{"period":"Warring States period (475–221 BCE)","sourceText":"《庄子·齐物论》","sourceTextEnglish":"Zhuangzi, Discussion on Making All Things Equal","originalExcerpt":"毛嫱、丽姬，人之所美也；鱼见之深入，鸟见之高飞。","storyEnglish":"The idiom originates from a story about two legendary beauties, Xi Shi and Wang Zhaojun. It is said that Xi Shi's beauty was so captivating that fish would forget to swim and sink to the bottom of the water when they saw her reflection. Similarly, Wang Zhaojun's beauty was so enchanting that geese flying overhead would forget to flap their wings and fall from the sky. The idiom is used to describe someone of exceptional beauty.","historicalFigures":["Xi Shi","Wang Zhaojun"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"coordinate","register":"literary, but very widely understood and used in ordinary speech","connotation":"positive","commonMistakes":"Learners often confuse this idiom with other idioms describing beauty, such as '闭月羞花'. However, '沉鱼落雁' specifically refers to beauty that captivates nature itself.","canStandAlone":false},"examples":[{"simplified":"她的美貌真是沉鱼落雁，让人惊叹不已。","english":"Her beauty is truly breathtaking, leaving everyone in awe.","traditional":"她的美貌真是沉魚落雁，讓人驚歎不已。"},{"simplified":"在这个舞会上，她以沉鱼落雁的姿态吸引了所有人的目光。","english":"At the ball, she attracted everyone's attention with her breathtaking beauty.","traditional":"在這個舞會上，她以沉魚落雁的姿態吸引了所有人的目光。"}],"synonyms":["闭月羞花"],"antonyms":[],"confusedWith":[{"id":"闭月羞花","note":"Both idioms describe great beauty, but '闭月羞花' refers to beauty that makes the moon hide and flowers feel shy."}],"traditional":"沉魚落雁","pinyinOverride":null},{"id":"he-li-ji-qun","simplified":"鹤立鸡群","literalMeaning":"a crane standing among chickens","figurativeMeaning":"to stand out from the crowd; to be conspicuously outstanding","englishEquivalents":["stand head and shoulders above the rest","a cut above the rest"],"shortGloss":"stand out from the crowd","characters":[{"char":"鹤","meaning":"crane"},{"char":"立","meaning":"stand"},{"char":"鸡","meaning":"chickens"},{"char":"群","meaning":"group; flock"}],"origin":{"period":"Southern and Northern Dynasties (420–589)","sourceText":"《世说新语·容止》","sourceTextEnglish":"A New Account of the Tales of the World, Appearance and Bearing","originalExcerpt":"王子猷云：“君子之行，若鹤立鸡群。”","storyEnglish":"The idiom originates from an anecdote in 'A New Account of the Tales of the World,' where Wang Ziyou described a gentleman's demeanor as being like a crane standing among chickens, highlighting his exceptional and distinguished presence.","historicalFigures":["Wang Ziyou"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"modifier-head","register":"literary, but very widely understood and used in ordinary speech","connotation":"positive","commonMistakes":"Learners might confuse this idiom with others that imply standing out in a negative way. This idiom specifically conveys a positive distinction, unlike some idioms that imply arrogance or unwelcome attention.","canStandAlone":false},"examples":[{"simplified":"在这次比赛中，他的表现如鹤立鸡群。","english":"In this competition, his performance stood out like a crane among chickens.","traditional":"在這次比賽中，他的表現如鶴立雞群。"},{"simplified":"她在公司里总是鹤立鸡群，令人瞩目。","english":"She always stands out in the company, attracting everyone's attention.","traditional":"她在公司裡總是鶴立雞群，令人矚目。"}],"synonyms":["出类拔萃","卓尔不群"],"antonyms":[],"confusedWith":[],"traditional":"鶴立雞群","pinyinOverride":null},{"id":"shun-yong-shi-zhi","simplified":"吮痈舐痔","literalMeaning":"suck abscess, lick hemorrhoid","figurativeMeaning":"to flatter someone excessively and disgustingly","englishEquivalents":["to brown-nose","to suck up","to grovel"],"shortGloss":"excessive flattery","characters":[{"char":"吮","meaning":"suck"},{"char":"痈","meaning":"abscess"},{"char":"舐","meaning":"lick"},{"char":"痔","meaning":"hemorrhoid"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"Origin disputed / folk etymology","storyEnglish":"The idiom describes an act of extreme and disgusting flattery, likening it to the revolting image of sucking an abscess or licking a hemorrhoid. It is used to criticize someone who goes to great lengths to ingratiate themselves with someone in power, often in a way that is seen as shameless or servile.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","object"],"structure":"coordinate","register":"literary, often used in critical or sarcastic contexts","connotation":"negative","commonMistakes":"Learners might confuse this idiom with less extreme expressions of flattery. It specifically implies a level of flattery that is revolting and shameless, not just excessive.","canStandAlone":false},"examples":[{"simplified":"他为了升职，真是吮痈舐痔，毫无尊严。","english":"He really sucked up to get promoted, completely without dignity.","traditional":"他為了升職，真是吮癰舐痔，毫無尊嚴。"},{"simplified":"在会议上，他的发言简直是吮痈舐痔，让人作呕。","english":"His speech at the meeting was nothing short of disgusting flattery, making people nauseous.","traditional":"在會議上，他的發言簡直是吮癰舐痔，讓人作嘔。"}],"synonyms":["阿谀奉承","拍马屁"],"antonyms":[],"confusedWith":[{"id":"阿谀奉承","note":"While both imply flattery, 吮痈舐痔 is more extreme and carries a stronger negative connotation."}],"traditional":"吮癰舐痔","pinyinOverride":null},{"id":"mu-hou-er-guan","simplified":"沐猴而冠","literalMeaning":"monkey wearing a hat","figurativeMeaning":"a person who is superficially dignified or respectable but lacks real substance or ability","englishEquivalents":["a wolf in sheep's clothing","all hat and no cattle"],"shortGloss":"superficially respectable but lacking substance","characters":[{"char":"沐","meaning":"wash; bathe"},{"char":"猴","meaning":"monkey"},{"char":"而","meaning":"and; but"},{"char":"冠","meaning":"hat; cap"}],"origin":{"period":"Warring States period (475–221 BCE)","sourceText":"《史记·项羽本纪》","sourceTextEnglish":"Records of the Grand Historian, Biography of Xiang Yu","originalExcerpt":"沐猴而冠，知其雄而已。","storyEnglish":"The idiom comes from a story in the 'Records of the Grand Historian' by Sima Qian. It describes a person who, despite wearing the attire of a gentleman, behaves like a monkey. The phrase was used to criticize someone who was superficially dignified but lacked true capability or virtue.","historicalFigures":["Xiang Yu"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"modifier-head","register":"literary, but understood in educated speech","connotation":"negative","commonMistakes":"Learners sometimes use this idiom to describe any kind of disguise or pretense, but it specifically implies a lack of genuine ability or virtue behind a respectable appearance.","canStandAlone":false},"examples":[{"simplified":"他不过是个沐猴而冠的人，根本没有真正的能力。","english":"He is just a person who is superficially dignified but lacks real ability.","traditional":"他不過是個沐猴而冠的人，根本沒有真正的能力。"},{"simplified":"在这个行业里，沐猴而冠的人并不少见。","english":"In this industry, it's not uncommon to see people who are superficially respectable but lack substance.","traditional":"在這個行業裡，沐猴而冠的人並不少見。"}],"synonyms":["金玉其外，败絮其中"],"antonyms":[],"confusedWith":[{"id":"狐假虎威","note":"狐假虎威 refers to someone who uses another's power to intimidate others, rather than lacking substance themselves."}],"traditional":"沐猴而冠","pinyinOverride":null},{"id":"gan-zhi-ru-yi","simplified":"甘之如饴","literalMeaning":"sweet as syrup","figurativeMeaning":"to endure hardship gladly; to find sweetness in adversity","englishEquivalents":["grin and bear it","take it on the chin"],"shortGloss":"endure hardship gladly","characters":[{"char":"甘","meaning":"sweet"},{"char":"之","meaning":"it; this"},{"char":"如","meaning":"like; as if"},{"char":"饴","meaning":"syrup; candy"}],"origin":{"period":"Han Dynasty (202 BCE – 220 CE)","sourceText":"《后汉书·卷六十五·冯衍传》","sourceTextEnglish":"Book of the Later Han, Volume 65, Biography of Feng Yan","originalExcerpt":"虽蒙斥逐，甘之如饴。","storyEnglish":"The idiom originates from the story of Feng Yan, a scholar during the Han Dynasty. Despite being exiled and facing many hardships, Feng Yan maintained a positive attitude and accepted his fate with grace, finding sweetness in his adversity as if it were candy.","historicalFigures":["Feng Yan"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"subject-predicate","register":"literary, but understood in educated speech","connotation":"positive","commonMistakes":"Learners often confuse this idiom with others that imply mere tolerance of hardship, but 甘之如饴 specifically conveys a sense of finding joy or sweetness in the adversity itself.","canStandAlone":false},"examples":[{"simplified":"他在逆境中甘之如饴，从不抱怨。","english":"He endures adversity gladly and never complains.","traditional":"他在逆境中甘之如飴，從不抱怨。"},{"simplified":"即使工作再辛苦，她也甘之如饴。","english":"Even if the work is tough, she endures it gladly.","traditional":"即使工作再辛苦，她也甘之如飴。"}],"synonyms":["乐在其中","自得其乐"],"antonyms":["苦不堪言"],"confusedWith":[{"id":"忍辱负重","note":"忍辱负重 means to endure humiliation and bear a heavy burden, focusing more on endurance than finding joy."}],"traditional":"甘之如飴","pinyinOverride":null},{"id":"yi-jian-shuang-diao","simplified":"一箭双鵰","literalMeaning":"one arrow, two eagles","figurativeMeaning":"to achieve two goals with a single action","englishEquivalents":["kill two birds with one stone"],"shortGloss":"achieve two goals at once","characters":[{"char":"一","meaning":"one"},{"char":"箭","meaning":"arrow"},{"char":"双","meaning":"two; double"},{"char":"鵰","meaning":"eagles"}],"origin":{"period":"Northern and Southern Dynasties (420–589 CE)","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom originates from a story about a skilled archer who was able to shoot down two eagles with a single arrow. This impressive feat became a metaphor for accomplishing two objectives with one action.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"widely used in both formal and informal contexts","connotation":"positive","commonMistakes":"Learners often confuse this idiom with similar expressions that involve achieving multiple goals, but it specifically refers to achieving exactly two goals with one action.","canStandAlone":false},"examples":[{"simplified":"通过这次合作，我们可以一箭双鵰，既提高销量，又提升品牌知名度。","english":"Through this collaboration, we can kill two birds with one stone by increasing sales and enhancing brand awareness.","traditional":"通過這次合作，我們可以一箭雙鵰，既提高銷量，又提升品牌知名度。"},{"simplified":"他用一个方案解决了两个问题，真是一箭双鵰。","english":"He solved two problems with one solution; truly killing two birds with one stone.","traditional":"他用一個方案解決了兩個問題，真是一箭雙鵰。"}],"synonyms":["一举两得"],"antonyms":[],"confusedWith":[{"id":"一举两得","note":"While both idioms mean achieving multiple goals, 一举两得 is more general and not limited to exactly two outcomes."}],"traditional":"一箭雙鵰","pinyinOverride":null},{"id":"wang-yang-bu-lao","simplified":"亡羊补牢","literalMeaning":"lose sheep repair pen","figurativeMeaning":"to take action after suffering a loss to prevent further damage; better late than never","englishEquivalents":["Better late than never","Close the stable door after the horse has bolted"],"shortGloss":"take action after a loss","characters":[{"char":"亡","meaning":"lose"},{"char":"羊","meaning":"sheep"},{"char":"补","meaning":"repair"},{"char":"牢","meaning":"pen; enclosure"}],"origin":{"period":"Warring States period (475–221 BCE)","sourceText":"《战国策·楚策四》","sourceTextEnglish":"Strategies of the Warring States, Strategies of Chu, Chapter 4","originalExcerpt":"见羊亡而补牢，未为晚也。","storyEnglish":"In the Warring States period, a man discovered that one of his sheep had been lost because the pen was not secure. His friend advised him to repair the pen to prevent further losses. Initially, the man hesitated, thinking it was too late, but eventually, he followed the advice and fixed the pen, saving the rest of his sheep. The story illustrates the idea that it is never too late to take corrective action.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"literary, but very widely understood and used in ordinary speech","connotation":"neutral","commonMistakes":"Learners often confuse this idiom with expressions that imply futility, but it actually emphasizes the importance of taking corrective action even after a loss.","canStandAlone":false},"examples":[{"simplified":"虽然项目失败了，但我们应该亡羊补牢，改善计划。","english":"Even though the project failed, we should take corrective action and improve the plan.","traditional":"雖然項目失敗了，但我們應該亡羊補牢，改善計劃。"},{"simplified":"他意识到错误后，立即采取措施，真是亡羊补牢。","english":"After realizing the mistake, he immediately took action, truly a case of better late than never.","traditional":"他意識到錯誤後，立即採取措施，真是亡羊補牢。"}],"synonyms":["亡羊得牛"],"antonyms":[],"confusedWith":[{"id":"亡羊得牛","note":"亡羊得牛 implies gaining something unexpected after a loss, while 亡羊补牢 focuses on taking corrective action."}],"traditional":"亡羊補牢","pinyinOverride":null},{"id":"sai-weng-shi-ma","simplified":"塞翁失马","literalMeaning":"Old man from the frontier loses a horse","figurativeMeaning":"A setback may turn out to be a blessing in disguise","englishEquivalents":["A blessing in disguise","Every cloud has a silver lining"],"shortGloss":"a setback may be a blessing","characters":[{"char":"塞","meaning":"frontier"},{"char":"翁","meaning":"old man"},{"char":"失","meaning":"lose"},{"char":"马","meaning":"horse"}],"origin":{"period":"Han Dynasty (202 BCE – 220 CE)","sourceText":"《淮南子·人间训》","sourceTextEnglish":"Huainanzi, Lessons of the Human World","originalExcerpt":"塞翁失马，焉知非福。","storyEnglish":"The story tells of an old man living near the frontier who loses his horse. His neighbors commiserate with him, but he responds that it might not be a bad thing. Later, the horse returns with another horse, bringing him good fortune. This story illustrates that what seems like a misfortune may actually lead to good fortune.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["subject","predicate","object"],"structure":"subject-predicate","register":"literary, but very widely understood and used in ordinary speech","connotation":"neutral","commonMistakes":"Learners often use this idiom only for negative situations, but it actually emphasizes the unpredictable nature of events, where a negative event can lead to positive outcomes.","canStandAlone":true},"examples":[{"simplified":"虽然他这次考试没考好，但塞翁失马，可能会激励他更加努力。","english":"Although he didn't do well in this exam, it might be a blessing in disguise, encouraging him to work harder.","traditional":"雖然他這次考試沒考好，但塞翁失馬，可能會激勵他更加努力。"},{"simplified":"失去这份工作可能是塞翁失马，因为他找到了更好的机会。","english":"Losing this job might be a blessing in disguise because he found a better opportunity.","traditional":"失去這份工作可能是塞翁失馬，因為他找到了更好的機會。"}],"synonyms":[],"antonyms":[],"confusedWith":[{"id":"因祸得福","note":"Both idioms suggest a positive outcome from a negative situation, but 塞翁失马 emphasizes the unpredictability of events, while 因祸得福 focuses on directly benefiting from a misfortune."}],"traditional":"塞翁失馬","pinyinOverride":null},{"id":"ba-miao-zhu-zhang","simplified":"拔苗助长","literalMeaning":"pull seedlings to help them grow","figurativeMeaning":"to spoil things through excessive enthusiasm; to harm by being overzealous","englishEquivalents":["Haste makes waste","Killing the goose that lays the golden eggs"],"shortGloss":"harm by being overzealous","characters":[{"char":"拔","meaning":"pull"},{"char":"苗","meaning":"seedlings"},{"char":"助","meaning":"help"},{"char":"长","meaning":"grow"}],"origin":{"period":"Warring States period (475–221 BCE)","sourceText":"《孟子·公孙丑上》","sourceTextEnglish":"Mencius, Gongsun Chou I","originalExcerpt":"宋人有闵其苗之不长而揠之者，芒芒然归，以为助苗长矣。","storyEnglish":"The idiom comes from a story in the Warring States period. A farmer in the state of Song was anxious about the growth of his seedlings. In his impatience, he decided to pull them up slightly, thinking it would help them grow faster. When he returned home, he proudly told his family about his efforts. However, the seedlings withered and died as a result of his actions. The story illustrates the folly of trying to achieve success through impatience and excessive interference.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["subject","predicate","object"],"structure":"verb-object","register":"literary, but very widely understood and used in ordinary speech","connotation":"negative","commonMistakes":"Learners often misunderstand this idiom as simply meaning 'to help grow' without realizing the negative connotation of harming through overzealous actions. It is different from idioms that genuinely mean to assist growth or progress.","canStandAlone":false},"examples":[{"simplified":"他对孩子的学习太过于拔苗助长，结果适得其反。","english":"He was too overzealous in pushing his child's studies, and it backfired.","traditional":"他對孩子的學習太過於拔苗助長，結果適得其反。"},{"simplified":"我们应该顺其自然，而不是拔苗助长。","english":"We should let things take their natural course, rather than spoil them by being overzealous.","traditional":"我們應該順其自然，而不是拔苗助長。"}],"synonyms":["欲速则不达"],"antonyms":[],"confusedWith":[{"id":"助人为乐","note":"助人为乐 means 'to take pleasure in helping others', which is positive and lacks the negative connotation of harming through overzealous actions."}],"traditional":"拔苗助長","pinyinOverride":null},{"id":"jing-di-zhi-wa","simplified":"井底之蛙","literalMeaning":"frog at the bottom of a well","figurativeMeaning":"a person with a limited perspective or narrow view of the world","englishEquivalents":["frog in a well","narrow-minded person"],"shortGloss":"narrow-minded person","characters":[{"char":"井","meaning":"well"},{"char":"底","meaning":"bottom"},{"char":"之","meaning":"of"},{"char":"蛙","meaning":"frog"}],"origin":{"period":"Warring States period (475–221 BCE)","sourceText":"《庄子·秋水》","sourceTextEnglish":"Zhuangzi, Chapter \\"Autumn Floods\\"","originalExcerpt":"井蛙不可以语于海者，拘于虚也。","storyEnglish":"The idiom originates from a story in the Daoist text 'Zhuangzi'. It describes a frog living at the bottom of a well, who boasts about its comfortable life to a sea turtle. The turtle, having seen the vastness of the ocean, knows how limited the frog's perspective is. This story illustrates how people can be unaware of the broader world due to their limited experiences.","historicalFigures":["Zhuangzi"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["subject","object","attributive"],"structure":"modifier-head","register":"literary, but widely used in both formal and informal contexts","connotation":"negative","commonMistakes":"Learners may confuse this idiom with similar expressions about ignorance, but it specifically emphasizes a lack of perspective due to limited experience, not just ignorance in general.","canStandAlone":false},"examples":[{"simplified":"他从来没有出过国，是个典型的井底之蛙。","english":"He has never been abroad and is a typical frog in a well.","traditional":"他從來沒有出過國，是個典型的井底之蛙。"},{"simplified":"我们不能做井底之蛙，要多看看外面的世界。","english":"We shouldn't be like a frog in a well; we need to see more of the outside world.","traditional":"我們不能做井底之蛙，要多看看外面的世界。"}],"synonyms":["坐井观天"],"antonyms":[],"confusedWith":[{"id":"坐井观天","note":"Both idioms describe limited perspective, but 井底之蛙 focuses more on the narrow-mindedness of the individual."}],"traditional":"井底之蛙","pinyinOverride":null},{"id":"ji-quan-bu-ning","simplified":"鸡犬不宁","literalMeaning":"chickens and dogs are not peaceful","figurativeMeaning":"a situation of utter chaos and disturbance","englishEquivalents":["all hell broke loose","in disarray"],"shortGloss":"chaotic and disturbed","characters":[{"char":"鸡","meaning":"chickens"},{"char":"犬","meaning":"dogs"},{"char":"不","meaning":"not"},{"char":"宁","meaning":"peaceful"}],"origin":{"period":"Warring States period (475–221 BCE)","sourceText":"《战国策·齐策四》","sourceTextEnglish":"Strategies of the Warring States, Strategies of Qi, Volume 4","originalExcerpt":"鸡犬之声相闻，老死不相往来。","storyEnglish":"The idiom originates from a passage in the 'Strategies of the Warring States', where it describes a scenario in which the sounds of chickens and dogs can be heard, but people live in such isolation that they do not interact with each other until they die of old age. Over time, the idiom evolved to describe a situation of chaos and disturbance where even the animals are not at peace.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"subject-predicate","register":"commonly used in both written and spoken Chinese","connotation":"negative","commonMistakes":"Learners may confuse this idiom with others that describe chaos but do not emphasize the disturbance to animals. It's important to note the specific imagery of chickens and dogs being disturbed.","canStandAlone":false},"examples":[{"simplified":"小偷闯入村子后，村里鸡犬不宁。","english":"After the thief broke into the village, all hell broke loose.","traditional":"小偷闖入村子後，村裡雞犬不寧。"},{"simplified":"他的到来让整个办公室鸡犬不宁。","english":"His arrival threw the entire office into disarray.","traditional":"他的到來讓整個辦公室雞犬不寧。"}],"synonyms":["鸡飞狗跳"],"antonyms":["风平浪静"],"confusedWith":[{"id":"鸡飞狗跳","note":"While both idioms describe chaos, 鸡飞狗跳 emphasizes frantic activity, whereas 鸡犬不宁 emphasizes disturbance and unrest."}],"traditional":"雞犬不寧","pinyinOverride":null},{"id":"zi-xiang-mao-dun","simplified":"自相矛盾","literalMeaning":"self mutually spear shield","figurativeMeaning":"to contradict oneself","englishEquivalents":["self-contradiction","to be one's own worst enemy"],"shortGloss":"self-contradiction","characters":[{"char":"自","meaning":"self"},{"char":"相","meaning":"mutually"},{"char":"矛","meaning":"spear"},{"char":"盾","meaning":"shield"}],"origin":{"period":"Warring States period (475–221 BCE)","sourceText":"《韩非子·难一》","sourceTextEnglish":"Han Feizi, Difficulties, Chapter 1","originalExcerpt":"楚人有鬻盾与矛者，誉之曰：“吾盾之坚，物莫能陷也。”又誉其矛曰：“吾矛之利，于物无不陷也。”或曰：“以子之矛，陷子之盾，何如？”其人弗能应也。","storyEnglish":"In the state of Chu, there was a man who sold both spears and shields. He claimed that his shields were so strong that nothing could pierce them, and that his spears were so sharp that they could pierce anything. Someone asked him, 'What if your spear is used to pierce your shield?' The man was unable to respond. This story illustrates the concept of self-contradiction.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["subject","predicate","object"],"structure":"verb-object","register":"literary, but very widely understood and used in ordinary speech","connotation":"negative","commonMistakes":"Learners often confuse this idiom with others involving contradiction, but it specifically refers to self-contradiction, not contradictions between different people or ideas.","canStandAlone":false},"examples":[{"simplified":"他说的话前后不一致，真是自相矛盾。","english":"What he said was inconsistent, truly self-contradictory.","traditional":"他說的話前後不一致，真是自相矛盾。"},{"simplified":"如果你总是自相矛盾，别人就很难相信你。","english":"If you are always self-contradictory, others will find it hard to trust you.","traditional":"如果你總是自相矛盾，別人就很難相信你。"}],"synonyms":[],"antonyms":[],"confusedWith":[{"id":"自相残杀","note":"自相残杀 means to inflict harm on one's own group, not self-contradiction."}],"traditional":"自相矛盾","pinyinOverride":null},{"id":"po-fu-chen-zhou","simplified":"破釜沉舟","literalMeaning":"break the cauldrons and sink the boats","figurativeMeaning":"to commit to a course of action with no turning back; to make a determined effort","englishEquivalents":["burn one's boats","cross the Rubicon"],"shortGloss":"commit with no turning back","characters":[{"char":"破","meaning":"break"},{"char":"釜","meaning":"cauldron"},{"char":"沉","meaning":"sink"},{"char":"舟","meaning":"boat"}],"origin":{"period":"Warring States period (475–221 BCE)","sourceText":"《史记·项羽本纪》","sourceTextEnglish":"Records of the Grand Historian, Biography of Xiang Yu","originalExcerpt":"项羽乃悉引兵渡河，皆沉船，破釜甑，烧庐舍，以示士卒必死，无一还心。","storyEnglish":"The idiom originates from a story about Xiang Yu, a prominent military leader during the late Qin Dynasty. In a decisive battle, he ordered his troops to cross a river and then destroyed their own boats and cooking pots. This drastic action left them with no option but to fight to the death, as retreat was impossible. This strategy led to a significant victory, demonstrating the power of commitment and determination.","historicalFigures":["Xiang Yu"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"literary, but very widely understood and used in ordinary speech","connotation":"positive","commonMistakes":"Learners often confuse this idiom with similar expressions that imply recklessness. However, 破釜沉舟 emphasizes determination and commitment rather than rashness.","canStandAlone":false},"examples":[{"simplified":"为了实现梦想，他决定破釜沉舟，全力以赴。","english":"To achieve his dreams, he decided to burn his boats and give it his all.","traditional":"為了實現夢想，他決定破釜沉舟，全力以赴。"},{"simplified":"在这次比赛中，我们必须破釜沉舟，才能赢得胜利。","english":"In this competition, we must commit with no turning back to secure victory.","traditional":"在這次比賽中，我們必須破釜沉舟，才能贏得勝利。"}],"synonyms":["背水一战"],"antonyms":[],"confusedWith":[{"id":"孤注一掷","note":"孤注一掷 implies taking a gamble or risk, whereas 破釜沉舟 emphasizes determination and commitment without the implication of gambling."}],"traditional":"破釜沉舟","pinyinOverride":null},{"id":"bei-gong-she-ying","simplified":"杯弓蛇影","literalMeaning":"cup bow snake shadow","figurativeMeaning":"to be overly suspicious or to mistake something harmless for a threat","englishEquivalents":["making a mountain out of a molehill","seeing ghosts","jumping at shadows"],"shortGloss":"mistaking harmless things for threats","characters":[{"char":"杯","meaning":"cup"},{"char":"弓","meaning":"bow"},{"char":"蛇","meaning":"snake"},{"char":"影","meaning":"shadow"}],"origin":{"period":"Eastern Jin Dynasty (317–420 CE)","sourceText":"《晋书·乐广传》","sourceTextEnglish":"Book of Jin, Biography of Yue Guang","originalExcerpt":"广尝与客饮，见壁上有悬弓影，误以为蛇，客心恶之，竟成疾。","storyEnglish":"The story behind this idiom comes from the Eastern Jin Dynasty. Yue Guang once entertained a guest with wine. The guest saw the shadow of a bow on the wall and mistook it for a snake. This misunderstanding caused the guest to feel uneasy and eventually fall ill. It was only later that the guest realized it was just the shadow of a bow, not a snake.","historicalFigures":["Yue Guang"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["subject","predicate","object","attributive"],"structure":"modifier-head","register":"literary, but very widely understood and used in ordinary speech","connotation":"negative","commonMistakes":"Learners might confuse this idiom with ones that imply actual danger or threats, but it specifically refers to unfounded fears or misunderstandings. It doesn't apply to situations where the threat is real.","canStandAlone":false},"examples":[{"simplified":"他总是杯弓蛇影，看到一点小问题就紧张不已。","english":"He is always jumping at shadows, getting anxious over the slightest issues.","traditional":"他總是杯弓蛇影，看到一點小問題就緊張不已。"},{"simplified":"我们不应该杯弓蛇影，要冷静分析问题。","english":"We shouldn't be overly suspicious; we need to calmly analyze the problem.","traditional":"我們不應該杯弓蛇影，要冷靜分析問題。"}],"synonyms":["草木皆兵"],"antonyms":[],"confusedWith":[{"id":"草木皆兵","note":"While both idioms involve fear, 草木皆兵 refers to being so fearful that everything seems like an enemy, whereas 杯弓蛇影 refers to a specific misunderstanding or unfounded suspicion."}],"traditional":"杯弓蛇影","pinyinOverride":null},{"id":"ru-mu-san-fen","simplified":"入木三分","literalMeaning":"penetrate wood three-tenths","figurativeMeaning":"to be deeply impressed or to have profound insight","englishEquivalents":["deeply impressed","profound insight"],"shortGloss":"deeply impressed or insightful","characters":[{"char":"入","meaning":"penetrate"},{"char":"木","meaning":"wood"},{"char":"三","meaning":"three"},{"char":"分","meaning":"tenths"}],"origin":{"period":"Eastern Jin dynasty (317–420)","sourceText":"《世说新语·巧艺》","sourceTextEnglish":"A New Account of the Tales of the World, Skill and Artistry","originalExcerpt":"王羲之书《乐毅论》，笔力劲健，透入木三分。","storyEnglish":"The idiom comes from a story about the famous calligrapher Wang Xizhi. It is said that when he wrote the 'Essay on Music', his brush strokes were so powerful that they penetrated three-tenths into the wood of the writing board. This became a metaphor for having a profound impact or deep insight.","historicalFigures":["Wang Xizhi"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"modifier-head","register":"literary, but widely used in both written and spoken Chinese","connotation":"positive","commonMistakes":"Learners might confuse this idiom with similar expressions that imply superficiality. It's important to remember that this idiom conveys depth and intensity.","canStandAlone":false},"examples":[{"simplified":"他的分析真是入木三分，让人佩服。","english":"His analysis is truly insightful and impressive.","traditional":"他的分析真是入木三分，讓人佩服。"},{"simplified":"这篇文章对社会现象的描述入木三分。","english":"This article provides a profound description of social phenomena.","traditional":"這篇文章對社會現象的描述入木三分。"}],"synonyms":["鞭辟入里"],"antonyms":[],"confusedWith":[{"id":"浮光掠影","note":"浮光掠影 suggests a superficial or cursory understanding, unlike 入木三分 which implies depth."}],"traditional":"入木三分","pinyinOverride":null},{"id":"hu-jia-hu-wei","simplified":"狐假虎威","literalMeaning":"the fox borrows the tiger's might","figurativeMeaning":"to bully others by flaunting one's powerful connections","englishEquivalents":["to ride on someone's coattails","to throw one's weight around"],"shortGloss":"bully with borrowed authority","characters":[{"char":"狐","meaning":"fox"},{"char":"假","meaning":"to borrow; to use"},{"char":"虎","meaning":"tiger"},{"char":"威","meaning":"might; authority"}],"origin":{"period":"Warring States period (475–221 BCE)","sourceText":"《战国策·楚策一》","sourceTextEnglish":"Strategies of the Warring States, Strategies of Chu I","originalExcerpt":"虎求百兽而食之，得狐。狐曰：“子无敢食我也！天帝使我长百兽，今子食我，是逆天帝命也。子以我为不信，吾为子先行，子随我后，观百兽之见我而敢不走乎？”虎以为然，故遂与之行，兽见之皆走。虎不知兽畏己而走也，以为畏狐也。","storyEnglish":"In the Warring States period, a tiger caught a fox and was about to eat it. The fox, however, claimed that it was sent by the Emperor of Heaven to rule over all animals and that eating it would be defying the emperor's command. The fox suggested that the tiger follow it and see how all the animals would flee in fear. The tiger agreed, and as they walked together, all the animals indeed ran away. The tiger believed they were afraid of the fox, not realizing they were actually afraid of the tiger itself.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["subject","predicate","object"],"structure":"verb-object","register":"literary, but very widely understood and used in ordinary speech","connotation":"negative","commonMistakes":"Learners often confuse this idiom with those that imply genuine power or authority, but it specifically refers to someone using another's power to intimidate others.","canStandAlone":false},"examples":[{"simplified":"他总是狐假虎威，仗着他哥哥的权势欺负别人。","english":"He always bullies others by flaunting his brother's power.","traditional":"他總是狐假虎威，仗著他哥哥的權勢欺負別人。"},{"simplified":"小李在公司里狐假虎威，大家都不喜欢他。","english":"Xiao Li throws his weight around in the company, and nobody likes him.","traditional":"小李在公司裡狐假虎威，大家都不喜歡他。"}],"synonyms":["仗势欺人"],"antonyms":["自力更生"],"confusedWith":[{"id":"仗势欺人","note":"Both involve using power to intimidate, but 狐假虎威 emphasizes borrowed power, while 仗势欺人 can be one's own power."}],"traditional":"狐假虎威","pinyinOverride":null},{"id":"xiong-you-cheng-zhu","simplified":"胸有成竹","literalMeaning":"chest has finished bamboo","figurativeMeaning":"to have a well-thought-out plan or to have confidence in what one is doing","englishEquivalents":["to have a plan in mind","to have confidence in one's plan"],"shortGloss":"to have a plan in mind","characters":[{"char":"胸","meaning":"chest; metaphorically, one's mind or heart"},{"char":"有","meaning":"to have"},{"char":"成","meaning":"completed; finished"},{"char":"竹","meaning":"bamboo"}],"origin":{"period":"Song Dynasty (960–1279)","sourceText":"《梦溪笔谈》","sourceTextEnglish":"Brush Talks from a Dream Brook","originalExcerpt":"画竹必先得成竹于胸中，执笔熟视，乃见其所欲画者成于纸上。","storyEnglish":"The idiom originates from the Song Dynasty text 'Brush Talks from a Dream Brook' by Shen Kuo. It describes the process of painting bamboo, where the artist must first have a clear image of the completed bamboo in their mind before they begin to paint. This metaphorically extends to having a clear plan or vision before taking action.","historicalFigures":["Shen Kuo"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"subject-predicate","register":"literary, but very widely understood and used in ordinary speech","connotation":"positive","commonMistakes":"Learners often confuse this idiom with others that imply confidence but lack the nuance of having a premeditated plan. It specifically emphasizes having a clear vision or plan before acting.","canStandAlone":false},"examples":[{"simplified":"他在演讲前已经胸有成竹，所以表现得很自信。","english":"He had a well-thought-out plan before the speech, so he appeared very confident.","traditional":"他在演講前已經胸有成竹，所以表現得很自信。"},{"simplified":"面对挑战，她总是胸有成竹，从不慌乱。","english":"When facing challenges, she always has a plan in mind and never panics.","traditional":"面對挑戰，她總是胸有成竹，從不慌亂。"}],"synonyms":["成竹在胸"],"antonyms":[],"confusedWith":[{"id":"胸有成竹","note":"This is the idiom itself; learners often confuse its specific meaning with other idioms that imply confidence without the aspect of planning."}],"traditional":"胸有成竹","pinyinOverride":null},{"id":"shui-luo-shi-chu","simplified":"水落石出","literalMeaning":"water recedes, rocks appear","figurativeMeaning":"the truth will come to light","englishEquivalents":["The truth will out","All will be revealed"],"shortGloss":"the truth will come to light","characters":[{"char":"水","meaning":"water"},{"char":"落","meaning":"recedes"},{"char":"石","meaning":"rocks"},{"char":"出","meaning":"appear"}],"origin":{"period":"Song Dynasty (960–1279)","sourceText":"《苏轼诗集·后赤壁赋》","sourceTextEnglish":"Su Shi's Poetry Collection, 'Later Ode on the Red Cliff'","originalExcerpt":"山高月小，水落石出。","storyEnglish":"The idiom originates from a poem by Su Shi, a famous Song Dynasty poet. In his poem 'Later Ode on the Red Cliff,' he describes a scene where, as the water level drops, the rocks that were previously submerged come into view. This imagery is used metaphorically to suggest that as time passes, hidden truths will eventually be revealed.","historicalFigures":["Su Shi"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"subject-predicate","register":"literary, but very widely understood and used in ordinary speech","connotation":"neutral","commonMistakes":"Learners often confuse this idiom with those that suggest a sudden revelation, but 水落石出 implies a gradual uncovering of truth over time, not an immediate discovery.","canStandAlone":false},"examples":[{"simplified":"经过调查，事情的真相终于水落石出。","english":"After the investigation, the truth of the matter finally came to light.","traditional":"經過調查，事情的真相終於水落石出。"},{"simplified":"时间会让一切水落石出。","english":"Time will reveal everything.","traditional":"時間會讓一切水落石出。"}],"synonyms":["真相大白"],"antonyms":["扑朔迷离"],"confusedWith":[{"id":"真相大白","note":"真相大白 suggests an immediate revelation of truth, while 水落石出 implies a gradual process."}],"traditional":"水落石出","pinyinOverride":null},{"id":"ru-yu-de-shui","simplified":"如鱼得水","literalMeaning":"like a fish getting water","figurativeMeaning":"to be in one's element; to feel at home in a suitable environment","englishEquivalents":["like a fish in water","in one's element"],"shortGloss":"in one's element","characters":[{"char":"如","meaning":"like; as if"},{"char":"鱼","meaning":"fish"},{"char":"得","meaning":"obtain; get"},{"char":"水","meaning":"water"}],"origin":{"period":"Three Kingdoms period (220–280 CE)","sourceText":"《三国志·蜀书·诸葛亮传》","sourceTextEnglish":"Records of the Three Kingdoms, Shu Book, Biography of Zhuge Liang","originalExcerpt":"孤之有孔明，犹鱼之有水也。","storyEnglish":"The idiom originates from a statement by Liu Bei, a warlord during the Three Kingdoms period, who compared his relationship with his strategist Zhuge Liang to that of a fish having water. Liu Bei felt that Zhuge Liang's presence was as essential and natural to him as water is to a fish.","historicalFigures":["Liu Bei","Zhuge Liang"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"modifier-head","register":"commonly used in both formal and informal contexts","connotation":"positive","commonMistakes":"Learners sometimes confuse this idiom with similar expressions that imply comfort but not necessarily suitability. It's important to note that 如鱼得水 emphasizes being in an environment where one can thrive.","canStandAlone":false},"examples":[{"simplified":"他在新公司如鱼得水，很快就得到了提升。","english":"He is in his element at the new company and was quickly promoted.","traditional":"他在新公司如魚得水，很快就得到了提升。"},{"simplified":"小明在游泳池里如鱼得水，游得非常快。","english":"Xiao Ming is like a fish in water in the swimming pool, swimming very fast.","traditional":"小明在游泳池裡如魚得水，遊得非常快。"}],"synonyms":["得心应手"],"antonyms":["如坐针毡"],"confusedWith":[{"id":"如虎添翼","note":"如虎添翼 means 'like a tiger with wings', emphasizing increased strength or capability, not just being in a suitable environment."}],"traditional":"如魚得水","pinyinOverride":null},{"id":"ju-yi-fan-san","simplified":"举一反三","literalMeaning":"raise one, infer three","figurativeMeaning":"to infer or deduce many things from one example; to learn by analogy","englishEquivalents":["learn by analogy","extrapolate from one example"],"shortGloss":"infer many from one example","characters":[{"char":"举","meaning":"raise, bring up"},{"char":"一","meaning":"one"},{"char":"反","meaning":"turn over, infer"},{"char":"三","meaning":"three"}],"origin":{"period":"Warring States period (475–221 BCE)","sourceText":"《论语·述而》","sourceTextEnglish":"Analects of Confucius, Chapter 7","originalExcerpt":"举一隅不以三隅反，则不复也。","storyEnglish":"In the Analects of Confucius, Confucius emphasizes the importance of being able to learn from one example and apply it to other situations. He suggests that if a student cannot infer three other things from one example, then he will not teach them further. This illustrates the value placed on the ability to think critically and learn independently.","historicalFigures":["Confucius"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"literary, but widely used in both formal and informal contexts","connotation":"positive","commonMistakes":"Learners might confuse this idiom with others that involve numbers, such as '三心二意', which has a negative connotation. '举一反三' is specifically about the ability to infer and learn, which is positive.","canStandAlone":false},"examples":[{"simplified":"老师希望学生能举一反三，而不是死记硬背。","english":"The teacher hopes that students can learn by analogy rather than just memorizing.","traditional":"老師希望學生能舉一反三，而不是死記硬背。"},{"simplified":"通过这个例子，他举一反三，解决了许多类似的问题。","english":"Through this example, he inferred many things and solved many similar problems.","traditional":"通過這個例子，他舉一反三，解決了許多類似的問題。"}],"synonyms":[],"antonyms":[],"confusedWith":[{"id":"三心二意","note":"三心二意 means to be indecisive or distracted, which is negative, unlike the positive connotation of learning effectively in 举一反三."}],"traditional":"舉一反三","pinyinOverride":null},{"id":"qing-chu-yu-lan","simplified":"青出于蓝","literalMeaning":"blue comes from indigo","figurativeMeaning":"the student surpasses the master","englishEquivalents":["The pupil surpasses the master","Outshining one's teacher"],"shortGloss":"student surpasses the teacher","characters":[{"char":"青","meaning":"blue/green"},{"char":"出","meaning":"comes from"},{"char":"于","meaning":"from"},{"char":"蓝","meaning":"indigo"}],"origin":{"period":"Warring States period (475–221 BCE)","sourceText":"《荀子·劝学》","sourceTextEnglish":"Xunzi, Encouraging Learning","originalExcerpt":"青，取之于蓝，而青于蓝。","storyEnglish":"The idiom comes from a passage in the text 'Xunzi,' where it is explained that the color blue is derived from the indigo plant, yet it is bluer than the plant itself. This metaphor is used to illustrate how students can surpass their teachers in skill and knowledge, just as the color blue surpasses the indigo plant in depth of color.","historicalFigures":["Xunzi"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["subject","predicate","object"],"structure":"subject-predicate","register":"literary, but widely used in both formal and informal contexts","connotation":"positive","commonMistakes":"Learners sometimes confuse this idiom with others that involve surpassing or excelling, but this specifically emphasizes the relationship between teacher and student.","canStandAlone":false},"examples":[{"simplified":"他的学生在比赛中表现得比他还好，真是青出于蓝。","english":"His student performed even better than him in the competition; truly, the student has surpassed the master.","traditional":"他的學生在比賽中表現得比他還好，真是青出於藍。"},{"simplified":"这位年轻的画家作品精湛，青出于蓝，令人惊叹。","english":"The young painter's work is exquisite, surpassing his teacher, and is truly astonishing.","traditional":"這位年輕的畫家作品精湛，青出於藍，令人驚歎。"}],"synonyms":["后浪推前浪"],"antonyms":[],"confusedWith":[{"id":"后来居上","note":"While both idioms involve surpassing, 后来居上 refers more broadly to later generations or newcomers surpassing the previous ones, not specifically a teacher-student context."}],"traditional":"青出於藍","pinyinOverride":null},{"id":"yin-shui-si-yuan","simplified":"饮水思源","literalMeaning":"drink water think of source","figurativeMeaning":"to remember one's roots or origins; to be grateful for one's blessings","englishEquivalents":["Remember where you came from","Count your blessings"],"shortGloss":"remember one's roots","characters":[{"char":"饮","meaning":"drink"},{"char":"水","meaning":"water"},{"char":"思","meaning":"think of"},{"char":"源","meaning":"source"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '饮水思源' encourages people to remember and appreciate their origins or the source of their benefits. It is often used to remind individuals to be grateful for the help and support they have received in their lives, just as one should think of the source of the water they drink.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"widely used in both formal and informal contexts","connotation":"positive","commonMistakes":"Learners might confuse this idiom with those that emphasize self-reliance or independence, but '饮水思源' specifically focuses on gratitude and remembering one's origins.","canStandAlone":false},"examples":[{"simplified":"我们要饮水思源，感谢那些帮助过我们的人。","english":"We should remember our roots and be grateful to those who have helped us.","traditional":"我們要飲水思源，感謝那些幫助過我們的人。"},{"simplified":"在成功的时候，不要忘记饮水思源。","english":"In times of success, don't forget to remember your roots.","traditional":"在成功的時候，不要忘記飲水思源。"}],"synonyms":["感恩图报"],"antonyms":[],"confusedWith":[],"traditional":"飲水思源","pinyinOverride":null},{"id":"qi-hu-nan-xia","simplified":"骑虎难下","literalMeaning":"riding a tiger, hard to get off","figurativeMeaning":"being in a difficult situation that is hard to escape from","englishEquivalents":["caught between a rock and a hard place","in a pickle"],"shortGloss":"stuck in a difficult situation","characters":[{"char":"骑","meaning":"ride"},{"char":"虎","meaning":"tiger"},{"char":"难","meaning":"difficult"},{"char":"下","meaning":"get off"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '骑虎难下' describes a situation where someone is in a precarious position, like riding a tiger. Once you are on the tiger, it is dangerous and difficult to dismount, as the tiger may attack. This metaphor is used to describe situations where one is stuck in a difficult position with no easy way out.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","complement"],"structure":"verb-object","register":"commonly used in both spoken and written Chinese","connotation":"negative","commonMistakes":"Learners might confuse this idiom with similar expressions that describe difficult situations, but '骑虎难下' specifically implies being unable to extricate oneself from a situation without facing consequences.","canStandAlone":false},"examples":[{"simplified":"他现在骑虎难下，只能硬着头皮继续下去。","english":"He is now in a difficult situation and can only grit his teeth and carry on.","traditional":"他現在騎虎難下，只能硬著頭皮繼續下去。"},{"simplified":"项目已经开始了，我们骑虎难下，只能尽力而为。","english":"The project has already started, and we are in a tough spot, so we can only do our best.","traditional":"項目已經開始了，我們騎虎難下，只能盡力而為。"}],"synonyms":["进退维谷"],"antonyms":[],"confusedWith":[{"id":"进退维谷","note":"While both idioms describe difficult situations, '进退维谷' emphasizes being trapped with no good options, whereas '骑虎难下' highlights the danger of trying to exit the situation."}],"traditional":"騎虎難下","pinyinOverride":null},{"id":"ji-mao-suan-pi","simplified":"鸡毛蒜皮","literalMeaning":"chicken feathers and garlic skins","figurativeMeaning":"trivial matters; insignificant things","englishEquivalents":["small potatoes","trivial matters","nitty-gritty"],"shortGloss":"trivial matters","characters":[{"char":"鸡","meaning":"chicken"},{"char":"毛","meaning":"feathers"},{"char":"蒜","meaning":"garlic"},{"char":"皮","meaning":"skins"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '鸡毛蒜皮' refers to things that are as trivial and insignificant as chicken feathers and garlic skins. These items are often considered useless and of little value, symbolizing matters that are not worth worrying about or paying attention to.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["object","attributive"],"structure":"coordinate","register":"colloquial, commonly used in everyday speech","connotation":"neutral","commonMistakes":"Learners might mistakenly use this idiom to describe something that is unimportant in a negative sense, but it is neutral and simply denotes triviality. It should not be used to describe something that is unimportant but also annoying or bothersome.","canStandAlone":false},"examples":[{"simplified":"我们不应该为这些鸡毛蒜皮的小事争吵。","english":"We shouldn't argue over such trivial matters.","traditional":"我們不應該為這些雞毛蒜皮的小事爭吵。"},{"simplified":"他总是关注那些鸡毛蒜皮的事情。","english":"He always pays attention to those trivial things.","traditional":"他總是關注那些雞毛蒜皮的事情。"}],"synonyms":["无关紧要","微不足道"],"antonyms":["举足轻重"],"confusedWith":[],"traditional":"雞毛蒜皮","pinyinOverride":null},{"id":"pi-ji-tai-lai","simplified":"否极泰来","literalMeaning":"extreme misfortune turns to fortune","figurativeMeaning":"when things reach their worst, they can only get better","englishEquivalents":["The darkest hour is just before the dawn","Every cloud has a silver lining"],"shortGloss":"things improve after reaching the worst","characters":[{"char":"否","meaning":"misfortune, adversity"},{"char":"极","meaning":"extreme, utmost"},{"char":"泰","meaning":"fortune, prosperity"},{"char":"来","meaning":"come, arrive"}],"origin":{"period":"Han Dynasty (202 BCE – 220 CE)","sourceText":"《周易·否卦》","sourceTextEnglish":"I Ching, Hexagram 12: Pi","originalExcerpt":"否极而泰来，天地否而不通。","storyEnglish":"The idiom originates from the I Ching, an ancient Chinese divination text. In the context of the hexagrams, 'Pi' represents obstruction and adversity, while 'Tai' represents smoothness and prosperity. The phrase suggests that when misfortune reaches its peak, it will naturally give way to good fortune, reflecting the cyclical nature of life and the balance between yin and yang.","historicalFigures":[],"relatedIdiomsFromSameSource":["物极必反"]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"cause-effect","register":"literary, but commonly used in both written and spoken Chinese","connotation":"positive","commonMistakes":"Learners often confuse this idiom with '物极必反', which also involves extremes but emphasizes the idea of reversal rather than improvement. '否极泰来' specifically conveys a positive outcome after adversity.","canStandAlone":false},"examples":[{"simplified":"在经历了漫长的低谷后，他相信否极泰来，未来会更好。","english":"After a prolonged period of downturn, he believes that things will improve and the future will be better.","traditional":"在經歷了漫長的低谷後，他相信否極泰來，未來會更好。"},{"simplified":"否极泰来，这次失败可能是成功的开始。","english":"When things reach their worst, they can only get better; this failure might be the beginning of success.","traditional":"否極泰來，這次失敗可能是成功的開始。"}],"synonyms":["柳暗花明"],"antonyms":["乐极生悲"],"confusedWith":[{"id":"物极必反","note":"While both idioms involve extremes, '物极必反' emphasizes reversal, not necessarily improvement."}],"traditional":"否極泰來","pinyinOverride":null},{"id":"si-mian-chu-ge","simplified":"四面楚歌","literalMeaning":"on all sides, Chu songs","figurativeMeaning":"to be surrounded by enemies or in a hopeless situation","englishEquivalents":["besieged on all sides","in dire straits"],"shortGloss":"surrounded by enemies","characters":[{"char":"四","meaning":"four; all around"},{"char":"面","meaning":"sides; directions"},{"char":"楚","meaning":"Chu; the state of Chu"},{"char":"歌","meaning":"songs"}],"origin":{"period":"Han Dynasty (202 BCE – 220 CE)","sourceText":"《史记·项羽本纪》","sourceTextEnglish":"Records of the Grand Historian, Biography of Xiang Yu","originalExcerpt":"项王军壁垓下，兵少食尽，汉军及诸侯兵围之数重。夜闻汉军四面皆楚歌，项王乃大惊曰：“汉皆已得楚乎？是何楚人之多也！”","storyEnglish":"The idiom originates from the story of Xiang Yu, a prominent warlord of the late Qin Dynasty. During the final battle at Gaixia, Xiang Yu's forces were surrounded by the Han army. To demoralize his troops, the Han army sang folk songs from Xiang Yu's homeland of Chu. Hearing the familiar songs, Xiang Yu's soldiers believed that their homeland had fallen, leading to despair and ultimately, Xiang Yu's defeat.","historicalFigures":["Xiang Yu"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"modifier-head","register":"literary, but widely understood and used in both formal and informal contexts","connotation":"negative","commonMistakes":"Learners might confuse this idiom with general expressions of being surrounded, but it specifically implies a sense of hopelessness and despair. It is not used for situations that are merely challenging.","canStandAlone":false},"examples":[{"simplified":"在公司破产后，他感到四面楚歌，不知道该如何是好。","english":"After the company went bankrupt, he felt besieged on all sides and didn't know what to do.","traditional":"在公司破產後，他感到四面楚歌，不知道該如何是好。"},{"simplified":"面对四面楚歌的局面，她依然保持冷静，寻找解决办法。","english":"Facing a situation where she was surrounded by enemies, she remained calm and looked for solutions.","traditional":"面對四面楚歌的局面，她依然保持冷靜，尋找解決辦法。"}],"synonyms":["腹背受敌"],"antonyms":["左右逢源"],"confusedWith":[{"id":"穷途末路","note":"While both idioms describe difficult situations, 四面楚歌 emphasizes being surrounded by enemies, whereas 穷途末路 focuses on being at the end of one's resources or options."}],"traditional":"四面楚歌","pinyinOverride":null},{"id":"gu-zhang-nan-ming","simplified":"孤掌难鸣","literalMeaning":"a lone palm cannot clap","figurativeMeaning":"it's difficult to achieve anything without support or cooperation","englishEquivalents":["It takes two to tango","No man is an island"],"shortGloss":"one can't succeed alone","characters":[{"char":"孤","meaning":"lone"},{"char":"掌","meaning":"palm (of the hand)"},{"char":"难","meaning":"difficult"},{"char":"鸣","meaning":"to sound"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '孤掌难鸣' suggests that just as a single hand cannot produce a clapping sound, an individual cannot accomplish much without the help or cooperation of others. It emphasizes the importance of collaboration and support in achieving goals.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"subject-predicate","register":"commonly used in both formal and informal contexts","connotation":"neutral","commonMistakes":"Learners may confuse this idiom with expressions that emphasize individual effort. It's important to remember that this idiom highlights the need for cooperation.","canStandAlone":false},"examples":[{"simplified":"在这个项目中，孤掌难鸣，我们需要团队合作。","english":"In this project, it's difficult to succeed alone; we need teamwork.","traditional":"在這個項目中，孤掌難鳴，我們需要團隊合作。"},{"simplified":"他意识到孤掌难鸣，于是开始寻求帮助。","english":"He realized that he couldn't succeed alone, so he started seeking help.","traditional":"他意識到孤掌難鳴，於是開始尋求幫助。"}],"synonyms":["众人拾柴火焰高"],"antonyms":["单枪匹马"],"confusedWith":[{"id":"单枪匹马","note":"单枪匹马 emphasizes individual effort, while 孤掌难鸣 stresses the need for cooperation."}],"traditional":"孤掌難鳴","pinyinOverride":null},{"id":"tian-yi-wu-feng","simplified":"天衣无缝","literalMeaning":"heavenly clothes without seams","figurativeMeaning":"flawless; perfect and without any defects","englishEquivalents":["seamless","flawless"],"shortGloss":"flawless; seamless","characters":[{"char":"天","meaning":"heavenly; divine"},{"char":"衣","meaning":"clothes"},{"char":"无","meaning":"without"},{"char":"缝","meaning":"seams"}],"origin":{"period":"Tang Dynasty (618–907 CE)","sourceText":"《无名氏·天仙配》","sourceTextEnglish":"Anonymous, 'The Heavenly Match'","originalExcerpt":"天衣本无缝，何须针线补。","storyEnglish":"The idiom originates from a story in which heavenly beings wore clothes that were perfect and seamless, symbolizing flawlessness and divine perfection. The phrase suggests that something is so perfect that it needs no improvement or alteration.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"subject-predicate","register":"literary, but commonly used in both written and spoken Chinese","connotation":"positive","commonMistakes":"Learners sometimes use this idiom to describe physical objects that are literally seamless, but it is more often used metaphorically to describe plans, performances, or works of art that are flawless.","canStandAlone":false},"examples":[{"simplified":"他的表演真是天衣无缝，让人无可挑剔。","english":"His performance was truly flawless, leaving no room for criticism.","traditional":"他的表演真是天衣無縫，讓人無可挑剔。"},{"simplified":"这次的计划天衣无缝，大家都很满意。","english":"This plan is seamless, and everyone is very satisfied.","traditional":"這次的計劃天衣無縫，大家都很滿意。"}],"synonyms":["完美无瑕","无懈可击"],"antonyms":["漏洞百出"],"confusedWith":[{"id":"无懈可击","note":"While both mean flawless, 无懈可击 often emphasizes being unassailable or invulnerable to criticism."}],"traditional":"天衣無縫","pinyinOverride":null},{"id":"xue-zhong-song-tan","simplified":"雪中送炭","literalMeaning":"deliver charcoal in snow","figurativeMeaning":"to provide timely help in someone’s hour of need","englishEquivalents":["a friend in need is a friend indeed","to offer help in a crisis"],"shortGloss":"timely help in need","characters":[{"char":"雪","meaning":"snow"},{"char":"中","meaning":"in"},{"char":"送","meaning":"deliver"},{"char":"炭","meaning":"charcoal"}],"origin":{"period":"Song Dynasty (960–1279)","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom originates from the idea of providing charcoal to someone during a snowy winter, which is a metaphor for giving someone what they desperately need when they are in a difficult situation. The story emphasizes the importance of helping others at the right moment, rather than offering assistance when it is no longer needed.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"commonly used in both written and spoken Chinese","connotation":"positive","commonMistakes":"Learners might confuse this idiom with others that suggest general help, but 雪中送炭 specifically emphasizes the timeliness and necessity of the help provided.","canStandAlone":false},"examples":[{"simplified":"在我最困难的时候，他雪中送炭，给了我很多帮助。","english":"When I was in my most difficult time, he provided timely help and gave me a lot of support.","traditional":"在我最困難的時候，他雪中送炭，給了我很多幫助。"},{"simplified":"她的捐款对我们来说真是雪中送炭。","english":"Her donation was truly a timely help for us.","traditional":"她的捐款對我們來說真是雪中送炭。"}],"synonyms":["济困扶危"],"antonyms":["落井下石"],"confusedWith":[{"id":"锦上添花","note":"锦上添花 means to add something superfluous or to embellish, which contrasts with the necessity implied in 雪中送炭."}],"traditional":"雪中送炭","pinyinOverride":null},{"id":"jiu-niu-yi-mao","simplified":"九牛一毛","literalMeaning":"nine cows, one hair","figurativeMeaning":"an insignificant part of a much larger whole; a drop in the ocean","englishEquivalents":["a drop in the bucket","a drop in the ocean"],"shortGloss":"a tiny part of a whole","characters":[{"char":"九","meaning":"nine"},{"char":"牛","meaning":"cows"},{"char":"一","meaning":"one"},{"char":"毛","meaning":"hair"}],"origin":{"period":"Han Dynasty (206 BCE – 220 CE)","sourceText":"《汉书·司马迁传》","sourceTextEnglish":"Book of Han, Biography of Sima Qian","originalExcerpt":"以一毛而累九牛，不为损矣。","storyEnglish":"The idiom originates from a passage in the 'Book of Han', where it is used to describe something so small and insignificant that it does not affect the larger whole. The metaphor compares a single hair taken from nine cows to emphasize the triviality of the loss.","historicalFigures":["Sima Qian"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["subject","object","adverbial"],"structure":"modifier-head","register":"literary, but widely understood and used in both formal and informal contexts","connotation":"neutral","commonMistakes":"Learners sometimes use this idiom to describe something small but still significant, which is incorrect. It should only be used when the small part is truly negligible.","canStandAlone":false},"examples":[{"simplified":"在他的财富中，这笔捐款只是九牛一毛。","english":"In his wealth, this donation is just a drop in the bucket.","traditional":"在他的財富中，這筆捐款只是九牛一毛。"},{"simplified":"对于整个项目的预算来说，这点开支简直是九牛一毛。","english":"For the entire project's budget, this expense is merely a drop in the ocean.","traditional":"對於整個項目的預算來說，這點開支簡直是九牛一毛。"}],"synonyms":["沧海一粟"],"antonyms":[],"confusedWith":[{"id":"沧海一粟","note":"Both idioms describe something insignificant, but '沧海一粟' uses the metaphor of a grain of millet in the ocean."}],"traditional":"九牛一毛","pinyinOverride":null},{"id":"jian-feng-shi-duo","simplified":"见风使舵","literalMeaning":"see the wind, steer the rudder","figurativeMeaning":"to act according to circumstances; to be opportunistic","englishEquivalents":["go with the flow","play it by ear"],"shortGloss":"act according to circumstances","characters":[{"char":"见","meaning":"see"},{"char":"风","meaning":"wind"},{"char":"使","meaning":"use"},{"char":"舵","meaning":"rudder"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '见风使舵' is believed to have originated from the idea of a sailor who adjusts the ship's rudder based on the direction of the wind. This metaphor is used to describe someone who changes their behavior or stance to suit the prevailing circumstances, often for personal advantage.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"commonly used in both spoken and written Chinese","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with '随波逐流', which also involves adapting to circumstances but often implies a lack of principles. '见风使舵' is more about strategic adaptability.","canStandAlone":false},"examples":[{"simplified":"在商场上，他总是见风使舵，灵活应对各种变化。","english":"In the business world, he always acts according to circumstances, flexibly responding to various changes.","traditional":"在商場上，他總是見風使舵，靈活應對各種變化。"},{"simplified":"面对复杂的局势，我们需要见风使舵，及时调整策略。","english":"Faced with a complex situation, we need to act according to circumstances and adjust our strategy in time.","traditional":"面對複雜的局勢，我們需要見風使舵，及時調整策略。"}],"synonyms":["随机应变"],"antonyms":["一成不变"],"confusedWith":[{"id":"随波逐流","note":"随波逐流 implies going along with the crowd without any principles, whereas 见风使舵 suggests strategic adaptability."}],"traditional":"見風使舵","pinyinOverride":null},{"id":"ma-dao-cheng-gong","simplified":"马到成功","literalMeaning":"horse arrives, success","figurativeMeaning":"to achieve instant success","englishEquivalents":["win at the starting line","hit the ground running"],"shortGloss":"achieve instant success","characters":[{"char":"马","meaning":"horse"},{"char":"到","meaning":"arrive"},{"char":"成","meaning":"accomplish"},{"char":"功","meaning":"success"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '马到成功' is believed to have originated from the idea of a general riding swiftly into battle and achieving victory as soon as he arrives. It conveys the hope or expectation that one will achieve success quickly and effortlessly, much like a horse that arrives at its destination with speed and power.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"verb-object","register":"commonly used in both formal and informal contexts, often in well-wishing","connotation":"positive","commonMistakes":"Learners might mistakenly use this idiom to describe gradual success, but it specifically implies quick and immediate success. It is often confused with idioms that suggest effort over time.","canStandAlone":false},"examples":[{"simplified":"祝你考试马到成功！","english":"I wish you instant success in your exam!","traditional":"祝你考試馬到成功！"},{"simplified":"他的新项目马到成功，真是令人羡慕。","english":"His new project achieved instant success, which is truly enviable.","traditional":"他的新項目馬到成功，真是令人羨慕。"}],"synonyms":["旗开得胜"],"antonyms":["事倍功半"],"confusedWith":[{"id":"事半功倍","note":"While '事半功倍' implies achieving more with less effort, '马到成功' emphasizes immediate success upon starting."}],"traditional":"馬到成功","pinyinOverride":null},{"id":"jin-shang-tian-hua","simplified":"锦上添花","literalMeaning":"add flowers to brocade","figurativeMeaning":"to make something beautiful even more beautiful; to improve on something that is already good","englishEquivalents":["icing on the cake","cherry on top"],"shortGloss":"enhance something already good","characters":[{"char":"锦","meaning":"brocade, a rich fabric"},{"char":"上","meaning":"on, upon"},{"char":"添","meaning":"add"},{"char":"花","meaning":"flowers"}],"origin":{"period":"Southern and Northern Dynasties (420–589 CE)","sourceText":"《南史·谢安传》","sourceTextEnglish":"History of the Southern Dynasties, Biography of Xie An","originalExcerpt":"谢安曰：'此犹锦上添花耳。'","storyEnglish":"The idiom originates from a story about Xie An, a prominent statesman during the Eastern Jin dynasty. When someone praised the beauty of a piece of brocade, Xie An remarked that adding flowers to it would make it even more beautiful. This comment highlighted the idea of enhancing something already splendid.","historicalFigures":["Xie An"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"literary, but very widely understood and used in ordinary speech","connotation":"positive","commonMistakes":"Learners sometimes use this idiom to describe necessary improvements, but it specifically refers to enhancements that are not essential but add beauty or value.","canStandAlone":false},"examples":[{"simplified":"她的演讲已经很精彩了，最后的故事更是锦上添花。","english":"Her speech was already excellent, and the final story was the icing on the cake.","traditional":"她的演講已經很精彩了，最後的故事更是錦上添花。"},{"simplified":"这幅画本来就很美，画家又在上面加了几笔，真是锦上添花。","english":"The painting was already beautiful, and the artist added a few more strokes, truly enhancing it.","traditional":"這幅畫本來就很美，畫家又在上面加了幾筆，真是錦上添花。"}],"synonyms":["如虎添翼"],"antonyms":["雪上加霜"],"confusedWith":[{"id":"雪中送炭","note":"雪中送炭 refers to providing help in times of need, whereas 锦上添花 is about adding beauty to something already good."}],"traditional":"錦上添花","pinyinOverride":null},{"id":"shun-shou-qian-yang","simplified":"顺手牵羊","literalMeaning":"conveniently lead away a sheep","figurativeMeaning":"to take advantage of an opportunity to steal or gain something small and easy","englishEquivalents":["make off with something","opportunistic theft"],"shortGloss":"opportunistic theft","characters":[{"char":"顺","meaning":"conveniently"},{"char":"手","meaning":"hand"},{"char":"牵","meaning":"lead away"},{"char":"羊","meaning":"sheep"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '顺手牵羊' originates from a folk story about a person who, while passing by a flock of sheep, conveniently leads one away without being noticed. This act of taking advantage of an opportunity to gain something small and easy became synonymous with opportunistic theft or taking advantage of a situation for personal gain.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"colloquial, commonly used in both spoken and written Chinese","connotation":"negative","commonMistakes":"Learners might confuse this idiom with similar expressions that imply taking advantage of opportunities, but this idiom specifically implies a negative, opportunistic theft. It's not used for positive or neutral opportunities.","canStandAlone":false},"examples":[{"simplified":"他在商店里顺手牵羊，拿走了一本书。","english":"He made off with a book from the store.","traditional":"他在商店裡順手牽羊，拿走了一本書。"},{"simplified":"在混乱中，有人顺手牵羊，偷走了钱包。","english":"In the chaos, someone took advantage of the situation to steal a wallet.","traditional":"在混亂中，有人順手牽羊，偷走了錢包。"}],"synonyms":[],"antonyms":[],"confusedWith":[{"id":"趁火打劫","note":"趁火打劫 implies taking advantage of a disaster to loot, which is more severe than 顺手牵羊."}],"traditional":"順手牽羊","pinyinOverride":null},{"id":"sha-ji-jing-hou","simplified":"杀鸡儆猴","literalMeaning":"kill the chicken to warn the monkey","figurativeMeaning":"to punish someone as a warning to others","englishEquivalents":["make an example of someone","set an example","send a message"],"shortGloss":"punish one to warn others","characters":[{"char":"杀","meaning":"kill"},{"char":"鸡","meaning":"chicken"},{"char":"儆","meaning":"warn"},{"char":"猴","meaning":"monkey"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '杀鸡儆猴' is based on a story where a person kills a chicken to scare the monkeys into obedience. The idea is that by punishing one individual, others will learn from the example and behave accordingly. It is often used to describe a situation where a minor punishment is used to deter more serious misbehavior.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["object","adverbial"],"structure":"verb-object","register":"commonly used in both formal and informal contexts","connotation":"neutral","commonMistakes":"Learners often confuse this idiom with those that imply direct punishment rather than using punishment as a deterrent. It's important to remember that the focus is on warning others.","canStandAlone":false},"examples":[{"simplified":"老板开除了一个员工，以杀鸡儆猴。","english":"The boss fired an employee to make an example of him.","traditional":"老闆開除了一個員工，以殺雞儆猴。"},{"simplified":"政府对小偷进行了严厉的处罚，意在杀鸡儆猴。","english":"The government imposed severe penalties on the thief to send a message.","traditional":"政府對小偷進行了嚴厲的處罰，意在殺雞儆猴。"}],"synonyms":["杀一儆百"],"antonyms":[],"confusedWith":[{"id":"杀一儆百","note":"Both idioms involve punishing one to warn others, but '杀一儆百' emphasizes the broader impact on a larger group."}],"traditional":"殺雞儆猴","pinyinOverride":null},{"id":"hai-qun-zhi-ma","simplified":"害群之马","literalMeaning":"a horse that harms the herd","figurativeMeaning":"a person who brings trouble to their group; a black sheep","englishEquivalents":["black sheep","rotten apple"],"shortGloss":"troublemaker in a group","characters":[{"char":"害","meaning":"to harm"},{"char":"群","meaning":"group, herd"},{"char":"之","meaning":"of (classical possessive particle)"},{"char":"马","meaning":"horse"}],"origin":{"period":"Han Dynasty (206 BCE – 220 CE)","sourceText":"《韩诗外传》","sourceTextEnglish":"Han Shi Wai Zhuan (Outer Commentary on the Book of Songs)","originalExcerpt":"一马之驹，害群之马也。","storyEnglish":"The idiom originates from a story in the Han Dynasty text 'Han Shi Wai Zhuan'. It describes a situation where one horse in a herd behaves badly, causing trouble for the entire group. This metaphor was used to illustrate how one person's negative behavior can affect the whole group.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["subject","predicate","object","attributive"],"structure":"modifier-head","register":"widely used in both formal and informal contexts","connotation":"negative","commonMistakes":"Learners may confuse this idiom with similar expressions that describe individual misbehavior, but this idiom specifically emphasizes the impact on the group. It should not be used to describe someone who is simply different or unique.","canStandAlone":false},"examples":[{"simplified":"他在公司里总是制造麻烦，真是个害群之马。","english":"He is always causing trouble in the company; he's truly a black sheep.","traditional":"他在公司裡總是製造麻煩，真是個害群之馬。"},{"simplified":"我们不能让一个害群之马影响整个团队的士气。","english":"We cannot let one troublemaker affect the morale of the entire team.","traditional":"我們不能讓一個害群之馬影響整個團隊的士氣。"}],"synonyms":["害群之羊"],"antonyms":[],"confusedWith":[{"id":"害群之羊","note":"Both idioms describe someone who negatively impacts a group, but '害群之羊' uses 'sheep' instead of 'horse'."}],"traditional":"害群之馬","pinyinOverride":null},{"id":"dui-niu-tan-qin","simplified":"对牛弹琴","literalMeaning":"to play the lute to a cow","figurativeMeaning":"to offer something valuable or meaningful to someone who cannot appreciate it; to speak to the wrong audience","englishEquivalents":["cast pearls before swine"],"shortGloss":"talk to the wrong audience","characters":[{"char":"对","meaning":"to, towards"},{"char":"牛","meaning":"cow"},{"char":"弹","meaning":"to play (a string instrument)"},{"char":"琴","meaning":"lute, zither"}],"origin":{"period":"Eastern Han dynasty (25–220 CE)","sourceText":"《风俗通义》","sourceTextEnglish":"Fengsu Tongyi","originalExcerpt":"对牛弹琴，牛不闻，乃至于耳。","storyEnglish":"The idiom originates from a story in the 'Fengsu Tongyi' where a man plays beautiful music on a lute to a cow. The cow, unable to appreciate the music, continues to graze without any reaction. The story illustrates the futility of offering something valuable to someone who cannot understand or appreciate it.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"commonly used in both spoken and written Chinese","connotation":"negative","commonMistakes":"Learners might mistakenly use this idiom to describe any situation where communication fails, but it specifically refers to situations where the audience is incapable of understanding or appreciating the message.","canStandAlone":false},"examples":[{"simplified":"跟他谈艺术简直是对牛弹琴。","english":"Talking to him about art is like playing the lute to a cow.","traditional":"跟他談藝術簡直是對牛彈琴。"},{"simplified":"在这种场合讲深奥的理论无异于对牛弹琴。","english":"Discussing profound theories in this setting is akin to playing the lute to a cow.","traditional":"在這種場合講深奧的理論無異於對牛彈琴。"}],"synonyms":["对牛鼓簧"],"antonyms":[],"confusedWith":[{"id":"对牛鼓簧","note":"Both idioms describe futile communication, but '对牛鼓簧' specifically refers to playing a reed pipe to a cow."}],"traditional":"對牛彈琴","pinyinOverride":null},{"id":"yi-luan-ji-shi","simplified":"以卵击石","literalMeaning":"use an egg to strike a rock","figurativeMeaning":"to attempt something doomed to fail; to fight against overwhelming odds","englishEquivalents":["a fool's errand","like a lamb to the slaughter"],"shortGloss":"attempt the impossible","characters":[{"char":"以","meaning":"use"},{"char":"卵","meaning":"egg"},{"char":"击","meaning":"strike"},{"char":"石","meaning":"rock"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '以卵击石' describes a situation where someone attempts to do something that is clearly impossible or destined to fail, akin to trying to break a rock with an egg. The imagery highlights the futility and hopelessness of the endeavor.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"widely used in both spoken and written Chinese","connotation":"negative","commonMistakes":"Learners often confuse this idiom with others involving '卵' (egg) or '石' (rock) but should note it specifically implies an impossible or futile effort. It should not be used for situations that are merely difficult but achievable.","canStandAlone":false},"examples":[{"simplified":"他想凭一己之力打败整个公司，简直是以卵击石。","english":"He thinks he can defeat the entire company by himself, which is like trying to break a rock with an egg.","traditional":"他想憑一己之力打敗整個公司，簡直是以卵擊石。"},{"simplified":"与经验丰富的对手竞争，他的努力无异于以卵击石。","english":"Competing against an experienced opponent, his efforts are akin to striking a rock with an egg.","traditional":"與經驗豐富的對手競爭，他的努力無異於以卵擊石。"}],"synonyms":["螳臂当车"],"antonyms":[],"confusedWith":[{"id":"鸡蛋碰石头","note":"Both idioms involve eggs and rocks, but '鸡蛋碰石头' is more colloquial and less formal."}],"traditional":"以卵擊石","pinyinOverride":null},{"id":"bei-shui-che-xin","simplified":"杯水车薪","literalMeaning":"a cup of water for a cartload of firewood","figurativeMeaning":"an inadequate measure; a drop in the bucket","englishEquivalents":["a drop in the ocean","too little, too late"],"shortGloss":"an inadequate measure","characters":[{"char":"杯","meaning":"cup"},{"char":"水","meaning":"water"},{"char":"车","meaning":"cart"},{"char":"薪","meaning":"firewood"}],"origin":{"period":"Northern and Southern Dynasties (420–589)","sourceText":"《南齐书·周颙传》","sourceTextEnglish":"Book of Southern Qi, Biography of Zhou Yong","originalExcerpt":"杯水救薪，止增其焰耳。","storyEnglish":"The idiom originates from a story about Zhou Yong, an official during the Southern Qi dynasty. When asked about dealing with a large problem, he compared it to trying to extinguish a cartload of burning firewood with just a cup of water, implying that the effort was far too small to make any difference.","historicalFigures":["Zhou Yong"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"literary, but commonly used in both written and spoken Chinese","connotation":"negative","commonMistakes":"Learners might confuse this idiom with others that involve water or fire, but this idiom specifically emphasizes the inadequacy of the effort compared to the problem size.","canStandAlone":false},"examples":[{"simplified":"在这么大的危机面前，这点帮助无异于杯水车薪。","english":"In the face of such a huge crisis, this little help is like a drop in the bucket.","traditional":"在這麼大的危機面前，這點幫助無異於杯水車薪。"},{"simplified":"他的努力虽然值得赞赏，但对于解决问题来说只是杯水车薪。","english":"His efforts, though commendable, are just a drop in the ocean when it comes to solving the problem.","traditional":"他的努力雖然值得讚賞，但對於解決問題來說只是杯水車薪。"}],"synonyms":["无济于事","杯水救薪"],"antonyms":["事半功倍"],"confusedWith":[{"id":"杯弓蛇影","note":"Though both idioms involve '杯', '杯弓蛇影' refers to being overly suspicious, not inadequacy."}],"traditional":"杯水車薪","pinyinOverride":null},{"id":"chun-feng-de-yi","simplified":"春风得意","literalMeaning":"spring wind proud","figurativeMeaning":"to be elated and proud of one's success","englishEquivalents":["riding high","on top of the world"],"shortGloss":"elated with success","characters":[{"char":"春","meaning":"spring"},{"char":"风","meaning":"wind"},{"char":"得","meaning":"to obtain"},{"char":"意","meaning":"satisfaction"}],"origin":{"period":"Tang dynasty (618–907 CE)","sourceText":"《登科后》","sourceTextEnglish":"After Passing the Imperial Examinations","originalExcerpt":"春风得意马蹄疾，一日看尽长安花。","storyEnglish":"This idiom comes from a poem by Meng Jiao, a Tang dynasty poet. The poem describes the joy and pride of a scholar who has just passed the imperial examinations, likening his happiness to a horse galloping swiftly in the spring breeze, eager to see all the flowers in the capital, Chang'an. The phrase captures the feeling of elation and success after achieving a significant milestone.","historicalFigures":["Meng Jiao"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"modifier-head","register":"literary, but very widely understood and used in ordinary speech","connotation":"positive","commonMistakes":"Learners often confuse this idiom with others involving 'spring' or 'wind', but this one specifically conveys a sense of success and elation. It should not be used to describe general happiness unrelated to achievement.","canStandAlone":false},"examples":[{"simplified":"他最近升职了，整个人春风得意。","english":"He was recently promoted and is feeling on top of the world.","traditional":"他最近升職了，整個人春風得意。"},{"simplified":"经过多年的努力，她终于考上了理想的大学，春风得意。","english":"After years of hard work, she finally got into her dream university and was elated with success.","traditional":"經過多年的努力，她終於考上了理想的大學，春風得意。"}],"synonyms":["得意洋洋","心花怒放"],"antonyms":["垂头丧气"],"confusedWith":[{"id":"春暖花开","note":"春暖花开 refers to the pleasantness of springtime, not to personal success."}],"traditional":"春風得意","pinyinOverride":null},{"id":"hua-bing-chong-ji","simplified":"画饼充饥","literalMeaning":"draw a cake to satisfy hunger","figurativeMeaning":"to console oneself with unrealistic hopes or illusions","englishEquivalents":["feeding on illusions","building castles in the air"],"shortGloss":"consoling with illusions","characters":[{"char":"画","meaning":"to draw"},{"char":"饼","meaning":"cake"},{"char":"充","meaning":"to satisfy"},{"char":"饥","meaning":"hunger"}],"origin":{"period":"Three Kingdoms period (220–280 CE)","sourceText":"《三国志·魏书·邴原传》","sourceTextEnglish":"Records of the Three Kingdoms, Book of Wei, Biography of Bing Yuan","originalExcerpt":"原曰：“画饼不可充饥，临书无益于事。”","storyEnglish":"During the Three Kingdoms period, a scholar named Bing Yuan was known for his wisdom. When asked for advice on how to deal with hunger, he famously remarked that drawing a cake would not satisfy hunger, just as empty words or plans without action are useless. This story gave rise to the idiom, which warns against relying on unrealistic hopes or illusions to solve real problems.","historicalFigures":["Bing Yuan"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"literary, but understood in educated speech","connotation":"negative","commonMistakes":"Learners might confuse this idiom with similar expressions about unrealistic expectations, but it specifically emphasizes the futility of illusions in addressing real needs.","canStandAlone":false},"examples":[{"simplified":"他总是画饼充饥，幻想着不劳而获。","english":"He always feeds on illusions, dreaming of getting something for nothing.","traditional":"他總是畫餅充飢，幻想著不勞而獲。"},{"simplified":"如果不采取实际行动，这些计划不过是画饼充饥。","english":"If no real action is taken, these plans are just castles in the air.","traditional":"如果不採取實際行動，這些計劃不過是畫餅充飢。"}],"synonyms":["望梅止渴"],"antonyms":[],"confusedWith":[{"id":"望梅止渴","note":"Both involve illusions, but 望梅止渴 is about psychological comfort, while 画饼充饥 emphasizes futility."}],"traditional":"畫餅充飢","pinyinOverride":null},{"id":"zhi-shang-tan-bing","simplified":"纸上谈兵","literalMeaning":"discussing military tactics on paper","figurativeMeaning":"to have unrealistic ideas or to talk about something in a theoretical way without practical experience","englishEquivalents":["armchair strategist","all talk and no action"],"shortGloss":"theoretical talk without action","characters":[{"char":"纸","meaning":"paper"},{"char":"上","meaning":"on"},{"char":"谈","meaning":"discuss"},{"char":"兵","meaning":"military tactics"}],"origin":{"period":"Warring States period (475–221 BCE)","sourceText":"《史记·廉颇蔺相如列传》","sourceTextEnglish":"Records of the Grand Historian, Biographies of Lian Po and Lin Xiangru","originalExcerpt":"赵括自少时学兵法，言兵事，纸上谈兵耳。","storyEnglish":"The idiom originates from the story of Zhao Kuo, a general of the State of Zhao during the Warring States period. Although Zhao Kuo was well-versed in military theory, he lacked practical experience. His strategies, which were sound in theory, failed in practice during the Battle of Changping, leading to a disastrous defeat for Zhao. This story illustrates the danger of relying solely on theoretical knowledge without practical application.","historicalFigures":["Zhao Kuo"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["attributive","adverbial","complement"],"structure":"modifier-head","register":"commonly used in both written and spoken Chinese","connotation":"negative","commonMistakes":"Learners often use this idiom to describe any kind of discussion, but it specifically implies a lack of practical experience or effectiveness. It is not just about talking, but about the impracticality of the talk.","canStandAlone":false},"examples":[{"simplified":"他总是纸上谈兵，缺乏实际操作经验。","english":"He is always an armchair strategist, lacking practical experience.","traditional":"他總是紙上談兵，缺乏實際操作經驗。"},{"simplified":"在这个项目中，我们不能纸上谈兵，需要实际行动。","english":"In this project, we can't just talk theoretically; we need real action.","traditional":"在這個項目中，我們不能紙上談兵，需要實際行動。"}],"synonyms":["空谈误国"],"antonyms":["实事求是"],"confusedWith":[{"id":"纸上谈论","note":"This phrase means to discuss on paper, but lacks the negative connotation of impracticality."}],"traditional":"紙上談兵","pinyinOverride":null},{"id":"lang-bei-wei-jian","simplified":"狼狈为奸","literalMeaning":"wolf and jackal working together","figurativeMeaning":"to collude in wrongdoing; to conspire together for evil purposes","englishEquivalents":["partners in crime","thick as thieves"],"shortGloss":"collude in wrongdoing","characters":[{"char":"狼","meaning":"wolf"},{"char":"狈","meaning":"jackal; a mythical creature similar to a wolf"},{"char":"为","meaning":"to become; to act as"},{"char":"奸","meaning":"treacherous; wicked; evil"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '狼狈为奸' is believed to originate from the idea of wolves and jackals, both seen as cunning and deceitful animals, working together to commit misdeeds. The phrase suggests a partnership between two or more parties to engage in dishonest or immoral activities.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"commonly used in both spoken and written Chinese to describe conspiratorial behavior","connotation":"negative","commonMistakes":"Learners often confuse this idiom with others that involve animals but do not imply collusion, such as '狐假虎威' (using someone else's power for one's own benefit). '狼狈为奸' specifically implies a partnership in wrongdoing.","canStandAlone":false},"examples":[{"simplified":"他们狼狈为奸，合伙骗取了公司的钱。","english":"They colluded in wrongdoing and conspired to embezzle the company's money.","traditional":"他們狼狽為奸，合夥騙取了公司的錢。"},{"simplified":"这两家公司狼狈为奸，操纵市场价格。","english":"These two companies conspired together to manipulate market prices.","traditional":"這兩家公司狼狽為奸，操縱市場價格。"}],"synonyms":["沆瀣一气","同流合污"],"antonyms":["光明磊落"],"confusedWith":[{"id":"狐假虎威","note":"狐假虎威 involves using someone else's power for one's own benefit, not collusion."}],"traditional":"狼狽為奸","pinyinOverride":null},{"id":"da-cao-jing-she","simplified":"打草惊蛇","literalMeaning":"beat the grass to startle the snake","figurativeMeaning":"to inadvertently alert an enemy or to act in a way that causes someone to be on guard","englishEquivalents":["let the cat out of the bag","tip one's hand"],"shortGloss":"to inadvertently alert someone","characters":[{"char":"打","meaning":"to hit or strike"},{"char":"草","meaning":"grass"},{"char":"惊","meaning":"to startle or frighten"},{"char":"蛇","meaning":"snake"}],"origin":{"period":"Tang Dynasty (618–907 CE)","sourceText":"《唐国史补》","sourceTextEnglish":"Supplement to the History of the Tang","originalExcerpt":"打草惊蛇，蛇不出，乃以火攻之。","storyEnglish":"The idiom comes from a story in the Tang Dynasty. A man wanted to catch a snake hiding in the grass. He hit the grass to scare the snake out, but the snake was alerted and escaped. The story illustrates the idea of taking an action that inadvertently warns the intended target.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"widely used in both spoken and written Chinese","connotation":"negative","commonMistakes":"Learners often confuse this idiom with similar expressions that imply intentional alerting, whereas this idiom specifically refers to unintentional actions that cause someone to become alert.","canStandAlone":false},"examples":[{"simplified":"我们要小心，不要打草惊蛇。","english":"We need to be careful not to alert them inadvertently.","traditional":"我們要小心，不要打草驚蛇。"},{"simplified":"他的行为无意中打草惊蛇，让对手提高了警惕。","english":"His actions inadvertently alerted the opponent, making them more vigilant.","traditional":"他的行為無意中打草驚蛇，讓對手提高了警惕。"}],"synonyms":[],"antonyms":[],"confusedWith":[{"id":"打草蛇惊","note":"This is a common misordering of the characters, but it does not form a valid idiom."}],"traditional":"打草驚蛇","pinyinOverride":null},{"id":"gou-ji-tiao-qiang","simplified":"狗急跳墙","literalMeaning":"dog, desperate, jump, wall","figurativeMeaning":"when driven to desperation, one will take desperate measures","englishEquivalents":["Desperate times call for desperate measures","A cornered animal will bite back"],"shortGloss":"desperation leads to drastic actions","characters":[{"char":"狗","meaning":"dog"},{"char":"急","meaning":"desperate"},{"char":"跳","meaning":"jump"},{"char":"墙","meaning":"wall"}],"origin":{"period":"Ming Dynasty (1368–1644)","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '狗急跳墙' comes from the observation that even a timid dog, when cornered and desperate, will attempt to jump over a wall to escape. This illustrates how desperation can drive someone to take bold or risky actions they would not normally consider.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"subject-predicate","register":"commonly used in both spoken and written Chinese","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with '狗仗人势' (a dog relies on its master's power), which has a negative connotation of bullying. '狗急跳墙' is about desperation leading to unexpected actions, not about relying on others.","canStandAlone":false},"examples":[{"simplified":"他平时很胆小，但这次狗急跳墙，竟然和对方打了起来。","english":"He is usually very timid, but this time, driven to desperation, he actually started a fight with the other person.","traditional":"他平時很膽小，但這次狗急跳牆，竟然和對方打了起來。"},{"simplified":"在经济危机中，公司为了生存，不得不狗急跳墙，采取了一些激进的措施。","english":"During the economic crisis, the company had to take desperate measures to survive.","traditional":"在經濟危機中，公司為了生存，不得不狗急跳牆，採取了一些激進的措施。"}],"synonyms":["铤而走险"],"antonyms":[],"confusedWith":[{"id":"狗仗人势","note":"狗仗人势 refers to relying on someone else's power to bully others, while 狗急跳墙 is about taking desperate actions when cornered."}],"traditional":"狗急跳牆","pinyinOverride":null},{"id":"chi-li-pa-wai","simplified":"吃里扒外","literalMeaning":"eat inside, pull outside","figurativeMeaning":"to bite the hand that feeds you; to betray one's own side","englishEquivalents":["bite the hand that feeds you","turncoat","betray one's benefactor"],"shortGloss":"betray one's benefactor","characters":[{"char":"吃","meaning":"eat"},{"char":"里","meaning":"inside"},{"char":"扒","meaning":"pull"},{"char":"外","meaning":"outside"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '吃里扒外' describes someone who benefits from a group or individual but acts against their interests. It is akin to the English expression 'to bite the hand that feeds you.' The imagery is of someone who 'eats' or benefits from the inside, yet 'pulls' or acts in favor of the outside, indicating betrayal or disloyalty.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"coordinate","register":"commonly used in both spoken and written Chinese, often in informal contexts","connotation":"negative","commonMistakes":"Learners might confuse this idiom with expressions that simply mean 'ungrateful' without the element of betrayal. It's important to note that '吃里扒外' specifically involves acting against one's own side.","canStandAlone":false},"examples":[{"simplified":"他真是吃里扒外，拿了公司的钱却帮助竞争对手。","english":"He really bites the hand that feeds him, taking the company's money while helping the competitors.","traditional":"他真是吃裡扒外，拿了公司的錢卻幫助競爭對手。"},{"simplified":"这种吃里扒外的人，最终会失去所有人的信任。","english":"People who betray their benefactors like this will eventually lose everyone's trust.","traditional":"這種吃裡扒外的人，最終會失去所有人的信任。"}],"synonyms":["背信弃义"],"antonyms":["忠心耿耿"],"confusedWith":[{"id":"忘恩负义","note":"While both idioms involve ingratitude, '忘恩负义' focuses on being ungrateful without necessarily betraying one's own side."}],"traditional":"吃裡扒外","pinyinOverride":null},{"id":"fu-yao-zhi-shang","simplified":"扶摇直上","literalMeaning":"rise straight up on a whirlwind","figurativeMeaning":"to rise rapidly in position or status","englishEquivalents":["shoot up","skyrocket","rise through the ranks"],"shortGloss":"rise rapidly in status","characters":[{"char":"扶","meaning":"support; help"},{"char":"摇","meaning":"whirlwind"},{"char":"直","meaning":"straight"},{"char":"上","meaning":"up"}],"origin":{"period":"Warring States period (475–221 BCE)","sourceText":"《庄子·逍遥游》","sourceTextEnglish":"Zhuangzi, Chapter: Free and Easy Wandering","originalExcerpt":"乘扶摇而上者九万里。","storyEnglish":"In the text 'Zhuangzi', there is a story about a mythical bird called the Peng, which rises ninety thousand li into the sky, riding on a whirlwind. This image of the Peng rising effortlessly and rapidly became a metaphor for someone who advances quickly and successfully in their career or status.","historicalFigures":["Zhuangzi"],"relatedIdiomsFromSameSource":["逍遥游"]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"literary, but very widely understood and used in ordinary speech","connotation":"positive","commonMistakes":"Learners might confuse this idiom with others that imply gradual progress. '扶摇直上' specifically connotes a rapid and impressive rise, not a slow or steady one.","canStandAlone":false},"examples":[{"simplified":"他的事业扶摇直上，短短几年就成为了公司总裁。","english":"His career skyrocketed, and within just a few years, he became the company's president.","traditional":"他的事業扶搖直上，短短幾年就成為了公司總裁。"},{"simplified":"在这个行业中，她的名声扶摇直上，几乎无人不知。","english":"In this industry, her reputation has soared, and almost everyone knows her.","traditional":"在這個行業中，她的名聲扶搖直上，幾乎無人不知。"}],"synonyms":["平步青云"],"antonyms":["江河日下"],"confusedWith":[{"id":"步步高升","note":"步步高升 implies a gradual rise, whereas 扶摇直上 suggests a rapid ascent."}],"traditional":"扶搖直上","pinyinOverride":null},{"id":"xu-zhang-sheng-shi","simplified":"虚张声势","literalMeaning":"falsely display one's power","figurativeMeaning":"to bluff; to make a show of strength when one is actually weak","englishEquivalents":["bluff","put on a brave front","all bark and no bite"],"shortGloss":"to bluff or feign strength","characters":[{"char":"虚","meaning":"false; empty"},{"char":"张","meaning":"to display; to spread"},{"char":"声","meaning":"sound; voice"},{"char":"势","meaning":"power; momentum"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '虚张声势' describes the act of pretending to have power or strength that one does not actually possess. It is often used to describe someone who tries to intimidate others by making a lot of noise or showing off, but who lacks real substance or capability.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"commonly used in both spoken and written Chinese","connotation":"negative","commonMistakes":"Learners often confuse this idiom with '声势浩大', which means having a grand or impressive momentum. '虚张声势' implies a lack of real power, while '声势浩大' suggests genuine strength.","canStandAlone":false},"examples":[{"simplified":"他只是虚张声势，其实并没有什么实力。","english":"He is just bluffing; he doesn't actually have any real strength.","traditional":"他只是虛張聲勢，其實並沒有什麼實力。"},{"simplified":"不要被他的虚张声势吓倒，他根本没有能力做到。","english":"Don't be intimidated by his bluffing; he doesn't have the ability to do it.","traditional":"不要被他的虛張聲勢嚇倒，他根本沒有能力做到。"}],"synonyms":["虚有其表","色厉内荏"],"antonyms":["声势浩大"],"confusedWith":[{"id":"声势浩大","note":"声势浩大 implies genuine strength and momentum, unlike 虚张声势 which implies bluffing."}],"traditional":"虛張聲勢","pinyinOverride":null},{"id":"qian-jun-yi-fa","simplified":"千钧一发","literalMeaning":"a thousand jun hanging by a hair","figurativeMeaning":"a situation of extreme peril or danger, where disaster is imminent","englishEquivalents":["hanging by a thread","a close call"],"shortGloss":"a perilous situation","characters":[{"char":"千","meaning":"thousand"},{"char":"钧","meaning":"a unit of weight (about 30 kg)"},{"char":"一","meaning":"one"},{"char":"发","meaning":"hair"}],"origin":{"period":"Han Dynasty (206 BCE – 220 CE)","sourceText":"《汉书·枚乘传》","sourceTextEnglish":"Book of Han, Biography of Mei Cheng","originalExcerpt":"千钧之弩，发于一发之机。","storyEnglish":"The idiom originates from the 'Book of Han', where it describes the immense weight of a thousand jun (an ancient unit of weight) being suspended by a single hair, illustrating a situation of extreme danger or tension. This metaphor was used to emphasize the precariousness of certain situations.","historicalFigures":["Mei Cheng"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"modifier-head","register":"literary, but widely understood and used in both written and spoken Chinese","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with similar expressions that describe danger but lack the specific imagery of a heavy weight suspended by a hair. It's important to use it in contexts where the emphasis is on the precariousness and imminent danger.","canStandAlone":false},"examples":[{"simplified":"在那次事故中，他们的生命真是千钧一发。","english":"During that accident, their lives were truly hanging by a thread.","traditional":"在那次事故中，他們的生命真是千鈞一髮。"},{"simplified":"比赛最后一分钟，比分仍然是千钧一发。","english":"In the last minute of the game, the score was still hanging by a thread.","traditional":"比賽最後一分鐘，比分仍然是千鈞一髮。"}],"synonyms":["岌岌可危"],"antonyms":[],"confusedWith":[{"id":"危在旦夕","note":"While both idioms describe danger, 危在旦夕 emphasizes imminent danger without the imagery of hanging by a thread."}],"traditional":"千鈞一髮","pinyinOverride":null},{"id":"mang-ren-mo-xiang","simplified":"盲人摸象","literalMeaning":"blind people touch an elephant","figurativeMeaning":"to draw conclusions based on incomplete information","englishEquivalents":["the blind men and the elephant","missing the forest for the trees"],"shortGloss":"drawing conclusions from incomplete information","characters":[{"char":"盲","meaning":"blind"},{"char":"人","meaning":"people"},{"char":"摸","meaning":"touch"},{"char":"象","meaning":"elephant"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom originates from a story about several blind men who encounter an elephant for the first time. Each man touches a different part of the elephant and describes it based on the part he feels. One touches the trunk and says the elephant is like a snake, another touches the leg and says it is like a tree, and so on. Each man perceives only a part of the whole, leading to incomplete and misleading conclusions. The story illustrates how people can misunderstand or misinterpret a situation when they only have partial knowledge.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["subject","predicate","object"],"structure":"subject-predicate","register":"commonly used in both spoken and written Chinese","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with others that involve blindness or elephants, but it specifically refers to the idea of partial understanding leading to incorrect conclusions.","canStandAlone":false},"examples":[{"simplified":"在没有完整数据的情况下做决定就像盲人摸象。","english":"Making decisions without complete data is like the blind men touching the elephant.","traditional":"在沒有完整數據的情況下做決定就像盲人摸象。"},{"simplified":"他对这个问题的看法有点像盲人摸象，只看到了一部分。","english":"His view on this issue is a bit like the blind men touching the elephant; he only sees part of it.","traditional":"他對這個問題的看法有點像盲人摸象，只看到了一部分。"}],"synonyms":["管中窥豹"],"antonyms":[],"confusedWith":[],"traditional":"盲人摸象","pinyinOverride":null},{"id":"bai-fa-bai-zhong","simplified":"百发百中","literalMeaning":"hundred shots, hundred hits","figurativeMeaning":"to be extremely accurate or successful; to always hit the target","englishEquivalents":["hit the nail on the head","right on target"],"shortGloss":"always successful or accurate","characters":[{"char":"百","meaning":"hundred"},{"char":"发","meaning":"shots"},{"char":"百","meaning":"hundred"},{"char":"中","meaning":"hits the target"}],"origin":{"period":"Warring States period (475–221 BCE)","sourceText":"《战国策·西周策》","sourceTextEnglish":"Strategies of the Warring States, Strategies of Western Zhou","originalExcerpt":"百发而百中，百中而不敢为。","storyEnglish":"The idiom originates from the 'Strategies of the Warring States', where it describes an archer who was so skilled that he could hit the target with every shot. This was used to illustrate the idea of precision and reliability in achieving one's goals.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"coordinate","register":"widely used in both formal and informal contexts","connotation":"positive","commonMistakes":"Learners sometimes confuse this idiom with others that involve success or achievement but lack the emphasis on precision and consistency. It specifically implies repeated accuracy, not just occasional success.","canStandAlone":false},"examples":[{"simplified":"他的预测总是百发百中。","english":"His predictions are always right on target.","traditional":"他的預測總是百發百中。"},{"simplified":"这个射手在比赛中百发百中，令人惊叹。","english":"The archer was astonishing in the competition, hitting the target every time.","traditional":"這個射手在比賽中百發百中，令人驚歎。"}],"synonyms":["屡试不爽","无往不利"],"antonyms":["百无一中"],"confusedWith":[{"id":"屡试不爽","note":"Both imply success, but 屡试不爽 emphasizes repeated trials without failure, not necessarily precision."}],"traditional":"百發百中","pinyinOverride":null},{"id":"lao-ma-shi-tu","simplified":"老马识途","literalMeaning":"old horse knows the way","figurativeMeaning":"an experienced person knows what to do; experience leads the way","englishEquivalents":["an old hand","experience is the best teacher"],"shortGloss":"experience knows the way","characters":[{"char":"老","meaning":"old"},{"char":"马","meaning":"horse"},{"char":"识","meaning":"knows"},{"char":"途","meaning":"way; path"}],"origin":{"period":"Warring States period (475–221 BCE)","sourceText":"《韩非子·说林上》","sourceTextEnglish":"Han Feizi, Sayings of the Forest, Part 1","originalExcerpt":"老马之智，识途也。","storyEnglish":"During the Warring States period, the state of Qi was at war with the state of Yan. The Qi army was lost in unfamiliar territory. An experienced general suggested that they release an old horse, as it would know the way home. Following the horse, the army successfully found their way back. This story illustrates the value of experience and knowledge gained over time.","historicalFigures":["Han Feizi"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["subject","predicate","attributive"],"structure":"subject-predicate","register":"literary, but widely used in both formal and informal contexts","connotation":"positive","commonMistakes":"Learners might confuse this idiom with others involving horses, such as 马到成功, which emphasizes quick success rather than experience. 老马识途 specifically highlights the value of experience and familiarity.","canStandAlone":false},"examples":[{"simplified":"在这个项目中，我们需要一个老马识途的人来指导我们。","english":"In this project, we need an experienced person to guide us.","traditional":"在這個項目中，我們需要一個老馬識途的人來指導我們。"},{"simplified":"他在这个行业工作了三十年，真是老马识途。","english":"He has worked in this industry for thirty years; he truly is an old hand.","traditional":"他在這個行業工作了三十年，真是老馬識途。"}],"synonyms":["经验丰富","久经沙场"],"antonyms":["初出茅庐"],"confusedWith":[{"id":"马到成功","note":"老马识途 emphasizes experience, while 马到成功 focuses on achieving success quickly."}],"traditional":"老馬識途","pinyinOverride":null},{"id":"lang-xin-gou-fei","simplified":"狼心狗肺","literalMeaning":"wolf heart, dog lungs","figurativeMeaning":"cruel and unscrupulous; heartless and treacherous","englishEquivalents":["heart of stone","cold-blooded"],"shortGloss":"cruel and unscrupulous","characters":[{"char":"狼","meaning":"wolf, symbolizing cruelty"},{"char":"心","meaning":"heart, representing one's nature or feelings"},{"char":"狗","meaning":"dog, symbolizing untrustworthiness"},{"char":"肺","meaning":"lungs, metaphorically used to describe one's character"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '狼心狗肺' is believed to have originated from folk expressions describing someone with a cruel and treacherous nature. The wolf is often associated with ferocity, while the dog in this context implies deceitfulness. Together, they paint a picture of someone who is heartless and unscrupulous.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["attributive","predicate"],"structure":"coordinate","register":"informal, commonly used in spoken Chinese","connotation":"negative","commonMistakes":"Learners might confuse this idiom with others that describe negative traits but with different nuances, such as '狼子野心' which implies ambition rather than cruelty. It's important to use '狼心狗肺' specifically when describing someone as heartless or treacherous.","canStandAlone":false},"examples":[{"simplified":"他真是狼心狗肺，竟然背叛了自己的朋友。","english":"He is truly heartless and treacherous, having betrayed his own friends.","traditional":"他真是狼心狗肺，竟然背叛了自己的朋友。"},{"simplified":"这样狼心狗肺的人，迟早会遭到报应。","english":"A person as cruel and unscrupulous as this will eventually face retribution.","traditional":"這樣狼心狗肺的人，遲早會遭到報應。"}],"synonyms":["狼子野心","蛇蝎心肠"],"antonyms":["仁心仁术"],"confusedWith":[{"id":"狼子野心","note":"While both involve negative traits, '狼子野心' refers to someone with ambitious and aggressive desires, not necessarily cruel or treacherous."}],"traditional":"狼心狗肺","pinyinOverride":null},{"id":"le-bu-si-shu","simplified":"乐不思蜀","literalMeaning":"happy not thinking of Shu","figurativeMeaning":"so happy and content in a new place or situation that one forgets their home or original situation","englishEquivalents":["Out of sight, out of mind","Happy as a clam"],"shortGloss":"so content one forgets home","characters":[{"char":"乐","meaning":"happy"},{"char":"不","meaning":"not"},{"char":"思","meaning":"think of"},{"char":"蜀","meaning":"Shu (an ancient Chinese state)"}],"origin":{"period":"Three Kingdoms period (220–280 CE)","sourceText":"《三国志·蜀书·后主传》","sourceTextEnglish":"Records of the Three Kingdoms, Book of Shu, Biography of the Later Lord","originalExcerpt":"及至洛，见乐，不复思蜀。","storyEnglish":"The idiom comes from the story of Liu Shan, the last emperor of the Shu Han during the Three Kingdoms period. After the fall of Shu, Liu Shan was taken to the Wei capital, Luoyang. There, he lived a comfortable life and was so content that he reportedly said he did not miss his former kingdom of Shu, leading to the expression '乐不思蜀'.","historicalFigures":["Liu Shan"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"subject-predicate","register":"literary, but understood and used in ordinary speech","connotation":"neutral","commonMistakes":"Learners sometimes mistake this idiom for a positive expression of loyalty or nostalgia, but it actually implies a lack of concern for one's origins due to current happiness.","canStandAlone":false},"examples":[{"simplified":"他在国外生活得很开心，几乎乐不思蜀。","english":"He is living so happily abroad that he almost forgets about home.","traditional":"他在國外生活得很開心，幾乎樂不思蜀。"},{"simplified":"自从搬到海边，她就乐不思蜀了。","english":"Since moving to the seaside, she has been so content that she doesn't think about her old home.","traditional":"自從搬到海邊，她就樂不思蜀了。"}],"synonyms":[],"antonyms":[],"confusedWith":[{"id":"叶公好龙","note":"While both involve a change in circumstances, '叶公好龙' implies a superficial love or interest, whereas '乐不思蜀' implies genuine contentment."}],"traditional":"樂不思蜀","pinyinOverride":null},{"id":"dong-shan-zai-qi","simplified":"东山再起","literalMeaning":"rise again from East Mountain","figurativeMeaning":"to make a comeback; to rise again after a setback","englishEquivalents":["make a comeback","rise from the ashes"],"shortGloss":"make a comeback","characters":[{"char":"东","meaning":"east"},{"char":"山","meaning":"mountain"},{"char":"再","meaning":"again"},{"char":"起","meaning":"rise"}],"origin":{"period":"Jin Dynasty (266–420)","sourceText":"《晋书·谢安传》","sourceTextEnglish":"Book of Jin, Biography of Xie An","originalExcerpt":"安东山再起，复为朝廷所用。","storyEnglish":"The idiom originates from the story of Xie An, a statesman of the Eastern Jin Dynasty. After retiring to East Mountain (Dongshan) due to political setbacks, he was later recalled to serve the court again. His successful return to politics and subsequent achievements gave rise to the expression '东山再起', symbolizing a comeback after a period of obscurity or inactivity.","historicalFigures":["Xie An"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial","complement"],"structure":"verb-object","register":"widely used in both written and spoken Chinese","connotation":"positive","commonMistakes":"Learners might confuse this idiom with '卷土重来', which also means making a comeback but often implies a more aggressive or forceful return. '东山再起' is more neutral and can imply a peaceful or strategic comeback.","canStandAlone":false},"examples":[{"simplified":"经过多年的努力，他终于东山再起，重回商界。","english":"After years of hard work, he finally made a comeback and returned to the business world.","traditional":"經過多年的努力，他終於東山再起，重回商界。"},{"simplified":"虽然公司破产了，但他相信自己有一天会东山再起。","english":"Although the company went bankrupt, he believes he will make a comeback one day.","traditional":"雖然公司破產了，但他相信自己有一天會東山再起。"}],"synonyms":["卷土重来"],"antonyms":[],"confusedWith":[{"id":"卷土重来","note":"Both idioms mean making a comeback, but '卷土重来' suggests a more forceful or aggressive return."}],"traditional":"東山再起","pinyinOverride":null},{"id":"mao-ku-lao-shu","simplified":"猫哭老鼠","literalMeaning":"cat cries for the mouse","figurativeMeaning":"to shed crocodile tears; to pretend to be sympathetic","englishEquivalents":["shed crocodile tears","hypocritical sympathy"],"shortGloss":"pretend sympathy","characters":[{"char":"猫","meaning":"cat"},{"char":"哭","meaning":"cry"},{"char":"老","meaning":"old"},{"char":"鼠","meaning":"mouse"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '猫哭老鼠' describes a situation where someone pretends to be sympathetic or mournful, much like a cat pretending to cry for a mouse it has caught. The imagery suggests insincerity, as a cat naturally preys on mice and would not genuinely mourn for one.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"subject-predicate","register":"informal, commonly used in both spoken and written Chinese","connotation":"negative","commonMistakes":"Learners may confuse this idiom with expressions of genuine sympathy. It's important to remember that it implies insincerity. It is also sometimes confused with '鳄鱼的眼泪' (crocodile tears), which has a similar meaning.","canStandAlone":false},"examples":[{"simplified":"他在葬礼上猫哭老鼠，实际上并不关心。","english":"He shed crocodile tears at the funeral, but in reality, he didn't care.","traditional":"他在葬禮上貓哭老鼠，實際上並不關心。"},{"simplified":"她对他的失败表示同情，但那不过是猫哭老鼠。","english":"She expressed sympathy for his failure, but it was just crocodile tears.","traditional":"她對他的失敗表示同情，但那不過是貓哭老鼠。"}],"synonyms":["鳄鱼的眼泪"],"antonyms":[],"confusedWith":[{"id":"鳄鱼的眼泪","note":"Both idioms describe insincere emotions, but '鳄鱼的眼泪' is more directly linked to the English 'crocodile tears'."}],"traditional":"貓哭老鼠","pinyinOverride":null},{"id":"jin-wu-zu-chi","simplified":"金无足赤","literalMeaning":"gold lacks pure red","figurativeMeaning":"nothing is perfect; everyone has flaws","englishEquivalents":["Nobody's perfect","Every rose has its thorn"],"shortGloss":"nothing is perfect","characters":[{"char":"金","meaning":"gold"},{"char":"无","meaning":"not have; lack"},{"char":"足","meaning":"sufficient; complete"},{"char":"赤","meaning":"red; pure"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '金无足赤' suggests that just as gold cannot be perfectly pure, people and things also have imperfections. This saying reminds us that it's natural for everything to have flaws and that perfection is an unrealistic expectation.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"subject-predicate","register":"commonly used in both formal and informal contexts","connotation":"neutral","commonMistakes":"Learners may mistakenly use this idiom to describe something that is entirely flawed, rather than acknowledging minor imperfections in something generally good.","canStandAlone":false},"examples":[{"simplified":"虽然他很优秀，但金无足赤，他也有一些小缺点。","english":"Although he is excellent, nobody's perfect, and he has some minor flaws.","traditional":"雖然他很優秀，但金無足赤，他也有一些小缺點。"},{"simplified":"金无足赤，我们应该接受自己的不完美。","english":"Nothing is perfect; we should accept our imperfections.","traditional":"金無足赤，我們應該接受自己的不完美。"}],"synonyms":["人无完人"],"antonyms":[],"confusedWith":[{"id":"完美无缺","note":"完美无缺 means 'perfect and without flaws', which is the opposite of 金无足赤."}],"traditional":"金無足赤","pinyinOverride":null},{"id":"ben-niao-xian-fei","simplified":"笨鸟先飞","literalMeaning":"clumsy bird flies first","figurativeMeaning":"someone who is less talented or capable works harder to succeed","englishEquivalents":["The early bird catches the worm","Slow and steady wins the race"],"shortGloss":"work harder if you're less talented","characters":[{"char":"笨","meaning":"clumsy or stupid"},{"char":"鸟","meaning":"bird"},{"char":"先","meaning":"first"},{"char":"飞","meaning":"fly"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '笨鸟先飞' is based on the idea that a clumsy or slow bird needs to start flying earlier than others to reach its destination on time. It is often used to describe people who, recognizing their own limitations, put in extra effort to achieve their goals. The phrase encourages diligence and perseverance, especially for those who may not have natural talent or advantages.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"subject-predicate","register":"commonly used in both spoken and written Chinese","connotation":"neutral","commonMistakes":"Learners might mistakenly use this idiom to imply a negative judgment about someone's intelligence, but it is more about emphasizing effort and perseverance. It's also important not to confuse it with idioms that simply mean 'early start' without the implication of extra effort due to limitations.","canStandAlone":false},"examples":[{"simplified":"他知道自己不是最聪明的学生，所以笨鸟先飞，每天都提前到教室学习。","english":"He knows he's not the smartest student, so he works harder and arrives early to study every day.","traditional":"他知道自己不是最聰明的學生，所以笨鳥先飛，每天都提前到教室學習。"},{"simplified":"虽然他起步晚，但他一直笨鸟先飞，最终取得了成功。","english":"Although he started late, he worked diligently and eventually succeeded.","traditional":"雖然他起步晚，但他一直笨鳥先飛，最終取得了成功。"}],"synonyms":[],"antonyms":[],"confusedWith":[{"id":"早起的鸟儿有虫吃","note":"This idiom focuses on the benefits of starting early, without the implication of overcoming a disadvantage."}],"traditional":"笨鳥先飛","pinyinOverride":null},{"id":"an-tu-suo-ji","simplified":"按图索骥","literalMeaning":"follow map search steed","figurativeMeaning":"to follow a plan or instructions rigidly without flexibility","englishEquivalents":["by the book","paint by numbers"],"shortGloss":"follow instructions rigidly","characters":[{"char":"按","meaning":"follow"},{"char":"图","meaning":"map"},{"char":"索","meaning":"search"},{"char":"骥","meaning":"steed"}],"origin":{"period":"Han Dynasty (202 BCE – 220 CE)","sourceText":"《汉书·梅福传》","sourceTextEnglish":"Book of Han, Biography of Mei Fu","originalExcerpt":"按图索骥，不亦难乎？","storyEnglish":"The idiom comes from a story in the Han Dynasty where a person was trying to find a legendary horse by following a map. The map described the horse's features in detail, but the searcher failed to find the horse because he relied too rigidly on the map without considering the actual circumstances. This story illustrates the folly of adhering too strictly to plans or instructions without adapting to the situation.","historicalFigures":["Mei Fu"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["adverbial","complement"],"structure":"verb-object","register":"literary, but used in both formal and informal contexts","connotation":"negative","commonMistakes":"Learners often confuse this idiom with similar expressions that imply careful planning, but 按图索骥 specifically criticizes inflexibility and lack of adaptation.","canStandAlone":false},"examples":[{"simplified":"在解决复杂问题时，按图索骥往往行不通。","english":"When solving complex problems, following instructions rigidly often doesn't work.","traditional":"在解決複雜問題時，按圖索驥往往行不通。"},{"simplified":"他总是按图索骥，缺乏创新精神。","english":"He always follows instructions rigidly, lacking an innovative spirit.","traditional":"他總是按圖索驥，缺乏創新精神。"}],"synonyms":["墨守成规"],"antonyms":["随机应变"],"confusedWith":[{"id":"墨守成规","note":"Both idioms imply inflexibility, but 墨守成规 emphasizes sticking to old ways, while 按图索骥 focuses on rigidly following instructions."}],"traditional":"按圖索驥","pinyinOverride":null},{"id":"qing-huang-bu-jie","simplified":"青黄不接","literalMeaning":"green and yellow do not meet","figurativeMeaning":"a temporary shortage or gap, especially in resources or finances","englishEquivalents":["a lean period","a gap in supply"],"shortGloss":"a temporary shortage or gap","characters":[{"char":"青","meaning":"green; young crops"},{"char":"黄","meaning":"yellow; ripe crops"},{"char":"不","meaning":"not"},{"char":"接","meaning":"meet; connect"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '青黄不接' describes a situation where there is a temporary shortage, often referring to the time between the depletion of old crops and the harvest of new ones. It metaphorically represents any period where resources are insufficient to meet needs, such as financial or material shortages.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"subject-predicate","register":"commonly used in both spoken and written Chinese to describe temporary shortages","connotation":"negative","commonMistakes":"Learners might confuse this idiom with others that describe permanent shortages or poverty. '青黄不接' specifically refers to a temporary gap, not a chronic state.","canStandAlone":false},"examples":[{"simplified":"公司最近资金周转困难，真是青黄不接。","english":"The company is currently facing cash flow problems; it's truly a lean period.","traditional":"公司最近資金週轉困難，真是青黃不接。"},{"simplified":"在农忙季节，粮食供应常常青黄不接。","english":"During the busy farming season, the food supply often experiences a temporary shortage.","traditional":"在農忙季節，糧食供應常常青黃不接。"}],"synonyms":["捉襟见肘"],"antonyms":[],"confusedWith":[{"id":"捉襟见肘","note":"While both describe shortages, '捉襟见肘' often implies a more chronic or visible lack, whereas '青黄不接' is about a temporary gap."}],"traditional":"青黃不接","pinyinOverride":null},{"id":"ji-quan-sheng-tian","simplified":"鸡犬升天","literalMeaning":"chickens and dogs ascend to heaven","figurativeMeaning":"when someone gains power or status, their close associates also benefit","englishEquivalents":["rising tide lifts all boats"],"shortGloss":"associates benefit from one's success","characters":[{"char":"鸡","meaning":"chickens"},{"char":"犬","meaning":"dogs"},{"char":"升","meaning":"ascend"},{"char":"天","meaning":"heaven"}],"origin":{"period":"Eastern Han Dynasty (25–220 CE)","sourceText":"《后汉书·方术传》","sourceTextEnglish":"Book of the Later Han, Biographies of Fangshu","originalExcerpt":"一人得道，鸡犬升天。","storyEnglish":"The idiom originates from the story of Fei Changfang, a Taoist practitioner during the Eastern Han Dynasty. It is said that when he achieved immortality, even his chickens and dogs ascended to heaven with him. This story illustrates how those close to someone who achieves great success or power can also benefit from their association.","historicalFigures":["Fei Changfang"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"subject-predicate","register":"literary, but understood and used in both formal and informal contexts","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with those that imply direct personal achievement rather than benefiting through association. It's important to remember it describes secondary beneficiaries.","canStandAlone":false},"examples":[{"simplified":"他当上了总经理，连他的朋友们也鸡犬升天。","english":"He became the general manager, and even his friends benefited from his success.","traditional":"他當上了總經理，連他的朋友們也雞犬升天。"},{"simplified":"随着公司的发展，许多员工也鸡犬升天。","english":"As the company grew, many employees also benefited.","traditional":"隨著公司的發展，許多員工也雞犬升天。"}],"synonyms":[],"antonyms":[],"confusedWith":[{"id":"飞黄腾达","note":"飞黄腾达 refers to achieving rapid success or promotion, focusing on the individual's achievement rather than the benefit to associates."}],"traditional":"雞犬升天","pinyinOverride":null},{"id":"fang-rui-yuan-zao","simplified":"方枘圆凿","literalMeaning":"square peg, round hole","figurativeMeaning":"a mismatch or incompatibility; something that doesn't fit","englishEquivalents":["square peg in a round hole"],"shortGloss":"a mismatch or incompatibility","characters":[{"char":"方","meaning":"square"},{"char":"枘","meaning":"peg"},{"char":"圆","meaning":"round"},{"char":"凿","meaning":"hole"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '方枘圆凿' describes a situation where something does not fit or match, much like trying to fit a square peg into a round hole. This metaphor is used to illustrate incompatibility or a poor fit between two things.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["attributive","predicate"],"structure":"coordinate","register":"widely used in both formal and informal contexts","connotation":"negative","commonMistakes":"Learners might confuse this idiom with others that suggest difficulty or challenge, but this idiom specifically refers to a mismatch or incompatibility, not just any difficult situation.","canStandAlone":false},"examples":[{"simplified":"这两家公司合并就像方枘圆凿，根本不合适。","english":"The merger of these two companies is like a square peg in a round hole; it's simply not suitable.","traditional":"這兩家公司合併就像方枘圓鑿，根本不合適。"},{"simplified":"他在这个职位上就像方枘圆凿，完全不合适。","english":"He is like a square peg in a round hole in this position, completely unsuitable.","traditional":"他在這個職位上就像方枘圓鑿，完全不合適。"}],"synonyms":[],"antonyms":[],"confusedWith":[],"traditional":"方枘圓鑿","pinyinOverride":null},{"id":"da-hai-lao-zhen","simplified":"大海捞针","literalMeaning":"fishing for a needle in the ocean","figurativeMeaning":"a futile or extremely difficult task","englishEquivalents":["like finding a needle in a haystack"],"shortGloss":"an impossible or very difficult task","characters":[{"char":"大","meaning":"big, vast"},{"char":"海","meaning":"sea, ocean"},{"char":"捞","meaning":"to fish out, to scoop up"},{"char":"针","meaning":"needle"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '大海捞针' is often used to describe a task that is nearly impossible to accomplish, akin to trying to find a single needle in the vastness of the ocean. It emphasizes the difficulty and futility of the endeavor, suggesting that the chances of success are extremely slim.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","object","adverbial"],"structure":"verb-object","register":"common in both spoken and written Chinese","connotation":"negative","commonMistakes":"Learners might confuse this idiom with others that describe difficult tasks, but '大海捞针' specifically emphasizes the near impossibility and futility of the task, rather than just difficulty.","canStandAlone":false},"examples":[{"simplified":"在这么多文件中找到那一页简直是大海捞针。","english":"Finding that one page among so many documents is like finding a needle in a haystack.","traditional":"在這麼多文件中找到那一頁簡直是大海撈針。"},{"simplified":"想在这个城市找到他，真是大海捞针。","english":"Trying to find him in this city is like fishing for a needle in the ocean.","traditional":"想在這個城市找到他，真是大海撈針。"}],"synonyms":[],"antonyms":[],"confusedWith":[],"traditional":"大海撈針","pinyinOverride":null},{"id":"yi-yan-jiu-ding","simplified":"一言九鼎","literalMeaning":"one word nine tripods","figurativeMeaning":"a word of enormous weight; words that carry great authority","englishEquivalents":["a word is as good as gold","words carry weight"],"shortGloss":"words of great authority","characters":[{"char":"一","meaning":"one, single"},{"char":"言","meaning":"word, speech"},{"char":"九","meaning":"nine"},{"char":"鼎","meaning":"tripod, a symbol of authority and power"}],"origin":{"period":"Warring States period (475–221 BCE)","sourceText":"《史记·平原君虞卿列传》","sourceTextEnglish":"Records of the Grand Historian, Biography of Lord Pingyuan and Yu Qing","originalExcerpt":"平原君曰：“先生之言，信如九鼎之重。”","storyEnglish":"During the Warring States period, Lord Pingyuan of the state of Zhao highly valued the advice of his advisor, Yu Qing. He once said that Yu Qing's words were as weighty as nine tripods, which were symbols of authority and power in ancient China. This expression came to signify words of great importance and authority.","historicalFigures":["Lord Pingyuan","Yu Qing"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"modifier-head","register":"literary, but understood and sometimes used in formal speech","connotation":"positive","commonMistakes":"Learners might confuse it with idioms that simply mean 'important' without the nuance of authority. It specifically refers to words that carry significant weight and influence.","canStandAlone":false},"examples":[{"simplified":"他的意见在公司里一言九鼎，大家都很重视。","english":"His opinions carry great weight in the company, and everyone values them highly.","traditional":"他的意見在公司裡一言九鼎，大家都很重視。"},{"simplified":"在这次会议上，他的一言九鼎，决定了项目的方向。","english":"In this meeting, his words carried great authority and determined the direction of the project.","traditional":"在這次會議上，他的一言九鼎，決定了項目的方向。"}],"synonyms":["举足轻重"],"antonyms":[],"confusedWith":[{"id":"举足轻重","note":"While both idioms imply importance, 一言九鼎 specifically refers to the weight of words, whereas 举足轻重 refers to a person's influence or importance in a situation."}],"traditional":"一言九鼎","pinyinOverride":null},{"id":"yi-zhen-jian-xie","simplified":"一针见血","literalMeaning":"one needle sees blood","figurativeMeaning":"to go straight to the heart of the matter; to hit the nail on the head","englishEquivalents":["hit the nail on the head","get to the point"],"shortGloss":"get straight to the point","characters":[{"char":"一","meaning":"one"},{"char":"针","meaning":"needle"},{"char":"见","meaning":"see"},{"char":"血","meaning":"blood"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom 一针见血 is thought to derive from the idea of a skilled doctor or acupuncturist who, with a single needle, can accurately find the problem and cause immediate results. It metaphorically describes someone who can address an issue directly and effectively, without unnecessary detours.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["adverbial","complement"],"structure":"verb-object","register":"widely used in both spoken and written Chinese","connotation":"positive","commonMistakes":"Learners might confuse 一针见血 with similar idioms that imply precision but lack the directness and impact, such as 一语中的, which focuses more on verbal accuracy rather than the broader concept of addressing an issue effectively.","canStandAlone":false},"examples":[{"simplified":"他的评论一针见血，指出了问题的核心。","english":"His comment hit the nail on the head, pointing out the core of the problem.","traditional":"他的評論一針見血，指出了問題的核心。"},{"simplified":"她总是能一针见血地指出我们的弱点。","english":"She always manages to pinpoint our weaknesses directly.","traditional":"她總是能一針見血地指出我們的弱點。"}],"synonyms":["一语中的"],"antonyms":[],"confusedWith":[{"id":"一语中的","note":"一语中的 emphasizes verbal precision, while 一针见血 emphasizes directness and impact."}],"traditional":"一針見血","pinyinOverride":null},{"id":"ge-an-guan-huo","simplified":"隔岸观火","literalMeaning":"watch the fire from the opposite shore","figurativeMeaning":"to watch a situation unfold without getting involved, especially when others are in trouble","englishEquivalents":["sit on the fence","look on with folded arms"],"shortGloss":"watch without intervening","characters":[{"char":"隔","meaning":"separated by"},{"char":"岸","meaning":"shore"},{"char":"观","meaning":"watch"},{"char":"火","meaning":"fire"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '隔岸观火' comes from the idea of watching a fire burn from a safe distance, such as from the opposite side of a river. It implies observing a dangerous or problematic situation without getting involved, often with a sense of detachment or indifference.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["adverbial","predicate"],"structure":"verb-object","register":"commonly used in both spoken and written Chinese","connotation":"negative","commonMistakes":"Learners sometimes use this idiom to describe any kind of observation, but it specifically implies a lack of involvement in a problematic situation. It should not be used to describe neutral or positive observation.","canStandAlone":false},"examples":[{"simplified":"在朋友遇到困难时，他选择了隔岸观火。","english":"When his friend was in trouble, he chose to watch from the sidelines.","traditional":"在朋友遇到困難時，他選擇了隔岸觀火。"},{"simplified":"面对公司的危机，经理们不能再隔岸观火了。","english":"Faced with the company's crisis, the managers can no longer stand by and watch.","traditional":"面對公司的危機，經理們不能再隔岸觀火了。"}],"synonyms":["袖手旁观"],"antonyms":["挺身而出"],"confusedWith":[{"id":"袖手旁观","note":"Both idioms mean to watch without intervening, but '袖手旁观' emphasizes inaction more explicitly."}],"traditional":"隔岸觀火","pinyinOverride":null},{"id":"yin-lang-ru-shi","simplified":"引狼入室","literalMeaning":"lead a wolf into the house","figurativeMeaning":"to invite trouble or danger by bringing in an enemy or harmful element","englishEquivalents":["invite trouble","harbor a snake in one's bosom"],"shortGloss":"invite danger into one's home","characters":[{"char":"引","meaning":"lead; bring in"},{"char":"狼","meaning":"wolf"},{"char":"入","meaning":"enter; into"},{"char":"室","meaning":"room; house"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '引狼入室' is believed to have originated from folk stories where someone unwittingly invites a dangerous person or element into their home, only to suffer the consequences later. The wolf symbolizes danger and threat, and the act of bringing it into one's house represents inviting trouble into one's life.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","object"],"structure":"verb-object","register":"widely used in both spoken and written Chinese","connotation":"negative","commonMistakes":"Learners often confuse this idiom with expressions that involve welcoming or hospitality, but it specifically implies inviting danger or harm. It should not be used for neutral or positive situations.","canStandAlone":false},"examples":[{"simplified":"他把那个可疑的人带回家，真是引狼入室。","english":"He brought that suspicious person home, truly inviting trouble.","traditional":"他把那個可疑的人帶回家，真是引狼入室。"},{"simplified":"与不可信的人合作无异于引狼入室。","english":"Cooperating with untrustworthy people is akin to inviting danger into one's home.","traditional":"與不可信的人合作無異於引狼入室。"}],"synonyms":["自讨苦吃","自作自受"],"antonyms":[],"confusedWith":[{"id":"请君入瓮","note":"请君入瓮 refers to setting a trap for someone else, whereas 引狼入室 is about inviting danger to oneself."}],"traditional":"引狼入室","pinyinOverride":null},{"id":"kou-mi-fu-jian","simplified":"口蜜腹剑","literalMeaning":"mouth like honey, belly like a sword","figurativeMeaning":"to speak sweet words while harboring malicious intentions","englishEquivalents":["a wolf in sheep's clothing","honey-tongued but dagger-hearted"],"shortGloss":"deceptively sweet-talking","characters":[{"char":"口","meaning":"mouth"},{"char":"蜜","meaning":"honey"},{"char":"腹","meaning":"belly"},{"char":"剑","meaning":"sword"}],"origin":{"period":"Tang Dynasty (618–907)","sourceText":"《资治通鉴·唐纪》","sourceTextEnglish":"Zizhi Tongjian, Chronicles of Tang","originalExcerpt":"杨国忠口蜜腹剑，外示恭顺，而内怀奸诈。","storyEnglish":"The idiom comes from a story about Yang Guozhong, a chancellor during the Tang Dynasty. He was known for his eloquent and flattering speech, which concealed his treacherous and deceitful nature. His behavior was described as having a 'mouth like honey, belly like a sword,' indicating his tendency to speak sweetly while plotting harm.","historicalFigures":["Yang Guozhong"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"modifier-head","register":"literary, but widely understood and used in both writing and speech","connotation":"negative","commonMistakes":"Learners might confuse this idiom with others that involve deception but lack the specific nuance of sweet words masking harmful intent. It's important to note the contrast between the outward appearance and inner intention.","canStandAlone":false},"examples":[{"simplified":"他是个口蜜腹剑的人，千万别被他的甜言蜜语所迷惑。","english":"He is a honey-tongued but dagger-hearted person, so don't be fooled by his sweet words.","traditional":"他是個口蜜腹劍的人，千萬別被他的甜言蜜語所迷惑。"},{"simplified":"在职场上，我们要小心那些口蜜腹剑的同事。","english":"In the workplace, we must be wary of colleagues who are deceptively sweet-talking.","traditional":"在職場上，我們要小心那些口蜜腹劍的同事。"}],"synonyms":["笑里藏刀"],"antonyms":[],"confusedWith":[{"id":"笑里藏刀","note":"Both involve deception, but 笑里藏刀 emphasizes hiding a knife behind a smile, while 口蜜腹剑 focuses on sweet words with harmful intent."}],"traditional":"口蜜腹劍","pinyinOverride":null},{"id":"ye-gong-hao-long","simplified":"叶公好龙","literalMeaning":"Lord Ye loves dragons","figurativeMeaning":"to pretend to love or admire something, but actually fear or dislike it","englishEquivalents":["to pay lip service","all talk and no action"],"shortGloss":"pretend admiration","characters":[{"char":"叶","meaning":"Ye (a surname)"},{"char":"公","meaning":"Lord"},{"char":"好","meaning":"love; like"},{"char":"龙","meaning":"dragon"}],"origin":{"period":"Eastern Zhou period (770–256 BCE)","sourceText":"《新序·杂事四》","sourceTextEnglish":"New Prefaces, Miscellaneous Affairs 4","originalExcerpt":"叶公子高好龙，雕文刻镂以为屋室。天龙闻而下之，窥头于牖，施尾于堂。叶公见之，弃而还走，失其魂魄，五色无主。","storyEnglish":"Lord Ye was known for his love of dragons. He decorated his house with carvings and paintings of dragons. When a real dragon heard about this and came down to visit, sticking its head through the window and its tail into the hall, Lord Ye was so frightened that he ran away in terror, losing his wits and composure. This story illustrates the difference between professed admiration and genuine appreciation.","historicalFigures":["Lord Ye"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["subject","predicate","object"],"structure":"subject-predicate","register":"literary, but widely understood and used in ordinary speech","connotation":"negative","commonMistakes":"Learners often use this idiom to describe genuine admiration, but it actually implies insincerity or hypocrisy. It differs from idioms like '口是心非', which more broadly means saying one thing and meaning another.","canStandAlone":false},"examples":[{"simplified":"他总是说自己喜欢挑战，但实际上是叶公好龙。","english":"He always says he likes challenges, but in reality, he's just paying lip service.","traditional":"他總是說自己喜歡挑戰，但實際上是葉公好龍。"},{"simplified":"如果你只是叶公好龙，那就不要假装对这项工作感兴趣。","english":"If you're just pretending to like it, then don't feign interest in this job.","traditional":"如果你只是葉公好龍，那就不要假裝對這項工作感興趣。"}],"synonyms":["口是心非"],"antonyms":["言行一致"],"confusedWith":[{"id":"口是心非","note":"While both involve insincerity, '口是心非' broadly means saying one thing and meaning another, not necessarily related to fear or dislike."}],"traditional":"葉公好龍","pinyinOverride":null},{"id":"kong-xue-lai-feng","simplified":"空穴来风","literalMeaning":"empty cave invites wind","figurativeMeaning":"rumors arise without basis","englishEquivalents":["no smoke without fire","where there's smoke, there's fire"],"shortGloss":"rumors without basis","characters":[{"char":"空","meaning":"empty"},{"char":"穴","meaning":"cave"},{"char":"来","meaning":"come"},{"char":"风","meaning":"wind"}],"origin":{"period":"Han Dynasty (206 BCE–220 CE)","sourceText":"《风俗通义》","sourceTextEnglish":"Fengsu Tongyi","originalExcerpt":"虚者，风必入之。故空穴来风，未必无因。","storyEnglish":"The idiom originates from the Han Dynasty text 'Fengsu Tongyi' by Ying Shao. It describes how an empty cave naturally invites the wind to enter, suggesting that rumors often arise because there is some underlying cause or reason, even if not immediately apparent.","historicalFigures":["Ying Shao"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"subject-predicate","register":"literary, but commonly used in both formal and informal contexts","connotation":"neutral","commonMistakes":"Learners often misunderstand this idiom as meaning that rumors are always baseless, but it actually implies that rumors often have some underlying cause. It is sometimes confused with '无风不起浪', which more directly suggests that there is always a cause for rumors.","canStandAlone":false},"examples":[{"simplified":"关于他的谣言不过是空穴来风，不必当真。","english":"The rumors about him are baseless and shouldn't be taken seriously.","traditional":"關於他的謠言不過是空穴來風，不必當真。"},{"simplified":"虽然这次的消息可能是空穴来风，但我们还是要调查清楚。","english":"Although this news might be baseless, we still need to investigate thoroughly.","traditional":"雖然這次的消息可能是空穴來風，但我們還是要調查清楚。"}],"synonyms":["无风不起浪"],"antonyms":[],"confusedWith":[{"id":"无风不起浪","note":"无风不起浪 implies that there is always a cause for rumors, whereas 空穴来风 suggests that rumors arise without a basis."}],"traditional":"空穴來風","pinyinOverride":null},{"id":"lin-yuan-xian-yu","simplified":"临渊羡鱼","literalMeaning":"stand by the pond and envy the fish","figurativeMeaning":"to wish for something without taking action to achieve it","englishEquivalents":["wishful thinking","if wishes were horses, beggars would ride"],"shortGloss":"wish without action","characters":[{"char":"临","meaning":"to approach, to be near"},{"char":"渊","meaning":"deep pool, abyss"},{"char":"羡","meaning":"to envy, to admire"},{"char":"鱼","meaning":"fish"}],"origin":{"period":"Warring States period (475–221 BCE)","sourceText":"《汉书·董仲舒传》","sourceTextEnglish":"Book of Han, Biography of Dong Zhongshu","originalExcerpt":"临渊羡鱼，不如退而结网。","storyEnglish":"The idiom originates from a story in the 'Book of Han' where it is advised that instead of merely standing by a pond and envying the fish, one should retreat and weave a net to catch them. This metaphor encourages taking practical steps to achieve one's desires rather than just wishing for them.","historicalFigures":["Dong Zhongshu"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["adverbial","complement"],"structure":"verb-object","register":"literary, but understood in educated speech","connotation":"negative","commonMistakes":"Learners often confuse this idiom with expressions that imply taking action, but it specifically refers to inaction and mere wishing. It should not be used to describe situations where effort is being made.","canStandAlone":false},"examples":[{"simplified":"他总是临渊羡鱼，却不愿意付出努力。","english":"He always wishes for things without taking action to achieve them.","traditional":"他總是臨淵羨魚，卻不願意付出努力。"},{"simplified":"如果你只是临渊羡鱼，你永远不会成功。","english":"If you only wish without acting, you will never succeed.","traditional":"如果你只是臨淵羨魚，你永遠不會成功。"}],"synonyms":["纸上谈兵"],"antonyms":["脚踏实地"],"confusedWith":[{"id":"望梅止渴","note":"望梅止渴 involves using imagination to comfort oneself, while 临渊羡鱼 emphasizes inaction."}],"traditional":"臨淵羨魚","pinyinOverride":null},{"id":"cao-chuan-jie-jian","simplified":"草船借箭","literalMeaning":"straw boat borrows arrows","figurativeMeaning":"to use others' resources for one's own gain; to achieve a goal using clever tactics","englishEquivalents":["kill two birds with one stone","turn the tables"],"shortGloss":"use others' resources cleverly","characters":[{"char":"草","meaning":"straw"},{"char":"船","meaning":"boat"},{"char":"借","meaning":"borrow"},{"char":"箭","meaning":"arrows"}],"origin":{"period":"Three Kingdoms period (220–280 CE)","sourceText":"《三国演义》","sourceTextEnglish":"Romance of the Three Kingdoms","originalExcerpt":"孔明曰：“吾欲借十万矢，汝可助我否？”","storyEnglish":"During the Three Kingdoms period, Zhuge Liang, a brilliant strategist, needed arrows for an upcoming battle. He devised a plan to borrow arrows from the enemy. He sent straw boats filled with straw men into the foggy river, tricking the enemy into shooting arrows at them. The arrows stuck into the straw, and Zhuge Liang successfully collected them, thus acquiring the needed arrows without using his own resources.","historicalFigures":["Zhuge Liang"],"relatedIdiomsFromSameSource":["三顾茅庐","草木皆兵"]},"usage":{"grammaticalRole":["subject","predicate","object"],"structure":"verb-object","register":"literary, but widely understood and used in both formal and informal contexts","connotation":"positive","commonMistakes":"Learners might confuse this idiom with simply borrowing something without permission, but it specifically refers to a clever tactic of using others' resources.","canStandAlone":false},"examples":[{"simplified":"他像草船借箭一样，利用了对手的资源来完成任务。","english":"He, like borrowing arrows with straw boats, used the opponent's resources to complete the task.","traditional":"他像草船借箭一樣，利用了對手的資源來完成任務。"},{"simplified":"在这次谈判中，他草船借箭，巧妙地达到了自己的目的。","english":"In this negotiation, he cleverly used the strategy of borrowing arrows with straw boats to achieve his goal.","traditional":"在這次談判中，他草船借箭，巧妙地達到了自己的目的。"}],"synonyms":["借刀杀人"],"antonyms":[],"confusedWith":[{"id":"借刀杀人","note":"While both involve using others, 借刀杀人 implies using others to do one's dirty work, often with malicious intent."}],"traditional":"草船借箭","pinyinOverride":null},{"id":"guo-he-chai-qiao","simplified":"过河拆桥","literalMeaning":"cross the river and dismantle the bridge","figurativeMeaning":"to abandon or betray someone after they have helped you","englishEquivalents":["burn one's bridges","bite the hand that feeds you"],"shortGloss":"abandon someone after getting help","characters":[{"char":"过","meaning":"cross"},{"char":"河","meaning":"river"},{"char":"拆","meaning":"dismantle"},{"char":"桥","meaning":"bridge"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '过河拆桥' describes a situation where someone receives help to overcome a difficulty (symbolized by crossing a river) and then, once they have achieved their goal, they destroy the means that helped them (the bridge), leaving others without the same support. It is often used to criticize ungrateful or treacherous behavior.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","object","adverbial"],"structure":"verb-object","register":"commonly used in both spoken and written Chinese","connotation":"negative","commonMistakes":"Learners sometimes confuse this idiom with '过河拆桥' (guo-he-chai-qiao) which has a similar structure but a different meaning. The key difference is that '过河拆桥' specifically implies betrayal after receiving help.","canStandAlone":false},"examples":[{"simplified":"他一旦成功就过河拆桥，把曾经帮助过他的人都抛在脑后。","english":"Once he succeeded, he abandoned those who had helped him, like crossing the river and dismantling the bridge.","traditional":"他一旦成功就過河拆橋，把曾經幫助過他的人都拋在腦後。"},{"simplified":"我们不能过河拆桥，应该感恩曾经帮助过我们的人。","english":"We shouldn't burn our bridges; we should be grateful to those who have helped us.","traditional":"我們不能過河拆橋，應該感恩曾經幫助過我們的人。"}],"synonyms":["卸磨杀驴"],"antonyms":["知恩图报"],"confusedWith":[],"traditional":"過河拆橋","pinyinOverride":null},{"id":"chao-san-mu-si","simplified":"朝三暮四","literalMeaning":"morning three, evening four","figurativeMeaning":"to be capricious or change one's mind frequently","englishEquivalents":["blow hot and cold","fickle-minded","change with the wind"],"shortGloss":"capricious or fickle-minded","characters":[{"char":"朝","meaning":"morning"},{"char":"三","meaning":"three"},{"char":"暮","meaning":"evening"},{"char":"四","meaning":"four"}],"origin":{"period":"Warring States period (475–221 BCE)","sourceText":"《庄子·齐物论》","sourceTextEnglish":"Zhuangzi, Chapter 'Qi Wu Lun'","originalExcerpt":"狙公赋芧，曰：“朝三而暮四。”众狙皆怒。曰：“然则朝四而暮三。”众狙皆悦。","storyEnglish":"The story comes from the book 'Zhuangzi'. A man who kept monkeys told them they would receive three chestnuts in the morning and four in the evening. The monkeys were unhappy with this arrangement. So he changed it to four in the morning and three in the evening, which pleased the monkeys. The story illustrates how people can be easily swayed by superficial changes.","historicalFigures":["Zhuangzi"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"coordinate","register":"literary, but widely understood and used in ordinary speech","connotation":"negative","commonMistakes":"Learners often confuse it with idioms that mean 'deceptive' or 'dishonest', but it specifically refers to inconsistency or capriciousness, not intentional deceit.","canStandAlone":false},"examples":[{"simplified":"他做事总是朝三暮四，让人很难信任。","english":"He is always so capricious in his actions, making it hard for people to trust him.","traditional":"他做事總是朝三暮四，讓人很難信任。"},{"simplified":"如果你朝三暮四，别人就不会认真对待你的决定。","english":"If you keep changing your mind, others won't take your decisions seriously.","traditional":"如果你朝三暮四，別人就不會認真對待你的決定。"}],"synonyms":["反复无常","变化无常"],"antonyms":["始终如一"],"confusedWith":[{"id":"言而无信","note":"言而无信 refers to being untrustworthy or not keeping promises, while 朝三暮四 refers to being capricious or inconsistent."}],"traditional":"朝三暮四","pinyinOverride":null},{"id":"zhi-lu-wei-ma","simplified":"指鹿为马","literalMeaning":"point at a deer and call it a horse","figurativeMeaning":"to deliberately misrepresent something; to distort facts or tell lies for ulterior motives","englishEquivalents":["call a spade a rake","white is black","up is down"],"shortGloss":"deliberately misrepresent facts","characters":[{"char":"指","meaning":"to point at"},{"char":"鹿","meaning":"deer"},{"char":"为","meaning":"to call; to consider as"},{"char":"马","meaning":"horse"}],"origin":{"period":"Qin Dynasty (221–206 BCE)","sourceText":"《史记·秦始皇本纪》","sourceTextEnglish":"Records of the Grand Historian, Annals of Qin Shihuang","originalExcerpt":"赵高欲为乱，恐群臣不听，乃先设验，持鹿献于二世，曰：“马也。”二世笑曰：“丞相误邪？谓鹿为马。”","storyEnglish":"During the Qin Dynasty, the eunuch Zhao Gao wanted to test the loyalty of the court officials and consolidate his power. He presented a deer to the Second Emperor of Qin, claiming it was a horse. Some officials, fearing Zhao Gao's power, agreed with him, while others did not. This event demonstrated Zhao Gao's control over the court and his ability to manipulate the truth.","historicalFigures":["Zhao Gao","Second Emperor of Qin"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","object"],"structure":"verb-object","register":"literary, but widely understood and used in both formal and informal contexts","connotation":"negative","commonMistakes":"Learners might confuse this idiom with similar expressions that involve genuine mistakes or misunderstandings, but 指鹿为马 specifically implies intentional deceit.","canStandAlone":false},"examples":[{"simplified":"他总是指鹿为马，让人无法相信他说的话。","english":"He always distorts the truth, making it impossible to believe what he says.","traditional":"他總是指鹿為馬，讓人無法相信他說的話。"},{"simplified":"在会议上，他竟然指鹿为马，试图掩盖事实。","english":"During the meeting, he blatantly misrepresented the facts, trying to cover up the truth.","traditional":"在會議上，他竟然指鹿為馬，試圖掩蓋事實。"}],"synonyms":["颠倒黑白","混淆是非"],"antonyms":["实事求是"],"confusedWith":[{"id":"颠倒黑白","note":"While both involve distortion of facts, 指鹿为马 implies a more deliberate and blatant misrepresentation."}],"traditional":"指鹿為馬","pinyinOverride":null},{"id":"zhu-lan-da-shui","simplified":"竹篮打水","literalMeaning":"bamboo basket fetch water","figurativeMeaning":"to work hard but achieve nothing; a futile effort","englishEquivalents":["a wild-goose chase","a fool's errand"],"shortGloss":"a futile effort","characters":[{"char":"竹","meaning":"bamboo"},{"char":"篮","meaning":"basket"},{"char":"打","meaning":"fetch"},{"char":"水","meaning":"water"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '竹篮打水' comes from the idea of trying to fetch water with a bamboo basket. Since bamboo baskets have holes, any attempt to carry water in them is futile. This idiom is used to describe efforts that are doomed to fail from the start, no matter how much effort is put in.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","object"],"structure":"verb-object","register":"commonly used in both spoken and written Chinese","connotation":"negative","commonMistakes":"Learners often confuse this idiom with ones that imply hard work, but this idiom specifically emphasizes the futility of the effort. It should not be used to describe efforts that are difficult but achievable.","canStandAlone":false},"examples":[{"simplified":"他每天加班到很晚，但没有得到任何认可，真是竹篮打水。","english":"He works overtime every day but receives no recognition; it's really a futile effort.","traditional":"他每天加班到很晚，但沒有得到任何認可，真是竹籃打水。"},{"simplified":"试图改变他的想法就像竹篮打水，完全是浪费时间。","english":"Trying to change his mind is like fetching water with a bamboo basket; it's a complete waste of time.","traditional":"試圖改變他的想法就像竹籃打水，完全是浪費時間。"}],"synonyms":["徒劳无功"],"antonyms":[],"confusedWith":[{"id":"事半功倍","note":"事半功倍 refers to achieving more with less effort, whereas 竹篮打水 emphasizes futile efforts."}],"traditional":"竹籃打水","pinyinOverride":null},{"id":"ge-qiang-you-er","simplified":"隔墙有耳","literalMeaning":"the wall has ears","figurativeMeaning":"be careful, someone might be listening; there are eavesdroppers around","englishEquivalents":["walls have ears"],"shortGloss":"be cautious of eavesdroppers","characters":[{"char":"隔","meaning":"separate; partition"},{"char":"墙","meaning":"wall"},{"char":"有","meaning":"have; there are"},{"char":"耳","meaning":"ears"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '隔墙有耳' suggests that even when you think you are speaking privately, there might be someone listening in. It serves as a reminder to be cautious about what you say, as information can easily be overheard and spread.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"subject-predicate","register":"common in both spoken and written Chinese, often used in informal contexts","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with others that involve secrecy or privacy, but '隔墙有耳' specifically emphasizes the risk of being overheard, not just keeping something secret.","canStandAlone":false},"examples":[{"simplified":"在办公室里谈论机密事项时要小心，隔墙有耳。","english":"Be careful when discussing confidential matters in the office; the walls have ears.","traditional":"在辦公室裡談論機密事項時要小心，隔牆有耳。"},{"simplified":"他提醒我在公共场合不要大声说话，因为隔墙有耳。","english":"He reminded me not to speak loudly in public places because the walls have ears.","traditional":"他提醒我在公共場合不要大聲說話，因為隔牆有耳。"}],"synonyms":[],"antonyms":[],"confusedWith":[{"id":"密不透风","note":"密不透风 refers to something being very secretive or airtight, whereas 隔墙有耳 warns of potential eavesdropping."}],"traditional":"隔牆有耳","pinyinOverride":null},{"id":"shui-zhong-lao-yue","simplified":"水中捞月","literalMeaning":"scoop the moon from the water","figurativeMeaning":"to make a futile attempt; to try to achieve the impossible","englishEquivalents":["chase a rainbow","catch the wind","a fool's errand"],"shortGloss":"a futile attempt","characters":[{"char":"水","meaning":"water"},{"char":"中","meaning":"in"},{"char":"捞","meaning":"scoop"},{"char":"月","meaning":"moon"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '水中捞月' comes from a folk tale about a monkey who saw the reflection of the moon in a well and tried to scoop it out, thinking it was the real moon. Despite its efforts, the monkey only managed to disturb the water and never captured the moon. This story illustrates the futility of attempting the impossible.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","object"],"structure":"verb-object","register":"commonly used in both spoken and written Chinese","connotation":"negative","commonMistakes":"Learners often confuse this idiom with expressions that imply hope or aspiration, but it specifically refers to attempts that are doomed to fail. It should not be used to describe realistic goals.","canStandAlone":false},"examples":[{"simplified":"他想要在一天之内学会所有的汉字，简直是水中捞月。","english":"He wants to learn all the Chinese characters in one day, which is simply a futile attempt.","traditional":"他想要在一天之內學會所有的漢字，簡直是水中撈月。"},{"simplified":"试图改变他的性格就像水中捞月。","english":"Trying to change his personality is like trying to scoop the moon from the water.","traditional":"試圖改變他的性格就像水中撈月。"}],"synonyms":["徒劳无功","白费力气"],"antonyms":[],"confusedWith":[{"id":"望梅止渴","note":"While both involve illusions, '望梅止渴' refers to comforting oneself with false hopes, not futile attempts."}],"traditional":"水中撈月","pinyinOverride":null},{"id":"lin-ke-jue-jing","simplified":"临渴掘井","literalMeaning":"approach thirst, dig well","figurativeMeaning":"to take action only when faced with a crisis; to make a last-minute effort","englishEquivalents":["a day late and a dollar short","too little, too late"],"shortGloss":"acting too late in a crisis","characters":[{"char":"临","meaning":"approach"},{"char":"渴","meaning":"thirst"},{"char":"掘","meaning":"dig"},{"char":"井","meaning":"well"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '临渴掘井' describes the futile attempt to dig a well only when one is already thirsty. It highlights the importance of preparation and foresight, as waiting until a crisis occurs often leads to inadequate solutions.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["adverbial","complement"],"structure":"verb-object","register":"commonly used in both written and spoken Chinese","connotation":"negative","commonMistakes":"Learners might confuse this idiom with others that imply taking action, but '临渴掘井' specifically emphasizes the futility and poor timing of the action. It should not be used to describe well-timed or proactive efforts.","canStandAlone":false},"examples":[{"simplified":"他总是临渴掘井，等到最后一刻才开始准备考试。","english":"He always waits until the last minute to start preparing for exams, like digging a well only when thirsty.","traditional":"他總是臨渴掘井，等到最後一刻才開始準備考試。"},{"simplified":"公司在财务危机时才想办法筹集资金，这真是临渴掘井。","english":"The company only tried to raise funds during the financial crisis, which was really a case of digging a well when already thirsty.","traditional":"公司在財務危機時才想辦法籌集資金，這真是臨渴掘井。"}],"synonyms":["亡羊补牢"],"antonyms":["未雨绸缪"],"confusedWith":[{"id":"亡羊补牢","note":"While both idioms involve taking action after a problem arises, '亡羊补牢' suggests that it's not too late to fix things, whereas '临渴掘井' implies the action is too late to be effective."}],"traditional":"臨渴掘井","pinyinOverride":null},{"id":"tang-bi-dang-che","simplified":"螳臂当车","literalMeaning":"mantis arm blocks the cart","figurativeMeaning":"to overestimate one's abilities and attempt something futile","englishEquivalents":["a fool's errand","tilting at windmills"],"shortGloss":"futile resistance","characters":[{"char":"螳","meaning":"mantis"},{"char":"臂","meaning":"arm"},{"char":"当","meaning":"block"},{"char":"车","meaning":"cart"}],"origin":{"period":"Warring States period (475–221 BCE)","sourceText":"《庄子·人间世》","sourceTextEnglish":"Zhuangzi, Chapter: The World of Men","originalExcerpt":"螳螂怒臂以当车辙，不知其不胜任也。","storyEnglish":"The idiom originates from a story in the 'Zhuangzi', where a mantis raises its arms to block a cart, unaware of its own inability to stop it. This story illustrates the futility of overestimating one's power against overwhelming odds.","historicalFigures":["Zhuangzi"],"relatedIdiomsFromSameSource":["井底之蛙"]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"literary, but used in both written and spoken Chinese","connotation":"negative","commonMistakes":"Learners often confuse this idiom with similar expressions of futility but fail to capture its specific imagery of a small creature facing an insurmountable obstacle. It differs from idioms that imply mere failure without the aspect of overestimation.","canStandAlone":false},"examples":[{"simplified":"他以为自己能改变公司的政策，简直是螳臂当车。","english":"He thought he could change the company's policy, but it was like a mantis trying to block a cart.","traditional":"他以為自己能改變公司的政策，簡直是螳臂當車。"},{"simplified":"试图一个人对抗整个系统，无异于螳臂当车。","english":"Trying to fight the entire system alone is like a mantis trying to block a cart.","traditional":"試圖一個人對抗整個系統，無異於螳臂當車。"}],"synonyms":["以卵击石"],"antonyms":[],"confusedWith":[{"id":"以卵击石","note":"Both idioms describe futile efforts, but 螳臂当车 emphasizes overestimation of one's abilities."}],"traditional":"螳臂當車","pinyinOverride":null},{"id":"du-mu-nan-zhi","simplified":"独木难支","literalMeaning":"a single tree cannot support","figurativeMeaning":"one person alone cannot accomplish a task; it requires collective effort","englishEquivalents":["It takes a village","Many hands make light work"],"shortGloss":"one person can't do it alone","characters":[{"char":"独","meaning":"single, alone"},{"char":"木","meaning":"tree, wood"},{"char":"难","meaning":"difficult"},{"char":"支","meaning":"support, sustain"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '独木难支' is based on the metaphor that a single tree cannot support a structure. It highlights the importance of teamwork and collective effort, suggesting that one person alone is insufficient to achieve a significant task. This concept is widely recognized in various cultures, emphasizing the power of collaboration.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"subject-predicate","register":"commonly used in both spoken and written Chinese to emphasize the need for cooperation","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with similar expressions that emphasize individual effort. Unlike those, '独木难支' stresses the necessity of collective action.","canStandAlone":false},"examples":[{"simplified":"在这个项目中，独木难支，我们需要团队的力量。","english":"In this project, one person alone cannot do it; we need the power of the team.","traditional":"在這個項目中，獨木難支，我們需要團隊的力量。"},{"simplified":"面对如此巨大的挑战，独木难支，大家必须齐心协力。","english":"Facing such a huge challenge, one person alone cannot manage; everyone must work together.","traditional":"面對如此巨大的挑戰，獨木難支，大家必須齊心協力。"}],"synonyms":["众志成城"],"antonyms":[],"confusedWith":[{"id":"孤掌难鸣","note":"Both idioms emphasize the need for more than one person, but '孤掌难鸣' specifically refers to the inability to achieve something without a counterpart or partner."}],"traditional":"獨木難支","pinyinOverride":null},{"id":"ye-chang-meng-duo","simplified":"夜长梦多","literalMeaning":"long night, many dreams","figurativeMeaning":"the longer you delay, the more problems may arise","englishEquivalents":["strike while the iron is hot","time waits for no one"],"shortGloss":"delaying leads to complications","characters":[{"char":"夜","meaning":"night"},{"char":"长","meaning":"long"},{"char":"梦","meaning":"dreams"},{"char":"多","meaning":"many"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom suggests that when a situation is prolonged unnecessarily, it can lead to unexpected complications or issues, much like how a long night might bring many dreams. It is often used to advise taking timely action to avoid potential problems.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"cause-effect","register":"commonly used in both spoken and written Chinese","connotation":"negative","commonMistakes":"Learners might confuse this idiom with expressions about actual dreams or sleep, but it metaphorically refers to complications arising from delays. It is not about literal dreams.","canStandAlone":false},"examples":[{"simplified":"我们应该尽快完成这个项目，夜长梦多。","english":"We should finish this project as soon as possible; the longer we wait, the more problems may arise.","traditional":"我們應該儘快完成這個項目，夜長夢多。"},{"simplified":"在谈判中，夜长梦多，最好尽快达成协议。","english":"In negotiations, delaying can lead to complications; it's best to reach an agreement quickly.","traditional":"在談判中，夜長夢多，最好儘快達成協議。"}],"synonyms":["拖泥带水"],"antonyms":["速战速决"],"confusedWith":[{"id":"夜有所梦","note":"夜有所梦 refers to having dreams at night, not to complications from delays."}],"traditional":"夜長夢多","pinyinOverride":null},{"id":"wo-xin-chang-dan","simplified":"卧薪尝胆","literalMeaning":"lie on firewood, taste gall","figurativeMeaning":"to endure hardships to strengthen one's resolve; to persevere through difficulties for future success","englishEquivalents":["to bite the bullet","to endure hardships for future success"],"shortGloss":"endure hardships to strengthen resolve","characters":[{"char":"卧","meaning":"to lie down"},{"char":"薪","meaning":"firewood"},{"char":"尝","meaning":"to taste"},{"char":"胆","meaning":"gall bladder"}],"origin":{"period":"Spring and Autumn period (770–476 BCE)","sourceText":"《史记·越王勾践世家》","sourceTextEnglish":"Records of the Grand Historian, House of Goujian of Yue","originalExcerpt":"越王勾践卧薪尝胆，三年而复国。","storyEnglish":"The idiom comes from the story of King Goujian of Yue, who, after being defeated and captured by the state of Wu, endured great hardships to strengthen his resolve for revenge. He slept on firewood and tasted gall every day to remind himself of his humiliation. After years of perseverance, he eventually rebuilt his strength and defeated Wu.","historicalFigures":["Goujian"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["adverbial","predicate"],"structure":"verb-object","register":"literary, but widely understood and used in both written and spoken Chinese","connotation":"positive","commonMistakes":"Learners sometimes use this idiom to describe any hardship, but it specifically refers to enduring hardship with a purpose or goal in mind. It should not be confused with idioms that simply describe suffering without a future aim.","canStandAlone":false},"examples":[{"simplified":"为了实现梦想，他卧薪尝胆，努力奋斗。","english":"To achieve his dreams, he endured hardships and worked tirelessly.","traditional":"為了實現夢想，他臥薪嚐膽，努力奮鬥。"},{"simplified":"经过多年的卧薪尝胆，他终于成功了。","english":"After years of enduring hardships, he finally succeeded.","traditional":"經過多年的臥薪嚐膽，他終於成功了。"}],"synonyms":["发愤图强"],"antonyms":[],"confusedWith":[{"id":"忍辱负重","note":"While both idioms involve enduring hardship, 忍辱负重 emphasizes enduring humiliation for a greater responsibility, not necessarily for revenge or future success."}],"traditional":"臥薪嚐膽","pinyinOverride":null},{"id":"zou-ma-guan-hua","simplified":"走马观花","literalMeaning":"ride a horse and view flowers","figurativeMeaning":"to make a quick, superficial observation","englishEquivalents":["a cursory glance","skim the surface"],"shortGloss":"superficial observation","characters":[{"char":"走","meaning":"ride"},{"char":"马","meaning":"horse"},{"char":"观","meaning":"view"},{"char":"花","meaning":"flowers"}],"origin":{"period":"Tang Dynasty (618–907)","sourceText":"《杜甫诗集》","sourceTextEnglish":"Collected Poems of Du Fu","originalExcerpt":"走马观花意未尽，停鞭细看始知深。","storyEnglish":"The idiom originates from a poem by Du Fu, a famous Tang Dynasty poet. In the poem, he describes the experience of riding a horse past flowers, suggesting that one cannot truly appreciate their beauty without stopping to look more closely. The phrase has come to mean making a quick and superficial observation without understanding the deeper details.","historicalFigures":["Du Fu"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["adverbial","attributive"],"structure":"verb-object","register":"widely used in both spoken and written Chinese","connotation":"neutral","commonMistakes":"Learners often confuse this idiom with others that imply a lack of understanding, but 走马观花 specifically emphasizes the speed and superficiality of the observation, not necessarily a lack of comprehension.","canStandAlone":false},"examples":[{"simplified":"我们只是走马观花地看了一下展览，没有深入了解。","english":"We just took a cursory glance at the exhibition and didn't delve into it.","traditional":"我們只是走馬觀花地看了一下展覽，沒有深入瞭解。"},{"simplified":"旅游时走马观花地参观各个景点，可能会错过很多有趣的细节。","english":"When traveling, if you visit the sights in a cursory manner, you might miss many interesting details.","traditional":"旅遊時走馬觀花地參觀各個景點，可能會錯過很多有趣的細節。"}],"synonyms":["浮光掠影"],"antonyms":["细致入微"],"confusedWith":[{"id":"浮光掠影","note":"Both imply superficial observation, but 走马观花 emphasizes speed, while 浮光掠影 suggests fleeting impressions."}],"traditional":"走馬觀花","pinyinOverride":null},{"id":"yi-si-bu-gou","simplified":"一丝不苟","literalMeaning":"not even a thread is neglected","figurativeMeaning":"meticulous and thorough; to attend to every detail","englishEquivalents":["meticulous","scrupulous","not leave a stone unturned"],"shortGloss":"meticulous and thorough","characters":[{"char":"一","meaning":"one; single"},{"char":"丝","meaning":"thread; slightest bit"},{"char":"不","meaning":"not"},{"char":"苟","meaning":"careless; negligent"}],"origin":{"period":"Qing Dynasty (1644–1912)","sourceText":"《曾国藩家书》","sourceTextEnglish":"Letters of Zeng Guofan","originalExcerpt":"凡事不可苟且，一丝一毫不可放松。","storyEnglish":"The idiom comes from the writings of Zeng Guofan, a prominent Qing Dynasty official and military leader. In his letters, he emphasized the importance of being meticulous and thorough in all matters, advising against any form of negligence. His attention to detail and insistence on high standards became well-regarded, and this phrase encapsulates his philosophy.","historicalFigures":["Zeng Guofan"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["adverbial","attributive"],"structure":"modifier-head","register":"widely used in both formal and informal contexts","connotation":"positive","commonMistakes":"Learners often confuse this idiom with others that imply thoroughness but lack the emphasis on meticulousness. It is important to note that 一丝不苟 specifically highlights attention to the smallest details.","canStandAlone":false},"examples":[{"simplified":"他做事一丝不苟，总是能达到完美的效果。","english":"He works meticulously and always achieves perfect results.","traditional":"他做事一絲不苟，總是能達到完美的效果。"},{"simplified":"她一丝不苟地检查每一个细节，确保没有错误。","english":"She meticulously checks every detail to ensure there are no mistakes.","traditional":"她一絲不苟地檢查每一個細節，確保沒有錯誤。"}],"synonyms":["精益求精","兢兢业业"],"antonyms":["粗心大意","马马虎虎"],"confusedWith":[{"id":"精益求精","note":"While both emphasize thoroughness, 精益求精 focuses more on continuous improvement rather than meticulous attention to detail."}],"traditional":"一絲不苟","pinyinOverride":null},{"id":"yi-ju-yi-dong","simplified":"一举一动","literalMeaning":"every move and action","figurativeMeaning":"every single move or action; all actions and movements","englishEquivalents":["every move","every action"],"shortGloss":"every move or action","characters":[{"char":"一","meaning":"every"},{"char":"举","meaning":"move"},{"char":"一","meaning":"every"},{"char":"动","meaning":"action"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom 一举一动 is a common expression used to describe observing or considering every single action or movement of a person. It emphasizes the thoroughness or meticulousness in watching or analyzing someone's behavior.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["object","attributive"],"structure":"coordinate","register":"widely used in both formal and informal contexts","connotation":"neutral","commonMistakes":"Learners might confuse 一举一动 with similar expressions that emphasize frequency rather than thoroughness. It's important to note that 一举一动 focuses on each individual action rather than the frequency of actions.","canStandAlone":false},"examples":[{"simplified":"他的一举一动都被保安监视着。","english":"His every move was being watched by the security guards.","traditional":"他的一舉一動都被保安監視著。"},{"simplified":"在面试中，你的一举一动都可能影响结果。","english":"In an interview, every move you make can affect the outcome.","traditional":"在面試中，你的一舉一動都可能影響結果。"}],"synonyms":["举止言谈"],"antonyms":[],"confusedWith":[{"id":"一言一行","note":"一言一行 emphasizes both words and actions, while 一举一动 focuses solely on actions and movements."}],"traditional":"一舉一動","pinyinOverride":null},{"id":"yi-ju-liang-de","simplified":"一举两得","literalMeaning":"one action, two gains","figurativeMeaning":"to achieve two things at once","englishEquivalents":["kill two birds with one stone"],"shortGloss":"achieve two things at once","characters":[{"char":"一","meaning":"one"},{"char":"举","meaning":"action"},{"char":"两","meaning":"two"},{"char":"得","meaning":"gain"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '一举两得' is believed to have originated from the idea of making one effort and achieving two benefits. It is commonly used to describe situations where a single action results in multiple positive outcomes. The exact historical origin is unclear, but it has been widely used in Chinese literature and speech.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["adverbial","predicate"],"structure":"verb-object","register":"widely used in both formal and informal contexts","connotation":"positive","commonMistakes":"Learners sometimes confuse this idiom with others that imply achieving multiple outcomes but with negative connotations. It's important to remember that 一举两得 always implies a positive result.","canStandAlone":false},"examples":[{"simplified":"他每天骑自行车上班，一举两得，既锻炼了身体，又节省了交通费。","english":"He rides his bike to work every day, achieving two things at once: getting exercise and saving on transportation costs.","traditional":"他每天騎自行車上班，一舉兩得，既鍛鍊了身體，又節省了交通費。"},{"simplified":"通过这次合作，我们一举两得，不仅扩大了市场，还提高了品牌知名度。","english":"Through this cooperation, we achieved two things at once: expanding the market and increasing brand awareness.","traditional":"通過這次合作，我們一舉兩得，不僅擴大了市場，還提高了品牌知名度。"}],"synonyms":["事半功倍"],"antonyms":[],"confusedWith":[{"id":"事倍功半","note":"事倍功半 means putting in a lot of effort but achieving little, which is the opposite of 一举两得."}],"traditional":"一舉兩得","pinyinOverride":null},{"id":"yi-shi-wu-cheng","simplified":"一事无成","literalMeaning":"not a single thing accomplished","figurativeMeaning":"to achieve nothing; to be unsuccessful in everything","englishEquivalents":["to get nowhere","to accomplish nothing","to be a failure"],"shortGloss":"to achieve nothing","characters":[{"char":"一","meaning":"one; single"},{"char":"事","meaning":"thing; matter"},{"char":"无","meaning":"without; not"},{"char":"成","meaning":"accomplished; completed"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom 一事无成 is used to describe someone who has not succeeded in any endeavor or has not accomplished anything significant. It is often used to express disappointment or criticism of someone who has not made any progress or achieved any goals.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","complement"],"structure":"verb-object","register":"commonly used in both spoken and written Chinese to describe lack of achievement","connotation":"negative","commonMistakes":"Learners might confuse 一事无成 with similar idioms that imply laziness or lack of effort. However, 一事无成 specifically emphasizes the outcome of having achieved nothing, regardless of effort.","canStandAlone":false},"examples":[{"simplified":"他工作了多年，但仍然一事无成。","english":"He has worked for many years, but still hasn't accomplished anything.","traditional":"他工作了多年，但仍然一事無成。"},{"simplified":"如果不努力，你可能会一事无成。","english":"If you don't work hard, you might end up achieving nothing.","traditional":"如果不努力，你可能會一事無成。"}],"synonyms":["毫无成就","一无所获"],"antonyms":["功成名就","大有作为"],"confusedWith":[{"id":"一无是处","note":"一无是处 means 'without a single redeeming feature', focusing on lack of merit rather than lack of achievement."}],"traditional":"一事無成","pinyinOverride":null},{"id":"yi-dong-bu-dong","simplified":"一动不动","literalMeaning":"one move not move","figurativeMeaning":"to remain completely still or motionless","englishEquivalents":["still as a statue","frozen in place"],"shortGloss":"completely still","characters":[{"char":"一","meaning":"one"},{"char":"动","meaning":"move"},{"char":"不","meaning":"not"},{"char":"动","meaning":"move"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '一动不动' is often used to describe someone or something that remains completely still, as if frozen in place. It is commonly used in everyday language to emphasize a lack of movement or reaction.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"modifier-head","register":"widely used in both spoken and written Chinese","connotation":"neutral","commonMistakes":"Learners sometimes confuse this idiom with others that involve movement, such as '动如脱兔' (moving like a rabbit). '一动不动' specifically emphasizes complete stillness.","canStandAlone":false},"examples":[{"simplified":"他站在那里一动不动，好像被施了魔法。","english":"He stood there completely still, as if he had been enchanted.","traditional":"他站在那裡一動不動，好像被施了魔法。"},{"simplified":"小猫在阳光下睡得很香，一动不动。","english":"The kitten slept soundly in the sunlight, completely still.","traditional":"小貓在陽光下睡得很香，一動不動。"}],"synonyms":["纹丝不动"],"antonyms":["动如脱兔"],"confusedWith":[{"id":"动如脱兔","note":"While '一动不动' means completely still, '动如脱兔' describes rapid movement."}],"traditional":"一動不動","pinyinOverride":null},{"id":"yi-ta-hu-tu","simplified":"一塌糊涂","literalMeaning":"one collapse muddled","figurativeMeaning":"in a complete mess; in a hopelessly chaotic state","englishEquivalents":["a complete mess","in shambles"],"shortGloss":"a complete mess","characters":[{"char":"一","meaning":"one; completely"},{"char":"塌","meaning":"collapse; fall down"},{"char":"糊","meaning":"muddled; confused"},{"char":"涂","meaning":"smear; apply"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom 一塌糊涂 is believed to have originated from colloquial expressions used to describe situations that are completely chaotic or disorganized. The phrase paints a vivid picture of something that has collapsed into a state of confusion, similar to a structure that has fallen and become a jumbled mess.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial","complement"],"structure":"modifier-head","register":"informal, commonly used in both spoken and written Chinese","connotation":"negative","commonMistakes":"Learners often confuse 一塌糊涂 with similar expressions like 乱七八糟, which also means messy but can imply a less severe state of disorder. 一塌糊涂 suggests a more hopeless or irreparable mess.","canStandAlone":false},"examples":[{"simplified":"他的房间总是一塌糊涂，东西到处乱扔。","english":"His room is always a complete mess, with things thrown everywhere.","traditional":"他的房間總是一塌糊塗，東西到處亂扔。"},{"simplified":"项目管理不善，导致整个计划一塌糊涂。","english":"Poor project management led to the entire plan being in shambles.","traditional":"項目管理不善，導致整個計劃一塌糊塗。"}],"synonyms":["乱七八糟","乌烟瘴气"],"antonyms":["井井有条"],"confusedWith":[{"id":"乱七八糟","note":"一塌糊涂 implies a more severe and hopeless state of chaos compared to 乱七八糟."}],"traditional":"一塌糊塗","pinyinOverride":null},{"id":"yi-sheng-bu-keng","simplified":"一声不吭","literalMeaning":"not utter a single sound","figurativeMeaning":"to remain completely silent; not to say a word","englishEquivalents":["not a peep","silent as the grave"],"shortGloss":"remain completely silent","characters":[{"char":"一","meaning":"one; a single"},{"char":"声","meaning":"sound; voice"},{"char":"不","meaning":"not"},{"char":"吭","meaning":"utter a sound"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom 一声不吭 is used to describe a situation where someone remains completely silent, not making any noise or uttering a word. It emphasizes the total absence of sound or speech from a person, often in situations where one might expect a reaction or comment.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"modifier-head","register":"widely used in both spoken and written Chinese","connotation":"neutral","commonMistakes":"Learners might confuse 一声不吭 with similar idioms like 默不作声, which also means to remain silent but can imply a more deliberate choice to stay silent. 一声不吭 emphasizes the absence of any sound or speech.","canStandAlone":false},"examples":[{"simplified":"他整晚一声不吭，似乎在思考什么重要的事情。","english":"He didn't say a word all night, as if he was pondering something important.","traditional":"他整晚一聲不吭，似乎在思考什麼重要的事情。"},{"simplified":"会议上，他一声不吭，显得有些不寻常。","english":"He remained completely silent during the meeting, which was somewhat unusual.","traditional":"會議上，他一聲不吭，顯得有些不尋常。"}],"synonyms":["默不作声"],"antonyms":[],"confusedWith":[{"id":"默不作声","note":"Both mean to remain silent, but 默不作声 can imply a more deliberate choice to stay silent."}],"traditional":"一聲不吭","pinyinOverride":null},{"id":"yi-ru-ji-wang","simplified":"一如既往","literalMeaning":"just as in the past","figurativeMeaning":"to continue as always; to remain consistent","englishEquivalents":["business as usual","same as ever"],"shortGloss":"continue as always","characters":[{"char":"一","meaning":"same"},{"char":"如","meaning":"as"},{"char":"既","meaning":"already"},{"char":"往","meaning":"past"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom 一如既往 is commonly used in modern Chinese to express the idea of continuing in the same manner as before. It is often used to describe consistency in behavior, actions, or situations. The phrase itself does not have a specific story or historical anecdote associated with it, and its origin is considered to be more of a folk expression rather than being tied to a classical text.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["adverbial","predicate"],"structure":"modifier-head","register":"commonly used in both formal and informal contexts","connotation":"neutral","commonMistakes":"Learners might confuse 一如既往 with similar expressions that imply change or difference, such as 与众不同 (different from others). It is important to remember that 一如既往 emphasizes consistency and sameness.","canStandAlone":false},"examples":[{"simplified":"他一如既往地支持我们的工作。","english":"He continues to support our work as always.","traditional":"他一如既往地支持我們的工作。"},{"simplified":"尽管遇到困难，她一如既往地努力工作。","english":"Despite the difficulties, she continues to work hard as always.","traditional":"儘管遇到困難，她一如既往地努力工作。"}],"synonyms":["一成不变"],"antonyms":["与众不同"],"confusedWith":[{"id":"与众不同","note":"与众不同 means 'different from others', which contrasts with 一如既往's emphasis on consistency."}],"traditional":"一如既往","pinyinOverride":null},{"id":"yi-gan-er-jing","simplified":"一干二净","literalMeaning":"completely clean","figurativeMeaning":"thoroughly; completely; entirely","englishEquivalents":["clean as a whistle","spotless","completely"],"shortGloss":"thoroughly; completely","characters":[{"char":"一","meaning":"one"},{"char":"干","meaning":"clean; dry"},{"char":"二","meaning":"two"},{"char":"净","meaning":"clean; pure"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom 一干二净 is used to describe something that is thoroughly cleaned or completely removed. It emphasizes the idea of leaving no trace behind, whether it's dirt, a problem, or any other unwanted element. The phrase is often used to describe thoroughness in both physical and metaphorical contexts.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["adverbial","complement"],"structure":"modifier-head","register":"commonly used in both spoken and written Chinese","connotation":"neutral","commonMistakes":"Learners might confuse 一干二净 with similar idioms that imply thoroughness but in different contexts. It specifically emphasizes cleanliness or complete removal, not just thoroughness in general.","canStandAlone":false},"examples":[{"simplified":"他把房间打扫得一干二净。","english":"He cleaned the room until it was spotless.","traditional":"他把房間打掃得一乾二淨。"},{"simplified":"她把过去的事情忘得一干二净。","english":"She completely forgot about the past events.","traditional":"她把過去的事情忘得一乾二淨。"}],"synonyms":["彻底","干干净净"],"antonyms":[],"confusedWith":[{"id":"干干净净","note":"干干净净 emphasizes cleanliness, while 一干二净 emphasizes thoroughness in removal or absence."}],"traditional":"一乾二淨","pinyinOverride":null},{"id":"yi-ying-ju-quan","simplified":"一应俱全","literalMeaning":"everything is complete","figurativeMeaning":"everything one might need is available; fully equipped","englishEquivalents":["everything one could wish for","all-inclusive","fully equipped"],"shortGloss":"everything is available","characters":[{"char":"一","meaning":"all, every"},{"char":"应","meaning":"to respond to, to meet"},{"char":"俱","meaning":"all, together"},{"char":"全","meaning":"complete, whole"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom 一应俱全 is used to describe a situation where everything one might need is available and nothing is lacking. It is often used to describe well-stocked stores, fully equipped facilities, or comprehensive services. The origin of this idiom is not tied to a specific classical text, but it has been widely used in Chinese literature and speech to convey completeness and thoroughness.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"subject-predicate","register":"commonly used in both written and spoken Chinese","connotation":"positive","commonMistakes":"Learners might confuse this idiom with similar expressions that imply abundance rather than completeness. 一应俱全 emphasizes that all necessary items are present, not just a large quantity of items.","canStandAlone":false},"examples":[{"simplified":"这家超市的商品种类繁多，一应俱全。","english":"This supermarket has a wide variety of goods; everything one might need is available.","traditional":"這家超市的商品種類繁多，一應俱全。"},{"simplified":"他们的服务项目一应俱全，顾客非常满意。","english":"Their range of services is fully equipped, and customers are very satisfied.","traditional":"他們的服務項目一應俱全，顧客非常滿意。"}],"synonyms":["应有尽有"],"antonyms":[],"confusedWith":[{"id":"应有尽有","note":"应有尽有 emphasizes having everything that should be there, while 一应俱全 emphasizes completeness and readiness."}],"traditional":"一應俱全","pinyinOverride":null},{"id":"yi-xin-yi-yi","simplified":"一心一意","literalMeaning":"one heart, one mind","figurativeMeaning":"wholeheartedly; with single-minded devotion","englishEquivalents":["wholeheartedly","with single-minded focus","with undivided attention"],"shortGloss":"wholeheartedly","characters":[{"char":"一","meaning":"one; single"},{"char":"心","meaning":"heart; mind"},{"char":"一","meaning":"one; single"},{"char":"意","meaning":"intention; thought"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom 一心一意 is believed to have originated from the idea of focusing one's entire heart and mind on a single task or goal. It emphasizes the importance of dedication and concentration in achieving success. While its exact origin is unclear, it has been widely used in Chinese literature and speech to express the concept of undivided attention and commitment.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["adverbial","attributive"],"structure":"coordinate","register":"commonly used in both written and spoken Chinese; suitable for formal and informal contexts","connotation":"positive","commonMistakes":"Learners might confuse 一心一意 with similar-sounding idioms that imply different kinds of focus or intent. It's important to remember that 一心一意 specifically emphasizes wholehearted dedication, not just any kind of focus.","canStandAlone":false},"examples":[{"simplified":"他一心一意地投入到工作中。","english":"He devoted himself wholeheartedly to his work.","traditional":"他一心一意地投入到工作中。"},{"simplified":"她一心一意地学习，希望能考上理想的大学。","english":"She studied with single-minded focus, hoping to get into her dream university.","traditional":"她一心一意地學習，希望能考上理想的大學。"}],"synonyms":["全心全意"],"antonyms":["三心二意"],"confusedWith":[{"id":"三心二意","note":"三心二意 means to be indecisive or to have a divided focus, which is the opposite of 一心一意's meaning of wholehearted dedication."}],"traditional":"一心一意","pinyinOverride":null},{"id":"yi-cheng-bu-bian","simplified":"一成不变","literalMeaning":"one established, not change","figurativeMeaning":"to remain unchanged; to be set in stone","englishEquivalents":["set in stone","unchanging","inflexible"],"shortGloss":"unchanging, inflexible","characters":[{"char":"一","meaning":"one"},{"char":"成","meaning":"established"},{"char":"不","meaning":"not"},{"char":"变","meaning":"change"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom 一成不变 describes a situation or condition that remains unchanged over time. It is often used to criticize inflexibility or a lack of adaptation to new circumstances. The phrase suggests that once something is established, it does not change, regardless of new developments or information.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"modifier-head","register":"widely used in both formal and informal contexts","connotation":"negative","commonMistakes":"Learners often confuse 一成不变 with idioms that imply stability in a positive sense. However, 一成不变 usually carries a negative connotation, suggesting rigidity or stubbornness.","canStandAlone":false},"examples":[{"simplified":"他的想法总是一成不变，从来不愿意接受新的观点。","english":"His ideas are always unchanging, and he never wants to accept new viewpoints.","traditional":"他的想法總是一成不變，從來不願意接受新的觀點。"},{"simplified":"在快速变化的时代，一成不变的策略很难成功。","english":"In a rapidly changing era, an inflexible strategy is unlikely to succeed.","traditional":"在快速變化的時代，一成不變的策略很難成功。"}],"synonyms":["墨守成规","固步自封"],"antonyms":["与时俱进","灵活变通"],"confusedWith":[{"id":"墨守成规","note":"Both imply inflexibility, but 墨守成规 specifically refers to adhering to old rules or conventions."}],"traditional":"一成不變","pinyinOverride":null},{"id":"yi-ji-zhi-chang","simplified":"一技之长","literalMeaning":"one skill of length","figurativeMeaning":"to have a special skill or expertise in a particular area","englishEquivalents":["a special skill","an area of expertise"],"shortGloss":"a special skill or expertise","characters":[{"char":"一","meaning":"one"},{"char":"技","meaning":"skill"},{"char":"之","meaning":"of"},{"char":"长","meaning":"length; expertise"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom 一技之长 refers to having a particular skill or expertise in a specific area. It emphasizes the importance of having at least one skill that one excels in, which can be valuable in various situations. The phrase is often used to highlight the significance of specialization and mastery in a certain field.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["subject","object","attributive"],"structure":"modifier-head","register":"widely used in both formal and informal contexts","connotation":"positive","commonMistakes":"Learners might confuse 一技之长 with more general terms for skills, failing to recognize its emphasis on specialization. It specifically refers to a notable or outstanding skill, not just any ability.","canStandAlone":false},"examples":[{"simplified":"他在编程方面有一技之长。","english":"He has a special skill in programming.","traditional":"他在編程方面有一技之長。"},{"simplified":"每个人都应该有一技之长，以便在职场中脱颖而出。","english":"Everyone should have a special skill to stand out in the workplace.","traditional":"每個人都應該有一技之長，以便在職場中脫穎而出。"}],"synonyms":["专长","特长"],"antonyms":[],"confusedWith":[],"traditional":"一技之長","pinyinOverride":null},{"id":"yi-wu-suo-you","simplified":"一无所有","literalMeaning":"one without anything","figurativeMeaning":"to have absolutely nothing; to be utterly destitute","englishEquivalents":["not a penny to one's name","without a stitch","penniless"],"shortGloss":"to have nothing at all","characters":[{"char":"一","meaning":"one; completely"},{"char":"无","meaning":"without; lacking"},{"char":"所","meaning":"anything; what"},{"char":"有","meaning":"have; possess"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom 一无所有 is often used to describe a state of complete poverty or lack of possessions. It conveys the idea of having nothing at all, whether materially or metaphorically. The phrase has been popularized in modern times, notably by the famous Chinese rock song by Cui Jian, which uses the idiom to express a sense of emptiness and longing.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","object"],"structure":"subject-predicate","register":"common in both written and spoken Chinese, often used in informal contexts","connotation":"negative","commonMistakes":"Learners might confuse 一无所有 with idioms that imply lack of specific things, but this idiom refers to a total lack of possessions or resources. It should not be used to describe a temporary or minor lack.","canStandAlone":false},"examples":[{"simplified":"他失去了工作，现在一无所有。","english":"He lost his job and now has absolutely nothing.","traditional":"他失去了工作，現在一無所有。"},{"simplified":"在大城市里，没有家庭支持的人常常感到一无所有。","english":"In big cities, people without family support often feel they have nothing at all.","traditional":"在大城市裡，沒有家庭支持的人常常感到一無所有。"}],"synonyms":["身无分文"],"antonyms":["应有尽有"],"confusedWith":[{"id":"身无分文","note":"身无分文 specifically refers to having no money, while 一无所有 implies having nothing at all."}],"traditional":"一無所有","pinyinOverride":null},{"id":"yi-wu-suo-zhi","simplified":"一无所知","literalMeaning":"not know a single thing","figurativeMeaning":"to be completely ignorant or unaware of something","englishEquivalents":["not have a clue","be in the dark"],"shortGloss":"completely ignorant","characters":[{"char":"一","meaning":"one; single"},{"char":"无","meaning":"not; without"},{"char":"所","meaning":"that which"},{"char":"知","meaning":"know"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom 一无所知 is used to describe a state of complete ignorance or lack of knowledge about a particular subject or situation. It emphasizes that the person knows absolutely nothing about the matter at hand.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","complement"],"structure":"modifier-head","register":"widely used in both formal and informal contexts","connotation":"negative","commonMistakes":"Learners might confuse 一无所知 with idioms that imply having some knowledge but not enough. This idiom specifically means having no knowledge at all.","canStandAlone":false},"examples":[{"simplified":"关于这个项目的细节，我一无所知。","english":"I am completely ignorant of the details of this project.","traditional":"關於這個項目的細節，我一無所知。"},{"simplified":"他对新政策一无所知，所以无法给出意见。","english":"He knows nothing about the new policy, so he can't give an opinion.","traditional":"他對新政策一無所知，所以無法給出意見。"}],"synonyms":["毫不知情"],"antonyms":["了如指掌"],"confusedWith":[{"id":"一知半解","note":"一知半解 means to have a superficial understanding, whereas 一无所知 means to know nothing at all."}],"traditional":"一無所知","pinyinOverride":null},{"id":"yi-gai-er-lun","simplified":"一概而论","literalMeaning":"treat all as one","figurativeMeaning":"to treat different matters as the same; to generalize","englishEquivalents":["to paint with a broad brush","to generalize","to lump together"],"shortGloss":"generalize; treat all as one","characters":[{"char":"一","meaning":"one; same"},{"char":"概","meaning":"general; all"},{"char":"而","meaning":"and; but"},{"char":"论","meaning":"discuss; consider"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom 一概而论 is used to caution against treating all situations or cases as if they are the same, without considering their individual differences. It emphasizes the importance of recognizing diversity and nuance in judgment and decision-making.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["adverbial","complement"],"structure":"modifier-head","register":"widely used in both formal and informal contexts","connotation":"negative","commonMistakes":"Learners often misuse this idiom by applying it to situations where generalization is appropriate. It specifically warns against oversimplification and ignoring important differences.","canStandAlone":false},"examples":[{"simplified":"在处理问题时，我们不能一概而论。","english":"When dealing with problems, we cannot generalize.","traditional":"在處理問題時，我們不能一概而論。"},{"simplified":"每个学生都有自己的特点，不能一概而论。","english":"Each student has their own characteristics and cannot be treated all the same.","traditional":"每個學生都有自己的特點，不能一概而論。"}],"synonyms":["以偏概全","混为一谈"],"antonyms":["区别对待"],"confusedWith":[{"id":"以偏概全","note":"Both involve generalization, but 以偏概全 refers to drawing conclusions from incomplete information, while 一概而论 refers to treating different things as the same."}],"traditional":"一概而論","pinyinOverride":null},{"id":"yi-mao-bu-ba","simplified":"一毛不拔","literalMeaning":"not pull out a single hair","figurativeMeaning":"extremely stingy or miserly","englishEquivalents":["tight-fisted","penny-pinching","not give an inch"],"shortGloss":"extremely stingy","characters":[{"char":"一","meaning":"one"},{"char":"毛","meaning":"hair"},{"char":"不","meaning":"not"},{"char":"拔","meaning":"pull out"}],"origin":{"period":"Warring States period (475–221 BCE)","sourceText":"《韩非子·外储说左上》","sourceTextEnglish":"Han Feizi, Outer Storage, Left Part 1","originalExcerpt":"杨朱之道，不拔一毛而利天下，不为也。","storyEnglish":"The idiom originates from a story in 'Han Feizi' about Yang Zhu, a philosopher who was criticized for his extreme individualism. It was said that Yang Zhu would not even pull out a single hair to benefit the world, illustrating his unwillingness to make even the smallest sacrifice for others. This story was used to criticize those who are excessively selfish or miserly.","historicalFigures":["Yang Zhu"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"modifier-head","register":"literary, but commonly used in both written and spoken Chinese","connotation":"negative","commonMistakes":"Learners often confuse this idiom with others that involve stinginess but may not carry the same extreme connotation. It specifically implies an unwillingness to make even the smallest effort or sacrifice.","canStandAlone":false},"examples":[{"simplified":"他真是一毛不拔，连一分钱都不愿意捐。","english":"He is truly tight-fisted, not willing to donate even a cent.","traditional":"他真是一毛不拔，連一分錢都不願意捐。"},{"simplified":"在公司里，他一毛不拔的名声已经传开了。","english":"In the company, his reputation for being extremely stingy has already spread.","traditional":"在公司裡，他一毛不拔的名聲已經傳開了。"}],"synonyms":["吝啬鬼","铁公鸡"],"antonyms":["慷慨解囊","大方"],"confusedWith":[{"id":"斤斤计较","note":"斤斤计较 refers to being overly concerned with trivial matters, not necessarily about money, while 一毛不拔 specifically refers to extreme stinginess."}],"traditional":"一毛不拔","pinyinOverride":null},{"id":"yi-mu-liao-ran","simplified":"一目了然","literalMeaning":"one glance clearly understood","figurativeMeaning":"obvious at a glance; clear and easy to understand","englishEquivalents":["clear at a glance","plain as day"],"shortGloss":"obvious at a glance","characters":[{"char":"一","meaning":"one"},{"char":"目","meaning":"glance"},{"char":"了","meaning":"clearly"},{"char":"然","meaning":"obvious"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom 一目了然 is used to describe something that is so clear and straightforward that it can be understood at a single glance. It emphasizes the ease with which information or a situation can be comprehended without needing further explanation.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"modifier-head","register":"commonly used in both written and spoken Chinese","connotation":"positive","commonMistakes":"Learners might confuse 一目了然 with more complex idioms that imply deeper understanding rather than immediate clarity. It should not be used to describe situations that require analysis or contemplation.","canStandAlone":false},"examples":[{"simplified":"这个图表设计得很好，一目了然。","english":"This chart is well-designed and clear at a glance.","traditional":"這個圖表設計得很好，一目瞭然。"},{"simplified":"他的意图一目了然，没有任何隐藏的动机。","english":"His intentions are obvious at a glance, with no hidden motives.","traditional":"他的意圖一目瞭然，沒有任何隱藏的動機。"}],"synonyms":["显而易见"],"antonyms":["扑朔迷离"],"confusedWith":[{"id":"显而易见","note":"Both mean something is obvious, but 一目了然 emphasizes visual clarity, while 显而易见 can apply to broader contexts."}],"traditional":"一目瞭然","pinyinOverride":null},{"id":"yi-chou-mo-zhan","simplified":"一筹莫展","literalMeaning":"not able to unfold a single plan","figurativeMeaning":"to be at a loss; unable to find a way out of a difficult situation","englishEquivalents":["at one's wits' end","at a loss","stuck"],"shortGloss":"at a loss; stuck","characters":[{"char":"一","meaning":"one"},{"char":"筹","meaning":"plan; strategy"},{"char":"莫","meaning":"cannot"},{"char":"展","meaning":"unfold; develop"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom 一筹莫展 describes a situation where someone is unable to come up with even a single plan or strategy to solve a problem. It conveys a sense of being stuck or at a loss, unable to make any progress. The phrase likely emerged from the idea of not being able to unfold or present even one筹, which historically referred to a bamboo tally or a plan.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"subject-predicate","register":"widely used in both formal and informal contexts","connotation":"negative","commonMistakes":"Learners often confuse 一筹莫展 with idioms that imply a lack of resources, whereas 一筹莫展 specifically refers to a lack of ideas or strategies. It should not be used to describe situations where the problem is a lack of physical resources.","canStandAlone":false},"examples":[{"simplified":"面对如此复杂的问题，他感到一筹莫展。","english":"Faced with such a complex problem, he felt at a loss.","traditional":"面對如此複雜的問題，他感到一籌莫展。"},{"simplified":"她在项目进展不顺利时一筹莫展。","english":"She was at her wits' end when the project didn't progress smoothly.","traditional":"她在項目進展不順利時一籌莫展。"}],"synonyms":["束手无策","无计可施"],"antonyms":["游刃有余"],"confusedWith":[{"id":"束手无策","note":"Both imply being at a loss, but 束手无策 emphasizes being helpless or unable to act, while 一筹莫展 focuses on the lack of ideas or plans."}],"traditional":"一籌莫展","pinyinOverride":null},{"id":"yi-yan-yi-xing","simplified":"一言一行","literalMeaning":"every word and every action","figurativeMeaning":"one's every word and action; everything one says and does","englishEquivalents":["every word and deed","words and actions"],"shortGloss":"every word and action","characters":[{"char":"一","meaning":"every"},{"char":"言","meaning":"word"},{"char":"一","meaning":"every"},{"char":"行","meaning":"action"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '一言一行' emphasizes the importance of being mindful of both what one says and what one does. It suggests that both words and actions are significant and should be consistent with each other. This idiom is often used to highlight the integrity or character of a person, as their words and actions are seen as a reflection of their true self.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["subject","object","attributive"],"structure":"coordinate","register":"commonly used in both formal and informal contexts","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with others that emphasize speech or action alone. It's important to remember that this idiom specifically highlights the combination of both words and actions.","canStandAlone":false},"examples":[{"simplified":"他的每一句话和每一个行为都体现出他的诚实。","english":"His every word and action reflect his honesty.","traditional":"他的每一句話和每一個行為都體現出他的誠實。"},{"simplified":"在公众场合，我们应该注意自己的一言一行。","english":"In public, we should be mindful of our words and actions.","traditional":"在公眾場合，我們應該注意自己的一言一行。"}],"synonyms":["言行一致"],"antonyms":[],"confusedWith":[{"id":"言行不一","note":"While '一言一行' emphasizes consistency in words and actions, '言行不一' highlights a discrepancy between what one says and does."}],"traditional":"一言一行","pinyinOverride":null},{"id":"yi-yan-bu-fa","simplified":"一言不发","literalMeaning":"not utter a single word","figurativeMeaning":"to remain completely silent","englishEquivalents":["not say a word","keep silent"],"shortGloss":"remain silent","characters":[{"char":"一","meaning":"one"},{"char":"言","meaning":"word"},{"char":"不","meaning":"not"},{"char":"发","meaning":"utter"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '一言不发' is used to describe a situation where someone chooses to remain completely silent, not uttering even a single word. It is often used to emphasize the extent of someone's silence, whether due to anger, contemplation, or other reasons.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"widely used in both spoken and written Chinese","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with similar expressions that imply silence but with different connotations, such as '默不作声' which also means to remain silent but can imply a more passive or resigned silence.","canStandAlone":false},"examples":[{"simplified":"他整场会议一言不发，显得心事重重。","english":"He didn't say a word throughout the entire meeting, looking deeply preoccupied.","traditional":"他整場會議一言不發，顯得心事重重。"},{"simplified":"面对指责，她一言不发，只是默默地听着。","english":"Faced with the accusations, she remained completely silent, just listening quietly.","traditional":"面對指責，她一言不發，只是默默地聽著。"}],"synonyms":["默不作声"],"antonyms":["滔滔不绝"],"confusedWith":[{"id":"默不作声","note":"Both mean to remain silent, but '默不作声' can imply a more passive or resigned silence."}],"traditional":"一言不發","pinyinOverride":null},{"id":"yi-gu-zuo-qi","simplified":"一鼓作气","literalMeaning":"one drumbeat makes energy","figurativeMeaning":"to get something done in one sustained effort","englishEquivalents":["strike while the iron is hot","in one go","all in one breath"],"shortGloss":"do something in one sustained effort","characters":[{"char":"一","meaning":"one"},{"char":"鼓","meaning":"drum"},{"char":"作","meaning":"make"},{"char":"气","meaning":"energy"}],"origin":{"period":"Spring and Autumn period (770–476 BCE)","sourceText":"《左传·庄公十年》","sourceTextEnglish":"Zuo Zhuan, Duke Zhuang, Year 10","originalExcerpt":"夫战，勇气也。一鼓作气，再而衰，三而竭。","storyEnglish":"The idiom comes from a passage in the historical text 'Zuo Zhuan', which describes a battle strategy. It emphasizes the importance of using the initial momentum and energy to achieve victory. The idea is that the first strike carries the most energy and enthusiasm, which diminishes with each subsequent attempt.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["adverbial","complement"],"structure":"modifier-head","register":"literary, but very widely understood and used in ordinary speech","connotation":"positive","commonMistakes":"Learners might confuse this idiom with others that involve persistence over time, but 一鼓作气 specifically emphasizes completing something in one continuous effort without stopping.","canStandAlone":false},"examples":[{"simplified":"我们要一鼓作气完成这个项目。","english":"We need to complete this project in one go.","traditional":"我們要一鼓作氣完成這個項目。"},{"simplified":"他一鼓作气，把所有的作业都做完了。","english":"He finished all his homework in one sustained effort.","traditional":"他一鼓作氣，把所有的作業都做完了。"}],"synonyms":["一气呵成"],"antonyms":[],"confusedWith":[{"id":"持之以恒","note":"一鼓作气 emphasizes completing something in one go, while 持之以恒 focuses on persistence over time."}],"traditional":"一鼓作氣","pinyinOverride":null},{"id":"qi-zui-ba-she","simplified":"七嘴八舌","literalMeaning":"seven mouths and eight tongues","figurativeMeaning":"everyone talking at once; a lively discussion with many people speaking","englishEquivalents":["talking all at once","a cacophony of voices"],"shortGloss":"everyone talking at once","characters":[{"char":"七","meaning":"seven"},{"char":"嘴","meaning":"mouths"},{"char":"八","meaning":"eight"},{"char":"舌","meaning":"tongues"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '七嘴八舌' is used to describe a situation where many people are talking at once, creating a lively and noisy discussion. The numbers seven and eight are used symbolically to represent a large, indefinite number of people involved in the conversation.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["adverbial","attributive"],"structure":"coordinate","register":"colloquial and widely used in both spoken and written Chinese","connotation":"neutral","commonMistakes":"Learners sometimes confuse this idiom with others that involve numbers and body parts, but '七嘴八舌' specifically refers to a noisy, multi-person discussion. It should not be used to describe a situation with only one or two people talking.","canStandAlone":false},"examples":[{"simplified":"在会议上，大家七嘴八舌地讨论着这个问题。","english":"At the meeting, everyone was talking all at once about the issue.","traditional":"在會議上，大家七嘴八舌地討論著這個問題。"},{"simplified":"孩子们七嘴八舌地分享他们的假期经历。","english":"The children were all talking at once, sharing their holiday experiences.","traditional":"孩子們七嘴八舌地分享他們的假期經歷。"}],"synonyms":["人声鼎沸"],"antonyms":["鸦雀无声"],"confusedWith":[{"id":"人多嘴杂","note":"While both idioms involve many people talking, '人多嘴杂' emphasizes the confusion and disorder of the conversation, whereas '七嘴八舌' focuses on the lively and noisy aspect."}],"traditional":"七嘴八舌","pinyinOverride":null},{"id":"wan-wu-yi-shi","simplified":"万无一失","literalMeaning":"ten thousand without one mistake","figurativeMeaning":"absolutely safe; no risk of error","englishEquivalents":["foolproof","surefire","can't go wrong"],"shortGloss":"absolutely safe and reliable","characters":[{"char":"万","meaning":"ten thousand; myriad"},{"char":"无","meaning":"without; not have"},{"char":"一","meaning":"one"},{"char":"失","meaning":"mistake; error"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '万无一失' is believed to have originated from the idea of ensuring that something is so thoroughly planned and executed that there is virtually no chance of failure. It emphasizes the importance of meticulous preparation and attention to detail to achieve a foolproof outcome.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive","adverbial"],"structure":"modifier-head","register":"widely used in both formal and informal contexts","connotation":"positive","commonMistakes":"Learners might confuse this idiom with similar expressions that imply a high degree of certainty but not absolute certainty. '万无一失' implies a guarantee of success, whereas other expressions might only suggest a high likelihood.","canStandAlone":false},"examples":[{"simplified":"这次的计划经过反复推敲，万无一失。","english":"This plan has been thoroughly scrutinized and is foolproof.","traditional":"這次的計劃經過反覆推敲，萬無一失。"},{"simplified":"他做事总是考虑周到，确保万无一失。","english":"He always considers everything carefully to ensure nothing can go wrong.","traditional":"他做事總是考慮周到，確保萬無一失。"}],"synonyms":["十拿九稳"],"antonyms":["漏洞百出"],"confusedWith":[{"id":"十拿九稳","note":"While both imply confidence in success, '十拿九稳' suggests high probability, not absolute certainty."}],"traditional":"萬無一失","pinyinOverride":null},{"id":"san-fan-wu-ci","simplified":"三番五次","literalMeaning":"three times, five times","figurativeMeaning":"repeatedly; over and over again","englishEquivalents":["time and again","over and over","repeatedly"],"shortGloss":"repeatedly","characters":[{"char":"三","meaning":"three"},{"char":"番","meaning":"times; occurrences"},{"char":"五","meaning":"five"},{"char":"次","meaning":"times; occasions"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '三番五次' is used to describe actions or events that occur repeatedly. The numbers three and five are used here not to indicate specific counts, but rather to emphasize frequency and repetition. This expression is commonly used in both spoken and written Chinese to stress that something happens many times.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["adverbial"],"structure":"coordinate","register":"commonly used in both spoken and written Chinese","connotation":"neutral","commonMistakes":"Learners might confuse '三番五次' with '三三两两' which means 'in twos and threes' and refers to small groups of people. '三番五次' specifically emphasizes repetition, not grouping.","canStandAlone":false},"examples":[{"simplified":"他三番五次地提醒我不要忘记带钥匙。","english":"He reminded me over and over again not to forget my keys.","traditional":"他三番五次地提醒我不要忘記帶鑰匙。"},{"simplified":"老师三番五次地强调这个问题的重要性。","english":"The teacher repeatedly emphasized the importance of this issue.","traditional":"老師三番五次地強調這個問題的重要性。"}],"synonyms":["反复无常"],"antonyms":[],"confusedWith":[{"id":"三三两两","note":"三三两两 refers to small groups of people, not repetition."}],"traditional":"三番五次","pinyinOverride":null},{"id":"bu-liao-liao-zhi","simplified":"不了了之","literalMeaning":"not understand and end","figurativeMeaning":"to settle a matter by leaving it unresolved; to let something drift without a conclusion","englishEquivalents":["leave unfinished","let it go unresolved","sweep under the rug"],"shortGloss":"leave unresolved","characters":[{"char":"不","meaning":"not"},{"char":"了","meaning":"understand; finish"},{"char":"了","meaning":"understand; finish"},{"char":"之","meaning":"it; this"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '不了了之' is often used to describe situations where issues or tasks are left unresolved, often due to neglect or a decision to avoid dealing with them. The phrase suggests a lack of closure or a deliberate choice to let matters remain unfinished.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"commonly used in both written and spoken Chinese","connotation":"negative","commonMistakes":"Learners often confuse '不了了之' with '不了了事', which also means leaving something unresolved but is less commonly used. '不了了之' specifically implies a deliberate or negligent failure to conclude.","canStandAlone":false},"examples":[{"simplified":"这件事情最后不了了之，没有人再提起。","english":"The matter was ultimately left unresolved, and no one mentioned it again.","traditional":"這件事情最後不了了之，沒有人再提起。"},{"simplified":"他们的争论不了了之，谁也没有说服谁。","english":"Their argument ended without resolution, with neither side convincing the other.","traditional":"他們的爭論不了了之，誰也沒有說服誰。"}],"synonyms":[],"antonyms":["一锤定音"],"confusedWith":[{"id":"不了了事","note":"Both mean leaving something unresolved, but '不了了之' is more commonly used and implies a more deliberate neglect."}],"traditional":"不了了之","pinyinOverride":null},{"id":"bu-yi-le-hu","simplified":"不亦乐乎","literalMeaning":"not also joyful","figurativeMeaning":"extremely; exceedingly; to the utmost degree","englishEquivalents":["to the nth degree","to the max"],"shortGloss":"extremely; exceedingly","characters":[{"char":"不","meaning":"not"},{"char":"亦","meaning":"also"},{"char":"乐","meaning":"joyful; happy"},{"char":"乎","meaning":"an exclamatory particle, expressing surprise or emphasis"}],"origin":{"period":"Warring States period (475–221 BCE)","sourceText":"《论语·学而》","sourceTextEnglish":"The Analects of Confucius, Chapter Xue Er","originalExcerpt":"学而时习之，不亦说乎？","storyEnglish":"This idiom originates from Confucius's Analects, where Confucius discusses the joy of learning and practicing what one has learned. The phrase '不亦乐乎' is derived from the rhetorical question '学而时习之，不亦说乎？' which means 'Isn't it a pleasure to learn and practice what you have learned?' Over time, '不亦乐乎' evolved to mean doing something to an extreme or utmost degree.","historicalFigures":["Confucius"],"relatedIdiomsFromSameSource":["学而不厌","温故知新"]},"usage":{"grammaticalRole":["adverbial","complement"],"structure":"modifier-head","register":"literary, but commonly used in both written and spoken Chinese","connotation":"neutral","commonMistakes":"Learners often confuse '不亦乐乎' with expressions that simply mean 'happy' or 'joyful'. However, it is used to emphasize the extreme degree of an action or state, not just happiness.","canStandAlone":false},"examples":[{"simplified":"他工作起来总是干得不亦乐乎。","english":"He always works to the utmost degree.","traditional":"他工作起來總是幹得不亦樂乎。"},{"simplified":"孩子们在游乐场玩得不亦乐乎。","english":"The children played at the amusement park to the max.","traditional":"孩子們在遊樂場玩得不亦樂乎。"}],"synonyms":["极其","非常"],"antonyms":[],"confusedWith":[{"id":"乐不可支","note":"While '乐不可支' means being so happy that one cannot control oneself, '不亦乐乎' emphasizes doing something to an extreme degree, not necessarily related to happiness."}],"traditional":"不亦樂乎","pinyinOverride":null},{"id":"bu-yi-wei-ran","simplified":"不以为然","literalMeaning":"not consider it so","figurativeMeaning":"to disapprove or disagree; to not think much of something","englishEquivalents":["to not think much of","to disagree","to disapprove"],"shortGloss":"disapprove or disagree","characters":[{"char":"不","meaning":"not"},{"char":"以","meaning":"consider"},{"char":"为","meaning":"to be"},{"char":"然","meaning":"so; thus"}],"origin":{"period":"Han Dynasty (206 BCE – 220 CE)","sourceText":"《汉书·王吉传》","sourceTextEnglish":"Book of Han, Biography of Wang Ji","originalExcerpt":"吉以为不然。","storyEnglish":"The idiom originates from the 'Book of Han', where it describes Wang Ji's reaction to a certain situation. Wang Ji did not agree with the prevailing opinion and expressed his disagreement by saying he did not consider it to be so.","historicalFigures":["Wang Ji"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"widely used in both formal and informal contexts","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with '不以为意', which means 'to not take something seriously'. '不以为然' specifically implies disagreement or disapproval, not just a lack of concern.","canStandAlone":false},"examples":[{"simplified":"他对这个计划不以为然，认为还有很多问题需要解决。","english":"He did not think much of this plan, believing there were still many issues to resolve.","traditional":"他對這個計劃不以為然，認為還有很多問題需要解決。"},{"simplified":"虽然大家都赞同这个观点，但她却不以为然。","english":"Although everyone agreed with the opinion, she did not think much of it.","traditional":"雖然大家都贊同這個觀點，但她卻不以為然。"}],"synonyms":["不以为意"],"antonyms":[],"confusedWith":[{"id":"不以为意","note":"不以为意 means 'to not take something seriously', while 不以为然 implies disagreement or disapproval."}],"traditional":"不以為然","pinyinOverride":null},{"id":"bu-jia-si-suo","simplified":"不假思索","literalMeaning":"not use thinking","figurativeMeaning":"to react or respond without thinking; to act or speak without hesitation","englishEquivalents":["without a second thought","off the top of one's head"],"shortGloss":"without thinking","characters":[{"char":"不","meaning":"not"},{"char":"假","meaning":"use; employ"},{"char":"思","meaning":"think"},{"char":"索","meaning":"search; ponder"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '不假思索' describes the act of doing something without pausing to think. It is often used to highlight quick, instinctive actions or responses, suggesting a level of confidence or familiarity that allows one to act immediately.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["adverbial"],"structure":"modifier-head","register":"commonly used in both spoken and written Chinese","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with others that imply thoughtlessness or carelessness. '不假思索' implies quickness, not necessarily a lack of care.","canStandAlone":false},"examples":[{"simplified":"他不假思索地回答了问题。","english":"He answered the question without a second thought.","traditional":"他不假思索地回答了問題。"},{"simplified":"她不假思索地做出了决定。","english":"She made the decision without hesitation.","traditional":"她不假思索地做出了決定。"}],"synonyms":[],"antonyms":["深思熟虑"],"confusedWith":[{"id":"草率","note":"草率 implies carelessness or rashness, while 不假思索 implies quickness without necessarily being careless."}],"traditional":"不假思索","pinyinOverride":null},{"id":"bu-yan-qi-fan","simplified":"不厌其烦","literalMeaning":"not tire of the trouble","figurativeMeaning":"to be very patient and willing to take the trouble to do something","englishEquivalents":["go the extra mile","take pains","be patient"],"shortGloss":"patiently take the trouble","characters":[{"char":"不","meaning":"not"},{"char":"厌","meaning":"tire of"},{"char":"其","meaning":"its"},{"char":"烦","meaning":"trouble"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '不厌其烦' is used to describe someone who is willing to take the time and effort to do something, even if it involves a lot of trouble or repetition. It emphasizes patience and dedication, often in helping others or explaining something multiple times.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"modifier-head","register":"widely used in both formal and informal contexts","connotation":"positive","commonMistakes":"Learners often confuse this idiom with '不胜其烦', which means 'overwhelmed by the trouble'. '不厌其烦' has a positive connotation of patience, while '不胜其烦' has a negative connotation of being bothered.","canStandAlone":false},"examples":[{"simplified":"他不厌其烦地解释了好几遍。","english":"He patiently explained it several times.","traditional":"他不厭其煩地解釋了好幾遍。"},{"simplified":"老师不厌其烦地回答学生的问题。","english":"The teacher patiently answered the students' questions.","traditional":"老師不厭其煩地回答學生的問題。"}],"synonyms":["耐心细致","尽心尽力"],"antonyms":["不胜其烦"],"confusedWith":[{"id":"不胜其烦","note":"不胜其烦 means being overwhelmed by trouble, whereas 不厌其烦 means being patient despite trouble."}],"traditional":"不厭其煩","pinyinOverride":null},{"id":"bu-ke-si-yi","simplified":"不可思议","literalMeaning":"cannot be thought of or comprehended","figurativeMeaning":"inconceivable; unimaginable; beyond comprehension","englishEquivalents":["beyond belief","unbelievable","incredible"],"shortGloss":"inconceivable; beyond belief","characters":[{"char":"不","meaning":"not"},{"char":"可","meaning":"can; able to"},{"char":"思","meaning":"think; consider"},{"char":"议","meaning":"discuss; deliberate"}],"origin":{"period":"Buddhist texts in the Tang Dynasty (618–907)","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom 不可思议 originally comes from Buddhist texts, where it was used to describe the profound and incomprehensible nature of certain spiritual truths. Over time, it entered common usage in Chinese to describe anything that is beyond ordinary understanding or belief.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive","adverbial"],"structure":"modifier-head","register":"widely used in both formal and informal contexts","connotation":"neutral","commonMistakes":"Learners might confuse 不可思议 with similar expressions like 难以置信, which also means 'hard to believe'. However, 不可思议 often carries a sense of wonder or amazement, rather than just skepticism.","canStandAlone":false},"examples":[{"simplified":"他的成功真是不可思议。","english":"His success is truly beyond belief.","traditional":"他的成功真是不可思議。"},{"simplified":"这个地方的美丽是不可思议的。","english":"The beauty of this place is unimaginable.","traditional":"這個地方的美麗是不可思議的。"}],"synonyms":["难以置信"],"antonyms":[],"confusedWith":[{"id":"难以置信","note":"不可思议 often implies amazement, while 难以置信 can imply doubt or skepticism."}],"traditional":"不可思議","pinyinOverride":null},{"id":"bu-ke-huo-que","simplified":"不可或缺","literalMeaning":"cannot be or lack","figurativeMeaning":"indispensable; absolutely necessary","englishEquivalents":["indispensable","essential","cannot do without"],"shortGloss":"indispensable","characters":[{"char":"不","meaning":"not"},{"char":"可","meaning":"can"},{"char":"或","meaning":"or"},{"char":"缺","meaning":"lack"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '不可或缺' is used to describe something that is absolutely necessary and cannot be done without. It emphasizes the essential nature of an element or component in a particular context. The phrase has been widely used in modern Chinese to express the idea of indispensability.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"modifier-head","register":"widely used in both formal and informal contexts","connotation":"neutral","commonMistakes":"Learners often confuse '不可或缺' with '可有可无', which means 'dispensable' or 'not essential'. It's important to note that '不可或缺' emphasizes necessity, while '可有可无' suggests something is optional.","canStandAlone":false},"examples":[{"simplified":"水是生命中不可或缺的资源。","english":"Water is an indispensable resource for life.","traditional":"水是生命中不可或缺的資源。"},{"simplified":"在团队合作中，沟通是不可或缺的。","english":"In teamwork, communication is indispensable.","traditional":"在團隊合作中，溝通是不可或缺的。"}],"synonyms":["必不可少"],"antonyms":["可有可无"],"confusedWith":[{"id":"可有可无","note":"'可有可无' means something is optional or not essential, which is the opposite of '不可或缺'."}],"traditional":"不可或缺","pinyinOverride":null},{"id":"bu-de-er-zhi","simplified":"不得而知","literalMeaning":"cannot obtain and know","figurativeMeaning":"unable to find out; unknown","englishEquivalents":["unknown","can't be determined"],"shortGloss":"unknown; can't find out","characters":[{"char":"不","meaning":"not"},{"char":"得","meaning":"can obtain"},{"char":"而","meaning":"and"},{"char":"知","meaning":"know"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '不得而知' is used to express the idea that something cannot be known or is beyond one's ability to find out. It is often used when information is unavailable or when the answer to a question is not clear.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"neutral and commonly used in both written and spoken Chinese","connotation":"neutral","commonMistakes":"Learners sometimes misuse this idiom by using it in contexts where information is actually available but simply hasn't been sought out. It should be used when the information is genuinely inaccessible.","canStandAlone":false},"examples":[{"simplified":"他去了哪里，我不得而知。","english":"Where he went, I do not know.","traditional":"他去了哪裡，我不得而知。"},{"simplified":"事情的真相至今不得而知。","english":"The truth of the matter is still unknown.","traditional":"事情的真相至今不得而知。"}],"synonyms":["无从得知"],"antonyms":[],"confusedWith":[],"traditional":"不得而知","pinyinOverride":null},{"id":"bu-zhe-bu-kou","simplified":"不折不扣","literalMeaning":"not bend not deduct","figurativeMeaning":"thorough; to the letter; without any discount","englishEquivalents":["to the letter","thorough","without a doubt"],"shortGloss":"thorough; to the letter","characters":[{"char":"不","meaning":"not"},{"char":"折","meaning":"bend"},{"char":"不","meaning":"not"},{"char":"扣","meaning":"deduct"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '不折不扣' is believed to have originated from commercial practices where merchants would promise to deliver goods or services without any reduction in quality or quantity. It emphasizes the idea of fulfilling a promise completely and without compromise.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["attributive","adverbial"],"structure":"coordinate","register":"widely used in both formal and informal contexts","connotation":"neutral","commonMistakes":"Learners often confuse '不折不扣' with similar expressions that imply partial fulfillment. It is important to remember that this idiom emphasizes complete and thorough fulfillment.","canStandAlone":false},"examples":[{"simplified":"他是一个不折不扣的好人。","english":"He is a thoroughly good person.","traditional":"他是一個不折不扣的好人。"},{"simplified":"我们需要不折不扣地完成这个任务。","english":"We need to complete this task thoroughly.","traditional":"我們需要不折不扣地完成這個任務。"}],"synonyms":["彻头彻尾","完完全全"],"antonyms":["敷衍了事"],"confusedWith":[{"id":"敷衍了事","note":"不折不扣 means thorough and complete, while 敷衍了事 means to do something perfunctorily or carelessly."}],"traditional":"不折不扣","pinyinOverride":null},{"id":"bu-zheng-zhi-feng","simplified":"不正之风","literalMeaning":"improper wind","figurativeMeaning":"unhealthy trend or practice","englishEquivalents":["unwholesome trend","corrupt practice"],"shortGloss":"unhealthy trend or practice","characters":[{"char":"不","meaning":"not"},{"char":"正","meaning":"proper; correct"},{"char":"之","meaning":"of"},{"char":"风","meaning":"wind; trend"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '不正之风' refers to practices or trends that are considered unhealthy, improper, or corrupt. It is often used in the context of criticizing societal or organizational behaviors that deviate from accepted norms or ethics.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["attributive","object"],"structure":"modifier-head","register":"commonly used in both formal and informal contexts to describe negative trends or practices","connotation":"negative","commonMistakes":"Learners might confuse this idiom with more neutral terms for trends or practices, not realizing its negative connotation. It specifically implies a deviation from what is considered proper or ethical.","canStandAlone":false},"examples":[{"simplified":"我们必须抵制不正之风，维护社会的正义。","english":"We must resist unhealthy trends and uphold social justice.","traditional":"我們必須抵制不正之風，維護社會的正義。"},{"simplified":"这种不正之风在公司里已经持续了很久。","english":"This unhealthy practice has been ongoing in the company for a long time.","traditional":"這種不正之風在公司裡已經持續了很久。"}],"synonyms":["歪风邪气"],"antonyms":["正气凛然"],"confusedWith":[],"traditional":"不正之風","pinyinOverride":null},{"id":"bu-you-zi-zhu","simplified":"不由自主","literalMeaning":"not by one's own will","figurativeMeaning":"involuntarily; unable to control oneself","englishEquivalents":["against one's will","uncontrollably"],"shortGloss":"involuntarily; uncontrollably","characters":[{"char":"不","meaning":"not"},{"char":"由","meaning":"by"},{"char":"自","meaning":"oneself"},{"char":"主","meaning":"master; control"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '不由自主' describes a situation where someone acts without conscious control or intention. It is often used to express actions or reactions that occur spontaneously or involuntarily, without deliberate decision-making.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["adverbial","complement"],"structure":"modifier-head","register":"commonly used in both spoken and written Chinese","connotation":"neutral","commonMistakes":"Learners often confuse '不由自主' with '情不自禁', which also means to act involuntarily but often carries a more emotional or passionate connotation. '不由自主' is more neutral and can apply to a wider range of involuntary actions.","canStandAlone":false},"examples":[{"simplified":"听到这个消息，他不由自主地笑了。","english":"Upon hearing the news, he involuntarily laughed.","traditional":"聽到這個消息，他不由自主地笑了。"},{"simplified":"她不由自主地流下了眼泪。","english":"She couldn't help but shed tears.","traditional":"她不由自主地流下了眼淚。"}],"synonyms":["情不自禁"],"antonyms":[],"confusedWith":[{"id":"情不自禁","note":"While both idioms describe involuntary actions, '情不自禁' often implies an emotional response, whereas '不由自主' is more general and neutral."}],"traditional":"不由自主","pinyinOverride":null},{"id":"bu-xiang-shang-xia","simplified":"不相上下","literalMeaning":"not each other up down","figurativeMeaning":"equally matched; on par with each other","englishEquivalents":["neck and neck","on par","evenly matched"],"shortGloss":"equally matched","characters":[{"char":"不","meaning":"not"},{"char":"相","meaning":"each other"},{"char":"上","meaning":"up"},{"char":"下","meaning":"down"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '不相上下' is used to describe a situation where two parties are so evenly matched that neither has a clear advantage over the other. It conveys the idea that neither side is superior or inferior, and they are on equal footing.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"modifier-head","register":"commonly used in both spoken and written Chinese","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with '平分秋色', which also means evenly matched but often implies a division of honors or benefits. '不相上下' focuses more on the equality of ability or quality.","canStandAlone":false},"examples":[{"simplified":"这两支球队实力不相上下，比赛一定会很精彩。","english":"These two teams are equally matched in strength, so the game will definitely be exciting.","traditional":"這兩支球隊實力不相上下，比賽一定會很精彩。"},{"simplified":"他们在这场辩论中不相上下，观众很难判断谁更胜一筹。","english":"They were evenly matched in this debate, making it difficult for the audience to determine who was superior.","traditional":"他們在這場辯論中不相上下，觀眾很難判斷誰更勝一籌。"}],"synonyms":["旗鼓相当"],"antonyms":["天壤之别"],"confusedWith":[{"id":"平分秋色","note":"While both idioms imply equality, '平分秋色' often suggests a division of honors or benefits, whereas '不相上下' emphasizes equal ability or quality."}],"traditional":"不相上下","pinyinOverride":null},{"id":"bu-zhi-bu-jue","simplified":"不知不觉","literalMeaning":"not know not feel","figurativeMeaning":"unconsciously; without realizing it","englishEquivalents":["before you know it","without noticing","unawares"],"shortGloss":"unconsciously, without realizing","characters":[{"char":"不","meaning":"not"},{"char":"知","meaning":"know"},{"char":"不","meaning":"not"},{"char":"觉","meaning":"feel, perceive"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '不知不觉' is commonly used to describe a situation where something happens without one's awareness or conscious realization. It reflects the idea of time passing or changes occurring subtly and unnoticed.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["adverbial"],"structure":"coordinate","register":"widely used in both spoken and written Chinese","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with expressions that imply intentional ignorance, but '不知不觉' specifically refers to a lack of awareness without any deliberate action.","canStandAlone":false},"examples":[{"simplified":"时间过得真快，不知不觉就到了年底。","english":"Time flies; before you know it, it's the end of the year.","traditional":"時間過得真快，不知不覺就到了年底。"},{"simplified":"他不知不觉地就爱上了这个城市。","english":"He fell in love with the city without even realizing it.","traditional":"他不知不覺地就愛上了這個城市。"}],"synonyms":[],"antonyms":[],"confusedWith":[],"traditional":"不知不覺","pinyinOverride":null},{"id":"bu-zhi-suo-cuo","simplified":"不知所措","literalMeaning":"not know where to place","figurativeMeaning":"to be at a loss; to not know what to do","englishEquivalents":["at a loss","bewildered","not know which way to turn"],"shortGloss":"at a loss; bewildered","characters":[{"char":"不","meaning":"not"},{"char":"知","meaning":"know"},{"char":"所","meaning":"where"},{"char":"措","meaning":"to place; to put"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '不知所措' describes a situation where someone is so confused or overwhelmed that they do not know what action to take. It conveys a sense of being bewildered or at a loss, often in the face of unexpected or challenging circumstances.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","complement"],"structure":"verb-object","register":"commonly used in both written and spoken Chinese","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with expressions that imply a lack of knowledge or information, rather than a state of confusion or indecision. It specifically refers to being unsure of what action to take, not just lacking knowledge.","canStandAlone":false},"examples":[{"simplified":"听到这个消息后，他感到不知所措。","english":"After hearing the news, he felt at a loss.","traditional":"聽到這個消息後，他感到不知所措。"},{"simplified":"面对突如其来的变化，她一时不知所措。","english":"Faced with the sudden change, she was momentarily bewildered.","traditional":"面對突如其來的變化，她一時不知所措。"}],"synonyms":["手足无措"],"antonyms":["胸有成竹"],"confusedWith":[{"id":"无所适从","note":"Both express confusion, but 无所适从 emphasizes not knowing whom to follow or what advice to take."}],"traditional":"不知所措","pinyinOverride":null},{"id":"bu-yue-er-tong","simplified":"不约而同","literalMeaning":"without prior agreement, yet in unison","figurativeMeaning":"to do something in unison or coincidentally without prior arrangement","englishEquivalents":["great minds think alike","in sync","coincidentally"],"shortGloss":"act in unison without prior arrangement","characters":[{"char":"不","meaning":"not"},{"char":"约","meaning":"arrange, agree"},{"char":"而","meaning":"yet, but"},{"char":"同","meaning":"same, together"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom 不约而同 describes a situation where people do the same thing or have the same thought without having planned it together. It emphasizes the spontaneous and coincidental nature of the action or thought. The phrase is often used to highlight the harmony or similarity in thinking among individuals or groups.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"modifier-head","register":"widely used in both spoken and written Chinese","connotation":"neutral","commonMistakes":"Learners might confuse 不约而同 with idioms that imply deliberate coordination or planning. This idiom specifically emphasizes the lack of prior arrangement.","canStandAlone":false},"examples":[{"simplified":"他们不约而同地选择了同一家餐厅。","english":"They coincidentally chose the same restaurant.","traditional":"他們不約而同地選擇了同一家餐廳。"},{"simplified":"在会议上，大家不约而同地提出了相同的建议。","english":"At the meeting, everyone coincidentally made the same suggestion.","traditional":"在會議上，大家不約而同地提出了相同的建議。"}],"synonyms":["异口同声"],"antonyms":[],"confusedWith":[{"id":"心有灵犀一点通","note":"心有灵犀 implies a deep mutual understanding, while 不约而同 emphasizes coincidental actions without prior agreement."}],"traditional":"不約而同","pinyinOverride":null},{"id":"bu-yi-er-fei","simplified":"不翼而飞","literalMeaning":"without wings but flies away","figurativeMeaning":"to disappear without a trace; to vanish mysteriously","englishEquivalents":["vanish into thin air","disappear without a trace"],"shortGloss":"vanish mysteriously","characters":[{"char":"不","meaning":"not"},{"char":"翼","meaning":"wings"},{"char":"而","meaning":"and yet"},{"char":"飞","meaning":"fly"}],"origin":{"period":"Tang dynasty (618–907 CE)","sourceText":"《新唐书·李密传》","sourceTextEnglish":"New Book of Tang, Biography of Li Mi","originalExcerpt":"物不翼而飞，皆为盗贼所窃。","storyEnglish":"The idiom originates from a story in the 'New Book of Tang' about Li Mi, a Tang dynasty official. It describes how objects seemed to disappear mysteriously, as if they had flown away without wings, due to thefts by bandits. This vivid description led to the idiom being used to describe anything that vanishes inexplicably.","historicalFigures":["Li Mi"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"modifier-head","register":"widely used in both written and spoken Chinese","connotation":"neutral","commonMistakes":"Learners often confuse this idiom with similar expressions involving disappearance, but it specifically implies a mysterious or sudden vanishing, not just any disappearance.","canStandAlone":false},"examples":[{"simplified":"我的钱包不翼而飞了，我明明放在桌子上的。","english":"My wallet has vanished into thin air; I clearly left it on the table.","traditional":"我的錢包不翼而飛了，我明明放在桌子上的。"},{"simplified":"文件不翼而飞，大家都很着急。","english":"The document disappeared without a trace, and everyone was very anxious.","traditional":"文件不翼而飛，大家都很著急。"}],"synonyms":["无影无踪"],"antonyms":[],"confusedWith":[{"id":"无影无踪","note":"无影无踪 means 'without a trace', often used interchangeably, but 不翼而飞 emphasizes the mysterious aspect of disappearance."}],"traditional":"不翼而飛","pinyinOverride":null},{"id":"bu-chi-xia-wen","simplified":"不耻下问","literalMeaning":"not ashamed to ask those below","figurativeMeaning":"not ashamed to ask for advice from those of lower status or with less experience","englishEquivalents":["not too proud to ask questions","humble enough to learn from anyone"],"shortGloss":"humble enough to ask for advice","characters":[{"char":"不","meaning":"not"},{"char":"耻","meaning":"ashamed"},{"char":"下","meaning":"below, lower status"},{"char":"问","meaning":"ask"}],"origin":{"period":"Warring States period (475–221 BCE)","sourceText":"《论语·公冶长》","sourceTextEnglish":"Analects of Confucius, Gongye Chang chapter","originalExcerpt":"敏而好学，不耻下问，是以谓之‘文’也。","storyEnglish":"The idiom comes from the Analects of Confucius, where it is said that a person who is intelligent and loves learning, and is not ashamed to ask those of lower status for advice, is called 'cultured'. This highlights the virtue of humility and the willingness to learn from all sources, regardless of their social standing.","historicalFigures":["Confucius"],"relatedIdiomsFromSameSource":["学而不厌","诲人不倦"]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"modifier-head","register":"literary, but very widely understood and used in ordinary speech","connotation":"positive","commonMistakes":"Learners might mistakenly use this idiom to imply asking questions in general, but it specifically emphasizes the humility in asking those of lower status or less experience.","canStandAlone":false},"examples":[{"simplified":"他总是不耻下问，所以进步很快。","english":"He is never ashamed to ask those below him, so he progresses quickly.","traditional":"他總是不恥下問，所以進步很快。"},{"simplified":"在学习上，不耻下问是一种美德。","english":"In learning, being humble enough to ask for advice is a virtue.","traditional":"在學習上，不恥下問是一種美德。"}],"synonyms":["虚心请教"],"antonyms":["自以为是"],"confusedWith":[{"id":"自以为是","note":"自以为是 means being self-righteous or conceited, which is the opposite of the humility emphasized in 不耻下问."}],"traditional":"不恥下問","pinyinOverride":null},{"id":"bu-yan-er-yu","simplified":"不言而喻","literalMeaning":"not speak and yet understood","figurativeMeaning":"obvious without needing explanation","englishEquivalents":["it goes without saying","self-evident"],"shortGloss":"obvious without saying","characters":[{"char":"不","meaning":"not"},{"char":"言","meaning":"speak"},{"char":"而","meaning":"and yet"},{"char":"喻","meaning":"understood"}],"origin":{"period":"Han Dynasty (206 BCE – 220 CE)","sourceText":"《韩非子·解老》","sourceTextEnglish":"Han Feizi, Chapter Jie Lao","originalExcerpt":"不言而信，不比而周，不为而成。","storyEnglish":"The idiom originates from the philosophical writings of Han Feizi, a prominent legalist thinker during the Han Dynasty. In his work, he discusses concepts that are so clear and self-evident that they do not require verbal explanation. The phrase '不言而喻' captures the idea of something being understood without needing to be spoken.","historicalFigures":["Han Feizi"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"modifier-head","register":"widely used in both formal and informal contexts","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with similar phrases that imply something is 'obvious' but with a negative connotation. '不言而喻' is neutral and does not carry any negative implication.","canStandAlone":false},"examples":[{"simplified":"他的成功不言而喻，大家都很佩服他。","english":"His success is self-evident, and everyone admires him.","traditional":"他的成功不言而喻，大家都很佩服他。"},{"simplified":"这个道理不言而喻，不需要多解释。","english":"This principle is obvious and doesn't need further explanation.","traditional":"這個道理不言而喻，不需要多解釋。"}],"synonyms":["显而易见","一目了然"],"antonyms":[],"confusedWith":[{"id":"显而易见","note":"Both mean 'obvious', but '显而易见' emphasizes visibility, while '不言而喻' emphasizes understanding without words."}],"traditional":"不言而喻","pinyinOverride":null},{"id":"bu-ci-er-bie","simplified":"不辞而别","literalMeaning":"leave without saying goodbye","figurativeMeaning":"to leave without informing anyone; to depart secretly","englishEquivalents":["leave without a word","disappear without notice"],"shortGloss":"leave without saying goodbye","characters":[{"char":"不","meaning":"not"},{"char":"辞","meaning":"take leave; say goodbye"},{"char":"而","meaning":"and; but"},{"char":"别","meaning":"leave; depart"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '不辞而别' describes the act of leaving a place or situation without notifying others or saying goodbye. It is often used to describe someone who departs suddenly and unexpectedly, leaving others unaware of their departure.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"commonly used in both written and spoken Chinese","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with similar expressions that imply a more formal or polite departure. '不辞而别' specifically implies leaving without any notice or farewell.","canStandAlone":false},"examples":[{"simplified":"他昨天不辞而别，让我们很担心。","english":"He left without saying goodbye yesterday, which made us very worried.","traditional":"他昨天不辭而別，讓我們很擔心。"},{"simplified":"她总是习惯于不辞而别。","english":"She always has the habit of leaving without a word.","traditional":"她總是習慣於不辭而別。"}],"synonyms":[],"antonyms":[],"confusedWith":[{"id":"悄然离去","note":"While both imply leaving quietly, '悄然离去' suggests a more peaceful departure, whereas '不辞而别' emphasizes the lack of notice."}],"traditional":"不辭而別","pinyinOverride":null},{"id":"yu-zhong-bu-tong","simplified":"与众不同","literalMeaning":"different from the crowd","figurativeMeaning":"to be unique or extraordinary; to stand out from the crowd","englishEquivalents":["stand out from the crowd","one of a kind"],"shortGloss":"to be unique or different","characters":[{"char":"与","meaning":"with; from"},{"char":"众","meaning":"crowd; many people"},{"char":"不","meaning":"not"},{"char":"同","meaning":"same; alike"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '与众不同' is used to describe someone or something that stands out from others due to unique qualities or characteristics. It emphasizes being different from the majority in a positive way, often highlighting individuality or exceptional traits.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"modifier-head","register":"commonly used in both formal and informal contexts","connotation":"positive","commonMistakes":"Learners might confuse this idiom with '独一无二', which also means unique but implies being the only one of its kind. '与众不同' emphasizes being different from the majority rather than being singular.","canStandAlone":false},"examples":[{"simplified":"她的设计风格与众不同，吸引了很多客户。","english":"Her design style is unique, attracting many clients.","traditional":"她的設計風格與眾不同，吸引了很多客戶。"},{"simplified":"这位艺术家的作品总是与众不同，给人耳目一新的感觉。","english":"The artist's works are always unique, providing a refreshing experience.","traditional":"這位藝術家的作品總是與眾不同，給人耳目一新的感覺。"}],"synonyms":["独树一帜"],"antonyms":["随波逐流"],"confusedWith":[{"id":"独一无二","note":"While both idioms imply uniqueness, '独一无二' suggests being the only one of its kind, whereas '与众不同' emphasizes being different from the majority."}],"traditional":"與眾不同","pinyinOverride":null},{"id":"yu-ri-ju-zeng","simplified":"与日俱增","literalMeaning":"increase together with each passing day","figurativeMeaning":"to increase steadily or continuously over time","englishEquivalents":["grow day by day","increase steadily"],"shortGloss":"increase steadily over time","characters":[{"char":"与","meaning":"together with"},{"char":"日","meaning":"day"},{"char":"俱","meaning":"together"},{"char":"增","meaning":"increase"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '与日俱增' is used to describe something that grows or increases continuously over time. It is often used to describe emotions, prices, or quantities that steadily rise as time passes.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"modifier-head","register":"widely used in both written and spoken Chinese","connotation":"neutral","commonMistakes":"Learners might confuse '与日俱增' with idioms that imply sudden or rapid increase, but it specifically refers to gradual and steady growth over time.","canStandAlone":false},"examples":[{"simplified":"他的经验与日俱增。","english":"His experience is increasing day by day.","traditional":"他的經驗與日俱增。"},{"simplified":"随着时间的推移，她对这份工作的热情与日俱增。","english":"As time goes by, her enthusiasm for the job increases steadily.","traditional":"隨著時間的推移，她對這份工作的熱情與日俱增。"}],"synonyms":["日积月累"],"antonyms":["日渐消退"],"confusedWith":[{"id":"突飞猛进","note":"与日俱增 implies steady growth, while 突飞猛进 implies rapid and sudden progress."}],"traditional":"與日俱增","pinyinOverride":null},{"id":"yu-shi-ju-jin","simplified":"与时俱进","literalMeaning":"advance together with the times","figurativeMeaning":"to keep up with the times; to adapt to changing circumstances","englishEquivalents":["move with the times","keep up with the times"],"shortGloss":"keep up with the times","characters":[{"char":"与","meaning":"with"},{"char":"时","meaning":"time"},{"char":"俱","meaning":"together"},{"char":"进","meaning":"advance"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '与时俱进' emphasizes the importance of adapting to new developments and changes in society. It suggests that one should progress and evolve along with the times to remain relevant and effective.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"commonly used in both formal and informal contexts","connotation":"positive","commonMistakes":"Learners might confuse this idiom with more static expressions, misunderstanding its emphasis on active adaptation and progress. It's important to use it in contexts where change and adaptation are key.","canStandAlone":false},"examples":[{"simplified":"在这个快速发展的时代，我们必须与时俱进。","english":"In this rapidly developing era, we must keep up with the times.","traditional":"在這個快速發展的時代，我們必須與時俱進。"},{"simplified":"公司需要与时俱进，才能在市场上保持竞争力。","english":"The company needs to keep up with the times to remain competitive in the market.","traditional":"公司需要與時俱進，才能在市場上保持競爭力。"}],"synonyms":["顺应潮流"],"antonyms":["墨守成规"],"confusedWith":[{"id":"墨守成规","note":"与时俱进 emphasizes adapting to change, while 墨守成规 means sticking to old ways."}],"traditional":"與時俱進","pinyinOverride":null},{"id":"dong-ben-xi-zou","simplified":"东奔西走","literalMeaning":"run east, walk west","figurativeMeaning":"to run around busily; to be constantly on the move","englishEquivalents":["to be on the go","to hustle and bustle","to run around"],"shortGloss":"to be constantly on the move","characters":[{"char":"东","meaning":"east"},{"char":"奔","meaning":"run"},{"char":"西","meaning":"west"},{"char":"走","meaning":"walk"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom 东奔西走 describes the action of running around in different directions, often used to depict someone who is very busy and constantly on the move. It conveys the image of a person who is making efforts in various places, often for work or personal obligations.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"coordinate","register":"commonly used in both spoken and written Chinese, informal contexts","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with others that involve directions, such as 南来北往, which specifically refers to people coming and going from different directions rather than being busy.","canStandAlone":false},"examples":[{"simplified":"为了完成这个项目，他每天都东奔西走。","english":"To complete this project, he runs around busily every day.","traditional":"為了完成這個項目，他每天都東奔西走。"},{"simplified":"她总是东奔西走，几乎没有时间休息。","english":"She is always on the go, with hardly any time to rest.","traditional":"她總是東奔西走，幾乎沒有時間休息。"}],"synonyms":["四处奔波"],"antonyms":[],"confusedWith":[{"id":"南来北往","note":"南来北往 refers to people coming and going from different directions, not necessarily being busy."}],"traditional":"東奔西走","pinyinOverride":null},{"id":"dong-zhang-xi-wang","simplified":"东张西望","literalMeaning":"look east, look west","figurativeMeaning":"to look around in all directions; to glance around restlessly","englishEquivalents":["look around","cast about"],"shortGloss":"look around restlessly","characters":[{"char":"东","meaning":"east"},{"char":"张","meaning":"look"},{"char":"西","meaning":"west"},{"char":"望","meaning":"gaze"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom 东张西望 (dōng zhāng xī wàng) describes someone who is looking around in all directions, often with a sense of restlessness or distraction. It is commonly used to depict someone who is not focused or is searching for something without a clear direction.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"coordinate","register":"commonly used in both spoken and written Chinese","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with expressions that imply searching for something specific, but 东张西望 implies a more aimless or distracted looking around.","canStandAlone":false},"examples":[{"simplified":"他在街上东张西望，好像在找什么人。","english":"He was looking around on the street as if he was searching for someone.","traditional":"他在街上東張西望，好像在找什麼人。"},{"simplified":"考试的时候不要东张西望，要专心答题。","english":"During the exam, don't look around; focus on answering the questions.","traditional":"考試的時候不要東張西望，要專心答題。"}],"synonyms":["左顾右盼"],"antonyms":[],"confusedWith":[{"id":"左顾右盼","note":"Both idioms involve looking around, but 左顾右盼 often implies looking around with caution or consideration, whereas 东张西望 suggests more aimless or distracted looking."}],"traditional":"東張西望","pinyinOverride":null},{"id":"diu-san-la-si","simplified":"丢三落四","literalMeaning":"lose three, drop four","figurativeMeaning":"to be forgetful or absent-minded","englishEquivalents":["scatterbrained","absent-minded","forgetful"],"shortGloss":"forgetful or absent-minded","characters":[{"char":"丢","meaning":"lose"},{"char":"三","meaning":"three"},{"char":"落","meaning":"drop"},{"char":"四","meaning":"four"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '丢三落四' is believed to have originated from a folk saying that describes someone who is so forgetful that they lose three things and drop four. It is used to describe people who are often careless and forgetful, frequently misplacing or forgetting things.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"coordinate","register":"informal, commonly used in both speech and writing","connotation":"negative","commonMistakes":"Learners often confuse this idiom with others that imply carelessness, but '丢三落四' specifically emphasizes forgetfulness and absent-mindedness rather than general negligence.","canStandAlone":false},"examples":[{"simplified":"他总是丢三落四，常常忘记带钥匙。","english":"He is always forgetful, often forgetting to bring his keys.","traditional":"他總是丟三落四，常常忘記帶鑰匙。"},{"simplified":"她最近工作太忙，丢三落四的，连手机都忘了带。","english":"She's been so busy with work lately, so absent-minded that she even forgot to bring her phone.","traditional":"她最近工作太忙，丟三落四的，連手機都忘了帶。"}],"synonyms":["粗心大意"],"antonyms":["井井有条"],"confusedWith":[{"id":"粗心大意","note":"While both imply carelessness, '粗心大意' refers more to negligence and lack of attention to detail, not specifically forgetfulness."}],"traditional":"丟三落四","pinyinOverride":null},{"id":"ju-shi-zhu-mu","simplified":"举世瞩目","literalMeaning":"raise world gaze","figurativeMeaning":"to attract worldwide attention","englishEquivalents":["the center of global attention","in the global spotlight"],"shortGloss":"attract worldwide attention","characters":[{"char":"举","meaning":"raise"},{"char":"世","meaning":"world"},{"char":"瞩","meaning":"gaze"},{"char":"目","meaning":"eye"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '举世瞩目' is used to describe a person, event, or phenomenon that attracts attention from all over the world. It conveys the idea of being in the global spotlight, often due to significance, importance, or controversy.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"modifier-head","register":"commonly used in both formal and informal contexts to describe events or people that are widely noticed","connotation":"neutral","commonMistakes":"Learners might confuse '举世瞩目' with idioms that imply fame or notoriety without the global aspect. It's important to remember that this idiom specifically involves worldwide attention.","canStandAlone":false},"examples":[{"simplified":"这次奥运会在全球范围内举世瞩目。","english":"This Olympic Games attracted worldwide attention.","traditional":"這次奧運會在全球範圍內舉世矚目。"},{"simplified":"他的科学发现让他成为举世瞩目的焦点。","english":"His scientific discovery made him the center of global attention.","traditional":"他的科學發現讓他成為舉世矚目的焦點。"}],"synonyms":["万众瞩目"],"antonyms":["默默无闻"],"confusedWith":[{"id":"名声大噪","note":"While '名声大噪' means to become famous, it doesn't necessarily imply global attention like '举世瞩目' does."}],"traditional":"舉世矚目","pinyinOverride":null},{"id":"ju-qi-bu-ding","simplified":"举棋不定","literalMeaning":"raise chess piece, not decide","figurativeMeaning":"to hesitate in making a decision","englishEquivalents":["sitting on the fence","unable to make up one's mind"],"shortGloss":"indecisive","characters":[{"char":"举","meaning":"raise"},{"char":"棋","meaning":"chess piece"},{"char":"不","meaning":"not"},{"char":"定","meaning":"decide"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '举棋不定' is often used to describe someone who is hesitant or indecisive, much like a chess player who raises a piece but cannot decide where to place it. This imagery captures the essence of being unable to make a decision, whether in a game or in life.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"commonly used in both spoken and written Chinese","connotation":"negative","commonMistakes":"Learners often confuse this idiom with '犹豫不决', which also means indecisive but is more general. '举棋不定' specifically evokes the imagery of a chess game.","canStandAlone":false},"examples":[{"simplified":"他在工作和学习之间举棋不定。","english":"He is indecisive between work and study.","traditional":"他在工作和學習之間舉棋不定。"},{"simplified":"面对这个重要的决定，她举棋不定。","english":"She is indecisive in the face of this important decision.","traditional":"面對這個重要的決定，她舉棋不定。"}],"synonyms":["犹豫不决"],"antonyms":["果断决策"],"confusedWith":[{"id":"犹豫不决","note":"Both mean indecisive, but '举棋不定' specifically uses the chess metaphor."}],"traditional":"舉棋不定","pinyinOverride":null},{"id":"ju-zu-qing-zhong","simplified":"举足轻重","literalMeaning":"lift foot light heavy","figurativeMeaning":"to play a decisive role; to be of crucial importance","englishEquivalents":["to tip the scales","to be the linchpin","to hold the balance of power"],"shortGloss":"play a decisive role","characters":[{"char":"举","meaning":"lift"},{"char":"足","meaning":"foot"},{"char":"轻","meaning":"light"},{"char":"重","meaning":"heavy"}],"origin":{"period":"Eastern Han Dynasty (25–220 CE)","sourceText":"《后汉书·马援传》","sourceTextEnglish":"Book of the Later Han, Biography of Ma Yuan","originalExcerpt":"援每至一处，辄为之举足轻重。","storyEnglish":"The idiom comes from the biography of Ma Yuan in the 'Book of the Later Han'. Ma Yuan was a famous general whose presence and decisions were so influential that they could determine the outcome of important matters, much like how the movement of a foot could tip a scale. This idiom is used to describe someone or something that has a decisive impact on a situation.","historicalFigures":["Ma Yuan"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"modifier-head","register":"literary, but very widely understood and used in ordinary speech","connotation":"positive","commonMistakes":"Learners often confuse this idiom with others involving '轻' and '重', but it specifically refers to having a decisive or crucial impact, not just any kind of importance or weight.","canStandAlone":false},"examples":[{"simplified":"在这个项目中，他的意见举足轻重。","english":"In this project, his opinion is crucial.","traditional":"在這個項目中，他的意見舉足輕重。"},{"simplified":"她在公司里的地位举足轻重。","english":"Her position in the company is of crucial importance.","traditional":"她在公司裡的地位舉足輕重。"}],"synonyms":["至关重要","关键"],"antonyms":["无关紧要"],"confusedWith":[{"id":"轻重缓急","note":"轻重缓急 refers to prioritizing tasks by urgency and importance, not about having a decisive influence."}],"traditional":"舉足輕重","pinyinOverride":null},{"id":"le-ci-bu-pi","simplified":"乐此不疲","literalMeaning":"enjoy this without tiring","figurativeMeaning":"to enjoy something so much that one never tires of it","englishEquivalents":["never tire of","find endless joy in"],"shortGloss":"never tire of something","characters":[{"char":"乐","meaning":"enjoy"},{"char":"此","meaning":"this"},{"char":"不","meaning":"not"},{"char":"疲","meaning":"tired"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '乐此不疲' is used to describe someone who is so passionate about an activity or interest that they never grow tired of it. This expression is commonly used in modern Chinese to convey enthusiasm and dedication.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"modifier-head","register":"commonly used in both spoken and written Chinese","connotation":"positive","commonMistakes":"Learners might mistakenly use this idiom to describe something that is tiring but necessary, rather than something genuinely enjoyable. It should only be used when there is genuine enjoyment involved.","canStandAlone":false},"examples":[{"simplified":"他对摄影乐此不疲，每个周末都去拍照。","english":"He never tires of photography and goes out to take pictures every weekend.","traditional":"他對攝影樂此不疲，每個週末都去拍照。"},{"simplified":"孩子们对玩游戏乐此不疲，一玩就是一整天。","english":"The children never tire of playing games and can play all day long.","traditional":"孩子們對玩遊戲樂此不疲，一玩就是一整天。"}],"synonyms":["津津乐道"],"antonyms":[],"confusedWith":[{"id":"乐而忘返","note":"While both idioms involve enjoyment, '乐而忘返' implies being so absorbed that one forgets to return, whereas '乐此不疲' emphasizes not tiring of the activity."}],"traditional":"樂此不疲","pinyinOverride":null},{"id":"luan-qi-ba-zao","simplified":"乱七八糟","literalMeaning":"chaotic seven eight mess","figurativeMeaning":"in a complete mess; in disorder","englishEquivalents":["a complete mess","all over the place","in disarray"],"shortGloss":"in a complete mess","characters":[{"char":"乱","meaning":"chaotic; disorderly"},{"char":"七","meaning":"seven"},{"char":"八","meaning":"eight"},{"char":"糟","meaning":"mess; in a bad state"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '乱七八糟' is believed to have originated from the colloquial language, where '七' (seven) and '八' (eight) are used to signify a large, indefinite number, contributing to the sense of chaos and disorder. The phrase is used to describe situations or places that are in complete disarray.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"modifier-head","register":"colloquial, widely used in both spoken and written Chinese","connotation":"negative","commonMistakes":"Learners often confuse '乱七八糟' with idioms that describe confusion or complexity, but it specifically refers to physical or metaphorical messiness rather than mental confusion.","canStandAlone":false},"examples":[{"simplified":"他的房间总是乱七八糟的。","english":"His room is always a complete mess.","traditional":"他的房間總是亂七八糟的。"},{"simplified":"会议结束后，办公室变得乱七八糟。","english":"After the meeting, the office was in complete disarray.","traditional":"會議結束後，辦公室變得亂七八糟。"}],"synonyms":["杂乱无章","一团糟"],"antonyms":["井井有条"],"confusedWith":[{"id":"杂乱无章","note":"While both describe disorder, '杂乱无章' emphasizes lack of order or structure, often in writing or ideas, rather than physical mess."}],"traditional":"亂七八糟","pinyinOverride":null},{"id":"zheng-xian-kong-hou","simplified":"争先恐后","literalMeaning":"strive to be first, fear being last","figurativeMeaning":"to strive to be the first and fear being left behind; to compete fiercely","englishEquivalents":["race to the front","jostle for position"],"shortGloss":"compete fiercely to be first","characters":[{"char":"争","meaning":"strive, compete"},{"char":"先","meaning":"first, ahead"},{"char":"恐","meaning":"fear, worry"},{"char":"后","meaning":"behind, last"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '争先恐后' describes a situation where people are eager to be the first to do something and are afraid of being left behind. It is often used to depict a competitive environment where everyone is trying to outdo each other.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"coordinate","register":"widely used in both spoken and written Chinese","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with those that imply cooperation rather than competition. It's important to remember that this idiom specifically involves a sense of urgency and competition.","canStandAlone":false},"examples":[{"simplified":"在抢购打折商品时，人们争先恐后地涌入商店。","english":"During the sale, people rushed into the store, eager to be the first to grab the discounted items.","traditional":"在搶購打折商品時，人們爭先恐後地湧入商店。"},{"simplified":"运动员们在比赛中争先恐后，力求取得好成绩。","english":"The athletes competed fiercely in the race, each striving to achieve a good result.","traditional":"運動員們在比賽中爭先恐後，力求取得好成績。"}],"synonyms":["你追我赶"],"antonyms":["相安无事"],"confusedWith":[{"id":"齐心协力","note":"齐心协力 means to work together with one heart, which is cooperative rather than competitive."}],"traditional":"爭先恐後","pinyinOverride":null},{"id":"zheng-fen-duo-miao","simplified":"争分夺秒","literalMeaning":"fight for minutes, seize seconds","figurativeMeaning":"to make every second count; to race against time","englishEquivalents":["make every second count","race against time"],"shortGloss":"make every second count","characters":[{"char":"争","meaning":"strive, fight"},{"char":"分","meaning":"minutes"},{"char":"夺","meaning":"seize, snatch"},{"char":"秒","meaning":"seconds"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '争分夺秒' is often used to describe situations where time is of the essence and every moment must be utilized effectively. It conveys a sense of urgency and the need to maximize productivity by making the most of every minute and second.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["adverbial","attributive"],"structure":"coordinate","register":"commonly used in both spoken and written Chinese to emphasize urgency and efficiency","connotation":"positive","commonMistakes":"Learners might confuse it with idioms that imply haste without purpose. '争分夺秒' specifically emphasizes purposeful and efficient use of time, not just hurried action.","canStandAlone":false},"examples":[{"simplified":"在考试前的复习中，我们必须争分夺秒。","english":"During the review before exams, we must make every second count.","traditional":"在考試前的複習中，我們必須爭分奪秒。"},{"simplified":"为了赶上最后的期限，团队争分夺秒地工作。","english":"To meet the final deadline, the team worked against the clock.","traditional":"為了趕上最後的期限，團隊爭分奪秒地工作。"}],"synonyms":["分秒必争"],"antonyms":["虚度光阴"],"confusedWith":[{"id":"分秒必争","note":"Both emphasize efficient use of time, but '分秒必争' is more about the necessity of fighting for every moment."}],"traditional":"爭分奪秒","pinyinOverride":null},{"id":"wu-hu-si-hai","simplified":"五湖四海","literalMeaning":"five lakes and four seas","figurativeMeaning":"people from all over the world; all corners of the land","englishEquivalents":["from all walks of life","from all over the world"],"shortGloss":"people from everywhere","characters":[{"char":"五","meaning":"five"},{"char":"湖","meaning":"lakes"},{"char":"四","meaning":"four"},{"char":"海","meaning":"seas"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '五湖四海' is used to describe people coming together from various places, symbolized by the five great lakes and four seas. It emphasizes inclusivity and diversity, suggesting that no matter where people are from, they can unite and work together.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["subject","predicate","object","attributive"],"structure":"coordinate","register":"commonly used in both formal and informal contexts","connotation":"positive","commonMistakes":"Learners might confuse this idiom with others that involve numbers and geographical features, but it specifically refers to inclusivity and diversity, not just any large group.","canStandAlone":false},"examples":[{"simplified":"我们的团队来自五湖四海，充满了多样性。","english":"Our team comes from all over the world and is full of diversity.","traditional":"我們的團隊來自五湖四海，充滿了多樣性。"},{"simplified":"五湖四海的人们聚集在一起，庆祝这个特别的节日。","english":"People from all corners of the land gathered together to celebrate this special festival.","traditional":"五湖四海的人們聚集在一起，慶祝這個特別的節日。"}],"synonyms":["四面八方"],"antonyms":[],"confusedWith":[{"id":"四面八方","note":"While both idioms refer to people coming from various places, '四面八方' emphasizes directionality, whereas '五湖四海' emphasizes diversity and inclusivity."}],"traditional":"五湖四海","pinyinOverride":null},{"id":"wu-hua-ba-men","simplified":"五花八门","literalMeaning":"five flowers, eight doors","figurativeMeaning":"a wide variety; a rich diversity","englishEquivalents":["a wide array","a myriad of","a wide variety"],"shortGloss":"a wide variety","characters":[{"char":"五","meaning":"five"},{"char":"花","meaning":"flowers; used here to mean types or categories"},{"char":"八","meaning":"eight"},{"char":"门","meaning":"doors; used here to mean categories or types"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '五花八门' is believed to have originated from a combination of two separate expressions. '五花' refers to the five different colors used in traditional Chinese opera face painting, representing a variety of characters. '八门' refers to the eight categories of martial arts techniques. Together, they convey the idea of a wide variety or diversity.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["attributive","adverbial"],"structure":"coordinate","register":"common in both written and spoken Chinese","connotation":"neutral","commonMistakes":"Learners sometimes use this idiom to describe a single item or concept, but it should refer to a variety or diversity of things. It is also sometimes confused with idioms that imply chaos or disorganization, but '五花八门' does not carry that connotation.","canStandAlone":false},"examples":[{"simplified":"市场上的商品五花八门，让人眼花缭乱。","english":"The products in the market are so varied that they dazzle the eyes.","traditional":"市場上的商品五花八門，讓人眼花繚亂。"},{"simplified":"他有五花八门的兴趣爱好。","english":"He has a wide variety of hobbies and interests.","traditional":"他有五花八門的興趣愛好。"}],"synonyms":["丰富多彩","千变万化"],"antonyms":[],"confusedWith":[{"id":"杂乱无章","note":"杂乱无章 implies disorganization and chaos, unlike 五花八门 which simply indicates variety."}],"traditional":"五花八門","pinyinOverride":null},{"id":"jiao-tou-jie-er","simplified":"交头接耳","literalMeaning":"join heads, touch ears","figurativeMeaning":"to whisper to each other; to talk in hushed tones","englishEquivalents":["whispering","talking in hushed tones"],"shortGloss":"whispering to each other","characters":[{"char":"交","meaning":"join"},{"char":"头","meaning":"heads"},{"char":"接","meaning":"touch"},{"char":"耳","meaning":"ears"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '交头接耳' describes the action of people leaning close to each other to whisper or speak quietly, usually to avoid being overheard. It is often used to describe secretive or private conversations.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"commonly used in both spoken and written Chinese","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with those implying loud or public discussions. It specifically refers to quiet, private conversations.","canStandAlone":false},"examples":[{"simplified":"他们在会议上交头接耳，显然在讨论什么重要的事情。","english":"They were whispering to each other during the meeting, clearly discussing something important.","traditional":"他們在會議上交頭接耳，顯然在討論什麼重要的事情。"},{"simplified":"看到老师走过来，学生们停止了交头接耳。","english":"Seeing the teacher approaching, the students stopped whispering to each other.","traditional":"看到老師走過來，學生們停止了交頭接耳。"}],"synonyms":["窃窃私语"],"antonyms":["高谈阔论"],"confusedWith":[{"id":"窃窃私语","note":"Both refer to whispering, but '窃窃私语' emphasizes secrecy more strongly."}],"traditional":"交頭接耳","pinyinOverride":null},{"id":"cong-rong-bu-po","simplified":"从容不迫","literalMeaning":"calm and unhurried","figurativeMeaning":"to remain calm and unruffled in the face of pressure or urgency","englishEquivalents":["cool, calm, and collected","unflappable"],"shortGloss":"calm and unhurried","characters":[{"char":"从","meaning":"calm"},{"char":"容","meaning":"composed"},{"char":"不","meaning":"not"},{"char":"迫","meaning":"hurried"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '从容不迫' describes a person who remains calm and composed, without any sense of urgency, even in stressful situations. It is often used to praise someone who handles pressure gracefully.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["adverbial","attributive"],"structure":"modifier-head","register":"widely used in both formal and informal contexts","connotation":"positive","commonMistakes":"Learners sometimes confuse this idiom with '不慌不忙', which also means 'unhurried' but lacks the nuance of composure under pressure.","canStandAlone":false},"examples":[{"simplified":"他在面试中表现得从容不迫，给面试官留下了深刻的印象。","english":"He remained calm and unruffled during the interview, leaving a strong impression on the interviewer.","traditional":"他在面試中表現得從容不迫，給面試官留下了深刻的印象。"},{"simplified":"无论遇到什么困难，她总是从容不迫地解决问题。","english":"No matter what difficulties she faces, she always solves problems calmly and unhurriedly.","traditional":"無論遇到什麼困難，她總是從容不迫地解決問題。"}],"synonyms":["不慌不忙"],"antonyms":["惊慌失措"],"confusedWith":[{"id":"不慌不忙","note":"Both mean unhurried, but '从容不迫' emphasizes composure under pressure."}],"traditional":"從容不迫","pinyinOverride":null},{"id":"yi-shen-zuo-ze","simplified":"以身作则","literalMeaning":"use oneself as an example","figurativeMeaning":"to set an example by one's own actions","englishEquivalents":["lead by example"],"shortGloss":"lead by example","characters":[{"char":"以","meaning":"use"},{"char":"身","meaning":"oneself; body"},{"char":"作","meaning":"act as"},{"char":"则","meaning":"example; model"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '以身作则' emphasizes the importance of leading by example. It suggests that one should demonstrate the behavior or standards they expect from others through their own actions. This concept is widely valued in leadership and personal conduct, encouraging individuals to embody the principles they advocate.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"commonly used in both formal and informal contexts","connotation":"positive","commonMistakes":"Learners might confuse this idiom with others that involve setting examples, but '以身作则' specifically emphasizes using one's own actions as the example. It should not be confused with idioms that imply setting rules or standards without personal involvement.","canStandAlone":false},"examples":[{"simplified":"作为领导者，他总是以身作则，激励团队。","english":"As a leader, he always leads by example, inspiring the team.","traditional":"作為領導者，他總是以身作則，激勵團隊。"},{"simplified":"父母应该以身作则，给孩子树立良好的榜样。","english":"Parents should lead by example and set a good example for their children.","traditional":"父母應該以身作則，給孩子樹立良好的榜樣。"}],"synonyms":["身体力行"],"antonyms":[],"confusedWith":[{"id":"言行不一","note":"言行不一 means saying one thing and doing another, which is the opposite of leading by example."}],"traditional":"以身作則","pinyinOverride":null},{"id":"ren-zhong-dao-yuan","simplified":"任重道远","literalMeaning":"burden heavy, road long","figurativeMeaning":"to shoulder a heavy responsibility over a long journey; to have a long and arduous task ahead","englishEquivalents":["a long road ahead","heavy is the head that wears the crown"],"shortGloss":"a long and difficult task ahead","characters":[{"char":"任","meaning":"burden, responsibility"},{"char":"重","meaning":"heavy"},{"char":"道","meaning":"road, path"},{"char":"远","meaning":"long, far"}],"origin":{"period":"Han Dynasty (206 BCE – 220 CE)","sourceText":"《汉书·景十三王传》","sourceTextEnglish":"Book of Han, Biography of the Thirteen Kings of Jing","originalExcerpt":"任重而道远者，不择地而息。","storyEnglish":"The idiom originates from the 'Book of Han', where it is used to describe someone who has taken on a significant responsibility that requires perseverance over a long journey. It emphasizes the need for determination and endurance when faced with a challenging task.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"coordinate","register":"literary, but very widely understood and used in ordinary speech","connotation":"neutral","commonMistakes":"Learners often confuse this idiom with similar expressions that imply a short-term task. It specifically refers to long-term responsibilities and challenges.","canStandAlone":false},"examples":[{"simplified":"我们的项目任重道远，需要大家的共同努力。","english":"Our project is a long and arduous task that requires everyone's joint effort.","traditional":"我們的項目任重道遠，需要大家的共同努力。"},{"simplified":"他知道自己任重道远，但从未退缩。","english":"He knows he has a long and difficult journey ahead, but he has never backed down.","traditional":"他知道自己任重道遠，但從未退縮。"}],"synonyms":["负重致远"],"antonyms":[],"confusedWith":[{"id":"事半功倍","note":"事半功倍 refers to achieving more with less effort, while 任重道远 emphasizes a long and difficult task."}],"traditional":"任重道遠","pinyinOverride":null},{"id":"zhong-zhi-cheng-cheng","simplified":"众志成城","literalMeaning":"many wills form a fortress","figurativeMeaning":"unity is strength; when people are united, they can overcome any difficulty","englishEquivalents":["unity is strength","together we stand","united we conquer"],"shortGloss":"unity is strength","characters":[{"char":"众","meaning":"many; multitude"},{"char":"志","meaning":"will; determination"},{"char":"成","meaning":"to become; to form"},{"char":"城","meaning":"fortress; city wall"}],"origin":{"period":"Warring States period (475–221 BCE)","sourceText":"《国语·周语下》","sourceTextEnglish":"Discourses of the States, Zhou Yu II","originalExcerpt":"众志成城，众口铄金。","storyEnglish":"The idiom comes from the 'Discourses of the States', where it is said that when people's wills are united, they can form a strong defense like a fortress. This emphasizes the power of collective will and unity in overcoming challenges.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"subject-predicate","register":"literary, but very widely understood and used in ordinary speech","connotation":"positive","commonMistakes":"Learners might confuse it with idioms that emphasize individual effort rather than collective unity. It's important to remember that this idiom specifically highlights the strength found in unity.","canStandAlone":false},"examples":[{"simplified":"在抗击疫情的过程中，众志成城的精神尤为重要。","english":"During the fight against the pandemic, the spirit of unity is especially important.","traditional":"在抗擊疫情的過程中，眾志成城的精神尤為重要。"},{"simplified":"面对困难，我们要众志成城，共同克服。","english":"In the face of difficulties, we must unite and overcome them together.","traditional":"面對困難，我們要眾志成城，共同克服。"}],"synonyms":["团结一致","同心协力"],"antonyms":["各自为政"],"confusedWith":[{"id":"同心协力","note":"Both emphasize unity, but 同心协力 focuses more on working together harmoniously."}],"traditional":"眾志成城","pinyinOverride":null},{"id":"you-sheng-lie-tai","simplified":"优胜劣汰","literalMeaning":"superior wins, inferior is eliminated","figurativeMeaning":"survival of the fittest","englishEquivalents":["survival of the fittest"],"shortGloss":"survival of the fittest","characters":[{"char":"优","meaning":"superior; excellent"},{"char":"胜","meaning":"win; prevail"},{"char":"劣","meaning":"inferior; weak"},{"char":"汰","meaning":"eliminate; weed out"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '优胜劣汰' is often used to describe the natural process of selection where stronger or more capable individuals or entities succeed, while weaker ones are left behind. This concept is similar to the idea of 'survival of the fittest' in evolutionary biology, though the idiom itself is not directly rooted in a specific classical text.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["subject","predicate","object","attributive"],"structure":"coordinate","register":"commonly used in both formal and informal contexts","connotation":"neutral","commonMistakes":"Learners may confuse this idiom with others that involve competition or struggle, but '优胜劣汰' specifically emphasizes the process of natural selection and elimination based on capability or strength.","canStandAlone":false},"examples":[{"simplified":"在商业竞争中，优胜劣汰是常见的现象。","english":"In business competition, survival of the fittest is a common phenomenon.","traditional":"在商業競爭中，優勝劣汰是常見的現象。"},{"simplified":"自然界中，优胜劣汰的法则无处不在。","english":"In nature, the law of survival of the fittest is everywhere.","traditional":"自然界中，優勝劣汰的法則無處不在。"}],"synonyms":["适者生存"],"antonyms":[],"confusedWith":[{"id":"适者生存","note":"Both idioms describe natural selection, but '适者生存' more explicitly refers to adaptation."}],"traditional":"優勝劣汰","pinyinOverride":null},{"id":"si-shi-er-fei","simplified":"似是而非","literalMeaning":"seems right but actually wrong","figurativeMeaning":"something that appears correct but is actually incorrect or misleading","englishEquivalents":["a wolf in sheep's clothing","looks can be deceiving"],"shortGloss":"appears correct but is wrong","characters":[{"char":"似","meaning":"seems; appears"},{"char":"是","meaning":"right; correct"},{"char":"而","meaning":"but; yet"},{"char":"非","meaning":"wrong; incorrect"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '似是而非' is used to describe situations where something appears to be true or correct at first glance but is actually false or misleading upon closer examination. It highlights the importance of not taking things at face value and being cautious of deceptive appearances.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"modifier-head","register":"commonly used in both written and spoken Chinese to caution against superficial judgments","connotation":"negative","commonMistakes":"Learners might use this idiom to describe something that is ambiguous or unclear, but it specifically refers to things that are misleadingly incorrect. It is often confused with '模棱两可', which means ambiguous or equivocal.","canStandAlone":false},"examples":[{"simplified":"这篇文章看起来很有道理，但其实是似是而非的。","english":"This article seems reasonable, but it's actually misleading.","traditional":"這篇文章看起來很有道理，但其實是似是而非的。"},{"simplified":"他的解释听起来似是而非，不要轻易相信。","english":"His explanation sounds plausible but is misleading; don't believe it easily.","traditional":"他的解釋聽起來似是而非，不要輕易相信。"}],"synonyms":["挂羊头卖狗肉"],"antonyms":["实事求是"],"confusedWith":[{"id":"模棱两可","note":"模棱两可 means ambiguous or equivocal, not misleadingly incorrect."}],"traditional":"似是而非","pinyinOverride":null},{"id":"si-ceng-xiang-shi","simplified":"似曾相识","literalMeaning":"seems like once met","figurativeMeaning":"something feels familiar or déjà vu","englishEquivalents":["déjà vu","seems familiar"],"shortGloss":"feels familiar","characters":[{"char":"似","meaning":"seems like"},{"char":"曾","meaning":"once"},{"char":"相","meaning":"mutually"},{"char":"识","meaning":"recognize"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '似曾相识' is often used to describe the feeling when something or someone seems familiar, as if encountered before, even if it is the first time. This sensation is akin to the French term 'déjà vu'. The phrase captures the mysterious and sometimes unsettling feeling of familiarity in new experiences.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"modifier-head","register":"widely used in both spoken and written Chinese","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with expressions that imply actual past encounters, but it specifically refers to the feeling of familiarity without confirming a real past meeting.","canStandAlone":false},"examples":[{"simplified":"看到这幅画，我有种似曾相识的感觉。","english":"Seeing this painting, I have a feeling of déjà vu.","traditional":"看到這幅畫，我有種似曾相識的感覺。"},{"simplified":"她的声音让我觉得似曾相识。","english":"Her voice makes me feel like I've heard it before.","traditional":"她的聲音讓我覺得似曾相識。"}],"synonyms":[],"antonyms":[],"confusedWith":[],"traditional":"似曾相識","pinyinOverride":null},{"id":"kan-kan-er-tan","simplified":"侃侃而谈","literalMeaning":"speak openly and confidently","figurativeMeaning":"to speak with confidence and ease","englishEquivalents":["speak eloquently","speak with poise"],"shortGloss":"speak confidently and eloquently","characters":[{"char":"侃","meaning":"open; straightforward"},{"char":"侃","meaning":"open; straightforward"},{"char":"而","meaning":"and; thus"},{"char":"谈","meaning":"talk; speak"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom 侃侃而谈 is used to describe someone who speaks in a confident and articulate manner. It is often used to praise someone's ability to express themselves clearly and persuasively in conversation or public speaking. The origin of this idiom is not linked to a specific classical text, but it has been widely used in Chinese literature and speech to convey the idea of eloquence and confidence.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"modifier-head","register":"commonly used in both formal and informal contexts","connotation":"positive","commonMistakes":"Learners might confuse this idiom with others that imply verbosity or excessive talking. 侃侃而谈 specifically conveys confidence and clarity, not just talking at length.","canStandAlone":false},"examples":[{"simplified":"他在会议上侃侃而谈，赢得了大家的赞赏。","english":"He spoke confidently at the meeting and earned everyone's admiration.","traditional":"他在會議上侃侃而談，贏得了大家的讚賞。"},{"simplified":"她总是能侃侃而谈，给人留下深刻的印象。","english":"She always speaks eloquently, leaving a deep impression on people.","traditional":"她總是能侃侃而談，給人留下深刻的印象。"}],"synonyms":["滔滔不绝"],"antonyms":["吞吞吐吐"],"confusedWith":[{"id":"滔滔不绝","note":"滔滔不绝 means to talk non-stop, often without the implication of eloquence or confidence."}],"traditional":"侃侃而談","pinyinOverride":null},{"id":"gong-bu-ying-qiu","simplified":"供不应求","literalMeaning":"supply does not meet demand","figurativeMeaning":"demand exceeds supply; there is not enough to meet the demand","englishEquivalents":["in short supply","scarcity","demand outstrips supply"],"shortGloss":"demand exceeds supply","characters":[{"char":"供","meaning":"supply"},{"char":"不","meaning":"not"},{"char":"应","meaning":"meet"},{"char":"求","meaning":"demand"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '供不应求' describes a situation where the supply of a product or service is insufficient to meet the demand for it. This concept is widely applicable in economics and business, and the phrase is used to describe shortages in various contexts, from goods to services.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"subject-predicate","register":"commonly used in both formal and informal contexts, especially in economic and business discussions","connotation":"neutral","commonMistakes":"Learners sometimes confuse this idiom with phrases that imply abundance rather than scarcity. It specifically refers to a shortage where demand is higher than supply.","canStandAlone":false},"examples":[{"simplified":"由于疫情的影响，许多医疗物资供不应求。","english":"Due to the impact of the pandemic, many medical supplies are in short supply.","traditional":"由於疫情的影響，許多醫療物資供不應求。"},{"simplified":"在旅游旺季，酒店房间常常供不应求。","english":"During the peak tourist season, hotel rooms are often in short supply.","traditional":"在旅遊旺季，酒店房間常常供不應求。"}],"synonyms":["供不应接"],"antonyms":["供过于求"],"confusedWith":[{"id":"供过于求","note":"供过于求 means 'supply exceeds demand', which is the opposite situation of 供不应求."}],"traditional":"供不應求","pinyinOverride":null},{"id":"yi-yi-bu-she","simplified":"依依不舍","literalMeaning":"reluctant to part","figurativeMeaning":"unwilling to leave or part with someone or something","englishEquivalents":["hard to say goodbye","reluctant to part","with a heavy heart"],"shortGloss":"unwilling to part","characters":[{"char":"依","meaning":"cling"},{"char":"依","meaning":"cling"},{"char":"不","meaning":"not"},{"char":"舍","meaning":"give up; part with"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom 依依不舍 is used to describe the feeling of being reluctant to leave someone or something behind. It conveys a sense of attachment and emotional difficulty in parting. The phrase is often used in contexts such as farewells, moving away, or leaving a beloved place.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"modifier-head","register":"widely used in both spoken and written Chinese, suitable for both formal and informal contexts","connotation":"neutral","commonMistakes":"Learners might confuse 依依不舍 with idioms that imply a more permanent separation or loss. It's important to note that 依依不舍 emphasizes the emotional reluctance to part, not the finality of the separation.","canStandAlone":false},"examples":[{"simplified":"分别的时候，大家都依依不舍。","english":"When it was time to say goodbye, everyone was reluctant to part.","traditional":"分別的時候，大家都依依不捨。"},{"simplified":"他对这座城市依依不舍，不愿意搬走。","english":"He was reluctant to leave this city and didn't want to move away.","traditional":"他對這座城市依依不捨，不願意搬走。"}],"synonyms":["恋恋不舍"],"antonyms":["挥手告别"],"confusedWith":[{"id":"恋恋不舍","note":"Both idioms express reluctance to part, but 恋恋不舍 often emphasizes a deeper emotional attachment."}],"traditional":"依依不捨","pinyinOverride":null},{"id":"qing-jia-dang-chan","simplified":"倾家荡产","literalMeaning":"collapse family, lose property","figurativeMeaning":"to lose everything; to be bankrupt","englishEquivalents":["lose everything","go bankrupt"],"shortGloss":"lose everything; go bankrupt","characters":[{"char":"倾","meaning":"collapse; fall"},{"char":"家","meaning":"family; home"},{"char":"荡","meaning":"sweep away; eliminate"},{"char":"产","meaning":"property; assets"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '倾家荡产' is often used to describe a situation where someone loses all their wealth and property, typically due to poor financial decisions, gambling, or unforeseen circumstances. The imagery is of a family collapsing and all their possessions being swept away, leaving them with nothing.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","complement"],"structure":"verb-object","register":"commonly used in both spoken and written Chinese to describe financial ruin","connotation":"negative","commonMistakes":"Learners often confuse this idiom with others that describe financial loss, but '倾家荡产' specifically implies a total loss of all assets, not just a significant loss.","canStandAlone":false},"examples":[{"simplified":"他因为赌博而倾家荡产。","english":"He lost everything because of gambling.","traditional":"他因為賭博而傾家蕩產。"},{"simplified":"如果不小心投资，可能会倾家荡产。","english":"If you're not careful with investments, you might lose everything.","traditional":"如果不小心投資，可能會傾家蕩產。"}],"synonyms":["一贫如洗"],"antonyms":["家财万贯"],"confusedWith":[{"id":"一败涂地","note":"While both idioms imply failure, '一败涂地' refers to a complete defeat or failure, not specifically financial ruin."}],"traditional":"傾家蕩產","pinyinOverride":null},{"id":"guang-ming-lei-luo","simplified":"光明磊落","literalMeaning":"bright and upright","figurativeMeaning":"open and honest; straightforward and upright in one's dealings","englishEquivalents":["above board","with a clear conscience"],"shortGloss":"open and honest","characters":[{"char":"光","meaning":"bright"},{"char":"明","meaning":"clear, bright"},{"char":"磊","meaning":"upright, honest"},{"char":"落","meaning":"open, straightforward"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '光明磊落' is used to describe someone who is open, honest, and straightforward in their actions and dealings. It emphasizes transparency and integrity, suggesting that the person has nothing to hide and acts with a clear conscience.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"coordinate","register":"literary, but very widely understood and used in ordinary speech","connotation":"positive","commonMistakes":"Learners sometimes confuse this idiom with '光明正大', which also means open and honest but often emphasizes fairness and justice. '光明磊落' focuses more on personal integrity.","canStandAlone":false},"examples":[{"simplified":"他为人光明磊落，从不做亏心事。","english":"He is an open and honest person who never does anything against his conscience.","traditional":"他為人光明磊落，從不做虧心事。"},{"simplified":"她的光明磊落让大家都很信任她。","english":"Her openness and honesty make everyone trust her.","traditional":"她的光明磊落讓大家都很信任她。"}],"synonyms":["光明正大"],"antonyms":["阴险狡诈"],"confusedWith":[{"id":"光明正大","note":"Both idioms describe honesty, but '光明正大' emphasizes fairness and justice, while '光明磊落' focuses on personal integrity."}],"traditional":"光明磊落","pinyinOverride":null},{"id":"jing-jing-ye-ye","simplified":"兢兢业业","literalMeaning":"cautious and conscientious","figurativeMeaning":"to be diligent and meticulous in one's work","englishEquivalents":["diligent and meticulous","conscientious and careful"],"shortGloss":"diligent and meticulous","characters":[{"char":"兢","meaning":"cautious"},{"char":"兢","meaning":"cautious"},{"char":"业","meaning":"work; task"},{"char":"业","meaning":"work; task"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom 兢兢业业 is used to describe someone who is very diligent and meticulous in their work. It emphasizes a careful and conscientious approach to tasks, ensuring that everything is done thoroughly and with attention to detail.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["adverbial","attributive"],"structure":"AABB","register":"commonly used in both formal and informal contexts to praise someone's work ethic","connotation":"positive","commonMistakes":"Learners may confuse this idiom with others that imply diligence but lack the nuance of meticulousness. It's important to use it when emphasizing both carefulness and hard work.","canStandAlone":false},"examples":[{"simplified":"他在工作中总是兢兢业业，从不马虎。","english":"He is always diligent and meticulous in his work, never careless.","traditional":"他在工作中總是兢兢業業，從不馬虎。"},{"simplified":"经理对她兢兢业业的态度非常满意。","english":"The manager is very satisfied with her diligent and meticulous attitude.","traditional":"經理對她兢兢業業的態度非常滿意。"}],"synonyms":["勤勤恳恳"],"antonyms":["敷衍了事"],"confusedWith":[{"id":"勤勤恳恳","note":"勤勤恳恳 also means diligent, but it doesn't emphasize meticulousness as much as 兢兢业业 does."}],"traditional":"兢兢業業","pinyinOverride":null},{"id":"quan-li-yi-fu","simplified":"全力以赴","literalMeaning":"exert all strength to go","figurativeMeaning":"to give it one's all; to go all out","englishEquivalents":["give it one's all","go all out","pull out all the stops"],"shortGloss":"give it one's all","characters":[{"char":"全","meaning":"all; whole"},{"char":"力","meaning":"strength; effort"},{"char":"以","meaning":"to use; with"},{"char":"赴","meaning":"to go to; to attend"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '全力以赴' is commonly used to express the idea of dedicating all one's energy and effort towards a particular goal or task. The phrase emphasizes the importance of commitment and determination in achieving success.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["adverbial","complement"],"structure":"modifier-head","register":"widely used in both spoken and written Chinese, suitable for formal and informal contexts","connotation":"positive","commonMistakes":"Learners might mistakenly use this idiom as a standalone sentence, but it typically modifies a verb to describe how an action is performed.","canStandAlone":false},"examples":[{"simplified":"为了这次比赛，他全力以赴地训练。","english":"He trained with all his might for this competition.","traditional":"為了這次比賽，他全力以赴地訓練。"},{"simplified":"我们必须全力以赴，才能完成这个项目。","english":"We must go all out to complete this project.","traditional":"我們必須全力以赴，才能完成這個項目。"}],"synonyms":["竭尽全力"],"antonyms":["敷衍了事"],"confusedWith":[{"id":"全神贯注","note":"全神贯注 means to concentrate fully, focusing attention, rather than exerting effort."}],"traditional":"全力以赴","pinyinOverride":null},{"id":"quan-xin-quan-yi","simplified":"全心全意","literalMeaning":"whole heart whole intent","figurativeMeaning":"to do something with complete dedication and sincerity","englishEquivalents":["wholeheartedly","with all one's heart","with full devotion"],"shortGloss":"wholeheartedly","characters":[{"char":"全","meaning":"whole, complete"},{"char":"心","meaning":"heart, mind"},{"char":"全","meaning":"whole, complete"},{"char":"意","meaning":"intent, intention"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '全心全意' is commonly used to express complete dedication and sincerity in one's actions. It emphasizes putting one's whole heart and mind into a task or relationship. The exact origin of this idiom is uncertain, but it has been widely used in Chinese literature and speech to convey the idea of wholehearted commitment.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["adverbial","attributive"],"structure":"coordinate","register":"widely used in both formal and informal contexts","connotation":"positive","commonMistakes":"Learners might confuse this idiom with similar expressions that do not convey the same level of complete dedication. It is important to use it when emphasizing full commitment, not just partial effort.","canStandAlone":false},"examples":[{"simplified":"他全心全意地投入到工作中。","english":"He devoted himself wholeheartedly to his work.","traditional":"他全心全意地投入到工作中。"},{"simplified":"她全心全意地照顾生病的母亲。","english":"She took care of her sick mother with all her heart.","traditional":"她全心全意地照顧生病的母親。"}],"synonyms":["尽心尽力","竭尽全力"],"antonyms":[],"confusedWith":[{"id":"尽心尽力","note":"尽心尽力 emphasizes doing one's best, which may not always imply the same level of emotional dedication as 全心全意."}],"traditional":"全心全意","pinyinOverride":null},{"id":"xing-gao-cai-lie","simplified":"兴高采烈","literalMeaning":"excitement high, spirits bright","figurativeMeaning":"in high spirits; elated","englishEquivalents":["on cloud nine","over the moon","in high spirits"],"shortGloss":"elated, in high spirits","characters":[{"char":"兴","meaning":"excitement"},{"char":"高","meaning":"high"},{"char":"采","meaning":"spirits"},{"char":"烈","meaning":"bright"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '兴高采烈' is commonly used to describe someone who is in high spirits or elated. It is often used to depict a state of joy and excitement, though its exact origin is not tied to a specific classical text. The phrase paints a vivid picture of someone whose excitement and enthusiasm are visibly high.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"coordinate","register":"widely used in both spoken and written Chinese, suitable for informal and formal contexts","connotation":"positive","commonMistakes":"Learners often confuse '兴高采烈' with idioms that describe general happiness. However, '兴高采烈' specifically conveys a sense of excitement and high spirits, not just contentment.","canStandAlone":false},"examples":[{"simplified":"他兴高采烈地告诉我们他得到了新工作。","english":"He told us with great excitement that he got a new job.","traditional":"他興高采烈地告訴我們他得到了新工作。"},{"simplified":"孩子们兴高采烈地跑进了游乐园。","english":"The children ran into the amusement park in high spirits.","traditional":"孩子們興高采烈地跑進了遊樂園。"}],"synonyms":["欢天喜地","喜气洋洋"],"antonyms":["愁眉苦脸"],"confusedWith":[{"id":"喜出望外","note":"While both express happiness, '喜出望外' emphasizes unexpected joy, whereas '兴高采烈' focuses on high spirits and excitement."}],"traditional":"興高采烈","pinyinOverride":null},{"id":"zai-jie-zai-li","simplified":"再接再厉","literalMeaning":"again press again sharpen","figurativeMeaning":"to continue to put in effort; to persist and work even harder","englishEquivalents":["keep up the good work","press on","keep pushing"],"shortGloss":"persist and work harder","characters":[{"char":"再","meaning":"again"},{"char":"接","meaning":"press on"},{"char":"再","meaning":"again"},{"char":"厉","meaning":"sharpen; exert"}],"origin":{"period":"Tang Dynasty (618–907)","sourceText":"《新唐书·李光弼传》","sourceTextEnglish":"New Book of Tang, Biography of Li Guangbi","originalExcerpt":"光弼再接再厉，卒破贼。","storyEnglish":"The idiom originates from a historical account in the 'New Book of Tang', where General Li Guangbi, after initial success in battle, was encouraged to continue his efforts and eventually achieved victory. The phrase '再接再厉' was used to describe his persistence and determination to keep pressing on and sharpening his efforts until the enemy was defeated.","historicalFigures":["Li Guangbi"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["adverbial","complement"],"structure":"coordinate","register":"commonly used in both formal and informal contexts","connotation":"positive","commonMistakes":"Learners often confuse this idiom with '再接再厉' (zài jiē zài lì) which does not exist. The mistake usually involves incorrect repetition of characters or misunderstanding its use as a standalone phrase.","canStandAlone":false},"examples":[{"simplified":"比赛虽然输了，但我们要再接再厉，争取下次胜利。","english":"Although we lost the match, we must keep up the effort and strive for victory next time.","traditional":"比賽雖然輸了，但我們要再接再厲，爭取下次勝利。"},{"simplified":"他在工作中再接再厉，终于得到了升职。","english":"He continued to work hard and was eventually promoted.","traditional":"他在工作中再接再厲，終於得到了升職。"}],"synonyms":["坚持不懈","锲而不舍"],"antonyms":["半途而废"],"confusedWith":[],"traditional":"再接再厲","pinyinOverride":null},{"id":"bing-tian-xue-di","simplified":"冰天雪地","literalMeaning":"ice sky snow ground","figurativeMeaning":"a world of ice and snow; extremely cold and snowy conditions","englishEquivalents":["a winter wonderland","frozen wasteland"],"shortGloss":"a world of ice and snow","characters":[{"char":"冰","meaning":"ice"},{"char":"天","meaning":"sky"},{"char":"雪","meaning":"snow"},{"char":"地","meaning":"ground"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '冰天雪地' is used to describe a landscape covered in ice and snow, typically evoking the imagery of harsh winter conditions. It is often used to emphasize the severity of the cold weather and the beauty or desolation of a snowy environment.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["attributive","adverbial"],"structure":"coordinate","register":"common in both spoken and written Chinese, often used in descriptive contexts","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with others that describe cold weather, but '冰天雪地' specifically emphasizes both the ice and snow aspect of the environment.","canStandAlone":false},"examples":[{"simplified":"在冰天雪地的环境中，动物们必须适应严酷的气候。","english":"In the icy and snowy environment, animals must adapt to the harsh climate.","traditional":"在冰天雪地的環境中，動物們必須適應嚴酷的氣候。"},{"simplified":"他们在冰天雪地中徒步旅行，欣赏冬日的美景。","english":"They hiked in the world of ice and snow, enjoying the winter scenery.","traditional":"他們在冰天雪地中徒步旅行，欣賞冬日的美景。"}],"synonyms":["白雪皑皑"],"antonyms":["烈日炎炎"],"confusedWith":[{"id":"白雪皑皑","note":"While both describe snowy conditions, '白雪皑皑' focuses more on the snow-covered aspect, whereas '冰天雪地' emphasizes both ice and snow."}],"traditional":"冰天雪地","pinyinOverride":null},{"id":"bing-shan-yi-jiao","simplified":"冰山一角","literalMeaning":"tip of the iceberg","figurativeMeaning":"a small, visible part of a much larger, hidden issue or problem","englishEquivalents":["tip of the iceberg"],"shortGloss":"a small part of a larger issue","characters":[{"char":"冰","meaning":"ice"},{"char":"山","meaning":"mountain"},{"char":"一","meaning":"one, a"},{"char":"角","meaning":"corner, tip"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '冰山一角' is derived from the metaphor of an iceberg, where only a small portion is visible above water while the majority remains hidden beneath the surface. This imagery is used to describe situations where only a small part of a problem or issue is apparent, while the larger part is concealed or not immediately obvious.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["subject","predicate","object","attributive"],"structure":"modifier-head","register":"commonly used in both formal and informal contexts","connotation":"neutral","commonMistakes":"Learners might mistakenly use this idiom to describe something small in size, rather than understanding it implies a larger hidden context. It is often confused with idioms that describe smallness without the implication of hidden depth.","canStandAlone":false},"examples":[{"simplified":"这个问题只是冰山一角，背后还有很多复杂的因素。","english":"This problem is just the tip of the iceberg; there are many complex factors behind it.","traditional":"這個問題只是冰山一角，背後還有很多複雜的因素。"},{"simplified":"我们看到的腐败只是冰山一角，真正的情况更严重。","english":"The corruption we see is just the tip of the iceberg; the real situation is more severe.","traditional":"我們看到的腐敗只是冰山一角，真正的情況更嚴重。"}],"synonyms":[],"antonyms":[],"confusedWith":[],"traditional":"冰山一角","pinyinOverride":null},{"id":"feng-mao-lin-jiao","simplified":"凤毛麟角","literalMeaning":"phoenix feathers and unicorn horns","figurativeMeaning":"something extremely rare and precious","englishEquivalents":["rare as hen's teeth","one in a million"],"shortGloss":"extremely rare and precious","characters":[{"char":"凤","meaning":"phoenix"},{"char":"毛","meaning":"feathers"},{"char":"麟","meaning":"unicorn"},{"char":"角","meaning":"horns"}],"origin":{"period":"Tang Dynasty (618–907 CE)","sourceText":"《新唐书·李泌传》","sourceTextEnglish":"New Book of Tang, Biography of Li Mi","originalExcerpt":"世之麟凤毛角，何足贵也。","storyEnglish":"The idiom originates from a passage in the 'New Book of Tang', where it is used to describe Li Mi, a highly esteemed and rare talent in the court. The phrase 'phoenix feathers and unicorn horns' is used metaphorically to emphasize the rarity and value of such a person.","historicalFigures":["Li Mi"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["attributive","predicate"],"structure":"coordinate","register":"literary, but very widely understood and used in ordinary speech","connotation":"positive","commonMistakes":"Learners may confuse this idiom with others that imply rarity but lack the connotation of value, such as '稀世珍宝' which specifically refers to rare treasures. '凤毛麟角' emphasizes both rarity and preciousness.","canStandAlone":false},"examples":[{"simplified":"他的才华真是凤毛麟角，难得一见。","english":"His talent is truly one in a million, extremely rare to see.","traditional":"他的才華真是鳳毛麟角，難得一見。"},{"simplified":"这种古董在市场上凤毛麟角，价格自然不菲。","english":"Such antiques are extremely rare in the market, so their price is naturally high.","traditional":"這種古董在市場上鳳毛麟角，價格自然不菲。"}],"synonyms":["稀世珍宝"],"antonyms":["比比皆是"],"confusedWith":[{"id":"稀世珍宝","note":"While both imply rarity, '稀世珍宝' specifically refers to rare treasures, not talents or qualities."}],"traditional":"鳳毛麟角","pinyinOverride":null},{"id":"chu-ren-yi-liao","simplified":"出人意料","literalMeaning":"exceed people's expectations","figurativeMeaning":"unexpected; surprising","englishEquivalents":["out of the blue","unexpectedly","to everyone's surprise"],"shortGloss":"unexpected; surprising","characters":[{"char":"出","meaning":"exceed"},{"char":"人","meaning":"people's"},{"char":"意","meaning":"expectations"},{"char":"料","meaning":"anticipation"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom 出人意料 is used to describe situations or outcomes that are surprising or not anticipated by people. It emphasizes the element of surprise or deviation from what was expected.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"modifier-head","register":"commonly used in both written and spoken Chinese","connotation":"neutral","commonMistakes":"Learners might confuse 出人意料 with idioms that imply shock or disbelief, but 出人意料 simply denotes something unexpected without necessarily being shocking.","canStandAlone":false},"examples":[{"simplified":"他的成功出人意料。","english":"His success was unexpected.","traditional":"他的成功出人意料。"},{"simplified":"比赛的结果出人意料。","english":"The result of the match was surprising.","traditional":"比賽的結果出人意料。"}],"synonyms":["出乎意料"],"antonyms":["意料之中"],"confusedWith":[{"id":"出乎意料","note":"Both mean unexpected, but 出乎意料 is more formal."}],"traditional":"出人意料","pinyinOverride":null},{"id":"chu-kou-cheng-zhang","simplified":"出口成章","literalMeaning":"exit mouth become chapter","figurativeMeaning":"to speak eloquently and fluently","englishEquivalents":["speak with eloquence","silver-tongued","words flow like a river"],"shortGloss":"speak eloquently","characters":[{"char":"出","meaning":"exit, come out"},{"char":"口","meaning":"mouth"},{"char":"成","meaning":"become, turn into"},{"char":"章","meaning":"chapter, composition"}],"origin":{"period":"Han Dynasty (206 BCE – 220 CE)","sourceText":"《世说新语·文学》","sourceTextEnglish":"A New Account of the Tales of the World, Literature","originalExcerpt":"王子猷出口成章，顷刻万变。","storyEnglish":"The idiom originates from a story about Wang Ziyou, a talented scholar known for his eloquence. It is said that he could produce beautiful and well-structured compositions as soon as he opened his mouth, impressing everyone with his quick wit and command of language.","historicalFigures":["Wang Ziyou"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"subject-predicate","register":"literary, but widely understood and used in speech","connotation":"positive","commonMistakes":"Learners might confuse this idiom with '出口伤人' (to speak hurtfully), which has a negative connotation. '出口成章' is always positive, highlighting eloquence and fluency.","canStandAlone":false},"examples":[{"simplified":"他在演讲中出口成章，赢得了观众的热烈掌声。","english":"He spoke eloquently during the speech, winning enthusiastic applause from the audience.","traditional":"他在演講中出口成章，贏得了觀眾的熱烈掌聲。"},{"simplified":"她总是能出口成章，令人佩服。","english":"She always speaks with eloquence, earning admiration from others.","traditional":"她總是能出口成章，令人佩服。"}],"synonyms":["妙语连珠"],"antonyms":["语无伦次"],"confusedWith":[{"id":"出口伤人","note":"出口伤人 means to speak hurtfully, which is negative, unlike the positive connotation of 出口成章."}],"traditional":"出口成章","pinyinOverride":null},{"id":"bie-ju-jiang-xin","simplified":"别具匠心","literalMeaning":"distinctly possess craftsman's heart","figurativeMeaning":"to have originality and ingenuity; to show unique creativity","englishEquivalents":["think outside the box","show originality","display creativity"],"shortGloss":"show originality and creativity","characters":[{"char":"别","meaning":"distinctly; separately"},{"char":"具","meaning":"possess; have"},{"char":"匠","meaning":"craftsman; artisan"},{"char":"心","meaning":"heart; mind"}],"origin":{"period":"Northern and Southern Dynasties (420–589)","sourceText":"《南史·王僧虔传》","sourceTextEnglish":"History of the Southern Dynasties, Biography of Wang Sengqian","originalExcerpt":"王僧虔云：“写字者，须自具匠心，别具一格。”","storyEnglish":"The idiom comes from a passage in the 'History of the Southern Dynasties' where Wang Sengqian, a notable calligrapher, emphasized the importance of originality in art. He stated that a calligrapher must possess a craftsman's heart and create works that are uniquely their own, setting them apart from others.","historicalFigures":["Wang Sengqian"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"verb-object","register":"literary, but widely used in both formal and informal contexts to praise creativity","connotation":"positive","commonMistakes":"Learners might confuse this idiom with others that simply mean 'creative' without the nuance of craftsmanship and originality. It specifically praises unique and skillful creativity.","canStandAlone":false},"examples":[{"simplified":"他的设计别具匠心，令人耳目一新。","english":"His design is uniquely creative and refreshing.","traditional":"他的設計別具匠心，令人耳目一新。"},{"simplified":"这位艺术家的作品总是别具匠心，令人赞叹。","english":"The artist's works always display originality and ingenuity, earning admiration.","traditional":"這位藝術家的作品總是別具匠心，令人讚歎。"}],"synonyms":["独具匠心"],"antonyms":["千篇一律"],"confusedWith":[{"id":"独具匠心","note":"Both idioms praise originality, but '独具匠心' emphasizes having a unique style."}],"traditional":"別具匠心","pinyinOverride":null},{"id":"gua-mu-xiang-kan","simplified":"刮目相看","literalMeaning":"scrape eyes and look at","figurativeMeaning":"to look at someone with new eyes; to have a newfound respect for someone","englishEquivalents":["see someone in a new light","have a newfound respect for someone"],"shortGloss":"see someone in a new light","characters":[{"char":"刮","meaning":"scrape"},{"char":"目","meaning":"eyes"},{"char":"相","meaning":"mutually"},{"char":"看","meaning":"look at"}],"origin":{"period":"Three Kingdoms period (220–280 CE)","sourceText":"《三国志·吴书·吕蒙传》","sourceTextEnglish":"Records of the Three Kingdoms, Book of Wu, Biography of Lü Meng","originalExcerpt":"士别三日，即更刮目相待。","storyEnglish":"The idiom originates from a story about Lü Meng, a general of the state of Wu during the Three Kingdoms period. Lü Meng was initially considered unremarkable, but after studying diligently, he became a respected strategist. His transformation prompted his superior, Sun Quan, to remark that one should not judge a person based on past impressions, as they may have changed significantly. Sun Quan advised others to 'scrape their eyes and look again' at Lü Meng, acknowledging his newfound abilities.","historicalFigures":["Lü Meng","Sun Quan"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"literary, but widely used in both spoken and written Chinese","connotation":"positive","commonMistakes":"Learners sometimes confuse this idiom with similar expressions that imply merely noticing someone, rather than recognizing a significant positive change in their abilities or character.","canStandAlone":false},"examples":[{"simplified":"经过多年的努力，他终于让同事们刮目相看。","english":"After years of hard work, he finally made his colleagues see him in a new light.","traditional":"經過多年的努力，他終於讓同事們刮目相看。"},{"simplified":"她的进步让老师们刮目相看。","english":"Her progress made the teachers look at her with newfound respect.","traditional":"她的進步讓老師們刮目相看。"}],"synonyms":["另眼相看"],"antonyms":[],"confusedWith":[{"id":"另眼相看","note":"While both idioms involve seeing someone differently, 刮目相看 emphasizes a positive change in perception due to improvement, whereas 另眼相看 can simply mean treating someone differently without the implication of improvement."}],"traditional":"刮目相看","pinyinOverride":null},{"id":"ke-bu-rong-huan","simplified":"刻不容缓","literalMeaning":"moment does not allow delay","figurativeMeaning":"extremely urgent; no time to lose","englishEquivalents":["no time to lose","time is of the essence"],"shortGloss":"extremely urgent","characters":[{"char":"刻","meaning":"moment"},{"char":"不","meaning":"not"},{"char":"容","meaning":"allow"},{"char":"缓","meaning":"delay"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '刻不容缓' is used to describe situations that are extremely urgent and require immediate attention. The phrase suggests that even a moment's delay is unacceptable. It is commonly used in modern Chinese to emphasize the urgency of an action or decision.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"modifier-head","register":"widely used in both formal and informal contexts","connotation":"neutral","commonMistakes":"Learners sometimes confuse this idiom with '迫在眉睫', which also indicates urgency but suggests something is imminent rather than simply urgent.","canStandAlone":false},"examples":[{"simplified":"这个项目刻不容缓，我们必须马上开始。","english":"This project is extremely urgent; we must start immediately.","traditional":"這個項目刻不容緩，我們必須馬上開始。"},{"simplified":"面对刻不容缓的危机，政府采取了紧急措施。","english":"Facing the urgent crisis, the government took emergency measures.","traditional":"面對刻不容緩的危機，政府採取了緊急措施。"}],"synonyms":["迫在眉睫","燃眉之急"],"antonyms":[],"confusedWith":[{"id":"迫在眉睫","note":"Both indicate urgency, but '迫在眉睫' suggests something is imminent and visible, whereas '刻不容缓' emphasizes the need for immediate action."}],"traditional":"刻不容緩","pinyinOverride":null},{"id":"ke-zhou-qiu-jian","simplified":"刻舟求剑","literalMeaning":"carve boat seek sword","figurativeMeaning":"to act without regard to changing circumstances; to be stubbornly inflexible","englishEquivalents":["to miss the forest for the trees","to be inflexible","to stick to the old ways"],"shortGloss":"ignoring changing circumstances","characters":[{"char":"刻","meaning":"carve"},{"char":"舟","meaning":"boat"},{"char":"求","meaning":"seek"},{"char":"剑","meaning":"sword"}],"origin":{"period":"Warring States period (475–221 BCE)","sourceText":"《吕氏春秋·察今》","sourceTextEnglish":"The Annals of Lü Buwei, Examining the Present","originalExcerpt":"楚人有涉江者，其剑自舟中坠于水，遽契其舟，曰：“是吾剑之所从坠。”舟止，从其所契者入水求之。","storyEnglish":"In the Warring States period, a man from the state of Chu was crossing a river when his sword fell into the water. He quickly carved a mark on the side of the boat to indicate where the sword had fallen. Once the boat stopped, he jumped into the water to search for the sword at the marked spot, not realizing that the boat had moved, and the sword was no longer there. This story illustrates the folly of not adapting to changing circumstances.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["subject","predicate","object"],"structure":"verb-object","register":"literary, but widely understood in modern contexts","connotation":"negative","commonMistakes":"Learners might confuse this idiom with others that involve boats or swords, but this one specifically emphasizes inflexibility and ignoring change. It should not be used to describe situations that are merely difficult or challenging.","canStandAlone":false},"examples":[{"simplified":"在这个快速变化的时代，刻舟求剑的做法是行不通的。","english":"In this rapidly changing era, the approach of ignoring changing circumstances is unworkable.","traditional":"在這個快速變化的時代，刻舟求劍的做法是行不通的。"},{"simplified":"他总是刻舟求剑，不愿意接受新的方法。","english":"He is always inflexible, unwilling to accept new methods.","traditional":"他總是刻舟求劍，不願意接受新的方法。"}],"synonyms":["墨守成规","抱残守缺"],"antonyms":["随机应变"],"confusedWith":[{"id":"刻骨铭心","note":"刻骨铭心 means 'unforgettable' and is unrelated to inflexibility or ignoring change."}],"traditional":"刻舟求劍","pinyinOverride":null},{"id":"qian-suo-wei-you","simplified":"前所未有","literalMeaning":"before this, not yet have","figurativeMeaning":"unprecedented; never before seen","englishEquivalents":["unprecedented","never before seen"],"shortGloss":"unprecedented","characters":[{"char":"前","meaning":"before"},{"char":"所","meaning":"place; here used as a particle for emphasis"},{"char":"未","meaning":"not yet"},{"char":"有","meaning":"have"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '前所未有' is used to describe something that has never happened before or is unprecedented. It emphasizes the novelty or uniqueness of an event or situation. The phrase has been used in various historical contexts to highlight the extraordinary nature of an occurrence.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["attributive","predicate"],"structure":"modifier-head","register":"commonly used in both formal and informal contexts","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with expressions that simply mean 'rare' or 'unusual'. '前所未有' specifically emphasizes that something has never happened before.","canStandAlone":false},"examples":[{"simplified":"这次的科技进步是前所未有的。","english":"This technological advancement is unprecedented.","traditional":"這次的科技進步是前所未有的。"},{"simplified":"他们面临着前所未有的挑战。","english":"They are facing unprecedented challenges.","traditional":"他們面臨著前所未有的挑戰。"}],"synonyms":["史无前例"],"antonyms":[],"confusedWith":[{"id":"罕见","note":"'罕见' means 'rare', which is not as strong as '前所未有', which means 'unprecedented'."}],"traditional":"前所未有","pinyinOverride":null},{"id":"qian-wu-gu-ren","simplified":"前无古人","literalMeaning":"before, no ancient people","figurativeMeaning":"unprecedented; never before achieved","englishEquivalents":["unprecedented","never before seen"],"shortGloss":"unprecedented achievement","characters":[{"char":"前","meaning":"before; in front"},{"char":"无","meaning":"no; none"},{"char":"古","meaning":"ancient"},{"char":"人","meaning":"people"}],"origin":{"period":"Tang dynasty (618–907 CE)","sourceText":"《旧唐书·魏徵传》","sourceTextEnglish":"Old Book of Tang, Biography of Wei Zheng","originalExcerpt":"前无古人，后无来者。","storyEnglish":"The idiom comes from a description of Wei Zheng, a prominent official during the Tang dynasty, who was praised for his unprecedented achievements and contributions. The phrase '前无古人' was used to highlight that no one before him had accomplished what he did.","historicalFigures":["Wei Zheng"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"modifier-head","register":"literary, but widely understood and used in both formal and informal contexts","connotation":"positive","commonMistakes":"Learners might confuse this idiom with those that imply something is unique or rare, but '前无古人' specifically emphasizes that something has never been achieved before.","canStandAlone":false},"examples":[{"simplified":"他的成就是前无古人的。","english":"His achievements are unprecedented.","traditional":"他的成就是前無古人的。"},{"simplified":"这项技术的突破是前无古人的。","english":"This technological breakthrough is unprecedented.","traditional":"這項技術的突破是前無古人的。"}],"synonyms":["空前绝后"],"antonyms":[],"confusedWith":[{"id":"独一无二","note":"While '独一无二' means unique or one of a kind, '前无古人' emphasizes that something has never been done before."}],"traditional":"前無古人","pinyinOverride":null},{"id":"qian-fu-hou-ji","simplified":"前赴后继","literalMeaning":"front advance, rear follow","figurativeMeaning":"to advance wave upon wave; to keep going despite setbacks","englishEquivalents":["one after another","in unending succession"],"shortGloss":"advance wave upon wave","characters":[{"char":"前","meaning":"front, forward"},{"char":"赴","meaning":"to go to, to advance"},{"char":"后","meaning":"rear, behind"},{"char":"继","meaning":"to follow, to succeed"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '前赴后继' describes a situation where people continue to advance or take action one after another, often in the face of adversity or danger. It conveys a sense of perseverance and determination, with each group or individual following the previous one without hesitation.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"coordinate","register":"literary, but widely understood and used in ordinary speech","connotation":"positive","commonMistakes":"Learners often confuse this idiom with those that imply a lack of organization or chaos, but '前赴后继' implies a determined and organized effort. It should not be used to describe situations that are merely chaotic or disorganized.","canStandAlone":false},"examples":[{"simplified":"在抗击疫情的过程中，医护人员前赴后继，不畏艰险。","english":"In the fight against the epidemic, medical staff advanced wave upon wave, undaunted by the dangers.","traditional":"在抗擊疫情的過程中，醫護人員前赴後繼，不畏艱險。"},{"simplified":"为了实现梦想，他前赴后继，从不放弃。","english":"In order to achieve his dreams, he kept going one after another, never giving up.","traditional":"為了實現夢想，他前赴後繼，從不放棄。"}],"synonyms":["前仆后继"],"antonyms":[],"confusedWith":[{"id":"乱七八糟","note":"前赴后继 implies organized perseverance, while 乱七八糟 implies chaos and disorder."}],"traditional":"前赴後繼","pinyinOverride":null},{"id":"li-bu-cong-xin","simplified":"力不从心","literalMeaning":"strength does not follow heart","figurativeMeaning":"to lack the ability to do what one wishes to do; to be unable to carry out one's intentions","englishEquivalents":["The spirit is willing, but the flesh is weak"],"shortGloss":"unable to do as one wishes","characters":[{"char":"力","meaning":"strength; ability"},{"char":"不","meaning":"not"},{"char":"从","meaning":"follow"},{"char":"心","meaning":"heart; intention"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '力不从心' describes a situation where one's desires or intentions are strong, but they lack the capability or resources to fulfill them. It is often used to express frustration when one's physical or situational limitations prevent them from achieving their goals.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","complement"],"structure":"subject-predicate","register":"commonly used in both spoken and written Chinese","connotation":"negative","commonMistakes":"Learners often confuse this idiom with '心有余而力不足', which has a similar meaning but emphasizes having more desire than strength. '力不从心' is more about the mismatch between intention and capability.","canStandAlone":false},"examples":[{"simplified":"他想帮助他们，但由于身体原因，他力不从心。","english":"He wanted to help them, but due to health reasons, he was unable to do so.","traditional":"他想幫助他們，但由於身體原因，他力不從心。"},{"simplified":"面对如此繁重的工作，他感到力不从心。","english":"Faced with such a heavy workload, he felt unable to cope.","traditional":"面對如此繁重的工作，他感到力不從心。"}],"synonyms":["心有余而力不足"],"antonyms":[],"confusedWith":[{"id":"心有余而力不足","note":"Both idioms express a mismatch between desire and ability, but '心有余而力不足' emphasizes having more desire than strength, while '力不从心' focuses on the inability to act on one's intentions."}],"traditional":"力不從心","pinyinOverride":null},{"id":"li-suo-neng-ji","simplified":"力所能及","literalMeaning":"strength that can reach","figurativeMeaning":"within one's capabilities; something one is able to do","englishEquivalents":["within one's power","within one's means"],"shortGloss":"within one's capabilities","characters":[{"char":"力","meaning":"strength, ability"},{"char":"所","meaning":"that which"},{"char":"能","meaning":"can, able to"},{"char":"及","meaning":"reach, extend to"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '力所能及' is commonly used to describe tasks or responsibilities that are within a person's ability to accomplish. It emphasizes doing what one is capable of, without overextending oneself. The phrase is often used to encourage people to contribute or help in ways that are manageable for them.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"modifier-head","register":"commonly used in both written and spoken Chinese","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with expressions that imply going beyond one's limits, such as '超越自我'. '力所能及' specifically refers to staying within one's capabilities.","canStandAlone":false},"examples":[{"simplified":"他总是愿意帮助别人，做一些力所能及的事情。","english":"He is always willing to help others by doing things within his capabilities.","traditional":"他總是願意幫助別人，做一些力所能及的事情。"},{"simplified":"我们应该在力所能及的范围内尽量帮助有需要的人。","english":"We should try our best to help those in need within the scope of our abilities.","traditional":"我們應該在力所能及的範圍內儘量幫助有需要的人。"}],"synonyms":["量力而行"],"antonyms":["力不从心"],"confusedWith":[{"id":"超越自我","note":"While '力所能及' means within one's capabilities, '超越自我' means to surpass oneself, often implying going beyond one's current limits."}],"traditional":"力所能及","pinyinOverride":null},{"id":"shi-bu-ke-dang","simplified":"势不可当","literalMeaning":"momentum cannot be resisted","figurativeMeaning":"unstoppable; too powerful to be resisted","englishEquivalents":["unstoppable force","irresistible momentum"],"shortGloss":"unstoppable force","characters":[{"char":"势","meaning":"momentum; force"},{"char":"不","meaning":"not; cannot"},{"char":"可","meaning":"can; able to"},{"char":"当","meaning":"resist; withstand"}],"origin":{"period":"Three Kingdoms period (220–280 CE)","sourceText":"《三国志·蜀书·诸葛亮传》","sourceTextEnglish":"Records of the Three Kingdoms, Shu Book, Biography of Zhuge Liang","originalExcerpt":"亮率大军南征，势不可当。","storyEnglish":"The idiom originates from the historical text 'Records of the Three Kingdoms', describing Zhuge Liang leading a powerful army on a southern campaign, with such momentum that it was described as 'unstoppable'. This phrase captures the idea of an overwhelming force that cannot be resisted.","historicalFigures":["Zhuge Liang"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"subject-predicate","register":"literary, but very widely understood and used in ordinary speech","connotation":"neutral","commonMistakes":"Learners sometimes confuse this idiom with others that imply a more negative or destructive force. It's important to note that '势不可当' can be used positively to describe any overwhelming force, not just destructive ones.","canStandAlone":false},"examples":[{"simplified":"他的事业发展势不可当，短短几年就成为行业领军人物。","english":"His career development was unstoppable, and within a few years, he became a leader in the industry.","traditional":"他的事業發展勢不可當，短短幾年就成為行業領軍人物。"},{"simplified":"这支球队的进攻势不可当，对手根本无法抵挡。","english":"The team's offense was unstoppable, and the opponents could not resist at all.","traditional":"這支球隊的進攻勢不可當，對手根本無法抵擋。"}],"synonyms":["势如破竹"],"antonyms":[],"confusedWith":[{"id":"所向披靡","note":"Both describe an unstoppable force, but '所向披靡' emphasizes defeating all opposition, while '势不可当' focuses on the unstoppable momentum itself."}],"traditional":"勢不可當","pinyinOverride":null},{"id":"yong-wang-zhi-qian","simplified":"勇往直前","literalMeaning":"bravely advance straight ahead","figurativeMeaning":"to advance courageously without hesitation","englishEquivalents":["forge ahead","press forward","go forward with courage"],"shortGloss":"advance courageously","characters":[{"char":"勇","meaning":"brave"},{"char":"往","meaning":"go"},{"char":"直","meaning":"straight"},{"char":"前","meaning":"ahead"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '勇往直前' is often used to describe someone who is determined and courageous, moving forward without fear or hesitation. It embodies the spirit of bravery and determination, encouraging people to face challenges head-on.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"widely used in both formal and informal contexts","connotation":"positive","commonMistakes":"Learners might confuse this idiom with others that imply recklessness. '勇往直前' emphasizes courage and determination, not rashness.","canStandAlone":false},"examples":[{"simplified":"在困难面前，我们必须勇往直前。","english":"In the face of difficulties, we must forge ahead.","traditional":"在困難面前，我們必須勇往直前。"},{"simplified":"他勇往直前地追求自己的梦想。","english":"He courageously pursued his dreams.","traditional":"他勇往直前地追求自己的夢想。"}],"synonyms":["奋勇向前","义无反顾"],"antonyms":["畏缩不前"],"confusedWith":[{"id":"鲁莽行事","note":"鲁莽行事 implies acting recklessly without thought, while 勇往直前 emphasizes courage and determination."}],"traditional":"勇往直前","pinyinOverride":null},{"id":"bao-luo-wan-xiang","simplified":"包罗万象","literalMeaning":"encompass myriad phenomena","figurativeMeaning":"to cover everything; all-inclusive","englishEquivalents":["all-encompassing","comprehensive"],"shortGloss":"all-encompassing","characters":[{"char":"包","meaning":"to include, to encompass"},{"char":"罗","meaning":"to gather, to collect"},{"char":"万","meaning":"ten thousand, myriad"},{"char":"象","meaning":"phenomena, things"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom 包罗万象 is believed to have originated from the idea of encompassing all things in the universe. It suggests a vast and comprehensive scope, where nothing is left out. The phrase is often used to describe something that is all-inclusive or covers a wide range of subjects.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["attributive","adverbial"],"structure":"modifier-head","register":"widely used in both formal and informal contexts","connotation":"neutral","commonMistakes":"Learners might confuse 包罗万象 with similar idioms that also imply comprehensiveness, but it's important to note that 包罗万象 emphasizes the inclusion of a wide variety of elements or aspects.","canStandAlone":false},"examples":[{"simplified":"这本百科全书包罗万象，几乎涵盖了所有的学科。","english":"This encyclopedia is all-encompassing, covering almost every discipline.","traditional":"這本百科全書包羅萬象，幾乎涵蓋了所有的學科。"},{"simplified":"他的知识面包罗万象，几乎没有他不知道的事情。","english":"His knowledge is all-encompassing; there's almost nothing he doesn't know.","traditional":"他的知識面包羅萬象，幾乎沒有他不知道的事情。"}],"synonyms":["无所不包","应有尽有"],"antonyms":[],"confusedWith":[{"id":"无所不包","note":"Both imply comprehensiveness, but 无所不包 emphasizes leaving nothing out, while 包罗万象 emphasizes including a wide variety."}],"traditional":"包羅萬象","pinyinOverride":null},{"id":"hua-xian-wei-yi","simplified":"化险为夷","literalMeaning":"turn danger into safety","figurativeMeaning":"to turn a dangerous situation into a safe one; to avert disaster","englishEquivalents":["turn the tide","avert disaster","pull through"],"shortGloss":"avert disaster, turn danger into safety","characters":[{"char":"化","meaning":"to transform"},{"char":"险","meaning":"danger"},{"char":"为","meaning":"to become"},{"char":"夷","meaning":"safe, level"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '化险为夷' is commonly used to describe situations where a potentially dangerous or disastrous scenario is successfully turned into a safe or favorable outcome. The phrase captures the idea of skillfully navigating through difficulties and emerging unscathed.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","object","adverbial"],"structure":"verb-object","register":"widely used in both formal and informal contexts","connotation":"positive","commonMistakes":"Learners might confuse this idiom with those that imply a permanent change, whereas '化险为夷' specifically refers to overcoming temporary danger. It should not be used to describe situations where the danger is not averted.","canStandAlone":false},"examples":[{"simplified":"经过大家的努力，我们终于化险为夷。","english":"Thanks to everyone's efforts, we finally averted disaster.","traditional":"經過大家的努力，我們終於化險為夷。"},{"simplified":"他总是能在关键时刻化险为夷。","english":"He always manages to turn danger into safety at critical moments.","traditional":"他總是能在關鍵時刻化險為夷。"}],"synonyms":["转危为安"],"antonyms":["雪上加霜"],"confusedWith":[{"id":"转危为安","note":"Both idioms mean averting danger, but '转危为安' emphasizes turning a crisis into peace."}],"traditional":"化險為夷","pinyinOverride":null},{"id":"qian-jun-wan-ma","simplified":"千军万马","literalMeaning":"thousands of troops and tens of thousands of horses","figurativeMeaning":"a powerful and overwhelming force; a large and formidable group","englishEquivalents":["an army of thousands","a mighty force"],"shortGloss":"a formidable and overwhelming force","characters":[{"char":"千","meaning":"thousand"},{"char":"军","meaning":"troops; army"},{"char":"万","meaning":"ten thousand"},{"char":"马","meaning":"horses"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '千军万马' is often used to describe a scene of a massive and powerful force, akin to an army with thousands of soldiers and horses. It conveys the idea of an overwhelming and formidable presence, often used in both literal and metaphorical contexts to emphasize strength and magnitude.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["subject","object","attributive"],"structure":"modifier-head","register":"commonly used in both written and spoken Chinese to describe overwhelming forces or situations","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with others that describe large numbers, but '千军万马' specifically emphasizes a powerful and overwhelming force, not just any large group.","canStandAlone":false},"examples":[{"simplified":"比赛开始时，千军万马般的观众涌入体育场。","english":"As the game began, a crowd like an army of thousands surged into the stadium.","traditional":"比賽開始時，千軍萬馬般的觀眾湧入體育場。"},{"simplified":"他在商场上如千军万马般势不可挡。","english":"In the business world, he is as unstoppable as a mighty force.","traditional":"他在商場上如千軍萬馬般勢不可擋。"}],"synonyms":["人山人海"],"antonyms":[],"confusedWith":[{"id":"人山人海","note":"While both describe large numbers, '人山人海' emphasizes a large crowd of people, not necessarily a powerful force."}],"traditional":"千軍萬馬","pinyinOverride":null},{"id":"qian-bian-wan-hua","simplified":"千变万化","literalMeaning":"thousand changes, ten thousand transformations","figurativeMeaning":"ever-changing; constantly changing in a myriad of ways","englishEquivalents":["ever-changing","constantly evolving"],"shortGloss":"ever-changing","characters":[{"char":"千","meaning":"thousand"},{"char":"变","meaning":"change"},{"char":"万","meaning":"ten thousand"},{"char":"化","meaning":"transform"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '千变万化' is used to describe something that is constantly changing or evolving in countless ways. It emphasizes the idea of transformation and variability, often used to describe nature, technology, or situations that are dynamic and unpredictable.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"coordinate","register":"commonly used in both written and spoken Chinese","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with others that involve change but have a more specific context, such as '变化多端', which also implies deceit or trickery. '千变万化' is more neutral and broad in scope.","canStandAlone":false},"examples":[{"simplified":"现代科技的发展速度千变万化，让人难以跟上。","english":"The speed of modern technological development is ever-changing, making it hard for people to keep up.","traditional":"現代科技的發展速度千變萬化，讓人難以跟上。"},{"simplified":"大自然的景色千变万化，每一刻都有不同的美。","english":"The scenery of nature is ever-changing, with different beauty at every moment.","traditional":"大自然的景色千變萬化，每一刻都有不同的美。"}],"synonyms":["变化多端"],"antonyms":[],"confusedWith":[{"id":"变化多端","note":"While both idioms involve change, '变化多端' often implies unpredictability or deceit, whereas '千变万化' is more neutral and broad."}],"traditional":"千變萬化","pinyinOverride":null},{"id":"qian-zi-bai-tai","simplified":"千姿百态","literalMeaning":"thousand postures, hundred forms","figurativeMeaning":"in a variety of shapes and expressions; diverse and varied","englishEquivalents":["in all shapes and sizes","a myriad of forms"],"shortGloss":"diverse and varied forms","characters":[{"char":"千","meaning":"thousand"},{"char":"姿","meaning":"postures"},{"char":"百","meaning":"hundred"},{"char":"态","meaning":"forms"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '千姿百态' is used to describe something that appears in many different forms or expressions. It is often used to describe natural scenery, art, or human expressions, emphasizing the diversity and variety present in the subject.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["attributive","adverbial"],"structure":"coordinate","register":"widely used in both written and spoken Chinese, suitable for both formal and informal contexts","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with others that describe diversity, such as '五花八门', which specifically refers to a wide variety of things, often with a sense of complexity or confusion. '千姿百态' focuses more on the diversity of appearances or expressions.","canStandAlone":false},"examples":[{"simplified":"公园里的花卉千姿百态，美不胜收。","english":"The flowers in the park are in a myriad of forms, overwhelmingly beautiful.","traditional":"公園裡的花卉千姿百態，美不勝收。"},{"simplified":"艺术展上的作品千姿百态，各具特色。","english":"The artworks at the exhibition are diverse and varied, each with its own unique style.","traditional":"藝術展上的作品千姿百態，各具特色。"}],"synonyms":["五花八门"],"antonyms":[],"confusedWith":[{"id":"五花八门","note":"While both describe diversity, '五花八门' often implies a wide range of types or categories, sometimes with a sense of complexity."}],"traditional":"千姿百態","pinyinOverride":null},{"id":"qian-fang-bai-ji","simplified":"千方百计","literalMeaning":"thousand methods hundred plans","figurativeMeaning":"to try every possible way; to do everything possible","englishEquivalents":["leave no stone unturned","by hook or by crook"],"shortGloss":"try every possible way","characters":[{"char":"千","meaning":"thousand"},{"char":"方","meaning":"methods"},{"char":"百","meaning":"hundred"},{"char":"计","meaning":"plans"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '千方百计' is believed to have originated from the idea of using numerous methods and plans to achieve a goal. It emphasizes the determination and creativity involved in overcoming obstacles by trying every possible approach.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["adverbial","complement"],"structure":"coordinate","register":"widely used in both spoken and written Chinese","connotation":"neutral","commonMistakes":"Learners may confuse this idiom with similar expressions that imply deceit or trickery. '千方百计' does not inherently carry a negative connotation and simply emphasizes effort and resourcefulness.","canStandAlone":false},"examples":[{"simplified":"为了完成这个项目，他千方百计地寻找解决方案。","english":"In order to complete this project, he tried every possible way to find a solution.","traditional":"為了完成這個項目，他千方百計地尋找解決方案。"},{"simplified":"她千方百计地想让孩子们开心。","english":"She tried every possible way to make the children happy.","traditional":"她千方百計地想讓孩子們開心。"}],"synonyms":["想方设法"],"antonyms":[],"confusedWith":[{"id":"不择手段","note":"While '不择手段' implies using unscrupulous methods, '千方百计' focuses on effort and resourcefulness without a negative connotation."}],"traditional":"千方百計","pinyinOverride":null},{"id":"ban-xin-ban-yi","simplified":"半信半疑","literalMeaning":"half believe, half doubt","figurativeMeaning":"to be skeptical or doubtful; to be unsure whether to believe something","englishEquivalents":["to be on the fence","to have doubts","to be in two minds"],"shortGloss":"skeptical or doubtful","characters":[{"char":"半","meaning":"half"},{"char":"信","meaning":"believe"},{"char":"半","meaning":"half"},{"char":"疑","meaning":"doubt"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '半信半疑' describes a state of being where someone is unsure whether to believe something or not. It reflects a mixed feeling of belief and doubt, often arising when one encounters information that is not entirely convincing or lacks sufficient evidence.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"coordinate","register":"widely used in both spoken and written Chinese","connotation":"neutral","commonMistakes":"Learners often confuse '半信半疑' with '将信将疑', which also means to be doubtful but implies a slightly stronger inclination towards belief. '半信半疑' is more balanced between belief and doubt.","canStandAlone":false},"examples":[{"simplified":"他对这个消息半信半疑，不知道该不该相信。","english":"He was skeptical about the news and didn't know whether to believe it.","traditional":"他對這個消息半信半疑，不知道該不該相信。"},{"simplified":"听到这个故事，我半信半疑，总觉得有些不真实。","english":"Hearing the story, I was doubtful, always feeling it was somewhat unreal.","traditional":"聽到這個故事，我半信半疑，總覺得有些不真實。"}],"synonyms":["将信将疑"],"antonyms":[],"confusedWith":[{"id":"将信将疑","note":"Both express doubt, but '将信将疑' leans more towards belief than '半信半疑'."}],"traditional":"半信半疑","pinyinOverride":null},{"id":"ban-tu-er-fei","simplified":"半途而废","literalMeaning":"halfway and abandon","figurativeMeaning":"to give up halfway; to leave something unfinished","englishEquivalents":["give up halfway","leave unfinished","throw in the towel"],"shortGloss":"give up halfway","characters":[{"char":"半","meaning":"half"},{"char":"途","meaning":"way; journey"},{"char":"而","meaning":"and; but"},{"char":"废","meaning":"abandon; discard"}],"origin":{"period":"Han Dynasty (206 BCE – 220 CE)","sourceText":"《战国策·秦策一》","sourceTextEnglish":"Strategies of the Warring States, Strategies of Qin I","originalExcerpt":"锲而舍之，朽木不折；锲而不舍，金石可镂。","storyEnglish":"The idiom comes from a story in the 'Strategies of the Warring States', where it is said that if one chisels and then gives up, even rotten wood won't break; but if one chisels without giving up, even metal and stone can be engraved. This emphasizes the importance of perseverance and not abandoning tasks halfway.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"widely used in both written and spoken Chinese","connotation":"negative","commonMistakes":"Learners often confuse it with idioms that imply completion, such as '功德圆满'. 半途而废 specifically means not finishing something, which is a negative trait.","canStandAlone":false},"examples":[{"simplified":"他总是半途而废，从来没有完成过一个项目。","english":"He always gives up halfway and has never completed a single project.","traditional":"他總是半途而廢，從來沒有完成過一個項目。"},{"simplified":"学习一门语言需要坚持不懈，而不是半途而废。","english":"Learning a language requires perseverance, not giving up halfway.","traditional":"學習一門語言需要堅持不懈，而不是半途而廢。"}],"synonyms":["虎头蛇尾"],"antonyms":["坚持不懈","持之以恒"],"confusedWith":[{"id":"功德圆满","note":"功德圆满 means to complete something perfectly, which is the opposite of giving up halfway."}],"traditional":"半途而廢","pinyinOverride":null},{"id":"nan-yuan-bei-zhe","simplified":"南辕北辙","literalMeaning":"south rein north track","figurativeMeaning":"to act in a way that defeats one's purpose; to go about something in a completely wrong way","englishEquivalents":["to go against one's own interests","to run counter to one's goals"],"shortGloss":"acting counter to one's goals","characters":[{"char":"南","meaning":"south"},{"char":"辕","meaning":"carriage shaft; rein"},{"char":"北","meaning":"north"},{"char":"辙","meaning":"track; rut"}],"origin":{"period":"Warring States period (475–221 BCE)","sourceText":"《战国策·魏策四》","sourceTextEnglish":"Strategies of the Warring States, Strategies of Wei, Chapter 4","originalExcerpt":"今者臣来，见人于道北行而马南向，问之，曰：‘我欲之楚。’","storyEnglish":"During the Warring States period, a man from the state of Wei wanted to travel to the state of Chu. He set out on his journey, but despite his intentions, he was heading north while his destination was to the south. When questioned, he insisted that he was going to Chu, but his actions were leading him in the opposite direction. This story illustrates the futility of one's efforts when actions contradict goals.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"literary, but widely understood and used in both formal and informal contexts","connotation":"negative","commonMistakes":"Learners might use this idiom to describe any kind of mistake, but it specifically refers to actions that directly contradict one's stated goals. It is not a general term for errors.","canStandAlone":false},"examples":[{"simplified":"他一边想省钱，一边却不停地购物，真是南辕北辙。","english":"He wants to save money, yet he keeps shopping non-stop; he's really going against his own goals.","traditional":"他一邊想省錢，一邊卻不停地購物，真是南轅北轍。"},{"simplified":"如果你想减肥，却每天吃快餐，这就是南辕北辙。","english":"If you want to lose weight but eat fast food every day, that's counterproductive.","traditional":"如果你想減肥，卻每天吃快餐，這就是南轅北轍。"}],"synonyms":[],"antonyms":[],"confusedWith":[{"id":"背道而驰","note":"Both idioms describe actions that are contrary to goals, but 背道而驰 emphasizes moving in opposite directions, while 南辕北辙 focuses on actions contradicting intentions."}],"traditional":"南轅北轍","pinyinOverride":null},{"id":"bo-da-jing-shen","simplified":"博大精深","literalMeaning":"broad, great, refined, deep","figurativeMeaning":"profound and extensive; having great depth and breadth, often used to describe knowledge, culture, or art","englishEquivalents":["profound and extensive","deep and broad"],"shortGloss":"profound and extensive","characters":[{"char":"博","meaning":"broad, extensive"},{"char":"大","meaning":"great, large"},{"char":"精","meaning":"refined, precise"},{"char":"深","meaning":"deep, profound"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '博大精深' is often used to describe something that is both extensive in scope and profound in depth, such as a body of knowledge, a cultural tradition, or an artistic work. It emphasizes both the breadth and the depth of the subject, suggesting that it is not only wide-ranging but also deeply insightful and sophisticated.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["attributive","predicate"],"structure":"coordinate","register":"commonly used in both formal and informal contexts to describe complex subjects","connotation":"positive","commonMistakes":"Learners might confuse '博大精深' with idioms that only imply depth or breadth, but this idiom specifically emphasizes both qualities. It should not be used to describe something that is only large or only profound.","canStandAlone":false},"examples":[{"simplified":"中国文化博大精深，吸引了全世界的学者。","english":"Chinese culture is profound and extensive, attracting scholars from all over the world.","traditional":"中國文化博大精深，吸引了全世界的學者。"},{"simplified":"他的知识博大精深，让人佩服。","english":"His knowledge is profound and extensive, earning admiration from others.","traditional":"他的知識博大精深，讓人佩服。"}],"synonyms":["深不可测","渊博"],"antonyms":[],"confusedWith":[{"id":"深不可测","note":"While both describe depth, '深不可测' emphasizes unfathomable depth without the breadth implied by '博大精深'."}],"traditional":"博大精深","pinyinOverride":null},{"id":"yuan-zhi-yuan-wei","simplified":"原汁原味","literalMeaning":"original juice, original taste","figurativeMeaning":"authentic; in its original form; unaltered","englishEquivalents":["true to the original","authentic","in its original form"],"shortGloss":"authentic; unaltered","characters":[{"char":"原","meaning":"original"},{"char":"汁","meaning":"juice"},{"char":"原","meaning":"original"},{"char":"味","meaning":"taste"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '原汁原味' is used to describe something that is kept in its original state, without any alterations or modifications. It emphasizes authenticity and the preservation of the original qualities, much like savoring the original taste and juice of a fruit.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["attributive","adverbial"],"structure":"coordinate","register":"commonly used in both spoken and written Chinese to emphasize authenticity","connotation":"positive","commonMistakes":"Learners might confuse this idiom with phrases that suggest imitation or reproduction. It specifically emphasizes the original and unaltered state, unlike '仿制' (imitation) or '复制' (reproduction).","canStandAlone":false},"examples":[{"simplified":"这道菜是原汁原味的意大利风味。","english":"This dish is authentic Italian flavor.","traditional":"這道菜是原汁原味的意大利風味。"},{"simplified":"他喜欢看原汁原味的外国电影，不喜欢配音版。","english":"He likes to watch foreign films in their original form, not dubbed versions.","traditional":"他喜歡看原汁原味的外國電影，不喜歡配音版。"}],"synonyms":["地道","纯正"],"antonyms":["改头换面"],"confusedWith":[{"id":"仿制","note":"仿制 means imitation, which is different from maintaining the original state."}],"traditional":"原汁原味","pinyinOverride":null},{"id":"fa-yang-guang-da","simplified":"发扬光大","literalMeaning":"develop and glorify","figurativeMeaning":"to enhance and carry forward; to develop and promote","englishEquivalents":["carry forward","promote and enhance"],"shortGloss":"enhance and promote","characters":[{"char":"发","meaning":"develop"},{"char":"扬","meaning":"promote"},{"char":"光","meaning":"glorify"},{"char":"大","meaning":"expand"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '发扬光大' is often used to describe the process of taking something valuable, such as a tradition, skill, or idea, and further developing it to reach a wider audience or to enhance its impact. It emphasizes the importance of not only preserving but also improving and expanding upon what has been inherited from the past.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","object","attributive"],"structure":"verb-object","register":"widely used in both formal and informal contexts","connotation":"positive","commonMistakes":"Learners might confuse this idiom with ones that only imply preservation rather than active enhancement and promotion. It is important to note that '发扬光大' involves an element of development and expansion.","canStandAlone":false},"examples":[{"simplified":"我们应该努力发扬光大传统文化。","english":"We should strive to enhance and promote traditional culture.","traditional":"我們應該努力發揚光大傳統文化。"},{"simplified":"这家公司成功地发扬光大了他们的核心价值。","english":"The company successfully enhanced and promoted their core values.","traditional":"這家公司成功地發揚光大了他們的核心價值。"}],"synonyms":["继往开来"],"antonyms":[],"confusedWith":[{"id":"继承传统","note":"继承传统 focuses on inheriting and preserving traditions, while 发扬光大 emphasizes development and promotion."}],"traditional":"發揚光大","pinyinOverride":null},{"id":"qu-er-dai-zhi","simplified":"取而代之","literalMeaning":"take and replace it","figurativeMeaning":"to replace someone or something; to take over","englishEquivalents":["take over","supplant","replace"],"shortGloss":"to replace or supplant","characters":[{"char":"取","meaning":"take"},{"char":"而","meaning":"and then"},{"char":"代","meaning":"replace"},{"char":"之","meaning":"it"}],"origin":{"period":"Warring States period (475–221 BCE)","sourceText":"《孟子·梁惠王下》","sourceTextEnglish":"Mencius, King Hui of Liang II","originalExcerpt":"取而代之，若寇仇然。","storyEnglish":"The idiom comes from a passage in the book 'Mencius' where Mencius discusses the concept of one ruler replacing another as if they were enemies. This idea of taking over or supplanting is captured in the phrase '取而代之'.","historicalFigures":["Mencius"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","object"],"structure":"verb-object","register":"literary, but widely used in both formal and informal contexts","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with similar phrases that imply cooperation rather than replacement. It's important to note that this idiom specifically implies taking over or supplanting.","canStandAlone":false},"examples":[{"simplified":"新公司计划取而代之，成为市场的领导者。","english":"The new company plans to take over and become the market leader.","traditional":"新公司計劃取而代之，成為市場的領導者。"},{"simplified":"他努力工作，希望有一天能取而代之。","english":"He works hard, hoping to one day take over.","traditional":"他努力工作，希望有一天能取而代之。"}],"synonyms":["取代","顶替"],"antonyms":[],"confusedWith":[{"id":"合作共赢","note":"合作共赢 means 'win-win cooperation', which implies working together rather than replacing or supplanting."}],"traditional":"取而代之","pinyinOverride":null},{"id":"shou-chong-ruo-jing","simplified":"受宠若惊","literalMeaning":"receive favor as if alarmed","figurativeMeaning":"to be overwhelmed or flattered by unexpected favor or attention","englishEquivalents":["taken aback by favor","flattered and surprised"],"shortGloss":"overwhelmed by unexpected favor","characters":[{"char":"受","meaning":"receive"},{"char":"宠","meaning":"favor"},{"char":"若","meaning":"as if"},{"char":"惊","meaning":"alarmed; surprised"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom describes the feeling of being unexpectedly favored or praised to the point of being startled or overwhelmed. It reflects the idea that someone is so surprised by the attention or favor they receive that they react with a mix of joy and disbelief.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","complement"],"structure":"modifier-head","register":"commonly used in both spoken and written Chinese","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with expressions that solely convey surprise without the element of receiving favor. It specifically implies being flattered or honored, not just surprised.","canStandAlone":false},"examples":[{"simplified":"当他被邀请上台领奖时，他感到受宠若惊。","english":"When he was invited on stage to receive the award, he felt overwhelmed by the unexpected favor.","traditional":"當他被邀請上臺領獎時，他感到受寵若驚。"},{"simplified":"老板突然称赞了他的工作表现，让他受宠若惊。","english":"The boss suddenly praised his work performance, which left him flattered and surprised.","traditional":"老闆突然稱讚了他的工作表現，讓他受寵若驚。"}],"synonyms":["受之无愧","受宠若惊"],"antonyms":[],"confusedWith":[{"id":"大吃一惊","note":"大吃一惊 means to be greatly surprised or shocked, without the aspect of receiving favor."}],"traditional":"受寵若驚","pinyinOverride":null},{"id":"shou-yi-fei-qian","simplified":"受益匪浅","literalMeaning":"benefit not shallow","figurativeMeaning":"to greatly benefit from something","englishEquivalents":["gain a lot","learn a lot","benefit greatly"],"shortGloss":"to benefit greatly","characters":[{"char":"受","meaning":"receive"},{"char":"益","meaning":"benefit"},{"char":"匪","meaning":"not"},{"char":"浅","meaning":"shallow"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '受益匪浅' is used to express that someone has gained significant benefits or insights from an experience or event. The phrase suggests that the benefits received are deep and substantial, rather than superficial.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","complement"],"structure":"modifier-head","register":"widely used in both formal and informal contexts","connotation":"positive","commonMistakes":"Learners often confuse '受益匪浅' with '受益无穷', which means 'benefit endlessly'. '受益匪浅' emphasizes significant benefits, while '受益无穷' suggests benefits that are limitless.","canStandAlone":false},"examples":[{"simplified":"通过这次培训，我受益匪浅。","english":"I benefited greatly from this training.","traditional":"通過這次培訓，我受益匪淺。"},{"simplified":"读这本书让我受益匪浅。","english":"Reading this book has benefited me greatly.","traditional":"讀這本書讓我受益匪淺。"}],"synonyms":["获益良多"],"antonyms":[],"confusedWith":[{"id":"受益无穷","note":"受益无穷 means 'benefit endlessly', emphasizing limitless benefits rather than significant ones."}],"traditional":"受益匪淺","pinyinOverride":null},{"id":"bian-huan-mo-ce","simplified":"变幻莫测","literalMeaning":"change unpredictable measure","figurativeMeaning":"unpredictable; constantly changing and difficult to predict","englishEquivalents":["unpredictable","ever-changing"],"shortGloss":"unpredictable and ever-changing","characters":[{"char":"变","meaning":"change"},{"char":"幻","meaning":"illusion; fantasy"},{"char":"莫","meaning":"cannot"},{"char":"测","meaning":"measure; fathom"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '变幻莫测' is often used to describe situations, environments, or phenomena that are constantly changing and difficult to predict. It emphasizes the idea of unpredictability and the inability to foresee what will happen next. The exact origin of this idiom is not well-documented, but it has been used in Chinese literature and speech to convey the concept of change that is beyond human control or understanding.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"modifier-head","register":"widely used in both formal and informal contexts","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with others that imply change, but '变幻莫测' specifically emphasizes unpredictability and the inability to measure or foresee changes.","canStandAlone":false},"examples":[{"simplified":"天气变幻莫测，我们最好带上雨伞。","english":"The weather is unpredictable, so we should bring an umbrella.","traditional":"天氣變幻莫測，我們最好帶上雨傘。"},{"simplified":"股市行情变幻莫测，投资者需要谨慎。","english":"The stock market is unpredictable, and investors need to be cautious.","traditional":"股市行情變幻莫測，投資者需要謹慎。"}],"synonyms":["变化无常"],"antonyms":[],"confusedWith":[{"id":"变化无常","note":"While both idioms describe change, '变化无常' emphasizes inconsistency, whereas '变幻莫测' emphasizes unpredictability."}],"traditional":"變幻莫測","pinyinOverride":null},{"id":"gu-jin-zhong-wai","simplified":"古今中外","literalMeaning":"ancient and modern, Chinese and foreign","figurativeMeaning":"throughout all times and places; universally","englishEquivalents":["throughout history and across the world","universally"],"shortGloss":"universally, across all times and places","characters":[{"char":"古","meaning":"ancient"},{"char":"今","meaning":"modern"},{"char":"中","meaning":"Chinese"},{"char":"外","meaning":"foreign"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '古今中外' is used to express the idea that something is universally applicable or recognized throughout all times and places. It emphasizes the comprehensive nature of a statement or idea, suggesting that it holds true regardless of the era or geographical location.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["adverbial","attributive"],"structure":"coordinate","register":"commonly used in both formal and informal contexts","connotation":"neutral","commonMistakes":"Learners might mistakenly use this idiom to refer to something specific to a certain time or place, but it actually implies universality. It should not be used to describe something that is only relevant in a particular context.","canStandAlone":false},"examples":[{"simplified":"这个道理古今中外都适用。","english":"This principle is applicable throughout all times and places.","traditional":"這個道理古今中外都適用。"},{"simplified":"古今中外的文化都有其独特的魅力。","english":"Cultures from all times and places have their unique charm.","traditional":"古今中外的文化都有其獨特的魅力。"}],"synonyms":[],"antonyms":[],"confusedWith":[],"traditional":"古今中外","pinyinOverride":null},{"id":"ke-cheng-zhi-ji","simplified":"可乘之机","literalMeaning":"an opportunity that can be taken advantage of","figurativeMeaning":"an opportunity that can be exploited or taken advantage of","englishEquivalents":["a window of opportunity","an opening","a chance to capitalize"],"shortGloss":"an exploitable opportunity","characters":[{"char":"可","meaning":"can, able to"},{"char":"乘","meaning":"to ride, to take advantage of"},{"char":"之","meaning":"of, possessive particle"},{"char":"机","meaning":"opportunity, chance"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '可乘之机' describes a situation where an opportunity arises that can be taken advantage of. It is often used in contexts where someone is looking for or has found a chance to achieve something, especially in competitive or strategic situations.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["object","attributive"],"structure":"modifier-head","register":"commonly used in both written and spoken Chinese","connotation":"neutral","commonMistakes":"Learners often confuse this idiom with similar expressions that imply a more negative connotation, such as '趁虚而入', which suggests taking advantage of someone's weakness. '可乘之机' is neutral and does not imply any moral judgment.","canStandAlone":false},"examples":[{"simplified":"他一直在等待一个可乘之机来展示他的才能。","english":"He has been waiting for a window of opportunity to showcase his talents.","traditional":"他一直在等待一個可乘之機來展示他的才能。"},{"simplified":"在谈判中，我们必须找到一个可乘之机来达成协议。","english":"In the negotiations, we must find an opening to reach an agreement.","traditional":"在談判中，我們必須找到一個可乘之機來達成協議。"}],"synonyms":["机会","良机"],"antonyms":[],"confusedWith":[{"id":"趁虚而入","note":"趁虚而入 implies taking advantage of a weakness, whereas 可乘之机 is neutral and simply refers to an opportunity."}],"traditional":"可乘之機","pinyinOverride":null},{"id":"ke-xiang-er-zhi","simplified":"可想而知","literalMeaning":"can think and know","figurativeMeaning":"it is obvious; it goes without saying","englishEquivalents":["it stands to reason","it's clear","obviously"],"shortGloss":"it is obvious","characters":[{"char":"可","meaning":"can; able to"},{"char":"想","meaning":"think; imagine"},{"char":"而","meaning":"and; thus"},{"char":"知","meaning":"know"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '可想而知' is used to express that something is so evident or logical that it can be easily understood or deduced without needing further explanation. It emphasizes the obviousness of a situation or conclusion.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"modifier-head","register":"commonly used in both spoken and written Chinese, suitable for informal and formal contexts","connotation":"neutral","commonMistakes":"Learners might mistakenly use this idiom to describe something that is not obvious or requires detailed explanation. It should only be used when the conclusion is clear and evident.","canStandAlone":false},"examples":[{"simplified":"他每天都在努力学习，他的成绩可想而知会很好。","english":"He studies hard every day, so it's obvious that his grades will be good.","traditional":"他每天都在努力學習，他的成績可想而知會很好。"},{"simplified":"在这样的天气里，交通状况可想而知会很糟糕。","english":"In such weather, it's clear that the traffic conditions will be terrible.","traditional":"在這樣的天氣裡，交通狀況可想而知會很糟糕。"}],"synonyms":["不言而喻"],"antonyms":[],"confusedWith":[{"id":"不言而喻","note":"Both idioms mean something is obvious, but '不言而喻' emphasizes that it doesn't need to be spoken, while '可想而知' focuses on being able to deduce it."}],"traditional":"可想而知","pinyinOverride":null},{"id":"shi-wu-qian-li","simplified":"史无前例","literalMeaning":"history has no previous example","figurativeMeaning":"unprecedented; never happened before","englishEquivalents":["unprecedented","never before seen"],"shortGloss":"unprecedented","characters":[{"char":"史","meaning":"history"},{"char":"无","meaning":"without; no"},{"char":"前","meaning":"previous"},{"char":"例","meaning":"example"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '史无前例' is used to describe situations or events that have never occurred before in history. It emphasizes the uniqueness and novelty of a circumstance, suggesting that there is no historical precedent to draw upon. This phrase is often used in both formal and informal contexts to highlight the groundbreaking nature of an event or action.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"modifier-head","register":"widely used in both formal and informal contexts","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with '前所未有', which also means unprecedented but is more focused on the absence of prior occurrence rather than the historical aspect.","canStandAlone":false},"examples":[{"simplified":"这次的经济危机是史无前例的。","english":"This economic crisis is unprecedented.","traditional":"這次的經濟危機是史無前例的。"},{"simplified":"他的创新设计在业界是史无前例的。","english":"His innovative design is unprecedented in the industry.","traditional":"他的創新設計在業界是史無前例的。"}],"synonyms":["前所未有"],"antonyms":[],"confusedWith":[{"id":"前所未有","note":"Both mean unprecedented, but '前所未有' focuses more on the absence of prior occurrence."}],"traditional":"史無前例","pinyinOverride":null},{"id":"si-kong-jian-guan","simplified":"司空见惯","literalMeaning":"Si Kong sees as usual","figurativeMeaning":"something that is commonly seen or a common occurrence","englishEquivalents":["a dime a dozen","commonplace","nothing out of the ordinary"],"shortGloss":"a common sight","characters":[{"char":"司","meaning":"Si (a surname, referring to an official title)"},{"char":"空","meaning":"Kong (a surname, referring to an official title)"},{"char":"见","meaning":"see"},{"char":"惯","meaning":"accustomed to"}],"origin":{"period":"Tang Dynasty (618–907 CE)","sourceText":"《世说新语·排调》","sourceTextEnglish":"A New Account of the Tales of the World, Section on Ridicule","originalExcerpt":"司空见惯，浑不足怪。","storyEnglish":"During the Tang Dynasty, there was an official titled 'Si Kong' who was known for seeing many things as ordinary due to his vast experience. The phrase '司空见惯' was used to describe his attitude towards things that others might find surprising but were routine for him.","historicalFigures":["Si Kong"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","object","attributive"],"structure":"subject-predicate","register":"literary, but very widely understood and used in ordinary speech","connotation":"neutral","commonMistakes":"Learners often confuse this idiom with expressions that imply rarity or uniqueness. It specifically refers to things that are common and not surprising.","canStandAlone":false},"examples":[{"simplified":"在大城市，交通堵塞是司空见惯的事情。","english":"In big cities, traffic jams are a common occurrence.","traditional":"在大城市，交通堵塞是司空見慣的事情。"},{"simplified":"他对这种批评已经司空见惯，不再感到生气。","english":"He is so used to this kind of criticism that he no longer gets angry.","traditional":"他對這種批評已經司空見慣，不再感到生氣。"}],"synonyms":["习以为常"],"antonyms":["凤毛麟角"],"confusedWith":[{"id":"习以为常","note":"Both idioms refer to something being common, but 习以为常 emphasizes being accustomed to it."}],"traditional":"司空見慣","pinyinOverride":null},{"id":"chi-he-wan-le","simplified":"吃喝玩乐","literalMeaning":"eat, drink, play, and be merry","figurativeMeaning":"to indulge in a life of pleasure and enjoyment","englishEquivalents":["eat, drink, and be merry","live it up"],"shortGloss":"indulge in pleasure","characters":[{"char":"吃","meaning":"eat"},{"char":"喝","meaning":"drink"},{"char":"玩","meaning":"play"},{"char":"乐","meaning":"be merry"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '吃喝玩乐' is commonly used to describe a lifestyle focused on enjoying life's pleasures, such as eating, drinking, playing, and having fun. It reflects a carefree attitude and is often used to describe someone who prioritizes enjoyment and leisure over work or responsibilities.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","object","attributive"],"structure":"coordinate","register":"informal, commonly used in everyday speech","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with more negative expressions implying laziness or irresponsibility. However, '吃喝玩乐' is neutral and simply describes a focus on enjoyment.","canStandAlone":false},"examples":[{"simplified":"他每天都在吃喝玩乐，从不关心工作。","english":"He spends every day indulging in pleasure and never cares about work.","traditional":"他每天都在吃喝玩樂，從不關心工作。"},{"simplified":"周末的时候，我们可以暂时放下工作，尽情吃喝玩乐。","english":"On weekends, we can temporarily put work aside and fully enjoy ourselves.","traditional":"週末的時候，我們可以暫時放下工作，盡情吃喝玩樂。"}],"synonyms":["花天酒地"],"antonyms":["埋头苦干"],"confusedWith":[{"id":"花天酒地","note":"While both idioms refer to indulgence in pleasure, '花天酒地' often carries a more negative connotation of excessive indulgence."}],"traditional":"吃喝玩樂","pinyinOverride":null},{"id":"ge-shu-ji-jian","simplified":"各抒己见","literalMeaning":"each express one's own view","figurativeMeaning":"everyone gives their own opinion","englishEquivalents":["speak one's mind","everyone has their say"],"shortGloss":"everyone expresses their opinion","characters":[{"char":"各","meaning":"each"},{"char":"抒","meaning":"express"},{"char":"己","meaning":"one's own"},{"char":"见","meaning":"view, opinion"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom 各抒己见 is commonly used to describe a situation where everyone is encouraged to express their own opinions or viewpoints. It emphasizes the diversity of thoughts and the value of open discussion. The exact origin of this idiom is not tied to a specific classical text, but it has been widely used in modern Chinese to promote open dialogue.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"commonly used in both formal and informal contexts to encourage open discussion","connotation":"neutral","commonMistakes":"Learners often confuse 各抒己见 with expressing a single unified opinion. It actually emphasizes the diversity of opinions. It should not be used when referring to a consensus.","canStandAlone":false},"examples":[{"simplified":"在会议上，大家各抒己见，提出了许多有价值的建议。","english":"During the meeting, everyone expressed their own opinions and offered many valuable suggestions.","traditional":"在會議上，大家各抒己見，提出了許多有價值的建議。"},{"simplified":"在这个问题上，我们应该各抒己见，找到最好的解决方案。","english":"On this issue, we should each express our own views to find the best solution.","traditional":"在這個問題上，我們應該各抒己見，找到最好的解決方案。"}],"synonyms":["畅所欲言"],"antonyms":["异口同声"],"confusedWith":[{"id":"异口同声","note":"异口同声 means 'speak with one voice', which is the opposite of expressing individual opinions."}],"traditional":"各抒己見","pinyinOverride":null},{"id":"tong-zhou-gong-ji","simplified":"同舟共济","literalMeaning":"same boat, together cross","figurativeMeaning":"to work together to overcome difficulties","englishEquivalents":["in the same boat","pull together","united we stand"],"shortGloss":"work together to overcome difficulties","characters":[{"char":"同","meaning":"same"},{"char":"舟","meaning":"boat"},{"char":"共","meaning":"together"},{"char":"济","meaning":"cross (a river)"}],"origin":{"period":"Three Kingdoms period (220–280 CE)","sourceText":"《孙子兵法·九地》","sourceTextEnglish":"Sun Tzu's Art of War, Chapter Nine: The Nine Situations","originalExcerpt":"夫战者，以正合，以奇胜。故善出奇者，无穷如天地，不竭如江河。同舟共济，患难与共。","storyEnglish":"The idiom originates from a passage in Sun Tzu's 'Art of War', where it emphasizes the importance of unity and cooperation among soldiers when facing challenges. The metaphor of being in the same boat highlights the necessity of working together to reach the other side safely, especially in difficult situations.","historicalFigures":["Sun Tzu"],"relatedIdiomsFromSameSource":["奇正相生","以正合，以奇胜"]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"coordinate","register":"widely used in both formal and informal contexts","connotation":"positive","commonMistakes":"Learners may confuse this idiom with '同甘共苦', which also means sharing both good and bad times, but '同舟共济' specifically emphasizes cooperation in overcoming difficulties.","canStandAlone":false},"examples":[{"simplified":"在困难时期，我们必须同舟共济，共渡难关。","english":"In difficult times, we must work together to overcome challenges.","traditional":"在困難時期，我們必須同舟共濟，共渡難關。"},{"simplified":"面对疫情，各国需要同舟共济，携手抗击。","english":"In the face of the pandemic, countries need to work together to combat it.","traditional":"面對疫情，各國需要同舟共濟，攜手抗擊。"}],"synonyms":["同甘共苦","风雨同舟"],"antonyms":[],"confusedWith":[{"id":"同甘共苦","note":"While both idioms involve sharing experiences, '同舟共济' focuses on cooperation in overcoming difficulties, whereas '同甘共苦' emphasizes sharing both good and bad times."}],"traditional":"同舟共濟","pinyinOverride":null},{"id":"ming-fu-qi-shi","simplified":"名副其实","literalMeaning":"name matches reality","figurativeMeaning":"to be true to one's name; to live up to the reputation","englishEquivalents":["to live up to one's name","to be true to one's name"],"shortGloss":"live up to one's name","characters":[{"char":"名","meaning":"name"},{"char":"副","meaning":"match; correspond"},{"char":"其","meaning":"its; his/her/its"},{"char":"实","meaning":"reality; truth"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '名副其实' is often used to describe someone or something that truly matches their reputation or title. It implies that the person's abilities or the quality of something genuinely corresponds to what is claimed or expected.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"modifier-head","register":"widely used in both formal and informal contexts","connotation":"positive","commonMistakes":"Learners might confuse '名副其实' with '名不副实', which means the opposite: not living up to one's name. It's important to note the positive connotation of '名副其实'.","canStandAlone":false},"examples":[{"simplified":"这家餐厅的菜名副其实，味道非常好。","english":"The dishes at this restaurant live up to their name; they taste excellent.","traditional":"這家餐廳的菜名副其實，味道非常好。"},{"simplified":"他在比赛中的表现名副其实，果然是冠军水平。","english":"His performance in the competition truly lived up to his reputation; it was indeed championship level.","traditional":"他在比賽中的表現名副其實，果然是冠軍水平。"}],"synonyms":["名不虚传"],"antonyms":["名不副实"],"confusedWith":[{"id":"名不副实","note":"While '名副其实' means living up to one's name, '名不副实' means not living up to one's name."}],"traditional":"名副其實","pinyinOverride":null},{"id":"hou-gu-zhi-you","simplified":"后顾之忧","literalMeaning":"worries about looking back","figurativeMeaning":"worries about future consequences or concerns that distract from current tasks","englishEquivalents":["worries about future consequences","concerns that distract from the present"],"shortGloss":"worries about future consequences","characters":[{"char":"后","meaning":"behind, later"},{"char":"顾","meaning":"look back"},{"char":"之","meaning":"of"},{"char":"忧","meaning":"worry, concern"}],"origin":{"period":"Han Dynasty (202 BCE – 220 CE)","sourceText":"《汉书·韩安国传》","sourceTextEnglish":"Book of Han, Biography of Han Anguo","originalExcerpt":"无后顾之忧。","storyEnglish":"The idiom originates from the 'Book of Han', where it describes a situation where one has no worries about future consequences or disturbances from behind, allowing them to focus on the task at hand. It was used to describe a state of being free from concerns that might distract from current responsibilities.","historicalFigures":["Han Anguo"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["object","attributive"],"structure":"modifier-head","register":"literary, but widely used in both written and spoken Chinese","connotation":"negative","commonMistakes":"Learners often confuse this idiom with expressions that mean 'looking back with regret', but it specifically refers to concerns about future consequences that affect current actions.","canStandAlone":false},"examples":[{"simplified":"他已经解决了所有的后顾之忧，可以专心工作。","english":"He has resolved all his worries about future consequences and can focus on his work.","traditional":"他已經解決了所有的後顧之憂，可以專心工作。"},{"simplified":"为了没有后顾之忧，他们提前做好了所有准备。","english":"To have no worries about future consequences, they prepared everything in advance.","traditional":"為了沒有後顧之憂，他們提前做好了所有準備。"}],"synonyms":["无后顾之忧"],"antonyms":[],"confusedWith":[{"id":"顾虑重重","note":"顾虑重重 refers to having many worries or concerns, not necessarily about future consequences."}],"traditional":"後顧之憂","pinyinOverride":null},{"id":"tun-tun-tu-tu","simplified":"吞吞吐吐","literalMeaning":"swallow swallow spit spit","figurativeMeaning":"to speak hesitantly or evasively","englishEquivalents":["hem and haw","beat around the bush"],"shortGloss":"speak hesitantly or evasively","characters":[{"char":"吞","meaning":"swallow"},{"char":"吞","meaning":"swallow"},{"char":"吐","meaning":"spit"},{"char":"吐","meaning":"spit"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '吞吞吐吐' is used to describe someone who is hesitant and unclear in their speech, as if they are swallowing their words and then spitting them out. This expression vividly captures the image of someone who is unsure or unwilling to speak directly, often due to nervousness, uncertainty, or a desire to conceal something.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"AABB","register":"commonly used in both spoken and written Chinese","connotation":"negative","commonMistakes":"Learners might confuse this idiom with others that involve hesitation, but '吞吞吐吐' specifically implies a lack of clarity or directness in speech. It is not used to describe physical hesitation or delay.","canStandAlone":false},"examples":[{"simplified":"他在面试中吞吞吐吐，显得很不自信。","english":"He hemmed and hawed during the interview, appearing very unconfident.","traditional":"他在面試中吞吞吐吐，顯得很不自信。"},{"simplified":"她说话总是吞吞吐吐，让人很难理解她的意思。","english":"She always speaks hesitantly, making it hard for people to understand her meaning.","traditional":"她說話總是吞吞吐吐，讓人很難理解她的意思。"}],"synonyms":["支支吾吾"],"antonyms":["直言不讳"],"confusedWith":[{"id":"支支吾吾","note":"Both idioms describe hesitant speech, but '支支吾吾' emphasizes mumbling or stammering more than evasiveness."}],"traditional":"吞吞吐吐","pinyinOverride":null},{"id":"hong-tang-da-xiao","simplified":"哄堂大笑","literalMeaning":"uproarious laughter fills the hall","figurativeMeaning":"everyone bursts into laughter","englishEquivalents":["burst into laughter","uproarious laughter"],"shortGloss":"everyone bursts into laughter","characters":[{"char":"哄","meaning":"uproarious, loud"},{"char":"堂","meaning":"hall, room"},{"char":"大","meaning":"big, great"},{"char":"笑","meaning":"laugh, laughter"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '哄堂大笑' describes a situation where a group of people all burst into laughter at the same time, often due to something humorous or unexpected. The phrase paints a vivid picture of laughter filling a room or hall, suggesting a shared moment of amusement.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"commonly used in both spoken and written Chinese","connotation":"positive","commonMistakes":"Learners might confuse this idiom with similar expressions that describe laughter but do not imply a collective reaction. It specifically refers to a group of people laughing together.","canStandAlone":false},"examples":[{"simplified":"他的笑话让全班哄堂大笑。","english":"His joke made the whole class burst into laughter.","traditional":"他的笑話讓全班鬨堂大笑。"},{"simplified":"演出中一个小插曲引得观众哄堂大笑。","english":"A small incident during the performance made the audience burst into laughter.","traditional":"演出中一個小插曲引得觀眾鬨堂大笑。"}],"synonyms":[],"antonyms":[],"confusedWith":[],"traditional":"鬨堂大笑","pinyinOverride":null},{"id":"ku-xiao-bu-de","simplified":"哭笑不得","literalMeaning":"cry laugh not able","figurativeMeaning":"to be in a situation where you don't know whether to laugh or cry; to be in a very awkward or embarrassing situation","englishEquivalents":["not know whether to laugh or cry","caught between a rock and a hard place"],"shortGloss":"not know whether to laugh or cry","characters":[{"char":"哭","meaning":"cry"},{"char":"笑","meaning":"laugh"},{"char":"不","meaning":"not"},{"char":"得","meaning":"able"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '哭笑不得' describes a situation where someone is caught in an awkward or embarrassing predicament, leaving them unsure whether to laugh or cry. It captures the feeling of being torn between conflicting emotions in response to an unexpected or absurd situation.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","complement"],"structure":"verb-object","register":"common in both spoken and written Chinese, used in informal and semi-formal contexts","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with others that describe emotional states, but '哭笑不得' specifically refers to a situation that is both awkward and amusing. It is not used to describe simple sadness or happiness.","canStandAlone":false},"examples":[{"simplified":"他的回答让人哭笑不得。","english":"His answer left people not knowing whether to laugh or cry.","traditional":"他的回答讓人哭笑不得。"},{"simplified":"遇到这种情况，我真是哭笑不得。","english":"Faced with this situation, I really don't know whether to laugh or cry.","traditional":"遇到這種情況，我真是哭笑不得。"}],"synonyms":["啼笑皆非"],"antonyms":[],"confusedWith":[{"id":"啼笑皆非","note":"Both idioms describe awkward situations, but '啼笑皆非' emphasizes that both crying and laughing would be inappropriate."}],"traditional":"哭笑不得","pinyinOverride":null},{"id":"xi-chu-wang-wai","simplified":"喜出望外","literalMeaning":"joy comes out beyond expectations","figurativeMeaning":"to be pleasantly surprised","englishEquivalents":["over the moon","pleasantly surprised"],"shortGloss":"pleasantly surprised","characters":[{"char":"喜","meaning":"joy"},{"char":"出","meaning":"comes out"},{"char":"望","meaning":"expectations"},{"char":"外","meaning":"beyond"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '喜出望外' describes the feeling of being pleasantly surprised when something turns out better than expected. It is often used when someone receives unexpected good news or when an outcome exceeds their expectations.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"modifier-head","register":"widely used in both spoken and written Chinese","connotation":"positive","commonMistakes":"Learners might confuse this idiom with expressions that mean 'unexpected' without the positive connotation. It's important to remember that '喜出望外' specifically conveys a sense of joy and pleasant surprise.","canStandAlone":false},"examples":[{"simplified":"听到他通过考试的消息，她喜出望外。","english":"She was pleasantly surprised to hear that he passed the exam.","traditional":"聽到他通過考試的消息，她喜出望外。"},{"simplified":"收到意外的礼物，他感到喜出望外。","english":"He felt over the moon to receive an unexpected gift.","traditional":"收到意外的禮物，他感到喜出望外。"}],"synonyms":["惊喜交集"],"antonyms":[],"confusedWith":[{"id":"出乎意料","note":"While both idioms involve unexpected outcomes, '出乎意料' does not necessarily imply a positive surprise."}],"traditional":"喜出望外","pinyinOverride":null},{"id":"xi-nu-ai-le","simplified":"喜怒哀乐","literalMeaning":"happiness, anger, sorrow, joy","figurativeMeaning":"the full range of human emotions","englishEquivalents":["the full spectrum of emotions","the ups and downs of life"],"shortGloss":"the full range of emotions","characters":[{"char":"喜","meaning":"happiness"},{"char":"怒","meaning":"anger"},{"char":"哀","meaning":"sorrow"},{"char":"乐","meaning":"joy"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '喜怒哀乐' is used to describe the complete range of human emotions. It is often used to emphasize that someone is experiencing or expressing all possible feelings, from happiness and joy to anger and sorrow. The phrase captures the essence of human emotional experience.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["subject","object","attributive"],"structure":"coordinate","register":"neutral, commonly used in both spoken and written Chinese","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with specific emotions rather than understanding it as a collective term for all emotions. It's important to use it to describe the full range of emotions rather than individual feelings.","canStandAlone":false},"examples":[{"simplified":"人生中有许多喜怒哀乐，我们都要学会面对。","english":"In life, there are many emotions, and we must learn to face them all.","traditional":"人生中有許多喜怒哀樂，我們都要學會面對。"},{"simplified":"他的表演把角色的喜怒哀乐表现得淋漓尽致。","english":"His performance vividly portrayed the character's full range of emotions.","traditional":"他的表演把角色的喜怒哀樂表現得淋漓盡致。"}],"synonyms":[],"antonyms":[],"confusedWith":[],"traditional":"喜怒哀樂","pinyinOverride":null},{"id":"xi-wen-le-jian","simplified":"喜闻乐见","literalMeaning":"happy to hear, delighted to see","figurativeMeaning":"something that is well-received and enjoyed by people","englishEquivalents":["a welcome sight","music to one's ears"],"shortGloss":"something well-received and enjoyed","characters":[{"char":"喜","meaning":"happy"},{"char":"闻","meaning":"to hear"},{"char":"乐","meaning":"delighted"},{"char":"见","meaning":"to see"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '喜闻乐见' is commonly used to describe things that are popular and well-received by the general public. It emphasizes the positive reception and enjoyment people have towards certain events, news, or phenomena. The phrase itself does not have a specific origin story but has been used widely in modern Chinese to convey approval and delight.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["attributive","adverbial"],"structure":"coordinate","register":"commonly used in both formal and informal contexts","connotation":"positive","commonMistakes":"Learners might confuse this idiom with phrases that imply personal enjoyment rather than general public approval. It is important to note that '喜闻乐见' refers to something that is broadly appreciated, not just personally liked.","canStandAlone":false},"examples":[{"simplified":"这部电影内容丰富，喜闻乐见。","english":"This movie is rich in content and well-received by audiences.","traditional":"這部電影內容豐富，喜聞樂見。"},{"simplified":"他的演讲风趣幽默，令人喜闻乐见。","english":"His speech is witty and humorous, making it a welcome sight for everyone.","traditional":"他的演講風趣幽默，令人喜聞樂見。"}],"synonyms":["广受欢迎","人见人爱"],"antonyms":["无人问津"],"confusedWith":[],"traditional":"喜聞樂見","pinyinOverride":null},{"id":"si-tong-ba-da","simplified":"四通八达","literalMeaning":"four directions, eight reaches","figurativeMeaning":"to be well-connected in all directions; to have an extensive network","englishEquivalents":["all roads lead to Rome","well-connected","extensive network"],"shortGloss":"well-connected in all directions","characters":[{"char":"四","meaning":"four"},{"char":"通","meaning":"to connect"},{"char":"八","meaning":"eight"},{"char":"达","meaning":"to reach"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '四通八达' is often used to describe a place or network that is well-connected in all directions. It conveys the idea of having multiple routes or connections, making it easy to reach or communicate with various places. The phrase uses the numbers four and eight to symbolize completeness and abundance in directions.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"coordinate","register":"commonly used in both written and spoken Chinese to describe transportation networks, communication systems, or social connections","connotation":"positive","commonMistakes":"Learners might confuse it with idioms that imply chaos or disorder due to the mention of multiple directions, but '四通八达' specifically refers to being well-organized and connected.","canStandAlone":false},"examples":[{"simplified":"这个城市的交通系统四通八达，非常方便。","english":"The city's transportation system is well-connected, making it very convenient.","traditional":"這個城市的交通系統四通八達，非常方便。"},{"simplified":"他的社交网络四通八达，几乎没有他不认识的人。","english":"His social network is extensive; there are hardly any people he doesn't know.","traditional":"他的社交網絡四通八達，幾乎沒有他不認識的人。"}],"synonyms":["畅通无阻","纵横交错"],"antonyms":["闭塞","孤立无援"],"confusedWith":[{"id":"杂乱无章","note":"杂乱无章 means disorganized or chaotic, unlike 四通八达 which implies well-organized connectivity."}],"traditional":"四通八達","pinyinOverride":null},{"id":"si-mian-ba-fang","simplified":"四面八方","literalMeaning":"four sides and eight directions","figurativeMeaning":"from all directions; all around","englishEquivalents":["from all sides","from every direction"],"shortGloss":"from all directions","characters":[{"char":"四","meaning":"four"},{"char":"面","meaning":"sides"},{"char":"八","meaning":"eight"},{"char":"方","meaning":"directions"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '四面八方' is used to describe something coming from all directions, indicating a comprehensive or all-encompassing situation. It is often used to describe how people, news, or influences can come from every possible direction, emphasizing the idea of being surrounded or having a wide reach.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["adverbial"],"structure":"coordinate","register":"commonly used in both spoken and written Chinese","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with expressions that imply chaos or disorder, but '四面八方' simply indicates a comprehensive spread or reach without any negative connotation.","canStandAlone":false},"examples":[{"simplified":"消息从四面八方传来。","english":"News came from all directions.","traditional":"消息從四面八方傳來。"},{"simplified":"游客们从四面八方赶来参加节日。","english":"Tourists came from all directions to attend the festival.","traditional":"遊客們從四面八方趕來參加節日。"}],"synonyms":[],"antonyms":[],"confusedWith":[],"traditional":"四面八方","pinyinOverride":null},{"id":"yin-ren-er-yi","simplified":"因人而异","literalMeaning":"depending on the person, it differs","figurativeMeaning":"it varies from person to person","englishEquivalents":["to each their own","different strokes for different folks"],"shortGloss":"varies by individual","characters":[{"char":"因","meaning":"depending on"},{"char":"人","meaning":"person"},{"char":"而","meaning":"and"},{"char":"异","meaning":"different"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '因人而异' is used to express the idea that something varies depending on the individual. It highlights the concept that people have different preferences, needs, or responses, and therefore, a one-size-fits-all approach is not always applicable.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"subject-predicate","register":"commonly used in both spoken and written Chinese","connotation":"neutral","commonMistakes":"Learners may confuse this idiom with fixed expressions that imply uniformity, such as '一视同仁' (treat everyone equally). '因人而异' emphasizes variability rather than uniformity.","canStandAlone":false},"examples":[{"simplified":"治疗方案应该因人而异，不能一概而论。","english":"Treatment plans should vary from person to person and cannot be generalized.","traditional":"治療方案應該因人而異，不能一概而論。"},{"simplified":"教育方法需要因人而异，以适应不同学生的需求。","english":"Teaching methods need to vary from person to person to meet the needs of different students.","traditional":"教育方法需要因人而異，以適應不同學生的需求。"}],"synonyms":[],"antonyms":["一视同仁"],"confusedWith":[{"id":"一视同仁","note":"一视同仁 means treating everyone equally, which contrasts with the variability implied by 因人而异."}],"traditional":"因人而異","pinyinOverride":null},{"id":"yin-di-zhi-yi","simplified":"因地制宜","literalMeaning":"according to the land, devise suitable measures","figurativeMeaning":"to adapt measures to local conditions; to act according to actual circumstances","englishEquivalents":["cut your coat according to your cloth","horses for courses"],"shortGloss":"adapt to local conditions","characters":[{"char":"因","meaning":"according to"},{"char":"地","meaning":"land; place"},{"char":"制","meaning":"devise; make"},{"char":"宜","meaning":"suitable; appropriate"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '因地制宜' emphasizes the importance of adapting strategies and actions based on the specific characteristics and conditions of a particular place or situation. It suggests that one should not apply a one-size-fits-all approach but rather tailor solutions to fit the unique circumstances encountered.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["adverbial","attributive"],"structure":"verb-object","register":"commonly used in both written and spoken Chinese, especially in contexts discussing policy, strategy, or problem-solving","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with others that suggest flexibility or adaptability, but '因地制宜' specifically emphasizes tailoring actions to the specific conditions of a place or situation, rather than general adaptability.","canStandAlone":false},"examples":[{"simplified":"在农业生产中，我们必须因地制宜，选择合适的作物。","english":"In agricultural production, we must adapt to local conditions and choose suitable crops.","traditional":"在農業生產中，我們必須因地制宜，選擇合適的作物。"},{"simplified":"城市规划需要因地制宜，以满足不同地区的需求。","english":"Urban planning needs to adapt to local conditions to meet the needs of different areas.","traditional":"城市規劃需要因地制宜，以滿足不同地區的需求。"}],"synonyms":["量体裁衣"],"antonyms":[],"confusedWith":[{"id":"随机应变","note":"While '随机应变' emphasizes flexibility and adaptability in response to changing situations, '因地制宜' focuses on tailoring actions to specific local conditions."}],"traditional":"因地制宜","pinyinOverride":null},{"id":"tu-sheng-tu-zhang","simplified":"土生土长","literalMeaning":"earth-born earth-grown","figurativeMeaning":"born and raised in a particular place; native","englishEquivalents":["born and bred","native"],"shortGloss":"native; born and raised","characters":[{"char":"土","meaning":"earth; local"},{"char":"生","meaning":"born"},{"char":"土","meaning":"earth; local"},{"char":"长","meaning":"grow"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '土生土长' is used to describe someone who was born and grew up in a particular place, emphasizing their deep roots and familiarity with the local culture and environment. It highlights a person's connection to their birthplace.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"coordinate","register":"commonly used in both spoken and written Chinese","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with others that describe origin or upbringing but lack the specific emphasis on being native to a place. It should not be used for temporary residents.","canStandAlone":false},"examples":[{"simplified":"他是北京土生土长的，对这里的一切都很熟悉。","english":"He was born and raised in Beijing, so he's very familiar with everything here.","traditional":"他是北京土生土長的，對這裡的一切都很熟悉。"},{"simplified":"作为一个土生土长的上海人，她对这座城市有着深厚的感情。","english":"As someone born and bred in Shanghai, she has a deep affection for the city.","traditional":"作為一個土生土長的上海人，她對這座城市有著深厚的感情。"}],"synonyms":[],"antonyms":[],"confusedWith":[],"traditional":"土生土長","pinyinOverride":null},{"id":"zai-suo-nan-mian","simplified":"在所难免","literalMeaning":"in place difficult to avoid","figurativeMeaning":"unavoidable; inevitable","englishEquivalents":["inevitable","unavoidable","bound to happen"],"shortGloss":"inevitable, unavoidable","characters":[{"char":"在","meaning":"in, at"},{"char":"所","meaning":"place, location"},{"char":"难","meaning":"difficult"},{"char":"免","meaning":"avoid"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '在所难免' is used to express the idea that certain situations or outcomes are unavoidable or inevitable. It is commonly used in both written and spoken Chinese to acknowledge that some things cannot be prevented or avoided.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"modifier-head","register":"commonly used in both formal and informal contexts","connotation":"neutral","commonMistakes":"Learners often confuse '在所难免' with '不可避免', which also means 'unavoidable'. However, '在所难免' is more often used in a broader range of contexts, while '不可避免' is slightly more formal.","canStandAlone":false},"examples":[{"simplified":"在快速发展的社会中，竞争在所难免。","english":"In a rapidly developing society, competition is unavoidable.","traditional":"在快速發展的社會中，競爭在所難免。"},{"simplified":"犯错误是学习过程中的一部分，在所难免。","english":"Making mistakes is a part of the learning process and is inevitable.","traditional":"犯錯誤是學習過程中的一部分，在所難免。"}],"synonyms":["不可避免"],"antonyms":[],"confusedWith":[{"id":"不可避免","note":"Both mean 'unavoidable', but '不可避免' is slightly more formal."}],"traditional":"在所難免","pinyinOverride":null},{"id":"chui-tou-sang-qi","simplified":"垂头丧气","literalMeaning":"hang head, lose spirit","figurativeMeaning":"to be dejected or dispirited","englishEquivalents":["downcast","crestfallen","hang one's head"],"shortGloss":"dejected or dispirited","characters":[{"char":"垂","meaning":"hang"},{"char":"头","meaning":"head"},{"char":"丧","meaning":"lose"},{"char":"气","meaning":"spirit"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '垂头丧气' describes someone who is visibly dejected or dispirited, often with their head hanging down. It conveys a sense of having lost hope or enthusiasm, akin to the physical posture of someone who is feeling downcast.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"coordinate","register":"commonly used in both spoken and written Chinese","connotation":"negative","commonMistakes":"Learners might confuse this idiom with similar expressions of sadness or disappointment, but '垂头丧气' specifically emphasizes a visible, physical expression of dejection, often involving body language.","canStandAlone":false},"examples":[{"simplified":"比赛输了以后，他垂头丧气地回家了。","english":"After losing the game, he went home looking dejected.","traditional":"比賽輸了以後，他垂頭喪氣地回家了。"},{"simplified":"她听到坏消息后垂头丧气，一句话也不说。","english":"She was crestfallen after hearing the bad news and didn't say a word.","traditional":"她聽到壞消息後垂頭喪氣，一句話也不說。"}],"synonyms":["无精打采"],"antonyms":["兴高采烈"],"confusedWith":[{"id":"无精打采","note":"Both describe a lack of energy or enthusiasm, but '无精打采' focuses more on a lack of energy, while '垂头丧气' emphasizes visible dejection."}],"traditional":"垂頭喪氣","pinyinOverride":null},{"id":"mai-tou-ku-gan","simplified":"埋头苦干","literalMeaning":"bury head and work hard","figurativeMeaning":"to immerse oneself in hard work; to work diligently and persistently","englishEquivalents":["put one's nose to the grindstone","work one's fingers to the bone"],"shortGloss":"work diligently and persistently","characters":[{"char":"埋","meaning":"bury"},{"char":"头","meaning":"head"},{"char":"苦","meaning":"hard; bitter"},{"char":"干","meaning":"work"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '埋头苦干' describes the act of focusing intently on a task and working hard without distraction. It emphasizes diligence and persistence in completing work, often in challenging or demanding situations. The phrase is commonly used to praise someone who is dedicated and hardworking.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"widely used in both formal and informal contexts","connotation":"positive","commonMistakes":"Learners might confuse this idiom with similar expressions that imply working hard but do not emphasize the aspect of immersion or focus. It's important to note that '埋头苦干' suggests a deep commitment to the task at hand.","canStandAlone":false},"examples":[{"simplified":"为了完成项目，他每天都埋头苦干。","english":"To complete the project, he immersed himself in hard work every day.","traditional":"為了完成項目，他每天都埋頭苦幹。"},{"simplified":"她埋头苦干，希望能在年底前升职。","english":"She is working diligently, hoping to get a promotion by the end of the year.","traditional":"她埋頭苦幹，希望能在年底前升職。"}],"synonyms":["全力以赴","兢兢业业"],"antonyms":["敷衍了事"],"confusedWith":[{"id":"废寝忘食","note":"While both idioms imply dedication, '废寝忘食' emphasizes neglecting basic needs like eating and sleeping, whereas '埋头苦干' focuses on diligent work."}],"traditional":"埋頭苦幹","pinyinOverride":null},{"id":"ye-yi-ji-ri","simplified":"夜以继日","literalMeaning":"night to continue day","figurativeMeaning":"to work tirelessly day and night","englishEquivalents":["around the clock","day and night","non-stop"],"shortGloss":"working tirelessly day and night","characters":[{"char":"夜","meaning":"night"},{"char":"以","meaning":"to use, to take"},{"char":"继","meaning":"to continue"},{"char":"日","meaning":"day"}],"origin":{"period":"Han Dynasty (206 BCE – 220 CE)","sourceText":"《汉书·李广苏建传》","sourceTextEnglish":"Book of Han, Biography of Li Guang and Su Jian","originalExcerpt":"夜以继日，思虑无穷。","storyEnglish":"The idiom comes from the 'Book of Han', where it describes the relentless efforts of officials who worked tirelessly, continuing their tasks from night into day without rest. This phrase captures the dedication and hard work of individuals who push themselves to complete their duties regardless of the time.","historicalFigures":["Li Guang","Su Jian"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["adverbial","attributive"],"structure":"modifier-head","register":"literary, but very widely understood and used in ordinary speech","connotation":"positive","commonMistakes":"Learners often confuse this idiom with others that imply working hard, but 夜以继日 specifically emphasizes the continuous, unbroken nature of the effort, unlike idioms that might imply hard work with breaks.","canStandAlone":false},"examples":[{"simplified":"为了完成项目，他夜以继日地工作。","english":"To complete the project, he worked tirelessly day and night.","traditional":"為了完成項目，他夜以繼日地工作。"},{"simplified":"科学家们夜以继日地研究，希望能找到解决方案。","english":"The scientists worked around the clock, hoping to find a solution.","traditional":"科學家們夜以繼日地研究，希望能找到解決方案。"}],"synonyms":["废寝忘食","通宵达旦"],"antonyms":[],"confusedWith":[{"id":"废寝忘食","note":"废寝忘食 emphasizes neglecting sleep and meals due to dedication, while 夜以继日 emphasizes continuous effort without rest."}],"traditional":"夜以繼日","pinyinOverride":null},{"id":"da-gong-wu-si","simplified":"大公无私","literalMeaning":"great impartiality without selfishness","figurativeMeaning":"to be completely selfless and impartial","englishEquivalents":["selfless and impartial","without personal bias"],"shortGloss":"selfless and impartial","characters":[{"char":"大","meaning":"great"},{"char":"公","meaning":"impartial"},{"char":"无","meaning":"without"},{"char":"私","meaning":"selfishness"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '大公无私' is often used to describe someone who acts with complete selflessness and impartiality, putting the common good above personal interests. The phrase emphasizes the virtue of being fair and just, without letting personal gains or biases influence one's decisions.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"modifier-head","register":"commonly used in both formal and informal contexts","connotation":"positive","commonMistakes":"Learners sometimes confuse this idiom with similar ones that emphasize fairness but not necessarily selflessness. It's important to note that '大公无私' stresses both impartiality and the absence of selfish motives.","canStandAlone":false},"examples":[{"simplified":"他做事总是大公无私，从不考虑个人得失。","english":"He always acts selflessly and impartially, never considering personal gains or losses.","traditional":"他做事總是大公無私，從不考慮個人得失。"},{"simplified":"领导者应该大公无私，以公众利益为重。","english":"Leaders should be selfless and impartial, prioritizing the public interest.","traditional":"領導者應該大公無私，以公眾利益為重。"}],"synonyms":["公正无私"],"antonyms":["假公济私"],"confusedWith":[{"id":"公正无私","note":"While both emphasize fairness, '大公无私' also highlights selflessness."}],"traditional":"大公無私","pinyinOverride":null},{"id":"da-tong-xiao-yi","simplified":"大同小异","literalMeaning":"big same, small different","figurativeMeaning":"essentially the same with only minor differences","englishEquivalents":["six of one, half a dozen of the other","much the same","similar with minor differences"],"shortGloss":"essentially the same","characters":[{"char":"大","meaning":"big"},{"char":"同","meaning":"same"},{"char":"小","meaning":"small"},{"char":"异","meaning":"different"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '大同小异' is used to describe situations where two things are fundamentally the same but have minor differences. It is often used to emphasize that the differences are not significant enough to affect the overall similarity.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"coordinate","register":"commonly used in both spoken and written Chinese","connotation":"neutral","commonMistakes":"Learners sometimes use this idiom to describe things that are completely identical, but it is meant for situations where there are minor differences. It should not be used when the differences are significant.","canStandAlone":false},"examples":[{"simplified":"这两种产品大同小异，选择哪一个都可以。","english":"These two products are essentially the same, you can choose either one.","traditional":"這兩種產品大同小異，選擇哪一個都可以。"},{"simplified":"虽然他们的观点大同小异，但还是有一些细微的差别。","english":"Although their views are essentially the same, there are still some subtle differences.","traditional":"雖然他們的觀點大同小異，但還是有一些細微的差別。"}],"synonyms":[],"antonyms":[],"confusedWith":[],"traditional":"大同小異","pinyinOverride":null},{"id":"da-ming-ding-ding","simplified":"大名鼎鼎","literalMeaning":"big name tripod tripod","figurativeMeaning":"famous; well-known","englishEquivalents":["famous","renowned","well-known"],"shortGloss":"famous; renowned","characters":[{"char":"大","meaning":"big; great"},{"char":"名","meaning":"name; reputation"},{"char":"鼎","meaning":"tripod; used here to emphasize greatness"},{"char":"鼎","meaning":"tripod; used here to emphasize greatness"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '大名鼎鼎' is used to describe someone or something that is very famous or well-known. The repetition of '鼎' (tripod) is used to emphasize the greatness or prominence of the name. The exact origin of this idiom is unclear, but it has been widely used in Chinese literature and speech to denote fame.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["attributive","predicate"],"structure":"modifier-head","register":"commonly used in both written and spoken Chinese","connotation":"positive","commonMistakes":"Learners might confuse '大名鼎鼎' with '鼎鼎大名', which has the same meaning but a different word order. Both are correct and interchangeable.","canStandAlone":false},"examples":[{"simplified":"他是一个大名鼎鼎的作家。","english":"He is a famous writer.","traditional":"他是一個大名鼎鼎的作家。"},{"simplified":"这家餐厅在当地大名鼎鼎。","english":"This restaurant is very well-known locally.","traditional":"這家餐廳在當地大名鼎鼎。"}],"synonyms":["鼎鼎大名"],"antonyms":[],"confusedWith":[{"id":"鼎鼎大名","note":"Both '大名鼎鼎' and '鼎鼎大名' mean 'famous', but they differ in word order. They are interchangeable."}],"traditional":"大名鼎鼎","pinyinOverride":null},{"id":"da-da-lie-lie","simplified":"大大咧咧","literalMeaning":"big big careless careless","figurativeMeaning":"carefree and casual; not paying attention to small details","englishEquivalents":["carefree","easygoing","laid-back"],"shortGloss":"carefree and casual","characters":[{"char":"大","meaning":"big; here it emphasizes the degree"},{"char":"大","meaning":"big; repetition for emphasis"},{"char":"咧","meaning":"careless; casual"},{"char":"咧","meaning":"careless; casual; repetition for emphasis"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '大大咧咧' is believed to have originated from colloquial expressions used to describe someone who is easygoing and does not pay much attention to minor details. It emphasizes a carefree attitude, often seen as a positive trait in social interactions.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["attributive","adverbial"],"structure":"AABB","register":"informal, commonly used in everyday speech","connotation":"neutral","commonMistakes":"Learners might confuse '大大咧咧' with idioms that imply irresponsibility or laziness. However, '大大咧咧' is more about being relaxed and not overly concerned with details, rather than being neglectful.","canStandAlone":false},"examples":[{"simplified":"他性格大大咧咧，从不为小事烦恼。","english":"He is easygoing and never worries about small matters.","traditional":"他性格大大咧咧，從不為小事煩惱。"},{"simplified":"她总是大大咧咧的，和谁都能聊得来。","english":"She is always so carefree and can chat with anyone easily.","traditional":"她總是大大咧咧的，和誰都能聊得來。"}],"synonyms":["随随便便","漫不经心"],"antonyms":["小心翼翼","谨小慎微"],"confusedWith":[{"id":"粗心大意","note":"While '粗心大意' implies carelessness and oversight, '大大咧咧' suggests a relaxed and easygoing demeanor without negative connotations."}],"traditional":"大大咧咧","pinyinOverride":null},{"id":"da-jing-xiao-guai","simplified":"大惊小怪","literalMeaning":"big surprise, small wonder","figurativeMeaning":"to make a fuss about nothing; to be surprised or alarmed at something trivial","englishEquivalents":["make a mountain out of a molehill","much ado about nothing"],"shortGloss":"make a fuss over nothing","characters":[{"char":"大","meaning":"big"},{"char":"惊","meaning":"surprise"},{"char":"小","meaning":"small"},{"char":"怪","meaning":"wonder"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '大惊小怪' is used to describe someone who makes a big deal out of something insignificant. It suggests that the person is overreacting to a minor issue, treating it as if it were a major problem.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"coordinate","register":"colloquial, commonly used in both spoken and written Chinese","connotation":"negative","commonMistakes":"Learners often confuse this idiom with expressions that genuinely indicate surprise or concern. It's important to note that '大惊小怪' implies an unnecessary or exaggerated reaction.","canStandAlone":false},"examples":[{"simplified":"他总是为一点小事大惊小怪。","english":"He always makes a fuss over trivial matters.","traditional":"他總是為一點小事大驚小怪。"},{"simplified":"别为这点小问题大惊小怪。","english":"Don't make a fuss over such a small issue.","traditional":"別為這點小問題大驚小怪。"}],"synonyms":["小题大做"],"antonyms":[],"confusedWith":[{"id":"大惊失色","note":"大惊失色 means to be genuinely shocked or frightened, not overreacting to something minor."}],"traditional":"大驚小怪","pinyinOverride":null},{"id":"da-you-ke-wei","simplified":"大有可为","literalMeaning":"greatly has potential to be done","figurativeMeaning":"promising; having great potential","englishEquivalents":["promising","full of potential"],"shortGloss":"promising; full of potential","characters":[{"char":"大","meaning":"greatly"},{"char":"有","meaning":"has"},{"char":"可","meaning":"can; possible"},{"char":"为","meaning":"to do; to act"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '大有可为' is used to describe situations, projects, or people that show great promise and potential for success. It is often used to encourage someone to pursue a course of action that seems likely to yield positive results.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"modifier-head","register":"commonly used in both formal and informal contexts","connotation":"positive","commonMistakes":"Learners might confuse this idiom with '无可奈何', which has a negative connotation of helplessness. '大有可为' is positive and suggests potential and opportunity.","canStandAlone":false},"examples":[{"simplified":"这项新技术大有可为，值得投资。","english":"This new technology is promising and worth investing in.","traditional":"這項新技術大有可為，值得投資。"},{"simplified":"他的计划大有可为，我们应该支持他。","english":"His plan is full of potential; we should support him.","traditional":"他的計劃大有可為，我們應該支持他。"}],"synonyms":["前途无量"],"antonyms":["无可奈何"],"confusedWith":[{"id":"无可奈何","note":"While '无可奈何' expresses helplessness, '大有可为' is about potential and opportunity."}],"traditional":"大有可為","pinyinOverride":null},{"id":"da-jie-xiao-xiang","simplified":"大街小巷","literalMeaning":"big streets and small alleys","figurativeMeaning":"everywhere; all over the place","englishEquivalents":["every nook and cranny","far and wide"],"shortGloss":"everywhere; all over the place","characters":[{"char":"大","meaning":"big"},{"char":"街","meaning":"street"},{"char":"小","meaning":"small"},{"char":"巷","meaning":"alley"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '大街小巷' is used to describe a place that is thoroughly covered or a concept that is widely known. It paints a picture of both the main streets and the small alleys being included, suggesting that something is present or known everywhere.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["adverbial"],"structure":"coordinate","register":"commonly used in both written and spoken Chinese","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with those that describe specific locations rather than the ubiquity of something. It's important to use it to emphasize widespread presence or knowledge.","canStandAlone":false},"examples":[{"simplified":"这个消息已经传遍了大街小巷。","english":"This news has spread everywhere.","traditional":"這個消息已經傳遍了大街小巷。"},{"simplified":"他的名字在大街小巷都能听到。","english":"His name can be heard everywhere.","traditional":"他的名字在大街小巷都能聽到。"}],"synonyms":["无处不在"],"antonyms":[],"confusedWith":[],"traditional":"大街小巷","pinyinOverride":null},{"id":"tian-lun-zhi-le","simplified":"天伦之乐","literalMeaning":"heavenly relationship's happiness","figurativeMeaning":"the happiness of family life","englishEquivalents":["family bliss","domestic happiness"],"shortGloss":"happiness of family life","characters":[{"char":"天","meaning":"heaven"},{"char":"伦","meaning":"relationship, order"},{"char":"之","meaning":"of"},{"char":"乐","meaning":"happiness, joy"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '天伦之乐' refers to the joy and happiness derived from family life and relationships. It emphasizes the natural and harmonious bonds within a family, akin to a heavenly order. The phrase is often used to describe the contentment and joy found in spending time with family members.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["object","attributive"],"structure":"modifier-head","register":"commonly used in both written and spoken Chinese to express familial happiness","connotation":"positive","commonMistakes":"Learners might confuse this idiom with phrases that refer to general happiness or joy, but '天伦之乐' specifically emphasizes the joy within a family context.","canStandAlone":false},"examples":[{"simplified":"周末的时候，我最喜欢和家人一起享受天伦之乐。","english":"On weekends, I love enjoying the happiness of family life with my family.","traditional":"週末的時候，我最喜歡和家人一起享受天倫之樂。"},{"simplified":"过年时，大家团聚在一起，感受天伦之乐。","english":"During the New Year, everyone gathers together to experience the joy of family life.","traditional":"過年時，大家團聚在一起，感受天倫之樂。"}],"synonyms":["合家欢乐"],"antonyms":[],"confusedWith":[{"id":"其乐融融","note":"While both idioms refer to happiness, '其乐融融' can refer to any harmonious and joyful atmosphere, not limited to family."}],"traditional":"天倫之樂","pinyinOverride":null},{"id":"tian-jing-di-yi","simplified":"天经地义","literalMeaning":"heaven's law, earth's principle","figurativeMeaning":"something that is perfectly justified and right; a matter of course","englishEquivalents":["as a matter of course","self-evident truth"],"shortGloss":"self-evident truth","characters":[{"char":"天","meaning":"heaven"},{"char":"经","meaning":"law, canon"},{"char":"地","meaning":"earth"},{"char":"义","meaning":"principle, righteousness"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '天经地义' is believed to have originated from the idea that certain principles are as fundamental and unchanging as the laws of heaven and earth. These principles are considered self-evident and universally accepted, much like the natural order of the world.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"coordinate","register":"commonly used in both formal and informal contexts","connotation":"positive","commonMistakes":"Learners might confuse this idiom with phrases that imply something is merely common sense, but '天经地义' carries a stronger sense of moral or universal truth. It should not be used for trivial matters.","canStandAlone":false},"examples":[{"simplified":"孝顺父母是天经地义的事情。","english":"Being filial to one's parents is a self-evident truth.","traditional":"孝順父母是天經地義的事情。"},{"simplified":"他认为帮助有需要的人是天经地义的。","english":"He believes that helping those in need is perfectly justified.","traditional":"他認為幫助有需要的人是天經地義的。"}],"synonyms":["理所当然","无可厚非"],"antonyms":[],"confusedWith":[{"id":"理所当然","note":"While both imply something is self-evident, '理所当然' is more about common sense, whereas '天经地义' implies a deeper, moral truth."}],"traditional":"天經地義","pinyinOverride":null},{"id":"tian-chang-di-jiu","simplified":"天长地久","literalMeaning":"heaven long earth enduring","figurativeMeaning":"lasting and eternal; enduring as long as heaven and earth","englishEquivalents":["eternal","everlasting","enduring"],"shortGloss":"eternal and enduring","characters":[{"char":"天","meaning":"heaven"},{"char":"长","meaning":"long"},{"char":"地","meaning":"earth"},{"char":"久","meaning":"enduring"}],"origin":{"period":"Warring States period (475–221 BCE)","sourceText":"《道德经》","sourceTextEnglish":"Tao Te Ching","originalExcerpt":"天长地久。天地所以能长且久者，以其不自生，故能长生。","storyEnglish":"The idiom comes from the Tao Te Ching, a classical Chinese text attributed to Laozi. The text reflects on the enduring nature of heaven and earth, suggesting that their longevity is due to their selflessness and naturalness. This concept is used metaphorically to describe anything that is everlasting and enduring.","historicalFigures":["Laozi"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"coordinate","register":"literary, but widely understood and used in both formal and informal contexts","connotation":"positive","commonMistakes":"Learners might mistakenly use this idiom to describe short-lived or temporary things. It is important to use it in contexts that imply longevity or permanence.","canStandAlone":false},"examples":[{"simplified":"他们的友谊天长地久。","english":"Their friendship is everlasting.","traditional":"他們的友誼天長地久。"},{"simplified":"希望我们的爱情能天长地久。","english":"I hope our love can last forever.","traditional":"希望我們的愛情能天長地久。"}],"synonyms":["永恒不变","持久不衰"],"antonyms":["短暂易逝"],"confusedWith":[{"id":"地久天长","note":"This is a variation of the same idiom with the order of 'heaven' and 'earth' reversed, but it carries the same meaning."}],"traditional":"天長地久","pinyinOverride":null},{"id":"tou-tou-shi-dao","simplified":"头头是道","literalMeaning":"head head is way","figurativeMeaning":"to speak or do things in a clear, logical, and orderly manner","englishEquivalents":["make perfect sense","clear and logical","coherent"],"shortGloss":"clear and logical","characters":[{"char":"头","meaning":"head; aspect"},{"char":"头","meaning":"head; aspect"},{"char":"是","meaning":"is; to be"},{"char":"道","meaning":"way; method"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '头头是道' is believed to have originated from the idea of organizing thoughts or actions in a way that each 'head' or 'aspect' is aligned with the 'way' or 'method'. It emphasizes clarity and logical structure in speech or actions.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"subject-predicate","register":"commonly used in both spoken and written Chinese, suitable for formal and informal contexts","connotation":"positive","commonMistakes":"Learners often confuse this idiom with others that imply clarity but lack the emphasis on logical order. It is important to note that '头头是道' specifically refers to being methodical and coherent.","canStandAlone":false},"examples":[{"simplified":"他的演讲头头是道，让人印象深刻。","english":"His speech was clear and logical, leaving a deep impression.","traditional":"他的演講頭頭是道，讓人印象深刻。"},{"simplified":"她解释问题时，总是头头是道，大家都很佩服。","english":"When she explains problems, she is always clear and logical, and everyone admires her.","traditional":"她解釋問題時，總是頭頭是道，大家都很佩服。"}],"synonyms":["井井有条"],"antonyms":["语无伦次"],"confusedWith":[{"id":"井井有条","note":"While both idioms imply orderliness, '井井有条' often refers to physical or procedural order, whereas '头头是道' emphasizes logical clarity in speech or thought."}],"traditional":"頭頭是道","pinyinOverride":null},{"id":"kua-kua-qi-tan","simplified":"夸夸其谈","literalMeaning":"boast boast their talk","figurativeMeaning":"to talk big or boastfully without substance","englishEquivalents":["all talk and no action","empty talk"],"shortGloss":"boastful and empty talk","characters":[{"char":"夸","meaning":"boast"},{"char":"夸","meaning":"boast"},{"char":"其","meaning":"their"},{"char":"谈","meaning":"talk"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom 夸夸其谈 is used to describe someone who speaks in a grandiose or boastful manner without much substance or real content. It is often used to criticize people who are more focused on impressing others with their words than on actual achievements or meaningful contributions.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"modifier-head","register":"commonly used in both spoken and written Chinese to criticize boastful speech","connotation":"negative","commonMistakes":"Learners might confuse 夸夸其谈 with idioms that imply effective communication. However, 夸夸其谈 specifically criticizes speech that is all style and no substance.","canStandAlone":false},"examples":[{"simplified":"他总是夸夸其谈，但从来没有实际行动。","english":"He is always full of empty talk, but never takes any real action.","traditional":"他總是誇誇其談，但從來沒有實際行動。"},{"simplified":"在会议上，他的发言被认为是夸夸其谈，没有实质内容。","english":"His speech at the meeting was considered boastful and lacking in substance.","traditional":"在會議上，他的發言被認為是誇誇其談，沒有實質內容。"}],"synonyms":["纸上谈兵"],"antonyms":["实事求是"],"confusedWith":[{"id":"纸上谈兵","note":"纸上谈兵 refers to theoretical talk without practical experience, while 夸夸其谈 emphasizes boastfulness."}],"traditional":"誇誇其談","pinyinOverride":null},{"id":"ru-yuan-yi-chang","simplified":"如愿以偿","literalMeaning":"as desired, to fulfill","figurativeMeaning":"to have one's wishes fulfilled","englishEquivalents":["wish come true","get one's wish"],"shortGloss":"wish fulfilled","characters":[{"char":"如","meaning":"as"},{"char":"愿","meaning":"wish"},{"char":"以","meaning":"in order to"},{"char":"偿","meaning":"fulfill"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '如愿以偿' is used to describe a situation where someone's desires or wishes are fulfilled. It is commonly used in both spoken and written Chinese to express the satisfaction of achieving something one has long hoped for.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","complement"],"structure":"verb-object","register":"commonly used in both spoken and written Chinese","connotation":"positive","commonMistakes":"Learners might confuse this idiom with '事与愿违' (things go contrary to one's wishes), which has an opposite meaning. '如愿以偿' should be used when wishes are fulfilled, not when they are thwarted.","canStandAlone":false},"examples":[{"simplified":"经过多年的努力，他终于如愿以偿，考上了理想的大学。","english":"After years of hard work, he finally had his wish fulfilled and got into his dream university.","traditional":"經過多年的努力，他終於如願以償，考上了理想的大學。"},{"simplified":"她一直想要一个孩子，现在她如愿以偿，成为了母亲。","english":"She always wanted a child, and now her wish has come true; she has become a mother.","traditional":"她一直想要一個孩子，現在她如願以償，成為了母親。"}],"synonyms":["心想事成"],"antonyms":["事与愿违"],"confusedWith":[{"id":"事与愿违","note":"如愿以偿 means having one's wishes fulfilled, while 事与愿违 means things go contrary to one's wishes."}],"traditional":"如願以償","pinyinOverride":null},{"id":"ru-chi-ru-zui","simplified":"如痴如醉","literalMeaning":"like crazy, like drunk","figurativeMeaning":"to be completely absorbed or captivated, as if in a trance","englishEquivalents":["entranced","spellbound","mesmerized"],"shortGloss":"entranced or captivated","characters":[{"char":"如","meaning":"like; as if"},{"char":"痴","meaning":"crazy; obsessed"},{"char":"如","meaning":"like; as if"},{"char":"醉","meaning":"drunk; intoxicated"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '如痴如醉' is used to describe a state where someone is so captivated or absorbed by something that they appear to be in a trance, similar to being drunk or crazy. This expression captures the intensity of focus or fascination one might have, whether it be with art, music, or any other passion.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"coordinate","register":"widely used in both written and spoken Chinese","connotation":"neutral","commonMistakes":"Learners may confuse this idiom with expressions that imply literal drunkenness or madness. It should be used to describe a figurative state of being deeply absorbed or captivated.","canStandAlone":false},"examples":[{"simplified":"他对音乐的热爱让他如痴如醉。","english":"His love for music makes him completely absorbed.","traditional":"他對音樂的熱愛讓他如痴如醉。"},{"simplified":"她看着那幅画，如痴如醉，无法移开视线。","english":"She gazed at the painting, entranced, unable to look away.","traditional":"她看著那幅畫，如痴如醉，無法移開視線。"}],"synonyms":["如梦如幻","心醉神迷"],"antonyms":[],"confusedWith":[{"id":"醉生梦死","note":"醉生梦死 implies living a life of dissipation and indulgence, often with negative connotations, unlike 如痴如醉 which is neutral and about being captivated."}],"traditional":"如痴如醉","pinyinOverride":null},{"id":"gu-lou-gua-wen","simplified":"孤陋寡闻","literalMeaning":"isolated and ignorant","figurativeMeaning":"having limited knowledge or experience; ignorant","englishEquivalents":["ignorant","narrow-minded","uninformed"],"shortGloss":"ignorant, uninformed","characters":[{"char":"孤","meaning":"isolated"},{"char":"陋","meaning":"ignorant"},{"char":"寡","meaning":"scant"},{"char":"闻","meaning":"knowledge"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '孤陋寡闻' is often used to describe someone who has limited exposure to the world and lacks knowledge. It emphasizes the idea of being isolated and having scant information or experience, leading to a narrow perspective.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"coordinate","register":"commonly used in both spoken and written Chinese, often in a self-deprecating or critical context","connotation":"negative","commonMistakes":"Learners sometimes use this idiom to describe physical isolation, but it specifically refers to a lack of knowledge or experience. It is also sometimes confused with idioms that describe being out of touch with current events, but it is more about general ignorance.","canStandAlone":false},"examples":[{"simplified":"他因为孤陋寡闻，所以经常闹笑话。","english":"He often makes a fool of himself because he is ignorant.","traditional":"他因為孤陋寡聞，所以經常鬧笑話。"},{"simplified":"我对这个领域孤陋寡闻，需要多学习。","english":"I am ignorant in this field and need to learn more.","traditional":"我對這個領域孤陋寡聞，需要多學習。"}],"synonyms":["井底之蛙"],"antonyms":["博学多才"],"confusedWith":[{"id":"井底之蛙","note":"Both describe limited perspective, but '井底之蛙' emphasizes narrow vision rather than ignorance."}],"traditional":"孤陋寡聞","pinyinOverride":null},{"id":"shi-shi-qiu-shi","simplified":"实事求是","literalMeaning":"seek truth from facts","figurativeMeaning":"to be practical and realistic; to seek truth from facts","englishEquivalents":["call a spade a spade","face the facts"],"shortGloss":"be practical and realistic","characters":[{"char":"实","meaning":"real; true"},{"char":"事","meaning":"matter; fact"},{"char":"求","meaning":"seek; pursue"},{"char":"是","meaning":"truth; right"}],"origin":{"period":"Han Dynasty (202 BCE – 220 CE)","sourceText":"《汉书·河间献王传》","sourceTextEnglish":"Book of Han, Biography of King Xian of Hejian","originalExcerpt":"修学好古，实事求是。","storyEnglish":"The idiom originates from the 'Book of Han', where it describes the scholarly approach of Liu De, King Xian of Hejian, who was known for his dedication to learning and his realistic approach to understanding historical texts. He emphasized the importance of basing one's understanding on factual evidence rather than speculation.","historicalFigures":["Liu De"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"widely used in both formal and informal contexts, especially in political and academic discussions","connotation":"positive","commonMistakes":"Learners sometimes confuse this idiom with ones that imply stubbornness or inflexibility, but 实事求是 emphasizes a flexible and open-minded approach to finding the truth based on evidence.","canStandAlone":false},"examples":[{"simplified":"在科学研究中，我们必须实事求是。","english":"In scientific research, we must seek truth from facts.","traditional":"在科學研究中，我們必須實事求是。"},{"simplified":"他总是实事求是地分析问题。","english":"He always analyzes problems in a practical and realistic way.","traditional":"他總是實事求是地分析問題。"}],"synonyms":["一针见血","开诚布公"],"antonyms":["掩耳盗铃"],"confusedWith":[{"id":"墨守成规","note":"实事求是 is about being realistic and evidence-based, while 墨守成规 means sticking to old ways without change."}],"traditional":"實事求是","pinyinOverride":null},{"id":"shi-hua-shi-shuo","simplified":"实话实说","literalMeaning":"truthful words, truthful speaking","figurativeMeaning":"to speak the truth; to tell it like it is","englishEquivalents":["speak the truth","tell it like it is","speak frankly"],"shortGloss":"speak the truth","characters":[{"char":"实","meaning":"real, true"},{"char":"话","meaning":"words, speech"},{"char":"实","meaning":"real, true"},{"char":"说","meaning":"speak, say"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '实话实说' is commonly used in modern Chinese to encourage honesty and straightforwardness in communication. It emphasizes the importance of speaking truthfully and is often used in situations where honesty is valued over tact or diplomacy.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"ABAC","register":"commonly used in both spoken and written Chinese, informal and formal contexts","connotation":"positive","commonMistakes":"Learners might confuse '实话实说' with similar expressions that imply bluntness or rudeness. However, this idiom is generally positive and emphasizes honesty rather than harshness.","canStandAlone":false},"examples":[{"simplified":"在面试中，实话实说是很重要的。","english":"In an interview, it is important to speak the truth.","traditional":"在面試中，實話實說是很重要的。"},{"simplified":"我知道你不想听，但我还是要实话实说。","english":"I know you don't want to hear it, but I still have to tell it like it is.","traditional":"我知道你不想聽，但我還是要實話實說。"}],"synonyms":["坦诚相见"],"antonyms":["口是心非"],"confusedWith":[{"id":"直言不讳","note":"While both emphasize honesty, '直言不讳' often implies a more blunt or direct approach."}],"traditional":"實話實說","pinyinOverride":null},{"id":"jia-yu-hu-xiao","simplified":"家喻户晓","literalMeaning":"every family knows, every household understands","figurativeMeaning":"widely known; well-known to everyone","englishEquivalents":["household name","known far and wide"],"shortGloss":"widely known","characters":[{"char":"家","meaning":"family"},{"char":"喻","meaning":"to know"},{"char":"户","meaning":"household"},{"char":"晓","meaning":"to understand"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom 家喻户晓 describes something that is so well-known that it is understood by every family and household. It emphasizes the extent of the fame or recognition of a person, story, or fact. The origin of this idiom is not tied to a specific classical text, but it has been used in Chinese literature and speech to convey the idea of widespread knowledge or fame.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"coordinate","register":"widely used in both formal and informal contexts","connotation":"positive","commonMistakes":"Learners might confuse 家喻户晓 with idioms that imply fame but not necessarily widespread understanding, such as 名声大噪 (famous but not necessarily understood).","canStandAlone":false},"examples":[{"simplified":"这位歌手的名字已经家喻户晓。","english":"The singer's name is already a household name.","traditional":"這位歌手的名字已經家喻戶曉。"},{"simplified":"这个故事在全国范围内家喻户晓。","english":"This story is widely known across the country.","traditional":"這個故事在全國範圍內家喻戶曉。"}],"synonyms":["妇孺皆知"],"antonyms":[],"confusedWith":[{"id":"名声大噪","note":"名声大噪 implies being famous, but not necessarily understood by everyone."}],"traditional":"家喻戶曉","pinyinOverride":null},{"id":"rong-guang-huan-fa","simplified":"容光焕发","literalMeaning":"appearance light shine emit","figurativeMeaning":"to look radiant and full of energy","englishEquivalents":["radiant","glowing","beaming"],"shortGloss":"to look radiant and full of energy","characters":[{"char":"容","meaning":"appearance"},{"char":"光","meaning":"light"},{"char":"焕","meaning":"shine"},{"char":"发","meaning":"emit"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '容光焕发' is used to describe someone who looks particularly radiant and full of life, often due to good news, health, or happiness. The phrase evokes an image of light shining from a person's appearance, suggesting vitality and energy.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"modifier-head","register":"commonly used in both written and spoken Chinese","connotation":"positive","commonMistakes":"Learners might confuse this idiom with others that describe physical appearance but lack the connotation of vitality. It specifically implies a healthy, energetic glow, not just any kind of beauty.","canStandAlone":false},"examples":[{"simplified":"她今天看起来容光焕发，真是太美了。","english":"She looks radiant today, truly beautiful.","traditional":"她今天看起來容光煥發，真是太美了。"},{"simplified":"经过一段时间的休息，他显得容光焕发。","english":"After some rest, he appears radiant and full of energy.","traditional":"經過一段時間的休息，他顯得容光煥發。"}],"synonyms":["神采奕奕"],"antonyms":["无精打采"],"confusedWith":[{"id":"光彩夺目","note":"While both idioms describe an impressive appearance, '光彩夺目' emphasizes dazzling beauty, not necessarily vitality."}],"traditional":"容光煥發","pinyinOverride":null},{"id":"liao-liao-wu-ji","simplified":"寥寥无几","literalMeaning":"few and not many","figurativeMeaning":"very few; hardly any","englishEquivalents":["few and far between","scarce as hen's teeth"],"shortGloss":"very few; hardly any","characters":[{"char":"寥","meaning":"few"},{"char":"寥","meaning":"few"},{"char":"无","meaning":"not"},{"char":"几","meaning":"many"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '寥寥无几' is used to describe a situation where there are very few of something. It emphasizes the scarcity or rarity of the items or people being referred to. The origin of this idiom is not tied to a specific classical text, and it is commonly used in modern Chinese to express the idea of something being scarce or rare.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"modifier-head","register":"commonly used in both written and spoken Chinese","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with similar expressions that imply a complete absence, but '寥寥无几' specifically means that there are very few, not none at all.","canStandAlone":false},"examples":[{"simplified":"在这个偏远的村庄，年轻人寥寥无几。","english":"In this remote village, young people are few and far between.","traditional":"在這個偏遠的村莊，年輕人寥寥無幾。"},{"simplified":"他对这个问题的了解寥寥无几。","english":"His understanding of this issue is very limited.","traditional":"他對這個問題的瞭解寥寥無幾。"}],"synonyms":["屈指可数"],"antonyms":["比比皆是"],"confusedWith":[{"id":"寥若晨星","note":"Both idioms imply scarcity, but '寥若晨星' emphasizes rarity in a more poetic sense, like stars at dawn."}],"traditional":"寥寥無幾","pinyinOverride":null},{"id":"dui-zheng-xia-yao","simplified":"对症下药","literalMeaning":"apply medicine to the illness","figurativeMeaning":"to take appropriate measures to solve a problem; to address a situation with the right solution","englishEquivalents":["take the right measures","apply the right remedy"],"shortGloss":"take appropriate measures","characters":[{"char":"对","meaning":"to face; to address"},{"char":"症","meaning":"symptom; illness"},{"char":"下","meaning":"to apply; to administer"},{"char":"药","meaning":"medicine; remedy"}],"origin":{"period":"Tang Dynasty (618–907)","sourceText":"《孙思邈·千金方》","sourceTextEnglish":"Sun Simiao's 'Prescriptions Worth a Thousand Gold'","originalExcerpt":"凡大医治病，必当安神定志，无欲无求，先发大慈恻隐之心，誓愿普救含灵之苦。若有疾厄来求救者，不得问其贵贱贫富，长幼妍蚩，怨亲善友，华夷愚智，普同一等，皆如至亲之想，勿得瞋怒。... 诊病必当审因，方可对症下药。","storyEnglish":"The idiom originates from the medical text 'Prescriptions Worth a Thousand Gold' by Sun Simiao, a renowned physician of the Tang Dynasty. He emphasized the importance of diagnosing the illness accurately before prescribing the appropriate remedy. This principle of applying the right solution to a specific problem has since been extended to various fields beyond medicine.","historicalFigures":["Sun Simiao"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"widely used in both formal and informal contexts","connotation":"positive","commonMistakes":"Learners often confuse this idiom with general problem-solving idioms. It specifically implies using a targeted solution, not just any solution.","canStandAlone":false},"examples":[{"simplified":"在处理复杂问题时，我们必须对症下药。","english":"When dealing with complex problems, we must take appropriate measures.","traditional":"在處理複雜問題時，我們必須對症下藥。"},{"simplified":"医生根据病人的症状对症下药。","english":"The doctor prescribed the right medicine based on the patient's symptoms.","traditional":"醫生根據病人的症狀對症下藥。"}],"synonyms":["因地制宜"],"antonyms":[],"confusedWith":[{"id":"头痛医头，脚痛医脚","note":"This idiom implies a superficial or temporary solution, unlike 对症下药 which suggests a thorough and appropriate approach."}],"traditional":"對症下藥","pinyinOverride":null},{"id":"xiaoxin-yiyi","simplified":"小心翼翼","literalMeaning":"small heart with wings","figurativeMeaning":"to act with great care and caution","englishEquivalents":["with the utmost care","gingerly","cautiously"],"shortGloss":"with great care and caution","characters":[{"char":"小","meaning":"small"},{"char":"心","meaning":"heart; careful"},{"char":"翼","meaning":"wing"},{"char":"翼","meaning":"wing"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '小心翼翼' is believed to have originated from the idea of handling something as delicately as if it had wings, requiring careful and gentle treatment. It emphasizes the need for caution and attentiveness in one's actions.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["adverbial","attributive"],"structure":"coordinate","register":"widely used in both spoken and written Chinese","connotation":"neutral","commonMistakes":"Learners might confuse '小心翼翼' with '小心' (careful), but '小心翼翼' conveys a stronger sense of caution and meticulousness. It is often used in contexts where extreme care is necessary.","canStandAlone":false},"examples":[{"simplified":"他小心翼翼地把花瓶放回架子上。","english":"He carefully placed the vase back on the shelf.","traditional":"他小心翼翼地把花瓶放回架子上。"},{"simplified":"她小心翼翼地走过结冰的路面。","english":"She walked gingerly across the icy road.","traditional":"她小心翼翼地走過結冰的路面。"}],"synonyms":["谨小慎微"],"antonyms":["粗心大意"],"confusedWith":[{"id":"小心","note":"'小心' means careful, but '小心翼翼' implies a higher degree of caution and meticulousness."}],"traditional":"小心翼翼","pinyinOverride":null},{"id":"xiao-cai-yi-die","simplified":"小菜一碟","literalMeaning":"small dish one plate","figurativeMeaning":"something very easy to do; a piece of cake","englishEquivalents":["a piece of cake","easy as pie"],"shortGloss":"something very easy","characters":[{"char":"小","meaning":"small"},{"char":"菜","meaning":"dish"},{"char":"一","meaning":"one"},{"char":"碟","meaning":"plate"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '小菜一碟' is believed to have originated from the idea of a small dish being easy to prepare and serve. Over time, it came to metaphorically represent tasks that are simple and require little effort, much like preparing a small plate of food.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","complement"],"structure":"modifier-head","register":"informal, commonly used in both spoken and written Chinese","connotation":"neutral","commonMistakes":"Learners often confuse this idiom with more formal expressions of ease, but '小菜一碟' is informal and not suitable for formal writing. It is also sometimes confused with idioms that imply triviality rather than ease.","canStandAlone":false},"examples":[{"simplified":"这道题对他来说小菜一碟。","english":"This problem is a piece of cake for him.","traditional":"這道題對他來說小菜一碟。"},{"simplified":"修理这个机器对我来说小菜一碟。","english":"Fixing this machine is a piece of cake for me.","traditional":"修理這個機器對我來說小菜一碟。"}],"synonyms":["轻而易举","易如反掌"],"antonyms":["难如登天"],"confusedWith":[{"id":"轻而易举","note":"Both mean something is easy, but '轻而易举' is more formal."}],"traditional":"小菜一碟","pinyinOverride":null},{"id":"ceng-chu-bu-qiong","simplified":"层出不穷","literalMeaning":"layer upon layer emerge without end","figurativeMeaning":"to emerge one after another; to appear continuously","englishEquivalents":["endless stream","one after another","unceasing"],"shortGloss":"endless emergence","characters":[{"char":"层","meaning":"layer; continuously"},{"char":"出","meaning":"come out; emerge"},{"char":"不","meaning":"not"},{"char":"穷","meaning":"end; exhaust"}],"origin":{"period":"Song Dynasty (960–1279)","sourceText":"《宋史·乐志》","sourceTextEnglish":"History of Song, Music Records","originalExcerpt":"层出不穷，变幻无穷。","storyEnglish":"The idiom '层出不穷' originates from the 'History of Song', where it was used to describe the continuous and endless emergence of new things or phenomena. It suggests a situation where new developments or problems keep appearing one after another, without any sign of stopping.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"widely used in both formal and informal contexts","connotation":"neutral","commonMistakes":"Learners often confuse this idiom with similar expressions that imply a negative connotation, but '层出不穷' itself is neutral and can describe both positive and negative situations.","canStandAlone":false},"examples":[{"simplified":"科技的发展让新产品层出不穷。","english":"The development of technology leads to an endless stream of new products.","traditional":"科技的發展讓新產品層出不窮。"},{"simplified":"在这个行业中，挑战层出不穷。","english":"In this industry, challenges emerge one after another.","traditional":"在這個行業中，挑戰層出不窮。"}],"synonyms":["接连不断","络绎不绝"],"antonyms":["寥寥无几"],"confusedWith":[{"id":"应接不暇","note":"While both idioms describe a situation of abundance, '应接不暇' emphasizes being overwhelmed by the abundance, whereas '层出不穷' simply notes continuous emergence."}],"traditional":"層出不窮","pinyinOverride":null},{"id":"ju-an-si-wei","simplified":"居安思危","literalMeaning":"reside in peace, think of danger","figurativeMeaning":"to remain vigilant and be prepared for potential problems even in times of peace and stability","englishEquivalents":["forewarned is forearmed","hope for the best, prepare for the worst"],"shortGloss":"stay vigilant even in peace","characters":[{"char":"居","meaning":"reside"},{"char":"安","meaning":"peace"},{"char":"思","meaning":"think"},{"char":"危","meaning":"danger"}],"origin":{"period":"Warring States period (475–221 BCE)","sourceText":"《左传·襄公十一年》","sourceTextEnglish":"Zuo Zhuan, Duke Xiang, Year 11","originalExcerpt":"居安思危，思则有备，有备无患。","storyEnglish":"The idiom comes from the 'Zuo Zhuan', a historical narrative of the Spring and Autumn period. It advises rulers and individuals to remain vigilant and prepared for potential dangers even when they are in a state of peace and stability. This mindset ensures that they are ready to face any unforeseen challenges.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["adverbial","attributive"],"structure":"coordinate","register":"literary, but very widely understood and used in ordinary speech","connotation":"neutral","commonMistakes":"Learners sometimes use this idiom to describe a current state of danger, but it actually emphasizes the importance of preparation during peaceful times.","canStandAlone":false},"examples":[{"simplified":"在经济繁荣时期，我们也要居安思危，做好风险管理。","english":"Even during times of economic prosperity, we should remain vigilant and manage risks effectively.","traditional":"在經濟繁榮時期，我們也要居安思危，做好風險管理。"},{"simplified":"他总是居安思危，未雨绸缪。","english":"He always stays vigilant and prepares for the future.","traditional":"他總是居安思危，未雨綢繆。"}],"synonyms":["未雨绸缪"],"antonyms":[],"confusedWith":[{"id":"临渴掘井","note":"临渴掘井 refers to taking action only when it's too late, while 居安思危 emphasizes preparation in advance."}],"traditional":"居安思危","pinyinOverride":null},{"id":"ju-gao-bu-xia","simplified":"居高不下","literalMeaning":"remain high and not fall","figurativeMeaning":"to remain at a high level without decreasing, often used in the context of prices or statistics","englishEquivalents":["remain high","stay elevated"],"shortGloss":"remain high without falling","characters":[{"char":"居","meaning":"to remain"},{"char":"高","meaning":"high"},{"char":"不","meaning":"not"},{"char":"下","meaning":"fall"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '居高不下' is commonly used in modern Chinese to describe situations where something, such as prices or statistics, remains high and does not decrease. It is often used in economic contexts, such as describing inflation rates or housing prices that persist at elevated levels.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"commonly used in both formal and informal contexts, especially in economic discussions","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with others that imply a rise in levels, but '居高不下' specifically indicates that something remains high without falling, not that it is increasing.","canStandAlone":false},"examples":[{"simplified":"最近房价居高不下，让很多人买不起房。","english":"Recently, housing prices have remained high, making it unaffordable for many people to buy a home.","traditional":"最近房價居高不下，讓很多人買不起房。"},{"simplified":"尽管政府采取了措施，物价仍然居高不下。","english":"Despite the government's measures, prices remain high.","traditional":"儘管政府採取了措施，物價仍然居高不下。"}],"synonyms":["高居不下"],"antonyms":["节节下降"],"confusedWith":[{"id":"水涨船高","note":"水涨船高 implies that as one thing rises, another rises correspondingly, whereas 居高不下 means something remains high without falling."}],"traditional":"居高不下","pinyinOverride":null},{"id":"qi-you-ci-li","simplified":"岂有此理","literalMeaning":"how can there be such a principle","figurativeMeaning":"outrageous; absurd; preposterous","englishEquivalents":["How absurd!","Nonsense!","Ridiculous!"],"shortGloss":"outrageous; absurd","characters":[{"char":"岂","meaning":"how (used in a rhetorical question)"},{"char":"有","meaning":"have; exist"},{"char":"此","meaning":"this"},{"char":"理","meaning":"reason; principle"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '岂有此理' is often used to express disbelief or indignation at something perceived as unreasonable or absurd. It rhetorically questions how such a situation could exist, implying that it defies logic or accepted principles.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["standalone-exclamation"],"structure":"other","register":"commonly used in both spoken and written Chinese to express strong disbelief or indignation","connotation":"negative","commonMistakes":"Learners might mistakenly use this idiom in formal writing where a more neutral tone is required. It's best used in contexts where strong emotion or disbelief is appropriate.","canStandAlone":true},"examples":[{"simplified":"他说他能一夜之间学会中文，岂有此理！","english":"He said he could learn Chinese overnight, how absurd!","traditional":"他說他能一夜之間學會中文，豈有此理！"},{"simplified":"他们竟然认为这样做是对的，岂有此理！","english":"They actually think doing this is right, how preposterous!","traditional":"他們竟然認為這樣做是對的，豈有此理！"}],"synonyms":["荒谬绝伦","不可思议"],"antonyms":[],"confusedWith":[],"traditional":"豈有此理","pinyinOverride":null},{"id":"feng-hui-lu-zhuan","simplified":"峰回路转","literalMeaning":"peaks turn, paths twist","figurativeMeaning":"a situation with many twists and turns, often leading to a hopeful or positive outcome","englishEquivalents":["twists and turns","ups and downs"],"shortGloss":"twists and turns leading to a positive outcome","characters":[{"char":"峰","meaning":"peaks"},{"char":"回","meaning":"turn"},{"char":"路","meaning":"paths"},{"char":"转","meaning":"twist"}],"origin":{"period":"Tang dynasty (618–907 CE)","sourceText":"《白居易·长恨歌》","sourceTextEnglish":"Bai Juyi's 'Song of Everlasting Regret'","originalExcerpt":"峰回路转，有所不见，而景象开阔。","storyEnglish":"The idiom originates from Bai Juyi's famous poem 'Song of Everlasting Regret', which describes the twists and turns of a mountain path that eventually opens up to a wide and beautiful view. This metaphor is used to describe situations in life where, despite initial difficulties and complications, the outcome is ultimately positive and hopeful.","historicalFigures":["Bai Juyi"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["adverbial","attributive"],"structure":"coordinate","register":"literary, but widely understood and used in both formal and informal contexts","connotation":"positive","commonMistakes":"Learners often use this idiom to describe any complicated situation, but it specifically implies a positive or hopeful outcome after difficulties.","canStandAlone":false},"examples":[{"simplified":"在他的职业生涯中，虽然有过许多峰回路转，但最终他取得了成功。","english":"In his career, although there were many twists and turns, he ultimately achieved success.","traditional":"在他的職業生涯中，雖然有過許多峰迴路轉，但最終他取得了成功。"},{"simplified":"这部电影的情节峰回路转，让观众始终保持兴趣。","english":"The movie's plot had many twists and turns, keeping the audience engaged throughout.","traditional":"這部電影的情節峰迴路轉，讓觀眾始終保持興趣。"}],"synonyms":["柳暗花明"],"antonyms":[],"confusedWith":[{"id":"柳暗花明","note":"Both idioms describe situations with unexpected positive outcomes, but '柳暗花明' emphasizes the suddenness of the change."}],"traditional":"峰迴路轉","pinyinOverride":null},{"id":"chuan-liu-bu-xi","simplified":"川流不息","literalMeaning":"river flows without ceasing","figurativeMeaning":"something continuous and unending, like a steady stream","englishEquivalents":["a constant stream","endless flow"],"shortGloss":"continuous and unending flow","characters":[{"char":"川","meaning":"river"},{"char":"流","meaning":"flow"},{"char":"不","meaning":"not"},{"char":"息","meaning":"cease"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '川流不息' is often used to describe something that is continuous and unending, much like the flow of a river. It is commonly used to describe traffic, people, or any situation where there is a constant and uninterrupted flow.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial","attributive"],"structure":"subject-predicate","register":"commonly used in both written and spoken Chinese","connotation":"neutral","commonMistakes":"Learners might confuse it with idioms that imply a more chaotic or uncontrolled flow, but '川流不息' emphasizes a steady and continuous movement.","canStandAlone":false},"examples":[{"simplified":"节假日，广场上的游客川流不息。","english":"During the holidays, there is a constant stream of tourists in the square.","traditional":"節假日，廣場上的遊客川流不息。"},{"simplified":"城市的交通川流不息，仿佛永远不会停歇。","english":"The city's traffic flows endlessly, as if it will never stop.","traditional":"城市的交通川流不息，彷彿永遠不會停歇。"}],"synonyms":["络绎不绝"],"antonyms":[],"confusedWith":[{"id":"人山人海","note":"While both describe large numbers of people, '人山人海' emphasizes a crowded situation, whereas '川流不息' emphasizes continuous flow."}],"traditional":"川流不息","pinyinOverride":null},{"id":"zuo-gu-you-pan","simplified":"左顾右盼","literalMeaning":"look left, look right","figurativeMeaning":"to look around anxiously or to hesitate","englishEquivalents":["look over one's shoulder","hesitate"],"shortGloss":"look around anxiously","characters":[{"char":"左","meaning":"left"},{"char":"顾","meaning":"look"},{"char":"右","meaning":"right"},{"char":"盼","meaning":"look"}],"origin":{"period":"Han Dynasty (202 BCE – 220 CE)","sourceText":"《史记·项羽本纪》","sourceTextEnglish":"Records of the Grand Historian, Biography of Xiang Yu","originalExcerpt":"项王则受璧，置之坐上，左右顾盼，未有应者。","storyEnglish":"The idiom comes from a passage in the 'Records of the Grand Historian' where Xiang Yu, a prominent warlord, is described as looking left and right, waiting for someone to respond to his call. This scene captures the sense of looking around anxiously or hesitating, which is the essence of the idiom.","historicalFigures":["Xiang Yu"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"coordinate","register":"commonly used in both formal and informal contexts","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with others that involve looking or observing, but it specifically conveys hesitation or anxiousness rather than mere observation.","canStandAlone":false},"examples":[{"simplified":"他在面试时显得很紧张，不停地左顾右盼。","english":"He seemed very nervous during the interview, constantly looking around anxiously.","traditional":"他在面試時顯得很緊張，不停地左顧右盼。"},{"simplified":"她在街上左顾右盼，似乎在寻找什么人。","english":"She looked around on the street, seemingly searching for someone.","traditional":"她在街上左顧右盼，似乎在尋找什麼人。"}],"synonyms":[],"antonyms":[],"confusedWith":[],"traditional":"左顧右盼","pinyinOverride":null},{"id":"ying-you-jin-you","simplified":"应有尽有","literalMeaning":"should have, all have","figurativeMeaning":"to have everything one could wish for; to be fully equipped","englishEquivalents":["everything one could ask for","all-inclusive","fully equipped"],"shortGloss":"to have everything one could wish for","characters":[{"char":"应","meaning":"should"},{"char":"有","meaning":"have"},{"char":"尽","meaning":"all"},{"char":"有","meaning":"have"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '应有尽有' is often used to describe a situation or place where everything that is needed or desired is available. It suggests completeness and abundance, implying that nothing is lacking. This idiom is commonly used in advertising to describe well-stocked stores or comprehensive services.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"subject-predicate","register":"commonly used in both formal and informal contexts","connotation":"positive","commonMistakes":"Learners might confuse this idiom with similar expressions that imply abundance but lack the nuance of completeness. It specifically conveys that everything needed is present, not just a large quantity.","canStandAlone":false},"examples":[{"simplified":"这家商店商品齐全，应有尽有。","english":"This store is well-stocked; it has everything one could ask for.","traditional":"這家商店商品齊全，應有盡有。"},{"simplified":"他的书房里书籍应有尽有，真是个读书人的天堂。","english":"His study is filled with books of every kind; it's truly a paradise for readers.","traditional":"他的書房裡書籍應有盡有，真是個讀書人的天堂。"}],"synonyms":["一应俱全"],"antonyms":[],"confusedWith":[],"traditional":"應有盡有","pinyinOverride":null},{"id":"fei-qin-wang-shi","simplified":"废寝忘食","literalMeaning":"neglect sleep forget food","figurativeMeaning":"to be so absorbed in work or an activity that one forgets to eat and sleep","englishEquivalents":["burning the midnight oil","lost in work","immersed in work"],"shortGloss":"completely absorbed in work","characters":[{"char":"废","meaning":"neglect"},{"char":"寝","meaning":"sleep"},{"char":"忘","meaning":"forget"},{"char":"食","meaning":"food"}],"origin":{"period":"Han Dynasty (206 BCE – 220 CE)","sourceText":"《汉书·董仲舒传》","sourceTextEnglish":"Book of Han, Biography of Dong Zhongshu","originalExcerpt":"废寝忘食，以至于精疲力竭。","storyEnglish":"The idiom comes from the 'Book of Han', where it describes the dedication of Dong Zhongshu, a prominent scholar of the Han Dynasty. He was so engrossed in his studies and work that he often neglected to eat and sleep, leading to exhaustion. This idiom is now used to describe someone who is deeply absorbed in their work or passion.","historicalFigures":["Dong Zhongshu"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"coordinate","register":"literary, but very widely understood and used in ordinary speech","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with expressions that imply laziness or neglect of duty, but it actually conveys dedication and hard work. It should not be used to describe someone who is simply lazy or neglectful.","canStandAlone":false},"examples":[{"simplified":"他为了完成这个项目，废寝忘食地工作。","english":"He worked tirelessly, neglecting sleep and food, to complete the project.","traditional":"他為了完成這個項目，廢寢忘食地工作。"},{"simplified":"她对新书的写作废寝忘食，几乎忘了时间的流逝。","english":"She was so absorbed in writing her new book that she almost lost track of time.","traditional":"她對新書的寫作廢寢忘食，幾乎忘了時間的流逝。"}],"synonyms":["夜以继日"],"antonyms":["游手好闲"],"confusedWith":[{"id":"游手好闲","note":"游手好闲 means to be idle and lazy, which is the opposite of being absorbed in work."}],"traditional":"廢寢忘食","pinyinOverride":null},{"id":"kai-tian-pi-di","simplified":"开天辟地","literalMeaning":"open sky cleave earth","figurativeMeaning":"a groundbreaking or unprecedented event; to create something entirely new","englishEquivalents":["break new ground","pioneer","make history"],"shortGloss":"groundbreaking event","characters":[{"char":"开","meaning":"open"},{"char":"天","meaning":"sky; heaven"},{"char":"辟","meaning":"cleave; split"},{"char":"地","meaning":"earth; ground"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '开天辟地' is often associated with the Chinese creation myth of Pangu, who is said to have separated the sky from the earth, creating the world. This act of creation is used metaphorically to describe any groundbreaking or unprecedented event.","historicalFigures":["Pangu"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["attributive","adverbial","predicate"],"structure":"verb-object","register":"literary, but widely understood and used in both formal and informal contexts","connotation":"positive","commonMistakes":"Learners might confuse this idiom with more general terms for innovation, but '开天辟地' specifically implies a foundational or unprecedented change, not just any new idea.","canStandAlone":false},"examples":[{"simplified":"这项技术的发明真是开天辟地，改变了整个行业。","english":"The invention of this technology was truly groundbreaking and changed the entire industry.","traditional":"這項技術的發明真是開天闢地，改變了整個行業。"},{"simplified":"他在科学界做出了开天辟地的贡献。","english":"He made groundbreaking contributions to the scientific community.","traditional":"他在科學界做出了開天闢地的貢獻。"}],"synonyms":["破天荒","首开先河"],"antonyms":[],"confusedWith":[{"id":"推陈出新","note":"While both idioms involve innovation, '推陈出新' emphasizes improving upon the old, whereas '开天辟地' implies creating something entirely new."}],"traditional":"開天闢地","pinyinOverride":null},{"id":"yi-kou-tong-sheng","simplified":"异口同声","literalMeaning":"different mouths, same voice","figurativeMeaning":"to speak in unison; to express the same opinion","englishEquivalents":["speak with one voice","in unison"],"shortGloss":"speak in unison","characters":[{"char":"异","meaning":"different"},{"char":"口","meaning":"mouth"},{"char":"同","meaning":"same"},{"char":"声","meaning":"voice"}],"origin":{"period":"Han Dynasty (202 BCE – 220 CE)","sourceText":"《史记·秦始皇本纪》","sourceTextEnglish":"Records of the Grand Historian, Annals of Qin Shi Huang","originalExcerpt":"群臣异口同声，称万岁。","storyEnglish":"The idiom originates from the 'Records of the Grand Historian' by Sima Qian, where it describes a scene in which all the ministers of the court, despite being different individuals, unanimously praised the emperor, Qin Shi Huang, by shouting 'Long live the emperor!' in unison.","historicalFigures":["Qin Shi Huang"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"modifier-head","register":"widely used in both formal and informal contexts","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with others that involve agreement, but this idiom specifically emphasizes the simultaneous expression of the same opinion or statement by multiple people.","canStandAlone":false},"examples":[{"simplified":"在会议上，大家异口同声地表示支持这个计划。","english":"At the meeting, everyone expressed their support for the plan in unison.","traditional":"在會議上，大家異口同聲地表示支持這個計劃。"},{"simplified":"孩子们异口同声地回答了老师的问题。","english":"The children answered the teacher's question in unison.","traditional":"孩子們異口同聲地回答了老師的問題。"}],"synonyms":["众口一词"],"antonyms":[],"confusedWith":[{"id":"众口一词","note":"While both idioms involve agreement, '众口一词' emphasizes the consistency of opinion rather than the simultaneous expression."}],"traditional":"異口同聲","pinyinOverride":null},{"id":"yi-xiang-tian-kai","simplified":"异想天开","literalMeaning":"strange thoughts open to the sky","figurativeMeaning":"to indulge in flights of fancy; to have unrealistic or impractical ideas","englishEquivalents":["pipe dream","castles in the air"],"shortGloss":"indulge in unrealistic ideas","characters":[{"char":"异","meaning":"strange; different"},{"char":"想","meaning":"thought; idea"},{"char":"天","meaning":"sky; heaven"},{"char":"开","meaning":"open"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '异想天开' describes the act of having fantastical or unrealistic ideas, as if one's thoughts are so strange and lofty that they reach the sky. It is often used to describe someone who is dreaming up impractical plans or ideas.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"modifier-head","register":"commonly used in both spoken and written Chinese to describe unrealistic thinking","connotation":"negative","commonMistakes":"Learners often confuse this idiom with positive expressions of creativity. However, '异想天开' implies impracticality rather than innovation.","canStandAlone":false},"examples":[{"simplified":"他总是异想天开，想要发明一种能让人飞的鞋子。","english":"He is always indulging in flights of fancy, wanting to invent shoes that allow people to fly.","traditional":"他總是異想天開，想要發明一種能讓人飛的鞋子。"},{"simplified":"你这样异想天开，怎么可能成功呢？","english":"How can you succeed if you keep indulging in such unrealistic ideas?","traditional":"你這樣異想天開，怎麼可能成功呢？"}],"synonyms":["痴人说梦"],"antonyms":["脚踏实地"],"confusedWith":[{"id":"天马行空","note":"While both involve imaginative thinking, '天马行空' often has a positive connotation of creativity, unlike '异想天开'."}],"traditional":"異想天開","pinyinOverride":null},{"id":"nong-xu-zuo-jia","simplified":"弄虚作假","literalMeaning":"engage in trickery, make falsehoods","figurativeMeaning":"to deceive or cheat; to engage in fraudulent activities","englishEquivalents":["to pull the wool over someone's eyes","to cook the books"],"shortGloss":"to deceive or cheat","characters":[{"char":"弄","meaning":"engage in"},{"char":"虚","meaning":"trickery, falsehood"},{"char":"作","meaning":"make, create"},{"char":"假","meaning":"false, fake"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '弄虚作假' is used to describe actions that involve deception and trickery. It conveys the idea of creating falsehoods or engaging in fraudulent activities to deceive others. The exact origin of this idiom is uncertain, but it has been widely used in Chinese literature and speech to criticize dishonest behavior.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"coordinate","register":"commonly used in both formal and informal contexts to describe deceitful actions","connotation":"negative","commonMistakes":"Learners might confuse this idiom with similar expressions that involve dishonesty, but '弄虚作假' specifically emphasizes the act of creating falsehoods or engaging in trickery. It should not be used to describe minor lies or exaggerations.","canStandAlone":false},"examples":[{"simplified":"他在考试中弄虚作假，被老师发现了。","english":"He cheated in the exam and was caught by the teacher.","traditional":"他在考試中弄虛作假，被老師發現了。"},{"simplified":"公司财务报告中弄虚作假，导致股价暴跌。","english":"The company's financial reports were falsified, leading to a sharp drop in stock prices.","traditional":"公司財務報告中弄虛作假，導致股價暴跌。"}],"synonyms":["欺上瞒下","弄假成真"],"antonyms":["实事求是"],"confusedWith":[{"id":"弄假成真","note":"While both involve deception, '弄假成真' refers to a falsehood becoming reality, whereas '弄虚作假' is about deliberate deceit."}],"traditional":"弄虛作假","pinyinOverride":null},{"id":"yin-ren-ru-sheng","simplified":"引人入胜","literalMeaning":"lead people into a captivating place","figurativeMeaning":"fascinating; captivating; able to attract and hold one's attention","englishEquivalents":["captivating","gripping","spellbinding"],"shortGloss":"captivating and fascinating","characters":[{"char":"引","meaning":"to lead"},{"char":"人","meaning":"people"},{"char":"入","meaning":"into"},{"char":"胜","meaning":"a captivating place"}],"origin":{"period":"Ming Dynasty (1368–1644)","sourceText":"《徐霞客游记》","sourceTextEnglish":"Xu Xiake's Travels","originalExcerpt":"游人至此，皆引人入胜。","storyEnglish":"The idiom originates from the travel writings of Xu Xiake, a famous Ming Dynasty geographer and explorer. In his travelogue, Xu describes various scenic spots that are so beautiful and captivating that they draw people in, making them feel as if they have entered a wondrous place. The phrase '引人入胜' was used to describe such enchanting experiences.","historicalFigures":["Xu Xiake"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"modifier-head","register":"literary, but widely used in both written and spoken Chinese","connotation":"positive","commonMistakes":"Learners might confuse this idiom with similar phrases that imply mere interest rather than deep captivation. It's important to note that '引人入胜' conveys a stronger sense of fascination.","canStandAlone":false},"examples":[{"simplified":"这本小说情节引人入胜，让我一口气读完了。","english":"The plot of this novel is so captivating that I read it all in one go.","traditional":"這本小說情節引人入勝，讓我一口氣讀完了。"},{"simplified":"他的演讲引人入胜，观众们都听得入迷了。","english":"His speech was captivating, and the audience was completely absorbed.","traditional":"他的演講引人入勝，觀眾們都聽得入迷了。"}],"synonyms":["扣人心弦"],"antonyms":[],"confusedWith":[],"traditional":"引人入勝","pinyinOverride":null},{"id":"yin-ren-zhu-mu","simplified":"引人注目","literalMeaning":"attract people's attention","figurativeMeaning":"to attract attention; to be eye-catching or noticeable","englishEquivalents":["catch someone's eye","stand out","draw attention"],"shortGloss":"eye-catching; noticeable","characters":[{"char":"引","meaning":"to attract or draw"},{"char":"人","meaning":"people"},{"char":"注","meaning":"to focus or pay attention"},{"char":"目","meaning":"eyes"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '引人注目' is used to describe something or someone that draws attention or stands out in a crowd. It is often used in contexts where something is particularly striking or noteworthy, causing people to look or take notice.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"verb-object","register":"commonly used in both written and spoken Chinese","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with similar expressions that imply attracting attention for negative reasons. '引人注目' is neutral and does not imply whether the attention is positive or negative.","canStandAlone":false},"examples":[{"simplified":"她的穿着非常引人注目。","english":"Her outfit is very eye-catching.","traditional":"她的穿著非常引人注目。"},{"simplified":"这座建筑的设计引人注目。","english":"The design of this building is attention-grabbing.","traditional":"這座建築的設計引人注目。"}],"synonyms":["引人注意","吸引眼球"],"antonyms":["默默无闻"],"confusedWith":[{"id":"引人注意","note":"Both mean to attract attention, but '引人注意' can imply a more deliberate action to gain attention."}],"traditional":"引人注目","pinyinOverride":null},{"id":"yin-jing-ju-dian","simplified":"引经据典","literalMeaning":"quote classics cite texts","figurativeMeaning":"to quote classical texts or authoritative sources to support one's argument","englishEquivalents":["quote chapter and verse","cite authorities"],"shortGloss":"quote classical texts","characters":[{"char":"引","meaning":"to quote"},{"char":"经","meaning":"classics"},{"char":"据","meaning":"to cite"},{"char":"典","meaning":"texts"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '引经据典' refers to the practice of quoting classical texts or authoritative sources to support one's argument or viewpoint. This practice has been a hallmark of scholarly work in Chinese culture, where the classics are often seen as the ultimate authority on various subjects. The idiom emphasizes the importance of grounding one's arguments in respected sources.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["adverbial","attributive"],"structure":"coordinate","register":"literary, but widely understood and used in both written and spoken Chinese","connotation":"neutral","commonMistakes":"Learners sometimes use this idiom to imply that any kind of quoting is involved, but it specifically refers to quoting classical or authoritative texts. It is not used for casual or modern references.","canStandAlone":false},"examples":[{"simplified":"在辩论中，他总是喜欢引经据典。","english":"In debates, he always likes to quote classical texts.","traditional":"在辯論中，他總是喜歡引經據典。"},{"simplified":"这篇文章引经据典，令人信服。","english":"This article quotes authoritative texts, making it convincing.","traditional":"這篇文章引經據典，令人信服。"}],"synonyms":["旁征博引"],"antonyms":[],"confusedWith":[{"id":"旁征博引","note":"While both involve citing sources, 旁征博引 emphasizes citing a wide range of sources, not just classical texts."}],"traditional":"引經據典","pinyinOverride":null},{"id":"zhang-deng-jie-cai","simplified":"张灯结彩","literalMeaning":"hang lanterns and tie colorful decorations","figurativeMeaning":"to celebrate festively; to decorate for a joyous occasion","englishEquivalents":["paint the town red","deck the halls"],"shortGloss":"celebrate festively with decorations","characters":[{"char":"张","meaning":"hang"},{"char":"灯","meaning":"lanterns"},{"char":"结","meaning":"tie"},{"char":"彩","meaning":"colorful decorations"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '张灯结彩' is commonly used to describe the act of decorating a place with lanterns and colorful ornaments, especially during festivals and celebrations. It evokes an image of a vibrant and joyous atmosphere, where people come together to celebrate and enjoy festive occasions.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"commonly used in both written and spoken Chinese, especially around festive times","connotation":"positive","commonMistakes":"Learners might confuse this idiom with others related to celebrations, but '张灯结彩' specifically emphasizes the visual aspect of hanging lanterns and decorations. It is not used to describe the act of partying or feasting.","canStandAlone":false},"examples":[{"simplified":"春节期间，家家户户都张灯结彩，迎接新年的到来。","english":"During the Spring Festival, every household hangs lanterns and colorful decorations to welcome the New Year.","traditional":"春節期間，家家戶戶都張燈結綵，迎接新年的到來。"},{"simplified":"为了庆祝公司的周年纪念，他们在办公室里张灯结彩。","english":"To celebrate the company's anniversary, they decorated the office with lanterns and colorful ornaments.","traditional":"為了慶祝公司的週年紀念，他們在辦公室裡張燈結綵。"}],"synonyms":["喜气洋洋","欢天喜地"],"antonyms":["冷冷清清"],"confusedWith":[{"id":"欢天喜地","note":"While both idioms relate to celebrations, '欢天喜地' focuses on the joyful mood, whereas '张灯结彩' emphasizes the decorative aspect."}],"traditional":"張燈結綵","pinyinOverride":null},{"id":"gui-gen-dao-di","simplified":"归根到底","literalMeaning":"return to the root and reach the bottom","figurativeMeaning":"ultimately; in the final analysis","englishEquivalents":["when all is said and done","at the end of the day"],"shortGloss":"ultimately; in the final analysis","characters":[{"char":"归","meaning":"return"},{"char":"根","meaning":"root"},{"char":"到","meaning":"reach"},{"char":"底","meaning":"bottom"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '归根到底' is often used to express the idea of getting to the essence or fundamental nature of something. It suggests that no matter how complex a situation may seem, there is a basic truth or root cause that can be identified. The phrase is commonly used in discussions to emphasize the importance of understanding the core issue.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["adverbial"],"structure":"other","register":"common in both spoken and written Chinese, used in formal and informal contexts","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with phrases that suggest a conclusion or result, but '归根到底' specifically emphasizes analyzing or understanding the fundamental nature of something.","canStandAlone":false},"examples":[{"simplified":"归根到底，成功需要坚持和努力。","english":"Ultimately, success requires perseverance and effort.","traditional":"歸根到底，成功需要堅持和努力。"},{"simplified":"归根到底，这个问题是因为沟通不畅造成的。","english":"In the final analysis, this problem was caused by poor communication.","traditional":"歸根到底，這個問題是因為溝通不暢造成的。"}],"synonyms":["总而言之","说到底"],"antonyms":[],"confusedWith":[{"id":"水落石出","note":"While '水落石出' also involves reaching a conclusion, it specifically refers to the truth being revealed over time, not analyzing the fundamental nature."}],"traditional":"歸根到底","pinyinOverride":null},{"id":"dang-zhi-wu-kui","simplified":"当之无愧","literalMeaning":"deserve it without shame","figurativeMeaning":"fully deserving of a title or honor; worthy of the recognition","englishEquivalents":["worthy of the name","deserve the credit"],"shortGloss":"fully deserving of honor","characters":[{"char":"当","meaning":"deserve"},{"char":"之","meaning":"it; this"},{"char":"无","meaning":"without"},{"char":"愧","meaning":"shame; guilt"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '当之无愧' is used to express that someone is fully deserving of a title, honor, or recognition without any sense of shame or guilt. It emphasizes the idea that the person has earned their status or praise through their actions or achievements.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"modifier-head","register":"commonly used in both formal and informal contexts","connotation":"positive","commonMistakes":"Learners might confuse this idiom with similar expressions that imply unworthiness or shame. It's important to remember that '当之无愧' is used to affirm someone's deserving status, not to question it.","canStandAlone":false},"examples":[{"simplified":"他在这次比赛中表现出色，当之无愧地获得了冠军。","english":"He performed excellently in the competition and deservedly won the championship.","traditional":"他在這次比賽中表現出色，當之無愧地獲得了冠軍。"},{"simplified":"她的努力和贡献使她成为当之无愧的领导者。","english":"Her efforts and contributions make her a leader truly worthy of the title.","traditional":"她的努力和貢獻使她成為當之無愧的領導者。"}],"synonyms":["名副其实","实至名归"],"antonyms":[],"confusedWith":[],"traditional":"當之無愧","pinyinOverride":null},{"id":"dang-wu-zhi-ji","simplified":"当务之急","literalMeaning":"the urgent matter of the moment","figurativeMeaning":"the most pressing task or priority at hand","englishEquivalents":["top priority","urgent task","pressing matter"],"shortGloss":"top priority","characters":[{"char":"当","meaning":"current"},{"char":"务","meaning":"affair; task"},{"char":"之","meaning":"of"},{"char":"急","meaning":"urgent"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom 当务之急 is used to emphasize the importance of addressing the most pressing issue or task at hand. It is often used in contexts where prioritization is necessary, highlighting the need to focus on what is most urgent before attending to other matters.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["subject","predicate","object","attributive"],"structure":"modifier-head","register":"widely used in both formal and informal contexts","connotation":"neutral","commonMistakes":"Learners sometimes confuse 当务之急 with other idioms that imply urgency but do not specifically refer to the most important task. It's important to use it when referring to the top priority, not just any urgent matter.","canStandAlone":false},"examples":[{"simplified":"解决这个问题是我们的当务之急。","english":"Solving this problem is our top priority.","traditional":"解決這個問題是我們的當務之急。"},{"simplified":"在这种情况下，找到安全的地方是当务之急。","english":"In this situation, finding a safe place is the most pressing task.","traditional":"在這種情況下，找到安全的地方是當務之急。"}],"synonyms":["燃眉之急"],"antonyms":[],"confusedWith":[{"id":"迫在眉睫","note":"迫在眉睫 also indicates urgency but refers to something imminent rather than the top priority."}],"traditional":"當務之急","pinyinOverride":null},{"id":"dang-ji-li-duan","simplified":"当机立断","literalMeaning":"seize the moment, make a decision","figurativeMeaning":"to make a prompt decision; to act decisively when the opportunity arises","englishEquivalents":["strike while the iron is hot","seize the day"],"shortGloss":"act decisively","characters":[{"char":"当","meaning":"at, in the moment"},{"char":"机","meaning":"opportunity, critical moment"},{"char":"立","meaning":"immediately, promptly"},{"char":"断","meaning":"decide, make a decision"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '当机立断' emphasizes the importance of making quick and decisive decisions when faced with an opportunity or critical moment. It suggests that hesitation can lead to missed opportunities, and one must be ready to act promptly to achieve success.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"widely used in both formal and informal contexts","connotation":"positive","commonMistakes":"Learners might confuse this idiom with '犹豫不决' (hesitate and be indecisive), which has the opposite meaning. '当机立断' should be used to describe someone who acts quickly and decisively.","canStandAlone":false},"examples":[{"simplified":"在危机时刻，他总是能够当机立断，找到解决办法。","english":"In times of crisis, he is always able to make prompt decisions and find solutions.","traditional":"在危機時刻，他總是能夠當機立斷，找到解決辦法。"},{"simplified":"面对突如其来的机会，她当机立断，接受了新的工作。","english":"Faced with a sudden opportunity, she acted decisively and accepted the new job.","traditional":"面對突如其來的機會，她當機立斷，接受了新的工作。"}],"synonyms":["果断决策","立刻决定"],"antonyms":["犹豫不决"],"confusedWith":[{"id":"犹豫不决","note":"犹豫不决 means to hesitate and be indecisive, which is the opposite of acting decisively."}],"traditional":"當機立斷","pinyinOverride":null},{"id":"xing-xing-se-se","simplified":"形形色色","literalMeaning":"shapes and colors","figurativeMeaning":"various and diverse; of all kinds","englishEquivalents":["various and sundry","all shapes and sizes","a wide variety"],"shortGloss":"various and diverse","characters":[{"char":"形","meaning":"shape; form"},{"char":"形","meaning":"shape; form"},{"char":"色","meaning":"color; kind"},{"char":"色","meaning":"color; kind"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '形形色色' is used to describe a wide variety of things, emphasizing diversity and multiplicity. It is often used to refer to people, objects, or ideas that come in many different forms and types.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["attributive","adverbial"],"structure":"AABB","register":"commonly used in both written and spoken Chinese","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with others that also describe variety, but '形形色色' specifically emphasizes the diversity in forms and types, not just quantity.","canStandAlone":false},"examples":[{"simplified":"市场上有形形色色的商品供你选择。","english":"There are a wide variety of products in the market for you to choose from.","traditional":"市場上有形形色色的商品供你選擇。"},{"simplified":"他交了很多朋友，形形色色的人都有。","english":"He has made many friends, and they come in all shapes and sizes.","traditional":"他交了很多朋友，形形色色的人都有。"}],"synonyms":["五花八门","各式各样"],"antonyms":[],"confusedWith":[{"id":"五花八门","note":"While both idioms describe variety, '五花八门' often emphasizes the complexity and range of options, whereas '形形色色' focuses more on diversity in forms and types."}],"traditional":"形形色色","pinyinOverride":null},{"id":"xing-ying-bu-li","simplified":"形影不离","literalMeaning":"form and shadow inseparable","figurativeMeaning":"inseparable; always together","englishEquivalents":["joined at the hip","inseparable","like two peas in a pod"],"shortGloss":"inseparable; always together","characters":[{"char":"形","meaning":"form; body"},{"char":"影","meaning":"shadow"},{"char":"不","meaning":"not"},{"char":"离","meaning":"separate; leave"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '形影不离' describes a relationship where two people or things are as inseparable as a form and its shadow. This suggests a close bond or constant companionship, where one is always found with the other.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"modifier-head","register":"commonly used in both spoken and written Chinese","connotation":"positive","commonMistakes":"Learners might confuse this idiom with others that imply closeness but not necessarily inseparability. It's important to use it when describing relationships or situations where the entities are always together.","canStandAlone":false},"examples":[{"simplified":"他们俩从小就是形影不离的好朋友。","english":"They have been inseparable friends since childhood.","traditional":"他們倆從小就是形影不離的好朋友。"},{"simplified":"这对夫妻总是形影不离，一起出现在各种场合。","english":"This couple is always together, appearing inseparable at various events.","traditional":"這對夫妻總是形影不離，一起出現在各種場合。"}],"synonyms":["如影随形"],"antonyms":["形单影只"],"confusedWith":[{"id":"如影随形","note":"Both idioms describe inseparability, but '如影随形' emphasizes following closely like a shadow."}],"traditional":"形影不離","pinyinOverride":null},{"id":"bin-bin-you-li","simplified":"彬彬有礼","literalMeaning":"refined and courteous","figurativeMeaning":"polite and courteous in manner","englishEquivalents":["polite and courteous","well-mannered","courteous"],"shortGloss":"polite and courteous","characters":[{"char":"彬","meaning":"refined"},{"char":"彬","meaning":"refined"},{"char":"有","meaning":"have"},{"char":"礼","meaning":"manners; courtesy"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '彬彬有礼' is used to describe someone who is very polite and courteous. It emphasizes a refined and well-mannered demeanor. The repetition of the character '彬' highlights the emphasis on refinement and elegance in behavior.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"modifier-head","register":"widely used in both written and spoken Chinese","connotation":"positive","commonMistakes":"Learners might confuse '彬彬有礼' with '有礼貌', which also means polite but lacks the emphasis on refinement and elegance. '彬彬有礼' is often used to describe a more formal or elegant politeness.","canStandAlone":false},"examples":[{"simplified":"他总是彬彬有礼，让人感到很舒服。","english":"He is always polite and courteous, making people feel very comfortable.","traditional":"他總是彬彬有禮，讓人感到很舒服。"},{"simplified":"在正式场合中，彬彬有礼的态度是非常重要的。","english":"In formal occasions, a polite and courteous attitude is very important.","traditional":"在正式場合中，彬彬有禮的態度是非常重要的。"}],"synonyms":["有礼貌","温文尔雅"],"antonyms":["粗鲁无礼"],"confusedWith":[{"id":"有礼貌","note":"Both mean polite, but '彬彬有礼' emphasizes refinement and elegance."}],"traditional":"彬彬有禮","pinyinOverride":null},{"id":"de-bu-chang-shi","simplified":"得不偿失","literalMeaning":"gain not compensate loss","figurativeMeaning":"the gains do not outweigh the losses; not worth the effort","englishEquivalents":["not worth the candle","penny wise, pound foolish"],"shortGloss":"not worth the effort","characters":[{"char":"得","meaning":"gain"},{"char":"不","meaning":"not"},{"char":"偿","meaning":"compensate"},{"char":"失","meaning":"loss"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '得不偿失' is often used to describe situations where the effort or cost put into something is not justified by the benefits gained. It emphasizes the imbalance between what is gained and what is lost, suggesting that the endeavor is not worthwhile.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"commonly used in both spoken and written Chinese, suitable for formal and informal contexts","connotation":"negative","commonMistakes":"Learners often confuse this idiom with others that involve gains and losses, such as '损失惨重' (suffer heavy losses), which focuses solely on the magnitude of loss rather than the balance between gain and loss.","canStandAlone":false},"examples":[{"simplified":"为了省钱而买便宜货，结果得不偿失。","english":"Buying cheap goods to save money ended up not being worth it.","traditional":"為了省錢而買便宜貨，結果得不償失。"},{"simplified":"如果为了小利而失去长远的利益，那就是得不偿失。","english":"If you lose long-term benefits for small gains, it's not worth the effort.","traditional":"如果為了小利而失去長遠的利益，那就是得不償失。"}],"synonyms":["得不偿失"],"antonyms":["物有所值"],"confusedWith":[{"id":"损失惨重","note":"损失惨重 focuses on the severity of the loss, not the balance between gain and loss."}],"traditional":"得不償失","pinyinOverride":null},{"id":"de-tian-du-hou","simplified":"得天独厚","literalMeaning":"receive heaven's unique favor","figurativeMeaning":"to be uniquely endowed by nature; to have exceptional advantages","englishEquivalents":["blessed with natural advantages","uniquely gifted","a cut above the rest"],"shortGloss":"uniquely endowed by nature","characters":[{"char":"得","meaning":"to receive"},{"char":"天","meaning":"heaven; nature"},{"char":"独","meaning":"unique; alone"},{"char":"厚","meaning":"abundant; generous"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '得天独厚' is often used to describe someone or something that has been naturally endowed with exceptional qualities or advantages. It suggests that these advantages are so unique and abundant that they seem to be a special gift from heaven or nature itself.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["attributive","predicate"],"structure":"modifier-head","register":"widely used in both formal and informal contexts","connotation":"positive","commonMistakes":"Learners sometimes confuse this idiom with others that imply hard work or effort, but '得天独厚' specifically refers to natural advantages rather than those earned through effort.","canStandAlone":false},"examples":[{"simplified":"这个地区得天独厚，适合发展旅游业。","english":"This region is uniquely endowed by nature, making it suitable for developing tourism.","traditional":"這個地區得天獨厚，適合發展旅遊業。"},{"simplified":"他在音乐方面得天独厚，年纪轻轻就成为了著名的钢琴家。","english":"He is uniquely gifted in music and became a famous pianist at a young age.","traditional":"他在音樂方面得天獨厚，年紀輕輕就成為了著名的鋼琴家。"}],"synonyms":["天赋异禀"],"antonyms":[],"confusedWith":[{"id":"后天努力","note":"得天独厚 refers to natural advantages, while 后天努力 emphasizes effort and hard work."}],"traditional":"得天獨厚","pinyinOverride":null},{"id":"de-xin-ying-shou","simplified":"得心应手","literalMeaning":"obtain heart respond hand","figurativeMeaning":"to do something with high proficiency and ease","englishEquivalents":["with great skill and ease","like a fish in water"],"shortGloss":"do with skill and ease","characters":[{"char":"得","meaning":"obtain, achieve"},{"char":"心","meaning":"heart, mind"},{"char":"应","meaning":"respond, correspond"},{"char":"手","meaning":"hand"}],"origin":{"period":"Northern and Southern Dynasties (420–589 CE)","sourceText":"《南史·王僧虔传》","sourceTextEnglish":"History of the Southern Dynasties, Biography of Wang Sengqian","originalExcerpt":"书至于此，得心应手，转腕成章。","storyEnglish":"The idiom originates from a description of Wang Sengqian, a talented calligrapher during the Southern Dynasties. It was said that when he wrote, his heart and hand worked in perfect harmony, allowing him to create beautiful characters effortlessly. This phrase has since been used to describe someone who performs a task with great skill and ease.","historicalFigures":["Wang Sengqian"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"modifier-head","register":"widely used in both formal and informal contexts","connotation":"positive","commonMistakes":"Learners sometimes confuse this idiom with others that imply effortlessness but lack the connotation of skill, such as 游刃有余, which specifically refers to handling complex tasks with ease.","canStandAlone":false},"examples":[{"simplified":"他弹钢琴弹得心应手，令人赞叹。","english":"He plays the piano with great skill and ease, earning admiration.","traditional":"他彈鋼琴彈得心應手，令人讚歎。"},{"simplified":"经过多年的练习，她现在画画已经得心应手了。","english":"After years of practice, she now paints with great skill and ease.","traditional":"經過多年的練習，她現在畫畫已經得心應手了。"}],"synonyms":["游刃有余"],"antonyms":[],"confusedWith":[{"id":"游刃有余","note":"While both imply ease, 游刃有余 emphasizes handling complex tasks, whereas 得心应手 highlights proficiency and skill."}],"traditional":"得心應手","pinyinOverride":null},{"id":"de-yi-yang-yang","simplified":"得意扬扬","literalMeaning":"proud and elated","figurativeMeaning":"to be very pleased with oneself; to be triumphant","englishEquivalents":["on cloud nine","walking on air","over the moon"],"shortGloss":"triumphantly pleased","characters":[{"char":"得","meaning":"to obtain, to gain"},{"char":"意","meaning":"satisfaction, meaning"},{"char":"扬","meaning":"to raise, to lift"},{"char":"扬","meaning":"to raise, to lift"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom 得意扬扬 is often used to describe someone who is visibly pleased with their achievements or success. It conveys a sense of triumph and self-satisfaction, as if the person is walking with their head held high, basking in their own glory.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"coordinate","register":"commonly used in both written and spoken Chinese","connotation":"positive","commonMistakes":"Learners often confuse 得意扬扬 with related idioms that describe arrogance, such as 自鸣得意. However, 得意扬扬 is more about being pleased with oneself rather than being boastful.","canStandAlone":false},"examples":[{"simplified":"他得意扬扬地走出考场，因为他知道自己考得很好。","english":"He walked out of the exam room triumphantly because he knew he had done well.","traditional":"他得意揚揚地走出考場，因為他知道自己考得很好。"},{"simplified":"比赛结束后，她得意扬扬地接受了大家的祝贺。","english":"After the competition, she accepted everyone's congratulations with great pride.","traditional":"比賽結束後，她得意揚揚地接受了大家的祝賀。"}],"synonyms":["自鸣得意","洋洋得意"],"antonyms":["垂头丧气","灰心丧气"],"confusedWith":[{"id":"自鸣得意","note":"自鸣得意 implies a sense of arrogance and self-satisfaction, while 得意扬扬 focuses more on the feeling of triumph."}],"traditional":"得意揚揚","pinyinOverride":null},{"id":"xun-xu-jian-jin","simplified":"循序渐进","literalMeaning":"follow order gradually advance","figurativeMeaning":"to proceed step by step; to advance gradually and steadily","englishEquivalents":["step by step","gradual progress"],"shortGloss":"proceed step by step","characters":[{"char":"循","meaning":"follow"},{"char":"序","meaning":"order"},{"char":"渐","meaning":"gradually"},{"char":"进","meaning":"advance"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '循序渐进' emphasizes the importance of progressing in an orderly and gradual manner. It suggests that success or achievement is best attained by taking small, consistent steps rather than rushing or skipping necessary stages.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["adverbial","attributive"],"structure":"modifier-head","register":"commonly used in both formal and informal contexts","connotation":"positive","commonMistakes":"Learners might confuse this idiom with expressions that imply rapid progress. It's important to remember that '循序渐进' emphasizes gradual and steady advancement.","canStandAlone":false},"examples":[{"simplified":"学习一门新语言需要循序渐进，不能急于求成。","english":"Learning a new language requires a step-by-step approach; you can't rush it.","traditional":"學習一門新語言需要循序漸進，不能急於求成。"},{"simplified":"在工作中，我们应该循序渐进，稳扎稳打。","english":"In work, we should proceed step by step, building a solid foundation.","traditional":"在工作中，我們應該循序漸進，穩紮穩打。"}],"synonyms":["按部就班"],"antonyms":["急于求成"],"confusedWith":[{"id":"急于求成","note":"急于求成 implies impatience and rushing, whereas 循序渐进 emphasizes gradual progress."}],"traditional":"循序漸進","pinyinOverride":null},{"id":"wei-bu-zu-dao","simplified":"微不足道","literalMeaning":"tiny not enough to speak of","figurativeMeaning":"insignificant; negligible; not worth mentioning","englishEquivalents":["not worth mentioning","insignificant","negligible"],"shortGloss":"insignificant; negligible","characters":[{"char":"微","meaning":"tiny; small"},{"char":"不","meaning":"not"},{"char":"足","meaning":"enough"},{"char":"道","meaning":"to speak of"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '微不足道' is used to describe something so small or insignificant that it is not worth mentioning. It is commonly used in both written and spoken Chinese to downplay the importance of something, often out of modesty or to emphasize the insignificance of a detail in the context of a larger discussion.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive","adverbial"],"structure":"coordinate","register":"widely used in both formal and informal contexts","connotation":"neutral","commonMistakes":"Learners might confuse '微不足道' with '无足轻重', which also means 'insignificant' but is often used in contexts where the lack of importance is more pronounced. '微不足道' is more about modesty or downplaying.","canStandAlone":false},"examples":[{"simplified":"他在公司里的贡献微不足道。","english":"His contributions to the company are insignificant.","traditional":"他在公司裡的貢獻微不足道。"},{"simplified":"这笔钱对我来说微不足道。","english":"This amount of money is negligible to me.","traditional":"這筆錢對我來說微不足道。"}],"synonyms":["无足轻重"],"antonyms":[],"confusedWith":[{"id":"无足轻重","note":"'无足轻重' emphasizes a lack of influence or importance, often in a broader context, while '微不足道' is more about modesty or downplaying."}],"traditional":"微不足道","pinyinOverride":null},{"id":"de-cai-jian-bei","simplified":"德才兼备","literalMeaning":"virtue and talent both possessed","figurativeMeaning":"to be both virtuous and talented","englishEquivalents":["a person of integrity and ability","a well-rounded individual"],"shortGloss":"virtuous and talented","characters":[{"char":"德","meaning":"virtue, moral character"},{"char":"才","meaning":"talent, ability"},{"char":"兼","meaning":"both, simultaneously"},{"char":"备","meaning":"possess, have"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '德才兼备' describes a person who possesses both moral integrity and professional competence. It is often used to commend individuals who are not only skilled in their field but also have a strong sense of ethics and responsibility.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["attributive","predicate"],"structure":"modifier-head","register":"commonly used in both formal and informal contexts to describe well-rounded individuals","connotation":"positive","commonMistakes":"Learners sometimes confuse '德才兼备' with idioms that emphasize only talent or only virtue. It is important to remember that this idiom specifically highlights the combination of both qualities.","canStandAlone":false},"examples":[{"simplified":"他是一个德才兼备的领导者。","english":"He is a leader who is both virtuous and talented.","traditional":"他是一個德才兼備的領導者。"},{"simplified":"公司需要德才兼备的人才来推动发展。","english":"The company needs individuals who are both virtuous and talented to drive development.","traditional":"公司需要德才兼備的人才來推動發展。"}],"synonyms":["才德兼备"],"antonyms":[],"confusedWith":[{"id":"才高八斗","note":"才高八斗 emphasizes exceptional talent but does not necessarily imply virtue."}],"traditional":"德才兼備","pinyinOverride":null},{"id":"xin-an-li-de","simplified":"心安理得","literalMeaning":"heart at peace, reason obtained","figurativeMeaning":"to feel at ease and justified; to have peace of mind knowing one is in the right","englishEquivalents":["to have a clear conscience","to sleep easy","to rest easy"],"shortGloss":"to feel at ease and justified","characters":[{"char":"心","meaning":"heart; mind"},{"char":"安","meaning":"peaceful; at ease"},{"char":"理","meaning":"reason; logic"},{"char":"得","meaning":"obtained; gained"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '心安理得' is thought to have originated from the idea that when one's actions are justified by reason and morality, the heart can be at peace. It reflects the concept that a clear conscience arises from knowing one's actions are right and justifiable.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"coordinate","register":"widely used in both spoken and written Chinese","connotation":"positive","commonMistakes":"Learners sometimes confuse this idiom with others that imply feeling justified but not necessarily at peace. It specifically conveys both justification and peace of mind.","canStandAlone":false},"examples":[{"simplified":"他做了正确的决定，所以心安理得。","english":"He made the right decision, so he feels at ease and justified.","traditional":"他做了正確的決定，所以心安理得。"},{"simplified":"只要你问心无愧，就可以心安理得地面对一切。","english":"As long as you have a clear conscience, you can face everything with peace of mind.","traditional":"只要你問心無愧，就可以心安理得地面對一切。"}],"synonyms":["问心无愧"],"antonyms":[],"confusedWith":[{"id":"理直气壮","note":"理直气壮 means to speak or act boldly with confidence, often without the peace of mind aspect."}],"traditional":"心安理得","pinyinOverride":null},{"id":"xin-ji-ru-fen","simplified":"心急如焚","literalMeaning":"heart anxious like burning","figurativeMeaning":"to be extremely anxious or worried","englishEquivalents":["anxious as a cat on a hot tin roof","worried sick"],"shortGloss":"extremely anxious","characters":[{"char":"心","meaning":"heart"},{"char":"急","meaning":"anxious"},{"char":"如","meaning":"like"},{"char":"焚","meaning":"burning"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '心急如焚' describes a state of extreme anxiety, as if one's heart is burning with worry. It is often used to depict situations where someone is deeply concerned about an outcome or the wellbeing of others.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"subject-predicate","register":"commonly used in both spoken and written Chinese","connotation":"negative","commonMistakes":"Learners sometimes confuse this idiom with '心如止水' (heart like still water), which means to be calm and unperturbed. The key difference is that '心急如焚' conveys a sense of urgency and anxiety, while '心如止水' suggests tranquility.","canStandAlone":false},"examples":[{"simplified":"听到孩子生病的消息，她心急如焚。","english":"Upon hearing the news of her child's illness, she was extremely anxious.","traditional":"聽到孩子生病的消息，她心急如焚。"},{"simplified":"考试成绩还没出来，他心急如焚。","english":"He was extremely anxious as the exam results had not yet been released.","traditional":"考試成績還沒出來，他心急如焚。"}],"synonyms":["焦急如焚"],"antonyms":["心如止水"],"confusedWith":[{"id":"心如止水","note":"心如止水 means to be calm and unperturbed, which is the opposite of the anxious state described by 心急如焚."}],"traditional":"心急如焚","pinyinOverride":null},{"id":"xin-xiang-shi-cheng","simplified":"心想事成","literalMeaning":"heart desires, things accomplish","figurativeMeaning":"wishes come true","englishEquivalents":["wishful thinking","dreams come true"],"shortGloss":"wishes come true","characters":[{"char":"心","meaning":"heart; mind"},{"char":"想","meaning":"think; desire"},{"char":"事","meaning":"things; matters"},{"char":"成","meaning":"accomplish; become true"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '心想事成' is commonly used to express the hope that one's wishes or desires will be fulfilled. It is often used in well-wishing contexts, such as during the New Year or other celebrations, to convey the sentiment that whatever one hopes for will come to pass.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","standalone-exclamation"],"structure":"subject-predicate","register":"commonly used in both formal and informal contexts, especially in well-wishing","connotation":"positive","commonMistakes":"Learners might confuse this idiom with those that imply effort or hard work is needed to achieve results, whereas '心想事成' focuses on the fulfillment of desires without explicit emphasis on effort.","canStandAlone":true},"examples":[{"simplified":"祝你新年快乐，心想事成！","english":"Wishing you a Happy New Year, may all your wishes come true!","traditional":"祝你新年快樂，心想事成！"},{"simplified":"她相信只要努力，心想事成。","english":"She believes that as long as she works hard, her wishes will come true.","traditional":"她相信只要努力，心想事成。"}],"synonyms":["如愿以偿"],"antonyms":[],"confusedWith":[{"id":"事半功倍","note":"心想事成 focuses on wishes coming true, while 事半功倍 emphasizes achieving more with less effort."}],"traditional":"心想事成","pinyinOverride":null},{"id":"xin-ling-shou-qiao","simplified":"心灵手巧","literalMeaning":"heart clever, hands skillful","figurativeMeaning":"ingenious and dexterous; skillful and clever","englishEquivalents":["handy","nimble-fingered","skilled"],"shortGloss":"ingenious and dexterous","characters":[{"char":"心","meaning":"heart; mind"},{"char":"灵","meaning":"clever; quick-witted"},{"char":"手","meaning":"hand"},{"char":"巧","meaning":"skillful; dexterous"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '心灵手巧' is used to describe someone who is both clever and skillful, particularly with their hands. It is often used to compliment someone who can create or fix things easily and creatively. The exact origin of this idiom is unclear, but it has been used in Chinese for a long time to praise artisans and craftsmen.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"coordinate","register":"commonly used in both spoken and written Chinese","connotation":"positive","commonMistakes":"Learners might confuse this idiom with others that involve skill or cleverness but lack the dual emphasis on both mental and manual dexterity. It should not be used to describe someone who is only clever or only skillful with their hands.","canStandAlone":false},"examples":[{"simplified":"她心灵手巧，能做出各种精美的手工艺品。","english":"She is ingenious and dexterous, able to create all kinds of exquisite handicrafts.","traditional":"她心靈手巧，能做出各種精美的手工藝品。"},{"simplified":"这个心灵手巧的工匠很快修好了破损的家具。","english":"The skillful and clever craftsman quickly repaired the damaged furniture.","traditional":"這個心靈手巧的工匠很快修好了破損的傢俱。"}],"synonyms":["巧夺天工","心灵手敏"],"antonyms":[],"confusedWith":[{"id":"手足无措","note":"手足无措 means to be at a loss, which is the opposite of being skillful and clever."}],"traditional":"心靈手巧","pinyinOverride":null},{"id":"xin-gan-qing-yuan","simplified":"心甘情愿","literalMeaning":"heart sweet, feelings willing","figurativeMeaning":"to be perfectly willing; to do something gladly and willingly","englishEquivalents":["willingly and gladly","of one's own free will"],"shortGloss":"willingly and gladly","characters":[{"char":"心","meaning":"heart; mind"},{"char":"甘","meaning":"sweet; willing"},{"char":"情","meaning":"feelings; emotions"},{"char":"愿","meaning":"willing; to wish"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '心甘情愿' is believed to have originated from the idea of doing something with a willing heart and without any reluctance. It reflects a state of mind where one is content and happy to undertake a task or make a sacrifice, often for the benefit of others or for a cause one believes in. The phrase emphasizes the absence of external pressure and highlights the genuine willingness of the individual.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"coordinate","register":"widely used in both spoken and written Chinese","connotation":"positive","commonMistakes":"Learners often confuse this idiom with expressions that imply reluctance or obligation. Unlike '勉为其难' (to do something reluctantly), '心甘情愿' emphasizes genuine willingness.","canStandAlone":false},"examples":[{"simplified":"为了孩子的未来，她心甘情愿地辞去了高薪工作。","english":"For the sake of her child's future, she willingly resigned from her high-paying job.","traditional":"為了孩子的未來，她心甘情願地辭去了高薪工作。"},{"simplified":"他心甘情愿地帮助朋友搬家，没有要求任何回报。","english":"He gladly helped his friend move house without asking for anything in return.","traditional":"他心甘情願地幫助朋友搬家，沒有要求任何回報。"}],"synonyms":["心悦诚服","甘心情愿"],"antonyms":["勉为其难"],"confusedWith":[{"id":"勉为其难","note":"心甘情愿 implies willingness, while 勉为其难 implies reluctance."}],"traditional":"心甘情願","pinyinOverride":null},{"id":"bi-bu-ke-shao","simplified":"必不可少","literalMeaning":"must not be lacking","figurativeMeaning":"absolutely necessary; indispensable","englishEquivalents":["indispensable","essential","can't do without"],"shortGloss":"absolutely necessary","characters":[{"char":"必","meaning":"must"},{"char":"不","meaning":"not"},{"char":"可","meaning":"can"},{"char":"少","meaning":"be lacking"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '必不可少' is used to describe something that is so essential that it cannot be done without. It emphasizes the importance and necessity of an element or factor in a particular context.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"modifier-head","register":"widely used in both formal and informal contexts","connotation":"positive","commonMistakes":"Learners might confuse '必不可少' with '可有可无', which means 'optional' or 'not essential'. It's important to remember that '必不可少' emphasizes necessity, while '可有可无' suggests something is not crucial.","canStandAlone":false},"examples":[{"simplified":"水是生命中必不可少的资源。","english":"Water is an indispensable resource for life.","traditional":"水是生命中必不可少的資源。"},{"simplified":"在这个项目中，团队合作是必不可少的。","english":"In this project, teamwork is essential.","traditional":"在這個項目中，團隊合作是必不可少的。"}],"synonyms":["不可或缺","不可缺少"],"antonyms":["可有可无"],"confusedWith":[{"id":"可有可无","note":"必不可少 means something is essential, while 可有可无 means something is optional or not necessary."}],"traditional":"必不可少","pinyinOverride":null},{"id":"nian-nian-bu-wang","simplified":"念念不忘","literalMeaning":"think think not forget","figurativeMeaning":"to keep something constantly in mind; to never forget","englishEquivalents":["never forget","always remember"],"shortGloss":"never forget","characters":[{"char":"念","meaning":"think"},{"char":"念","meaning":"think"},{"char":"不","meaning":"not"},{"char":"忘","meaning":"forget"}],"origin":{"period":"Ming dynasty (1368–1644)","sourceText":"《增广贤文》","sourceTextEnglish":"Expanded Writings of Worthy Words","originalExcerpt":"念念不忘，必有回响。","storyEnglish":"The idiom comes from the Ming dynasty text 'Expanded Writings of Worthy Words'. It suggests that if you keep something in mind persistently, it will eventually have an effect or response. The phrase emphasizes the power of memory and focus.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"modifier-head","register":"widely used in both formal and informal contexts","connotation":"neutral","commonMistakes":"Learners sometimes confuse this idiom with 忘乎所以, which means to forget oneself or lose self-control. 念念不忘 emphasizes persistent memory, while 忘乎所以 implies losing awareness.","canStandAlone":false},"examples":[{"simplified":"他对过去的事情念念不忘。","english":"He never forgets the events of the past.","traditional":"他對過去的事情念念不忘。"},{"simplified":"她念念不忘自己的梦想。","english":"She always remembers her dreams.","traditional":"她念念不忘自己的夢想。"}],"synonyms":["铭记在心"],"antonyms":["置之脑后"],"confusedWith":[{"id":"忘乎所以","note":"念念不忘 means to always remember, while 忘乎所以 means to lose oneself or forget one's surroundings."}],"traditional":"念念不忘","pinyinOverride":null},{"id":"hu-leng-hu-re","simplified":"忽冷忽热","literalMeaning":"suddenly cold, suddenly hot","figurativeMeaning":"to be inconsistent or unpredictable in attitude or behavior","englishEquivalents":["blow hot and cold","fickle","inconsistent"],"shortGloss":"inconsistent or unpredictable","characters":[{"char":"忽","meaning":"suddenly"},{"char":"冷","meaning":"cold"},{"char":"忽","meaning":"suddenly"},{"char":"热","meaning":"hot"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '忽冷忽热' describes someone whose behavior or attitude changes unpredictably, like the weather shifting suddenly from cold to hot. It is often used to describe people who are emotionally inconsistent or whose level of interest fluctuates rapidly.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"coordinate","register":"commonly used in both spoken and written Chinese","connotation":"negative","commonMistakes":"Learners often confuse '忽冷忽热' with weather-related expressions, but it is primarily used to describe inconsistency in behavior or attitude, not actual temperature changes.","canStandAlone":false},"examples":[{"simplified":"他对待工作的态度总是忽冷忽热，让人很难捉摸。","english":"His attitude towards work is always inconsistent, making him hard to figure out.","traditional":"他對待工作的態度總是忽冷忽熱，讓人很難捉摸。"},{"simplified":"她对我的态度忽冷忽热，我不知道她到底怎么想的。","english":"Her attitude towards me is unpredictable, and I don't know what she really thinks.","traditional":"她對我的態度忽冷忽熱，我不知道她到底怎麼想的。"}],"synonyms":["变化无常","反复无常"],"antonyms":["始终如一","一成不变"],"confusedWith":[{"id":"冷热交替","note":"冷热交替 refers to alternating hot and cold, often in a literal sense, such as weather or physical sensations, rather than describing a person's behavior."}],"traditional":"忽冷忽熱","pinyinOverride":null},{"id":"si-qian-xiang-hou","simplified":"思前想后","literalMeaning":"think before, consider after","figurativeMeaning":"to think over carefully; to consider all aspects","englishEquivalents":["think twice","weigh the pros and cons","consider all angles"],"shortGloss":"to think over carefully","characters":[{"char":"思","meaning":"think"},{"char":"前","meaning":"before"},{"char":"想","meaning":"consider"},{"char":"后","meaning":"after"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom 思前想后 is commonly used to describe the process of thoroughly considering a situation from all possible angles before making a decision. It emphasizes the importance of careful thought and deliberation, suggesting that one should not rush into decisions without considering the potential consequences.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["adverbial"],"structure":"coordinate","register":"widely used in both spoken and written Chinese","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with those that imply hesitation or indecisiveness. 思前想后 emphasizes careful consideration, not indecision.","canStandAlone":false},"examples":[{"simplified":"在做出这个重要决定之前，他思前想后了很久。","english":"Before making this important decision, he thought it over carefully for a long time.","traditional":"在做出這個重要決定之前，他思前想後了很久。"},{"simplified":"她总是思前想后，确保不会遗漏任何细节。","english":"She always considers all aspects to ensure no details are overlooked.","traditional":"她總是思前想後，確保不會遺漏任何細節。"}],"synonyms":["深思熟虑","三思而行"],"antonyms":["轻举妄动"],"confusedWith":[{"id":"犹豫不决","note":"犹豫不决 means to hesitate and be unable to make a decision, while 思前想后 means to carefully consider all aspects before deciding."}],"traditional":"思前想後","pinyinOverride":null},{"id":"yi-ran-zi-de","simplified":"怡然自得","literalMeaning":"pleasantly self-satisfied","figurativeMeaning":"to be content and at ease with oneself","englishEquivalents":["happy as a clam","content as a cucumber"],"shortGloss":"content and at ease","characters":[{"char":"怡","meaning":"pleasant; happy"},{"char":"然","meaning":"so; in such a manner"},{"char":"自","meaning":"self"},{"char":"得","meaning":"satisfied; content"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The phrase '怡然自得' is often used to describe a person who is at peace with themselves and their surroundings, feeling content and satisfied. It reflects a state of inner harmony and happiness, without external pressures or concerns.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"modifier-head","register":"commonly used in both written and spoken Chinese","connotation":"positive","commonMistakes":"Learners might confuse this idiom with '自得其乐', which also involves self-contentment but emphasizes finding joy in oneself. '怡然自得' focuses more on a state of ease and satisfaction.","canStandAlone":false},"examples":[{"simplified":"他坐在阳光下，怡然自得地看书。","english":"He sat in the sunlight, reading a book contentedly.","traditional":"他坐在陽光下，怡然自得地看書。"},{"simplified":"在乡村生活，他感到怡然自得。","english":"Living in the countryside, he felt content and at ease.","traditional":"在鄉村生活，他感到怡然自得。"}],"synonyms":["自得其乐"],"antonyms":["愁眉苦脸"],"confusedWith":[{"id":"自得其乐","note":"While both idioms involve self-contentment, '自得其乐' emphasizes finding joy in oneself, whereas '怡然自得' focuses on a state of ease and satisfaction."}],"traditional":"怡然自得","pinyinOverride":null},{"id":"ji-zhong-sheng-zhi","simplified":"急中生智","literalMeaning":"emergency gives birth to wisdom","figurativeMeaning":"to come up with a clever solution in a moment of crisis","englishEquivalents":["necessity is the mother of invention"],"shortGloss":"quick thinking in a crisis","characters":[{"char":"急","meaning":"urgent; in a hurry"},{"char":"中","meaning":"in; during"},{"char":"生","meaning":"give birth to; produce"},{"char":"智","meaning":"wisdom; cleverness"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '急中生智' describes the phenomenon where someone, when faced with an urgent situation, suddenly comes up with a clever idea or solution. It reflects the human ability to think quickly and adapt under pressure, often leading to ingenious outcomes.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"commonly used in both spoken and written Chinese","connotation":"positive","commonMistakes":"Learners sometimes confuse this idiom with similar expressions that involve wisdom or cleverness but lack the element of urgency. It's important to use it specifically in contexts where quick thinking in a crisis is involved.","canStandAlone":false},"examples":[{"simplified":"在比赛的最后一刻，他急中生智，想出了一个绝妙的得分方法。","english":"In the final moments of the game, he came up with a brilliant way to score.","traditional":"在比賽的最後一刻，他急中生智，想出了一個絕妙的得分方法。"},{"simplified":"她在面试时遇到难题，但急中生智，给出了一个令人满意的答案。","english":"She faced a tough question during the interview but quickly thought of a satisfactory answer.","traditional":"她在面試時遇到難題，但急中生智，給出了一個令人滿意的答案。"}],"synonyms":["灵机一动"],"antonyms":[],"confusedWith":[{"id":"灵机一动","note":"While both involve clever thinking, '灵机一动' does not necessarily imply an urgent situation."}],"traditional":"急中生智","pinyinOverride":null},{"id":"ji-yu-qiu-cheng","simplified":"急于求成","literalMeaning":"eager to seek success","figurativeMeaning":"to be impatient for quick results; to seek quick success without considering the necessary steps","englishEquivalents":["haste makes waste","Rome wasn't built in a day"],"shortGloss":"impatient for quick success","characters":[{"char":"急","meaning":"eager, anxious"},{"char":"于","meaning":"to, towards"},{"char":"求","meaning":"to seek"},{"char":"成","meaning":"success, completion"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom 急于求成 describes the mindset of someone who is overly eager to achieve success quickly, often without taking the necessary steps or considering the long-term consequences. This attitude can lead to mistakes and failures because the person is focused on immediate results rather than a sustainable process.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"modifier-head","register":"commonly used in both spoken and written Chinese, often in educational or business contexts","connotation":"negative","commonMistakes":"Learners often confuse 急于求成 with similar expressions that imply diligence or hard work, but 急于求成 specifically refers to impatience and a lack of thoroughness.","canStandAlone":false},"examples":[{"simplified":"在学习上，急于求成往往会导致事倍功半。","english":"In learning, being impatient for quick results often leads to doing twice the work for half the result.","traditional":"在學習上，急於求成往往會導致事倍功半。"},{"simplified":"他总是急于求成，结果反而浪费了更多时间。","english":"He is always impatient for quick success, which ends up wasting more time instead.","traditional":"他總是急於求成，結果反而浪費了更多時間。"}],"synonyms":["欲速则不达"],"antonyms":["循序渐进"],"confusedWith":[{"id":"事半功倍","note":"事半功倍 means achieving more with less effort, which is the opposite of the impatience implied by 急于求成."}],"traditional":"急於求成","pinyinOverride":null},{"id":"ji-gong-jin-li","simplified":"急功近利","literalMeaning":"eager for success, close to profit","figurativeMeaning":"seeking quick success and instant benefits","englishEquivalents":["short-sighted pursuit of quick gains","looking for instant gratification"],"shortGloss":"seeking quick success","characters":[{"char":"急","meaning":"eager"},{"char":"功","meaning":"achievement"},{"char":"近","meaning":"near"},{"char":"利","meaning":"profit"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom 急功近利 describes a mindset where one is overly focused on achieving quick results and immediate profits, often at the expense of long-term success. This attitude can lead to hasty decisions and a lack of thorough planning.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["attributive","adverbial"],"structure":"modifier-head","register":"commonly used in both written and spoken Chinese, often in a critical context","connotation":"negative","commonMistakes":"Learners often confuse 急功近利 with similar idioms that imply diligence or hard work. However, 急功近利 specifically criticizes the impatience for quick results rather than valuing consistent effort.","canStandAlone":false},"examples":[{"simplified":"他总是急功近利，结果常常事与愿违。","english":"He is always seeking quick success, and as a result, things often don't go as planned.","traditional":"他總是急功近利，結果常常事與願違。"},{"simplified":"急功近利的态度可能导致长期的失败。","english":"An attitude of seeking quick success and instant benefits can lead to long-term failure.","traditional":"急功近利的態度可能導致長期的失敗。"}],"synonyms":["急于求成"],"antonyms":["脚踏实地"],"confusedWith":[{"id":"急于求成","note":"急于求成 also implies impatience for results, but 急功近利 emphasizes the focus on immediate benefits or profits."}],"traditional":"急功近利","pinyinOverride":null},{"id":"zong-er-yan-zhi","simplified":"总而言之","literalMeaning":"in sum, speaking of it","figurativeMeaning":"in summary; to sum up","englishEquivalents":["in a nutshell","in short","to sum up"],"shortGloss":"in summary","characters":[{"char":"总","meaning":"to sum up"},{"char":"而","meaning":"and; but"},{"char":"言","meaning":"to speak"},{"char":"之","meaning":"it; this"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '总而言之' is commonly used in both spoken and written Chinese to indicate a summary or conclusion. It is often used to transition to a final statement or to encapsulate the main points of a discussion. The phrase itself is straightforward, combining the idea of summarizing ('总') with speaking ('言') about something ('之').","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["adverbial"],"structure":"modifier-head","register":"widely used in both formal and informal contexts","connotation":"neutral","commonMistakes":"Learners might mistakenly use this idiom as a standalone sentence, but it typically introduces a summary or conclusion within a larger statement.","canStandAlone":false},"examples":[{"simplified":"总而言之，我们需要更加努力。","english":"In summary, we need to work harder.","traditional":"總而言之，我們需要更加努力。"},{"simplified":"总而言之，这次会议取得了很大的成功。","english":"To sum up, the meeting was a great success.","traditional":"總而言之，這次會議取得了很大的成功。"}],"synonyms":["简而言之","概括来说"],"antonyms":[],"confusedWith":[],"traditional":"總而言之","pinyinOverride":null},{"id":"lian-lian-bu-she","simplified":"恋恋不舍","literalMeaning":"reluctant to part","figurativeMeaning":"unwilling to leave or part with something or someone","englishEquivalents":["hard to say goodbye","reluctant to leave"],"shortGloss":"unwilling to part","characters":[{"char":"恋","meaning":"to love; to be attached to"},{"char":"恋","meaning":"to love; to be attached to"},{"char":"不","meaning":"not"},{"char":"舍","meaning":"to give up; to part with"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '恋恋不舍' describes the feeling of being unwilling to leave or part with someone or something. It is often used to express a deep emotional attachment, such as when saying goodbye to a loved one or leaving a cherished place.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["adverbial","complement"],"structure":"modifier-head","register":"widely used in both spoken and written Chinese","connotation":"neutral","commonMistakes":"Learners sometimes confuse this idiom with '依依不舍', which has a similar meaning but emphasizes a more mutual or reciprocal feeling of reluctance to part.","canStandAlone":false},"examples":[{"simplified":"他对故乡恋恋不舍，离开时流下了眼泪。","english":"He was reluctant to leave his hometown and shed tears when he left.","traditional":"他對故鄉戀戀不捨，離開時流下了眼淚。"},{"simplified":"孩子们对游乐园恋恋不舍，不愿意回家。","english":"The children were unwilling to leave the amusement park and didn't want to go home.","traditional":"孩子們對遊樂園戀戀不捨，不願意回家。"}],"synonyms":["依依不舍"],"antonyms":[],"confusedWith":[{"id":"依依不舍","note":"Both idioms express reluctance to part, but '依依不舍' often implies a more mutual or emotional connection."}],"traditional":"戀戀不捨","pinyinOverride":null},{"id":"huang-ran-da-wu","simplified":"恍然大悟","literalMeaning":"suddenly realize greatly understand","figurativeMeaning":"to suddenly realize or understand something; to have a moment of enlightenment","englishEquivalents":["a light bulb moment","an epiphany"],"shortGloss":"sudden realization","characters":[{"char":"恍","meaning":"suddenly"},{"char":"然","meaning":"so; thus"},{"char":"大","meaning":"greatly"},{"char":"悟","meaning":"understand; realize"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '恍然大悟' describes the moment when someone suddenly comes to a clear understanding of something that was previously confusing or unclear. It captures the feeling of enlightenment or a sudden insight, akin to a 'light bulb moment' in English.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","complement"],"structure":"modifier-head","register":"widely used in both formal and informal contexts","connotation":"positive","commonMistakes":"Learners often confuse this idiom with similar expressions of realization but may misuse it by applying it to situations that don't involve a sudden insight. It specifically refers to a moment of clarity, not a gradual understanding.","canStandAlone":false},"examples":[{"simplified":"听了老师的解释，我恍然大悟。","english":"After hearing the teacher's explanation, I suddenly understood.","traditional":"聽了老師的解釋，我恍然大悟。"},{"simplified":"他看了说明书后，恍然大悟，原来是自己装错了。","english":"After reading the manual, he suddenly realized that he had assembled it incorrectly.","traditional":"他看了說明書後，恍然大悟，原來是自己裝錯了。"}],"synonyms":["茅塞顿开"],"antonyms":[],"confusedWith":[{"id":"豁然开朗","note":"Both idioms involve realization, but '豁然开朗' often implies a broader sense of clarity and relief, not just understanding."}],"traditional":"恍然大悟","pinyinOverride":null},{"id":"xi-xi-xiang-guan","simplified":"息息相关","literalMeaning":"breath breath mutually related","figurativeMeaning":"closely related; intimately connected","englishEquivalents":["closely linked","intimately connected"],"shortGloss":"closely related","characters":[{"char":"息","meaning":"breath"},{"char":"息","meaning":"breath"},{"char":"相","meaning":"mutually"},{"char":"关","meaning":"related"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '息息相关' is believed to have originated from the idea that two things are as closely connected as one's breath is to life. It emphasizes the inseparable and intimate connection between two entities or concepts.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"modifier-head","register":"widely used in both formal and informal contexts","connotation":"neutral","commonMistakes":"Learners might mistakenly think it only applies to physical connections, but it is often used for abstract relationships as well.","canStandAlone":false},"examples":[{"simplified":"环境保护与我们的生活息息相关。","english":"Environmental protection is closely related to our lives.","traditional":"環境保護與我們的生活息息相關。"},{"simplified":"这两个问题息息相关，不能单独解决。","english":"These two issues are closely linked and cannot be solved separately.","traditional":"這兩個問題息息相關，不能單獨解決。"}],"synonyms":["密不可分","紧密相连"],"antonyms":[],"confusedWith":[{"id":"息息相通","note":"While both idioms suggest a close connection, '息息相通' emphasizes mutual understanding or communication."}],"traditional":"息息相關","pinyinOverride":null},{"id":"qia-dao-hao-chu","simplified":"恰到好处","literalMeaning":"just to the good place","figurativeMeaning":"just right; perfectly appropriate","englishEquivalents":["hit the nail on the head","just right","perfectly fitting"],"shortGloss":"perfectly appropriate","characters":[{"char":"恰","meaning":"just, exactly"},{"char":"到","meaning":"to, reach"},{"char":"好","meaning":"good, suitable"},{"char":"处","meaning":"place, point"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '恰到好处' is used to describe a situation, action, or remark that is perfectly appropriate or fitting. It conveys the idea of something being done or said in just the right way, neither too much nor too little. This expression is often used to praise someone's ability to handle situations with precision and appropriateness.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"modifier-head","register":"commonly used in both spoken and written Chinese, suitable for formal and informal contexts","connotation":"positive","commonMistakes":"Learners might confuse this idiom with similar expressions that imply adequacy rather than perfection. '恰到好处' specifically emphasizes the precision and appropriateness of an action or remark.","canStandAlone":false},"examples":[{"simplified":"他的演讲恰到好处，观众都很满意。","english":"His speech was perfectly appropriate, and the audience was very satisfied.","traditional":"他的演講恰到好處，觀眾都很滿意。"},{"simplified":"这幅画的颜色搭配得恰到好处。","english":"The color combination in this painting is just right.","traditional":"這幅畫的顏色搭配得恰到好處。"}],"synonyms":["恰如其分"],"antonyms":["过犹不及"],"confusedWith":[{"id":"适可而止","note":"While both imply appropriateness, '适可而止' suggests knowing when to stop, whereas '恰到好处' emphasizes perfect fitting."}],"traditional":"恰到好處","pinyinOverride":null},{"id":"qia-ru-qi-fen","simplified":"恰如其分","literalMeaning":"just like its part","figurativeMeaning":"appropriate; fitting; just right","englishEquivalents":["just right","perfectly appropriate"],"shortGloss":"appropriate; fitting","characters":[{"char":"恰","meaning":"just right; exactly"},{"char":"如","meaning":"like; as if"},{"char":"其","meaning":"its; his; her"},{"char":"分","meaning":"part; share; portion"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '恰如其分' is used to describe something that is perfectly appropriate or fitting for the situation. It suggests that something is done or said in a way that is neither excessive nor insufficient, but just right.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["attributive","adverbial"],"structure":"modifier-head","register":"commonly used in both spoken and written Chinese","connotation":"positive","commonMistakes":"Learners might confuse '恰如其分' with '过犹不及', which means 'too much is as bad as too little'. While both involve balance, '恰如其分' emphasizes appropriateness, whereas '过犹不及' warns against extremes.","canStandAlone":false},"examples":[{"simplified":"他的发言恰如其分，大家都很赞同。","english":"His speech was perfectly appropriate, and everyone agreed.","traditional":"他的發言恰如其分，大家都很贊同。"},{"simplified":"她的建议总是恰如其分，令人信服。","english":"Her suggestions are always perfectly fitting and convincing.","traditional":"她的建議總是恰如其分，令人信服。"}],"synonyms":["适可而止"],"antonyms":["过犹不及"],"confusedWith":[{"id":"过犹不及","note":"过犹不及 means 'too much is as bad as too little', focusing on avoiding extremes, while 恰如其分 emphasizes being just right."}],"traditional":"恰如其分","pinyinOverride":null},{"id":"nao-xiu-cheng-nu","simplified":"恼羞成怒","literalMeaning":"angry and ashamed become furious","figurativeMeaning":"to become furious out of embarrassment","englishEquivalents":["fly into a rage out of humiliation","lose one's temper due to embarrassment"],"shortGloss":"fly into a rage from shame","characters":[{"char":"恼","meaning":"angry"},{"char":"羞","meaning":"ashamed"},{"char":"成","meaning":"become"},{"char":"怒","meaning":"furious"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom describes a situation where someone, feeling embarrassed or ashamed, reacts by becoming extremely angry. It captures the psychological transition from embarrassment to rage, often seen in situations where one's pride is hurt.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"cause-effect","register":"commonly used in both spoken and written Chinese","connotation":"negative","commonMistakes":"Learners often confuse this idiom with those that describe anger alone, but 恼羞成怒 specifically involves a transition from embarrassment to anger. It is not used for anger that arises from other emotions or situations.","canStandAlone":false},"examples":[{"simplified":"他在会议上被批评后恼羞成怒，离开了房间。","english":"He flew into a rage out of humiliation after being criticized in the meeting and left the room.","traditional":"他在會議上被批評後惱羞成怒，離開了房間。"},{"simplified":"她因为被揭穿谎言而恼羞成怒，开始大喊大叫。","english":"She became furious out of embarrassment when her lie was exposed and started yelling.","traditional":"她因為被揭穿謊言而惱羞成怒，開始大喊大叫。"}],"synonyms":["怒火中烧","暴跳如雷"],"antonyms":["心平气和"],"confusedWith":[{"id":"怒火中烧","note":"怒火中烧 describes being extremely angry, but does not imply the anger comes from embarrassment."}],"traditional":"惱羞成怒","pinyinOverride":null},{"id":"beihuan-lihe","simplified":"悲欢离合","literalMeaning":"sorrow, joy, parting, reunion","figurativeMeaning":"the vicissitudes of life; the emotional ups and downs and separations and reunions that people experience","englishEquivalents":["the joys and sorrows of life","the ups and downs of life"],"shortGloss":"the ups and downs of life","characters":[{"char":"悲","meaning":"sorrow"},{"char":"欢","meaning":"joy"},{"char":"离","meaning":"parting"},{"char":"合","meaning":"reunion"}],"origin":{"period":"Song Dynasty (960–1279)","sourceText":"《苏轼·水调歌头》","sourceTextEnglish":"Su Shi's 'Shui Diao Ge Tou'","originalExcerpt":"人有悲欢离合，月有阴晴圆缺，此事古难全。","storyEnglish":"The idiom comes from a famous poem by Su Shi, a renowned poet of the Song Dynasty. In the poem 'Shui Diao Ge Tou', Su Shi reflects on the inevitability of separation and reunion, and the joys and sorrows that accompany them, drawing a parallel with the phases of the moon. He expresses a philosophical acceptance of these changes as part of life.","historicalFigures":["Su Shi"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["subject","object"],"structure":"coordinate","register":"literary, but widely understood and used in both written and spoken Chinese","connotation":"neutral","commonMistakes":"Learners sometimes use this idiom to describe only negative emotions, but it encompasses both positive and negative experiences. It is also sometimes confused with idioms that only describe emotional states, rather than events.","canStandAlone":false},"examples":[{"simplified":"人生中总有悲欢离合，我们要学会坦然面对。","english":"In life, there are always ups and downs; we must learn to face them calmly.","traditional":"人生中總有悲歡離合，我們要學會坦然面對。"},{"simplified":"这部电影讲述了一个家庭的悲欢离合。","english":"This movie tells the story of a family's joys and sorrows.","traditional":"這部電影講述了一個家庭的悲歡離合。"}],"synonyms":[],"antonyms":[],"confusedWith":[],"traditional":"悲歡離合","pinyinOverride":null},{"id":"qing-bu-zi-jin","simplified":"情不自禁","literalMeaning":"feelings not self-restrain","figurativeMeaning":"unable to restrain one's emotions; overwhelmed by emotion","englishEquivalents":["can't help oneself","overcome with emotion"],"shortGloss":"unable to restrain emotions","characters":[{"char":"情","meaning":"emotions, feelings"},{"char":"不","meaning":"not"},{"char":"自","meaning":"self"},{"char":"禁","meaning":"restrain, control"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '情不自禁' is used to describe a situation where someone is so overwhelmed by their emotions that they cannot control their actions or words. It is commonly used in contexts where people express feelings such as joy, sadness, or excitement without restraint.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"modifier-head","register":"widely used in both spoken and written Chinese","connotation":"neutral","commonMistakes":"Learners often confuse this idiom with expressions that imply intentional actions. '情不自禁' specifically refers to involuntary emotional responses, not deliberate actions.","canStandAlone":false},"examples":[{"simplified":"听到这个好消息，她情不自禁地笑了。","english":"Upon hearing the good news, she couldn't help but smile.","traditional":"聽到這個好消息，她情不自禁地笑了。"},{"simplified":"他情不自禁地流下了眼泪。","english":"He couldn't hold back his tears.","traditional":"他情不自禁地流下了眼淚。"}],"synonyms":["不由自主"],"antonyms":[],"confusedWith":[{"id":"不由自主","note":"Both refer to involuntary actions, but '不由自主' emphasizes lack of control over one's actions, while '情不自禁' emphasizes emotional overwhelm."}],"traditional":"情不自禁","pinyinOverride":null},{"id":"jing-tian-dong-di","simplified":"惊天动地","literalMeaning":"astonish heaven and move earth","figurativeMeaning":"to be earth-shattering; to have a tremendous impact","englishEquivalents":["earth-shattering","world-shaking"],"shortGloss":"earth-shattering impact","characters":[{"char":"惊","meaning":"astonish"},{"char":"天","meaning":"heaven"},{"char":"动","meaning":"move"},{"char":"地","meaning":"earth"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '惊天动地' is often used to describe events or actions that have a significant and profound impact, as if they could astonish the heavens and move the earth. It is frequently applied to describe heroic deeds, major achievements, or significant changes.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"coordinate","register":"literary, but very widely understood and used in ordinary speech","connotation":"positive","commonMistakes":"Learners sometimes use this idiom to describe minor events, but it is reserved for truly significant or impactful occurrences. It should not be used lightly.","canStandAlone":false},"examples":[{"simplified":"他的成就真是惊天动地，让所有人都感到震惊。","english":"His achievements were truly earth-shattering, leaving everyone in awe.","traditional":"他的成就真是驚天動地，讓所有人都感到震驚。"},{"simplified":"这部电影的特效惊天动地，观众们都被震撼了。","english":"The special effects in this movie were earth-shattering, and the audience was amazed.","traditional":"這部電影的特效驚天動地，觀眾們都被震撼了。"}],"synonyms":["震撼人心","石破天惊"],"antonyms":[],"confusedWith":[{"id":"翻天覆地","note":"翻天覆地 also describes significant change or impact, but emphasizes complete transformation or upheaval."}],"traditional":"驚天動地","pinyinOverride":null},{"id":"jing-xin-dong-po","simplified":"惊心动魄","literalMeaning":"startle the heart, move the soul","figurativeMeaning":"extremely thrilling or shocking","englishEquivalents":["heart-stopping","breathtaking","spine-chilling"],"shortGloss":"extremely thrilling or shocking","characters":[{"char":"惊","meaning":"startle"},{"char":"心","meaning":"heart"},{"char":"动","meaning":"move"},{"char":"魄","meaning":"soul"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom 惊心动魄 is used to describe events or experiences that are extremely thrilling, shocking, or emotionally stirring. It is often used in the context of stories, movies, or situations that evoke strong emotional reactions, leaving a deep impression on the audience.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["attributive","adverbial"],"structure":"coordinate","register":"widely used in both formal and informal contexts","connotation":"neutral","commonMistakes":"Learners sometimes confuse 惊心动魄 with similar idioms that describe fear or surprise, but this idiom specifically emphasizes the intensity and emotional impact of an experience.","canStandAlone":false},"examples":[{"simplified":"那部电影的情节惊心动魄，让我久久不能平静。","english":"The plot of that movie was heart-stopping, leaving me unsettled for a long time.","traditional":"那部電影的情節驚心動魄，讓我久久不能平靜。"},{"simplified":"这场比赛的最后几分钟真是惊心动魄。","english":"The last few minutes of the match were truly breathtaking.","traditional":"這場比賽的最後幾分鐘真是驚心動魄。"}],"synonyms":["扣人心弦","惊魂未定"],"antonyms":[],"confusedWith":[{"id":"惊魂未定","note":"惊魂未定 emphasizes being in a state of shock or fear after a frightening experience, while 惊心动魄 highlights the thrilling or intense nature of an event."}],"traditional":"驚心動魄","pinyinOverride":null},{"id":"jing-huang-shi-cuo","simplified":"惊慌失措","literalMeaning":"panic and lose composure","figurativeMeaning":"to be thrown into panic and at a loss for what to do","englishEquivalents":["panic-stricken","at a loss","flustered"],"shortGloss":"panic and lose composure","characters":[{"char":"惊","meaning":"frightened"},{"char":"慌","meaning":"panic"},{"char":"失","meaning":"lose"},{"char":"措","meaning":"composure; measures"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '惊慌失措' describes a state of panic where someone is so frightened or surprised that they lose their ability to act or think clearly. It is commonly used to describe situations where people are overwhelmed by sudden events and do not know how to respond.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"coordinate","register":"commonly used in both written and spoken Chinese","connotation":"negative","commonMistakes":"Learners might confuse this idiom with others that involve panic or fear, but '惊慌失措' specifically emphasizes the loss of composure and inability to act. It should not be used to describe situations where someone is frightened but still in control.","canStandAlone":false},"examples":[{"simplified":"听到火警铃声，他惊慌失措，不知道该往哪里跑。","english":"Hearing the fire alarm, he was panic-stricken and didn't know where to run.","traditional":"聽到火警鈴聲，他驚慌失措，不知道該往哪裡跑。"},{"simplified":"面对突如其来的问题，她惊慌失措，无法做出决定。","english":"Faced with the sudden problem, she was flustered and unable to make a decision.","traditional":"面對突如其來的問題，她驚慌失措，無法做出決定。"}],"synonyms":["手足无措","六神无主"],"antonyms":["镇定自若","泰然自若"],"confusedWith":[{"id":"手足无措","note":"Both idioms describe a state of panic, but '手足无措' emphasizes being at a loss for what to do with one's hands and feet, while '惊慌失措' highlights the panic and loss of composure."}],"traditional":"驚慌失措","pinyinOverride":null},{"id":"xiang-fang-she-fa","simplified":"想方设法","literalMeaning":"think of ways and set up methods","figurativeMeaning":"to try every possible means; to do everything possible","englishEquivalents":["leave no stone unturned","pull out all the stops"],"shortGloss":"try every possible means","characters":[{"char":"想","meaning":"think"},{"char":"方","meaning":"ways"},{"char":"设","meaning":"set up"},{"char":"法","meaning":"methods"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom 想方设法 is used to describe the act of trying every possible way to achieve a goal. It is not directly traceable to a specific classical text but has been widely used in Chinese language to convey the idea of exhausting all possibilities to solve a problem or achieve an objective.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["adverbial","predicate"],"structure":"coordinate","register":"common in both spoken and written Chinese","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with others that imply a more negative or desperate connotation, but 想方设法 is neutral and simply emphasizes thoroughness and determination.","canStandAlone":false},"examples":[{"simplified":"为了完成这个项目，我们必须想方设法。","english":"To complete this project, we must try every possible means.","traditional":"為了完成這個項目，我們必須想方設法。"},{"simplified":"他想方设法地解决了这个难题。","english":"He tried every possible way to solve this difficult problem.","traditional":"他想方設法地解決了這個難題。"}],"synonyms":["千方百计"],"antonyms":[],"confusedWith":[{"id":"绞尽脑汁","note":"While both imply effort, 绞尽脑汁 emphasizes mental effort and brainstorming, whereas 想方设法 is broader, including all kinds of efforts."}],"traditional":"想方設法","pinyinOverride":null},{"id":"chou-mei-ku-lian","simplified":"愁眉苦脸","literalMeaning":"worried eyebrows, bitter face","figurativeMeaning":"to wear a worried or distressed expression","englishEquivalents":["to wear a long face","to look glum","to look worried"],"shortGloss":"to look worried or distressed","characters":[{"char":"愁","meaning":"worried"},{"char":"眉","meaning":"eyebrows"},{"char":"苦","meaning":"bitter"},{"char":"脸","meaning":"face"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '愁眉苦脸' is used to describe someone who appears worried or distressed, often with furrowed brows and a downturned mouth. It is a vivid depiction of a person's facial expression when they are troubled or unhappy.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"coordinate","register":"commonly used in both spoken and written Chinese","connotation":"negative","commonMistakes":"Learners often confuse this idiom with others that describe sadness or anger. It specifically refers to a worried or distressed expression, not just any negative emotion.","canStandAlone":false},"examples":[{"simplified":"他最近工作压力大，总是愁眉苦脸的。","english":"He's been under a lot of work pressure lately and always looks worried.","traditional":"他最近工作壓力大，總是愁眉苦臉的。"},{"simplified":"看到她愁眉苦脸的样子，我知道她遇到了麻烦。","english":"Seeing her worried expression, I knew she was in trouble.","traditional":"看到她愁眉苦臉的樣子，我知道她遇到了麻煩。"}],"synonyms":["忧心忡忡","愁云惨淡"],"antonyms":["喜笑颜开"],"confusedWith":[{"id":"愁云惨淡","note":"While both describe a negative emotional state, '愁云惨淡' refers more to a gloomy atmosphere rather than a specific facial expression."}],"traditional":"愁眉苦臉","pinyinOverride":null},{"id":"yu-yan-yu-lie","simplified":"愈演愈烈","literalMeaning":"the more it develops, the more intense it becomes","figurativeMeaning":"to become increasingly intense or severe","englishEquivalents":["spiraling out of control","getting worse and worse"],"shortGloss":"increasingly intense","characters":[{"char":"愈","meaning":"more, increasingly"},{"char":"演","meaning":"develop, evolve"},{"char":"愈","meaning":"more, increasingly"},{"char":"烈","meaning":"intense, severe"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '愈演愈烈' is used to describe situations that become more intense or severe as they progress. It is often used in contexts where a problem or conflict is escalating and becoming harder to control.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"modifier-head","register":"common in both written and spoken Chinese","connotation":"negative","commonMistakes":"Learners often confuse this idiom with others that describe improvement or positive progression, but '愈演愈烈' specifically refers to negative escalation.","canStandAlone":false},"examples":[{"simplified":"这场争论愈演愈烈，双方都不愿意让步。","english":"The argument is getting increasingly intense, and neither side is willing to compromise.","traditional":"這場爭論愈演愈烈，雙方都不願意讓步。"},{"simplified":"由于缺乏有效的管理，问题愈演愈烈。","english":"Due to a lack of effective management, the problem is becoming increasingly severe.","traditional":"由於缺乏有效的管理，問題愈演愈烈。"}],"synonyms":["每况愈下"],"antonyms":[],"confusedWith":[{"id":"愈来愈好","note":"This idiom means 'getting better and better', which is the opposite of '愈演愈烈'."}],"traditional":"愈演愈烈","pinyinOverride":null},{"id":"yi-xiang-bu-dao","simplified":"意想不到","literalMeaning":"thought imagine not arrive","figurativeMeaning":"unexpected; unforeseen","englishEquivalents":["out of the blue","unexpected","unforeseen"],"shortGloss":"unexpected; unforeseen","characters":[{"char":"意","meaning":"thought; idea"},{"char":"想","meaning":"imagine"},{"char":"不","meaning":"not"},{"char":"到","meaning":"arrive; reach"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '意想不到' is commonly used to describe events or outcomes that are completely unexpected or unforeseen. It is not tied to a specific historical story or text but has become a widely used expression in modern Chinese to convey surprise or unpredictability.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive","adverbial"],"structure":"modifier-head","register":"widely used in both spoken and written Chinese","connotation":"neutral","commonMistakes":"Learners might confuse '意想不到' with '意料之外' (beyond expectation), but '意想不到' emphasizes the element of surprise, while '意料之外' suggests something was not anticipated but might have been foreseeable.","canStandAlone":false},"examples":[{"simplified":"这次比赛的结果真是意想不到。","english":"The result of this competition was truly unexpected.","traditional":"這次比賽的結果真是意想不到。"},{"simplified":"他突然辞职，真是意想不到。","english":"His sudden resignation was completely unforeseen.","traditional":"他突然辭職，真是意想不到。"}],"synonyms":["出乎意料","意料之外"],"antonyms":[],"confusedWith":[{"id":"意料之外","note":"Both imply something unexpected, but '意料之外' suggests it was not anticipated, while '意想不到' emphasizes the surprise."}],"traditional":"意想不到","pinyinOverride":null},{"id":"cheng-jia-li-ye","simplified":"成家立业","literalMeaning":"establish a family and start a career","figurativeMeaning":"to settle down with a family and have a successful career","englishEquivalents":["settle down and start a family","establish oneself"],"shortGloss":"settle down with a family and career","characters":[{"char":"成","meaning":"establish"},{"char":"家","meaning":"family"},{"char":"立","meaning":"set up"},{"char":"业","meaning":"career"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '成家立业' reflects the traditional Chinese values of establishing a family and building a successful career. It emphasizes the importance of stability and responsibility in both personal and professional life. While the exact origin of the phrase is not tied to a specific classical text, it has been widely used in Chinese culture to describe the ideal progression of a person's life.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","object"],"structure":"coordinate","register":"common in both spoken and written Chinese","connotation":"positive","commonMistakes":"Learners sometimes confuse this idiom with phrases that only refer to career success or only to family life, but it specifically encompasses both aspects. It should not be used to describe situations where only one of these elements is present.","canStandAlone":false},"examples":[{"simplified":"他已经成家立业，生活很稳定。","english":"He has settled down with a family and a career, and his life is very stable.","traditional":"他已經成家立業，生活很穩定。"},{"simplified":"年轻人都希望能早日成家立业。","english":"Young people all hope to settle down and start a family and career soon.","traditional":"年輕人都希望能早日成家立業。"}],"synonyms":["安家立业"],"antonyms":[],"confusedWith":[{"id":"事业有成","note":"事业有成 focuses solely on career success, without the family aspect."}],"traditional":"成家立業","pinyinOverride":null},{"id":"cheng-qun-jie-dui","simplified":"成群结队","literalMeaning":"form groups and join teams","figurativeMeaning":"in groups; in large numbers","englishEquivalents":["in droves","in large groups","in swarms"],"shortGloss":"in groups or large numbers","characters":[{"char":"成","meaning":"form, become"},{"char":"群","meaning":"group, crowd"},{"char":"结","meaning":"tie, join"},{"char":"队","meaning":"team, group"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '成群结队' is used to describe people or animals moving together in groups or large numbers. It emphasizes the collective nature of the movement, suggesting a sense of unity or common purpose. The phrase is often used in contexts where large numbers of people or animals are seen together, such as tourists visiting a popular site or birds migrating.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["adverbial","attributive"],"structure":"coordinate","register":"commonly used in both written and spoken Chinese","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with ones that imply chaos or disorder, but '成群结队' specifically refers to organized or purposeful grouping. It is not used for random or chaotic gatherings.","canStandAlone":false},"examples":[{"simplified":"周末，游客们成群结队地来到公园。","english":"On the weekend, tourists came to the park in droves.","traditional":"週末，遊客們成群結隊地來到公園。"},{"simplified":"候鸟成群结队地飞往南方过冬。","english":"The migratory birds flew south in large groups for the winter.","traditional":"候鳥成群結隊地飛往南方過冬。"}],"synonyms":["三五成群"],"antonyms":[],"confusedWith":[{"id":"乌合之众","note":"While '成群结队' implies organized groups, '乌合之众' refers to a disorderly crowd."}],"traditional":"成群結隊","pinyinOverride":null},{"id":"huo-duo-huo-shao","simplified":"或多或少","literalMeaning":"or more or less","figurativeMeaning":"more or less; to some extent","englishEquivalents":["more or less","to some extent"],"shortGloss":"more or less","characters":[{"char":"或","meaning":"or; perhaps"},{"char":"多","meaning":"more"},{"char":"或","meaning":"or; perhaps"},{"char":"少","meaning":"less"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '或多或少' is commonly used in modern Chinese to express the idea of something being approximate or not exact. It conveys the sense that something is not entirely one way or another, but somewhere in between. The phrase is often used in everyday conversation to indicate that a situation or quantity is not precise but falls within a certain range.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["adverbial"],"structure":"coordinate","register":"widely used in both spoken and written Chinese","connotation":"neutral","commonMistakes":"Learners might confuse '或多或少' with expressions that imply exactness. It is important to remember that this idiom suggests approximation rather than precision.","canStandAlone":false},"examples":[{"simplified":"他或多或少了解一些情况。","english":"He more or less understands the situation.","traditional":"他或多或少了解一些情況。"},{"simplified":"这个计划或多或少会有一些变化。","english":"This plan will have some changes, more or less.","traditional":"這個計劃或多或少會有一些變化。"}],"synonyms":["差不多"],"antonyms":[],"confusedWith":[{"id":"大致","note":"While both imply approximation, '大致' often refers to a rough outline or general idea, whereas '或多或少' emphasizes a range or degree."}],"traditional":"或多或少","pinyinOverride":null},{"id":"jieran-butong","simplified":"截然不同","literalMeaning":"completely different","figurativeMeaning":"entirely different; poles apart","englishEquivalents":["worlds apart","like night and day"],"shortGloss":"completely different","characters":[{"char":"截","meaning":"cut off; completely"},{"char":"然","meaning":"like; as if"},{"char":"不","meaning":"not"},{"char":"同","meaning":"same; alike"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '截然不同' is used to describe two things that are entirely different from each other. It emphasizes a stark contrast, often used in contexts where the differences are clear and unmistakable. The phrase itself does not have a specific story or historical anecdote associated with its origin.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"modifier-head","register":"commonly used in both written and spoken Chinese","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with phrases that imply minor differences. However, '截然不同' is used to describe stark, unmistakable differences. It's important not to use it for subtle or nuanced distinctions.","canStandAlone":false},"examples":[{"simplified":"这两种文化截然不同，很难比较。","english":"These two cultures are completely different, making them hard to compare.","traditional":"這兩種文化截然不同，很難比較。"},{"simplified":"他的观点与我的截然不同。","english":"His viewpoint is entirely different from mine.","traditional":"他的觀點與我的截然不同。"}],"synonyms":["天壤之别"],"antonyms":["如出一辙"],"confusedWith":[{"id":"大相径庭","note":"While both idioms describe differences, '大相径庭' often implies a significant difference but not necessarily a complete or absolute one."}],"traditional":"截然不同","pinyinOverride":null},{"id":"suo-zuo-suo-wei","simplified":"所作所为","literalMeaning":"what is done and what is acted","figurativeMeaning":"one's actions and behavior","englishEquivalents":["actions and deeds","conduct","behavior"],"shortGloss":"actions and behavior","characters":[{"char":"所","meaning":"what"},{"char":"作","meaning":"do"},{"char":"所","meaning":"what"},{"char":"为","meaning":"act"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '所作所为' is used to describe the entirety of someone's actions and behavior. It emphasizes the deeds and conduct of a person, often in the context of evaluating their character or intentions.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["subject","object","attributive"],"structure":"coordinate","register":"neutral, commonly used in both written and spoken Chinese","connotation":"neutral","commonMistakes":"Learners might confuse '所作所为' with '行为' (behavior) or '举动' (action), which are more general and do not emphasize the entirety of one's actions as strongly.","canStandAlone":false},"examples":[{"simplified":"他的所作所为让人非常失望。","english":"His actions and behavior were very disappointing.","traditional":"他的所作所為讓人非常失望。"},{"simplified":"我们应该对自己的所作所为负责。","english":"We should be responsible for our own actions and behavior.","traditional":"我們應該對自己的所作所為負責。"}],"synonyms":["行为举止"],"antonyms":[],"confusedWith":[{"id":"行为","note":"'行为' refers more generally to behavior, without the emphasis on the entirety of actions."}],"traditional":"所作所為","pinyinOverride":null},{"id":"pu-mian-er-lai","simplified":"扑面而来","literalMeaning":"hit the face and come","figurativeMeaning":"to come directly at someone; to be confronted with something suddenly","englishEquivalents":["hit you in the face","come at you head-on"],"shortGloss":"come directly at someone","characters":[{"char":"扑","meaning":"to pounce; to rush at"},{"char":"面","meaning":"face"},{"char":"而","meaning":"and; but"},{"char":"来","meaning":"to come"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '扑面而来' is often used to describe situations where something comes at you suddenly and directly, much like a gust of wind or a strong smell. It conveys the sense of being confronted with something unexpected or overwhelming.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"widely used in both spoken and written Chinese","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with expressions that imply a more gradual or indirect approach. '扑面而来' specifically conveys immediacy and directness.","canStandAlone":false},"examples":[{"simplified":"一股清新的空气扑面而来，让人精神一振。","english":"A breath of fresh air hit me in the face, invigorating my spirit.","traditional":"一股清新的空氣撲面而來，讓人精神一振。"},{"simplified":"走进花园，花香扑面而来。","english":"As I walked into the garden, the fragrance of flowers came at me head-on.","traditional":"走進花園，花香撲面而來。"}],"synonyms":[],"antonyms":[],"confusedWith":[],"traditional":"撲面而來","pinyinOverride":null},{"id":"kou-ren-xin-xian","simplified":"扣人心弦","literalMeaning":"touch a person's heartstrings","figurativeMeaning":"to be emotionally moving or gripping","englishEquivalents":["pull at one's heartstrings","emotionally gripping"],"shortGloss":"emotionally moving","characters":[{"char":"扣","meaning":"to touch or strike"},{"char":"人","meaning":"person's"},{"char":"心","meaning":"heart"},{"char":"弦","meaning":"strings (as of a musical instrument)"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '扣人心弦' is often used to describe something that is deeply moving or emotionally engaging, much like a piece of music that resonates with the listener's emotions. The imagery of 'touching the heartstrings' suggests a direct connection to one's emotional core, similar to how a musician might pluck the strings of an instrument to produce a beautiful sound.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"modifier-head","register":"widely used in both written and spoken Chinese","connotation":"positive","commonMistakes":"Learners might confuse this idiom with others that involve emotional impact but lack the nuance of being specifically 'moving' or 'gripping'. It is not used for mild or neutral emotional effects.","canStandAlone":false},"examples":[{"simplified":"这部电影的情节非常扣人心弦。","english":"The plot of this movie is very emotionally gripping.","traditional":"這部電影的情節非常扣人心絃。"},{"simplified":"他的演讲扣人心弦，让观众感动不已。","english":"His speech was emotionally moving, leaving the audience deeply touched.","traditional":"他的演講扣人心絃，讓觀眾感動不已。"}],"synonyms":["感人肺腑"],"antonyms":[],"confusedWith":[{"id":"感人肺腑","note":"Both idioms describe something emotionally moving, but 扣人心弦 emphasizes the gripping aspect, while 感人肺腑 focuses on deep emotional impact."}],"traditional":"扣人心絃","pinyinOverride":null},{"id":"yi-yang-dun-cuo","simplified":"抑扬顿挫","literalMeaning":"restrain, raise, pause, fall","figurativeMeaning":"to modulate one's voice; to speak with varied intonation and rhythm","englishEquivalents":["rise and fall of the voice","intonation","cadence"],"shortGloss":"modulate voice with intonation","characters":[{"char":"抑","meaning":"restrain; lower"},{"char":"扬","meaning":"raise; elevate"},{"char":"顿","meaning":"pause; stop"},{"char":"挫","meaning":"fall; setback"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '抑扬顿挫' describes the modulation of one's voice in speech or music, emphasizing the importance of varying pitch and rhythm to convey emotion and meaning effectively. It is often used to describe eloquent speakers or skilled musicians who can captivate their audience through their dynamic delivery.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["adverbial","attributive"],"structure":"coordinate","register":"commonly used in both literary and spoken contexts to describe speech or music","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with those describing emotional states rather than vocal modulation. It specifically refers to the variation in tone and rhythm, not the content or emotion of the speech.","canStandAlone":false},"examples":[{"simplified":"他的演讲抑扬顿挫，吸引了所有听众。","english":"His speech was full of intonation and rhythm, captivating all the listeners.","traditional":"他的演講抑揚頓挫，吸引了所有聽眾。"},{"simplified":"这位歌手的表演抑扬顿挫，令人陶醉。","english":"The singer's performance was full of modulation and rhythm, enchanting the audience.","traditional":"這位歌手的表演抑揚頓挫，令人陶醉。"}],"synonyms":[],"antonyms":[],"confusedWith":[],"traditional":"抑揚頓挫","pinyinOverride":null},{"id":"chi-zhi-yi-heng","simplified":"持之以恒","literalMeaning":"persist with it constantly","figurativeMeaning":"to persevere; to persist in doing something consistently over time","englishEquivalents":["persevere","keep at it","stick to it"],"shortGloss":"persevere consistently","characters":[{"char":"持","meaning":"to hold; to persist"},{"char":"之","meaning":"it; this"},{"char":"以","meaning":"with"},{"char":"恒","meaning":"constant; persistent"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '持之以恒' emphasizes the importance of persistence and consistency in achieving goals. It suggests that success comes from maintaining a steady effort over time, rather than from sporadic bursts of activity. The phrase is often used to encourage people to keep working towards their objectives, even when progress seems slow.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"commonly used in both formal and informal contexts to encourage perseverance","connotation":"positive","commonMistakes":"Learners might confuse this idiom with others that suggest persistence but lack the element of consistency over time. It is important to note that '持之以恒' emphasizes ongoing, steady effort.","canStandAlone":false},"examples":[{"simplified":"学习一门语言需要持之以恒。","english":"Learning a language requires perseverance.","traditional":"學習一門語言需要持之以恆。"},{"simplified":"他持之以恒地锻炼，终于达到了理想的体重。","english":"He exercised consistently and finally reached his ideal weight.","traditional":"他持之以恆地鍛鍊，終於達到了理想的體重。"}],"synonyms":["锲而不舍","坚持不懈"],"antonyms":["半途而废"],"confusedWith":[{"id":"锲而不舍","note":"Both mean persistence, but '持之以恒' emphasizes consistent effort over time, while '锲而不舍' focuses on not giving up."}],"traditional":"持之以恆","pinyinOverride":null},{"id":"zhi-shou-hua-jiao","simplified":"指手画脚","literalMeaning":"point with hands and draw with feet","figurativeMeaning":"to criticize or give orders indiscriminately; to gesticulate and criticize","englishEquivalents":["to boss around","to wag one's finger","to play armchair critic"],"shortGloss":"to criticize indiscriminately","characters":[{"char":"指","meaning":"point"},{"char":"手","meaning":"hand"},{"char":"画","meaning":"draw"},{"char":"脚","meaning":"foot"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '指手画脚' describes someone who is overly critical or likes to give orders without much thought. The imagery of pointing with hands and drawing with feet suggests someone who is making exaggerated gestures, often associated with giving unsolicited advice or criticism.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"coordinate","register":"commonly used in both spoken and written Chinese, informal contexts","connotation":"negative","commonMistakes":"Learners often confuse this idiom with expressions that mean to give constructive criticism. However, '指手画脚' implies a negative, unwelcome interference.","canStandAlone":false},"examples":[{"simplified":"他总是喜欢对别人的工作指手画脚。","english":"He always likes to criticize others' work indiscriminately.","traditional":"他總是喜歡對別人的工作指手畫腳。"},{"simplified":"在会议上，他不停地指手画脚，让大家很不满。","english":"During the meeting, he kept criticizing and giving orders, which made everyone very dissatisfied.","traditional":"在會議上，他不停地指手畫腳，讓大家很不滿。"}],"synonyms":["评头论足","指指点点"],"antonyms":[],"confusedWith":[{"id":"评头论足","note":"While both involve criticism, '评头论足' focuses more on nitpicking details, whereas '指手画脚' implies broader, often unwelcome interference."}],"traditional":"指手畫腳","pinyinOverride":null},{"id":"ai-jia-ai-hu","simplified":"挨家挨户","literalMeaning":"visit every house and every household","figurativeMeaning":"to go from house to house; to visit every household","englishEquivalents":["door-to-door","house-to-house"],"shortGloss":"go from house to house","characters":[{"char":"挨","meaning":"to approach; to go to"},{"char":"家","meaning":"house; family"},{"char":"挨","meaning":"to approach; to go to"},{"char":"户","meaning":"household; door"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '挨家挨户' describes the action of visiting each house or household in a particular area. It is often used to describe activities such as conducting surveys, delivering goods, or spreading information by going door-to-door.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["adverbial"],"structure":"ABAC","register":"commonly used in both spoken and written Chinese","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with similar expressions that imply visiting places rather than households. It specifically refers to visiting individual homes or families, not just locations.","canStandAlone":false},"examples":[{"simplified":"志愿者挨家挨户地分发传单。","english":"The volunteers distributed flyers door-to-door.","traditional":"志願者挨家挨戶地分發傳單。"},{"simplified":"他挨家挨户地推销他的产品。","english":"He went from house to house selling his products.","traditional":"他挨家挨戶地推銷他的產品。"}],"synonyms":["逐家逐户"],"antonyms":[],"confusedWith":[{"id":"走街串巷","note":"走街串巷 refers to wandering through streets and alleys, not specifically visiting households."}],"traditional":"挨家挨戶","pinyinOverride":null},{"id":"sun-ren-li-ji","simplified":"损人利己","literalMeaning":"harm others to benefit oneself","figurativeMeaning":"to harm others for one's own gain; to be selfish and unscrupulous","englishEquivalents":["dog-eat-dog","every man for himself"],"shortGloss":"selfish gain at others' expense","characters":[{"char":"损","meaning":"harm"},{"char":"人","meaning":"others"},{"char":"利","meaning":"benefit"},{"char":"己","meaning":"oneself"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '损人利己' describes a behavior where an individual causes harm to others in order to gain personal benefits. It reflects a selfish and unscrupulous attitude, often criticized in moral teachings. The phrase is commonly used to describe actions that are self-serving at the expense of others' well-being.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"verb-object","register":"common in both spoken and written Chinese, often used in a critical context","connotation":"negative","commonMistakes":"Learners often confuse this idiom with neutral or positive expressions about self-benefit, but it specifically implies unethical behavior. It should not be used to describe situations where mutual benefit is achieved.","canStandAlone":false},"examples":[{"simplified":"他总是损人利己，大家都不喜欢他。","english":"He always harms others for his own gain, so nobody likes him.","traditional":"他總是損人利己，大家都不喜歡他。"},{"simplified":"这种损人利己的行为最终会受到惩罚。","english":"Such selfish and harmful behavior will eventually be punished.","traditional":"這種損人利己的行為最終會受到懲罰。"}],"synonyms":["自私自利","损公肥私"],"antonyms":["舍己为人","助人为乐"],"confusedWith":[{"id":"自私自利","note":"While both imply selfishness, '自私自利' focuses more on self-interest without necessarily harming others."}],"traditional":"損人利己","pinyinOverride":null},{"id":"jie-er-lian-san","simplified":"接二连三","literalMeaning":"connect two, link three","figurativeMeaning":"one after another; in quick succession","englishEquivalents":["one after another","in quick succession","back-to-back"],"shortGloss":"in quick succession","characters":[{"char":"接","meaning":"connect"},{"char":"二","meaning":"two"},{"char":"连","meaning":"link"},{"char":"三","meaning":"three"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '接二连三' is believed to have originated from the idea of events or things occurring continuously, one after another, like connecting the numbers two and three in a sequence. It is used to describe situations where things happen in rapid succession without interruption.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["adverbial"],"structure":"modifier-head","register":"widely used in both spoken and written Chinese","connotation":"neutral","commonMistakes":"Learners often confuse '接二连三' with '接踵而至', which also means events happening one after another but often implies a more overwhelming or burdensome sense. '接二连三' is neutral and doesn't carry this connotation.","canStandAlone":false},"examples":[{"simplified":"最近几天，问题接二连三地出现。","english":"In recent days, problems have been occurring one after another.","traditional":"最近幾天，問題接二連三地出現。"},{"simplified":"他接二连三地打电话来催促我们。","english":"He kept calling one after another to urge us.","traditional":"他接二連三地打電話來催促我們。"}],"synonyms":["络绎不绝"],"antonyms":[],"confusedWith":[{"id":"接踵而至","note":"While both idioms describe successive occurrences, '接踵而至' often implies a more overwhelming or burdensome series of events."}],"traditional":"接二連三","pinyinOverride":null},{"id":"cuo-shou-bu-ji","simplified":"措手不及","literalMeaning":"arrange hands not reach","figurativeMeaning":"caught unprepared or off guard","englishEquivalents":["caught off guard","taken by surprise"],"shortGloss":"caught unprepared","characters":[{"char":"措","meaning":"arrange, manage"},{"char":"手","meaning":"hand"},{"char":"不","meaning":"not"},{"char":"及","meaning":"reach, in time"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '措手不及' describes a situation where someone is caught unprepared or off guard. It conveys the idea of being unable to react in time because the event happens too suddenly. The phrase is often used to describe unexpected situations that leave people scrambling to respond.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"commonly used in both spoken and written Chinese","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with similar expressions that imply a lack of preparation, but '措手不及' specifically emphasizes the suddenness of the situation. It is not used for situations where someone is simply unprepared due to negligence.","canStandAlone":false},"examples":[{"simplified":"地震来得太突然，让很多人措手不及。","english":"The earthquake struck so suddenly that it caught many people off guard.","traditional":"地震來得太突然，讓很多人措手不及。"},{"simplified":"他的提问让我措手不及，不知道该怎么回答。","english":"His question caught me off guard, and I didn't know how to answer.","traditional":"他的提問讓我措手不及，不知道該怎麼回答。"}],"synonyms":["猝不及防"],"antonyms":[],"confusedWith":[{"id":"猝不及防","note":"Both idioms describe being caught off guard, but '猝不及防' emphasizes the inability to defend or guard against something sudden."}],"traditional":"措手不及","pinyinOverride":null},{"id":"ti-xin-diao-dan","simplified":"提心吊胆","literalMeaning":"lift heart hang gallbladder","figurativeMeaning":"to be very anxious or nervous","englishEquivalents":["on pins and needles","with one's heart in one's mouth"],"shortGloss":"anxious and nervous","characters":[{"char":"提","meaning":"lift"},{"char":"心","meaning":"heart"},{"char":"吊","meaning":"hang"},{"char":"胆","meaning":"gallbladder"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '提心吊胆' describes a state of extreme anxiety or nervousness, as if one's heart and gallbladder are being physically lifted and suspended. This vivid imagery conveys the feeling of being on edge, often due to fear or worry about something uncertain or dangerous.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["adverbial","complement"],"structure":"coordinate","register":"commonly used in both spoken and written Chinese","connotation":"negative","commonMistakes":"Learners might confuse it with idioms that simply mean 'worried' without the implication of fear or anxiety. It's important to use this idiom in contexts where there is a sense of nervous anticipation or fear.","canStandAlone":false},"examples":[{"simplified":"考试成绩还没出来，我一直提心吊胆。","english":"The exam results haven't come out yet, and I've been on pins and needles.","traditional":"考試成績還沒出來，我一直提心吊膽。"},{"simplified":"听说他出车祸了，我们都提心吊胆地等消息。","english":"We heard he was in a car accident, and we were all anxiously waiting for news.","traditional":"聽說他出車禍了，我們都提心吊膽地等消息。"}],"synonyms":["忐忑不安","心惊胆战"],"antonyms":["心安理得"],"confusedWith":[{"id":"心惊胆战","note":"Both express fear, but '心惊胆战' emphasizes being frightened, while '提心吊胆' emphasizes nervousness and anxiety."}],"traditional":"提心吊膽","pinyinOverride":null},{"id":"ya-miao-zhu-zhang","simplified":"揠苗助长","literalMeaning":"pull seedlings to help them grow","figurativeMeaning":"to spoil things through excessive enthusiasm or by trying to rush progress","englishEquivalents":["Haste makes waste","Don't rush things","Too much zeal spoils everything"],"shortGloss":"ruin by rushing","characters":[{"char":"揠","meaning":"to pull up"},{"char":"苗","meaning":"seedlings"},{"char":"助","meaning":"to help"},{"char":"长","meaning":"to grow"}],"origin":{"period":"Warring States period (475–221 BCE)","sourceText":"《孟子·公孙丑上》","sourceTextEnglish":"Mencius, Gongsun Chou I","originalExcerpt":"宋人有闵其苗之不长而揠之者，芒芒然归，谓其人曰：‘今日病矣！予助苗长矣。’","storyEnglish":"In the state of Song during the Warring States period, there was a farmer who was anxious about his seedlings not growing fast enough. In his impatience, he went to the field and pulled them up a little to help them grow. Exhausted, he returned home and told his family, 'I am worn out today; I have been helping the seedlings to grow.' His son ran to the field and found that the seedlings had all withered. This story illustrates the folly of trying to speed up natural processes through forceful intervention.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"literary, but widely understood and used in ordinary speech","connotation":"negative","commonMistakes":"Learners often use this idiom to describe any kind of help, but it specifically refers to harmful interference due to impatience or overzealousness. It is not used for positive or neutral assistance.","canStandAlone":false},"examples":[{"simplified":"他对孩子的学习太着急，结果揠苗助长，适得其反。","english":"He was too anxious about his child's studies, and as a result, he ended up spoiling things by trying to rush progress.","traditional":"他對孩子的學習太著急，結果揠苗助長，適得其反。"},{"simplified":"在项目管理中，过于急功近利可能会揠苗助长，导致失败。","english":"In project management, being overly eager for quick success can lead to spoiling things by rushing, resulting in failure.","traditional":"在項目管理中，過於急功近利可能會揠苗助長，導致失敗。"}],"synonyms":["欲速则不达"],"antonyms":["循序渐进"],"confusedWith":[{"id":"欲速则不达","note":"Both idioms caution against haste, but 揠苗助长 emphasizes harmful interference, while 欲速则不达 focuses on the futility of rushing."}],"traditional":"揠苗助長","pinyinOverride":null},{"id":"yao-yao-yu-zhui","simplified":"摇摇欲坠","literalMeaning":"shaking and about to fall","figurativeMeaning":"on the verge of collapse; in a precarious situation","englishEquivalents":["on the brink of collapse","teetering on the edge","hanging by a thread"],"shortGloss":"on the verge of collapse","characters":[{"char":"摇","meaning":"shake; sway"},{"char":"摇","meaning":"shake; sway"},{"char":"欲","meaning":"about to; desire"},{"char":"坠","meaning":"fall; drop"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '摇摇欲坠' is often used to describe a situation or structure that is unstable and on the verge of collapse. It evokes the image of something that is swaying and about to fall, indicating imminent failure or disaster. The origin of this idiom is not tied to a specific classical text, but it has been used in Chinese literature to describe precarious situations.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"modifier-head","register":"commonly used in both written and spoken Chinese to describe unstable situations","connotation":"negative","commonMistakes":"Learners might confuse this idiom with others that describe instability, but '摇摇欲坠' specifically implies imminent collapse, not just general instability.","canStandAlone":false},"examples":[{"simplified":"那座老房子已经摇摇欲坠，随时可能倒塌。","english":"That old house is on the verge of collapse and could fall at any moment.","traditional":"那座老房子已經搖搖欲墜，隨時可能倒塌。"},{"simplified":"公司的财务状况摇摇欲坠，需要立即采取措施。","english":"The company's financial situation is on the brink of collapse and immediate action is needed.","traditional":"公司的財務狀況搖搖欲墜，需要立即採取措施。"}],"synonyms":["岌岌可危"],"antonyms":["稳如泰山"],"confusedWith":[{"id":"岌岌可危","note":"Both describe precarious situations, but '岌岌可危' emphasizes danger rather than imminent collapse."}],"traditional":"搖搖欲墜","pinyinOverride":null},{"id":"gai-xie-gui-zheng","simplified":"改邪归正","literalMeaning":"change evil return to right","figurativeMeaning":"to give up evil ways and return to the right path; to reform and become a better person","englishEquivalents":["turn over a new leaf","mend one's ways"],"shortGloss":"reform and return to the right path","characters":[{"char":"改","meaning":"change"},{"char":"邪","meaning":"evil"},{"char":"归","meaning":"return"},{"char":"正","meaning":"right; correct"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '改邪归正' is used to describe someone who has decided to abandon their previous wrongdoings or immoral behavior and has chosen to follow a more virtuous and righteous path. It emphasizes the idea of personal reform and moral improvement.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"widely used in both formal and informal contexts","connotation":"positive","commonMistakes":"Learners might confuse this idiom with similar phrases that imply temporary change rather than a genuine reformation. It's important to note that '改邪归正' implies a sincere and lasting change.","canStandAlone":false},"examples":[{"simplified":"他决定改邪归正，重新开始新生活。","english":"He decided to turn over a new leaf and start a new life.","traditional":"他決定改邪歸正，重新開始新生活。"},{"simplified":"经过一番反思，她终于改邪归正，不再做违法的事情。","english":"After some reflection, she finally mended her ways and stopped doing illegal things.","traditional":"經過一番反思，她終於改邪歸正，不再做違法的事情。"}],"synonyms":["弃暗投明"],"antonyms":["冥顽不灵"],"confusedWith":[{"id":"弃暗投明","note":"Both imply a change from bad to good, but '弃暗投明' often emphasizes a change in allegiance or ideology."}],"traditional":"改邪歸正","pinyinOverride":null},{"id":"jiu-si-fu-shang","simplified":"救死扶伤","literalMeaning":"save the dying and help the injured","figurativeMeaning":"to provide aid and relief to those in distress, especially in medical contexts","englishEquivalents":["come to the rescue","provide aid and comfort"],"shortGloss":"provide aid to the distressed","characters":[{"char":"救","meaning":"save"},{"char":"死","meaning":"dying"},{"char":"扶","meaning":"help"},{"char":"伤","meaning":"injured"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '救死扶伤' is commonly used to describe the noble actions of those who provide medical care and assistance to people in critical conditions or who are injured. It emphasizes the humanitarian spirit of helping those in need, particularly in life-threatening situations.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"verb-object + verb-object","register":"commonly used in both formal and informal contexts, especially in medical or humanitarian discussions","connotation":"positive","commonMistakes":"Learners might confuse this idiom with others that involve helping or saving, but '救死扶伤' specifically refers to medical aid and assistance to those in dire need.","canStandAlone":false},"examples":[{"simplified":"医生的职责就是救死扶伤。","english":"The duty of a doctor is to save the dying and help the injured.","traditional":"醫生的職責就是救死扶傷。"},{"simplified":"在地震灾区，许多志愿者都在努力救死扶伤。","english":"In the earthquake-stricken area, many volunteers are working hard to provide aid to the distressed.","traditional":"在地震災區，許多志願者都在努力救死扶傷。"}],"synonyms":["扶危济困"],"antonyms":[],"confusedWith":[],"traditional":"救死扶傷","pinyinOverride":null},{"id":"jing-er-yuan-zhi","simplified":"敬而远之","literalMeaning":"respect but keep at a distance","figurativeMeaning":"to maintain a respectful distance from someone or something; to avoid close involvement while showing respect","englishEquivalents":["keep at arm's length","respect but avoid"],"shortGloss":"respect but keep distance","characters":[{"char":"敬","meaning":"respect"},{"char":"而","meaning":"but"},{"char":"远","meaning":"distance"},{"char":"之","meaning":"it; him/her"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '敬而远之' suggests a strategy of maintaining a respectful distance from someone or something that may be troublesome or problematic. It implies showing respect outwardly while avoiding deep involvement or entanglement. This approach can be used in various contexts, such as dealing with difficult people or situations where one wants to avoid conflict or complications.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"modifier-head","register":"commonly used in both formal and informal contexts","connotation":"neutral","commonMistakes":"Learners often confuse this idiom with similar expressions that imply avoidance without respect. The key aspect of this idiom is the element of respect, which distinguishes it from purely negative or dismissive idioms.","canStandAlone":false},"examples":[{"simplified":"对待那些喜欢挑拨是非的人，我们应该敬而远之。","english":"We should keep a respectful distance from those who like to stir up trouble.","traditional":"對待那些喜歡挑撥是非的人，我們應該敬而遠之。"},{"simplified":"他对公司的政治斗争选择敬而远之。","english":"He chose to keep a respectful distance from the company's political struggles.","traditional":"他對公司的政治鬥爭選擇敬而遠之。"}],"synonyms":[],"antonyms":[],"confusedWith":[{"id":"避而不见","note":"避而不见 implies avoiding meeting someone altogether, without the element of respect."}],"traditional":"敬而遠之","pinyinOverride":null},{"id":"shu-yi-shu-er","simplified":"数一数二","literalMeaning":"count one, count two","figurativeMeaning":"to be one of the best; to be among the top","englishEquivalents":["second to none","top-notch"],"shortGloss":"one of the best","characters":[{"char":"数","meaning":"count"},{"char":"一","meaning":"one"},{"char":"数","meaning":"count"},{"char":"二","meaning":"two"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '数一数二' is used to describe someone or something that is among the best in a particular field or category. The phrase literally means 'count one, count two,' suggesting that the person or thing is always counted among the top ranks. The origin of this idiom is not tied to a specific classical text, but it has been widely used in Chinese to denote excellence.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"coordinate","register":"commonly used in both spoken and written Chinese","connotation":"positive","commonMistakes":"Learners might mistakenly use this idiom to mean 'average' due to its literal meaning involving numbers. However, it actually signifies being among the best.","canStandAlone":false},"examples":[{"simplified":"他的数学成绩在班里数一数二。","english":"His math grades are among the best in the class.","traditional":"他的數學成績在班裡數一數二。"},{"simplified":"这家餐厅的菜在这座城市里数一数二。","english":"The food at this restaurant is among the best in the city.","traditional":"這家餐廳的菜在這座城市裡數一數二。"}],"synonyms":["名列前茅"],"antonyms":["默默无闻"],"confusedWith":[{"id":"三心二意","note":"While '数一数二' means being among the best, '三心二意' means being indecisive or having a divided mind."}],"traditional":"數一數二","pinyinOverride":null},{"id":"zhan-ding-jie-tie","simplified":"斩钉截铁","literalMeaning":"cut nails and sever iron","figurativeMeaning":"to speak or act decisively and resolutely","englishEquivalents":["speak with finality","put one's foot down"],"shortGloss":"speak or act decisively","characters":[{"char":"斩","meaning":"cut"},{"char":"钉","meaning":"nails"},{"char":"截","meaning":"sever"},{"char":"铁","meaning":"iron"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '斩钉截铁' is believed to have originated from a metaphorical expression describing the decisiveness and strength required to cut nails and sever iron. It conveys the idea of being firm and unwavering in one's decisions or actions, much like the force needed to cut through tough materials.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"coordinate","register":"literary, but very widely understood and used in ordinary speech","connotation":"positive","commonMistakes":"Learners might confuse this idiom with expressions that imply aggression rather than decisiveness. It is important to note that this idiom emphasizes firmness and clarity rather than hostility.","canStandAlone":false},"examples":[{"simplified":"他斩钉截铁地表示不会改变决定。","english":"He stated emphatically that he would not change his decision.","traditional":"他斬釘截鐵地表示不會改變決定。"},{"simplified":"她斩钉截铁地拒绝了所有的邀请。","english":"She firmly rejected all the invitations.","traditional":"她斬釘截鐵地拒絕了所有的邀請。"}],"synonyms":["坚决果断","一言九鼎"],"antonyms":["优柔寡断"],"confusedWith":[{"id":"铁石心肠","note":"While '铁石心肠' refers to being cold-hearted or unfeeling, '斩钉截铁' emphasizes decisiveness without emotional connotations."}],"traditional":"斬釘截鐵","pinyinOverride":null},{"id":"duan-duan-xu-xu","simplified":"断断续续","literalMeaning":"intermittent and continuous","figurativeMeaning":"intermittently; off and on; sporadically","englishEquivalents":["off and on","intermittently","sporadically"],"shortGloss":"intermittently","characters":[{"char":"断","meaning":"intermittent; broken"},{"char":"断","meaning":"intermittent; broken"},{"char":"续","meaning":"continuous; to continue"},{"char":"续","meaning":"continuous; to continue"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '断断续续' is used to describe something that happens intermittently or sporadically. It is often used to describe events, actions, or processes that are not continuous but occur in fits and starts.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["adverbial"],"structure":"AABB","register":"commonly used in both spoken and written Chinese","connotation":"neutral","commonMistakes":"Learners might confuse '断断续续' with '连续不断', which means 'continuous and unbroken'. '断断续续' implies interruptions, while '连续不断' emphasizes continuity.","canStandAlone":false},"examples":[{"simplified":"他断断续续地讲述了他的旅行经历。","english":"He recounted his travel experiences intermittently.","traditional":"他斷斷續續地講述了他的旅行經歷。"},{"simplified":"这场雨断断续续地下了一整天。","english":"The rain fell off and on throughout the day.","traditional":"這場雨斷斷續續地下了一整天。"}],"synonyms":[],"antonyms":["连续不断"],"confusedWith":[{"id":"连续不断","note":"连续不断 means continuous and unbroken, without interruptions."}],"traditional":"斷斷續續","pinyinOverride":null},{"id":"duan-zhang-qu-yi","simplified":"断章取义","literalMeaning":"cut a section and take the meaning","figurativeMeaning":"to quote out of context; to take a passage out of context and misinterpret its meaning","englishEquivalents":["quote out of context","take out of context"],"shortGloss":"quote out of context","characters":[{"char":"断","meaning":"cut"},{"char":"章","meaning":"section"},{"char":"取","meaning":"take"},{"char":"义","meaning":"meaning"}],"origin":{"period":"Eastern Han Dynasty (25–220 CE)","sourceText":"《文心雕龙·辨骚》","sourceTextEnglish":"The Literary Mind and the Carving of Dragons, Chapter: Discerning the Sao","originalExcerpt":"断章取义，不知其全。","storyEnglish":"The idiom originates from the work 'The Literary Mind and the Carving of Dragons' by Liu Xie, a literary critic of the Eastern Han Dynasty. In the text, Liu Xie discusses the importance of understanding a text in its entirety rather than taking a part of it and interpreting it in isolation. The phrase '断章取义' is used to criticize those who extract a passage from its context and derive a meaning that was not intended by the original author.","historicalFigures":["Liu Xie"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["object","adverbial"],"structure":"verb-object","register":"commonly used in both formal and informal contexts","connotation":"negative","commonMistakes":"Learners often use this idiom without realizing it implies a negative judgment about the speaker's understanding or honesty. It's not just about quoting, but about misrepresenting the original meaning.","canStandAlone":false},"examples":[{"simplified":"他总是断章取义，误导别人。","english":"He always quotes out of context, misleading others.","traditional":"他總是斷章取義，誤導別人。"},{"simplified":"在讨论中，我们应该避免断章取义。","english":"In discussions, we should avoid quoting out of context.","traditional":"在討論中，我們應該避免斷章取義。"}],"synonyms":["以偏概全"],"antonyms":[],"confusedWith":[{"id":"以偏概全","note":"以偏概全 means to generalize based on incomplete information, which is similar but not identical to quoting out of context."}],"traditional":"斷章取義","pinyinOverride":null},{"id":"xin-chen-dai-xie","simplified":"新陈代谢","literalMeaning":"new replace old metabolism","figurativeMeaning":"the process of renewal and replacement; the cycle of new replacing old","englishEquivalents":["out with the old, in with the new"],"shortGloss":"renewal and replacement process","characters":[{"char":"新","meaning":"new"},{"char":"陈","meaning":"old"},{"char":"代","meaning":"replace"},{"char":"谢","meaning":"metabolism; decline"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '新陈代谢' originally refers to the biological process of metabolism, where old cells are replaced by new ones. Over time, it has come to symbolize the broader concept of renewal and replacement in various contexts, such as societal changes or the natural cycle of life.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["subject","predicate","object","attributive"],"structure":"modifier-head","register":"commonly used in both formal and informal contexts, especially in discussions about change and renewal","connotation":"neutral","commonMistakes":"Learners sometimes confuse this idiom with phrases specifically about biological processes, but it is more broadly applicable to any context of renewal or replacement.","canStandAlone":false},"examples":[{"simplified":"社会的发展需要新陈代谢，不断创新。","english":"The development of society requires renewal and innovation.","traditional":"社會的發展需要新陳代謝，不斷創新。"},{"simplified":"公司的新陈代谢是保持竞争力的关键。","english":"The renewal process within the company is key to maintaining competitiveness.","traditional":"公司的新陳代謝是保持競爭力的關鍵。"}],"synonyms":[],"antonyms":[],"confusedWith":[],"traditional":"新陳代謝","pinyinOverride":null},{"id":"wu-jia-zhi-bao","simplified":"无价之宝","literalMeaning":"priceless treasure","figurativeMeaning":"an invaluable asset or treasure; something extremely precious","englishEquivalents":["priceless gem","invaluable treasure"],"shortGloss":"invaluable treasure","characters":[{"char":"无","meaning":"no; without"},{"char":"价","meaning":"price"},{"char":"之","meaning":"of"},{"char":"宝","meaning":"treasure"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '无价之宝' is used to describe something so valuable that it cannot be assigned a price. It often refers to objects, people, or qualities that are considered invaluable due to their rarity, significance, or emotional value. The origin of this idiom is not tied to a specific classical text, but it has been widely used in Chinese literature and conversation to emphasize the immeasurable worth of something.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["subject","object","attributive"],"structure":"modifier-head","register":"widely used in both formal and informal contexts","connotation":"positive","commonMistakes":"Learners might confuse this idiom with similar expressions that denote high monetary value, but '无价之宝' emphasizes emotional or intrinsic worth rather than financial value.","canStandAlone":false},"examples":[{"simplified":"这幅画是无价之宝，不能用金钱来衡量。","english":"This painting is a priceless treasure and cannot be measured by money.","traditional":"這幅畫是無價之寶，不能用金錢來衡量。"},{"simplified":"友谊是无价之宝，我们应该珍惜。","english":"Friendship is an invaluable treasure that we should cherish.","traditional":"友誼是無價之寶，我們應該珍惜。"}],"synonyms":["稀世珍宝","价值连城"],"antonyms":[],"confusedWith":[{"id":"价值连城","note":"While both idioms imply high value, '价值连城' specifically refers to something worth a fortune, often in monetary terms, whereas '无价之宝' emphasizes intrinsic or emotional value."}],"traditional":"無價之寶","pinyinOverride":null},{"id":"wu-guan-jin-yao","simplified":"无关紧要","literalMeaning":"no relation tight important","figurativeMeaning":"of no importance; irrelevant","englishEquivalents":["of no consequence","irrelevant","not important"],"shortGloss":"irrelevant; unimportant","characters":[{"char":"无","meaning":"no; without"},{"char":"关","meaning":"relation; connection"},{"char":"紧","meaning":"tight; urgent"},{"char":"要","meaning":"important"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '无关紧要' is commonly used in modern Chinese to describe something that is not important or relevant to the matter at hand. It emphasizes the lack of significance or impact of a particular issue or detail.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial","complement"],"structure":"modifier-head","register":"commonly used in both spoken and written Chinese","connotation":"neutral","commonMistakes":"Learners might confuse '无关紧要' with '无足轻重', which also means insignificant but often implies a lack of influence or weight, rather than relevance.","canStandAlone":false},"examples":[{"simplified":"这件事对我们来说无关紧要。","english":"This matter is irrelevant to us.","traditional":"這件事對我們來說無關緊要。"},{"simplified":"他提出的问题无关紧要，我们不必理会。","english":"The question he raised is irrelevant, we don't need to pay attention to it.","traditional":"他提出的問題無關緊要，我們不必理會。"}],"synonyms":["无足轻重"],"antonyms":["举足轻重"],"confusedWith":[{"id":"无足轻重","note":"Both idioms mean insignificant, but '无足轻重' often refers to lack of influence or weight, while '无关紧要' emphasizes irrelevance."}],"traditional":"無關緊要","pinyinOverride":null},{"id":"wu-dong-yu-zhong","simplified":"无动于衷","literalMeaning":"no movement at heart","figurativeMeaning":"indifferent; unmoved; showing no reaction","englishEquivalents":["unmoved","indifferent","unfazed"],"shortGloss":"indifferent, unmoved","characters":[{"char":"无","meaning":"no; without"},{"char":"动","meaning":"move"},{"char":"于","meaning":"at; in"},{"char":"衷","meaning":"heart; feelings"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '无动于衷' describes a situation where someone remains indifferent or unaffected by events or emotions that would typically provoke a reaction. The phrase suggests a lack of emotional response, as if one's heart does not move or stir despite external stimuli.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial","complement"],"structure":"modifier-head","register":"widely used in both formal and informal contexts","connotation":"negative","commonMistakes":"Learners often confuse this idiom with expressions that imply calmness or composure, but '无动于衷' specifically conveys indifference or lack of concern, which can carry a negative connotation.","canStandAlone":false},"examples":[{"simplified":"面对别人的批评，他总是无动于衷。","english":"He always remains indifferent in the face of criticism from others.","traditional":"面對別人的批評，他總是無動於衷。"},{"simplified":"即使看到如此感人的场面，他也无动于衷。","english":"Even when witnessing such a touching scene, he was unmoved.","traditional":"即使看到如此感人的場面，他也無動於衷。"}],"synonyms":["漠不关心","冷漠无情"],"antonyms":["感同身受","热泪盈眶"],"confusedWith":[{"id":"泰然自若","note":"While '泰然自若' implies calmness and composure, '无动于衷' suggests indifference or lack of concern."}],"traditional":"無動於衷","pinyinOverride":null},{"id":"wu-ke-hou-fei","simplified":"无可厚非","literalMeaning":"nothing to strongly criticize","figurativeMeaning":"there is little room for criticism; not much to blame","englishEquivalents":["nothing to write home about","not much to complain about"],"shortGloss":"not much to criticize","characters":[{"char":"无","meaning":"not; without"},{"char":"可","meaning":"can; able to"},{"char":"厚","meaning":"thick; strong"},{"char":"非","meaning":"criticize; blame"}],"origin":{"period":"Qing Dynasty (1644–1912)","sourceText":"《清史稿》","sourceTextEnglish":"Draft History of Qing","originalExcerpt":"其言虽不尽是，然无可厚非。","storyEnglish":"The idiom comes from a passage in the 'Draft History of Qing', where it is used to describe a situation where a statement or action, while not entirely correct, does not warrant strong criticism. It suggests a level of understanding or tolerance for minor faults.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"modifier-head","register":"commonly used in both written and spoken Chinese, suitable for formal and informal contexts","connotation":"neutral","commonMistakes":"Learners often confuse this idiom with expressions that imply complete approval or praise. It is important to note that it means there is not much to criticize, not that something is perfect.","canStandAlone":false},"examples":[{"simplified":"他的工作虽然有些小错误，但总体来说无可厚非。","english":"Although there are some minor errors in his work, overall there is not much to criticize.","traditional":"他的工作雖然有些小錯誤，但總體來說無可厚非。"},{"simplified":"这篇文章的观点无可厚非，值得一读。","english":"The viewpoints in this article are not much to criticize and are worth reading.","traditional":"這篇文章的觀點無可厚非，值得一讀。"}],"synonyms":["无伤大雅"],"antonyms":["不可救药"],"confusedWith":[{"id":"无可奈何","note":"无可奈何 means 'helpless' or 'no alternative', which is different from the idea of having little to criticize."}],"traditional":"無可厚非","pinyinOverride":null},{"id":"wu-ke-nai-he","simplified":"无可奈何","literalMeaning":"nothing can be done","figurativeMeaning":"to feel helpless or have no choice in a situation","englishEquivalents":["between a rock and a hard place","at one's wits' end"],"shortGloss":"helpless, no choice","characters":[{"char":"无","meaning":"no, not"},{"char":"可","meaning":"can, able to"},{"char":"奈","meaning":"to deal with, to cope"},{"char":"何","meaning":"what, how"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '无可奈何' describes a situation where someone feels utterly helpless and unable to change the circumstances they are in. It conveys a sense of resignation and acceptance that nothing can be done to alter the situation.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial","complement"],"structure":"modifier-head","register":"widely used in both spoken and written Chinese","connotation":"negative","commonMistakes":"Learners often confuse this idiom with expressions that imply a lack of effort, but '无可奈何' specifically conveys helplessness despite effort. It is not used to describe laziness or unwillingness.","canStandAlone":false},"examples":[{"simplified":"面对这样的情况，我感到无可奈何。","english":"Faced with such a situation, I feel helpless.","traditional":"面對這樣的情況，我感到無可奈何。"},{"simplified":"他无可奈何地接受了这个结果。","english":"He resignedly accepted the outcome.","traditional":"他無可奈何地接受了這個結果。"}],"synonyms":["束手无策","无能为力"],"antonyms":["游刃有余"],"confusedWith":[{"id":"无能为力","note":"Both express helplessness, but '无能为力' emphasizes inability to act, while '无可奈何' emphasizes resignation."}],"traditional":"無可奈何","pinyinOverride":null},{"id":"wu-jia-ke-gui","simplified":"无家可归","literalMeaning":"no home to return to","figurativeMeaning":"homeless; having no place to call home","englishEquivalents":["homeless","without a roof over one's head"],"shortGloss":"homeless","characters":[{"char":"无","meaning":"without"},{"char":"家","meaning":"home"},{"char":"可","meaning":"can; able to"},{"char":"归","meaning":"return to"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '无家可归' describes the state of being homeless, without a place to return to or call one's own. It is often used to describe individuals who have lost their homes due to various circumstances, such as natural disasters, war, or economic hardship.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"modifier-head","register":"common in both spoken and written Chinese","connotation":"negative","commonMistakes":"Learners sometimes confuse '无家可归' with '流浪' (wandering), but '无家可归' specifically emphasizes the lack of a home, while '流浪' focuses on the act of wandering without a fixed destination.","canStandAlone":false},"examples":[{"simplified":"他失去了工作和房子，现在无家可归。","english":"He lost his job and house, and is now homeless.","traditional":"他失去了工作和房子，現在無家可歸。"},{"simplified":"许多无家可归的人在冬天面临严峻的挑战。","english":"Many homeless people face severe challenges in the winter.","traditional":"許多無家可歸的人在冬天面臨嚴峻的挑戰。"}],"synonyms":["流离失所"],"antonyms":["安居乐业"],"confusedWith":[{"id":"流浪","note":"流浪 refers to wandering without a fixed destination, not necessarily being homeless."}],"traditional":"無家可歸","pinyinOverride":null},{"id":"wu-wei-bu-zhi","simplified":"无微不至","literalMeaning":"no detail too small to attend to","figurativeMeaning":"meticulous attention to detail; caring for someone in every possible way","englishEquivalents":["leave no stone unturned","attend to every detail"],"shortGloss":"meticulous care and attention","characters":[{"char":"无","meaning":"no; not"},{"char":"微","meaning":"minute; tiny"},{"char":"不","meaning":"not"},{"char":"至","meaning":"reach; attend to"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '无微不至' is used to describe someone who is extremely attentive and considerate, taking care of every tiny detail. It is often used to praise caregivers, hosts, or anyone who shows great care and meticulous attention to the needs of others.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"modifier-head","register":"widely used in both formal and informal contexts to praise someone's attentiveness and care","connotation":"positive","commonMistakes":"Learners might confuse this idiom with others that imply attention to detail but lack the connotation of care and consideration for others. It specifically emphasizes thoughtful and considerate attention.","canStandAlone":false},"examples":[{"simplified":"她对病人的照顾无微不至，令人感动。","english":"Her meticulous care for the patients is touching.","traditional":"她對病人的照顧無微不至，令人感動。"},{"simplified":"在他的无微不至的关心下，老人恢复得很快。","english":"Under his meticulous care, the elderly person recovered quickly.","traditional":"在他的無微不至的關心下，老人恢復得很快。"}],"synonyms":["体贴入微"],"antonyms":["漠不关心"],"confusedWith":[{"id":"事无巨细","note":"While both idioms imply attention to detail, '事无巨细' focuses on handling all matters regardless of size, without the connotation of personal care."}],"traditional":"無微不至","pinyinOverride":null},{"id":"wu-you-wu-lv","simplified":"无忧无虑","literalMeaning":"without worries, without concerns","figurativeMeaning":"carefree and without worries","englishEquivalents":["without a care in the world","carefree","footloose and fancy-free"],"shortGloss":"carefree and without worries","characters":[{"char":"无","meaning":"without"},{"char":"忧","meaning":"worries"},{"char":"无","meaning":"without"},{"char":"虑","meaning":"concerns"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '无忧无虑' describes a state of being free from worries and concerns. It is often used to describe a carefree lifestyle or the innocence of childhood, where one is not burdened by the stresses of adult life. The phrase emphasizes a life of simplicity and happiness, untroubled by the complexities and anxieties that often accompany responsibility.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"coordinate","register":"commonly used in both spoken and written Chinese, suitable for describing a carefree state","connotation":"positive","commonMistakes":"Learners might confuse this idiom with others that describe happiness or contentment, but '无忧无虑' specifically emphasizes the absence of worries and concerns, not just general happiness.","canStandAlone":false},"examples":[{"simplified":"他的童年是无忧无虑的。","english":"His childhood was carefree and without worries.","traditional":"他的童年是無憂無慮的。"},{"simplified":"退休后，他们过上了无忧无虑的生活。","english":"After retirement, they lived a carefree life.","traditional":"退休後，他們過上了無憂無慮的生活。"}],"synonyms":["逍遥自在","自由自在"],"antonyms":["忧心忡忡","愁眉苦脸"],"confusedWith":[{"id":"心满意足","note":"无忧无虑 emphasizes lack of worries, while 心满意足 focuses on contentment and satisfaction."}],"traditional":"無憂無慮","pinyinOverride":null},{"id":"wu-suo-shi-shi","simplified":"无所事事","literalMeaning":"nothing to do","figurativeMeaning":"to be idle or have nothing to do","englishEquivalents":["twiddle one's thumbs","have time on one's hands"],"shortGloss":"idle, nothing to do","characters":[{"char":"无","meaning":"without"},{"char":"所","meaning":"place or thing"},{"char":"事","meaning":"affair, matter"},{"char":"事","meaning":"affair, matter"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '无所事事' is used to describe a state of having nothing to do, often implying idleness or lack of purpose. It is commonly used in modern Chinese to describe someone who is not engaged in any meaningful activity.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"modifier-head","register":"commonly used in both spoken and written Chinese","connotation":"neutral","commonMistakes":"Learners often confuse this idiom with expressions that imply laziness or unwillingness to work, but it simply describes a state of idleness without judgment.","canStandAlone":false},"examples":[{"simplified":"他最近无所事事，总是在家看电视。","english":"He's been idle lately, just staying at home watching TV.","traditional":"他最近無所事事，總是在家看電視。"},{"simplified":"假期里，我无所事事，只能在家休息。","english":"During the holidays, I had nothing to do and could only rest at home.","traditional":"假期裡，我無所事事，只能在家休息。"}],"synonyms":["闲来无事","无所作为"],"antonyms":["忙忙碌碌"],"confusedWith":[{"id":"无所作为","note":"无所作为 implies a lack of achievement or action, often with a negative connotation, whereas 无所事事 is neutral and describes idleness."}],"traditional":"無所事事","pinyinOverride":null},{"id":"wu-suo-zuo-wei","simplified":"无所作为","literalMeaning":"nothing to accomplish","figurativeMeaning":"to be inactive or unproductive; to make no attempt to improve or change","englishEquivalents":["sit on one's hands","do nothing","idle away"],"shortGloss":"inactive or unproductive","characters":[{"char":"无","meaning":"without"},{"char":"所","meaning":"place; here it implies 'anything'"},{"char":"作","meaning":"to do"},{"char":"为","meaning":"action; achievement"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '无所作为' is used to describe a state of inactivity or lack of effort to change or improve a situation. It emphasizes a passive attitude where no actions are taken to achieve goals or make progress.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"modifier-head","register":"commonly used in both written and spoken Chinese, suitable for formal and informal contexts","connotation":"negative","commonMistakes":"Learners may confuse '无所作为' with '无为而治', which refers to a Daoist concept of governance through non-action. '无所作为' is negative, implying laziness or lack of initiative, while '无为而治' is about achieving harmony through minimal intervention.","canStandAlone":false},"examples":[{"simplified":"他整天无所作为，浪费了很多时间。","english":"He idles away all day, wasting a lot of time.","traditional":"他整天無所作為，浪費了很多時間。"},{"simplified":"在这个项目上，我们不能无所作为。","english":"We cannot be inactive on this project.","traditional":"在這個項目上，我們不能無所作為。"}],"synonyms":["无所事事","无为而治"],"antonyms":["积极进取","大有作为"],"confusedWith":[{"id":"无为而治","note":"无为而治 refers to a Daoist approach of governance through non-action, which is not inherently negative."}],"traditional":"無所作為","pinyinOverride":null},{"id":"wu-ji-yu-shi","simplified":"无济于事","literalMeaning":"no help to the matter","figurativeMeaning":"to be of no help; to be useless","englishEquivalents":["of no avail","useless","to no effect"],"shortGloss":"useless; ineffective","characters":[{"char":"无","meaning":"no; not"},{"char":"济","meaning":"help; aid"},{"char":"于","meaning":"to; towards"},{"char":"事","meaning":"matter; affair"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '无济于事' is commonly used to describe situations where efforts or actions do not bring about any positive change or effect. It emphasizes the futility of certain actions in resolving a problem or achieving a desired outcome.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","complement"],"structure":"verb-object","register":"widely used in both spoken and written Chinese","connotation":"negative","commonMistakes":"Learners might confuse this idiom with expressions that imply partial success or minimal help. It is important to remember that '无济于事' implies complete ineffectiveness.","canStandAlone":false},"examples":[{"simplified":"即使再努力，也无济于事。","english":"Even with more effort, it would be of no avail.","traditional":"即使再努力，也無濟於事。"},{"simplified":"他的解释无济于事，大家还是不明白。","english":"His explanation was useless; everyone still didn't understand.","traditional":"他的解釋無濟於事，大家還是不明白。"}],"synonyms":["徒劳无功","杯水车薪"],"antonyms":["事半功倍"],"confusedWith":[{"id":"事倍功半","note":"While '无济于事' means completely ineffective, '事倍功半' refers to efforts that yield less than expected results, not complete ineffectiveness."}],"traditional":"無濟於事","pinyinOverride":null},{"id":"wu-jing-da-cai","simplified":"无精打采","literalMeaning":"without spirit, hit listless","figurativeMeaning":"listless, dispirited, lacking energy or enthusiasm","englishEquivalents":["down in the dumps","out of sorts","in low spirits"],"shortGloss":"listless and dispirited","characters":[{"char":"无","meaning":"without"},{"char":"精","meaning":"spirit, energy"},{"char":"打","meaning":"hit, strike"},{"char":"采","meaning":"vitality, spirit"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '无精打采' is used to describe someone who appears listless or lacking in energy. It is often used to describe a person's demeanor when they are feeling down or unwell, but the exact origin of the phrase is not well-documented in classical texts.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"modifier-head","register":"commonly used in both spoken and written Chinese","connotation":"negative","commonMistakes":"Learners often confuse '无精打采' with '精神焕发', which means full of energy and spirit. The former has a negative connotation of lacking energy, while the latter is positive.","canStandAlone":false},"examples":[{"simplified":"他今天看起来无精打采的，好像没睡好。","english":"He looks listless today, as if he didn't sleep well.","traditional":"他今天看起來無精打采的，好像沒睡好。"},{"simplified":"最近天气不好，大家都无精打采的。","english":"The weather has been bad lately, and everyone seems out of sorts.","traditional":"最近天氣不好，大家都無精打采的。"}],"synonyms":["垂头丧气","心灰意冷"],"antonyms":["精神焕发"],"confusedWith":[{"id":"精神焕发","note":"精神焕发 means full of energy and spirit, which is the opposite of 无精打采."}],"traditional":"無精打采","pinyinOverride":null},{"id":"wu-neng-wei-li","simplified":"无能为力","literalMeaning":"without ability to exert force","figurativeMeaning":"powerless to do anything; unable to help","englishEquivalents":["powerless","helpless","at a loss"],"shortGloss":"powerless to act","characters":[{"char":"无","meaning":"without"},{"char":"能","meaning":"ability"},{"char":"为","meaning":"to do"},{"char":"力","meaning":"strength; force"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '无能为力' is used to describe situations where someone feels powerless or unable to take effective action. It conveys a sense of helplessness in the face of circumstances beyond one's control. The exact origin of this phrase is not tied to a specific classical text, but it has been widely used in Chinese literature and speech to express this sentiment.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","complement"],"structure":"modifier-head","register":"commonly used in both written and spoken Chinese","connotation":"negative","commonMistakes":"Learners sometimes confuse '无能为力' with '无所不能' (capable of anything), which has the opposite meaning. It's important to note that '无能为力' implies a lack of ability to change a situation.","canStandAlone":false},"examples":[{"simplified":"面对这样的灾难，我们感到无能为力。","english":"In the face of such a disaster, we feel powerless.","traditional":"面對這樣的災難，我們感到無能為力。"},{"simplified":"虽然他很想帮助，但他对此事无能为力。","english":"Although he wanted to help, he was powerless to do anything about it.","traditional":"雖然他很想幫助，但他對此事無能為力。"}],"synonyms":["束手无策"],"antonyms":["无所不能"],"confusedWith":[{"id":"无所不能","note":"无所不能 means capable of anything, which is the opposite of 无能为力."}],"traditional":"無能為力","pinyinOverride":null},{"id":"wu-lun-ru-he","simplified":"无论如何","literalMeaning":"no matter how","figurativeMeaning":"in any case; no matter what","englishEquivalents":["no matter what","in any case","come what may"],"shortGloss":"in any case","characters":[{"char":"无","meaning":"no; not"},{"char":"论","meaning":"regard; consider"},{"char":"如","meaning":"like; as if"},{"char":"何","meaning":"what; how"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '无论如何' is commonly used in modern Chinese to express determination or inevitability, emphasizing that something will happen regardless of the circumstances. It does not have a specific origin story tied to a classical text, but it is widely used in both written and spoken Chinese.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["adverbial"],"structure":"modifier-head","register":"widely used in both formal and informal contexts","connotation":"neutral","commonMistakes":"Learners might confuse '无论如何' with '不管怎样', which has a similar meaning but is used slightly differently in terms of formality and context. '无论如何' is more formal and often used in writing.","canStandAlone":false},"examples":[{"simplified":"无论如何，我们都要完成这个项目。","english":"No matter what, we must complete this project.","traditional":"無論如何，我們都要完成這個項目。"},{"simplified":"他无论如何也不会放弃这个机会。","english":"He will not give up this opportunity no matter what.","traditional":"他無論如何也不會放棄這個機會。"}],"synonyms":["不管怎样"],"antonyms":[],"confusedWith":[{"id":"不管怎样","note":"'不管怎样' is less formal and often used in spoken language, while '无论如何' is more formal and common in writing."}],"traditional":"無論如何","pinyinOverride":null},{"id":"wu-hua-ke-shuo","simplified":"无话可说","literalMeaning":"no words can be spoken","figurativeMeaning":"to be left speechless; to have nothing to say","englishEquivalents":["speechless","at a loss for words"],"shortGloss":"speechless, nothing to say","characters":[{"char":"无","meaning":"no; without"},{"char":"话","meaning":"words; speech"},{"char":"可","meaning":"can; able to"},{"char":"说","meaning":"speak; say"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '无话可说' is used to describe a situation where someone is left without words, often due to surprise, shock, or a lack of arguments. It is commonly used in modern Chinese to express being speechless or having nothing further to add to a conversation.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","complement"],"structure":"modifier-head","register":"commonly used in both spoken and written Chinese","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with expressions that imply unwillingness to speak, but '无话可说' specifically means having nothing to say due to being speechless or at a loss for words.","canStandAlone":true},"examples":[{"simplified":"他的表现让我无话可说。","english":"His performance left me speechless.","traditional":"他的表現讓我無話可說。"},{"simplified":"面对这样的指责，他无话可说。","english":"Faced with such accusations, he was at a loss for words.","traditional":"面對這樣的指責，他無話可說。"}],"synonyms":["哑口无言"],"antonyms":[],"confusedWith":[{"id":"无言以对","note":"Both imply being speechless, but '无言以对' emphasizes being unable to respond specifically."}],"traditional":"無話可說","pinyinOverride":null},{"id":"wu-bian-wu-ji","simplified":"无边无际","literalMeaning":"without edge, without boundary","figurativeMeaning":"boundless; limitless; vast","englishEquivalents":["endless","limitless","boundless"],"shortGloss":"boundless; limitless","characters":[{"char":"无","meaning":"without"},{"char":"边","meaning":"edge"},{"char":"无","meaning":"without"},{"char":"际","meaning":"boundary"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '无边无际' is used to describe something that is vast and limitless, such as the sky or the ocean. It emphasizes the idea of something being so extensive that it seems to have no boundaries or limits.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"coordinate","register":"common in both written and spoken Chinese","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with similar expressions that describe vastness but have different nuances, such as '浩瀚无垠', which specifically refers to the vastness of the sea or sky.","canStandAlone":false},"examples":[{"simplified":"沙漠看起来无边无际，让人感到渺小。","english":"The desert seemed boundless, making one feel small.","traditional":"沙漠看起來無邊無際，讓人感到渺小。"},{"simplified":"夜空无边无际，星星点缀其中。","english":"The night sky is limitless, with stars scattered throughout.","traditional":"夜空無邊無際，星星點綴其中。"}],"synonyms":["浩瀚无垠","广阔无垠"],"antonyms":["有限","边界分明"],"confusedWith":[{"id":"浩瀚无垠","note":"While both describe vastness, '浩瀚无垠' is often used for the sea or sky, emphasizing their grandeur."}],"traditional":"無邊無際","pinyinOverride":null},{"id":"ri-fu-yi-ri","simplified":"日复一日","literalMeaning":"day after day","figurativeMeaning":"something that happens repeatedly or monotonously over time","englishEquivalents":["day in, day out","day after day"],"shortGloss":"repeatedly, monotonously over time","characters":[{"char":"日","meaning":"day"},{"char":"复","meaning":"repeat"},{"char":"一","meaning":"one"},{"char":"日","meaning":"day"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '日复一日' describes the repetitive nature of certain activities or situations. It is often used to express a sense of monotony or routine, where each day feels the same as the last.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["adverbial","attributive"],"structure":"modifier-head","register":"commonly used in both spoken and written Chinese to describe repetitive actions or situations","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with others that describe time, such as '年复一年' (year after year), which emphasizes a longer time span. '日复一日' specifically refers to daily repetition.","canStandAlone":false},"examples":[{"simplified":"他日复一日地做同样的工作，感到非常无聊。","english":"He does the same work day after day and feels very bored.","traditional":"他日復一日地做同樣的工作，感到非常無聊。"},{"simplified":"日复一日的训练让她变得更加优秀。","english":"The day-in, day-out training made her more excellent.","traditional":"日復一日的訓練讓她變得更加優秀。"}],"synonyms":["年复一年"],"antonyms":[],"confusedWith":[{"id":"年复一年","note":"This idiom refers to repetition over years, not days."}],"traditional":"日復一日","pinyinOverride":null},{"id":"ri-xin-yue-yi","simplified":"日新月异","literalMeaning":"daily new, monthly different","figurativeMeaning":"constantly changing and improving; rapid progress","englishEquivalents":["ever-changing","constantly evolving"],"shortGloss":"constantly changing and improving","characters":[{"char":"日","meaning":"day"},{"char":"新","meaning":"new"},{"char":"月","meaning":"month"},{"char":"异","meaning":"different"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '日新月异' is believed to have originated from the idea that things are constantly changing and improving over time. It reflects the notion that with each passing day and month, new developments and changes occur, leading to progress and innovation. This concept has been embraced in various contexts, from technology to personal growth.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["adverbial","attributive"],"structure":"coordinate","register":"commonly used in both formal and informal contexts to describe rapid progress or change","connotation":"positive","commonMistakes":"Learners sometimes use this idiom to describe minor or insignificant changes, but it is more appropriately used for significant progress or transformation.","canStandAlone":false},"examples":[{"simplified":"科技的发展日新月异，让我们的生活更加便利。","english":"The rapid progress of technology is constantly changing and improving, making our lives more convenient.","traditional":"科技的發展日新月異，讓我們的生活更加便利。"},{"simplified":"在这个日新月异的时代，我们必须不断学习以跟上潮流。","english":"In this ever-changing era, we must continually learn to keep up with the trends.","traditional":"在這個日新月異的時代，我們必須不斷學習以跟上潮流。"}],"synonyms":["突飞猛进"],"antonyms":["一成不变"],"confusedWith":[{"id":"日积月累","note":"日积月累 refers to gradual accumulation over time, whereas 日新月异 emphasizes rapid change and improvement."}],"traditional":"日新月異","pinyinOverride":null},{"id":"shi-hao-shi-huai","simplified":"时好时坏","literalMeaning":"sometimes good, sometimes bad","figurativeMeaning":"inconsistent or unpredictable in quality or performance","englishEquivalents":["hit or miss","blow hot and cold"],"shortGloss":"inconsistent quality","characters":[{"char":"时","meaning":"sometimes"},{"char":"好","meaning":"good"},{"char":"时","meaning":"sometimes"},{"char":"坏","meaning":"bad"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '时好时坏' describes a situation or condition that is inconsistent, alternating between being good and bad. It is often used to describe things like the weather, someone's mood, or the performance of a machine.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"coordinate","register":"commonly used in both spoken and written Chinese","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with '好坏参半' (good and bad mixed together), which implies a simultaneous presence of good and bad elements, rather than an alternation.","canStandAlone":false},"examples":[{"simplified":"这台电脑的性能时好时坏，让人很头疼。","english":"The performance of this computer is hit or miss, which is quite frustrating.","traditional":"這臺電腦的性能時好時壞，讓人很頭疼。"},{"simplified":"他的心情时好时坏，让人捉摸不透。","english":"His mood is unpredictable, making it hard to understand him.","traditional":"他的心情時好時壞，讓人捉摸不透。"}],"synonyms":["忽好忽坏"],"antonyms":["一如既往"],"confusedWith":[{"id":"好坏参半","note":"好坏参半 implies a mix of good and bad elements present at the same time, not alternation."}],"traditional":"時好時壞","pinyinOverride":null},{"id":"xian-er-yi-jian","simplified":"显而易见","literalMeaning":"obvious and easy to see","figurativeMeaning":"obvious; evident; clear and easy to understand","englishEquivalents":["clear as day","plain as the nose on your face"],"shortGloss":"obvious and clear","characters":[{"char":"显","meaning":"obvious; evident"},{"char":"而","meaning":"and; as well as"},{"char":"易","meaning":"easy"},{"char":"见","meaning":"to see"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '显而易见' is often used to describe something that is so clear and obvious that it requires no further explanation. It emphasizes the ease with which something can be understood or recognized.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"coordinate","register":"widely used in both spoken and written Chinese","connotation":"neutral","commonMistakes":"Learners sometimes confuse '显而易见' with idioms that imply something is hidden or difficult to understand. Remember, this idiom is used to emphasize clarity and obviousness.","canStandAlone":false},"examples":[{"simplified":"他的错误显而易见，不需要再解释。","english":"His mistake is obvious and needs no further explanation.","traditional":"他的錯誤顯而易見，不需要再解釋。"},{"simplified":"这个问题的答案显而易见。","english":"The answer to this question is obvious.","traditional":"這個問題的答案顯而易見。"}],"synonyms":["一目了然"],"antonyms":["扑朔迷离"],"confusedWith":[{"id":"扑朔迷离","note":"扑朔迷离 means something is confusing or difficult to understand, which is the opposite of 显而易见."}],"traditional":"顯而易見","pinyinOverride":null},{"id":"yun-tou-zhuan-xiang","simplified":"晕头转向","literalMeaning":"dizzy head turn direction","figurativeMeaning":"to be confused and disoriented","englishEquivalents":["to be in a daze","to be all at sea"],"shortGloss":"confused and disoriented","characters":[{"char":"晕","meaning":"dizzy"},{"char":"头","meaning":"head"},{"char":"转","meaning":"turn"},{"char":"向","meaning":"direction"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '晕头转向' is believed to have originated from the feeling of dizziness and confusion one experiences when physically spinning around. It metaphorically describes a state of mental disorientation or confusion, as if one's head is spinning and unable to find the right direction.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","complement"],"structure":"coordinate","register":"widely used in both spoken and written Chinese","connotation":"negative","commonMistakes":"Learners sometimes confuse this idiom with others that imply physical dizziness rather than mental confusion. It is important to use it in contexts where mental disorientation is meant.","canStandAlone":false},"examples":[{"simplified":"他一整天忙得晕头转向，连午饭都忘了吃。","english":"He was so busy all day that he was in a daze and even forgot to eat lunch.","traditional":"他一整天忙得暈頭轉向，連午飯都忘了吃。"},{"simplified":"在陌生的城市里，他迷路了，晕头转向，不知道该往哪走。","english":"In the unfamiliar city, he got lost, disoriented, and didn't know which way to go.","traditional":"在陌生的城市裡，他迷路了，暈頭轉向，不知道該往哪走。"}],"synonyms":["不知所措","迷迷糊糊"],"antonyms":["头脑清醒"],"confusedWith":[{"id":"头晕目眩","note":"头晕目眩 refers to physical dizziness, often due to illness or spinning, not mental confusion."}],"traditional":"暈頭轉向","pinyinOverride":null},{"id":"bao-feng-zhou-yu","simplified":"暴风骤雨","literalMeaning":"violent wind and sudden rain","figurativeMeaning":"a sudden and intense outburst or onslaught, often used to describe a fierce attack or a rapid and intense change","englishEquivalents":["stormy weather","a tempest","a whirlwind"],"shortGloss":"a sudden and intense onslaught","characters":[{"char":"暴","meaning":"violent, sudden"},{"char":"风","meaning":"wind"},{"char":"骤","meaning":"sudden, abrupt"},{"char":"雨","meaning":"rain"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom 暴风骤雨 is often used metaphorically to describe situations that change rapidly and intensely, much like a sudden storm. It is not tied to a specific classical story but rather reflects a common natural phenomenon that is easily understood across cultures.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["subject","predicate","object","attributive"],"structure":"coordinate","register":"widely used in both formal and informal contexts","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with literal weather conditions. It is important to understand its metaphorical use to describe sudden and intense situations rather than actual weather.","canStandAlone":false},"examples":[{"simplified":"改革的过程如同暴风骤雨，迅速而猛烈。","english":"The process of reform was like a tempest, rapid and intense.","traditional":"改革的過程如同暴風驟雨，迅速而猛烈。"},{"simplified":"他的批评如暴风骤雨般袭来，让人措手不及。","english":"His criticism came like a sudden storm, catching people off guard.","traditional":"他的批評如暴風驟雨般襲來，讓人措手不及。"}],"synonyms":["狂风暴雨","电闪雷鸣"],"antonyms":["风平浪静"],"confusedWith":[{"id":"狂风暴雨","note":"Both describe intense weather, but 狂风暴雨 can also emphasize chaos and disorder."}],"traditional":"暴風驟雨","pinyinOverride":null},{"id":"you-sheng-you-se","simplified":"有声有色","literalMeaning":"have sound have color","figurativeMeaning":"vivid and impressive; lively and full of interest","englishEquivalents":["vivid and lively","full of life","colorful and engaging"],"shortGloss":"vivid and lively","characters":[{"char":"有","meaning":"have"},{"char":"声","meaning":"sound"},{"char":"有","meaning":"have"},{"char":"色","meaning":"color"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '有声有色' is used to describe something that is vivid and lively, often used to praise a performance, description, or story that is engaging and full of life. The phrase suggests that the subject is not only audible but also visually appealing, creating a complete and impressive experience.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"coordinate","register":"commonly used in both written and spoken Chinese","connotation":"positive","commonMistakes":"Learners might confuse this idiom with phrases that only describe visual appeal or sound, but '有声有色' implies both auditory and visual vividness. It is often used to describe performances or narratives, not just visual art.","canStandAlone":false},"examples":[{"simplified":"他的演讲有声有色，观众都听得入迷了。","english":"His speech was vivid and lively, and the audience was captivated.","traditional":"他的演講有聲有色，觀眾都聽得入迷了。"},{"simplified":"这部电影拍得有声有色，令人难忘。","english":"The movie was filmed in a vivid and lively manner, making it unforgettable.","traditional":"這部電影拍得有聲有色，令人難忘。"}],"synonyms":["绘声绘色","栩栩如生"],"antonyms":["平淡无奇"],"confusedWith":[{"id":"绘声绘色","note":"Both describe vividness, but '绘声绘色' emphasizes detailed and lifelike depiction, often in storytelling."}],"traditional":"有聲有色","pinyinOverride":null},{"id":"you-zhao-yi-ri","simplified":"有朝一日","literalMeaning":"have morning one day","figurativeMeaning":"someday in the future; if the opportunity arises","englishEquivalents":["one day","someday","in the future"],"shortGloss":"someday in the future","characters":[{"char":"有","meaning":"have"},{"char":"朝","meaning":"morning; day"},{"char":"一","meaning":"one"},{"char":"日","meaning":"day"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '有朝一日' is often used to express the hope or expectation that something will happen in the future, though its exact origin is not tied to a specific classical text. It conveys a sense of anticipation or aspiration for a future event or opportunity.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["adverbial"],"structure":"modifier-head","register":"commonly used in both spoken and written Chinese","connotation":"neutral","commonMistakes":"Learners often confuse '有朝一日' with specific time expressions, but it is more indefinite and should not be used when a specific date or time is known.","canStandAlone":false},"examples":[{"simplified":"有朝一日，我希望能环游世界。","english":"Someday, I hope to travel around the world.","traditional":"有朝一日，我希望能環遊世界。"},{"simplified":"他相信有朝一日会实现自己的梦想。","english":"He believes that one day he will achieve his dreams.","traditional":"他相信有朝一日會實現自己的夢想。"}],"synonyms":[],"antonyms":[],"confusedWith":[],"traditional":"有朝一日","pinyinOverride":null},{"id":"you-tiao-bu-wen","simplified":"有条不紊","literalMeaning":"have order not chaos","figurativeMeaning":"to be methodical and orderly","englishEquivalents":["in an orderly fashion","methodically","systematically"],"shortGloss":"methodical and orderly","characters":[{"char":"有","meaning":"have"},{"char":"条","meaning":"order; line"},{"char":"不","meaning":"not"},{"char":"紊","meaning":"chaos; disorder"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '有条不紊' describes a situation or process that is carried out in a well-organized and systematic manner. The phrase emphasizes the presence of order and the absence of chaos. It is often used to praise someone for their methodical approach to tasks or to describe a process that is running smoothly and efficiently.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["adverbial","attributive"],"structure":"modifier-head","register":"widely used in both formal and informal contexts","connotation":"positive","commonMistakes":"Learners might confuse '有条不紊' with '井井有条', which also means orderly but emphasizes neatness and tidiness. '有条不紊' focuses more on the absence of chaos.","canStandAlone":false},"examples":[{"simplified":"她做事总是有条不紊，从不慌乱。","english":"She always does things methodically and never gets flustered.","traditional":"她做事總是有條不紊，從不慌亂。"},{"simplified":"会议在他的主持下，有条不紊地进行。","english":"The meeting proceeded in an orderly fashion under his leadership.","traditional":"會議在他的主持下，有條不紊地進行。"}],"synonyms":["井井有条"],"antonyms":["杂乱无章"],"confusedWith":[{"id":"井井有条","note":"Both imply orderliness, but '井井有条' emphasizes neatness and tidiness, while '有条不紊' focuses on the absence of chaos."}],"traditional":"有條不紊","pinyinOverride":null},{"id":"you-de-fang-shi","simplified":"有的放矢","literalMeaning":"have a target and shoot arrows","figurativeMeaning":"to speak or act with a clear aim or purpose","englishEquivalents":["hit the target","aim with precision"],"shortGloss":"act with purpose","characters":[{"char":"有","meaning":"have"},{"char":"的","meaning":"target"},{"char":"放","meaning":"release"},{"char":"矢","meaning":"arrow"}],"origin":{"period":"Warring States period (475–221 BCE)","sourceText":"《礼记·射义》","sourceTextEnglish":"Book of Rites, Chapter on Archery","originalExcerpt":"有的而射，斯可以观德矣。","storyEnglish":"The idiom originates from the 'Book of Rites', where it discusses the importance of having a clear target when shooting arrows. This metaphorically extends to the idea of having a clear purpose or goal in one's actions or words.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["adverbial","attributive"],"structure":"modifier-head","register":"literary, but very widely understood and used in ordinary speech","connotation":"positive","commonMistakes":"Learners sometimes confuse this idiom with similar expressions that imply aimlessness, such as '漫无目的'. It's important to remember that '有的放矢' emphasizes having a clear goal.","canStandAlone":false},"examples":[{"simplified":"他做事总是有的放矢，从不浪费时间。","english":"He always acts with a clear aim and never wastes time.","traditional":"他做事總是有的放矢，從不浪費時間。"},{"simplified":"在谈判中，我们需要有的放矢，以便达成协议。","english":"In negotiations, we need to have a clear aim to reach an agreement.","traditional":"在談判中，我們需要有的放矢，以便達成協議。"}],"synonyms":["对症下药","目标明确"],"antonyms":["漫无目的"],"confusedWith":[{"id":"漫无目的","note":"漫无目的 means aimless or without a clear goal, which is the opposite of 有的放矢."}],"traditional":"有的放矢","pinyinOverride":null},{"id":"zhao-xi-xiang-chu","simplified":"朝夕相处","literalMeaning":"morning and evening together","figurativeMeaning":"to be together from morning till night; to be closely associated","englishEquivalents":["joined at the hip","inseparable"],"shortGloss":"inseparable; closely associated","characters":[{"char":"朝","meaning":"morning"},{"char":"夕","meaning":"evening"},{"char":"相","meaning":"mutually"},{"char":"处","meaning":"to be with"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '朝夕相处' describes the close relationship between people who spend all their time together, from morning till night. It emphasizes the idea of being inseparable and constantly in each other's company.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"modifier-head","register":"commonly used in both spoken and written Chinese","connotation":"neutral","commonMistakes":"Learners often confuse this idiom with '形影不离', which also means inseparable but emphasizes the physical closeness rather than the time spent together.","canStandAlone":false},"examples":[{"simplified":"他们是好朋友，总是朝夕相处。","english":"They are good friends and are always together from morning till night.","traditional":"他們是好朋友，總是朝夕相處。"},{"simplified":"在项目期间，我们朝夕相处，建立了深厚的友谊。","english":"During the project, we spent all our time together and developed a deep friendship.","traditional":"在項目期間，我們朝夕相處，建立了深厚的友誼。"}],"synonyms":["形影不离"],"antonyms":[],"confusedWith":[{"id":"形影不离","note":"While both idioms mean inseparable, '形影不离' emphasizes physical proximity, whereas '朝夕相处' emphasizes spending time together."}],"traditional":"朝夕相處","pinyinOverride":null},{"id":"zhao-qi-peng-bo","simplified":"朝气蓬勃","literalMeaning":"morning energy exuberant","figurativeMeaning":"full of youthful vigor and energy","englishEquivalents":["full of youthful vigor","bubbling with energy"],"shortGloss":"full of youthful energy","characters":[{"char":"朝","meaning":"morning"},{"char":"气","meaning":"energy"},{"char":"蓬","meaning":"exuberant"},{"char":"勃","meaning":"vigorous"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '朝气蓬勃' is used to describe someone or something that is full of youthful energy and vitality. It is often used to describe young people or new projects that are brimming with enthusiasm and potential.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"modifier-head","register":"commonly used in both formal and informal contexts","connotation":"positive","commonMistakes":"Learners might confuse this idiom with others that involve energy or vigor, such as '生机勃勃', which also means full of life but is more often used for nature or situations rather than people.","canStandAlone":false},"examples":[{"simplified":"这个团队朝气蓬勃，充满了创新的想法。","english":"This team is full of youthful vigor and brimming with innovative ideas.","traditional":"這個團隊朝氣蓬勃，充滿了創新的想法。"},{"simplified":"他是一个朝气蓬勃的年轻人，总是充满活力。","english":"He is a young man full of youthful vigor, always energetic.","traditional":"他是一個朝氣蓬勃的年輕人，總是充滿活力。"}],"synonyms":["生机勃勃"],"antonyms":["暮气沉沉"],"confusedWith":[{"id":"生机勃勃","note":"While both idioms describe vitality, '生机勃勃' is often used for nature or situations, not people."}],"traditional":"朝氣蓬勃","pinyinOverride":null},{"id":"za-luan-wu-zhang","simplified":"杂乱无章","literalMeaning":"chaotic and without order","figurativeMeaning":"disorganized and lacking structure","englishEquivalents":["all over the place","haphazard","in disarray"],"shortGloss":"disorganized and chaotic","characters":[{"char":"杂","meaning":"mixed; miscellaneous"},{"char":"乱","meaning":"chaotic; disorderly"},{"char":"无","meaning":"without; lacking"},{"char":"章","meaning":"order; pattern"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '杂乱无章' is used to describe a situation or collection of items that are in complete disarray, lacking any sort of logical order or organization. It is often used to criticize a lack of planning or structure in both physical and abstract contexts.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"coordinate","register":"commonly used in both spoken and written Chinese to describe disorganization","connotation":"negative","commonMistakes":"Learners might confuse '杂乱无章' with '井井有条', which means 'neat and orderly'. It's important to remember that '杂乱无章' has a negative connotation of disorganization.","canStandAlone":false},"examples":[{"simplified":"他的房间总是杂乱无章，找东西很困难。","english":"His room is always in disarray, making it difficult to find anything.","traditional":"他的房間總是雜亂無章，找東西很困難。"},{"simplified":"这篇文章写得杂乱无章，读起来很费劲。","english":"This article is written in a disorganized manner, making it difficult to read.","traditional":"這篇文章寫得雜亂無章，讀起來很費勁。"}],"synonyms":["乱七八糟","一团糟"],"antonyms":["井井有条"],"confusedWith":[{"id":"井井有条","note":"While '杂乱无章' means disorganized, '井井有条' means neat and orderly."}],"traditional":"雜亂無章","pinyinOverride":null},{"id":"shu-shou-wu-ce","simplified":"束手无策","literalMeaning":"tie hands, no strategy","figurativeMeaning":"to be at a loss; to be helpless in the face of a problem","englishEquivalents":["at one's wits' end","at a loss","without a clue"],"shortGloss":"helpless; at a loss","characters":[{"char":"束","meaning":"to tie; to bind"},{"char":"手","meaning":"hands"},{"char":"无","meaning":"without; no"},{"char":"策","meaning":"strategy; plan"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '束手无策' describes a situation where someone is completely at a loss and unable to come up with any plan or strategy to solve a problem. The phrase literally means 'to have one's hands tied and no strategy,' conveying a sense of helplessness and inability to act. It is often used to describe situations where all options have been exhausted, and no solution is in sight.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","complement"],"structure":"modifier-head","register":"widely used in both formal and informal contexts","connotation":"negative","commonMistakes":"Learners often confuse this idiom with others that imply a lack of action, such as '无能为力', which specifically means lacking the power or ability to act. '束手无策' emphasizes the absence of a plan or strategy, not just the inability to act.","canStandAlone":false},"examples":[{"simplified":"面对突如其来的危机，他感到束手无策。","english":"Faced with the sudden crisis, he felt at a loss.","traditional":"面對突如其來的危機，他感到束手無策。"},{"simplified":"医生对这种罕见的疾病也束手无策。","english":"The doctors were also at a loss with this rare disease.","traditional":"醫生對這種罕見的疾病也束手無策。"}],"synonyms":["无能为力","一筹莫展"],"antonyms":["游刃有余"],"confusedWith":[{"id":"无能为力","note":"无能为力 emphasizes lacking the power to act, while 束手无策 emphasizes lacking a plan or strategy."}],"traditional":"束手無策","pinyinOverride":null},{"id":"lai-zhi-bu-yi","simplified":"来之不易","literalMeaning":"come by not easy","figurativeMeaning":"hard-earned; achieved with great difficulty","englishEquivalents":["hard-earned","not easily achieved"],"shortGloss":"hard-earned","characters":[{"char":"来","meaning":"come"},{"char":"之","meaning":"of; from"},{"char":"不","meaning":"not"},{"char":"易","meaning":"easy"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '来之不易' is used to describe something that is obtained or achieved with considerable effort and difficulty. It emphasizes the value and effort involved in acquiring something, highlighting that it was not easily obtained.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"modifier-head","register":"commonly used in both spoken and written Chinese to emphasize the difficulty of achieving something","connotation":"positive","commonMistakes":"Learners may confuse it with similar-sounding phrases that do not convey the same sense of difficulty and effort. It specifically emphasizes the hard work involved, unlike some idioms that merely suggest rarity or value.","canStandAlone":false},"examples":[{"simplified":"这次胜利来之不易，我们付出了很多努力。","english":"This victory was hard-earned; we put in a lot of effort.","traditional":"這次勝利來之不易，我們付出了很多努力。"},{"simplified":"他的成功来之不易，是多年辛勤工作的结果。","english":"His success was hard-earned; it was the result of many years of hard work.","traditional":"他的成功來之不易，是多年辛勤工作的結果。"}],"synonyms":["得来不易"],"antonyms":[],"confusedWith":[{"id":"轻而易举","note":"轻而易举 means 'easy to achieve' and is the opposite of 来之不易, which emphasizes difficulty and effort."}],"traditional":"來之不易","pinyinOverride":null},{"id":"lai-long-qu-mai","simplified":"来龙去脉","literalMeaning":"the dragon's coming and going veins","figurativeMeaning":"the sequence of events; the ins and outs of a matter","englishEquivalents":["the whole story","the full picture"],"shortGloss":"the sequence of events","characters":[{"char":"来","meaning":"coming"},{"char":"龙","meaning":"dragon"},{"char":"去","meaning":"going"},{"char":"脉","meaning":"veins, context"}],"origin":{"period":"Tang Dynasty (618–907 CE)","sourceText":"《旧唐书·地理志》","sourceTextEnglish":"Old Book of Tang, Geographical Records","originalExcerpt":"山有脉，水有源，来龙去脉，皆有条理。","storyEnglish":"The idiom '来龙去脉' originally comes from the geomantic principles of feng shui, where it was used to describe the flow and connection of mountain ranges and watercourses, resembling the movement of a dragon. Over time, it evolved to refer more generally to understanding the full context or sequence of events in any situation.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["object","attributive"],"structure":"coordinate","register":"widely used in both formal and informal contexts","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with others that involve dragons, but '来龙去脉' specifically refers to understanding the full context or sequence of events, not just any situation involving a dragon.","canStandAlone":false},"examples":[{"simplified":"在做决定之前，我们需要了解事情的来龙去脉。","english":"Before making a decision, we need to understand the whole story.","traditional":"在做決定之前，我們需要了解事情的來龍去脈。"},{"simplified":"他详细地解释了这个项目的来龙去脉。","english":"He explained the ins and outs of the project in detail.","traditional":"他詳細地解釋了這個項目的來龍去脈。"}],"synonyms":["前因后果"],"antonyms":[],"confusedWith":[{"id":"画龙点睛","note":"来龙去脉 refers to understanding the full context, while 画龙点睛 means adding the finishing touch."}],"traditional":"來龍去脈","pinyinOverride":null},{"id":"gen-shen-di-gu","simplified":"根深蒂固","literalMeaning":"roots deep, stem solid","figurativeMeaning":"deep-rooted; firmly established","englishEquivalents":["deep-rooted","firmly entrenched"],"shortGloss":"deeply rooted; entrenched","characters":[{"char":"根","meaning":"root"},{"char":"深","meaning":"deep"},{"char":"蒂","meaning":"stem"},{"char":"固","meaning":"solid; firm"}],"origin":{"period":"Han Dynasty (206 BCE – 220 CE)","sourceText":"《汉书·元帝纪》","sourceTextEnglish":"Book of Han, Annals of Emperor Yuan","originalExcerpt":"根深蒂固，难以动摇。","storyEnglish":"The phrase '根深蒂固' is used in the 'Book of Han' to describe something that is so deeply rooted and firmly established that it is difficult to shake or change. It originally referred to the strength and stability of a plant's roots and stem, metaphorically extending to ideas, traditions, or systems that are firmly entrenched.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["attributive","predicate"],"structure":"modifier-head","register":"commonly used in both formal and informal contexts","connotation":"neutral","commonMistakes":"Learners might confuse it with idioms that imply temporary or superficial stability. '根深蒂固' specifically refers to something that is deeply and firmly established, not just temporarily stable.","canStandAlone":false},"examples":[{"simplified":"他的偏见已经根深蒂固，很难改变。","english":"His prejudices are deeply rooted and difficult to change.","traditional":"他的偏見已經根深蒂固，很難改變。"},{"simplified":"这种文化习俗在当地根深蒂固。","english":"This cultural custom is deeply entrenched in the local area.","traditional":"這種文化習俗在當地根深蒂固。"}],"synonyms":["积重难返"],"antonyms":[],"confusedWith":[{"id":"一成不变","note":"While '根深蒂固' refers to something deeply established, '一成不变' means something that remains unchanged, often with a negative connotation of being inflexible."}],"traditional":"根深蒂固","pinyinOverride":null},{"id":"ge-ge-bu-ru","simplified":"格格不入","literalMeaning":"fit fit not enter","figurativeMeaning":"incompatible; unable to get along or fit in","englishEquivalents":["like oil and water","out of place"],"shortGloss":"incompatible, doesn't fit","characters":[{"char":"格","meaning":"fit; pattern"},{"char":"格","meaning":"fit; pattern"},{"char":"不","meaning":"not"},{"char":"入","meaning":"enter"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '格格不入' is used to describe a situation where someone or something does not fit in or is incompatible with their surroundings or with others. It conveys a sense of being out of place or unable to integrate harmoniously.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"modifier-head","register":"widely used in both formal and informal contexts","connotation":"negative","commonMistakes":"Learners often confuse '格格不入' with idioms that imply conflict or opposition, but it specifically refers to a lack of compatibility or harmony, not active conflict.","canStandAlone":false},"examples":[{"simplified":"他在新公司里感到格格不入。","english":"He feels out of place in the new company.","traditional":"他在新公司裡感到格格不入。"},{"simplified":"这件家具和房间的风格格格不入。","english":"This piece of furniture is incompatible with the style of the room.","traditional":"這件傢俱和房間的風格格格不入。"}],"synonyms":["水火不容"],"antonyms":["和谐共处"],"confusedWith":[{"id":"水火不容","note":"While both imply incompatibility, '水火不容' suggests active conflict, whereas '格格不入' focuses on not fitting in."}],"traditional":"格格不入","pinyinOverride":null},{"id":"meng-mei-yi-qiu","simplified":"梦寐以求","literalMeaning":"dream and sleep to seek","figurativeMeaning":"to yearn for something day and night; to long for something with all one's heart","englishEquivalents":["to yearn for","to long for","to dream of"],"shortGloss":"yearn for day and night","characters":[{"char":"梦","meaning":"dream"},{"char":"寐","meaning":"sleep"},{"char":"以","meaning":"in order to"},{"char":"求","meaning":"seek"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom 梦寐以求 describes a deep longing or desire for something, so intense that one dreams of it even in sleep. It emphasizes the persistence and intensity of the yearning, suggesting that it occupies both the waking and sleeping thoughts of the person.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"verb-object","register":"widely used in both formal and informal contexts","connotation":"positive","commonMistakes":"Learners often confuse this idiom with similar expressions that imply mere wishful thinking, whereas 梦寐以求 suggests a deep and persistent longing.","canStandAlone":false},"examples":[{"simplified":"他终于得到了那个梦寐以求的工作。","english":"He finally got the job he had been dreaming of day and night.","traditional":"他終於得到了那個夢寐以求的工作。"},{"simplified":"这是我梦寐以求的机会，我一定会好好珍惜。","english":"This is the opportunity I've been longing for; I will definitely cherish it.","traditional":"這是我夢寐以求的機會，我一定會好好珍惜。"}],"synonyms":["魂牵梦萦","朝思暮想"],"antonyms":[],"confusedWith":[{"id":"心想事成","note":"心想事成 means 'wishes come true,' which implies fulfillment, while 梦寐以求 focuses on the longing itself."}],"traditional":"夢寐以求","pinyinOverride":null},{"id":"huan-sheng-xiao-yu","simplified":"欢声笑语","literalMeaning":"happy sounds and laughing words","figurativeMeaning":"a scene filled with joy and laughter","englishEquivalents":["laughter and merriment","joyous atmosphere"],"shortGloss":"joyful and lively atmosphere","characters":[{"char":"欢","meaning":"joyful, happy"},{"char":"声","meaning":"sound, voice"},{"char":"笑","meaning":"laugh, smile"},{"char":"语","meaning":"words, speech"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '欢声笑语' is often used to describe a lively and cheerful atmosphere, such as at a festive gathering or celebration. It evokes the image of people enjoying themselves, with laughter and happy chatter filling the air.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["subject","object","attributive"],"structure":"coordinate","register":"commonly used in both spoken and written Chinese to describe joyful gatherings","connotation":"positive","commonMistakes":"Learners might confuse this idiom with others that describe noise or sound, but '欢声笑语' specifically conveys a positive, joyful atmosphere. It should not be used to describe situations that are merely loud or chaotic.","canStandAlone":false},"examples":[{"simplified":"节日的晚上，整个村庄充满了欢声笑语。","english":"On the festival evening, the whole village was filled with joy and laughter.","traditional":"節日的晚上，整個村莊充滿了歡聲笑語。"},{"simplified":"婚礼上，到处都是欢声笑语。","english":"At the wedding, there was laughter and merriment everywhere.","traditional":"婚禮上，到處都是歡聲笑語。"}],"synonyms":["其乐融融","欢天喜地"],"antonyms":["愁眉苦脸"],"confusedWith":[{"id":"喧闹","note":"喧闹 refers to noise and commotion, which can be neutral or negative, unlike the positive connotation of 欢声笑语."}],"traditional":"歡聲笑語","pinyinOverride":null},{"id":"xin-xin-xiang-rong","simplified":"欣欣向荣","literalMeaning":"thriving and flourishing","figurativeMeaning":"thriving; flourishing; prospering","englishEquivalents":["thriving","flourishing","prosperous"],"shortGloss":"thriving and flourishing","characters":[{"char":"欣","meaning":"happy; joyous"},{"char":"欣","meaning":"happy; joyous"},{"char":"向","meaning":"towards"},{"char":"荣","meaning":"prosperity; flourishing"}],"origin":{"period":"Han Dynasty (206 BCE – 220 CE)","sourceText":"《文选·宋玉·神女赋》","sourceTextEnglish":"Selections of Refined Literature, Song Yu's 'Rhapsody on the Goddess'","originalExcerpt":"草木欣欣向荣，春风吹又生。","storyEnglish":"The idiom comes from a description of nature in Song Yu's 'Rhapsody on the Goddess,' where the flourishing of plants and trees is depicted as they thrive and grow under the influence of the spring wind. This imagery of natural growth and prosperity is used metaphorically to describe situations or entities that are thriving and flourishing.","historicalFigures":["Song Yu"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"subject-predicate","register":"literary, but very widely understood and used in ordinary speech","connotation":"positive","commonMistakes":"Learners might confuse this idiom with others that suggest growth but not necessarily prosperity, such as 生机勃勃, which emphasizes vitality rather than prosperity.","canStandAlone":false},"examples":[{"simplified":"近年来，这个城市的经济欣欣向荣。","english":"In recent years, the city's economy has been thriving.","traditional":"近年來，這個城市的經濟欣欣向榮。"},{"simplified":"春天来了，花园里的植物欣欣向荣。","english":"Spring has arrived, and the plants in the garden are flourishing.","traditional":"春天來了，花園裡的植物欣欣向榮。"}],"synonyms":["蒸蒸日上","繁荣昌盛"],"antonyms":["日薄西山","衰败不堪"],"confusedWith":[{"id":"生机勃勃","note":"生机勃勃 emphasizes vitality and liveliness, not necessarily prosperity."}],"traditional":"欣欣向榮","pinyinOverride":null},{"id":"ci-qi-bi-fu","simplified":"此起彼伏","literalMeaning":"this rises, that falls","figurativeMeaning":"occurrences happening one after another; continuous and unending","englishEquivalents":["one after another","in succession","continuous"],"shortGloss":"occurrences happening continuously","characters":[{"char":"此","meaning":"this"},{"char":"起","meaning":"rise"},{"char":"彼","meaning":"that"},{"char":"伏","meaning":"fall"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '此起彼伏' describes a situation where as soon as one thing finishes or subsides, another begins. It is often used to describe events or sounds that occur in succession, such as waves crashing on a shore or people speaking in a crowd.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"coordinate","register":"commonly used in both written and spoken Chinese","connotation":"neutral","commonMistakes":"Learners might mistakenly use this idiom to describe events that are unrelated or not in succession. It specifically refers to things happening continuously and in a connected manner.","canStandAlone":false},"examples":[{"simplified":"抗议声此起彼伏，政府不得不采取措施。","english":"The protests rose one after another, forcing the government to take action.","traditional":"抗議聲此起彼伏，政府不得不採取措施。"},{"simplified":"在会议上，讨论声此起彼伏。","english":"During the meeting, the discussions continued one after another.","traditional":"在會議上，討論聲此起彼伏。"}],"synonyms":["络绎不绝"],"antonyms":[],"confusedWith":[{"id":"层出不穷","note":"While both idioms describe continuous occurrences, '层出不穷' emphasizes the endless emergence of new things, whereas '此起彼伏' focuses on the alternation of rising and falling."}],"traditional":"此起彼伏","pinyinOverride":null},{"id":"bi-bi-jie-shi","simplified":"比比皆是","literalMeaning":"everywhere is","figurativeMeaning":"can be found everywhere; very common","englishEquivalents":["a dime a dozen","common as dirt"],"shortGloss":"very common; everywhere","characters":[{"char":"比","meaning":"everywhere"},{"char":"比","meaning":"everywhere"},{"char":"皆","meaning":"all"},{"char":"是","meaning":"is"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom 比比皆是 is used to describe something that is very common or ubiquitous. It suggests that whatever is being referred to can be found everywhere. The exact origin of this idiom is unclear, but it has been used in Chinese literature and speech to convey the idea of abundance or prevalence.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"modifier-head","register":"commonly used in both written and spoken Chinese","connotation":"neutral","commonMistakes":"Learners might confuse 比比皆是 with idioms that imply rarity or uniqueness. It is important to remember that this idiom emphasizes commonality and abundance.","canStandAlone":false},"examples":[{"simplified":"在大城市里，高楼大厦比比皆是。","english":"In big cities, skyscrapers are everywhere.","traditional":"在大城市裡，高樓大廈比比皆是。"},{"simplified":"这种花在这个季节比比皆是。","english":"These flowers are very common in this season.","traditional":"這種花在這個季節比比皆是。"}],"synonyms":["随处可见"],"antonyms":["凤毛麟角"],"confusedWith":[{"id":"凤毛麟角","note":"凤毛麟角 refers to something rare and precious, the opposite of 比比皆是."}],"traditional":"比比皆是","pinyinOverride":null},{"id":"shui-zhang-chuan-gao","simplified":"水涨船高","literalMeaning":"water rises, boat rises","figurativeMeaning":"when the general situation improves, everyone benefits","englishEquivalents":["A rising tide lifts all boats"],"shortGloss":"everyone benefits from a general improvement","characters":[{"char":"水","meaning":"water"},{"char":"涨","meaning":"rise"},{"char":"船","meaning":"boat"},{"char":"高","meaning":"high"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '水涨船高' is based on the simple observation that when water levels rise, boats floating on the water rise as well. This natural phenomenon is used metaphorically to describe how improvements in a general situation or environment can lead to benefits for all involved. The idiom suggests that positive changes in the broader context will naturally lead to improvements for individuals or smaller entities within that context.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"cause-effect","register":"commonly used in both written and spoken Chinese","connotation":"positive","commonMistakes":"Learners might confuse this idiom with others that involve water or boats, but it's important to remember that this idiom specifically refers to the idea of collective benefit from an overall improvement. It is not about individual effort or struggle.","canStandAlone":false},"examples":[{"simplified":"经济发展了，大家的收入也提高了，真是水涨船高。","english":"As the economy developed, everyone's income increased as well; truly, a rising tide lifts all boats.","traditional":"經濟發展了，大家的收入也提高了，真是水漲船高。"},{"simplified":"在这个行业中，技术进步让所有公司都受益，水涨船高。","english":"In this industry, technological advancements have benefited all companies, a rising tide lifts all boats.","traditional":"在這個行業中，技術進步讓所有公司都受益，水漲船高。"}],"synonyms":[],"antonyms":[],"confusedWith":[],"traditional":"水漲船高","pinyinOverride":null},{"id":"qiu-tong-cun-yi","simplified":"求同存异","literalMeaning":"seek common ground, preserve differences","figurativeMeaning":"to seek common ground while reserving differences; to agree to disagree","englishEquivalents":["agree to disagree"],"shortGloss":"seek common ground, preserve differences","characters":[{"char":"求","meaning":"seek"},{"char":"同","meaning":"common ground"},{"char":"存","meaning":"preserve"},{"char":"异","meaning":"differences"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '求同存异' is often used in diplomatic and interpersonal contexts to emphasize the importance of finding common ground with others while respecting and maintaining individual differences. It reflects a pragmatic approach to conflict resolution and cooperation, suggesting that parties can work together on shared goals without needing to resolve all differences.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"commonly used in both formal and informal contexts, especially in discussions about diplomacy and cooperation","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with similar-sounding phrases that imply complete agreement or unity, but '求同存异' specifically emphasizes maintaining differences while working together on common interests.","canStandAlone":false},"examples":[{"simplified":"在国际谈判中，我们应该求同存异，找到共同利益。","english":"In international negotiations, we should seek common ground while preserving differences and find common interests.","traditional":"在國際談判中，我們應該求同存異，找到共同利益。"},{"simplified":"朋友之间有时需要求同存异，以维持友谊。","english":"Sometimes friends need to agree to disagree in order to maintain their friendship.","traditional":"朋友之間有時需要求同存異，以維持友誼。"}],"synonyms":[],"antonyms":[],"confusedWith":[],"traditional":"求同存異","pinyinOverride":null},{"id":"han-ma-gong-lao","simplified":"汗马功劳","literalMeaning":"sweat of the horse's labor","figurativeMeaning":"great achievements or contributions, especially in battle or hard work","englishEquivalents":["hard-earned achievements","significant contributions"],"shortGloss":"great achievements or contributions","characters":[{"char":"汗","meaning":"sweat"},{"char":"马","meaning":"horse"},{"char":"功","meaning":"achievement"},{"char":"劳","meaning":"labor"}],"origin":{"period":"Han Dynasty (206 BCE – 220 CE)","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '汗马功劳' originates from the times when horses were essential in warfare. The phrase metaphorically describes the sweat and effort of horses in battle, symbolizing the hard work and achievements of soldiers. Over time, it has come to represent any significant contributions or achievements, not limited to military contexts.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["subject","object","attributive"],"structure":"modifier-head","register":"widely used in both formal and informal contexts","connotation":"positive","commonMistakes":"Learners might confuse this idiom with those that specifically refer to military achievements. However, '汗马功劳' can refer to any significant contribution, not just in a military context.","canStandAlone":false},"examples":[{"simplified":"他在公司的发展中立下了汗马功劳。","english":"He made significant contributions to the company's development.","traditional":"他在公司的發展中立下了汗馬功勞。"},{"simplified":"为了这次比赛的成功，大家都付出了汗马功劳。","english":"Everyone made great efforts for the success of this competition.","traditional":"為了這次比賽的成功，大家都付出了汗馬功勞。"}],"synonyms":["丰功伟绩"],"antonyms":[],"confusedWith":[{"id":"丰功伟绩","note":"While both refer to great achievements, '丰功伟绩' often emphasizes the magnitude of the achievements, whereas '汗马功劳' highlights the effort involved."}],"traditional":"汗馬功勞","pinyinOverride":null},{"id":"mei-wan-mei-liao","simplified":"没完没了","literalMeaning":"no end no finish","figurativeMeaning":"endless; never-ending","englishEquivalents":["never-ending","endless","unceasing"],"shortGloss":"endless; never-ending","characters":[{"char":"没","meaning":"not"},{"char":"完","meaning":"finish"},{"char":"没","meaning":"not"},{"char":"了","meaning":"end"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom 没完没了 is used to describe situations or actions that seem to go on indefinitely without a conclusion. It is often used to express frustration or annoyance at something that is dragging on without resolution.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"coordinate","register":"commonly used in both spoken and written Chinese","connotation":"negative","commonMistakes":"Learners might confuse 没完没了 with similar expressions like 无休止, which also means endless but is more formal. 没完没了 is more colloquial and often carries a sense of annoyance.","canStandAlone":false},"examples":[{"simplified":"他总是没完没了地抱怨。","english":"He is always complaining endlessly.","traditional":"他總是沒完沒了地抱怨。"},{"simplified":"这场会议没完没了，真让人疲惫。","english":"This meeting is never-ending and truly exhausting.","traditional":"這場會議沒完沒了，真讓人疲憊。"}],"synonyms":["无休止","无穷无尽"],"antonyms":["一了百了"],"confusedWith":[{"id":"无休止","note":"无休止 also means endless but is more formal and less colloquial than 没完没了."}],"traditional":"沒完沒了","pinyinOverride":null},{"id":"fei-fei-yang-yang","simplified":"沸沸扬扬","literalMeaning":"boiling and spreading","figurativeMeaning":"a situation full of noise and excitement; a commotion or uproar","englishEquivalents":["in a frenzy","in an uproar"],"shortGloss":"in a commotion or uproar","characters":[{"char":"沸","meaning":"boiling"},{"char":"沸","meaning":"boiling"},{"char":"扬","meaning":"spreading"},{"char":"扬","meaning":"spreading"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom 沸沸扬扬 is used to describe a situation that is lively and bustling, often with noise and excitement. It evokes the image of boiling water that is bubbling and spreading, symbolizing a scene of commotion or uproar. The exact origin of this idiom is unclear, but it has been used in Chinese literature and speech to convey the sense of a lively and chaotic atmosphere.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"AABB","register":"commonly used in both spoken and written Chinese to describe lively or chaotic situations","connotation":"neutral","commonMistakes":"Learners might confuse 沸沸扬扬 with similar-sounding idioms that describe noise, but this idiom specifically emphasizes a lively and bustling atmosphere, not just noise.","canStandAlone":false},"examples":[{"simplified":"新闻一出，整个城市都沸沸扬扬。","english":"As soon as the news broke, the whole city was in an uproar.","traditional":"新聞一齣，整個城市都沸沸揚揚。"},{"simplified":"他的演讲让会场沸沸扬扬。","english":"His speech set the conference hall in a frenzy.","traditional":"他的演講讓會場沸沸揚揚。"}],"synonyms":["热闹非凡","人声鼎沸"],"antonyms":["鸦雀无声"],"confusedWith":[{"id":"热火朝天","note":"热火朝天 emphasizes enthusiasm and activity, while 沸沸扬扬 emphasizes noise and commotion."}],"traditional":"沸沸揚揚","pinyinOverride":null},{"id":"jin-jin-you-wei","simplified":"津津有味","literalMeaning":"with relish and taste","figurativeMeaning":"to do something with great interest and pleasure","englishEquivalents":["with gusto","with keen interest"],"shortGloss":"with great interest and pleasure","characters":[{"char":"津","meaning":"relish, interest"},{"char":"津","meaning":"relish, interest"},{"char":"有","meaning":"have, possess"},{"char":"味","meaning":"taste, flavor"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '津津有味' is often used to describe someone who is deeply engaged in an activity, such as reading a book or eating a meal, with great enjoyment and interest. The phrase emphasizes the pleasure and enthusiasm with which the activity is undertaken.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["adverbial","complement"],"structure":"modifier-head","register":"common in both written and spoken Chinese, used in everyday contexts","connotation":"positive","commonMistakes":"Learners might confuse this idiom with similar expressions that describe interest but lack the element of enjoyment. It is important to note that '津津有味' implies both interest and pleasure.","canStandAlone":false},"examples":[{"simplified":"他津津有味地读着那本小说。","english":"He read the novel with great interest and pleasure.","traditional":"他津津有味地讀著那本小說。"},{"simplified":"孩子们津津有味地吃着妈妈做的晚餐。","english":"The children ate the dinner their mother made with gusto.","traditional":"孩子們津津有味地吃著媽媽做的晚餐。"}],"synonyms":["兴致勃勃"],"antonyms":[],"confusedWith":[{"id":"兴致勃勃","note":"While both idioms describe interest, '兴致勃勃' focuses more on enthusiasm and excitement, whereas '津津有味' emphasizes enjoyment and pleasure."}],"traditional":"津津有味","pinyinOverride":null},{"id":"shen-ru-ren-xin","simplified":"深入人心","literalMeaning":"deeply enter people's hearts","figurativeMeaning":"to be deeply ingrained in people's minds; to have a profound impact","englishEquivalents":["strike a chord","resonate with people"],"shortGloss":"deeply ingrained in people's minds","characters":[{"char":"深","meaning":"deep"},{"char":"入","meaning":"enter"},{"char":"人","meaning":"people"},{"char":"心","meaning":"heart"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '深入人心' is used to describe something that has a profound impact on people, such as an idea, a piece of art, or a movement. It suggests that the subject has resonated deeply with individuals, becoming a part of their thoughts and feelings.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"commonly used in both written and spoken Chinese, suitable for formal and informal contexts","connotation":"positive","commonMistakes":"Learners might confuse this idiom with expressions that mean 'popular' or 'well-known,' but '深入人心' emphasizes deep emotional or intellectual impact rather than mere popularity.","canStandAlone":false},"examples":[{"simplified":"这部电影的主题深入人心，让观众久久不能忘怀。","english":"The theme of this movie resonates deeply with the audience, leaving a lasting impression.","traditional":"這部電影的主題深入人心，讓觀眾久久不能忘懷。"},{"simplified":"他的演讲内容深入人心，激励了许多人。","english":"The content of his speech struck a chord with many, inspiring them.","traditional":"他的演講內容深入人心，激勵了許多人。"}],"synonyms":["感人肺腑"],"antonyms":[],"confusedWith":[{"id":"家喻户晓","note":"家喻户晓 means 'widely known,' focusing on popularity rather than deep impact."}],"traditional":"深入人心","pinyinOverride":null},{"id":"shen-qing-hou-yi","simplified":"深情厚谊","literalMeaning":"deep affection, thick friendship","figurativeMeaning":"profound friendship and deep affection","englishEquivalents":["deep friendship","strong bonds"],"shortGloss":"profound friendship","characters":[{"char":"深","meaning":"deep"},{"char":"情","meaning":"affection"},{"char":"厚","meaning":"thick, profound"},{"char":"谊","meaning":"friendship"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom 深情厚谊 is used to describe a relationship characterized by deep affection and strong bonds of friendship. It is often used in speeches or writings to express gratitude or to highlight the importance of a close and enduring relationship.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["subject","object","attributive"],"structure":"modifier-head","register":"commonly used in both formal and informal contexts to express strong emotional bonds","connotation":"positive","commonMistakes":"Learners might confuse 深情厚谊 with similar expressions that emphasize romantic love rather than friendship. It's important to note that this idiom specifically refers to non-romantic, platonic relationships.","canStandAlone":false},"examples":[{"simplified":"他们之间有着深情厚谊，几十年来一直保持联系。","english":"They have a profound friendship and have stayed in touch for decades.","traditional":"他們之間有著深情厚誼，幾十年來一直保持聯繫。"},{"simplified":"在这次聚会上，我们感受到了他对我们的深情厚谊。","english":"At this gathering, we felt his deep affection and strong bonds of friendship towards us.","traditional":"在這次聚會上，我們感受到了他對我們的深情厚誼。"}],"synonyms":["情深意重"],"antonyms":[],"confusedWith":[{"id":"深情厚爱","note":"深情厚爱 emphasizes romantic love, while 深情厚谊 focuses on friendship."}],"traditional":"深情厚誼","pinyinOverride":null},{"id":"yuanyuan-buduan","simplified":"源源不断","literalMeaning":"source source unceasing","figurativeMeaning":"to flow in an endless stream; continuously; unceasingly","englishEquivalents":["in a steady stream","unceasingly","endlessly"],"shortGloss":"in a steady stream","characters":[{"char":"源","meaning":"source; origin"},{"char":"源","meaning":"source; origin"},{"char":"不","meaning":"not; un-"},{"char":"断","meaning":"break; cease"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '源源不断' describes something that flows continuously and without interruption, like a river that keeps flowing. It is often used to describe resources, ideas, or people coming in a steady and unending stream.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["adverbial","attributive"],"structure":"modifier-head","register":"commonly used in both written and spoken Chinese","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with others that imply a sudden influx or a sporadic flow. '源源不断' specifically emphasizes a continuous and steady flow.","canStandAlone":false},"examples":[{"simplified":"新鲜的水果源源不断地运到市场。","english":"Fresh fruits are being delivered to the market in a steady stream.","traditional":"新鮮的水果源源不斷地運到市場。"},{"simplified":"他的灵感源源不断，创作了许多优秀的作品。","english":"His inspiration flows unceasingly, resulting in many excellent works.","traditional":"他的靈感源源不斷，創作了許多優秀的作品。"}],"synonyms":["络绎不绝","川流不息"],"antonyms":["断断续续"],"confusedWith":[{"id":"络绎不绝","note":"Both describe continuous flow, but '络绎不绝' often refers to people or vehicles, while '源源不断' can refer to a broader range of things."}],"traditional":"源源不斷","pinyinOverride":null},{"id":"yuan-yuan-liu-chang","simplified":"源远流长","literalMeaning":"source distant, flow long","figurativeMeaning":"having a long history and a far-reaching influence","englishEquivalents":["time-honored","of long standing"],"shortGloss":"long-standing and influential","characters":[{"char":"源","meaning":"source"},{"char":"远","meaning":"distant"},{"char":"流","meaning":"flow"},{"char":"长","meaning":"long"}],"origin":{"period":"Han Dynasty (206 BCE – 220 CE)","sourceText":"《文选·张衡·东京赋》","sourceTextEnglish":"Selections of Refined Literature, Zhang Heng, Ode to the Eastern Capital","originalExcerpt":"源远而流长，兹事体大。","storyEnglish":"The idiom comes from a work by Zhang Heng, a scholar and official of the Eastern Han Dynasty. In his 'Ode to the Eastern Capital,' he uses the phrase to describe the long and influential history of the capital city, Luoyang. The imagery of a river with a distant source and a long flow is used to convey the idea of a tradition or influence that is both ancient and enduring.","historicalFigures":["Zhang Heng"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"subject-predicate","register":"literary, but very widely understood and used in ordinary speech","connotation":"positive","commonMistakes":"Learners might confuse this idiom with those that describe something as simply 'old' without the connotation of influence or continuity. It specifically implies both a long history and ongoing impact.","canStandAlone":false},"examples":[{"simplified":"中华文化源远流长，影响深远。","english":"Chinese culture has a long history and far-reaching influence.","traditional":"中華文化源遠流長，影響深遠。"},{"simplified":"这座古城的历史源远流长，吸引了无数游客。","english":"The ancient city has a long-standing history that attracts countless tourists.","traditional":"這座古城的歷史源遠流長，吸引了無數遊客。"}],"synonyms":["历史悠久"],"antonyms":[],"confusedWith":[],"traditional":"源遠流長","pinyinOverride":null},{"id":"tao-tao-bu-jue","simplified":"滔滔不绝","literalMeaning":"unceasingly like a torrent","figurativeMeaning":"to talk on and on without stopping","englishEquivalents":["talk a mile a minute","talk endlessly","ramble on"],"shortGloss":"talk endlessly","characters":[{"char":"滔","meaning":"surging; overflowing"},{"char":"滔","meaning":"surging; overflowing"},{"char":"不","meaning":"not"},{"char":"绝","meaning":"cease; stop"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom 滔滔不绝 is often used to describe someone who talks continuously and at length, much like a river that flows without stopping. The imagery of a torrent conveys the idea of speech that is abundant and unending.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["adverbial","predicate"],"structure":"modifier-head","register":"commonly used in both spoken and written Chinese","connotation":"neutral","commonMistakes":"Learners often confuse 滔滔不绝 with idioms that imply talking nonsense or irrelevance, but 滔滔不绝 specifically refers to the continuous nature of speech, not its content.","canStandAlone":false},"examples":[{"simplified":"他对这个话题滔滔不绝地讲了一个小时。","english":"He talked endlessly about this topic for an hour.","traditional":"他對這個話題滔滔不絕地講了一個小時。"},{"simplified":"她总是滔滔不绝地分享她的旅行经历。","english":"She always talks endlessly about her travel experiences.","traditional":"她總是滔滔不絕地分享她的旅行經歷。"}],"synonyms":["口若悬河"],"antonyms":["沉默寡言"],"confusedWith":[{"id":"喋喋不休","note":"喋喋不休 also means to talk continuously, but often with a negative connotation of being annoying or repetitive."}],"traditional":"滔滔不絕","pinyinOverride":null},{"id":"qian-yi-mo-hua","simplified":"潜移默化","literalMeaning":"subtly change silently transform","figurativeMeaning":"to influence or change someone or something gradually and imperceptibly","englishEquivalents":["to influence imperceptibly","to change subtly","gradual influence"],"shortGloss":"gradually influence or change","characters":[{"char":"潜","meaning":"subtly, quietly"},{"char":"移","meaning":"change, shift"},{"char":"默","meaning":"silently, quietly"},{"char":"化","meaning":"transform, influence"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom 潜移默化 describes the process of influencing or changing someone or something in a subtle and gradual manner, often without the person being aware of the change. It emphasizes the quiet and imperceptible nature of the transformation.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["adverbial","attributive"],"structure":"modifier-head","register":"commonly used in both written and spoken Chinese, suitable for formal and informal contexts","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with those that imply a more direct or immediate influence. 潜移默化 emphasizes a gradual, almost unnoticed change.","canStandAlone":false},"examples":[{"simplified":"他的性格在这些年的潜移默化中变得更加成熟。","english":"His character has matured over the years through subtle influences.","traditional":"他的性格在這些年的潛移默化中變得更加成熟。"},{"simplified":"在父母的潜移默化下，她逐渐养成了良好的习惯。","english":"Under the subtle influence of her parents, she gradually developed good habits.","traditional":"在父母的潛移默化下，她逐漸養成了良好的習慣。"}],"synonyms":["耳濡目染"],"antonyms":[],"confusedWith":[{"id":"耳濡目染","note":"耳濡目染 emphasizes influence through exposure to sights and sounds, while 潜移默化 emphasizes a more subtle, gradual change."}],"traditional":"潛移默化","pinyinOverride":null},{"id":"ling-ji-yi-dong","simplified":"灵机一动","literalMeaning":"a clever idea suddenly moves","figurativeMeaning":"to have a sudden clever idea or inspiration","englishEquivalents":["a lightbulb moment","a stroke of genius","an aha moment"],"shortGloss":"a sudden clever idea","characters":[{"char":"灵","meaning":"clever, quick-witted"},{"char":"机","meaning":"opportunity, moment"},{"char":"一","meaning":"one, a single"},{"char":"动","meaning":"move, stir"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '灵机一动' describes a moment when someone suddenly comes up with a clever idea or solution to a problem. It is often used to depict a flash of inspiration or a sudden realization that leads to solving a difficult situation.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"widely used in both spoken and written Chinese, suitable for informal and formal contexts","connotation":"positive","commonMistakes":"Learners might confuse this idiom with '灵光一闪', which also refers to a sudden idea but emphasizes the fleeting nature of the thought. '灵机一动' suggests a more substantial and actionable idea.","canStandAlone":false},"examples":[{"simplified":"他正在苦思冥想，突然灵机一动，想出了一个好办法。","english":"He was racking his brains when he suddenly had a lightbulb moment and came up with a good solution.","traditional":"他正在苦思冥想，突然靈機一動，想出了一個好辦法。"},{"simplified":"在比赛的最后一分钟，她灵机一动，改变了策略。","english":"In the last minute of the game, she had a stroke of genius and changed her strategy.","traditional":"在比賽的最後一分鐘，她靈機一動，改變了策略。"}],"synonyms":["灵光一闪"],"antonyms":[],"confusedWith":[{"id":"灵光一闪","note":"Both idioms refer to sudden ideas, but '灵光一闪' emphasizes a brief, fleeting thought, while '灵机一动' suggests a more practical and actionable idea."}],"traditional":"靈機一動","pinyinOverride":null},{"id":"re-lei-ying-kuang","simplified":"热泪盈眶","literalMeaning":"hot tears fill the eyes","figurativeMeaning":"to be moved to tears; deeply touched or emotional","englishEquivalents":["moved to tears","tearful with emotion"],"shortGloss":"moved to tears","characters":[{"char":"热","meaning":"hot"},{"char":"泪","meaning":"tears"},{"char":"盈","meaning":"to fill"},{"char":"眶","meaning":"eye socket"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '热泪盈眶' describes the feeling of being so moved or emotional that one's eyes fill with tears. It is often used to express profound gratitude, joy, or sorrow. The exact origin of this idiom is unclear, but it has been widely used in Chinese literature and speech to convey deep emotional responses.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"subject-predicate","register":"commonly used in both written and spoken Chinese to express deep emotion","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with expressions that describe physical pain rather than emotional response. It's important to remember that this idiom specifically conveys being emotionally moved.","canStandAlone":false},"examples":[{"simplified":"听到这个好消息，她感动得热泪盈眶。","english":"Hearing the good news, she was moved to tears.","traditional":"聽到這個好消息，她感動得熱淚盈眶。"},{"simplified":"他的演讲如此感人，许多人都热泪盈眶。","english":"His speech was so touching that many people were moved to tears.","traditional":"他的演講如此感人，許多人都熱淚盈眶。"}],"synonyms":["感人肺腑"],"antonyms":[],"confusedWith":[],"traditional":"熱淚盈眶","pinyinOverride":null},{"id":"huan-ran-yi-xin","simplified":"焕然一新","literalMeaning":"shining and completely new","figurativeMeaning":"to take on an entirely new look; to be completely transformed","englishEquivalents":["brand new","a fresh start","completely transformed"],"shortGloss":"completely transformed","characters":[{"char":"焕","meaning":"shining; bright"},{"char":"然","meaning":"like; as if"},{"char":"一","meaning":"one; completely"},{"char":"新","meaning":"new"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom 焕然一新 is used to describe something that has been completely transformed or renewed, often in appearance. It conveys the idea of something looking fresh and new, as if it has been given a new lease on life. The origin of this idiom is not tied to a specific classical text, but it has been used in Chinese literature and speech to express the idea of renewal and transformation.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"modifier-head","register":"widely used in both written and spoken Chinese","connotation":"positive","commonMistakes":"Learners might confuse 焕然一新 with idioms that simply mean 'new' without the implication of transformation. It's important to use it in contexts where a significant change or renewal has occurred.","canStandAlone":false},"examples":[{"simplified":"经过装修，房子焕然一新。","english":"After the renovation, the house was completely transformed.","traditional":"經過裝修，房子煥然一新。"},{"simplified":"她换了发型，看起来焕然一新。","english":"She changed her hairstyle and looked completely transformed.","traditional":"她換了髮型，看起來煥然一新。"}],"synonyms":["耳目一新"],"antonyms":[],"confusedWith":[{"id":"焕发青春","note":"焕发青春 specifically refers to regaining youthful vitality, while 焕然一新 refers to a complete transformation or renewal in appearance or condition."}],"traditional":"煥然一新","pinyinOverride":null},{"id":"xi-xi-rang-rang","simplified":"熙熙攘攘","literalMeaning":"bustling and crowded","figurativeMeaning":"bustling with activity; crowded and lively","englishEquivalents":["bustling with activity","hustle and bustle"],"shortGloss":"bustling with activity","characters":[{"char":"熙","meaning":"prosperous; bustling"},{"char":"熙","meaning":"prosperous; bustling"},{"char":"攘","meaning":"crowded; bustling"},{"char":"攘","meaning":"crowded; bustling"}],"origin":{"period":"Warring States period (475–221 BCE)","sourceText":"《孟子·滕文公上》","sourceTextEnglish":"Mencius, Teng Wen Gong I","originalExcerpt":"滕文公问曰：“滕小国也，间于齐楚，事齐乎？事楚乎？”孟子对曰：“是谋非吾所能及也。熙熙攘攘，天下皆是也。”","storyEnglish":"In the text of Mencius, the ruler of the small state of Teng asks Mencius whether they should serve the state of Qi or Chu. Mencius responds that such political strategies are beyond his expertise, and he describes the world as '熙熙攘攘', indicating that everywhere is bustling and crowded with people pursuing their own interests.","historicalFigures":["Mencius","Teng Wen Gong"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"AABB","register":"commonly used in both written and spoken Chinese","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with others that describe chaos or disorder, but '熙熙攘攘' specifically conveys a sense of lively activity, not chaos.","canStandAlone":false},"examples":[{"simplified":"节日期间，商场里熙熙攘攘，人山人海。","english":"During the holidays, the mall is bustling with activity and packed with people.","traditional":"節日期間，商場裡熙熙攘攘，人山人海。"},{"simplified":"早晨的市场熙熙攘攘，充满了活力。","english":"The morning market is bustling with activity and full of energy.","traditional":"早晨的市場熙熙攘攘，充滿了活力。"}],"synonyms":["人声鼎沸","车水马龙"],"antonyms":["冷冷清清"],"confusedWith":[{"id":"乱七八糟","note":"乱七八糟 means messy or chaotic, whereas 熙熙攘攘 refers to lively and bustling activity."}],"traditional":"熙熙攘攘","pinyinOverride":null},{"id":"ai-bu-shi-shou","simplified":"爱不释手","literalMeaning":"love it so much that one cannot let go","figurativeMeaning":"to be so fond of something that one cannot bear to part with it","englishEquivalents":["can't put it down","attached to it","fond of it"],"shortGloss":"so fond of it, can't let go","characters":[{"char":"爱","meaning":"love"},{"char":"不","meaning":"not"},{"char":"释","meaning":"release"},{"char":"手","meaning":"hand"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '爱不释手' describes a situation where someone is so enamored with an object that they cannot bring themselves to put it down. It is often used to describe a deep fondness or attachment to something, such as a book, a gift, or a new gadget.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","complement"],"structure":"subject-predicate","register":"widely used in both spoken and written Chinese, suitable for informal and formal contexts","connotation":"positive","commonMistakes":"Learners might confuse this idiom with similar expressions that imply physical attachment, but '爱不释手' specifically conveys emotional attachment or fondness. It is not used for people, only objects.","canStandAlone":false},"examples":[{"simplified":"这本书太好看了，我爱不释手。","english":"This book is so good, I can't put it down.","traditional":"這本書太好看了，我愛不釋手。"},{"simplified":"他对新手机爱不释手，整天都在玩。","english":"He is so fond of his new phone that he plays with it all day.","traditional":"他對新手機愛不釋手，整天都在玩。"}],"synonyms":["爱不忍释"],"antonyms":[],"confusedWith":[{"id":"手不释卷","note":"手不释卷 specifically refers to being engrossed in reading, while 爱不释手 can refer to any object."}],"traditional":"愛不釋手","pinyinOverride":null},{"id":"wu-mei-jia-lian","simplified":"物美价廉","literalMeaning":"goods beautiful price cheap","figurativeMeaning":"high quality and inexpensive","englishEquivalents":["good value for money","bang for the buck"],"shortGloss":"high quality and inexpensive","characters":[{"char":"物","meaning":"goods; products"},{"char":"美","meaning":"beautiful; excellent"},{"char":"价","meaning":"price"},{"char":"廉","meaning":"cheap; inexpensive"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '物美价廉' is used to describe products that are both high in quality and low in price. It is a common expression in modern Chinese to praise goods that provide good value for money. The origin of this idiom is not tied to a specific classical text, but it reflects a universal appreciation for getting a good deal.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"coordinate","register":"commonly used in both spoken and written Chinese","connotation":"positive","commonMistakes":"Learners might confuse this idiom with phrases that only emphasize low price without considering quality. It is important to remember that '物美价廉' implies both good quality and affordability.","canStandAlone":false},"examples":[{"simplified":"这家店的商品物美价廉，吸引了很多顾客。","english":"The products in this store are high quality and inexpensive, attracting many customers.","traditional":"這家店的商品物美價廉，吸引了很多顧客。"},{"simplified":"他总是能找到物美价廉的东西。","english":"He always manages to find things that are high quality and inexpensive.","traditional":"他總是能找到物美價廉的東西。"}],"synonyms":["价廉物美"],"antonyms":[],"confusedWith":[{"id":"价廉物美","note":"This is essentially the same idiom with the order of 'price' and 'quality' reversed, but the meaning remains unchanged."}],"traditional":"物美價廉","pinyinOverride":null},{"id":"you-yu-bu-jue","simplified":"犹豫不决","literalMeaning":"hesitate not decide","figurativeMeaning":"to be indecisive or hesitant","englishEquivalents":["sit on the fence","waffle","be on the fence"],"shortGloss":"indecisive; hesitant","characters":[{"char":"犹","meaning":"hesitate"},{"char":"豫","meaning":"hesitate"},{"char":"不","meaning":"not"},{"char":"决","meaning":"decide"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '犹豫不决' describes a state of being unable to make a decision due to hesitation or uncertainty. It is commonly used to describe someone who is wavering between options and unable to commit to a choice.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"coordinate","register":"widely used in both formal and informal contexts","connotation":"negative","commonMistakes":"Learners often confuse '犹豫不决' with '举棋不定', which also means indecisive but is more specifically used in contexts involving strategic decisions, like chess. '犹豫不决' is more general.","canStandAlone":false},"examples":[{"simplified":"在选择大学时，他总是犹豫不决。","english":"When choosing a university, he was always indecisive.","traditional":"在選擇大學時，他總是猶豫不決。"},{"simplified":"她犹豫不决，不知道该不该接受这个工作机会。","english":"She was hesitant and didn't know whether to accept the job offer.","traditional":"她猶豫不決，不知道該不該接受這個工作機會。"}],"synonyms":["举棋不定"],"antonyms":["果断决策"],"confusedWith":[{"id":"举棋不定","note":"Both mean indecisive, but '举棋不定' is often used in strategic contexts."}],"traditional":"猶豫不決","pinyinOverride":null},{"id":"du-yi-wu-er","simplified":"独一无二","literalMeaning":"only one, no second","figurativeMeaning":"unique; unparalleled","englishEquivalents":["one of a kind","unique","unparalleled"],"shortGloss":"unique; unparalleled","characters":[{"char":"独","meaning":"only; alone"},{"char":"一","meaning":"one"},{"char":"无","meaning":"without; no"},{"char":"二","meaning":"two; second"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom 独一无二 is used to describe something or someone that is unique and unparalleled, emphasizing that there is no other like it. It is often used to highlight the distinctiveness or rarity of an object, person, or situation.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["attributive","predicate"],"structure":"modifier-head","register":"widely used in both spoken and written Chinese","connotation":"positive","commonMistakes":"Learners sometimes confuse 独一无二 with similar expressions that imply rarity but not uniqueness, such as 绝无仅有. 独一无二 emphasizes that there is nothing else like it.","canStandAlone":false},"examples":[{"simplified":"这幅画的风格独一无二。","english":"The style of this painting is unique.","traditional":"這幅畫的風格獨一無二。"},{"simplified":"他的才华在公司里是独一无二的。","english":"His talent is unparalleled in the company.","traditional":"他的才華在公司裡是獨一無二的。"}],"synonyms":["无与伦比","绝无仅有"],"antonyms":[],"confusedWith":[{"id":"绝无仅有","note":"绝无仅有 means extremely rare, but not necessarily unique."}],"traditional":"獨一無二","pinyinOverride":null},{"id":"lang-tun-hu-yan","simplified":"狼吞虎咽","literalMeaning":"wolf down, tiger swallow","figurativeMeaning":"to gobble up food ravenously","englishEquivalents":["wolf down","gobble up","eat like a horse"],"shortGloss":"eat ravenously","characters":[{"char":"狼","meaning":"wolf"},{"char":"吞","meaning":"swallow"},{"char":"虎","meaning":"tiger"},{"char":"咽","meaning":"gulp"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '狼吞虎咽' is believed to describe the way wolves and tigers eat their prey, quickly and voraciously. It is used to depict someone eating in a very fast and greedy manner, as if they were a wild animal devouring its meal.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["adverbial","predicate"],"structure":"coordinate","register":"commonly used in both spoken and written Chinese to describe eating habits","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with others that describe speed or greed in contexts other than eating. It's specifically about eating quickly and greedily.","canStandAlone":false},"examples":[{"simplified":"他饿坏了，坐下来就狼吞虎咽地吃起来。","english":"He was starving and sat down to gobble up his food ravenously.","traditional":"他餓壞了，坐下來就狼吞虎嚥地吃起來。"},{"simplified":"孩子们放学回家后，总是狼吞虎咽地吃点心。","english":"The children always gobble up their snacks ravenously after school.","traditional":"孩子們放學回家後，總是狼吞虎嚥地吃點心。"}],"synonyms":["饥不择食"],"antonyms":[],"confusedWith":[{"id":"囫囵吞枣","note":"囫囵吞枣 means to swallow something whole without understanding it, not related to eating quickly."}],"traditional":"狼吞虎嚥","pinyinOverride":null},{"id":"li-suo-dang-ran","simplified":"理所当然","literalMeaning":"reason that is naturally so","figurativeMeaning":"something that is taken for granted or considered as a matter of course","englishEquivalents":["as a matter of course","naturally","self-evident"],"shortGloss":"taken for granted","characters":[{"char":"理","meaning":"reason; logic"},{"char":"所","meaning":"that which; place"},{"char":"当","meaning":"ought to; should"},{"char":"然","meaning":"so; thus"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '理所当然' is used to describe something that is considered obvious or expected without needing further explanation. It reflects the idea that certain things are inherently logical or natural, and therefore do not require justification.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"modifier-head","register":"widely used in both formal and informal contexts","connotation":"neutral","commonMistakes":"Learners often use this idiom to describe things that are not actually self-evident or obvious, which can lead to misunderstandings. It's important to ensure that the context truly supports the idea of something being naturally expected.","canStandAlone":false},"examples":[{"simplified":"他认为自己应该得到这份工作是理所当然的。","english":"He thinks it's only natural that he should get the job.","traditional":"他認為自己應該得到這份工作是理所當然的。"},{"simplified":"在这种情况下，帮助朋友是理所当然的。","english":"In this situation, helping a friend is taken for granted.","traditional":"在這種情況下，幫助朋友是理所當然的。"}],"synonyms":["天经地义","不言而喻"],"antonyms":["不可思议"],"confusedWith":[{"id":"理直气壮","note":"理直气壮 means to speak or act with confidence due to being in the right, while 理所当然 refers to something being self-evident or taken for granted."}],"traditional":"理所當然","pinyinOverride":null},{"id":"li-zhi-qi-zhuang","simplified":"理直气壮","literalMeaning":"reason straight, spirit robust","figurativeMeaning":"to speak or act with confidence because one is in the right","englishEquivalents":["speak with confidence","stand one's ground"],"shortGloss":"confidently assertive","characters":[{"char":"理","meaning":"reason; logic"},{"char":"直","meaning":"straight; upright"},{"char":"气","meaning":"spirit; energy"},{"char":"壮","meaning":"robust; strong"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '理直气壮' is used to describe someone who is confident and assertive because they believe they are justified or correct. It emphasizes the moral or logical strength behind one's actions or words, allowing them to act with boldness and assurance.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"coordinate","register":"commonly used in both spoken and written Chinese","connotation":"positive","commonMistakes":"Learners often confuse '理直气壮' with being aggressive or confrontational, but it specifically implies confidence due to being right, not just forcefulness.","canStandAlone":false},"examples":[{"simplified":"他在会议上理直气壮地提出了自己的观点。","english":"He confidently presented his views at the meeting.","traditional":"他在會議上理直氣壯地提出了自己的觀點。"},{"simplified":"因为有充分的证据，她理直气壮地反驳了对方的指控。","english":"With ample evidence, she confidently refuted the accusations.","traditional":"因為有充分的證據，她理直氣壯地反駁了對方的指控。"}],"synonyms":["义正词严"],"antonyms":["理屈词穷"],"confusedWith":[{"id":"咄咄逼人","note":"While '咄咄逼人' implies being aggressive or overbearing, '理直气壮' emphasizes confidence due to being right."}],"traditional":"理直氣壯","pinyinOverride":null},{"id":"qin-qi-shu-hua","simplified":"琴棋书画","literalMeaning":"zither, chess, calligraphy, painting","figurativeMeaning":"the four arts of the Chinese scholar; refined cultural pursuits","englishEquivalents":["the four arts","cultural refinement"],"shortGloss":"the four arts of the Chinese scholar","characters":[{"char":"琴","meaning":"zither, referring to the guqin, a traditional Chinese musical instrument"},{"char":"棋","meaning":"chess, referring to the game of Go (围棋)"},{"char":"书","meaning":"calligraphy, the art of writing Chinese characters"},{"char":"画","meaning":"painting, the art of Chinese brush painting"}],"origin":{"period":"Tang dynasty (618–907)","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '琴棋书画' refers to the four traditional arts that were considered essential for a cultured Chinese scholar. These arts are playing the guqin (a type of zither), playing the game of Go, practicing calligraphy, and creating brush paintings. Mastery of these arts was seen as a mark of a well-rounded and refined individual in ancient Chinese society.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["subject","object","attributive"],"structure":"coordinate","register":"literary, but widely understood and used in ordinary speech","connotation":"positive","commonMistakes":"Learners sometimes use this idiom to refer to any artistic activity, but it specifically refers to these four traditional arts. It should not be confused with idioms that refer to modern or Western arts.","canStandAlone":false},"examples":[{"simplified":"他从小就学习琴棋书画，是个很有文化的人。","english":"He has been learning the four arts since childhood and is a very cultured person.","traditional":"他從小就學習琴棋書畫，是個很有文化的人。"},{"simplified":"在古代，琴棋书画是文人必备的技能。","english":"In ancient times, the four arts were essential skills for scholars.","traditional":"在古代，琴棋書畫是文人必備的技能。"}],"synonyms":[],"antonyms":[],"confusedWith":[],"traditional":"琴棋書畫","pinyinOverride":null},{"id":"jie-da-huan-xi","simplified":"皆大欢喜","literalMeaning":"all greatly happy","figurativeMeaning":"everyone is happy; a win-win situation","englishEquivalents":["everyone is happy","a win-win situation"],"shortGloss":"everyone is happy","characters":[{"char":"皆","meaning":"all"},{"char":"大","meaning":"greatly"},{"char":"欢","meaning":"happy"},{"char":"喜","meaning":"joyful"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '皆大欢喜' is often used to describe a situation where all parties involved are satisfied and happy with the outcome. It is commonly used in contexts where a compromise or solution is reached that benefits everyone.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"modifier-head","register":"commonly used in both spoken and written Chinese","connotation":"positive","commonMistakes":"Learners might mistakenly use this idiom in contexts where not all parties are satisfied. It should only be used when the outcome is genuinely positive for everyone involved.","canStandAlone":false},"examples":[{"simplified":"经过调解，双方皆大欢喜地达成了协议。","english":"After mediation, both parties happily reached an agreement.","traditional":"經過調解，雙方皆大歡喜地達成了協議。"},{"simplified":"这个方案让所有人皆大欢喜。","english":"This plan makes everyone happy.","traditional":"這個方案讓所有人皆大歡喜。"}],"synonyms":[],"antonyms":[],"confusedWith":[],"traditional":"皆大歡喜","pinyinOverride":null},{"id":"sheng-qi-ling-ren","simplified":"盛气凌人","literalMeaning":"arrogant air oppresses others","figurativeMeaning":"to be overbearing or domineering","englishEquivalents":["high and mighty","overbearing","domineering"],"shortGloss":"overbearing or domineering","characters":[{"char":"盛","meaning":"arrogant, haughty"},{"char":"气","meaning":"air, manner"},{"char":"凌","meaning":"to oppress, to bully"},{"char":"人","meaning":"others, people"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '盛气凌人' describes a person who carries themselves with an air of arrogance, often looking down on others and behaving in a domineering manner. The phrase is commonly used to criticize someone who is perceived as overbearing.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"modifier-head","register":"commonly used in both spoken and written Chinese to describe arrogant behavior","connotation":"negative","commonMistakes":"Learners might confuse this idiom with positive expressions of confidence. However, '盛气凌人' specifically implies a negative, overbearing attitude rather than mere confidence.","canStandAlone":false},"examples":[{"simplified":"他总是盛气凌人，让人很不舒服。","english":"He is always overbearing, which makes people very uncomfortable.","traditional":"他總是盛氣凌人，讓人很不舒服。"},{"simplified":"她用盛气凌人的态度对待同事，结果大家都不愿意和她合作。","english":"She treated her colleagues with a domineering attitude, and as a result, no one wanted to work with her.","traditional":"她用盛氣凌人的態度對待同事，結果大家都不願意和她合作。"}],"synonyms":["咄咄逼人"],"antonyms":["平易近人"],"confusedWith":[{"id":"自信满满","note":"While '自信满满' means full of confidence, '盛气凌人' implies a negative, overbearing attitude."}],"traditional":"盛氣凌人","pinyinOverride":null},{"id":"mu-bu-zhuan-jing","simplified":"目不转睛","literalMeaning":"eyes not turning pupils","figurativeMeaning":"to stare fixedly; to watch attentively without distraction","englishEquivalents":["to be glued to","to be riveted","to be transfixed"],"shortGloss":"to stare intently","characters":[{"char":"目","meaning":"eyes"},{"char":"不","meaning":"not"},{"char":"转","meaning":"turn"},{"char":"睛","meaning":"pupils"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '目不转睛' describes the action of staring intently at something without moving one's eyes. It conveys a sense of deep focus and concentration, often used when someone is completely absorbed in watching something or someone.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"commonly used in both spoken and written Chinese","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with others that involve looking or seeing, such as '目不暇接', which means being overwhelmed by the sight of many things. '目不转睛' specifically emphasizes the act of staring intently without distraction.","canStandAlone":false},"examples":[{"simplified":"他目不转睛地盯着屏幕，完全忘记了时间。","english":"He stared at the screen without blinking, completely losing track of time.","traditional":"他目不轉睛地盯著屏幕，完全忘記了時間。"},{"simplified":"孩子们目不转睛地看着魔术表演。","english":"The children watched the magic show with rapt attention.","traditional":"孩子們目不轉睛地看著魔術表演。"}],"synonyms":["聚精会神"],"antonyms":["心不在焉"],"confusedWith":[{"id":"目不暇接","note":"目不暇接 means being overwhelmed by many things to see, while 目不转睛 means focusing intently on one thing."}],"traditional":"目不轉睛","pinyinOverride":null},{"id":"mu-zhong-wu-ren","simplified":"目中无人","literalMeaning":"eyes contain no one","figurativeMeaning":"to be arrogant and consider everyone else beneath oneself","englishEquivalents":["look down on others","high and mighty","full of oneself"],"shortGloss":"arrogant; looks down on others","characters":[{"char":"目","meaning":"eyes"},{"char":"中","meaning":"in; within"},{"char":"无","meaning":"no; none"},{"char":"人","meaning":"people; person"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '目中无人' is used to describe someone who is so arrogant that they see no one else as worthy of their attention or respect. It conveys the image of a person whose eyes metaphorically contain no other people, indicating a lack of regard for others.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"modifier-head","register":"commonly used in both spoken and written Chinese to describe arrogance","connotation":"negative","commonMistakes":"Learners often confuse this idiom with '目不识丁' which means 'illiterate'. '目中无人' specifically refers to arrogance, not ignorance or lack of education.","canStandAlone":false},"examples":[{"simplified":"他总是目中无人，难怪没有朋友。","english":"He is always so arrogant, no wonder he has no friends.","traditional":"他總是目中無人，難怪沒有朋友。"},{"simplified":"她的成功让她变得目中无人。","english":"Her success has made her arrogant.","traditional":"她的成功讓她變得目中無人。"}],"synonyms":["自高自大","不可一世"],"antonyms":["谦虚谨慎"],"confusedWith":[{"id":"目不识丁","note":"目不识丁 means 'illiterate', not related to arrogance."}],"traditional":"目中無人","pinyinOverride":null},{"id":"mu-deng-kou-dai","simplified":"目瞪口呆","literalMeaning":"eyes stare, mouth agape","figurativeMeaning":"to be dumbfounded or stunned","englishEquivalents":["dumbstruck","stunned","flabbergasted"],"shortGloss":"dumbfounded","characters":[{"char":"目","meaning":"eyes"},{"char":"瞪","meaning":"stare"},{"char":"口","meaning":"mouth"},{"char":"呆","meaning":"agape; stupefied"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '目瞪口呆' is used to describe a state of being so surprised or shocked that one is left staring with wide eyes and an open mouth. It captures the physical reaction of being utterly stunned by an unexpected event or revelation.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","complement"],"structure":"coordinate","register":"commonly used in both spoken and written Chinese, informal contexts","connotation":"neutral","commonMistakes":"Learners often confuse this idiom with others that describe surprise, but '目瞪口呆' specifically conveys a sense of being so shocked that one is temporarily speechless or unable to react.","canStandAlone":false},"examples":[{"simplified":"听到这个消息后，他目瞪口呆，不知道该说什么。","english":"Upon hearing the news, he was dumbfounded and didn't know what to say.","traditional":"聽到這個消息後，他目瞪口呆，不知道該說什麼。"},{"simplified":"看到如此壮观的景象，游客们都目瞪口呆。","english":"The tourists were all stunned by the spectacular sight.","traditional":"看到如此壯觀的景象，遊客們都目瞪口呆。"}],"synonyms":["瞠目结舌"],"antonyms":[],"confusedWith":[{"id":"瞠目结舌","note":"Both describe surprise, but '瞠目结舌' emphasizes being too shocked to speak, while '目瞪口呆' focuses on the physical reaction of staring and being agape."}],"traditional":"目瞪口呆","pinyinOverride":null},{"id":"xiang-ti-bing-lun","simplified":"相提并论","literalMeaning":"mention together and discuss","figurativeMeaning":"to mention two things together as if they are comparable, often implying they are not","englishEquivalents":["compare apples and oranges","lump together"],"shortGloss":"to compare two unlike things","characters":[{"char":"相","meaning":"each other, mutual"},{"char":"提","meaning":"mention, bring up"},{"char":"并","meaning":"together, simultaneously"},{"char":"论","meaning":"discuss, debate"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '相提并论' is used to describe the act of comparing two things that are not truly comparable. It often carries a negative connotation, suggesting that the comparison is inappropriate or that the two items are of different natures or qualities. The phrase is commonly used to caution against making such comparisons.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","object"],"structure":"verb-object","register":"widely used in both formal and informal contexts","connotation":"negative","commonMistakes":"Learners often use this idiom to suggest that two things are comparable, but it actually implies they are not. It's important to use it when highlighting inappropriate comparisons.","canStandAlone":false},"examples":[{"simplified":"这两种产品质量差距太大，不能相提并论。","english":"The quality gap between these two products is too large to compare them.","traditional":"這兩種產品質量差距太大，不能相提並論。"},{"simplified":"他的工作经验和你的完全不同，不能相提并论。","english":"His work experience is completely different from yours and cannot be compared.","traditional":"他的工作經驗和你的完全不同，不能相提並論。"}],"synonyms":[],"antonyms":["天壤之别"],"confusedWith":[{"id":"等量齐观","note":"等量齐观 suggests treating different things as equal, while 相提并论 highlights inappropriate comparisons."}],"traditional":"相提並論","pinyinOverride":null},{"id":"xiang-fu-xiang-cheng","simplified":"相辅相成","literalMeaning":"mutually assist and mutually complement","figurativeMeaning":"to complement each other; to work together to achieve a better result","englishEquivalents":["complement each other","work hand in hand","go hand in hand"],"shortGloss":"complement each other","characters":[{"char":"相","meaning":"mutually"},{"char":"辅","meaning":"assist"},{"char":"相","meaning":"mutually"},{"char":"成","meaning":"accomplish; complement"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '相辅相成' describes a situation where two or more elements or people work together harmoniously, each enhancing the other's qualities to achieve a greater outcome. The concept is often used to describe partnerships or collaborations where the strengths of each party complement and enhance the overall result.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"coordinate","register":"widely used in both formal and informal contexts","connotation":"positive","commonMistakes":"Learners sometimes confuse this idiom with '互相帮助' (mutually help), which focuses more on mutual aid rather than the complementary aspect. '相辅相成' emphasizes the idea of mutual enhancement and synergy.","canStandAlone":false},"examples":[{"simplified":"这两种方法相辅相成，可以更好地解决问题。","english":"These two methods complement each other and can solve the problem better.","traditional":"這兩種方法相輔相成，可以更好地解決問題。"},{"simplified":"在团队中，每个人的技能相辅相成，使得项目进展顺利。","english":"In the team, everyone's skills complement each other, which makes the project progress smoothly.","traditional":"在團隊中，每個人的技能相輔相成，使得項目進展順利。"}],"synonyms":["互相补充"],"antonyms":[],"confusedWith":[{"id":"互相帮助","note":"While '互相帮助' means mutual help, '相辅相成' emphasizes complementing and enhancing each other."}],"traditional":"相輔相成","pinyinOverride":null},{"id":"mei-kai-yan-xiao","simplified":"眉开眼笑","literalMeaning":"eyebrows open, eyes smile","figurativeMeaning":"to beam with joy; to be all smiles","englishEquivalents":["grinning from ear to ear","beaming with joy"],"shortGloss":"beaming with joy","characters":[{"char":"眉","meaning":"eyebrow"},{"char":"开","meaning":"open"},{"char":"眼","meaning":"eye"},{"char":"笑","meaning":"smile"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '眉开眼笑' describes a person's facial expression when they are extremely happy or pleased. It paints a vivid picture of someone whose eyebrows are raised and eyes are smiling, conveying a sense of joy and satisfaction. This expression is commonly used in everyday conversation to describe someone who is visibly delighted.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","complement"],"structure":"coordinate","register":"widely used in both spoken and written Chinese, informal","connotation":"positive","commonMistakes":"Learners might confuse this idiom with others that describe facial expressions, but '眉开眼笑' specifically conveys a sense of joy and happiness. It should not be used to describe someone who is merely content or calm.","canStandAlone":false},"examples":[{"simplified":"听到这个好消息，她立刻眉开眼笑。","english":"Upon hearing the good news, she immediately beamed with joy.","traditional":"聽到這個好消息，她立刻眉開眼笑。"},{"simplified":"孩子们看到礼物，个个眉开眼笑。","english":"The children were all smiles when they saw the gifts.","traditional":"孩子們看到禮物，個個眉開眼笑。"}],"synonyms":["喜笑颜开"],"antonyms":["愁眉苦脸"],"confusedWith":[{"id":"笑逐颜开","note":"Both describe happiness, but '笑逐颜开' emphasizes a more gradual unfolding of a smile."}],"traditional":"眉開眼笑","pinyinOverride":null},{"id":"zhi-zu-chang-le","simplified":"知足常乐","literalMeaning":"know contentment, always happy","figurativeMeaning":"contentment brings happiness; being satisfied with what one has leads to happiness","englishEquivalents":["Contentment is happiness","Happiness lies in contentment"],"shortGloss":"contentment brings happiness","characters":[{"char":"知","meaning":"know"},{"char":"足","meaning":"contentment"},{"char":"常","meaning":"always"},{"char":"乐","meaning":"happy"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom 知足常乐 emphasizes the idea that happiness comes from being content with what one has. It suggests that those who are satisfied with their current situation and do not constantly strive for more will find happiness more easily. This concept is a common theme in various philosophical and religious teachings, but the specific origin of the idiom is not clearly traceable to a single classical text.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","standalone-exclamation"],"structure":"subject-predicate","register":"widely used in both spoken and written Chinese, suitable for both formal and informal contexts","connotation":"positive","commonMistakes":"Learners might confuse this idiom with similar expressions about happiness, but it's specifically about finding happiness through contentment, not through external achievements or possessions.","canStandAlone":true},"examples":[{"simplified":"他总是知足常乐，从不抱怨。","english":"He is always content and happy, never complaining.","traditional":"他總是知足常樂，從不抱怨。"},{"simplified":"知足常乐是我生活的座右铭。","english":"Contentment brings happiness is my life's motto.","traditional":"知足常樂是我生活的座右銘。"}],"synonyms":["随遇而安"],"antonyms":["得寸进尺"],"confusedWith":[{"id":"得过且过","note":"While both involve a sense of contentment, 得过且过 implies a lack of ambition or effort, whereas 知足常乐 emphasizes happiness through contentment."}],"traditional":"知足常樂","pinyinOverride":null},{"id":"li-shang-wang-lai","simplified":"礼尚往来","literalMeaning":"courtesy values mutual exchange","figurativeMeaning":"courtesy demands reciprocity; to return politeness for politeness","englishEquivalents":["tit for tat","one good turn deserves another"],"shortGloss":"reciprocal courtesy","characters":[{"char":"礼","meaning":"courtesy; etiquette"},{"char":"尚","meaning":"value; esteem"},{"char":"往","meaning":"go; reciprocate"},{"char":"来","meaning":"come; return"}],"origin":{"period":"Warring States period (475–221 BCE)","sourceText":"《礼记·曲礼上》","sourceTextEnglish":"Book of Rites, Qu Li I","originalExcerpt":"礼尚往来，往而不来，非礼也；来而不往，亦非礼也。","storyEnglish":"The idiom originates from the 'Book of Rites', an ancient Confucian text that discusses the importance of rituals and etiquette. The passage emphasizes that proper etiquette involves mutual exchange; if someone extends courtesy to you, it is only proper to reciprocate. This principle is seen as foundational to maintaining harmonious social relationships.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["subject","predicate","object","adverbial"],"structure":"subject-predicate","register":"literary, but very widely understood and used in ordinary speech","connotation":"neutral","commonMistakes":"Learners sometimes use this idiom to imply a strict or transactional exchange, but it actually emphasizes the importance of mutual respect and courtesy rather than a rigid quid pro quo.","canStandAlone":false},"examples":[{"simplified":"在商业合作中，礼尚往来是非常重要的。","english":"In business cooperation, reciprocal courtesy is very important.","traditional":"在商業合作中，禮尚往來是非常重要的。"},{"simplified":"他送了我一份礼物，出于礼尚往来，我也准备了一份回礼。","english":"He gave me a gift, and out of reciprocal courtesy, I also prepared a return gift.","traditional":"他送了我一份禮物，出於禮尚往來，我也準備了一份回禮。"}],"synonyms":[],"antonyms":[],"confusedWith":[{"id":"以牙还牙","note":"礼尚往来 emphasizes mutual courtesy, while 以牙还牙 (an eye for an eye) implies retaliation or revenge."}],"traditional":"禮尚往來","pinyinOverride":null},{"id":"cheng-xin-ru-yi","simplified":"称心如意","literalMeaning":"satisfy heart like intention","figurativeMeaning":"to have everything as one wishes; perfectly matching one's desires","englishEquivalents":["everything goes as planned","to one's heart's content","just as one wishes"],"shortGloss":"everything goes as planned","characters":[{"char":"称","meaning":"satisfy"},{"char":"心","meaning":"heart"},{"char":"如","meaning":"like"},{"char":"意","meaning":"intention"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '称心如意' is believed to have originated from the desire for one's heart and intentions to be fulfilled. It is used to describe situations where everything goes according to one's wishes, providing a sense of satisfaction and contentment.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"coordinate","register":"commonly used in both written and spoken Chinese","connotation":"positive","commonMistakes":"Learners often confuse '称心如意' with '心满意足', which also means satisfaction but emphasizes being content with what one has, rather than having things go exactly as wished.","canStandAlone":false},"examples":[{"simplified":"他的新工作让他感到称心如意。","english":"His new job makes him feel everything is going as he wishes.","traditional":"他的新工作讓他感到稱心如意。"},{"simplified":"希望你在新的一年里一切称心如意。","english":"I hope everything goes as you wish in the new year.","traditional":"希望你在新的一年裡一切稱心如意。"}],"synonyms":["心想事成","如愿以偿"],"antonyms":["事与愿违"],"confusedWith":[{"id":"心满意足","note":"心满意足 emphasizes being content with what one has, while 称心如意 focuses on things going as one wishes."}],"traditional":"稱心如意","pinyinOverride":null},{"id":"tu-ru-qi-lai","simplified":"突如其来","literalMeaning":"suddenly like its coming","figurativeMeaning":"to happen suddenly or unexpectedly","englishEquivalents":["out of the blue","all of a sudden"],"shortGloss":"happen unexpectedly","characters":[{"char":"突","meaning":"suddenly"},{"char":"如","meaning":"like"},{"char":"其","meaning":"its"},{"char":"来","meaning":"come"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom 突如其来 is used to describe events or situations that occur unexpectedly, without warning. It is often used to convey the suddenness and surprise of an occurrence, much like something appearing out of nowhere.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["adverbial"],"structure":"modifier-head","register":"commonly used in both written and spoken Chinese","connotation":"neutral","commonMistakes":"Learners might confuse 突如其来 with idioms that imply gradual change. 突如其来 specifically emphasizes suddenness, so it should not be used for events that develop over time.","canStandAlone":false},"examples":[{"simplified":"暴风雨突如其来，我们都没带伞。","english":"The storm came out of the blue, and none of us had brought an umbrella.","traditional":"暴風雨突如其來，我們都沒帶傘。"},{"simplified":"他的辞职决定让公司感到突如其来。","english":"His decision to resign came as a complete surprise to the company.","traditional":"他的辭職決定讓公司感到突如其來。"}],"synonyms":["猝不及防"],"antonyms":[],"confusedWith":[{"id":"渐入佳境","note":"渐入佳境 refers to a gradual improvement or getting into a better situation, which is the opposite of suddenness."}],"traditional":"突如其來","pinyinOverride":null},{"id":"jie-jin-quan-li","simplified":"竭尽全力","literalMeaning":"exhaust all full strength","figurativeMeaning":"to do one's utmost; to spare no effort","englishEquivalents":["give it one's all","leave no stone unturned"],"shortGloss":"do one's utmost","characters":[{"char":"竭","meaning":"exhaust"},{"char":"尽","meaning":"exhaust; use up"},{"char":"全","meaning":"all; whole"},{"char":"力","meaning":"strength; effort"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '竭尽全力' is commonly used to express the idea of putting forth maximum effort to achieve a goal. It emphasizes the act of using all available resources and strength to accomplish something. The phrase is often used in motivational contexts, encouraging individuals to strive for their best.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"widely used in both written and spoken Chinese, suitable for formal and informal contexts","connotation":"positive","commonMistakes":"Learners might confuse this idiom with similar expressions that imply effort but not to the same exhaustive extent. It's important to use it when truly emphasizing the maximum effort put forth.","canStandAlone":false},"examples":[{"simplified":"为了完成这个项目，他竭尽全力。","english":"He spared no effort to complete this project.","traditional":"為了完成這個項目，他竭盡全力。"},{"simplified":"他们竭尽全力去帮助那些需要帮助的人。","english":"They did their utmost to help those in need.","traditional":"他們竭盡全力去幫助那些需要幫助的人。"}],"synonyms":["全力以赴","不遗余力"],"antonyms":[],"confusedWith":[{"id":"全力以赴","note":"Both mean to put in maximum effort, but '全力以赴' emphasizes going towards a goal with full effort, while '竭尽全力' emphasizes exhausting all resources."}],"traditional":"竭盡全力","pinyinOverride":null},{"id":"cu-xin-da-yi","simplified":"粗心大意","literalMeaning":"careless heart, big intention","figurativeMeaning":"careless and negligent","englishEquivalents":["careless","negligent","sloppy"],"shortGloss":"careless and negligent","characters":[{"char":"粗","meaning":"careless"},{"char":"心","meaning":"heart"},{"char":"大","meaning":"big"},{"char":"意","meaning":"intention"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '粗心大意' is used to describe someone who is careless and negligent in their actions or thoughts. It emphasizes a lack of attention to detail and a tendency to overlook important aspects, leading to mistakes or oversights.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["attributive","predicate"],"structure":"coordinate","register":"widely used in both formal and informal contexts","connotation":"negative","commonMistakes":"Learners might confuse this idiom with similar expressions like '马马虎虎', which means 'so-so' or 'mediocre'. '粗心大意' specifically refers to carelessness and negligence, not mediocrity.","canStandAlone":false},"examples":[{"simplified":"他做事总是粗心大意，经常犯错。","english":"He is always careless and negligent in his work, often making mistakes.","traditional":"他做事總是粗心大意，經常犯錯。"},{"simplified":"因为粗心大意，他把重要的文件丢了。","english":"Due to his carelessness, he lost the important documents.","traditional":"因為粗心大意，他把重要的文件丟了。"}],"synonyms":["马虎"],"antonyms":["细心","谨慎"],"confusedWith":[{"id":"马马虎虎","note":"While '马马虎虎' means 'so-so' or 'mediocre', '粗心大意' specifically refers to being careless and negligent."}],"traditional":"粗心大意","pinyinOverride":null},{"id":"jing-da-xi-suan","simplified":"精打细算","literalMeaning":"careful calculation and meticulous planning","figurativeMeaning":"to plan carefully and budget meticulously","englishEquivalents":["penny-wise","scrimp and save"],"shortGloss":"careful planning and budgeting","characters":[{"char":"精","meaning":"meticulous"},{"char":"打","meaning":"calculate"},{"char":"细","meaning":"detailed"},{"char":"算","meaning":"plan"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '精打细算' is believed to have originated from the practice of careful budgeting and planning in traditional Chinese households and businesses. It emphasizes the importance of being meticulous and detailed in financial planning to ensure resources are used efficiently and effectively.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"coordinate","register":"commonly used in both formal and informal contexts","connotation":"positive","commonMistakes":"Learners often confuse this idiom with similar expressions that imply stinginess. However, '精打细算' focuses on careful and efficient planning, not being miserly.","canStandAlone":false},"examples":[{"simplified":"为了买房子，他们精打细算，节省每一分钱。","english":"To buy a house, they planned carefully and saved every penny.","traditional":"為了買房子，他們精打細算，節省每一分錢。"},{"simplified":"公司在预算上精打细算，以确保盈利。","english":"The company meticulously plans its budget to ensure profitability.","traditional":"公司在預算上精打細算，以確保盈利。"}],"synonyms":["量入为出","勤俭节约"],"antonyms":["挥金如土"],"confusedWith":[{"id":"吝啬","note":"精打细算 involves careful planning, whereas 吝啬 implies stinginess or miserliness."}],"traditional":"精打細算","pinyinOverride":null},{"id":"jing-pi-li-jie","simplified":"精疲力竭","literalMeaning":"energy exhausted, strength depleted","figurativeMeaning":"completely exhausted; worn out","englishEquivalents":["dead tired","worn out","exhausted"],"shortGloss":"completely exhausted","characters":[{"char":"精","meaning":"energy"},{"char":"疲","meaning":"exhausted"},{"char":"力","meaning":"strength"},{"char":"竭","meaning":"depleted"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '精疲力竭' describes a state of being utterly exhausted, both mentally and physically. It is often used to depict someone who has exerted all their energy and strength, leaving them completely worn out. The phrase has been used in various contexts throughout Chinese literature to convey extreme fatigue.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","complement"],"structure":"coordinate","register":"widely used in both spoken and written Chinese","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with others that describe tiredness but do not convey the same intensity of exhaustion. It is important to use it only when describing extreme fatigue.","canStandAlone":false},"examples":[{"simplified":"经过一整天的工作，他已经精疲力竭了。","english":"After a whole day of work, he was completely exhausted.","traditional":"經過一整天的工作，他已經精疲力竭了。"},{"simplified":"马拉松比赛结束后，选手们都精疲力竭。","english":"After the marathon, the runners were all worn out.","traditional":"馬拉松比賽結束後，選手們都精疲力竭。"}],"synonyms":["筋疲力尽"],"antonyms":[],"confusedWith":[{"id":"筋疲力尽","note":"Both idioms describe exhaustion, but '筋疲力尽' emphasizes physical tiredness more specifically."}],"traditional":"精疲力竭","pinyinOverride":null},{"id":"jing-yi-qiu-jing","simplified":"精益求精","literalMeaning":"improve and seek perfection","figurativeMeaning":"to constantly strive for perfection; to improve on something that is already outstanding","englishEquivalents":["to perfect one's skills","to refine and improve","to polish to perfection"],"shortGloss":"strive for perfection","characters":[{"char":"精","meaning":"excellent; refined"},{"char":"益","meaning":"increase; more"},{"char":"求","meaning":"seek; strive for"},{"char":"精","meaning":"excellence; perfection"}],"origin":{"period":"Han Dynasty (206 BCE – 220 CE)","sourceText":"《后汉书·马援传》","sourceTextEnglish":"Book of the Later Han, Biography of Ma Yuan","originalExcerpt":"精益求精，欲罢不能。","storyEnglish":"The idiom comes from a passage in the 'Book of the Later Han', which describes the attitude of continually improving one's skills and work. It emphasizes the pursuit of excellence and the desire to perfect something that is already good. This mindset is exemplified in the biography of Ma Yuan, a famous general known for his dedication and pursuit of perfection in his military strategies.","historicalFigures":["Ma Yuan"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["adverbial","attributive"],"structure":"verb-object","register":"widely used in both formal and informal contexts","connotation":"positive","commonMistakes":"Learners often confuse this idiom with phrases that mean 'to start from scratch' or 'to improve from a poor state', but it specifically refers to enhancing something already good.","canStandAlone":false},"examples":[{"simplified":"他在工作中总是精益求精，力求做到最好。","english":"He always strives for perfection in his work, aiming to do his best.","traditional":"他在工作中總是精益求精，力求做到最好。"},{"simplified":"这家公司以精益求精的态度，不断改进产品质量。","english":"This company continuously improves product quality with an attitude of striving for perfection.","traditional":"這家公司以精益求精的態度，不斷改進產品質量。"}],"synonyms":["追求完美","力求完美"],"antonyms":[],"confusedWith":[],"traditional":"精益求精","pinyinOverride":null},{"id":"jing-cai-fen-cheng","simplified":"精彩纷呈","literalMeaning":"brilliant and varied in presentation","figurativeMeaning":"brilliant and dazzling; full of wonderful and varied content","englishEquivalents":["a feast for the eyes","spectacular display"],"shortGloss":"brilliant and dazzling","characters":[{"char":"精","meaning":"brilliant; excellent"},{"char":"彩","meaning":"color; splendor"},{"char":"纷","meaning":"numerous; varied"},{"char":"呈","meaning":"present; display"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '精彩纷呈' is often used to describe events, performances, or presentations that are full of brilliant and varied elements, captivating the audience with their diversity and excellence. It emphasizes the richness and splendor of the content being presented.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"coordinate","register":"commonly used in both written and spoken Chinese to describe events, performances, or works that are impressive and varied","connotation":"positive","commonMistakes":"Learners might confuse '精彩纷呈' with '五光十色', which also describes something colorful but focuses more on visual aspects rather than the overall brilliance and variety of content.","canStandAlone":false},"examples":[{"simplified":"这次音乐会精彩纷呈，观众们都非常满意。","english":"The concert was brilliant and dazzling, and the audience was very satisfied.","traditional":"這次音樂會精彩紛呈，觀眾們都非常滿意。"},{"simplified":"电影节上的影片精彩纷呈，让人目不暇接。","english":"The films at the festival were brilliant and varied, leaving people dazzled.","traditional":"電影節上的影片精彩紛呈，讓人目不暇接。"}],"synonyms":["五光十色","绚丽多彩"],"antonyms":["平淡无奇"],"confusedWith":[{"id":"五光十色","note":"五光十色 emphasizes the colorful and visual aspect, while 精彩纷呈 highlights the brilliance and variety of content."}],"traditional":"精彩紛呈","pinyinOverride":null},{"id":"su-bu-xiang-shi","simplified":"素不相识","literalMeaning":"never mutually known","figurativeMeaning":"to be complete strangers; to not know each other at all","englishEquivalents":["complete strangers","not know each other from Adam"],"shortGloss":"complete strangers","characters":[{"char":"素","meaning":"never"},{"char":"不","meaning":"not"},{"char":"相","meaning":"mutually"},{"char":"识","meaning":"know"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '素不相识' is used to describe two people who have never met before and have no prior acquaintance. It emphasizes the complete lack of familiarity between them.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"modifier-head","register":"commonly used in both written and spoken Chinese","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with ones that imply a lack of understanding rather than a lack of acquaintance. It's important to note that this idiom specifically refers to not having met or known each other before.","canStandAlone":false},"examples":[{"simplified":"他们素不相识，却在旅途中成为了好朋友。","english":"They were complete strangers, but became good friends during the journey.","traditional":"他們素不相識，卻在旅途中成為了好朋友。"},{"simplified":"虽然我们素不相识，但他还是热心地帮助了我。","english":"Even though we were complete strangers, he still helped me warmly.","traditional":"雖然我們素不相識，但他還是熱心地幫助了我。"}],"synonyms":["互不相识"],"antonyms":[],"confusedWith":[{"id":"萍水相逢","note":"While both idioms describe strangers, '萍水相逢' emphasizes a chance meeting, whereas '素不相识' emphasizes having no prior acquaintance."}],"traditional":"素不相識","pinyinOverride":null},{"id":"yue-ding-su-cheng","simplified":"约定俗成","literalMeaning":"agreed upon, becomes customary","figurativeMeaning":"something that becomes established or accepted through common practice or consensus","englishEquivalents":["conventionally accepted","customarily established"],"shortGloss":"established by common practice","characters":[{"char":"约","meaning":"agree"},{"char":"定","meaning":"decide"},{"char":"俗","meaning":"custom"},{"char":"成","meaning":"become"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '约定俗成' refers to practices or conventions that become established over time through mutual agreement or widespread acceptance. It highlights how certain customs or norms are not necessarily dictated by formal rules but are instead formed by consensus and repeated practice.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"modifier-head","register":"commonly used in both written and spoken Chinese, especially in discussions about cultural practices or social norms","connotation":"neutral","commonMistakes":"Learners might confuse '约定俗成' with idioms that imply legal or formal agreement, but it specifically refers to informal consensus or practices that become standard over time.","canStandAlone":false},"examples":[{"simplified":"这个习俗是约定俗成的，没有法律规定。","english":"This custom is conventionally accepted and not mandated by law.","traditional":"這個習俗是約定俗成的，沒有法律規定。"},{"simplified":"语言中的许多表达都是约定俗成的。","english":"Many expressions in language are established by common practice.","traditional":"語言中的許多表達都是約定俗成的。"}],"synonyms":[],"antonyms":[],"confusedWith":[{"id":"约法三章","note":"约法三章 refers to a formal agreement or set of rules, whereas 约定俗成 refers to informal consensus or customs."}],"traditional":"約定俗成","pinyinOverride":null},{"id":"jing-jiu-bu-xi","simplified":"经久不息","literalMeaning":"last long without ceasing","figurativeMeaning":"to endure for a long time; to continue without stopping","englishEquivalents":["endure indefinitely","go on and on"],"shortGloss":"endure for a long time","characters":[{"char":"经","meaning":"to endure"},{"char":"久","meaning":"long time"},{"char":"不","meaning":"not"},{"char":"息","meaning":"cease"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '经久不息' is used to describe something that continues for a long time without stopping. It is often used in contexts such as applause, discussions, or phenomena that persist over time.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"modifier-head","register":"commonly used in both written and spoken Chinese","connotation":"neutral","commonMistakes":"Learners might confuse '经久不息' with '经久不衰', which also means lasting a long time but often implies not only duration but also maintaining strength or vitality.","canStandAlone":false},"examples":[{"simplified":"音乐会结束后，观众的掌声经久不息。","english":"After the concert ended, the audience's applause continued for a long time.","traditional":"音樂會結束後，觀眾的掌聲經久不息。"},{"simplified":"他的影响力在社会上经久不息。","english":"His influence in society continues without ceasing.","traditional":"他的影響力在社會上經久不息。"}],"synonyms":["经久不衰"],"antonyms":[],"confusedWith":[{"id":"经久不衰","note":"While both idioms imply lasting a long time, '经久不衰' emphasizes not only duration but also maintaining strength or vitality."}],"traditional":"經久不息","pinyinOverride":null},{"id":"hui-sheng-hui-se","simplified":"绘声绘色","literalMeaning":"draw sound, draw color","figurativeMeaning":"vivid and lifelike; to describe something in a very detailed and lively manner","englishEquivalents":["vividly","in full color","in living color"],"shortGloss":"vivid and lifelike","characters":[{"char":"绘","meaning":"to draw or paint"},{"char":"声","meaning":"sound"},{"char":"绘","meaning":"to draw or paint"},{"char":"色","meaning":"color"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '绘声绘色' is used to describe a way of telling a story or describing something that is so vivid and detailed that it feels like the listener or reader can hear the sounds and see the colors. It emphasizes the liveliness and detail of the description, making the scene come alive in the imagination.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["adverbial","attributive"],"structure":"coordinate","register":"commonly used in both spoken and written Chinese to describe vivid storytelling or descriptions","connotation":"positive","commonMistakes":"Learners might confuse this idiom with others that describe vividness but lack the dual emphasis on both sound and color. It specifically implies a multi-sensory description.","canStandAlone":false},"examples":[{"simplified":"他把故事讲得绘声绘色，大家都听得入了迷。","english":"He told the story so vividly that everyone was captivated.","traditional":"他把故事講得繪聲繪色，大家都聽得入了迷。"},{"simplified":"这本书把人物描写得绘声绘色，仿佛他们就在眼前。","english":"The book describes the characters so vividly, it's as if they are right in front of you.","traditional":"這本書把人物描寫得繪聲繪色，彷彿他們就在眼前。"}],"synonyms":["栩栩如生","活灵活现"],"antonyms":[],"confusedWith":[{"id":"栩栩如生","note":"While both idioms describe vividness, '栩栩如生' specifically emphasizes lifelikeness, often used for art or representations."}],"traditional":"繪聲繪色","pinyinOverride":null},{"id":"luo-yi-bu-jue","simplified":"络绎不绝","literalMeaning":"continuous and unending","figurativeMeaning":"an endless stream; continuously without interruption","englishEquivalents":["an endless stream","unceasing flow"],"shortGloss":"an endless stream","characters":[{"char":"络","meaning":"intertwined"},{"char":"绎","meaning":"in succession"},{"char":"不","meaning":"not"},{"char":"绝","meaning":"cease"}],"origin":{"period":"Northern and Southern Dynasties (420–589 CE)","sourceText":"《后汉书·张衡传》","sourceTextEnglish":"Book of the Later Han, Biography of Zhang Heng","originalExcerpt":"车马络绎不绝，填街塞巷。","storyEnglish":"The idiom comes from a description in the 'Book of the Later Han' where it describes a scene of carriages and horses coming and going in an unending stream, filling the streets and alleys. This vivid imagery captures the idea of a continuous and bustling flow of activity.","historicalFigures":["Zhang Heng"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"modifier-head","register":"commonly used in both written and spoken Chinese","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with similar expressions that imply a chaotic or disorderly flow, but '络绎不绝' specifically refers to a continuous and orderly stream.","canStandAlone":false},"examples":[{"simplified":"节日期间，游客络绎不绝地来到这个小镇。","english":"During the holiday, tourists came to the town in an endless stream.","traditional":"節日期間，遊客絡繹不絕地來到這個小鎮。"},{"simplified":"会议结束后，嘉宾们络绎不绝地离开了会场。","english":"After the meeting ended, the guests left the venue in an unceasing flow.","traditional":"會議結束後，嘉賓們絡繹不絕地離開了會場。"}],"synonyms":["川流不息"],"antonyms":[],"confusedWith":[{"id":"熙熙攘攘","note":"While '络绎不绝' refers to a continuous flow, '熙熙攘攘' implies a bustling and crowded scene with more chaos."}],"traditional":"絡繹不絕","pinyinOverride":null},{"id":"zui-kui-huo-shou","simplified":"罪魁祸首","literalMeaning":"crime chief disaster head","figurativeMeaning":"the main culprit or instigator of a problem","englishEquivalents":["the main culprit","the ringleader","the mastermind"],"shortGloss":"the main culprit","characters":[{"char":"罪","meaning":"crime; wrongdoing"},{"char":"魁","meaning":"chief; leader"},{"char":"祸","meaning":"disaster; misfortune"},{"char":"首","meaning":"head; leader"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '罪魁祸首' is used to describe the person or entity primarily responsible for a crime or a problem. The term combines the ideas of crime ('罪') and disaster ('祸') with leadership ('魁' and '首'), emphasizing the role of a leader or instigator in causing trouble. It is often used in contexts where identifying the main cause or person responsible for an issue is important.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["subject","object","attributive"],"structure":"modifier-head","register":"widely used in both formal and informal contexts","connotation":"negative","commonMistakes":"Learners often confuse '罪魁祸首' with idioms that simply mean 'criminal' or 'wrongdoer.' This idiom specifically refers to the primary instigator or main cause of a problem, not just any participant.","canStandAlone":false},"examples":[{"simplified":"调查显示，这家公司是污染事件的罪魁祸首。","english":"The investigation revealed that this company was the main culprit of the pollution incident.","traditional":"調查顯示，這家公司是汙染事件的罪魁禍首。"},{"simplified":"他被认为是这次事故的罪魁祸首。","english":"He is considered the main culprit of this accident.","traditional":"他被認為是這次事故的罪魁禍首。"}],"synonyms":["首恶"],"antonyms":[],"confusedWith":[{"id":"主犯","note":"While '主犯' also refers to a main perpetrator, it is more commonly used in legal contexts specifically for crimes, whereas '罪魁祸首' can be used more broadly for any major cause of a problem."}],"traditional":"罪魁禍首","pinyinOverride":null},{"id":"mei-zhong-bu-zu","simplified":"美中不足","literalMeaning":"beautiful but lacking","figurativeMeaning":"something that is generally good but has a small flaw","englishEquivalents":["a fly in the ointment","not quite perfect"],"shortGloss":"a small flaw in something good","characters":[{"char":"美","meaning":"beautiful"},{"char":"中","meaning":"in"},{"char":"不","meaning":"not"},{"char":"足","meaning":"sufficient"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '美中不足' is used to describe a situation where something is generally excellent or beautiful but has a small, often minor, flaw. The phrase emphasizes that while the overall quality is high, there is a particular aspect that is not perfect. The origin of this idiom is not attributed to a specific classical text, and it is considered to have developed over time as a common expression in Chinese language.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"modifier-head","register":"widely used in both spoken and written Chinese","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with expressions that mean something is entirely flawed, but '美中不足' specifically refers to minor imperfections in something otherwise good.","canStandAlone":false},"examples":[{"simplified":"这幅画很漂亮，只是美中不足的是颜色有点暗。","english":"This painting is very beautiful; the only flaw is that the colors are a bit dark.","traditional":"這幅畫很漂亮，只是美中不足的是顏色有點暗。"},{"simplified":"他的演讲很精彩，美中不足的是时间有点长。","english":"His speech was excellent; the only drawback was that it was a bit long.","traditional":"他的演講很精彩，美中不足的是時間有點長。"}],"synonyms":["白璧微瑕"],"antonyms":[],"confusedWith":[{"id":"瑕不掩瑜","note":"While '瑕不掩瑜' acknowledges flaws, it emphasizes that the overall excellence overshadows them, unlike '美中不足' which highlights the flaw."}],"traditional":"美中不足","pinyinOverride":null},{"id":"fan-tian-fu-di","simplified":"翻天覆地","literalMeaning":"overturn heaven and earth","figurativeMeaning":"to undergo tremendous change; earth-shattering","englishEquivalents":["turn the world upside down","revolutionary change"],"shortGloss":"tremendous change","characters":[{"char":"翻","meaning":"overturn"},{"char":"天","meaning":"heaven"},{"char":"覆","meaning":"cover, overturn"},{"char":"地","meaning":"earth"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '翻天覆地' is used to describe a situation where there is a dramatic and comprehensive change, akin to turning the world upside down. The phrase evokes imagery of such significant transformation that it feels as if the very fabric of the world has been altered.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"coordinate","register":"commonly used in both written and spoken Chinese to describe significant changes","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with expressions that imply chaos or disorder. However, '翻天覆地' specifically refers to significant change, not necessarily negative or chaotic.","canStandAlone":false},"examples":[{"simplified":"改革开放以来，中国发生了翻天覆地的变化。","english":"Since the reform and opening up, China has undergone tremendous changes.","traditional":"改革開放以來，中國發生了翻天覆地的變化。"},{"simplified":"这项新技术给我们的生活带来了翻天覆地的影响。","english":"This new technology has brought about earth-shattering impacts on our lives.","traditional":"這項新技術給我們的生活帶來了翻天覆地的影響。"}],"synonyms":["天翻地覆"],"antonyms":[],"confusedWith":[{"id":"天翻地覆","note":"These idioms are synonymous and often used interchangeably."}],"traditional":"翻天覆地","pinyinOverride":null},{"id":"fan-lai-fu-qu","simplified":"翻来覆去","literalMeaning":"turn over and over","figurativeMeaning":"to toss and turn; to do something repeatedly or over and over again","englishEquivalents":["toss and turn","over and over","again and again"],"shortGloss":"toss and turn; repeatedly","characters":[{"char":"翻","meaning":"turn over"},{"char":"来","meaning":"come"},{"char":"覆","meaning":"turn over"},{"char":"去","meaning":"go"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '翻来覆去' is commonly used to describe someone who is unable to sleep and keeps turning over in bed, or to describe an action that is repeated many times. Its exact origin is unclear, but it has been used in Chinese literature and speech for centuries to convey the idea of repetition or restlessness.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["adverbial","complement"],"structure":"coordinate","register":"commonly used in both spoken and written Chinese","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with others that involve repetition, but it specifically conveys a sense of physical or metaphorical turning or repeating. It is not used for planned or structured repetition.","canStandAlone":false},"examples":[{"simplified":"他在床上翻来覆去，怎么也睡不着。","english":"He tossed and turned in bed, unable to fall asleep.","traditional":"他在床上翻來覆去，怎麼也睡不著。"},{"simplified":"这篇文章我已经翻来覆去地修改了好几遍。","english":"I have revised this article over and over again.","traditional":"這篇文章我已經翻來覆去地修改了好幾遍。"}],"synonyms":["反复无常","周而复始"],"antonyms":[],"confusedWith":[{"id":"反复无常","note":"While both involve repetition, '反复无常' implies inconsistency or unpredictability, whereas '翻来覆去' does not."}],"traditional":"翻來覆去","pinyinOverride":null},{"id":"nai-ren-xun-wei","simplified":"耐人寻味","literalMeaning":"worth someone seeking the taste","figurativeMeaning":"thought-provoking; intriguing; something that is worth pondering over","englishEquivalents":["food for thought","thought-provoking","intriguing"],"shortGloss":"thought-provoking and intriguing","characters":[{"char":"耐","meaning":"worth; able to endure"},{"char":"人","meaning":"person; someone"},{"char":"寻","meaning":"seek; search"},{"char":"味","meaning":"taste; flavor"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom 耐人寻味 is often used to describe something, such as a piece of writing, a conversation, or an artwork, that leaves a lasting impression and invites deeper reflection. It suggests that there is more beneath the surface that is worth exploring and thinking about.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["attributive","predicate"],"structure":"modifier-head","register":"widely used in both written and spoken Chinese, suitable for formal and informal contexts","connotation":"positive","commonMistakes":"Learners might confuse 耐人寻味 with idioms that simply mean 'interesting' without the implication of depth or thoughtfulness. It specifically implies that something is worth pondering over, not just superficially engaging.","canStandAlone":false},"examples":[{"simplified":"这本书的内容非常耐人寻味，值得反复阅读。","english":"The content of this book is very thought-provoking and worth reading multiple times.","traditional":"這本書的內容非常耐人尋味，值得反覆閱讀。"},{"simplified":"他的演讲耐人寻味，让我对这个问题有了新的思考。","english":"His speech was thought-provoking and gave me new insights into the issue.","traditional":"他的演講耐人尋味，讓我對這個問題有了新的思考。"}],"synonyms":["发人深省"],"antonyms":[],"confusedWith":[{"id":"引人入胜","note":"引人入胜 means 'fascinating' or 'captivating', focusing more on immediate engagement rather than deeper reflection."}],"traditional":"耐人尋味","pinyinOverride":null},{"id":"er-shu-neng-xiang","simplified":"耳熟能详","literalMeaning":"ear familiar can detail","figurativeMeaning":"so familiar that one can recite it in detail","englishEquivalents":["a household name","familiar to everyone"],"shortGloss":"very familiar and well-known","characters":[{"char":"耳","meaning":"ear"},{"char":"熟","meaning":"familiar"},{"char":"能","meaning":"can"},{"char":"详","meaning":"detail"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom 耳熟能详 describes something that is so familiar to a person that they can easily recall and describe it in detail. It is often used to refer to popular songs, stories, or names that are widely known and recognized.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"modifier-head","register":"commonly used in both written and spoken Chinese","connotation":"neutral","commonMistakes":"Learners sometimes confuse this idiom with similar expressions that imply mere familiarity without the ability to describe in detail. It's important to note that 耳熟能详 implies a deeper level of familiarity.","canStandAlone":false},"examples":[{"simplified":"这首歌已经耳熟能详，几乎每个人都会唱。","english":"This song is so well-known that almost everyone can sing it.","traditional":"這首歌已經耳熟能詳，幾乎每個人都會唱。"},{"simplified":"他的名字在这个行业里耳熟能详。","english":"His name is a household name in this industry.","traditional":"他的名字在這個行業里耳熟能詳。"}],"synonyms":["家喻户晓"],"antonyms":[],"confusedWith":[{"id":"耳闻目睹","note":"耳闻目睹 means to hear and see with one's own ears and eyes, emphasizing direct experience rather than familiarity."}],"traditional":"耳熟能詳","pinyinOverride":null},{"id":"er-mu-yi-xin","simplified":"耳目一新","literalMeaning":"ears and eyes suddenly new","figurativeMeaning":"to have a completely new impression; to see or hear something refreshing and new","englishEquivalents":["a breath of fresh air","a new perspective"],"shortGloss":"a refreshing new change","characters":[{"char":"耳","meaning":"ears"},{"char":"目","meaning":"eyes"},{"char":"一","meaning":"one; suddenly"},{"char":"新","meaning":"new"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '耳目一新' is used to describe a situation where one's senses are refreshed by something new and different. It conveys the idea of being pleasantly surprised by a change that brings a new perspective or experience.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"subject-predicate","register":"commonly used in both spoken and written Chinese, suitable for formal and informal contexts","connotation":"positive","commonMistakes":"Learners might confuse this idiom with others that involve '耳' or '目' but do not convey the sense of refreshing change. It's important to remember that this idiom specifically implies a positive new impression.","canStandAlone":false},"examples":[{"simplified":"这次展览让人耳目一新，真是太精彩了。","english":"This exhibition was a breath of fresh air, it was truly wonderful.","traditional":"這次展覽讓人耳目一新，真是太精彩了。"},{"simplified":"他的设计风格独特，总是让人耳目一新。","english":"His design style is unique and always offers a refreshing new perspective.","traditional":"他的設計風格獨特，總是讓人耳目一新。"}],"synonyms":["焕然一新"],"antonyms":["陈旧不堪"],"confusedWith":[{"id":"耳提面命","note":"While both involve '耳', '耳提面命' means to give earnest advice, not a refreshing change."}],"traditional":"耳目一新","pinyinOverride":null},{"id":"ju-jing-hui-shen","simplified":"聚精会神","literalMeaning":"gather energy, focus spirit","figurativeMeaning":"to concentrate one's attention; to focus intently","englishEquivalents":["focus one's mind","concentrate fully","pay full attention"],"shortGloss":"to concentrate fully","characters":[{"char":"聚","meaning":"gather"},{"char":"精","meaning":"energy; essence"},{"char":"会","meaning":"converge; gather"},{"char":"神","meaning":"spirit; mind"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '聚精会神' describes the act of gathering one's energy and focusing one's mind on a task or subject. It is often used to emphasize the importance of concentration and attentiveness in achieving success or understanding something deeply.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"coordinate","register":"widely used in both formal and informal contexts","connotation":"positive","commonMistakes":"Learners sometimes confuse this idiom with others that imply physical gathering rather than mental focus. It specifically refers to concentrating the mind, not assembling people or objects.","canStandAlone":false},"examples":[{"simplified":"在考试中，我们必须聚精会神，不能分心。","english":"During the exam, we must concentrate fully and not get distracted.","traditional":"在考試中，我們必須聚精會神，不能分心。"},{"simplified":"他聚精会神地听讲，生怕错过任何重要信息。","english":"He listened intently to the lecture, afraid of missing any important information.","traditional":"他聚精會神地聽講，生怕錯過任何重要信息。"}],"synonyms":["全神贯注","专心致志"],"antonyms":["心不在焉"],"confusedWith":[{"id":"全神贯注","note":"Both idioms mean to concentrate fully, but '全神贯注' emphasizes being fully absorbed in something."}],"traditional":"聚精會神","pinyinOverride":null},{"id":"si-wu-ji-dan","simplified":"肆无忌惮","literalMeaning":"unrestrained without scruples","figurativeMeaning":"to act recklessly and without any scruples or restraint","englishEquivalents":["to act with impunity","to throw caution to the wind"],"shortGloss":"act recklessly without restraint","characters":[{"char":"肆","meaning":"recklessly"},{"char":"无","meaning":"without"},{"char":"忌","meaning":"scruples"},{"char":"惮","meaning":"fear, hesitation"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '肆无忌惮' describes someone who acts without any sense of restraint or moral consideration. It conveys the idea of behaving in a bold and unscrupulous manner, often disregarding rules or norms. The phrase is commonly used to criticize those who act with complete disregard for others or societal expectations.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"modifier-head","register":"commonly used in both written and spoken Chinese to describe reckless behavior","connotation":"negative","commonMistakes":"Learners often confuse this idiom with expressions that imply bravery or courage, but '肆无忌惮' carries a negative connotation of recklessness and lack of moral restraint.","canStandAlone":false},"examples":[{"simplified":"他在会上肆无忌惮地批评了所有人。","english":"He criticized everyone at the meeting without any restraint.","traditional":"他在會上肆無忌憚地批評了所有人。"},{"simplified":"这些人肆无忌惮地破坏环境。","english":"These people are recklessly damaging the environment.","traditional":"這些人肆無忌憚地破壞環境。"}],"synonyms":["为所欲为","横行霸道"],"antonyms":["谨小慎微"],"confusedWith":[{"id":"无所畏惧","note":"无所畏惧 means 'fearless', which can be positive, while 肆无忌惮 implies negative recklessness."}],"traditional":"肆無忌憚","pinyinOverride":null},{"id":"hu-si-luan-xiang","simplified":"胡思乱想","literalMeaning":"reckless thoughts chaotic ideas","figurativeMeaning":"to let one's imagination run wild; to have unfounded thoughts or worries","englishEquivalents":["overthink","let one's imagination run wild"],"shortGloss":"overthink; wild imagination","characters":[{"char":"胡","meaning":"reckless, without basis"},{"char":"思","meaning":"think, thoughts"},{"char":"乱","meaning":"chaotic, disorderly"},{"char":"想","meaning":"imagine, ideas"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '胡思乱想' describes the act of letting one's imagination run wild, often leading to unnecessary worry or anxiety. It is commonly used to caution against overthinking or forming baseless assumptions.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","object"],"structure":"coordinate","register":"commonly used in both spoken and written Chinese","connotation":"negative","commonMistakes":"Learners often confuse this idiom with similar expressions that involve thinking, but '胡思乱想' specifically implies a lack of basis or reason in the thoughts. It should not be used to describe thoughtful or logical thinking.","canStandAlone":false},"examples":[{"simplified":"他总是胡思乱想，担心一些不可能发生的事情。","english":"He always overthinks, worrying about things that are unlikely to happen.","traditional":"他總是胡思亂想，擔心一些不可能發生的事情。"},{"simplified":"别胡思乱想了，专心工作吧。","english":"Stop letting your imagination run wild and focus on your work.","traditional":"別胡思亂想了，專心工作吧。"}],"synonyms":["杞人忧天"],"antonyms":[],"confusedWith":[{"id":"异想天开","note":"While both involve imaginative thinking, '异想天开' refers to having unrealistic or fantastical ideas, often in a creative sense, rather than unfounded worries."}],"traditional":"胡思亂想","pinyinOverride":null},{"id":"jiao-ta-shi-di","simplified":"脚踏实地","literalMeaning":"feet step solid ground","figurativeMeaning":"to be down-to-earth; to work steadily and make solid progress","englishEquivalents":["down-to-earth","steady as she goes"],"shortGloss":"practical and realistic","characters":[{"char":"脚","meaning":"foot"},{"char":"踏","meaning":"step on"},{"char":"实","meaning":"solid"},{"char":"地","meaning":"ground"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '脚踏实地' is often used to describe someone who is practical and focused on making steady progress. It emphasizes the importance of being grounded and realistic in one's approach to tasks or goals, rather than being overly ambitious or unrealistic.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["adverbial","attributive"],"structure":"modifier-head","register":"commonly used in both formal and informal contexts","connotation":"positive","commonMistakes":"Learners sometimes confuse this idiom with ones that imply a lack of ambition, but '脚踏实地' conveys a positive sense of being practical and reliable.","canStandAlone":false},"examples":[{"simplified":"他是一个脚踏实地的人，总是一步一个脚印地前进。","english":"He is a down-to-earth person who always makes progress step by step.","traditional":"他是一個腳踏實地的人，總是一步一個腳印地前進。"},{"simplified":"在这个项目中，我们需要脚踏实地地工作，确保每个细节都不出错。","english":"In this project, we need to work steadily and ensure that no detail is overlooked.","traditional":"在這個項目中，我們需要腳踏實地地工作，確保每個細節都不出錯。"}],"synonyms":["实事求是"],"antonyms":["好高骛远"],"confusedWith":[{"id":"好高骛远","note":"好高骛远 implies being overly ambitious without a realistic plan, unlike 脚踏实地, which is about being practical and realistic."}],"traditional":"腳踏實地","pinyinOverride":null},{"id":"tuo-kou-er-chu","simplified":"脱口而出","literalMeaning":"blurt out","figurativeMeaning":"to say something without thinking; to blurt out","englishEquivalents":["blurt out","speak without thinking"],"shortGloss":"blurt out without thinking","characters":[{"char":"脱","meaning":"to shed; to take off"},{"char":"口","meaning":"mouth"},{"char":"而","meaning":"and; thus"},{"char":"出","meaning":"to go out; to come out"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '脱口而出' describes the action of saying something spontaneously or without forethought. It is often used when someone speaks impulsively, without considering the consequences or the appropriateness of their words. The phrase captures the idea of words 'escaping' from one's mouth before they are fully processed by the mind.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"commonly used in both spoken and written Chinese","connotation":"neutral","commonMistakes":"Learners often confuse this idiom with similar expressions that imply intentional speech. '脱口而出' specifically refers to unintentional or spontaneous speech.","canStandAlone":false},"examples":[{"simplified":"他一激动就脱口而出，说了不该说的话。","english":"In his excitement, he blurted out things he shouldn't have said.","traditional":"他一激動就脫口而出，說了不該說的話。"},{"simplified":"她没想太多，脱口而出自己的想法。","english":"Without much thought, she blurted out her opinion.","traditional":"她沒想太多，脫口而出自己的想法。"}],"synonyms":["信口开河"],"antonyms":[],"confusedWith":[{"id":"信口开河","note":"While both involve speaking, '信口开河' implies speaking carelessly or exaggerating, whereas '脱口而出' focuses on the spontaneity of speech."}],"traditional":"脫口而出","pinyinOverride":null},{"id":"tuo-ying-er-chu","simplified":"脱颖而出","literalMeaning":"remove the awn and emerge","figurativeMeaning":"to stand out; to distinguish oneself","englishEquivalents":["stand out from the crowd","rise above the rest"],"shortGloss":"to stand out or excel","characters":[{"char":"脱","meaning":"remove"},{"char":"颖","meaning":"awn; sharp point"},{"char":"而","meaning":"and; thus"},{"char":"出","meaning":"emerge; come out"}],"origin":{"period":"Warring States period (475–221 BCE)","sourceText":"《史记·平原君虞卿列传》","sourceTextEnglish":"Records of the Grand Historian, Biography of Lord Pingyuan and Yu Qing","originalExcerpt":"良玉不琢，不成器；君子不学，不成名。锥处囊中，其末立见，脱颖而出也。","storyEnglish":"The idiom originates from a story in the 'Records of the Grand Historian' where it is said that a sharp tool, like an awl, will naturally pierce through a bag and reveal its point. This metaphor was used to describe a person of talent who will naturally stand out and be recognized, just as the sharp point of an awl emerges from a bag.","historicalFigures":["Lord Pingyuan","Yu Qing"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"literary, but very widely understood and used in ordinary speech","connotation":"positive","commonMistakes":"Learners often confuse this idiom with others that mean 'to excel' but lack the nuance of emerging from obscurity. It specifically implies standing out from a group.","canStandAlone":false},"examples":[{"simplified":"在比赛中，他的表现让他脱颖而出。","english":"In the competition, his performance made him stand out.","traditional":"在比賽中，他的表現讓他脫穎而出。"},{"simplified":"经过多年的努力，她终于在公司里脱颖而出。","english":"After years of hard work, she finally stood out in the company.","traditional":"經過多年的努力，她終於在公司裡脫穎而出。"}],"synonyms":["出类拔萃","鹤立鸡群"],"antonyms":[],"confusedWith":[{"id":"出类拔萃","note":"Both mean to excel, but 出类拔萃 emphasizes being outstanding among peers, while 脱颖而出 emphasizes emerging from obscurity."}],"traditional":"脫穎而出","pinyinOverride":null},{"id":"zi-yi-wei-shi","simplified":"自以为是","literalMeaning":"self think to be right","figurativeMeaning":"to be self-righteous; to think one is always right","englishEquivalents":["self-righteous","know-it-all"],"shortGloss":"self-righteous","characters":[{"char":"自","meaning":"self"},{"char":"以","meaning":"think"},{"char":"为","meaning":"to be"},{"char":"是","meaning":"right"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '自以为是' describes someone who considers themselves to be always right, often without listening to others' opinions. It is commonly used to criticize someone who is overly confident in their own judgment.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"verb-object","register":"commonly used in both spoken and written Chinese","connotation":"negative","commonMistakes":"Learners often misuse this idiom by applying it to situations where someone is simply confident, rather than arrogantly dismissive of others' views. It implies a negative judgment about the person's attitude.","canStandAlone":false},"examples":[{"simplified":"他总是自以为是，从不听别人的建议。","english":"He always thinks he's right and never listens to others' advice.","traditional":"他總是自以為是，從不聽別人的建議。"},{"simplified":"自以为是的人很难与他人合作。","english":"It's difficult for self-righteous people to collaborate with others.","traditional":"自以為是的人很難與他人合作。"}],"synonyms":["自命不凡"],"antonyms":["虚怀若谷"],"confusedWith":[{"id":"自作聪明","note":"自作聪明 implies someone pretends to be clever, while 自以为是 implies someone arrogantly thinks they are always right."}],"traditional":"自以為是","pinyinOverride":null},{"id":"zi-li-geng-sheng","simplified":"自力更生","literalMeaning":"self-reliance regenerate life","figurativeMeaning":"to rely on one's own efforts; self-reliance","englishEquivalents":["self-reliance","stand on one's own two feet"],"shortGloss":"self-reliance","characters":[{"char":"自","meaning":"self"},{"char":"力","meaning":"effort; power"},{"char":"更","meaning":"again; further"},{"char":"生","meaning":"life; to live"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '自力更生' emphasizes the importance of relying on one's own efforts and resources to overcome difficulties or achieve goals. It is often used to encourage individuals or groups to be self-sufficient and not depend on external assistance.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"modifier-head","register":"widely used in both formal and informal contexts","connotation":"positive","commonMistakes":"Learners might confuse this idiom with phrases that imply independence from others in a negative sense. '自力更生' is positive, emphasizing empowerment and self-sufficiency.","canStandAlone":false},"examples":[{"simplified":"在困难时期，我们必须学会自力更生。","english":"In difficult times, we must learn to rely on ourselves.","traditional":"在困難時期，我們必須學會自力更生。"},{"simplified":"他通过自力更生，成功地建立了自己的公司。","english":"Through self-reliance, he successfully established his own company.","traditional":"他通過自力更生，成功地建立了自己的公司。"}],"synonyms":["自给自足"],"antonyms":["依赖他人"],"confusedWith":[{"id":"独立自主","note":"While both emphasize independence, '独立自主' focuses more on political or personal independence, whereas '自力更生' emphasizes self-reliance in practical efforts."}],"traditional":"自力更生","pinyinOverride":null},{"id":"zi-shi-zhi-zhong","simplified":"自始至终","literalMeaning":"from start to finish","figurativeMeaning":"from beginning to end; throughout","englishEquivalents":["from start to finish","from beginning to end","throughout"],"shortGloss":"from beginning to end","characters":[{"char":"自","meaning":"from"},{"char":"始","meaning":"beginning"},{"char":"至","meaning":"to"},{"char":"终","meaning":"end"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom 自始至终 is a straightforward expression that conveys the idea of something occurring from the very beginning to the very end. It is often used to emphasize consistency or completeness in an action or process.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["adverbial","complement"],"structure":"modifier-head","register":"widely used in both written and spoken Chinese","connotation":"neutral","commonMistakes":"Learners sometimes confuse 自始至终 with 从头到尾, which is a synonym but can carry a slightly more informal tone. Both mean 'from start to finish', but 自始至终 is often used in more formal contexts.","canStandAlone":false},"examples":[{"simplified":"他自始至终都保持着冷静。","english":"He remained calm from start to finish.","traditional":"他自始至終都保持著冷靜。"},{"simplified":"这个项目自始至终都很顺利。","english":"The project went smoothly from beginning to end.","traditional":"這個項目自始至終都很順利。"}],"synonyms":["从头到尾"],"antonyms":[],"confusedWith":[{"id":"从头到尾","note":"Both mean 'from start to finish', but 自始至终 is more formal."}],"traditional":"自始至終","pinyinOverride":null},{"id":"zi-qiang-bu-xi","simplified":"自强不息","literalMeaning":"strive for self-improvement without rest","figurativeMeaning":"to continuously strive to improve oneself","englishEquivalents":["keep improving oneself","unceasing self-improvement"],"shortGloss":"unceasing self-improvement","characters":[{"char":"自","meaning":"self"},{"char":"强","meaning":"strengthen"},{"char":"不","meaning":"not"},{"char":"息","meaning":"rest"}],"origin":{"period":"Zhou Dynasty (1046–256 BCE)","sourceText":"《周易·乾》","sourceTextEnglish":"I Ching, Qian Hexagram","originalExcerpt":"天行健，君子以自强不息。","storyEnglish":"This idiom comes from the I Ching, one of the oldest Chinese classic texts. It describes how a noble person should follow the example of the heavens, which are constantly in motion, by continuously striving to improve themselves without ceasing.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"literary, but widely understood and used in both formal and informal contexts","connotation":"positive","commonMistakes":"Learners might confuse this idiom with others that imply improvement, but this one specifically emphasizes continuous and unceasing effort. It is not about occasional or sporadic improvement.","canStandAlone":false},"examples":[{"simplified":"他一直在努力学习，真是自强不息的典范。","english":"He has been studying diligently all the time; he truly exemplifies unceasing self-improvement.","traditional":"他一直在努力學習，真是自強不息的典範。"},{"simplified":"在工作中，我们应该自强不息，追求卓越。","english":"In our work, we should continuously strive for self-improvement and pursue excellence.","traditional":"在工作中，我們應該自強不息，追求卓越。"}],"synonyms":["奋发图强","持之以恒"],"antonyms":["自暴自弃"],"confusedWith":[{"id":"奋发图强","note":"While both emphasize improvement, 奋发图强 focuses more on vigorous efforts to overcome difficulties, whereas 自强不息 emphasizes continuous self-improvement."}],"traditional":"自強不息","pinyinOverride":null},{"id":"zi-ran-er-ran","simplified":"自然而然","literalMeaning":"naturally and so","figurativeMeaning":"something happening naturally or automatically without external force","englishEquivalents":["naturally","automatically","of its own accord"],"shortGloss":"happens naturally","characters":[{"char":"自","meaning":"self; naturally"},{"char":"然","meaning":"so; thus"},{"char":"而","meaning":"and; thus"},{"char":"然","meaning":"so; thus"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '自然而然' describes a process or event that occurs naturally, without any external intervention or effort. It emphasizes the idea that certain things will happen on their own, given the right conditions, much like how plants grow when they receive sunlight and water.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["adverbial","predicate"],"structure":"coordinate","register":"commonly used in both spoken and written Chinese, informal and formal contexts","connotation":"neutral","commonMistakes":"Learners might confuse '自然而然' with '理所当然', which means something is taken for granted or considered as a matter of course. '自然而然' emphasizes the natural occurrence, while '理所当然' emphasizes the justification or reasonableness.","canStandAlone":false},"examples":[{"simplified":"经过多年的努力，他的成功自然而然地到来了。","english":"After years of hard work, his success came naturally.","traditional":"經過多年的努力，他的成功自然而然地到來了。"},{"simplified":"随着时间的推移，问题自然而然地解决了。","english":"As time went by, the problem resolved itself naturally.","traditional":"隨著時間的推移，問題自然而然地解決了。"}],"synonyms":["顺其自然"],"antonyms":[],"confusedWith":[{"id":"理所当然","note":"自然而然 refers to something happening naturally, while 理所当然 implies something is taken for granted or justified."}],"traditional":"自然而然","pinyinOverride":null},{"id":"jie-yi-suo-shi","simplified":"节衣缩食","literalMeaning":"reduce clothing and cut down on food","figurativeMeaning":"to live frugally; to economize on living expenses","englishEquivalents":["tighten one's belt","live on a shoestring"],"shortGloss":"live frugally","characters":[{"char":"节","meaning":"reduce; economize"},{"char":"衣","meaning":"clothing"},{"char":"缩","meaning":"cut down; shrink"},{"char":"食","meaning":"food"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '节衣缩食' describes a lifestyle of frugality and careful management of resources. It emphasizes the importance of reducing personal consumption, such as spending less on clothing and food, in order to save money or resources for more important needs. This concept has been valued in various cultures as a means of ensuring financial stability and preparing for future uncertainties.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"coordinate","register":"common in both written and spoken Chinese, suitable for formal and informal contexts","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with expressions that imply poverty, but it specifically refers to the choice to economize, not necessarily out of necessity.","canStandAlone":false},"examples":[{"simplified":"为了买房子，他们不得不节衣缩食。","english":"In order to buy a house, they had to live frugally.","traditional":"為了買房子，他們不得不節衣縮食。"},{"simplified":"他一直节衣缩食，为的是给孩子们存学费。","english":"He has always lived frugally to save money for his children's tuition.","traditional":"他一直節衣縮食，為的是給孩子們存學費。"}],"synonyms":["省吃俭用"],"antonyms":["挥金如土"],"confusedWith":[{"id":"省吃俭用","note":"Both mean living frugally, but 节衣缩食 emphasizes reducing spending on clothing and food specifically."}],"traditional":"節衣縮食","pinyinOverride":null},{"id":"ku-jin-gan-lai","simplified":"苦尽甘来","literalMeaning":"bitterness ends, sweetness comes","figurativeMeaning":"after enduring hardships, happiness will follow","englishEquivalents":["Every cloud has a silver lining","After the storm comes the calm"],"shortGloss":"hard times are followed by good times","characters":[{"char":"苦","meaning":"bitterness; hardship"},{"char":"尽","meaning":"end; exhaust"},{"char":"甘","meaning":"sweetness; happiness"},{"char":"来","meaning":"come; arrive"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '苦尽甘来' is believed to have originated from the idea that life is a cycle of ups and downs. After enduring difficult times, one can expect better times to follow. This concept is deeply rooted in Chinese culture and philosophy, emphasizing perseverance and hope.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"cause-effect","register":"widely used in both spoken and written Chinese, suitable for both formal and informal contexts","connotation":"positive","commonMistakes":"Learners often confuse this idiom with '否极泰来' (fǒu jí tài lái), which also means that good times follow bad, but is more formal and literary. '苦尽甘来' is more commonly used in everyday speech.","canStandAlone":false},"examples":[{"simplified":"经过多年的努力和坚持，他终于迎来了苦尽甘来的时刻。","english":"After years of hard work and perseverance, he finally reached a time when the bitterness ended and sweetness came.","traditional":"經過多年的努力和堅持，他終於迎來了苦盡甘來的時刻。"},{"simplified":"她相信，只要继续努力，总会有苦尽甘来的那一天。","english":"She believes that as long as she keeps working hard, there will eventually be a day when the bitterness ends and sweetness comes.","traditional":"她相信，只要繼續努力，總會有苦盡甘來的那一天。"}],"synonyms":["雨过天晴","否极泰来"],"antonyms":[],"confusedWith":[{"id":"否极泰来","note":"Both idioms convey the idea of good times following bad, but '否极泰来' is more formal and literary."}],"traditional":"苦盡甘來","pinyinOverride":null},{"id":"mo-ming-qi-miao","simplified":"莫名其妙","literalMeaning":"cannot describe its mysteriousness","figurativeMeaning":"baffling; inexplicable; without rhyme or reason","englishEquivalents":["beyond comprehension","inexplicable","without rhyme or reason"],"shortGloss":"baffling or inexplicable","characters":[{"char":"莫","meaning":"cannot"},{"char":"名","meaning":"describe"},{"char":"其","meaning":"its"},{"char":"妙","meaning":"mysteriousness"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '莫名其妙' is used to describe situations or things that are baffling or inexplicable. It is often used when something occurs that cannot be easily explained or understood, leaving people puzzled.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive","adverbial"],"structure":"modifier-head","register":"commonly used in both spoken and written Chinese","connotation":"neutral","commonMistakes":"Learners often use this idiom to describe people, but it is more appropriately used for situations or things that are puzzling or inexplicable.","canStandAlone":false},"examples":[{"simplified":"他的行为让人感到莫名其妙。","english":"His behavior was beyond comprehension.","traditional":"他的行為讓人感到莫名其妙。"},{"simplified":"这件事情发生得莫名其妙，没有人知道原因。","english":"This incident happened inexplicably, and no one knows the reason.","traditional":"這件事情發生得莫名其妙，沒有人知道原因。"}],"synonyms":["不可思议","匪夷所思"],"antonyms":[],"confusedWith":[{"id":"不可思议","note":"Both describe something difficult to understand, but '不可思议' often has a more positive or awe-inspiring connotation."}],"traditional":"莫名其妙","pinyinOverride":null},{"id":"ping-shui-xiang-feng","simplified":"萍水相逢","literalMeaning":"duckweed meets in water","figurativeMeaning":"to meet by chance, like two strangers crossing paths","englishEquivalents":["ships that pass in the night"],"shortGloss":"a chance encounter","characters":[{"char":"萍","meaning":"duckweed, symbolizing something floating or drifting"},{"char":"水","meaning":"water, the medium where duckweed floats"},{"char":"相","meaning":"mutually, each other"},{"char":"逢","meaning":"to meet, to encounter"}],"origin":{"period":"Tang Dynasty (618–907)","sourceText":"《孟郊诗集·送崔爽之湖南》","sourceTextEnglish":"Meng Jiao's Poetry Collection, 'Seeing Off Cui Shuang to Hunan'","originalExcerpt":"萍水相逢，尽是他乡之客。","storyEnglish":"The idiom originates from a poem by Meng Jiao, where he describes the chance meeting of two people who are both far from home, like duckweed meeting on the water. The imagery of duckweed, which drifts with the current, emphasizes the randomness and fleeting nature of such encounters.","historicalFigures":["Meng Jiao"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"literary, but understood in modern speech","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with expressions that imply a deeper connection or relationship, but it specifically refers to a chance, often brief, encounter.","canStandAlone":false},"examples":[{"simplified":"我们在旅途中萍水相逢，却成了好朋友。","english":"We met by chance during the journey, yet became good friends.","traditional":"我們在旅途中萍水相逢，卻成了好朋友。"},{"simplified":"在这个城市里，萍水相逢的人很多。","english":"In this city, there are many people you meet by chance.","traditional":"在這個城市裡，萍水相逢的人很多。"}],"synonyms":["不期而遇"],"antonyms":[],"confusedWith":[{"id":"一见如故","note":"一见如故 implies an immediate, deep connection, unlike the fleeting nature of 萍水相逢."}],"traditional":"萍水相逢","pinyinOverride":null},{"id":"xiu-shou-pang-guan","simplified":"袖手旁观","literalMeaning":"fold one's arms and watch","figurativeMeaning":"to stand by and watch without offering help","englishEquivalents":["sit on the sidelines","stand idly by"],"shortGloss":"stand by without helping","characters":[{"char":"袖","meaning":"sleeve"},{"char":"手","meaning":"hand"},{"char":"旁","meaning":"beside"},{"char":"观","meaning":"watch"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '袖手旁观' describes a situation where someone chooses not to get involved or help, even when they are in a position to do so. The imagery is of someone folding their arms and merely observing a situation unfold without taking any action.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"commonly used in both written and spoken Chinese","connotation":"negative","commonMistakes":"Learners might confuse this idiom with positive expressions of neutrality or non-interference, but it specifically implies a lack of action where help is expected.","canStandAlone":false},"examples":[{"simplified":"看到有人需要帮助，他却袖手旁观。","english":"He stood idly by when he saw someone in need of help.","traditional":"看到有人需要幫助，他卻袖手旁觀。"},{"simplified":"在危机时刻，我们不能袖手旁观。","english":"In times of crisis, we cannot just stand by and watch.","traditional":"在危機時刻，我們不能袖手旁觀。"}],"synonyms":["冷眼旁观"],"antonyms":["挺身而出"],"confusedWith":[{"id":"冷眼旁观","note":"Both imply observing without involvement, but '冷眼旁观' emphasizes a cold or indifferent attitude."}],"traditional":"袖手旁觀","pinyinOverride":null},{"id":"jian-yi-yong-wei","simplified":"见义勇为","literalMeaning":"see righteousness, act bravely","figurativeMeaning":"to act bravely for a just cause; to stand up for what is right","englishEquivalents":["stand up for justice","do the right thing","act with courage"],"shortGloss":"act bravely for a just cause","characters":[{"char":"见","meaning":"see"},{"char":"义","meaning":"righteousness"},{"char":"勇","meaning":"brave"},{"char":"为","meaning":"act"}],"origin":{"period":"Han Dynasty (206 BCE – 220 CE)","sourceText":"《后汉书·卷八十八·列女传》","sourceTextEnglish":"Book of the Later Han, Volume 88, Biographies of Exemplary Women","originalExcerpt":"见义勇为，士之有勇也。","storyEnglish":"The idiom comes from a story in the 'Book of the Later Han' about individuals who were praised for their bravery in standing up for justice. The phrase highlights the virtue of acting courageously when one encounters a just cause, emphasizing the moral duty to intervene and help others.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"modifier-head","register":"commonly used in both formal and informal contexts","connotation":"positive","commonMistakes":"Learners might confuse this idiom with others that involve bravery but lack the moral or ethical component. It's important to remember that '见义勇为' specifically implies acting bravely for a righteous cause.","canStandAlone":false},"examples":[{"simplified":"他见义勇为，救了落水的孩子。","english":"He acted bravely for a just cause and saved the child who fell into the water.","traditional":"他見義勇為，救了落水的孩子。"},{"simplified":"在危急时刻，他总是见义勇为。","english":"In critical moments, he always stands up for what is right.","traditional":"在危急時刻，他總是見義勇為。"}],"synonyms":["舍己为人","挺身而出"],"antonyms":["袖手旁观"],"confusedWith":[{"id":"勇往直前","note":"While both involve bravery, '勇往直前' means to advance courageously without hesitation, lacking the specific moral context of '见义勇为'."}],"traditional":"見義勇為","pinyinOverride":null},{"id":"jian-ren-jian-zhi","simplified":"见仁见智","literalMeaning":"see benevolence, see wisdom","figurativeMeaning":"different people have different views; opinions differ","englishEquivalents":["to each their own","beauty is in the eye of the beholder"],"shortGloss":"opinions differ","characters":[{"char":"见","meaning":"see"},{"char":"仁","meaning":"benevolence"},{"char":"见","meaning":"see"},{"char":"智","meaning":"wisdom"}],"origin":{"period":"Eastern Han Dynasty (25–220 CE)","sourceText":"《周易·系辞下》","sourceTextEnglish":"Book of Changes, Xici II","originalExcerpt":"仁者见之谓之仁，智者见之谓之智。","storyEnglish":"The phrase comes from the 'Book of Changes' (I Ching), where it is stated that benevolent people see benevolence in things, while wise people see wisdom. This reflects the idea that different people perceive the same thing in different ways based on their own nature and perspective.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"coordinate","register":"widely used in both formal and informal contexts","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with others that imply disagreement or conflict, but 见仁见智 is neutral and simply acknowledges differing perspectives.","canStandAlone":false},"examples":[{"simplified":"对于这个问题，大家见仁见智，没有统一的看法。","english":"Regarding this issue, everyone has different opinions; there is no consensus.","traditional":"對於這個問題，大家見仁見智，沒有統一的看法。"},{"simplified":"艺术作品的好坏常常是见仁见智的。","english":"The quality of an art piece is often a matter of personal opinion.","traditional":"藝術作品的好壞常常是見仁見智的。"}],"synonyms":[],"antonyms":[],"confusedWith":[{"id":"莫衷一是","note":"While both idioms involve differing opinions, 莫衷一是 implies an inability to reach a conclusion, whereas 见仁见智 simply acknowledges differing views."}],"traditional":"見仁見智","pinyinOverride":null},{"id":"jian-li-wang-yi","simplified":"见利忘义","literalMeaning":"see profit, forget righteousness","figurativeMeaning":"to forget one's principles when tempted by personal gain","englishEquivalents":["sell one's soul","throw principles to the wind"],"shortGloss":"abandon principles for profit","characters":[{"char":"见","meaning":"see"},{"char":"利","meaning":"profit"},{"char":"忘","meaning":"forget"},{"char":"义","meaning":"righteousness"}],"origin":{"period":"Eastern Han dynasty (25–220 CE)","sourceText":"《后汉书·杨震传》","sourceTextEnglish":"Book of the Later Han, Biography of Yang Zhen","originalExcerpt":"见利而忘其义，非君子也。","storyEnglish":"The idiom originates from a story about Yang Zhen, a famous official during the Eastern Han dynasty. Yang Zhen was known for his integrity and righteousness. Once, he was offered a bribe by a friend, but he refused it, saying, 'Heaven knows, Earth knows, you know, and I know. How can you say no one knows?' This story illustrates the principle of not abandoning one's moral integrity for personal gain.","historicalFigures":["Yang Zhen"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"widely used in both formal and informal contexts","connotation":"negative","commonMistakes":"Learners might confuse this idiom with similar expressions that involve profit, but this idiom specifically emphasizes the abandonment of moral principles. It should not be used to describe situations where profit is gained without ethical compromise.","canStandAlone":false},"examples":[{"simplified":"他为了钱财而见利忘义，失去了朋友的信任。","english":"He lost his friends' trust because he abandoned his principles for money.","traditional":"他為了錢財而見利忘義，失去了朋友的信任。"},{"simplified":"在商业竞争中，有些人容易见利忘义。","english":"In business competition, some people easily forget their principles for profit.","traditional":"在商業競爭中，有些人容易見利忘義。"}],"synonyms":["利令智昏"],"antonyms":["见义勇为"],"confusedWith":[{"id":"见风使舵","note":"见风使舵 means to act according to circumstances, not necessarily involving moral compromise."}],"traditional":"見利忘義","pinyinOverride":null},{"id":"jian-duo-shi-guang","simplified":"见多识广","literalMeaning":"seen much, know widely","figurativeMeaning":"experienced and knowledgeable","englishEquivalents":["worldly-wise","well-informed","knowledgeable"],"shortGloss":"experienced and knowledgeable","characters":[{"char":"见","meaning":"see"},{"char":"多","meaning":"much; many"},{"char":"识","meaning":"know"},{"char":"广","meaning":"wide; broad"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom 见多识广 is believed to have originated from the idea that a person who has seen and experienced many things in life tends to have a broad understanding and knowledge of the world. It emphasizes the value of practical experience and exposure to diverse situations in gaining wisdom.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"coordinate","register":"commonly used in both written and spoken Chinese","connotation":"positive","commonMistakes":"Learners sometimes confuse this idiom with others that suggest intelligence or cleverness, but 见多识广 specifically emphasizes knowledge gained through experience rather than innate intelligence.","canStandAlone":false},"examples":[{"simplified":"他在国外生活多年，见多识广。","english":"He has lived abroad for many years and is very knowledgeable.","traditional":"他在國外生活多年，見多識廣。"},{"simplified":"这位教授见多识广，总是能给出独到的见解。","english":"This professor is experienced and knowledgeable, always able to provide unique insights.","traditional":"這位教授見多識廣，總是能給出獨到的見解。"}],"synonyms":["博学多才","学富五车"],"antonyms":["孤陋寡闻"],"confusedWith":[{"id":"博学多才","note":"While both idioms suggest knowledge, 博学多才 emphasizes scholarly learning and talent, whereas 见多识广 emphasizes experience."}],"traditional":"見多識廣","pinyinOverride":null},{"id":"chu-mu-jing-xin","simplified":"触目惊心","literalMeaning":"touch the eye, startle the heart","figurativeMeaning":"shocking or startling to see","englishEquivalents":["shocking","eye-opening"],"shortGloss":"shocking to see","characters":[{"char":"触","meaning":"to touch"},{"char":"目","meaning":"eye"},{"char":"惊","meaning":"to startle"},{"char":"心","meaning":"heart"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '触目惊心' is used to describe something that is so shocking or startling that it impacts both the eyes and the heart. The phrase conveys the idea that the sight of something is so intense that it causes an emotional reaction. It is often used to describe scenes of devastation, disaster, or anything that leaves a deep impression due to its shocking nature.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"coordinate","register":"widely used in both written and spoken Chinese","connotation":"negative","commonMistakes":"Learners sometimes confuse this idiom with those that describe positive surprises. It specifically refers to negative or shocking situations.","canStandAlone":false},"examples":[{"simplified":"这场事故的现场真是触目惊心。","english":"The scene of the accident was truly shocking.","traditional":"這場事故的現場真是觸目驚心。"},{"simplified":"战争带来的破坏让人触目惊心。","english":"The destruction caused by the war is shocking to see.","traditional":"戰爭帶來的破壞讓人觸目驚心。"}],"synonyms":["惨不忍睹","惊心动魄"],"antonyms":[],"confusedWith":[{"id":"赏心悦目","note":"赏心悦目 describes something that is pleasing to the eye and heart, the opposite of shocking."}],"traditional":"觸目驚心","pinyinOverride":null},{"id":"tao-jia-huan-jia","simplified":"讨价还价","literalMeaning":"ask price return price","figurativeMeaning":"to haggle or negotiate over a price or terms","englishEquivalents":["bargain","haggle","negotiate"],"shortGloss":"to haggle or negotiate","characters":[{"char":"讨","meaning":"ask for"},{"char":"价","meaning":"price"},{"char":"还","meaning":"return"},{"char":"价","meaning":"price"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '讨价还价' describes the process of bargaining, where one party asks for a price and the other party responds with a counteroffer. This back-and-forth negotiation is common in markets and business transactions.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["verb-object"],"structure":"verb-object","register":"widely used in both spoken and written Chinese, informal contexts","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with fixed-price situations where negotiation is not possible. It specifically refers to situations where bargaining is expected.","canStandAlone":false},"examples":[{"simplified":"在市场上买东西时，讨价还价是很常见的。","english":"Haggling is very common when buying things at the market.","traditional":"在市場上買東西時，討價還價是很常見的。"},{"simplified":"他总是喜欢讨价还价，以得到最好的价格。","english":"He always likes to haggle to get the best price.","traditional":"他總是喜歡討價還價，以得到最好的價格。"}],"synonyms":["议价","讲价"],"antonyms":["一口价"],"confusedWith":[{"id":"一口价","note":"一口价 means a fixed price with no negotiation, while 讨价还价 involves bargaining."}],"traditional":"討價還價","pinyinOverride":null},{"id":"ji-yi-you-xin","simplified":"记忆犹新","literalMeaning":"memory still fresh","figurativeMeaning":"to remember something vividly; something is still fresh in one's memory","englishEquivalents":["fresh in one's mind","vivid memory"],"shortGloss":"vivid memory","characters":[{"char":"记","meaning":"remember"},{"char":"忆","meaning":"memory"},{"char":"犹","meaning":"still"},{"char":"新","meaning":"new; fresh"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '记忆犹新' is used to describe a situation where a memory is still very vivid and clear in someone's mind, as if it just happened. It emphasizes the freshness and clarity of the memory.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"modifier-head","register":"commonly used in both spoken and written Chinese","connotation":"neutral","commonMistakes":"Learners sometimes confuse this idiom with others that involve memory, but '记忆犹新' specifically emphasizes the freshness and vividness of a memory.","canStandAlone":false},"examples":[{"simplified":"虽然已经过去多年，但那次旅行的经历我记忆犹新。","english":"Even though many years have passed, the experience of that trip is still fresh in my memory.","traditional":"雖然已經過去多年，但那次旅行的經歷我記憶猶新。"},{"simplified":"他的演讲内容我记忆犹新，仿佛昨天才听过。","english":"I remember the content of his speech vividly, as if I heard it just yesterday.","traditional":"他的演講內容我記憶猶新，彷彿昨天才聽過。"}],"synonyms":[],"antonyms":[],"confusedWith":[],"traditional":"記憶猶新","pinyinOverride":null},{"id":"zhu-ru-ci-lei","simplified":"诸如此类","literalMeaning":"such as this kind","figurativeMeaning":"and so on; things like this","englishEquivalents":["and the like","such things","and so forth"],"shortGloss":"and so on; things like this","characters":[{"char":"诸","meaning":"various; all"},{"char":"如","meaning":"like; as"},{"char":"此","meaning":"this"},{"char":"类","meaning":"kind; type"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '诸如此类' is used to refer to things that are similar in nature or category. It is often used to conclude a list of examples, indicating that there are other similar items not explicitly mentioned.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["adverbial"],"structure":"modifier-head","register":"commonly used in both spoken and written Chinese","connotation":"neutral","commonMistakes":"Learners sometimes use this idiom to refer to a single item, but it is intended to imply a category or group of similar items. It should not be used to describe a singular, specific instance.","canStandAlone":false},"examples":[{"simplified":"他喜欢听古典音乐、爵士乐、摇滚乐，诸如此类。","english":"He likes listening to classical music, jazz, rock, and the like.","traditional":"他喜歡聽古典音樂、爵士樂、搖滾樂，諸如此類。"},{"simplified":"我们可以去博物馆、公园、动物园，诸如此类的地方。","english":"We can go to museums, parks, zoos, and places like that.","traditional":"我們可以去博物館、公園、動物園，諸如此類的地方。"}],"synonyms":[],"antonyms":[],"confusedWith":[],"traditional":"諸如此類","pinyinOverride":null},{"id":"zan-bu-jue-kou","simplified":"赞不绝口","literalMeaning":"praise not cease mouth","figurativeMeaning":"to praise someone or something highly and continuously","englishEquivalents":["sing someone's praises","speak highly of","full of praise"],"shortGloss":"speak highly of continuously","characters":[{"char":"赞","meaning":"praise"},{"char":"不","meaning":"not"},{"char":"绝","meaning":"cease"},{"char":"口","meaning":"mouth"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '赞不绝口' describes a situation where someone is so impressed by something that they cannot stop praising it. This expression is often used to convey admiration and approval, suggesting that the praise is genuine and heartfelt.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"commonly used in both formal and informal contexts","connotation":"positive","commonMistakes":"Learners might confuse this idiom with expressions that imply insincere or exaggerated praise. '赞不绝口' is used for genuine admiration, not flattery.","canStandAlone":false},"examples":[{"simplified":"他对这部电影赞不绝口，推荐给了所有的朋友。","english":"He couldn't stop praising the movie and recommended it to all his friends.","traditional":"他對這部電影讚不絕口，推薦給了所有的朋友。"},{"simplified":"老师对她的作文赞不绝口，说她的写作水平很高。","english":"The teacher was full of praise for her essay, saying her writing skills were excellent.","traditional":"老師對她的作文讚不絕口，說她的寫作水平很高。"}],"synonyms":["交口称赞","赞叹不已"],"antonyms":["嗤之以鼻"],"confusedWith":[{"id":"阿谀奉承","note":"阿谀奉承 implies insincere flattery, while 赞不绝口 is genuine praise."}],"traditional":"讚不絕口","pinyinOverride":null},{"id":"zou-tou-wu-lu","simplified":"走投无路","literalMeaning":"walk to no road","figurativeMeaning":"to be at the end of one's rope; to be in a desperate situation with no way out","englishEquivalents":["at the end of one's rope","between a rock and a hard place"],"shortGloss":"in a desperate situation","characters":[{"char":"走","meaning":"walk"},{"char":"投","meaning":"turn to"},{"char":"无","meaning":"no"},{"char":"路","meaning":"road"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '走投无路' describes a situation where a person has exhausted all options and finds themselves with no path forward. It is often used to depict a state of desperation or hopelessness, where no solution seems possible.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","complement"],"structure":"verb-object","register":"widely used in both spoken and written Chinese; common in everyday language","connotation":"negative","commonMistakes":"Learners might confuse this idiom with similar expressions that imply having limited options, but '走投无路' specifically means having no options left at all. It should not be used lightly, as it conveys a strong sense of desperation.","canStandAlone":false},"examples":[{"simplified":"他失去了工作，债务缠身，真是走投无路。","english":"He lost his job and is overwhelmed with debt; he's truly at the end of his rope.","traditional":"他失去了工作，債務纏身，真是走投無路。"},{"simplified":"在走投无路的时候，她决定向朋友求助。","english":"When she was in a desperate situation, she decided to ask her friends for help.","traditional":"在走投無路的時候，她決定向朋友求助。"}],"synonyms":["穷途末路"],"antonyms":[],"confusedWith":[{"id":"山穷水尽","note":"Both idioms describe desperate situations, but '山穷水尽' emphasizes the exhaustion of resources, while '走投无路' focuses on having no way out."}],"traditional":"走投無路","pinyinOverride":null},{"id":"zu-bu-chu-hu","simplified":"足不出户","literalMeaning":"feet do not leave the house","figurativeMeaning":"to stay at home all the time; to be housebound","englishEquivalents":["stay at home","homebound"],"shortGloss":"stay at home","characters":[{"char":"足","meaning":"feet"},{"char":"不","meaning":"not"},{"char":"出","meaning":"leave"},{"char":"户","meaning":"house"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '足不出户' describes someone who does not leave their home, either due to choice, necessity, or circumstances. It reflects a lifestyle or situation where a person remains indoors and does not venture outside.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"subject-predicate","register":"commonly used in both spoken and written Chinese to describe staying at home","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with expressions that imply laziness or unwillingness to leave home, but it simply describes the act of staying indoors without such connotations.","canStandAlone":false},"examples":[{"simplified":"疫情期间，他足不出户，一直在家工作。","english":"During the pandemic, he stayed at home all the time and worked from home.","traditional":"疫情期間，他足不出戶，一直在家工作。"},{"simplified":"她最近足不出户，因为她在准备考试。","english":"She hasn't left the house recently because she's preparing for exams.","traditional":"她最近足不出戶，因為她在準備考試。"}],"synonyms":["闭门不出"],"antonyms":["走南闯北"],"confusedWith":[{"id":"闭门不出","note":"Both idioms mean staying indoors, but '闭门不出' emphasizes not opening the door or interacting with the outside world."}],"traditional":"足不出戶","pinyinOverride":null},{"id":"zu-zhi-duo-mou","simplified":"足智多谋","literalMeaning":"full of wisdom and many strategies","figurativeMeaning":"very resourceful and full of clever plans","englishEquivalents":["resourceful","full of crafty schemes","shrewd and strategic"],"shortGloss":"resourceful and strategic","characters":[{"char":"足","meaning":"full, ample"},{"char":"智","meaning":"wisdom, intelligence"},{"char":"多","meaning":"many, much"},{"char":"谋","meaning":"strategies, schemes"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '足智多谋' describes a person who is very resourceful and capable of coming up with clever strategies. It is often used to praise someone who can handle complex situations with intelligence and cunning. The exact origin of the idiom is not well-documented, but it has been used in Chinese literature and speech to describe strategic thinkers and wise leaders.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["attributive","predicate"],"structure":"coordinate","register":"literary, but very widely understood and used in ordinary speech","connotation":"positive","commonMistakes":"Learners might confuse this idiom with others that emphasize wisdom but not necessarily strategic thinking. It's important to note that '足智多谋' highlights both intelligence and the ability to devise plans.","canStandAlone":false},"examples":[{"simplified":"他是一个足智多谋的领导者，总能找到解决问题的方法。","english":"He is a resourceful leader who always finds ways to solve problems.","traditional":"他是一個足智多謀的領導者，總能找到解決問題的方法。"},{"simplified":"在这次谈判中，她表现得足智多谋，赢得了对方的尊重。","english":"In this negotiation, she was resourceful and strategic, earning the respect of the other party.","traditional":"在這次談判中，她表現得足智多謀，贏得了對方的尊重。"}],"synonyms":["机智过人","聪明才智"],"antonyms":["愚不可及","无计可施"],"confusedWith":[{"id":"聪明才智","note":"While both idioms emphasize intelligence, '聪明才智' focuses more on innate intelligence and talent, whereas '足智多谋' emphasizes strategic thinking and planning."}],"traditional":"足智多謀","pinyinOverride":null},{"id":"shen-bu-you-ji","simplified":"身不由己","literalMeaning":"body not by self","figurativeMeaning":"to be unable to control oneself; to be forced into something against one's will","englishEquivalents":["out of one's control","at the mercy of circumstances"],"shortGloss":"unable to control oneself","characters":[{"char":"身","meaning":"body; oneself"},{"char":"不","meaning":"not"},{"char":"由","meaning":"by; due to"},{"char":"己","meaning":"oneself"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom 身不由己 describes a situation where a person is unable to act according to their own will, often due to external pressures or circumstances. It reflects a sense of being compelled by forces beyond one's control, whether those are social, political, or personal. The phrase is commonly used to express sympathy or understanding for someone in a difficult situation.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"subject-predicate","register":"widely used in both formal and informal contexts","connotation":"neutral","commonMistakes":"Learners often confuse 身不由己 with idioms that imply voluntary action. Unlike phrases that suggest intentional behavior, 身不由己 specifically refers to situations where one has no choice.","canStandAlone":false},"examples":[{"simplified":"他虽然不想离开家乡，但因为工作的原因，他身不由己。","english":"Although he didn't want to leave his hometown, he was forced to because of work.","traditional":"他雖然不想離開家鄉，但因為工作的原因，他身不由己。"},{"simplified":"在那种情况下，她也是身不由己。","english":"In that situation, she was also unable to control her actions.","traditional":"在那種情況下，她也是身不由己。"}],"synonyms":["无可奈何"],"antonyms":["随心所欲"],"confusedWith":[{"id":"自作自受","note":"自作自受 implies suffering the consequences of one's own actions, while 身不由己 implies lack of control over one's actions."}],"traditional":"身不由己","pinyinOverride":null},{"id":"qing-er-yi-ju","simplified":"轻而易举","literalMeaning":"light and easy to lift","figurativeMeaning":"something that is very easy to do","englishEquivalents":["a piece of cake","easy as pie"],"shortGloss":"very easy to do","characters":[{"char":"轻","meaning":"light"},{"char":"而","meaning":"and"},{"char":"易","meaning":"easy"},{"char":"举","meaning":"lift"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '轻而易举' is used to describe tasks or actions that are very easy to accomplish, as if they require little effort. The phrase combines the ideas of being 'light' and 'easy to lift', metaphorically suggesting that the task is not burdensome.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"coordinate","register":"commonly used in both spoken and written Chinese","connotation":"positive","commonMistakes":"Learners might confuse this idiom with others that describe ease but have different nuances, such as '不费吹灰之力', which implies no effort at all. '轻而易举' suggests ease but not necessarily zero effort.","canStandAlone":false},"examples":[{"simplified":"这个任务对他来说轻而易举。","english":"This task is a piece of cake for him.","traditional":"這個任務對他來說輕而易舉。"},{"simplified":"她轻而易举地通过了考试。","english":"She passed the exam with ease.","traditional":"她輕而易舉地通過了考試。"}],"synonyms":["不费吹灰之力","易如反掌"],"antonyms":["困难重重"],"confusedWith":[{"id":"不费吹灰之力","note":"This idiom implies no effort at all, while '轻而易举' suggests ease but not necessarily zero effort."}],"traditional":"輕而易舉","pinyinOverride":null},{"id":"guo-yi-bu-qu","simplified":"过意不去","literalMeaning":"pass meaning not go","figurativeMeaning":"to feel apologetic or sorry about something","englishEquivalents":["feel guilty","feel bad about","have a guilty conscience"],"shortGloss":"feel apologetic or guilty","characters":[{"char":"过","meaning":"pass, exceed"},{"char":"意","meaning":"meaning, intention"},{"char":"不","meaning":"not"},{"char":"去","meaning":"go"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '过意不去' is used to express a feeling of guilt or regret when one believes they have wronged someone or failed to meet expectations. It conveys a sense of personal responsibility and the desire to make amends.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","complement"],"structure":"modifier-head","register":"commonly used in both spoken and written Chinese, informal contexts","connotation":"negative","commonMistakes":"Learners often confuse this idiom with '过意不去' (guo-yi-bu-qu) in the sense of 'unable to go', but it specifically refers to feeling sorry or guilty. It's important to use it in contexts where an apology or regret is involved.","canStandAlone":false},"examples":[{"simplified":"他因为没能参加朋友的婚礼而过意不去。","english":"He felt guilty for not being able to attend his friend's wedding.","traditional":"他因為沒能參加朋友的婚禮而過意不去。"},{"simplified":"我对昨天的误会感到过意不去。","english":"I feel sorry about the misunderstanding yesterday.","traditional":"我對昨天的誤會感到過意不去。"}],"synonyms":["内疚","歉疚"],"antonyms":[],"confusedWith":[{"id":"过不去","note":"过不去 (guo-bu-qu) means 'unable to pass' or 'difficult to deal with', which is different from feeling sorry or guilty."}],"traditional":"過意不去","pinyinOverride":null},{"id":"yun-chou-wei-wo","simplified":"运筹帷幄","literalMeaning":"plan within the tent","figurativeMeaning":"to strategize and make plans from behind the scenes","englishEquivalents":["call the shots","pull the strings"],"shortGloss":"strategize behind the scenes","characters":[{"char":"运","meaning":"to manage; to plan"},{"char":"筹","meaning":"to strategize; to make plans"},{"char":"帷","meaning":"tent; curtain"},{"char":"幄","meaning":"tent; canopy"}],"origin":{"period":"Han Dynasty (202 BCE – 220 CE)","sourceText":"《史记·高祖本纪》","sourceTextEnglish":"Records of the Grand Historian, Annals of Gaozu","originalExcerpt":"运筹帷幄之中，决胜千里之外。","storyEnglish":"The idiom comes from a passage in the 'Records of the Grand Historian' by Sima Qian, describing how Liu Bang, the founder of the Han Dynasty, was able to make strategic decisions from within his tent that led to victories far away on the battlefield. It highlights the importance of strategic planning and leadership from behind the scenes.","historicalFigures":["Liu Bang"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"literary, but widely understood and used in both formal and informal contexts","connotation":"positive","commonMistakes":"Learners often confuse this idiom with those that imply direct action rather than planning. It specifically refers to strategizing and planning, not executing tasks directly.","canStandAlone":false},"examples":[{"simplified":"在这次竞选中，他运筹帷幄，最终取得了胜利。","english":"In this election, he strategized behind the scenes and ultimately achieved victory.","traditional":"在這次競選中，他運籌帷幄，最終取得了勝利。"},{"simplified":"她虽然不在前线，但一直在运筹帷幄，提供重要的决策。","english":"Although she is not on the front lines, she has been strategizing behind the scenes, providing crucial decisions.","traditional":"她雖然不在前線，但一直在運籌帷幄，提供重要的決策。"}],"synonyms":["决胜千里"],"antonyms":[],"confusedWith":[{"id":"身先士卒","note":"运筹帷幄 refers to planning and strategizing, while 身先士卒 refers to leading by example, often in a direct and active manner."}],"traditional":"運籌帷幄","pinyinOverride":null},{"id":"yuan-jin-wen-ming","simplified":"远近闻名","literalMeaning":"far and near, heard of name","figurativeMeaning":"widely known; famous far and wide","englishEquivalents":["famous far and wide","well-known","renowned"],"shortGloss":"widely known","characters":[{"char":"远","meaning":"far"},{"char":"近","meaning":"near"},{"char":"闻","meaning":"heard"},{"char":"名","meaning":"name; reputation"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '远近闻名' describes someone or something that is known by people both nearby and far away. It emphasizes a wide-reaching reputation, suggesting that the fame or renown extends over a large area. The phrase is often used to highlight the popularity or prominence of a person, place, or event.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"coordinate","register":"commonly used in both spoken and written Chinese","connotation":"positive","commonMistakes":"Learners might confuse '远近闻名' with idioms that imply notoriety rather than fame. It is important to remember that this idiom has a positive connotation, referring to a good reputation.","canStandAlone":false},"examples":[{"simplified":"这家餐厅在当地远近闻名。","english":"This restaurant is well-known in the area.","traditional":"這家餐廳在當地遠近聞名。"},{"simplified":"他的艺术作品远近闻名，吸引了许多游客。","english":"His artwork is famous far and wide, attracting many visitors.","traditional":"他的藝術作品遠近聞名，吸引了許多遊客。"}],"synonyms":["家喻户晓","名声大振"],"antonyms":[],"confusedWith":[{"id":"臭名远扬","note":"While '远近闻名' has a positive connotation of being well-known, '臭名远扬' means to be infamous or notorious."}],"traditional":"遠近聞名","pinyinOverride":null},{"id":"po-bu-ji-dai","simplified":"迫不及待","literalMeaning":"urgent not reach wait","figurativeMeaning":"too impatient to wait; eager to do something immediately","englishEquivalents":["can't wait","eager beaver"],"shortGloss":"too impatient to wait","characters":[{"char":"迫","meaning":"urgent; pressing"},{"char":"不","meaning":"not"},{"char":"及","meaning":"reach"},{"char":"待","meaning":"wait"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '迫不及待' describes a situation where someone is so eager or impatient that they cannot wait any longer. It is commonly used in modern Chinese to express a strong desire to do something immediately.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["adverbial","predicate"],"structure":"modifier-head","register":"commonly used in both spoken and written Chinese","connotation":"neutral","commonMistakes":"Learners often confuse this idiom with '急不可耐', which also means being impatient but carries a slightly more negative connotation of being rash or reckless.","canStandAlone":false},"examples":[{"simplified":"他迫不及待地打开了礼物。","english":"He couldn't wait to open the gift.","traditional":"他迫不及待地打開了禮物。"},{"simplified":"新电影上映了，她迫不及待地去看。","english":"The new movie was released, and she couldn't wait to see it.","traditional":"新電影上映了，她迫不及待地去看。"}],"synonyms":["急不可耐"],"antonyms":[],"confusedWith":[{"id":"急不可耐","note":"急不可耐 implies a more negative sense of impatience, suggesting rashness."}],"traditional":"迫不及待","pinyinOverride":null},{"id":"zhong-zhong-zhi-zhong","simplified":"重中之重","literalMeaning":"the most important among the important","figurativeMeaning":"the top priority; the most important thing","englishEquivalents":["top priority","of utmost importance"],"shortGloss":"top priority","characters":[{"char":"重","meaning":"important"},{"char":"中","meaning":"among"},{"char":"之","meaning":"of"},{"char":"重","meaning":"important"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '重中之重' is used to emphasize that something is the most important among a group of important things. It highlights the top priority or the most crucial aspect that requires attention.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["subject","predicate","object","attributive"],"structure":"modifier-head","register":"commonly used in both formal and informal contexts","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with other expressions of importance, but '重中之重' specifically denotes the highest priority among several important things.","canStandAlone":false},"examples":[{"simplified":"在这个项目中，安全是重中之重。","english":"In this project, safety is the top priority.","traditional":"在這個項目中，安全是重中之重。"},{"simplified":"我们必须把客户满意度作为公司的重中之重。","english":"We must make customer satisfaction the company's top priority.","traditional":"我們必須把客戶滿意度作為公司的重中之重。"}],"synonyms":["首要任务","头等大事"],"antonyms":[],"confusedWith":[],"traditional":"重中之重","pinyinOverride":null},{"id":"zhen-feng-xiang-dui","simplified":"针锋相对","literalMeaning":"needle point mutually opposed","figurativeMeaning":"to engage in a tit-for-tat confrontation; to go head-to-head","englishEquivalents":["tit for tat","head-to-head","eye for an eye"],"shortGloss":"direct confrontation","characters":[{"char":"针","meaning":"needle"},{"char":"锋","meaning":"point, tip"},{"char":"相","meaning":"mutually"},{"char":"对","meaning":"oppose, counter"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '针锋相对' describes a situation where two parties are engaged in a direct confrontation, each countering the other's moves with equal force or precision. The imagery of needle points facing each other suggests a sharp, precise, and potentially tense standoff.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"modifier-head","register":"common in both spoken and written Chinese, used in formal and informal contexts","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with more aggressive or violent idioms. '针锋相对' implies a strategic and precise confrontation, not necessarily hostile or physical.","canStandAlone":false},"examples":[{"simplified":"在辩论中，他们针锋相对，互不相让。","english":"In the debate, they went head-to-head, neither giving an inch.","traditional":"在辯論中，他們針鋒相對，互不相讓。"},{"simplified":"两国在贸易谈判中针锋相对，难以达成协议。","english":"The two countries were in a tit-for-tat confrontation during the trade negotiations, making it difficult to reach an agreement.","traditional":"兩國在貿易談判中針鋒相對，難以達成協議。"}],"synonyms":["针尖对麦芒","针锋相对"],"antonyms":["和睦相处"],"confusedWith":[{"id":"以牙还牙","note":"While both involve retaliation, '以牙还牙' suggests revenge or retribution, whereas '针锋相对' is more about strategic confrontation."}],"traditional":"針鋒相對","pinyinOverride":null},{"id":"cuo-zong-fu-za","simplified":"错综复杂","literalMeaning":"interwoven and complex","figurativeMeaning":"intricate and complicated; having a complex and tangled situation","englishEquivalents":["intricate and complex","tangled web","complicated situation"],"shortGloss":"intricate and complex","characters":[{"char":"错","meaning":"interwoven"},{"char":"综","meaning":"intertwined"},{"char":"复","meaning":"complex"},{"char":"杂","meaning":"mixed"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '错综复杂' is used to describe situations, systems, or problems that are highly intricate and complicated. It conveys the idea of multiple elements being interwoven in a way that makes them difficult to unravel or understand. The phrase is often used in contexts where there are many interconnected parts or factors contributing to a complex whole.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["attributive","predicate"],"structure":"coordinate","register":"commonly used in both formal and informal contexts to describe complex situations","connotation":"neutral","commonMistakes":"Learners often confuse '错综复杂' with simpler terms for 'complex' without realizing it implies a high degree of intricacy and interconnection. It should not be used for situations that are merely complicated but not interwoven.","canStandAlone":false},"examples":[{"simplified":"这个问题错综复杂，需要花时间仔细分析。","english":"This problem is intricate and complex, and requires time for careful analysis.","traditional":"這個問題錯綜複雜，需要花時間仔細分析。"},{"simplified":"国际关系错综复杂，不能简单化处理。","english":"International relations are intricate and complex, and cannot be handled simplistically.","traditional":"國際關係錯綜複雜，不能簡單化處理。"}],"synonyms":["盘根错节","纷繁复杂"],"antonyms":["简单明了"],"confusedWith":[{"id":"复杂","note":"复杂 means 'complex' but lacks the nuance of being interwoven or intricately connected like 错综复杂."}],"traditional":"錯綜複雜","pinyinOverride":null},{"id":"qie-er-bu-she","simplified":"锲而不舍","literalMeaning":"chisel and not give up","figurativeMeaning":"to persevere with determination; to keep on working at something without giving up","englishEquivalents":["persevere","keep at it","never give up"],"shortGloss":"persevere with determination","characters":[{"char":"锲","meaning":"to chisel"},{"char":"而","meaning":"and"},{"char":"不","meaning":"not"},{"char":"舍","meaning":"give up"}],"origin":{"period":"Warring States period (475–221 BCE)","sourceText":"《荀子·劝学》","sourceTextEnglish":"Xunzi, Encouraging Learning","originalExcerpt":"锲而舍之，朽木不折；锲而不舍，金石可镂。","storyEnglish":"The idiom comes from a passage in the 'Xunzi', where it is used to illustrate the importance of perseverance. The text compares the act of chiseling to the process of learning or achieving a goal. If one chisels and then gives up, even rotten wood cannot be carved. However, if one chisels without giving up, even metal and stone can be engraved. This metaphor emphasizes the power of persistence and determination in overcoming obstacles.","historicalFigures":["Xunzi"],"relatedIdiomsFromSameSource":["学而不厌"]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"coordinate","register":"literary, but very widely understood and used in ordinary speech","connotation":"positive","commonMistakes":"Learners might confuse this idiom with similar ones that emphasize effort but not necessarily perseverance. It's important to note that this idiom specifically highlights the aspect of not giving up.","canStandAlone":false},"examples":[{"simplified":"他在学习上锲而不舍，最终考上了理想的大学。","english":"He persevered in his studies and eventually got into his dream university.","traditional":"他在學習上鍥而不捨，最終考上了理想的大學。"},{"simplified":"只要锲而不舍，你一定能实现自己的目标。","english":"As long as you persevere, you will definitely achieve your goals.","traditional":"只要鍥而不捨，你一定能實現自己的目標。"}],"synonyms":["坚持不懈","持之以恒"],"antonyms":["半途而废"],"confusedWith":[{"id":"坚持不懈","note":"Both emphasize perseverance, but 锲而不舍 uses a metaphor of chiseling, while 坚持不懈 is more direct."}],"traditional":"鍥而不捨","pinyinOverride":null},{"id":"sui-chu-ke-jian","simplified":"随处可见","literalMeaning":"everywhere can be seen","figurativeMeaning":"ubiquitous; can be seen everywhere","englishEquivalents":["common as dirt","a dime a dozen"],"shortGloss":"ubiquitous; everywhere","characters":[{"char":"随","meaning":"everywhere; wherever"},{"char":"处","meaning":"place; location"},{"char":"可","meaning":"can; able to"},{"char":"见","meaning":"see; be seen"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '随处可见' is commonly used to describe something that is so common or widespread that it can be seen everywhere. It does not have a specific origin story but is used in modern Chinese to express the ubiquity of an object or phenomenon.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"subject-predicate","register":"neutral, commonly used in both spoken and written Chinese","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with others that imply rarity or scarcity. It's important to remember that '随处可见' emphasizes the commonness and widespread nature of something.","canStandAlone":false},"examples":[{"simplified":"在这个城市，咖啡馆随处可见。","english":"In this city, coffee shops can be seen everywhere.","traditional":"在這個城市，咖啡館隨處可見。"},{"simplified":"现代社会中，智能手机随处可见。","english":"In modern society, smartphones are ubiquitous.","traditional":"現代社會中，智能手機隨處可見。"}],"synonyms":["比比皆是"],"antonyms":["凤毛麟角"],"confusedWith":[{"id":"凤毛麟角","note":"While '随处可见' means something is common, '凤毛麟角' means something is extremely rare."}],"traditional":"隨處可見","pinyinOverride":null},{"id":"sui-xin-suo-yu","simplified":"随心所欲","literalMeaning":"follow heart's desires","figurativeMeaning":"to do as one pleases; to follow one's inclinations","englishEquivalents":["do as you please","follow your heart"],"shortGloss":"do as one pleases","characters":[{"char":"随","meaning":"follow"},{"char":"心","meaning":"heart"},{"char":"所","meaning":"that which"},{"char":"欲","meaning":"desire"}],"origin":{"period":"Warring States period (475–221 BCE)","sourceText":"《论语·为政》","sourceTextEnglish":"The Analects of Confucius, Chapter 2","originalExcerpt":"从心所欲，不逾矩。","storyEnglish":"This idiom originates from 'The Analects of Confucius,' where Confucius describes reaching an age where he could follow his heart's desires without overstepping boundaries. It reflects the idea of acting freely while maintaining moral integrity.","historicalFigures":["Confucius"],"relatedIdiomsFromSameSource":["温故知新","学而不厌"]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"commonly used in both formal and informal contexts","connotation":"neutral","commonMistakes":"Learners often confuse this idiom with '为所欲为', which implies acting without regard for rules or consequences. '随心所欲' suggests freedom within moral or social boundaries.","canStandAlone":false},"examples":[{"simplified":"退休后，他终于可以随心所欲地生活。","english":"After retirement, he can finally live as he pleases.","traditional":"退休後，他終於可以隨心所欲地生活。"},{"simplified":"她总是随心所欲地选择自己的道路。","english":"She always chooses her own path as she pleases.","traditional":"她總是隨心所欲地選擇自己的道路。"}],"synonyms":["为所欲为"],"antonyms":["循规蹈矩"],"confusedWith":[{"id":"为所欲为","note":"为所欲为 implies acting without regard for rules, whereas 随心所欲 suggests freedom within boundaries."}],"traditional":"隨心所欲","pinyinOverride":null},{"id":"sui-shi-sui-di","simplified":"随时随地","literalMeaning":"at any time, at any place","figurativeMeaning":"anytime and anywhere; always ready and available","englishEquivalents":["anytime, anywhere","at all times and places"],"shortGloss":"anytime, anywhere","characters":[{"char":"随","meaning":"follow; at one's convenience"},{"char":"时","meaning":"time"},{"char":"随","meaning":"follow; at one's convenience"},{"char":"地","meaning":"place"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '随时随地' is commonly used to express the idea of being ready or available at any time and in any place. It is often used in contexts where flexibility and readiness are emphasized, such as customer service or mobile technology.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["adverbial"],"structure":"modifier-head","register":"common in both spoken and written Chinese, informal to neutral","connotation":"neutral","commonMistakes":"Learners might mistakenly use this idiom in contexts where specific times or places are required, rather than expressing flexibility. It should be used to indicate availability or readiness without constraints.","canStandAlone":false},"examples":[{"simplified":"现代科技让我们可以随时随地获取信息。","english":"Modern technology allows us to access information anytime and anywhere.","traditional":"現代科技讓我們可以隨時隨地獲取信息。"},{"simplified":"他总是随时随地准备帮助别人。","english":"He is always ready to help others anytime and anywhere.","traditional":"他總是隨時隨地準備幫助別人。"}],"synonyms":[],"antonyms":[],"confusedWith":[],"traditional":"隨時隨地","pinyinOverride":null},{"id":"nan-yi-zhi-xin","simplified":"难以置信","literalMeaning":"difficult to believe","figurativeMeaning":"hard to believe; incredible","englishEquivalents":["hard to believe","incredible","unbelievable"],"shortGloss":"hard to believe","characters":[{"char":"难","meaning":"difficult"},{"char":"以","meaning":"to"},{"char":"置","meaning":"to place"},{"char":"信","meaning":"belief"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '难以置信' is commonly used in modern Chinese to express skepticism or astonishment at something that seems too extraordinary to be true. Its origins are not tied to a specific classical text, and it likely evolved as a natural expression of disbelief in everyday language.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","complement"],"structure":"modifier-head","register":"widely used in both written and spoken Chinese","connotation":"neutral","commonMistakes":"Learners often confuse '难以置信' with '不可思议', which also means 'unbelievable' but carries a stronger sense of something being beyond comprehension. '难以置信' is more about personal disbelief.","canStandAlone":false},"examples":[{"simplified":"他的成功故事真是难以置信。","english":"His success story is truly hard to believe.","traditional":"他的成功故事真是難以置信。"},{"simplified":"这个消息让人难以置信。","english":"This news is hard to believe.","traditional":"這個消息讓人難以置信。"}],"synonyms":["不可思议"],"antonyms":[],"confusedWith":[{"id":"不可思议","note":"While both express disbelief, '不可思议' implies something is beyond comprehension, whereas '难以置信' focuses on personal incredulity."}],"traditional":"難以置信","pinyinOverride":null},{"id":"nan-de-yi-jian","simplified":"难得一见","literalMeaning":"difficult to obtain one sight","figurativeMeaning":"rarely seen; a rare sight","englishEquivalents":["once in a blue moon","rare as hen's teeth"],"shortGloss":"a rare sight","characters":[{"char":"难","meaning":"difficult"},{"char":"得","meaning":"to obtain"},{"char":"一","meaning":"one"},{"char":"见","meaning":"to see"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '难得一见' is used to describe something that is rarely seen or encountered. It emphasizes the rarity and special nature of the event or object being referred to. The phrase likely evolved from common speech to express the idea of something being so uncommon that it is difficult to even catch a glimpse of it.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"modifier-head","register":"widely used in both formal and informal contexts","connotation":"neutral","commonMistakes":"Learners often confuse this idiom with similar phrases that mean 'difficult to achieve' rather than 'rarely seen'. It's important to remember that this idiom specifically refers to the rarity of seeing or encountering something.","canStandAlone":false},"examples":[{"simplified":"这幅画是难得一见的艺术珍品。","english":"This painting is a rare artistic treasure.","traditional":"這幅畫是難得一見的藝術珍品。"},{"simplified":"在城市里看到这么多星星真是难得一见。","english":"Seeing so many stars in the city is truly a rare sight.","traditional":"在城市裡看到這麼多星星真是難得一見。"}],"synonyms":["凤毛麟角"],"antonyms":[],"confusedWith":[{"id":"难能可贵","note":"难能可贵 means 'commendable' or 'praiseworthy', focusing on the value of achieving something difficult, not the rarity of seeing it."}],"traditional":"難得一見","pinyinOverride":null},{"id":"nan-neng-ke-gui","simplified":"难能可贵","literalMeaning":"difficult to achieve, worthy of praise","figurativeMeaning":"something that is commendable or praiseworthy because it is hard to achieve","englishEquivalents":["commendable","praiseworthy","worthy of admiration"],"shortGloss":"commendable achievement","characters":[{"char":"难","meaning":"difficult"},{"char":"能","meaning":"able to"},{"char":"可","meaning":"worthy"},{"char":"贵","meaning":"valuable, praiseworthy"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '难能可贵' is used to describe actions, achievements, or qualities that are particularly commendable because they are difficult to accomplish. It highlights the value and worthiness of something that is not easily attainable.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["attributive","predicate"],"structure":"modifier-head","register":"widely used in both formal and informal contexts","connotation":"positive","commonMistakes":"Learners might confuse this idiom with general praise, but it specifically emphasizes the difficulty and worthiness of the achievement. It should not be used for ordinary or easily achieved actions.","canStandAlone":false},"examples":[{"simplified":"他在这么短的时间内完成了任务，真是难能可贵。","english":"He completed the task in such a short time, which is truly commendable.","traditional":"他在這麼短的時間內完成了任務，真是難能可貴。"},{"simplified":"在逆境中保持乐观是一种难能可贵的品质。","english":"Maintaining optimism in adversity is a commendable quality.","traditional":"在逆境中保持樂觀是一種難能可貴的品質。"}],"synonyms":["可圈可点","值得称赞"],"antonyms":[],"confusedWith":[{"id":"可圈可点","note":"Both idioms express commendation, but '可圈可点' emphasizes noteworthy aspects rather than difficulty."}],"traditional":"難能可貴","pinyinOverride":null},{"id":"ji-si-guang-yi","simplified":"集思广益","literalMeaning":"gather ideas, broaden benefits","figurativeMeaning":"to pool ideas for greater benefit; to benefit from collective wisdom","englishEquivalents":["two heads are better than one","many hands make light work"],"shortGloss":"pool ideas for greater benefit","characters":[{"char":"集","meaning":"gather"},{"char":"思","meaning":"thoughts; ideas"},{"char":"广","meaning":"broad; wide"},{"char":"益","meaning":"benefit; advantage"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '集思广益' emphasizes the value of collective thinking and collaboration. It suggests that when people come together to share their ideas and insights, the outcome is more beneficial and effective than individual efforts. This concept is widely appreciated in teamwork and collaborative environments.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"commonly used in both formal and informal contexts","connotation":"positive","commonMistakes":"Learners might mistakenly use this idiom in contexts where individual effort is emphasized, rather than collaboration. It's important to use it in situations involving group input or teamwork.","canStandAlone":false},"examples":[{"simplified":"在这个项目中，我们需要集思广益，才能找到最佳解决方案。","english":"In this project, we need to pool our ideas to find the best solution.","traditional":"在這個項目中，我們需要集思廣益，才能找到最佳解決方案。"},{"simplified":"公司鼓励员工集思广益，以推动创新。","english":"The company encourages employees to pool their ideas to drive innovation.","traditional":"公司鼓勵員工集思廣益，以推動創新。"}],"synonyms":["群策群力"],"antonyms":[],"confusedWith":[],"traditional":"集思廣益","pinyinOverride":null},{"id":"xue-shang-jia-shuang","simplified":"雪上加霜","literalMeaning":"add frost on top of snow","figurativeMeaning":"to make a bad situation worse","englishEquivalents":["add insult to injury","make matters worse"],"shortGloss":"make a bad situation worse","characters":[{"char":"雪","meaning":"snow"},{"char":"上","meaning":"on top of"},{"char":"加","meaning":"add"},{"char":"霜","meaning":"frost"}],"origin":{"period":"Southern and Northern Dynasties (420–589 CE)","sourceText":"《晋书·谢安传》","sourceTextEnglish":"Book of Jin, Biography of Xie An","originalExcerpt":"谢安曰：‘此所谓雪上加霜也。’","storyEnglish":"The idiom originates from a story about Xie An, a prominent statesman during the Eastern Jin Dynasty. When faced with additional troubles on top of existing ones, he remarked that it was like 'adding frost on top of snow,' signifying the compounding of difficulties.","historicalFigures":["Xie An"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"widely used in both formal and informal contexts","connotation":"negative","commonMistakes":"Learners often confuse this idiom with similar expressions that imply simple difficulty, but 雪上加霜 specifically refers to worsening an already bad situation.","canStandAlone":false},"examples":[{"simplified":"他已经很累了，现在又生病了，真是雪上加霜。","english":"He was already very tired, and now he's sick too, which really makes matters worse.","traditional":"他已經很累了，現在又生病了，真是雪上加霜。"},{"simplified":"公司业绩不好，裁员更是雪上加霜。","english":"The company's performance was poor, and the layoffs only made matters worse.","traditional":"公司業績不好，裁員更是雪上加霜。"}],"synonyms":["祸不单行"],"antonyms":[],"confusedWith":[{"id":"祸不单行","note":"While both idioms involve misfortune, 雪上加霜 emphasizes worsening an existing bad situation, whereas 祸不单行 suggests that misfortunes often come together."}],"traditional":"雪上加霜","pinyinOverride":null},{"id":"mian-mu-quan-fei","simplified":"面目全非","literalMeaning":"face entirely not","figurativeMeaning":"to be changed beyond recognition","englishEquivalents":["unrecognizable","a complete transformation"],"shortGloss":"changed beyond recognition","characters":[{"char":"面","meaning":"face"},{"char":"目","meaning":"appearance"},{"char":"全","meaning":"entirely"},{"char":"非","meaning":"not"}],"origin":{"period":"Tang Dynasty (618–907 CE)","sourceText":"《南柯太守传》","sourceTextEnglish":"The Governor of Nanke","originalExcerpt":"及还，宫室器械，一皆面目全非，莫可识认。","storyEnglish":"In the story 'The Governor of Nanke', a man dreams of living a life of luxury and power in an ant kingdom. When he wakes up, he finds that everything he experienced was just a dream, and the world around him has changed so much that it is unrecognizable.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"subject-predicate","register":"commonly used in both formal and informal contexts","connotation":"neutral","commonMistakes":"Learners often confuse this idiom with similar expressions that imply a positive transformation. However, 面目全非 is neutral and does not imply whether the change is good or bad.","canStandAlone":false},"examples":[{"simplified":"经过多年的发展，这个城市已经面目全非。","english":"After many years of development, this city has changed beyond recognition.","traditional":"經過多年的發展，這個城市已經面目全非。"},{"simplified":"他回到家乡，发现一切都面目全非。","english":"He returned to his hometown and found that everything had changed beyond recognition.","traditional":"他回到家鄉，發現一切都面目全非。"}],"synonyms":[],"antonyms":[],"confusedWith":[{"id":"焕然一新","note":"焕然一新 implies a positive, refreshing change, whereas 面目全非 is neutral and focuses on the extent of change."}],"traditional":"面目全非","pinyinOverride":null},{"id":"mian-hong-er-chi","simplified":"面红耳赤","literalMeaning":"face red, ears scarlet","figurativeMeaning":"to be flushed with embarrassment or anger","englishEquivalents":["red-faced","blushing with embarrassment"],"shortGloss":"flushed with embarrassment or anger","characters":[{"char":"面","meaning":"face"},{"char":"红","meaning":"red"},{"char":"耳","meaning":"ears"},{"char":"赤","meaning":"scarlet"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '面红耳赤' describes someone whose face and ears turn red, typically due to embarrassment or anger. This vivid imagery captures the physical reaction that often accompanies strong emotions. The expression is widely used in both spoken and written Chinese to describe such situations.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","complement"],"structure":"coordinate","register":"common in both spoken and written Chinese","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with those that describe anger or embarrassment without the physical reaction. It's important to note that '面红耳赤' specifically refers to the visible change in complexion.","canStandAlone":false},"examples":[{"simplified":"他被老师批评后，面红耳赤，不知道说什么好。","english":"After being criticized by the teacher, he was red-faced and didn't know what to say.","traditional":"他被老師批評後，面紅耳赤，不知道說什麼好。"},{"simplified":"她因为说错话而面红耳赤。","english":"She blushed with embarrassment because she misspoke.","traditional":"她因為說錯話而面紅耳赤。"}],"synonyms":["脸红脖子粗"],"antonyms":[],"confusedWith":[{"id":"怒发冲冠","note":"While both idioms can describe anger, '怒发冲冠' specifically refers to extreme anger, often without the physical aspect of blushing."}],"traditional":"面紅耳赤","pinyinOverride":null},{"id":"mian-mian-ju-dao","simplified":"面面俱到","literalMeaning":"every aspect is attended to","figurativeMeaning":"to attend to every detail; to cover all aspects","englishEquivalents":["leave no stone unturned","cover all bases"],"shortGloss":"attend to every detail","characters":[{"char":"面","meaning":"aspect, side"},{"char":"面","meaning":"aspect, side"},{"char":"俱","meaning":"all, every"},{"char":"到","meaning":"arrive, reach"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '面面俱到' is used to describe a situation where someone has considered or attended to all aspects of a matter. It emphasizes thoroughness and attention to detail, ensuring that nothing is overlooked.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"modifier-head","register":"commonly used in both written and spoken Chinese","connotation":"positive","commonMistakes":"Learners might confuse this idiom with others that suggest thoroughness but lack the nuance of attending to every aspect. It's important to use it when emphasizing comprehensive coverage.","canStandAlone":false},"examples":[{"simplified":"他在准备这次会议时，面面俱到，确保没有遗漏任何细节。","english":"He attended to every detail while preparing for the meeting, ensuring nothing was overlooked.","traditional":"他在準備這次會議時，面面俱到，確保沒有遺漏任何細節。"},{"simplified":"为了让活动成功，我们需要面面俱到地计划。","english":"To ensure the success of the event, we need to plan thoroughly and cover all aspects.","traditional":"為了讓活動成功，我們需要面面俱到地計劃。"}],"synonyms":["无微不至"],"antonyms":["顾此失彼"],"confusedWith":[{"id":"无微不至","note":"While both idioms suggest thoroughness, '无微不至' emphasizes meticulous care in small details, often with a connotation of personal care or attention."}],"traditional":"面面俱到","pinyinOverride":null},{"id":"shun-qi-zi-ran","simplified":"顺其自然","literalMeaning":"follow its nature","figurativeMeaning":"to let things take their own course; to go with the flow","englishEquivalents":["let nature take its course","go with the flow"],"shortGloss":"let things take their own course","characters":[{"char":"顺","meaning":"follow; comply with"},{"char":"其","meaning":"its; their"},{"char":"自","meaning":"self; own"},{"char":"然","meaning":"nature; naturally"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '顺其自然' is often used to express the idea of accepting things as they are and not forcing changes. It suggests a philosophy of allowing events to unfold naturally rather than trying to control or alter them. This approach is often associated with a sense of peace and acceptance.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"commonly used in both spoken and written Chinese, informal","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with expressions that imply passivity or inaction. However, '顺其自然' does not suggest doing nothing; rather, it means not forcing things and allowing them to develop naturally.","canStandAlone":false},"examples":[{"simplified":"面对不可改变的事情，我们只能顺其自然。","english":"When faced with things we cannot change, we can only let nature take its course.","traditional":"面對不可改變的事情，我們只能順其自然。"},{"simplified":"他决定不再过于担心，而是顺其自然。","english":"He decided not to worry too much and just go with the flow.","traditional":"他決定不再過於擔心，而是順其自然。"}],"synonyms":["随遇而安"],"antonyms":["力挽狂澜"],"confusedWith":[{"id":"无为而治","note":"While both suggest a non-interfering approach, '无为而治' is more specific to governance and leadership, implying a Taoist philosophy of ruling by non-action."}],"traditional":"順其自然","pinyinOverride":null},{"id":"shun-li-cheng-zhang","simplified":"顺理成章","literalMeaning":"follow logic become chapter","figurativeMeaning":"something that follows naturally or logically; logical and well-organized","englishEquivalents":["fall into place","make perfect sense"],"shortGloss":"logical and natural progression","characters":[{"char":"顺","meaning":"follow; in accordance with"},{"char":"理","meaning":"logic; reason"},{"char":"成","meaning":"become; turn into"},{"char":"章","meaning":"chapter; order"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '顺理成章' is used to describe a situation where things develop in a logical and natural manner. It suggests that when something is reasonable and follows a logical sequence, the outcome will naturally be well-structured and coherent. The phrase is often used to describe writing or arguments that are clear and logically organized.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"modifier-head","register":"commonly used in both written and spoken Chinese","connotation":"positive","commonMistakes":"Learners often confuse this idiom with those that imply unexpected or sudden outcomes. '顺理成章' specifically refers to outcomes that are logical and expected.","canStandAlone":false},"examples":[{"simplified":"他的计划很周密，结果顺理成章地成功了。","english":"His plan was very thorough, and as a result, it succeeded logically and naturally.","traditional":"他的計劃很周密，結果順理成章地成功了。"},{"simplified":"经过多次讨论，大家的意见顺理成章地达成了一致。","english":"After many discussions, everyone's opinions naturally and logically reached a consensus.","traditional":"經過多次討論，大家的意見順理成章地達成了一致。"}],"synonyms":["水到渠成"],"antonyms":[],"confusedWith":[{"id":"突如其来","note":"突如其来 refers to something happening suddenly and unexpectedly, unlike 顺理成章 which implies a logical progression."}],"traditional":"順理成章","pinyinOverride":null},{"id":"gu-quan-da-ju","simplified":"顾全大局","literalMeaning":"consider the whole situation","figurativeMeaning":"to take the big picture into account; to consider the overall situation","englishEquivalents":["see the big picture","keep the big picture in mind"],"shortGloss":"consider the big picture","characters":[{"char":"顾","meaning":"consider"},{"char":"全","meaning":"whole, entire"},{"char":"大","meaning":"big, great"},{"char":"局","meaning":"situation, overall situation"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '顾全大局' is used to emphasize the importance of considering the overall situation or the bigger picture, rather than focusing on individual parts or personal interests. It is often used in contexts where making a decision requires taking into account the broader implications or the common good.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","object","adverbial"],"structure":"verb-object","register":"widely used in both formal and informal contexts","connotation":"positive","commonMistakes":"Learners might confuse this idiom with those that emphasize individual or small-scale considerations. It is important to remember that this idiom stresses the importance of the overall situation.","canStandAlone":false},"examples":[{"simplified":"在做决定时，我们必须顾全大局。","english":"When making decisions, we must consider the big picture.","traditional":"在做決定時，我們必須顧全大局。"},{"simplified":"为了公司的发展，他选择顾全大局，放弃了个人利益。","english":"For the sake of the company's development, he chose to consider the big picture and gave up personal interests.","traditional":"為了公司的發展，他選擇顧全大局，放棄了個人利益。"}],"synonyms":["统筹兼顾"],"antonyms":["目光短浅"],"confusedWith":[{"id":"目光短浅","note":"While '顾全大局' emphasizes considering the overall situation, '目光短浅' refers to having a short-sighted view."}],"traditional":"顧全大局","pinyinOverride":null},{"id":"gu-ming-si-yi","simplified":"顾名思义","literalMeaning":"consider the name, think of the meaning","figurativeMeaning":"as the name implies; the meaning is apparent from the name","englishEquivalents":["as the name suggests","self-explanatory"],"shortGloss":"as the name implies","characters":[{"char":"顾","meaning":"consider"},{"char":"名","meaning":"name"},{"char":"思","meaning":"think"},{"char":"义","meaning":"meaning"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '顾名思义' is used to express that the meaning of something can be easily understood from its name. It emphasizes the importance of names in conveying the essence or purpose of something.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["adverbial"],"structure":"modifier-head","register":"commonly used in both formal and informal contexts","connotation":"neutral","commonMistakes":"Learners sometimes use this idiom incorrectly by applying it to situations where the name does not clearly indicate the meaning. It should only be used when the name genuinely reflects the essence of the subject.","canStandAlone":false},"examples":[{"simplified":"这个产品的名字叫“速溶咖啡”，顾名思义，就是可以快速溶解的咖啡。","english":"The product is called 'instant coffee', which, as the name suggests, is coffee that dissolves quickly.","traditional":"這個產品的名字叫“速溶咖啡”，顧名思義，就是可以快速溶解的咖啡。"},{"simplified":"他的外号是“书虫”，顾名思义，他非常喜欢读书。","english":"His nickname is 'bookworm', which, as the name implies, means he loves reading.","traditional":"他的外號是“書蟲”，顧名思義，他非常喜歡讀書。"}],"synonyms":[],"antonyms":[],"confusedWith":[],"traditional":"顧名思義","pinyinOverride":null},{"id":"dian-dao-hei-bai","simplified":"颠倒黑白","literalMeaning":"invert black and white","figurativeMeaning":"to distort the truth; to misrepresent facts","englishEquivalents":["to turn things upside down","to twist the truth","to whitewash"],"shortGloss":"distort the truth","characters":[{"char":"颠","meaning":"invert, turn upside down"},{"char":"倒","meaning":"reverse, turn around"},{"char":"黑","meaning":"black"},{"char":"白","meaning":"white"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '颠倒黑白' is used to describe a situation where someone deliberately misrepresents facts or distorts the truth. The phrase literally means 'to invert black and white', symbolizing the reversal of truth and falsehood. It is often used to criticize those who manipulate information for their own benefit.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","object","adverbial"],"structure":"verb-object","register":"commonly used in both written and spoken Chinese","connotation":"negative","commonMistakes":"Learners might confuse this idiom with '混淆是非' (confuse right and wrong), but '颠倒黑白' specifically implies a deliberate act of misrepresentation rather than mere confusion.","canStandAlone":false},"examples":[{"simplified":"他总是颠倒黑白，让人无法相信他的话。","english":"He always distorts the truth, making it hard for people to trust what he says.","traditional":"他總是顛倒黑白，讓人無法相信他的話。"},{"simplified":"在法庭上，证人被指控颠倒黑白。","english":"In court, the witness was accused of distorting the truth.","traditional":"在法庭上，證人被指控顛倒黑白。"}],"synonyms":["混淆是非","指鹿为马"],"antonyms":["实事求是"],"confusedWith":[{"id":"混淆是非","note":"混淆是非 means to confuse right and wrong, which can be unintentional, unlike 颠倒黑白 which implies deliberate distortion."}],"traditional":"顛倒黑白","pinyinOverride":null},{"id":"feng-chui-yu-da","simplified":"风吹雨打","literalMeaning":"wind blows, rain beats","figurativeMeaning":"to withstand hardships and challenges","englishEquivalents":["weather the storm","stand the test of time"],"shortGloss":"endure hardships","characters":[{"char":"风","meaning":"wind"},{"char":"吹","meaning":"blows"},{"char":"雨","meaning":"rain"},{"char":"打","meaning":"beats"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '风吹雨打' is commonly used to describe the ability to endure and overcome difficult situations, much like how structures or people withstand the literal forces of wind and rain. It emphasizes resilience and perseverance in the face of adversity.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"coordinate","register":"commonly used in both spoken and written Chinese to describe resilience","connotation":"positive","commonMistakes":"Learners might confuse this idiom with others that describe natural phenomena without the connotation of endurance. It specifically implies resilience, not just exposure to elements.","canStandAlone":false},"examples":[{"simplified":"经过多年的风吹雨打，这座老房子依然坚固。","english":"After many years of weathering the storm, this old house remains sturdy.","traditional":"經過多年的風吹雨打，這座老房子依然堅固。"},{"simplified":"他在风吹雨打中成长，变得更加坚强。","english":"He grew stronger by enduring hardships and challenges.","traditional":"他在風吹雨打中成長，變得更加堅強。"}],"synonyms":["历经沧桑","饱经风霜"],"antonyms":[],"confusedWith":[{"id":"风雨同舟","note":"While '风雨同舟' emphasizes solidarity and mutual support during hardships, '风吹雨打' focuses on individual resilience and endurance."}],"traditional":"風吹雨打","pinyinOverride":null},{"id":"feng-he-ri-li","simplified":"风和日丽","literalMeaning":"wind gentle sun beautiful","figurativeMeaning":"a fine and sunny day with gentle breeze","englishEquivalents":["a beautiful day","a fair weather"],"shortGloss":"a fine and sunny day","characters":[{"char":"风","meaning":"wind"},{"char":"和","meaning":"gentle"},{"char":"日","meaning":"sun"},{"char":"丽","meaning":"beautiful"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '风和日丽' is used to describe a day with pleasant weather, characterized by a gentle breeze and beautiful sunshine. It is often used in literature and conversation to depict an ideal day for outdoor activities or to set a serene scene.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["attributive","adverbial"],"structure":"coordinate","register":"commonly used in both spoken and written Chinese","connotation":"positive","commonMistakes":"Learners might confuse this idiom with others that describe weather, but '风和日丽' specifically emphasizes both the pleasantness of the wind and the beauty of the sun. It should not be used to describe weather that is too hot or too windy.","canStandAlone":false},"examples":[{"simplified":"今天风和日丽，正适合去野餐。","english":"Today is a beautiful day with a gentle breeze, perfect for a picnic.","traditional":"今天風和日麗，正適合去野餐。"},{"simplified":"在风和日丽的日子里，公园里总是挤满了人。","english":"On fine and sunny days, the park is always crowded with people.","traditional":"在風和日麗的日子裡，公園裡總是擠滿了人。"}],"synonyms":["阳光明媚","风光旖旎"],"antonyms":["狂风暴雨","阴云密布"],"confusedWith":[{"id":"阳光明媚","note":"While both describe pleasant weather, '阳光明媚' focuses more on the brightness and warmth of the sun."}],"traditional":"風和日麗","pinyinOverride":null},{"id":"feng-tu-ren-qing","simplified":"风土人情","literalMeaning":"local customs and conditions","figurativeMeaning":"the local customs, culture, and social practices of a place","englishEquivalents":["local customs","cultural practices"],"shortGloss":"local customs and culture","characters":[{"char":"风","meaning":"customs, practices"},{"char":"土","meaning":"land, local"},{"char":"人","meaning":"people, human"},{"char":"情","meaning":"feelings, sentiments"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '风土人情' refers to the unique customs, traditions, and social practices of a particular region or community. It emphasizes the cultural and social aspects that define a place and its people. This idiom is often used to describe the distinctive cultural characteristics that one might encounter when visiting different areas.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["subject","object","attributive"],"structure":"coordinate","register":"commonly used in both formal and informal contexts to describe cultural aspects","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with others that describe specific cultural practices or festivals. It is important to note that '风土人情' refers broadly to the overall cultural and social atmosphere of a place, not specific events.","canStandAlone":false},"examples":[{"simplified":"每个国家都有自己独特的风土人情。","english":"Every country has its own unique local customs and culture.","traditional":"每個國家都有自己獨特的風土人情。"},{"simplified":"了解一个地方的风土人情有助于更好地融入当地生活。","english":"Understanding the local customs and culture of a place helps in better integrating into local life.","traditional":"瞭解一個地方的風土人情有助於更好地融入當地生活。"}],"synonyms":[],"antonyms":[],"confusedWith":[],"traditional":"風土人情","pinyinOverride":null},{"id":"feng-yu-wu-zu","simplified":"风雨无阻","literalMeaning":"wind and rain without obstruction","figurativeMeaning":"to carry on regardless of difficulties or obstacles","englishEquivalents":["come rain or shine"],"shortGloss":"carry on despite obstacles","characters":[{"char":"风","meaning":"wind"},{"char":"雨","meaning":"rain"},{"char":"无","meaning":"without"},{"char":"阻","meaning":"obstruction"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '风雨无阻' is often used to describe someone who is determined to continue their work or activities regardless of adverse conditions, such as bad weather. It emphasizes perseverance and commitment.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["adverbial"],"structure":"modifier-head","register":"commonly used in both spoken and written Chinese","connotation":"positive","commonMistakes":"Learners might confuse this idiom with others that involve weather, but '风雨无阻' specifically emphasizes persistence despite obstacles, not just enduring bad weather.","canStandAlone":false},"examples":[{"simplified":"无论天气如何，我们都风雨无阻地去上班。","english":"No matter the weather, we go to work come rain or shine.","traditional":"無論天氣如何，我們都風雨無阻地去上班。"},{"simplified":"他每天早上风雨无阻地跑步。","english":"He goes for a run every morning, come rain or shine.","traditional":"他每天早上風雨無阻地跑步。"}],"synonyms":[],"antonyms":[],"confusedWith":[],"traditional":"風雨無阻","pinyinOverride":null},{"id":"feng-can-lu-su","simplified":"风餐露宿","literalMeaning":"eat in the wind, sleep in the dew","figurativeMeaning":"to endure the hardships of travel or life in the open; to rough it","englishEquivalents":["rough it","live out in the open"],"shortGloss":"endure hardships of travel","characters":[{"char":"风","meaning":"wind"},{"char":"餐","meaning":"eat"},{"char":"露","meaning":"dew"},{"char":"宿","meaning":"sleep"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '风餐露宿' describes the experience of eating and sleeping in the open, exposed to the elements. It is often used to depict the hardships faced by travelers or those who live without shelter, enduring the wind and dew as they eat and sleep outdoors.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"coordinate","register":"commonly used in both written and spoken Chinese to describe enduring hardships, especially during travel","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with those that imply deliberate adventurousness or leisure. '风餐露宿' specifically emphasizes enduring hardship rather than seeking adventure.","canStandAlone":false},"examples":[{"simplified":"为了完成这次探险，他们不得不风餐露宿。","english":"To complete this expedition, they had to endure eating and sleeping in the open.","traditional":"為了完成這次探險，他們不得不風餐露宿。"},{"simplified":"他在旅途中风餐露宿，经历了许多困难。","english":"He roughed it during his travels, experiencing many hardships.","traditional":"他在旅途中風餐露宿，經歷了許多困難。"}],"synonyms":["餐风宿露"],"antonyms":[],"confusedWith":[{"id":"餐风宿露","note":"Essentially synonymous, but '餐风宿露' is a less common variant."}],"traditional":"風餐露宿","pinyinOverride":null},{"id":"fei-qin-zou-shou","simplified":"飞禽走兽","literalMeaning":"flying birds, running beasts","figurativeMeaning":"all kinds of animals; wildlife","englishEquivalents":["birds and beasts","all creatures great and small"],"shortGloss":"all kinds of animals","characters":[{"char":"飞","meaning":"flying"},{"char":"禽","meaning":"birds"},{"char":"走","meaning":"running"},{"char":"兽","meaning":"beasts"}],"origin":{"period":"Han Dynasty (206 BCE – 220 CE)","sourceText":"《淮南子·原道训》","sourceTextEnglish":"Huainanzi, Chapter on the Original Way","originalExcerpt":"飞禽走兽，莫不有养。","storyEnglish":"The idiom '飞禽走兽' originates from the 'Huainanzi', a philosophical text from the Han Dynasty. The text discusses the natural world, stating that all flying birds and running beasts are nurtured by the environment. This phrase has come to represent all kinds of animals in general.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["subject","object","attributive"],"structure":"coordinate","register":"commonly used in both written and spoken Chinese to refer to animals collectively","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with ones that refer to specific types of animals rather than all animals collectively. It is important to remember that this idiom encompasses all wildlife, not just birds or beasts alone.","canStandAlone":false},"examples":[{"simplified":"这片森林里有很多飞禽走兽。","english":"There are many birds and beasts in this forest.","traditional":"這片森林裡有很多飛禽走獸。"},{"simplified":"他对飞禽走兽的习性很感兴趣。","english":"He is very interested in the habits of wildlife.","traditional":"他對飛禽走獸的習性很感興趣。"}],"synonyms":["鸟兽虫鱼"],"antonyms":[],"confusedWith":[{"id":"鸟兽散","note":"飞禽走兽 refers to all kinds of animals, whereas 鸟兽散 describes a situation where people disperse in panic, like startled birds and beasts."}],"traditional":"飛禽走獸","pinyinOverride":null},{"id":"bao-jing-cang-sang","simplified":"饱经沧桑","literalMeaning":"fully experienced vicissitudes","figurativeMeaning":"having experienced many changes and hardships in life","englishEquivalents":["weathered many storms","seen it all"],"shortGloss":"experienced many hardships","characters":[{"char":"饱","meaning":"fully"},{"char":"经","meaning":"experienced"},{"char":"沧","meaning":"blue, vast (often used to denote the sea)"},{"char":"桑","meaning":"mulberry (often used to denote the land)"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '饱经沧桑' is believed to have originated from the imagery of the sea (沧海) turning into mulberry fields (桑田) and vice versa, symbolizing great changes over time. It describes someone who has lived through many significant changes and hardships, gaining wisdom and resilience.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"modifier-head","register":"literary, but widely used in both written and spoken Chinese","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with others that describe hardship but do not emphasize the aspect of change over time. It specifically refers to enduring and witnessing significant changes.","canStandAlone":false},"examples":[{"simplified":"他是一个饱经沧桑的老人，经历了许多风风雨雨。","english":"He is an elderly man who has weathered many storms and experienced much in life.","traditional":"他是一個飽經滄桑的老人，經歷了許多風風雨雨。"},{"simplified":"这座城市饱经沧桑，见证了历史的变迁。","english":"This city has experienced many vicissitudes and witnessed historical changes.","traditional":"這座城市飽經滄桑，見證了歷史的變遷。"}],"synonyms":["历尽沧桑","饱经风霜"],"antonyms":[],"confusedWith":[{"id":"饱经风霜","note":"Both idioms describe enduring hardships, but '饱经沧桑' emphasizes experiencing significant changes over time."}],"traditional":"飽經滄桑","pinyinOverride":null},{"id":"hai-ren-ting-wen","simplified":"骇人听闻","literalMeaning":"shocking to hear","figurativeMeaning":"shocking or horrifying; something that is appalling to hear about","englishEquivalents":["shocking","horrifying","appalling"],"shortGloss":"shocking or horrifying","characters":[{"char":"骇","meaning":"to shock or startle"},{"char":"人","meaning":"people"},{"char":"听","meaning":"to hear"},{"char":"闻","meaning":"to hear about"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '骇人听闻' is used to describe events or news that are so shocking or horrifying that they are difficult to believe. It is often used in the context of crime reports or unexpected disasters that leave people stunned.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["attributive","predicate"],"structure":"modifier-head","register":"commonly used in both written and spoken Chinese, especially in news and media to describe shocking events","connotation":"negative","commonMistakes":"Learners often confuse it with idioms that mean surprising or unexpected but lack the negative connotation of horror or shock. It should not be used for mildly surprising events.","canStandAlone":false},"examples":[{"simplified":"这起骇人听闻的谋杀案震惊了整个城市。","english":"This shocking murder case has stunned the entire city.","traditional":"這起駭人聽聞的謀殺案震驚了整個城市。"},{"simplified":"他的行为真是骇人听闻，令人无法理解。","english":"His actions are truly horrifying and beyond comprehension.","traditional":"他的行為真是駭人聽聞，令人無法理解。"}],"synonyms":["触目惊心","惊心动魄"],"antonyms":[],"confusedWith":[{"id":"惊人","note":"惊人 means surprising or astonishing, which can be positive or neutral, unlike the negative shock of 骇人听闻."}],"traditional":"駭人聽聞","pinyinOverride":null},{"id":"xian-wei-ren-zhi","simplified":"鲜为人知","literalMeaning":"rarely known by people","figurativeMeaning":"little known; rarely known or understood by people","englishEquivalents":["little-known","obscure","not widely known"],"shortGloss":"little known","characters":[{"char":"鲜","meaning":"rarely"},{"char":"为","meaning":"by"},{"char":"人","meaning":"people"},{"char":"知","meaning":"know"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '鲜为人知' is used to describe something that is not widely known or is obscure. It emphasizes the rarity of knowledge or awareness about a particular subject or fact among people.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"modifier-head","register":"widely used in both written and spoken Chinese, suitable for formal and informal contexts","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with others that imply secrecy or deliberate concealment, but '鲜为人知' simply refers to something not widely known, without any implication of intentional hiding.","canStandAlone":false},"examples":[{"simplified":"这本书的内容鲜为人知，但非常有趣。","english":"The content of this book is little known, but very interesting.","traditional":"這本書的內容鮮為人知，但非常有趣。"},{"simplified":"他在一个鲜为人知的小镇上长大。","english":"He grew up in a little-known small town.","traditional":"他在一個鮮為人知的小鎮上長大。"}],"synonyms":["默默无闻"],"antonyms":["家喻户晓"],"confusedWith":[{"id":"秘而不宣","note":"秘而不宣 implies deliberate secrecy, whereas 鲜为人知 simply means not widely known."}],"traditional":"鮮為人知","pinyinOverride":null},{"id":"ya-que-wu-sheng","simplified":"鸦雀无声","literalMeaning":"crows and sparrows make no sound","figurativeMeaning":"complete silence; so quiet you could hear a pin drop","englishEquivalents":["as silent as the grave","quiet as a mouse"],"shortGloss":"complete silence","characters":[{"char":"鸦","meaning":"crow"},{"char":"雀","meaning":"sparrow"},{"char":"无","meaning":"without; no"},{"char":"声","meaning":"sound; noise"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '鸦雀无声' is used to describe a situation where it is extremely quiet, so much so that even the birds, which are usually noisy, are silent. This expression emphasizes the depth of the silence, suggesting an atmosphere of tension or anticipation.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"subject-predicate","register":"commonly used in both spoken and written Chinese to describe silence","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with similar expressions that describe quietness but not absolute silence. It's important to use it when describing a situation of complete silence.","canStandAlone":false},"examples":[{"simplified":"会议室里鸦雀无声，大家都在等待经理的决定。","english":"The conference room was completely silent as everyone awaited the manager's decision.","traditional":"會議室裡鴉雀無聲，大家都在等待經理的決定。"},{"simplified":"演讲开始后，观众鸦雀无声，专心地听着。","english":"After the speech began, the audience was silent, listening attentively.","traditional":"演講開始後，觀眾鴉雀無聲，專心地聽著。"}],"synonyms":["万籁俱寂"],"antonyms":["人声鼎沸"],"confusedWith":[{"id":"万籁俱寂","note":"Both describe silence, but 万籁俱寂 emphasizes the absence of all natural sounds, not just birds."}],"traditional":"鴉雀無聲","pinyinOverride":null},{"id":"peng-cheng-wan-li","simplified":"鹏程万里","literalMeaning":"roc's journey of ten thousand miles","figurativeMeaning":"to have a bright future; to have great prospects","englishEquivalents":["the sky's the limit","to have a promising future"],"shortGloss":"great prospects","characters":[{"char":"鹏","meaning":"roc, a mythical giant bird"},{"char":"程","meaning":"journey, distance"},{"char":"万","meaning":"ten thousand"},{"char":"里","meaning":"miles, a traditional Chinese unit of distance"}],"origin":{"period":"Tang dynasty (618–907 CE)","sourceText":"《庄子·逍遥游》","sourceTextEnglish":"Zhuangzi, Free and Easy Wandering","originalExcerpt":"鹏之徙于南冥也，水击三千里，抟扶摇而上者九万里。","storyEnglish":"The idiom originates from the writings of Zhuangzi, a Daoist philosopher. In his work, he describes a mythical bird called the 'roc' (鹏) which can fly vast distances, symbolizing the idea of having great potential and boundless prospects. The roc's journey is an allegory for achieving great success and reaching new heights.","historicalFigures":["Zhuangzi"],"relatedIdiomsFromSameSource":["逍遥游"]},"usage":{"grammaticalRole":["subject","predicate","object","attributive"],"structure":"modifier-head","register":"literary, but widely used in both formal and informal contexts","connotation":"positive","commonMistakes":"Learners might confuse this idiom with others involving long journeys, but 鹏程万里 specifically implies great potential and success, not just travel.","canStandAlone":false},"examples":[{"simplified":"他刚刚大学毕业，前途似锦，鹏程万里。","english":"He just graduated from college and has a promising future ahead.","traditional":"他剛剛大學畢業，前途似錦，鵬程萬里。"},{"simplified":"祝你在新工作中鹏程万里，取得更大的成就。","english":"I wish you great success and achievements in your new job.","traditional":"祝你在新工作中鵬程萬里，取得更大的成就。"}],"synonyms":["前途无量","大展宏图"],"antonyms":[],"confusedWith":[{"id":"千里之行，始于足下","note":"This idiom emphasizes starting a journey with small steps, not the vast potential or success implied by 鹏程万里."}],"traditional":"鵬程萬里","pinyinOverride":null},{"id":"mo-mo-wu-wen","simplified":"默默无闻","literalMeaning":"silent and without reputation","figurativeMeaning":"unknown; without attracting attention or fame","englishEquivalents":["unknown","obscure","unsung"],"shortGloss":"unknown or obscure","characters":[{"char":"默","meaning":"silent"},{"char":"默","meaning":"silent"},{"char":"无","meaning":"without"},{"char":"闻","meaning":"reputation; fame"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '默默无闻' describes someone who is not well-known or famous, often due to their quiet nature or because they work behind the scenes. It emphasizes the lack of recognition or fame, despite possibly significant contributions or efforts.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"modifier-head","register":"widely used in both written and spoken Chinese","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with others that imply insignificance or lack of value. However, '默默无闻' specifically refers to the lack of public recognition, not the importance or quality of the work or person.","canStandAlone":false},"examples":[{"simplified":"他在公司里一直默默无闻，但他的工作非常出色。","english":"He has always been unknown in the company, but his work is outstanding.","traditional":"他在公司裡一直默默無聞，但他的工作非常出色。"},{"simplified":"这个默默无闻的科学家最终获得了诺贝尔奖。","english":"This obscure scientist eventually won the Nobel Prize.","traditional":"這個默默無聞的科學家最終獲得了諾貝爾獎。"}],"synonyms":["籍籍无名"],"antonyms":["名声大噪"],"confusedWith":[{"id":"籍籍无名","note":"Both imply lack of fame, but '籍籍无名' can suggest mediocrity, while '默默无闻' does not."}],"traditional":"默默無聞","pinyinOverride":null},{"id":"qi-xin-xie-li","simplified":"齐心协力","literalMeaning":"unite hearts and combine strengths","figurativeMeaning":"to work together with one heart and one mind; to collaborate effectively","englishEquivalents":["united we stand","pull together","teamwork makes the dream work"],"shortGloss":"work together harmoniously","characters":[{"char":"齐","meaning":"together; in unison"},{"char":"心","meaning":"heart; mind"},{"char":"协","meaning":"cooperate; coordinate"},{"char":"力","meaning":"strength; effort"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '齐心协力' emphasizes the importance of unity and cooperation. It suggests that when people work together with a shared purpose and combine their efforts, they can achieve great things. This concept has been valued in Chinese culture for centuries, though the exact origin of the phrase is not tied to a specific classical text.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"coordinate","register":"commonly used in both formal and informal contexts","connotation":"positive","commonMistakes":"Learners might confuse this idiom with similar phrases that emphasize individual effort rather than collective effort. It's important to remember that this idiom specifically highlights teamwork and collaboration.","canStandAlone":false},"examples":[{"simplified":"在这个项目中，我们需要齐心协力才能成功。","english":"In this project, we need to work together to succeed.","traditional":"在這個項目中，我們需要齊心協力才能成功。"},{"simplified":"只有齐心协力，我们才能克服困难。","english":"Only by working together can we overcome difficulties.","traditional":"只有齊心協力，我們才能克服困難。"}],"synonyms":["同心协力","众志成城"],"antonyms":["各自为政"],"confusedWith":[{"id":"各自为政","note":"While 齐心协力 emphasizes teamwork, 各自为政 refers to acting independently without coordination."}],"traditional":"齊心協力","pinyinOverride":null},{"id":"ai-wu-ji-wu","simplified":"爱屋及乌","literalMeaning":"love the house, reach the crow","figurativeMeaning":"to love someone and extend that love to those connected to them","englishEquivalents":["Love me, love my dog"],"shortGloss":"love extends to all connected","characters":[{"char":"爱","meaning":"love"},{"char":"屋","meaning":"house"},{"char":"及","meaning":"reach; extend to"},{"char":"乌","meaning":"crow"}],"origin":{"period":"Northern and Southern Dynasties (420–589 CE)","sourceText":"《世说新语·德行》","sourceTextEnglish":"A New Account of the Tales of the World, Virtuous Conduct","originalExcerpt":"王子敬云：‘吾爱其屋而及其乌。’","storyEnglish":"The idiom originates from a story in the 'A New Account of the Tales of the World' where Wang Zijin expressed his affection for a person by saying that he loved not only the person but also the house they lived in and even the crow on the roof. This illustrates how one's affection for someone can extend to everything associated with them.","historicalFigures":["Wang Zijin"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"literary, but widely understood and used in ordinary speech","connotation":"positive","commonMistakes":"Learners may confuse this idiom with expressions that simply mean 'to love everything indiscriminately'. It specifically refers to extending love from a person to their surroundings or associations.","canStandAlone":false},"examples":[{"simplified":"他对她的爱是爱屋及乌的，连她的宠物都很喜欢。","english":"His love for her is such that he even likes her pets.","traditional":"他對她的愛是愛屋及烏的，連她的寵物都很喜歡。"},{"simplified":"因为爱屋及乌，他对她的家人也很关心。","english":"Because of his love for her, he also cares deeply for her family.","traditional":"因為愛屋及烏，他對她的家人也很關心。"}],"synonyms":[],"antonyms":[],"confusedWith":[],"traditional":"愛屋及烏","pinyinOverride":null},{"id":"an-bu-jiu-ban","simplified":"按部就班","literalMeaning":"follow steps proceed orderly","figurativeMeaning":"to follow the prescribed order; to act according to convention","englishEquivalents":["follow the rules","by the book","step by step"],"shortGloss":"proceed methodically","characters":[{"char":"按","meaning":"follow"},{"char":"部","meaning":"steps; sections"},{"char":"就","meaning":"proceed"},{"char":"班","meaning":"order; class"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '按部就班' is believed to originate from the idea of following a set sequence or order, much like a book is divided into sections and chapters. It emphasizes the importance of adhering to a structured approach, whether in work, study, or other activities.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["adverbial","attributive"],"structure":"modifier-head","register":"commonly used in both formal and informal contexts","connotation":"neutral","commonMistakes":"Learners often confuse '按部就班' with '循规蹈矩', which also means following rules but carries a more rigid connotation. '按部就班' is more about following a logical order rather than strict adherence to rules.","canStandAlone":false},"examples":[{"simplified":"在学习新技能时，我们应该按部就班，循序渐进。","english":"When learning a new skill, we should proceed methodically, step by step.","traditional":"在學習新技能時，我們應該按部就班，循序漸進。"},{"simplified":"他做事总是按部就班，从不急于求成。","english":"He always works methodically, never rushing to achieve quick results.","traditional":"他做事總是按部就班，從不急於求成。"}],"synonyms":["循序渐进"],"antonyms":["急于求成"],"confusedWith":[{"id":"循规蹈矩","note":"Both involve following rules, but '循规蹈矩' implies strict adherence, while '按部就班' emphasizes orderly progression."}],"traditional":"按部就班","pinyinOverride":null},{"id":"bai-nian-shu-ren","simplified":"百年树人","literalMeaning":"a hundred years to cultivate a person","figurativeMeaning":"it takes a long time to nurture and educate a person","englishEquivalents":["Rome wasn't built in a day","It takes time to nurture talent"],"shortGloss":"nurturing talent takes time","characters":[{"char":"百","meaning":"hundred"},{"char":"年","meaning":"years"},{"char":"树","meaning":"to cultivate, to nurture"},{"char":"人","meaning":"person"}],"origin":{"period":"Qing Dynasty (1644–1912)","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom emphasizes the importance and the long-term effort required in educating and nurturing individuals. It suggests that just as it takes a long time to grow a tree, it takes even longer to cultivate a person's character and abilities. This idea has been echoed in various Chinese texts and teachings, highlighting the value placed on education and personal development.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"subject-predicate","register":"literary, but widely used in educational contexts","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with others that emphasize speed or efficiency, but this idiom specifically highlights the long-term nature of education and personal growth.","canStandAlone":false},"examples":[{"simplified":"教育是百年树人的事业，需要耐心和坚持。","english":"Education is a long-term endeavor that requires patience and perseverance.","traditional":"教育是百年樹人的事業，需要耐心和堅持。"},{"simplified":"他深知百年树人的道理，所以在教育上从不急功近利。","english":"He understands the principle of nurturing talent over time, so he never seeks quick success in education.","traditional":"他深知百年樹人的道理，所以在教育上從不急功近利。"}],"synonyms":["十年树木，百年树人"],"antonyms":[],"confusedWith":[{"id":"一蹴而就","note":"一蹴而就 means achieving success in one step, which contrasts with the long-term effort implied by 百年树人."}],"traditional":"百年樹人","pinyinOverride":null},{"id":"bai-zhe-bu-nao","simplified":"百折不挠","literalMeaning":"hundred bends not bend","figurativeMeaning":"to be indomitable; to persevere despite setbacks","englishEquivalents":["unwavering determination","indomitable spirit"],"shortGloss":"indomitable perseverance","characters":[{"char":"百","meaning":"hundred"},{"char":"折","meaning":"bends; setbacks"},{"char":"不","meaning":"not"},{"char":"挠","meaning":"bend; yield"}],"origin":{"period":"Han Dynasty (206 BCE – 220 CE)","sourceText":"《后汉书·张衡传》","sourceTextEnglish":"Book of the Later Han, Biography of Zhang Heng","originalExcerpt":"百折不挠，终不失志。","storyEnglish":"The idiom comes from the 'Book of the Later Han,' where it describes the character of Zhang Heng, a famous scholar and inventor. Despite facing numerous challenges and setbacks in his career, Zhang Heng remained steadfast and never lost his determination to achieve his goals. This phrase captures the essence of his indomitable spirit.","historicalFigures":["Zhang Heng"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"modifier-head","register":"literary, but widely used in both written and spoken Chinese","connotation":"positive","commonMistakes":"Learners often confuse this idiom with others that imply stubbornness rather than perseverance. It specifically emphasizes resilience in the face of repeated difficulties, not mere obstinacy.","canStandAlone":false},"examples":[{"simplified":"在创业的过程中，我们需要百折不挠的精神。","english":"In the process of starting a business, we need an indomitable spirit.","traditional":"在創業的過程中，我們需要百折不撓的精神。"},{"simplified":"他百折不挠地追求自己的梦想，最终取得了成功。","english":"He pursued his dreams with unwavering determination and eventually succeeded.","traditional":"他百折不撓地追求自己的夢想，最終取得了成功。"}],"synonyms":["坚韧不拔","锲而不舍"],"antonyms":["半途而废"],"confusedWith":[{"id":"顽固不化","note":"顽固不化 implies stubbornness without flexibility, while 百折不挠 emphasizes resilience and perseverance."}],"traditional":"百折不撓","pinyinOverride":null},{"id":"ban-men-nong-fu","simplified":"班门弄斧","literalMeaning":"wield an axe at Lu Ban's door","figurativeMeaning":"to show off one's skill in front of an expert, to teach a fish how to swim","englishEquivalents":["to teach a fish how to swim","to teach one's grandmother to suck eggs"],"shortGloss":"show off in front of an expert","characters":[{"char":"班","meaning":"Lu Ban, a legendary master carpenter"},{"char":"门","meaning":"door"},{"char":"弄","meaning":"wield, show off"},{"char":"斧","meaning":"axe"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"Lu Ban was a legendary carpenter and craftsman in ancient China, known for his exceptional skills. The idiom '班门弄斧' refers to someone trying to show off their skills in front of a true expert, akin to wielding an axe at the door of Lu Ban, which would be seen as presumptuous and foolish.","historicalFigures":["Lu Ban"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"literary, but very widely understood and used in ordinary speech","connotation":"negative","commonMistakes":"Learners often use this idiom without realizing it implies a negative judgment about the speaker's overconfidence. It is different from '自不量力' which means overestimating one's abilities, as '班门弄斧' specifically involves showing off in front of an expert.","canStandAlone":false},"examples":[{"simplified":"在音乐大师面前弹琴，我真是班门弄斧。","english":"Playing the piano in front of a music master, I am truly showing off in front of an expert.","traditional":"在音樂大師面前彈琴，我真是班門弄斧。"},{"simplified":"他在数学教授面前讲解简单的数学题，简直是班门弄斧。","english":"He explained simple math problems in front of a math professor, which was truly showing off in front of an expert.","traditional":"他在數學教授面前講解簡單的數學題，簡直是班門弄斧。"}],"synonyms":["自不量力"],"antonyms":[],"confusedWith":[{"id":"自不量力","note":"自不量力 means overestimating one's abilities, not necessarily in front of an expert."}],"traditional":"班門弄斧","pinyinOverride":null},{"id":"bi-men-zao-che","simplified":"闭门造车","literalMeaning":"close the door to make a car","figurativeMeaning":"to work behind closed doors without considering outside input or reality","englishEquivalents":["work in isolation","ivory tower"],"shortGloss":"work in isolation","characters":[{"char":"闭","meaning":"close"},{"char":"门","meaning":"door"},{"char":"造","meaning":"make"},{"char":"车","meaning":"car"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '闭门造车' describes the act of creating something in isolation, without considering external factors or feedback. The phrase suggests that such an approach can lead to impractical or flawed results, much like trying to build a vehicle without understanding the road conditions or the needs of the driver.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"commonly used in both spoken and written Chinese to criticize impractical or isolated methods","connotation":"negative","commonMistakes":"Learners might confuse this idiom with those that mean 'self-reliance' or 'independence', but '闭门造车' specifically implies a lack of awareness or consideration of external factors.","canStandAlone":false},"examples":[{"simplified":"他总是闭门造车，结果产品不符合市场需求。","english":"He always works in isolation, so the products don't meet market needs.","traditional":"他總是閉門造車，結果產品不符合市場需求。"},{"simplified":"在现代社会，闭门造车的做法很难成功。","english":"In modern society, working in isolation is unlikely to succeed.","traditional":"在現代社會，閉門造車的做法很難成功。"}],"synonyms":["自以为是","孤芳自赏"],"antonyms":["集思广益"],"confusedWith":[{"id":"自力更生","note":"自力更生 means self-reliance, which is positive, while 闭门造车 implies impracticality due to isolation."}],"traditional":"閉門造車","pinyinOverride":null},{"id":"bian-ben-jia-li","simplified":"变本加厉","literalMeaning":"change the original and increase the severity","figurativeMeaning":"to intensify or aggravate a situation; to make something worse","englishEquivalents":["add fuel to the fire","make matters worse"],"shortGloss":"to intensify or worsen","characters":[{"char":"变","meaning":"change"},{"char":"本","meaning":"original"},{"char":"加","meaning":"add"},{"char":"厉","meaning":"severity"}],"origin":{"period":"Northern and Southern Dynasties (420–589)","sourceText":"《梁书·武帝纪上》","sourceTextEnglish":"Book of Liang, Annals of Emperor Wu","originalExcerpt":"变本加厉，未有已也。","storyEnglish":"The phrase '变本加厉' is found in the 'Book of Liang', which describes how certain policies or actions were intensified, worsening the situation. It highlights the idea of taking an already problematic situation and making it even more severe.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"widely used in both formal and informal contexts","connotation":"negative","commonMistakes":"Learners often confuse this idiom with those that mean improvement or enhancement, but it specifically refers to worsening a situation. It should not be used to describe positive intensification.","canStandAlone":false},"examples":[{"simplified":"他的行为不仅没有解决问题，反而变本加厉。","english":"His actions not only failed to solve the problem but actually made it worse.","traditional":"他的行為不僅沒有解決問題，反而變本加厲。"},{"simplified":"如果不及时制止，这种情况只会变本加厉。","english":"If not stopped in time, this situation will only get worse.","traditional":"如果不及時制止，這種情況只會變本加厲。"}],"synonyms":["火上浇油","雪上加霜"],"antonyms":[],"confusedWith":[{"id":"锦上添花","note":"锦上添花 means to add something good to something already good, while 变本加厉 means to worsen an already bad situation."}],"traditional":"變本加厲","pinyinOverride":null},{"id":"biao-xin-li-yi","simplified":"标新立异","literalMeaning":"set up new and establish different","figurativeMeaning":"to pursue new and different ideas; to be unconventional","englishEquivalents":["break new ground","think outside the box"],"shortGloss":"to be unconventional","characters":[{"char":"标","meaning":"set up; establish"},{"char":"新","meaning":"new"},{"char":"立","meaning":"establish"},{"char":"异","meaning":"different; unusual"}],"origin":{"period":"Northern and Southern Dynasties (420–589 CE)","sourceText":"《世说新语·文学》","sourceTextEnglish":"A New Account of the Tales of the World, Literature","originalExcerpt":"标新立异，务为奇绝。","storyEnglish":"The idiom comes from 'A New Account of the Tales of the World', a collection of anecdotes and historical stories from the Northern and Southern Dynasties period. It describes the tendency of some scholars to deliberately pursue new and different ideas, often for the sake of being unconventional or unique.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"commonly used in both written and spoken Chinese to describe innovative or unconventional approaches","connotation":"neutral","commonMistakes":"Learners often confuse this idiom with ones that imply mere novelty without purpose. 标新立异 suggests a deliberate effort to be different, not just new for the sake of novelty.","canStandAlone":false},"examples":[{"simplified":"他总是喜欢标新立异，提出一些与众不同的想法。","english":"He always likes to be unconventional, coming up with ideas that are different from others.","traditional":"他總是喜歡標新立異，提出一些與眾不同的想法。"},{"simplified":"在艺术创作中，标新立异是非常重要的。","english":"In artistic creation, being unconventional is very important.","traditional":"在藝術創作中，標新立異是非常重要的。"}],"synonyms":["独树一帜"],"antonyms":["循规蹈矩"],"confusedWith":[{"id":"独树一帜","note":"独树一帜 emphasizes establishing a unique style or school, while 标新立异 focuses on pursuing new and different ideas."}],"traditional":"標新立異","pinyinOverride":null},{"id":"bie-chu-xin-cai","simplified":"别出心裁","literalMeaning":"different from the heart's design","figurativeMeaning":"to adopt an original approach; to be creative or innovative","englishEquivalents":["think outside the box","break the mold"],"shortGloss":"be original and creative","characters":[{"char":"别","meaning":"different"},{"char":"出","meaning":"to come out"},{"char":"心","meaning":"heart; mind"},{"char":"裁","meaning":"design; plan"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '别出心裁' suggests creating something new or taking an original approach. It emphasizes the importance of creativity and innovation, encouraging people to think differently and not just follow established patterns or ideas. The phrase is often used to praise someone's unique style or inventive ideas.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"verb-object","register":"commonly used in both written and spoken Chinese to praise creativity","connotation":"positive","commonMistakes":"Learners might confuse it with idioms that imply mere difference without the positive connotation of creativity, such as '与众不同'. '别出心裁' specifically praises originality and innovation.","canStandAlone":false},"examples":[{"simplified":"他的设计总是别出心裁，让人眼前一亮。","english":"His designs are always original and innovative, making people feel refreshed.","traditional":"他的設計總是別出心裁，讓人眼前一亮。"},{"simplified":"这位艺术家的作品别出心裁，吸引了很多观众。","english":"The artist's works are uniquely creative, attracting a lot of viewers.","traditional":"這位藝術家的作品別出心裁，吸引了很多觀眾。"}],"synonyms":["独具匠心"],"antonyms":["循规蹈矩"],"confusedWith":[{"id":"与众不同","note":"While both imply being different, '与众不同' does not necessarily carry the positive connotation of creativity and innovation that '别出心裁' does."}],"traditional":"別出心裁","pinyinOverride":null},{"id":"bin-zhi-ru-gui","simplified":"宾至如归","literalMeaning":"guests arrive as if returning home","figurativeMeaning":"to make guests feel at home; to treat guests with hospitality","englishEquivalents":["make oneself at home","feel at home","home away from home"],"shortGloss":"make guests feel at home","characters":[{"char":"宾","meaning":"guest"},{"char":"至","meaning":"arrive"},{"char":"如","meaning":"as if"},{"char":"归","meaning":"return home"}],"origin":{"period":"Han Dynasty (206 BCE – 220 CE)","sourceText":"《后汉书·张衡传》","sourceTextEnglish":"Book of the Later Han, Biography of Zhang Heng","originalExcerpt":"宾客至者，皆如归焉。","storyEnglish":"The idiom comes from the 'Book of the Later Han', where it describes the hospitality of Zhang Heng, a famous scholar and official. It was said that guests visiting him felt as comfortable as if they were returning to their own homes, due to his warm and welcoming nature.","historicalFigures":["Zhang Heng"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"subject-predicate","register":"literary, but very widely understood and used in ordinary speech","connotation":"positive","commonMistakes":"Learners might confuse this idiom with expressions that imply literal returning home, but it specifically refers to making guests feel comfortable and welcome.","canStandAlone":false},"examples":[{"simplified":"这家酒店的服务让人宾至如归。","english":"The service at this hotel makes people feel at home.","traditional":"這家酒店的服務讓人賓至如歸。"},{"simplified":"他的待客之道让每位客人都宾至如归。","english":"His way of hosting makes every guest feel at home.","traditional":"他的待客之道讓每位客人都賓至如歸。"}],"synonyms":["如坐春风"],"antonyms":[],"confusedWith":[{"id":"归心似箭","note":"归心似箭 refers to the eagerness to return home, not about hospitality."}],"traditional":"賓至如歸","pinyinOverride":null},{"id":"bu-gong-zi-po","simplified":"不攻自破","literalMeaning":"not attacked, self-destructs","figurativeMeaning":"to collapse or fail without being challenged; to be discredited on its own","englishEquivalents":["fall apart on its own","self-defeating","collapse under its own weight"],"shortGloss":"collapse without attack","characters":[{"char":"不","meaning":"not"},{"char":"攻","meaning":"attack"},{"char":"自","meaning":"self"},{"char":"破","meaning":"break; collapse"}],"origin":{"period":"Three Kingdoms period (220–280 CE)","sourceText":"《三国志·魏书·武帝纪》","sourceTextEnglish":"Records of the Three Kingdoms, Book of Wei, Annals of Emperor Wu","originalExcerpt":"兵不血刃，敌自破也。","storyEnglish":"The idiom originates from the 'Records of the Three Kingdoms,' where it is described how a situation or argument can collapse without any external pressure or attack. It suggests that the inherent flaws or weaknesses in a plan or argument will lead to its downfall without needing external intervention.","historicalFigures":["Cao Cao"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"modifier-head","register":"literary, but used in both formal and informal contexts","connotation":"neutral","commonMistakes":"Learners sometimes use this idiom to describe situations that require external intervention to fail, which is incorrect. It specifically refers to situations that fail due to their own flaws.","canStandAlone":false},"examples":[{"simplified":"他的谎言不攻自破，因为他自己说漏了嘴。","english":"His lie fell apart on its own because he let something slip.","traditional":"他的謊言不攻自破，因為他自己說漏了嘴。"},{"simplified":"这个计划不攻自破，因为缺乏实际可行性。","english":"The plan collapsed under its own weight due to a lack of feasibility.","traditional":"這個計劃不攻自破，因為缺乏實際可行性。"}],"synonyms":["自取灭亡","自我毁灭"],"antonyms":[],"confusedWith":[{"id":"不堪一击","note":"不堪一击 means 'unable to withstand a single blow,' implying external attack, unlike 不攻自破 which implies self-collapse."}],"traditional":"不攻自破","pinyinOverride":null},{"id":"bu-ke-jiu-yao","simplified":"不可救药","literalMeaning":"cannot be cured with medicine","figurativeMeaning":"beyond hope; incorrigible","englishEquivalents":["beyond redemption","a lost cause"],"shortGloss":"beyond hope or remedy","characters":[{"char":"不","meaning":"not"},{"char":"可","meaning":"can; able to"},{"char":"救","meaning":"save; rescue"},{"char":"药","meaning":"medicine"}],"origin":{"period":"Warring States period (475–221 BCE)","sourceText":"《韩非子·喻老》","sourceTextEnglish":"Han Feizi, chapter Yu Lao","originalExcerpt":"今世之愚者，不可救药也。","storyEnglish":"The idiom originates from the writings of Han Feizi, a philosopher during the Warring States period. In his work, he describes people who are so foolish or stubborn that they are beyond help, much like a patient who cannot be cured with medicine. This metaphor was used to illustrate the idea that some individuals or situations are beyond redemption or repair.","historicalFigures":["Han Feizi"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"modifier-head","register":"literary, but very widely understood and used in ordinary speech","connotation":"negative","commonMistakes":"Learners often confuse this idiom with similar expressions that imply difficulty rather than impossibility. Unlike expressions that suggest a challenge, 不可救药 implies a complete lack of hope for improvement.","canStandAlone":false},"examples":[{"simplified":"他的坏习惯已经不可救药了。","english":"His bad habits are beyond redemption.","traditional":"他的壞習慣已經不可救藥了。"},{"simplified":"这个项目的失败是因为管理层的不可救药的错误。","english":"The failure of this project was due to the management's incorrigible mistakes.","traditional":"這個項目的失敗是因為管理層的不可救藥的錯誤。"}],"synonyms":["无可救药"],"antonyms":[],"confusedWith":[{"id":"无可奈何","note":"无可奈何 means having no choice or being helpless, not necessarily beyond hope."}],"traditional":"不可救藥","pinyinOverride":null},{"id":"bu-lao-er-huo","simplified":"不劳而获","literalMeaning":"not labor but gain","figurativeMeaning":"to gain something without putting in any effort; to reap without sowing","englishEquivalents":["reap without sowing","get something for nothing"],"shortGloss":"gain without effort","characters":[{"char":"不","meaning":"not"},{"char":"劳","meaning":"labor; work"},{"char":"而","meaning":"and; but"},{"char":"获","meaning":"gain; obtain"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '不劳而获' is commonly used to describe situations where someone gains benefits or rewards without putting in the necessary effort or work. It is often used to criticize those who expect to receive something without contributing or working for it.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"commonly used in both spoken and written Chinese, often in a critical context","connotation":"negative","commonMistakes":"Learners sometimes confuse this idiom with positive expressions about efficiency or smart work, but it specifically implies an unfair or undeserved gain.","canStandAlone":false},"examples":[{"simplified":"他总是想不劳而获，从不愿意努力工作。","english":"He always wants to gain without effort and never wants to work hard.","traditional":"他總是想不勞而獲，從不願意努力工作。"},{"simplified":"不劳而获的想法是不现实的。","english":"The idea of gaining without effort is unrealistic.","traditional":"不勞而獲的想法是不現實的。"}],"synonyms":["坐享其成"],"antonyms":["自食其力"],"confusedWith":[{"id":"坐享其成","note":"Both imply gaining without personal effort, but '坐享其成' emphasizes benefiting from others' work."}],"traditional":"不勞而獲","pinyinOverride":null},{"id":"bu-wu-zheng-ye","simplified":"不务正业","literalMeaning":"not attend to one's proper occupation","figurativeMeaning":"to neglect one's main work or duties; to not do one's job properly","englishEquivalents":["not do one's job","neglect one's duties"],"shortGloss":"neglect one's duties","characters":[{"char":"不","meaning":"not"},{"char":"务","meaning":"attend to"},{"char":"正","meaning":"proper"},{"char":"业","meaning":"occupation"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '不务正业' describes someone who does not focus on their main job or responsibilities. Instead of attending to their proper duties, they may engage in unrelated or frivolous activities. This phrase is often used to criticize someone for not taking their responsibilities seriously.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","object","attributive"],"structure":"verb-object","register":"common in both spoken and written Chinese, often used in a critical context","connotation":"negative","commonMistakes":"Learners might confuse this idiom with phrases that mean 'to be versatile' or 'to have multiple skills', but '不务正业' specifically implies neglect and irresponsibility towards one's primary duties.","canStandAlone":false},"examples":[{"simplified":"他总是玩游戏，不务正业。","english":"He is always playing games and neglecting his duties.","traditional":"他總是玩遊戲，不務正業。"},{"simplified":"如果你继续不务正业，迟早会被解雇。","english":"If you continue to neglect your duties, you'll be fired sooner or later.","traditional":"如果你繼續不務正業，遲早會被解僱。"}],"synonyms":["游手好闲"],"antonyms":["兢兢业业"],"confusedWith":[{"id":"多才多艺","note":"多才多艺 means 'versatile' or 'talented in many areas', which is positive, unlike 不务正业 which is negative."}],"traditional":"不務正業","pinyinOverride":null},{"id":"bu-xing-ren-shi","simplified":"不省人事","literalMeaning":"not aware of human affairs","figurativeMeaning":"to be unconscious or in a coma","englishEquivalents":["out cold","unconscious","in a coma"],"shortGloss":"unconscious or in a coma","characters":[{"char":"不","meaning":"not"},{"char":"省","meaning":"aware, conscious"},{"char":"人","meaning":"human"},{"char":"事","meaning":"affairs, matters"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '不省人事' is used to describe a state where someone is unconscious or unaware of their surroundings, as if they are not aware of any human affairs. The exact origin of this idiom is unclear, but it has been used in Chinese literature and language to describe someone who has fainted or is in a coma.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","complement"],"structure":"modifier-head","register":"commonly used in both written and spoken Chinese, in medical or dramatic contexts","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with expressions related to ignorance or lack of understanding, but it specifically refers to a physical state of unconsciousness.","canStandAlone":false},"examples":[{"simplified":"他摔倒后就不省人事了。","english":"He was unconscious after he fell.","traditional":"他摔倒後就不省人事了。"},{"simplified":"医生说病人已经不省人事，需要立即抢救。","english":"The doctor said the patient was unconscious and needed immediate resuscitation.","traditional":"醫生說病人已經不省人事，需要立即搶救。"}],"synonyms":["昏迷不醒"],"antonyms":["神志清醒"],"confusedWith":[{"id":"不知所措","note":"不知所措 means 'at a loss' or 'not knowing what to do', which is different from being physically unconscious."}],"traditional":"不省人事","pinyinOverride":null},{"id":"bu-yi-yu-li","simplified":"不遗余力","literalMeaning":"not spare remaining strength","figurativeMeaning":"to spare no effort; to do one's utmost","englishEquivalents":["go all out","leave no stone unturned"],"shortGloss":"spare no effort","characters":[{"char":"不","meaning":"not"},{"char":"遗","meaning":"spare"},{"char":"余","meaning":"remaining"},{"char":"力","meaning":"strength"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '不遗余力' is commonly used to describe someone who is putting in their maximum effort without holding back any strength or resources. It is often used to commend someone for their dedication and hard work in achieving a goal.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"widely used in both formal and informal contexts","connotation":"positive","commonMistakes":"Learners sometimes confuse this idiom with similar expressions that imply effort but do not convey the same intensity of exertion. It specifically means to use all available resources and energy.","canStandAlone":false},"examples":[{"simplified":"为了完成这个项目，他不遗余力地工作。","english":"To complete this project, he spared no effort in his work.","traditional":"為了完成這個項目，他不遺餘力地工作。"},{"simplified":"她不遗余力地帮助朋友渡过难关。","english":"She spared no effort in helping her friend through tough times.","traditional":"她不遺餘力地幫助朋友渡過難關。"}],"synonyms":["全力以赴","竭尽全力"],"antonyms":[],"confusedWith":[{"id":"尽力而为","note":"尽力而为 means to do one's best within one's limits, which may not imply using all available resources."}],"traditional":"不遺餘力","pinyinOverride":null},{"id":"bu-ze-shou-duan","simplified":"不择手段","literalMeaning":"not choose means","figurativeMeaning":"to achieve one's goal by any means necessary, often implying unscrupulous or unethical methods","englishEquivalents":["by hook or by crook","the ends justify the means"],"shortGloss":"by any means necessary","characters":[{"char":"不","meaning":"not"},{"char":"择","meaning":"choose"},{"char":"手","meaning":"means; method"},{"char":"段","meaning":"method; means"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '不择手段' is believed to have originated from the idea that a person is willing to use any method, regardless of its morality or ethics, to achieve their goals. It reflects a pragmatic, often ruthless approach to problem-solving.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"commonly used in both formal and informal contexts, often with a negative connotation","connotation":"negative","commonMistakes":"Learners often confuse this idiom with positive expressions of determination. However, '不择手段' implies a willingness to use unethical or ruthless methods, unlike neutral or positive expressions of perseverance.","canStandAlone":false},"examples":[{"simplified":"为了赢得比赛，他不择手段。","english":"He used any means necessary to win the competition.","traditional":"為了贏得比賽，他不擇手段。"},{"simplified":"有些商人为了赚钱不择手段。","english":"Some businessmen will stop at nothing to make money.","traditional":"有些商人為了賺錢不擇手段。"}],"synonyms":["无所不用其极"],"antonyms":["光明正大"],"confusedWith":[{"id":"不屈不挠","note":"While '不屈不挠' means to be unyielding and persistent, it does not imply unethical behavior, unlike '不择手段'."}],"traditional":"不擇手段","pinyinOverride":null},{"id":"bu-zi-liang-li","simplified":"不自量力","literalMeaning":"not self measure strength","figurativeMeaning":"to overestimate one's own abilities; to be unaware of one's limitations","englishEquivalents":["bite off more than one can chew","overreach oneself"],"shortGloss":"overestimate one's abilities","characters":[{"char":"不","meaning":"not"},{"char":"自","meaning":"oneself"},{"char":"量","meaning":"measure"},{"char":"力","meaning":"strength; ability"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '不自量力' is used to describe someone who does not accurately assess their own capabilities and attempts tasks beyond their ability. It emphasizes the importance of self-awareness and understanding one's limitations.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"modifier-head","register":"commonly used in both spoken and written Chinese","connotation":"negative","commonMistakes":"Learners often confuse '不自量力' with '自不量力', which has a similar meaning but is less commonly used. The key is to remember that '不自量力' is the standard form.","canStandAlone":false},"examples":[{"simplified":"他不自量力，想要在一个月内完成所有工作。","english":"He overestimated his abilities and thought he could finish all the work in a month.","traditional":"他不自量力，想要在一個月內完成所有工作。"},{"simplified":"面对如此强大的对手，我们不能不自量力。","english":"Facing such a strong opponent, we must not overestimate our abilities.","traditional":"面對如此強大的對手，我們不能不自量力。"}],"synonyms":["自不量力"],"antonyms":["量力而行"],"confusedWith":[{"id":"自不量力","note":"Both mean overestimating one's abilities, but '不自量力' is the more standard form."}],"traditional":"不自量力","pinyinOverride":null},{"id":"chang-nian-lei-yue","simplified":"长年累月","literalMeaning":"long years accumulate months","figurativeMeaning":"over a long period of time; year after year","englishEquivalents":["over the years","for many years","year in, year out"],"shortGloss":"over a long period of time","characters":[{"char":"长","meaning":"long"},{"char":"年","meaning":"year"},{"char":"累","meaning":"accumulate"},{"char":"月","meaning":"month"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '长年累月' is used to describe something that happens continuously or persists over a long period of time, often implying enduring effort or gradual accumulation. It emphasizes the passage of time and the persistence required to achieve something significant.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["adverbial"],"structure":"modifier-head","register":"commonly used in both spoken and written Chinese","connotation":"neutral","commonMistakes":"Learners sometimes confuse this idiom with others that involve time, such as 日积月累, which emphasizes gradual accumulation rather than the mere passage of time.","canStandAlone":false},"examples":[{"simplified":"他长年累月地工作，终于攒够了买房的钱。","english":"He worked for many years and finally saved enough money to buy a house.","traditional":"他長年累月地工作，終於攢夠了買房的錢。"},{"simplified":"长年累月的训练让她成为了一名优秀的运动员。","english":"Years of training made her an excellent athlete.","traditional":"長年累月的訓練讓她成為了一名優秀的運動員。"}],"synonyms":["日积月累"],"antonyms":[],"confusedWith":[{"id":"日积月累","note":"日积月累 focuses on gradual accumulation, while 长年累月 emphasizes the passage of time."}],"traditional":"長年累月","pinyinOverride":null},{"id":"chen-huo-da-jie","simplified":"趁火打劫","literalMeaning":"take advantage of a fire to rob","figurativeMeaning":"to exploit a crisis for personal gain","englishEquivalents":["to fish in troubled waters","to take advantage of a crisis","to strike while the iron is hot"],"shortGloss":"exploit a crisis for gain","characters":[{"char":"趁","meaning":"take advantage of"},{"char":"火","meaning":"fire"},{"char":"打","meaning":"to rob"},{"char":"劫","meaning":"robbery"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '趁火打劫' describes the act of taking advantage of someone else's misfortune or a chaotic situation to benefit oneself, often in a morally questionable way. The imagery of robbing during a fire highlights the opportunistic and unscrupulous nature of such actions.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"commonly used in both formal and informal contexts","connotation":"negative","commonMistakes":"Learners might confuse this idiom with similar expressions that involve taking advantage of opportunities, but '趁火打劫' specifically implies an unethical or opportunistic action during someone else's crisis.","canStandAlone":false},"examples":[{"simplified":"他在公司危机时趁火打劫，买下了大量的股票。","english":"He exploited the company's crisis to buy a large amount of stock.","traditional":"他在公司危機時趁火打劫，買下了大量的股票。"},{"simplified":"在混乱中趁火打劫是不道德的行为。","english":"Taking advantage of the chaos to exploit others is unethical.","traditional":"在混亂中趁火打劫是不道德的行為。"}],"synonyms":["乘人之危"],"antonyms":["雪中送炭"],"confusedWith":[{"id":"见利忘义","note":"While both idioms involve unethical behavior, '见利忘义' focuses on forgetting morals for profit, not necessarily exploiting a crisis."}],"traditional":"趁火打劫","pinyinOverride":null},{"id":"chong-dao-fu-zhe","simplified":"重蹈覆辙","literalMeaning":"repeat the overturned cart","figurativeMeaning":"to repeat the same mistake","englishEquivalents":["make the same mistake again","fall into the same trap","history repeats itself"],"shortGloss":"repeat the same mistake","characters":[{"char":"重","meaning":"again, repeat"},{"char":"蹈","meaning":"tread, follow"},{"char":"覆","meaning":"overturn"},{"char":"辙","meaning":"cart track, rut"}],"origin":{"period":"Eastern Jin dynasty (317–420)","sourceText":"《晋书·谢安传》","sourceTextEnglish":"Book of Jin, Biography of Xie An","originalExcerpt":"前车已覆，后车何不鉴之？而复蹈其辙乎？","storyEnglish":"The idiom comes from a story about Xie An, a statesman during the Eastern Jin dynasty. When discussing the mistakes of others, he warned that one should learn from past errors to avoid repeating them. The metaphor of a cart overturning and following the same tracks was used to illustrate the folly of not learning from past mistakes.","historicalFigures":["Xie An"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"widely used in both spoken and written Chinese","connotation":"negative","commonMistakes":"Learners often confuse this idiom with expressions that mean simply 'repeating actions' without the negative connotation of repeating a mistake. It specifically implies not learning from past errors.","canStandAlone":false},"examples":[{"simplified":"我们应该从失败中吸取教训，避免重蹈覆辙。","english":"We should learn from our failures to avoid repeating the same mistakes.","traditional":"我們應該從失敗中吸取教訓，避免重蹈覆轍。"},{"simplified":"经过上次的教训，他再也不敢重蹈覆辙了。","english":"After the lesson from last time, he dared not repeat the same mistake again.","traditional":"經過上次的教訓，他再也不敢重蹈覆轍了。"}],"synonyms":["重蹈旧辙"],"antonyms":["吸取教训"],"confusedWith":[{"id":"重温旧梦","note":"重温旧梦 means to relive past experiences, often with a nostalgic or positive connotation, unlike 重蹈覆辙 which implies repeating mistakes."}],"traditional":"重蹈覆轍","pinyinOverride":null},{"id":"chou-mei-bu-zhan","simplified":"愁眉不展","literalMeaning":"worried brows not unfolding","figurativeMeaning":"to be worried or distressed, with a troubled expression","englishEquivalents":["to wear a worried look","to have a furrowed brow"],"shortGloss":"to look worried or distressed","characters":[{"char":"愁","meaning":"worried"},{"char":"眉","meaning":"brows"},{"char":"不","meaning":"not"},{"char":"展","meaning":"unfold"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '愁眉不展' describes someone who is visibly worried or distressed, as if their eyebrows are tightly furrowed and unable to relax. This expression captures the physical manifestation of worry or anxiety, where one's facial expression reflects their inner turmoil.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"modifier-head","register":"common in both written and spoken Chinese","connotation":"negative","commonMistakes":"Learners might confuse this idiom with similar expressions like '眉头紧锁' (brows tightly locked), which also describe a worried expression but emphasize the tightness rather than the inability to relax.","canStandAlone":false},"examples":[{"simplified":"他最近工作压力很大，总是愁眉不展。","english":"He's been under a lot of pressure at work lately and always looks worried.","traditional":"他最近工作壓力很大，總是愁眉不展。"},{"simplified":"看到她愁眉不展的样子，我决定去安慰她。","english":"Seeing her worried expression, I decided to comfort her.","traditional":"看到她愁眉不展的樣子，我決定去安慰她。"}],"synonyms":["眉头紧锁"],"antonyms":["眉开眼笑"],"confusedWith":[{"id":"眉头紧锁","note":"Both describe a worried expression, but '眉头紧锁' emphasizes the tightness of the brows."}],"traditional":"愁眉不展","pinyinOverride":null},{"id":"chu-lei-ba-cui","simplified":"出类拔萃","literalMeaning":"stand out from the crowd","figurativeMeaning":"to be outstanding; to excel among one's peers","englishEquivalents":["stand head and shoulders above the rest","rise above the crowd"],"shortGloss":"to excel among peers","characters":[{"char":"出","meaning":"to stand out"},{"char":"类","meaning":"category; group"},{"char":"拔","meaning":"to pull out; to select"},{"char":"萃","meaning":"the best; elite"}],"origin":{"period":"Warring States period (475–221 BCE)","sourceText":"《孟子·公孙丑下》","sourceTextEnglish":"Mencius, Gongsun Chou II","originalExcerpt":"出于其类，拔乎其萃，自生民以来，未有盛于孔子也。","storyEnglish":"The idiom comes from a passage in the 'Mencius', where Mencius praises Confucius as someone who stands out from his peers and is unmatched since the beginning of mankind. The phrase '出于其类，拔乎其萃' describes someone who is outstanding and excels beyond others in their group.","historicalFigures":["Mencius","Confucius"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"verb-object","register":"literary, but very widely understood and used in ordinary speech","connotation":"positive","commonMistakes":"Learners might confuse this idiom with similar phrases that mean 'to be different' rather than 'to excel'. It specifically implies superiority, not just difference.","canStandAlone":false},"examples":[{"simplified":"在这次比赛中，他的表现出类拔萃。","english":"In this competition, his performance was outstanding.","traditional":"在這次比賽中，他的表現出類拔萃。"},{"simplified":"她是我们班上出类拔萃的学生。","english":"She is the most outstanding student in our class.","traditional":"她是我們班上出類拔萃的學生。"}],"synonyms":["鹤立鸡群"],"antonyms":[],"confusedWith":[{"id":"与众不同","note":"与众不同 means 'to be different from others', which does not necessarily imply excellence."}],"traditional":"出類拔萃","pinyinOverride":null},{"id":"chui-mao-qiu-ci","simplified":"吹毛求疵","literalMeaning":"blow hair seek defect","figurativeMeaning":"to nitpick or find fault in trivial details","englishEquivalents":["nitpick","split hairs","find fault"],"shortGloss":"to nitpick or find fault","characters":[{"char":"吹","meaning":"blow"},{"char":"毛","meaning":"hair"},{"char":"求","meaning":"seek"},{"char":"疵","meaning":"defect"}],"origin":{"period":"Han Dynasty (206 BCE – 220 CE)","sourceText":"《汉书·东方朔传》","sourceTextEnglish":"Book of Han, Biography of Dongfang Shuo","originalExcerpt":"吹毛求小疵。","storyEnglish":"The idiom originates from a story in the Book of Han, where it describes someone who would blow on a hair to find even the smallest defect. This metaphor was used to illustrate a person who is excessively critical and focuses on insignificant flaws.","historicalFigures":["Dongfang Shuo"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"commonly used in both formal and informal contexts","connotation":"negative","commonMistakes":"Learners often confuse this idiom with similar expressions that imply thoroughness or attention to detail, but 吹毛求疵 specifically carries a negative connotation of being overly critical.","canStandAlone":false},"examples":[{"simplified":"他总是喜欢吹毛求疵，让人很不舒服。","english":"He always likes to nitpick, which makes people uncomfortable.","traditional":"他總是喜歡吹毛求疵，讓人很不舒服。"},{"simplified":"在团队合作中，吹毛求疵并不利于问题的解决。","english":"In team collaboration, nitpicking is not conducive to solving problems.","traditional":"在團隊合作中，吹毛求疵並不利於問題的解決。"}],"synonyms":["挑三拣四","鸡蛋里挑骨头"],"antonyms":["宽宏大量"],"confusedWith":[{"id":"一丝不苟","note":"一丝不苟 means to be meticulous and thorough, without the negative connotation of fault-finding."}],"traditional":"吹毛求疵","pinyinOverride":null},{"id":"chui-xian-san-chi","simplified":"垂涎三尺","literalMeaning":"drool three feet","figurativeMeaning":"to be extremely envious or desirous of something","englishEquivalents":["drool over","salivate over"],"shortGloss":"extremely envious or desirous","characters":[{"char":"垂","meaning":"to hang down"},{"char":"涎","meaning":"saliva"},{"char":"三","meaning":"three"},{"char":"尺","meaning":"feet (a unit of length)"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '垂涎三尺' is often used to describe someone who is extremely envious or desirous of something, to the point where they metaphorically drool over it. The image is of someone so eager or greedy that their saliva would hang down three feet. This vivid imagery captures the intensity of their longing or desire.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"modifier-head","register":"commonly used in both spoken and written Chinese","connotation":"negative","commonMistakes":"Learners might confuse this idiom with expressions that mean simply wanting something, but '垂涎三尺' implies an excessive or greedy desire. It is also sometimes confused with idioms that describe admiration, but this idiom has a negative connotation.","canStandAlone":false},"examples":[{"simplified":"看到桌上的美食，他垂涎三尺。","english":"Seeing the delicious food on the table, he was drooling over it.","traditional":"看到桌上的美食，他垂涎三尺。"},{"simplified":"她对那辆豪车垂涎三尺。","english":"She was drooling over that luxury car.","traditional":"她對那輛豪車垂涎三尺。"}],"synonyms":["眼馋","垂涎欲滴"],"antonyms":[],"confusedWith":[{"id":"望梅止渴","note":"While '望梅止渴' involves imagining something to satisfy a desire, '垂涎三尺' emphasizes excessive desire or envy."}],"traditional":"垂涎三尺","pinyinOverride":null},{"id":"chun-wang-chi-han","simplified":"唇亡齿寒","literalMeaning":"lips gone, teeth cold","figurativeMeaning":"one thing relies on another; if one fails, the other is in danger","englishEquivalents":["interdependent","mutually dependent","one cannot survive without the other"],"shortGloss":"interdependence; mutual reliance","characters":[{"char":"唇","meaning":"lips"},{"char":"亡","meaning":"gone; destroyed"},{"char":"齿","meaning":"teeth"},{"char":"寒","meaning":"cold"}],"origin":{"period":"Warring States period (475–221 BCE)","sourceText":"《左传·僖公五年》","sourceTextEnglish":"Zuo Zhuan, Duke Xi, Year 5","originalExcerpt":"晋侯谓秦伯曰：“唇亡则齿寒，愿王图之。”","storyEnglish":"During the Warring States period, the state of Jin was concerned about the state of Qin's intentions. The Duke of Jin sent an envoy to the Duke of Qin, warning him that if the state of Jin were destroyed, Qin would be in danger too. He used the metaphor 'if the lips are gone, the teeth will be cold' to illustrate their interdependence.","historicalFigures":["Duke of Jin","Duke of Qin"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["subject","predicate","object","attributive"],"structure":"cause-effect","register":"literary, but widely understood and used in ordinary speech","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with ones that imply a direct cause-effect relationship rather than mutual dependence. It is important to understand that this idiom emphasizes interdependence rather than a one-way causation.","canStandAlone":false},"examples":[{"simplified":"两国关系密切，唇亡齿寒，任何一方的动荡都会影响另一方。","english":"The two countries have a close relationship; they are interdependent, and any turmoil in one will affect the other.","traditional":"兩國關係密切，唇亡齒寒，任何一方的動盪都會影響另一方。"},{"simplified":"在这个项目中，各部门之间唇亡齿寒，必须紧密合作。","english":"In this project, the departments are interdependent and must work closely together.","traditional":"在這個項目中，各部門之間唇亡齒寒，必須緊密合作。"}],"synonyms":["休戚与共","唇齿相依"],"antonyms":[],"confusedWith":[],"traditional":"唇亡齒寒","pinyinOverride":null},{"id":"cong-shan-ru-liu","simplified":"从善如流","literalMeaning":"follow goodness like a stream","figurativeMeaning":"to readily accept good advice or follow good examples","englishEquivalents":["go with the flow","take advice willingly"],"shortGloss":"readily accept good advice","characters":[{"char":"从","meaning":"follow"},{"char":"善","meaning":"goodness"},{"char":"如","meaning":"like"},{"char":"流","meaning":"a stream"}],"origin":{"period":"Han Dynasty (206 BCE – 220 CE)","sourceText":"《后汉书·张衡传》","sourceTextEnglish":"Book of the Later Han, Biography of Zhang Heng","originalExcerpt":"从善如流，闻谏则喜。","storyEnglish":"The idiom originates from the 'Book of the Later Han', where it describes a person who is willing to accept good advice as naturally as water flows in a stream. It praises the virtue of being open-minded and receptive to wise counsel.","historicalFigures":["Zhang Heng"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"modifier-head","register":"literary, but commonly used in both written and spoken Chinese","connotation":"positive","commonMistakes":"Learners might confuse this idiom with expressions that imply passivity, but 从善如流 specifically emphasizes the active willingness to accept good advice, not just going along with any flow.","canStandAlone":false},"examples":[{"simplified":"他总是从善如流，乐于接受别人的建议。","english":"He always readily accepts good advice and is happy to take others' suggestions.","traditional":"他總是從善如流，樂於接受別人的建議。"},{"simplified":"在工作中，从善如流是一个重要的品质。","english":"In the workplace, being open to good advice is an important quality.","traditional":"在工作中，從善如流是一個重要的品質。"}],"synonyms":["虚怀若谷"],"antonyms":["刚愎自用"],"confusedWith":[{"id":"随波逐流","note":"随波逐流 means to follow the crowd passively, without one's own judgment, which differs from the positive connotation of 从善如流."}],"traditional":"從善如流","pinyinOverride":null},{"id":"da-dao-kuo-fu","simplified":"大刀阔斧","literalMeaning":"big knife, broad axe","figurativeMeaning":"to act boldly and decisively","englishEquivalents":["take bold action","cut through the Gordian knot"],"shortGloss":"act boldly and decisively","characters":[{"char":"大","meaning":"big"},{"char":"刀","meaning":"knife"},{"char":"阔","meaning":"broad"},{"char":"斧","meaning":"axe"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '大刀阔斧' is believed to have originated from the imagery of using large, powerful tools like a big knife and a broad axe to cut through obstacles. It conveys the idea of taking bold and decisive actions, often in the context of reform or problem-solving.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["adverbial","attributive"],"structure":"coordinate","register":"widely used in both formal and informal contexts","connotation":"positive","commonMistakes":"Learners sometimes confuse this idiom with others that involve caution or hesitation, but '大刀阔斧' specifically implies boldness and decisiveness. It should not be used to describe careful or tentative actions.","canStandAlone":false},"examples":[{"simplified":"他在改革中采取了大刀阔斧的措施。","english":"He took bold and decisive measures in the reform.","traditional":"他在改革中採取了大刀闊斧的措施。"},{"simplified":"公司需要大刀阔斧地进行结构调整。","english":"The company needs to make bold structural adjustments.","traditional":"公司需要大刀闊斧地進行結構調整。"}],"synonyms":["雷厉风行"],"antonyms":["畏首畏尾"],"confusedWith":[{"id":"小心翼翼","note":"小心翼翼 means to act with great caution, which is the opposite of the boldness implied by 大刀阔斧."}],"traditional":"大刀闊斧","pinyinOverride":null},{"id":"da-yan-bu-can","simplified":"大言不惭","literalMeaning":"big words not ashamed","figurativeMeaning":"to boast shamelessly; to talk big without feeling embarrassed","englishEquivalents":["to brag without shame","to talk big","to boast shamelessly"],"shortGloss":"boast shamelessly","characters":[{"char":"大","meaning":"big; grand"},{"char":"言","meaning":"words; speech"},{"char":"不","meaning":"not"},{"char":"惭","meaning":"ashamed"}],"origin":{"period":"Three Kingdoms period (220–280 CE)","sourceText":"《三国志·魏书·王肃传》","sourceTextEnglish":"Records of the Three Kingdoms, Book of Wei, Biography of Wang Su","originalExcerpt":"大言不惭，谓己为胜。","storyEnglish":"The idiom originates from the 'Records of the Three Kingdoms,' where it describes someone who boasts about their abilities without feeling any shame. The phrase was used to criticize those who exaggerated their capabilities, particularly in the context of political or military achievements.","historicalFigures":["Wang Su"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"commonly used in both written and spoken Chinese to describe someone who boasts without feeling embarrassed","connotation":"negative","commonMistakes":"Learners might confuse this idiom with ones that simply mean 'to speak loudly' or 'to speak confidently,' but it specifically implies shamelessness in boasting.","canStandAlone":false},"examples":[{"simplified":"他总是大言不惭地说自己能解决所有问题。","english":"He always boasts shamelessly that he can solve all problems.","traditional":"他總是大言不慚地說自己能解決所有問題。"},{"simplified":"在会议上，他大言不惭地宣称自己的计划是最好的。","english":"At the meeting, he shamelessly claimed that his plan was the best.","traditional":"在會議上，他大言不慚地宣稱自己的計劃是最好的。"}],"synonyms":["自吹自擂"],"antonyms":["谦虚谨慎"],"confusedWith":[{"id":"夸夸其谈","note":"While both involve boasting, 夸夸其谈 emphasizes speaking in an exaggerated manner, not necessarily shamelessly."}],"traditional":"大言不慚","pinyinOverride":null},{"id":"dao-ting-tu-shuo","simplified":"道听途说","literalMeaning":"road listen, road speak","figurativeMeaning":"to hear and spread rumors; unverified information","englishEquivalents":["hear it through the grapevine","rumor has it","idle gossip"],"shortGloss":"unverified hearsay or gossip","characters":[{"char":"道","meaning":"road; path"},{"char":"听","meaning":"to listen"},{"char":"途","meaning":"road; way"},{"char":"说","meaning":"to speak"}],"origin":{"period":"Warring States period (475–221 BCE)","sourceText":"《论语·阳货》","sourceTextEnglish":"The Analects of Confucius, Yang Huo chapter","originalExcerpt":"子曰：“道听而途说，德之弃也。”","storyEnglish":"In The Analects of Confucius, Confucius criticizes the practice of spreading unverified information. He describes '道听途说' as something that a virtuous person should avoid, as it leads to the abandonment of moral integrity.","historicalFigures":["Confucius"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["subject","object","attributive"],"structure":"coordinate","register":"literary, but widely understood and used in both written and spoken Chinese","connotation":"negative","commonMistakes":"Learners often use this idiom to describe any type of news or information, but it specifically refers to unverified or unreliable information. It should not be used to describe credible sources.","canStandAlone":false},"examples":[{"simplified":"我们不能相信这些道听途说的消息。","english":"We cannot trust this hearsay information.","traditional":"我們不能相信這些道聽途說的消息。"},{"simplified":"他总是道听途说，不加以验证。","english":"He always spreads rumors without verifying them.","traditional":"他總是道聽途說，不加以驗證。"}],"synonyms":["以讹传讹"],"antonyms":["实事求是"],"confusedWith":[{"id":"以讹传讹","note":"Both involve spreading false information, but '以讹传讹' emphasizes the distortion of information as it spreads."}],"traditional":"道聽途說","pinyinOverride":null},{"id":"de-cun-jin-chi","simplified":"得寸进尺","literalMeaning":"gain an inch, advance a foot","figurativeMeaning":"to be insatiable; to take advantage of a small gain to demand more","englishEquivalents":["give an inch, take a mile","insatiable greed"],"shortGloss":"insatiable greed or demands","characters":[{"char":"得","meaning":"gain, obtain"},{"char":"寸","meaning":"inch"},{"char":"进","meaning":"advance, progress"},{"char":"尺","meaning":"foot (unit of length)"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '得寸进尺' describes a situation where someone, after gaining a small advantage or concession, becomes greedy and demands even more. This expression is often used to criticize someone who is never satisfied and always wants more than what they have been given.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"widely used in both spoken and written Chinese","connotation":"negative","commonMistakes":"Learners often confuse this idiom with expressions that simply mean 'to progress' or 'to improve', but '得寸进尺' specifically implies greed and taking advantage beyond what is fair.","canStandAlone":false},"examples":[{"simplified":"他总是得寸进尺，从不满足。","english":"He is always insatiable, never satisfied with what he has.","traditional":"他總是得寸進尺，從不滿足。"},{"simplified":"如果你对他让步，他可能会得寸进尺。","english":"If you make concessions to him, he might take advantage and demand even more.","traditional":"如果你對他讓步，他可能會得寸進尺。"}],"synonyms":["贪得无厌"],"antonyms":["知足常乐"],"confusedWith":[{"id":"步步高升","note":"While '步步高升' means to rise steadily, often in a career, '得寸进尺' implies greed and taking more than what is fair."}],"traditional":"得寸進尺","pinyinOverride":null},{"id":"de-guo-qie-guo","simplified":"得过且过","literalMeaning":"get by and let pass","figurativeMeaning":"to muddle through life without ambition or planning; to take things as they come","englishEquivalents":["live for the moment","go with the flow","take each day as it comes"],"shortGloss":"muddle through life","characters":[{"char":"得","meaning":"get"},{"char":"过","meaning":"pass"},{"char":"且","meaning":"and"},{"char":"过","meaning":"pass"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '得过且过' describes a mindset of taking life as it comes without worrying too much about the future. It suggests a lack of ambition or long-term planning, focusing instead on getting through each day as it comes. The phrase is often used to describe someone who is content with the status quo and does not strive for improvement.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"coordinate","register":"widely used in both spoken and written Chinese, informal","connotation":"negative","commonMistakes":"Learners often confuse this idiom with positive expressions about enjoying life, but it actually implies a lack of ambition or effort. It is not a compliment.","canStandAlone":false},"examples":[{"simplified":"他总是得过且过，从来不为未来做计划。","english":"He always muddles through life and never makes plans for the future.","traditional":"他總是得過且過，從來不為未來做計劃。"},{"simplified":"如果你继续得过且过，可能会错过很多机会。","english":"If you continue to just muddle through, you might miss many opportunities.","traditional":"如果你繼續得過且過，可能會錯過很多機會。"}],"synonyms":["混日子"],"antonyms":["未雨绸缪"],"confusedWith":[{"id":"随遇而安","note":"得过且过 implies a lack of ambition, while 随遇而安 suggests adapting to circumstances positively."}],"traditional":"得過且過","pinyinOverride":null},{"id":"de-yi-wang-xing","simplified":"得意忘形","literalMeaning":"pleased to the point of forgetting one's form","figurativeMeaning":"to become so pleased with oneself that one loses composure or forgets one's manners","englishEquivalents":["beside oneself with joy","carried away with success"],"shortGloss":"overjoyed to the point of losing composure","characters":[{"char":"得","meaning":"to obtain; to gain"},{"char":"意","meaning":"pleasure; satisfaction"},{"char":"忘","meaning":"to forget"},{"char":"形","meaning":"form; composure"}],"origin":{"period":"Eastern Jin dynasty (317–420 CE)","sourceText":"《世说新语·任诞》","sourceTextEnglish":"A New Account of the Tales of the World, Chapter on Unrestrained Behavior","originalExcerpt":"王子猷居山阴，夜大雪，眠觉，开室，命酌酒，四望皎然。因起彷徨，咏《诗》曰：“白雪纷纷何所似？”忽忆戴安道，便乘船就之。既至，造门不前而返。人问其故，王曰：“吾本乘兴而行，兴尽而返，何必见戴？”","storyEnglish":"The idiom comes from a story about Wang Ziyou, who lived in Shanyin. One night, after a heavy snowfall, he awoke, opened his door, and ordered wine. He looked around and recited a poem about the snow. Suddenly, he remembered his friend Dai Andao and decided to visit him by boat. However, upon reaching Dai's house, he turned back without entering. When asked why, Wang replied, 'I came on a whim and now that the whim is gone, why should I meet Dai?' This story illustrates how Wang was so carried away by his initial excitement that he acted impulsively.","historicalFigures":["Wang Ziyou","Dai Andao"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"cause-effect","register":"literary, but understood in educated speech","connotation":"negative","commonMistakes":"Learners often confuse this idiom with positive expressions of joy, but it specifically implies losing composure or acting inappropriately due to excessive pride or excitement.","canStandAlone":false},"examples":[{"simplified":"他赢得了比赛，但千万不要得意忘形。","english":"He won the competition, but he mustn't get carried away with himself.","traditional":"他贏得了比賽，但千萬不要得意忘形。"},{"simplified":"成功固然值得庆祝，但也不能得意忘形。","english":"Success is certainly worth celebrating, but one shouldn't lose composure.","traditional":"成功固然值得慶祝，但也不能得意忘形。"}],"synonyms":["自鸣得意"],"antonyms":["谦虚谨慎"],"confusedWith":[{"id":"自鸣得意","note":"While both involve self-satisfaction, 自鸣得意 focuses on self-praise, whereas 得意忘形 emphasizes losing composure."}],"traditional":"得意忘形","pinyinOverride":null},{"id":"de-gao-wang-zhong","simplified":"德高望重","literalMeaning":"virtue high, prestige heavy","figurativeMeaning":"a person of high moral standing and great reputation","englishEquivalents":["held in high esteem","respected and admired"],"shortGloss":"highly respected and esteemed","characters":[{"char":"德","meaning":"virtue, moral character"},{"char":"高","meaning":"high, lofty"},{"char":"望","meaning":"reputation, prestige"},{"char":"重","meaning":"heavy, significant"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '德高望重' is commonly used to describe individuals who are not only morally upright but also enjoy a high level of respect and admiration from others. The phrase emphasizes both the individual's character and their esteemed position in society. It is often used to refer to elders or leaders who have earned respect through their actions and integrity.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["attributive","predicate"],"structure":"coordinate","register":"widely used in both formal and informal contexts, especially to praise respected figures","connotation":"positive","commonMistakes":"Learners might confuse this idiom with others that involve '德' (virtue) but lack the same emphasis on reputation. It's specifically used for people who are both virtuous and respected.","canStandAlone":false},"examples":[{"simplified":"他是一位德高望重的教授，学生们都很尊敬他。","english":"He is a professor of high moral standing and great reputation, and all the students respect him greatly.","traditional":"他是一位德高望重的教授，學生們都很尊敬他。"},{"simplified":"在这个村子里，李爷爷是德高望重的人物。","english":"In this village, Grandpa Li is a person of high moral standing and great reputation.","traditional":"在這個村子裡，李爺爺是德高望重的人物。"}],"synonyms":["德才兼备","才高八斗"],"antonyms":[],"confusedWith":[{"id":"德才兼备","note":"While both idioms involve '德' (virtue), '德才兼备' emphasizes both virtue and talent, not necessarily reputation."}],"traditional":"德高望重","pinyinOverride":null},{"id":"er-ru-mu-ran","simplified":"耳濡目染","literalMeaning":"ears moistened, eyes dyed","figurativeMeaning":"to be unconsciously influenced by what one constantly sees and hears","englishEquivalents":["to be subtly influenced","to be affected by osmosis"],"shortGloss":"subtly influenced by surroundings","characters":[{"char":"耳","meaning":"ears"},{"char":"濡","meaning":"moistened"},{"char":"目","meaning":"eyes"},{"char":"染","meaning":"dyed"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom 耳濡目染 describes the process of being subtly and unconsciously influenced by one's environment, particularly through constant exposure to certain behaviors or ideas. It suggests that just as ears can be moistened and eyes can be dyed, a person can be influenced by what they hear and see repeatedly.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"coordinate","register":"widely used in both written and spoken Chinese","connotation":"neutral","commonMistakes":"Learners might confuse 耳濡目染 with idioms that imply deliberate teaching or learning, but this idiom emphasizes unconscious influence. It's also sometimes mistaken for idioms about direct influence, rather than subtle, passive absorption.","canStandAlone":false},"examples":[{"simplified":"在这样的环境中长大，他耳濡目染，自然也变得很有礼貌。","english":"Growing up in such an environment, he was subtly influenced and naturally became very polite.","traditional":"在這樣的環境中長大，他耳濡目染，自然也變得很有禮貌。"},{"simplified":"孩子们在父母的耳濡目染下，逐渐养成了良好的习惯。","english":"Under the subtle influence of their parents, the children gradually developed good habits.","traditional":"孩子們在父母的耳濡目染下，逐漸養成了良好的習慣。"}],"synonyms":["潜移默化"],"antonyms":[],"confusedWith":[{"id":"潜移默化","note":"潜移默化 also means subtle influence, but it often implies a more gradual and imperceptible change."}],"traditional":"耳濡目染","pinyinOverride":null},{"id":"fen-bu-gu-shen","simplified":"奋不顾身","literalMeaning":"exert oneself without regard for one's own body","figurativeMeaning":"to risk one's life regardless of personal safety; to act with total disregard for oneself","englishEquivalents":["to risk life and limb","to throw caution to the wind"],"shortGloss":"risking life and limb","characters":[{"char":"奋","meaning":"exert oneself"},{"char":"不","meaning":"not"},{"char":"顾","meaning":"care for; regard"},{"char":"身","meaning":"body; self"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '奋不顾身' describes a person who is willing to take great risks and act with complete disregard for their own safety. It is often used to praise someone who shows great courage and selflessness, especially in dangerous situations.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"commonly used in both written and spoken Chinese to describe acts of bravery or selflessness","connotation":"positive","commonMistakes":"Learners might confuse this idiom with others that involve bravery but do not imply the same level of selflessness or disregard for personal safety. It's important to note that '奋不顾身' emphasizes the lack of concern for one's own well-being.","canStandAlone":false},"examples":[{"simplified":"他在火灾中奋不顾身地救出了被困的人。","english":"He risked his life to save the trapped people in the fire.","traditional":"他在火災中奮不顧身地救出了被困的人。"},{"simplified":"为了保护国家，他奋不顾身地冲向敌人。","english":"To protect the country, he charged at the enemy without regard for his own safety.","traditional":"為了保護國家，他奮不顧身地衝向敵人。"}],"synonyms":["舍生忘死"],"antonyms":["畏首畏尾"],"confusedWith":[{"id":"舍生取义","note":"While both idioms involve self-sacrifice, '舍生取义' emphasizes sacrificing oneself for a righteous cause, whereas '奋不顾身' focuses on the act of risking one's life without concern for personal safety."}],"traditional":"奮不顧身","pinyinOverride":null},{"id":"feng-chi-dian-che","simplified":"风驰电掣","literalMeaning":"wind gallops, lightning flashes","figurativeMeaning":"extremely fast; at lightning speed","englishEquivalents":["as fast as lightning","at breakneck speed"],"shortGloss":"extremely fast","characters":[{"char":"风","meaning":"wind"},{"char":"驰","meaning":"gallop"},{"char":"电","meaning":"lightning"},{"char":"掣","meaning":"flash"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '风驰电掣' is used to describe something moving with incredible speed, similar to the way wind rushes or lightning flashes. The imagery of wind and lightning conveys a sense of rapidity and power. The exact origin of this idiom is not clearly documented, but it has been used in Chinese literature and speech to emphasize swiftness.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["adverbial","predicate"],"structure":"coordinate","register":"commonly used in both written and spoken Chinese to describe speed","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with others that involve speed but have different nuances, such as '一日千里' which implies rapid progress rather than just speed. '风驰电掣' specifically emphasizes the swiftness of movement.","canStandAlone":false},"examples":[{"simplified":"他开车风驰电掣地赶往机场。","english":"He drove to the airport at breakneck speed.","traditional":"他開車風馳電掣地趕往機場。"},{"simplified":"比赛中，他风驰电掣般地冲过终点线。","english":"In the race, he dashed across the finish line as fast as lightning.","traditional":"比賽中，他風馳電掣般地衝過終點線。"}],"synonyms":["一日千里"],"antonyms":[],"confusedWith":[{"id":"一日千里","note":"While both idioms involve speed, '一日千里' emphasizes rapid progress rather than just movement speed."}],"traditional":"風馳電掣","pinyinOverride":null},{"id":"feng-gong-shou-fa","simplified":"奉公守法","literalMeaning":"serve the public and obey the law","figurativeMeaning":"to be law-abiding and dutiful","englishEquivalents":["law-abiding citizen","play by the rules"],"shortGloss":"law-abiding and dutiful","characters":[{"char":"奉","meaning":"to serve, to offer respectfully"},{"char":"公","meaning":"public, common, fair"},{"char":"守","meaning":"to guard, to observe"},{"char":"法","meaning":"law, method"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '奉公守法' emphasizes the virtues of serving the public interest and adhering to the laws. It is often used to describe individuals who are conscientious and law-abiding, fulfilling their duties with integrity and respect for the rules.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"coordinate","register":"commonly used in both formal and informal contexts to describe someone who is law-abiding and dutiful","connotation":"positive","commonMistakes":"Learners might confuse this idiom with others that involve law or duty but do not emphasize both public service and lawfulness. It is specifically about being both dutiful and law-abiding.","canStandAlone":false},"examples":[{"simplified":"他一直以来都是一个奉公守法的好公民。","english":"He has always been a law-abiding and dutiful citizen.","traditional":"他一直以來都是一個奉公守法的好公民。"},{"simplified":"在这个公司工作，最重要的是奉公守法。","english":"The most important thing about working at this company is to be law-abiding and dutiful.","traditional":"在這個公司工作，最重要的是奉公守法。"}],"synonyms":["遵纪守法"],"antonyms":["违法乱纪"],"confusedWith":[{"id":"遵纪守法","note":"While both idioms emphasize lawfulness, '奉公守法' includes a sense of public duty."}],"traditional":"奉公守法","pinyinOverride":null},{"id":"fu-yan-se-ze","simplified":"敷衍塞责","literalMeaning":"perfunctorily fulfill one's duty","figurativeMeaning":"to perform one's duties in a careless or negligent manner; to go through the motions without genuine effort","englishEquivalents":["go through the motions","cut corners"],"shortGloss":"perform duties carelessly","characters":[{"char":"敷","meaning":"apply; spread"},{"char":"衍","meaning":"extend; develop"},{"char":"塞","meaning":"fill; block"},{"char":"责","meaning":"duty; responsibility"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '敷衍塞责' describes a situation where someone performs their duties superficially or without genuine effort. It suggests a lack of thoroughness and responsibility, often resulting in subpar outcomes. The phrase likely emerged from the combination of words meaning to spread or apply superficially and to block or fill responsibilities, metaphorically illustrating a careless approach to one's duties.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"commonly used in both formal and informal contexts to criticize lack of effort or diligence","connotation":"negative","commonMistakes":"Learners often confuse this idiom with similar expressions that imply negligence, but '敷衍塞责' specifically emphasizes the superficial fulfillment of duties rather than outright neglect.","canStandAlone":false},"examples":[{"simplified":"他总是敷衍塞责，难怪他的工作总是出问题。","english":"He always goes through the motions, no wonder his work always has problems.","traditional":"他總是敷衍塞責，難怪他的工作總是出問題。"},{"simplified":"如果你继续敷衍塞责，迟早会被发现的。","english":"If you continue to cut corners, you'll be found out sooner or later.","traditional":"如果你繼續敷衍塞責，遲早會被發現的。"}],"synonyms":["得过且过","草草了事"],"antonyms":["尽职尽责","全力以赴"],"confusedWith":[{"id":"得过且过","note":"While both imply a lack of thoroughness, '得过且过' suggests a more passive attitude of just getting by, whereas '敷衍塞责' involves actively performing duties carelessly."}],"traditional":"敷衍塞責","pinyinOverride":null},{"id":"gai-guo-zi-xin","simplified":"改过自新","literalMeaning":"change past mistakes, renew oneself","figurativeMeaning":"to reform oneself; to correct one's past mistakes and start anew","englishEquivalents":["turn over a new leaf","make a fresh start"],"shortGloss":"reform oneself","characters":[{"char":"改","meaning":"change"},{"char":"过","meaning":"mistakes"},{"char":"自","meaning":"oneself"},{"char":"新","meaning":"new"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '改过自新' emphasizes the idea of acknowledging one's past mistakes and making a conscious effort to improve oneself and start afresh. It is often used to encourage people to leave behind their wrongdoings and embrace a better path.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"widely used in both formal and informal contexts","connotation":"positive","commonMistakes":"Learners sometimes confuse this idiom with others that involve change or improvement, but '改过自新' specifically emphasizes personal reform and correcting past mistakes.","canStandAlone":false},"examples":[{"simplified":"他决定改过自新，重新开始他的生活。","english":"He decided to turn over a new leaf and start his life anew.","traditional":"他決定改過自新，重新開始他的生活。"},{"simplified":"经过反思，他意识到自己的错误，并努力改过自新。","english":"After reflecting, he realized his mistakes and worked hard to reform himself.","traditional":"經過反思，他意識到自己的錯誤，並努力改過自新。"}],"synonyms":["痛改前非"],"antonyms":[],"confusedWith":[{"id":"焕然一新","note":"While '焕然一新' refers to a complete transformation or renewal, '改过自新' specifically involves correcting past mistakes."}],"traditional":"改過自新","pinyinOverride":null},{"id":"gao-zhan-yuan-zhu","simplified":"高瞻远瞩","literalMeaning":"high view, far gaze","figurativeMeaning":"to have foresight and vision; to be able to see the big picture","englishEquivalents":["to have foresight","to see the big picture"],"shortGloss":"foresight and vision","characters":[{"char":"高","meaning":"high"},{"char":"瞻","meaning":"to view"},{"char":"远","meaning":"far"},{"char":"瞩","meaning":"to gaze"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom 高瞻远瞩 describes someone who has the ability to see beyond the immediate and anticipate future developments. It emphasizes the importance of having a broad perspective and long-term vision, qualities that are highly valued in leadership and strategic planning.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"coordinate","register":"literary, but very widely understood and used in ordinary speech","connotation":"positive","commonMistakes":"Learners might confuse this idiom with ones that emphasize immediate observation rather than long-term vision. It is important to use it in contexts where foresight is being praised.","canStandAlone":false},"examples":[{"simplified":"这位领导者高瞻远瞩，为公司制定了长远的发展计划。","english":"This leader has foresight and vision, and has set long-term development plans for the company.","traditional":"這位領導者高瞻遠矚，為公司制定了長遠的發展計劃。"},{"simplified":"高瞻远瞩的策略帮助我们在竞争中取得了优势。","english":"The strategy with foresight and vision helped us gain an advantage in the competition.","traditional":"高瞻遠矚的策略幫助我們在競爭中取得了優勢。"}],"synonyms":["深谋远虑"],"antonyms":["鼠目寸光"],"confusedWith":[{"id":"目光短浅","note":"目光短浅 refers to short-sightedness, the opposite of having foresight."}],"traditional":"高瞻遠矚","pinyinOverride":null},{"id":"gao-zhen-wu-you","simplified":"高枕无忧","literalMeaning":"high pillow no worries","figurativeMeaning":"to be free of worries; to live in peace without concerns","englishEquivalents":["sleep easy","rest easy","without a care in the world"],"shortGloss":"to be free of worries","characters":[{"char":"高","meaning":"high"},{"char":"枕","meaning":"pillow"},{"char":"无","meaning":"no; without"},{"char":"忧","meaning":"worries; concerns"}],"origin":{"period":"Warring States period (475–221 BCE)","sourceText":"《战国策·齐策四》","sourceTextEnglish":"Strategies of the Warring States, Strategies of Qi, Chapter 4","originalExcerpt":"王坐于堂上而高枕无忧。","storyEnglish":"The idiom originates from a story in the 'Strategies of the Warring States'. It describes a king who, after securing his kingdom and ensuring peace, could sit on his throne and sleep with his pillow high, free from worries. This imagery of a high pillow symbolizes a state of complete relaxation and lack of concern, as the king no longer needed to worry about threats to his rule.","historicalFigures":["King of Qi"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","complement"],"structure":"subject-predicate","register":"literary, but widely understood and used in ordinary speech","connotation":"positive","commonMistakes":"Learners might confuse this idiom with similar expressions about sleep, but it specifically conveys a sense of peace and lack of worry, not just the act of sleeping well.","canStandAlone":false},"examples":[{"simplified":"经过多年的努力，他终于可以高枕无忧了。","english":"After years of hard work, he can finally rest easy.","traditional":"經過多年的努力，他終於可以高枕無憂了。"},{"simplified":"只有解决了所有问题，我们才能高枕无忧。","english":"Only after solving all the problems can we be free of worries.","traditional":"只有解決了所有問題，我們才能高枕無憂。"}],"synonyms":["无忧无虑","安枕无忧"],"antonyms":["提心吊胆"],"confusedWith":[{"id":"无忧无虑","note":"While both idioms mean being free of worries, 无忧无虑 often emphasizes a carefree attitude, especially in children, whereas 高枕无忧 implies a state achieved after resolving concerns."}],"traditional":"高枕無憂","pinyinOverride":null},{"id":"ge-you-qian-qiu","simplified":"各有千秋","literalMeaning":"each has a thousand autumns","figurativeMeaning":"each has its own merits; everyone has their strengths","englishEquivalents":["to each their own","different strokes for different folks"],"shortGloss":"each has its own merits","characters":[{"char":"各","meaning":"each"},{"char":"有","meaning":"has"},{"char":"千","meaning":"thousand"},{"char":"秋","meaning":"autumn; metaphorically, merits or qualities"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom 各有千秋 is believed to have originated from the idea that just as autumn is a season of harvest and beauty, each person or thing has its own unique qualities and strengths that can be appreciated. The phrase suggests that comparisons are unnecessary because everyone or everything has its own distinct merits.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"subject-predicate","register":"commonly used in both spoken and written Chinese","connotation":"positive","commonMistakes":"Learners might confuse 各有千秋 with similar idioms that emphasize differences without the positive connotation of unique strengths. It is important to use this idiom when highlighting the positive aspects of differences.","canStandAlone":false},"examples":[{"simplified":"这两位艺术家的作品各有千秋，很难说谁更好。","english":"The works of these two artists each have their own merits, so it's hard to say who is better.","traditional":"這兩位藝術家的作品各有千秋，很難說誰更好。"},{"simplified":"不同的文化各有千秋，我们应该互相尊重。","english":"Different cultures each have their own merits, and we should respect one another.","traditional":"不同的文化各有千秋，我們應該互相尊重。"}],"synonyms":["各有所长"],"antonyms":[],"confusedWith":[{"id":"各有所好","note":"各有所好 means 'each has their own preferences', focusing on personal tastes rather than merits."}],"traditional":"各有千秋","pinyinOverride":null},{"id":"gong-kui-yi-kui","simplified":"功亏一篑","literalMeaning":"effort fails by one basket of earth","figurativeMeaning":"to fail at the last hurdle; to fall short of success due to a minor shortcoming","englishEquivalents":["to fall at the last hurdle","to miss by a hair's breadth"],"shortGloss":"to fail at the last hurdle","characters":[{"char":"功","meaning":"achievement; effort"},{"char":"亏","meaning":"to fail; to lack"},{"char":"一","meaning":"one"},{"char":"篑","meaning":"basket of earth"}],"origin":{"period":"Warring States period (475–221 BCE)","sourceText":"《尚书·旅獒》","sourceTextEnglish":"Book of Documents, Chapter: Lü Ao","originalExcerpt":"为山九仞，功亏一篑。","storyEnglish":"The idiom comes from the 'Book of Documents,' where it is said that building a mountain nine fathoms high could fail for lack of a single basket of earth. It emphasizes the importance of seeing a task through to completion, as even a small oversight can lead to failure.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","complement"],"structure":"verb-object","register":"literary, but very widely understood and used in ordinary speech","connotation":"negative","commonMistakes":"Learners often confuse this idiom with others that imply a complete failure from the start, rather than a failure due to a minor final shortcoming. It specifically refers to falling short at the very end of an effort.","canStandAlone":false},"examples":[{"simplified":"他在最后一刻放弃了，真是功亏一篑。","english":"He gave up at the last moment, truly a case of failing at the last hurdle.","traditional":"他在最後一刻放棄了，真是功虧一簣。"},{"simplified":"如果不坚持下去，我们可能会功亏一篑。","english":"If we don't persevere, we might fail at the last hurdle.","traditional":"如果不堅持下去，我們可能會功虧一簣。"}],"synonyms":[],"antonyms":["功成名就"],"confusedWith":[{"id":"半途而废","note":"半途而废 refers to giving up halfway, while 功亏一篑 emphasizes failure at the very end."}],"traditional":"功虧一簣","pinyinOverride":null},{"id":"gou-xin-dou-jiao","simplified":"勾心斗角","literalMeaning":"hook heart, fight angles","figurativeMeaning":"to engage in intrigue and rivalry; to scheme and compete against each other","englishEquivalents":["plot and scheme","intrigue and rivalry"],"shortGloss":"engage in intrigue and rivalry","characters":[{"char":"勾","meaning":"hook; to plot or scheme"},{"char":"心","meaning":"heart; mind"},{"char":"斗","meaning":"fight; compete"},{"char":"角","meaning":"angle; corner; rivalry"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '勾心斗角' is believed to have originated from the competitive and often deceitful environment of ancient Chinese courts, where officials would engage in schemes and rivalries to gain favor or power. The phrase metaphorically describes the mental and strategic battles that occur in such environments.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"coordinate","register":"commonly used in both written and spoken Chinese to describe competitive and scheming behavior, especially in political or organizational contexts","connotation":"negative","commonMistakes":"Learners might confuse this idiom with more neutral expressions of competition, but '勾心斗角' specifically implies deceit and underhanded tactics. It should not be used to describe fair or friendly competition.","canStandAlone":false},"examples":[{"simplified":"在公司里，勾心斗角的现象很常见。","english":"In the company, intrigue and rivalry are very common.","traditional":"在公司裡，勾心鬥角的現象很常見。"},{"simplified":"他不喜欢勾心斗角的政治游戏。","english":"He doesn't like the political games of intrigue and rivalry.","traditional":"他不喜歡勾心鬥角的政治遊戲。"}],"synonyms":["尔虞我诈","明争暗斗"],"antonyms":["团结一致"],"confusedWith":[{"id":"明争暗斗","note":"Both involve competition, but '明争暗斗' emphasizes open and hidden struggles, while '勾心斗角' focuses on scheming and intrigue."}],"traditional":"勾心鬥角","pinyinOverride":null},{"id":"gou-qie-tou-an","simplified":"苟且偷安","literalMeaning":"carelessly and temporarily steal comfort","figurativeMeaning":"to seek temporary ease and comfort without regard for the future; to live in the moment without ambition","englishEquivalents":["live for today","take the path of least resistance"],"shortGloss":"seek temporary comfort without future concern","characters":[{"char":"苟","meaning":"carelessly"},{"char":"且","meaning":"temporarily"},{"char":"偷","meaning":"steal"},{"char":"安","meaning":"comfort"}],"origin":{"period":"Han Dynasty (206 BCE – 220 CE)","sourceText":"《后汉书·光武帝纪》","sourceTextEnglish":"Book of the Later Han, Annals of Emperor Guangwu","originalExcerpt":"苟且偷安，非长久之计。","storyEnglish":"The idiom comes from a passage in the 'Book of the Later Han', where it is used to describe a strategy that focuses on immediate comfort and safety without considering long-term consequences. It warns against the shortsightedness of such an approach.","historicalFigures":["Emperor Guangwu"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"coordinate","register":"literary, but can be used in both formal writing and speech","connotation":"negative","commonMistakes":"Learners often confuse this idiom with those that imply laziness or procrastination, but it specifically refers to seeking comfort without future planning.","canStandAlone":false},"examples":[{"simplified":"他总是苟且偷安，不愿意为未来努力。","english":"He always seeks temporary comfort and is unwilling to work hard for the future.","traditional":"他總是苟且偷安，不願意為未來努力。"},{"simplified":"在面对挑战时，苟且偷安只会让问题变得更糟。","english":"When facing challenges, seeking temporary comfort will only make the problem worse.","traditional":"在面對挑戰時，苟且偷安只會讓問題變得更糟。"}],"synonyms":[],"antonyms":["未雨绸缪"],"confusedWith":[{"id":"得过且过","note":"While both idioms involve a lack of long-term planning, '得过且过' emphasizes getting by without ambition, whereas '苟且偷安' focuses on seeking comfort."}],"traditional":"苟且偷安","pinyinOverride":null},{"id":"gu-zhu-yi-zhi","simplified":"孤注一掷","literalMeaning":"single stake, one throw","figurativeMeaning":"to risk everything on a single venture","englishEquivalents":["all or nothing","go for broke"],"shortGloss":"risk everything on one attempt","characters":[{"char":"孤","meaning":"single, alone"},{"char":"注","meaning":"stake, bet"},{"char":"一","meaning":"one"},{"char":"掷","meaning":"throw, cast"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '孤注一掷' is believed to originate from gambling, where a player might bet all their remaining money on a single throw of the dice. It metaphorically describes a situation where someone takes a significant risk by committing all their resources to one final effort, hoping for success.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"widely used in both spoken and written Chinese","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with others that involve risk, but '孤注一掷' specifically implies putting everything on the line for one last attempt. It is not used for general risky behavior.","canStandAlone":false},"examples":[{"simplified":"他决定孤注一掷，把所有的钱都投资在这个项目上。","english":"He decided to risk everything and invest all his money in this project.","traditional":"他決定孤注一擲，把所有的錢都投資在這個項目上。"},{"simplified":"在最后一场比赛中，他们孤注一掷，拼尽全力争取胜利。","english":"In the final match, they went all out, risking everything to secure the victory.","traditional":"在最後一場比賽中，他們孤注一擲，拼盡全力爭取勝利。"}],"synonyms":["破釜沉舟"],"antonyms":[],"confusedWith":[{"id":"背水一战","note":"While both involve taking a risk, '背水一战' implies a strategic decision to fight with no retreat, whereas '孤注一掷' is about risking everything on one attempt."}],"traditional":"孤注一擲","pinyinOverride":null},{"id":"gu-ming-diao-yu","simplified":"沽名钓誉","literalMeaning":"sell name, fish for praise","figurativeMeaning":"to fish for fame and compliments; to seek personal gain by pretending to be virtuous","englishEquivalents":["fishing for compliments","seeking fame and fortune"],"shortGloss":"fishing for fame and praise","characters":[{"char":"沽","meaning":"to sell; to seek"},{"char":"名","meaning":"name; fame"},{"char":"钓","meaning":"to fish; to lure"},{"char":"誉","meaning":"praise; reputation"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '沽名钓誉' describes the act of seeking fame and praise through insincere or deceitful means. It implies that someone is more concerned with appearances and accolades than with genuine virtue or achievement. The imagery of 'selling' one's name and 'fishing' for praise suggests a transactional and manipulative approach to gaining a good reputation.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"literary, but understood in educated speech","connotation":"negative","commonMistakes":"Learners might confuse this idiom with more neutral expressions about gaining fame. Unlike neutral terms, this idiom carries a negative connotation of deceit or insincerity.","canStandAlone":false},"examples":[{"simplified":"他总是沽名钓誉，实际上并没有多少真才实学。","english":"He is always fishing for compliments, but in reality, he doesn't have much genuine talent or knowledge.","traditional":"他總是沽名釣譽，實際上並沒有多少真才實學。"},{"simplified":"在这个项目中，我们不需要沽名钓誉的人，只需要真正能做事的人。","english":"In this project, we don't need people who are fishing for fame; we need people who can actually get things done.","traditional":"在這個項目中，我們不需要沽名釣譽的人，只需要真正能做事的人。"}],"synonyms":["虚情假意","装腔作势"],"antonyms":["实事求是","脚踏实地"],"confusedWith":[{"id":"沽名钓誉","note":"This idiom is sometimes confused with neutral expressions about gaining fame, but it specifically implies deceitful or insincere methods."}],"traditional":"沽名釣譽","pinyinOverride":null},{"id":"gu-se-gu-xiang","simplified":"古色古香","literalMeaning":"ancient color, ancient fragrance","figurativeMeaning":"having an antique or classical charm","englishEquivalents":["old-world charm","antique elegance"],"shortGloss":"antique charm","characters":[{"char":"古","meaning":"ancient"},{"char":"色","meaning":"color"},{"char":"古","meaning":"ancient"},{"char":"香","meaning":"fragrance"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '古色古香' is used to describe objects, places, or even atmospheres that evoke a sense of antiquity or classical beauty. It is often used in the context of traditional Chinese architecture, furniture, or art that retains an old-world charm.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["attributive"],"structure":"coordinate","register":"commonly used in both literary and spoken Chinese to describe things with an antique or classical charm","connotation":"positive","commonMistakes":"Learners might mistakenly use this idiom to describe something simply old or outdated, but it specifically refers to things that are charmingly antique or classically beautiful.","canStandAlone":false},"examples":[{"simplified":"这家茶馆古色古香，吸引了很多游客。","english":"This teahouse has an antique charm and attracts many tourists.","traditional":"這家茶館古色古香，吸引了很多遊客。"},{"simplified":"她的家布置得古色古香，仿佛回到了过去的时代。","english":"Her home is decorated with an antique elegance, as if stepping back into a bygone era.","traditional":"她的家佈置得古色古香，彷彿回到了過去的時代。"}],"synonyms":["古朴典雅"],"antonyms":["现代化"],"confusedWith":[],"traditional":"古色古香","pinyinOverride":null},{"id":"guai-wan-mo-jiao","simplified":"拐弯抹角","literalMeaning":"turn corners and rub angles","figurativeMeaning":"to beat around the bush; to speak in a roundabout way","englishEquivalents":["beat around the bush","talk in circles"],"shortGloss":"beat around the bush","characters":[{"char":"拐","meaning":"to turn"},{"char":"弯","meaning":"bend, curve"},{"char":"抹","meaning":"rub, wipe"},{"char":"角","meaning":"corner, angle"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '拐弯抹角' is used to describe someone who does not speak directly or straightforwardly, often avoiding the main point by talking in a roundabout manner. The imagery of turning corners and rubbing angles suggests taking a convoluted path rather than a direct one. This expression is commonly used in everyday conversation to describe evasive or indirect communication.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["adverbial","predicate"],"structure":"coordinate","register":"informal, commonly used in both spoken and written Chinese","connotation":"negative","commonMistakes":"Learners might confuse this idiom with direct expressions of speaking or communicating, but it specifically implies indirectness or evasiveness. It should not be used to describe straightforward communication.","canStandAlone":false},"examples":[{"simplified":"他说话总是拐弯抹角，让人很难理解他的意思。","english":"He always beats around the bush, making it hard for people to understand what he means.","traditional":"他說話總是拐彎抹角，讓人很難理解他的意思。"},{"simplified":"如果你有问题，就直接问，不要拐弯抹角。","english":"If you have a question, just ask directly, don't beat around the bush.","traditional":"如果你有問題，就直接問，不要拐彎抹角。"}],"synonyms":["旁敲侧击","吞吞吐吐"],"antonyms":["直截了当"],"confusedWith":[{"id":"直截了当","note":"直截了当 means to speak directly and straightforwardly, the opposite of 拐弯抹角."}],"traditional":"拐彎抹角","pinyinOverride":null},{"id":"guang-ming-zheng-da","simplified":"光明正大","literalMeaning":"bright and upright","figurativeMeaning":"open and aboveboard; honest and straightforward","englishEquivalents":["aboveboard","honest and straightforward","with integrity"],"shortGloss":"open and aboveboard","characters":[{"char":"光","meaning":"bright"},{"char":"明","meaning":"clear"},{"char":"正","meaning":"upright"},{"char":"大","meaning":"grand"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '光明正大' is used to describe actions or behavior that are conducted in an honest, open, and straightforward manner. It emphasizes transparency and integrity, suggesting that there is nothing to hide. The exact origin of this idiom is not clearly documented in a specific classical text, but it has been widely used in Chinese literature and speech to commend moral uprightness and honesty.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"coordinate","register":"commonly used in both formal and informal contexts","connotation":"positive","commonMistakes":"Learners might confuse '光明正大' with idioms that imply deceit or cunning due to its positive connotation. It is important to remember that this idiom is used to describe honesty and transparency.","canStandAlone":false},"examples":[{"simplified":"他的行为光明正大，没有什么可隐瞒的。","english":"His actions are open and aboveboard, with nothing to hide.","traditional":"他的行為光明正大，沒有什麼可隱瞞的。"},{"simplified":"我们要光明正大地处理这个问题。","english":"We need to handle this issue in an honest and straightforward manner.","traditional":"我們要光明正大地處理這個問題。"}],"synonyms":["坦坦荡荡"],"antonyms":["鬼鬼祟祟"],"confusedWith":[{"id":"鬼鬼祟祟","note":"光明正大 is positive, implying honesty, while 鬼鬼祟祟 implies sneaky or secretive behavior."}],"traditional":"光明正大","pinyinOverride":null},{"id":"hai-di-lao-zhen","simplified":"海底捞针","literalMeaning":"fish for a needle at the bottom of the sea","figurativeMeaning":"an extremely difficult or impossible task","englishEquivalents":["like finding a needle in a haystack"],"shortGloss":"an impossible task","characters":[{"char":"海","meaning":"sea"},{"char":"底","meaning":"bottom"},{"char":"捞","meaning":"to fish for"},{"char":"针","meaning":"needle"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '海底捞针' is used to describe a task that is extremely difficult to accomplish, akin to trying to find a needle at the bottom of the sea. This metaphor highlights the near impossibility of the task due to the vastness of the sea and the small size of a needle.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["attributive","adverbial"],"structure":"verb-object","register":"commonly used in both spoken and written Chinese","connotation":"negative","commonMistakes":"Learners might confuse this idiom with those that describe difficult but achievable tasks. This idiom specifically implies near impossibility, not just difficulty.","canStandAlone":false},"examples":[{"simplified":"在这么多文件中找到那一页，简直是海底捞针。","english":"Finding that one page among so many documents is like fishing for a needle at the bottom of the sea.","traditional":"在這麼多文件中找到那一頁，簡直是海底撈針。"},{"simplified":"想在大城市里找到一个老朋友，真是海底捞针。","english":"Trying to find an old friend in a big city is really like fishing for a needle at the bottom of the sea.","traditional":"想在大城市裡找到一個老朋友，真是海底撈針。"}],"synonyms":[],"antonyms":[],"confusedWith":[],"traditional":"海底撈針","pinyinOverride":null},{"id":"han-xin-ru-ku","simplified":"含辛茹苦","literalMeaning":"endure hardship and swallow bitterness","figurativeMeaning":"to endure hardships and sufferings","englishEquivalents":["to bear hardships","to go through thick and thin"],"shortGloss":"endure hardships and sufferings","characters":[{"char":"含","meaning":"to endure"},{"char":"辛","meaning":"hardship"},{"char":"茹","meaning":"to swallow"},{"char":"苦","meaning":"bitterness"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom 含辛茹苦 describes the experience of enduring great hardships and sufferings. It is often used to describe people who have gone through difficult times, such as parents who have worked hard to raise their children despite many challenges. The phrase evokes the image of someone swallowing bitterness and enduring pain, emphasizing their resilience and determination.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"coordinate","register":"common in both written and spoken Chinese, often used in a literary context","connotation":"neutral","commonMistakes":"Learners might confuse 含辛茹苦 with similar idioms that also describe enduring hardship, such as 艰苦奋斗, which focuses more on the struggle and effort rather than the endurance of suffering.","canStandAlone":false},"examples":[{"simplified":"她为了孩子们的未来，含辛茹苦地工作。","english":"She worked hard, enduring hardships for the sake of her children's future.","traditional":"她為了孩子們的未來，含辛茹苦地工作。"},{"simplified":"在创业的过程中，他含辛茹苦，终于取得了成功。","english":"During the process of starting his business, he endured many hardships and finally achieved success.","traditional":"在創業的過程中，他含辛茹苦，終於取得了成功。"}],"synonyms":["艰苦奋斗","忍辱负重"],"antonyms":[],"confusedWith":[{"id":"艰苦奋斗","note":"艰苦奋斗 emphasizes the struggle and effort, while 含辛茹苦 focuses on enduring suffering."}],"traditional":"含辛茹苦","pinyinOverride":null},{"id":"hao-gao-wu-yuan","simplified":"好高骛远","literalMeaning":"love heights, pursue distance","figurativeMeaning":"to aim too high and pursue unrealistic goals","englishEquivalents":["reach for the stars","bite off more than you can chew"],"shortGloss":"aiming too high; unrealistic goals","characters":[{"char":"好","meaning":"love; fond of"},{"char":"高","meaning":"high"},{"char":"骛","meaning":"pursue"},{"char":"远","meaning":"far; distant"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom 好高骛远 describes someone who is overly ambitious, aiming for goals that are beyond their reach without considering their current capabilities. It serves as a caution against setting unrealistic expectations and encourages focusing on achievable objectives.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"coordinate","register":"commonly used in both written and spoken Chinese to describe overly ambitious behavior","connotation":"negative","commonMistakes":"Learners often confuse this idiom with expressions that simply mean 'ambitious' without the negative connotation of being unrealistic. It specifically implies a lack of practicality.","canStandAlone":false},"examples":[{"simplified":"他总是好高骛远，从不脚踏实地。","english":"He always aims too high and never keeps his feet on the ground.","traditional":"他總是好高騖遠，從不腳踏實地。"},{"simplified":"在制定目标时，我们不应该好高骛远。","english":"When setting goals, we shouldn't aim too high and pursue unrealistic ones.","traditional":"在制定目標時，我們不應該好高騖遠。"}],"synonyms":["眼高手低"],"antonyms":["脚踏实地"],"confusedWith":[{"id":"雄心勃勃","note":"雄心勃勃 means 'ambitious' but does not carry the negative connotation of being unrealistic."}],"traditional":"好高騖遠","pinyinOverride":null},{"id":"hao-yi-e-lao","simplified":"好逸恶劳","literalMeaning":"love ease, hate labor","figurativeMeaning":"to love ease and comfort and hate work; to be lazy","englishEquivalents":["lazybones","work-shy"],"shortGloss":"lazy and work-averse","characters":[{"char":"好","meaning":"to like or love"},{"char":"逸","meaning":"ease, comfort"},{"char":"恶","meaning":"to hate or detest"},{"char":"劳","meaning":"labor, work"}],"origin":{"period":"Han Dynasty (206 BCE – 220 CE)","sourceText":"《汉书·贾谊传》","sourceTextEnglish":"Book of Han, Biography of Jia Yi","originalExcerpt":"人之情，莫不好逸而恶劳。","storyEnglish":"The idiom originates from the 'Book of Han', where Jia Yi, a prominent scholar and statesman, discusses human nature. He observes that it is a common tendency for people to prefer ease and comfort over hard work. This observation has since been encapsulated in the idiom 好逸恶劳.","historicalFigures":["Jia Yi"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adjectival"],"structure":"coordinate","register":"widely used in both formal and informal contexts","connotation":"negative","commonMistakes":"Learners often confuse this idiom with others that describe laziness, but it specifically emphasizes the preference for ease over effort. It is not used to describe temporary laziness but a habitual tendency.","canStandAlone":false},"examples":[{"simplified":"他总是好逸恶劳，从不愿意努力工作。","english":"He always loves ease and hates work, never willing to put in effort.","traditional":"他總是好逸惡勞，從不願意努力工作。"},{"simplified":"好逸恶劳的人很难在竞争激烈的环境中成功。","english":"People who love ease and hate work find it hard to succeed in a competitive environment.","traditional":"好逸惡勞的人很難在競爭激烈的環境中成功。"}],"synonyms":["游手好闲"],"antonyms":["勤奋努力"],"confusedWith":[{"id":"游手好闲","note":"While both idioms describe laziness, 游手好闲 emphasizes idleness and lack of occupation, whereas 好逸恶劳 focuses on the preference for ease over work."}],"traditional":"好逸惡勞","pinyinOverride":null},{"id":"hu-zuo-fei-wei","simplified":"胡作非为","literalMeaning":"recklessly do wrong","figurativeMeaning":"to act wildly and without regard for rules or laws","englishEquivalents":["run amok","act lawlessly"],"shortGloss":"act recklessly and lawlessly","characters":[{"char":"胡","meaning":"recklessly"},{"char":"作","meaning":"do"},{"char":"非","meaning":"wrong"},{"char":"为","meaning":"act"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom 胡作非为 describes actions that are reckless and lawless, often used to criticize someone who acts without considering rules or consequences. It conveys a sense of chaos and disregard for order.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"commonly used in both formal and informal contexts to criticize lawless behavior","connotation":"negative","commonMistakes":"Learners often confuse 胡作非为 with idioms that describe mere mischief or minor rule-breaking, but it specifically implies serious, lawless actions.","canStandAlone":false},"examples":[{"simplified":"他在公司里胡作非为，最终被解雇了。","english":"He acted recklessly in the company and was eventually fired.","traditional":"他在公司裡胡作非為，最終被解僱了。"},{"simplified":"那些胡作非为的人迟早会受到法律的制裁。","english":"Those who act lawlessly will eventually face legal consequences.","traditional":"那些胡作非為的人遲早會受到法律的制裁。"}],"synonyms":["无法无天"],"antonyms":["循规蹈矩"],"confusedWith":[{"id":"胡闹","note":"胡闹 refers to making a fuss or causing trouble, often in a less serious or playful context, unlike the lawlessness implied by 胡作非为."}],"traditional":"胡作非為","pinyinOverride":null},{"id":"hua-yan-qiao-yu","simplified":"花言巧语","literalMeaning":"flowery words, skillful language","figurativeMeaning":"deceptive or insincere talk meant to persuade or flatter","englishEquivalents":["sweet talk","smooth talk","honeyed words"],"shortGloss":"deceptive or insincere talk","characters":[{"char":"花","meaning":"flowery, ornate"},{"char":"言","meaning":"words, speech"},{"char":"巧","meaning":"skillful, clever"},{"char":"语","meaning":"language, talk"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '花言巧语' is believed to have originated from the idea of using ornate and skillful language to deceive or flatter others. While the exact origin is unclear, it reflects the notion of using language not to convey truth, but to manipulate or persuade others with insincerity.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["attributive","adverbial"],"structure":"coordinate","register":"commonly used in both spoken and written Chinese, often with a negative connotation","connotation":"negative","commonMistakes":"Learners often confuse this idiom with positive expressions of eloquence. However, '花言巧语' specifically implies deceit or insincerity, unlike neutral or positive terms for skillful speaking.","canStandAlone":false},"examples":[{"simplified":"他总是用花言巧语来哄骗别人。","english":"He always uses sweet talk to deceive others.","traditional":"他總是用花言巧語來哄騙別人。"},{"simplified":"不要被他的花言巧语所迷惑。","english":"Don't be fooled by his smooth talk.","traditional":"不要被他的花言巧語所迷惑。"}],"synonyms":["甜言蜜语"],"antonyms":["实话实说"],"confusedWith":[{"id":"口若悬河","note":"While '口若悬河' describes fluent and eloquent speaking, it does not imply deceit or insincerity like '花言巧语' does."}],"traditional":"花言巧語","pinyinOverride":null},{"id":"hui-jin-ru-tu","simplified":"挥金如土","literalMeaning":"to scatter gold like dirt","figurativeMeaning":"to spend money lavishly or wastefully","englishEquivalents":["spend money like water","throw money around","money burns a hole in one's pocket"],"shortGloss":"spend money lavishly","characters":[{"char":"挥","meaning":"to scatter or throw"},{"char":"金","meaning":"gold, money"},{"char":"如","meaning":"like, as if"},{"char":"土","meaning":"dirt, soil"}],"origin":{"period":"Eastern Han Dynasty (25–220 CE)","sourceText":"《后汉书·杨震传》","sourceTextEnglish":"Book of the Later Han, Biography of Yang Zhen","originalExcerpt":"挥金如土，何患无财。","storyEnglish":"The idiom originates from the story of Yang Zhen, a virtuous official during the Eastern Han Dynasty, who was known for his integrity and refusal to accept bribes. The phrase '挥金如土' describes those who spend money as if it were worthless, contrasting with Yang Zhen's frugality and moral uprightness.","historicalFigures":["Yang Zhen"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"commonly used in both written and spoken Chinese to describe extravagant spending","connotation":"negative","commonMistakes":"Learners might confuse this idiom with similar expressions that describe wealth, but '挥金如土' specifically emphasizes wastefulness and extravagance, not just having money.","canStandAlone":false},"examples":[{"simplified":"他挥金如土，不久就破产了。","english":"He spent money like water and soon went bankrupt.","traditional":"他揮金如土，不久就破產了。"},{"simplified":"在奢侈品店里，她挥金如土，毫不犹豫。","english":"In the luxury store, she threw money around without hesitation.","traditional":"在奢侈品店裡，她揮金如土，毫不猶豫。"}],"synonyms":["一掷千金","大手大脚"],"antonyms":["精打细算","量入为出"],"confusedWith":[{"id":"一掷千金","note":"Both describe spending large amounts of money, but '一掷千金' can imply spending for a purpose or gamble, not necessarily wasteful."}],"traditional":"揮金如土","pinyinOverride":null},{"id":"hun-shui-mo-yu","simplified":"混水摸鱼","literalMeaning":"muddy waters catch fish","figurativeMeaning":"to take advantage of a confused situation to gain something","englishEquivalents":["fish in troubled waters","take advantage of chaos"],"shortGloss":"exploit chaos for gain","characters":[{"char":"混","meaning":"muddy"},{"char":"水","meaning":"water"},{"char":"摸","meaning":"catch"},{"char":"鱼","meaning":"fish"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '混水摸鱼' comes from the idea that when waters are muddy, fish are less likely to see predators, making them easier to catch. This metaphorically suggests that in a chaotic or unclear situation, it's easier to achieve one's goals or gain an advantage.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","object","adverbial"],"structure":"verb-object","register":"commonly used in both formal and informal contexts","connotation":"negative","commonMistakes":"Learners often confuse this idiom with similar expressions that simply describe chaos, but this idiom specifically implies taking advantage of that chaos for personal gain.","canStandAlone":false},"examples":[{"simplified":"在公司重组期间，他试图混水摸鱼，获得更多的权力。","english":"During the company's restructuring, he tried to fish in troubled waters to gain more power.","traditional":"在公司重組期間，他試圖混水摸魚，獲得更多的權力。"},{"simplified":"一些投机者在市场动荡时混水摸鱼，赚取了不少利润。","english":"Some speculators fished in troubled waters during the market turmoil and made significant profits.","traditional":"一些投機者在市場動盪時混水摸魚，賺取了不少利潤。"}],"synonyms":["趁火打劫"],"antonyms":["光明磊落"],"confusedWith":[{"id":"浑水摸鱼","note":"This is a common misspelling of 混水摸鱼, with the same pronunciation but a different first character."}],"traditional":"混水摸魚","pinyinOverride":null},{"id":"jia-gong-ji-si","simplified":"假公济私","literalMeaning":"use public resources for private gain","figurativeMeaning":"to abuse public office for personal gain","englishEquivalents":["feather one's own nest","abuse of power"],"shortGloss":"abuse public office for personal gain","characters":[{"char":"假","meaning":"to borrow or use"},{"char":"公","meaning":"public"},{"char":"济","meaning":"to aid or benefit"},{"char":"私","meaning":"private"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '假公济私' is used to describe situations where someone in a position of authority uses their public office or resources for personal benefit. While the exact origin of this idiom is unclear, it reflects a common theme in Chinese culture and literature where officials are expected to act with integrity and not exploit their positions for selfish purposes.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"commonly used in both formal and informal contexts to criticize unethical behavior","connotation":"negative","commonMistakes":"Learners often confuse this idiom with others that involve public and private matters, but '假公济私' specifically implies unethical behavior by someone in a position of power.","canStandAlone":false},"examples":[{"simplified":"他利用职权假公济私，被公司解雇了。","english":"He abused his position for personal gain and was fired by the company.","traditional":"他利用職權假公濟私，被公司解僱了。"},{"simplified":"政府官员必须避免假公济私，以维护公众信任。","english":"Government officials must avoid abusing their power for personal gain to maintain public trust.","traditional":"政府官員必須避免假公濟私，以維護公眾信任。"}],"synonyms":["以权谋私","中饱私囊"],"antonyms":[],"confusedWith":[{"id":"以权谋私","note":"Both involve abusing power, but '以权谋私' emphasizes using authority specifically, while '假公济私' can involve any public resource."}],"traditional":"假公濟私","pinyinOverride":null},{"id":"jian-yi-si-qian","simplified":"见异思迁","literalMeaning":"see something different, think of moving","figurativeMeaning":"to be fickle and change one's mind or loyalties easily","englishEquivalents":["fickle-minded","easily swayed"],"shortGloss":"fickle-minded","characters":[{"char":"见","meaning":"see"},{"char":"异","meaning":"different"},{"char":"思","meaning":"think"},{"char":"迁","meaning":"move"}],"origin":{"period":"Han Dynasty (206 BCE – 220 CE)","sourceText":"《汉书·王嘉传》","sourceTextEnglish":"Book of Han, Biography of Wang Jia","originalExcerpt":"见异而思迁，非忠也。","storyEnglish":"The idiom originates from the 'Book of Han', where it describes someone who, upon seeing something different or new, immediately thinks of changing their current situation or allegiance. This behavior was criticized as lacking loyalty and steadfastness.","historicalFigures":["Wang Jia"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"commonly used in both written and spoken Chinese to describe someone who is indecisive or easily swayed","connotation":"negative","commonMistakes":"Learners might confuse this idiom with others that describe change, but this specifically implies a lack of loyalty or consistency. It should not be used to describe positive adaptability.","canStandAlone":false},"examples":[{"simplified":"他总是见异思迁，很难依靠。","english":"He is always fickle-minded and hard to rely on.","traditional":"他總是見異思遷，很難依靠。"},{"simplified":"在工作中，见异思迁会让你失去信任。","english":"In the workplace, being fickle-minded can cause you to lose trust.","traditional":"在工作中，見異思遷會讓你失去信任。"}],"synonyms":["朝三暮四"],"antonyms":["始终如一"],"confusedWith":[{"id":"朝三暮四","note":"Both describe fickleness, but 朝三暮四 often implies being capricious or inconsistent in a more whimsical sense."}],"traditional":"見異思遷","pinyinOverride":null},{"id":"jie-zu-xian-deng","simplified":"捷足先登","literalMeaning":"quick feet first to climb","figurativeMeaning":"the early bird catches the worm; those who act quickly or arrive first have the advantage","englishEquivalents":["The early bird catches the worm","First come, first served"],"shortGloss":"the early bird catches the worm","characters":[{"char":"捷","meaning":"quick"},{"char":"足","meaning":"feet"},{"char":"先","meaning":"first"},{"char":"登","meaning":"to climb"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom suggests that those who are quick to act or arrive first will have the advantage. It is often used to encourage promptness and swift action, emphasizing the benefits of being proactive.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"subject-predicate","register":"commonly used in both spoken and written Chinese, suitable for informal and formal contexts","connotation":"positive","commonMistakes":"Learners sometimes confuse this idiom with others that emphasize speed without the aspect of gaining an advantage. It specifically implies not just being fast, but also being the first to achieve something.","canStandAlone":false},"examples":[{"simplified":"在抢购打折商品时，捷足先登的人总是能买到最好的。","english":"When it comes to grabbing discounted goods, those who act quickly always get the best deals.","traditional":"在搶購打折商品時，捷足先登的人總是能買到最好的。"},{"simplified":"如果你想得到这个职位，你必须捷足先登。","english":"If you want to get this position, you must act quickly.","traditional":"如果你想得到這個職位，你必須捷足先登。"}],"synonyms":["先发制人"],"antonyms":["后发制人"],"confusedWith":[{"id":"先发制人","note":"While both emphasize acting quickly, 先发制人 focuses more on taking initiative to control a situation rather than just being first."}],"traditional":"捷足先登","pinyinOverride":null},{"id":"jin-tui-liang-nan","simplified":"进退两难","literalMeaning":"advance or retreat both difficult","figurativeMeaning":"to be in a dilemma; to be in a difficult situation with no easy way out","englishEquivalents":["between a rock and a hard place","caught in a bind"],"shortGloss":"in a dilemma","characters":[{"char":"进","meaning":"advance"},{"char":"退","meaning":"retreat"},{"char":"两","meaning":"both"},{"char":"难","meaning":"difficult"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '进退两难' describes a situation where a person finds themselves in a predicament, unable to move forward or backward without encountering difficulties. The expression captures the essence of being caught between two equally challenging options, with no clear or easy solution in sight.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive","complement"],"structure":"coordinate","register":"commonly used in both formal and informal contexts","connotation":"negative","commonMistakes":"Learners often confuse this idiom with others that describe difficult situations, but '进退两难' specifically emphasizes the lack of a good option in either direction. It should not be used when there is a clear solution or choice.","canStandAlone":false},"examples":[{"simplified":"他现在进退两难，不知道该怎么办。","english":"He is now in a dilemma and doesn't know what to do.","traditional":"他現在進退兩難，不知道該怎麼辦。"},{"simplified":"面对这样的局面，她感到进退两难。","english":"Faced with such a situation, she felt caught between a rock and a hard place.","traditional":"面對這樣的局面，她感到進退兩難。"}],"synonyms":["左右为难"],"antonyms":[],"confusedWith":[{"id":"左右为难","note":"Both idioms describe a dilemma, but '左右为难' focuses on being unable to decide between two options, while '进退两难' emphasizes the difficulty of both advancing and retreating."}],"traditional":"進退兩難","pinyinOverride":null},{"id":"jin-tui-wei-gu","simplified":"进退维谷","literalMeaning":"advance or retreat, both are valleys","figurativeMeaning":"to be in a dilemma; to be in a difficult situation with no way out","englishEquivalents":["between a rock and a hard place","caught between the devil and the deep blue sea"],"shortGloss":"in a dilemma","characters":[{"char":"进","meaning":"advance"},{"char":"退","meaning":"retreat"},{"char":"维","meaning":"both"},{"char":"谷","meaning":"valley; difficult situation"}],"origin":{"period":"Warring States period (475–221 BCE)","sourceText":"《左传·僖公三十三年》","sourceTextEnglish":"Zuo Zhuan, Duke Xi, Year 33","originalExcerpt":"进退维谷，左右为难。","storyEnglish":"The idiom comes from the historical text 'Zuo Zhuan', where it describes a situation in which a person is caught in a difficult position, unable to advance or retreat without encountering difficulties. The phrase metaphorically describes being stuck in a valley, with no easy way out, symbolizing a dilemma.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"coordinate","register":"literary, but widely understood and used in both formal and informal contexts","connotation":"negative","commonMistakes":"Learners often confuse this idiom with '左右为难', which also means being in a dilemma but lacks the imagery of being trapped in a valley. '进退维谷' emphasizes the lack of options more vividly.","canStandAlone":false},"examples":[{"simplified":"他现在进退维谷，不知道该怎么办。","english":"He is now in a dilemma and doesn't know what to do.","traditional":"他現在進退維谷，不知道該怎麼辦。"},{"simplified":"面对这样的局面，我们感到进退维谷。","english":"Facing such a situation, we feel caught between a rock and a hard place.","traditional":"面對這樣的局面，我們感到進退維谷。"}],"synonyms":["左右为难"],"antonyms":[],"confusedWith":[{"id":"左右为难","note":"Both idioms describe a dilemma, but '进退维谷' emphasizes the imagery of being trapped with no way out."}],"traditional":"進退維谷","pinyinOverride":null},{"id":"jing-jing-you-tiao","simplified":"井井有条","literalMeaning":"well-organized with clear lines","figurativeMeaning":"in perfect order; methodical and orderly","englishEquivalents":["neat and tidy","shipshape","in apple-pie order"],"shortGloss":"methodical and orderly","characters":[{"char":"井","meaning":"well (as in a water well), orderly"},{"char":"井","meaning":"repetition for emphasis, orderly"},{"char":"有","meaning":"have, possess"},{"char":"条","meaning":"lines, order"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom 井井有条 is believed to have originated from the idea of a well-organized layout, similar to the orderly arrangement of wells or fields. It emphasizes the importance of having a clear structure and organization, whether in physical spaces or in plans and thoughts.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"modifier-head","register":"commonly used in both written and spoken Chinese","connotation":"positive","commonMistakes":"Learners might confuse this idiom with others that imply neatness but lack the emphasis on systematic order. It specifically refers to a well-organized and methodical arrangement, not just cleanliness.","canStandAlone":false},"examples":[{"simplified":"她的办公室总是井井有条，令人印象深刻。","english":"Her office is always in perfect order, which is impressive.","traditional":"她的辦公室總是井井有條，令人印象深刻。"},{"simplified":"他把所有的文件整理得井井有条。","english":"He organized all the documents in perfect order.","traditional":"他把所有的文件整理得井井有條。"}],"synonyms":["有条不紊","秩序井然"],"antonyms":["杂乱无章"],"confusedWith":[{"id":"杂乱无章","note":"井井有条 means orderly and methodical, while 杂乱无章 means messy and disorganized."}],"traditional":"井井有條","pinyinOverride":null},{"id":"ju-gong-jin-cui","simplified":"鞠躬尽瘁","literalMeaning":"bow down and exhaust one's energies","figurativeMeaning":"to dedicate oneself wholeheartedly to a cause or duty","englishEquivalents":["to give one's all","to work tirelessly"],"shortGloss":"dedicate oneself wholeheartedly","characters":[{"char":"鞠","meaning":"to bow"},{"char":"躬","meaning":"body"},{"char":"尽","meaning":"exhaust"},{"char":"瘁","meaning":"fatigue"}],"origin":{"period":"Three Kingdoms period (220–280 CE)","sourceText":"《三国志·蜀书·诸葛亮传》","sourceTextEnglish":"Records of the Three Kingdoms, Shu Book, Biography of Zhuge Liang","originalExcerpt":"鞠躬尽瘁，死而后已。","storyEnglish":"This idiom comes from a statement made by Zhuge Liang, a famous strategist and statesman during the Three Kingdoms period. He expressed his dedication to serving his country by saying he would bow down and exhaust all his energies, continuing to work tirelessly until his death.","historicalFigures":["Zhuge Liang"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"coordinate","register":"literary, but very widely understood and used in ordinary speech","connotation":"positive","commonMistakes":"Learners sometimes confuse this idiom with similar expressions of dedication, but it specifically implies a deep, self-sacrificing commitment. It is not used for casual or minor efforts.","canStandAlone":false},"examples":[{"simplified":"他为公司的发展鞠躬尽瘁，令人敬佩。","english":"He dedicated himself wholeheartedly to the company's development, earning admiration.","traditional":"他為公司的發展鞠躬盡瘁，令人敬佩。"},{"simplified":"她在教育事业上鞠躬尽瘁，直到退休。","english":"She devoted herself tirelessly to the field of education until her retirement.","traditional":"她在教育事業上鞠躬盡瘁，直到退休。"}],"synonyms":["全心全意","尽心尽力"],"antonyms":[],"confusedWith":[{"id":"全心全意","note":"While both imply dedication, 鞠躬尽瘁 suggests a more self-sacrificing effort."}],"traditional":"鞠躬盡瘁","pinyinOverride":null},{"id":"kai-men-jian-shan","simplified":"开门见山","literalMeaning":"open the door and see the mountain","figurativeMeaning":"to get straight to the point; to speak directly","englishEquivalents":["cut to the chase","get to the point"],"shortGloss":"get straight to the point","characters":[{"char":"开","meaning":"open"},{"char":"门","meaning":"door"},{"char":"见","meaning":"see"},{"char":"山","meaning":"mountain"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '开门见山' is believed to have originated from the idea of opening a door and immediately seeing a mountain, symbolizing directness and straightforwardness. It suggests that one should get straight to the main point without unnecessary preamble.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["adverbial","attributive"],"structure":"verb-object","register":"commonly used in both formal and informal contexts","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with expressions that imply abruptness or rudeness, but '开门见山' simply emphasizes clarity and directness without negative connotations.","canStandAlone":false},"examples":[{"simplified":"我们开门见山，直接讨论问题的核心。","english":"Let's get straight to the point and discuss the core of the issue.","traditional":"我們開門見山，直接討論問題的核心。"},{"simplified":"他开门见山地提出了他的建议。","english":"He straightforwardly presented his suggestion.","traditional":"他開門見山地提出了他的建議。"}],"synonyms":["直截了当"],"antonyms":["拐弯抹角"],"confusedWith":[{"id":"直言不讳","note":"While both idioms imply directness, '直言不讳' emphasizes speaking frankly without holding back, which can sometimes be blunt."}],"traditional":"開門見山","pinyinOverride":null},{"id":"kai-yuan-jie-liu","simplified":"开源节流","literalMeaning":"open source, restrict flow","figurativeMeaning":"to increase income and reduce expenditure; to maximize income and minimize spending","englishEquivalents":["cut costs and increase revenue","tighten the belt"],"shortGloss":"increase income, reduce expenses","characters":[{"char":"开","meaning":"open"},{"char":"源","meaning":"source"},{"char":"节","meaning":"restrict"},{"char":"流","meaning":"flow"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '开源节流' is commonly used in modern Chinese to describe the strategy of increasing income while reducing expenses. It is often used in business and financial contexts to emphasize the importance of both generating more revenue and controlling costs effectively.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","object","adverbial"],"structure":"coordinate","register":"widely used in both formal and informal contexts, especially in business and finance","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with others that focus solely on cost-cutting, but '开源节流' emphasizes both increasing income and reducing expenses. It should not be used when only one aspect is being addressed.","canStandAlone":false},"examples":[{"simplified":"公司为了度过经济危机，必须开源节流。","english":"To survive the economic crisis, the company must increase income and reduce expenses.","traditional":"公司為了度過經濟危機，必須開源節流。"},{"simplified":"在家庭理财中，开源节流是非常重要的策略。","english":"In household financial management, increasing income and reducing expenses is a very important strategy.","traditional":"在家庭理財中，開源節流是非常重要的策略。"}],"synonyms":["增收节支"],"antonyms":[],"confusedWith":[{"id":"节衣缩食","note":"While '节衣缩食' focuses on frugality and reducing consumption, '开源节流' includes both increasing income and reducing expenses."}],"traditional":"開源節流","pinyinOverride":null},{"id":"kang-kai-jie-nang","simplified":"慷慨解囊","literalMeaning":"generous open purse","figurativeMeaning":"to give generously or to help financially without hesitation","englishEquivalents":["open one's wallet","give generously","be generous with money"],"shortGloss":"give generously","characters":[{"char":"慷","meaning":"generous"},{"char":"慨","meaning":"generous; magnanimous"},{"char":"解","meaning":"open; untie"},{"char":"囊","meaning":"purse; bag"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '慷慨解囊' is believed to have originated from stories of individuals who were willing to help others by giving money or resources without hesitation. The phrase paints a vivid picture of someone opening their purse or bag to offer help, symbolizing generosity and willingness to assist those in need.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"widely used in both formal and informal contexts","connotation":"positive","commonMistakes":"Learners might confuse this idiom with phrases that mean simply spending money, but '慷慨解囊' specifically implies generosity and willingness to help others financially.","canStandAlone":false},"examples":[{"simplified":"在慈善活动中，他总是慷慨解囊。","english":"At charity events, he always gives generously.","traditional":"在慈善活動中，他總是慷慨解囊。"},{"simplified":"看到朋友有困难，她毫不犹豫地慷慨解囊。","english":"Seeing her friend in trouble, she didn't hesitate to give generously.","traditional":"看到朋友有困難，她毫不猶豫地慷慨解囊。"}],"synonyms":["大方捐赠","乐善好施"],"antonyms":["吝啬鬼","斤斤计较"],"confusedWith":[{"id":"挥金如土","note":"While both involve spending money, '挥金如土' means to spend money extravagantly without concern, not necessarily for generosity."}],"traditional":"慷慨解囊","pinyinOverride":null},{"id":"ke-ku-nai-lao","simplified":"刻苦耐劳","literalMeaning":"endure hardship and tolerate toil","figurativeMeaning":"hardworking and able to endure hardships","englishEquivalents":["hardworking and diligent","industrious"],"shortGloss":"hardworking and diligent","characters":[{"char":"刻","meaning":"endure"},{"char":"苦","meaning":"hardship"},{"char":"耐","meaning":"tolerate"},{"char":"劳","meaning":"toil"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '刻苦耐劳' is used to describe someone who is very hardworking and can endure hardships without complaint. It emphasizes the virtues of diligence and perseverance, often praised in various cultural contexts. The exact origin of this idiom is not traceable to a specific classical text, but it has been widely used in Chinese literature and speech to commend individuals who demonstrate these qualities.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"coordinate","register":"commonly used in both formal and informal contexts to praise someone's work ethic","connotation":"positive","commonMistakes":"Learners might confuse this idiom with others that emphasize different aspects of diligence, such as '勤奋' (diligent) which does not necessarily imply enduring hardship. '刻苦耐劳' specifically highlights the ability to withstand tough conditions.","canStandAlone":false},"examples":[{"simplified":"他是一个刻苦耐劳的员工，总是超额完成任务。","english":"He is a hardworking and diligent employee who always exceeds his tasks.","traditional":"他是一個刻苦耐勞的員工，總是超額完成任務。"},{"simplified":"在艰难的环境中，刻苦耐劳是成功的关键。","english":"In difficult environments, being hardworking and able to endure hardships is the key to success.","traditional":"在艱難的環境中，刻苦耐勞是成功的關鍵。"}],"synonyms":["勤奋努力","吃苦耐劳"],"antonyms":["好逸恶劳"],"confusedWith":[{"id":"勤奋","note":"While both emphasize diligence, '勤奋' does not necessarily imply enduring hardship, whereas '刻苦耐劳' does."}],"traditional":"刻苦耐勞","pinyinOverride":null},{"id":"kou-shi-xin-fei","simplified":"口是心非","literalMeaning":"mouth says yes, heart says no","figurativeMeaning":"to say one thing but mean another; to be insincere","englishEquivalents":["speak with a forked tongue","double-tongued"],"shortGloss":"insincere; say one thing, mean another","characters":[{"char":"口","meaning":"mouth"},{"char":"是","meaning":"is; yes"},{"char":"心","meaning":"heart"},{"char":"非","meaning":"not; no"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '口是心非' describes a situation where a person's words do not match their true feelings or intentions. It is often used to highlight insincerity or hypocrisy, where someone may verbally agree or express support but internally disagree or harbor different intentions.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"modifier-head","register":"commonly used in both spoken and written Chinese","connotation":"negative","commonMistakes":"Learners often confuse this idiom with others that involve deception, but '口是心非' specifically emphasizes the discrepancy between words and true feelings, not necessarily deceitful actions.","canStandAlone":false},"examples":[{"simplified":"他总是口是心非，让人很难信任他。","english":"He always says one thing but means another, making it hard for people to trust him.","traditional":"他總是口是心非，讓人很難信任他。"},{"simplified":"在这种情况下，口是心非只会让问题变得更复杂。","english":"In this situation, being insincere will only complicate matters further.","traditional":"在這種情況下，口是心非只會讓問題變得更復雜。"}],"synonyms":["言不由衷"],"antonyms":["表里如一"],"confusedWith":[{"id":"言行不一","note":"While both idioms involve inconsistency, '言行不一' focuses on the inconsistency between words and actions, whereas '口是心非' emphasizes the inconsistency between words and true feelings."}],"traditional":"口是心非","pinyinOverride":null},{"id":"ku-kou-po-xin","simplified":"苦口婆心","literalMeaning":"bitter mouth, motherly heart","figurativeMeaning":"to advise someone earnestly and with good intentions, often despite their reluctance to listen","englishEquivalents":["speak with heartfelt sincerity","give earnest advice"],"shortGloss":"earnest and sincere advice","characters":[{"char":"苦","meaning":"bitter, implying difficulty or unpleasantness"},{"char":"口","meaning":"mouth, referring to speech or words"},{"char":"婆","meaning":"motherly, indicating a caring or nurturing approach"},{"char":"心","meaning":"heart, representing sincerity and good intentions"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '苦口婆心' is often used to describe someone who offers advice or criticism with the best intentions, even if the recipient may not want to hear it. The 'bitter mouth' suggests that the advice might be hard to swallow, while the 'motherly heart' indicates that it is given out of care and concern, much like a mother would advise her child.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["adverbial","attributive"],"structure":"modifier-head","register":"commonly used in both spoken and written Chinese, often in contexts involving advice or persuasion","connotation":"positive","commonMistakes":"Learners might confuse this idiom with others that involve persuasion or advice but lack the connotation of sincere care. It's important to remember that '苦口婆心' implies a nurturing intention, not just any form of advice.","canStandAlone":false},"examples":[{"simplified":"他苦口婆心地劝说朋友不要放弃学业。","english":"He earnestly advised his friend not to give up on his studies.","traditional":"他苦口婆心地勸說朋友不要放棄學業。"},{"simplified":"父母总是苦口婆心地提醒我们注意身体健康。","english":"Parents always remind us to take care of our health with heartfelt sincerity.","traditional":"父母總是苦口婆心地提醒我們注意身體健康。"}],"synonyms":["语重心长","循循善诱"],"antonyms":[],"confusedWith":[{"id":"语重心长","note":"Both idioms involve giving advice, but '语重心长' emphasizes the weight and depth of the words, while '苦口婆心' emphasizes the caring intention."}],"traditional":"苦口婆心","pinyinOverride":null},{"id":"kuai-zhi-ren-kou","simplified":"脍炙人口","literalMeaning":"delicacies praised by everyone","figurativeMeaning":"something universally praised or appreciated","englishEquivalents":["widely acclaimed","universally praised","popular"],"shortGloss":"universally praised","characters":[{"char":"脍","meaning":"minced fish or meat"},{"char":"炙","meaning":"roasted meat"},{"char":"人","meaning":"people"},{"char":"口","meaning":"mouth"}],"origin":{"period":"Tang dynasty (618–907 CE)","sourceText":"《新唐书·魏征传》","sourceTextEnglish":"New Book of Tang, Biography of Wei Zheng","originalExcerpt":"脍炙人口，百姓皆知。","storyEnglish":"The idiom originates from the Tang dynasty, where it was used to describe the works of a poet whose verses were so well-crafted that they were as enjoyable as the finest delicacies, and everyone praised them. The phrase captures the idea of something being so excellent that it becomes widely appreciated and talked about by all.","historicalFigures":["Wei Zheng"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"subject-predicate","register":"literary, but commonly used in both written and spoken Chinese","connotation":"positive","commonMistakes":"Learners might confuse this idiom with phrases that only mean 'popular' without the connotation of high quality. It specifically implies something is praised for its excellence, not just widely known.","canStandAlone":false},"examples":[{"simplified":"这部电影真是脍炙人口，观众们都赞不绝口。","english":"This movie is truly widely acclaimed; the audience can't stop praising it.","traditional":"這部電影真是膾炙人口，觀眾們都讚不絕口。"},{"simplified":"他的作品脍炙人口，许多人都在传颂。","english":"His works are universally praised, and many people are spreading them.","traditional":"他的作品膾炙人口，許多人都在傳頌。"}],"synonyms":["家喻户晓","有口皆碑"],"antonyms":[],"confusedWith":[{"id":"家喻户晓","note":"While both mean something is well-known, 脍炙人口 emphasizes praise and acclaim, whereas 家喻户晓 simply means widely known."}],"traditional":"膾炙人口","pinyinOverride":null},{"id":"lan-yu-chong-shu","simplified":"滥竽充数","literalMeaning":"play the yu to make up the numbers","figurativeMeaning":"to pretend to be competent or to fill a position without the necessary skills","englishEquivalents":["to pad the numbers","to bluff one's way through","to make up the numbers"],"shortGloss":"pretend to be competent","characters":[{"char":"滥","meaning":"carelessly; indiscriminately"},{"char":"竽","meaning":"a traditional wind instrument"},{"char":"充","meaning":"to fill; to make up"},{"char":"数","meaning":"number; count"}],"origin":{"period":"Warring States period (475–221 BCE)","sourceText":"《韩非子·内储说上》","sourceTextEnglish":"Han Feizi, Inner Chapters, Part 1","originalExcerpt":"南郭处士请为王吹竽，王许之。充数而已。","storyEnglish":"In the state of Qi during the Warring States period, there was a king who enjoyed listening to an ensemble of musicians playing the yu, a traditional wind instrument. A man named Nanguo, who could not actually play the instrument, joined the ensemble and pretended to play, simply moving his fingers without producing any sound. He managed to deceive the king and others by blending in with the group. However, when a new king ascended the throne and wanted to hear solo performances, Nanguo's lack of skill was exposed, and he had to flee.","historicalFigures":["Nanguo"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"commonly used in both spoken and written Chinese","connotation":"negative","commonMistakes":"Learners often confuse this idiom with others that involve deception, but it specifically implies incompetence hidden within a group. It is not used for individual deceit without a group context.","canStandAlone":false},"examples":[{"simplified":"他不会游泳，却在游泳队里滥竽充数。","english":"He can't swim, yet he's in the swim team just to make up the numbers.","traditional":"他不會游泳，卻在游泳隊裡濫竽充數。"},{"simplified":"如果你不想滥竽充数，就得努力提高自己的技能。","english":"If you don't want to just make up the numbers, you need to work hard to improve your skills.","traditional":"如果你不想濫竽充數，就得努力提高自己的技能。"}],"synonyms":["鱼目混珠"],"antonyms":["名副其实"],"confusedWith":[{"id":"鱼目混珠","note":"While both involve deception, 鱼目混珠 refers to passing off something fake as genuine, not necessarily incompetence within a group."}],"traditional":"濫竽充數","pinyinOverride":null},{"id":"li-jing-tu-zhi","simplified":"励精图治","literalMeaning":"exert energy to plan governance","figurativeMeaning":"to spare no effort in governing a country; to work hard for the prosperity of a nation","englishEquivalents":["spare no effort","work tirelessly","dedicate oneself to governance"],"shortGloss":"work tirelessly for good governance","characters":[{"char":"励","meaning":"exert"},{"char":"精","meaning":"energy"},{"char":"图","meaning":"plan"},{"char":"治","meaning":"governance"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '励精图治' is often used to describe a ruler or leader who dedicates themselves fully to the task of governing and improving their country. It emphasizes the idea of putting in great effort and careful planning to achieve effective governance and prosperity.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"formal written Chinese, often used in political contexts","connotation":"positive","commonMistakes":"Learners might confuse this idiom with those that imply mere diligence in personal tasks, rather than the broader context of governance and leadership. It specifically refers to efforts in ruling or managing a state or organization.","canStandAlone":false},"examples":[{"simplified":"作为国家领导人，他励精图治，取得了显著的成就。","english":"As the leader of the country, he worked tirelessly for its governance and achieved remarkable success.","traditional":"作為國家領導人，他勵精圖治，取得了顯著的成就。"},{"simplified":"在他的励精图治下，公司逐渐走出了困境。","english":"Under his dedicated leadership, the company gradually emerged from its difficulties.","traditional":"在他的勵精圖治下，公司逐漸走出了困境。"}],"synonyms":["鞠躬尽瘁"],"antonyms":[],"confusedWith":[{"id":"兢兢业业","note":"兢兢业业 refers to being diligent and conscientious in one's work, but not specifically related to governance or leadership."}],"traditional":"勵精圖治","pinyinOverride":null},{"id":"liao-ru-zhi-zhang","simplified":"了如指掌","literalMeaning":"as clear as pointing to one's palm","figurativeMeaning":"to know something like the back of one's hand; to be thoroughly familiar with something","englishEquivalents":["know like the back of one's hand","be thoroughly familiar with","have down pat"],"shortGloss":"thoroughly familiar","characters":[{"char":"了","meaning":"understand"},{"char":"如","meaning":"like; as if"},{"char":"指","meaning":"finger"},{"char":"掌","meaning":"palm"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom 了如指掌 is used to describe a situation where someone is extremely familiar with something, as if they can see it as clearly as they can see the palm of their hand. The origin of this idiom is not tied to a specific historical text, but it has been used in Chinese literature and speech for centuries to convey the idea of deep familiarity and understanding.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"modifier-head","register":"widely used in both spoken and written Chinese","connotation":"positive","commonMistakes":"Learners often confuse this idiom with similar expressions of familiarity, but it specifically conveys a deep and thorough understanding. It should not be used for superficial or cursory knowledge.","canStandAlone":false},"examples":[{"simplified":"他对这座城市的地形了如指掌。","english":"He knows the layout of this city like the back of his hand.","traditional":"他對這座城市的地形瞭如指掌。"},{"simplified":"经过多年的研究，她对这个课题了如指掌。","english":"After years of research, she is thoroughly familiar with this subject.","traditional":"經過多年的研究，她對這個課題了如指掌。"}],"synonyms":["熟能生巧","驾轻就熟"],"antonyms":["一窍不通"],"confusedWith":[{"id":"胸有成竹","note":"While both idioms imply confidence, 胸有成竹 suggests having a well-thought-out plan, whereas 了如指掌 emphasizes thorough familiarity."}],"traditional":"瞭如指掌","pinyinOverride":null},{"id":"liu-li-shi-suo","simplified":"流离失所","literalMeaning":"wander and lose one's place","figurativeMeaning":"to be displaced and homeless","englishEquivalents":["uprooted and homeless","displaced","without a fixed abode"],"shortGloss":"displaced and homeless","characters":[{"char":"流","meaning":"to flow; to wander"},{"char":"离","meaning":"to leave; to part"},{"char":"失","meaning":"to lose"},{"char":"所","meaning":"place"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '流离失所' describes the plight of people who have been forced to leave their homes due to war, natural disasters, or other crises, leaving them without a stable place to live. It evokes the image of people wandering aimlessly, having lost their homes and sense of belonging.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"coordinate","register":"commonly used in both written and spoken Chinese, especially in news and formal contexts","connotation":"negative","commonMistakes":"Learners might confuse this idiom with similar expressions that describe being lost or confused, but '流离失所' specifically refers to the physical displacement and loss of home.","canStandAlone":false},"examples":[{"simplified":"战争使许多家庭流离失所。","english":"The war caused many families to be displaced and homeless.","traditional":"戰爭使許多家庭流離失所。"},{"simplified":"在地震后，成千上万的人流离失所。","english":"After the earthquake, thousands of people were left displaced and homeless.","traditional":"在地震後，成千上萬的人流離失所。"}],"synonyms":["颠沛流离"],"antonyms":["安居乐业"],"confusedWith":[{"id":"迷失方向","note":"迷失方向 refers to being lost or lacking direction, not physical displacement."}],"traditional":"流離失所","pinyinOverride":null},{"id":"lu-bu-shi-yi","simplified":"路不拾遗","literalMeaning":"the road does not pick up lost items","figurativeMeaning":"a society where people are honest and do not take things that do not belong to them","englishEquivalents":["honesty prevails","a society of integrity"],"shortGloss":"a society of honesty and integrity","characters":[{"char":"路","meaning":"road"},{"char":"不","meaning":"not"},{"char":"拾","meaning":"pick up"},{"char":"遗","meaning":"lost items"}],"origin":{"period":"Warring States period (475–221 BCE)","sourceText":"《韩非子·外储说左上》","sourceTextEnglish":"Han Feizi, Outer Storage, Left Upper","originalExcerpt":"国无盗贼，道不拾遗，民不妄取。","storyEnglish":"The idiom comes from a description in the 'Han Feizi', a work by the philosopher Han Fei. It describes an ideal society where people are so honest that even if items are lost on the road, no one picks them up because they do not belong to them. This reflects a high level of moral integrity and social order.","historicalFigures":["Han Fei"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"subject-predicate","register":"literary, but can be used in formal speech to describe a highly moral society","connotation":"positive","commonMistakes":"Learners might confuse this idiom with expressions about cleanliness or tidiness, but it specifically refers to honesty and integrity in society.","canStandAlone":false},"examples":[{"simplified":"在那个村子里，路不拾遗，人人都很诚实。","english":"In that village, honesty prevails, and everyone is very trustworthy.","traditional":"在那個村子裡，路不拾遺，人人都很誠實。"},{"simplified":"古代的理想社会是路不拾遗，夜不闭户。","english":"The ideal society in ancient times was one where honesty prevailed and doors did not need to be locked at night.","traditional":"古代的理想社會是路不拾遺，夜不閉戶。"}],"synonyms":["夜不闭户"],"antonyms":[],"confusedWith":[],"traditional":"路不拾遺","pinyinOverride":null},{"id":"luo-hua-liu-shui","simplified":"落花流水","literalMeaning":"fallen flowers and flowing water","figurativeMeaning":"a scene of desolation; to be utterly defeated","englishEquivalents":["a crushing defeat","in shambles"],"shortGloss":"a scene of desolation or defeat","characters":[{"char":"落","meaning":"fallen"},{"char":"花","meaning":"flowers"},{"char":"流","meaning":"flowing"},{"char":"水","meaning":"water"}],"origin":{"period":"Tang Dynasty (618–907 CE)","sourceText":"《全唐诗》","sourceTextEnglish":"Complete Tang Poems","originalExcerpt":"落花流水春去也，天上人间。","storyEnglish":"The idiom '落花流水' originates from a poem by the Tang Dynasty poet Liu Yuxi. In the poem, the imagery of fallen flowers and flowing water is used to depict the passing of spring and the inevitable changes in life. Over time, this imagery came to symbolize defeat and desolation, as the beauty of spring fades away, leaving behind a scene of emptiness.","historicalFigures":["Liu Yuxi"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"coordinate","register":"literary, but understood in modern contexts to describe defeat or desolation","connotation":"negative","commonMistakes":"Learners often confuse this idiom with others that involve nature imagery, but '落花流水' specifically conveys a sense of loss or defeat, not just any natural scene.","canStandAlone":false},"examples":[{"simplified":"比赛结束后，他们的球队落花流水，毫无还手之力。","english":"After the match ended, their team was utterly defeated, with no power to fight back.","traditional":"比賽結束後，他們的球隊落花流水，毫無還手之力。"},{"simplified":"看到公司破产，他感到一片落花流水，心情沉重。","english":"Seeing the company go bankrupt, he felt a scene of desolation and was deeply saddened.","traditional":"看到公司破產，他感到一片落花流水，心情沉重。"}],"synonyms":["一败涂地"],"antonyms":["旗开得胜"],"confusedWith":[{"id":"花好月圆","note":"While '落花流水' conveys defeat or desolation, '花好月圆' describes a scene of beauty and harmony."}],"traditional":"落花流水","pinyinOverride":null},{"id":"man-zai-er-gui","simplified":"满载而归","literalMeaning":"return with a full load","figurativeMeaning":"to return home with abundant rewards or great success","englishEquivalents":["come back loaded","return with the spoils","bring home the bacon"],"shortGloss":"return with great success","characters":[{"char":"满","meaning":"full"},{"char":"载","meaning":"load"},{"char":"而","meaning":"and"},{"char":"归","meaning":"return"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom 满载而归 is used to describe someone who returns home with a great deal of success or with many rewards. It evokes the image of a person or a group who has gone out on a journey or venture and comes back with a full load of goods or achievements, signifying a fruitful and prosperous endeavor.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","complement"],"structure":"verb-object","register":"common in both spoken and written Chinese, suitable for both formal and informal contexts","connotation":"positive","commonMistakes":"Learners might confuse 满载而归 with idioms that imply a return with mixed or negative results. It's important to remember that this idiom specifically conveys a positive outcome.","canStandAlone":false},"examples":[{"simplified":"经过一整天的努力，他们终于满载而归。","english":"After a whole day of effort, they finally returned with great success.","traditional":"經過一整天的努力，他們終於滿載而歸。"},{"simplified":"他去参加比赛，结果满载而归，赢得了许多奖项。","english":"He went to the competition and returned with many awards, achieving great success.","traditional":"他去參加比賽，結果滿載而歸，贏得了許多獎項。"}],"synonyms":["凯旋而归"],"antonyms":["一无所获"],"confusedWith":[{"id":"一无所获","note":"满载而归 means returning with success, while 一无所获 means returning empty-handed."}],"traditional":"滿載而歸","pinyinOverride":null},{"id":"man-tiao-si-li","simplified":"慢条斯理","literalMeaning":"slow strips this reason","figurativeMeaning":"to do something slowly and methodically; unhurriedly","englishEquivalents":["slow and steady","unhurriedly","methodically"],"shortGloss":"slow and methodical","characters":[{"char":"慢","meaning":"slow"},{"char":"条","meaning":"strips; clauses"},{"char":"斯","meaning":"this"},{"char":"理","meaning":"reason; logic"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom 慢条斯理 is believed to have originated from the idea of doing things in a slow and orderly manner. It reflects a calm and deliberate approach to tasks, emphasizing the importance of taking one's time to ensure thoroughness and accuracy.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["adverbial","attributive"],"structure":"modifier-head","register":"commonly used in both spoken and written Chinese to describe a leisurely, unhurried approach","connotation":"neutral","commonMistakes":"Learners might mistakenly use this idiom to describe laziness or procrastination, but it actually implies a deliberate and careful pace rather than a lack of motivation.","canStandAlone":false},"examples":[{"simplified":"他慢条斯理地喝着茶，似乎一点也不着急。","english":"He drank his tea slowly and methodically, seemingly not in a hurry at all.","traditional":"他慢條斯理地喝著茶，似乎一點也不著急。"},{"simplified":"她总是慢条斯理地整理文件，确保没有任何错误。","english":"She always organizes the files methodically, ensuring there are no mistakes.","traditional":"她總是慢條斯理地整理文件，確保沒有任何錯誤。"}],"synonyms":["不慌不忙"],"antonyms":["急功近利"],"confusedWith":[{"id":"拖拖拉拉","note":"拖拖拉拉 implies procrastination or dawdling, while 慢条斯理 suggests a deliberate and careful pace."}],"traditional":"慢條斯理","pinyinOverride":null},{"id":"mao-sui-zi-jian","simplified":"毛遂自荐","literalMeaning":"Mao Sui self-recommend","figurativeMeaning":"to volunteer oneself for a task or position","englishEquivalents":["put oneself forward","self-recommendation"],"shortGloss":"volunteer oneself","characters":[{"char":"毛","meaning":"Mao (a personal name)"},{"char":"遂","meaning":"Sui (a personal name)"},{"char":"自","meaning":"self"},{"char":"荐","meaning":"recommend"}],"origin":{"period":"Warring States period (475–221 BCE)","sourceText":"《史记·平原君虞卿列传》","sourceTextEnglish":"Records of the Grand Historian, Biography of Lord Pingyuan and Yu Qing","originalExcerpt":"毛遂自荐，曰：“臣乃今日请行。”","storyEnglish":"During the Warring States period, Mao Sui was a retainer of Lord Pingyuan. When Lord Pingyuan was seeking someone to persuade the state of Zhao to form an alliance, Mao Sui volunteered himself, saying, 'I will go today.' Despite being relatively unknown, his self-recommendation led to success, and he became famous for his boldness and capability.","historicalFigures":["Mao Sui","Lord Pingyuan"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["subject","predicate","object"],"structure":"verb-object","register":"widely used in both formal and informal contexts","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with phrases that imply arrogance. However, 毛遂自荐 emphasizes the act of volunteering oneself, often in a positive or neutral context.","canStandAlone":false},"examples":[{"simplified":"在会议上，他毛遂自荐，愿意负责这个项目。","english":"In the meeting, he volunteered himself to take charge of the project.","traditional":"在會議上，他毛遂自薦，願意負責這個項目。"},{"simplified":"她毛遂自荐参加比赛，展示了她的勇气。","english":"She put herself forward to participate in the competition, showing her courage.","traditional":"她毛遂自薦參加比賽，展示了她的勇氣。"}],"synonyms":[],"antonyms":[],"confusedWith":[],"traditional":"毛遂自薦","pinyinOverride":null},{"id":"mei-kuang-yu-xia","simplified":"每况愈下","literalMeaning":"each situation gets worse","figurativeMeaning":"to steadily deteriorate or worsen over time","englishEquivalents":["go from bad to worse","deteriorate","decline steadily"],"shortGloss":"steadily worsen","characters":[{"char":"每","meaning":"each; every"},{"char":"况","meaning":"situation; condition"},{"char":"愈","meaning":"more; increasingly"},{"char":"下","meaning":"down; worse"}],"origin":{"period":"Eastern Jin dynasty (317–420)","sourceText":"《世说新语·言语》","sourceTextEnglish":"A New Account of the Tales of the World, Language section","originalExcerpt":"王子敬在荆州，作书与谢安曰：“每况愈下。”","storyEnglish":"The idiom originates from a letter written by Wang Xizhi, a famous calligrapher, to Xie An, a prominent statesman. In the letter, Wang Xizhi lamented that the situation was deteriorating with each passing day. The phrase '每况愈下' was used to express this ongoing decline.","historicalFigures":["Wang Xizhi","Xie An"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"subject-predicate","register":"widely used in both formal and informal contexts","connotation":"negative","commonMistakes":"Learners often confuse this idiom with '每况愈好', which does not exist. The idiom specifically refers to worsening conditions, not improvement.","canStandAlone":false},"examples":[{"simplified":"公司的业绩每况愈下，老板非常担心。","english":"The company's performance is steadily worsening, and the boss is very worried.","traditional":"公司的業績每況愈下，老闆非常擔心。"},{"simplified":"他的健康状况每况愈下，需要尽快治疗。","english":"His health is deteriorating steadily and needs prompt treatment.","traditional":"他的健康狀況每況愈下，需要儘快治療。"}],"synonyms":["江河日下"],"antonyms":["蒸蒸日上"],"confusedWith":[],"traditional":"每況愈下","pinyinOverride":null},{"id":"mei-xia-yu-kuang","simplified":"每下愈况","literalMeaning":"each descent worsens the situation","figurativeMeaning":"things are getting progressively worse","englishEquivalents":["going from bad to worse","downhill all the way"],"shortGloss":"going from bad to worse","characters":[{"char":"每","meaning":"each"},{"char":"下","meaning":"downward"},{"char":"愈","meaning":"increasingly"},{"char":"况","meaning":"situation"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '每下愈况' is used to describe a situation that is deteriorating progressively. It suggests that with each step or action, the condition becomes worse. The phrase is often used to express frustration or concern about a situation that seems to be spiraling out of control.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"subject-predicate","register":"commonly used in both spoken and written Chinese","connotation":"negative","commonMistakes":"Learners might confuse this idiom with phrases that imply improvement or positive change. It's important to remember that this idiom specifically conveys a negative progression.","canStandAlone":false},"examples":[{"simplified":"公司的财务状况每下愈况，必须采取措施改善。","english":"The company's financial situation is going from bad to worse, and measures must be taken to improve it.","traditional":"公司的財務狀況每下愈況，必須採取措施改善。"},{"simplified":"如果不尽快解决问题，情况只会每下愈况。","english":"If the problem is not resolved quickly, the situation will only get worse.","traditional":"如果不盡快解決問題，情況只會每下愈況。"}],"synonyms":["江河日下"],"antonyms":["蒸蒸日上"],"confusedWith":[{"id":"蒸蒸日上","note":"蒸蒸日上 means 'flourishing' or 'improving day by day', which is the opposite of 每下愈况."}],"traditional":"每下愈況","pinyinOverride":null},{"id":"ming-mu-zhang-dan","simplified":"明目张胆","literalMeaning":"bright eyes, bold gallbladder","figurativeMeaning":"to do something openly and without fear; brazenly","englishEquivalents":["brazenly","openly and boldly"],"shortGloss":"brazenly, openly","characters":[{"char":"明","meaning":"bright"},{"char":"目","meaning":"eyes"},{"char":"张","meaning":"to open"},{"char":"胆","meaning":"gallbladder; courage"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '明目张胆' is believed to have originated from a folk saying. It combines the idea of having 'bright eyes' to see clearly and 'bold gallbladder' to act without fear. This phrase is used to describe someone who does something openly and without any attempt to hide their actions, often in a shameless or audacious manner.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["adverbial","attributive"],"structure":"modifier-head","register":"commonly used in both written and spoken Chinese","connotation":"negative","commonMistakes":"Learners often confuse this idiom with positive expressions of confidence. However, it carries a negative connotation, implying shamelessness or audacity.","canStandAlone":false},"examples":[{"simplified":"他明目张胆地在会议上撒谎。","english":"He brazenly lied during the meeting.","traditional":"他明目張膽地在會議上撒謊。"},{"simplified":"这些人明目张胆地违反法律。","english":"These people openly and boldly violate the law.","traditional":"這些人明目張膽地違反法律。"}],"synonyms":["肆无忌惮"],"antonyms":["小心翼翼"],"confusedWith":[{"id":"光明正大","note":"光明正大 means to act openly and honestly, with a positive connotation, unlike 明目张胆 which implies shamelessness."}],"traditional":"明目張膽","pinyinOverride":null},{"id":"ming-zhe-bao-shen","simplified":"明哲保身","literalMeaning":"wise to protect oneself","figurativeMeaning":"to act wisely to protect oneself from trouble or harm, often by avoiding involvement in contentious issues","englishEquivalents":["keep one's head down","play it safe"],"shortGloss":"act wisely to avoid trouble","characters":[{"char":"明","meaning":"wise"},{"char":"哲","meaning":"philosopher; wise person"},{"char":"保","meaning":"protect"},{"char":"身","meaning":"oneself; body"}],"origin":{"period":"Warring States period (475–221 BCE)","sourceText":"《左传·昭公二十年》","sourceTextEnglish":"Zuo Zhuan, Duke Zhao, Year 20","originalExcerpt":"明哲保身，不能以也。","storyEnglish":"The idiom originates from the 'Zuo Zhuan', an ancient Chinese historical text. It describes a situation where a wise person chooses to protect themselves by staying out of potentially harmful situations. The phrase implies that wisdom sometimes involves avoiding unnecessary risks or conflicts.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"literary, but very widely understood and used in ordinary speech","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with those that imply cowardice or selfishness. However, '明哲保身' emphasizes wisdom and prudence rather than fear or self-interest.","canStandAlone":false},"examples":[{"simplified":"在复杂的政治环境中，他选择明哲保身。","english":"In the complex political environment, he chose to keep his head down.","traditional":"在複雜的政治環境中，他選擇明哲保身。"},{"simplified":"有时候，明哲保身是最明智的选择。","english":"Sometimes, playing it safe is the wisest choice.","traditional":"有時候，明哲保身是最明智的選擇。"}],"synonyms":[],"antonyms":[],"confusedWith":[],"traditional":"明哲保身","pinyinOverride":null},{"id":"ming-zhi-gu-fan","simplified":"明知故犯","literalMeaning":"knowingly commit an offense","figurativeMeaning":"to do something wrong despite knowing it is wrong","englishEquivalents":["knowingly break the rules","deliberately flout the law"],"shortGloss":"knowingly commit an offense","characters":[{"char":"明","meaning":"clearly, knowingly"},{"char":"知","meaning":"know"},{"char":"故","meaning":"intentionally, deliberately"},{"char":"犯","meaning":"commit an offense"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '明知故犯' describes a situation where someone knowingly and deliberately commits an offense or breaks a rule, despite being fully aware of the consequences. It emphasizes the intentional aspect of the wrongdoing.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"commonly used in both written and spoken Chinese to describe deliberate wrongdoing","connotation":"negative","commonMistakes":"Learners might confuse this idiom with similar expressions that imply accidental wrongdoing. '明知故犯' specifically emphasizes the deliberate nature of the action.","canStandAlone":false},"examples":[{"simplified":"他明知故犯，结果被公司开除了。","english":"He knowingly broke the rules and ended up being fired by the company.","traditional":"他明知故犯，結果被公司開除了。"},{"simplified":"明知故犯的人往往会受到更严厉的惩罚。","english":"Those who knowingly commit offenses often face harsher punishments.","traditional":"明知故犯的人往往會受到更嚴厲的懲罰。"}],"synonyms":["故意为之"],"antonyms":["无心之失"],"confusedWith":[{"id":"无心之失","note":"无心之失 refers to an unintentional mistake, while 明知故犯 emphasizes deliberate wrongdoing."}],"traditional":"明知故犯","pinyinOverride":null},{"id":"mo-shou-cheng-gui","simplified":"墨守成规","literalMeaning":"adhere to established rules","figurativeMeaning":"to stick to conventions or old ways without change","englishEquivalents":["stick to the old ways","follow the beaten path"],"shortGloss":"stick to conventions","characters":[{"char":"墨","meaning":"ink; refers to Mozi, a philosopher known for his rigid adherence to rules"},{"char":"守","meaning":"guard; adhere to"},{"char":"成","meaning":"established; accomplished"},{"char":"规","meaning":"rules; regulations"}],"origin":{"period":"Warring States period (475–221 BCE)","sourceText":"《墨子》","sourceTextEnglish":"Mozi","originalExcerpt":"","storyEnglish":"The idiom originates from the teachings of Mozi, a Chinese philosopher during the Warring States period. Mozi was known for his strict adherence to his own set of rules and principles, which he believed were the best way to achieve a harmonious society. Over time, '墨守成规' came to describe anyone who rigidly follows established conventions without considering new ideas or changes.","historicalFigures":["Mozi"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"widely used in both formal and informal contexts","connotation":"negative","commonMistakes":"Learners might confuse this idiom with positive expressions of tradition or stability. However, it carries a negative connotation of inflexibility and resistance to change.","canStandAlone":false},"examples":[{"simplified":"他总是墨守成规，从不愿意尝试新方法。","english":"He always sticks to conventions and never wants to try new methods.","traditional":"他總是墨守成規，從不願意嘗試新方法。"},{"simplified":"在这个快速变化的时代，墨守成规可能会让你落后。","english":"In this fast-changing era, sticking to conventions might leave you behind.","traditional":"在這個快速變化的時代，墨守成規可能會讓你落後。"}],"synonyms":["因循守旧","抱残守缺"],"antonyms":["推陈出新","标新立异"],"confusedWith":[{"id":"循规蹈矩","note":"While both involve following rules, '循规蹈矩' is more about following rules in a disciplined manner, often with a neutral or positive connotation."}],"traditional":"墨守成規","pinyinOverride":null},{"id":"nong-qiao-fan-zhuo","simplified":"弄巧反拙","literalMeaning":"try to be clever but end up being clumsy","figurativeMeaning":"to try to be clever but end up making a fool of oneself; to backfire","englishEquivalents":["backfire","shoot oneself in the foot"],"shortGloss":"backfire; attempt cleverness but fail","characters":[{"char":"弄","meaning":"try to do"},{"char":"巧","meaning":"clever"},{"char":"反","meaning":"instead"},{"char":"拙","meaning":"clumsy"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom describes a situation where someone attempts to show off their cleverness or skill, but instead of achieving the desired effect, they end up making a mistake or causing an unintended negative outcome. It serves as a cautionary reminder to not overestimate one's abilities or to be too clever for one's own good.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"cause-effect","register":"commonly used in both spoken and written Chinese","connotation":"negative","commonMistakes":"Learners often confuse this idiom with similar ones that involve cleverness, but this idiom specifically emphasizes the failure or backfire of the attempt. It should not be used to describe successful cleverness.","canStandAlone":false},"examples":[{"simplified":"他想通过撒谎来掩盖错误，结果弄巧反拙，被老板发现了。","english":"He tried to cover up his mistake by lying, but it backfired, and his boss found out.","traditional":"他想通過撒謊來掩蓋錯誤，結果弄巧反拙，被老闆發現了。"},{"simplified":"她本想炫耀自己的厨艺，没想到弄巧反拙，把菜烧糊了。","english":"She intended to show off her cooking skills, but it backfired, and she burnt the dish.","traditional":"她本想炫耀自己的廚藝，沒想到弄巧反拙，把菜燒糊了。"}],"synonyms":["事与愿违"],"antonyms":[],"confusedWith":[{"id":"聪明反被聪明误","note":"Both involve cleverness leading to failure, but 聪明反被聪明误 emphasizes being too clever for one's own good, while 弄巧反拙 highlights the clumsiness of the attempt."}],"traditional":"弄巧反拙","pinyinOverride":null},{"id":"pu-tian-tong-qing","simplified":"普天同庆","literalMeaning":"all under heaven celebrate together","figurativeMeaning":"a universal celebration; everyone rejoices together","englishEquivalents":["a cause for universal celebration","everyone rejoices","a joyous occasion for all"],"shortGloss":"universal celebration","characters":[{"char":"普","meaning":"universal; everywhere"},{"char":"天","meaning":"heaven; sky"},{"char":"同","meaning":"together; same"},{"char":"庆","meaning":"celebrate; rejoice"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '普天同庆' is used to describe a situation where an event is so joyous and significant that it causes everyone to celebrate together. It is often used in the context of national holidays, major victories, or other events that bring widespread happiness.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"modifier-head","register":"common in both formal and informal contexts, often used in speeches and writing to describe national or large-scale celebrations","connotation":"positive","commonMistakes":"Learners might confuse this idiom with others that involve celebration but do not imply a universal or widespread rejoicing. It specifically conveys a sense of unity in celebration.","canStandAlone":false},"examples":[{"simplified":"国庆节是一个普天同庆的日子。","english":"National Day is a day of universal celebration.","traditional":"國慶節是一個普天同慶的日子。"},{"simplified":"新年的到来让普天同庆。","english":"The arrival of the New Year brings universal celebration.","traditional":"新年的到來讓普天同慶。"}],"synonyms":[],"antonyms":[],"confusedWith":[],"traditional":"普天同慶","pinyinOverride":null},{"id":"qi-ren-you-tian","simplified":"杞人忧天","literalMeaning":"man of Qi fears the sky falling","figurativeMeaning":"to worry unnecessarily; to be alarmed by imaginary fears","englishEquivalents":["crying over spilt milk","making a mountain out of a molehill"],"shortGloss":"unnecessary worry","characters":[{"char":"杞","meaning":"Qi (a state in ancient China)"},{"char":"人","meaning":"person, man"},{"char":"忧","meaning":"worry, fear"},{"char":"天","meaning":"sky, heaven"}],"origin":{"period":"Warring States period (475–221 BCE)","sourceText":"《列子·天瑞》","sourceTextEnglish":"Liezi, Chapter Tian Rui","originalExcerpt":"杞国有人忧天地崩坠，身亡所寄，废寝食者。","storyEnglish":"In the state of Qi, there was a man who was constantly worried that the sky would fall and the earth would collapse, leaving him with nowhere to live. His anxiety was so great that he could neither eat nor sleep. This story illustrates the futility of worrying about things that are unlikely to happen.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["subject","predicate","object"],"structure":"subject-predicate","register":"literary, but very widely understood and used in ordinary speech","connotation":"negative","commonMistakes":"Learners often use this idiom to describe any kind of worry, but it specifically refers to irrational or unnecessary worries. It is not suitable for genuine concerns.","canStandAlone":false},"examples":[{"simplified":"他总是杞人忧天，担心一些不可能发生的事情。","english":"He is always worrying unnecessarily, fretting over things that are unlikely to happen.","traditional":"他總是杞人憂天，擔心一些不可能發生的事情。"},{"simplified":"别杞人忧天了，专注于你能控制的事情吧。","english":"Stop worrying unnecessarily and focus on things you can control.","traditional":"別杞人憂天了，專注於你能控制的事情吧。"}],"synonyms":["庸人自扰"],"antonyms":[],"confusedWith":[{"id":"杯弓蛇影","note":"杯弓蛇影 refers to being overly suspicious or seeing danger where there is none, while 杞人忧天 is about unnecessary worry."}],"traditional":"杞人憂天","pinyinOverride":null},{"id":"qian-pian-yi-lu","simplified":"千篇一律","literalMeaning":"a thousand articles, one rule","figurativeMeaning":"monotonous; following the same pattern; lacking variety","englishEquivalents":["cut from the same cloth","cookie-cutter","same old, same old"],"shortGloss":"monotonous; lacking variety","characters":[{"char":"千","meaning":"thousand"},{"char":"篇","meaning":"articles; pieces of writing"},{"char":"一","meaning":"one; single"},{"char":"律","meaning":"rule; pattern"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '千篇一律' is believed to have originated from the observation that many written works or speeches can follow a similar pattern or style, leading to a lack of originality or variety. It is often used to criticize works that are repetitive or lack creativity.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive","adverbial"],"structure":"modifier-head","register":"commonly used in both written and spoken Chinese to describe something as monotonous or lacking in variety","connotation":"negative","commonMistakes":"Learners might confuse this idiom with others that describe uniformity, but '千篇一律' specifically emphasizes monotony and lack of creativity. It is not simply about being the same, but about being unoriginal.","canStandAlone":false},"examples":[{"simplified":"这篇文章写得千篇一律，没有什么新意。","english":"This article is monotonous and lacks originality.","traditional":"這篇文章寫得千篇一律，沒有什麼新意。"},{"simplified":"他的设计总是千篇一律，没有突破。","english":"His designs are always the same, with no breakthroughs.","traditional":"他的設計總是千篇一律，沒有突破。"}],"synonyms":["一成不变","如出一辙"],"antonyms":["别出心裁","独具匠心"],"confusedWith":[{"id":"一成不变","note":"While both idioms suggest a lack of change, '一成不变' emphasizes unchanging nature, whereas '千篇一律' highlights monotony and lack of originality."}],"traditional":"千篇一律","pinyinOverride":null},{"id":"qian-zai-nan-feng","simplified":"千载难逢","literalMeaning":"thousand years hard to encounter","figurativeMeaning":"a rare opportunity; something that happens once in a lifetime","englishEquivalents":["once in a lifetime","a golden opportunity"],"shortGloss":"a rare opportunity","characters":[{"char":"千","meaning":"thousand"},{"char":"载","meaning":"years"},{"char":"难","meaning":"hard"},{"char":"逢","meaning":"encounter"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '千载难逢' is used to describe an extremely rare opportunity, akin to something that might only occur once in a thousand years. While its exact origin is unclear, it has been used in Chinese literature and speech to emphasize the rarity and value of certain opportunities.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["attributive","adverbial"],"structure":"modifier-head","register":"widely used in both formal and informal contexts","connotation":"positive","commonMistakes":"Learners might confuse this idiom with others that suggest difficulty or rarity without the positive connotation of opportunity. It's important to use it in contexts where the rarity is beneficial or desirable.","canStandAlone":false},"examples":[{"simplified":"这次工作机会真是千载难逢，我一定要好好把握。","english":"This job opportunity is truly a once-in-a-lifetime chance, I must seize it.","traditional":"這次工作機會真是千載難逢，我一定要好好把握。"},{"simplified":"他遇到了一个千载难逢的投资机会，决定立刻行动。","english":"He came across a rare investment opportunity and decided to act immediately.","traditional":"他遇到了一個千載難逢的投資機會，決定立刻行動。"}],"synonyms":["机不可失"],"antonyms":[],"confusedWith":[{"id":"千辛万苦","note":"千辛万苦 refers to enduring many hardships, while 千载难逢 emphasizes a rare opportunity."}],"traditional":"千載難逢","pinyinOverride":null},{"id":"qian-che-zhi-jian","simplified":"前车之鉴","literalMeaning":"the lesson of the preceding cart","figurativeMeaning":"a lesson learned from others' mistakes","englishEquivalents":["learn from others' mistakes","a cautionary tale"],"shortGloss":"learn from others' mistakes","characters":[{"char":"前","meaning":"preceding"},{"char":"车","meaning":"cart"},{"char":"之","meaning":"of"},{"char":"鉴","meaning":"lesson"}],"origin":{"period":"Northern and Southern Dynasties (420–589 CE)","sourceText":"《世说新语·排调》","sourceTextEnglish":"A New Account of the Tales of the World, Chapter on Ridicule","originalExcerpt":"王戎曰：“前车覆，后车诫。”","storyEnglish":"The idiom originates from a story in 'A New Account of the Tales of the World.' In the story, Wang Rong, a scholar, uses the metaphor of a cart overturning to warn others that they should learn from the mistakes of those who came before them. The idea is that if the cart in front of you overturns, you should be cautious and avoid making the same mistake.","historicalFigures":["Wang Rong"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["subject","object","attributive"],"structure":"modifier-head","register":"literary, but widely used in both written and spoken Chinese","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with others that involve '车' (cart) but have different meanings, such as '车水马龙'. It's important to remember that '前车之鉴' specifically refers to learning from past mistakes.","canStandAlone":false},"examples":[{"simplified":"我们应该以历史为前车之鉴，避免重蹈覆辙。","english":"We should use history as a lesson to avoid repeating the same mistakes.","traditional":"我們應該以歷史為前車之鑑，避免重蹈覆轍。"},{"simplified":"他的失败是我们前车之鉴，我们必须更加小心。","english":"His failure is a lesson for us; we must be more cautious.","traditional":"他的失敗是我們前車之鑑，我們必須更加小心。"}],"synonyms":["引以为戒"],"antonyms":[],"confusedWith":[{"id":"车水马龙","note":"车水马龙 describes a bustling scene with heavy traffic, not related to learning from mistakes."}],"traditional":"前車之鑑","pinyinOverride":null},{"id":"qiang-ci-duo-li","simplified":"强词夺理","literalMeaning":"force words seize reason","figurativeMeaning":"to argue irrationally; to twist words and force logic","englishEquivalents":["to argue black is white","to twist the truth","to make a specious argument"],"shortGloss":"argue irrationally","characters":[{"char":"强","meaning":"forcefully"},{"char":"词","meaning":"words"},{"char":"夺","meaning":"seize"},{"char":"理","meaning":"reason"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom 强词夺理 describes a situation where someone uses forceful or misleading arguments to make an unreasonable point seem reasonable. It is often used to criticize someone who is twisting facts or logic to suit their own purposes, rather than engaging in honest debate.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"commonly used in both written and spoken Chinese to criticize faulty reasoning","connotation":"negative","commonMistakes":"Learners might confuse this idiom with ones that describe clever or skillful argumentation, but 强词夺理 specifically implies a lack of genuine logic or fairness.","canStandAlone":false},"examples":[{"simplified":"他总是强词夺理，让人很难沟通。","english":"He always argues irrationally, making it difficult to communicate.","traditional":"他總是強詞奪理，讓人很難溝通。"},{"simplified":"在辩论中，她并没有事实依据，只是在强词夺理。","english":"In the debate, she had no factual basis and was just twisting words.","traditional":"在辯論中，她並沒有事實依據，只是在強詞奪理。"}],"synonyms":["歪曲事实","胡搅蛮缠"],"antonyms":["实事求是"],"confusedWith":[{"id":"巧舌如簧","note":"巧舌如簧 refers to being eloquent and persuasive, not necessarily irrational or misleading."}],"traditional":"強詞奪理","pinyinOverride":null},{"id":"qing-tong-shou-zu","simplified":"情同手足","literalMeaning":"feelings like hands and feet","figurativeMeaning":"as close as brothers; having a deep, brotherly bond","englishEquivalents":["as close as brothers","thick as thieves"],"shortGloss":"as close as brothers","characters":[{"char":"情","meaning":"feelings; emotions"},{"char":"同","meaning":"same; like"},{"char":"手","meaning":"hand"},{"char":"足","meaning":"foot"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '情同手足' is used to describe a relationship between people that is as close and inseparable as that of one's own hands and feet. It emphasizes a deep, brotherly bond, suggesting that the individuals involved support and care for each other as if they were family.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"modifier-head","register":"commonly used in both spoken and written Chinese to describe close friendships or relationships","connotation":"positive","commonMistakes":"Learners might confuse this idiom with others that describe close relationships but lack the familial bond aspect. It specifically implies a brotherly closeness, not just any close relationship.","canStandAlone":false},"examples":[{"simplified":"他们从小一起长大，情同手足。","english":"They grew up together and are as close as brothers.","traditional":"他們從小一起長大，情同手足。"},{"simplified":"在困难的时候，他总是帮助我，我们情同手足。","english":"In difficult times, he always helps me; we are as close as brothers.","traditional":"在困難的時候，他總是幫助我，我們情同手足。"}],"synonyms":["亲如兄弟"],"antonyms":[],"confusedWith":[{"id":"亲如兄弟","note":"Both idioms describe a close relationship, but '情同手足' emphasizes the emotional bond, while '亲如兄弟' highlights the familial aspect."}],"traditional":"情同手足","pinyinOverride":null},{"id":"ren-fu-yu-shi","simplified":"人浮于事","literalMeaning":"people float above tasks","figurativeMeaning":"there are more people than work available; overstaffing","englishEquivalents":["Too many cooks spoil the broth","Overstaffed"],"shortGloss":"overstaffed; more people than work","characters":[{"char":"人","meaning":"people"},{"char":"浮","meaning":"float"},{"char":"于","meaning":"above"},{"char":"事","meaning":"tasks; work"}],"origin":{"period":"Tang Dynasty (618–907)","sourceText":"《新唐书·魏徵传》","sourceTextEnglish":"New Book of Tang, Biography of Wei Zheng","originalExcerpt":"今人浮于事，文繁于实。","storyEnglish":"The idiom originates from a statement made by Wei Zheng, a prominent chancellor during the Tang Dynasty. He criticized the bureaucracy of his time, noting that there were more officials than necessary tasks, leading to inefficiency. His observation was that people were 'floating above tasks,' meaning there were too many people for the amount of work available.","historicalFigures":["Wei Zheng"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"subject-predicate","register":"formal written Chinese, but also used in speech to describe bureaucratic inefficiency","connotation":"negative","commonMistakes":"Learners might confuse this idiom with expressions about being busy, but it actually describes inefficiency due to overstaffing. It should not be used to describe a situation where there is too much work.","canStandAlone":false},"examples":[{"simplified":"在这家公司，人浮于事，导致效率低下。","english":"In this company, there are more people than tasks, leading to inefficiency.","traditional":"在這家公司，人浮於事，導致效率低下。"},{"simplified":"政府部门常常人浮于事，浪费了许多资源。","english":"Government departments are often overstaffed, wasting many resources.","traditional":"政府部門常常人浮於事，浪費了許多資源。"}],"synonyms":["冗员充斥"],"antonyms":["人尽其才"],"confusedWith":[{"id":"人满为患","note":"人满为患 describes overcrowding causing problems, not specifically overstaffing."}],"traditional":"人浮於事","pinyinOverride":null},{"id":"ren-yun-yi-yun","simplified":"人云亦云","literalMeaning":"people say, also say","figurativeMeaning":"to echo others' views without having one's own opinion; to follow the crowd","englishEquivalents":["to parrot others","to follow the herd","to go with the flow"],"shortGloss":"to echo others' views","characters":[{"char":"人","meaning":"people"},{"char":"云","meaning":"say"},{"char":"亦","meaning":"also"},{"char":"云","meaning":"say"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '人云亦云' describes someone who lacks original thought and simply repeats what others say. The phrase literally means 'people say, also say,' reflecting the idea of echoing the opinions of others without forming one's own. It is often used to criticize individuals who conform to popular opinion without critical thinking.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"commonly used in both spoken and written Chinese to describe unoriginal thinking","connotation":"negative","commonMistakes":"Learners often confuse this idiom with similar expressions that imply agreement, but '人云亦云' specifically criticizes a lack of independent thought. It should not be used to simply indicate agreement.","canStandAlone":false},"examples":[{"simplified":"他总是人云亦云，从来没有自己的看法。","english":"He always parrots others and never has his own opinion.","traditional":"他總是人云亦云，從來沒有自己的看法。"},{"simplified":"在这个问题上，我们不能人云亦云，必须独立思考。","english":"On this issue, we cannot just follow the crowd; we must think independently.","traditional":"在這個問題上，我們不能人云亦云，必須獨立思考。"}],"synonyms":["随波逐流"],"antonyms":["独立思考"],"confusedWith":[{"id":"随声附和","note":"Both imply agreement, but '随声附和' can be less critical and simply mean to agree with someone."}],"traditional":"人云亦云","pinyinOverride":null},{"id":"ren-lao-ren-yuan","simplified":"任劳任怨","literalMeaning":"endure toil, endure complaints","figurativeMeaning":"to work hard and endure criticism without complaint","englishEquivalents":["to bear the burden without complaint","to take it on the chin"],"shortGloss":"work hard and endure criticism","characters":[{"char":"任","meaning":"endure"},{"char":"劳","meaning":"toil"},{"char":"任","meaning":"endure"},{"char":"怨","meaning":"complaints"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '任劳任怨' describes a person who is willing to take on hard work and endure any complaints or criticism that may come their way. It reflects a spirit of dedication and resilience, often praised in contexts where perseverance and humility are valued.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"coordinate","register":"commonly used in both formal and informal contexts","connotation":"positive","commonMistakes":"Learners might confuse this idiom with those that imply passivity or resignation. However, it specifically conveys a proactive willingness to endure both hard work and criticism.","canStandAlone":false},"examples":[{"simplified":"他在公司里总是任劳任怨，大家都很佩服他。","english":"He always works hard and endures criticism at the company, and everyone admires him.","traditional":"他在公司裡總是任勞任怨，大家都很佩服他。"},{"simplified":"在这个项目中，她任劳任怨，最终取得了成功。","english":"In this project, she worked hard and endured criticism, eventually achieving success.","traditional":"在這個項目中，她任勞任怨，最終取得了成功。"}],"synonyms":["默默无闻","无怨无悔"],"antonyms":["怨天尤人"],"confusedWith":[{"id":"逆来顺受","note":"While '任劳任怨' implies active endurance and dedication, '逆来顺受' suggests passive acceptance of adversity."}],"traditional":"任勞任怨","pinyinOverride":null},{"id":"rong-hua-fu-gui","simplified":"荣华富贵","literalMeaning":"glory, splendor, wealth, nobility","figurativeMeaning":"wealth and high social status; prosperity and luxury","englishEquivalents":["riches and honor","wealth and glory"],"shortGloss":"wealth and high status","characters":[{"char":"荣","meaning":"glory; honor"},{"char":"华","meaning":"splendor; magnificence"},{"char":"富","meaning":"wealth; riches"},{"char":"贵","meaning":"nobility; high status"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '荣华富贵' is often used to describe a life of luxury and high social standing. It is a common expression in Chinese culture, reflecting the traditional values of seeking prosperity and honor. The phrase is frequently used in literature and conversation to denote someone who has achieved great success and wealth.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["subject","object","attributive"],"structure":"coordinate","register":"widely used in both formal and informal contexts","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with others that imply temporary success or superficial wealth. '荣华富贵' implies a more stable and recognized status.","canStandAlone":false},"examples":[{"simplified":"他一生追求荣华富贵。","english":"He spent his life in pursuit of wealth and high social status.","traditional":"他一生追求榮華富貴。"},{"simplified":"荣华富贵并不是人生的唯一目标。","english":"Wealth and high status are not the only goals in life.","traditional":"榮華富貴並不是人生的唯一目標。"}],"synonyms":["富贵荣华"],"antonyms":["清贫如洗"],"confusedWith":[{"id":"纸醉金迷","note":"While both idioms involve wealth, '纸醉金迷' suggests a more hedonistic and indulgent lifestyle."}],"traditional":"榮華富貴","pinyinOverride":null},{"id":"fu-gui-rong-hua","simplified":"富贵荣华","literalMeaning":"wealth, honor, glory, splendor","figurativeMeaning":"wealth and high social status","englishEquivalents":["wealth and honor","riches and glory"],"shortGloss":"wealth and high status","characters":[{"char":"富","meaning":"wealth"},{"char":"贵","meaning":"nobility; high status"},{"char":"荣","meaning":"glory"},{"char":"华","meaning":"splendor"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '富贵荣华' is a traditional Chinese expression that has been used for centuries to describe a life filled with wealth and high social standing. It is often used in literature and conversation to convey the idea of living a prosperous and honorable life, though its exact origins are not tied to a specific classical text.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["subject","object","attributive"],"structure":"coordinate","register":"literary, but very widely understood and used in ordinary speech","connotation":"neutral","commonMistakes":"Learners often confuse '富贵荣华' with '荣华富贵', which has the same meaning but a different word order. Both are correct and interchangeable.","canStandAlone":false},"examples":[{"simplified":"他一生追求富贵荣华，但最终明白了平淡才是真。","english":"He spent his life pursuing wealth and high status, but ultimately realized that simplicity is true happiness.","traditional":"他一生追求富貴榮華，但最終明白了平淡才是真。"},{"simplified":"在古代，富贵荣华是许多人梦寐以求的生活。","english":"In ancient times, wealth and high status were the life many people dreamed of.","traditional":"在古代，富貴榮華是許多人夢寐以求的生活。"}],"synonyms":["荣华富贵"],"antonyms":["清贫如洗"],"confusedWith":[{"id":"荣华富贵","note":"This is essentially the same idiom with the words in a different order, meaning wealth and high status."}],"traditional":"富貴榮華","pinyinOverride":null},{"id":"ru-huo-ru-tu","simplified":"如火如荼","literalMeaning":"like fire, like tea","figurativeMeaning":"in full swing; with great momentum and intensity","englishEquivalents":["in full swing","going strong"],"shortGloss":"in full swing","characters":[{"char":"如","meaning":"like; as if"},{"char":"火","meaning":"fire"},{"char":"如","meaning":"like; as if"},{"char":"荼","meaning":"a kind of plant, often interpreted as 'tea'"}],"origin":{"period":"Warring States period (475–221 BCE)","sourceText":"《国语·吴语》","sourceTextEnglish":"Discourses of the States, Wu Discourses","originalExcerpt":"今兹吴国，气焰如火，兵势如荼。","storyEnglish":"The idiom originates from the 'Discourses of the States', where it describes the state of Wu's military power as being as intense and unstoppable as a raging fire and as pervasive as the growth of a plant called 'tu'. Over time, the phrase came to describe anything that is in full swing or progressing with great intensity.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"coordinate","register":"literary, but very widely understood and used in ordinary speech","connotation":"neutral","commonMistakes":"Learners often misinterpret '荼' as 'tea', but in this context, it refers to a plant that grows densely. The idiom is often confused with expressions that imply chaos, but it actually refers to intensity and momentum.","canStandAlone":false},"examples":[{"simplified":"节日的庆祝活动如火如荼地进行着。","english":"The festival celebrations are in full swing.","traditional":"節日的慶祝活動如火如荼地進行著。"},{"simplified":"公司的新项目如火如荼地展开。","english":"The company's new project is progressing with great momentum.","traditional":"公司的新項目如火如荼地展開。"}],"synonyms":["如日中天"],"antonyms":["偃旗息鼓"],"confusedWith":[{"id":"火上浇油","note":"如火如荼 describes intensity and momentum, while 火上浇油 means to exacerbate a situation."}],"traditional":"如火如荼","pinyinOverride":null},{"id":"ru-shi-zhong-fu","simplified":"如释重负","literalMeaning":"as if relieved of a heavy burden","figurativeMeaning":"to feel a sense of relief after a burden is lifted","englishEquivalents":["a weight off one's shoulders","breathe a sigh of relief"],"shortGloss":"feel relieved","characters":[{"char":"如","meaning":"as if"},{"char":"释","meaning":"to release"},{"char":"重","meaning":"heavy"},{"char":"负","meaning":"burden"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom 如释重负 describes the feeling of relief one experiences when a heavy burden is lifted. It is often used to express the emotional release and comfort that comes after a stressful or difficult situation has been resolved.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","complement"],"structure":"modifier-head","register":"widely used in both formal and informal contexts","connotation":"positive","commonMistakes":"Learners might confuse this idiom with expressions that imply actual physical weight, but it is used metaphorically to describe emotional or psychological relief.","canStandAlone":false},"examples":[{"simplified":"考试结束后，我如释重负。","english":"After the exam was over, I felt as if a weight had been lifted off my shoulders.","traditional":"考試結束後，我如釋重負。"},{"simplified":"听到好消息后，她如释重负地笑了。","english":"After hearing the good news, she smiled with relief.","traditional":"聽到好消息後，她如釋重負地笑了。"}],"synonyms":["心旷神怡"],"antonyms":["如坐针毡"],"confusedWith":[{"id":"如坐针毡","note":"如坐针毡 describes feeling anxious or uncomfortable, the opposite of relief."}],"traditional":"如釋重負","pinyinOverride":null},{"id":"san-si-er-xing","simplified":"三思而行","literalMeaning":"think thrice before acting","figurativeMeaning":"to think carefully before taking action","englishEquivalents":["look before you leap","think twice","consider carefully"],"shortGloss":"think carefully before acting","characters":[{"char":"三","meaning":"three"},{"char":"思","meaning":"to think"},{"char":"而","meaning":"and then"},{"char":"行","meaning":"to act"}],"origin":{"period":"Warring States period (475–221 BCE)","sourceText":"《论语·公冶长》","sourceTextEnglish":"The Analects of Confucius, Gongye Chang","originalExcerpt":"季文子三思而后行。","storyEnglish":"The idiom originates from a passage in 'The Analects of Confucius' where Confucius praises Ji Wenzi for his cautious approach to decision-making, as he would think three times before acting. This practice was seen as a sign of wisdom and prudence.","historicalFigures":["Confucius","Ji Wenzi"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["adverbial"],"structure":"modifier-head","register":"widely used in both formal and informal contexts","connotation":"positive","commonMistakes":"Learners might confuse this idiom with similar ones that emphasize speed or decisiveness, like '速战速决'. '三思而行' emphasizes careful consideration, not haste.","canStandAlone":false},"examples":[{"simplified":"在做出重要决定之前，我们应该三思而行。","english":"Before making an important decision, we should think carefully.","traditional":"在做出重要決定之前，我們應該三思而行。"},{"simplified":"他总是三思而行，所以很少犯错。","english":"He always thinks carefully before acting, so he rarely makes mistakes.","traditional":"他總是三思而行，所以很少犯錯。"}],"synonyms":["深思熟虑"],"antonyms":["贸然行事"],"confusedWith":[{"id":"速战速决","note":"速战速决 means to act quickly and decisively, which is the opposite of the careful consideration emphasized by 三思而行."}],"traditional":"三思而行","pinyinOverride":null},{"id":"seng-duo-zhou-shao","simplified":"僧多粥少","literalMeaning":"monks many, porridge little","figurativeMeaning":"demand exceeds supply; not enough to go around","englishEquivalents":["Too many cooks spoil the broth","Not enough to go around"],"shortGloss":"demand exceeds supply","characters":[{"char":"僧","meaning":"monks"},{"char":"多","meaning":"many"},{"char":"粥","meaning":"porridge"},{"char":"少","meaning":"little"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '僧多粥少' describes a situation where there are too many people and not enough resources to satisfy everyone. The image it conjures is of a monastery with many monks but only a small amount of porridge, leading to a shortage. This idiom is used to highlight situations where demand outstrips supply.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"subject-predicate","register":"commonly used in both spoken and written Chinese","connotation":"negative","commonMistakes":"Learners might confuse this idiom with others that involve scarcity, but '僧多粥少' specifically emphasizes the imbalance between the number of people and the available resources.","canStandAlone":false},"examples":[{"simplified":"在经济不景气的时候，工作机会就像僧多粥少。","english":"During an economic downturn, job opportunities are scarce, like too many monks and too little porridge.","traditional":"在經濟不景氣的時候，工作機會就像僧多粥少。"},{"simplified":"这次活动的名额有限，真是僧多粥少。","english":"The spots for this event are limited; it's truly a case of too many monks and too little porridge.","traditional":"這次活動的名額有限，真是僧多粥少。"}],"synonyms":["供不应求"],"antonyms":["供过于求"],"confusedWith":[],"traditional":"僧多粥少","pinyinOverride":null},{"id":"sha-ji-qu-luan","simplified":"杀鸡取卵","literalMeaning":"kill the chicken to get the eggs","figurativeMeaning":"to act shortsightedly, sacrificing long-term benefits for immediate gain","englishEquivalents":["kill the goose that lays the golden eggs"],"shortGloss":"shortsighted gain at long-term cost","characters":[{"char":"杀","meaning":"kill"},{"char":"鸡","meaning":"chicken"},{"char":"取","meaning":"take"},{"char":"卵","meaning":"eggs"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom comes from a fable about a farmer who owned a chicken that laid one egg every day. Impatient and greedy, he decided to kill the chicken to get all the eggs at once, only to find there were no eggs inside. This story is used to illustrate the folly of sacrificing future benefits for immediate gain.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","object"],"structure":"verb-object","register":"commonly used in both spoken and written Chinese","connotation":"negative","commonMistakes":"Learners might confuse this idiom with similar-sounding ones that involve chickens or eggs but have different meanings. It's important to remember that this idiom specifically refers to shortsighted actions that harm long-term interests.","canStandAlone":false},"examples":[{"simplified":"为了眼前的利益而杀鸡取卵是不可取的。","english":"It is unwise to kill the chicken to get the eggs for immediate benefits.","traditional":"為了眼前的利益而殺雞取卵是不可取的。"},{"simplified":"他为了快速盈利而杀鸡取卵，结果公司倒闭了。","english":"He acted shortsightedly to make quick profits, and as a result, the company went bankrupt.","traditional":"他為了快速盈利而殺雞取卵，結果公司倒閉了。"}],"synonyms":["竭泽而渔"],"antonyms":[],"confusedWith":[{"id":"鸡飞蛋打","note":"鸡飞蛋打 refers to a situation where both efforts and results are lost, while 杀鸡取卵 refers to shortsighted actions sacrificing long-term benefits."}],"traditional":"殺雞取卵","pinyinOverride":null},{"id":"she-ji-wei-ren","simplified":"舍己为人","literalMeaning":"give up oneself for others","figurativeMeaning":"to sacrifice one's own interests for the sake of others","englishEquivalents":["self-sacrifice","put others first"],"shortGloss":"self-sacrifice for others","characters":[{"char":"舍","meaning":"to give up"},{"char":"己","meaning":"oneself"},{"char":"为","meaning":"for"},{"char":"人","meaning":"others"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '舍己为人' reflects the noble act of putting others' needs before one's own. It is often used to describe individuals who make personal sacrifices for the benefit of others, embodying altruism and selflessness. The exact origin of this idiom is unclear, but it has been a part of Chinese culture for centuries, emphasizing the value of community and collective well-being.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"commonly used in both formal and informal contexts","connotation":"positive","commonMistakes":"Learners might confuse this idiom with expressions that imply self-harm or unnecessary sacrifice. It specifically refers to selfless acts that benefit others, not just any form of self-denial.","canStandAlone":false},"examples":[{"simplified":"他总是舍己为人，帮助需要帮助的人。","english":"He always puts others first, helping those in need.","traditional":"他總是捨己為人，幫助需要幫助的人。"},{"simplified":"她的舍己为人精神感动了所有人。","english":"Her spirit of self-sacrifice moved everyone.","traditional":"她的捨己為人精神感動了所有人。"}],"synonyms":["无私奉献"],"antonyms":["自私自利"],"confusedWith":[{"id":"自我牺牲","note":"While both involve sacrifice, 自我牺牲 often implies a more extreme or personal cost, whereas 舍己为人 emphasizes benefiting others."}],"traditional":"捨己為人","pinyinOverride":null},{"id":"shi-ban-gong-bei","simplified":"事半功倍","literalMeaning":"half the effort, double the result","figurativeMeaning":"to achieve greater results with less effort; to be highly efficient","englishEquivalents":["work smarter, not harder","more bang for your buck"],"shortGloss":"achieve more with less effort","characters":[{"char":"事","meaning":"effort; work"},{"char":"半","meaning":"half"},{"char":"功","meaning":"achievement; result"},{"char":"倍","meaning":"double"}],"origin":{"period":"Han Dynasty (202 BCE – 220 CE)","sourceText":"《后汉书·耿弇传》","sourceTextEnglish":"Book of the Later Han, Biography of Geng Yan","originalExcerpt":"今遣此三人，事半而功倍。","storyEnglish":"The idiom comes from a story in the 'Book of the Later Han' about Geng Yan, a general who was known for his strategic thinking. He once sent three people to accomplish a task, and they achieved results that were far greater than expected, illustrating the idea of achieving more with less effort.","historicalFigures":["Geng Yan"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"modifier-head","register":"widely used in both formal and informal contexts","connotation":"positive","commonMistakes":"Learners often confuse this idiom with those that emphasize hard work rather than efficiency. It's important to note that 事半功倍 highlights achieving more with less effort, not just working hard.","canStandAlone":false},"examples":[{"simplified":"如果你能找到正确的方法，你就能事半功倍。","english":"If you can find the right method, you can achieve more with less effort.","traditional":"如果你能找到正確的方法，你就能事半功倍。"},{"simplified":"使用现代科技可以让我们的工作事半功倍。","english":"Using modern technology can make our work much more efficient.","traditional":"使用現代科技可以讓我們的工作事半功倍。"}],"synonyms":["事倍功半"],"antonyms":["事倍功半"],"confusedWith":[{"id":"事倍功半","note":"事倍功半 means 'more effort, less result', the opposite of 事半功倍."}],"traditional":"事半功倍","pinyinOverride":null},{"id":"shi-bei-gong-ban","simplified":"事倍功半","literalMeaning":"effort doubled, result halved","figurativeMeaning":"to put in twice the effort for half the result; inefficient work","englishEquivalents":["spinning one's wheels","inefficient effort","working hard but getting nowhere"],"shortGloss":"inefficient effort","characters":[{"char":"事","meaning":"effort, work"},{"char":"倍","meaning":"double"},{"char":"功","meaning":"result, achievement"},{"char":"半","meaning":"half"}],"origin":{"period":"Han Dynasty (206 BCE – 220 CE)","sourceText":"《史记·淮阴侯列传》","sourceTextEnglish":"Records of the Grand Historian, Biography of the Marquis of Huaiyin","originalExcerpt":"事半而功倍，功半而事倍。","storyEnglish":"The idiom originates from the 'Records of the Grand Historian' by Sima Qian. In the biography of Han Xin, a famous general, it is noted that his strategies often resulted in 'half the effort, double the result.' This idiom, however, flips the phrase to describe situations where one puts in a lot of effort but achieves little, highlighting inefficiency.","historicalFigures":["Han Xin"],"relatedIdiomsFromSameSource":["事半功倍"]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"modifier-head","register":"commonly used in both spoken and written Chinese","connotation":"negative","commonMistakes":"Learners often confuse this idiom with '事半功倍', which means achieving more with less effort. It's important to note the reversal in meaning.","canStandAlone":false},"examples":[{"simplified":"如果不计划好，可能会事倍功半。","english":"If you don't plan well, you might end up putting in twice the effort for half the result.","traditional":"如果不計劃好，可能會事倍功半。"},{"simplified":"他的方法让我们事倍功半，效率很低。","english":"His method made us work inefficiently, putting in a lot of effort for little gain.","traditional":"他的方法讓我們事倍功半，效率很低。"}],"synonyms":[],"antonyms":["事半功倍"],"confusedWith":[{"id":"事半功倍","note":"The opposite meaning, achieving more with less effort."}],"traditional":"事倍功半","pinyinOverride":null},{"id":"shi-si-ru-gui","simplified":"视死如归","literalMeaning":"regard death as a return home","figurativeMeaning":"to face death fearlessly; to approach death with equanimity","englishEquivalents":["to go to one's death unflinchingly","to face death with equanimity"],"shortGloss":"face death fearlessly","characters":[{"char":"视","meaning":"regard; view"},{"char":"死","meaning":"death"},{"char":"如","meaning":"as if; like"},{"char":"归","meaning":"return home"}],"origin":{"period":"Warring States period (475–221 BCE)","sourceText":"《左传·襄公三十一年》","sourceTextEnglish":"Zuo Zhuan, Duke Xiang, Year 31","originalExcerpt":"视死如归，勇也。","storyEnglish":"The idiom originates from the 'Zuo Zhuan', an ancient Chinese narrative history. In the text, it describes the bravery of those who face death as if they were merely returning home. This expression was used to commend the courage and determination of warriors who were not afraid to sacrifice their lives for their country.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"modifier-head","register":"literary, but widely understood and used in both formal and informal contexts","connotation":"positive","commonMistakes":"Learners might confuse this idiom with expressions that imply recklessness or a lack of concern for life. However, it specifically denotes a noble or courageous attitude towards death, not carelessness.","canStandAlone":false},"examples":[{"simplified":"他在战场上视死如归，毫不畏惧。","english":"He faced death on the battlefield fearlessly, without any hesitation.","traditional":"他在戰場上視死如歸，毫不畏懼。"},{"simplified":"为了国家的未来，许多英雄视死如归。","english":"For the future of the country, many heroes faced death as if returning home.","traditional":"為了國家的未來，許多英雄視死如歸。"}],"synonyms":["舍生取义","英勇无畏"],"antonyms":["贪生怕死"],"confusedWith":[{"id":"舍生取义","note":"While both idioms involve sacrifice, 舍生取义 emphasizes sacrificing life for a just cause, whereas 视死如归 focuses on the fearless attitude towards death."}],"traditional":"視死如歸","pinyinOverride":null},{"id":"shou-bu-shi-juan","simplified":"手不释卷","literalMeaning":"hand does not release the scroll","figurativeMeaning":"to be diligent in study; to read avidly","englishEquivalents":["bookworm","avid reader"],"shortGloss":"diligent in study","characters":[{"char":"手","meaning":"hand"},{"char":"不","meaning":"not"},{"char":"释","meaning":"release"},{"char":"卷","meaning":"scroll"}],"origin":{"period":"Eastern Han Dynasty (25–220 CE)","sourceText":"《三国志·魏书·王肃传》","sourceTextEnglish":"Records of the Three Kingdoms, Book of Wei, Biography of Wang Su","originalExcerpt":"肃好学，手不释卷。","storyEnglish":"The idiom originates from the biography of Wang Su in the 'Records of the Three Kingdoms'. Wang Su was known for his love of learning and was described as someone who never let go of his scrolls, even during meals or while walking. This dedication to study became proverbial.","historicalFigures":["Wang Su"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"subject-predicate","register":"literary, but very widely understood and used in ordinary speech","connotation":"positive","commonMistakes":"Learners might confuse this idiom with others that involve reading or books, but this one specifically emphasizes the diligence and constant engagement with study materials.","canStandAlone":false},"examples":[{"simplified":"他从小就手不释卷，成绩一直很好。","english":"He has been an avid reader since childhood, and his grades have always been excellent.","traditional":"他從小就手不釋卷，成績一直很好。"},{"simplified":"为了准备考试，她最近手不释卷。","english":"She has been reading avidly lately to prepare for the exam.","traditional":"為了準備考試，她最近手不釋卷。"}],"synonyms":["孜孜不倦"],"antonyms":["游手好闲"],"confusedWith":[{"id":"废寝忘食","note":"While both idioms imply dedication, 废寝忘食 emphasizes neglecting basic needs due to focus, whereas 手不释卷 specifically refers to constant reading."}],"traditional":"手不釋卷","pinyinOverride":null},{"id":"shou-kou-ru-ping","simplified":"守口如瓶","literalMeaning":"guard mouth like bottle","figurativeMeaning":"to keep a secret; to be tight-lipped","englishEquivalents":["mum's the word","keep it under wraps"],"shortGloss":"keep a secret","characters":[{"char":"守","meaning":"guard"},{"char":"口","meaning":"mouth"},{"char":"如","meaning":"like; as if"},{"char":"瓶","meaning":"bottle"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '守口如瓶' describes someone who is very good at keeping secrets, as if their mouth is sealed like a bottle. The imagery suggests that just as a bottle keeps its contents securely inside, a person who '守口如瓶' keeps information from spilling out.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"modifier-head","register":"widely used in both spoken and written Chinese, informal contexts","connotation":"neutral","commonMistakes":"Learners sometimes confuse this idiom with expressions that mean 'to be silent' in general, but '守口如瓶' specifically emphasizes the act of keeping a secret.","canStandAlone":false},"examples":[{"simplified":"他对这件事守口如瓶，没有透露任何信息。","english":"He kept the matter under wraps and didn't reveal any information.","traditional":"他對這件事守口如瓶，沒有透露任何信息。"},{"simplified":"为了保护朋友的隐私，她守口如瓶。","english":"To protect her friend's privacy, she kept it under wraps.","traditional":"為了保護朋友的隱私，她守口如瓶。"}],"synonyms":["守口如瓶","三缄其口"],"antonyms":[],"confusedWith":[{"id":"缄默不语","note":"缄默不语 means to remain silent, but does not specifically imply keeping a secret."}],"traditional":"守口如瓶","pinyinOverride":null},{"id":"shou-wang-xiang-zhu","simplified":"守望相助","literalMeaning":"guard and watch, mutually assist","figurativeMeaning":"to watch over and help each other; mutual aid and support","englishEquivalents":["lend a helping hand","look out for each other"],"shortGloss":"mutual aid and support","characters":[{"char":"守","meaning":"guard"},{"char":"望","meaning":"watch"},{"char":"相","meaning":"mutually"},{"char":"助","meaning":"assist"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '守望相助' is believed to have originated from the idea of neighboring communities or individuals watching over each other's safety and providing mutual assistance, especially in times of need or danger. It emphasizes the importance of community solidarity and cooperation.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"coordinate","register":"commonly used in both spoken and written Chinese to emphasize community spirit and cooperation","connotation":"positive","commonMistakes":"Learners might confuse this idiom with others that emphasize individual effort rather than mutual support. It's important to remember that '守望相助' specifically highlights mutual aid.","canStandAlone":false},"examples":[{"simplified":"在自然灾害面前，邻里之间应该守望相助。","english":"In the face of natural disasters, neighbors should watch over and help each other.","traditional":"在自然災害面前，鄰里之間應該守望相助。"},{"simplified":"这个社区以守望相助而闻名。","english":"This community is known for its mutual aid and support.","traditional":"這個社區以守望相助而聞名。"}],"synonyms":["同舟共济"],"antonyms":[],"confusedWith":[{"id":"自力更生","note":"自力更生 emphasizes self-reliance, whereas 守望相助 focuses on mutual support."}],"traditional":"守望相助","pinyinOverride":null},{"id":"shu-neng-sheng-qiao","simplified":"熟能生巧","literalMeaning":"practice can produce skill","figurativeMeaning":"skill comes from practice; practice makes perfect","englishEquivalents":["Practice makes perfect","Repetition is the mother of skill"],"shortGloss":"skill comes from practice","characters":[{"char":"熟","meaning":"familiar, practiced"},{"char":"能","meaning":"can, able to"},{"char":"生","meaning":"produce, give rise to"},{"char":"巧","meaning":"skill, cleverness"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '熟能生巧' is based on the idea that through repeated practice and familiarity with a task, one can develop skill and proficiency. It emphasizes that expertise is not innate but acquired through diligent practice.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"subject-predicate","register":"commonly used in both spoken and written Chinese","connotation":"positive","commonMistakes":"Learners sometimes use this idiom to imply that skill can be achieved without effort, but it specifically emphasizes the necessity of practice. It is also sometimes confused with '勤能补拙', which focuses more on hard work compensating for lack of talent.","canStandAlone":false},"examples":[{"simplified":"经过多年的练习，他终于明白了熟能生巧的道理。","english":"After years of practice, he finally understood the principle that practice makes perfect.","traditional":"經過多年的練習，他終於明白了熟能生巧的道理。"},{"simplified":"无论多么复杂的技术，熟能生巧，只要你坚持练习。","english":"No matter how complex the technique, practice makes perfect as long as you keep practicing.","traditional":"無論多麼複雜的技術，熟能生巧，只要你堅持練習。"}],"synonyms":["勤能补拙"],"antonyms":[],"confusedWith":[{"id":"勤能补拙","note":"While '熟能生巧' emphasizes skill from practice, '勤能补拙' focuses on hard work compensating for lack of talent."}],"traditional":"熟能生巧","pinyinOverride":null},{"id":"shui-dao-qu-cheng","simplified":"水到渠成","literalMeaning":"water arrives, channel forms","figurativeMeaning":"when the conditions are right, success naturally follows","englishEquivalents":["When the time is right, success will follow","Everything falls into place"],"shortGloss":"success follows naturally","characters":[{"char":"水","meaning":"water"},{"char":"到","meaning":"arrives"},{"char":"渠","meaning":"channel"},{"char":"成","meaning":"forms"}],"origin":{"period":"Tang Dynasty (618–907)","sourceText":"《杜工部集》","sourceTextEnglish":"Collected Works of Du Fu","originalExcerpt":"水到渠成，事不难也。","storyEnglish":"The idiom comes from a poem by Du Fu, a famous Tang Dynasty poet. In his poem, Du Fu uses the metaphor of water naturally forming a channel when it arrives, to illustrate the idea that when the right conditions are met, success will naturally follow without much effort.","historicalFigures":["Du Fu"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"subject-predicate","register":"literary, but commonly used in both written and spoken Chinese","connotation":"positive","commonMistakes":"Learners sometimes confuse this idiom with ones that imply effort is unnecessary, but it actually emphasizes the importance of preparation and timing.","canStandAlone":true},"examples":[{"simplified":"只要你努力学习，水到渠成，考试一定会通过的。","english":"As long as you study hard, success will naturally follow, and you will definitely pass the exam.","traditional":"只要你努力學習，水到渠成，考試一定會通過的。"},{"simplified":"我们已经做好了所有准备，水到渠成，项目很快就会完成。","english":"We have prepared everything, and success will naturally follow; the project will be completed soon.","traditional":"我們已經做好了所有準備，水到渠成，項目很快就會完成。"}],"synonyms":["瓜熟蒂落"],"antonyms":[],"confusedWith":[{"id":"事半功倍","note":"水到渠成 emphasizes natural success following preparation, while 事半功倍 emphasizes achieving more with less effort."}],"traditional":"水到渠成","pinyinOverride":null},{"id":"sui-yu-er-an","simplified":"随遇而安","literalMeaning":"adapt to circumstances and be content","figurativeMeaning":"to be adaptable and content in any situation","englishEquivalents":["go with the flow","make the best of a bad situation"],"shortGloss":"adapt and be content","characters":[{"char":"随","meaning":"follow; adapt"},{"char":"遇","meaning":"encounter; situation"},{"char":"而","meaning":"and; thus"},{"char":"安","meaning":"peace; contentment"}],"origin":{"period":"Eastern Jin Dynasty (317–420)","sourceText":"《世说新语·排调》","sourceTextEnglish":"A New Account of the Tales of the World, Chapter on Ridicule","originalExcerpt":"随遇而安，未尝有求。","storyEnglish":"This idiom originates from the Eastern Jin Dynasty, where it was used to describe a person who could adapt to any situation and remain content without seeking more. It reflects a philosophy of being at peace with one's circumstances, no matter where one finds oneself.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"modifier-head","register":"literary, but widely used in both written and spoken Chinese","connotation":"positive","commonMistakes":"Learners often confuse this idiom with those that imply passivity or resignation, but 随遇而安 emphasizes adaptability and contentment rather than giving up.","canStandAlone":false},"examples":[{"simplified":"他总是随遇而安，从不抱怨。","english":"He always adapts to circumstances and never complains.","traditional":"他總是隨遇而安，從不抱怨。"},{"simplified":"在新的环境中，她很快就学会了随遇而安。","english":"In the new environment, she quickly learned to adapt and be content.","traditional":"在新的環境中，她很快就學會了隨遇而安。"}],"synonyms":["随波逐流"],"antonyms":["怨天尤人"],"confusedWith":[{"id":"随波逐流","note":"随波逐流 implies going along passively without direction, while 随遇而安 emphasizes contentment and adaptability."}],"traditional":"隨遇而安","pinyinOverride":null},{"id":"kou-ruo-xuan-he","simplified":"口若悬河","literalMeaning":"mouth like a hanging river","figurativeMeaning":"to speak eloquently and continuously","englishEquivalents":["to have the gift of the gab","to be a smooth talker"],"shortGloss":"speak eloquently and fluently","characters":[{"char":"口","meaning":"mouth"},{"char":"若","meaning":"like"},{"char":"悬","meaning":"hanging"},{"char":"河","meaning":"river"}],"origin":{"period":"Three Kingdoms period (220–280 CE)","sourceText":"《三国志·吴书·张昭传》","sourceTextEnglish":"Records of the Three Kingdoms, Book of Wu, Biography of Zhang Zhao","originalExcerpt":"昭口若悬河，辩才无碍。","storyEnglish":"The idiom originates from the 'Records of the Three Kingdoms', where it describes Zhang Zhao, a statesman of the Eastern Wu during the Three Kingdoms period. It was said that Zhang Zhao could speak with such eloquence and fluency that his words flowed like a river, impressing all who heard him.","historicalFigures":["Zhang Zhao"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"modifier-head","register":"literary, but widely used in both written and spoken Chinese","connotation":"positive","commonMistakes":"Learners might confuse this idiom with others that involve speaking, such as 口是心非, which has a negative connotation of saying one thing but meaning another. 口若悬河 specifically emphasizes eloquence and fluency.","canStandAlone":false},"examples":[{"simplified":"他的演讲口若悬河，观众都听得入迷。","english":"His speech was so eloquent and fluent that the audience was captivated.","traditional":"他的演講口若懸河，觀眾都聽得入迷。"},{"simplified":"她在辩论中口若悬河，让对手无言以对。","english":"She spoke so eloquently in the debate that her opponents were left speechless.","traditional":"她在辯論中口若懸河，讓對手無言以對。"}],"synonyms":["滔滔不绝"],"antonyms":["沉默寡言"],"confusedWith":[{"id":"口是心非","note":"口是心非 means to say one thing and mean another, which is different from the eloquence implied by 口若悬河."}],"traditional":"口若懸河","pinyinOverride":null},{"id":"tiao-bo-li-jian","simplified":"挑拨离间","literalMeaning":"provoke separation and division","figurativeMeaning":"to sow discord; to incite conflict or division between people","englishEquivalents":["sow discord","drive a wedge between","stir up trouble"],"shortGloss":"sow discord","characters":[{"char":"挑","meaning":"provoke"},{"char":"拨","meaning":"stir up"},{"char":"离","meaning":"separate"},{"char":"间","meaning":"divide"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '挑拨离间' is used to describe actions that deliberately create conflict or division between people. It suggests the act of instigating misunderstandings or disputes, often for personal gain or to cause harm to relationships.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["verb-object"],"structure":"verb-object","register":"common in both spoken and written Chinese","connotation":"negative","commonMistakes":"Learners often confuse this idiom with similar expressions that mean 'to cause trouble' in a more general sense. '挑拨离间' specifically refers to causing discord between people.","canStandAlone":false},"examples":[{"simplified":"他总是喜欢挑拨离间，让我们之间产生误会。","english":"He always likes to sow discord, causing misunderstandings between us.","traditional":"他總是喜歡挑撥離間，讓我們之間產生誤會。"},{"simplified":"不要听信他的挑拨离间，我们要团结一致。","english":"Don't believe his attempts to sow discord; we must stay united.","traditional":"不要聽信他的挑撥離間，我們要團結一致。"}],"synonyms":["搬弄是非","挑拨是非"],"antonyms":["和睦相处"],"confusedWith":[{"id":"挑拨是非","note":"While both involve causing trouble, '挑拨是非' focuses more on creating disputes or controversies, not necessarily between specific people."}],"traditional":"挑撥離間","pinyinOverride":null},{"id":"ting-er-zou-xian","simplified":"铤而走险","literalMeaning":"risk danger by running","figurativeMeaning":"to take a desperate risk; to risk everything in a crisis","englishEquivalents":["take a leap of faith","throw caution to the wind","go out on a limb"],"shortGloss":"take a desperate risk","characters":[{"char":"铤","meaning":"to rush forward"},{"char":"而","meaning":"and; thus"},{"char":"走","meaning":"to walk; to go"},{"char":"险","meaning":"danger; risk"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '铤而走险' describes a situation where someone takes a significant risk, often out of desperation or necessity. It suggests a scenario where the individual feels they have no other choice but to take a bold, potentially dangerous action in hopes of achieving a positive outcome. The idiom is often used to describe actions taken when conventional options have been exhausted.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"commonly used in both written and spoken Chinese, especially in contexts discussing risk-taking","connotation":"neutral","commonMistakes":"Learners often confuse this idiom with others that involve risk, such as 冒险 (to take a risk), but 铤而走险 specifically implies a sense of desperation or last resort.","canStandAlone":false},"examples":[{"simplified":"他为了还债，不得不铤而走险去做非法的事情。","english":"He had to take a desperate risk and do something illegal to pay off his debts.","traditional":"他為了還債，不得不鋌而走險去做非法的事情。"},{"simplified":"在绝望中，她决定铤而走险，尝试新的方法。","english":"In desperation, she decided to take a risk and try a new approach.","traditional":"在絕望中，她決定鋌而走險，嘗試新的方法。"}],"synonyms":["孤注一掷"],"antonyms":["稳扎稳打"],"confusedWith":[{"id":"冒险","note":"冒险 means to take a risk, but without the implication of desperation or last resort."}],"traditional":"鋌而走險","pinyinOverride":null},{"id":"tong-gan-gong-ku","simplified":"同甘共苦","literalMeaning":"share sweetness, share bitterness","figurativeMeaning":"to share both joys and sorrows; to stick together through thick and thin","englishEquivalents":["through thick and thin","for better or worse"],"shortGloss":"share joys and sorrows","characters":[{"char":"同","meaning":"together"},{"char":"甘","meaning":"sweetness"},{"char":"共","meaning":"together"},{"char":"苦","meaning":"bitterness"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '同甘共苦' is often used to describe a relationship or partnership where people support each other through both good times and bad. It emphasizes loyalty and solidarity, suggesting that true companionship involves sharing both happiness and hardship equally.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"coordinate","register":"widely used in both formal and informal contexts","connotation":"positive","commonMistakes":"Learners sometimes confuse this idiom with those that only refer to positive or negative experiences. It's important to remember that it encompasses both good and bad times.","canStandAlone":false},"examples":[{"simplified":"他们是一对同甘共苦的好朋友。","english":"They are good friends who share both joys and sorrows.","traditional":"他們是一對同甘共苦的好朋友。"},{"simplified":"夫妻之间应该同甘共苦，互相扶持。","english":"Between husband and wife, there should be mutual support through thick and thin.","traditional":"夫妻之間應該同甘共苦，互相扶持。"}],"synonyms":["风雨同舟"],"antonyms":[],"confusedWith":[],"traditional":"同甘共苦","pinyinOverride":null},{"id":"tong-gui-yu-jin","simplified":"同归于尽","literalMeaning":"together return to exhaustion","figurativeMeaning":"to perish together; mutual destruction","englishEquivalents":["mutually assured destruction","go down together","take each other down"],"shortGloss":"mutual destruction","characters":[{"char":"同","meaning":"together"},{"char":"归","meaning":"return"},{"char":"于","meaning":"to"},{"char":"尽","meaning":"exhaustion; end"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom 同归于尽 describes a situation where two parties are so determined to defeat each other that they end up destroying one another in the process. It is often used to describe conflicts where neither side emerges victorious, as both are brought to ruin.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"used in both formal and informal contexts, especially in discussions of conflict or competition","connotation":"negative","commonMistakes":"Learners often confuse this idiom with those that imply cooperation or partnership due to the character 同 (together). However, 同归于尽 specifically refers to mutual destruction, not collaboration.","canStandAlone":false},"examples":[{"simplified":"如果继续这样下去，他们只会同归于尽。","english":"If they continue like this, they will only end up destroying each other.","traditional":"如果繼續這樣下去，他們只會同歸於盡。"},{"simplified":"这场战争的结果是双方同归于尽，没有赢家。","english":"The result of this war was mutual destruction, with no winners.","traditional":"這場戰爭的結果是雙方同歸於盡，沒有贏家。"}],"synonyms":["玉石俱焚"],"antonyms":[],"confusedWith":[{"id":"同舟共济","note":"同舟共济 means to work together in times of difficulty, which is the opposite of mutual destruction."}],"traditional":"同歸於盡","pinyinOverride":null},{"id":"tong-liu-he-wu","simplified":"同流合污","literalMeaning":"join the flow, merge with the filth","figurativeMeaning":"to go along with bad influences; to join others in their corrupt or immoral activities","englishEquivalents":["to go with the flow","to join the bandwagon","to follow the crowd"],"shortGloss":"to join in corrupt activities","characters":[{"char":"同","meaning":"together with; to join"},{"char":"流","meaning":"flow; current"},{"char":"合","meaning":"to combine; to merge"},{"char":"污","meaning":"filth; corruption"}],"origin":{"period":"Eastern Han dynasty (25–220 CE)","sourceText":"《后汉书·独行列传》","sourceTextEnglish":"Book of the Later Han, Biographies of Exemplary Individuals","originalExcerpt":"与世推移，同流合污。","storyEnglish":"The idiom originates from the 'Book of the Later Han', where it describes individuals who, instead of maintaining their integrity, choose to go along with the corrupt practices of their peers. It highlights the moral compromise involved in joining others in their unethical behavior.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"literary, but understood in modern contexts","connotation":"negative","commonMistakes":"Learners often confuse this idiom with neutral expressions like 'go with the flow,' but it specifically implies a negative moral judgment about following bad influences.","canStandAlone":false},"examples":[{"simplified":"他为了升职，不得不同流合污。","english":"In order to get promoted, he had no choice but to join in the corrupt activities.","traditional":"他為了升職，不得不同流合汙。"},{"simplified":"我们不能为了利益而同流合污。","english":"We cannot join in corrupt activities just for the sake of profit.","traditional":"我們不能為了利益而同流合汙。"}],"synonyms":["随波逐流"],"antonyms":["洁身自好"],"confusedWith":[{"id":"随波逐流","note":"While both involve going along with others, '随波逐流' is more neutral and lacks the negative moral judgment of '同流合污'."}],"traditional":"同流合汙","pinyinOverride":null},{"id":"tou-ji-qu-qiao","simplified":"投机取巧","literalMeaning":"seize opportunity, take cleverness","figurativeMeaning":"to exploit opportunities and use cunning methods for personal gain","englishEquivalents":["opportunistic","cut corners","play the angles"],"shortGloss":"opportunistic and cunning","characters":[{"char":"投","meaning":"seize"},{"char":"机","meaning":"opportunity"},{"char":"取","meaning":"take"},{"char":"巧","meaning":"cleverness"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '投机取巧' describes the behavior of someone who takes advantage of situations and uses clever but often unethical methods to achieve their goals. It is often used to criticize those who prioritize personal gain over integrity.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["adverbial","attributive"],"structure":"coordinate","register":"commonly used in both spoken and written Chinese to describe opportunistic behavior","connotation":"negative","commonMistakes":"Learners might confuse this idiom with positive expressions of cleverness or intelligence, but it specifically implies a lack of integrity or ethics. It should not be used to praise someone's intelligence.","canStandAlone":false},"examples":[{"simplified":"他总是投机取巧，不愿意脚踏实地地工作。","english":"He always looks for shortcuts and isn't willing to work diligently.","traditional":"他總是投機取巧，不願意腳踏實地地工作。"},{"simplified":"在商业中，投机取巧可能带来短期利益，但长期来看并不可靠。","english":"In business, being opportunistic may bring short-term gains, but it is not reliable in the long run.","traditional":"在商業中，投機取巧可能帶來短期利益，但長期來看並不可靠。"}],"synonyms":["见风使舵","投机倒把"],"antonyms":["脚踏实地","诚实守信"],"confusedWith":[{"id":"聪明才智","note":"聪明才智 refers to genuine intelligence and talent, while 投机取巧 implies unethical opportunism."}],"traditional":"投機取巧","pinyinOverride":null},{"id":"tu-lao-wu-gong","simplified":"徒劳无功","literalMeaning":"vain effort without achievement","figurativeMeaning":"to make a futile effort; to work hard but achieve nothing","englishEquivalents":["a wild goose chase","spinning one's wheels","in vain"],"shortGloss":"futile effort","characters":[{"char":"徒","meaning":"in vain"},{"char":"劳","meaning":"effort"},{"char":"无","meaning":"without"},{"char":"功","meaning":"achievement"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '徒劳无功' describes situations where someone puts in a lot of effort but fails to achieve any results. It is often used to caution against efforts that are unlikely to succeed or to describe past efforts that have proven fruitless.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"modifier-head","register":"commonly used in both spoken and written Chinese","connotation":"negative","commonMistakes":"Learners sometimes confuse '徒劳无功' with '事半功倍', which means achieving more with less effort. '徒劳无功' emphasizes the lack of results despite effort, while '事半功倍' highlights efficiency and success.","canStandAlone":false},"examples":[{"simplified":"他努力了很久，但最终还是徒劳无功。","english":"He worked hard for a long time, but ultimately it was all in vain.","traditional":"他努力了很久，但最終還是徒勞無功。"},{"simplified":"如果没有明确的计划，所有的努力可能都会徒劳无功。","english":"Without a clear plan, all efforts might be futile.","traditional":"如果沒有明確的計劃，所有的努力可能都會徒勞無功。"}],"synonyms":["白费力气","无济于事"],"antonyms":["事半功倍"],"confusedWith":[{"id":"事半功倍","note":"事半功倍 means achieving more with less effort, opposite to the lack of results in 徒劳无功."}],"traditional":"徒勞無功","pinyinOverride":null},{"id":"tui-chen-chu-xin","simplified":"推陈出新","literalMeaning":"discard the old, introduce the new","figurativeMeaning":"to innovate; to improve by replacing the old with the new","englishEquivalents":["out with the old, in with the new","innovate"],"shortGloss":"innovate by replacing the old","characters":[{"char":"推","meaning":"to push; to promote"},{"char":"陈","meaning":"old; outdated"},{"char":"出","meaning":"to produce; to bring forth"},{"char":"新","meaning":"new"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '推陈出新' is used to describe the process of innovation, where outdated ideas or practices are replaced with new and improved ones. It emphasizes the importance of progress and creativity in various fields, from technology to art.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"verb-object","register":"widely used in both formal and informal contexts","connotation":"positive","commonMistakes":"Learners sometimes confuse this idiom with phrases that only imply discarding the old without the aspect of introducing something new. It's important to remember that '推陈出新' emphasizes both removal and innovation.","canStandAlone":false},"examples":[{"simplified":"公司需要推陈出新，以保持竞争力。","english":"The company needs to innovate to stay competitive.","traditional":"公司需要推陳出新，以保持競爭力。"},{"simplified":"艺术家们不断推陈出新，创造出新的风格。","english":"Artists constantly innovate, creating new styles.","traditional":"藝術家們不斷推陳出新，創造出新的風格。"}],"synonyms":["革故鼎新"],"antonyms":[],"confusedWith":[{"id":"革故鼎新","note":"Both idioms involve innovation, but '革故鼎新' has a stronger emphasis on reform and transformation."}],"traditional":"推陳出新","pinyinOverride":null},{"id":"wang-chen-mo-ji","simplified":"望尘莫及","literalMeaning":"gaze at dust, unable to reach","figurativeMeaning":"to be far inferior; unable to catch up","englishEquivalents":["can't hold a candle to","out of one's league"],"shortGloss":"unable to catch up or compare","characters":[{"char":"望","meaning":"to gaze at"},{"char":"尘","meaning":"dust"},{"char":"莫","meaning":"unable to"},{"char":"及","meaning":"reach"}],"origin":{"period":"Three Kingdoms period (220–280 CE)","sourceText":"《三国志·魏书·王昶传》","sourceTextEnglish":"Records of the Three Kingdoms, Book of Wei, Biography of Wang Chang","originalExcerpt":"望尘而莫及也。","storyEnglish":"The idiom comes from the story of Wang Chang, a general during the Three Kingdoms period. It was said that his abilities were so superior that others could only see the dust he left behind as he advanced, unable to catch up with him. This expression was used to describe someone whose skills or achievements are far beyond the reach of others.","historicalFigures":["Wang Chang"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"literary, but commonly used in both written and spoken Chinese","connotation":"negative","commonMistakes":"Learners often confuse this idiom with expressions that imply a literal physical chase, but it is used metaphorically to describe being unable to match someone's achievements or abilities.","canStandAlone":false},"examples":[{"simplified":"他的能力太强了，我们只能望尘莫及。","english":"His abilities are so strong that we can only watch from afar, unable to catch up.","traditional":"他的能力太強了，我們只能望塵莫及。"},{"simplified":"在数学方面，他让其他同学望尘莫及。","english":"In mathematics, he leaves the other students far behind.","traditional":"在數學方面，他讓其他同學望塵莫及。"}],"synonyms":["相形见绌"],"antonyms":[],"confusedWith":[{"id":"望而却步","note":"望而却步 means to shrink back at the sight of something daunting, not to be unable to catch up."}],"traditional":"望塵莫及","pinyinOverride":null},{"id":"wang-en-fu-yi","simplified":"忘恩负义","literalMeaning":"forget kindness, betray righteousness","figurativeMeaning":"to be ungrateful and treacherous","englishEquivalents":["bite the hand that feeds you","ungrateful wretch"],"shortGloss":"ungrateful and treacherous","characters":[{"char":"忘","meaning":"forget"},{"char":"恩","meaning":"kindness"},{"char":"负","meaning":"betray"},{"char":"义","meaning":"righteousness"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '忘恩负义' is used to describe someone who is ungrateful and betrays those who have helped them. The phrase suggests a moral failing in which a person forgets the kindness and favors they have received and acts against those who supported them.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"coordinate","register":"widely used in both formal and informal contexts","connotation":"negative","commonMistakes":"Learners might confuse this idiom with similar expressions that imply mere forgetfulness, but '忘恩负义' specifically involves a moral judgment about ingratitude and betrayal.","canStandAlone":false},"examples":[{"simplified":"他对曾经帮助过他的人忘恩负义。","english":"He was ungrateful and treacherous to those who had helped him.","traditional":"他對曾經幫助過他的人忘恩負義。"},{"simplified":"忘恩负义的人往往会失去朋友。","english":"Ungrateful and treacherous people often lose friends.","traditional":"忘恩負義的人往往會失去朋友。"}],"synonyms":["恩将仇报"],"antonyms":["知恩图报"],"confusedWith":[{"id":"恩将仇报","note":"Both involve ingratitude, but '恩将仇报' specifically means repaying kindness with enmity."}],"traditional":"忘恩負義","pinyinOverride":null},{"id":"wei-fei-zuo-dai","simplified":"为非作歹","literalMeaning":"do wrong and commit evil","figurativeMeaning":"to engage in criminal activities; to commit crimes","englishEquivalents":["commit crimes","engage in wrongdoing"],"shortGloss":"commit crimes","characters":[{"char":"为","meaning":"do"},{"char":"非","meaning":"wrong"},{"char":"作","meaning":"commit"},{"char":"歹","meaning":"evil"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom 为非作歹 is used to describe someone who engages in illegal or immoral activities. It is a general term for committing crimes or doing bad things, and does not originate from a specific classical story or text.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","object"],"structure":"coordinate","register":"commonly used in both written and spoken Chinese to describe criminal behavior","connotation":"negative","commonMistakes":"Learners might confuse this idiom with others that describe bad behavior, but 为非作歹 specifically implies criminal actions rather than minor misbehavior.","canStandAlone":false},"examples":[{"simplified":"他因为为非作歹而被警察逮捕。","english":"He was arrested by the police for committing crimes.","traditional":"他因為為非作歹而被警察逮捕。"},{"simplified":"这些年，他一直在为非作歹，最终受到了法律的制裁。","english":"Over the years, he engaged in criminal activities and was eventually punished by the law.","traditional":"這些年，他一直在為非作歹，最終受到了法律的制裁。"}],"synonyms":["胡作非为","违法乱纪"],"antonyms":["安分守己"],"confusedWith":[{"id":"胡作非为","note":"胡作非为 also refers to doing bad things, but it can imply reckless or unruly behavior without the specific criminal connotation."}],"traditional":"為非作歹","pinyinOverride":null},{"id":"wei-yu-chou-mou","simplified":"未雨绸缪","literalMeaning":"before it rains, mend the roof","figurativeMeaning":"to take precautions before it is too late; to prepare for a rainy day","englishEquivalents":["Prepare for a rainy day","An ounce of prevention is worth a pound of cure"],"shortGloss":"prepare ahead to avoid trouble","characters":[{"char":"未","meaning":"not yet"},{"char":"雨","meaning":"rain"},{"char":"绸","meaning":"silk; to bind"},{"char":"缪","meaning":"to bind; to mend"}],"origin":{"period":"Warring States period (475–221 BCE)","sourceText":"《诗经·豳风·鸱鸮》","sourceTextEnglish":"The Book of Songs, Bin Feng, The Owl","originalExcerpt":"迨天之未阴雨，彻彼桑土，绸缪牖户。","storyEnglish":"The idiom comes from a poem in the 'Book of Songs', which advises people to repair their homes before the rainy season arrives. The poem emphasizes the importance of taking preventive measures to avoid future problems.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["adverbial","attributive"],"structure":"modifier-head","register":"literary, but very widely understood and used in ordinary speech","connotation":"positive","commonMistakes":"Learners sometimes confuse this idiom with others that involve preparation, such as 临渴掘井, which implies waiting until the last minute to prepare. 未雨绸缪 emphasizes early preparation.","canStandAlone":false},"examples":[{"simplified":"我们应该未雨绸缪，为未来做好准备。","english":"We should prepare for a rainy day and get ready for the future.","traditional":"我們應該未雨綢繆，為未來做好準備。"},{"simplified":"公司在经济危机前未雨绸缪，储备了大量资金。","english":"The company prepared ahead of the economic crisis by saving a large amount of funds.","traditional":"公司在經濟危機前未雨綢繆，儲備了大量資金。"}],"synonyms":["防患未然"],"antonyms":["临渴掘井"],"confusedWith":[{"id":"临渴掘井","note":"临渴掘井 refers to taking action only when a problem arises, unlike 未雨绸缪, which emphasizes early preparation."}],"traditional":"未雨綢繆","pinyinOverride":null},{"id":"wen-gu-zhi-xin","simplified":"温故知新","literalMeaning":"review the old to know the new","figurativeMeaning":"to gain new insights through reviewing old material; learning from the past","englishEquivalents":["Learn from the past","Review old knowledge to gain new insights"],"shortGloss":"learn from reviewing the past","characters":[{"char":"温","meaning":"review"},{"char":"故","meaning":"old"},{"char":"知","meaning":"know"},{"char":"新","meaning":"new"}],"origin":{"period":"Spring and Autumn period (770–476 BCE)","sourceText":"《论语·为政》","sourceTextEnglish":"The Analects of Confucius, Chapter 2","originalExcerpt":"温故而知新，可以为师矣。","storyEnglish":"This idiom comes from Confucius' teachings in 'The Analects.' Confucius emphasized the importance of reviewing past knowledge to gain new insights and understanding. He believed that by doing so, one could become a teacher or a person of wisdom. This concept highlights the value of continuous learning and reflection.","historicalFigures":["Confucius"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"literary, but widely used in educational contexts and everyday speech","connotation":"positive","commonMistakes":"Learners sometimes use this idiom to mean simply 'reviewing old material' without the aspect of gaining new insights. It is important to emphasize the transformative learning aspect.","canStandAlone":false},"examples":[{"simplified":"老师常说，温故知新是学习的好方法。","english":"The teacher often says that reviewing old material to gain new insights is a good method of learning.","traditional":"老師常說，溫故知新是學習的好方法。"},{"simplified":"通过温故知新，他在工作中不断进步。","english":"By reviewing the old to know the new, he continuously makes progress in his work.","traditional":"通過溫故知新，他在工作中不斷進步。"}],"synonyms":["学而时习之"],"antonyms":[],"confusedWith":[{"id":"温故而知新","note":"This is a common variant of the idiom, but both carry the same meaning."}],"traditional":"溫故知新","pinyinOverride":null},{"id":"wu-bing-shen-yin","simplified":"无病呻吟","literalMeaning":"moaning without illness","figurativeMeaning":"to complain or grumble without real cause; to make a fuss over nothing","englishEquivalents":["making a mountain out of a molehill","crying wolf","much ado about nothing"],"shortGloss":"complaining without cause","characters":[{"char":"无","meaning":"without"},{"char":"病","meaning":"illness"},{"char":"呻","meaning":"moan"},{"char":"吟","meaning":"groan"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '无病呻吟' describes the act of complaining or expressing dissatisfaction without any real reason or cause. It suggests that the person is making unnecessary complaints, similar to someone moaning as if in pain when they are not actually sick. This idiom is often used to criticize people who exaggerate their problems or make a fuss over trivial matters.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"commonly used in both spoken and written Chinese to describe unnecessary complaints","connotation":"negative","commonMistakes":"Learners might confuse this idiom with phrases that describe genuine suffering or hardship. It's important to remember that '无病呻吟' specifically refers to complaining without a real cause.","canStandAlone":false},"examples":[{"simplified":"他总是无病呻吟，抱怨工作太累。","english":"He is always complaining without cause, grumbling that work is too tiring.","traditional":"他總是無病呻吟，抱怨工作太累。"},{"simplified":"不要无病呻吟，先看看事情的真实情况。","english":"Don't make a fuss over nothing; first, look at the real situation.","traditional":"不要無病呻吟，先看看事情的真實情況。"}],"synonyms":["小题大做"],"antonyms":["实事求是"],"confusedWith":[{"id":"庸人自扰","note":"While both idioms involve unnecessary worry, '庸人自扰' emphasizes self-inflicted worry, whereas '无病呻吟' focuses on complaining without cause."}],"traditional":"無病呻吟","pinyinOverride":null},{"id":"wu-ti-tou-di","simplified":"五体投地","literalMeaning":"five bodies cast to the ground","figurativeMeaning":"to show the utmost respect or admiration for someone","englishEquivalents":["prostrate oneself in admiration","bow down in reverence"],"shortGloss":"show utmost respect","characters":[{"char":"五","meaning":"five"},{"char":"体","meaning":"bodies"},{"char":"投","meaning":"cast"},{"char":"地","meaning":"ground"}],"origin":{"period":"Northern and Southern Dynasties (420–589 CE)","sourceText":"《梁书·韦叡传》","sourceTextEnglish":"Book of Liang, Biography of Wei Rui","originalExcerpt":"五体投地，诚心敬服。","storyEnglish":"The idiom originates from the Book of Liang, where it describes the act of showing complete submission and respect by prostrating oneself with all five parts of the body touching the ground. This was a gesture of utmost reverence and admiration, often used in a religious or highly respectful context.","historicalFigures":["Wei Rui"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"literary, but understood and sometimes used in formal speech","connotation":"positive","commonMistakes":"Learners might confuse this idiom with expressions of mere politeness. It implies a deep, almost reverential respect, not just ordinary courtesy.","canStandAlone":false},"examples":[{"simplified":"他对这位科学家的成就五体投地。","english":"He is in complete admiration of the scientist's achievements.","traditional":"他對這位科學家的成就五體投地。"},{"simplified":"她的演讲让所有人五体投地。","english":"Her speech left everyone in awe and admiration.","traditional":"她的演講讓所有人五體投地。"}],"synonyms":["顶礼膜拜"],"antonyms":["嗤之以鼻"],"confusedWith":[{"id":"顶礼膜拜","note":"Both express deep respect, but 五体投地 emphasizes physical prostration, while 顶礼膜拜 can be more metaphorical."}],"traditional":"五體投地","pinyinOverride":null},{"id":"xi-shi-ning-ren","simplified":"息事宁人","literalMeaning":"stop matters, make people peaceful","figurativeMeaning":"to make peace by resolving disputes; to calm things down","englishEquivalents":["let bygones be bygones","bury the hatchet","keep the peace"],"shortGloss":"make peace by resolving disputes","characters":[{"char":"息","meaning":"stop; cease"},{"char":"事","meaning":"matter; affair"},{"char":"宁","meaning":"make peaceful; calm"},{"char":"人","meaning":"people"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '息事宁人' is believed to have originated from the idea of resolving conflicts and calming tensions among people. It emphasizes the importance of stopping disputes to maintain harmony and peace. While the exact origin is unclear, it reflects a common cultural value of prioritizing peace over prolonged conflict.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"commonly used in both spoken and written Chinese, especially in contexts involving conflict resolution","connotation":"positive","commonMistakes":"Learners might confuse this idiom with expressions that imply ignoring problems rather than resolving them. '息事宁人' specifically involves taking action to calm and resolve issues, not just avoiding them.","canStandAlone":false},"examples":[{"simplified":"为了息事宁人，他决定主动道歉。","english":"To keep the peace, he decided to apologize first.","traditional":"為了息事寧人，他決定主動道歉。"},{"simplified":"在这种情况下，息事宁人是最好的选择。","english":"In this situation, making peace is the best choice.","traditional":"在這種情況下，息事寧人是最好的選擇。"}],"synonyms":["化干戈为玉帛"],"antonyms":["挑拨离间"],"confusedWith":[{"id":"得过且过","note":"While '息事宁人' involves actively resolving conflicts, '得过且过' implies a passive attitude of just getting by without addressing issues."}],"traditional":"息事寧人","pinyinOverride":null},{"id":"xiang-an-wu-shi","simplified":"相安无事","literalMeaning":"live together without incident","figurativeMeaning":"to live together in peace; to get along without conflict","englishEquivalents":["live in harmony","peaceful coexistence"],"shortGloss":"peaceful coexistence","characters":[{"char":"相","meaning":"mutually"},{"char":"安","meaning":"peace"},{"char":"无","meaning":"without"},{"char":"事","meaning":"incident"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '相安无事' describes a situation where people or groups live together peacefully without any conflicts or incidents. It is often used to describe harmonious relationships, whether in a family, community, or between nations.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"common in both spoken and written Chinese","connotation":"positive","commonMistakes":"Learners often confuse this idiom with similar ones that imply temporary peace rather than a stable, ongoing harmony. It's important to note that '相安无事' suggests a lasting peaceful coexistence.","canStandAlone":false},"examples":[{"simplified":"他们虽然性格不同，但一直相安无事。","english":"Although they have different personalities, they have always lived together in peace.","traditional":"他們雖然性格不同，但一直相安無事。"},{"simplified":"经过调解，这两个国家终于相安无事。","english":"After mediation, the two countries finally coexist peacefully.","traditional":"經過調解，這兩個國家終於相安無事。"}],"synonyms":["和睦相处"],"antonyms":["争吵不休","水火不容"],"confusedWith":[],"traditional":"相安無事","pinyinOverride":null},{"id":"xin-hui-yi-lan","simplified":"心灰意懒","literalMeaning":"heart is ash, intention is lazy","figurativeMeaning":"to feel disheartened and dispirited","englishEquivalents":["down in the dumps","disheartened","lost all hope"],"shortGloss":"disheartened and dispirited","characters":[{"char":"心","meaning":"heart; feelings"},{"char":"灰","meaning":"ash; disheartened"},{"char":"意","meaning":"intention; spirit"},{"char":"懒","meaning":"lazy; dispirited"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '心灰意懒' describes a state of being where one's heart feels like ash, symbolizing a loss of hope or enthusiasm, and one's intentions or spirit become lazy or dispirited. It is often used to describe someone who has experienced setbacks or disappointments and has lost motivation.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"coordinate","register":"widely used in both spoken and written Chinese","connotation":"negative","commonMistakes":"Learners might confuse this idiom with others that describe sadness or depression, but '心灰意懒' specifically emphasizes a loss of motivation and spirit, not just feeling sad.","canStandAlone":false},"examples":[{"simplified":"经历了这次失败，他感到心灰意懒。","english":"After experiencing this failure, he felt disheartened and dispirited.","traditional":"經歷了這次失敗，他感到心灰意懶。"},{"simplified":"她的心灰意懒让朋友们都很担心。","english":"Her disheartened and dispirited state worried her friends.","traditional":"她的心灰意懶讓朋友們都很擔心。"}],"synonyms":["垂头丧气","无精打采"],"antonyms":["斗志昂扬"],"confusedWith":[{"id":"垂头丧气","note":"While both describe a negative emotional state, '垂头丧气' emphasizes a physical demeanor of dejection, whereas '心灰意懒' focuses on a loss of motivation and spirit."}],"traditional":"心灰意懶","pinyinOverride":null},{"id":"xin-kuang-shen-yi","simplified":"心旷神怡","literalMeaning":"heart spacious spirit delighted","figurativeMeaning":"to feel relaxed and happy; to be in a carefree and joyful state","englishEquivalents":["at ease","in high spirits"],"shortGloss":"relaxed and happy","characters":[{"char":"心","meaning":"heart, mind"},{"char":"旷","meaning":"spacious, open"},{"char":"神","meaning":"spirit, mind"},{"char":"怡","meaning":"joyful, delighted"}],"origin":{"period":"Tang dynasty (618–907)","sourceText":"《晋书·谢安传》","sourceTextEnglish":"Book of Jin, Biography of Xie An","originalExcerpt":"安常乘小船游于江湖，心旷神怡，宠辱偕忘。","storyEnglish":"The idiom originates from the biography of Xie An, a famous statesman of the Eastern Jin dynasty. Xie An was known for his calm and composed demeanor. It is said that he would often take a small boat to enjoy the scenery of the rivers and lakes, during which he felt relaxed and happy, forgetting both honor and disgrace.","historicalFigures":["Xie An"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"coordinate","register":"literary, but widely used in both written and spoken Chinese","connotation":"positive","commonMistakes":"Learners might confuse this idiom with others that describe happiness or relaxation, but it specifically conveys a sense of being carefree and at ease, often in a natural setting.","canStandAlone":false},"examples":[{"simplified":"在山顶上，望着远处的风景，我感到心旷神怡。","english":"On the mountaintop, looking at the distant scenery, I felt relaxed and happy.","traditional":"在山頂上，望著遠處的風景，我感到心曠神怡。"},{"simplified":"听着轻音乐，他心旷神怡，忘却了所有烦恼。","english":"Listening to the soft music, he felt relaxed and happy, forgetting all his worries.","traditional":"聽著輕音樂，他心曠神怡，忘卻了所有煩惱。"}],"synonyms":["悠然自得","神清气爽"],"antonyms":[],"confusedWith":[{"id":"心花怒放","note":"心花怒放 means to be extremely happy or overjoyed, often in response to a specific event, while 心旷神怡 describes a more serene and relaxed joy."}],"traditional":"心曠神怡","pinyinOverride":null},{"id":"xin-kou-kai-he","simplified":"信口开河","literalMeaning":"speak casually and open a river","figurativeMeaning":"to speak carelessly or boastfully without thinking","englishEquivalents":["shoot one's mouth off","talk through one's hat"],"shortGloss":"speak carelessly or boastfully","characters":[{"char":"信","meaning":"casually, without thought"},{"char":"口","meaning":"mouth"},{"char":"开","meaning":"open"},{"char":"河","meaning":"river"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '信口开河' is believed to have originated from the idea of speaking without restraint, as if opening a river with one's mouth. It suggests that the words flow out uncontrollably, much like a river breaking its banks. This idiom is used to describe someone who talks without thinking, often making exaggerated or unfounded statements.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"informal, commonly used in both spoken and written Chinese","connotation":"negative","commonMistakes":"Learners often confuse this idiom with similar expressions that involve speaking, but '信口开河' specifically implies speaking without thinking or boasting. It should not be used to describe speaking eloquently or convincingly.","canStandAlone":false},"examples":[{"simplified":"他说话总是信口开河，不能完全相信。","english":"He always speaks carelessly, so you can't fully trust him.","traditional":"他說話總是信口開河，不能完全相信。"},{"simplified":"在重要场合，信口开河会让人觉得你不够专业。","english":"Speaking carelessly in important situations can make people think you're unprofessional.","traditional":"在重要場合，信口開河會讓人覺得你不夠專業。"}],"synonyms":["口无遮拦","胡言乱语"],"antonyms":["谨言慎行"],"confusedWith":[{"id":"口若悬河","note":"While '口若悬河' describes speaking fluently and eloquently, '信口开河' implies speaking carelessly or boastfully."}],"traditional":"信口開河","pinyinOverride":null},{"id":"xin-kou-ci-huang","simplified":"信口雌黄","literalMeaning":"speak carelessly, male yellow","figurativeMeaning":"to make irresponsible remarks; to speak without thinking","englishEquivalents":["shooting off at the mouth","talking through one's hat"],"shortGloss":"make irresponsible remarks","characters":[{"char":"信","meaning":"carelessly, without thought"},{"char":"口","meaning":"mouth, speak"},{"char":"雌","meaning":"female, but used here in a classical sense meaning 'false'"},{"char":"黄","meaning":"yellow, referring to the color of corrections made on documents"}],"origin":{"period":"Southern and Northern Dynasties (420–589)","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '信口雌黄' is said to originate from the practice of using yellow pigment to make corrections on official documents. The term '雌黄' refers to orpiment, a yellow mineral used for this purpose. Over time, the phrase came to describe someone who speaks carelessly or makes false statements, as if they were making hasty corrections without proper thought.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"literary, but understood and used in educated speech","connotation":"negative","commonMistakes":"Learners often confuse this idiom with others that involve speaking, such as '口若悬河', which means to speak eloquently. '信口雌黄' specifically implies speaking irresponsibly or falsely.","canStandAlone":false},"examples":[{"simplified":"他总是信口雌黄，不能相信他说的话。","english":"He always makes irresponsible remarks, so you can't trust what he says.","traditional":"他總是信口雌黃，不能相信他說的話。"},{"simplified":"在重要会议上，信口雌黄是不被允许的。","english":"Making irresponsible remarks is not allowed in important meetings.","traditional":"在重要會議上，信口雌黃是不被允許的。"}],"synonyms":["胡言乱语"],"antonyms":["实事求是"],"confusedWith":[{"id":"口若悬河","note":"While '口若悬河' means to speak eloquently, '信口雌黄' implies speaking carelessly or falsely."}],"traditional":"信口雌黃","pinyinOverride":null},{"id":"xu-xu-ru-sheng","simplified":"栩栩如生","literalMeaning":"vividly like life","figurativeMeaning":"lifelike; true to life; vividly realistic","englishEquivalents":["lifelike","true to life","vivid"],"shortGloss":"lifelike; vividly realistic","characters":[{"char":"栩","meaning":"vivid; lively"},{"char":"栩","meaning":"vivid; lively"},{"char":"如","meaning":"like; as if"},{"char":"生","meaning":"life; living"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '栩栩如生' is used to describe something that is so vividly depicted that it seems to come to life. It is often used in the context of art, literature, or descriptions that are exceptionally realistic.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"modifier-head","register":"commonly used in both written and spoken Chinese to describe art, literature, or performances","connotation":"positive","commonMistakes":"Learners might confuse this idiom with others that describe vividness or realism, but '栩栩如生' specifically emphasizes lifelikeness. It should not be used to describe abstract concepts.","canStandAlone":false},"examples":[{"simplified":"这幅画栩栩如生，仿佛人物要从画中走出来。","english":"This painting is so lifelike, it seems as if the figures are about to step out of the canvas.","traditional":"這幅畫栩栩如生，彷彿人物要從畫中走出來。"},{"simplified":"他的雕塑作品栩栩如生，吸引了很多游客。","english":"His sculptures are so lifelike that they attract many visitors.","traditional":"他的雕塑作品栩栩如生，吸引了很多遊客。"}],"synonyms":["惟妙惟肖"],"antonyms":[],"confusedWith":[{"id":"惟妙惟肖","note":"Both describe vivid realism, but '惟妙惟肖' emphasizes the skill and precision in imitation, while '栩栩如生' emphasizes lifelikeness."}],"traditional":"栩栩如生","pinyinOverride":null},{"id":"xuan-ya-le-ma","simplified":"悬崖勒马","literalMeaning":"rein in the horse at the edge of the cliff","figurativeMeaning":"to stop before it's too late; to pull back from the brink of disaster","englishEquivalents":["pull back from the brink","stop in the nick of time"],"shortGloss":"stop before it's too late","characters":[{"char":"悬","meaning":"hanging; suspended"},{"char":"崖","meaning":"cliff"},{"char":"勒","meaning":"to rein in; to pull back"},{"char":"马","meaning":"horse"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '悬崖勒马' is derived from the imagery of a rider pulling back on the reins of a horse just before it reaches the edge of a cliff, preventing a fall into disaster. It serves as a metaphor for recognizing a dangerous situation and taking action to avoid catastrophe.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"widely used in both spoken and written Chinese","connotation":"positive","commonMistakes":"Learners might confuse this idiom with others that involve stopping or preventing, but '悬崖勒马' specifically emphasizes stopping just in time to avoid disaster.","canStandAlone":false},"examples":[{"simplified":"在投资股票时，他及时悬崖勒马，避免了巨大的损失。","english":"When investing in stocks, he pulled back just in time and avoided a huge loss.","traditional":"在投資股票時，他及時懸崖勒馬，避免了巨大的損失。"},{"simplified":"如果我们不想后悔，现在就必须悬崖勒马。","english":"If we don't want to regret it, we must stop before it's too late.","traditional":"如果我們不想後悔，現在就必須懸崖勒馬。"}],"synonyms":["急流勇退","回头是岸"],"antonyms":[],"confusedWith":[{"id":"亡羊补牢","note":"While both idioms involve corrective actions, '亡羊补牢' refers to taking action after a mistake has been made, whereas '悬崖勒马' emphasizes stopping just in time to prevent disaster."}],"traditional":"懸崖勒馬","pinyinOverride":null},{"id":"xue-zu-shi-lu","simplified":"削足适履","literalMeaning":"cut foot to fit shoe","figurativeMeaning":"to force something to fit by inappropriate means; to act in a way that is counterproductive","englishEquivalents":["cutting off one's nose to spite one's face","forcing a square peg into a round hole"],"shortGloss":"forcing a fit by inappropriate means","characters":[{"char":"削","meaning":"to cut"},{"char":"足","meaning":"foot"},{"char":"适","meaning":"to fit"},{"char":"履","meaning":"shoe"}],"origin":{"period":"Warring States period (475–221 BCE)","sourceText":"《韩非子·外储说左上》","sourceTextEnglish":"Han Feizi, Outer Storage, Left Upper Section","originalExcerpt":"齐人有好履者，尝置之其坐。及去，忘之，已行，乃曰：“吾忘我履之坐矣。”反归取之，坐已失。乃曰：“吾忘我足之长短矣。”乃削其足以适其履。","storyEnglish":"In the Warring States period, there was a man from the state of Qi who loved shoes. One day, he left his shoes at his seat and forgot them. After walking some distance, he remembered and went back to find them, but they were gone. He then said, 'I have forgotten the length of my feet.' So, he cut his feet to fit the shoes he had left behind. This story illustrates the absurdity of forcing something to fit by inappropriate means.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["subject","predicate","object"],"structure":"verb-object","register":"literary, but widely understood and used in ordinary speech","connotation":"negative","commonMistakes":"Learners often confuse this idiom with others that involve 'fitting' or 'matching', but this idiom specifically implies an inappropriate or absurd method of achieving the fit.","canStandAlone":false},"examples":[{"simplified":"他为了赶上潮流，削足适履地改变自己的风格。","english":"In order to keep up with the trend, he absurdly changed his style to fit in.","traditional":"他為了趕上潮流，削足適履地改變自己的風格。"},{"simplified":"如果你硬要削足适履，结果只会适得其反。","english":"If you insist on forcing a fit, the result will only be counterproductive.","traditional":"如果你硬要削足適履，結果只會適得其反。"}],"synonyms":[],"antonyms":[],"confusedWith":[{"id":"刻舟求剑","note":"Both idioms involve inappropriate actions, but 刻舟求剑 refers to being inflexible and not adapting to change, while 削足适履 involves forcing a fit."}],"traditional":"削足適履","pinyinOverride":null},{"id":"xun-gen-jiu-di","simplified":"寻根究底","literalMeaning":"seek root investigate bottom","figurativeMeaning":"to get to the bottom of something; to investigate thoroughly","englishEquivalents":["get to the bottom of","dig deep","leave no stone unturned"],"shortGloss":"investigate thoroughly","characters":[{"char":"寻","meaning":"seek"},{"char":"根","meaning":"root"},{"char":"究","meaning":"investigate"},{"char":"底","meaning":"bottom"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '寻根究底' is used to describe the act of thoroughly investigating or probing into the details of a matter. It emphasizes the effort to understand the fundamental reasons or causes behind something. Although its exact origin is unclear, it reflects a common human desire to seek understanding and clarity.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["verb-object","adverbial"],"structure":"verb-object","register":"commonly used in both formal and informal contexts","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with others that suggest superficial investigation. '寻根究底' implies a thorough and deep investigation, not a cursory glance.","canStandAlone":false},"examples":[{"simplified":"他对每个问题都要寻根究底，直到找到答案为止。","english":"He has to get to the bottom of every issue until he finds the answer.","traditional":"他對每個問題都要尋根究底，直到找到答案為止。"},{"simplified":"在科学研究中，寻根究底是非常重要的。","english":"In scientific research, it is very important to investigate thoroughly.","traditional":"在科學研究中，尋根究底是非常重要的。"}],"synonyms":["刨根问底"],"antonyms":[],"confusedWith":[{"id":"走马观花","note":"走马观花 means to look at things superficially, unlike 寻根究底 which means to investigate thoroughly."}],"traditional":"尋根究底","pinyinOverride":null},{"id":"xun-xun-shan-you","simplified":"循循善诱","literalMeaning":"step by step good guidance","figurativeMeaning":"to guide someone skillfully and patiently","englishEquivalents":["lead by example","guide with skill and patience"],"shortGloss":"guide skillfully and patiently","characters":[{"char":"循","meaning":"step by step"},{"char":"循","meaning":"step by step"},{"char":"善","meaning":"good"},{"char":"诱","meaning":"to guide or lead"}],"origin":{"period":"Warring States period (475–221 BCE)","sourceText":"《论语·子罕》","sourceTextEnglish":"The Analects of Confucius, Zihan","originalExcerpt":"循循善诱，博我以文，约我以礼。","storyEnglish":"The idiom comes from 'The Analects of Confucius,' where it describes the teaching style of Confucius. He was known for his methodical and patient approach to teaching, guiding his students step by step, and using literature and rituals to broaden their understanding and discipline their behavior.","historicalFigures":["Confucius"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"coordinate","register":"literary, but very widely understood and used in ordinary speech","connotation":"positive","commonMistakes":"Learners sometimes confuse this idiom with those that imply forceful persuasion, but it specifically refers to gentle and skillful guidance.","canStandAlone":false},"examples":[{"simplified":"老师循循善诱地引导学生，帮助他们理解复杂的概念。","english":"The teacher skillfully and patiently guided the students, helping them understand complex concepts.","traditional":"老師循循善誘地引導學生，幫助他們理解複雜的概念。"},{"simplified":"在父母的循循善诱下，他逐渐学会了独立思考。","english":"Under the skillful and patient guidance of his parents, he gradually learned to think independently.","traditional":"在父母的循循善誘下，他逐漸學會了獨立思考。"}],"synonyms":["因材施教"],"antonyms":[],"confusedWith":[{"id":"威逼利诱","note":"威逼利诱 implies coercion and temptation, unlike the gentle guidance of 循循善诱."}],"traditional":"循循善誘","pinyinOverride":null},{"id":"ya-su-gong-shang","simplified":"雅俗共赏","literalMeaning":"elegant and vulgar together appreciate","figurativeMeaning":"something that appeals to both refined and common tastes","englishEquivalents":["appeals to all tastes","for both the highbrow and lowbrow","universally appealing"],"shortGloss":"appeals to all tastes","characters":[{"char":"雅","meaning":"elegant; refined"},{"char":"俗","meaning":"vulgar; common"},{"char":"共","meaning":"together"},{"char":"赏","meaning":"appreciate; enjoy"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '雅俗共赏' is used to describe works of art, literature, or entertainment that can be appreciated by both those with refined tastes and those with more common preferences. It emphasizes the universal appeal of certain creations that transcend social and cultural boundaries.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"modifier-head","register":"commonly used in both formal and informal contexts","connotation":"positive","commonMistakes":"Learners might mistakenly use this idiom to describe something that is only appreciated by one group. It specifically refers to things that appeal to both refined and common tastes.","canStandAlone":false},"examples":[{"simplified":"这部电影雅俗共赏，适合全家观看。","english":"This movie appeals to all tastes and is suitable for the whole family to watch.","traditional":"這部電影雅俗共賞，適合全家觀看。"},{"simplified":"他的作品雅俗共赏，深受观众喜爱。","english":"His works appeal to both refined and common tastes and are loved by audiences.","traditional":"他的作品雅俗共賞，深受觀眾喜愛。"}],"synonyms":[],"antonyms":[],"confusedWith":[],"traditional":"雅俗共賞","pinyinOverride":null},{"id":"yan-xing-yi-zhi","simplified":"言行一致","literalMeaning":"words and actions consistent","figurativeMeaning":"to act according to one's words; to be true to one's word","englishEquivalents":["practice what you preach","walk the talk"],"shortGloss":"actions match words","characters":[{"char":"言","meaning":"words; speech"},{"char":"行","meaning":"actions; deeds"},{"char":"一","meaning":"one; consistent"},{"char":"致","meaning":"consistent; in agreement"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '言行一致' emphasizes the importance of ensuring that one's actions are consistent with one's words. It is often used to praise individuals who demonstrate integrity and reliability by following through on their promises and commitments.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"modifier-head","register":"widely used in both formal and informal contexts","connotation":"positive","commonMistakes":"Learners sometimes confuse this idiom with '言而无信' (words without trust), which has a negative connotation. '言行一致' is positive and praises consistency between words and actions.","canStandAlone":false},"examples":[{"simplified":"他是一个言行一致的人，大家都很信任他。","english":"He is a person whose actions match his words, and everyone trusts him.","traditional":"他是一個言行一致的人，大家都很信任他。"},{"simplified":"领导要求员工做到言行一致，以提高公司的信誉。","english":"The leader requires employees to ensure their actions match their words to enhance the company's credibility.","traditional":"領導要求員工做到言行一致，以提高公司的信譽。"}],"synonyms":["表里如一"],"antonyms":["言而无信"],"confusedWith":[{"id":"言而无信","note":"言而无信 means 'words without trust', which implies unreliability, unlike 言行一致 which is positive."}],"traditional":"言行一致","pinyinOverride":null},{"id":"yang-zun-chu-you","simplified":"养尊处优","literalMeaning":"nurture respect, occupy comfort","figurativeMeaning":"to live in comfort and luxury, often with a sense of entitlement","englishEquivalents":["born with a silver spoon","live in the lap of luxury"],"shortGloss":"live in comfort and luxury","characters":[{"char":"养","meaning":"nurture; support"},{"char":"尊","meaning":"respect; honor"},{"char":"处","meaning":"occupy; dwell"},{"char":"优","meaning":"comfort; ease"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom 养尊处优 describes a lifestyle where one is surrounded by comfort and luxury, often implying a sense of entitlement or being accustomed to such a life without hardship. It is commonly used to describe someone who has been raised in a privileged environment.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"modifier-head","register":"commonly used in both written and spoken Chinese to describe a luxurious lifestyle","connotation":"neutral","commonMistakes":"Learners often confuse this idiom with those that imply laziness or idleness, but 养尊处优 specifically refers to living in luxury and comfort, not necessarily being inactive.","canStandAlone":false},"examples":[{"simplified":"他从小养尊处优，不知道生活的艰辛。","english":"He has lived in comfort and luxury since childhood and doesn't know the hardships of life.","traditional":"他從小養尊處優，不知道生活的艱辛。"},{"simplified":"在养尊处优的环境中长大，她很难适应艰苦的工作。","english":"Having grown up in a luxurious environment, she finds it difficult to adapt to hard work.","traditional":"在養尊處優的環境中長大，她很難適應艱苦的工作。"}],"synonyms":["锦衣玉食"],"antonyms":["艰苦朴素"],"confusedWith":[{"id":"好逸恶劳","note":"好逸恶劳 implies a dislike for work and a preference for ease, whereas 养尊处优 focuses on living in luxury."}],"traditional":"養尊處優","pinyinOverride":null},{"id":"yi-bai-tu-di","simplified":"一败涂地","literalMeaning":"complete defeat, ground covered with mud","figurativeMeaning":"to suffer a crushing defeat; to be utterly defeated","englishEquivalents":["to suffer a crushing defeat","to be utterly defeated"],"shortGloss":"to suffer a crushing defeat","characters":[{"char":"一","meaning":"complete, total"},{"char":"败","meaning":"defeat, failure"},{"char":"涂","meaning":"to smear, to cover"},{"char":"地","meaning":"ground, earth"}],"origin":{"period":"Han Dynasty (202 BCE – 220 CE)","sourceText":"《史记·淮阴侯列传》","sourceTextEnglish":"Records of the Grand Historian, Biography of Marquis of Huaiyin","originalExcerpt":"信乃使万人先行，出，击楚军，大破之，楚军一败涂地。","storyEnglish":"The idiom comes from the story of Han Xin, a famous general during the Han Dynasty. In a battle against the Chu forces, Han Xin devised a clever strategy that led to a decisive victory. The Chu army was utterly defeated, and the battlefield was described as being covered with the remnants of their defeat, leading to the expression '一败涂地'.","historicalFigures":["Han Xin"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"widely used in both formal and informal contexts","connotation":"negative","commonMistakes":"Learners often confuse this idiom with similar expressions of defeat, but '一败涂地' emphasizes the completeness and severity of the defeat. It should not be used for minor losses.","canStandAlone":false},"examples":[{"simplified":"在比赛中，我们的球队一败涂地。","english":"In the match, our team suffered a crushing defeat.","traditional":"在比賽中，我們的球隊一敗塗地。"},{"simplified":"他的生意计划失败了，结果是一败涂地。","english":"His business plan failed, resulting in a complete defeat.","traditional":"他的生意計劃失敗了，結果是一敗塗地。"}],"synonyms":["全军覆没","惨败"],"antonyms":["大获全胜"],"confusedWith":[{"id":"惨败","note":"While both mean defeat, '惨败' can refer to a disastrous defeat without necessarily implying the totality that '一败涂地' does."}],"traditional":"一敗塗地","pinyinOverride":null},{"id":"yi-fan-feng-shun","simplified":"一帆风顺","literalMeaning":"one sail, wind favorable","figurativeMeaning":"to proceed smoothly without any difficulties","englishEquivalents":["smooth sailing","everything goes smoothly"],"shortGloss":"smooth and trouble-free progress","characters":[{"char":"一","meaning":"one"},{"char":"帆","meaning":"sail"},{"char":"风","meaning":"wind"},{"char":"顺","meaning":"favorable"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom 一帆风顺 is believed to have originated from the imagery of a sailboat catching a favorable wind, allowing it to travel smoothly and swiftly. It is often used to wish someone success and a trouble-free journey, whether literal or metaphorical.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"modifier-head","register":"widely used in both formal and informal contexts, often in well-wishing","connotation":"positive","commonMistakes":"Learners might mistakenly use this idiom in contexts where difficulties are expected or unavoidable. It is best used when wishing for or describing an absence of obstacles.","canStandAlone":false},"examples":[{"simplified":"祝你们的旅途一帆风顺。","english":"I wish you a smooth and trouble-free journey.","traditional":"祝你們的旅途一帆風順。"},{"simplified":"希望新项目一帆风顺，取得成功。","english":"I hope the new project goes smoothly and succeeds.","traditional":"希望新項目一帆風順，取得成功。"}],"synonyms":["顺风顺水"],"antonyms":["波折不断"],"confusedWith":[{"id":"风平浪静","note":"风平浪静 refers specifically to calm weather conditions, not necessarily smooth progress in a task or journey."}],"traditional":"一帆風順","pinyinOverride":null},{"id":"yi-jian-ru-gu","simplified":"一见如故","literalMeaning":"at first sight, like old friends","figurativeMeaning":"to feel like old friends upon first meeting; to hit it off immediately","englishEquivalents":["love at first sight","click instantly","hit it off"],"shortGloss":"feel like old friends at first meeting","characters":[{"char":"一","meaning":"one"},{"char":"见","meaning":"meet"},{"char":"如","meaning":"like"},{"char":"故","meaning":"old (friend)"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '一见如故' describes the feeling of meeting someone for the first time and immediately feeling as if you have known them for a long time. It captures the sense of instant rapport and connection, as if two people are old friends reunited.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"commonly used in both spoken and written Chinese","connotation":"positive","commonMistakes":"Learners might confuse this idiom with '一见钟情' (love at first sight), which specifically refers to romantic attraction. '一见如故' is broader and can apply to friendships or any non-romantic relationships.","canStandAlone":false},"examples":[{"simplified":"他们第一次见面就一见如故，聊得非常开心。","english":"They hit it off immediately at their first meeting and had a great conversation.","traditional":"他們第一次見面就一見如故，聊得非常開心。"},{"simplified":"我和他一见如故，仿佛认识了很多年。","english":"He and I felt like old friends upon first meeting, as if we had known each other for years.","traditional":"我和他一見如故，彷彿認識了很多年。"}],"synonyms":["一见倾心"],"antonyms":[],"confusedWith":[{"id":"一见钟情","note":"一见钟情 refers specifically to falling in love at first sight, whereas 一见如故 is about general rapport and connection."}],"traditional":"一見如故","pinyinOverride":null},{"id":"yi-jue-bu-zhen","simplified":"一蹶不振","literalMeaning":"one fall not recover","figurativeMeaning":"to be unable to recover after a setback or failure","englishEquivalents":["down and out","unable to get back on one's feet"],"shortGloss":"unable to recover from a setback","characters":[{"char":"一","meaning":"one"},{"char":"蹶","meaning":"fall"},{"char":"不","meaning":"not"},{"char":"振","meaning":"recover"}],"origin":{"period":"Han Dynasty (206 BCE – 220 CE)","sourceText":"《史记·淮阴侯列传》","sourceTextEnglish":"Records of the Grand Historian, Biography of Marquis of Huaiyin","originalExcerpt":"淮阴侯韩信，虽一蹶不振，然犹能自振。","storyEnglish":"The idiom originates from the biography of Han Xin, a famous general of the Han Dynasty, in the 'Records of the Grand Historian' by Sima Qian. Despite facing setbacks and being unable to recover at one point, Han Xin eventually managed to regain his strength and position. The idiom is used to describe someone who, unlike Han Xin, fails to recover from a downfall.","historicalFigures":["Han Xin"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"widely used in both formal and informal contexts","connotation":"negative","commonMistakes":"Learners often confuse this idiom with similar expressions that imply recovery, but 一蹶不振 specifically means the inability to recover. It should not be used to describe temporary setbacks.","canStandAlone":false},"examples":[{"simplified":"他在生意失败后，一蹶不振，再也没有恢复过来。","english":"After his business failed, he was unable to recover and never got back on his feet.","traditional":"他在生意失敗後，一蹶不振，再也沒有恢復過來。"},{"simplified":"经历了那次挫折，她一蹶不振，失去了生活的动力。","english":"After experiencing that setback, she was unable to recover and lost her motivation in life.","traditional":"經歷了那次挫折，她一蹶不振，失去了生活的動力。"}],"synonyms":["一败涂地"],"antonyms":["东山再起"],"confusedWith":[{"id":"东山再起","note":"东山再起 means to make a comeback, which is the opposite of 一蹶不振."}],"traditional":"一蹶不振","pinyinOverride":null},{"id":"yi-lao-yong-yi","simplified":"一劳永逸","literalMeaning":"one effort forever benefit","figurativeMeaning":"to put in a great effort once to ensure lasting peace or benefit; to make a single, decisive effort to solve a problem once and for all","englishEquivalents":["nip it in the bud","once and for all"],"shortGloss":"solve a problem once and for all","characters":[{"char":"一","meaning":"one"},{"char":"劳","meaning":"effort"},{"char":"永","meaning":"forever"},{"char":"逸","meaning":"benefit"}],"origin":{"period":"Qing Dynasty (1644–1912)","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom suggests that by putting in a significant amount of effort at once, one can achieve a lasting solution or benefit. It is often used to describe actions or decisions that aim to resolve issues completely so that they do not recur.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["adverbial","complement"],"structure":"modifier-head","register":"widely used in both formal and informal contexts","connotation":"positive","commonMistakes":"Learners often confuse this idiom with those that imply ongoing effort rather than a single decisive action. It specifically refers to solving a problem once and for all, not to continuous effort.","canStandAlone":false},"examples":[{"simplified":"我们应该一劳永逸地解决这个问题。","english":"We should solve this problem once and for all.","traditional":"我們應該一勞永逸地解決這個問題。"},{"simplified":"他想找到一个一劳永逸的方法来管理时间。","english":"He wants to find a way to manage his time once and for all.","traditional":"他想找到一個一勞永逸的方法來管理時間。"}],"synonyms":[],"antonyms":[],"confusedWith":[{"id":"持之以恒","note":"一劳永逸 refers to a single decisive effort, while 持之以恒 means to persevere continuously."}],"traditional":"一勞永逸","pinyinOverride":null},{"id":"yi-luo-qian-zhang","simplified":"一落千丈","literalMeaning":"one drop a thousand zhang","figurativeMeaning":"to suffer a drastic decline or setback","englishEquivalents":["to fall off a cliff","to take a nosedive"],"shortGloss":"drastic decline","characters":[{"char":"一","meaning":"one"},{"char":"落","meaning":"fall"},{"char":"千","meaning":"thousand"},{"char":"丈","meaning":"zhang (a unit of length, about 3.3 meters)"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom 一落千丈 is often used to describe a situation where something experiences a sudden and significant decline, much like falling from a great height. The term 'zhang' is a traditional Chinese unit of length, emphasizing the severity of the drop.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","complement"],"structure":"verb-object","register":"commonly used in both written and spoken Chinese","connotation":"negative","commonMistakes":"Learners often confuse 一落千丈 with idioms that describe gradual decline. This idiom specifically implies a sudden and steep drop.","canStandAlone":false},"examples":[{"simplified":"他的成绩一落千丈，真让人担心。","english":"His grades have taken a nosedive, which is really concerning.","traditional":"他的成績一落千丈，真讓人擔心。"},{"simplified":"公司因为管理不善，业绩一落千丈。","english":"Due to poor management, the company's performance has plummeted.","traditional":"公司因為管理不善，業績一落千丈。"}],"synonyms":["江河日下","急转直下"],"antonyms":["蒸蒸日上"],"confusedWith":[{"id":"江河日下","note":"江河日下 implies a gradual decline, whereas 一落千丈 indicates a sudden drop."}],"traditional":"一落千丈","pinyinOverride":null},{"id":"yi-pu-shi-han","simplified":"一暴十寒","literalMeaning":"one day of sun, ten days of cold","figurativeMeaning":"to work hard for a short time but not persist; inconsistent effort","englishEquivalents":["one step forward, two steps back","fits and starts"],"shortGloss":"inconsistent effort","characters":[{"char":"一","meaning":"one"},{"char":"暴","meaning":"expose to the sun"},{"char":"十","meaning":"ten"},{"char":"寒","meaning":"cold"}],"origin":{"period":"Warring States period (475–221 BCE)","sourceText":"《孟子·告子上》","sourceTextEnglish":"Mencius, Gaozi I","originalExcerpt":"虽有天下易生之物也，一日暴之，十日寒之，未有能生者也。","storyEnglish":"This idiom comes from the teachings of Mencius, a famous Confucian philosopher. He used the metaphor of exposing plants to one day of sunlight followed by ten days of cold to illustrate the futility of inconsistent effort. Just as plants cannot thrive without consistent care, people cannot succeed without persistent effort.","historicalFigures":["Mencius"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"coordinate","register":"literary, but understood in educated speech","connotation":"negative","commonMistakes":"Learners often confuse this idiom with those that imply perseverance, but it actually highlights inconsistency and lack of persistence. It should not be used to describe consistent hard work.","canStandAlone":false},"examples":[{"simplified":"他学习总是一暴十寒，难怪成绩不好。","english":"He studies in fits and starts, no wonder his grades aren't good.","traditional":"他學習總是一暴十寒，難怪成績不好。"},{"simplified":"如果你一暴十寒地锻炼，效果不会好。","english":"If you exercise inconsistently, the results won't be good.","traditional":"如果你一暴十寒地鍛鍊，效果不會好。"}],"synonyms":[],"antonyms":["持之以恒"],"confusedWith":[{"id":"持之以恒","note":"持之以恒 means to persevere consistently, which is the opposite of 一暴十寒's meaning of inconsistency."}],"traditional":"一暴十寒","pinyinOverride":null},{"id":"yi-shi-tong-ren","simplified":"一视同仁","literalMeaning":"treat equally as same kind","figurativeMeaning":"to treat everyone equally without discrimination","englishEquivalents":["treat everyone equally","without discrimination"],"shortGloss":"treat everyone equally","characters":[{"char":"一","meaning":"one, same"},{"char":"视","meaning":"to view, to treat"},{"char":"同","meaning":"same, equal"},{"char":"仁","meaning":"benevolence, kindness"}],"origin":{"period":"Han Dynasty (202 BCE – 220 CE)","sourceText":"《后汉书·东平宪王苍传》","sourceTextEnglish":"Book of the Later Han, Biography of Dongping Xian Wang Cang","originalExcerpt":"务崇仁义，一视同仁。","storyEnglish":"The idiom comes from the 'Book of the Later Han', where it describes the conduct of Dongping Xian Wang Cang, a prince who was known for his benevolence and fairness. He was praised for treating all people with the same kindness and justice, without showing favoritism or discrimination.","historicalFigures":["Dongping Xian Wang Cang"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["adverbial","attributive"],"structure":"modifier-head","register":"widely used in both formal and informal contexts","connotation":"positive","commonMistakes":"Learners might confuse this idiom with others that involve fairness, but 一视同仁 specifically emphasizes equal treatment without bias. It is not about fairness in judgment or decision-making, but about equal treatment in social interactions.","canStandAlone":false},"examples":[{"simplified":"公司规定对所有员工一视同仁。","english":"The company policy is to treat all employees equally.","traditional":"公司規定對所有員工一視同仁。"},{"simplified":"老师对学生一视同仁，不会偏袒任何人。","english":"The teacher treats all students equally and does not show favoritism to anyone.","traditional":"老師對學生一視同仁，不會偏袒任何人。"}],"synonyms":["平等待人"],"antonyms":["厚此薄彼"],"confusedWith":[{"id":"一碗水端平","note":"一碗水端平 emphasizes fairness and impartiality in judgment, while 一视同仁 focuses on equal treatment."}],"traditional":"一視同仁","pinyinOverride":null},{"id":"yi-wang-da-jin","simplified":"一网打尽","literalMeaning":"one net capture all","figurativeMeaning":"to catch everything in one go; to capture everything in one fell swoop","englishEquivalents":["catch all in one go","sweep the board"],"shortGloss":"catch everything in one go","characters":[{"char":"一","meaning":"one"},{"char":"网","meaning":"net"},{"char":"打","meaning":"to hit; to capture"},{"char":"尽","meaning":"all; completely"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '一网打尽' originates from the idea of using a single net to capture all the fish in a pond or all the birds in a trap. It metaphorically describes a situation where one action or effort successfully captures or deals with everything or everyone involved.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","object","adverbial"],"structure":"verb-object","register":"commonly used in both written and spoken Chinese","connotation":"neutral","commonMistakes":"Learners often confuse this idiom with those that imply a more selective or gradual process. Unlike idioms that suggest a step-by-step approach, 一网打尽 implies a single, comprehensive action.","canStandAlone":false},"examples":[{"simplified":"警方在这次行动中将犯罪团伙一网打尽。","english":"The police captured the entire criminal gang in one fell swoop during this operation.","traditional":"警方在這次行動中將犯罪團伙一網打盡。"},{"simplified":"他计划通过这次收购一网打尽所有竞争对手。","english":"He plans to eliminate all competitors in one go through this acquisition.","traditional":"他計劃通過這次收購一網打盡所有競爭對手。"}],"synonyms":["一举歼灭","一举成名"],"antonyms":[],"confusedWith":[{"id":"逐个击破","note":"逐个击破 refers to dealing with things one by one, not all at once."}],"traditional":"一網打盡","pinyinOverride":null},{"id":"yi-yi-gu-xing","simplified":"一意孤行","literalMeaning":"single intention, act alone","figurativeMeaning":"to insist on doing things one's own way; to act willfully and disregard others' advice","englishEquivalents":["go one's own way","stick to one's guns","stubborn as a mule"],"shortGloss":"insist on one's own way","characters":[{"char":"一","meaning":"single; one"},{"char":"意","meaning":"intention; will"},{"char":"孤","meaning":"alone; solitary"},{"char":"行","meaning":"to act; to do"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom 一意孤行 describes a person who is determined to follow their own plans or ideas, regardless of advice or opposition from others. It conveys a sense of stubbornness and a refusal to consider alternative perspectives. The phrase is often used to criticize someone who is perceived as being inflexible or unwilling to compromise.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"commonly used in both written and spoken Chinese to describe stubborn or willful behavior","connotation":"negative","commonMistakes":"Learners often confuse 一意孤行 with idioms that imply determination or perseverance, but 一意孤行 specifically suggests a negative stubbornness and refusal to listen to others.","canStandAlone":false},"examples":[{"simplified":"他总是一意孤行，从不听别人的建议。","english":"He always insists on doing things his own way and never listens to others' advice.","traditional":"他總是一意孤行，從不聽別人的建議。"},{"simplified":"尽管大家反对，他还是一意孤行地做了决定。","english":"Despite everyone's objections, he still made the decision on his own.","traditional":"儘管大家反對，他還是一意孤行地做了決定。"}],"synonyms":["固执己见","独断专行"],"antonyms":["从善如流"],"confusedWith":[{"id":"坚持不懈","note":"坚持不懈 means to persevere and not give up, which has a positive connotation, unlike 一意孤行."}],"traditional":"一意孤行","pinyinOverride":null},{"id":"yi-zhi-ban-jie","simplified":"一知半解","literalMeaning":"one knowledge half understanding","figurativeMeaning":"to have a superficial understanding; to know only a little about something","englishEquivalents":["a little knowledge is a dangerous thing","know just enough to be dangerous"],"shortGloss":"superficial understanding","characters":[{"char":"一","meaning":"one"},{"char":"知","meaning":"knowledge"},{"char":"半","meaning":"half"},{"char":"解","meaning":"understanding"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom 一知半解 describes someone who has only a partial or superficial understanding of a subject. It is often used to caution against overconfidence in one's knowledge when it is incomplete. The phrase suggests that having a little knowledge can be misleading or even dangerous, as it may lead to incorrect conclusions or actions.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"coordinate","register":"commonly used in both spoken and written Chinese","connotation":"negative","commonMistakes":"Learners often misuse this idiom by applying it to situations where someone has no knowledge at all, rather than a superficial understanding. It is not synonymous with complete ignorance.","canStandAlone":false},"examples":[{"simplified":"他对这个问题只有一知半解，所以不能给出正确的答案。","english":"He only has a superficial understanding of this issue, so he can't provide the correct answer.","traditional":"他對這個問題只有一知半解，所以不能給出正確的答案。"},{"simplified":"如果你对某个领域只有一知半解，最好不要贸然发表意见。","english":"If you only have a superficial understanding of a field, it's best not to hastily express your opinions.","traditional":"如果你對某個領域只有一知半解，最好不要貿然發表意見。"}],"synonyms":["浅尝辄止"],"antonyms":["融会贯通"],"confusedWith":[{"id":"一窍不通","note":"一窍不通 means to know nothing at all, whereas 一知半解 implies having some, but incomplete, knowledge."}],"traditional":"一知半解","pinyinOverride":null},{"id":"yi-ya-huan-ya","simplified":"以牙还牙","literalMeaning":"use a tooth to return a tooth","figurativeMeaning":"to retaliate or take revenge in kind","englishEquivalents":["an eye for an eye","tit for tat"],"shortGloss":"retaliate in kind","characters":[{"char":"以","meaning":"use"},{"char":"牙","meaning":"tooth"},{"char":"还","meaning":"return"},{"char":"牙","meaning":"tooth"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '以牙还牙' is believed to have originated from the concept of retributive justice, similar to the 'eye for an eye' principle found in various ancient legal systems. It suggests that one should respond to harm or offense with an equivalent action, emphasizing equal retaliation.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"common in both spoken and written Chinese, understood in everyday contexts","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with '以牙还眼' (using a tooth to return an eye), which is not a standard idiom. It's important to remember that the idiom emphasizes equivalent retaliation, not disproportionate revenge.","canStandAlone":false},"examples":[{"simplified":"他对我不友好，我也以牙还牙。","english":"He was unfriendly to me, so I retaliated in kind.","traditional":"他對我不友好，我也以牙還牙。"},{"simplified":"在商业竞争中，有时需要以牙还牙。","english":"In business competition, sometimes you need to retaliate in kind.","traditional":"在商業競爭中，有時需要以牙還牙。"}],"synonyms":["针锋相对"],"antonyms":["以德报怨"],"confusedWith":[{"id":"以眼还眼","note":"This idiom is often confused due to its similarity, but '以眼还眼' is not a standard idiom in Chinese."}],"traditional":"以牙還牙","pinyinOverride":null},{"id":"yi-ru-fan-zhang","simplified":"易如反掌","literalMeaning":"easy as turning over one's palm","figurativeMeaning":"extremely easy to do","englishEquivalents":["as easy as pie","a piece of cake"],"shortGloss":"very easy","characters":[{"char":"易","meaning":"easy"},{"char":"如","meaning":"like; as if"},{"char":"反","meaning":"turn over"},{"char":"掌","meaning":"palm (of the hand)"}],"origin":{"period":"Han Dynasty (206 BCE – 220 CE)","sourceText":"《史记·平原君虞卿列传》","sourceTextEnglish":"Records of the Grand Historian, Biography of Pingyuan Jun and Yu Qing","originalExcerpt":"此易反掌耳。","storyEnglish":"The idiom comes from a passage in the 'Records of the Grand Historian' by Sima Qian. In the text, a task is described as being as easy as turning over one's palm, emphasizing its simplicity and effortlessness.","historicalFigures":["Sima Qian"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"modifier-head","register":"widely used in both formal and informal contexts","connotation":"positive","commonMistakes":"Learners might confuse this idiom with others that imply ease but have different nuances. For example, '轻而易举' also means easy but suggests simplicity in execution rather than inherent ease.","canStandAlone":false},"examples":[{"simplified":"这个问题对他来说易如反掌。","english":"This problem is as easy as pie for him.","traditional":"這個問題對他來說易如反掌。"},{"simplified":"她做这项工作易如反掌。","english":"She finds this task a piece of cake.","traditional":"她做這項工作易如反掌。"}],"synonyms":["轻而易举"],"antonyms":["难如登天"],"confusedWith":[{"id":"轻而易举","note":"Both mean easy, but '轻而易举' emphasizes ease in execution."}],"traditional":"易如反掌","pinyinOverride":null},{"id":"ying-ren-er-jie","simplified":"迎刃而解","literalMeaning":"meet the edge and resolve","figurativeMeaning":"to solve a problem with ease; to easily resolve a complex issue","englishEquivalents":["cut the Gordian knot","solve with ease"],"shortGloss":"solve a problem easily","characters":[{"char":"迎","meaning":"meet"},{"char":"刃","meaning":"edge of a blade"},{"char":"而","meaning":"and then"},{"char":"解","meaning":"solve; untangle"}],"origin":{"period":"Han Dynasty (206 BCE – 220 CE)","sourceText":"《后汉书·光武帝纪》","sourceTextEnglish":"Book of the Later Han, Annals of Emperor Guangwu","originalExcerpt":"事有迎刃而解者，亦有因循而难者。","storyEnglish":"The idiom comes from a passage in the 'Book of the Later Han', where it is used to describe how some problems can be easily solved, just like a knife cutting through bamboo. The idea is that once the first cut is made, the rest follows smoothly and effortlessly.","historicalFigures":["Emperor Guangwu"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"literary, but very widely understood and used in ordinary speech","connotation":"positive","commonMistakes":"Learners may confuse this idiom with others that imply difficulty or struggle in solving problems. It specifically refers to ease and smoothness in resolving issues.","canStandAlone":false},"examples":[{"simplified":"这个问题看似复杂，但其实可以迎刃而解。","english":"This problem seems complex, but it can actually be solved with ease.","traditional":"這個問題看似複雜，但其實可以迎刃而解。"},{"simplified":"只要找到关键，其他问题就能迎刃而解。","english":"As long as the key is found, other issues can be easily resolved.","traditional":"只要找到關鍵，其他問題就能迎刃而解。"}],"synonyms":["水到渠成"],"antonyms":["举步维艰"],"confusedWith":[{"id":"举步维艰","note":"迎刃而解 implies ease in solving problems, whereas 举步维艰 suggests difficulty and struggle."}],"traditional":"迎刃而解","pinyinOverride":null},{"id":"ying-jie-bu-xia","simplified":"应接不暇","literalMeaning":"respond and receive not leisure","figurativeMeaning":"to be overwhelmed with things to do; too busy to attend to all","englishEquivalents":["snowed under","overwhelmed","too much to handle"],"shortGloss":"overwhelmed with things to do","characters":[{"char":"应","meaning":"respond"},{"char":"接","meaning":"receive"},{"char":"不","meaning":"not"},{"char":"暇","meaning":"leisure"}],"origin":{"period":"Northern and Southern Dynasties (420–589)","sourceText":"《南史·王僧辩传》","sourceTextEnglish":"History of the Southern Dynasties, Biography of Wang Sengbian","originalExcerpt":"宾客迎来送往，应接不暇。","storyEnglish":"The idiom originates from the 'History of the Southern Dynasties', where it describes a situation in which Wang Sengbian, a prominent general and politician, was so busy with guests coming and going that he found it difficult to attend to all of them. This phrase vividly captures the feeling of being overwhelmed by too many tasks or responsibilities.","historicalFigures":["Wang Sengbian"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"commonly used in both written and spoken Chinese, suitable for formal and informal contexts","connotation":"neutral","commonMistakes":"Learners often confuse this idiom with '忙不过来', which also means being busy but lacks the nuance of being overwhelmed by a multitude of tasks or people. '应接不暇' implies a more intense level of busyness.","canStandAlone":false},"examples":[{"simplified":"节日期间，商场里顾客众多，店员们应接不暇。","english":"During the holiday season, the store was so crowded with customers that the staff were overwhelmed.","traditional":"節日期間，商場裡顧客眾多，店員們應接不暇。"},{"simplified":"新项目启动后，经理每天都应接不暇。","english":"After the new project launched, the manager was overwhelmed every day.","traditional":"新項目啟動後，經理每天都應接不暇。"}],"synonyms":["忙不过来"],"antonyms":[],"confusedWith":[{"id":"忙不过来","note":"Both mean being busy, but '应接不暇' implies being overwhelmed by too many tasks or people, whereas '忙不过来' is more general."}],"traditional":"應接不暇","pinyinOverride":null},{"id":"you-rou-gua-duan","simplified":"优柔寡断","literalMeaning":"gentle and indecisive","figurativeMeaning":"indecisive; unable to make decisions","englishEquivalents":["sitting on the fence","wishy-washy"],"shortGloss":"indecisive","characters":[{"char":"优","meaning":"gentle"},{"char":"柔","meaning":"soft"},{"char":"寡","meaning":"lacking"},{"char":"断","meaning":"decisiveness"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '优柔寡断' describes someone who is gentle and soft in their demeanor but lacks decisiveness. It is used to characterize individuals who struggle to make decisions promptly or firmly.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"modifier-head","register":"widely used in both spoken and written Chinese","connotation":"negative","commonMistakes":"Learners often confuse this idiom with ones that describe gentleness or kindness, but '优柔寡断' specifically emphasizes a lack of decisiveness. It should not be used to describe someone who is simply gentle or considerate.","canStandAlone":false},"examples":[{"simplified":"他做事总是优柔寡断，错过了很多机会。","english":"He is always indecisive, missing many opportunities.","traditional":"他做事總是優柔寡斷，錯過了很多機會。"},{"simplified":"在紧急情况下，优柔寡断可能会导致更大的问题。","english":"In emergency situations, indecisiveness can lead to bigger problems.","traditional":"在緊急情況下，優柔寡斷可能會導致更大的問題。"}],"synonyms":["犹豫不决"],"antonyms":["果断"],"confusedWith":[{"id":"优柔","note":"While '优柔' means gentle and soft, it does not carry the negative connotation of indecisiveness that '优柔寡断' does."}],"traditional":"優柔寡斷","pinyinOverride":null},{"id":"you-shou-hao-xian","simplified":"游手好闲","literalMeaning":"wandering hands, fond of leisure","figurativeMeaning":"to be idle and lazy; to avoid work","englishEquivalents":["idle hands are the devil's workshop","lazybones","couch potato"],"shortGloss":"idle and lazy","characters":[{"char":"游","meaning":"to wander"},{"char":"手","meaning":"hands"},{"char":"好","meaning":"fond of"},{"char":"闲","meaning":"leisure"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '游手好闲' describes someone who avoids work and prefers to spend their time in leisure. It paints a picture of a person whose hands are not engaged in productive work but are instead wandering aimlessly. This phrase is often used to criticize someone for being lazy or not contributing to society.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"modifier-head","register":"commonly used in both spoken and written Chinese, often with a negative connotation","connotation":"negative","commonMistakes":"Learners might confuse '游手好闲' with positive leisure-related idioms, but it specifically implies laziness and avoidance of work. It should not be used to describe someone who is simply enjoying a well-deserved rest.","canStandAlone":false},"examples":[{"simplified":"他整天游手好闲，不愿意找工作。","english":"He spends all day being idle and lazy, unwilling to find a job.","traditional":"他整天遊手好閒，不願意找工作。"},{"simplified":"游手好闲的人往往没有长远的计划。","english":"People who are idle and lazy often lack long-term plans.","traditional":"遊手好閒的人往往沒有長遠的計劃。"}],"synonyms":["无所事事","懒惰成性"],"antonyms":["勤劳致富","兢兢业业"],"confusedWith":[{"id":"悠然自得","note":"悠然自得 describes a state of being relaxed and content, without the negative connotation of laziness."}],"traditional":"遊手好閒","pinyinOverride":null},{"id":"you-mu-gong-du","simplified":"有目共睹","literalMeaning":"have eyes together witness","figurativeMeaning":"obvious to all; something that is evident and undeniable","englishEquivalents":["plain as day","clear as crystal","self-evident"],"shortGloss":"obvious to all","characters":[{"char":"有","meaning":"have"},{"char":"目","meaning":"eyes"},{"char":"共","meaning":"together"},{"char":"睹","meaning":"witness"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '有目共睹' is used to describe something that is so clear and evident that anyone who sees it can agree on its truth. It emphasizes the undeniable nature of a fact or situation, suggesting that it is as obvious as something witnessed by many people.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"modifier-head","register":"widely used in both formal and informal contexts","connotation":"neutral","commonMistakes":"Learners might confuse '有目共睹' with idioms that imply personal opinion rather than universal agreement. It's important to use this idiom only when the fact is undeniable and widely recognized.","canStandAlone":false},"examples":[{"simplified":"他的努力是有目共睹的，大家都很佩服他。","english":"His hard work is obvious to all, and everyone admires him.","traditional":"他的努力是有目共睹的，大家都很佩服他。"},{"simplified":"公司的业绩有目共睹，投资者们都很满意。","english":"The company's performance is evident to all, and the investors are very satisfied.","traditional":"公司的業績有目共睹，投資者們都很滿意。"}],"synonyms":["显而易见","不言而喻"],"antonyms":[],"confusedWith":[{"id":"众所周知","note":"While both idioms describe something widely recognized, '众所周知' emphasizes common knowledge, whereas '有目共睹' emphasizes visible evidence."}],"traditional":"有目共睹","pinyinOverride":null},{"id":"you-yong-wu-mou","simplified":"有勇无谋","literalMeaning":"have courage, lack strategy","figurativeMeaning":"brave but lacking in wisdom or strategy","englishEquivalents":["All brawn and no brains","Fools rush in where angels fear to tread"],"shortGloss":"brave but lacking strategy","characters":[{"char":"有","meaning":"have"},{"char":"勇","meaning":"courage"},{"char":"无","meaning":"without"},{"char":"谋","meaning":"strategy"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '有勇无谋' describes someone who is courageous but lacks the necessary wisdom or strategy to achieve success. It is often used to caution against acting rashly without proper planning or consideration of the consequences.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"coordinate","register":"commonly used in both spoken and written Chinese","connotation":"negative","commonMistakes":"Learners often confuse this idiom with '有勇有谋' (brave and strategic), which has a positive connotation. It's important to note that '无' indicates the absence of strategy, making it negative.","canStandAlone":false},"examples":[{"simplified":"他总是有勇无谋，结果常常吃亏。","english":"He is always brave but lacks strategy, which often leads to his disadvantage.","traditional":"他總是有勇無謀，結果常常吃虧。"},{"simplified":"在战场上，有勇无谋的人很容易失败。","english":"On the battlefield, those who are brave but lack strategy are likely to fail.","traditional":"在戰場上，有勇無謀的人很容易失敗。"}],"synonyms":[],"antonyms":["有勇有谋"],"confusedWith":[{"id":"有勇有谋","note":"This idiom means having both courage and strategy, which is positive, unlike '有勇无谋'."}],"traditional":"有勇無謀","pinyinOverride":null},{"id":"zhen-zhi-zhuo-jian","simplified":"真知灼见","literalMeaning":"true knowledge, penetrating insight","figurativeMeaning":"keen insight; profound knowledge and understanding","englishEquivalents":["keen insight","penetrating insight","profound understanding"],"shortGloss":"keen insight and understanding","characters":[{"char":"真","meaning":"true"},{"char":"知","meaning":"knowledge"},{"char":"灼","meaning":"penetrating"},{"char":"见","meaning":"insight"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '真知灼见' is often used to describe someone who has a deep and accurate understanding of a subject. The phrase emphasizes the combination of true knowledge and the ability to see things clearly and insightfully. It is not directly traceable to a specific classical text, but it has been widely used in Chinese literature and speech to commend someone's intellectual acuity.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["subject","predicate","object","attributive"],"structure":"coordinate","register":"widely used in both formal and informal contexts","connotation":"positive","commonMistakes":"Learners might confuse this idiom with others that imply general knowledge without the depth of insight. It specifically emphasizes both true understanding and the ability to perceive deeply.","canStandAlone":false},"examples":[{"simplified":"他的演讲充满了真知灼见，让人受益匪浅。","english":"His speech was full of keen insights, which greatly benefited the audience.","traditional":"他的演講充滿了真知灼見，讓人受益匪淺。"},{"simplified":"这本书提供了对社会问题的真知灼见。","english":"This book provides profound insights into social issues.","traditional":"這本書提供了對社會問題的真知灼見。"}],"synonyms":["高瞻远瞩","洞察秋毫"],"antonyms":["一知半解"],"confusedWith":[{"id":"一知半解","note":"一知半解 means having only a superficial understanding, unlike 真知灼见 which implies deep insight."}],"traditional":"真知灼見","pinyinOverride":null},{"id":"zheng-zheng-ri-shang","simplified":"蒸蒸日上","literalMeaning":"steaming day rising","figurativeMeaning":"to improve and become more prosperous day by day","englishEquivalents":["going from strength to strength","on the up and up"],"shortGloss":"growing more prosperous","characters":[{"char":"蒸","meaning":"steaming; rising"},{"char":"蒸","meaning":"steaming; rising"},{"char":"日","meaning":"day"},{"char":"上","meaning":"up; rising"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom 蒸蒸日上 is believed to have originated from the imagery of steam rising steadily, symbolizing continuous improvement and prosperity. It is often used to describe businesses, economies, or situations that are thriving and developing positively over time.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"modifier-head","register":"commonly used in both formal and informal contexts to describe positive growth","connotation":"positive","commonMistakes":"Learners might confuse this idiom with others that describe improvement, but 蒸蒸日上 specifically emphasizes steady and continuous progress. It is often used in contexts like business or economic growth.","canStandAlone":false},"examples":[{"simplified":"公司的业绩蒸蒸日上，老板非常满意。","english":"The company's performance is improving day by day, and the boss is very satisfied.","traditional":"公司的業績蒸蒸日上，老闆非常滿意。"},{"simplified":"经过多年的努力，他的事业终于蒸蒸日上。","english":"After years of hard work, his career is finally thriving.","traditional":"經過多年的努力，他的事業終於蒸蒸日上。"}],"synonyms":["欣欣向荣","日新月异"],"antonyms":["每况愈下"],"confusedWith":[{"id":"欣欣向荣","note":"Both describe positive growth, but 欣欣向荣 often refers to flourishing in a more general or natural sense."}],"traditional":"蒸蒸日上","pinyinOverride":null},{"id":"zhi-mi-bu-wu","simplified":"执迷不悟","literalMeaning":"persist in error, not awaken","figurativeMeaning":"to stubbornly persist in one's errors; to refuse to see reason","englishEquivalents":["stubbornly refuse to change","blindly persist in error"],"shortGloss":"stubbornly refuse to change","characters":[{"char":"执","meaning":"persist"},{"char":"迷","meaning":"error; delusion"},{"char":"不","meaning":"not"},{"char":"悟","meaning":"awaken; realize"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '执迷不悟' describes someone who stubbornly clings to their mistakes or wrong beliefs, refusing to acknowledge or correct them. It is often used to describe a person who is blind to the truth or unwilling to change their ways, despite clear evidence or advice to the contrary.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"modifier-head","register":"widely used in both spoken and written Chinese","connotation":"negative","commonMistakes":"Learners often confuse '执迷不悟' with '固执己见', which means to stubbornly hold onto one's own views. '执迷不悟' specifically emphasizes the refusal to acknowledge one's mistakes, while '固执己见' focuses on holding one's own opinions.","canStandAlone":false},"examples":[{"simplified":"他执迷不悟，总是不听别人的劝告。","english":"He stubbornly refuses to change and never listens to others' advice.","traditional":"他執迷不悟，總是不聽別人的勸告。"},{"simplified":"尽管事实摆在眼前，他还是执迷不悟。","english":"Despite the facts being right in front of him, he still stubbornly refuses to see reason.","traditional":"儘管事實擺在眼前，他還是執迷不悟。"}],"synonyms":["顽固不化","冥顽不灵"],"antonyms":["幡然醒悟"],"confusedWith":[{"id":"固执己见","note":"固执己见 means to stubbornly hold onto one's own views, while 执迷不悟 emphasizes refusal to acknowledge one's mistakes."}],"traditional":"執迷不悟","pinyinOverride":null},{"id":"zhi-gao-qi-yang","simplified":"趾高气扬","literalMeaning":"toes high, spirit raised","figurativeMeaning":"to be arrogant or conceited","englishEquivalents":["to walk with one's nose in the air","to be full of oneself"],"shortGloss":"arrogant and conceited","characters":[{"char":"趾","meaning":"toes"},{"char":"高","meaning":"high"},{"char":"气","meaning":"spirit"},{"char":"扬","meaning":"raised"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '趾高气扬' describes someone who walks with their toes pointed high and their spirit elevated, symbolizing arrogance and conceit. It is often used to describe people who are overly proud of themselves and look down on others.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"coordinate","register":"commonly used in both spoken and written Chinese","connotation":"negative","commonMistakes":"Learners often confuse this idiom with positive expressions of confidence. However, it specifically implies an undesirable level of arrogance.","canStandAlone":false},"examples":[{"simplified":"他最近升职了，走路都趾高气扬的。","english":"He got promoted recently and now walks around with his nose in the air.","traditional":"他最近升職了，走路都趾高氣揚的。"},{"simplified":"不要因为一点小成就就趾高气扬。","english":"Don't become arrogant just because of a small achievement.","traditional":"不要因為一點小成就就趾高氣揚。"}],"synonyms":["自高自大","目中无人"],"antonyms":["谦虚谨慎"],"confusedWith":[{"id":"自信满满","note":"自信满满 means 'full of confidence' and has a positive connotation, unlike 趾高气扬 which is negative."}],"traditional":"趾高氣揚","pinyinOverride":null},{"id":"zhi-tong-dao-he","simplified":"志同道合","literalMeaning":"aspirations same, paths join","figurativeMeaning":"to share the same ideals and follow the same path; to have a common goal","englishEquivalents":["like-minded","birds of a feather flock together"],"shortGloss":"like-minded; share common goals","characters":[{"char":"志","meaning":"aspirations; ambitions"},{"char":"同","meaning":"same; alike"},{"char":"道","meaning":"path; way"},{"char":"合","meaning":"join; unite"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '志同道合' is used to describe people who not only share the same ambitions or ideals but also follow the same path to achieve them. It emphasizes a deep level of agreement and unity in both thought and action. The origin of this idiom is not tied to a specific classical text, but it has been widely used in Chinese literature and speech to describe harmonious partnerships or friendships.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"coordinate","register":"commonly used in both spoken and written Chinese","connotation":"positive","commonMistakes":"Learners often confuse this idiom with others that imply mere agreement, but '志同道合' specifically emphasizes both shared ideals and a shared path. It is more than just agreeing on a topic; it implies a deeper connection.","canStandAlone":false},"examples":[{"simplified":"他们是志同道合的朋友，一起创业。","english":"They are like-minded friends who started a business together.","traditional":"他們是志同道合的朋友，一起創業。"},{"simplified":"在这个项目中，我们需要志同道合的团队成员。","english":"For this project, we need team members who share the same goals.","traditional":"在這個項目中，我們需要志同道合的團隊成員。"}],"synonyms":["同心协力","同舟共济"],"antonyms":["分道扬镳"],"confusedWith":[{"id":"同心协力","note":"While both imply cooperation, '同心协力' focuses more on working together with one heart and effort, rather than sharing the same ideals."}],"traditional":"志同道合","pinyinOverride":null},{"id":"zhi-zhi-bu-li","simplified":"置之不理","literalMeaning":"put aside and ignore","figurativeMeaning":"to ignore or pay no attention to something or someone","englishEquivalents":["turn a blind eye","ignore","pay no heed"],"shortGloss":"ignore or disregard","characters":[{"char":"置","meaning":"put, place"},{"char":"之","meaning":"it, this"},{"char":"不","meaning":"not"},{"char":"理","meaning":"pay attention to, manage"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '置之不理' is commonly used to describe a situation where someone deliberately ignores or refuses to engage with a person or issue. The phrase suggests a conscious decision to set something aside and not deal with it, often implying neglect or indifference.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","object"],"structure":"verb-object","register":"neutral and commonly used in both written and spoken Chinese","connotation":"negative","commonMistakes":"Learners might confuse this idiom with similar expressions that imply a more passive form of neglect, whereas '置之不理' suggests a deliberate choice to ignore. It should not be used for situations where the neglect is unintentional.","canStandAlone":false},"examples":[{"simplified":"他对我的建议置之不理。","english":"He ignored my suggestion.","traditional":"他對我的建議置之不理。"},{"simplified":"无论我怎么说，他都置之不理。","english":"No matter what I say, he pays no attention.","traditional":"無論我怎麼說，他都置之不理。"}],"synonyms":["视而不见","不闻不问"],"antonyms":["重视","关注"],"confusedWith":[{"id":"视而不见","note":"While both mean to ignore, '视而不见' implies seeing but pretending not to notice, whereas '置之不理' is more about actively choosing not to engage."}],"traditional":"置之不理","pinyinOverride":null},{"id":"zhong-yan-ni-er","simplified":"忠言逆耳","literalMeaning":"loyal words go against the ear","figurativeMeaning":"honest advice is hard to accept","englishEquivalents":["Truth hurts","Honest advice is unpleasant to hear"],"shortGloss":"honest advice is hard to accept","characters":[{"char":"忠","meaning":"loyal, honest"},{"char":"言","meaning":"words, speech"},{"char":"逆","meaning":"against, contrary"},{"char":"耳","meaning":"ear"}],"origin":{"period":"Eastern Han dynasty (25–220 CE)","sourceText":"《后汉书·卷三十六·梁统传》","sourceTextEnglish":"Book of the Later Han, Volume 36, Biography of Liang Tong","originalExcerpt":"忠言逆耳利于行，良药苦口利于病。","storyEnglish":"The idiom comes from the biography of Liang Tong in the 'Book of the Later Han'. It suggests that just as good medicine tastes bitter but cures illness, honest advice may be unpleasant to hear but is beneficial for one's actions. The saying emphasizes the value of accepting criticism and advice, even if it is difficult to hear.","historicalFigures":["Liang Tong"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["subject","predicate"],"structure":"subject-predicate","register":"literary, but commonly used in both written and spoken Chinese","connotation":"neutral","commonMistakes":"Learners often misinterpret this idiom as having a negative connotation, but it is neutral and emphasizes the value of honest advice. It is also sometimes confused with idioms that imply criticism without constructive intent.","canStandAlone":true},"examples":[{"simplified":"虽然忠言逆耳，但我们应该认真听取。","english":"Although honest advice is hard to accept, we should listen carefully.","traditional":"雖然忠言逆耳，但我們應該認真聽取。"},{"simplified":"他给了我一些忠言逆耳的建议，我决定采纳。","english":"He gave me some honest advice that was hard to hear, but I decided to take it.","traditional":"他給了我一些忠言逆耳的建議，我決定採納。"}],"synonyms":[],"antonyms":[],"confusedWith":[{"id":"良药苦口","note":"Both idioms emphasize the value of something unpleasant but beneficial, but '良药苦口' specifically refers to medicine and health."}],"traditional":"忠言逆耳","pinyinOverride":null},{"id":"zhuang-long-zuo-ya","simplified":"装聋作哑","literalMeaning":"pretend to be deaf and mute","figurativeMeaning":"to feign ignorance or pretend not to notice","englishEquivalents":["turn a blind eye","play dumb"],"shortGloss":"feign ignorance","characters":[{"char":"装","meaning":"pretend"},{"char":"聋","meaning":"deaf"},{"char":"作","meaning":"act as"},{"char":"哑","meaning":"mute"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '装聋作哑' describes someone who pretends to be unaware of a situation by acting as if they cannot hear or speak. This behavior is often used to avoid responsibility or involvement in a matter. The origin of this idiom is not tied to a specific classical text but is rather a common expression that has evolved over time.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"coordinate","register":"commonly used in both spoken and written Chinese","connotation":"negative","commonMistakes":"Learners sometimes confuse this idiom with similar expressions that imply genuine ignorance, but '装聋作哑' specifically involves intentional pretense. It is important to note the negative connotation of willful ignorance.","canStandAlone":false},"examples":[{"simplified":"他明明知道答案，却装聋作哑。","english":"He clearly knew the answer, yet he pretended not to hear or speak.","traditional":"他明明知道答案，卻裝聾作啞。"},{"simplified":"面对批评，他总是装聋作哑。","english":"When faced with criticism, he always plays dumb.","traditional":"面對批評，他總是裝聾作啞。"}],"synonyms":["视而不见","置若罔闻"],"antonyms":[],"confusedWith":[{"id":"不知不觉","note":"This idiom means 'unaware' or 'unconscious', without the implication of intentional pretense."}],"traditional":"裝聾作啞","pinyinOverride":null},{"id":"zi-bao-zi-qi","simplified":"自暴自弃","literalMeaning":"self-abandon self-give up","figurativeMeaning":"to give up on oneself and stop trying to improve","englishEquivalents":["give up on oneself","abandon oneself to despair"],"shortGloss":"to give up on oneself","characters":[{"char":"自","meaning":"self"},{"char":"暴","meaning":"expose"},{"char":"自","meaning":"self"},{"char":"弃","meaning":"abandon"}],"origin":{"period":"Warring States period (475–221 BCE)","sourceText":"《孟子·离娄上》","sourceTextEnglish":"Mencius, Li Lou I","originalExcerpt":"自暴者，不可与有言也；自弃者，不可与有为也。","storyEnglish":"The idiom comes from a passage in the book of Mencius, where it is said that those who give up on themselves cannot be reasoned with or helped to achieve anything. The idea is that self-abandonment leads to a lack of progress and improvement, as one has already decided to stop trying.","historicalFigures":["Mencius"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"coordinate","register":"literary, but very widely understood and used in ordinary speech","connotation":"negative","commonMistakes":"Learners might confuse this idiom with expressions that imply external abandonment rather than self-abandonment. It specifically refers to a person's own decision to give up on themselves.","canStandAlone":false},"examples":[{"simplified":"他最近情绪低落，几乎到了自暴自弃的地步。","english":"He has been feeling down lately, almost to the point of giving up on himself.","traditional":"他最近情緒低落，幾乎到了自暴自棄的地步。"},{"simplified":"我们不能因为一次失败就自暴自弃。","english":"We shouldn't give up on ourselves just because of one failure.","traditional":"我們不能因為一次失敗就自暴自棄。"}],"synonyms":["破罐破摔"],"antonyms":["自强不息"],"confusedWith":[{"id":"自甘堕落","note":"自甘堕落 implies willingly indulging in bad behavior, while 自暴自弃 focuses on giving up on self-improvement."}],"traditional":"自暴自棄","pinyinOverride":null},{"id":"zi-tou-luo-wang","simplified":"自投罗网","literalMeaning":"to throw oneself into a net","figurativeMeaning":"to walk right into a trap; to court disaster","englishEquivalents":["walk into a trap","court disaster"],"shortGloss":"to walk into a trap","characters":[{"char":"自","meaning":"oneself"},{"char":"投","meaning":"to throw; to cast"},{"char":"罗","meaning":"net"},{"char":"网","meaning":"net"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '自投罗网' describes a situation where someone unwittingly puts themselves in a position of danger or disadvantage, much like an animal that walks into a hunter's net. It is often used to describe someone who, through their own actions or decisions, ends up in a predicament they could have avoided.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","object"],"structure":"verb-object","register":"commonly used in both spoken and written Chinese","connotation":"negative","commonMistakes":"Learners often confuse this idiom with similar expressions that involve traps or danger, but '自投罗网' specifically implies voluntary or unwitting involvement in the trap. It should not be used for situations where the danger is imposed by others.","canStandAlone":false},"examples":[{"simplified":"他明知道那是个骗局，却还是自投罗网。","english":"He knew it was a scam, yet he still walked right into the trap.","traditional":"他明知道那是個騙局，卻還是自投羅網。"},{"simplified":"如果你不小心，这样做可能会让你自投罗网。","english":"If you're not careful, doing this might lead you to walk into a trap.","traditional":"如果你不小心，這樣做可能會讓你自投羅網。"}],"synonyms":["自取灭亡","引火烧身"],"antonyms":[],"confusedWith":[{"id":"引狼入室","note":"While '引狼入室' means inviting trouble by bringing in a dangerous element, '自投罗网' implies falling into a trap through one's own actions."}],"traditional":"自投羅網","pinyinOverride":null},{"id":"zuo-jing-guan-tian","simplified":"坐井观天","literalMeaning":"sit in a well and look at the sky","figurativeMeaning":"to have a narrow view or limited outlook","englishEquivalents":["frog in a well","limited perspective"],"shortGloss":"narrow-minded view","characters":[{"char":"坐","meaning":"sit"},{"char":"井","meaning":"well"},{"char":"观","meaning":"look at"},{"char":"天","meaning":"sky"}],"origin":{"period":"Han Dynasty (202 BCE – 220 CE)","sourceText":"《韩诗外传》","sourceTextEnglish":"Outer Commentary on the Han Poems","originalExcerpt":"井蛙不可以语于海者，拘于虚也；夏虫不可以语于冰者，笃于时也；曲士不可以语于道者，束于教也。","storyEnglish":"The idiom comes from a story about a frog living at the bottom of a well. The frog believed that the sky was only as big as the opening of the well. One day, a turtle from the sea visited and told the frog about the vastness of the ocean, but the frog couldn't comprehend it. This story illustrates how a limited perspective can prevent one from understanding the broader world.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"literary, but commonly used in both written and spoken Chinese","connotation":"negative","commonMistakes":"Learners may confuse this idiom with similar expressions that describe ignorance, but 坐井观天 specifically emphasizes a limited perspective due to one's environment or experiences.","canStandAlone":false},"examples":[{"simplified":"他总是坐井观天，无法理解外面的世界有多大。","english":"He always has a narrow view and can't understand how big the outside world is.","traditional":"他總是坐井觀天，無法理解外面的世界有多大。"},{"simplified":"如果你不多出去走走，就会像坐井观天的青蛙一样。","english":"If you don't go out more, you'll be like the frog in the well with a limited perspective.","traditional":"如果你不多出去走走，就會像坐井觀天的青蛙一樣。"}],"synonyms":["井底之蛙"],"antonyms":[],"confusedWith":[{"id":"井底之蛙","note":"Both idioms describe limited perspective, but 坐井观天 emphasizes the act of looking from a confined space."}],"traditional":"坐井觀天","pinyinOverride":null},{"id":"zuo-xiang-qi-cheng","simplified":"坐享其成","literalMeaning":"sit and enjoy its success","figurativeMeaning":"to enjoy the fruits of others' labor without contributing","englishEquivalents":["reap where one has not sown","freeload","ride on someone's coattails"],"shortGloss":"benefit without effort","characters":[{"char":"坐","meaning":"sit"},{"char":"享","meaning":"enjoy"},{"char":"其","meaning":"its"},{"char":"成","meaning":"success, achievement"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '坐享其成' describes a situation where someone benefits from the hard work or achievements of others without having contributed to the effort themselves. It is often used to criticize those who take advantage of others' labor without putting in any effort of their own.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"commonly used in both spoken and written Chinese, often with a negative connotation","connotation":"negative","commonMistakes":"Learners might confuse this idiom with positive expressions of teamwork or collaboration. However, it specifically implies benefiting without contributing.","canStandAlone":false},"examples":[{"simplified":"他总是坐享其成，从不愿意付出努力。","english":"He always reaps where he has not sown, never willing to put in the effort.","traditional":"他總是坐享其成，從不願意付出努力。"},{"simplified":"在这个项目中，我们不能让任何人坐享其成。","english":"In this project, we can't let anyone freeload.","traditional":"在這個項目中，我們不能讓任何人坐享其成。"}],"synonyms":["不劳而获"],"antonyms":["自力更生"],"confusedWith":[{"id":"同舟共济","note":"同舟共济 implies working together and sharing both efforts and rewards, unlike 坐享其成 which implies benefiting without effort."}],"traditional":"坐享其成","pinyinOverride":null},{"id":"ai-hong-bian-di","simplified":"哀鸿遍地","literalMeaning":"sorrowful cries of wild geese everywhere","figurativeMeaning":"a scene of widespread misery and desolation","englishEquivalents":["cries of despair everywhere","widespread misery"],"shortGloss":"widespread misery and desolation","characters":[{"char":"哀","meaning":"sorrowful"},{"char":"鸿","meaning":"wild geese"},{"char":"遍","meaning":"everywhere"},{"char":"地","meaning":"ground, place"}],"origin":{"period":"Tang Dynasty (618–907 CE)","sourceText":"《杜甫诗选·哀江头》","sourceTextEnglish":"Selected Poems of Du Fu, 'Lament at the Riverbank'","originalExcerpt":"哀鸿遍野，行人断肠。","storyEnglish":"The idiom originates from a poem by Du Fu, a famous Tang Dynasty poet. In his poem 'Lament at the Riverbank', Du Fu describes the desolate scene of refugees fleeing from war, comparing their cries to the mournful calls of wild geese. This vivid imagery captures the widespread suffering and despair of the people during times of turmoil.","historicalFigures":["Du Fu"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"subject-predicate","register":"literary, but understood in modern contexts to describe widespread suffering","connotation":"negative","commonMistakes":"Learners might confuse this idiom with expressions that describe personal sadness rather than widespread suffering. It specifically refers to a collective scene of misery, not individual grief.","canStandAlone":false},"examples":[{"simplified":"战争过后，村庄里哀鸿遍地，令人心痛。","english":"After the war, the village was a scene of widespread misery, which was heartbreaking.","traditional":"戰爭過後，村莊裡哀鴻遍地，令人心痛。"},{"simplified":"自然灾害使得整个地区哀鸿遍地，急需援助。","english":"The natural disaster left the entire region in widespread misery, urgently needing aid.","traditional":"自然災害使得整個地區哀鴻遍地，急需援助。"}],"synonyms":["民不聊生"],"antonyms":[],"confusedWith":[{"id":"哀声叹气","note":"哀声叹气 refers to sighing in sadness or disappointment, usually on a personal level, not widespread suffering."}],"traditional":"哀鴻遍地","pinyinOverride":null},{"id":"ai-sheng-tan-qi","simplified":"嗳声叹气","literalMeaning":"sighing and moaning","figurativeMeaning":"to sigh and moan in distress or frustration","englishEquivalents":["sighing and groaning","moaning and groaning"],"shortGloss":"sighing and moaning in distress","characters":[{"char":"嗳","meaning":"sigh"},{"char":"声","meaning":"sound"},{"char":"叹","meaning":"sigh"},{"char":"气","meaning":"breath"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '嗳声叹气' describes the act of sighing and moaning, often due to feelings of distress, frustration, or dissatisfaction. It is commonly used to depict someone who is visibly upset or troubled, expressing their emotions through audible sighs and groans.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"coordinate","register":"colloquial, commonly used in everyday speech","connotation":"negative","commonMistakes":"Learners often confuse this idiom with those that describe physical pain, but it specifically refers to emotional distress or frustration. It should not be used to describe physical ailments.","canStandAlone":false},"examples":[{"simplified":"他整天嗳声叹气，看来心情很不好。","english":"He has been sighing and moaning all day; it seems like he's in a bad mood.","traditional":"他整天噯聲嘆氣，看來心情很不好。"},{"simplified":"别再嗳声叹气了，问题总会有解决的办法。","english":"Stop sighing and moaning; there will always be a solution to the problem.","traditional":"別再噯聲嘆氣了，問題總會有解決的辦法。"}],"synonyms":[],"antonyms":[],"confusedWith":[],"traditional":"噯聲嘆氣","pinyinOverride":null},{"id":"ai-dong-shou-e","simplified":"挨冻受饿","literalMeaning":"suffer cold endure hunger","figurativeMeaning":"to endure hardship and deprivation, often due to poverty or difficult circumstances","englishEquivalents":["go hungry and cold","live in poverty","suffer hardship"],"shortGloss":"endure hardship and deprivation","characters":[{"char":"挨","meaning":"suffer, endure"},{"char":"冻","meaning":"cold, freezing"},{"char":"受","meaning":"suffer, endure"},{"char":"饿","meaning":"hunger, starvation"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '挨冻受饿' describes the experience of enduring severe hardship, particularly in terms of lacking basic necessities like warmth and food. It is often used to depict the struggles of those living in poverty or facing difficult circumstances where they must endure cold and hunger.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"coordinate","register":"commonly used in both spoken and written Chinese to describe hardship","connotation":"negative","commonMistakes":"Learners might confuse this idiom with others that describe hardship but do not specifically emphasize the aspects of cold and hunger. It's important to use it in contexts where these specific deprivations are relevant.","canStandAlone":false},"examples":[{"simplified":"他小时候家里很穷，经常挨冻受饿。","english":"When he was young, his family was very poor, and he often went hungry and cold.","traditional":"他小時候家裡很窮，經常挨凍受餓。"},{"simplified":"在战争期间，许多人都挨冻受饿。","english":"During the war, many people suffered from cold and hunger.","traditional":"在戰爭期間，許多人都挨凍受餓。"}],"synonyms":["饥寒交迫"],"antonyms":["丰衣足食"],"confusedWith":[{"id":"饥寒交迫","note":"Both idioms describe hardship, but '饥寒交迫' emphasizes being beset by both hunger and cold simultaneously."}],"traditional":"挨凍受餓","pinyinOverride":null},{"id":"ai-jian-ca-bei","simplified":"挨肩擦背","literalMeaning":"touch shoulder rub back","figurativeMeaning":"to be in close contact or proximity with someone","englishEquivalents":["rub shoulders","be in close quarters"],"shortGloss":"be in close contact","characters":[{"char":"挨","meaning":"touch"},{"char":"肩","meaning":"shoulder"},{"char":"擦","meaning":"rub"},{"char":"背","meaning":"back"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '挨肩擦背' describes a situation where people are in very close physical proximity to each other, such as in a crowded place. The imagery of touching shoulders and rubbing backs conveys the idea of being packed tightly together, often used to describe bustling urban environments or crowded events.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"commonly used in both spoken and written Chinese, informal contexts","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with expressions that imply physical affection or intimacy, but it primarily refers to physical proximity in crowded settings.","canStandAlone":false},"examples":[{"simplified":"在地铁上，人们挨肩擦背，几乎没有空间。","english":"On the subway, people were rubbing shoulders, with almost no space between them.","traditional":"在地鐵上，人們挨肩擦背，幾乎沒有空間。"},{"simplified":"节日的市场上，大家挨肩擦背，热闹非凡。","english":"At the festival market, everyone was in close quarters, creating a lively atmosphere.","traditional":"節日的市場上，大家挨肩擦背，熱鬧非凡。"}],"synonyms":["摩肩接踵"],"antonyms":[],"confusedWith":[{"id":"肩并肩","note":"肩并肩 (shoulder to shoulder) implies cooperation or solidarity, not just physical proximity."}],"traditional":"挨肩擦背","pinyinOverride":null},{"id":"ai-ren-guan-chang","simplified":"矮人观场","literalMeaning":"short person watching a performance","figurativeMeaning":"having a limited perspective or understanding due to one's position or viewpoint","englishEquivalents":["can't see the forest for the trees","limited viewpoint"],"shortGloss":"limited perspective","characters":[{"char":"矮","meaning":"short (in stature)"},{"char":"人","meaning":"person"},{"char":"观","meaning":"watch, observe"},{"char":"场","meaning":"performance, scene"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '矮人观场' metaphorically describes a situation where someone has a limited perspective or understanding, similar to how a short person might struggle to see a performance over the heads of others. It highlights the idea that one's viewpoint can be restricted by their position or circumstances.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["subject","predicate","object","attributive"],"structure":"modifier-head","register":"literary, but can be used in both formal and informal contexts","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with others that describe ignorance or lack of knowledge, but '矮人观场' specifically emphasizes limited perspective due to one's position rather than a lack of information.","canStandAlone":false},"examples":[{"simplified":"他对这个问题的看法就像矮人观场，缺乏全局视野。","english":"His view on this issue is like a short person watching a performance, lacking a comprehensive perspective.","traditional":"他對這個問題的看法就像矮人觀場，缺乏全局視野。"},{"simplified":"如果只从一个角度考虑问题，就像矮人观场，无法看到全貌。","english":"If you consider the problem from only one angle, it's like a short person watching a performance, unable to see the whole picture.","traditional":"如果只從一個角度考慮問題，就像矮人觀場，無法看到全貌。"}],"synonyms":["坐井观天"],"antonyms":[],"confusedWith":[{"id":"井底之蛙","note":"While both idioms describe limited perspective, '井底之蛙' emphasizes ignorance due to isolation, whereas '矮人观场' focuses on physical or situational limitations."}],"traditional":"矮人觀場","pinyinOverride":null},{"id":"ai-ren-kan-xi","simplified":"矮人看戏","literalMeaning":"a short person watching a play","figurativeMeaning":"to have a limited perspective or understanding due to one's position or circumstances","englishEquivalents":["can't see the forest for the trees"],"shortGloss":"limited perspective","characters":[{"char":"矮","meaning":"short (in height)"},{"char":"人","meaning":"person"},{"char":"看","meaning":"watch"},{"char":"戏","meaning":"play, drama"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"This idiom is based on the idea that a short person watching a play might have difficulty seeing the full performance due to their height. It metaphorically describes someone who cannot fully understand or appreciate a situation because of their limited viewpoint or experience.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["attributive","adverbial"],"structure":"modifier-head","register":"informal, used in both spoken and written Chinese","connotation":"negative","commonMistakes":"Learners might confuse this idiom with others that describe ignorance or lack of understanding, but this idiom specifically emphasizes the limitation due to one's position or circumstances, not a lack of intelligence.","canStandAlone":false},"examples":[{"simplified":"他对公司的运作就像矮人看戏，很多事情都看不清楚。","english":"He views the company's operations like a short person watching a play; he can't see many things clearly.","traditional":"他對公司的運作就像矮人看戲，很多事情都看不清楚。"},{"simplified":"如果不站在更高的角度看问题，就像矮人看戏，只能看到局部。","english":"If you don't look at the problem from a higher perspective, it's like a short person watching a play; you can only see part of it.","traditional":"如果不站在更高的角度看問題，就像矮人看戲，只能看到局部。"}],"synonyms":[],"antonyms":[],"confusedWith":[],"traditional":"矮人看戲","pinyinOverride":null},{"id":"ai-cai-ru-ming","simplified":"爱财如命","literalMeaning":"love money like life","figurativeMeaning":"to be extremely fond of money; to love money as much as one's own life","englishEquivalents":["money-grubber","penny-pincher"],"shortGloss":"extremely fond of money","characters":[{"char":"爱","meaning":"love"},{"char":"财","meaning":"wealth; money"},{"char":"如","meaning":"like; as if"},{"char":"命","meaning":"life"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '爱财如命' describes someone who is so fond of money that they treat it as importantly as their own life. It is often used to criticize someone who is excessively greedy or miserly.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"modifier-head","register":"commonly used in both spoken and written Chinese, often in a critical or humorous context","connotation":"negative","commonMistakes":"Learners might confuse this idiom with others that involve money, but this one specifically emphasizes an extreme attachment to money, almost to the point of obsession.","canStandAlone":false},"examples":[{"simplified":"他爱财如命，连一分钱都不愿意借给别人。","english":"He is so fond of money that he wouldn't even lend a single cent to others.","traditional":"他愛財如命，連一分錢都不願意借給別人。"},{"simplified":"她总是爱财如命，什么事情都要先考虑能不能赚钱。","english":"She always loves money as much as her life, considering whether something can make money before anything else.","traditional":"她總是愛財如命，什麼事情都要先考慮能不能賺錢。"}],"synonyms":["一毛不拔","财迷心窍"],"antonyms":["挥金如土","视金如土"],"confusedWith":[{"id":"一毛不拔","note":"While both idioms involve money, '一毛不拔' emphasizes stinginess, whereas '爱财如命' emphasizes an extreme fondness for money."}],"traditional":"愛財如命","pinyinOverride":null},{"id":"ai-cai-ruo-ke","simplified":"爱才若渴","literalMeaning":"love talent as if thirsty","figurativeMeaning":"to eagerly seek out and value talented individuals","englishEquivalents":["thirst for talent","talent scout"],"shortGloss":"eagerly seek talent","characters":[{"char":"爱","meaning":"love; cherish"},{"char":"才","meaning":"talent; talented people"},{"char":"若","meaning":"as if; like"},{"char":"渴","meaning":"thirsty"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom 爱才若渴 describes the attitude of someone who is eager to find and appreciate talented individuals, much like a person who is thirsty seeks water. It is often used to commend leaders or organizations that actively seek out and nurture talent.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"modifier-head","register":"commonly used in both formal and informal contexts","connotation":"positive","commonMistakes":"Learners may confuse this idiom with similar expressions that emphasize valuing talent without the sense of eagerness or urgency. It specifically conveys a strong desire to find and appreciate talent.","canStandAlone":false},"examples":[{"simplified":"这家公司一直以来都爱才若渴，吸引了很多优秀的人才。","english":"This company has always eagerly sought talent, attracting many outstanding individuals.","traditional":"這家公司一直以來都愛才若渴，吸引了很多優秀的人才。"},{"simplified":"领导者应该爱才若渴，才能带领团队走向成功。","english":"Leaders should eagerly seek out talent to lead their teams to success.","traditional":"領導者應該愛才若渴，才能帶領團隊走向成功。"}],"synonyms":[],"antonyms":[],"confusedWith":[],"traditional":"愛才若渴","pinyinOverride":null},{"id":"ai-fu-xian-pin","simplified":"爱富嫌贫","literalMeaning":"love the rich, dislike the poor","figurativeMeaning":"to favor the rich and disdain the poor; to be snobbish","englishEquivalents":["snobbery","to curry favor with the rich","to look down on the poor"],"shortGloss":"favor the rich, disdain the poor","characters":[{"char":"爱","meaning":"love; favor"},{"char":"富","meaning":"rich; wealthy"},{"char":"嫌","meaning":"dislike; disdain"},{"char":"贫","meaning":"poor; impoverished"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '爱富嫌贫' describes the behavior of people who show preference or admiration for those who are wealthy while looking down upon those who are less fortunate. This attitude is often criticized as being superficial and unjust.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"coordinate","register":"commonly used in both spoken and written Chinese to criticize snobbish behavior","connotation":"negative","commonMistakes":"Learners might confuse this idiom with others that involve wealth or poverty, but this one specifically emphasizes the act of favoring the rich while disdaining the poor.","canStandAlone":false},"examples":[{"simplified":"他总是爱富嫌贫，所以朋友不多。","english":"He always favors the rich and disdains the poor, so he doesn't have many friends.","traditional":"他總是愛富嫌貧，所以朋友不多。"},{"simplified":"在这个社会，爱富嫌贫的现象依然存在。","english":"In this society, the phenomenon of favoring the rich and disdaining the poor still exists.","traditional":"在這個社會，愛富嫌貧的現象依然存在。"}],"synonyms":["嫌贫爱富"],"antonyms":[],"confusedWith":[{"id":"嫌贫爱富","note":"The order of the characters is reversed, but the meaning is the same."}],"traditional":"愛富嫌貧","pinyinOverride":null},{"id":"an-fen-shou-ji","simplified":"安分守己","literalMeaning":"content with one's lot and keep oneself","figurativeMeaning":"to be content with one's position and behave oneself; to abide by the rules and not seek trouble","englishEquivalents":["keep to one's own business","mind one's own business","stay in one's lane"],"shortGloss":"content and law-abiding","characters":[{"char":"安","meaning":"content, peaceful"},{"char":"分","meaning":"one's lot, duty"},{"char":"守","meaning":"to guard, to keep"},{"char":"己","meaning":"oneself"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '安分守己' is believed to have originated from the idea of being satisfied with one's current situation and behaving in a manner that is consistent with societal norms. It emphasizes the virtues of contentment and self-discipline, encouraging individuals to focus on their own responsibilities and not to overreach or cause trouble.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"coordinate","register":"widely used in both formal and informal contexts","connotation":"positive","commonMistakes":"Learners might confuse this idiom with '安于现状', which implies being complacent with one's current situation without striving for improvement. '安分守己' specifically emphasizes behaving properly and not causing trouble.","canStandAlone":false},"examples":[{"simplified":"他是一个安分守己的人，从不惹是生非。","english":"He is a person who minds his own business and never stirs up trouble.","traditional":"他是一個安分守己的人，從不惹是生非。"},{"simplified":"在公司里，只要安分守己，就能平稳度日。","english":"In the company, as long as you keep to yourself and follow the rules, you can live steadily.","traditional":"在公司裡，只要安分守己，就能平穩度日。"}],"synonyms":["安于现状"],"antonyms":["惹是生非"],"confusedWith":[{"id":"安于现状","note":"While both involve contentment, '安于现状' suggests complacency, whereas '安分守己' emphasizes proper behavior and rule-following."}],"traditional":"安分守己","pinyinOverride":null},{"id":"an-jia-le-ye","simplified":"安家乐业","literalMeaning":"peaceful home joyful work","figurativeMeaning":"to live in peace and work happily","englishEquivalents":["live in peace and contentment","settle down happily"],"shortGloss":"live peacefully and work happily","characters":[{"char":"安","meaning":"peaceful"},{"char":"家","meaning":"home"},{"char":"乐","meaning":"joyful"},{"char":"业","meaning":"work"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '安家乐业' is used to describe a situation where people live peacefully and work happily, often after having settled down in a stable environment. It reflects a state of contentment and satisfaction with one's living and working conditions.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","object"],"structure":"coordinate","register":"commonly used in both formal and informal contexts","connotation":"positive","commonMistakes":"Learners sometimes confuse this idiom with others that involve '乐' (joy) but have different contexts, such as '乐不思蜀'. '安家乐业' specifically emphasizes both peaceful living and joyful working.","canStandAlone":false},"examples":[{"simplified":"他们在这个小镇安家乐业，过着幸福的生活。","english":"They live in peace and work happily in this small town, leading a happy life.","traditional":"他們在這個小鎮安家樂業，過著幸福的生活。"},{"simplified":"经过多年的努力，他们终于能够安家乐业。","english":"After many years of hard work, they can finally live in peace and work happily.","traditional":"經過多年的努力，他們終於能夠安家樂業。"}],"synonyms":["安居乐业"],"antonyms":[],"confusedWith":[{"id":"乐不思蜀","note":"While '乐不思蜀' refers to being so happy that one forgets their home, '安家乐业' emphasizes both peaceful living and joyful working."}],"traditional":"安家樂業","pinyinOverride":null},{"id":"an-ju-le-ye","simplified":"安居乐业","literalMeaning":"peaceful living, joyful working","figurativeMeaning":"to live and work in peace and contentment","englishEquivalents":["live in peace and work happily","a peaceful and prosperous life"],"shortGloss":"live and work in peace","characters":[{"char":"安","meaning":"peaceful"},{"char":"居","meaning":"live"},{"char":"乐","meaning":"joyful"},{"char":"业","meaning":"work"}],"origin":{"period":"Warring States period (475–221 BCE)","sourceText":"《老子》","sourceTextEnglish":"Laozi (Tao Te Ching)","originalExcerpt":"是以圣人方而不割，廉而不刿，直而不肆，光而不耀。安居乐业。","storyEnglish":"The phrase '安居乐业' is derived from the teachings of Laozi, a foundational figure in Taoism. It reflects the ideal state of society where people can live peacefully and work happily without disturbances. This concept emphasizes the importance of harmony and balance in life, which are central themes in Taoist philosophy.","historicalFigures":["Laozi"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"coordinate","register":"literary, but very widely understood and used in ordinary speech","connotation":"positive","commonMistakes":"Learners might confuse '安居乐业' with phrases that only emphasize peace or only emphasize work, but this idiom specifically conveys both living in peace and working happily. It should not be used to describe situations that are only peaceful or only prosperous.","canStandAlone":false},"examples":[{"simplified":"在这个国家，人们安居乐业，生活幸福。","english":"In this country, people live and work in peace and contentment, leading happy lives.","traditional":"在這個國家，人們安居樂業，生活幸福。"},{"simplified":"政府的目标是让所有公民都能安居乐业。","english":"The government's goal is for all citizens to live and work in peace and contentment.","traditional":"政府的目標是讓所有公民都能安居樂業。"}],"synonyms":["国泰民安"],"antonyms":["民不聊生"],"confusedWith":[{"id":"安然无恙","note":"While '安然无恙' means being safe and sound, '安居乐业' emphasizes both peaceful living and joyful working."}],"traditional":"安居樂業","pinyinOverride":null},{"id":"an-shen-ding-po","simplified":"安神定魄","literalMeaning":"calm the spirit and stabilize the soul","figurativeMeaning":"to calm one's nerves and stabilize one's emotions","englishEquivalents":["calm one's nerves","steady one's mind"],"shortGloss":"calm the nerves and emotions","characters":[{"char":"安","meaning":"calm"},{"char":"神","meaning":"spirit"},{"char":"定","meaning":"stabilize"},{"char":"魄","meaning":"soul"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '安神定魄' is often used to describe the process of calming one's nerves and stabilizing emotions, especially in stressful situations. It is believed to have originated from traditional Chinese medicine, where calming the spirit and stabilizing the soul are important for maintaining mental health.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","object"],"structure":"coordinate","register":"commonly used in both literary and spoken Chinese, especially in contexts related to mental health and well-being","connotation":"positive","commonMistakes":"Learners might confuse this idiom with others that involve calming or stabilizing, such as '心平气和', which specifically refers to maintaining a calm and even-tempered disposition. '安神定魄' is more about calming the nerves and emotions.","canStandAlone":false},"examples":[{"simplified":"在压力大的时候，我们应该学会安神定魄。","english":"In times of stress, we should learn to calm our nerves and stabilize our emotions.","traditional":"在壓力大的時候，我們應該學會安神定魄。"},{"simplified":"听音乐可以帮助我们安神定魄。","english":"Listening to music can help us calm our nerves and stabilize our emotions.","traditional":"聽音樂可以幫助我們安神定魄。"}],"synonyms":["心平气和"],"antonyms":[],"confusedWith":[{"id":"心平气和","note":"While '心平气和' focuses on maintaining a calm and even-tempered disposition, '安神定魄' is about calming the nerves and emotions."}],"traditional":"安神定魄","pinyinOverride":null},{"id":"an-du-chen-cang","simplified":"暗渡陈仓","literalMeaning":"secretly cross the Chen Cang","figurativeMeaning":"to carry out a plan under the guise of another; to feign one thing while doing another","englishEquivalents":["to make a feint to the east but attack in the west","to create a diversion"],"shortGloss":"to feign one thing while doing another","characters":[{"char":"暗","meaning":"secretly"},{"char":"渡","meaning":"cross"},{"char":"陈","meaning":"Chen"},{"char":"仓","meaning":"Cang"}],"origin":{"period":"Han Dynasty (206 BCE–220 CE)","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom originates from a historical event during the early Han Dynasty. After the fall of the Qin Dynasty, Liu Bang and Xiang Yu were vying for control over China. Liu Bang's strategist, Han Xin, devised a plan to distract Xiang Yu's forces by pretending to attack one location while secretly crossing the Chen Cang road to launch a surprise attack. This strategy was successful and helped Liu Bang gain an advantage. The idiom has since come to mean carrying out a plan under the guise of another.","historicalFigures":["Liu Bang","Han Xin","Xiang Yu"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"literary, but widely understood and used in ordinary speech","connotation":"neutral","commonMistakes":"Learners often confuse this idiom with similar ones that involve deception, but it specifically implies a strategic diversion rather than simple deceit.","canStandAlone":false},"examples":[{"simplified":"他用暗渡陈仓的策略成功地赢得了比赛。","english":"He used the strategy of 'secretly crossing the Chen Cang' to successfully win the match.","traditional":"他用暗渡陳倉的策略成功地贏得了比賽。"},{"simplified":"为了达成目标，公司采取了暗渡陈仓的方式。","english":"To achieve their goal, the company adopted a strategy of 'secretly crossing the Chen Cang'.","traditional":"為了達成目標，公司採取了暗渡陳倉的方式。"}],"synonyms":["声东击西"],"antonyms":[],"confusedWith":[{"id":"声东击西","note":"Both involve strategic deception, but 声东击西 emphasizes creating a diversion, while 暗渡陈仓 focuses on the secret execution of the plan."}],"traditional":"暗渡陳倉","pinyinOverride":null},{"id":"an-dan-wu-guang","simplified":"暗淡无光","literalMeaning":"dim and without light","figurativeMeaning":"dull and lackluster; lacking vitality or brilliance","englishEquivalents":["dull as dishwater","lackluster","uninspiring"],"shortGloss":"dull and lackluster","characters":[{"char":"暗","meaning":"dark"},{"char":"淡","meaning":"dim"},{"char":"无","meaning":"without"},{"char":"光","meaning":"light"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom 暗淡无光 is often used to describe something that lacks brightness or appeal, whether literally, like a dimly lit room, or figuratively, like a person's uninspired performance. It is a descriptive phrase that conveys a sense of dullness or lack of vitality.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"coordinate","register":"commonly used in both written and spoken Chinese","connotation":"negative","commonMistakes":"Learners might confuse 暗淡无光 with idioms that describe literal darkness rather than metaphorical dullness. It is important to use this idiom in contexts where lack of vitality or appeal is being described, not just physical darkness.","canStandAlone":false},"examples":[{"simplified":"他的演讲暗淡无光，没有打动观众。","english":"His speech was lackluster and failed to impress the audience.","traditional":"他的演講暗淡無光，沒有打動觀眾。"},{"simplified":"这幅画色彩暗淡无光，缺乏吸引力。","english":"The painting's colors are dull and lackluster, lacking appeal.","traditional":"這幅畫色彩暗淡無光，缺乏吸引力。"}],"synonyms":["黯然失色","平淡无奇"],"antonyms":["光彩夺目","绚丽多彩"],"confusedWith":[{"id":"黯然失色","note":"Both describe lack of brilliance, but 黯然失色 often implies being overshadowed by something else."}],"traditional":"暗淡無光","pinyinOverride":null},{"id":"an-ran-shen-shang","simplified":"黯然神伤","literalMeaning":"dark and spirit wounded","figurativeMeaning":"to feel deeply saddened or disheartened","englishEquivalents":["down in the dumps","heartbroken","crestfallen"],"shortGloss":"deeply saddened","characters":[{"char":"黯","meaning":"dark; gloomy"},{"char":"然","meaning":"in such a way; -ly"},{"char":"神","meaning":"spirit; mind"},{"char":"伤","meaning":"wounded; hurt"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '黯然神伤' is used to describe a state of deep sadness or emotional hurt. It conveys the image of someone's spirit being wounded, leaving them feeling gloomy and disheartened. The exact origin of this idiom is unclear, but it has been used in literature and spoken language to express profound sorrow.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"modifier-head","register":"commonly used in both written and spoken Chinese to express deep emotional sadness","connotation":"negative","commonMistakes":"Learners might confuse this idiom with others that express sadness but with different nuances, such as '心灰意冷' which implies a loss of hope. '黯然神伤' specifically emphasizes a deep emotional hurt.","canStandAlone":false},"examples":[{"simplified":"听到这个消息后，他黯然神伤，久久不能平静。","english":"After hearing the news, he was deeply saddened and couldn't calm down for a long time.","traditional":"聽到這個消息後，他黯然神傷，久久不能平靜。"},{"simplified":"她看着旧照片，黯然神伤，回忆起过去的时光。","english":"Looking at the old photos, she felt deeply saddened, reminiscing about the past.","traditional":"她看著舊照片，黯然神傷，回憶起過去的時光。"}],"synonyms":["心灰意冷","愁眉苦脸"],"antonyms":["喜笑颜开","心花怒放"],"confusedWith":[{"id":"心灰意冷","note":"While both express sadness, '心灰意冷' implies a loss of hope and motivation, whereas '黯然神伤' focuses on emotional hurt."}],"traditional":"黯然神傷","pinyinOverride":null},{"id":"an-ran-shi-se","simplified":"黯然失色","literalMeaning":"dimly lose color","figurativeMeaning":"to pale in comparison; to be overshadowed","englishEquivalents":["pale in comparison","overshadowed"],"shortGloss":"to pale in comparison","characters":[{"char":"黯","meaning":"dim; dark"},{"char":"然","meaning":"so; thus"},{"char":"失","meaning":"lose"},{"char":"色","meaning":"color"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '黯然失色' is often used to describe a situation where something or someone appears less impressive when compared to another. It conveys the idea of being overshadowed or outshone, much like how colors appear dull when placed next to something more vibrant.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"modifier-head","register":"widely used in both written and spoken Chinese","connotation":"negative","commonMistakes":"Learners often confuse this idiom with '光彩夺目', which means 'dazzling' or 'eye-catching'. '黯然失色' has a negative connotation, implying something is less impressive, while '光彩夺目' is positive.","canStandAlone":false},"examples":[{"simplified":"在她的光芒下，其他明星都黯然失色。","english":"Under her radiance, other stars all pale in comparison.","traditional":"在她的光芒下，其他明星都黯然失色。"},{"simplified":"这幅画在大师的作品旁显得黯然失色。","english":"This painting pales in comparison next to the master's work.","traditional":"這幅畫在大師的作品旁顯得黯然失色。"}],"synonyms":["相形见绌"],"antonyms":["光彩夺目"],"confusedWith":[{"id":"光彩夺目","note":"光彩夺目 means 'dazzling' or 'eye-catching', which is positive, unlike the negative connotation of 黯然失色."}],"traditional":"黯然失色","pinyinOverride":null},{"id":"an-ran-wu-se","simplified":"黯然无色","literalMeaning":"dark and without color","figurativeMeaning":"to feel dejected or dispirited; to lose one's luster","englishEquivalents":["down in the dumps","feel blue"],"shortGloss":"to feel dejected or dispirited","characters":[{"char":"黯","meaning":"dark, gloomy"},{"char":"然","meaning":"in such a manner"},{"char":"无","meaning":"without"},{"char":"色","meaning":"color, luster"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '黯然无色' is used to describe a state of feeling downcast or dispirited. It conveys the idea of losing one's brightness or vitality, much like a color that has faded or become dull. The exact origin of this idiom is uncertain, but it has been used in Chinese literature to describe a person's emotional state when they are feeling particularly low or defeated.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"modifier-head","register":"commonly used in both written and spoken Chinese","connotation":"negative","commonMistakes":"Learners often confuse this idiom with others that describe physical darkness or lack of color, but '黯然无色' specifically refers to an emotional state. It should not be used to describe literal colors or objects.","canStandAlone":false},"examples":[{"simplified":"听到这个消息后，他黯然无色，整个人都没有精神。","english":"After hearing the news, he was down in the dumps and completely dispirited.","traditional":"聽到這個消息後，他黯然無色，整個人都沒有精神。"},{"simplified":"比赛失败后，球队的士气黯然无色。","english":"After the loss, the team's morale was completely deflated.","traditional":"比賽失敗後，球隊的士氣黯然無色。"}],"synonyms":["垂头丧气","心灰意冷"],"antonyms":["神采奕奕","兴高采烈"],"confusedWith":[{"id":"黯然失色","note":"While '黯然无色' refers to feeling dejected, '黯然失色' means to lose one's brilliance or to be overshadowed by something else."}],"traditional":"黯然無色","pinyinOverride":null},{"id":"ang-tou-tian-wai","simplified":"昂头天外","literalMeaning":"raise head beyond the sky","figurativeMeaning":"to be ambitious or have lofty aspirations","englishEquivalents":["aim high","reach for the stars"],"shortGloss":"to have lofty ambitions","characters":[{"char":"昂","meaning":"raise"},{"char":"头","meaning":"head"},{"char":"天","meaning":"sky"},{"char":"外","meaning":"beyond"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '昂头天外' is used to describe someone who has high ambitions or aims for something beyond the ordinary. It evokes the image of someone looking up and beyond the sky, symbolizing their desire to achieve great things.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"modifier-head","register":"common in both written and spoken Chinese, often used in motivational contexts","connotation":"positive","commonMistakes":"Learners might confuse this idiom with those that imply arrogance or overconfidence. '昂头天外' specifically refers to having high aspirations, not necessarily overestimating one's abilities.","canStandAlone":false},"examples":[{"simplified":"他从小就昂头天外，希望有一天能成为一名宇航员。","english":"Since childhood, he has aimed high, hoping to become an astronaut one day.","traditional":"他從小就昂頭天外，希望有一天能成為一名宇航員。"},{"simplified":"在这个项目中，我们需要昂头天外，才能取得突破性的进展。","english":"In this project, we need to aim high to achieve a breakthrough.","traditional":"在這個項目中，我們需要昂頭天外，才能取得突破性的進展。"}],"synonyms":["志存高远"],"antonyms":["安于现状"],"confusedWith":[{"id":"自高自大","note":"While '昂头天外' refers to having high aspirations, '自高自大' implies arrogance and overestimating oneself."}],"traditional":"昂頭天外","pinyinOverride":null},{"id":"ao-ya-ji-kou","simplified":"聱牙戟口","literalMeaning":"awkward teeth, halberd mouth","figurativeMeaning":"difficult to pronounce or awkward in speech","englishEquivalents":["tongue-twister"],"shortGloss":"awkward or difficult to pronounce","characters":[{"char":"聱","meaning":"awkward"},{"char":"牙","meaning":"teeth"},{"char":"戟","meaning":"halberd"},{"char":"口","meaning":"mouth"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom is used to describe language or text that is difficult to pronounce or awkward to read aloud. It evokes the image of words that are as challenging to navigate as a mouth full of awkward teeth or a mouth armed with a halberd.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["attributive","adverbial"],"structure":"coordinate","register":"literary, but can be used in both formal and informal contexts","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with those that describe difficult content rather than difficult pronunciation. It specifically refers to the phonetic challenge, not the complexity of ideas.","canStandAlone":false},"examples":[{"simplified":"这段文字聱牙戟口，读起来很费劲。","english":"This passage is difficult to pronounce and awkward to read.","traditional":"這段文字聱牙戟口，讀起來很費勁。"},{"simplified":"他写的诗总是聱牙戟口，让人难以朗诵。","english":"His poems are always awkward and difficult to recite.","traditional":"他寫的詩總是聱牙戟口，讓人難以朗誦。"}],"synonyms":[],"antonyms":[],"confusedWith":[],"traditional":"聱牙戟口","pinyinOverride":null},{"id":"ao-ya-jie-qu","simplified":"聱牙诘屈","literalMeaning":"difficult teeth, twisted and bent","figurativeMeaning":"difficult to read or understand due to complex language or structure","englishEquivalents":["hard to read","convoluted","dense"],"shortGloss":"difficult or convoluted language","characters":[{"char":"聱","meaning":"difficult, awkward"},{"char":"牙","meaning":"teeth, used here to imply difficulty"},{"char":"诘","meaning":"twisted, intricate"},{"char":"屈","meaning":"bent, curved"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '聱牙诘屈' is used to describe language or writing that is difficult to read or understand due to its complexity or convoluted structure. The imagery of 'awkward teeth' and 'twisted and bent' conveys the sense of struggling through challenging text.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["attributive","adverbial"],"structure":"coordinate","register":"literary, but can be used in formal speech to critique writing style","connotation":"negative","commonMistakes":"Learners often confuse this idiom with ones that describe physical difficulty or awkwardness, but it specifically refers to language or writing. It is not used to describe physical actions.","canStandAlone":false},"examples":[{"simplified":"这篇文章太聱牙诘屈了，我读了好几遍才明白。","english":"This article is so convoluted that I had to read it several times to understand.","traditional":"這篇文章太聱牙詰屈了，我讀了好幾遍才明白。"},{"simplified":"他的演讲虽然内容丰富，但语言聱牙诘屈，听众很难理解。","english":"Although his speech was rich in content, the language was convoluted, making it difficult for the audience to understand.","traditional":"他的演講雖然內容豐富，但語言聱牙詰屈，聽眾很難理解。"}],"synonyms":["晦涩难懂"],"antonyms":["浅显易懂"],"confusedWith":[{"id":"晦涩难懂","note":"Both describe difficult language, but '晦涩难懂' emphasizes obscurity, while '聱牙诘屈' emphasizes convoluted structure."}],"traditional":"聱牙詰屈","pinyinOverride":null},{"id":"ao-man-wu-li","simplified":"傲慢无礼","literalMeaning":"arrogant and without manners","figurativeMeaning":"arrogant and rude; displaying a lack of respect and courtesy","englishEquivalents":["high and mighty","rude and disrespectful"],"shortGloss":"arrogant and rude","characters":[{"char":"傲","meaning":"arrogant"},{"char":"慢","meaning":"slow; here it implies arrogance"},{"char":"无","meaning":"without"},{"char":"礼","meaning":"manners; courtesy"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '傲慢无礼' is used to describe someone who behaves in an arrogant and disrespectful manner, lacking the courtesy expected in social interactions. It is often used to criticize individuals who act superior and disregard the feelings or status of others.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"coordinate","register":"commonly used in both spoken and written Chinese to criticize someone's behavior","connotation":"negative","commonMistakes":"Learners often confuse this idiom with similar expressions that describe arrogance but do not emphasize the lack of manners. It's important to note that '无礼' specifically refers to being rude or discourteous.","canStandAlone":false},"examples":[{"simplified":"他对长辈傲慢无礼，让人很不舒服。","english":"He was arrogant and rude to the elders, making everyone uncomfortable.","traditional":"他對長輩傲慢無禮，讓人很不舒服。"},{"simplified":"她的傲慢无礼让同事们都不愿意和她合作。","english":"Her arrogance and rudeness made her colleagues unwilling to work with her.","traditional":"她的傲慢無禮讓同事們都不願意和她合作。"}],"synonyms":["目中无人","盛气凌人"],"antonyms":["谦虚有礼"],"confusedWith":[{"id":"目中无人","note":"Both describe arrogance, but '目中无人' emphasizes ignoring others, not necessarily being rude."}],"traditional":"傲慢無禮","pinyinOverride":null},{"id":"ao-ni-yi-qie","simplified":"傲睨一切","literalMeaning":"arrogantly look down on everything","figurativeMeaning":"to look down on everything with arrogance; to be disdainful and condescending","englishEquivalents":["look down one's nose at","high and mighty"],"shortGloss":"arrogantly disdainful","characters":[{"char":"傲","meaning":"arrogant"},{"char":"睨","meaning":"to look askance"},{"char":"一","meaning":"one; everything"},{"char":"切","meaning":"all; everything"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom describes a person who looks down on everything and everyone around them with arrogance and disdain. It conveys a sense of superiority and condescension, often used to criticize someone who behaves as if they are above others.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"modifier-head","register":"literary, but can be used in both formal and informal contexts to describe someone's attitude","connotation":"negative","commonMistakes":"Learners may confuse this idiom with others that describe confidence or self-assuredness, but '傲睨一切' specifically implies a negative, disdainful attitude. It should not be used to describe positive self-confidence.","canStandAlone":false},"examples":[{"simplified":"他总是傲睨一切，不愿听取别人的意见。","english":"He always looks down on everything, unwilling to listen to others' opinions.","traditional":"他總是傲睨一切，不願聽取別人的意見。"},{"simplified":"她以傲睨一切的态度面对同事，结果没有人愿意与她合作。","english":"She faced her colleagues with an arrogantly disdainful attitude, and as a result, no one wanted to work with her.","traditional":"她以傲睨一切的態度面對同事，結果沒有人願意與她合作。"}],"synonyms":["目中无人"],"antonyms":["虚怀若谷"],"confusedWith":[{"id":"目中无人","note":"Both imply arrogance, but '目中无人' focuses more on ignoring others, while '傲睨一切' emphasizes a disdainful attitude towards everything."}],"traditional":"傲睨一切","pinyinOverride":null},{"id":"ao-shi-qing-wu","simplified":"傲世轻物","literalMeaning":"proud of the world, disdainful of things","figurativeMeaning":"to be arrogant and disdainful, looking down on everything and everyone","englishEquivalents":["look down one's nose at","high and mighty"],"shortGloss":"arrogant and disdainful","characters":[{"char":"傲","meaning":"proud, arrogant"},{"char":"世","meaning":"world, society"},{"char":"轻","meaning":"disdain, look down upon"},{"char":"物","meaning":"things, people"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '傲世轻物' describes someone who is so proud and self-satisfied that they look down on the world and everything in it. This attitude of arrogance and disdain can alienate others and is generally seen as a negative trait.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"coordinate","register":"literary, but understood in educated speech","connotation":"negative","commonMistakes":"Learners often confuse this idiom with similar ones that describe confidence or pride without the negative connotation of disdain. It's important to note the negative judgment implied by '轻物'.","canStandAlone":false},"examples":[{"simplified":"他总是傲世轻物，难怪没有朋友。","english":"He is always so arrogant and disdainful, no wonder he has no friends.","traditional":"他總是傲世輕物，難怪沒有朋友。"},{"simplified":"她的傲世轻物态度让同事们很不满。","english":"Her arrogant and disdainful attitude made her colleagues very unhappy.","traditional":"她的傲世輕物態度讓同事們很不滿。"}],"synonyms":["目中无人"],"antonyms":["谦虚谨慎"],"confusedWith":[{"id":"目中无人","note":"Both describe arrogance, but '目中无人' specifically means disregarding others, while '傲世轻物' includes disdain for things as well."}],"traditional":"傲世輕物","pinyinOverride":null},{"id":"ai-ai-yu-jue","simplified":"哀哀欲绝","literalMeaning":"grief-stricken to the point of breaking","figurativeMeaning":"overwhelmed with grief; inconsolable","englishEquivalents":["heartbroken","devastated","inconsolable"],"shortGloss":"overwhelmed with grief","characters":[{"char":"哀","meaning":"sorrowful"},{"char":"哀","meaning":"sorrowful"},{"char":"欲","meaning":"about to; almost"},{"char":"绝","meaning":"break; end"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom describes a state of profound grief, so intense that it feels as though one's heart or spirit is about to break. It is often used to describe someone who is mourning a great loss, such as the death of a loved one.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","complement"],"structure":"subject-predicate","register":"literary, but can be used in emotional contexts in speech","connotation":"negative","commonMistakes":"Learners might confuse this idiom with expressions that simply mean 'sad' or 'unhappy'. It specifically conveys an extreme level of grief, not just ordinary sadness.","canStandAlone":false},"examples":[{"simplified":"听到这个消息，她哀哀欲绝，无法自已。","english":"Upon hearing the news, she was inconsolable and couldn't control herself.","traditional":"聽到這個消息，她哀哀欲絕，無法自已。"},{"simplified":"他失去了心爱的宠物，哀哀欲绝。","english":"He was heartbroken after losing his beloved pet.","traditional":"他失去了心愛的寵物，哀哀欲絕。"}],"synonyms":["悲痛欲绝","痛不欲生"],"antonyms":[],"confusedWith":[{"id":"悲痛欲绝","note":"Both express deep sorrow, but 哀哀欲绝 emphasizes the overwhelming nature of the grief."}],"traditional":"哀哀欲絕","pinyinOverride":null},{"id":"ai-bing-bi-sheng","simplified":"哀兵必胜","literalMeaning":"sorrowful soldiers surely win","figurativeMeaning":"those who fight with a just cause or righteous indignation are sure to win","englishEquivalents":["Righteous indignation leads to victory","Moral high ground wins the battle"],"shortGloss":"righteous cause ensures victory","characters":[{"char":"哀","meaning":"sorrowful; grieving"},{"char":"兵","meaning":"soldiers; troops"},{"char":"必","meaning":"surely; certainly"},{"char":"胜","meaning":"win; victory"}],"origin":{"period":"Warring States period (475–221 BCE)","sourceText":"《孙子兵法·谋攻》","sourceTextEnglish":"The Art of War by Sun Tzu, Chapter: Attack by Stratagem","originalExcerpt":"故哀兵必胜。","storyEnglish":"In Sun Tzu's 'The Art of War', it is stated that soldiers who are driven by a sense of righteousness or who have suffered injustice are often more motivated and determined, leading them to victory. The idea is that when soldiers are fighting for a just cause, their morale and resolve are stronger, making them more likely to succeed.","historicalFigures":["Sun Tzu"],"relatedIdiomsFromSameSource":["知己知彼，百战不殆","兵贵神速"]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"subject-predicate","register":"literary, but widely understood and used in both formal and informal contexts","connotation":"positive","commonMistakes":"Learners sometimes misinterpret this idiom as suggesting that sadness or despair alone leads to victory, rather than understanding it as the moral strength derived from a just cause.","canStandAlone":false},"examples":[{"simplified":"在这场战斗中，哀兵必胜，因为他们是为了正义而战。","english":"In this battle, those with a just cause are sure to win, because they fight for justice.","traditional":"在這場戰鬥中，哀兵必勝，因為他們是為了正義而戰。"},{"simplified":"历史证明，哀兵必胜，正义的力量不可小觑。","english":"History has proven that those with a righteous cause are sure to win; the power of justice should not be underestimated.","traditional":"歷史證明，哀兵必勝，正義的力量不可小覷。"}],"synonyms":["正义必胜"],"antonyms":["骄兵必败"],"confusedWith":[{"id":"骄兵必败","note":"While '哀兵必胜' emphasizes victory through righteousness, '骄兵必败' warns that arrogance leads to defeat."}],"traditional":"哀兵必勝","pinyinOverride":null},{"id":"ai-si-ru-chao","simplified":"哀思如潮","literalMeaning":"grief like a tide","figurativeMeaning":"overwhelmed with grief; grief surging like a tide","englishEquivalents":["grief-stricken","overcome with sorrow"],"shortGloss":"overwhelmed with grief","characters":[{"char":"哀","meaning":"grief, sorrow"},{"char":"思","meaning":"thoughts, feelings"},{"char":"如","meaning":"like, as"},{"char":"潮","meaning":"tide, wave"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '哀思如潮' is used to describe a state of being overwhelmed by grief, as if one's sorrow is surging like a tide. It is often used in contexts of mourning or deep personal loss, capturing the intense and uncontrollable nature of such emotions.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"subject-predicate","register":"literary, but can be used in both formal writing and spoken language","connotation":"negative","commonMistakes":"Learners might confuse this idiom with expressions that describe less intense emotions. It's important to use it in contexts of deep and overwhelming grief, not just mild sadness.","canStandAlone":false},"examples":[{"simplified":"听到他去世的消息，我的哀思如潮。","english":"Upon hearing the news of his death, I was overwhelmed with grief.","traditional":"聽到他去世的消息，我的哀思如潮。"},{"simplified":"在葬礼上，大家的哀思如潮，无法自已。","english":"At the funeral, everyone's grief surged like a tide, uncontrollable.","traditional":"在葬禮上，大家的哀思如潮，無法自已。"}],"synonyms":["悲痛欲绝","痛不欲生"],"antonyms":[],"confusedWith":[{"id":"悲痛欲绝","note":"While both express deep sorrow, '悲痛欲绝' emphasizes being heartbroken to the point of despair, whereas '哀思如潮' focuses on the overwhelming nature of grief."}],"traditional":"哀思如潮","pinyinOverride":null},{"id":"ai-tong-yu-jue","simplified":"哀痛欲绝","literalMeaning":"grief and pain almost to the point of breaking","figurativeMeaning":"overwhelmed with grief; heartbroken","englishEquivalents":["heartbroken","grief-stricken"],"shortGloss":"overwhelmed with grief","characters":[{"char":"哀","meaning":"grief"},{"char":"痛","meaning":"pain"},{"char":"欲","meaning":"almost"},{"char":"绝","meaning":"to break; to end"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '哀痛欲绝' describes a state of being so overwhelmed by grief and sorrow that one feels as if they might break or be unable to continue. It is often used to express the deep emotional pain experienced after a significant loss, such as the death of a loved one.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","complement"],"structure":"modifier-head","register":"literary, but can be used in both formal and informal contexts to express deep sorrow","connotation":"negative","commonMistakes":"Learners may confuse this idiom with similar expressions of sadness, but '哀痛欲绝' specifically conveys an extreme level of grief, beyond ordinary sadness.","canStandAlone":false},"examples":[{"simplified":"听到这个消息后，她哀痛欲绝，无法自已。","english":"Upon hearing the news, she was overwhelmed with grief and couldn't control herself.","traditional":"聽到這個消息後，她哀痛欲絕，無法自已。"},{"simplified":"他的去世让家人哀痛欲绝。","english":"His passing left the family heartbroken.","traditional":"他的去世讓家人哀痛欲絕。"}],"synonyms":["悲痛欲绝"],"antonyms":[],"confusedWith":[{"id":"悲痛欲绝","note":"Both express extreme grief, but '哀痛欲绝' emphasizes the overwhelming nature of the sorrow."}],"traditional":"哀痛欲絕","pinyinOverride":null},{"id":"ai-jian-da-bei","simplified":"挨肩搭背","literalMeaning":"press shoulder and touch back","figurativeMeaning":"to be very close to each other; to be in close contact","englishEquivalents":["shoulder to shoulder","in close proximity","cheek by jowl"],"shortGloss":"in close contact","characters":[{"char":"挨","meaning":"press closely"},{"char":"肩","meaning":"shoulder"},{"char":"搭","meaning":"touch"},{"char":"背","meaning":"back"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '挨肩搭背' describes a situation where people are physically very close to each other, as if their shoulders and backs are touching. It is often used to describe crowded places or situations where people are in close proximity.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["adverbial","attributive"],"structure":"coordinate","register":"commonly used in both spoken and written Chinese to describe crowded situations","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with expressions that imply emotional closeness rather than physical proximity. It specifically refers to physical closeness.","canStandAlone":false},"examples":[{"simplified":"地铁上人很多，大家挨肩搭背地站着。","english":"There were many people on the subway, standing shoulder to shoulder.","traditional":"地鐵上人很多，大家挨肩搭背地站著。"},{"simplified":"在演唱会现场，观众们挨肩搭背，气氛热烈。","english":"At the concert, the audience was packed closely together, creating an enthusiastic atmosphere.","traditional":"在演唱會現場，觀眾們挨肩搭背，氣氛熱烈。"}],"synonyms":["肩摩踵接","人山人海"],"antonyms":[],"confusedWith":[{"id":"亲密无间","note":"亲密无间 refers to emotional closeness and intimacy, not physical proximity."}],"traditional":"挨肩搭背","pinyinOverride":null},{"id":"ai-men-zhu-hu","simplified":"挨门逐户","literalMeaning":"go to each door, approach each household","figurativeMeaning":"to go from door to door, usually in the context of canvassing, soliciting, or searching","englishEquivalents":["go door to door","canvass","solicit door-to-door"],"shortGloss":"go door to door","characters":[{"char":"挨","meaning":"approach, go to"},{"char":"门","meaning":"door"},{"char":"逐","meaning":"one by one, successively"},{"char":"户","meaning":"household"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '挨门逐户' describes the action of going from one household to the next, typically for the purpose of canvassing, soliciting, or searching. It is often used in contexts where someone is systematically visiting each house in an area, such as salespeople, political canvassers, or census takers.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["adverbial"],"structure":"verb-object + verb-object","register":"commonly used in both formal and informal contexts","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with similar expressions that imply a more forceful or intrusive action. '挨门逐户' is neutral and simply describes the methodical nature of the action.","canStandAlone":false},"examples":[{"simplified":"为了推销新产品，他挨门逐户地拜访邻居。","english":"To promote the new product, he went door to door visiting neighbors.","traditional":"為了推銷新產品，他挨門逐戶地拜訪鄰居。"},{"simplified":"志愿者们挨门逐户地分发传单。","english":"The volunteers distributed flyers from door to door.","traditional":"志願者們挨門逐戶地分發傳單。"}],"synonyms":[],"antonyms":[],"confusedWith":[],"traditional":"挨門逐戶","pinyinOverride":null},{"id":"ai-ren-kan-chang","simplified":"矮人看场","literalMeaning":"a short person watching a field","figurativeMeaning":"to have a limited perspective or to be unable to see the whole picture","englishEquivalents":["can't see the forest for the trees"],"shortGloss":"limited perspective","characters":[{"char":"矮","meaning":"short (in stature)"},{"char":"人","meaning":"person"},{"char":"看","meaning":"to watch"},{"char":"场","meaning":"field"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom describes a situation where a short person is tasked with watching over a large field. Due to their limited height, they cannot see the entire field, symbolizing a limited perspective or inability to grasp the full scope of a situation.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"verb-object","register":"informal, used in conversational Chinese to describe someone's limited viewpoint","connotation":"negative","commonMistakes":"Learners might confuse this idiom with expressions that imply physical limitations rather than metaphorical ones. It specifically refers to a lack of comprehensive understanding.","canStandAlone":false},"examples":[{"simplified":"他总是矮人看场，无法理解整个计划。","english":"He always has a limited perspective and can't understand the whole plan.","traditional":"他總是矮人看場，無法理解整個計劃。"},{"simplified":"在这个问题上，你不能矮人看场，要从长远考虑。","english":"On this issue, you can't have a limited perspective; you need to think long-term.","traditional":"在這個問題上，你不能矮人看場，要從長遠考慮。"}],"synonyms":[],"antonyms":["高瞻远瞩"],"confusedWith":[{"id":"井底之蛙","note":"Both idioms describe limited perspective, but 井底之蛙 emphasizes ignorance due to isolation, while 矮人看场 highlights inability to see the whole picture."}],"traditional":"矮人看場","pinyinOverride":null},{"id":"ai-bu-ren-shi","simplified":"爱不忍释","literalMeaning":"love it too much to let go","figurativeMeaning":"to be so fond of something that one cannot bear to part with it","englishEquivalents":["can't put it down","attached to it"],"shortGloss":"can't bear to let go","characters":[{"char":"爱","meaning":"love"},{"char":"不","meaning":"not"},{"char":"忍","meaning":"bear; endure"},{"char":"释","meaning":"release; let go"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom describes a situation where someone is so enamored with an object, such as a book or a piece of art, that they cannot bring themselves to put it down or let it go. This reflects a deep emotional attachment and appreciation for the item.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"commonly used in both spoken and written Chinese, suitable for informal contexts","connotation":"positive","commonMistakes":"Learners might confuse this idiom with similar expressions that imply reluctance due to negative reasons, such as fear or obligation. '爱不忍释' specifically conveys a positive attachment.","canStandAlone":false},"examples":[{"simplified":"这本小说太精彩了，我爱不忍释。","english":"This novel is so captivating that I can't put it down.","traditional":"這本小說太精彩了，我愛不忍釋。"},{"simplified":"他对那幅画爱不忍释，久久不愿离开。","english":"He was so fond of the painting that he couldn't bear to leave it.","traditional":"他對那幅畫愛不忍釋，久久不願離開。"}],"synonyms":["爱不释手"],"antonyms":[],"confusedWith":[{"id":"爱不释手","note":"Both idioms express an inability to let go due to fondness, but '爱不释手' is more commonly used specifically for physical objects."}],"traditional":"愛不忍釋","pinyinOverride":null},{"id":"ai-guo-ru-jia","simplified":"爱国如家","literalMeaning":"love country like home","figurativeMeaning":"to love and be devoted to one's country as if it were one's own family","englishEquivalents":["patriotism","love of country"],"shortGloss":"patriotic devotion","characters":[{"char":"爱","meaning":"love"},{"char":"国","meaning":"country"},{"char":"如","meaning":"like, as if"},{"char":"家","meaning":"home, family"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '爱国如家' reflects the idea that one should love and be devoted to their country with the same intensity and care as they would their own family. This concept is deeply rooted in the cultural values of loyalty and patriotism, often emphasized in Chinese literature and history.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"modifier-head","register":"commonly used in both formal and informal contexts to express patriotism","connotation":"positive","commonMistakes":"Learners might confuse this idiom with more general expressions of love or loyalty, but it specifically emphasizes patriotic devotion. It should not be used to describe personal relationships or non-national entities.","canStandAlone":false},"examples":[{"simplified":"他一直以来都爱国如家，为国家的发展贡献了很多。","english":"He has always been devoted to his country like it was his own family, contributing greatly to its development.","traditional":"他一直以來都愛國如家，為國家的發展貢獻了很多。"},{"simplified":"在危难时刻，许多人表现出爱国如家的精神。","english":"In times of crisis, many people show a spirit of loving their country as if it were their own family.","traditional":"在危難時刻，許多人表現出愛國如家的精神。"}],"synonyms":["精忠报国"],"antonyms":[],"confusedWith":[{"id":"爱屋及乌","note":"While both involve love, 爱屋及乌 refers to loving everything related to someone you love, not specifically about patriotism."}],"traditional":"愛國如家","pinyinOverride":null},{"id":"ai-min-ru-zi","simplified":"爱民如子","literalMeaning":"love the people like one's own children","figurativeMeaning":"to care for the people with great compassion and kindness, as if they were one's own children","englishEquivalents":["care for the people like one's own children"],"shortGloss":"care for the people compassionately","characters":[{"char":"爱","meaning":"love"},{"char":"民","meaning":"the people"},{"char":"如","meaning":"like; as if"},{"char":"子","meaning":"children"}],"origin":{"period":"Warring States period (475–221 BCE)","sourceText":"《孟子·梁惠王上》","sourceTextEnglish":"Mencius, King Hui of Liang I","originalExcerpt":"爱民如子，治国如家。","storyEnglish":"The phrase comes from the teachings of Mencius, a Confucian philosopher during the Warring States period. Mencius advised rulers to govern with benevolence and to care for their subjects as if they were their own children. This approach, he argued, would lead to a harmonious and prosperous state.","historicalFigures":["Mencius"],"relatedIdiomsFromSameSource":["治国如家"]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"verb-object","register":"literary, but understood in formal contexts","connotation":"positive","commonMistakes":"Learners might confuse this idiom with more general expressions of kindness, but it specifically refers to a ruler's or leader's duty to care for their people. It is not used for ordinary acts of kindness.","canStandAlone":false},"examples":[{"simplified":"这位领导一向爱民如子，深受大家的尊敬。","english":"This leader has always cared for the people like his own children and is deeply respected by everyone.","traditional":"這位領導一向愛民如子，深受大家的尊敬。"},{"simplified":"古代的贤君常被赞誉为爱民如子的典范。","english":"Wise rulers of ancient times were often praised as models of caring for the people like their own children.","traditional":"古代的賢君常被讚譽為愛民如子的典範。"}],"synonyms":["视民如伤"],"antonyms":["暴政"],"confusedWith":[{"id":"爱屋及乌","note":"While both involve love and care, 爱屋及乌 refers to loving everything related to someone you love, not specifically about rulers and their subjects."}],"traditional":"愛民如子","pinyinOverride":null},{"id":"ai-mo-neng-zhu","simplified":"爱莫能助","literalMeaning":"love but cannot help","figurativeMeaning":"to be willing to help but unable to do so","englishEquivalents":["My hands are tied","I wish I could help","Out of my hands"],"shortGloss":"unable to help despite willingness","characters":[{"char":"爱","meaning":"love; wish"},{"char":"莫","meaning":"cannot; not"},{"char":"能","meaning":"able; can"},{"char":"助","meaning":"help; assist"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '爱莫能助' is used to express a situation where someone genuinely wishes to help another person but is unable to do so due to circumstances beyond their control. The phrase captures the feeling of helplessness when one's desire to assist is thwarted by external limitations.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","complement"],"structure":"subject-predicate","register":"widely used in both formal and informal contexts","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with expressions that imply unwillingness to help. However, '爱莫能助' specifically conveys a desire to help but an inability to do so.","canStandAlone":false},"examples":[{"simplified":"他的问题太复杂，我爱莫能助。","english":"His problem is too complicated, I wish I could help but I can't.","traditional":"他的問題太複雜，我愛莫能助。"},{"simplified":"虽然我很想帮忙，但在这种情况下，我爱莫能助。","english":"Although I really want to help, in this situation, my hands are tied.","traditional":"雖然我很想幫忙，但在這種情況下，我愛莫能助。"}],"synonyms":[],"antonyms":[],"confusedWith":[{"id":"袖手旁观","note":"袖手旁观 implies standing by and watching without helping, often with a sense of indifference, whereas 爱莫能助 conveys a desire to help but an inability to do so."}],"traditional":"愛莫能助","pinyinOverride":null},{"id":"ai-qian-ru-ming","simplified":"爱钱如命","literalMeaning":"love money like life","figurativeMeaning":"to be extremely greedy or obsessed with money","englishEquivalents":["money-grubber","penny-pincher","miser"],"shortGloss":"obsessed with money","characters":[{"char":"爱","meaning":"love"},{"char":"钱","meaning":"money"},{"char":"如","meaning":"like"},{"char":"命","meaning":"life"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"This idiom describes a person who values money as much as their own life, indicating extreme greed or obsession with wealth. It is often used to criticize someone who prioritizes money over all else.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"modifier-head","register":"commonly used in both spoken and written Chinese, often with a negative connotation","connotation":"negative","commonMistakes":"Learners might confuse this idiom with similar expressions that describe wealth, but this idiom specifically implies an unhealthy obsession with money, not just wealthiness.","canStandAlone":false},"examples":[{"simplified":"他爱钱如命，连朋友的帮助都不愿意接受。","english":"He is so obsessed with money that he even refuses help from friends.","traditional":"他愛錢如命，連朋友的幫助都不願意接受。"},{"simplified":"那个商人爱钱如命，总是想方设法多赚钱。","english":"That businessman is obsessed with money and is always finding ways to make more.","traditional":"那個商人愛錢如命，總是想方設法多賺錢。"}],"synonyms":["一毛不拔","财迷心窍"],"antonyms":["视金钱如粪土"],"confusedWith":[{"id":"财迷心窍","note":"Both imply obsession with money, but 财迷心窍 suggests being blinded by greed to the point of irrationality."}],"traditional":"愛錢如命","pinyinOverride":null},{"id":"ai-zeng-fen-ming","simplified":"爱憎分明","literalMeaning":"love and hate clearly distinguished","figurativeMeaning":"to be clear about whom or what one loves or hates; to have clear likes and dislikes","englishEquivalents":["to know one's own mind","to have clear likes and dislikes"],"shortGloss":"clear likes and dislikes","characters":[{"char":"爱","meaning":"love"},{"char":"憎","meaning":"hate"},{"char":"分","meaning":"distinguish"},{"char":"明","meaning":"clear"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '爱憎分明' describes a person who has clear and distinct feelings about what they love and what they hate. It is often used to praise someone for their straightforwardness and honesty in expressing their preferences and aversions.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"modifier-head","register":"widely used in both written and spoken Chinese","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with others that involve emotions, but this one specifically emphasizes clarity and distinction in feelings. It should not be used to describe someone who is indecisive or ambiguous in their emotions.","canStandAlone":false},"examples":[{"simplified":"他是一个爱憎分明的人，从不掩饰自己的感情。","english":"He is a person with clear likes and dislikes, never hiding his feelings.","traditional":"他是一個愛憎分明的人，從不掩飾自己的感情。"},{"simplified":"在工作中，她总是爱憎分明，大家都很欣赏她的直率。","english":"In her work, she always has clear likes and dislikes, and everyone appreciates her straightforwardness.","traditional":"在工作中，她總是愛憎分明，大家都很欣賞她的直率。"}],"synonyms":["是非分明"],"antonyms":["模棱两可"],"confusedWith":[{"id":"模棱两可","note":"模棱两可 means ambiguous or indecisive, which is the opposite of having clear likes and dislikes."}],"traditional":"愛憎分明","pinyinOverride":null},{"id":"ai-shou-ai-jiao","simplified":"碍手碍脚","literalMeaning":"obstruct hands obstruct feet","figurativeMeaning":"to be a hindrance or nuisance; to get in the way","englishEquivalents":["in the way","a stumbling block","a nuisance"],"shortGloss":"to be a hindrance","characters":[{"char":"碍","meaning":"obstruct"},{"char":"手","meaning":"hands"},{"char":"碍","meaning":"obstruct"},{"char":"脚","meaning":"feet"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '碍手碍脚' is commonly used to describe someone or something that is in the way and causing inconvenience. It is often used in situations where a person feels hindered by another's presence or actions, much like having one's hands and feet obstructed.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"coordinate","register":"commonly used in both spoken and written Chinese, informal contexts","connotation":"negative","commonMistakes":"Learners might confuse it with idioms that imply physical obstruction only, but it can also refer to metaphorical hindrances. It is not used to describe objects, only people or actions.","canStandAlone":false},"examples":[{"simplified":"他在厨房里总是碍手碍脚的，还是让他去客厅吧。","english":"He's always in the way in the kitchen; it's better to let him stay in the living room.","traditional":"他在廚房裡總是礙手礙腳的，還是讓他去客廳吧。"},{"simplified":"如果你帮不上忙，就别在这里碍手碍脚了。","english":"If you can't help, then don't be a hindrance here.","traditional":"如果你幫不上忙，就別在這裡礙手礙腳了。"}],"synonyms":["妨碍","阻碍"],"antonyms":["助人为乐"],"confusedWith":[{"id":"妨碍","note":"While both imply obstruction, '妨碍' is more formal and can refer to both physical and abstract hindrances."}],"traditional":"礙手礙腳","pinyinOverride":null},{"id":"ai-mei-bu-ming","simplified":"暧昧不明","literalMeaning":"ambiguous and unclear","figurativeMeaning":"vague and unclear; lacking clarity or definition","englishEquivalents":["neither here nor there","in a gray area"],"shortGloss":"vague and unclear","characters":[{"char":"暧","meaning":"ambiguous"},{"char":"昧","meaning":"obscure"},{"char":"不","meaning":"not"},{"char":"明","meaning":"clear"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom 暧昧不明 is often used to describe situations, relationships, or statements that are intentionally or unintentionally unclear. It suggests a lack of clarity that can lead to misunderstandings or confusion.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"modifier-head","register":"commonly used in both written and spoken Chinese to describe unclear situations or relationships","connotation":"neutral","commonMistakes":"Learners might confuse 暧昧不明 with 暧昧, which can specifically refer to ambiguous romantic feelings. 暧昧不明 is broader and applies to any unclear situation.","canStandAlone":false},"examples":[{"simplified":"他的态度一直暧昧不明，让人很难判断他的真实想法。","english":"His attitude has always been vague and unclear, making it difficult to discern his true thoughts.","traditional":"他的態度一直曖昧不明，讓人很難判斷他的真實想法。"},{"simplified":"这份合同的条款暧昧不明，可能会导致法律纠纷。","english":"The terms of this contract are vague and unclear, which might lead to legal disputes.","traditional":"這份合同的條款曖昧不明，可能會導致法律糾紛。"}],"synonyms":["模糊不清"],"antonyms":["一清二楚"],"confusedWith":[{"id":"暧昧","note":"暧昧 often refers to ambiguous romantic feelings, while 暧昧不明 is broader and not limited to romance."}],"traditional":"曖昧不明","pinyinOverride":null},{"id":"ai-mei-zhi-qing","simplified":"暧昧之情","literalMeaning":"ambiguous feelings","figurativeMeaning":"a romantic or ambiguous relationship where feelings are not clearly expressed","englishEquivalents":["undefined relationship","it's complicated"],"shortGloss":"ambiguous romantic feelings","characters":[{"char":"暧","meaning":"ambiguous, unclear"},{"char":"昧","meaning":"obscure, hidden"},{"char":"之","meaning":"of"},{"char":"情","meaning":"feelings, emotions"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '暧昧之情' is used to describe a situation where two people have romantic feelings for each other, but these feelings are not openly acknowledged or clearly defined. It often refers to a relationship that is in a gray area between friendship and romance.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["subject","object","attributive"],"structure":"modifier-head","register":"commonly used in both spoken and written Chinese, especially in informal contexts","connotation":"neutral","commonMistakes":"Learners might confuse '暧昧之情' with '暧昧关系', which specifically refers to an ambiguous relationship rather than the feelings themselves. '暧昧之情' focuses more on the emotional aspect.","canStandAlone":false},"examples":[{"simplified":"他们之间有一种暧昧之情，但谁也没有表白。","english":"There is an ambiguous feeling between them, but neither has confessed.","traditional":"他們之間有一種曖昧之情，但誰也沒有表白。"},{"simplified":"这种暧昧之情让他们的关系变得复杂。","english":"These ambiguous feelings have complicated their relationship.","traditional":"這種曖昧之情讓他們的關係變得複雜。"}],"synonyms":[],"antonyms":[],"confusedWith":[{"id":"暧昧关系","note":"While '暧昧之情' refers to the feelings, '暧昧关系' refers to the relationship itself."}],"traditional":"曖昧之情","pinyinOverride":null},{"id":"an-an-wen-wen","simplified":"安安稳稳","literalMeaning":"peaceful and stable","figurativeMeaning":"safe and sound; calm and steady","englishEquivalents":["safe and sound","calm and steady"],"shortGloss":"safe and sound","characters":[{"char":"安","meaning":"peaceful"},{"char":"安","meaning":"peaceful"},{"char":"稳","meaning":"stable"},{"char":"稳","meaning":"stable"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '安安稳稳' is commonly used to describe a situation or state that is peaceful, stable, and without disturbances. It emphasizes a sense of security and tranquility, often used in contexts where one desires or appreciates a lack of chaos or danger.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["adverbial","attributive"],"structure":"AABB","register":"widely used in both spoken and written Chinese, suitable for formal and informal contexts","connotation":"positive","commonMistakes":"Learners might confuse '安安稳稳' with '平平安安', which also means safe and sound but emphasizes peace over stability. '安安稳稳' is more about stability and calmness.","canStandAlone":false},"examples":[{"simplified":"他希望能过上安安稳稳的生活。","english":"He hopes to live a calm and steady life.","traditional":"他希望能過上安安穩穩的生活。"},{"simplified":"经过一番波折，事情终于安安稳稳地解决了。","english":"After some twists and turns, the matter was finally resolved calmly and steadily.","traditional":"經過一番波折，事情終於安安穩穩地解決了。"}],"synonyms":["平平安安"],"antonyms":["动荡不安"],"confusedWith":[{"id":"平平安安","note":"Both emphasize safety, but '平平安安' focuses more on peace and security, while '安安稳稳' emphasizes stability."}],"traditional":"安安穩穩","pinyinOverride":null},{"id":"an-bang-ding-guo","simplified":"安邦定国","literalMeaning":"stabilize the nation and secure the country","figurativeMeaning":"to bring peace and stability to a country; to govern effectively","englishEquivalents":["bring peace to the country","ensure national stability"],"shortGloss":"bring peace and stability to a country","characters":[{"char":"安","meaning":"stabilize; bring peace"},{"char":"邦","meaning":"nation; country"},{"char":"定","meaning":"secure; settle"},{"char":"国","meaning":"country; state"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '安邦定国' is often used to describe the efforts of leaders or governments to bring about peace and stability within a nation. It emphasizes the importance of effective governance and the establishment of order to ensure the well-being of a country's citizens.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","object"],"structure":"verb-object + verb-object","register":"formal, often used in political or historical contexts","connotation":"positive","commonMistakes":"Learners might confuse this idiom with others that involve governance or stability, but '安邦定国' specifically emphasizes the dual actions of stabilizing and securing a nation.","canStandAlone":false},"examples":[{"simplified":"新政府上台后，努力安邦定国，恢复社会秩序。","english":"After the new government took power, they worked hard to bring peace and stability to the country and restore social order.","traditional":"新政府上臺後，努力安邦定國，恢復社會秩序。"},{"simplified":"他的目标是安邦定国，造福百姓。","english":"His goal is to bring peace and stability to the country and benefit the people.","traditional":"他的目標是安邦定國，造福百姓。"}],"synonyms":["治国安邦"],"antonyms":[],"confusedWith":[{"id":"治国安邦","note":"Both idioms involve governance and stability, but '治国安邦' focuses more on governance ('治国') as the primary action."}],"traditional":"安邦定國","pinyinOverride":null},{"id":"an-bang-zhi-guo","simplified":"安邦治国","literalMeaning":"stabilize the nation, govern the country","figurativeMeaning":"to bring peace and stability to the country through effective governance","englishEquivalents":["to govern with a steady hand","to bring peace and order"],"shortGloss":"stabilize and govern the nation","characters":[{"char":"安","meaning":"stabilize; bring peace"},{"char":"邦","meaning":"nation; state"},{"char":"治","meaning":"govern; manage"},{"char":"国","meaning":"country; nation"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '安邦治国' is often used to describe the actions of a wise and effective ruler who brings peace and stability to their nation. It emphasizes the importance of good governance and leadership in maintaining a prosperous and orderly society.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"verb-object + verb-object","register":"formal written Chinese, often used in political contexts","connotation":"positive","commonMistakes":"Learners might confuse this idiom with others that involve governance but do not emphasize stability and peace, such as '治国安民', which focuses more on governing the people.","canStandAlone":false},"examples":[{"simplified":"他的目标是安邦治国，为人民带来幸福。","english":"His goal is to stabilize the nation and govern the country, bringing happiness to the people.","traditional":"他的目標是安邦治國，為人民帶來幸福。"},{"simplified":"一个成功的领导者必须具备安邦治国的能力。","english":"A successful leader must possess the ability to stabilize the nation and govern the country.","traditional":"一個成功的領導者必須具備安邦治國的能力。"}],"synonyms":["治国安民"],"antonyms":[],"confusedWith":[{"id":"治国安民","note":"While both involve governance, '治国安民' focuses more on governing the people specifically, rather than the broader concept of stabilizing the nation."}],"traditional":"安邦治國","pinyinOverride":null},{"id":"an-bu-wang-wei","simplified":"安不忘危","literalMeaning":"safe not forget danger","figurativeMeaning":"to remain vigilant and prepared for potential dangers even in times of peace or safety","englishEquivalents":["stay alert","be prepared","expect the unexpected"],"shortGloss":"stay vigilant in safety","characters":[{"char":"安","meaning":"safe"},{"char":"不","meaning":"not"},{"char":"忘","meaning":"forget"},{"char":"危","meaning":"danger"}],"origin":{"period":"Warring States period (475–221 BCE)","sourceText":"《左传·襄公十一年》","sourceTextEnglish":"Zuo Zhuan, Duke Xiang, Year 11","originalExcerpt":"安而不忘危，存而不忘亡，治而不忘乱。","storyEnglish":"The idiom comes from the historical text 'Zuo Zhuan', which records events during the Warring States period. The passage advises rulers to remain cautious and prepared for potential dangers even when they are in a state of peace and stability. It emphasizes the importance of foresight and vigilance to maintain long-term security and prosperity.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"coordinate","register":"literary, but understood and used in formal speech","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with others that emphasize complacency, such as '安于现状'. However, '安不忘危' specifically stresses the importance of vigilance and preparation.","canStandAlone":false},"examples":[{"simplified":"在和平时期，我们也要安不忘危，做好应对突发事件的准备。","english":"Even in times of peace, we must remain vigilant and be prepared for emergencies.","traditional":"在和平時期，我們也要安不忘危，做好應對突發事件的準備。"},{"simplified":"公司在盈利的时候，管理层仍然安不忘危，制定了详细的风险管理计划。","english":"When the company was profitable, the management still remained vigilant and developed a detailed risk management plan.","traditional":"公司在盈利的時候，管理層仍然安不忘危，制定了詳細的風險管理計劃。"}],"synonyms":["居安思危"],"antonyms":[],"confusedWith":[{"id":"安于现状","note":"While '安不忘危' emphasizes vigilance, '安于现状' means being content with the current situation and not seeking change."}],"traditional":"安不忘危","pinyinOverride":null},{"id":"an-bu-dang-che","simplified":"安步当车","literalMeaning":"walk leisurely as if riding a carriage","figurativeMeaning":"to walk instead of using a vehicle; to take things at a leisurely pace","englishEquivalents":["take it easy","go at a leisurely pace"],"shortGloss":"walk instead of ride","characters":[{"char":"安","meaning":"peacefully, leisurely"},{"char":"步","meaning":"walk, step"},{"char":"当","meaning":"regard as, treat as"},{"char":"车","meaning":"carriage, vehicle"}],"origin":{"period":"Warring States period (475–221 BCE)","sourceText":"《战国策·齐策四》","sourceTextEnglish":"Strategies of the Warring States, Strategies of Qi, Chapter 4","originalExcerpt":"安步以当车，晚食以当肉。","storyEnglish":"The idiom comes from a passage in the 'Strategies of the Warring States', where it is suggested that one can walk leisurely as if they were riding in a carriage, and eat a late meal as if it were a feast. This reflects a philosophy of contentment and simplicity, valuing what one has rather than seeking more.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"literary, but can be used in everyday speech to suggest a relaxed approach","connotation":"positive","commonMistakes":"Learners might confuse this idiom with those that imply laziness or procrastination. However, it suggests a deliberate choice to take things slowly and enjoy the process, not avoidance of effort.","canStandAlone":false},"examples":[{"simplified":"他喜欢安步当车，享受沿途的风景。","english":"He likes to walk leisurely, enjoying the scenery along the way.","traditional":"他喜歡安步當車，享受沿途的風景。"},{"simplified":"在城市里，安步当车是一种健康的生活方式。","english":"In the city, walking instead of driving is a healthy lifestyle choice.","traditional":"在城市裡，安步當車是一種健康的生活方式。"}],"synonyms":["慢条斯理"],"antonyms":["争分夺秒"],"confusedWith":[{"id":"慢条斯理","note":"慢条斯理 emphasizes slowness and deliberation, while 安步当车 emphasizes walking as a choice over riding."}],"traditional":"安步當車","pinyinOverride":null},{"id":"an-chang-chu-shun","simplified":"安常处顺","literalMeaning":"be at peace with the usual and dwell in harmony","figurativeMeaning":"to be content with one's lot and adapt to circumstances","englishEquivalents":["go with the flow","accept things as they are"],"shortGloss":"contentment with one's lot","characters":[{"char":"安","meaning":"be at peace"},{"char":"常","meaning":"usual, normal"},{"char":"处","meaning":"dwell, live"},{"char":"顺","meaning":"harmony, compliance"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom suggests a mindset of accepting and being content with the usual circumstances of life, and living in harmony with the situation one finds oneself in. It emphasizes the value of contentment and adaptability.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"coordinate","register":"literary, but can be used in both formal and informal contexts","connotation":"positive","commonMistakes":"Learners might confuse this idiom with those that imply passivity or resignation. However, it specifically emphasizes contentment and adaptability, not passivity.","canStandAlone":false},"examples":[{"simplified":"在困难时期，我们应该安常处顺，保持乐观。","english":"In difficult times, we should go with the flow and remain optimistic.","traditional":"在困難時期，我們應該安常處順，保持樂觀。"},{"simplified":"他总是安常处顺，从不抱怨。","english":"He is always content with his lot and never complains.","traditional":"他總是安常處順，從不抱怨。"}],"synonyms":["随遇而安"],"antonyms":["怨天尤人"],"confusedWith":[{"id":"逆来顺受","note":"While both involve acceptance, 逆来顺受 implies enduring adversity passively, whereas 安常处顺 emphasizes contentment and adaptability."}],"traditional":"安常處順","pinyinOverride":null},{"id":"an-jia-li-ye","simplified":"安家立业","literalMeaning":"settle down and establish a career","figurativeMeaning":"to settle down with a stable home and career; to establish oneself","englishEquivalents":["put down roots","settle down"],"shortGloss":"settle down and establish oneself","characters":[{"char":"安","meaning":"settle"},{"char":"家","meaning":"home"},{"char":"立","meaning":"establish"},{"char":"业","meaning":"career"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '安家立业' refers to the process of settling down in a stable home and establishing a career. It is commonly used to describe someone who has reached a stage in life where they have a secure home and a stable job, indicating a sense of stability and responsibility.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","object"],"structure":"coordinate","register":"commonly used in both spoken and written Chinese","connotation":"positive","commonMistakes":"Learners might confuse this idiom with similar phrases that only refer to career success, but '安家立业' emphasizes both home and career stability.","canStandAlone":false},"examples":[{"simplified":"他在这个城市安家立业了。","english":"He has settled down and established himself in this city.","traditional":"他在這個城市安家立業了。"},{"simplified":"年轻人应该努力工作，早日安家立业。","english":"Young people should work hard to settle down and establish themselves early.","traditional":"年輕人應該努力工作，早日安家立業。"}],"synonyms":["成家立业"],"antonyms":[],"confusedWith":[{"id":"成家立业","note":"Both idioms involve settling down and establishing a career, but '成家立业' specifically emphasizes starting a family."}],"traditional":"安家立業","pinyinOverride":null},{"id":"an-fu-xu-pin","simplified":"安富恤贫","literalMeaning":"settle the rich, relieve the poor","figurativeMeaning":"to ensure the well-being of the wealthy while caring for the poor; to balance social welfare","englishEquivalents":["care for the rich and the poor alike","balance wealth and poverty"],"shortGloss":"balance wealth and poverty","characters":[{"char":"安","meaning":"settle, make stable"},{"char":"富","meaning":"rich, wealthy"},{"char":"恤","meaning":"relieve, show compassion"},{"char":"贫","meaning":"poor, poverty"}],"origin":{"period":"Han Dynasty (206 BCE – 220 CE)","sourceText":"《汉书·食货志》","sourceTextEnglish":"Book of Han, Treatise on Food and Money","originalExcerpt":"安富尊荣，恤贫穷困苦。","storyEnglish":"The idiom originates from the 'Book of Han,' where it discusses the responsibilities of the government to maintain social stability by ensuring the wealthy are settled and the poor are cared for. This reflects a philosophy of balancing social welfare to maintain harmony within the state.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"coordinate","register":"formal written Chinese, occasionally used in speech to discuss social policies","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with those that only focus on poverty alleviation, missing the aspect of balancing both wealth and poverty. It is not solely about helping the poor but also involves stabilizing the wealthy.","canStandAlone":false},"examples":[{"simplified":"政府的政策应该安富恤贫，以促进社会和谐。","english":"The government's policies should balance wealth and poverty to promote social harmony.","traditional":"政府的政策應該安富恤貧，以促進社會和諧。"},{"simplified":"在制定经济计划时，我们必须考虑如何安富恤贫。","english":"When formulating economic plans, we must consider how to balance wealth and poverty.","traditional":"在制定經濟計劃時，我們必須考慮如何安富恤貧。"}],"synonyms":[],"antonyms":[],"confusedWith":[],"traditional":"安富恤貧","pinyinOverride":null},{"id":"an-jia-luo-hu","simplified":"安家落户","literalMeaning":"settle home establish household","figurativeMeaning":"to settle down and make a home in a new place","englishEquivalents":["put down roots","settle down"],"shortGloss":"settle down and make a home","characters":[{"char":"安","meaning":"settle"},{"char":"家","meaning":"home"},{"char":"落","meaning":"establish"},{"char":"户","meaning":"household"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '安家落户' is used to describe the process of settling down in a new place and establishing a home there. It conveys the idea of finding stability and creating a permanent residence. The phrase is commonly used when someone moves to a new city or country and decides to make it their home.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","object"],"structure":"verb-object","register":"commonly used in both spoken and written Chinese","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with expressions that imply temporary residence. '安家落户' specifically means establishing a permanent home, not just staying somewhere temporarily.","canStandAlone":false},"examples":[{"simplified":"他们在这个城市安家落户，开始了新的生活。","english":"They settled down in this city and started a new life.","traditional":"他們在這個城市安家落戶，開始了新的生活。"},{"simplified":"经过多年的漂泊，他终于决定在乡村安家落户。","english":"After years of wandering, he finally decided to settle down in the countryside.","traditional":"經過多年的漂泊，他終於決定在鄉村安家落戶。"}],"synonyms":["定居","落地生根"],"antonyms":[],"confusedWith":[{"id":"暂居","note":"暂居 implies temporary residence, while 安家落户 implies a permanent settlement."}],"traditional":"安家落戶","pinyinOverride":null},{"id":"an-liang-chu-bao","simplified":"安良除暴","literalMeaning":"comfort the good, eliminate the violent","figurativeMeaning":"to protect the good and eliminate the bad; to maintain justice and order","englishEquivalents":["uphold justice","protect the innocent","fight against evil"],"shortGloss":"protect the good and eliminate evil","characters":[{"char":"安","meaning":"comfort, protect"},{"char":"良","meaning":"good, virtuous"},{"char":"除","meaning":"eliminate, remove"},{"char":"暴","meaning":"violent, evil"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '安良除暴' describes the ideal of protecting good people and eliminating those who are violent or evil. It is often used to describe the actions of just rulers or heroes who strive to maintain peace and justice in society.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","object"],"structure":"coordinate","register":"literary, but can be used in formal speech or writing","connotation":"positive","commonMistakes":"Learners might confuse this idiom with others that involve justice or protection, but '安良除暴' specifically emphasizes both protecting the good and eliminating the bad.","canStandAlone":false},"examples":[{"simplified":"政府应该安良除暴，维护社会的稳定。","english":"The government should protect the good and eliminate the bad to maintain social stability.","traditional":"政府應該安良除暴，維護社會的穩定。"},{"simplified":"他立志成为一名警察，安良除暴，保护市民。","english":"He aspired to become a police officer to protect the good and eliminate the bad, safeguarding the citizens.","traditional":"他立志成為一名警察，安良除暴，保護市民。"}],"synonyms":["扶危济困","惩恶扬善"],"antonyms":[],"confusedWith":[{"id":"惩恶扬善","note":"Both involve promoting good and punishing evil, but '惩恶扬善' focuses more on punishment and reward."}],"traditional":"安良除暴","pinyinOverride":null},{"id":"an-min-gao-shi","simplified":"安民告示","literalMeaning":"calm the people, announcement","figurativeMeaning":"a public notice intended to reassure the populace","englishEquivalents":["public reassurance","official announcement"],"shortGloss":"public reassurance notice","characters":[{"char":"安","meaning":"calm, reassure"},{"char":"民","meaning":"people, populace"},{"char":"告","meaning":"announce, inform"},{"char":"示","meaning":"notice, announcement"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '安民告示' refers to a practice where authorities issue announcements to reassure the public during times of unrest or uncertainty. These notices are meant to calm fears and provide information to the populace, ensuring stability and order.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["subject","object"],"structure":"modifier-head","register":"commonly used in both formal and informal contexts","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with general announcements or notices, but it specifically refers to those intended to reassure or calm the public.","canStandAlone":false},"examples":[{"simplified":"政府发布了一则安民告示，以缓解市民的恐慌。","english":"The government issued a public reassurance notice to alleviate the citizens' panic.","traditional":"政府發佈了一則安民告示，以緩解市民的恐慌。"},{"simplified":"在危机时刻，安民告示可以帮助稳定社会情绪。","english":"In times of crisis, a public reassurance notice can help stabilize social emotions.","traditional":"在危機時刻，安民告示可以幫助穩定社會情緒。"}],"synonyms":[],"antonyms":[],"confusedWith":[],"traditional":"安民告示","pinyinOverride":null},{"id":"an-nei-rang-wai","simplified":"安内攘外","literalMeaning":"stabilize the interior, repel the exterior","figurativeMeaning":"to stabilize internal affairs while defending against external threats","englishEquivalents":["secure the inside, repel the outside"],"shortGloss":"stabilize internally, defend externally","characters":[{"char":"安","meaning":"stabilize, secure"},{"char":"内","meaning":"internal, inside"},{"char":"攘","meaning":"repel, expel"},{"char":"外","meaning":"external, outside"}],"origin":{"period":"Warring States period (475–221 BCE)","sourceText":"《战国策·齐策》","sourceTextEnglish":"Strategies of the Warring States, Strategies of Qi","originalExcerpt":"王曰：“安内而攘外者，霸者之事也。”","storyEnglish":"During the Warring States period, the concept of '安内攘外' was emphasized as a strategy for rulers to maintain stability within their own states while also defending against external threats. This approach was seen as essential for a ruler to achieve dominance and maintain power.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","object"],"structure":"coordinate","register":"formal written Chinese, often used in political or strategic contexts","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with those that focus solely on internal or external issues, but it specifically addresses both aspects simultaneously.","canStandAlone":false},"examples":[{"simplified":"政府需要安内攘外，以确保国家的安全和稳定。","english":"The government needs to stabilize internally and defend externally to ensure the nation's security and stability.","traditional":"政府需要安內攘外，以確保國家的安全和穩定。"},{"simplified":"在复杂的国际环境中，安内攘外是每个国家必须面对的挑战。","english":"In a complex international environment, stabilizing internally and defending externally is a challenge every country must face.","traditional":"在複雜的國際環境中，安內攘外是每個國家必須面對的挑戰。"}],"synonyms":[],"antonyms":[],"confusedWith":[],"traditional":"安內攘外","pinyinOverride":null},{"id":"an-pin-le-dao","simplified":"安贫乐道","literalMeaning":"content with poverty, delight in the Way","figurativeMeaning":"to be content with a simple life and find joy in following one's principles or the right path","englishEquivalents":["contentment with simplicity","happy with a simple life"],"shortGloss":"content with simplicity and principles","characters":[{"char":"安","meaning":"content, at peace"},{"char":"贫","meaning":"poverty, poor"},{"char":"乐","meaning":"delight, joy"},{"char":"道","meaning":"the Way, principles"}],"origin":{"period":"Eastern Han dynasty (25–220 CE)","sourceText":"《后汉书·逸民传》","sourceTextEnglish":"Book of the Later Han, Biographies of Hermits","originalExcerpt":"安贫乐道，不以为耻。","storyEnglish":"The idiom comes from the 'Book of the Later Han', which describes individuals who were content with their poverty and found joy in adhering to their principles. They did not consider their lack of wealth to be shameful, but rather took pride in their virtuous way of living.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"coordinate","register":"literary, but commonly understood and used in both writing and speech","connotation":"positive","commonMistakes":"Learners often confuse this idiom with others that involve poverty, such as '安居乐业', which focuses on living and working happily, not necessarily in poverty. '安贫乐道' emphasizes contentment with a simple life and adherence to principles.","canStandAlone":false},"examples":[{"simplified":"他虽然收入不高，但总是安贫乐道，生活得很快乐。","english":"Although his income is not high, he is always content with simplicity and principles, and lives happily.","traditional":"他雖然收入不高，但總是安貧樂道，生活得很快樂。"},{"simplified":"在这个物欲横流的时代，安贫乐道显得尤为珍贵。","english":"In this materialistic age, being content with simplicity and principles is especially precious.","traditional":"在這個物慾橫流的時代，安貧樂道顯得尤為珍貴。"}],"synonyms":[],"antonyms":[],"confusedWith":[{"id":"安居乐业","note":"Focuses on living and working happily, not necessarily in poverty or with a focus on principles."}],"traditional":"安貧樂道","pinyinOverride":null},{"id":"an-ran-wu-shi","simplified":"安然无事","literalMeaning":"safe and sound without incident","figurativeMeaning":"to be safe and sound; to be unscathed","englishEquivalents":["safe and sound","unscathed","without a hitch"],"shortGloss":"safe and sound","characters":[{"char":"安","meaning":"safe"},{"char":"然","meaning":"thus; in this way"},{"char":"无","meaning":"without"},{"char":"事","meaning":"incident; trouble"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '安然无事' is commonly used to describe a situation where someone or something emerges from a potentially dangerous or problematic situation without any harm or trouble. It is often used to reassure others that everything is fine and no harm has come to anyone involved.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"modifier-head","register":"widely used in both written and spoken Chinese","connotation":"positive","commonMistakes":"Learners sometimes use this idiom in contexts where there is no potential danger or problem to begin with, which can make the usage seem unnecessary or redundant. It should be used when there is an implication of having avoided trouble.","canStandAlone":false},"examples":[{"simplified":"经过一场暴风雨，船只安然无事地返回港口。","english":"After the storm, the ship returned to the harbor safe and sound.","traditional":"經過一場暴風雨，船隻安然無事地返回港口。"},{"simplified":"他在事故中安然无事，没有受伤。","english":"He was unscathed in the accident and was not injured.","traditional":"他在事故中安然無事，沒有受傷。"}],"synonyms":["平安无事"],"antonyms":["祸不单行"],"confusedWith":[{"id":"平安无事","note":"Both mean being safe, but '平安无事' emphasizes peace and tranquility more."}],"traditional":"安然無事","pinyinOverride":null},{"id":"an-ru-pan-shi","simplified":"安如磐石","literalMeaning":"stable as a rock","figurativeMeaning":"very stable and secure, unshakeable","englishEquivalents":["rock-solid","as steady as a rock"],"shortGloss":"very stable and secure","characters":[{"char":"安","meaning":"stable, secure"},{"char":"如","meaning":"as, like"},{"char":"磐","meaning":"large rock, boulder"},{"char":"石","meaning":"stone, rock"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '安如磐石' describes something that is extremely stable and secure, like a large rock that cannot be easily moved. It is often used to describe situations, structures, or relationships that are very solid and reliable.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"modifier-head","register":"commonly used in both formal and informal contexts","connotation":"positive","commonMistakes":"Learners might confuse this idiom with others that imply stability but not necessarily security. It specifically conveys a sense of unshakeable security, not just any kind of stability.","canStandAlone":false},"examples":[{"simplified":"这座建筑安如磐石，经历了多次地震都没有损坏。","english":"This building is rock-solid; it has withstood multiple earthquakes without damage.","traditional":"這座建築安如磐石，經歷了多次地震都沒有損壞。"},{"simplified":"他们的友谊安如磐石，无论发生什么都不会动摇。","english":"Their friendship is as steady as a rock and won't waver no matter what happens.","traditional":"他們的友誼安如磐石，無論發生什麼都不會動搖。"}],"synonyms":["坚如磐石"],"antonyms":["岌岌可危"],"confusedWith":[{"id":"坚如磐石","note":"Both idioms convey a sense of stability, but '坚如磐石' emphasizes strength and firmness, while '安如磐石' emphasizes security and stability."}],"traditional":"安如磐石","pinyinOverride":null},{"id":"an-shen-zhi-chu","simplified":"安身之处","literalMeaning":"place to settle oneself","figurativeMeaning":"a place to live or settle down; a place of refuge or safety","englishEquivalents":["a place to call home","safe haven"],"shortGloss":"a place to settle down","characters":[{"char":"安","meaning":"settle; peaceful"},{"char":"身","meaning":"body; oneself"},{"char":"之","meaning":"of; possessive particle"},{"char":"处","meaning":"place; location"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '安身之处' is used to describe a place where one can settle down and live in peace. It emphasizes the importance of having a stable and secure environment. The phrase is often used in contexts where someone is seeking a new home or a safe place to reside.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["object","attributive"],"structure":"modifier-head","register":"commonly used in both written and spoken Chinese","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with similar phrases that imply temporary lodging rather than a permanent or stable place. It's important to note that '安身之处' suggests a more lasting and secure environment.","canStandAlone":false},"examples":[{"simplified":"他正在寻找一个安身之处。","english":"He is looking for a place to settle down.","traditional":"他正在尋找一個安身之處。"},{"simplified":"在这个城市里找到一个安身之处并不容易。","english":"It's not easy to find a place to settle down in this city.","traditional":"在這個城市裡找到一個安身之處並不容易。"}],"synonyms":["栖身之所"],"antonyms":[],"confusedWith":[{"id":"栖身之所","note":"While both refer to a place to stay, '栖身之所' often implies a temporary or less stable situation compared to '安身之处'."}],"traditional":"安身之處","pinyinOverride":null},{"id":"an-ran-wu-yang","simplified":"安然无恙","literalMeaning":"safe and sound without any trouble","figurativeMeaning":"to be safe and sound, without any harm or damage","englishEquivalents":["safe and sound","in one piece"],"shortGloss":"safe and sound","characters":[{"char":"安","meaning":"safe"},{"char":"然","meaning":"so; in such a manner"},{"char":"无","meaning":"without"},{"char":"恙","meaning":"illness; trouble"}],"origin":{"period":"Han Dynasty (206 BCE – 220 CE)","sourceText":"《汉书·李广苏建传》","sourceTextEnglish":"Book of Han, Biography of Li Guang and Su Jian","originalExcerpt":"广乃谢病，居家数月，安然无恙。","storyEnglish":"The idiom originates from the 'Book of Han', where it describes the state of Li Guang, a general who, after retiring due to illness, lived peacefully at home without any trouble. The phrase '安然无恙' was used to describe his condition of being safe and without any illness or trouble.","historicalFigures":["Li Guang"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"modifier-head","register":"widely used in both formal and informal contexts","connotation":"positive","commonMistakes":"Learners often confuse this idiom with similar phrases that imply recovery from illness, but '安然无恙' specifically means being safe without any trouble, not necessarily recovering from an illness.","canStandAlone":false},"examples":[{"simplified":"经过长途旅行，他终于安然无恙地回到了家。","english":"After the long journey, he finally returned home safe and sound.","traditional":"經過長途旅行，他終於安然無恙地回到了家。"},{"simplified":"尽管经历了风暴，船只仍然安然无恙。","english":"Despite the storm, the ship remained safe and sound.","traditional":"儘管經歷了風暴，船隻仍然安然無恙。"}],"synonyms":["平安无事"],"antonyms":["危在旦夕"],"confusedWith":[{"id":"平安无事","note":"Both imply safety, but '平安无事' emphasizes peace and lack of incidents, while '安然无恙' emphasizes being unharmed."}],"traditional":"安然無恙","pinyinOverride":null},{"id":"an-ru-tai-shan","simplified":"安如太山","literalMeaning":"stable as Mount Tai","figurativeMeaning":"as solid and unshakable as Mount Tai; extremely stable and secure","englishEquivalents":["rock solid","as steady as a rock"],"shortGloss":"extremely stable and secure","characters":[{"char":"安","meaning":"stable, secure"},{"char":"如","meaning":"as, like"},{"char":"太","meaning":"Mount Tai (a symbol of stability)"},{"char":"山","meaning":"mountain"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '安如太山' uses Mount Tai as a metaphor for stability and permanence. Mount Tai, located in Shandong Province, is one of China's Five Great Mountains and has been a symbol of strength and endurance throughout Chinese history. The phrase suggests that something is as stable and unmovable as this revered mountain.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"modifier-head","register":"literary, but understood in ordinary speech","connotation":"positive","commonMistakes":"Learners might confuse this idiom with others that use '山' (mountain) but do not convey the same sense of stability. It's important to remember that this idiom specifically emphasizes unshakeable security.","canStandAlone":false},"examples":[{"simplified":"他的信念安如太山，从未动摇。","english":"His beliefs are as stable as Mount Tai, never wavering.","traditional":"他的信念安如太山，從未動搖。"},{"simplified":"公司财务状况安如太山，让投资者非常放心。","english":"The company's financial situation is rock solid, giving investors great confidence.","traditional":"公司財務狀況安如太山，讓投資者非常放心。"}],"synonyms":["坚如磐石"],"antonyms":["岌岌可危"],"confusedWith":[{"id":"稳如泰山","note":"Both idioms convey stability, but '稳如泰山' is more commonly used in modern contexts."}],"traditional":"安如太山","pinyinOverride":null},{"id":"an-shen-zhi-di","simplified":"安身之地","literalMeaning":"a place to settle one's body","figurativeMeaning":"a place to live or settle down; a safe haven","englishEquivalents":["a place to call home","a safe haven"],"shortGloss":"a place to settle down","characters":[{"char":"安","meaning":"settle; peaceful"},{"char":"身","meaning":"body; oneself"},{"char":"之","meaning":"of; possessive particle"},{"char":"地","meaning":"place; location"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '安身之地' refers to a place where one can settle down and live peacefully. It emphasizes the importance of having a stable and secure environment for oneself. The phrase has been used in various contexts throughout Chinese literature to denote a place of safety and comfort, though its exact origin in classical texts is not clearly documented.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["object","attributive"],"structure":"modifier-head","register":"commonly used in both spoken and written Chinese","connotation":"neutral","commonMistakes":"Learners might confuse it with idioms that imply luxury or wealth, but '安身之地' focuses on safety and stability rather than opulence.","canStandAlone":false},"examples":[{"simplified":"他终于找到了一个安身之地，可以安心生活。","english":"He finally found a place to settle down and live in peace.","traditional":"他終於找到了一個安身之地，可以安心生活。"},{"simplified":"在这个城市里，他一直在寻找一个安身之地。","english":"In this city, he has been searching for a place to call home.","traditional":"在這個城市裡，他一直在尋找一個安身之地。"}],"synonyms":["栖身之所"],"antonyms":[],"confusedWith":[{"id":"安居乐业","note":"While '安居乐业' emphasizes living peacefully and working happily, '安身之地' focuses on finding a safe place to settle."}],"traditional":"安身之地","pinyinOverride":null},{"id":"an-ying-zha-zhai","simplified":"安营扎寨","literalMeaning":"set up camp and establish a stronghold","figurativeMeaning":"to settle down in a place and establish a base of operations","englishEquivalents":["set up camp","establish a base","dig in"],"shortGloss":"set up camp and establish a base","characters":[{"char":"安","meaning":"set up"},{"char":"营","meaning":"camp"},{"char":"扎","meaning":"establish"},{"char":"寨","meaning":"stronghold"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '安营扎寨' is believed to have originated from military practices where armies would set up camps and fortify their positions before engaging in battle. Over time, it came to be used more broadly to describe the act of settling down and establishing a presence in any location.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","object"],"structure":"verb-object + verb-object","register":"commonly used in both formal and informal contexts","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with expressions that only mean 'to camp' without the implication of establishing a more permanent or strategic presence.","canStandAlone":false},"examples":[{"simplified":"我们在山脚下安营扎寨，准备明天的登山活动。","english":"We set up camp at the foot of the mountain, preparing for tomorrow's hiking activity.","traditional":"我們在山腳下安營紮寨，準備明天的登山活動。"},{"simplified":"创业初期，他们在城市中心安营扎寨，逐步扩大业务。","english":"In the early stages of their startup, they set up a base in the city center and gradually expanded their business.","traditional":"創業初期，他們在城市中心安營紮寨，逐步擴大業務。"}],"synonyms":[],"antonyms":[],"confusedWith":[{"id":"扎营","note":"扎营 means simply 'to camp' without the implication of establishing a strategic base."}],"traditional":"安營紮寨","pinyinOverride":null},{"id":"an-yu-xian-zhuang","simplified":"安于现状","literalMeaning":"content with current situation","figurativeMeaning":"to be content with the status quo and not seek change or improvement","englishEquivalents":["content with the status quo","satisfied with things as they are"],"shortGloss":"content with the status quo","characters":[{"char":"安","meaning":"content, at ease"},{"char":"于","meaning":"with, in"},{"char":"现","meaning":"current, present"},{"char":"状","meaning":"situation, state"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '安于现状' describes a mindset where an individual or group is satisfied with the current state of affairs and does not wish to pursue further change or improvement. It reflects a sense of complacency or acceptance of the present circumstances, whether they are good or bad.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"commonly used in both formal and informal contexts","connotation":"neutral","commonMistakes":"Learners might confuse '安于现状' with idioms that imply satisfaction due to positive circumstances, while this idiom can also imply complacency in less favorable situations.","canStandAlone":false},"examples":[{"simplified":"他总是安于现状，从不想改变。","english":"He is always content with the status quo and never wants to change.","traditional":"他總是安於現狀，從不想改變。"},{"simplified":"面对挑战，我们不能安于现状。","english":"In the face of challenges, we cannot be content with the status quo.","traditional":"面對挑戰，我們不能安於現狀。"}],"synonyms":[],"antonyms":["力争上游"],"confusedWith":[{"id":"得过且过","note":"While '安于现状' implies contentment with the current situation, '得过且过' suggests a more passive attitude of just getting by without concern for improvement."}],"traditional":"安於現狀","pinyinOverride":null},{"id":"an-ma-lao-dun","simplified":"鞍马劳顿","literalMeaning":"saddle horse weary exhausted","figurativeMeaning":"weary from travel or hard work","englishEquivalents":["worn out from travel","road-weary"],"shortGloss":"weary from travel","characters":[{"char":"鞍","meaning":"saddle"},{"char":"马","meaning":"horse"},{"char":"劳","meaning":"weary"},{"char":"顿","meaning":"exhausted"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '鞍马劳顿' is believed to describe the exhaustion one feels after a long journey on horseback. In ancient times, travel was often done on horseback, and the phrase captures the physical fatigue and weariness that comes from being on the road for an extended period.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"modifier-head","register":"commonly used in both written and spoken Chinese to describe exhaustion from travel or work","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with others that describe general tiredness without the specific context of travel or work. It is important to use it when referring to exhaustion due to travel or physical labor.","canStandAlone":false},"examples":[{"simplified":"经过长途跋涉，他感到鞍马劳顿。","english":"After the long journey, he felt weary from travel.","traditional":"經過長途跋涉，他感到鞍馬勞頓。"},{"simplified":"会议结束后，大家都显得鞍马劳顿。","english":"After the meeting ended, everyone appeared worn out from the effort.","traditional":"會議結束後，大家都顯得鞍馬勞頓。"}],"synonyms":["筋疲力尽"],"antonyms":[],"confusedWith":[{"id":"筋疲力尽","note":"While both describe exhaustion, 鞍马劳顿 specifically implies weariness from travel or physical exertion, whereas 筋疲力尽 can refer to general exhaustion."}],"traditional":"鞍馬勞頓","pinyinOverride":null},{"id":"an-qian-ma-hou","simplified":"鞍前马后","literalMeaning":"in front of the saddle and behind the horse","figurativeMeaning":"to serve someone loyally and attentively","englishEquivalents":["at one's beck and call","to be at someone's service"],"shortGloss":"serve loyally and attentively","characters":[{"char":"鞍","meaning":"saddle"},{"char":"前","meaning":"front"},{"char":"马","meaning":"horse"},{"char":"后","meaning":"behind"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '鞍前马后' is believed to have originated from the imagery of a servant or attendant who is always ready to assist their master, whether in front of the saddle or behind the horse. This reflects the idea of being constantly available and attentive to the needs of someone important.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["adverbial","attributive"],"structure":"coordinate","register":"literary, but can be used in both formal and informal contexts","connotation":"neutral","commonMistakes":"Learners might mistakenly use this idiom to describe any kind of service, but it specifically implies a loyal and attentive service, often with a sense of devotion.","canStandAlone":false},"examples":[{"simplified":"他总是鞍前马后地为老板服务。","english":"He is always at his boss's beck and call.","traditional":"他總是鞍前馬後地為老闆服務。"},{"simplified":"她在家里鞍前马后，照顾全家人的生活起居。","english":"She serves her family loyally, attending to everyone's daily needs.","traditional":"她在家裡鞍前馬後，照顧全家人的生活起居。"}],"synonyms":["唯命是从"],"antonyms":[],"confusedWith":[{"id":"马不停蹄","note":"While both involve horses, '马不停蹄' means to keep going without rest, not serving someone."}],"traditional":"鞍前馬後","pinyinOverride":null},{"id":"an-bing-bu-dong","simplified":"按兵不动","literalMeaning":"hold troops, not move","figurativeMeaning":"to bide one's time; to hold back and wait for the right moment to act","englishEquivalents":["bide one's time","hold one's horses"],"shortGloss":"bide one's time","characters":[{"char":"按","meaning":"to hold back; to restrain"},{"char":"兵","meaning":"troops; soldiers"},{"char":"不","meaning":"not"},{"char":"动","meaning":"to move"}],"origin":{"period":"Warring States period (475–221 BCE)","sourceText":"《史记·孙子吴起列传》","sourceTextEnglish":"Records of the Grand Historian, Biography of Sun Tzu and Wu Qi","originalExcerpt":"吴起按兵不动，示之以弱，敌人果然中计。","storyEnglish":"The idiom originates from a story about the military strategist Wu Qi during the Warring States period. Wu Qi was known for his strategic prowess and once faced a formidable enemy. Instead of attacking immediately, he chose to hold his troops back, giving the appearance of weakness. This tactic lured the enemy into a false sense of security, allowing Wu Qi to strike at the opportune moment and secure victory.","historicalFigures":["Wu Qi"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"commonly used in both formal and informal contexts","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with similar expressions that imply indecisiveness, but 按兵不动 specifically refers to a deliberate, strategic choice to wait for the right moment.","canStandAlone":false},"examples":[{"simplified":"在谈判中，他选择按兵不动，等待更好的机会。","english":"During the negotiations, he chose to bide his time and wait for a better opportunity.","traditional":"在談判中，他選擇按兵不動，等待更好的機會。"},{"simplified":"面对对手的挑衅，他按兵不动，没有立即回应。","english":"Faced with the opponent's provocation, he held back and did not respond immediately.","traditional":"面對對手的挑釁，他按兵不動，沒有立即回應。"}],"synonyms":["韬光养晦"],"antonyms":["一触即发"],"confusedWith":[{"id":"犹豫不决","note":"犹豫不决 implies indecisiveness, while 按兵不动 is a strategic decision to wait."}],"traditional":"按兵不動","pinyinOverride":null},{"id":"an-na-bu-zhu","simplified":"按捺不住","literalMeaning":"cannot press down and hold","figurativeMeaning":"unable to restrain oneself; unable to hold back one's emotions or impulses","englishEquivalents":["can't contain oneself","bursting with excitement","unable to hold back"],"shortGloss":"unable to restrain oneself","characters":[{"char":"按","meaning":"press"},{"char":"捺","meaning":"hold down"},{"char":"不","meaning":"not"},{"char":"住","meaning":"able to"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '按捺不住' describes a situation where someone is so overwhelmed by emotions or impulses that they cannot keep them under control. It is often used to describe feelings of excitement, anger, or anticipation that are difficult to suppress.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","complement"],"structure":"verb-object","register":"commonly used in both written and spoken Chinese, suitable for everyday conversation","connotation":"neutral","commonMistakes":"Learners often confuse this idiom with '按兵不动', which means to hold back troops and wait. '按捺不住' specifically refers to an inability to control emotions or impulses, not strategic patience.","canStandAlone":false},"examples":[{"simplified":"听到这个好消息，他按捺不住地笑了出来。","english":"Hearing the good news, he couldn't contain himself and burst out laughing.","traditional":"聽到這個好消息，他按捺不住地笑了出來。"},{"simplified":"她按捺不住内心的激动，立刻给朋友打了电话。","english":"She couldn't hold back her excitement and immediately called her friend.","traditional":"她按捺不住內心的激動，立刻給朋友打了電話。"}],"synonyms":["情不自禁","难以自持"],"antonyms":["按兵不动"],"confusedWith":[{"id":"按兵不动","note":"按兵不动 means to hold back troops and wait, implying strategic patience, unlike 按捺不住 which is about emotional restraint."}],"traditional":"按捺不住","pinyinOverride":null},{"id":"an-jian-nan-fang","simplified":"暗箭难防","literalMeaning":"dark arrow hard to defend","figurativeMeaning":"it's hard to guard against hidden dangers or treachery","englishEquivalents":["it's hard to guard against a hidden dagger","beware of hidden dangers"],"shortGloss":"hard to guard against hidden threats","characters":[{"char":"暗","meaning":"hidden, secret"},{"char":"箭","meaning":"arrow"},{"char":"难","meaning":"difficult, hard"},{"char":"防","meaning":"defend against, guard"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '暗箭难防' is often used to describe situations where unexpected or secretive threats are difficult to anticipate and defend against. The imagery of a 'dark arrow' suggests an attack that comes without warning, symbolizing treachery or deceit that is not easily seen or countered.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"subject-predicate","register":"commonly used in both formal and informal contexts to describe unexpected challenges or betrayals","connotation":"negative","commonMistakes":"Learners may confuse this idiom with those that describe overt threats. '暗箭难防' specifically refers to hidden or unexpected dangers, not obvious ones.","canStandAlone":false},"examples":[{"simplified":"在职场上，暗箭难防，我们必须小心谨慎。","english":"In the workplace, hidden threats are hard to guard against, so we must be cautious.","traditional":"在職場上，暗箭難防，我們必須小心謹慎。"},{"simplified":"他总是担心有人会在背后搞小动作，因为暗箭难防。","english":"He is always worried that someone might scheme behind his back because hidden threats are hard to guard against.","traditional":"他總是擔心有人會在背後搞小動作，因為暗箭難防。"}],"synonyms":["防不胜防"],"antonyms":[],"confusedWith":[{"id":"明枪易躲","note":"This idiom refers to obvious threats that are easier to avoid, contrasting with the hidden nature of threats in '暗箭难防'."}],"traditional":"暗箭難防","pinyinOverride":null},{"id":"an-jian-shang-ren","simplified":"暗箭伤人","literalMeaning":"hidden arrow harms people","figurativeMeaning":"to harm someone by underhanded means; to attack someone by stealth","englishEquivalents":["stab in the back","underhanded attack"],"shortGloss":"to harm someone by stealth","characters":[{"char":"暗","meaning":"hidden, secret"},{"char":"箭","meaning":"arrow"},{"char":"伤","meaning":"to harm, to injure"},{"char":"人","meaning":"people, person"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '暗箭伤人' is believed to have originated from the idea of shooting arrows from a hidden position to harm others without being seen. It metaphorically describes someone who uses deceitful or underhanded tactics to harm others, much like a hidden arrow that strikes unexpectedly.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"commonly used in both written and spoken Chinese to describe deceitful actions","connotation":"negative","commonMistakes":"Learners might confuse this idiom with similar expressions that involve direct confrontation. Unlike direct attacks, this idiom specifically refers to secretive or deceitful actions.","canStandAlone":false},"examples":[{"simplified":"他总是暗箭伤人，大家都不信任他。","english":"He always attacks people by stealth, so no one trusts him.","traditional":"他總是暗箭傷人，大家都不信任他。"},{"simplified":"在职场上，暗箭伤人是不可取的行为。","english":"In the workplace, underhanded attacks are unacceptable behavior.","traditional":"在職場上，暗箭傷人是不可取的行為。"}],"synonyms":["背后捅刀"],"antonyms":["光明正大"],"confusedWith":[{"id":"背后捅刀","note":"Both involve deceit, but '背后捅刀' specifically implies betrayal by someone trusted."}],"traditional":"暗箭傷人","pinyinOverride":null},{"id":"an-shi-feng-deng","simplified":"暗室逢灯","literalMeaning":"dark room encounter lamp","figurativeMeaning":"to find a solution or guidance in a difficult situation","englishEquivalents":["a light in the dark","a guiding light"],"shortGloss":"finding guidance in darkness","characters":[{"char":"暗","meaning":"dark"},{"char":"室","meaning":"room"},{"char":"逢","meaning":"encounter"},{"char":"灯","meaning":"lamp"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '暗室逢灯' is often used to describe a situation where someone finds guidance or a solution in a difficult or confusing situation, much like finding a lamp in a dark room. The exact origin of the idiom is unclear, but it metaphorically represents the relief and clarity that comes from finding light in darkness.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"commonly used in both written and spoken Chinese","connotation":"positive","commonMistakes":"Learners might confuse this idiom with others that involve 'light' or 'darkness' but do not carry the same positive connotation of finding a solution or guidance.","canStandAlone":false},"examples":[{"simplified":"在他人生的低谷时，朋友的建议如同暗室逢灯。","english":"During the low point of his life, his friend's advice was like a light in the dark.","traditional":"在他人生的低谷時，朋友的建議如同暗室逢燈。"},{"simplified":"她的出现对我来说是暗室逢灯，让我看到了希望。","english":"Her appearance was like a guiding light to me, giving me hope.","traditional":"她的出現對我來說是暗室逢燈，讓我看到了希望。"}],"synonyms":["柳暗花明"],"antonyms":[],"confusedWith":[],"traditional":"暗室逢燈","pinyinOverride":null},{"id":"an-song-qiu-bo","simplified":"暗送秋波","literalMeaning":"secretly send autumn waves","figurativeMeaning":"to flirt or send amorous glances","englishEquivalents":["make eyes at","flirt with"],"shortGloss":"to flirt or send amorous glances","characters":[{"char":"暗","meaning":"secretly"},{"char":"送","meaning":"send"},{"char":"秋","meaning":"autumn"},{"char":"波","meaning":"waves"}],"origin":{"period":"Tang Dynasty (618–907 CE)","sourceText":"《西厢记》","sourceTextEnglish":"Romance of the Western Chamber","originalExcerpt":"","storyEnglish":"The idiom comes from the Tang Dynasty play 'Romance of the Western Chamber', where a young couple communicates their romantic interest through subtle, non-verbal cues. The 'autumn waves' metaphorically refers to the alluring, gentle glances exchanged between lovers, reminiscent of the soft, undulating waves seen in autumn.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"literary, but understood and used in modern speech, especially in romantic contexts","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with expressions that imply overt romantic actions. However, '暗送秋波' specifically refers to subtle, non-verbal flirting, not explicit gestures.","canStandAlone":false},"examples":[{"simplified":"在聚会上，他暗送秋波，引起了她的注意。","english":"At the party, he made eyes at her, catching her attention.","traditional":"在聚會上，他暗送秋波，引起了她的注意。"},{"simplified":"他们在课堂上暗送秋波，老师却没有发现。","english":"They exchanged flirtatious glances in class, but the teacher didn't notice.","traditional":"他們在課堂上暗送秋波，老師卻沒有發現。"}],"synonyms":["眉目传情"],"antonyms":[],"confusedWith":[{"id":"眉来眼去","note":"Both involve non-verbal romantic communication, but '眉来眼去' can imply a mutual exchange, while '暗送秋波' focuses on one-sided action."}],"traditional":"暗送秋波","pinyinOverride":null},{"id":"an-wu-tian-ri","simplified":"暗无天日","literalMeaning":"dark without daylight","figurativeMeaning":"a situation of extreme oppression or darkness, where justice and truth are obscured","englishEquivalents":["a dark and oppressive time","a reign of terror"],"shortGloss":"a dark, oppressive situation","characters":[{"char":"暗","meaning":"dark"},{"char":"无","meaning":"without"},{"char":"天","meaning":"sky; heaven; day"},{"char":"日","meaning":"sun; day"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom 暗无天日 is used to describe a period or situation where there is no justice or fairness, akin to living in darkness without the light of day. It conveys a sense of despair and hopelessness, often used to criticize tyrannical regimes or corrupt systems.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"modifier-head","register":"literary, but widely understood and used in both written and spoken Chinese","connotation":"negative","commonMistakes":"Learners might confuse 暗无天日 with similar expressions that describe literal darkness, but this idiom specifically refers to metaphorical darkness in terms of oppression or injustice.","canStandAlone":false},"examples":[{"simplified":"在那个暗无天日的时代，人们生活在恐惧之中。","english":"In that dark and oppressive era, people lived in fear.","traditional":"在那個暗無天日的時代，人們生活在恐懼之中。"},{"simplified":"他觉得公司的管理方式让员工感到暗无天日。","english":"He felt that the company's management style made employees feel like they were in a dark and oppressive situation.","traditional":"他覺得公司的管理方式讓員工感到暗無天日。"}],"synonyms":["乌烟瘴气"],"antonyms":["光明正大"],"confusedWith":[{"id":"黑暗","note":"黑暗 refers to literal darkness, whereas 暗无天日 describes a metaphorical, oppressive darkness."}],"traditional":"暗無天日","pinyinOverride":null},{"id":"an-zhong-mo-suo","simplified":"暗中摸索","literalMeaning":"explore in the dark","figurativeMeaning":"to explore or search for a solution without guidance or clear direction","englishEquivalents":["feeling one's way","groping in the dark"],"shortGloss":"searching without guidance","characters":[{"char":"暗","meaning":"dark"},{"char":"中","meaning":"in, within"},{"char":"摸","meaning":"feel, grope"},{"char":"索","meaning":"search, explore"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom 暗中摸索 describes the experience of trying to find one's way or solve a problem without clear guidance, much like feeling one's way through a dark room. It suggests a process of trial and error, where one must rely on intuition or guesswork due to a lack of information or direction.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["adverbial","complement"],"structure":"verb-object","register":"commonly used in both spoken and written Chinese to describe situations of uncertainty or lack of direction","connotation":"neutral","commonMistakes":"Learners might confuse 暗中摸索 with idioms that imply more deliberate or informed searching. This idiom specifically conveys a lack of clarity or direction.","canStandAlone":false},"examples":[{"simplified":"在没有明确指示的情况下，他只能暗中摸索。","english":"Without clear instructions, he could only feel his way.","traditional":"在沒有明確指示的情況下，他只能暗中摸索。"},{"simplified":"创业初期，我们都是在暗中摸索。","english":"In the early stages of the startup, we were all groping in the dark.","traditional":"創業初期，我們都是在暗中摸索。"}],"synonyms":["摸着石头过河"],"antonyms":[],"confusedWith":[{"id":"摸着石头过河","note":"Both involve trial and error, but 摸着石头过河 implies a more cautious and step-by-step approach."}],"traditional":"暗中摸索","pinyinOverride":null},{"id":"ang-shou-kuo-bu","simplified":"昂首阔步","literalMeaning":"raise head, stride wide","figurativeMeaning":"to walk with confidence and pride","englishEquivalents":["walk tall","strut one's stuff"],"shortGloss":"walk with confidence","characters":[{"char":"昂","meaning":"raise"},{"char":"首","meaning":"head"},{"char":"阔","meaning":"wide"},{"char":"步","meaning":"step"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom 昂首阔步 describes someone walking with their head held high and taking large, confident steps. It conveys an image of self-assurance and pride, often used to describe someone who is confident in their abilities or position.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"commonly used in both written and spoken Chinese to describe confident behavior","connotation":"positive","commonMistakes":"Learners might confuse this idiom with others that involve walking or movement but lack the specific connotation of confidence and pride. It's important to use it in contexts where the subject is displaying self-assurance.","canStandAlone":false},"examples":[{"simplified":"他昂首阔步地走进了会议室，显得非常自信。","english":"He walked into the meeting room with his head held high, appearing very confident.","traditional":"他昂首闊步地走進了會議室，顯得非常自信。"},{"simplified":"在比赛结束后，获胜的队伍昂首阔步地离开了球场。","english":"After the game ended, the winning team strode off the field with confidence.","traditional":"在比賽結束後，獲勝的隊伍昂首闊步地離開了球場。"}],"synonyms":["趾高气扬"],"antonyms":["垂头丧气"],"confusedWith":[{"id":"趾高气扬","note":"While both idioms describe confident behavior, 趾高气扬 often implies arrogance, whereas 昂首阔步 is more neutral or positive."}],"traditional":"昂首闊步","pinyinOverride":null},{"id":"ang-shou-ting-xiong","simplified":"昂首挺胸","literalMeaning":"raise head, straighten chest","figurativeMeaning":"to be confident and proud","englishEquivalents":["hold one's head high","stand tall"],"shortGloss":"be confident and proud","characters":[{"char":"昂","meaning":"raise"},{"char":"首","meaning":"head"},{"char":"挺","meaning":"straighten"},{"char":"胸","meaning":"chest"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '昂首挺胸' describes the posture of someone who is confident and proud, with their head held high and chest out. It is often used to describe someone who is facing challenges or adversity with courage and self-assurance.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"coordinate","register":"commonly used in both spoken and written Chinese to describe confidence or pride","connotation":"positive","commonMistakes":"Learners might confuse this idiom with those that imply arrogance or boastfulness. '昂首挺胸' conveys confidence without the negative connotations of arrogance.","canStandAlone":false},"examples":[{"simplified":"他在比赛中昂首挺胸，毫不畏惧。","english":"He held his head high in the competition, showing no fear.","traditional":"他在比賽中昂首挺胸，毫不畏懼。"},{"simplified":"面对困难，我们应该昂首挺胸，勇敢面对。","english":"In the face of difficulties, we should stand tall and confront them bravely.","traditional":"面對困難，我們應該昂首挺胸，勇敢面對。"}],"synonyms":["趾高气扬"],"antonyms":["垂头丧气"],"confusedWith":[{"id":"趾高气扬","note":"趾高气扬 implies arrogance, while 昂首挺胸 suggests confidence without arrogance."}],"traditional":"昂首挺胸","pinyinOverride":null},{"id":"ang-shou-wang-tian","simplified":"昂首望天","literalMeaning":"raise head look at sky","figurativeMeaning":"to be arrogant and conceited, ignoring reality or practical concerns","englishEquivalents":["head in the clouds","nose in the air"],"shortGloss":"arrogant and impractical","characters":[{"char":"昂","meaning":"raise"},{"char":"首","meaning":"head"},{"char":"望","meaning":"look at"},{"char":"天","meaning":"sky"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom describes someone who is so focused on lofty or unrealistic goals that they ignore the practical matters at hand. It paints a picture of a person who is literally looking up at the sky, oblivious to what is happening around them.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"used in both literary and colloquial contexts to describe someone who is overly proud or disconnected from reality","connotation":"negative","commonMistakes":"Learners might confuse this idiom with positive expressions of ambition or aspiration. However, it specifically implies arrogance and impracticality.","canStandAlone":false},"examples":[{"simplified":"他总是昂首望天，不愿意听取别人的建议。","english":"He always has his head in the clouds and refuses to listen to others' advice.","traditional":"他總是昂首望天，不願意聽取別人的建議。"},{"simplified":"在这个项目中，我们不能昂首望天，而是要脚踏实地。","english":"In this project, we can't have our heads in the clouds; we need to be practical.","traditional":"在這個項目中，我們不能昂首望天，而是要腳踏實地。"}],"synonyms":["目中无人"],"antonyms":["脚踏实地"],"confusedWith":[{"id":"志存高远","note":"志存高远 means having high ambitions, which is positive, unlike the arrogance implied by 昂首望天."}],"traditional":"昂首望天","pinyinOverride":null},{"id":"ao-ao-dai-bu","simplified":"嗷嗷待哺","literalMeaning":"crying loudly, waiting to be fed","figurativeMeaning":"to be in urgent need of help or sustenance","englishEquivalents":["crying for help","waiting to be fed"],"shortGloss":"in urgent need of help","characters":[{"char":"嗷","meaning":"cry loudly"},{"char":"嗷","meaning":"cry loudly"},{"char":"待","meaning":"waiting"},{"char":"哺","meaning":"to be fed"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '嗷嗷待哺' describes the image of young birds or animals crying out loudly as they wait to be fed by their parents. This vivid imagery has been extended metaphorically to describe people or situations in desperate need of assistance or resources.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"modifier-head","register":"literary, but can be used in both formal and informal contexts","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with others that involve waiting or crying, but this idiom specifically conveys a sense of urgent need or desperation.","canStandAlone":false},"examples":[{"simplified":"灾区的人民嗷嗷待哺，需要紧急救援。","english":"The people in the disaster area are crying for help and need urgent relief.","traditional":"災區的人民嗷嗷待哺，需要緊急救援。"},{"simplified":"在经济危机中，许多家庭嗷嗷待哺。","english":"During the economic crisis, many families were in urgent need of assistance.","traditional":"在經濟危機中，許多家庭嗷嗷待哺。"}],"synonyms":[],"antonyms":[],"confusedWith":[],"traditional":"嗷嗷待哺","pinyinOverride":null},{"id":"ao-geng-shou-ye","simplified":"熬更守夜","literalMeaning":"endure night watch","figurativeMeaning":"to stay up late or keep vigil through the night","englishEquivalents":["burn the midnight oil","pull an all-nighter"],"shortGloss":"stay up late, keep vigil","characters":[{"char":"熬","meaning":"endure, suffer through"},{"char":"更","meaning":"night watch, a period of the night"},{"char":"守","meaning":"guard, keep watch"},{"char":"夜","meaning":"night"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '熬更守夜' describes the act of staying awake through the night, often to complete a task or keep watch. Historically, night watches were divided into periods, and guards had to endure these long hours. Over time, the phrase came to symbolize the effort and endurance required to stay up late, whether for work or other reasons.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"commonly used in both written and spoken Chinese","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with others that imply staying up late, but '熬更守夜' specifically emphasizes endurance and vigilance, often with a sense of duty or necessity.","canStandAlone":false},"examples":[{"simplified":"为了完成项目，他不得不熬更守夜。","english":"To finish the project, he had to stay up late.","traditional":"為了完成項目，他不得不熬更守夜。"},{"simplified":"熬更守夜对身体健康不利。","english":"Staying up late is not good for one's health.","traditional":"熬更守夜對身體健康不利。"}],"synonyms":["挑灯夜战"],"antonyms":[],"confusedWith":[{"id":"夜以继日","note":"夜以继日 implies working continuously day and night, not just staying up late."}],"traditional":"熬更守夜","pinyinOverride":null},{"id":"ao-xin-fei-li","simplified":"熬心费力","literalMeaning":"burn heart, expend effort","figurativeMeaning":"to work hard and endure mental anguish; to toil and suffer","englishEquivalents":["blood, sweat, and tears","to go through fire and water"],"shortGloss":"to toil and suffer","characters":[{"char":"熬","meaning":"to endure, to suffer"},{"char":"心","meaning":"heart, mind"},{"char":"费","meaning":"to expend, to spend"},{"char":"力","meaning":"effort, strength"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '熬心费力' describes the experience of enduring significant mental and physical challenges. It conveys the idea of putting one's heart and soul into a task, often at great personal cost. The phrase is used to highlight the intensity of effort and the emotional toll involved in achieving something difficult.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"coordinate","register":"commonly used in both spoken and written Chinese to describe arduous efforts","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with others that describe hard work but lack the emotional or mental anguish component, such as '埋头苦干'.","canStandAlone":false},"examples":[{"simplified":"为了完成这个项目，他熬心费力，几乎没有休息。","english":"To complete this project, he worked tirelessly and endured much mental strain, hardly taking any breaks.","traditional":"為了完成這個項目，他熬心費力，幾乎沒有休息。"},{"simplified":"她熬心费力地照顾生病的母亲，令人感动。","english":"She toiled and suffered to care for her sick mother, which was truly moving.","traditional":"她熬心費力地照顧生病的母親，令人感動。"}],"synonyms":["呕心沥血"],"antonyms":[],"confusedWith":[{"id":"埋头苦干","note":"埋头苦干 focuses on hard work without the emotional or mental anguish implied by 熬心费力."}],"traditional":"熬心費力","pinyinOverride":null},{"id":"ao-gu-lin-lin","simplified":"傲骨嶙嶙","literalMeaning":"proud bones protruding","figurativeMeaning":"having a proud and unyielding character","englishEquivalents":["stiff-necked","unyielding spirit"],"shortGloss":"proud and unyielding character","characters":[{"char":"傲","meaning":"proud"},{"char":"骨","meaning":"bones"},{"char":"嶙","meaning":"protruding"},{"char":"嶙","meaning":"protruding"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '傲骨嶙嶙' describes someone with a proud and unyielding character, likening their spirit to bones that stand out prominently. This imagery suggests a person who remains steadfast and does not easily bend to external pressures or compromise their principles.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["attributive","predicate"],"structure":"modifier-head","register":"literary, but understood in educated speech","connotation":"positive","commonMistakes":"Learners often confuse this idiom with expressions that merely indicate stubbornness without the positive connotation of integrity and pride. It's important to use it to describe someone who is unyielding in a principled way, not just obstinate.","canStandAlone":false},"examples":[{"simplified":"他是一个傲骨嶙嶙的人，从不向权势低头。","english":"He is a person with an unyielding spirit, never bowing to power.","traditional":"他是一個傲骨嶙嶙的人，從不向權勢低頭。"},{"simplified":"在逆境中，她展现出傲骨嶙嶙的精神。","english":"In adversity, she displayed a proud and unyielding spirit.","traditional":"在逆境中，她展現出傲骨嶙嶙的精神。"}],"synonyms":["铁骨铮铮"],"antonyms":["随波逐流"],"confusedWith":[{"id":"顽固不化","note":"While '顽固不化' implies stubbornness without positive connotations, '傲骨嶙嶙' suggests a principled and proud character."}],"traditional":"傲骨嶙嶙","pinyinOverride":null},{"id":"ao-man-bu-xun","simplified":"傲慢不逊","literalMeaning":"arrogant and disrespectful","figurativeMeaning":"arrogant and rude; showing no respect for others","englishEquivalents":["high and mighty","full of oneself"],"shortGloss":"arrogant and disrespectful","characters":[{"char":"傲","meaning":"arrogant"},{"char":"慢","meaning":"proud"},{"char":"不","meaning":"not"},{"char":"逊","meaning":"yielding; modest"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '傲慢不逊' is used to describe someone who is excessively proud and shows no respect for others. It is a common expression in Chinese to criticize someone who behaves in a conceited and disrespectful manner.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"coordinate","register":"commonly used in both spoken and written Chinese to describe arrogant behavior","connotation":"negative","commonMistakes":"Learners might confuse '傲慢不逊' with '自高自大', which also means arrogant but lacks the specific connotation of disrespect towards others.","canStandAlone":false},"examples":[{"simplified":"他的态度傲慢不逊，让人很反感。","english":"His arrogant and disrespectful attitude is very off-putting.","traditional":"他的態度傲慢不遜，讓人很反感。"},{"simplified":"作为一个领导者，他不应该表现得傲慢不逊。","english":"As a leader, he should not behave in an arrogant and disrespectful manner.","traditional":"作為一個領導者，他不應該表現得傲慢不遜。"}],"synonyms":["自高自大","目中无人"],"antonyms":["谦虚谨慎"],"confusedWith":[{"id":"自高自大","note":"Both describe arrogance, but '傲慢不逊' emphasizes disrespect towards others."}],"traditional":"傲慢不遜","pinyinOverride":null},{"id":"ao-ni-wan-wu","simplified":"傲睨万物","literalMeaning":"arrogantly gaze at all things","figurativeMeaning":"to look down on everything with arrogance","englishEquivalents":["look down one's nose at everything","be disdainful of everything"],"shortGloss":"arrogantly disdain everything","characters":[{"char":"傲","meaning":"arrogant"},{"char":"睨","meaning":"to gaze at"},{"char":"万","meaning":"ten thousand, all"},{"char":"物","meaning":"things"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '傲睨万物' describes a person who looks down on everything around them with arrogance and disdain. It captures the image of someone who considers themselves superior to the world and its inhabitants.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"modifier-head","register":"literary, but can be used in formal speech to describe someone's attitude","connotation":"negative","commonMistakes":"Learners might confuse this idiom with others that describe confidence or self-assuredness, but '傲睨万物' specifically implies a negative, disdainful arrogance.","canStandAlone":false},"examples":[{"simplified":"他总是傲睨万物，让人觉得很不舒服。","english":"He always looks down on everything, making people feel very uncomfortable.","traditional":"他總是傲睨萬物，讓人覺得很不舒服。"},{"simplified":"她的态度傲睨万物，似乎没有什么能入她的眼。","english":"Her attitude is disdainful of everything, as if nothing is worthy of her attention.","traditional":"她的態度傲睨萬物，似乎沒有什麼能入她的眼。"}],"synonyms":[],"antonyms":[],"confusedWith":[{"id":"目中无人","note":"While both idioms describe arrogance, '目中无人' emphasizes ignoring others, whereas '傲睨万物' emphasizes disdain for everything."}],"traditional":"傲睨萬物","pinyinOverride":null},{"id":"ao-ni-zi-ruo","simplified":"傲睨自若","literalMeaning":"arrogant gaze self-assured","figurativeMeaning":"to remain calm and composed in the face of challenges or pressure","englishEquivalents":["keep a stiff upper lip","maintain one's composure"],"shortGloss":"stay calm and composed","characters":[{"char":"傲","meaning":"arrogant"},{"char":"睨","meaning":"gaze"},{"char":"自","meaning":"self"},{"char":"若","meaning":"as if"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '傲睨自若' describes a person who remains calm and composed, even when facing difficult situations. It conveys an image of someone who is confident and unflustered, maintaining their dignity and poise regardless of external pressures.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"modifier-head","register":"literary, but can be used in formal speech and writing","connotation":"neutral","commonMistakes":"Learners may confuse this idiom with other expressions of arrogance. However, '傲睨自若' emphasizes calmness and composure, not haughtiness.","canStandAlone":false},"examples":[{"simplified":"在危机面前，他总是傲睨自若。","english":"In the face of a crisis, he always remains calm and composed.","traditional":"在危機面前，他總是傲睨自若。"},{"simplified":"即使在比赛中落后，他依然傲睨自若。","english":"Even when trailing in the competition, he still maintains his composure.","traditional":"即使在比賽中落後，他依然傲睨自若。"}],"synonyms":["泰然自若"],"antonyms":["惊慌失措"],"confusedWith":[{"id":"傲慢无礼","note":"傲慢无礼 means being arrogant and rude, whereas 傲睨自若 emphasizes calmness and composure."}],"traditional":"傲睨自若","pinyinOverride":null},{"id":"ao-ran-yi-li","simplified":"傲然屹立","literalMeaning":"proudly stand tall","figurativeMeaning":"to stand firm and unyielding, often in the face of adversity","englishEquivalents":["stand tall","stand firm"],"shortGloss":"stand firm and unyielding","characters":[{"char":"傲","meaning":"proud"},{"char":"然","meaning":"adverbial particle, indicating manner"},{"char":"屹","meaning":"stand tall"},{"char":"立","meaning":"stand"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '傲然屹立' is often used to describe someone or something that remains strong and unyielding, despite challenges or difficulties. It evokes the image of a person or structure standing proudly and firmly, like a mountain that withstands the test of time and weather.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"widely used in both written and spoken Chinese, often in formal contexts","connotation":"positive","commonMistakes":"Learners might confuse this idiom with others that imply stubbornness rather than resilience. It's important to note that '傲然屹立' carries a positive connotation of dignity and strength, not obstinacy.","canStandAlone":false},"examples":[{"simplified":"在风暴中，这座灯塔依然傲然屹立。","english":"In the storm, the lighthouse still stood tall and firm.","traditional":"在風暴中，這座燈塔依然傲然屹立。"},{"simplified":"尽管面临许多困难，他依然傲然屹立，毫不退缩。","english":"Despite facing many difficulties, he stood firm and unyielding, without retreating.","traditional":"儘管面臨許多困難，他依然傲然屹立，毫不退縮。"}],"synonyms":["坚定不移","屹立不倒"],"antonyms":["摇摇欲坠"],"confusedWith":[{"id":"固执己见","note":"固执己见 implies stubbornness and unwillingness to change one's views, while 傲然屹立 emphasizes resilience and strength."}],"traditional":"傲然屹立","pinyinOverride":null},{"id":"ao-shuang-dou-xue","simplified":"傲霜斗雪","literalMeaning":"proud of frost, fight snow","figurativeMeaning":"to be strong and resilient in the face of adversity","englishEquivalents":["stand firm against adversity","weather the storm"],"shortGloss":"resilient against adversity","characters":[{"char":"傲","meaning":"proud"},{"char":"霜","meaning":"frost"},{"char":"斗","meaning":"fight"},{"char":"雪","meaning":"snow"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '傲霜斗雪' is often used to describe someone who remains strong and unyielding despite facing harsh conditions, much like plants that continue to thrive in the cold of winter. It emphasizes resilience and courage in the face of challenges.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"coordinate","register":"literary, but understood and used in both formal and informal contexts","connotation":"positive","commonMistakes":"Learners might confuse this idiom with others that involve winter imagery but do not emphasize resilience. It's important to note that '傲霜斗雪' specifically highlights strength and courage in adversity.","canStandAlone":false},"examples":[{"simplified":"他在逆境中傲霜斗雪，从未放弃。","english":"He stood firm against adversity, never giving up.","traditional":"他在逆境中傲霜鬥雪，從未放棄。"},{"simplified":"梅花在寒冬中傲霜斗雪，象征着坚韧不拔的精神。","english":"The plum blossoms stand resilient against the frost and snow of winter, symbolizing an indomitable spirit.","traditional":"梅花在寒冬中傲霜鬥雪，象徵著堅韌不拔的精神。"}],"synonyms":["坚韧不拔","百折不挠"],"antonyms":["临阵脱逃"],"confusedWith":[{"id":"梅花傲雪","note":"While both idioms involve winter imagery, '梅花傲雪' specifically refers to the plum blossom's beauty and resilience in winter, whereas '傲霜斗雪' emphasizes general resilience against adversity."}],"traditional":"傲霜鬥雪","pinyinOverride":null},{"id":"ao-tou-ao-nao","simplified":"傲头傲脑","literalMeaning":"proud head proud mind","figurativeMeaning":"arrogant and self-important","englishEquivalents":["high and mighty","stuck-up"],"shortGloss":"arrogant and self-important","characters":[{"char":"傲","meaning":"proud, arrogant"},{"char":"头","meaning":"head"},{"char":"傲","meaning":"proud, arrogant"},{"char":"脑","meaning":"mind"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '傲头傲脑' is believed to have originated from folk expressions describing someone who carries themselves with an air of arrogance and self-importance. It paints a picture of a person whose demeanor and attitude are haughty, as if they hold their head high above others.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["attributive","adverbial"],"structure":"coordinate","register":"informal, commonly used in spoken Chinese","connotation":"negative","commonMistakes":"Learners might confuse '傲头傲脑' with '自信' (self-confident), but '傲头傲脑' has a negative connotation of arrogance, whereas '自信' is positive.","canStandAlone":false},"examples":[{"simplified":"他总是傲头傲脑的，大家都不太喜欢他。","english":"He's always so arrogant and self-important that nobody really likes him.","traditional":"他總是傲頭傲腦的，大家都不太喜歡他。"},{"simplified":"她傲头傲脑地走进房间，引起了大家的不满。","english":"She walked into the room with an air of arrogance, causing everyone's displeasure.","traditional":"她傲頭傲腦地走進房間，引起了大家的不滿。"}],"synonyms":["目中无人","自高自大"],"antonyms":["谦虚谨慎"],"confusedWith":[{"id":"自信","note":"自信 means self-confident, which is positive, unlike the negative connotation of 傲头傲脑."}],"traditional":"傲頭傲腦","pinyinOverride":null},{"id":"ao-xian-man-shi","simplified":"傲贤慢士","literalMeaning":"arrogant to the wise, disrespectful to the capable","figurativeMeaning":"to be arrogant and dismissive towards talented or capable people","englishEquivalents":["Look down on others","Disdain for the competent"],"shortGloss":"arrogant towards the capable","characters":[{"char":"傲","meaning":"arrogant"},{"char":"贤","meaning":"wise, virtuous"},{"char":"慢","meaning":"disrespectful, dismissive"},{"char":"士","meaning":"scholars, capable people"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom describes a person who is arrogant and dismissive towards those who are wise or capable. It is often used to criticize someone who fails to recognize or respect the talents and abilities of others, potentially to their own detriment.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"coordinate","register":"literary, but can be used in formal speech","connotation":"negative","commonMistakes":"Learners might confuse this idiom with others that involve arrogance, but this specifically emphasizes arrogance towards those who are talented or wise, not just general arrogance.","canStandAlone":false},"examples":[{"simplified":"他总是傲贤慢士，结果没有人愿意帮助他。","english":"He is always arrogant and dismissive towards the capable, so no one is willing to help him.","traditional":"他總是傲賢慢士，結果沒有人願意幫助他。"},{"simplified":"在公司里，傲贤慢士的态度让他失去了很多机会。","english":"In the company, his attitude of being arrogant towards the capable cost him many opportunities.","traditional":"在公司裡，傲賢慢士的態度讓他失去了很多機會。"}],"synonyms":[],"antonyms":[],"confusedWith":[],"traditional":"傲賢慢士","pinyinOverride":null},{"id":"ao-yuan-you-ling","simplified":"奥援有灵","literalMeaning":"hidden support has spirit","figurativeMeaning":"having secret or hidden backing or support","englishEquivalents":["having friends in high places","backed by powerful allies"],"shortGloss":"secret backing or support","characters":[{"char":"奥","meaning":"hidden, secret"},{"char":"援","meaning":"support, assistance"},{"char":"有","meaning":"have, possess"},{"char":"灵","meaning":"spirit, effective"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom suggests the idea of having unseen or secret support that is effective and influential. It implies that someone has backing from powerful or influential sources that are not immediately visible to others.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"subject-predicate","register":"formal written Chinese, occasionally used in speech","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with others that imply overt support rather than hidden or secret backing. It's important to note the 'hidden' aspect of the support in this idiom.","canStandAlone":false},"examples":[{"simplified":"他能成功，全靠奥援有灵。","english":"He was able to succeed entirely because of his hidden support.","traditional":"他能成功，全靠奧援有靈。"},{"simplified":"在这次竞选中，她的奥援有灵，使她占据了优势。","english":"In this election, her hidden backing gave her an advantage.","traditional":"在這次競選中，她的奧援有靈，使她佔據了優勢。"}],"synonyms":[],"antonyms":[],"confusedWith":[],"traditional":"奧援有靈","pinyinOverride":null},{"id":"ai-ai-fu-mu","simplified":"哀哀父母","literalMeaning":"sorrowful sorrowful parents","figurativeMeaning":"the deep sorrow and hardship parents endure for their children","englishEquivalents":["a parent's love knows no bounds","parental sacrifice"],"shortGloss":"parental sorrow and sacrifice","characters":[{"char":"哀","meaning":"sorrowful, lamenting"},{"char":"哀","meaning":"sorrowful, lamenting"},{"char":"父","meaning":"father, parent"},{"char":"母","meaning":"mother, parent"}],"origin":{"period":"Warring States period (475–221 BCE)","sourceText":"《诗经·小雅·蓼莪》","sourceTextEnglish":"Book of Songs, Minor Odes, Liao E","originalExcerpt":"哀哀父母，生我劬劳。","storyEnglish":"This idiom originates from the 'Book of Songs', one of the oldest collections of Chinese poetry. The poem 'Liao E' reflects on the hardships and sacrifices parents endure to raise their children. It expresses gratitude and sorrow for the parents' efforts and the burdens they bear.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["subject","predicate","object"],"structure":"coordinate","register":"literary, often used in formal writing or speeches to express gratitude towards parents","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with others that express filial piety, but this idiom specifically emphasizes the sorrow and effort of parents, not the child's duty.","canStandAlone":false},"examples":[{"simplified":"在母亲节，我们要记得哀哀父母，感谢他们的付出。","english":"On Mother's Day, we should remember the sorrow and sacrifice of our parents and thank them for their dedication.","traditional":"在母親節，我們要記得哀哀父母，感謝他們的付出。"},{"simplified":"他常常感慨哀哀父母，努力工作以回报他们。","english":"He often reflects on the sorrow and sacrifice of his parents and works hard to repay them.","traditional":"他常常感慨哀哀父母，努力工作以回報他們。"}],"synonyms":[],"antonyms":[],"confusedWith":[{"id":"孝顺","note":"孝顺 (filial piety) focuses on the child's duty to parents, while 哀哀父母 emphasizes the parents' sacrifices."}],"traditional":"哀哀父母","pinyinOverride":null},{"id":"ai-gan-zhong-nian","simplified":"哀感中年","literalMeaning":"sorrow affects middle age","figurativeMeaning":"to feel a deep sense of sadness or melancholy often associated with middle age","englishEquivalents":["midlife crisis","melancholy of middle age"],"shortGloss":"midlife melancholy","characters":[{"char":"哀","meaning":"sorrow"},{"char":"感","meaning":"affect"},{"char":"中","meaning":"middle"},{"char":"年","meaning":"age"}],"origin":{"period":"Tang dynasty (618–907 CE)","sourceText":"《杜甫诗选》","sourceTextEnglish":"Selected Poems of Du Fu","originalExcerpt":"感时花溅泪，恨别鸟惊心。烽火连三月，家书抵万金。白头搔更短，浑欲不胜簪。","storyEnglish":"This idiom originates from a poem by Du Fu, a famous poet of the Tang dynasty. In his poem, Du Fu expresses the sorrow and melancholy he feels as he reflects on the passage of time and the hardships of life, particularly as he reaches middle age. The phrase captures the universal experience of reflecting on one's life and feeling a deep sense of sadness as one grows older.","historicalFigures":["Du Fu"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","complement"],"structure":"subject-predicate","register":"literary, but can be used in reflective or poetic contexts in modern speech","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with expressions that simply denote sadness, but it specifically refers to a reflective melancholy associated with middle age. It is not used for general sadness or depression.","canStandAlone":false},"examples":[{"simplified":"他最近常常感叹人生，哀感中年。","english":"He has recently been lamenting life, feeling the melancholy of middle age.","traditional":"他最近常常感嘆人生，哀感中年。"},{"simplified":"在四十岁生日那天，他不禁哀感中年。","english":"On his fortieth birthday, he couldn't help but feel the melancholy of middle age.","traditional":"在四十歲生日那天，他不禁哀感中年。"}],"synonyms":[],"antonyms":[],"confusedWith":[{"id":"伤春悲秋","note":"While both idioms express a sense of sadness, 伤春悲秋 refers more to a general melancholy related to the changing seasons, not specifically to middle age."}],"traditional":"哀感中年","pinyinOverride":null},{"id":"ai-gao-bin-fu","simplified":"哀告宾服","literalMeaning":"plead and submit as a guest","figurativeMeaning":"to plead for mercy and submit to authority","englishEquivalents":["beg for mercy","plead and surrender"],"shortGloss":"plead for mercy and submit","characters":[{"char":"哀","meaning":"to plead, to lament"},{"char":"告","meaning":"to inform, to announce"},{"char":"宾","meaning":"guest, visitor"},{"char":"服","meaning":"to submit, to obey"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '哀告宾服' is believed to originate from a story where a person, facing overwhelming odds, pleads for mercy and submits to a more powerful authority, much like a guest who acknowledges the host's dominance. The exact historical context and source of this idiom are not clearly documented, and it is often considered to have a folk origin.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"literary, but can be used in formal speech","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with others that involve submission or pleading, but it specifically implies a formal or respectful plea for mercy, often in a hierarchical context.","canStandAlone":false},"examples":[{"simplified":"在敌人面前，他不得不哀告宾服。","english":"In front of the enemy, he had no choice but to plead for mercy and submit.","traditional":"在敵人面前，他不得不哀告賓服。"},{"simplified":"为了保全家人，他选择了哀告宾服。","english":"To protect his family, he chose to plead for mercy and submit.","traditional":"為了保全家人，他選擇了哀告賓服。"}],"synonyms":[],"antonyms":[],"confusedWith":[],"traditional":"哀告賓服","pinyinOverride":null},{"id":"ai-li-zheng-shi","simplified":"哀梨蒸食","literalMeaning":"sorrowful pear steamed and eaten","figurativeMeaning":"to spoil something good by using it inappropriately; to waste a good thing","englishEquivalents":["kill the goose that lays the golden eggs","waste not, want not"],"shortGloss":"wasting something good","characters":[{"char":"哀","meaning":"sorrowful"},{"char":"梨","meaning":"pear"},{"char":"蒸","meaning":"steam"},{"char":"食","meaning":"eat"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '哀梨蒸食' refers to a story where someone steamed a pear, which is naturally sweet and best enjoyed raw, thus ruining its natural flavor. The story highlights the folly of misusing something good, thereby wasting its inherent value.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["adverbial","attributive"],"structure":"modifier-head","register":"literary, but understood in educated speech","connotation":"negative","commonMistakes":"Learners often misunderstand this idiom as simply referring to cooking or eating, but it actually criticizes the misuse or waste of valuable things. It's not about food, but about the principle of preserving value.","canStandAlone":false},"examples":[{"simplified":"他把珍贵的古董当普通家具使用，真是哀梨蒸食。","english":"He used the precious antique as regular furniture, truly a case of wasting something good.","traditional":"他把珍貴的古董當普通傢俱使用，真是哀梨蒸食。"},{"simplified":"如果你不珍惜这些资源，那就是哀梨蒸食。","english":"If you don't cherish these resources, it's like wasting something valuable.","traditional":"如果你不珍惜這些資源，那就是哀梨蒸食。"}],"synonyms":["暴殄天物"],"antonyms":[],"confusedWith":[{"id":"暴殄天物","note":"Both idioms deal with wasting valuable resources, but '暴殄天物' is more general, while '哀梨蒸食' specifically implies misuse."}],"traditional":"哀梨蒸食","pinyinOverride":null},{"id":"ai-si-hao-zhu","simplified":"哀丝豪竹","literalMeaning":"mournful silk, grand bamboo","figurativeMeaning":"music that evokes deep emotions, often with contrasting elements of sorrow and grandeur","englishEquivalents":["music that stirs the soul","haunting melody"],"shortGloss":"emotionally stirring music","characters":[{"char":"哀","meaning":"mournful, sorrowful"},{"char":"丝","meaning":"silk, referring to string instruments"},{"char":"豪","meaning":"grand, heroic"},{"char":"竹","meaning":"bamboo, referring to wind instruments"}],"origin":{"period":"Tang dynasty (618–907 CE)","sourceText":"《旧唐书·音乐志》","sourceTextEnglish":"Old Book of Tang, Treatise on Music","originalExcerpt":"哀丝豪竹，皆是乐中之妙。","storyEnglish":"This idiom comes from a description in the 'Old Book of Tang' where it refers to the profound and contrasting emotions that can be conveyed through music, particularly through the use of string and wind instruments. The 'silk' represents string instruments like the guqin, while 'bamboo' refers to wind instruments like the flute. Together, they create a powerful emotional experience.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["subject","object","attributive"],"structure":"coordinate","register":"literary, often used in discussions of music or art to describe deeply moving compositions","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with others that describe music but lack the specific emotional contrast of sorrow and grandeur. It's important to use it in contexts where the music's emotional depth is emphasized.","canStandAlone":false},"examples":[{"simplified":"这首曲子真是哀丝豪竹，让人心醉神迷。","english":"This piece truly embodies '哀丝豪竹', leaving one enchanted and deeply moved.","traditional":"這首曲子真是哀絲豪竹，讓人心醉神迷。"},{"simplified":"他的演奏充满了哀丝豪竹的情感，令人难以忘怀。","english":"His performance was full of the emotions of '哀丝豪竹', making it unforgettable.","traditional":"他的演奏充滿了哀絲豪竹的情感，令人難以忘懷。"}],"synonyms":[],"antonyms":[],"confusedWith":[],"traditional":"哀絲豪竹","pinyinOverride":null},{"id":"ai-feng-ji-feng","simplified":"挨风缉缝","literalMeaning":"lean on the wind, patch the seams","figurativeMeaning":"to take advantage of opportunities or loopholes; to exploit situations for personal gain","englishEquivalents":["play the angles","work the system"],"shortGloss":"exploit opportunities or loopholes","characters":[{"char":"挨","meaning":"lean on; get close to"},{"char":"风","meaning":"wind; opportunity"},{"char":"缉","meaning":"sew; patch"},{"char":"缝","meaning":"seam; gap"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '挨风缉缝' is believed to have originated from the idea of a tailor who skillfully patches seams by taking advantage of the wind to align the fabric. Over time, it came to describe people who are adept at finding and exploiting opportunities or loopholes in various situations for their own benefit.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["adverbial","attributive"],"structure":"coordinate","register":"used in both formal and informal contexts to describe someone who is opportunistic","connotation":"negative","commonMistakes":"Learners often confuse this idiom with positive expressions of resourcefulness. However, '挨风缉缝' carries a negative connotation of exploiting situations unethically.","canStandAlone":false},"examples":[{"simplified":"他总是挨风缉缝，利用规则的漏洞来获利。","english":"He always plays the angles, exploiting loopholes in the rules to profit.","traditional":"他總是挨風緝縫，利用規則的漏洞來獲利。"},{"simplified":"在商业中，挨风缉缝的人往往不受欢迎。","english":"In business, people who exploit opportunities unethically are often unwelcome.","traditional":"在商業中，挨風緝縫的人往往不受歡迎。"}],"synonyms":["投机取巧"],"antonyms":["光明磊落"],"confusedWith":[{"id":"见风使舵","note":"While both involve adapting to circumstances, '见风使舵' is more about being flexible and adaptable, not necessarily unethical."}],"traditional":"挨風緝縫","pinyinOverride":null},{"id":"ai-jian-ca-bang","simplified":"挨肩擦膀","literalMeaning":"shoulder to shoulder, rubbing arms","figurativeMeaning":"to be in close contact or proximity with others, often in a crowded or bustling environment","englishEquivalents":["shoulder to shoulder","cheek by jowl"],"shortGloss":"in close contact or proximity","characters":[{"char":"挨","meaning":"to be close to; to press against"},{"char":"肩","meaning":"shoulder"},{"char":"擦","meaning":"to rub"},{"char":"膀","meaning":"arm"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '挨肩擦膀' likely originates from the experience of being in crowded places where people are so close together that their shoulders and arms touch. It conveys the sense of being in a bustling, lively environment.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["adverbial","attributive"],"structure":"coordinate","register":"commonly used in both spoken and written Chinese to describe crowded or busy settings","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with expressions that imply physical conflict or aggression, but it simply describes proximity, not confrontation.","canStandAlone":false},"examples":[{"simplified":"在地铁上，我们常常挨肩擦膀。","english":"On the subway, we are often shoulder to shoulder.","traditional":"在地鐵上，我們常常挨肩擦膀。"},{"simplified":"节日的市场上，人们挨肩擦膀，热闹非凡。","english":"At the holiday market, people were shoulder to shoulder, creating a lively atmosphere.","traditional":"節日的市場上，人們挨肩擦膀，熱鬧非凡。"}],"synonyms":[],"antonyms":[],"confusedWith":[],"traditional":"挨肩擦膀","pinyinOverride":null},{"id":"ai-jian-ca-lian","simplified":"挨肩擦脸","literalMeaning":"press shoulder, rub face","figurativeMeaning":"to be in close contact or proximity with someone, often implying intimacy or familiarity","englishEquivalents":["rub shoulders with","be cheek by jowl with"],"shortGloss":"be in close contact","characters":[{"char":"挨","meaning":"press, close"},{"char":"肩","meaning":"shoulder"},{"char":"擦","meaning":"rub"},{"char":"脸","meaning":"face"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom likely originates from the imagery of people being physically close enough to touch shoulders and faces, suggesting a sense of intimacy or familiarity. It is often used to describe crowded situations or close relationships.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"informal, commonly used in everyday speech","connotation":"neutral","commonMistakes":"Learners may confuse this idiom with expressions that imply conflict or confrontation due to the physical imagery. It is important to remember it implies closeness or intimacy, not aggression.","canStandAlone":false},"examples":[{"simplified":"在地铁上，人们常常挨肩擦脸。","english":"On the subway, people often rub shoulders with each other.","traditional":"在地鐵上，人們常常挨肩擦臉。"},{"simplified":"他们在聚会上挨肩擦脸，看起来很亲密。","english":"They were rubbing shoulders at the party, looking very close.","traditional":"他們在聚會上挨肩擦臉，看起來很親密。"}],"synonyms":[],"antonyms":[],"confusedWith":[{"id":"针锋相对","note":"挨肩擦脸 implies closeness or intimacy, while 针锋相对 implies confrontation or opposition."}],"traditional":"挨肩擦臉","pinyinOverride":null},{"id":"ai-san-ding-wu","simplified":"挨三顶五","literalMeaning":"push three, bump five","figurativeMeaning":"to jostle or push around; to be crowded","englishEquivalents":["packed like sardines","jam-packed"],"shortGloss":"crowded or jostling","characters":[{"char":"挨","meaning":"push, jostle"},{"char":"三","meaning":"three"},{"char":"顶","meaning":"bump, push against"},{"char":"五","meaning":"five"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '挨三顶五' describes a situation where people are crowded together, pushing and jostling each other. It likely originated from the experience of being in a bustling, crowded place where people are constantly bumping into each other.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"coordinate","register":"colloquial, commonly used in everyday speech","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with expressions that imply conflict or fighting, but it specifically refers to a crowded or jostling situation, not an aggressive one.","canStandAlone":false},"examples":[{"simplified":"地铁上挨三顶五，真是挤得不行。","english":"The subway was so crowded, people were packed like sardines.","traditional":"地鐵上挨三頂五，真是擠得不行。"},{"simplified":"节日市场上挨三顶五，买东西很不方便。","english":"The market was jam-packed during the festival, making shopping very inconvenient.","traditional":"節日市場上挨三頂五，買東西很不方便。"}],"synonyms":["人山人海","摩肩接踵"],"antonyms":["空空如也"],"confusedWith":[{"id":"打打闹闹","note":"打打闹闹 implies playful fighting or roughhousing, not just being crowded."}],"traditional":"挨三頂五","pinyinOverride":null},{"id":"ai-shan-sai-hai","simplified":"挨山塞海","literalMeaning":"press against mountains, block the sea","figurativeMeaning":"crowded or packed with people","englishEquivalents":["packed like sardines","jam-packed","crowded to the gills"],"shortGloss":"extremely crowded","characters":[{"char":"挨","meaning":"press against"},{"char":"山","meaning":"mountain"},{"char":"塞","meaning":"block"},{"char":"海","meaning":"sea"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '挨山塞海' is used to describe a situation where there are so many people that it feels as if they are pressing against mountains and blocking the sea. It vividly conveys the sense of being in a densely packed crowd, similar to being in a place that is bursting at the seams with people.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"coordinate","register":"informal, commonly used in spoken Chinese to describe crowded places","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with others that describe difficult situations, but it specifically refers to a physical crowding of people, not challenges or obstacles.","canStandAlone":false},"examples":[{"simplified":"节日的广场上挨山塞海，几乎没有立足之地。","english":"The square was packed like sardines during the festival, with hardly any room to stand.","traditional":"節日的廣場上挨山塞海，幾乎沒有立足之地。"},{"simplified":"商场里挨山塞海，购物的人络绎不绝。","english":"The mall was jam-packed, with a continuous stream of shoppers.","traditional":"商場裡挨山塞海，購物的人絡繹不絕。"}],"synonyms":["人山人海"],"antonyms":[],"confusedWith":[{"id":"人满为患","note":"While both describe crowded situations, '人满为患' implies that the crowding is causing problems or difficulties."}],"traditional":"挨山塞海","pinyinOverride":null},{"id":"ai-bie-li-ku","simplified":"爱别离苦","literalMeaning":"love separation suffering","figurativeMeaning":"the pain of being separated from loved ones","englishEquivalents":["parting is such sweet sorrow","absence makes the heart grow fonder"],"shortGloss":"the pain of separation from loved ones","characters":[{"char":"爱","meaning":"love"},{"char":"别","meaning":"separation"},{"char":"离","meaning":"leave"},{"char":"苦","meaning":"suffering"}],"origin":{"period":"Buddhist texts","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"This idiom is derived from Buddhist teachings, which describe various forms of suffering in life. One of these is the suffering caused by being separated from loved ones. It reflects the universal human experience of longing and sadness when apart from those we care about.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["subject","predicate","object"],"structure":"modifier-head","register":"literary, but understood in ordinary speech","connotation":"negative","commonMistakes":"Learners often confuse this idiom with similar expressions of longing or nostalgia, but this idiom specifically emphasizes the suffering aspect of separation.","canStandAlone":false},"examples":[{"simplified":"每次出差，我都感受到爱别离苦。","english":"Every time I go on a business trip, I feel the pain of being separated from loved ones.","traditional":"每次出差，我都感受到愛別離苦。"},{"simplified":"他无法忍受爱别离苦，决定搬回家乡。","english":"Unable to bear the pain of being separated from loved ones, he decided to move back to his hometown.","traditional":"他無法忍受愛別離苦，決定搬回家鄉。"}],"synonyms":[],"antonyms":[],"confusedWith":[],"traditional":"愛別離苦","pinyinOverride":null},{"id":"ai-mao-fan-qiu","simplified":"爱毛反裘","literalMeaning":"cherish fur, wear fur inside out","figurativeMeaning":"to cherish something trivial while neglecting the essential; to put the cart before the horse","englishEquivalents":["put the cart before the horse","miss the forest for the trees"],"shortGloss":"cherish the trivial, neglect the essential","characters":[{"char":"爱","meaning":"cherish"},{"char":"毛","meaning":"fur"},{"char":"反","meaning":"inside out"},{"char":"裘","meaning":"fur coat"}],"origin":{"period":"Warring States period (475–221 BCE)","sourceText":"《韩非子·外储说左上》","sourceTextEnglish":"Han Feizi, Outer Storage, Left Upper","originalExcerpt":"爱其毛而反其裘，贵其末而轻其本。","storyEnglish":"The idiom originates from a passage in 'Han Feizi', where it describes a person who cherishes the fur of a coat so much that they wear it inside out, thus neglecting the primary function of the coat. This behavior is used as a metaphor for people who focus on trivial details while ignoring the essential aspects.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"literary, but understood in educated speech","connotation":"negative","commonMistakes":"Learners often confuse this idiom with others that involve prioritizing incorrectly, but this one specifically emphasizes neglecting the essential for the trivial.","canStandAlone":false},"examples":[{"simplified":"他总是爱毛反裘，关注细节而忽略整体。","english":"He always puts the cart before the horse, focusing on details while neglecting the big picture.","traditional":"他總是愛毛反裘，關注細節而忽略整體。"},{"simplified":"在这个项目中，我们不能爱毛反裘，必须把重点放在主要目标上。","english":"In this project, we can't neglect the essential for the trivial; we must focus on the main objectives.","traditional":"在這個項目中，我們不能愛毛反裘，必須把重點放在主要目標上。"}],"synonyms":["舍本逐末"],"antonyms":[],"confusedWith":[{"id":"舍本逐末","note":"Both idioms involve neglecting the essential, but '舍本逐末' emphasizes abandoning the essential for the trivial."}],"traditional":"愛毛反裘","pinyinOverride":null},{"id":"ai-he-shi-zhong","simplified":"爱鹤失众","literalMeaning":"love the crane, lose the crowd","figurativeMeaning":"to favor one thing excessively and lose sight of the bigger picture or greater good","englishEquivalents":["Don't miss the forest for the trees"],"shortGloss":"favor one and lose many","characters":[{"char":"爱","meaning":"love; cherish"},{"char":"鹤","meaning":"crane"},{"char":"失","meaning":"lose"},{"char":"众","meaning":"the crowd; many"}],"origin":{"period":"Song Dynasty (960–1279)","sourceText":"《宋史·赵普传》","sourceTextEnglish":"History of Song, Biography of Zhao Pu","originalExcerpt":"赵普曰：“爱鹤失众。”","storyEnglish":"The idiom originates from a story about Zhao Pu, a chancellor during the Song Dynasty. Zhao Pu was known for his wisdom and strategic thinking. Once, he advised Emperor Taizu of Song, warning him about the dangers of favoritism. He used the metaphor of loving a crane too much, which could lead to neglecting the larger flock, to illustrate the potential consequences of focusing too much on one thing at the expense of others.","historicalFigures":["Zhao Pu","Emperor Taizu of Song"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"literary, but can be used in formal speech and writing","connotation":"negative","commonMistakes":"Learners might confuse this idiom with others that involve favoritism, but this one specifically emphasizes losing the greater good due to excessive focus on one aspect.","canStandAlone":false},"examples":[{"simplified":"如果你只关注一个客户，而忽视了其他客户，那就是爱鹤失众。","english":"If you only focus on one client and neglect the others, that's like loving the crane and losing the crowd.","traditional":"如果你只關注一個客戶，而忽視了其他客戶，那就是愛鶴失眾。"},{"simplified":"管理者应该避免爱鹤失众的情况，确保每个团队成员都得到关注。","english":"Managers should avoid situations where they love the crane and lose the crowd, ensuring every team member receives attention.","traditional":"管理者應該避免愛鶴失眾的情況，確保每個團隊成員都得到關注。"}],"synonyms":["顾此失彼"],"antonyms":[],"confusedWith":[{"id":"顾此失彼","note":"Both idioms involve neglect due to favoritism, but '顾此失彼' emphasizes neglecting one thing while attending to another, not necessarily due to excessive favoritism."}],"traditional":"愛鶴失眾","pinyinOverride":null},{"id":"ai-li-cun-yang","simplified":"爱礼存羊","literalMeaning":"value rites keep sheep","figurativeMeaning":"to uphold rituals and propriety even at the cost of personal loss","englishEquivalents":["honor above gain","principle over profit"],"shortGloss":"uphold principles over profit","characters":[{"char":"爱","meaning":"value, cherish"},{"char":"礼","meaning":"rites, rituals"},{"char":"存","meaning":"keep, maintain"},{"char":"羊","meaning":"sheep"}],"origin":{"period":"Spring and Autumn period (770–476 BCE)","sourceText":"《左传·僖公三十二年》","sourceTextEnglish":"Zuo Zhuan, Duke Xi, Year 32","originalExcerpt":"子路曰：“君子爱人以德，爱礼存羊。”","storyEnglish":"During the Spring and Autumn period, a nobleman named Zilu was known for valuing rituals and propriety. One day, he was faced with a situation where he had to choose between adhering to rituals and keeping his sheep. He chose to uphold the rituals, even though it meant losing his sheep. This story illustrates the importance of maintaining principles over personal gain.","historicalFigures":["Zilu"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"literary, but understood in educated speech","connotation":"positive","commonMistakes":"Learners might confuse this idiom with others that involve animals or loss, but this idiom specifically emphasizes the importance of adhering to rituals and propriety.","canStandAlone":false},"examples":[{"simplified":"在商业中，我们应该爱礼存羊，不应只追求利润。","english":"In business, we should uphold principles over profit and not just pursue profit.","traditional":"在商業中，我們應該愛禮存羊，不應只追求利潤。"},{"simplified":"他宁愿爱礼存羊，也不愿意违背自己的信念。","english":"He would rather uphold principles over profit than betray his own beliefs.","traditional":"他寧願愛禮存羊，也不願意違背自己的信念。"}],"synonyms":["舍生取义"],"antonyms":["见利忘义"],"confusedWith":[{"id":"亡羊补牢","note":"Though both involve sheep, 亡羊补牢 is about taking corrective action after a loss, not about upholding principles."}],"traditional":"愛禮存羊","pinyinOverride":null},{"id":"ai-ren-li-wu","simplified":"爱人利物","literalMeaning":"love people benefit things","figurativeMeaning":"to love people and benefit all things; to care for others and contribute positively to the world","englishEquivalents":["love others and benefit the world","do good to others"],"shortGloss":"care for others and contribute positively","characters":[{"char":"爱","meaning":"love"},{"char":"人","meaning":"people"},{"char":"利","meaning":"benefit"},{"char":"物","meaning":"things; the world"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '爱人利物' emphasizes the virtues of loving others and contributing positively to the world. It is often used to describe a person who is compassionate and works towards the betterment of society and the environment.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"coordinate","register":"literary, but can be used in formal speech","connotation":"positive","commonMistakes":"Learners might confuse this idiom with others that emphasize personal gain rather than altruism. It's important to remember that this idiom focuses on benefiting others and the world.","canStandAlone":false},"examples":[{"simplified":"他的生活理念是爱人利物，总是帮助需要帮助的人。","english":"His life philosophy is to love others and benefit the world; he always helps those in need.","traditional":"他的生活理念是愛人利物，總是幫助需要幫助的人。"},{"simplified":"公司提倡爱人利物的企业文化，鼓励员工参与公益活动。","english":"The company promotes a culture of caring for others and contributing positively, encouraging employees to participate in charitable activities.","traditional":"公司提倡愛人利物的企業文化，鼓勵員工參與公益活動。"}],"synonyms":[],"antonyms":[],"confusedWith":[],"traditional":"愛人利物","pinyinOverride":null},{"id":"ai-ri-xi-li","simplified":"爱日惜力","literalMeaning":"cherish the day, value strength","figurativeMeaning":"to make the most of one's time and energy; to work diligently","englishEquivalents":["make hay while the sun shines","seize the day"],"shortGloss":"make the most of time and energy","characters":[{"char":"爱","meaning":"cherish"},{"char":"日","meaning":"day"},{"char":"惜","meaning":"value"},{"char":"力","meaning":"strength"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '爱日惜力' emphasizes the importance of valuing one's time and energy. It suggests that one should work diligently and make the most of the opportunities available each day. The phrase is often used to encourage people to be industrious and not to waste their resources.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["attributive","adverbial"],"structure":"coordinate","register":"commonly used in both spoken and written Chinese to encourage diligence","connotation":"positive","commonMistakes":"Learners might confuse this idiom with others that emphasize urgency rather than diligence. It's important to note that '爱日惜力' focuses on consistent effort rather than immediate action.","canStandAlone":false},"examples":[{"simplified":"我们应该爱日惜力，努力工作。","english":"We should make the most of our time and energy and work hard.","traditional":"我們應該愛日惜力，努力工作。"},{"simplified":"他总是爱日惜力，从不浪费时间。","english":"He always makes the most of his time and energy, never wasting a moment.","traditional":"他總是愛日惜力，從不浪費時間。"}],"synonyms":["分秒必争"],"antonyms":["虚度光阴"],"confusedWith":[{"id":"争分夺秒","note":"While both emphasize the use of time, '争分夺秒' stresses urgency and speed, whereas '爱日惜力' emphasizes diligence and efficient use of resources."}],"traditional":"愛日惜力","pinyinOverride":null},{"id":"ai-su-hao-gu","simplified":"爱素好古","literalMeaning":"love simplicity, fond of antiquity","figurativeMeaning":"to have a passion for simplicity and ancient traditions or artifacts","englishEquivalents":["nostalgic for the past","fond of antiquity"],"shortGloss":"fondness for simplicity and antiquity","characters":[{"char":"爱","meaning":"love"},{"char":"素","meaning":"simplicity"},{"char":"好","meaning":"fond of"},{"char":"古","meaning":"ancient, antiquity"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '爱素好古' reflects a cultural appreciation for simplicity and ancient traditions. It is often used to describe someone who values the aesthetics and wisdom of the past, preferring traditional ways over modern complexity.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"coordinate","register":"literary, but can be used in formal speech","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with others that express a preference for old things, but '爱素好古' specifically emphasizes simplicity alongside antiquity.","canStandAlone":false},"examples":[{"simplified":"他爱素好古，家里摆满了古董。","english":"He loves simplicity and antiquity, and his house is filled with antiques.","traditional":"他愛素好古，家裡擺滿了古董。"},{"simplified":"这种爱素好古的风格在现代社会中仍然很受欢迎。","english":"This style of loving simplicity and antiquity is still popular in modern society.","traditional":"這種愛素好古的風格在現代社會中仍然很受歡迎。"}],"synonyms":[],"antonyms":[],"confusedWith":[],"traditional":"愛素好古","pinyinOverride":null},{"id":"ai-kou-shi-xiu","simplified":"碍口识羞","literalMeaning":"hindered mouth knows shame","figurativeMeaning":"to be too embarrassed to speak; to be tongue-tied out of shame","englishEquivalents":["tongue-tied","lost for words"],"shortGloss":"too embarrassed to speak","characters":[{"char":"碍","meaning":"hinder; obstruct"},{"char":"口","meaning":"mouth"},{"char":"识","meaning":"know; recognize"},{"char":"羞","meaning":"shame; embarrassment"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '碍口识羞' describes a situation where someone is too embarrassed to speak. It conveys the idea of being tongue-tied due to a sense of shame or embarrassment. The origin of this idiom is not well-documented, and it likely comes from folk expressions describing social situations where someone feels too shy or ashamed to express themselves verbally.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"modifier-head","register":"commonly used in both spoken and written Chinese to describe social embarrassment","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with others that describe speechlessness due to different emotions, such as surprise or fear. This idiom specifically refers to embarrassment.","canStandAlone":false},"examples":[{"simplified":"他面对大家的批评，碍口识羞，不知道该说什么。","english":"Faced with everyone's criticism, he was too embarrassed to speak and didn't know what to say.","traditional":"他面對大家的批評，礙口識羞，不知道該說什麼。"},{"simplified":"她在台上碍口识羞，半天说不出话来。","english":"She was tongue-tied on stage, unable to speak for a long time out of embarrassment.","traditional":"她在臺上礙口識羞，半天說不出話來。"}],"synonyms":[],"antonyms":[],"confusedWith":[{"id":"哑口无言","note":"哑口无言 refers to being speechless due to surprise or shock, not specifically embarrassment."}],"traditional":"礙口識羞","pinyinOverride":null},{"id":"an-che-pu-lun","simplified":"安车蒲轮","literalMeaning":"comfortable carriage with cattail wheels","figurativeMeaning":"to treat someone with great respect and care, often in the context of inviting or transporting an esteemed guest","englishEquivalents":["roll out the red carpet","treat like royalty"],"shortGloss":"treat with great respect and care","characters":[{"char":"安","meaning":"comfortable, peaceful"},{"char":"车","meaning":"carriage, vehicle"},{"char":"蒲","meaning":"cattail, a type of plant used here to describe the wheels"},{"char":"轮","meaning":"wheel"}],"origin":{"period":"Han Dynasty (206 BCE – 220 CE)","sourceText":"《后汉书·黄琼传》","sourceTextEnglish":"Book of the Later Han, Biography of Huang Qiong","originalExcerpt":"帝遣安车蒲轮，迎以为太傅。","storyEnglish":"During the Han Dynasty, the emperor sent a comfortable carriage with cattail wheels to invite Huang Qiong to serve as the Grand Tutor. This gesture was a sign of great respect and honor, as the emperor wanted to ensure Huang Qiong's comfort and demonstrate his high regard for him.","historicalFigures":["Huang Qiong"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["object","adverbial"],"structure":"modifier-head","register":"formal, used in both literary and spoken contexts to convey respect","connotation":"positive","commonMistakes":"Learners might confuse this idiom with others that imply luxury rather than respect. It's important to note that the emphasis is on the respectful treatment rather than opulence.","canStandAlone":false},"examples":[{"simplified":"为了表示诚意，公司派出安车蒲轮接待贵宾。","english":"To show their sincerity, the company sent a comfortable carriage to receive the distinguished guest.","traditional":"為了表示誠意，公司派出安車蒲輪接待貴賓。"},{"simplified":"他受到了安车蒲轮的待遇，被邀请到首都参加会议。","english":"He was treated with great respect and was invited to the capital to attend the conference.","traditional":"他受到了安車蒲輪的待遇，被邀請到首都參加會議。"}],"synonyms":[],"antonyms":[],"confusedWith":[],"traditional":"安車蒲輪","pinyinOverride":null},{"id":"an-du-le-ye","simplified":"安堵乐业","literalMeaning":"peaceful and content, happy in one's work","figurativeMeaning":"to live and work in peace and contentment","englishEquivalents":["live and work in peace","peaceful and content life"],"shortGloss":"live and work in peace","characters":[{"char":"安","meaning":"peaceful"},{"char":"堵","meaning":"content"},{"char":"乐","meaning":"happy"},{"char":"业","meaning":"work"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom 安堵乐业 describes a state where people live peacefully and are content with their work. It conveys the ideal of a stable and harmonious society where individuals can pursue their livelihoods without disturbance.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"coordinate","register":"commonly used in both formal and informal contexts to describe societal stability","connotation":"positive","commonMistakes":"Learners might confuse this idiom with similar ones that emphasize personal happiness rather than societal stability. It specifically refers to a broader context of societal peace and contentment.","canStandAlone":false},"examples":[{"simplified":"在这个国家，人民安堵乐业，生活幸福。","english":"In this country, people live and work in peace, and their lives are happy.","traditional":"在這個國家，人民安堵樂業，生活幸福。"},{"simplified":"政府的目标是让每个公民都能安堵乐业。","english":"The government's goal is for every citizen to live and work in peace and contentment.","traditional":"政府的目標是讓每個公民都能安堵樂業。"}],"synonyms":["安居乐业"],"antonyms":[],"confusedWith":[{"id":"安居乐业","note":"Both idioms describe a peaceful and content life, but 安居乐业 is more commonly used and emphasizes 'residing' as well as working in peace."}],"traditional":"安堵樂業","pinyinOverride":null},{"id":"an-du-ru-gu","simplified":"案堵如故","literalMeaning":"table block as before","figurativeMeaning":"a situation remains unchanged despite efforts to resolve it","englishEquivalents":["back to square one","status quo","no change"],"shortGloss":"situation remains unchanged","characters":[{"char":"案","meaning":"table"},{"char":"堵","meaning":"block"},{"char":"如","meaning":"as"},{"char":"故","meaning":"before"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '案堵如故' is believed to describe a situation where, despite attempts to change or resolve an issue, everything remains the same as it was before. The imagery of a 'table block' suggests an obstruction or problem that is as persistent as ever.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"modifier-head","register":"formal written Chinese, occasionally used in speech","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with others that imply a return to a previous state, but '案堵如故' specifically emphasizes the lack of change despite efforts.","canStandAlone":false},"examples":[{"simplified":"尽管进行了多次改革，公司的问题仍然案堵如故。","english":"Despite multiple reforms, the company's problems remain unchanged.","traditional":"儘管進行了多次改革，公司的問題仍然案堵如故。"},{"simplified":"他们努力解决争端，但局势案堵如故。","english":"They tried hard to resolve the dispute, but the situation remains unchanged.","traditional":"他們努力解決爭端，但局勢案堵如故。"}],"synonyms":["一成不变"],"antonyms":["焕然一新"],"confusedWith":[{"id":"故态复萌","note":"While '故态复萌' implies a return to a previous bad state, '案堵如故' emphasizes no change despite efforts."}],"traditional":"案堵如故","pinyinOverride":null},{"id":"an-fu-zun-rong","simplified":"安富尊荣","literalMeaning":"peaceful wealth, honored glory","figurativeMeaning":"to live in comfort and enjoy wealth and high status","englishEquivalents":["living in luxury","enjoying wealth and honor"],"shortGloss":"living in luxury and honor","characters":[{"char":"安","meaning":"peaceful"},{"char":"富","meaning":"wealth"},{"char":"尊","meaning":"honored"},{"char":"荣","meaning":"glory"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '安富尊荣' describes a state of living where one enjoys both material wealth and social prestige. It reflects a life of comfort and high status, often aspired to in traditional Chinese culture. The exact origin of this idiom is not clearly documented, but it has been used in various literary contexts to describe individuals or families who have achieved a high level of prosperity and honor.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"coordinate","register":"literary, but can be used in formal speech","connotation":"positive","commonMistakes":"Learners might confuse this idiom with others that involve wealth or honor but lack the aspect of peace and comfort. It's important to note that '安富尊荣' implies both material wealth and a peaceful, honorable life.","canStandAlone":false},"examples":[{"simplified":"他一生安富尊荣，从未经历过困苦。","english":"He lived a life of wealth and honor, never experiencing hardship.","traditional":"他一生安富尊榮，從未經歷過困苦。"},{"simplified":"在这个安富尊荣的家庭中，孩子们从小就接受良好的教育。","english":"In this wealthy and honorable family, the children received a good education from a young age.","traditional":"在這個安富尊榮的家庭中，孩子們從小就接受良好的教育。"}],"synonyms":["荣华富贵"],"antonyms":["贫困潦倒"],"confusedWith":[{"id":"荣华富贵","note":"While both idioms involve wealth and honor, '荣华富贵' emphasizes the transient nature of wealth and glory, whereas '安富尊荣' implies a stable, peaceful state."}],"traditional":"安富尊榮","pinyinOverride":null},{"id":"an-mei-dai-yan","simplified":"安眉带眼","literalMeaning":"calm eyebrows carry eyes","figurativeMeaning":"to have a calm and composed demeanor","englishEquivalents":["keep a straight face","maintain composure"],"shortGloss":"calm and composed demeanor","characters":[{"char":"安","meaning":"calm"},{"char":"眉","meaning":"eyebrows"},{"char":"带","meaning":"carry"},{"char":"眼","meaning":"eyes"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '安眉带眼' is believed to describe someone who maintains a calm and composed demeanor, even in challenging situations. The imagery of calm eyebrows and eyes suggests a person who does not show their emotions openly and remains steady.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["attributive","predicate"],"structure":"modifier-head","register":"commonly used in both spoken and written Chinese","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with others that involve facial expressions, such as '眉开眼笑', which has a positive connotation of happiness. '安眉带眼' is more about composure and neutrality.","canStandAlone":false},"examples":[{"simplified":"他在危机中总是安眉带眼，不露声色。","english":"He always remains calm and composed during crises, not revealing his emotions.","traditional":"他在危機中總是安眉帶眼，不露聲色。"},{"simplified":"面对批评，她安眉带眼，毫不动摇。","english":"Faced with criticism, she remained calm and composed, unwavering.","traditional":"面對批評，她安眉帶眼，毫不動搖。"}],"synonyms":[],"antonyms":[],"confusedWith":[{"id":"眉开眼笑","note":"While '安眉带眼' refers to maintaining composure, '眉开眼笑' means to be very happy and smiling."}],"traditional":"安眉帶眼","pinyinOverride":null},{"id":"an-ren-wu-qin","simplified":"安忍无亲","literalMeaning":"calmly endure without kin","figurativeMeaning":"to be ruthless and unfeeling, disregarding familial ties","englishEquivalents":["cold-hearted","ruthless","unfeeling"],"shortGloss":"ruthless and unfeeling","characters":[{"char":"安","meaning":"calmly"},{"char":"忍","meaning":"endure"},{"char":"无","meaning":"without"},{"char":"亲","meaning":"kin, familial ties"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '安忍无亲' describes a person who is so ruthless and unfeeling that they can calmly endure any situation without regard for familial ties. It is often used to criticize someone who acts in a cold-hearted manner, especially when they disregard the bonds of family.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"modifier-head","register":"formal written Chinese, sometimes used in speech to emphasize criticism","connotation":"negative","commonMistakes":"Learners might confuse this idiom with expressions that simply mean 'independent' or 'self-reliant', but '安忍无亲' specifically implies a lack of empathy and disregard for family ties.","canStandAlone":false},"examples":[{"simplified":"他为了权力，竟然安忍无亲，连自己的兄弟都不放过。","english":"For the sake of power, he was so ruthless that he even turned against his own brothers.","traditional":"他為了權力，竟然安忍無親，連自己的兄弟都不放過。"},{"simplified":"在商业竞争中，他安忍无亲，毫不留情。","english":"In business competition, he was ruthless and unfeeling, showing no mercy.","traditional":"在商業競爭中，他安忍無親，毫不留情。"}],"synonyms":["铁石心肠","无情无义"],"antonyms":["亲情至上","仁慈宽厚"],"confusedWith":[{"id":"无情无义","note":"Both imply a lack of empathy, but '无情无义' is more general, while '安忍无亲' emphasizes the disregard for familial ties."}],"traditional":"安忍無親","pinyinOverride":null},{"id":"an-shen-wei-le","simplified":"安身为乐","literalMeaning":"settle oneself to be happy","figurativeMeaning":"to find contentment in a simple and stable life","englishEquivalents":["Home is where the heart is","Contentment is wealth"],"shortGloss":"contentment in a simple life","characters":[{"char":"安","meaning":"settle; peaceful"},{"char":"身","meaning":"body; oneself"},{"char":"为","meaning":"to be; as"},{"char":"乐","meaning":"happy; content"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '安身为乐' suggests that true happiness comes from finding peace and stability in one's life. It emphasizes the idea that contentment is not about external wealth or status, but about being settled and at ease with oneself and one's circumstances.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"commonly used in both spoken and written Chinese to express a philosophical view on life","connotation":"positive","commonMistakes":"Learners might confuse this idiom with those that emphasize ambition or external success. It's important to remember that this idiom focuses on internal peace and contentment.","canStandAlone":false},"examples":[{"simplified":"他选择了乡下的生活，安身为乐。","english":"He chose a life in the countryside, finding contentment in simplicity.","traditional":"他選擇了鄉下的生活，安身為樂。"},{"simplified":"在繁忙的城市中，她努力做到安身为乐。","english":"In the bustling city, she strives to find contentment in her life.","traditional":"在繁忙的城市中，她努力做到安身為樂。"}],"synonyms":[],"antonyms":["穷奢极欲"],"confusedWith":[{"id":"安居乐业","note":"While both idioms involve contentment, '安居乐业' focuses more on being settled and happy in one's work and home life."}],"traditional":"安身為樂","pinyinOverride":null},{"id":"an-shi-li-chu","simplified":"安室利处","literalMeaning":"peaceful room, advantageous place","figurativeMeaning":"a safe and advantageous position or situation","englishEquivalents":["safe haven","secure position"],"shortGloss":"a safe and advantageous position","characters":[{"char":"安","meaning":"peaceful, safe"},{"char":"室","meaning":"room, place"},{"char":"利","meaning":"advantageous, beneficial"},{"char":"处","meaning":"place, position"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '安室利处' describes a situation or position that is both safe and advantageous. It is often used to refer to a place or condition where one can thrive without danger or risk. The exact origin of this idiom is unclear, but it has been used in various contexts to emphasize the importance of security and advantage.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["subject","object","attributive"],"structure":"modifier-head","register":"neutral, commonly used in both written and spoken Chinese","connotation":"positive","commonMistakes":"Learners might confuse this idiom with others that emphasize safety without the aspect of advantage, or vice versa. It's important to remember that this idiom conveys both safety and benefit.","canStandAlone":false},"examples":[{"simplified":"在动荡的市场中，他找到了一个安室利处。","english":"In the turbulent market, he found a safe and advantageous position.","traditional":"在動盪的市場中，他找到了一個安室利處。"},{"simplified":"选择一个安室利处对公司的发展至关重要。","english":"Choosing a safe and advantageous position is crucial for the company's development.","traditional":"選擇一個安室利處對公司的發展至關重要。"}],"synonyms":[],"antonyms":[],"confusedWith":[],"traditional":"安室利處","pinyinOverride":null},{"id":"an-xin-ding-zhi","simplified":"安心定志","literalMeaning":"calm heart, set determination","figurativeMeaning":"to be calm and focused; to have peace of mind and determination","englishEquivalents":["peace of mind","calm and collected"],"shortGloss":"calm and focused","characters":[{"char":"安","meaning":"calm, peaceful"},{"char":"心","meaning":"heart, mind"},{"char":"定","meaning":"set, determined"},{"char":"志","meaning":"will, determination"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '安心定志' is often used to describe a state of being where a person is both mentally calm and determined in their goals. It emphasizes the importance of having a peaceful mind to achieve one's aspirations.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"coordinate","register":"common in both written and spoken Chinese, often used in motivational contexts","connotation":"positive","commonMistakes":"Learners might confuse this idiom with similar ones that emphasize calmness but not determination. It's important to note that '安心定志' specifically highlights both peace of mind and a firm resolve.","canStandAlone":false},"examples":[{"simplified":"在面对困难时，我们需要安心定志，才能找到解决办法。","english":"When facing difficulties, we need to be calm and focused to find solutions.","traditional":"在面對困難時，我們需要安心定志，才能找到解決辦法。"},{"simplified":"他在比赛前总是能安心定志，发挥出最佳水平。","english":"He always manages to be calm and focused before a competition, performing at his best.","traditional":"他在比賽前總是能安心定志，發揮出最佳水平。"}],"synonyms":["心平气和","镇定自若"],"antonyms":["心神不宁","焦躁不安"],"confusedWith":[{"id":"心平气和","note":"While both idioms involve calmness, '心平气和' focuses more on maintaining a peaceful demeanor, without the element of determination."}],"traditional":"安心定志","pinyinOverride":null},{"id":"an-jia-xiu-bing","simplified":"案甲休兵","literalMeaning":"put down armor, rest weapons","figurativeMeaning":"to cease fighting and take a break from military activities; to enjoy a period of peace","englishEquivalents":["lay down arms","ceasefire","peaceful respite"],"shortGloss":"cease fighting and rest","characters":[{"char":"案","meaning":"put down, lay down"},{"char":"甲","meaning":"armor"},{"char":"休","meaning":"rest, cease"},{"char":"兵","meaning":"weapons, soldiers"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '案甲休兵' likely originated from the idea of soldiers putting down their armor and weapons to take a break from the rigors of battle. It symbolizes a temporary halt in warfare, allowing for rest and recuperation. This concept has been valued throughout history as a necessary respite from continuous conflict.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"literary, but can be used in formal speech to describe a ceasefire or peace period","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with expressions that imply a permanent end to conflict, rather than a temporary pause. It specifically refers to a break or rest, not a resolution.","canStandAlone":false},"examples":[{"simplified":"在谈判期间，双方决定案甲休兵。","english":"During the negotiations, both sides decided to lay down arms.","traditional":"在談判期間，雙方決定案甲休兵。"},{"simplified":"经过多年的战争，人民渴望案甲休兵的日子。","english":"After years of war, the people longed for days of peace and respite.","traditional":"經過多年的戰爭，人民渴望案甲休兵的日子。"}],"synonyms":["偃旗息鼓"],"antonyms":["兵戎相见"],"confusedWith":[{"id":"停战","note":"停战 refers to a formal ceasefire agreement, while 案甲休兵 implies a temporary rest without formalities."}],"traditional":"案甲休兵","pinyinOverride":null},{"id":"an-ming-ze-shi","simplified":"按名责实","literalMeaning":"according to the name, demand the reality","figurativeMeaning":"to ensure that something lives up to its name; to hold someone or something accountable to its reputation or title","englishEquivalents":["call a spade a spade","hold accountable"],"shortGloss":"hold accountable to reputation","characters":[{"char":"按","meaning":"according to"},{"char":"名","meaning":"name"},{"char":"责","meaning":"demand"},{"char":"实","meaning":"reality"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '按名责实' emphasizes the importance of ensuring that a person or thing truly lives up to its name or title. It suggests that one should not only rely on appearances or reputations but should also verify the actual substance or performance. This concept is often applied in contexts where accountability and authenticity are valued.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"formal written Chinese, but also used in speech when discussing accountability","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with those that emphasize superficial judgment. However, '按名责实' specifically involves verifying the actual substance behind a name or reputation.","canStandAlone":false},"examples":[{"simplified":"我们需要按名责实，确保每个项目都达到标准。","english":"We need to hold each project accountable to ensure they meet the standards.","traditional":"我們需要按名責實，確保每個項目都達到標準。"},{"simplified":"在评估员工时，公司应该按名责实。","english":"When evaluating employees, the company should ensure they live up to their titles.","traditional":"在評估員工時，公司應該按名責實。"}],"synonyms":[],"antonyms":[],"confusedWith":[],"traditional":"按名責實","pinyinOverride":null},{"id":"an-pei-xu-xing","simplified":"按辔徐行","literalMeaning":"hold the reins and proceed slowly","figurativeMeaning":"to proceed cautiously and steadily","englishEquivalents":["slow and steady wins the race","proceed with caution"],"shortGloss":"proceed cautiously","characters":[{"char":"按","meaning":"hold"},{"char":"辔","meaning":"reins"},{"char":"徐","meaning":"slowly"},{"char":"行","meaning":"proceed"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '按辔徐行' is believed to have originated from the practice of holding the reins tightly and moving slowly to ensure safety and control, especially when riding a horse. This approach emphasizes the importance of caution and steadiness in achieving one's goals.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["adverbial","attributive"],"structure":"verb-object","register":"literary, but can be used in formal speech to emphasize caution","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with others that imply slowness without the aspect of caution, such as 慢条斯理, which is more about being unhurried and methodical.","canStandAlone":false},"examples":[{"simplified":"在处理复杂问题时，我们应该按辔徐行。","english":"When dealing with complex issues, we should proceed cautiously.","traditional":"在處理複雜問題時，我們應該按轡徐行。"},{"simplified":"他总是按辔徐行，确保不会犯错。","english":"He always proceeds cautiously to ensure he doesn't make mistakes.","traditional":"他總是按轡徐行，確保不會犯錯。"}],"synonyms":["小心翼翼","稳扎稳打"],"antonyms":["急功近利"],"confusedWith":[{"id":"慢条斯理","note":"慢条斯理 emphasizes being unhurried and methodical, without the cautionary aspect."}],"traditional":"按轡徐行","pinyinOverride":null},{"id":"an-du-lao-xing","simplified":"案牍劳形","literalMeaning":"official documents weary the body","figurativeMeaning":"to be worn out by paperwork or administrative tasks","englishEquivalents":["buried in paperwork","drowning in red tape"],"shortGloss":"worn out by paperwork","characters":[{"char":"案","meaning":"desk; case"},{"char":"牍","meaning":"official documents; records"},{"char":"劳","meaning":"weary; tire"},{"char":"形","meaning":"body; form"}],"origin":{"period":"Han Dynasty (206 BCE – 220 CE)","sourceText":"《后汉书·杨震传》","sourceTextEnglish":"Book of the Later Han, Biography of Yang Zhen","originalExcerpt":"案牍劳形，未尝有懈。","storyEnglish":"The idiom comes from the 'Book of the Later Han', where it describes the diligent work of Yang Zhen, a government official who was known for his dedication to his duties. He was so committed to his work that he was constantly burdened by the volume of paperwork, which left him physically exhausted.","historicalFigures":["Yang Zhen"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"subject-predicate","register":"literary, but can be used in formal speech to describe modern situations","connotation":"negative","commonMistakes":"Learners might confuse this idiom with those describing physical labor, but it specifically refers to mental exhaustion from administrative tasks.","canStandAlone":false},"examples":[{"simplified":"他每天都被案牍劳形，没有时间休息。","english":"He is worn out by paperwork every day and has no time to rest.","traditional":"他每天都被案牘勞形，沒有時間休息。"},{"simplified":"在政府部门工作的人常常感到案牍劳形。","english":"People working in government departments often feel worn out by paperwork.","traditional":"在政府部門工作的人常常感到案牘勞形。"}],"synonyms":["疲于奔命"],"antonyms":[],"confusedWith":[{"id":"疲于奔命","note":"疲于奔命 refers to being exhausted from running around, while 案牍劳形 specifically refers to exhaustion from paperwork."}],"traditional":"案牘勞形","pinyinOverride":null},{"id":"an-qi-an-nao","simplified":"暗气暗恼","literalMeaning":"hidden anger, hidden resentment","figurativeMeaning":"to harbor resentment or anger without expressing it openly","englishEquivalents":["bottled-up anger","silent resentment"],"shortGloss":"harboring hidden anger","characters":[{"char":"暗","meaning":"hidden, secret"},{"char":"气","meaning":"anger"},{"char":"暗","meaning":"hidden, secret"},{"char":"恼","meaning":"annoyance, resentment"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom 暗气暗恼 describes a situation where someone feels anger or resentment but chooses not to express it openly. This can occur in various contexts, such as in personal relationships or workplace environments, where expressing such emotions might be deemed inappropriate or risky.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"coordinate","register":"commonly used in both spoken and written Chinese","connotation":"negative","commonMistakes":"Learners might confuse 暗气暗恼 with similar expressions that involve open expressions of anger. This idiom specifically refers to hidden or unexpressed emotions.","canStandAlone":false},"examples":[{"simplified":"他总是暗气暗恼，从不直接表达自己的不满。","english":"He always harbors hidden resentment and never directly expresses his dissatisfaction.","traditional":"他總是暗氣暗惱，從不直接表達自己的不滿。"},{"simplified":"在工作中，暗气暗恼只会影响自己的心情。","english":"In the workplace, harboring hidden resentment will only affect your own mood.","traditional":"在工作中，暗氣暗惱只會影響自己的心情。"}],"synonyms":["隐忍不发"],"antonyms":["直言不讳"],"confusedWith":[{"id":"怒火中烧","note":"怒火中烧 refers to being visibly angry, while 暗气暗恼 refers to hidden anger."}],"traditional":"暗氣暗惱","pinyinOverride":null},{"id":"an-ruo-wu-duan","simplified":"暗弱无断","literalMeaning":"dim, weak, without decision","figurativeMeaning":"lacking decisiveness and strength; indecisive and weak","englishEquivalents":["wishy-washy","indecisive","spineless"],"shortGloss":"indecisive and weak","characters":[{"char":"暗","meaning":"dim, lacking clarity or insight"},{"char":"弱","meaning":"weak, lacking strength"},{"char":"无","meaning":"without, lacking"},{"char":"断","meaning":"decision, decisiveness"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom 暗弱无断 is often used to describe someone who is unable to make firm decisions due to a lack of clarity and strength. It is not tied to a specific historical story but rather reflects a common critique of indecisive behavior.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"modifier-head","register":"commonly used in both spoken and written Chinese to describe indecisive behavior","connotation":"negative","commonMistakes":"Learners might confuse 暗弱无断 with similar idioms that imply lack of action, but this idiom specifically emphasizes indecisiveness due to lack of clarity and strength.","canStandAlone":false},"examples":[{"simplified":"他的领导风格总是暗弱无断，导致团队士气低落。","english":"His leadership style is always indecisive and weak, leading to low team morale.","traditional":"他的領導風格總是闇弱無斷，導致團隊士氣低落。"},{"simplified":"在关键时刻，他表现得暗弱无断，错失了良机。","english":"At the critical moment, he was indecisive and weak, missing a great opportunity.","traditional":"在關鍵時刻，他表現得闇弱無斷，錯失了良機。"}],"synonyms":["优柔寡断"],"antonyms":["果断决策"],"confusedWith":[{"id":"优柔寡断","note":"Both idioms describe indecisiveness, but 优柔寡断 focuses more on hesitation, while 暗弱无断 emphasizes lack of strength and clarity."}],"traditional":"闇弱無斷","pinyinOverride":null},{"id":"an-shi-kui-xin","simplified":"暗室亏心","literalMeaning":"dark room harms the heart","figurativeMeaning":"to do something shameful or immoral in secret","englishEquivalents":["skeletons in the closet","what's done in the dark will come to light"],"shortGloss":"secretly doing shameful things","characters":[{"char":"暗","meaning":"dark"},{"char":"室","meaning":"room"},{"char":"亏","meaning":"harm"},{"char":"心","meaning":"heart"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom suggests that even if one commits immoral acts in secret, they still harm one's conscience. It serves as a warning that unethical actions, even when hidden, can lead to internal guilt and moral corruption.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"modifier-head","register":"literary, but understood in modern contexts","connotation":"negative","commonMistakes":"Learners often confuse this idiom with those that imply public exposure of secrets, but 暗室亏心 focuses on the internal moral consequences rather than external discovery.","canStandAlone":false},"examples":[{"simplified":"他总是暗室亏心，难怪他最近看起来很不安。","english":"He always does shameful things in secret; no wonder he looks so uneasy lately.","traditional":"他總是暗室虧心，難怪他最近看起來很不安。"},{"simplified":"暗室亏心的行为迟早会被发现。","english":"Shameful actions done in secret will eventually be discovered.","traditional":"暗室虧心的行為遲早會被發現。"}],"synonyms":["见不得人","心怀鬼胎"],"antonyms":["光明磊落"],"confusedWith":[{"id":"见不得人","note":"Both imply shameful actions, but 暗室亏心 emphasizes internal guilt, while 见不得人 focuses on external shame."}],"traditional":"暗室虧心","pinyinOverride":null},{"id":"an-xiang-shu-ying","simplified":"暗香疏影","literalMeaning":"faint fragrance, sparse shadows","figurativeMeaning":"subtle beauty or elegance; understated charm","englishEquivalents":["a subtle charm","understated elegance"],"shortGloss":"subtle beauty or elegance","characters":[{"char":"暗","meaning":"faint, subtle"},{"char":"香","meaning":"fragrance, scent"},{"char":"疏","meaning":"sparse, scattered"},{"char":"影","meaning":"shadow, silhouette"}],"origin":{"period":"Song Dynasty (960–1279)","sourceText":"《林逋·山园小梅》","sourceTextEnglish":"Lin Bu's 'Little Plum in the Mountain Garden'","originalExcerpt":"疏影横斜水清浅，暗香浮动月黄昏。","storyEnglish":"The idiom comes from a poem by Lin Bu, a famous poet of the Song Dynasty. In his poem 'Little Plum in the Mountain Garden', he describes the beauty of plum blossoms. The lines 'Sparse shadows slant across the clear shallow water, faint fragrance floats in the dusk of the moon' evoke an image of subtle and understated beauty, which is the essence captured by the idiom.","historicalFigures":["Lin Bu"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["attributive","adverbial"],"structure":"coordinate","register":"literary, but understood in educated speech","connotation":"positive","commonMistakes":"Learners might mistakenly use this idiom to describe anything with a strong or obvious beauty, but it specifically refers to subtle and understated elegance.","canStandAlone":false},"examples":[{"simplified":"她的气质如同暗香疏影，令人难以忘怀。","english":"Her demeanor has a subtle elegance, like a faint fragrance and sparse shadows, that is unforgettable.","traditional":"她的氣質如同暗香疏影，令人難以忘懷。"},{"simplified":"这幅画以暗香疏影的风格展现了自然的美。","english":"This painting showcases the beauty of nature with a style of subtle elegance.","traditional":"這幅畫以暗香疏影的風格展現了自然的美。"}],"synonyms":[],"antonyms":[],"confusedWith":[],"traditional":"暗香疏影","pinyinOverride":null},{"id":"an-ran-shang-shen","simplified":"黯然伤神","literalMeaning":"darkly hurt spirit","figurativeMeaning":"to feel dejected or disheartened","englishEquivalents":["down in the dumps","feeling blue"],"shortGloss":"to feel dejected","characters":[{"char":"黯","meaning":"dark, gloomy"},{"char":"然","meaning":"adverbial suffix, indicating a state"},{"char":"伤","meaning":"hurt, wound"},{"char":"神","meaning":"spirit, mind"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '黯然伤神' is used to describe a state of feeling deeply dejected or disheartened. It evokes an image of someone whose spirit is darkened by sadness or disappointment. The exact origin of this idiom is not clearly documented in classical texts, but it has been used in literature and conversation to express a profound sense of melancholy.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"modifier-head","register":"commonly used in both written and spoken Chinese to describe emotional states","connotation":"negative","commonMistakes":"Learners might confuse this idiom with others that describe sadness but lack the depth of emotional impact. It's important to note that '黯然伤神' conveys a deeper, more profound sense of dejection.","canStandAlone":false},"examples":[{"simplified":"听到这个消息后，他黯然伤神，久久不能平静。","english":"After hearing the news, he was deeply dejected and couldn't calm down for a long time.","traditional":"聽到這個消息後，他黯然傷神，久久不能平靜。"},{"simplified":"她看着窗外的雨，黯然伤神，思绪万千。","english":"She gazed at the rain outside, feeling dejected, with a thousand thoughts running through her mind.","traditional":"她看著窗外的雨，黯然傷神，思緒萬千。"}],"synonyms":["心灰意冷","垂头丧气"],"antonyms":["喜气洋洋","兴高采烈"],"confusedWith":[{"id":"心灰意冷","note":"Both express dejection, but '心灰意冷' implies a loss of motivation or hope, while '黯然伤神' focuses more on emotional sadness."}],"traditional":"黯然傷神","pinyinOverride":null},{"id":"an-ran-xiao-hun","simplified":"黯然销魂","literalMeaning":"darkly disappear soul","figurativeMeaning":"overwhelmed with sorrow; heartbroken","englishEquivalents":["heartbroken","downcast","in the depths of despair"],"shortGloss":"overwhelmed with sorrow","characters":[{"char":"黯","meaning":"dark; gloomy"},{"char":"然","meaning":"in such a manner; like this"},{"char":"销","meaning":"disappear; melt away"},{"char":"魂","meaning":"soul; spirit"}],"origin":{"period":"Southern Dynasties (420–589)","sourceText":"《宋书·谢灵运传》","sourceTextEnglish":"Book of Song, Biography of Xie Lingyun","originalExcerpt":"黯然销魂者，唯别而已矣。","storyEnglish":"The idiom comes from a passage in the 'Book of Song', where the poet Xie Lingyun describes the profound sorrow and soul-crushing feeling of parting from a loved one. The phrase captures the deep emotional impact of separation, likening it to one's soul being extinguished.","historicalFigures":["Xie Lingyun"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"subject-predicate","register":"literary, but can be used in both written and spoken Chinese to express deep sorrow","connotation":"negative","commonMistakes":"Learners might confuse this idiom with expressions of general sadness, but it specifically conveys a deep, soul-crushing sorrow. It is more intense than simply feeling sad.","canStandAlone":false},"examples":[{"simplified":"他失去了爱人，整日黯然销魂。","english":"He lost his beloved and was heartbroken all day long.","traditional":"他失去了愛人，整日黯然銷魂。"},{"simplified":"离别时，她黯然销魂，泪流满面。","english":"At the time of parting, she was overwhelmed with sorrow, tears streaming down her face.","traditional":"離別時，她黯然銷魂，淚流滿面。"}],"synonyms":["悲痛欲绝","痛不欲生"],"antonyms":["喜出望外","心花怒放"],"confusedWith":[{"id":"心灰意冷","note":"While both express negative emotions, 心灰意冷 implies a loss of motivation or hope, not the deep sorrow of 黯然销魂."}],"traditional":"黯然銷魂","pinyinOverride":null},{"id":"ang-cang-qi-chi","simplified":"昂藏七尺","literalMeaning":"upright seven feet","figurativeMeaning":"a tall and imposing man","englishEquivalents":["a towering figure","a man of great stature"],"shortGloss":"a tall and imposing man","characters":[{"char":"昂","meaning":"upright, lofty"},{"char":"藏","meaning":"imposing, dignified"},{"char":"七","meaning":"seven"},{"char":"尺","meaning":"feet (unit of length)"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '昂藏七尺' is used to describe a man who is tall and impressive in appearance. The term '七尺' refers to a height of seven feet, which in ancient times was considered very tall. The words '昂藏' convey a sense of dignity and loftiness. This idiom is often used to praise someone's physical stature and commanding presence.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["attributive","predicate"],"structure":"modifier-head","register":"literary, but can be used in formal speech","connotation":"positive","commonMistakes":"Learners might mistakenly use this idiom for someone who is simply tall, without the connotation of dignity and presence. It is also sometimes confused with idioms that describe moral character rather than physical stature.","canStandAlone":false},"examples":[{"simplified":"他是个昂藏七尺的汉子，走到哪里都很引人注目。","english":"He is a tall and imposing man, attracting attention wherever he goes.","traditional":"他是個昂藏七尺的漢子，走到哪裡都很引人注目。"},{"simplified":"在古代，昂藏七尺的男子通常被认为是理想的武士。","english":"In ancient times, a man of seven feet stature was often considered an ideal warrior.","traditional":"在古代，昂藏七尺的男子通常被認為是理想的武士。"}],"synonyms":[],"antonyms":[],"confusedWith":[],"traditional":"昂藏七尺","pinyinOverride":null},{"id":"ang-shou-shen-mei","simplified":"昂首伸眉","literalMeaning":"raise head stretch eyebrows","figurativeMeaning":"to be elated and proud","englishEquivalents":["hold one's head high","walk with pride"],"shortGloss":"to be elated and proud","characters":[{"char":"昂","meaning":"raise"},{"char":"首","meaning":"head"},{"char":"伸","meaning":"stretch"},{"char":"眉","meaning":"eyebrows"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom 昂首伸眉 describes a person who is feeling proud and elated, often after achieving success or overcoming difficulties. The imagery of raising one's head and stretching one's eyebrows conveys a sense of confidence and self-assurance.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"coordinate","register":"literary, but can be used in formal speech","connotation":"positive","commonMistakes":"Learners might confuse this idiom with similar expressions that describe arrogance. However, 昂首伸眉 is positive and implies justified pride, not arrogance.","canStandAlone":false},"examples":[{"simplified":"他在比赛中获胜后，昂首伸眉地走出体育馆。","english":"After winning the competition, he walked out of the stadium with his head held high.","traditional":"他在比賽中獲勝後，昂首伸眉地走出體育館。"},{"simplified":"经过多年的努力，他终于成功了，昂首伸眉地面对未来。","english":"After years of hard work, he finally succeeded and faced the future with pride.","traditional":"經過多年的努力，他終於成功了，昂首伸眉地面對未來。"}],"synonyms":["扬眉吐气"],"antonyms":["垂头丧气"],"confusedWith":[{"id":"趾高气扬","note":"昂首伸眉 implies justified pride, while 趾高气扬 suggests arrogance."}],"traditional":"昂首伸眉","pinyinOverride":null},{"id":"ang-shou-tian-wai","simplified":"昂首天外","literalMeaning":"raise head beyond the sky","figurativeMeaning":"to be ambitious and aim high; to have lofty aspirations","englishEquivalents":["reach for the stars","aim high"],"shortGloss":"to have lofty aspirations","characters":[{"char":"昂","meaning":"raise"},{"char":"首","meaning":"head"},{"char":"天","meaning":"sky"},{"char":"外","meaning":"beyond"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom 昂首天外 is used to describe someone who has great ambition and aims for goals that are beyond ordinary reach. It evokes the image of someone looking up beyond the sky, symbolizing their high aspirations and determination to achieve greatness.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"modifier-head","register":"literary, but can be used in both formal and informal contexts","connotation":"positive","commonMistakes":"Learners might confuse this idiom with others that involve ambition but lack the same level of aspiration. It specifically implies aiming for something extraordinarily high.","canStandAlone":false},"examples":[{"simplified":"他从小就昂首天外，希望成为一名伟大的科学家。","english":"Since childhood, he has aimed high, hoping to become a great scientist.","traditional":"他從小就昂首天外，希望成為一名偉大的科學家。"},{"simplified":"在事业上，她总是昂首天外，从不满足于现状。","english":"In her career, she always aims high and is never satisfied with the status quo.","traditional":"在事業上，她總是昂首天外，從不滿足於現狀。"}],"synonyms":["志存高远"],"antonyms":["安于现状"],"confusedWith":[{"id":"志存高远","note":"Both idioms express high ambition, but 昂首天外 emphasizes aiming beyond ordinary limits."}],"traditional":"昂首天外","pinyinOverride":null},{"id":"ang-yu-xiang-ji","simplified":"盎盂相击","literalMeaning":"bowls and pots clashing","figurativeMeaning":"conflict or discord between similar parties","englishEquivalents":["clash of interests","infighting"],"shortGloss":"conflict between similar parties","characters":[{"char":"盎","meaning":"bowl"},{"char":"盂","meaning":"pot"},{"char":"相","meaning":"mutually"},{"char":"击","meaning":"clash"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom 盎盂相击 is thought to describe a situation where similar or related parties are in conflict with each other, much like bowls and pots clashing together. The imagery suggests that even items meant to complement each other can sometimes be at odds.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["subject","predicate","object"],"structure":"coordinate","register":"literary, but can be used in formal speech","connotation":"negative","commonMistakes":"Learners often confuse this idiom with those that describe external conflicts, but 盎盂相击 specifically refers to internal or similar-party conflicts.","canStandAlone":false},"examples":[{"simplified":"在公司内部，盎盂相击的现象时有发生。","english":"Within the company, conflicts between similar parties often occur.","traditional":"在公司內部，盎盂相擊的現象時有發生。"},{"simplified":"这次会议上，盎盂相击的情况让人感到不安。","english":"The clash of interests at the meeting made people uneasy.","traditional":"這次會議上，盎盂相擊的情況讓人感到不安。"}],"synonyms":[],"antonyms":[],"confusedWith":[{"id":"内讧","note":"内讧 refers more broadly to internal strife, not necessarily between similar parties."}],"traditional":"盎盂相擊","pinyinOverride":null},{"id":"ang-yu-xiang-qiao","simplified":"盎盂相敲","literalMeaning":"bowls and pots clashing against each other","figurativeMeaning":"to be in conflict or disagreement","englishEquivalents":["at odds","in conflict","butting heads"],"shortGloss":"in conflict or disagreement","characters":[{"char":"盎","meaning":"bowl"},{"char":"盂","meaning":"pot"},{"char":"相","meaning":"mutually"},{"char":"敲","meaning":"knock"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom 盎盂相敲 is believed to originate from the imagery of bowls and pots clashing against each other, symbolizing conflict or disagreement. Just as these vessels make noise when they collide, people in conflict create disturbances.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"coordinate","register":"literary, but can be used in formal speech","connotation":"negative","commonMistakes":"Learners might confuse this idiom with similar-sounding ones that imply harmony rather than conflict. It's important to remember that this idiom specifically denotes disagreement.","canStandAlone":false},"examples":[{"simplified":"他们两人总是盎盂相敲，无法达成一致。","english":"The two of them are always at odds, unable to reach an agreement.","traditional":"他們兩人總是盎盂相敲，無法達成一致。"},{"simplified":"在会议上，各部门盎盂相敲，讨论激烈。","english":"During the meeting, the departments were in conflict, and the discussion was intense.","traditional":"在會議上，各部門盎盂相敲，討論激烈。"}],"synonyms":["针锋相对","水火不容"],"antonyms":["和睦相处","相安无事"],"confusedWith":[{"id":"和睦相处","note":"和睦相处 means to live in harmony, which is the opposite of being in conflict."}],"traditional":"盎盂相敲","pinyinOverride":null},{"id":"ao-chang-gua-du","simplified":"熬肠刮肚","literalMeaning":"boil intestines scrape stomach","figurativeMeaning":"to endure extreme hunger or hardship","englishEquivalents":["to be on the breadline","to go hungry"],"shortGloss":"endure extreme hunger","characters":[{"char":"熬","meaning":"to boil; endure"},{"char":"肠","meaning":"intestines"},{"char":"刮","meaning":"to scrape"},{"char":"肚","meaning":"stomach"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '熬肠刮肚' is used to describe the experience of enduring extreme hunger or hardship. It metaphorically suggests the feeling of one's intestines being boiled and stomach being scraped due to the lack of food. The origin of this idiom is not clearly documented, and it likely emerged from folk expressions describing the severe discomfort of hunger.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"coordinate","register":"informal, often used in spoken Chinese to describe personal hardship","connotation":"negative","commonMistakes":"Learners might confuse this idiom with others that describe emotional suffering rather than physical hunger. It's important to use it specifically in contexts of physical deprivation.","canStandAlone":false},"examples":[{"simplified":"他为了还债，过着熬肠刮肚的日子。","english":"He is living a life of extreme hardship to pay off his debts.","traditional":"他為了還債，過著熬腸刮肚的日子。"},{"simplified":"在战争期间，许多人都熬肠刮肚，生活艰难。","english":"During the war, many people endured extreme hunger and hardship.","traditional":"在戰爭期間，許多人都熬腸刮肚，生活艱難。"}],"synonyms":["饥寒交迫"],"antonyms":[],"confusedWith":[{"id":"心如刀割","note":"心如刀割 describes emotional pain, while 熬肠刮肚 refers to physical hunger."}],"traditional":"熬腸刮肚","pinyinOverride":null},{"id":"ao-jiang-xia-cu","simplified":"熬姜呷醋","literalMeaning":"boil ginger, sip vinegar","figurativeMeaning":"to suffer needlessly; to endure unnecessary hardship","englishEquivalents":["making a mountain out of a molehill","much ado about nothing"],"shortGloss":"endure unnecessary hardship","characters":[{"char":"熬","meaning":"boil"},{"char":"姜","meaning":"ginger"},{"char":"呷","meaning":"sip"},{"char":"醋","meaning":"vinegar"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '熬姜呷醋' comes from the idea of taking actions that are unnecessary and cause discomfort. Boiling ginger and sipping vinegar are both actions that can create a strong, unpleasant taste experience, symbolizing needless suffering. It is often used to describe situations where people complicate their lives or endure hardships that could have been avoided.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"informal, commonly used in everyday speech","connotation":"negative","commonMistakes":"Learners might confuse this idiom with phrases that imply enduring necessary hardship, but '熬姜呷醋' specifically refers to needless suffering. It is important to use it in contexts where the hardship could have been avoided.","canStandAlone":false},"examples":[{"simplified":"他总是熬姜呷醋，把简单的事情复杂化。","english":"He always makes a mountain out of a molehill, complicating simple matters.","traditional":"他總是熬薑呷醋，把簡單的事情複雜化。"},{"simplified":"你何必熬姜呷醋，事情没那么糟糕。","english":"Why endure unnecessary hardship? Things aren't that bad.","traditional":"你何必熬薑呷醋，事情沒那麼糟糕。"}],"synonyms":[],"antonyms":[],"confusedWith":[],"traditional":"熬薑呷醋","pinyinOverride":null},{"id":"ao-qing-shou-dan","simplified":"熬清守淡","literalMeaning":"endure purity, keep blandness","figurativeMeaning":"to endure a simple and unadorned life; to live a life of simplicity and frugality","englishEquivalents":["live a simple life","embrace simplicity"],"shortGloss":"endure a simple life","characters":[{"char":"熬","meaning":"endure, suffer"},{"char":"清","meaning":"pure, clear"},{"char":"守","meaning":"keep, maintain"},{"char":"淡","meaning":"bland, simple"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '熬清守淡' is believed to have originated from the idea of enduring a life that is pure and unadorned, focusing on simplicity and frugality. It reflects a mindset of accepting and maintaining a lifestyle that is devoid of luxury or excess, often seen as a virtue in traditional Chinese culture.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"coordinate","register":"literary, but can be used in both written and spoken Chinese to convey a philosophical or lifestyle choice","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with others that emphasize hardship or poverty, but '熬清守淡' specifically refers to a voluntary choice of simplicity rather than enforced deprivation.","canStandAlone":false},"examples":[{"simplified":"他选择熬清守淡的生活方式，远离城市的喧嚣。","english":"He chose a lifestyle of simplicity and frugality, staying away from the hustle and bustle of the city.","traditional":"他選擇熬清守淡的生活方式，遠離城市的喧囂。"},{"simplified":"在这个物欲横流的时代，熬清守淡是一种难得的品质。","english":"In this materialistic age, living a simple life is a rare quality.","traditional":"在這個物慾橫流的時代，熬清守淡是一種難得的品質。"}],"synonyms":[],"antonyms":[],"confusedWith":[],"traditional":"熬清守淡","pinyinOverride":null},{"id":"ao-man-shao-li","simplified":"傲慢少礼","literalMeaning":"arrogant and lacking in manners","figurativeMeaning":"to be arrogant and disrespectful","englishEquivalents":["rude and arrogant","high and mighty","full of oneself"],"shortGloss":"arrogant and disrespectful","characters":[{"char":"傲","meaning":"arrogant"},{"char":"慢","meaning":"haughty"},{"char":"少","meaning":"lacking"},{"char":"礼","meaning":"manners"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '傲慢少礼' describes someone who is not only arrogant but also lacks the proper manners or respect towards others. It is often used to criticize individuals who behave in a condescending or disrespectful manner, especially in social or formal settings.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"coordinate","register":"commonly used in both spoken and written Chinese to describe someone's demeanor","connotation":"negative","commonMistakes":"Learners might confuse this idiom with others that describe arrogance, but '傲慢少礼' specifically emphasizes the lack of respect and manners, not just arrogance.","canStandAlone":false},"examples":[{"simplified":"他在会议上表现得傲慢少礼，让大家很不满。","english":"He behaved arrogantly and disrespectfully at the meeting, which made everyone very unhappy.","traditional":"他在會議上表現得傲慢少禮，讓大家很不滿。"},{"simplified":"这种傲慢少礼的态度在职场上是不可接受的。","english":"Such an arrogant and disrespectful attitude is unacceptable in the workplace.","traditional":"這種傲慢少禮的態度在職場上是不可接受的。"}],"synonyms":["目中无人","自高自大"],"antonyms":["谦虚有礼","彬彬有礼"],"confusedWith":[{"id":"目中无人","note":"While both idioms describe arrogance, '目中无人' emphasizes ignoring others, whereas '傲慢少礼' emphasizes a lack of manners."}],"traditional":"傲慢少禮","pinyinOverride":null},{"id":"ao-ni-de-zhi","simplified":"傲睨得志","literalMeaning":"arrogant gaze upon achieving ambition","figurativeMeaning":"to become arrogant and complacent after achieving success","englishEquivalents":["Pride comes before a fall","Success breeds arrogance"],"shortGloss":"arrogant after success","characters":[{"char":"傲","meaning":"arrogant"},{"char":"睨","meaning":"to gaze sideways"},{"char":"得","meaning":"to achieve"},{"char":"志","meaning":"ambition"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom describes the behavior of someone who, after achieving their goals, becomes arrogant and looks down on others. This kind of attitude often leads to negative consequences, as it alienates others and can lead to one's downfall.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"modifier-head","register":"literary, but understood in educated speech","connotation":"negative","commonMistakes":"Learners might confuse this idiom with similar expressions of pride, but it specifically refers to arrogance after achieving success, not general pride.","canStandAlone":false},"examples":[{"simplified":"他一旦成功就变得傲睨得志，结果失去了很多朋友。","english":"Once he succeeded, he became arrogant and complacent, and as a result, lost many friends.","traditional":"他一旦成功就變得傲睨得志，結果失去了很多朋友。"},{"simplified":"傲睨得志的人往往会遭遇挫折。","english":"People who become arrogant after success often encounter setbacks.","traditional":"傲睨得志的人往往會遭遇挫折。"}],"synonyms":["得意忘形"],"antonyms":["谦虚谨慎"],"confusedWith":[{"id":"得意忘形","note":"Both idioms describe arrogance, but 得意忘形 emphasizes losing oneself in success, while 傲睨得志 focuses on looking down on others."}],"traditional":"傲睨得志","pinyinOverride":null},{"id":"ao-ni-yi-shi","simplified":"傲睨一世","literalMeaning":"arrogantly look down upon the world","figurativeMeaning":"to be extremely arrogant and look down on everyone","englishEquivalents":["look down one's nose at","high and mighty"],"shortGloss":"extremely arrogant","characters":[{"char":"傲","meaning":"arrogant"},{"char":"睨","meaning":"to look askance"},{"char":"一","meaning":"one"},{"char":"世","meaning":"world"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '傲睨一世' describes someone who is so arrogant that they look down upon everyone else in the world. It conveys a sense of disdain and superiority, often used to criticize someone who is overly proud or haughty.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"modifier-head","register":"literary, but understood in modern contexts to describe arrogance","connotation":"negative","commonMistakes":"Learners may confuse this idiom with others that describe confidence or self-assuredness, but '傲睨一世' specifically implies a negative judgment of arrogance.","canStandAlone":false},"examples":[{"simplified":"他总是傲睨一世，让人很不舒服。","english":"He always looks down on everyone, which makes people very uncomfortable.","traditional":"他總是傲睨一世，讓人很不舒服。"},{"simplified":"她的态度傲睨一世，难怪没有人愿意接近她。","english":"Her attitude is extremely arrogant, no wonder no one wants to approach her.","traditional":"她的態度傲睨一世，難怪沒有人願意接近她。"}],"synonyms":["目中无人"],"antonyms":["谦虚谨慎"],"confusedWith":[{"id":"目中无人","note":"Both describe arrogance, but '目中无人' focuses more on ignoring others, while '傲睨一世' emphasizes looking down on the world."}],"traditional":"傲睨一世","pinyinOverride":null},{"id":"ai-jian-die-bei","simplified":"挨肩迭背","literalMeaning":"shoulder to shoulder, back to back","figurativeMeaning":"crowded or packed closely together","englishEquivalents":["shoulder to shoulder","packed like sardines"],"shortGloss":"crowded closely together","characters":[{"char":"挨","meaning":"to be close to, to press against"},{"char":"肩","meaning":"shoulder"},{"char":"迭","meaning":"to alternate, to stack"},{"char":"背","meaning":"back"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '挨肩迭背' describes a situation where people or objects are packed closely together, much like standing shoulder to shoulder and back to back. This phrase vividly conveys the image of a crowded space, often used to describe bustling places such as markets or public transport.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["adverbial","attributive"],"structure":"coordinate","register":"commonly used in both spoken and written Chinese to describe crowded situations","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with others that describe physical closeness but imply different contexts, such as '肩并肩' which specifically means 'side by side' without the implication of crowding.","canStandAlone":false},"examples":[{"simplified":"节日期间，商场里的人挨肩迭背，几乎没有空隙。","english":"During the holiday season, the mall was so crowded that people were packed shoulder to shoulder, with almost no space in between.","traditional":"節日期間，商場裡的人挨肩迭背，幾乎沒有空隙。"},{"simplified":"地铁车厢里挨肩迭背，乘客们几乎动不了。","english":"The subway car was so packed that passengers were shoulder to shoulder and could barely move.","traditional":"地鐵車廂裡挨肩迭背，乘客們幾乎動不了。"}],"synonyms":["摩肩接踵"],"antonyms":[],"confusedWith":[{"id":"肩并肩","note":"肩并肩 means 'side by side' and does not imply crowding, unlike 挨肩迭背 which emphasizes a lack of space."}],"traditional":"挨肩迭背","pinyinOverride":null},{"id":"ai-nu-chi-er","simplified":"騃女痴儿","literalMeaning":"foolish girl, silly child","figurativeMeaning":"naive and inexperienced people","englishEquivalents":["innocent as a lamb","greenhorn"],"shortGloss":"naive and inexperienced people","characters":[{"char":"騃","meaning":"foolish"},{"char":"女","meaning":"girl"},{"char":"痴","meaning":"silly"},{"char":"儿","meaning":"child"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '騃女痴儿' is used to describe people who are naive and inexperienced, much like a foolish girl or a silly child. It emphasizes the innocence and lack of worldly experience of such individuals.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["subject","object","attributive"],"structure":"coordinate","register":"literary, but can be used in spoken Chinese to describe someone naive","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with expressions that imply stupidity rather than innocence. It's important to note the emphasis on naivety rather than lack of intelligence.","canStandAlone":false},"examples":[{"simplified":"他还是个騃女痴儿，不知道社会的复杂。","english":"He is still a naive and inexperienced person, unaware of the complexities of society.","traditional":"他還是個騃女痴兒，不知道社會的複雜。"},{"simplified":"在职场上，騃女痴儿很容易被利用。","english":"In the workplace, naive and inexperienced people are easily exploited.","traditional":"在職場上，騃女痴兒很容易被利用。"}],"synonyms":[],"antonyms":[],"confusedWith":[],"traditional":"騃女痴兒","pinyinOverride":null},{"id":"ai-nu-chi-nan","simplified":"騃女痴男","literalMeaning":"foolish girl, silly boy","figurativeMeaning":"a couple deeply in love, oblivious to the world around them","englishEquivalents":["lovebirds","head over heels"],"shortGloss":"a couple deeply in love","characters":[{"char":"騃","meaning":"foolish, silly"},{"char":"女","meaning":"girl, woman"},{"char":"痴","meaning":"obsessed, infatuated"},{"char":"男","meaning":"boy, man"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom 騃女痴男 describes a couple so deeply in love that they are oblivious to everything else around them. It paints a picture of youthful, naive love where both parties are seen as foolishly infatuated with each other.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["subject","predicate","object"],"structure":"coordinate","register":"colloquial, often used in informal contexts","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with others that describe foolishness without the romantic context. It's important to remember that this idiom specifically refers to mutual infatuation.","canStandAlone":false},"examples":[{"simplified":"他们俩真是騃女痴男，整天形影不离。","english":"They are such lovebirds, always inseparable.","traditional":"他們倆真是騃女痴男，整天形影不離。"},{"simplified":"在朋友眼中，他们是典型的騃女痴男。","english":"In the eyes of their friends, they are the typical head-over-heels couple.","traditional":"在朋友眼中，他們是典型的騃女痴男。"}],"synonyms":["如胶似漆"],"antonyms":["貌合神离"],"confusedWith":[{"id":"痴心妄想","note":"痴心妄想 means 'wishful thinking' and lacks the mutual romantic context."}],"traditional":"騃女痴男","pinyinOverride":null},{"id":"ai-tong-dun-fu","simplified":"騃童钝夫","literalMeaning":"foolish child, dull man","figurativeMeaning":"a naive or simple-minded person","englishEquivalents":["simpleton","naive person"],"shortGloss":"a naive or simple-minded person","characters":[{"char":"騃","meaning":"foolish, silly"},{"char":"童","meaning":"child"},{"char":"钝","meaning":"dull, slow-witted"},{"char":"夫","meaning":"man, person"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '騃童钝夫' is used to describe someone who is naive or simple-minded, akin to a foolish child or a dull adult. It is not directly traceable to a specific classical text, but rather seems to have evolved as a descriptive phrase over time.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["subject","object","attributive"],"structure":"coordinate","register":"literary, but can be used in a humorous or slightly derogatory context in speech","connotation":"negative","commonMistakes":"Learners might confuse this idiom with others that describe foolishness, but it specifically combines the idea of childish naivety with adult dullness.","canStandAlone":false},"examples":[{"simplified":"他真是个騃童钝夫，什么都不懂。","english":"He really is a simpleton, he understands nothing.","traditional":"他真是個騃童鈍夫，什麼都不懂。"},{"simplified":"在复杂的谈判中，他显得像个騃童钝夫。","english":"In the complex negotiations, he appeared like a naive person.","traditional":"在複雜的談判中，他顯得像個騃童鈍夫。"}],"synonyms":[],"antonyms":[],"confusedWith":[],"traditional":"騃童鈍夫","pinyinOverride":null},{"id":"an-hui-xiao-chen","simplified":"黯晦消沉","literalMeaning":"dark, obscure, vanish, sink","figurativeMeaning":"to be in low spirits or to feel depressed and despondent","englishEquivalents":["down in the dumps","in the doldrums"],"shortGloss":"feeling depressed or despondent","characters":[{"char":"黯","meaning":"dark"},{"char":"晦","meaning":"obscure"},{"char":"消","meaning":"vanish"},{"char":"沉","meaning":"sink"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '黯晦消沉' is used to describe a state of feeling low or depressed. It conveys the imagery of darkness and obscurity, suggesting a mood that is heavy and difficult to lift. The exact origin of this idiom is not clearly documented, but it has been used in Chinese literature to depict characters who are experiencing emotional turmoil or a lack of motivation.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"coordinate","register":"commonly used in both written and spoken Chinese to describe emotional states","connotation":"negative","commonMistakes":"Learners might confuse this idiom with others that describe physical darkness or obscurity, but '黯晦消沉' specifically refers to an emotional state. It should not be used to describe literal darkness.","canStandAlone":false},"examples":[{"simplified":"自从失去工作后，他一直黯晦消沉。","english":"Since losing his job, he has been feeling down in the dumps.","traditional":"自從失去工作後，他一直黯晦消沉。"},{"simplified":"她最近看起来黯晦消沉，可能是因为生活中的压力。","english":"She seems to be in the doldrums lately, possibly due to the pressures of life.","traditional":"她最近看起來黯晦消沉，可能是因為生活中的壓力。"}],"synonyms":["郁郁寡欢","心灰意冷"],"antonyms":["精神焕发","意气风发"],"confusedWith":[{"id":"黯然失色","note":"While both idioms involve the character '黯', '黯然失色' refers to losing one's luster or being overshadowed, not feeling depressed."}],"traditional":"黯晦消沉","pinyinOverride":null},{"id":"an-lv-xi-hong","simplified":"暗绿稀红","literalMeaning":"dark green, sparse red","figurativeMeaning":"a scene with dark green foliage and sparse red flowers; often used to describe a tranquil, natural setting","englishEquivalents":["a touch of red amidst the green","a splash of color in nature"],"shortGloss":"a tranquil scene with sparse red flowers","characters":[{"char":"暗","meaning":"dark"},{"char":"绿","meaning":"green"},{"char":"稀","meaning":"sparse"},{"char":"红","meaning":"red"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '暗绿稀红' is often used to describe a natural scene where the predominant color is the dark green of leaves or foliage, with occasional sparse red flowers adding a touch of color. This creates a tranquil and serene atmosphere, often evoking a sense of peace and beauty in nature.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["attributive"],"structure":"modifier-head","register":"literary, often used in poetry and descriptive writing","connotation":"positive","commonMistakes":"Learners might confuse this idiom with others that describe colors, but '暗绿稀红' specifically evokes a tranquil natural scene with a predominance of green and a sparse presence of red.","canStandAlone":false},"examples":[{"simplified":"花园里，暗绿稀红的景色让人感到宁静。","english":"In the garden, the scene of dark green and sparse red made people feel tranquil.","traditional":"花園裡，暗綠稀紅的景色讓人感到寧靜。"},{"simplified":"画家用暗绿稀红的色调描绘了春天的景象。","english":"The painter used dark green and sparse red tones to depict the scene of spring.","traditional":"畫家用暗綠稀紅的色調描繪了春天的景象。"}],"synonyms":[],"antonyms":[],"confusedWith":[],"traditional":"暗綠稀紅","pinyinOverride":null},{"id":"an-sheng-le-ye","simplified":"安生乐业","literalMeaning":"peaceful life, happy work","figurativeMeaning":"to live in peace and work happily; to live a stable and contented life","englishEquivalents":["live and work in peace","peaceful and contented life"],"shortGloss":"live in peace and work happily","characters":[{"char":"安","meaning":"peaceful"},{"char":"生","meaning":"life"},{"char":"乐","meaning":"happy"},{"char":"业","meaning":"work"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom 安生乐业 is used to describe a situation where people live a peaceful and stable life, with happiness in their work. It reflects a common aspiration for a harmonious and fulfilling life.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"coordinate","register":"widely used in both formal and informal contexts","connotation":"positive","commonMistakes":"Learners sometimes confuse this idiom with similar ones that emphasize only peace or only happiness, but this idiom specifically highlights both living peacefully and working happily.","canStandAlone":false},"examples":[{"simplified":"在这个小镇上，人们都过着安生乐业的生活。","english":"In this small town, people live peaceful and happy lives.","traditional":"在這個小鎮上，人們都過著安生樂業的生活。"},{"simplified":"政府的目标是让每个公民都能安生乐业。","english":"The government's goal is for every citizen to live in peace and work happily.","traditional":"政府的目標是讓每個公民都能安生樂業。"}],"synonyms":["安居乐业"],"antonyms":[],"confusedWith":[{"id":"安居乐业","note":"Both idioms convey a similar meaning, but 安居乐业 is more commonly used and emphasizes 'settling down' in addition to living peacefully and working happily."}],"traditional":"安生樂業","pinyinOverride":null},{"id":"an-tu-suo-jun","simplified":"按图索骏","literalMeaning":"follow map search for steed","figurativeMeaning":"to follow a plan or instructions rigidly without adaptation","englishEquivalents":["by the book","paint by numbers"],"shortGloss":"rigidly follow instructions","characters":[{"char":"按","meaning":"according to, follow"},{"char":"图","meaning":"map, plan"},{"char":"索","meaning":"search for"},{"char":"骏","meaning":"steed, fine horse"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom suggests a scenario where someone is trying to find a fine horse by strictly following a map or plan, without considering the actual circumstances or adapting to changes. It highlights the folly of adhering too rigidly to instructions without using one's own judgment.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["adverbial","complement"],"structure":"verb-object","register":"used in both formal and informal contexts, often with a critical tone","connotation":"negative","commonMistakes":"Learners might confuse this idiom with 按图索骥 (àn tú suǒ jì), which has a similar structure but refers to searching for something based on a plan or map, often with a positive connotation of being methodical. 按图索骏, however, emphasizes the negative aspect of rigidity.","canStandAlone":false},"examples":[{"simplified":"他总是按图索骏，缺乏灵活性。","english":"He always follows instructions rigidly, lacking flexibility.","traditional":"他總是按圖索駿，缺乏靈活性。"},{"simplified":"在这个快速变化的市场中，按图索骏可能会导致失败。","english":"In this rapidly changing market, rigidly following a plan might lead to failure.","traditional":"在這個快速變化的市場中，按圖索駿可能會導致失敗。"}],"synonyms":[],"antonyms":[],"confusedWith":[{"id":"按图索骥","note":"按图索骥 (àn tú suǒ jì) is often used positively to mean searching methodically, unlike 按图索骏 which is negative."}],"traditional":"按圖索駿","pinyinOverride":null},{"id":"an-tu-zhong-jiu","simplified":"安土重旧","literalMeaning":"settle land value old","figurativeMeaning":"to be attached to one's native land and old friends; to be unwilling to leave one's home","englishEquivalents":["home is where the heart is","there's no place like home"],"shortGloss":"attached to home and old friends","characters":[{"char":"安","meaning":"settle"},{"char":"土","meaning":"land"},{"char":"重","meaning":"value"},{"char":"旧","meaning":"old"}],"origin":{"period":"Eastern Han Dynasty (25–220 CE)","sourceText":"《后汉书·张衡传》","sourceTextEnglish":"Book of the Later Han, Biography of Zhang Heng","originalExcerpt":"安土重旧，不好异物。","storyEnglish":"The idiom originates from the 'Book of the Later Han', where it describes people who are content with their homeland and value their old acquaintances, showing a reluctance to embrace new things or places.","historicalFigures":["Zhang Heng"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"coordinate","register":"literary, but can be used in formal speech and writing","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with those that express nostalgia or homesickness, but it specifically emphasizes contentment and attachment to one's current home and friends, not longing for a past home.","canStandAlone":false},"examples":[{"simplified":"他安土重旧，不愿意搬到大城市去。","english":"He is attached to his home and old friends and doesn't want to move to the big city.","traditional":"他安土重舊，不願意搬到大城市去。"},{"simplified":"在这个快速变化的时代，安土重旧的人越来越少。","english":"In this rapidly changing era, there are fewer and fewer people who are attached to their home and old friends.","traditional":"在這個快速變化的時代，安土重舊的人越來越少。"}],"synonyms":["恋旧情深"],"antonyms":["背井离乡"],"confusedWith":[{"id":"恋旧情深","note":"Both express attachment to the past, but 安土重旧 emphasizes attachment to one's current home and friends."}],"traditional":"安土重舊","pinyinOverride":null},{"id":"an-tu-zhong-ju","simplified":"安土重居","literalMeaning":"settle land value residence","figurativeMeaning":"to be attached to one's native land and unwilling to leave it","englishEquivalents":["home is where the heart is","there's no place like home"],"shortGloss":"attached to one's homeland","characters":[{"char":"安","meaning":"settle; be at peace"},{"char":"土","meaning":"land; soil"},{"char":"重","meaning":"value; emphasize"},{"char":"居","meaning":"reside; live"}],"origin":{"period":"Han Dynasty (206 BCE – 220 CE)","sourceText":"《汉书·地理志》","sourceTextEnglish":"Book of Han, Treatise on Geography","originalExcerpt":"民之安土重居，故俗不可移也。","storyEnglish":"The idiom comes from the 'Book of Han', where it describes the people's attachment to their homeland, emphasizing that their customs and way of life are deeply rooted and difficult to change. This reflects a strong sense of belonging and reluctance to leave one's native place.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"literary, but can be used in formal speech to express nostalgia or attachment to one's homeland","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with similar ones that express homesickness, but this idiom specifically emphasizes the unwillingness to leave one's homeland, not just missing it.","canStandAlone":false},"examples":[{"simplified":"他安土重居，不愿意搬到城市去。","english":"He is attached to his homeland and is unwilling to move to the city.","traditional":"他安土重居，不願意搬到城市去。"},{"simplified":"安土重居的情感在许多老一辈的人中尤为强烈。","english":"The sentiment of being attached to one's homeland is particularly strong among many of the older generation.","traditional":"安土重居的情感在許多老一輩的人中尤為強烈。"}],"synonyms":["恋土难移"],"antonyms":["背井离乡"],"confusedWith":[{"id":"恋土难移","note":"Both express attachment to one's homeland, but '恋土难移' emphasizes the difficulty of moving away."}],"traditional":"安土重居","pinyinOverride":null},{"id":"ang-shou-xin-mei","simplified":"卬首信眉","literalMeaning":"raise head, trust eyebrows","figurativeMeaning":"to look up with trust and confidence","englishEquivalents":["look up with trust","have faith in someone"],"shortGloss":"look up with trust","characters":[{"char":"卬","meaning":"raise, lift"},{"char":"首","meaning":"head"},{"char":"信","meaning":"trust, believe"},{"char":"眉","meaning":"eyebrows"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '卬首信眉' is believed to have originated from a folk expression, conveying the idea of looking up to someone with trust and confidence. It reflects a gesture of raising one's head and trusting what is seen or heard, often used to describe a relationship of faith or reliance.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["adverbial","complement"],"structure":"modifier-head","register":"literary, but can be used in formal speech","connotation":"positive","commonMistakes":"Learners might confuse this idiom with others that involve trust or belief, but this idiom specifically conveys a sense of looking up to someone with confidence. It is not used to describe blind faith.","canStandAlone":false},"examples":[{"simplified":"他对老师卬首信眉，毫不怀疑。","english":"He looks up to his teacher with trust and confidence, without any doubt.","traditional":"他對老師卬首信眉，毫不懷疑。"},{"simplified":"在危机时刻，我们需要一个可以卬首信眉的领导者。","english":"In times of crisis, we need a leader we can look up to with trust.","traditional":"在危機時刻，我們需要一個可以卬首信眉的領導者。"}],"synonyms":[],"antonyms":[],"confusedWith":[],"traditional":"卬首信眉","pinyinOverride":null},{"id":"ang-tou-kuo-bu","simplified":"卬头阔步","literalMeaning":"raise head, stride broadly","figurativeMeaning":"to walk with confidence and pride","englishEquivalents":["walk tall","hold one's head high"],"shortGloss":"walk with confidence and pride","characters":[{"char":"卬","meaning":"raise"},{"char":"头","meaning":"head"},{"char":"阔","meaning":"broad"},{"char":"步","meaning":"step"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '卬头阔步' describes the manner of walking with one's head held high and taking broad steps, symbolizing confidence and pride. It is often used to describe someone who is self-assured and unafraid to show it.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"commonly used in both formal and informal contexts","connotation":"positive","commonMistakes":"Learners might confuse this idiom with others that involve walking, such as '昂首阔步', which has a similar meaning but uses the character '昂' instead of '卬'.","canStandAlone":false},"examples":[{"simplified":"他卬头阔步地走进了会议室，显得非常自信。","english":"He walked into the meeting room with his head held high, looking very confident.","traditional":"他卬頭闊步地走進了會議室，顯得非常自信。"},{"simplified":"在取得胜利后，运动员们卬头阔步地绕场一周。","english":"After their victory, the athletes walked around the field with their heads held high.","traditional":"在取得勝利後，運動員們卬頭闊步地繞場一週。"}],"synonyms":["昂首阔步"],"antonyms":["垂头丧气"],"confusedWith":[{"id":"昂首阔步","note":"Both idioms describe walking with confidence, but '昂首阔步' is more commonly used."}],"traditional":"卬頭闊步","pinyinOverride":null},{"id":"ao-ku-shou-dan","simplified":"熬枯受淡","literalMeaning":"endure dryness, accept blandness","figurativeMeaning":"to endure hardship and monotony","englishEquivalents":["grin and bear it","weather the storm"],"shortGloss":"endure hardship and monotony","characters":[{"char":"熬","meaning":"endure"},{"char":"枯","meaning":"dryness"},{"char":"受","meaning":"accept"},{"char":"淡","meaning":"blandness"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '熬枯受淡' is believed to have originated from the idea of enduring difficult and monotonous conditions, much like surviving on bland food and enduring dry spells. It reflects the resilience and perseverance required to get through tough times.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"coordinate","register":"used in both literary and colloquial contexts, often to describe enduring tough situations","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with others that imply only enduring hardship without the aspect of monotony. It's important to remember that '熬枯受淡' includes both enduring hardship and accepting monotony.","canStandAlone":false},"examples":[{"simplified":"在这段时间，我们只能熬枯受淡，等待机会的来临。","english":"During this period, we can only endure hardship and monotony, waiting for an opportunity to arise.","traditional":"在這段時間，我們只能熬枯受淡，等待機會的來臨。"},{"simplified":"他在困境中熬枯受淡，终于迎来了成功的曙光。","english":"He endured hardship and monotony in adversity and finally saw the dawn of success.","traditional":"他在困境中熬枯受淡，終於迎來了成功的曙光。"}],"synonyms":[],"antonyms":[],"confusedWith":[],"traditional":"熬枯受淡","pinyinOverride":null},{"id":"ao-ya-ji-qu","simplified":"聱牙佶屈","literalMeaning":"difficult teeth, stiff and twisted","figurativeMeaning":"difficult to read or understand; awkwardly worded","englishEquivalents":["hard to read","awkward phrasing"],"shortGloss":"awkward or difficult language","characters":[{"char":"聱","meaning":"difficult, awkward"},{"char":"牙","meaning":"teeth"},{"char":"佶","meaning":"stiff, rigid"},{"char":"屈","meaning":"twisted, bent"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '聱牙佶屈' is used to describe language that is difficult to read or understand, often due to awkward or convoluted phrasing. The imagery of 'difficult teeth' and 'stiff and twisted' suggests something that is hard to chew or process, much like a text that is hard to comprehend.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["attributive","adverbial"],"structure":"coordinate","register":"literary, but can be used in formal writing to describe complex or awkward language","connotation":"negative","commonMistakes":"Learners might confuse this idiom with those that describe difficult situations rather than difficult language. It's specifically about the complexity or awkwardness of text or speech.","canStandAlone":false},"examples":[{"simplified":"这篇文章写得聱牙佶屈，让人很难理解。","english":"This article is written in such an awkward and convoluted way that it's hard to understand.","traditional":"這篇文章寫得聱牙佶屈，讓人很難理解。"},{"simplified":"他的演讲内容聱牙佶屈，听众很难跟上。","english":"His speech was so awkwardly phrased that the audience found it hard to follow.","traditional":"他的演講內容聱牙佶屈，聽眾很難跟上。"}],"synonyms":["晦涩难懂"],"antonyms":["通俗易懂"],"confusedWith":[{"id":"晦涩难懂","note":"Both describe difficult language, but '晦涩难懂' emphasizes obscurity and difficulty in understanding, while '聱牙佶屈' emphasizes awkwardness and convoluted phrasing."}],"traditional":"聱牙佶屈","pinyinOverride":null},{"id":"ao-you-fei-huo","simplified":"熬油费火","literalMeaning":"boil oil, waste fire","figurativeMeaning":"to waste resources or effort unnecessarily","englishEquivalents":["burning the candle at both ends","waste not, want not"],"shortGloss":"waste resources or effort","characters":[{"char":"熬","meaning":"boil or simmer for a long time"},{"char":"油","meaning":"oil"},{"char":"费","meaning":"waste or consume"},{"char":"火","meaning":"fire"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '熬油费火' likely originates from the idea of using excessive fire to boil oil, which is seen as wasteful. It metaphorically describes situations where resources or efforts are expended unnecessarily, leading to waste.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"informal, commonly used in spoken language","connotation":"negative","commonMistakes":"Learners might confuse this idiom with expressions that simply mean 'to work hard' without the negative connotation of wastefulness. It's important to note the emphasis on unnecessary expenditure.","canStandAlone":false},"examples":[{"simplified":"他这样做只是熬油费火，没有任何意义。","english":"What he's doing is just wasting resources, it has no meaning.","traditional":"他這樣做只是熬油費火，沒有任何意義。"},{"simplified":"在这个项目上投入太多资金，只会熬油费火。","english":"Investing too much money in this project will just be a waste of resources.","traditional":"在這個項目上投入太多資金，只會熬油費火。"}],"synonyms":["劳民伤财"],"antonyms":["物尽其用"],"confusedWith":[{"id":"事倍功半","note":"While both idioms involve inefficiency, '事倍功半' emphasizes achieving less with more effort, not necessarily waste."}],"traditional":"熬油費火","pinyinOverride":null},{"id":"ao-zhi-jing-qu","simplified":"鳌掷鲸呿","literalMeaning":"giant turtle throws, whale opens mouth","figurativeMeaning":"a grand spectacle; an impressive and awe-inspiring scene","englishEquivalents":["a sight to behold","a grand spectacle"],"shortGloss":"a grand spectacle","characters":[{"char":"鳌","meaning":"giant turtle; a mythical creature"},{"char":"掷","meaning":"to throw; to cast"},{"char":"鲸","meaning":"whale"},{"char":"呿","meaning":"to open the mouth"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '鳌掷鲸呿' is believed to describe a scene of immense grandeur and awe, likening it to the mythical image of a giant turtle throwing something while a whale opens its mouth. This imagery conveys the idea of a powerful and majestic spectacle. However, the exact origin of this idiom is not well-documented and is considered to be of folk origin.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["subject","predicate","object"],"structure":"coordinate","register":"literary, often used in poetry or formal writing to describe grand scenes","connotation":"positive","commonMistakes":"Learners might confuse this idiom with others that describe chaos or disorder due to the imagery of large creatures. However, this idiom specifically conveys grandeur and awe, not chaos.","canStandAlone":false},"examples":[{"simplified":"新年的烟花表演真是鳌掷鲸呿，令人叹为观止。","english":"The New Year's fireworks display was truly a grand spectacle, a sight to behold.","traditional":"新年的煙花表演真是鰲擲鯨呿，令人歎為觀止。"},{"simplified":"这部电影的特效场面如同鳌掷鲸呿，令人目不转睛。","english":"The special effects scenes in this movie are like a grand spectacle, captivating the audience.","traditional":"這部電影的特效場面如同鰲擲鯨呿，令人目不轉睛。"}],"synonyms":[],"antonyms":[],"confusedWith":[],"traditional":"鰲擲鯨呿","pinyinOverride":null},{"id":"an-yu-pan-shi","simplified":"安于盘石","literalMeaning":"settle on a rock","figurativeMeaning":"to be in a stable and secure position","englishEquivalents":["sitting pretty","on solid ground"],"shortGloss":"to be in a stable and secure position","characters":[{"char":"安","meaning":"settle"},{"char":"于","meaning":"on"},{"char":"盘","meaning":"rock"},{"char":"石","meaning":"stone"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '安于盘石' is believed to have originated from the imagery of being settled or resting on a large, stable rock, symbolizing a position of security and stability. It is often used to describe a situation where one feels safe and unthreatened.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"literary, but can be used in formal speech and writing","connotation":"positive","commonMistakes":"Learners might confuse this idiom with others that imply physical stability rather than metaphorical security. It is important to remember that this idiom is about feeling secure in a situation, not about physical stability.","canStandAlone":false},"examples":[{"simplified":"在新公司工作后，他感到安于盘石。","english":"After starting at the new company, he felt he was on solid ground.","traditional":"在新公司工作後，他感到安於盤石。"},{"simplified":"她的生活安于盘石，没有什么可担心的。","english":"Her life is stable and secure, with nothing to worry about.","traditional":"她的生活安於盤石，沒有什麼可擔心的。"}],"synonyms":["稳如泰山"],"antonyms":["岌岌可危"],"confusedWith":[{"id":"稳如泰山","note":"While both idioms imply stability, '稳如泰山' emphasizes physical steadiness, whereas '安于盘石' emphasizes a sense of security."}],"traditional":"安於盤石","pinyinOverride":null},{"id":"ai-jin-cheng-chuang","simplified":"哀矜惩创","literalMeaning":"pity and punish to create","figurativeMeaning":"to show compassion while administering punishment; to be lenient and understanding when enforcing discipline","englishEquivalents":["spare the rod and spoil the child","tough love"],"shortGloss":"compassionate discipline","characters":[{"char":"哀","meaning":"pity, compassion"},{"char":"矜","meaning":"sympathy, mercy"},{"char":"惩","meaning":"punish, discipline"},{"char":"创","meaning":"create, establish"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom suggests a balanced approach to discipline, where one should be compassionate and understanding while also enforcing rules and consequences. It emphasizes the importance of empathy in leadership and parenting, suggesting that true discipline involves both correction and care.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"coordinate","register":"literary, but can be used in formal speech and writing","connotation":"neutral","commonMistakes":"Learners often misunderstand this idiom as advocating for harsh punishment without compassion. It is important to note that it emphasizes a balance between discipline and empathy.","canStandAlone":false},"examples":[{"simplified":"作为老师，我们应该哀矜惩创，既要严格要求学生，也要理解他们的困难。","english":"As teachers, we should show compassionate discipline, being strict with students while also understanding their difficulties.","traditional":"作為老師，我們應該哀矜懲創，既要嚴格要求學生，也要理解他們的困難。"},{"simplified":"父母在教育孩子时，哀矜惩创是非常重要的原则。","english":"When educating children, it is very important for parents to practice compassionate discipline.","traditional":"父母在教育孩子時，哀矜懲創是非常重要的原則。"}],"synonyms":[],"antonyms":[],"confusedWith":[],"traditional":"哀矜懲創","pinyinOverride":null},{"id":"ai-fa-shuai-rong","simplified":"艾发衰容","literalMeaning":"gray hair, declining appearance","figurativeMeaning":"to describe someone who is aging and showing signs of old age","englishEquivalents":["over the hill","past one's prime"],"shortGloss":"showing signs of aging","characters":[{"char":"艾","meaning":"gray (referring to hair)"},{"char":"发","meaning":"hair"},{"char":"衰","meaning":"declining"},{"char":"容","meaning":"appearance"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '艾发衰容' is used to describe someone who is visibly aging, with gray hair and a declining appearance. It is often used in literature and conversation to comment on the inevitable process of aging.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["attributive","predicate"],"structure":"modifier-head","register":"literary, but can be used in both formal and informal contexts","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with others that describe aging but with different connotations. '艾发衰容' is neutral and descriptive, not inherently negative.","canStandAlone":false},"examples":[{"simplified":"他虽然艾发衰容，但仍然充满活力。","english":"Although he has gray hair and a declining appearance, he is still full of energy.","traditional":"他雖然艾發衰容，但仍然充滿活力。"},{"simplified":"她不在乎艾发衰容，反而欣然接受岁月的痕迹。","english":"She doesn't mind her gray hair and declining appearance; instead, she embraces the marks of time.","traditional":"她不在乎艾發衰容，反而欣然接受歲月的痕跡。"}],"synonyms":[],"antonyms":[],"confusedWith":[],"traditional":"艾發衰容","pinyinOverride":null},{"id":"ai-fei-qi-dao","simplified":"爱非其道","literalMeaning":"love not its way","figurativeMeaning":"to pursue something in the wrong way; to love or value something but go about it incorrectly","englishEquivalents":["barking up the wrong tree","missing the mark"],"shortGloss":"pursuing wrongly","characters":[{"char":"爱","meaning":"love; value"},{"char":"非","meaning":"not; wrong"},{"char":"其","meaning":"its; one's"},{"char":"道","meaning":"way; method"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom 爱非其道 describes the situation where someone has good intentions or desires but pursues them in an incorrect or ineffective manner. It emphasizes the importance of choosing the right method or path to achieve one's goals.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"modifier-head","register":"literary, but can be used in formal speech","connotation":"negative","commonMistakes":"Learners often confuse this idiom with similar-sounding ones that involve love or affection but do not convey the idea of pursuing something incorrectly. It's important to focus on the 'wrong way' aspect.","canStandAlone":false},"examples":[{"simplified":"他对这项工作爱非其道，结果浪费了很多时间。","english":"He pursued this work in the wrong way, resulting in a lot of wasted time.","traditional":"他對這項工作愛非其道，結果浪費了很多時間。"},{"simplified":"如果你爱非其道，就很难达到目标。","english":"If you pursue things in the wrong way, it's hard to achieve your goals.","traditional":"如果你愛非其道，就很難達到目標。"}],"synonyms":[],"antonyms":[],"confusedWith":[],"traditional":"愛非其道","pinyinOverride":null},{"id":"ai-jian-kai-wen","simplified":"僾见忾闻","literalMeaning":"obscurely seen, angrily heard","figurativeMeaning":"to be deeply moved or affected by something; to be emotionally stirred","englishEquivalents":["moved to the core","deeply touched","stirred emotionally"],"shortGloss":"deeply moved or affected","characters":[{"char":"僾","meaning":"obscurely, indistinctly"},{"char":"见","meaning":"see"},{"char":"忾","meaning":"angrily, with indignation"},{"char":"闻","meaning":"hear"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '僾见忾闻' is believed to describe a situation where one is emotionally stirred by something they see or hear. The exact origin of this idiom is not clear, and it is often considered to have emerged from folk usage rather than a specific classical text.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"coordinate","register":"literary, but can be used in formal speech or writing to express deep emotional impact","connotation":"neutral","commonMistakes":"Learners often confuse this idiom with others that describe physical visibility or audibility, but '僾见忾闻' specifically refers to emotional impact rather than sensory perception.","canStandAlone":false},"examples":[{"simplified":"听到他的故事，我僾见忾闻，久久不能平静。","english":"Hearing his story, I was deeply moved and couldn't calm down for a long time.","traditional":"聽到他的故事，我僾見愾聞，久久不能平靜。"},{"simplified":"那部电影让观众僾见忾闻，许多人都流下了眼泪。","english":"The movie deeply moved the audience, and many people were brought to tears.","traditional":"那部電影讓觀眾僾見愾聞，許多人都流下了眼淚。"}],"synonyms":[],"antonyms":[],"confusedWith":[{"id":"见闻广博","note":"While '见闻广博' refers to having extensive knowledge or experience, '僾见忾闻' focuses on emotional impact."}],"traditional":"僾見愾聞","pinyinOverride":null},{"id":"an-qi-suo-xi","simplified":"安其所习","literalMeaning":"be content with what one is accustomed to","figurativeMeaning":"to be content with one's usual way of life or habits","englishEquivalents":["old habits die hard","creature of habit"],"shortGloss":"content with one's habits","characters":[{"char":"安","meaning":"content, at ease"},{"char":"其","meaning":"one's, his/her"},{"char":"所","meaning":"that which"},{"char":"习","meaning":"habit, practice"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom suggests a person who is comfortable with their established routines and practices, preferring the familiar over the new or unknown. It reflects a mindset of being satisfied with one's current way of life, without seeking change.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"modifier-head","register":"neutral, commonly used in both spoken and written Chinese","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with similar expressions that imply laziness or resistance to change. However, this idiom does not carry a negative connotation and simply describes contentment with the familiar.","canStandAlone":false},"examples":[{"simplified":"他总是安其所习，不愿尝试新事物。","english":"He is always content with what he is accustomed to and is unwilling to try new things.","traditional":"他總是安其所習，不願嘗試新事物。"},{"simplified":"在新的环境中，她很快就安其所习了。","english":"In the new environment, she quickly became content with her usual habits.","traditional":"在新的環境中，她很快就安其所習了。"}],"synonyms":[],"antonyms":["好奇心强"],"confusedWith":[{"id":"墨守成规","note":"While both idioms involve sticking to the familiar, 墨守成规 implies a rigid adherence to old ways, often with a negative connotation."}],"traditional":"安其所習","pinyinOverride":null},{"id":"an-xiang-gong-jing","simplified":"安详恭敬","literalMeaning":"calm and respectful","figurativeMeaning":"to be calm and respectful in demeanor","englishEquivalents":["calm and respectful","serene and courteous"],"shortGloss":"calm and respectful","characters":[{"char":"安","meaning":"calm, peaceful"},{"char":"详","meaning":"detailed, but here it implies serenity"},{"char":"恭","meaning":"respectful"},{"char":"敬","meaning":"reverent, respectful"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '安详恭敬' is often used to describe a person's demeanor, particularly in formal or ceremonial contexts. It emphasizes a composed and respectful attitude, which is highly valued in many cultures. The exact origin of this idiom is not well-documented, but it reflects traditional values of calmness and respectfulness.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["attributive","adverbial"],"structure":"coordinate","register":"formal, often used in ceremonial or respectful contexts","connotation":"positive","commonMistakes":"Learners might confuse this idiom with others that imply calmness but lack the aspect of respectfulness, such as '安静'. '安详恭敬' specifically includes a respectful demeanor.","canStandAlone":false},"examples":[{"simplified":"他在会议上表现得安详恭敬，给大家留下了深刻的印象。","english":"He behaved in a calm and respectful manner at the meeting, leaving a deep impression on everyone.","traditional":"他在會議上表現得安詳恭敬，給大家留下了深刻的印象。"},{"simplified":"面对长辈，我们应该保持安详恭敬的态度。","english":"We should maintain a calm and respectful attitude when facing our elders.","traditional":"面對長輩，我們應該保持安詳恭敬的態度。"}],"synonyms":[],"antonyms":[],"confusedWith":[{"id":"安静","note":"'安静' means quiet or peaceful, lacking the aspect of respectfulness that '安详恭敬' includes."}],"traditional":"安詳恭敬","pinyinOverride":null},{"id":"an-yu-suo-xi","simplified":"安于所习","literalMeaning":"content with what is familiar","figurativeMeaning":"to be content with one's current situation or accustomed habits, often implying a reluctance to change or try new things","englishEquivalents":["set in one's ways","stuck in a rut"],"shortGloss":"content with the familiar","characters":[{"char":"安","meaning":"content, at ease"},{"char":"于","meaning":"in, at"},{"char":"所","meaning":"what, that which"},{"char":"习","meaning":"familiar, accustomed"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '安于所习' describes a mindset where a person is comfortable with their current habits or situation, often to the point of resisting change. It reflects a tendency to prefer the known and familiar, even if it means missing out on new opportunities or improvements.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"modifier-head","register":"neutral, commonly used in both spoken and written Chinese","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with those that imply laziness or stagnation, but '安于所习' specifically emphasizes contentment with familiarity rather than a lack of ambition.","canStandAlone":false},"examples":[{"simplified":"他总是安于所习，不愿尝试新的事物。","english":"He is always content with what is familiar and unwilling to try new things.","traditional":"他總是安於所習，不願嘗試新的事物。"},{"simplified":"在快速变化的时代，安于所习可能会错过很多机会。","english":"In a rapidly changing era, being content with what is familiar might lead to missing many opportunities.","traditional":"在快速變化的時代，安於所習可能會錯過很多機會。"}],"synonyms":["故步自封"],"antonyms":["勇于创新"],"confusedWith":[{"id":"故步自封","note":"While both imply a reluctance to change, '故步自封' has a stronger connotation of being self-satisfied and resistant to progress."}],"traditional":"安於所習","pinyinOverride":null},{"id":"ang-ang-bu-dong","simplified":"昂昂不动","literalMeaning":"upright and unmoving","figurativeMeaning":"steadfast and unyielding in one's principles or position","englishEquivalents":["stand one's ground","unwavering","steadfast"],"shortGloss":"steadfast and unyielding","characters":[{"char":"昂","meaning":"upright, proud"},{"char":"昂","meaning":"upright, proud"},{"char":"不","meaning":"not"},{"char":"动","meaning":"move"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '昂昂不动' is used to describe someone who remains steadfast and unyielding in their principles or position, regardless of external pressures or challenges. It conveys a sense of pride and dignity in maintaining one's stance.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"modifier-head","register":"literary, but can be used in formal speech","connotation":"positive","commonMistakes":"Learners might confuse this idiom with others that suggest stubbornness or inflexibility, but '昂昂不动' has a positive connotation of principled steadfastness.","canStandAlone":false},"examples":[{"simplified":"在面对巨大压力时，他依然昂昂不动。","english":"In the face of immense pressure, he remained steadfast and unyielding.","traditional":"在面對巨大壓力時，他依然昂昂不動。"},{"simplified":"她以昂昂不动的态度坚持自己的信念。","english":"She upheld her beliefs with a steadfast and unyielding attitude.","traditional":"她以昂昂不動的態度堅持自己的信念。"}],"synonyms":["坚定不移","坚贞不屈"],"antonyms":["摇摆不定"],"confusedWith":[{"id":"顽固不化","note":"While both imply not changing one's position, '顽固不化' has a negative connotation of stubbornness, unlike the positive steadfastness of '昂昂不动'."}],"traditional":"昂昂不動","pinyinOverride":null},{"id":"ao-ya-qu-qu","simplified":"聱牙诎曲","literalMeaning":"difficult teeth, bent and twisted","figurativeMeaning":"difficult to read or understand due to complex language or structure","englishEquivalents":["hard to read","convoluted","dense"],"shortGloss":"difficult to read or understand","characters":[{"char":"聱","meaning":"difficult; awkward (in reading)"},{"char":"牙","meaning":"teeth"},{"char":"诎","meaning":"bent; twisted"},{"char":"曲","meaning":"curved; winding"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '聱牙诎曲' is used to describe language or writing that is difficult to read or understand because of its complexity or awkwardness. The imagery of 'difficult teeth' and 'bent and twisted' conveys the idea of something that is not straightforward or easy to digest, much like a text that requires effort to comprehend.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["attributive","adverbial"],"structure":"coordinate","register":"literary, but can be used in critical or academic discussions","connotation":"negative","commonMistakes":"Learners might confuse this idiom with simpler expressions for 'difficult' without realizing it specifically refers to the complexity of language or writing. It is not used for general difficulty in tasks.","canStandAlone":false},"examples":[{"simplified":"这篇论文写得聱牙诎曲，让人难以理解。","english":"This paper is written in a convoluted manner, making it hard to understand.","traditional":"這篇論文寫得聱牙詘曲，讓人難以理解。"},{"simplified":"他的演讲内容聱牙诎曲，听众纷纷表示困惑。","english":"His speech was convoluted, and the audience expressed confusion.","traditional":"他的演講內容聱牙詘曲，聽眾紛紛表示困惑。"}],"synonyms":["晦涩难懂"],"antonyms":["浅显易懂"],"confusedWith":[{"id":"晦涩难懂","note":"While both idioms refer to difficulty in understanding, '晦涩难懂' emphasizes obscurity and lack of clarity, while '聱牙诎曲' focuses on awkwardness and complexity of language."}],"traditional":"聱牙詘曲","pinyinOverride":null},{"id":"ba-fang-feng-yu","simplified":"八方风雨","literalMeaning":"eight directions wind and rain","figurativeMeaning":"troubles or difficulties coming from all directions","englishEquivalents":["troubles from all sides","under siege from all directions"],"shortGloss":"troubles from all directions","characters":[{"char":"八","meaning":"eight, representing all directions"},{"char":"方","meaning":"directions"},{"char":"风","meaning":"wind, symbolizing challenges"},{"char":"雨","meaning":"rain, symbolizing difficulties"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '八方风雨' is used to describe a situation where challenges or troubles seem to come from every direction, much like being caught in a storm with wind and rain coming from all sides. It emphasizes the overwhelming nature of the difficulties faced.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["subject","predicate","object"],"structure":"coordinate","register":"commonly used in both spoken and written Chinese to describe overwhelming difficulties","connotation":"negative","commonMistakes":"Learners might confuse this idiom with others that involve '风雨' but do not imply challenges from all directions. It's important to note the '八方' aspect, which emphasizes the omnipresence of the troubles.","canStandAlone":false},"examples":[{"simplified":"公司最近面临八方风雨，需要全体员工的努力。","english":"The company is currently facing troubles from all directions and needs the efforts of all employees.","traditional":"公司最近面臨八方風雨，需要全體員工的努力。"},{"simplified":"在八方风雨中，他依然保持冷静。","english":"Amidst troubles from all sides, he remained calm.","traditional":"在八方風雨中，他依然保持冷靜。"}],"synonyms":[],"antonyms":[],"confusedWith":[{"id":"风雨同舟","note":"While '风雨同舟' emphasizes solidarity in facing difficulties, '八方风雨' highlights the overwhelming nature of the challenges."}],"traditional":"八方風雨","pinyinOverride":null},{"id":"ba-fang-zhi-yuan","simplified":"八方支援","literalMeaning":"support from all directions","figurativeMeaning":"to receive help and support from all sides","englishEquivalents":["help from all quarters","support from all sides"],"shortGloss":"support from all directions","characters":[{"char":"八","meaning":"eight; all around"},{"char":"方","meaning":"directions; quarters"},{"char":"支","meaning":"support; provide assistance"},{"char":"援","meaning":"aid; help"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '八方支援' is used to describe a situation where help and support come from all directions or quarters. It emphasizes the idea of receiving assistance from various sources, often in times of need or crisis. The phrase is commonly used in modern contexts to express gratitude or acknowledgment of widespread support.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["subject","predicate","object"],"structure":"modifier-head","register":"widely used in both formal and informal contexts","connotation":"positive","commonMistakes":"Learners might confuse this idiom with others that involve '八方' (all directions) but have different meanings. It's important to remember that '八方支援' specifically refers to receiving support or aid.","canStandAlone":false},"examples":[{"simplified":"在危机时刻，我们得到了八方支援。","english":"In times of crisis, we received support from all directions.","traditional":"在危機時刻，我們得到了八方支援。"},{"simplified":"这次活动的成功离不开八方支援。","english":"The success of this event could not have been achieved without support from all sides.","traditional":"這次活動的成功離不開八方支援。"}],"synonyms":["四面八方","众志成城"],"antonyms":[],"confusedWith":[{"id":"四面八方","note":"While both idioms involve 'all directions', '四面八方' refers more generally to 'everywhere' or 'all around', not specifically to receiving support."}],"traditional":"八方支援","pinyinOverride":null},{"id":"ba-mian-shi-feng","simplified":"八面驶风","literalMeaning":"eight sides sail wind","figurativeMeaning":"to be resourceful and handle things smoothly in all directions; to have everything under control","englishEquivalents":["have everything under control","smooth operator"],"shortGloss":"resourceful and smooth in all directions","characters":[{"char":"八","meaning":"eight"},{"char":"面","meaning":"sides"},{"char":"驶","meaning":"sail"},{"char":"风","meaning":"wind"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '八面驶风' is believed to have originated from the idea of a skilled sailor who can navigate smoothly regardless of the wind's direction. It metaphorically describes a person who is adept at managing situations and dealing with people from all sides, ensuring everything goes smoothly.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"commonly used in both spoken and written Chinese to describe someone who is very capable and resourceful","connotation":"positive","commonMistakes":"Learners might confuse this idiom with others that involve '风' (wind) but have different meanings, such as '风平浪静' which refers to calmness rather than resourcefulness.","canStandAlone":false},"examples":[{"simplified":"他在公司里八面驶风，深受同事们的尊敬。","english":"He handles everything smoothly at the company and is highly respected by his colleagues.","traditional":"他在公司裡八面駛風，深受同事們的尊敬。"},{"simplified":"她在社交场合八面驶风，总能化解尴尬。","english":"She is resourceful in social situations and can always defuse awkward moments.","traditional":"她在社交場合八面駛風，總能化解尷尬。"}],"synonyms":["八面玲珑"],"antonyms":[],"confusedWith":[{"id":"风平浪静","note":"风平浪静 refers to calmness and tranquility, not resourcefulness or adeptness."}],"traditional":"八面駛風","pinyinOverride":null},{"id":"ba-xian-guo-hai","simplified":"八仙过海","literalMeaning":"Eight Immortals cross the sea","figurativeMeaning":"each uses their own special skill to achieve a goal","englishEquivalents":["Each to their own","Every man for himself"],"shortGloss":"using individual skills to achieve a goal","characters":[{"char":"八","meaning":"eight"},{"char":"仙","meaning":"immortals"},{"char":"过","meaning":"cross"},{"char":"海","meaning":"sea"}],"origin":{"period":"Ming dynasty (1368–1644)","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom comes from a popular Chinese legend about the Eight Immortals, who are figures in Chinese mythology. In the story, the Eight Immortals encounter a vast sea they need to cross. Instead of using a boat, each immortal uses their unique magical power to cross the sea, showcasing their individual talents and creativity. This tale symbolizes the idea that different people can achieve the same goal using different methods.","historicalFigures":["The Eight Immortals"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["subject","predicate","object"],"structure":"subject-predicate","register":"commonly used in both spoken and written Chinese, often in informal contexts","connotation":"neutral","commonMistakes":"Learners might mistakenly use this idiom to imply teamwork, but it actually emphasizes individual effort and unique methods. It's often confused with idioms that stress collaboration.","canStandAlone":false},"examples":[{"simplified":"在这个项目中，我们就像八仙过海，各显神通。","english":"In this project, we are like the Eight Immortals crossing the sea, each showing their special skills.","traditional":"在這個項目中，我們就像八仙過海，各顯神通。"},{"simplified":"面对挑战，我们需要八仙过海，各自发挥自己的优势。","english":"Facing the challenge, we need to be like the Eight Immortals crossing the sea, each leveraging our own strengths.","traditional":"面對挑戰，我們需要八仙過海，各自發揮自己的優勢。"}],"synonyms":[],"antonyms":[],"confusedWith":[{"id":"齐心协力","note":"While 八仙过海 emphasizes individual efforts, 齐心协力 focuses on teamwork and cooperation."}],"traditional":"八仙過海","pinyinOverride":null},{"id":"ba-gao-cai-di","simplified":"扒高踩低","literalMeaning":"cling to the high, trample the low","figurativeMeaning":"to flatter the powerful and bully the weak; to be a sycophant","englishEquivalents":["kiss up, kick down","suck up to superiors","brown-nosing"],"shortGloss":"flatter the powerful, bully the weak","characters":[{"char":"扒","meaning":"cling to, curry favor with"},{"char":"高","meaning":"high, superior"},{"char":"踩","meaning":"trample, oppress"},{"char":"低","meaning":"low, inferior"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom describes a behavior where someone seeks to gain favor with those in power while mistreating those who are less powerful or influential. It is often used to criticize someone who is opportunistic and lacks integrity.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"coordinate","register":"commonly used in both spoken and written Chinese to criticize unethical behavior","connotation":"negative","commonMistakes":"Learners might confuse this idiom with others that involve social climbing or flattery, but this idiom specifically emphasizes the dual action of flattering superiors while oppressing subordinates.","canStandAlone":false},"examples":[{"simplified":"他总是扒高踩低，难怪没有人喜欢他。","english":"He always flatters the powerful and bullies the weak, no wonder no one likes him.","traditional":"他總是扒高踩低，難怪沒有人喜歡他。"},{"simplified":"在职场上，扒高踩低的人往往得不到真正的尊重。","english":"In the workplace, those who flatter the powerful and bully the weak often do not earn genuine respect.","traditional":"在職場上，扒高踩低的人往往得不到真正的尊重。"}],"synonyms":["趋炎附势","阿谀奉承"],"antonyms":["平等待人"],"confusedWith":[{"id":"趋炎附势","note":"Both involve currying favor, but 扒高踩低 specifically includes oppressing those below."}],"traditional":"扒高踩低","pinyinOverride":null},{"id":"ba-shan-she-shui","simplified":"跋山涉水","literalMeaning":"climb mountains and wade through water","figurativeMeaning":"to overcome numerous obstacles; to make a long and arduous journey","englishEquivalents":["go through fire and water","overcome all obstacles"],"shortGloss":"overcome numerous obstacles","characters":[{"char":"跋","meaning":"to climb"},{"char":"山","meaning":"mountains"},{"char":"涉","meaning":"to wade"},{"char":"水","meaning":"water"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '跋山涉水' is used to describe the effort and determination required to overcome difficult and challenging journeys, both literally and metaphorically. It evokes the image of someone traveling through rough terrain, climbing over mountains and wading through rivers, to reach their destination. This phrase highlights perseverance and endurance in the face of adversity.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"coordinate","register":"commonly used in both written and spoken Chinese to describe overcoming difficulties","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with those that specifically refer to physical travel, but it is often used metaphorically to describe any challenging journey or process.","canStandAlone":false},"examples":[{"simplified":"为了实现梦想，他跋山涉水，毫不退缩。","english":"To achieve his dreams, he overcame numerous obstacles without hesitation.","traditional":"為了實現夢想，他跋山涉水，毫不退縮。"},{"simplified":"他们跋山涉水，终于找到了失落的村庄。","english":"They traveled through difficult terrain and finally found the lost village.","traditional":"他們跋山涉水，終於找到了失落的村莊。"}],"synonyms":["千辛万苦","历尽艰辛"],"antonyms":[],"confusedWith":[],"traditional":"跋山涉水","pinyinOverride":null},{"id":"ba-dao-heng-xing","simplified":"霸道横行","literalMeaning":"tyranny rampant","figurativeMeaning":"acting in an overbearing and tyrannical manner; bullying others with power","englishEquivalents":["rule with an iron fist","throw one's weight around"],"shortGloss":"tyrannical behavior","characters":[{"char":"霸","meaning":"tyranny; domination"},{"char":"道","meaning":"way; path; doctrine"},{"char":"横","meaning":"rampant; unrestrained"},{"char":"行","meaning":"to go; to act"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '霸道横行' describes a situation where someone uses their power or influence to act in an overbearing or tyrannical manner, often disregarding rules or fairness. It is commonly used to criticize those who abuse their authority to impose their will on others.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"modifier-head","register":"commonly used in both written and spoken Chinese to criticize or describe oppressive behavior","connotation":"negative","commonMistakes":"Learners may confuse this idiom with ones that describe legitimate authority or leadership. '霸道横行' specifically implies abuse of power and tyranny, not just strong leadership.","canStandAlone":false},"examples":[{"simplified":"他在公司里总是霸道横行，没有人敢反对他。","english":"He always throws his weight around in the company, and no one dares to oppose him.","traditional":"他在公司裡總是霸道橫行，沒有人敢反對他。"},{"simplified":"这种霸道横行的行为让人非常反感。","english":"Such tyrannical behavior is very off-putting.","traditional":"這種霸道橫行的行為讓人非常反感。"}],"synonyms":["横行霸道"],"antonyms":[],"confusedWith":[{"id":"强权政治","note":"While '强权政治' refers to politics dominated by power, it does not necessarily imply the same level of personal tyranny and overbearing behavior as '霸道横行'."}],"traditional":"霸道橫行","pinyinOverride":null},{"id":"bai-fa-cang-cang","simplified":"白发苍苍","literalMeaning":"white hair grayish","figurativeMeaning":"having gray or white hair, typically used to describe an elderly person","englishEquivalents":["gray-haired","hoary-headed"],"shortGloss":"gray-haired, elderly","characters":[{"char":"白","meaning":"white"},{"char":"发","meaning":"hair"},{"char":"苍","meaning":"gray"},{"char":"苍","meaning":"grayish"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '白发苍苍' is used to describe someone who is elderly, characterized by their gray or white hair. It is often used to convey respect or to highlight the wisdom and experience that comes with age.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["attributive","predicate"],"structure":"modifier-head","register":"commonly used in both written and spoken Chinese to describe elderly people","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with other expressions related to age, but '白发苍苍' specifically emphasizes the visual aspect of gray or white hair.","canStandAlone":false},"examples":[{"simplified":"他已经白发苍苍，但仍然充满活力。","english":"He is already gray-haired, but still full of energy.","traditional":"他已經白髮蒼蒼，但仍然充滿活力。"},{"simplified":"白发苍苍的老人坐在公园的长椅上。","english":"The gray-haired old man sat on the park bench.","traditional":"白髮蒼蒼的老人坐在公園的長椅上。"}],"synonyms":["鹤发童颜"],"antonyms":[],"confusedWith":[{"id":"老态龙钟","note":"While both describe old age, '老态龙钟' emphasizes frailty and decrepitude, whereas '白发苍苍' focuses on the appearance of gray hair."}],"traditional":"白髮蒼蒼","pinyinOverride":null},{"id":"bai-fa-hong-yan","simplified":"白发红颜","literalMeaning":"white hair, red face","figurativeMeaning":"a young person with white hair, often due to stress or hardship","englishEquivalents":["prematurely aged","youth with an old appearance"],"shortGloss":"young person with white hair","characters":[{"char":"白","meaning":"white"},{"char":"发","meaning":"hair"},{"char":"红","meaning":"red"},{"char":"颜","meaning":"face, complexion"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '白发红颜' describes the phenomenon where a young person, often due to significant stress or hardship, develops white hair while still having a youthful face. This contrast highlights the impact of life's challenges on one's physical appearance.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["attributive","predicate"],"structure":"coordinate","register":"literary, but can be used in expressive speech","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with expressions that describe aging in general, but it specifically refers to the contrast between youthful features and prematurely white hair.","canStandAlone":false},"examples":[{"simplified":"经历了那么多磨难，她成了白发红颜。","english":"After going through so many hardships, she became a young person with white hair.","traditional":"經歷了那麼多磨難，她成了白髮紅顏。"},{"simplified":"他虽然年纪轻轻，却已是白发红颜。","english":"Though still young, he already has the appearance of a youth with white hair.","traditional":"他雖然年紀輕輕，卻已是白髮紅顏。"}],"synonyms":[],"antonyms":[],"confusedWith":[],"traditional":"白髮紅顏","pinyinOverride":null},{"id":"bai-gu-lu-ye","simplified":"白骨露野","literalMeaning":"white bones exposed in the wild","figurativeMeaning":"a scene of devastation and death, often used to describe the aftermath of war","englishEquivalents":["a field of bones","a scene of carnage"],"shortGloss":"a scene of devastation","characters":[{"char":"白","meaning":"white"},{"char":"骨","meaning":"bones"},{"char":"露","meaning":"exposed"},{"char":"野","meaning":"wild; open field"}],"origin":{"period":"Three Kingdoms period (220–280 CE)","sourceText":"《三国志·魏书·武帝纪》","sourceTextEnglish":"Records of the Three Kingdoms, Book of Wei, Annals of Emperor Wu","originalExcerpt":"白骨露于野，千里无鸡鸣。","storyEnglish":"The idiom comes from a description in the 'Records of the Three Kingdoms' depicting the aftermath of war. The passage describes a desolate scene where white bones are exposed in the fields, and there is no sound of roosters crowing for miles, illustrating the widespread devastation and death caused by the conflict.","historicalFigures":["Cao Cao"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["subject","predicate"],"structure":"subject-predicate","register":"literary, but understood in contexts discussing war or devastation","connotation":"negative","commonMistakes":"Learners may confuse this idiom with those describing peaceful rural scenes due to the character '野' (wild), but it specifically conveys devastation and death.","canStandAlone":false},"examples":[{"simplified":"战争过后，白骨露野，令人心痛。","english":"After the war, the white bones were exposed in the wild, causing heartbreak.","traditional":"戰爭過後，白骨露野，令人心痛。"},{"simplified":"历史书中常常描述白骨露野的惨状。","english":"History books often describe the tragic scenes of white bones exposed in the wild.","traditional":"歷史書中常常描述白骨露野的慘狀。"}],"synonyms":["哀鸿遍野"],"antonyms":[],"confusedWith":[{"id":"田园诗","note":"田园诗 refers to idyllic rural poetry, which is peaceful and serene, unlike the devastation implied by 白骨露野."}],"traditional":"白骨露野","pinyinOverride":null},{"id":"bai-hei-bu-fen","simplified":"白黑不分","literalMeaning":"white and black not distinguished","figurativeMeaning":"unable to distinguish right from wrong","englishEquivalents":["can't tell right from wrong","morally confused"],"shortGloss":"unable to distinguish right from wrong","characters":[{"char":"白","meaning":"white"},{"char":"黑","meaning":"black"},{"char":"不","meaning":"not"},{"char":"分","meaning":"distinguish"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '白黑不分' is used to describe a situation where someone cannot distinguish between right and wrong, much like being unable to tell the difference between black and white. It emphasizes moral confusion or a lack of discernment.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"modifier-head","register":"commonly used in both written and spoken Chinese to describe moral confusion","connotation":"negative","commonMistakes":"Learners might confuse '白黑不分' with '是非不分', which also means unable to distinguish right from wrong but is more focused on truth versus falsehood rather than moral clarity.","canStandAlone":false},"examples":[{"simplified":"他总是白黑不分，难怪会做出这样的决定。","english":"He always can't tell right from wrong, no wonder he made such a decision.","traditional":"他總是白黑不分，難怪會做出這樣的決定。"},{"simplified":"在复杂的情况下，她白黑不分，令人担忧。","english":"In complex situations, she can't distinguish right from wrong, which is worrying.","traditional":"在複雜的情況下，她白黑不分，令人擔憂。"}],"synonyms":["是非不分"],"antonyms":["明辨是非"],"confusedWith":[{"id":"是非不分","note":"Both idioms mean unable to distinguish right from wrong, but '是非不分' emphasizes truth versus falsehood."}],"traditional":"白黑不分","pinyinOverride":null},{"id":"bai-hei-dian-dao","simplified":"白黑颠倒","literalMeaning":"white and black reversed","figurativeMeaning":"to confuse right and wrong; to invert the truth","englishEquivalents":["turning the truth on its head","upside down logic"],"shortGloss":"confuse right and wrong","characters":[{"char":"白","meaning":"white"},{"char":"黑","meaning":"black"},{"char":"颠","meaning":"reverse"},{"char":"倒","meaning":"invert"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '白黑颠倒' is used to describe situations where truth and falsehood are mixed up, and right and wrong are confused. It is often used to criticize someone who deliberately distorts facts or misrepresents the truth.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"commonly used in both written and spoken Chinese","connotation":"negative","commonMistakes":"Learners might confuse this idiom with similar expressions that involve 'black' and 'white', but this idiom specifically emphasizes the inversion of truth and falsehood, not just any contrast between two things.","canStandAlone":false},"examples":[{"simplified":"他总是把事实白黑颠倒，让人无从分辨。","english":"He always turns the facts on their head, making it impossible for people to discern the truth.","traditional":"他總是把事實白黑顛倒，讓人無從分辨。"},{"simplified":"在这场辩论中，他的论点完全是白黑颠倒。","english":"In this debate, his arguments were completely upside down logic.","traditional":"在這場辯論中，他的論點完全是白黑顛倒。"}],"synonyms":["颠倒是非"],"antonyms":["是非分明"],"confusedWith":[{"id":"黑白分明","note":"While '黑白分明' means clear distinction between right and wrong, '白黑颠倒' refers to confusing or reversing them."}],"traditional":"白黑顛倒","pinyinOverride":null},{"id":"bai-shou-qiong-jing","simplified":"白首穷经","literalMeaning":"white head exhaust classics","figurativeMeaning":"to study diligently until old age","englishEquivalents":["Never too old to learn","Lifelong learning"],"shortGloss":"study diligently into old age","characters":[{"char":"白","meaning":"white, referring to white hair or old age"},{"char":"首","meaning":"head, indicating a person"},{"char":"穷","meaning":"exhaust, thoroughly study"},{"char":"经","meaning":"classics, referring to classical texts"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '白首穷经' describes the dedication to studying and learning throughout one's life, even into old age. It emphasizes the value of lifelong learning and the pursuit of knowledge, regardless of age. The phrase suggests that one should never stop seeking wisdom and understanding, as there is always more to learn.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"literary, but understood in educated speech","connotation":"positive","commonMistakes":"Learners might confuse this idiom with others that involve studying, but this one specifically emphasizes the aspect of continuing to study into old age. It should not be used to describe short-term or youthful study habits.","canStandAlone":false},"examples":[{"simplified":"他一直白首穷经，直到生命的最后一刻。","english":"He studied diligently until the very last moment of his life.","traditional":"他一直白首窮經，直到生命的最後一刻。"},{"simplified":"白首穷经是他一生的座右铭。","english":"Lifelong learning was his motto.","traditional":"白首窮經是他一生的座右銘。"}],"synonyms":["活到老学到老"],"antonyms":[],"confusedWith":[{"id":"学而不厌","note":"While both idioms involve studying, 学而不厌 focuses on being eager to learn without getting tired, not necessarily into old age."}],"traditional":"白首窮經","pinyinOverride":null},{"id":"bai-tou-dao-lao","simplified":"白头到老","literalMeaning":"white head until old","figurativeMeaning":"to live together until old age; to remain a devoted couple for life","englishEquivalents":["grow old together","till death do us part"],"shortGloss":"grow old together","characters":[{"char":"白","meaning":"white"},{"char":"头","meaning":"head"},{"char":"到","meaning":"until"},{"char":"老","meaning":"old"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '白头到老' is commonly used to describe a couple who remain together throughout their lives, growing old together. The imagery of 'white head' refers to the hair turning white with age, symbolizing a long life spent together in harmony and love.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","complement"],"structure":"verb-object","register":"common in both spoken and written Chinese, often used in wedding contexts or to describe enduring relationships","connotation":"positive","commonMistakes":"Learners sometimes confuse this idiom with expressions that imply merely aging, without the connotation of a lifelong partnership. It's important to use it specifically for relationships.","canStandAlone":false},"examples":[{"simplified":"他们希望能白头到老，一起度过余生。","english":"They hope to grow old together and spend the rest of their lives with each other.","traditional":"他們希望能白頭到老，一起度過餘生。"},{"simplified":"祝你们新婚快乐，白头到老。","english":"Wishing you a happy marriage and that you grow old together.","traditional":"祝你們新婚快樂，白頭到老。"}],"synonyms":["携手到老"],"antonyms":["分道扬镳"],"confusedWith":[{"id":"白发苍苍","note":"白发苍苍 refers to having white hair, emphasizing old age itself, not the aspect of a lifelong partnership."}],"traditional":"白頭到老","pinyinOverride":null},{"id":"bai-xue-yang-chun","simplified":"白雪阳春","literalMeaning":"white snow, sunny spring","figurativeMeaning":"elegant and refined artistic works, often in music or literature","englishEquivalents":["highbrow","cultured","refined"],"shortGloss":"elegant and refined works","characters":[{"char":"白","meaning":"white"},{"char":"雪","meaning":"snow"},{"char":"阳","meaning":"sunny"},{"char":"春","meaning":"spring"}],"origin":{"period":"Han Dynasty (206 BCE – 220 CE)","sourceText":"《宋书·乐志》","sourceTextEnglish":"Book of Song, Music Treatise","originalExcerpt":"昔楚襄王使宋玉对曰：‘客有歌于郢中者，其始曰《下里巴人》，国中属而和者数千人；其为《阳春白雪》，国中属而和者不过数十人。’","storyEnglish":"The idiom originates from a story in the Book of Song, where Song Yu, a famous poet, explained to King Xiang of Chu that when common songs like 'Xiali Bapin' were sung, thousands would join in, but when refined songs like 'Yangchun Baixue' were sung, only a few could follow. This illustrates the idea that elegant and sophisticated works are appreciated by only a select few.","historicalFigures":["Song Yu","King Xiang of Chu"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["attributive"],"structure":"coordinate","register":"literary, but known and used in educated speech","connotation":"positive","commonMistakes":"Learners might use this idiom to describe any kind of art, but it specifically refers to works that are elegant and refined, not just any artistic work.","canStandAlone":false},"examples":[{"simplified":"他的作品被认为是白雪阳春，只有少数人能欣赏。","english":"His works are considered elegant and refined, appreciated only by a few.","traditional":"他的作品被認為是白雪陽春，只有少數人能欣賞。"},{"simplified":"这部电影被批评为白雪阳春，观众难以理解。","english":"The film was criticized as being too highbrow, difficult for audiences to understand.","traditional":"這部電影被批評為白雪陽春，觀眾難以理解。"}],"synonyms":["阳春白雪"],"antonyms":["下里巴人"],"confusedWith":[{"id":"阳春白雪","note":"Both refer to refined works, but '阳春白雪' is more commonly used."}],"traditional":"白雪陽春","pinyinOverride":null},{"id":"bai-yu-wei-xia","simplified":"白玉微瑕","literalMeaning":"white jade with slight flaw","figurativeMeaning":"something or someone that is excellent but has minor imperfections","englishEquivalents":["a diamond with a flaw","nobody's perfect"],"shortGloss":"excellent but with minor flaws","characters":[{"char":"白","meaning":"white"},{"char":"玉","meaning":"jade"},{"char":"微","meaning":"slight"},{"char":"瑕","meaning":"flaw"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '白玉微瑕' is often used to describe a person or thing that is nearly perfect but has a small flaw. In ancient China, white jade was highly valued for its purity and beauty, and even a slight flaw in such a precious stone was noticeable. This idiom reflects the idea that even the most excellent things can have minor imperfections.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["attributive","predicate"],"structure":"modifier-head","register":"literary, but can be used in formal speech and writing","connotation":"neutral","commonMistakes":"Learners might use this idiom to describe something with major flaws, but it specifically refers to minor imperfections in something otherwise excellent.","canStandAlone":false},"examples":[{"simplified":"他的作品虽然白玉微瑕，但仍然很受欢迎。","english":"Although his work has minor flaws, it is still very popular.","traditional":"他的作品雖然白玉微瑕，但仍然很受歡迎。"},{"simplified":"这幅画白玉微瑕，但整体效果非常好。","english":"This painting has slight imperfections, but the overall effect is excellent.","traditional":"這幅畫白玉微瑕，但整體效果非常好。"}],"synonyms":[],"antonyms":[],"confusedWith":[],"traditional":"白玉微瑕","pinyinOverride":null},{"id":"bai-yu-wu-xia","simplified":"白玉无瑕","literalMeaning":"white jade without flaws","figurativeMeaning":"to be perfect and without blemish","englishEquivalents":["pure as the driven snow","spotless","flawless"],"shortGloss":"perfect and without blemish","characters":[{"char":"白","meaning":"white"},{"char":"玉","meaning":"jade"},{"char":"无","meaning":"without"},{"char":"瑕","meaning":"flaw"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '白玉无瑕' is often used to describe someone or something that is perfect and without any flaws, much like a piece of pure white jade. In Chinese culture, jade is highly valued and symbolizes purity and moral integrity. The phrase suggests an ideal state of being, free from any imperfections.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"modifier-head","register":"literary, but widely understood and used in both formal and informal contexts","connotation":"positive","commonMistakes":"Learners might confuse this idiom with other expressions involving '白玉' (white jade) that do not imply perfection. It's important to note that '无瑕' specifically denotes the absence of flaws.","canStandAlone":false},"examples":[{"simplified":"她的品德如白玉无瑕，让人敬佩。","english":"Her character is as flawless as white jade, earning everyone's admiration.","traditional":"她的品德如白玉無瑕，讓人敬佩。"},{"simplified":"这幅画作工精细，简直是白玉无瑕。","english":"The craftsmanship of this painting is so exquisite, it's simply flawless.","traditional":"這幅畫作工精細，簡直是白玉無瑕。"}],"synonyms":["完美无缺","无懈可击"],"antonyms":["瑕疵百出"],"confusedWith":[{"id":"白璧微瑕","note":"While '白玉无瑕' means completely flawless, '白璧微瑕' acknowledges a small flaw in something otherwise perfect."}],"traditional":"白玉無瑕","pinyinOverride":null},{"id":"bai-bu-shi-yi","simplified":"百不失一","literalMeaning":"a hundred does not miss one","figurativeMeaning":"extremely accurate or reliable, with no mistakes","englishEquivalents":["spot on","right on the money","perfectly accurate"],"shortGloss":"extremely accurate","characters":[{"char":"百","meaning":"hundred"},{"char":"不","meaning":"not"},{"char":"失","meaning":"miss"},{"char":"一","meaning":"one"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom suggests a level of precision or accuracy where out of a hundred attempts, not a single one would fail. It is often used to describe someone or something that is extremely reliable or accurate.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"modifier-head","register":"commonly used in both written and spoken Chinese","connotation":"positive","commonMistakes":"Learners might confuse this idiom with similar expressions that imply infallibility, but this idiom specifically emphasizes accuracy and reliability rather than perfection.","canStandAlone":false},"examples":[{"simplified":"他的预测总是百不失一。","english":"His predictions are always spot on.","traditional":"他的預測總是百不失一。"},{"simplified":"这个系统的检测结果百不失一，非常可靠。","english":"The system's test results are extremely accurate and reliable.","traditional":"這個系統的檢測結果百不失一，非常可靠。"}],"synonyms":["万无一失"],"antonyms":[],"confusedWith":[{"id":"万无一失","note":"While both idioms imply reliability, 万无一失 emphasizes infallibility, suggesting no chance of error at all."}],"traditional":"百不失一","pinyinOverride":null},{"id":"bai-chi-gan-tou","simplified":"百尺竿头","literalMeaning":"hundred-foot pole top","figurativeMeaning":"to have achieved a high level of success but still strive for improvement","englishEquivalents":["resting on one's laurels","reaching new heights"],"shortGloss":"striving for further improvement","characters":[{"char":"百","meaning":"hundred"},{"char":"尺","meaning":"foot (unit of length)"},{"char":"竿","meaning":"pole"},{"char":"头","meaning":"top"}],"origin":{"period":"Song Dynasty (960–1279)","sourceText":"《景德传灯录》","sourceTextEnglish":"Jingde Record of the Transmission of the Lamp","originalExcerpt":"百尺竿头，更进一步。","storyEnglish":"The idiom comes from a Zen Buddhist saying, which suggests that even when one has reached the top of a hundred-foot pole, there is still room to go further. It emphasizes the importance of continuous self-improvement and not becoming complacent with one's current achievements.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["subject","predicate","object","attributive"],"structure":"modifier-head","register":"literary, but understood and used in formal speech and writing","connotation":"positive","commonMistakes":"Learners often misunderstand this idiom as implying completion or finality, when it actually encourages further effort beyond current achievements. It should not be used to describe a finished state.","canStandAlone":false},"examples":[{"simplified":"他在事业上已经百尺竿头，但仍然不断学习。","english":"He has already reached great heights in his career, but he continues to learn.","traditional":"他在事業上已經百尺竿頭，但仍然不斷學習。"},{"simplified":"即使你已经百尺竿头，也不要停止进步。","english":"Even if you have reached the top, don't stop improving.","traditional":"即使你已經百尺竿頭，也不要停止進步。"}],"synonyms":["更进一步"],"antonyms":[],"confusedWith":[{"id":"功成名就","note":"功成名就 implies achieving success and fame, often with a sense of completion, while 百尺竿头 suggests further striving beyond success."}],"traditional":"百尺竿頭","pinyinOverride":null},{"id":"bai-er-he-shan","simplified":"百二河山","literalMeaning":"hundred and two rivers and mountains","figurativeMeaning":"a heavily fortified and strategically important area","englishEquivalents":["a stronghold","a strategic location"],"shortGloss":"a strategic stronghold","characters":[{"char":"百","meaning":"hundred"},{"char":"二","meaning":"two"},{"char":"河","meaning":"river"},{"char":"山","meaning":"mountain"}],"origin":{"period":"Han Dynasty (202 BCE – 220 CE)","sourceText":"《史记·项羽本纪》","sourceTextEnglish":"Records of the Grand Historian, Xiang Yu's Biography","originalExcerpt":"秦之地，带甲百万，地势险要，号称百二河山。","storyEnglish":"The idiom originates from the 'Records of the Grand Historian' by Sima Qian, where it describes the Qin state's territory as having a million armored soldiers and a strategic geographical advantage, referred to as '百二河山'. This expression highlights the formidable natural defenses and military strength of the region.","historicalFigures":["Xiang Yu"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["attributive","adverbial"],"structure":"modifier-head","register":"literary, but can be used in formal speech to emphasize strategic importance","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with general descriptions of natural beauty, but it specifically refers to strategic military importance, not just any picturesque landscape.","canStandAlone":false},"examples":[{"simplified":"这个地方是百二河山，必须严加防守。","english":"This place is a strategic stronghold and must be heavily guarded.","traditional":"這個地方是百二河山，必須嚴加防守。"},{"simplified":"他把公司总部设在百二河山之地，以确保安全。","english":"He set up the company headquarters in a strategically important area to ensure security.","traditional":"他把公司總部設在百二河山之地，以確保安全。"}],"synonyms":[],"antonyms":[],"confusedWith":[{"id":"山清水秀","note":"山清水秀 describes natural beauty, not strategic importance."}],"traditional":"百二河山","pinyinOverride":null},{"id":"bai-er-shan-he","simplified":"百二山河","literalMeaning":"hundred two mountains rivers","figurativeMeaning":"a heavily fortified and strategically important area","englishEquivalents":["a fortress","an impregnable stronghold"],"shortGloss":"a strategic stronghold","characters":[{"char":"百","meaning":"hundred"},{"char":"二","meaning":"two"},{"char":"山","meaning":"mountains"},{"char":"河","meaning":"rivers"}],"origin":{"period":"Han Dynasty (206 BCE – 220 CE)","sourceText":"《史记·项羽本纪》","sourceTextEnglish":"Records of the Grand Historian, Biography of Xiang Yu","originalExcerpt":"秦之地，带甲百万，地势险要，号称百二山河。","storyEnglish":"The idiom originates from the description of the Qin state during the Warring States period. It was said that the Qin territory was heavily fortified, with a million armored soldiers and strategically advantageous terrain, earning it the nickname '百二山河', meaning it was as secure as if it were defended by 120% of its natural defenses.","historicalFigures":["Xiang Yu"],"relatedIdiomsFromSameSource":["破釜沉舟"]},"usage":{"grammaticalRole":["attributive","object"],"structure":"modifier-head","register":"literary, but understood in educated speech","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with ones that describe natural beauty rather than strategic importance. It's important to note that this idiom emphasizes military strength and strategic advantage.","canStandAlone":false},"examples":[{"simplified":"这座城市地势险要，堪称百二山河。","english":"This city's terrain is strategically advantageous, truly a fortress.","traditional":"這座城市地勢險要，堪稱百二山河。"},{"simplified":"敌军无法攻破这片百二山河。","english":"The enemy army could not breach this impregnable stronghold.","traditional":"敵軍無法攻破這片百二山河。"}],"synonyms":["固若金汤"],"antonyms":["不堪一击"],"confusedWith":[{"id":"山清水秀","note":"山清水秀 describes natural beauty, not strategic importance."}],"traditional":"百二山河","pinyinOverride":null},{"id":"bai-yi-bai-shun","simplified":"百依百顺","literalMeaning":"hundred compliance hundred obedience","figurativeMeaning":"to be completely obedient and compliant","englishEquivalents":["to be at someone's beck and call","to be utterly compliant","to follow someone's every wish"],"shortGloss":"utterly compliant and obedient","characters":[{"char":"百","meaning":"hundred, completely"},{"char":"依","meaning":"comply, follow"},{"char":"百","meaning":"hundred, completely"},{"char":"顺","meaning":"obey, submit"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '百依百顺' describes someone who is entirely obedient and compliant, often used to describe a person who follows another's wishes without question. It emphasizes a high degree of submission and willingness to accommodate another's desires.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"coordinate","register":"commonly used in both spoken and written Chinese to describe someone who is very compliant","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with '唯命是从', which also means to follow orders, but '百依百顺' implies a more personal and voluntary compliance, often in a familial or affectionate context.","canStandAlone":false},"examples":[{"simplified":"他对父母总是百依百顺，从不顶嘴。","english":"He is always obedient to his parents and never talks back.","traditional":"他對父母總是百依百順，從不頂嘴。"},{"simplified":"她对孩子百依百顺，什么要求都答应。","english":"She is completely compliant with her child's wishes, agreeing to every request.","traditional":"她對孩子百依百順，什麼要求都答應。"}],"synonyms":["唯命是从","言听计从"],"antonyms":["桀骜不驯"],"confusedWith":[{"id":"唯命是从","note":"While both idioms imply obedience, '唯命是从' suggests following orders, often in a formal or authoritative context, whereas '百依百顺' implies a more personal and voluntary compliance."}],"traditional":"百依百順","pinyinOverride":null},{"id":"bai-yi-bai-sui","simplified":"百依百随","literalMeaning":"hundred comply hundred follow","figurativeMeaning":"to comply with every request; to be very accommodating","englishEquivalents":["to cater to someone's every whim","to be at someone's beck and call"],"shortGloss":"comply with every request","characters":[{"char":"百","meaning":"hundred; completely"},{"char":"依","meaning":"comply; agree"},{"char":"百","meaning":"hundred; completely"},{"char":"随","meaning":"follow; accommodate"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '百依百随' is believed to have originated from the idea of someone being so accommodating that they comply with and follow every request or desire of another person. It reflects a situation where one person is willing to go to great lengths to satisfy another, often used to describe a very indulgent or doting attitude.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"coordinate","register":"commonly used in both formal and informal contexts","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with '百发百中', which means to hit the target every time, due to the repeated use of '百'. However, '百依百随' emphasizes compliance and accommodation, not accuracy or precision.","canStandAlone":false},"examples":[{"simplified":"他对女朋友百依百随，什么要求都答应。","english":"He caters to his girlfriend's every whim, agreeing to whatever she asks.","traditional":"他對女朋友百依百隨，什麼要求都答應。"},{"simplified":"父母不应该对孩子百依百随，这样会宠坏他们。","english":"Parents shouldn't cater to their children's every whim, as it might spoil them.","traditional":"父母不應該對孩子百依百隨，這樣會寵壞他們。"}],"synonyms":["唯命是从"],"antonyms":["我行我素"],"confusedWith":[{"id":"百发百中","note":"百发百中 means to hit the target every time, focusing on accuracy, not compliance."}],"traditional":"百依百隨","pinyinOverride":null},{"id":"bai-zhang-gan-tou","simplified":"百丈竿头","literalMeaning":"hundred-zhang pole top","figurativeMeaning":"to reach a very high level of achievement, but still needing to strive for further progress","englishEquivalents":["reaching the pinnacle","at the peak, but still climbing"],"shortGloss":"reaching a high level, but still progressing","characters":[{"char":"百","meaning":"hundred"},{"char":"丈","meaning":"zhang (a unit of length, approximately 3.3 meters)"},{"char":"竿","meaning":"pole"},{"char":"头","meaning":"top"}],"origin":{"period":"Song Dynasty (960–1279)","sourceText":"《景德传灯录》","sourceTextEnglish":"Jingde Record of the Transmission of the Lamp","originalExcerpt":"百丈竿头，更进一步。","storyEnglish":"The idiom comes from a Zen Buddhist text, where it describes the idea that even if one has reached the top of a hundred-zhang pole, there is still room to make further progress. It emphasizes the importance of continuous improvement and not becoming complacent even after achieving great success.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["subject","predicate","object","complement"],"structure":"modifier-head","register":"literary, but widely understood and used in both formal and informal contexts","connotation":"positive","commonMistakes":"Learners may mistakenly use it to imply completion or finality, when it actually suggests ongoing effort and progress. It is often confused with idioms that imply reaching a final goal.","canStandAlone":false},"examples":[{"simplified":"他在事业上已经是百丈竿头，但他仍然每天努力工作。","english":"He has reached a very high level in his career, but he still works hard every day.","traditional":"他在事業上已經是百丈竿頭，但他仍然每天努力工作。"},{"simplified":"虽然你已经取得了很大的成就，但要记住百丈竿头，更进一步。","english":"Even though you have achieved great success, remember that there's always room for further progress.","traditional":"雖然你已經取得了很大的成就，但要記住百丈竿頭，更進一步。"}],"synonyms":["更进一步"],"antonyms":[],"confusedWith":[{"id":"功成名就","note":"功成名就 implies achieving success and fame, often with a sense of completion, unlike 百丈竿头 which suggests ongoing progress."}],"traditional":"百丈竿頭","pinyinOverride":null},{"id":"bai-wei-yao-tou","simplified":"摆尾摇头","literalMeaning":"wag tail, shake head","figurativeMeaning":"to act obsequiously or fawn over someone","englishEquivalents":["to curry favor","to fawn over","to butter someone up"],"shortGloss":"to act obsequiously","characters":[{"char":"摆","meaning":"wag"},{"char":"尾","meaning":"tail"},{"char":"摇","meaning":"shake"},{"char":"头","meaning":"head"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '摆尾摇头' describes the behavior of animals, such as dogs, who wag their tails and shake their heads to show friendliness or submission. This imagery is used metaphorically to describe people who act in a servile or overly flattering manner to gain favor or approval from others.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"coordinate","register":"informal, commonly used in spoken Chinese","connotation":"negative","commonMistakes":"Learners might confuse this idiom with similar expressions that involve physical movement but do not carry the same connotation of obsequiousness. It's important to understand the negative, servile implication of this idiom.","canStandAlone":false},"examples":[{"simplified":"他总是对老板摆尾摇头，真让人看不惯。","english":"He is always fawning over the boss, which is really off-putting.","traditional":"他總是對老闆擺尾搖頭，真讓人看不慣。"},{"simplified":"为了升职，他开始对上司摆尾摇头。","english":"To get a promotion, he started currying favor with his superior.","traditional":"為了升職，他開始對上司擺尾搖頭。"}],"synonyms":["阿谀奉承","拍马屁"],"antonyms":["直言不讳"],"confusedWith":[{"id":"摇头摆尾","note":"While both involve similar actions, '摇头摆尾' is often used to describe a carefree or leisurely demeanor, lacking the negative connotation of obsequiousness."}],"traditional":"擺尾搖頭","pinyinOverride":null},{"id":"bai-fa-luan-ji","simplified":"败法乱纪","literalMeaning":"break laws disrupt discipline","figurativeMeaning":"to violate laws and disrupt order","englishEquivalents":["break the law","disrupt order"],"shortGloss":"violate laws and disrupt order","characters":[{"char":"败","meaning":"break, destroy"},{"char":"法","meaning":"law"},{"char":"乱","meaning":"disrupt, disorder"},{"char":"纪","meaning":"discipline, order"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '败法乱纪' is used to describe actions that violate established laws and disrupt societal order. It emphasizes the negative impact of such behavior on the rule of law and social stability.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"coordinate","register":"formal written Chinese, often used in legal or official contexts","connotation":"negative","commonMistakes":"Learners might confuse this idiom with similar expressions that refer to minor rule-breaking. '败法乱纪' specifically implies serious violations that affect societal order.","canStandAlone":false},"examples":[{"simplified":"他的行为已经构成了败法乱纪，需要受到法律的制裁。","english":"His actions have constituted a violation of laws and disruption of order, and he needs to be sanctioned by the law.","traditional":"他的行為已經構成了敗法亂紀，需要受到法律的制裁。"},{"simplified":"在一个法治社会，任何败法乱纪的行为都不能被容忍。","english":"In a society governed by the rule of law, any actions that violate laws and disrupt order cannot be tolerated.","traditional":"在一個法治社會，任何敗法亂紀的行為都不能被容忍。"}],"synonyms":[],"antonyms":[],"confusedWith":[],"traditional":"敗法亂紀","pinyinOverride":null},{"id":"bai-guo-sang-jia","simplified":"败国丧家","literalMeaning":"ruin the country, lose the home","figurativeMeaning":"to bring ruin to one's country and family; to cause great destruction or downfall","englishEquivalents":["bring ruin and destruction","lead to downfall"],"shortGloss":"cause ruin to country and family","characters":[{"char":"败","meaning":"ruin, destroy"},{"char":"国","meaning":"country"},{"char":"丧","meaning":"lose, destroy"},{"char":"家","meaning":"home, family"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '败国丧家' is used to describe a situation where someone's actions lead to the downfall or ruin of both their country and their family. It emphasizes the severe consequences of mismanagement or betrayal, often in a political or familial context.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"coordinate","register":"formal written Chinese, often used in historical or political contexts","connotation":"negative","commonMistakes":"Learners might confuse this idiom with others that involve personal failure, but '败国丧家' specifically refers to causing destruction on a national and familial level.","canStandAlone":false},"examples":[{"simplified":"他的腐败行为最终导致了败国丧家。","english":"His corrupt actions ultimately led to the ruin of the country and his family.","traditional":"他的腐敗行為最終導致了敗國喪家。"},{"simplified":"在历史上，许多君主因决策失误而败国丧家。","english":"In history, many monarchs have brought ruin to their countries and families due to poor decisions.","traditional":"在歷史上，許多君主因決策失誤而敗國喪家。"}],"synonyms":[],"antonyms":[],"confusedWith":[],"traditional":"敗國喪家","pinyinOverride":null},{"id":"bai-xing-er-gui","simplified":"败兴而归","literalMeaning":"return in defeat and disappointment","figurativeMeaning":"to return home disappointed after an unsuccessful endeavor","englishEquivalents":["come back empty-handed","return crestfallen"],"shortGloss":"return disappointed","characters":[{"char":"败","meaning":"defeated, disappointed"},{"char":"兴","meaning":"interest, excitement"},{"char":"而","meaning":"and, but"},{"char":"归","meaning":"return"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '败兴而归' describes the feeling of returning home after an unsuccessful attempt at something, with a sense of disappointment. It is often used to describe situations where someone had high hopes or expectations, only to have them dashed.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","complement"],"structure":"verb-object + verb-object","register":"commonly used in both written and spoken Chinese","connotation":"negative","commonMistakes":"Learners might confuse this idiom with others that involve returning, but '败兴而归' specifically emphasizes the disappointment and lack of success. It should not be used when the return is neutral or positive.","canStandAlone":false},"examples":[{"simplified":"他本来想钓很多鱼，但最后败兴而归。","english":"He had hoped to catch a lot of fish, but in the end, he returned disappointed.","traditional":"他本來想釣很多魚，但最後敗興而歸。"},{"simplified":"经过一整天的购物，她没有找到合适的衣服，只好败兴而归。","english":"After a whole day of shopping, she didn't find suitable clothes and had to return disappointed.","traditional":"經過一整天的購物，她沒有找到合適的衣服，只好敗興而歸。"}],"synonyms":[],"antonyms":[],"confusedWith":[{"id":"无功而返","note":"While both idioms involve returning without success, '无功而返' focuses more on the lack of achievement rather than the emotional disappointment."}],"traditional":"敗興而歸","pinyinOverride":null},{"id":"bai-gui-qiu-shen","simplified":"拜鬼求神","literalMeaning":"worship ghosts, pray to gods","figurativeMeaning":"to seek help from all possible sources, often in desperation","englishEquivalents":["leave no stone unturned","try everything","grasp at straws"],"shortGloss":"seek help from all sources","characters":[{"char":"拜","meaning":"worship"},{"char":"鬼","meaning":"ghosts"},{"char":"求","meaning":"pray"},{"char":"神","meaning":"gods"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '拜鬼求神' is used to describe a situation where someone is so desperate for help that they will turn to any source, whether it be ghosts or gods. It reflects a state of seeking assistance from all possible avenues, often when conventional methods have failed.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"coordinate","register":"informal, used in both spoken and written Chinese","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with those that imply superstition or religious devotion. However, it is more about the act of seeking help from any possible source rather than genuine belief.","canStandAlone":false},"examples":[{"simplified":"在公司快要倒闭的时候，他拜鬼求神，希望能找到投资者。","english":"When the company was about to go bankrupt, he sought help from all sources, hoping to find an investor.","traditional":"在公司快要倒閉的時候，他拜鬼求神，希望能找到投資者。"},{"simplified":"她为了治好病，拜鬼求神，尝试了各种偏方。","english":"In order to cure her illness, she tried everything, including alternative remedies.","traditional":"她為了治好病，拜鬼求神，嘗試了各種偏方。"}],"synonyms":["无所不为","不择手段"],"antonyms":[],"confusedWith":[{"id":"拜神求佛","note":"拜神求佛 implies seeking divine intervention specifically, whereas 拜鬼求神 emphasizes seeking help from any source, divine or otherwise."}],"traditional":"拜鬼求神","pinyinOverride":null},{"id":"ban-ban-ke-kao","simplified":"班班可考","literalMeaning":"clear and verifiable","figurativeMeaning":"something that is clearly documented and can be verified","englishEquivalents":["plain as day","crystal clear"],"shortGloss":"clearly documented and verifiable","characters":[{"char":"班","meaning":"clear, distinct"},{"char":"班","meaning":"clear, distinct"},{"char":"可","meaning":"can, able to"},{"char":"考","meaning":"examine, verify"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '班班可考' is used to describe information or facts that are clearly documented and can be easily verified. The repetition of '班' emphasizes the clarity and distinctness of the information. While its exact origin is unclear, it is commonly used in contexts where evidence or documentation is readily available and indisputable.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"modifier-head","register":"formal written Chinese, often used in academic or legal contexts","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with others that imply clarity but not necessarily verifiability. It's important to note that '班班可考' emphasizes the ability to verify the information.","canStandAlone":false},"examples":[{"simplified":"这段历史的细节班班可考。","english":"The details of this historical period are clearly documented and verifiable.","traditional":"這段歷史的細節班班可考。"},{"simplified":"他的研究结果班班可考，数据非常清晰。","english":"His research results are clearly documented and verifiable; the data is very clear.","traditional":"他的研究結果班班可考，數據非常清晰。"}],"synonyms":[],"antonyms":[],"confusedWith":[],"traditional":"班班可考","pinyinOverride":null},{"id":"ban-chou-mo-zhan","simplified":"半筹莫展","literalMeaning":"half a strategy cannot unfold","figurativeMeaning":"to be at one's wits' end; unable to come up with any solution","englishEquivalents":["at a loss","at one's wits' end"],"shortGloss":"at a loss; no solution in sight","characters":[{"char":"半","meaning":"half"},{"char":"筹","meaning":"strategy; plan"},{"char":"莫","meaning":"cannot"},{"char":"展","meaning":"unfold; develop"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '半筹莫展' describes a situation where someone is completely out of ideas or solutions. It conveys the sense of being stuck and unable to make any progress, as if even half a plan cannot be put into action.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","complement"],"structure":"subject-predicate","register":"commonly used in both spoken and written Chinese","connotation":"negative","commonMistakes":"Learners might confuse this idiom with others that imply difficulty but not complete inability, such as '束手无策'. '半筹莫展' specifically indicates a total lack of solutions.","canStandAlone":false},"examples":[{"simplified":"面对如此复杂的问题，他半筹莫展。","english":"Faced with such a complex problem, he was at a loss.","traditional":"面對如此複雜的問題，他半籌莫展。"},{"simplified":"她尝试了各种方法，但仍然半筹莫展。","english":"She tried various methods, but was still at her wits' end.","traditional":"她嘗試了各種方法，但仍然半籌莫展。"}],"synonyms":["束手无策"],"antonyms":[],"confusedWith":[{"id":"束手无策","note":"Both express inability to solve a problem, but '束手无策' emphasizes being unable to act, while '半筹莫展' highlights the lack of any plan."}],"traditional":"半籌莫展","pinyinOverride":null},{"id":"bao-jing-shuang-xue","simplified":"饱经霜雪","literalMeaning":"fully experienced frost and snow","figurativeMeaning":"to have experienced many hardships and difficulties","englishEquivalents":["weathered many storms","been through thick and thin"],"shortGloss":"experienced many hardships","characters":[{"char":"饱","meaning":"fully"},{"char":"经","meaning":"experienced"},{"char":"霜","meaning":"frost"},{"char":"雪","meaning":"snow"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '饱经霜雪' is used to describe someone who has gone through many hardships, much like a tree that has withstood harsh winters of frost and snow. It conveys the idea of resilience and endurance in the face of adversity.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"verb-object","register":"commonly used in both written and spoken Chinese to describe someone with a lot of life experience","connotation":"neutral","commonMistakes":"Learners might confuse it with idioms that only refer to physical endurance, whereas this idiom emphasizes emotional and experiential resilience.","canStandAlone":false},"examples":[{"simplified":"经过多年的磨练，他已经饱经霜雪，变得更加坚强。","english":"After many years of trials, he has weathered many storms and become stronger.","traditional":"經過多年的磨練，他已經飽經霜雪，變得更加堅強。"},{"simplified":"她是一位饱经霜雪的老人，有着丰富的人生经验。","english":"She is an elderly woman who has experienced many hardships and has a wealth of life experience.","traditional":"她是一位飽經霜雪的老人，有著豐富的人生經驗。"}],"synonyms":["历尽沧桑","饱经风霜"],"antonyms":[],"confusedWith":[{"id":"饱经风霜","note":"Both idioms refer to enduring hardships, but '饱经风霜' is more common and emphasizes enduring harsh conditions."}],"traditional":"飽經霜雪","pinyinOverride":null},{"id":"bao-jing-you-huan","simplified":"饱经忧患","literalMeaning":"fully experience worries and hardships","figurativeMeaning":"to have gone through many trials and tribulations","englishEquivalents":["weathered many storms","been through the mill"],"shortGloss":"experienced many hardships","characters":[{"char":"饱","meaning":"fully"},{"char":"经","meaning":"experience"},{"char":"忧","meaning":"worries"},{"char":"患","meaning":"hardships"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '饱经忧患' is used to describe someone who has endured a significant amount of hardship and adversity throughout their life. It conveys the idea of having been tested by life's difficulties and emerging with a wealth of experience.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"modifier-head","register":"commonly used in both written and spoken Chinese","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with similar ones that describe enduring hardships, but '饱经忧患' specifically emphasizes the extensive experience of adversity.","canStandAlone":false},"examples":[{"simplified":"经过多年的战争，他饱经忧患，变得更加坚强。","english":"After many years of war, he has weathered many storms and become stronger.","traditional":"經過多年的戰爭，他飽經憂患，變得更加堅強。"},{"simplified":"她是一个饱经忧患的人，总是能从困境中找到出路。","english":"She is someone who has been through the mill and always finds a way out of difficult situations.","traditional":"她是一個飽經憂患的人，總是能從困境中找到出路。"}],"synonyms":["历尽沧桑"],"antonyms":[],"confusedWith":[],"traditional":"飽經憂患","pinyinOverride":null},{"id":"bao-chou-xue-chi","simplified":"报仇雪耻","literalMeaning":"avenge revenge, wash away shame","figurativeMeaning":"to take revenge and wipe away humiliation","englishEquivalents":["avenge a wrong","settle a score"],"shortGloss":"avenge and erase shame","characters":[{"char":"报","meaning":"avenge"},{"char":"仇","meaning":"revenge"},{"char":"雪","meaning":"wash away"},{"char":"耻","meaning":"shame"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '报仇雪耻' is used to describe the act of taking revenge to remove a past humiliation or shame. It emphasizes the strong desire to restore one's honor by retaliating against those who have wronged you.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","object"],"structure":"verb-object + verb-object","register":"commonly used in both written and spoken Chinese, especially in contexts discussing justice or personal vendettas","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with others that involve revenge but lack the aspect of erasing shame. It specifically implies both avenging and restoring honor.","canStandAlone":false},"examples":[{"simplified":"他发誓要报仇雪耻，为家族争光。","english":"He vowed to take revenge and wipe away the shame, bringing honor to his family.","traditional":"他發誓要報仇雪恥，為家族爭光。"},{"simplified":"经过多年的努力，他终于报仇雪耻。","english":"After years of effort, he finally avenged and erased the shame.","traditional":"經過多年的努力，他終於報仇雪恥。"}],"synonyms":["复仇雪耻"],"antonyms":[],"confusedWith":[{"id":"复仇","note":"复仇 focuses solely on revenge without the aspect of erasing shame."}],"traditional":"報仇雪恥","pinyinOverride":null},{"id":"bao-cheng-yi-tuan","simplified":"抱成一团","literalMeaning":"embrace into one group","figurativeMeaning":"to stick together; to unite closely","englishEquivalents":["stick together","unite as one","band together"],"shortGloss":"stick together; unite closely","characters":[{"char":"抱","meaning":"embrace, hold"},{"char":"成","meaning":"become, form"},{"char":"一","meaning":"one, single"},{"char":"团","meaning":"group, mass"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom 抱成一团 is used to describe a situation where people come together and unite as a single entity, often to achieve a common goal or to support each other. The imagery of embracing into one group suggests a close-knit unity and cooperation.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"commonly used in both spoken and written Chinese to describe unity and cooperation","connotation":"positive","commonMistakes":"Learners might confuse this idiom with others that imply physical closeness rather than unity of purpose. It's important to remember that 抱成一团 emphasizes cooperation and unity, not just physical proximity.","canStandAlone":false},"examples":[{"simplified":"在困难时期，我们必须抱成一团，共同面对挑战。","english":"In difficult times, we must stick together and face challenges as one.","traditional":"在困難時期，我們必須抱成一團，共同面對挑戰。"},{"simplified":"团队成员抱成一团，成功地完成了项目。","english":"The team members united closely and successfully completed the project.","traditional":"團隊成員抱成一團，成功地完成了項目。"}],"synonyms":["团结一致","齐心协力"],"antonyms":["各自为政"],"confusedWith":[{"id":"抱团取暖","note":"抱团取暖 implies coming together for mutual benefit, often in a survival context, while 抱成一团 emphasizes unity and cooperation."}],"traditional":"抱成一團","pinyinOverride":null},{"id":"bao-fu-bu-fan","simplified":"抱负不凡","literalMeaning":"ambition not ordinary","figurativeMeaning":"to have extraordinary ambitions","englishEquivalents":["aim high","think big"],"shortGloss":"to have extraordinary ambitions","characters":[{"char":"抱","meaning":"embrace; hold"},{"char":"负","meaning":"burden; ambition"},{"char":"不","meaning":"not"},{"char":"凡","meaning":"ordinary; common"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '抱负不凡' is used to describe someone who has ambitions that are not ordinary or common. It highlights a person's desire to achieve something significant or impactful, setting them apart from those with more modest goals.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"modifier-head","register":"commonly used in both written and spoken Chinese to describe ambitious individuals","connotation":"positive","commonMistakes":"Learners might confuse '抱负不凡' with '志向远大' (to have grand aspirations), but '抱负不凡' specifically emphasizes the extraordinary nature of the ambitions, not just their grandness.","canStandAlone":false},"examples":[{"simplified":"他从小就抱负不凡，希望能改变世界。","english":"Since childhood, he has had extraordinary ambitions, hoping to change the world.","traditional":"他從小就抱負不凡，希望能改變世界。"},{"simplified":"她的抱负不凡，使她在事业上不断追求卓越。","english":"Her extraordinary ambitions drive her to continually pursue excellence in her career.","traditional":"她的抱負不凡，使她在事業上不斷追求卓越。"}],"synonyms":["志向远大"],"antonyms":["胸无大志"],"confusedWith":[{"id":"志向远大","note":"Both describe having ambitions, but '抱负不凡' emphasizes the extraordinary nature, while '志向远大' focuses on the grandness."}],"traditional":"抱負不凡","pinyinOverride":null},{"id":"bao-qu-xian-yuan","simplified":"抱屈衔冤","literalMeaning":"harbor grievance, hold resentment","figurativeMeaning":"to feel wronged and resentful","englishEquivalents":["bear a grudge","harbor resentment"],"shortGloss":"to feel wronged and resentful","characters":[{"char":"抱","meaning":"harbor, hold"},{"char":"屈","meaning":"grievance, wrong"},{"char":"衔","meaning":"hold in the mouth, bear"},{"char":"冤","meaning":"injustice, resentment"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '抱屈衔冤' is used to describe someone who feels wronged and harbors resentment as a result. It conveys a sense of carrying a burden of injustice or grievance, often silently or without resolution. The imagery of 'holding' or 'harboring' these feelings suggests a deep-seated and ongoing emotional state.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","object"],"structure":"coordinate","register":"literary, but can be used in formal speech and writing","connotation":"negative","commonMistakes":"Learners might confuse this idiom with similar expressions that involve feeling wronged, but this idiom specifically emphasizes the ongoing nature of resentment. It is not simply about being wronged, but about the continued harboring of that feeling.","canStandAlone":false},"examples":[{"simplified":"他总是抱屈衔冤，无法释怀。","english":"He always harbors resentment and cannot let go.","traditional":"他總是抱屈銜冤，無法釋懷。"},{"simplified":"在这种情况下，抱屈衔冤是没有用的。","english":"In this situation, harboring resentment is of no use.","traditional":"在這種情況下，抱屈銜冤是沒有用的。"}],"synonyms":["心怀不满","积怨已久"],"antonyms":["心平气和"],"confusedWith":[{"id":"心怀不满","note":"Both involve feelings of dissatisfaction, but 抱屈衔冤 emphasizes ongoing resentment."}],"traditional":"抱屈銜冤","pinyinOverride":null},{"id":"bao-tou-tong-ku","simplified":"抱头痛哭","literalMeaning":"hold head cry bitterly","figurativeMeaning":"to cry bitterly, often in a moment of emotional release or reconciliation","englishEquivalents":["cry one's eyes out","weep bitterly"],"shortGloss":"cry bitterly in emotional release","characters":[{"char":"抱","meaning":"hold"},{"char":"头","meaning":"head"},{"char":"痛","meaning":"bitterly"},{"char":"哭","meaning":"cry"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '抱头痛哭' describes a scene where people are overwhelmed with emotion, often due to a reunion, reconciliation, or shared grief, and they hold their heads and cry bitterly. It emphasizes the depth of the emotional release experienced in such moments.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"commonly used in both written and spoken Chinese to describe intense emotional moments","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with others that involve crying, but '抱头痛哭' specifically emphasizes the intensity and physical expression of grief or relief. It is not used for mild sadness.","canStandAlone":false},"examples":[{"simplified":"得知真相后，他们抱头痛哭，互相安慰。","english":"After learning the truth, they cried bitterly, comforting each other.","traditional":"得知真相後，他們抱頭痛哭，互相安慰。"},{"simplified":"多年未见的朋友重聚时，忍不住抱头痛哭。","english":"When friends who hadn't seen each other for years reunited, they couldn't help but cry bitterly.","traditional":"多年未見的朋友重聚時，忍不住抱頭痛哭。"}],"synonyms":["痛哭流涕"],"antonyms":[],"confusedWith":[{"id":"痛哭流涕","note":"Both involve crying intensely, but '痛哭流涕' emphasizes tears flowing, while '抱头痛哭' emphasizes the physical action of holding one's head."}],"traditional":"抱頭痛哭","pinyinOverride":null},{"id":"bao-feng-ji-yu","simplified":"暴风疾雨","literalMeaning":"violent wind, swift rain","figurativeMeaning":"a sudden and intense situation or event, often with chaotic or destructive effects","englishEquivalents":["a stormy situation","tempest in a teapot"],"shortGloss":"a sudden, intense situation","characters":[{"char":"暴","meaning":"violent"},{"char":"风","meaning":"wind"},{"char":"疾","meaning":"swift"},{"char":"雨","meaning":"rain"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '暴风疾雨' is used to describe situations that arise suddenly and with great intensity, much like a violent storm. It is often applied to events that are chaotic or have the potential to cause disruption.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["subject","predicate","object"],"structure":"coordinate","register":"commonly used in both written and spoken Chinese to describe intense situations","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with others that describe weather phenomena literally, rather than metaphorically. It's important to use it in contexts where the focus is on the intensity and suddenness of a situation.","canStandAlone":false},"examples":[{"simplified":"这次会议就像暴风疾雨，充满了争论和冲突。","english":"The meeting was like a storm, full of arguments and conflicts.","traditional":"這次會議就像暴風疾雨，充滿了爭論和衝突。"},{"simplified":"市场的变化如同暴风疾雨，让投资者措手不及。","english":"The market changes were like a violent storm, catching investors off guard.","traditional":"市場的變化如同暴風疾雨，讓投資者措手不及。"}],"synonyms":["狂风暴雨"],"antonyms":[],"confusedWith":[{"id":"狂风暴雨","note":"Both describe intense weather, but '狂风暴雨' is more often used literally, while '暴风疾雨' is metaphorical."}],"traditional":"暴風疾雨","pinyinOverride":null},{"id":"ben-xiang-ben-tu","simplified":"本乡本土","literalMeaning":"native village, native land","figurativeMeaning":"one's hometown or native place; local","englishEquivalents":["homegrown","local","native"],"shortGloss":"native place; local","characters":[{"char":"本","meaning":"this; one's own"},{"char":"乡","meaning":"village; hometown"},{"char":"本","meaning":"this; one's own"},{"char":"土","meaning":"land; soil"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom 本乡本土 refers to one's native place or hometown. It emphasizes a sense of belonging and origin, often used to describe something that is local or homegrown. The repetition of '本' (one's own) and the pairing with '乡' (village) and '土' (land) underscores the connection to one's roots.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["attributive","adverbial"],"structure":"coordinate","register":"neutral, commonly used in both spoken and written Chinese","connotation":"neutral","commonMistakes":"Learners might confuse 本乡本土 with idioms that imply a broader regional identity rather than a specific hometown. It specifically refers to one's own local area, not just any local area.","canStandAlone":false},"examples":[{"simplified":"这家餐厅的菜都是本乡本土的风味。","english":"The dishes in this restaurant all have a local flavor.","traditional":"這家餐廳的菜都是本鄉本土的風味。"},{"simplified":"他是个本乡本土的企业家，对这里的市场非常了解。","english":"He is a local entrepreneur and knows the market here very well.","traditional":"他是個本鄉本土的企業家，對這裡的市場非常瞭解。"}],"synonyms":["土生土长"],"antonyms":["外来"],"confusedWith":[{"id":"土生土长","note":"本乡本土 emphasizes the place itself, while 土生土长 emphasizes being born and raised in a place."}],"traditional":"本鄉本土","pinyinOverride":null},{"id":"ben-zui-ben-she","simplified":"笨嘴笨舌","literalMeaning":"clumsy mouth clumsy tongue","figurativeMeaning":"inarticulate or not good at speaking","englishEquivalents":["tongue-tied","inarticulate"],"shortGloss":"inarticulate or tongue-tied","characters":[{"char":"笨","meaning":"clumsy, awkward"},{"char":"嘴","meaning":"mouth"},{"char":"笨","meaning":"clumsy, awkward"},{"char":"舌","meaning":"tongue"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '笨嘴笨舌' is used to describe someone who is not eloquent or struggles to express themselves clearly. The repetition of '笨' (clumsy) emphasizes the difficulty the person has with verbal communication.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["attributive","predicate"],"structure":"coordinate","register":"informal, commonly used in everyday speech","connotation":"negative","commonMistakes":"Learners might confuse this idiom with expressions that mean 'stupid' in a broader sense, but it specifically refers to being inarticulate or having difficulty speaking.","canStandAlone":false},"examples":[{"simplified":"他总是笨嘴笨舌的，无法清楚表达自己的想法。","english":"He is always tongue-tied and can't express his thoughts clearly.","traditional":"他總是笨嘴笨舌的，無法清楚表達自己的想法。"},{"simplified":"在公众场合说话时，她常常显得笨嘴笨舌。","english":"She often appears inarticulate when speaking in public.","traditional":"在公眾場合說話時，她常常顯得笨嘴笨舌。"}],"synonyms":["口拙","言语无味"],"antonyms":["口若悬河","能言善辩"],"confusedWith":[{"id":"笨手笨脚","note":"笨手笨脚 refers to being clumsy with one's hands, not speech."}],"traditional":"笨嘴笨舌","pinyinOverride":null},{"id":"bi-bu-de-yi","simplified":"逼不得已","literalMeaning":"forced without alternative","figurativeMeaning":"to have no choice but to do something; to be forced into a situation","englishEquivalents":["between a rock and a hard place","no other option","forced by circumstances"],"shortGloss":"forced to act with no other choice","characters":[{"char":"逼","meaning":"to force"},{"char":"不","meaning":"not"},{"char":"得","meaning":"able to"},{"char":"已","meaning":"stop; cease"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '逼不得已' describes a situation where someone is compelled to take an action because there are no other viable options. It reflects the feeling of being cornered and having to proceed with a decision or action out of necessity rather than choice.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"commonly used in both formal and informal contexts","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with expressions that imply willingness or choice, but '逼不得已' specifically conveys a lack of choice. It should not be used when there are other options available.","canStandAlone":false},"examples":[{"simplified":"他逼不得已才辞去了工作。","english":"He resigned from his job because he had no other choice.","traditional":"他逼不得已才辭去了工作。"},{"simplified":"在这种情况下，我们逼不得已只能接受这个条件。","english":"In this situation, we have no choice but to accept these terms.","traditional":"在這種情況下，我們逼不得已只能接受這個條件。"}],"synonyms":["迫不得已"],"antonyms":[],"confusedWith":[{"id":"心甘情愿","note":"心甘情愿 implies willingness and eagerness, while 逼不得已 implies being forced without choice."}],"traditional":"逼不得已","pinyinOverride":null},{"id":"bi-liang-wei-chang","simplified":"逼良为娼","literalMeaning":"force the good to become prostitutes","figurativeMeaning":"to compel someone to do bad things against their will, often due to circumstances","englishEquivalents":["drive someone to desperation","force someone into a corner"],"shortGloss":"compel someone to do bad things","characters":[{"char":"逼","meaning":"force"},{"char":"良","meaning":"good person"},{"char":"为","meaning":"to become"},{"char":"娼","meaning":"prostitute"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '逼良为娼' is often used to describe a situation where someone is forced into doing something morally questionable or undesirable due to external pressures or dire circumstances. The phrase literally means 'forcing good people to become prostitutes,' illustrating how extreme situations can lead individuals to actions they would not normally consider.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","object"],"structure":"verb-object","register":"literary, but can be used in serious contexts in speech","connotation":"negative","commonMistakes":"Learners may confuse this idiom with others that involve coercion, but it specifically implies forcing someone into morally questionable actions. It is not used for minor pressures or inconveniences.","canStandAlone":false},"examples":[{"simplified":"在经济压力下，他被逼良为娼，做了他从未想过的事情。","english":"Under economic pressure, he was forced into doing things he never thought he would do.","traditional":"在經濟壓力下，他被逼良為娼，做了他從未想過的事情。"},{"simplified":"社会的不公正常常逼良为娼，让人们走上不归路。","english":"Societal injustice often forces people into desperate actions, leading them down a path of no return.","traditional":"社會的不公正常常逼良為娼，讓人們走上不歸路。"}],"synonyms":[],"antonyms":[],"confusedWith":[{"id":"逼上梁山","note":"While both involve coercion, '逼上梁山' refers to being forced into rebellion or resistance, not morally questionable actions."}],"traditional":"逼良為娼","pinyinOverride":null},{"id":"bi-ren-tai-shen","simplified":"逼人太甚","literalMeaning":"press someone too much","figurativeMeaning":"to push someone too hard or go too far in forcing someone","englishEquivalents":["push someone too far","go too far","press too hard"],"shortGloss":"push someone too far","characters":[{"char":"逼","meaning":"press, force"},{"char":"人","meaning":"person, someone"},{"char":"太","meaning":"too, excessively"},{"char":"甚","meaning":"much, very"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '逼人太甚' is used to describe a situation where someone is being excessively pressured or forced beyond reasonable limits. It reflects the idea of pushing someone to their breaking point, often resulting in negative consequences.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"commonly used in both spoken and written Chinese","connotation":"negative","commonMistakes":"Learners may confuse this idiom with similar expressions that imply pressure, but '逼人太甚' specifically emphasizes excessive force or pressure. It is important to use it in contexts where someone is being pushed beyond reasonable limits.","canStandAlone":false},"examples":[{"simplified":"他已经很努力了，你不要逼人太甚。","english":"He has already tried very hard, don't push him too far.","traditional":"他已經很努力了，你不要逼人太甚。"},{"simplified":"在谈判中，我们要小心不要逼人太甚。","english":"In negotiations, we must be careful not to push the other side too hard.","traditional":"在談判中，我們要小心不要逼人太甚。"}],"synonyms":["得寸进尺","步步紧逼"],"antonyms":[],"confusedWith":[{"id":"得寸进尺","note":"While both imply pushing limits, '得寸进尺' suggests taking advantage of a situation to gain more, whereas '逼人太甚' focuses on excessive pressure."}],"traditional":"逼人太甚","pinyinOverride":null},{"id":"bi-shang-liang-shan","simplified":"逼上梁山","literalMeaning":"forced to go up Liangshan Mountain","figurativeMeaning":"forced to take desperate measures or to join a rebellion","englishEquivalents":["Driven to the wall","Forced into a corner"],"shortGloss":"forced into desperate measures","characters":[{"char":"逼","meaning":"forced"},{"char":"上","meaning":"up"},{"char":"梁","meaning":"Liang"},{"char":"山","meaning":"mountain"}],"origin":{"period":"Song Dynasty (960–1279)","sourceText":"《水浒传》","sourceTextEnglish":"Water Margin","originalExcerpt":"若不是官逼民反，怎肯上梁山。","storyEnglish":"The idiom originates from the classic Chinese novel 'Water Margin', where outlaws gather at Liangshan Mountain. Many of these outlaws were forced into rebellion due to corrupt officials and unjust circumstances. The phrase '逼上梁山' describes being left with no choice but to take extreme actions, similar to the characters in the novel who were driven to join the band of outlaws.","historicalFigures":["Song Jiang"],"relatedIdiomsFromSameSource":["替天行道","忠义堂"]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"literary, but widely understood and used in ordinary speech","connotation":"negative","commonMistakes":"Learners often confuse this idiom with expressions that imply voluntary action. However, '逼上梁山' specifically conveys being forced into a situation against one's will.","canStandAlone":false},"examples":[{"simplified":"他被公司逼上梁山，不得不辞职。","english":"He was forced into a corner by the company and had no choice but to resign.","traditional":"他被公司逼上梁山，不得不辭職。"},{"simplified":"在这样的压力下，她也只能逼上梁山，接受了不愿意的安排。","english":"Under such pressure, she was forced to take desperate measures and accept the arrangement she didn't want.","traditional":"在這樣的壓力下，她也只能逼上梁山，接受了不願意的安排。"}],"synonyms":["走投无路"],"antonyms":[],"confusedWith":[{"id":"自愿上山","note":"This phrase implies a voluntary action, unlike '逼上梁山' which implies being forced."}],"traditional":"逼上梁山","pinyinOverride":null},{"id":"bi-qing-lian-zhong","simplified":"鼻青脸肿","literalMeaning":"nose blue face swollen","figurativeMeaning":"to be badly bruised; to be beaten black and blue","englishEquivalents":["black and blue","bruised and battered"],"shortGloss":"badly bruised","characters":[{"char":"鼻","meaning":"nose"},{"char":"青","meaning":"blue or green (bruised)"},{"char":"脸","meaning":"face"},{"char":"肿","meaning":"swollen"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '鼻青脸肿' describes someone who has been physically beaten to the point of having visible bruises and swelling on their face. It vividly conveys the image of a person with a bruised nose and a swollen face, often used metaphorically to describe someone who has suffered a significant setback or defeat.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"coordinate","register":"colloquial, commonly used in both spoken and written Chinese","connotation":"negative","commonMistakes":"Learners might confuse the idiom with similar expressions that describe physical appearance, but this idiom specifically implies having been beaten or injured. It is not used to describe general tiredness or illness.","canStandAlone":false},"examples":[{"simplified":"他和人打架，结果鼻青脸肿地回来了。","english":"He got into a fight and came back black and blue.","traditional":"他和人打架，結果鼻青臉腫地回來了。"},{"simplified":"经过一场激烈的比赛，他鼻青脸肿，但仍然很高兴。","english":"After an intense match, he was bruised and battered, but still very happy.","traditional":"經過一場激烈的比賽，他鼻青臉腫，但仍然很高興。"}],"synonyms":["遍体鳞伤"],"antonyms":[],"confusedWith":[{"id":"面目全非","note":"While '面目全非' describes something being completely altered or unrecognizable, '鼻青脸肿' specifically refers to physical bruising and swelling."}],"traditional":"鼻青臉腫","pinyinOverride":null},{"id":"bi-liang-qi-guan","simplified":"比量齐观","literalMeaning":"compare measure equal view","figurativeMeaning":"to treat different things as if they are the same; to apply the same standard to different situations","englishEquivalents":["to compare apples and oranges","to lump together","to treat as equals"],"shortGloss":"treat different things as the same","characters":[{"char":"比","meaning":"compare"},{"char":"量","meaning":"measure"},{"char":"齐","meaning":"equal"},{"char":"观","meaning":"view"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom 比量齐观 is often used to criticize the inappropriate comparison of things that are inherently different. It suggests that one should not apply the same standard or viewpoint to things that are not comparable.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"formal written Chinese, but can be used in speech to emphasize the inappropriateness of a comparison","connotation":"negative","commonMistakes":"Learners often confuse this idiom with others that suggest equality or fairness, but 比量齐观 specifically criticizes inappropriate comparisons. It is not about fairness but about the error of treating different things as the same.","canStandAlone":false},"examples":[{"simplified":"在评价艺术作品时，不应该比量齐观。","english":"When evaluating works of art, one should not treat them as if they are the same.","traditional":"在評價藝術作品時，不應該比量齊觀。"},{"simplified":"不同文化的习俗不能比量齐观。","english":"The customs of different cultures should not be treated as if they are the same.","traditional":"不同文化的習俗不能比量齊觀。"}],"synonyms":[],"antonyms":[],"confusedWith":[{"id":"一视同仁","note":"一视同仁 means to treat everyone equally and fairly, which is different from 比量齐观's emphasis on inappropriate comparison."}],"traditional":"比量齊觀","pinyinOverride":null},{"id":"bi-quan-liang-li","simplified":"比权量力","literalMeaning":"compare authority measure strength","figurativeMeaning":"to assess one's own capabilities or resources before taking action","englishEquivalents":["know your limits","measure your strength","assess your capabilities"],"shortGloss":"assess one's capabilities","characters":[{"char":"比","meaning":"compare"},{"char":"权","meaning":"authority"},{"char":"量","meaning":"measure"},{"char":"力","meaning":"strength"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom encourages individuals to evaluate their own power and resources before engaging in any endeavor. It emphasizes the importance of self-awareness and realistic assessment to avoid overestimating one's abilities.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"commonly used in both spoken and written Chinese","connotation":"neutral","commonMistakes":"Learners often confuse this idiom with similar ones that emphasize competition rather than self-assessment. It's important to remember that it focuses on internal evaluation rather than external comparison.","canStandAlone":false},"examples":[{"simplified":"在做决定之前，我们应该比权量力。","english":"Before making a decision, we should assess our capabilities.","traditional":"在做決定之前，我們應該比權量力。"},{"simplified":"他总是比权量力，不会轻易做出承诺。","english":"He always assesses his capabilities and doesn't make promises lightly.","traditional":"他總是比權量力，不會輕易做出承諾。"}],"synonyms":["量力而行"],"antonyms":[],"confusedWith":[{"id":"量力而行","note":"Both idioms involve assessing one's capabilities, but 比权量力 specifically includes the aspect of comparing authority or resources."}],"traditional":"比權量力","pinyinOverride":null},{"id":"bi-shou-hua-jiao","simplified":"比手划脚","literalMeaning":"gesture with hands and feet","figurativeMeaning":"to gesticulate wildly; to make excessive gestures while speaking","englishEquivalents":["talk with one's hands","gesticulate"],"shortGloss":"gesticulate wildly","characters":[{"char":"比","meaning":"compare; here, it means to gesture"},{"char":"手","meaning":"hand"},{"char":"划","meaning":"draw; here, it means to gesture"},{"char":"脚","meaning":"foot"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '比手划脚' describes the act of using exaggerated gestures, often with both hands and feet, to communicate or emphasize a point. This can be seen in situations where someone is trying to explain something passionately or when language barriers exist, and gestures become a crucial part of communication.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"coordinate","register":"informal, commonly used in everyday speech","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with others that involve gestures, but '比手划脚' specifically emphasizes excessive or wild gesturing, often in a way that seems unnecessary or overly dramatic.","canStandAlone":false},"examples":[{"simplified":"他在会上比手划脚，试图让大家理解他的观点。","english":"He was gesticulating wildly at the meeting, trying to get everyone to understand his point.","traditional":"他在會上比手劃腳，試圖讓大家理解他的觀點。"},{"simplified":"她总是比手划脚地讲故事，增加了很多趣味。","english":"She always tells stories with a lot of gesturing, which adds a lot of fun.","traditional":"她總是比手劃腳地講故事，增加了很多趣味。"}],"synonyms":[],"antonyms":[],"confusedWith":[],"traditional":"比手劃腳","pinyinOverride":null},{"id":"bi-ci-bi-ci","simplified":"彼此彼此","literalMeaning":"you and me, you and me","figurativeMeaning":"we're in the same boat; we're in the same situation","englishEquivalents":["same here","likewise","we're in the same boat"],"shortGloss":"we're in the same situation","characters":[{"char":"彼","meaning":"that; the other"},{"char":"此","meaning":"this; here"},{"char":"彼","meaning":"that; the other"},{"char":"此","meaning":"this; here"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '彼此彼此' is often used to express that two parties are in a similar situation or share a common experience. It is a colloquial expression that emphasizes mutual understanding or shared circumstances, often used in friendly exchanges to downplay differences or highlight commonalities.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["standalone-exclamation"],"structure":"ABAC","register":"informal, commonly used in everyday conversation","connotation":"neutral","commonMistakes":"Learners may mistakenly use this idiom in formal writing or contexts where a more precise expression of similarity is required. It is best suited for informal exchanges.","canStandAlone":true},"examples":[{"simplified":"你也累了？彼此彼此。","english":"You're tired too? Same here.","traditional":"你也累了？彼此彼此。"},{"simplified":"他觉得工作压力大，我说彼此彼此。","english":"He said he feels a lot of work pressure, and I said, 'Same here.'","traditional":"他覺得工作壓力大，我說彼此彼此。"}],"synonyms":["半斤八两"],"antonyms":[],"confusedWith":[],"traditional":"彼此彼此","pinyinOverride":null},{"id":"bi-fa-kou-zhu","simplified":"笔伐口诛","literalMeaning":"pen attack, mouth execute","figurativeMeaning":"to criticize and condemn someone through writing and speech","englishEquivalents":["the pen is mightier than the sword","verbal attack"],"shortGloss":"criticize harshly in writing and speech","characters":[{"char":"笔","meaning":"pen; writing"},{"char":"伐","meaning":"attack; criticize"},{"char":"口","meaning":"mouth; speech"},{"char":"诛","meaning":"execute; condemn"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom 笔伐口诛 is believed to have originated from the idea that one can attack and condemn others through the power of writing and speech rather than physical force. It emphasizes the impact of words and writing in criticizing and denouncing wrongdoing or injustice.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"coordinate","register":"formal written Chinese, but can be used in speech to emphasize the power of criticism","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with those that imply physical confrontation, but 笔伐口诛 specifically refers to verbal and written criticism. It is not used for physical attacks.","canStandAlone":false},"examples":[{"simplified":"在这篇文章中，作者对腐败官员进行了笔伐口诛。","english":"In this article, the author launched a verbal and written attack on the corrupt officials.","traditional":"在這篇文章中，作者對腐敗官員進行了筆伐口誅。"},{"simplified":"他常常用笔伐口诛的方式来表达对社会不公的愤怒。","english":"He often uses criticism in writing and speech to express his anger at social injustice.","traditional":"他常常用筆伐口誅的方式來表達對社會不公的憤怒。"}],"synonyms":["口诛笔伐"],"antonyms":[],"confusedWith":[{"id":"口诛笔伐","note":"The order of characters is reversed, but the meaning is the same."}],"traditional":"筆伐口誅","pinyinOverride":null},{"id":"bi-sao-qian-jun","simplified":"笔扫千军","literalMeaning":"brush sweeps away a thousand armies","figurativeMeaning":"the power of writing or strategy can overcome great force","englishEquivalents":["The pen is mightier than the sword"],"shortGloss":"writing can overcome force","characters":[{"char":"笔","meaning":"brush; writing"},{"char":"扫","meaning":"sweep away"},{"char":"千","meaning":"thousand"},{"char":"军","meaning":"army; armies"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom suggests that the power of writing, ideas, or strategy can be more effective than brute force. It is often used to emphasize the importance of intellect and planning over sheer numbers or strength.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"literary, but understood in educated speech","connotation":"positive","commonMistakes":"Learners might confuse this idiom with those that emphasize physical strength or military might, but this idiom specifically highlights the power of intellect and strategy.","canStandAlone":false},"examples":[{"simplified":"在这场辩论中，他用笔扫千军的策略赢得了胜利。","english":"In this debate, he won with a strategy that swept away a thousand armies.","traditional":"在這場辯論中，他用筆掃千軍的策略贏得了勝利。"},{"simplified":"他的文章犹如笔扫千军，影响了无数读者。","english":"His article, like a brush sweeping away a thousand armies, influenced countless readers.","traditional":"他的文章猶如筆掃千軍，影響了無數讀者。"}],"synonyms":[],"antonyms":[],"confusedWith":[],"traditional":"筆掃千軍","pinyinOverride":null},{"id":"bi-yi-bu-xie","simplified":"鄙夷不屑","literalMeaning":"despise and disdain","figurativeMeaning":"to look down upon something or someone with contempt and disdain","englishEquivalents":["look down one's nose at","turn up one's nose at"],"shortGloss":"to look down on with contempt","characters":[{"char":"鄙","meaning":"despise"},{"char":"夷","meaning":"disdain"},{"char":"不","meaning":"not"},{"char":"屑","meaning":"consider worth"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '鄙夷不屑' is used to describe a strong feeling of contempt and disdain towards someone or something considered unworthy. It is often used in contexts where someone dismisses or looks down upon another's actions, opinions, or status.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"coordinate","register":"commonly used in both written and spoken Chinese to express disdain","connotation":"negative","commonMistakes":"Learners might confuse this idiom with similar expressions of disdain, but '鄙夷不屑' specifically implies both contempt and a sense of superiority. It should not be used lightly or in situations where the disdain is not strong.","canStandAlone":false},"examples":[{"simplified":"他对那些不诚实的人总是鄙夷不屑。","english":"He always looks down on dishonest people with contempt.","traditional":"他對那些不誠實的人總是鄙夷不屑。"},{"simplified":"她对这种行为鄙夷不屑，认为完全不值得理会。","english":"She disdains such behavior, considering it not worth any attention.","traditional":"她對這種行為鄙夷不屑，認為完全不值得理會。"}],"synonyms":["嗤之以鼻"],"antonyms":["刮目相看"],"confusedWith":[{"id":"不屑一顾","note":"Both express disdain, but '不屑一顾' specifically means not worth a glance, focusing more on the action of ignoring."}],"traditional":"鄙夷不屑","pinyinOverride":null},{"id":"bi-cao-sheng-quan","simplified":"必操胜券","literalMeaning":"certainly hold the winning ticket","figurativeMeaning":"to be certain of success; to have victory in one's grasp","englishEquivalents":["a sure thing","a guaranteed win"],"shortGloss":"certain of success","characters":[{"char":"必","meaning":"certainly"},{"char":"操","meaning":"hold"},{"char":"胜","meaning":"victory"},{"char":"券","meaning":"ticket"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '必操胜券' is believed to have originated from the idea of holding a winning ticket, symbolizing certainty in achieving victory. It reflects a situation where success is assured, much like holding a ticket that guarantees a win.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"modifier-head","register":"commonly used in both formal and informal contexts","connotation":"positive","commonMistakes":"Learners might confuse this idiom with others that imply effort or struggle, but '必操胜券' specifically conveys certainty and assurance of success without the implication of difficulty.","canStandAlone":false},"examples":[{"simplified":"这次比赛我们必操胜券。","english":"We are certain to win this competition.","traditional":"這次比賽我們必操勝券。"},{"simplified":"他准备得很充分，对这次考试必操胜券。","english":"He has prepared thoroughly and is certain of success in this exam.","traditional":"他準備得很充分，對這次考試必操勝券。"}],"synonyms":["胜券在握"],"antonyms":["胜负难料"],"confusedWith":[{"id":"胜券在握","note":"Both idioms imply certainty of success, but '胜券在握' emphasizes having the advantage in hand, while '必操胜券' stresses the certainty of victory."}],"traditional":"必操勝券","pinyinOverride":null},{"id":"bi-gong-bi-jing","simplified":"必恭必敬","literalMeaning":"must be respectful and must be reverent","figurativeMeaning":"to be very respectful and reverent","englishEquivalents":["with all due respect","with utmost reverence"],"shortGloss":"very respectful and reverent","characters":[{"char":"必","meaning":"must, necessarily"},{"char":"恭","meaning":"respectful"},{"char":"必","meaning":"must, necessarily"},{"char":"敬","meaning":"reverent"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '必恭必敬' is used to describe someone who behaves with great respect and reverence, often in formal or ceremonial contexts. The repetition of '必' emphasizes the necessity and importance of being both respectful ('恭') and reverent ('敬'). It is commonly used to describe the demeanor expected in situations involving authority or tradition.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["adverbial","attributive"],"structure":"coordinate","register":"commonly used in both formal and informal contexts to describe respectful behavior","connotation":"positive","commonMistakes":"Learners might confuse this idiom with similar expressions that involve respect, but '必恭必敬' specifically emphasizes both respect and reverence. It is not used for casual politeness.","canStandAlone":false},"examples":[{"simplified":"他对长辈必恭必敬，从不失礼。","english":"He is always very respectful and reverent towards his elders, never being impolite.","traditional":"他對長輩必恭必敬，從不失禮。"},{"simplified":"在重要的场合，我们应该必恭必敬地对待每一个人。","english":"In important occasions, we should treat everyone with the utmost respect and reverence.","traditional":"在重要的場合，我們應該必恭必敬地對待每一個人。"}],"synonyms":["彬彬有礼"],"antonyms":["傲慢无礼"],"confusedWith":[{"id":"彬彬有礼","note":"While both idioms involve respect, '彬彬有礼' focuses more on politeness and manners, whereas '必恭必敬' emphasizes reverence."}],"traditional":"必恭必敬","pinyinOverride":null},{"id":"bi-men-bu-chu","simplified":"闭门不出","literalMeaning":"close the door and not go out","figurativeMeaning":"to stay indoors and avoid social interaction or outside activities","englishEquivalents":["keep to oneself","stay in","be a recluse"],"shortGloss":"stay indoors, avoid going out","characters":[{"char":"闭","meaning":"close"},{"char":"门","meaning":"door"},{"char":"不","meaning":"not"},{"char":"出","meaning":"go out"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '闭门不出' describes the action of closing one's door and not going outside. It conveys the idea of staying indoors, either to avoid social interaction or simply to keep to oneself. This behavior can be voluntary, such as when someone chooses to focus on personal projects, or involuntary, such as during times of illness or quarantine.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"commonly used in both spoken and written Chinese","connotation":"neutral","commonMistakes":"Learners sometimes confuse this idiom with '闭关锁国', which refers to a country's policy of isolation, not personal behavior. '闭门不出' is about individual actions, not national policies.","canStandAlone":false},"examples":[{"simplified":"他最近一直闭门不出，可能是在忙着写论文。","english":"He has been staying indoors lately, probably busy writing his thesis.","traditional":"他最近一直閉門不出，可能是在忙著寫論文。"},{"simplified":"疫情期间，很多人选择闭门不出，以保护自己和他人。","english":"During the pandemic, many people chose to stay indoors to protect themselves and others.","traditional":"疫情期間，很多人選擇閉門不出，以保護自己和他人。"}],"synonyms":["足不出户"],"antonyms":["出门在外"],"confusedWith":[{"id":"闭关锁国","note":"闭关锁国 refers to a country's policy of isolation, not an individual's choice to stay indoors."}],"traditional":"閉門不出","pinyinOverride":null},{"id":"bi-men-du-shu","simplified":"闭门读书","literalMeaning":"close the door and read books","figurativeMeaning":"to focus on studying or learning without distractions","englishEquivalents":["hit the books","bury oneself in books"],"shortGloss":"focus on studying","characters":[{"char":"闭","meaning":"close"},{"char":"门","meaning":"door"},{"char":"读","meaning":"read"},{"char":"书","meaning":"books"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '闭门读书' likely originates from the idea of secluding oneself to concentrate on studying. By closing the door, one shuts out distractions and dedicates time to learning. This concept has been valued in many cultures as a way to achieve academic or personal growth.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"commonly used in both spoken and written Chinese, especially in educational contexts","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with others that involve reading or studying but have different nuances, such as '埋头苦读', which emphasizes hard work and diligence rather than seclusion.","canStandAlone":false},"examples":[{"simplified":"为了准备考试，他决定闭门读书。","english":"To prepare for the exam, he decided to focus on studying without distractions.","traditional":"為了準備考試，他決定閉門讀書。"},{"simplified":"她每天都闭门读书，希望能考上理想的大学。","english":"She studies diligently every day, hoping to get into her dream university.","traditional":"她每天都閉門讀書，希望能考上理想的大學。"}],"synonyms":["埋头苦读"],"antonyms":[],"confusedWith":[{"id":"埋头苦读","note":"While both idioms involve studying, '埋头苦读' emphasizes hard work and diligence, whereas '闭门读书' focuses on seclusion and concentration."}],"traditional":"閉門讀書","pinyinOverride":null},{"id":"bian-yi-cong-shi","simplified":"便宜从事","literalMeaning":"act according to convenience","figurativeMeaning":"to act as one sees fit; to use one's discretion","englishEquivalents":["use one's discretion","act as one sees fit"],"shortGloss":"act as one sees fit","characters":[{"char":"便","meaning":"convenient"},{"char":"宜","meaning":"suitable"},{"char":"从","meaning":"follow"},{"char":"事","meaning":"affairs; matters"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '便宜从事' suggests acting according to the situation or using one's discretion. It is often used in contexts where someone is given the freedom to make decisions based on the circumstances, without strict adherence to rules or orders.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"formal written Chinese, but can be used in speech when discussing official or formal matters","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with '见机行事' (act according to circumstances), but '便宜从事' emphasizes discretion and authority, while '见机行事' focuses on adapting to changing situations.","canStandAlone":false},"examples":[{"simplified":"在紧急情况下，你可以便宜从事。","english":"In an emergency, you can act as you see fit.","traditional":"在緊急情況下，你可以便宜從事。"},{"simplified":"经理授权他便宜从事，以便更快解决问题。","english":"The manager authorized him to use his discretion to solve the problem more quickly.","traditional":"經理授權他便宜從事，以便更快解決問題。"}],"synonyms":["见机行事"],"antonyms":[],"confusedWith":[{"id":"见机行事","note":"While both involve acting based on circumstances, '见机行事' focuses on adapting to changes, whereas '便宜从事' emphasizes discretion and authority."}],"traditional":"便宜從事","pinyinOverride":null},{"id":"bian-yi-xing-shi","simplified":"便宜行事","literalMeaning":"act as convenient","figurativeMeaning":"to act according to circumstances; to use one's discretion","englishEquivalents":["use your discretion","play it by ear"],"shortGloss":"act according to circumstances","characters":[{"char":"便","meaning":"convenient"},{"char":"宜","meaning":"appropriate"},{"char":"行","meaning":"to act"},{"char":"事","meaning":"affairs"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '便宜行事' suggests acting in a way that is most suitable to the current circumstances. It implies using one's judgment to make decisions when specific instructions are not available. The phrase has been used historically to empower individuals to make decisions on the spot, adapting to the situation as needed.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["adverbial","complement"],"structure":"verb-object","register":"commonly used in both formal and informal contexts","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with '见机行事' (act according to the situation), which is similar but emphasizes seizing opportunities. '便宜行事' focuses more on using discretion without explicit instructions.","canStandAlone":false},"examples":[{"simplified":"在紧急情况下，你可以便宜行事。","english":"In an emergency, you can act according to your discretion.","traditional":"在緊急情況下，你可以便宜行事。"},{"simplified":"经理不在的时候，你就便宜行事吧。","english":"When the manager is not around, just use your discretion.","traditional":"經理不在的時候，你就便宜行事吧。"}],"synonyms":["见机行事"],"antonyms":[],"confusedWith":[{"id":"见机行事","note":"Both involve acting based on circumstances, but '见机行事' emphasizes seizing the right moment."}],"traditional":"便宜行事","pinyinOverride":null},{"id":"bian-hua-bu-ce","simplified":"变化不测","literalMeaning":"change unpredictable","figurativeMeaning":"unpredictable changes; things are constantly changing and hard to predict","englishEquivalents":["unpredictable","in constant flux"],"shortGloss":"unpredictable changes","characters":[{"char":"变","meaning":"change"},{"char":"化","meaning":"transform"},{"char":"不","meaning":"not"},{"char":"测","meaning":"predict"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '变化不测' describes a situation where changes occur so rapidly and unpredictably that they cannot be foreseen. It is often used to describe volatile situations, such as the weather, stock markets, or political climates, where the outcome is uncertain and constantly shifting.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"modifier-head","register":"neutral, used in both formal and informal contexts","connotation":"neutral","commonMistakes":"Learners often confuse this idiom with others that describe change, such as '变化无常', which specifically emphasizes inconsistency rather than unpredictability.","canStandAlone":false},"examples":[{"simplified":"最近的天气变化不测，出门要带伞。","english":"The weather has been unpredictable lately, so take an umbrella when you go out.","traditional":"最近的天氣變化不測，出門要帶傘。"},{"simplified":"股市变化不测，投资需谨慎。","english":"The stock market is unpredictable, so invest with caution.","traditional":"股市變化不測，投資需謹慎。"}],"synonyms":["变化无常"],"antonyms":[],"confusedWith":[{"id":"变化无常","note":"变化无常 emphasizes inconsistency, while 变化不测 focuses on unpredictability."}],"traditional":"變化不測","pinyinOverride":null},{"id":"bian-huan-wu-chang","simplified":"变幻无常","literalMeaning":"change and transformation without constancy","figurativeMeaning":"unpredictable and constantly changing","englishEquivalents":["ever-changing","unpredictable","inconstant"],"shortGloss":"unpredictable and ever-changing","characters":[{"char":"变","meaning":"change"},{"char":"幻","meaning":"illusion; transformation"},{"char":"无","meaning":"without"},{"char":"常","meaning":"constancy; regularity"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '变幻无常' is used to describe situations, environments, or conditions that are constantly changing and unpredictable. It captures the idea that things can transform in unexpected ways, often without any regular pattern or predictability.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive","adverbial"],"structure":"modifier-head","register":"commonly used in both written and spoken Chinese to describe unpredictable situations","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with others that imply chaos or disorder. However, '变幻无常' specifically refers to unpredictability and changeability, not necessarily disorder.","canStandAlone":false},"examples":[{"simplified":"天气变幻无常，我们最好带上雨伞。","english":"The weather is unpredictable, so we should bring an umbrella.","traditional":"天氣變幻無常，我們最好帶上雨傘。"},{"simplified":"他的情绪变幻无常，让人难以捉摸。","english":"His moods are unpredictable and hard to grasp.","traditional":"他的情緒變幻無常，讓人難以捉摸。"}],"synonyms":["变化多端"],"antonyms":["一成不变"],"confusedWith":[{"id":"变化多端","note":"Both idioms describe changeability, but '变化多端' often implies a variety of changes, while '变幻无常' emphasizes unpredictability."}],"traditional":"變幻無常","pinyinOverride":null},{"id":"biao-xin-chuang-yi","simplified":"标新创异","literalMeaning":"establish new, create different","figurativeMeaning":"to pursue novelty and originality; to be unconventional","englishEquivalents":["break new ground","think outside the box"],"shortGloss":"pursue novelty and originality","characters":[{"char":"标","meaning":"establish"},{"char":"新","meaning":"new"},{"char":"创","meaning":"create"},{"char":"异","meaning":"different"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '标新创异' is used to describe the act of seeking novelty and originality, often by breaking away from traditional or conventional methods. It emphasizes the importance of innovation and creativity in various fields.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"coordinate","register":"commonly used in both written and spoken Chinese to describe innovative actions or ideas","connotation":"positive","commonMistakes":"Learners might confuse '标新创异' with '标新立异'. While both emphasize novelty, '标新立异' can sometimes carry a slightly negative connotation of being different for the sake of being different.","canStandAlone":false},"examples":[{"simplified":"这位艺术家总是标新创异，给观众带来惊喜。","english":"This artist always pursues novelty and originality, bringing surprises to the audience.","traditional":"這位藝術家總是標新創異，給觀眾帶來驚喜。"},{"simplified":"在科技领域，标新创异是取得成功的关键。","english":"In the field of technology, pursuing novelty and originality is the key to success.","traditional":"在科技領域，標新創異是取得成功的關鍵。"}],"synonyms":["标新立异"],"antonyms":[],"confusedWith":[{"id":"标新立异","note":"Both idioms emphasize novelty, but '标新立异' can imply being different just for the sake of it, sometimes negatively."}],"traditional":"標新創異","pinyinOverride":null},{"id":"bie-you-xin-gan","simplified":"别有心肝","literalMeaning":"have a different heart and liver","figurativeMeaning":"to have ulterior motives or hidden intentions","englishEquivalents":["have an axe to grind","have hidden agendas"],"shortGloss":"have ulterior motives","characters":[{"char":"别","meaning":"different; other"},{"char":"有","meaning":"have"},{"char":"心","meaning":"heart; intention"},{"char":"肝","meaning":"liver; often used metaphorically with 'heart'"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '别有心肝' refers to someone having hidden intentions or ulterior motives. The phrase uses 'heart' and 'liver' metaphorically, as these organs are traditionally associated with emotions and intentions in Chinese culture. The idiom suggests that a person may present one face to the world while harboring different intentions internally.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"modifier-head","register":"commonly used in both spoken and written Chinese","connotation":"negative","commonMistakes":"Learners might confuse this idiom with expressions that simply mean having a different opinion or perspective. However, '别有心肝' specifically implies deceit or hidden motives.","canStandAlone":false},"examples":[{"simplified":"他看起来很友好，但我觉得他别有心肝。","english":"He seems friendly, but I think he has ulterior motives.","traditional":"他看起來很友好，但我覺得他別有心肝。"},{"simplified":"这件事让我怀疑他是否别有心肝。","english":"This matter makes me suspect whether he has hidden intentions.","traditional":"這件事讓我懷疑他是否別有心肝。"}],"synonyms":["别有用心"],"antonyms":["光明磊落"],"confusedWith":[{"id":"别有用心","note":"Both imply ulterior motives, but '别有用心' is more commonly used and recognized."}],"traditional":"別有心肝","pinyinOverride":null},{"id":"bin-peng-man-zuo","simplified":"宾朋满座","literalMeaning":"guests and friends fill the seats","figurativeMeaning":"a gathering or event is very well-attended","englishEquivalents":["a full house","standing room only"],"shortGloss":"a well-attended gathering","characters":[{"char":"宾","meaning":"guests"},{"char":"朋","meaning":"friends"},{"char":"满","meaning":"full"},{"char":"座","meaning":"seats"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '宾朋满座' describes a situation where a gathering or event is very well-attended, with all seats filled by guests and friends. It is often used to convey the success or popularity of an event, such as a banquet, party, or meeting.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"subject-predicate","register":"common in both written and spoken Chinese, suitable for formal and informal contexts","connotation":"positive","commonMistakes":"Learners might confuse this idiom with expressions that simply mean 'crowded' without the positive connotation of a successful gathering. It's important to use it in contexts where the presence of guests is a positive sign.","canStandAlone":false},"examples":[{"simplified":"他的生日派对宾朋满座，大家都玩得很开心。","english":"His birthday party was a full house, and everyone had a great time.","traditional":"他的生日派對賓朋滿座，大家都玩得很開心。"},{"simplified":"婚礼当天，宴会厅里宾朋满座，气氛热闹非凡。","english":"On the wedding day, the banquet hall was filled with guests and friends, creating a lively atmosphere.","traditional":"婚禮當天，宴會廳裡賓朋滿座，氣氛熱鬧非凡。"}],"synonyms":["座无虚席"],"antonyms":["门可罗雀"],"confusedWith":[{"id":"座无虚席","note":"While both idioms describe a full house, '座无虚席' emphasizes the absence of empty seats, whereas '宾朋满座' highlights the presence of guests and friends."}],"traditional":"賓朋滿座","pinyinOverride":null},{"id":"bing-ji-yu-gu","simplified":"冰肌玉骨","literalMeaning":"ice skin, jade bones","figurativeMeaning":"a person of exceptional beauty and purity","englishEquivalents":["as beautiful as a goddess","ethereal beauty"],"shortGloss":"exceptional beauty and purity","characters":[{"char":"冰","meaning":"ice"},{"char":"肌","meaning":"skin"},{"char":"玉","meaning":"jade"},{"char":"骨","meaning":"bones"}],"origin":{"period":"Song Dynasty (960–1279)","sourceText":"《李清照·醉花阴》","sourceTextEnglish":"Li Qingzhao's poem 'Drunken in the Shade of Flowers'","originalExcerpt":"薄雾浓云愁永昼，瑞脑消金兽。佳节又重阳，玉枕纱厨，半夜凉初透。东篱把酒黄昏后，有暗香盈袖。莫道不消魂，帘卷西风，人比黄花瘦。","storyEnglish":"The idiom comes from a poem by the famous Song Dynasty poet Li Qingzhao. In her poem 'Drunken in the Shade of Flowers', she describes a woman of extraordinary beauty and purity, comparing her skin to ice and her bones to jade. This vivid imagery has since been used to describe someone with an ethereal and pure beauty.","historicalFigures":["Li Qingzhao"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["attributive"],"structure":"modifier-head","register":"literary, but can be used in poetic or romantic contexts in modern speech","connotation":"positive","commonMistakes":"Learners might mistakenly use this idiom to describe physical coldness or rigidity, but it actually refers to beauty and purity. It should not be used in contexts unrelated to describing a person's appearance or character.","canStandAlone":false},"examples":[{"simplified":"她有着冰肌玉骨的美貌，令人惊叹。","english":"She possesses an ethereal beauty, with skin like ice and bones like jade, that leaves people in awe.","traditional":"她有著冰肌玉骨的美貌，令人驚歎。"},{"simplified":"在诗人的笔下，她是一个冰肌玉骨的女子。","english":"In the poet's writing, she is a woman of exceptional beauty and purity.","traditional":"在詩人的筆下，她是一個冰肌玉骨的女子。"}],"synonyms":["倾国倾城","闭月羞花"],"antonyms":[],"confusedWith":[{"id":"冰清玉洁","note":"冰清玉洁 emphasizes purity and moral integrity, while 冰肌玉骨 focuses on physical beauty."}],"traditional":"冰肌玉骨","pinyinOverride":null},{"id":"bing-tan-bu-tou","simplified":"冰炭不投","literalMeaning":"ice and charcoal do not mix","figurativeMeaning":"two things or people are fundamentally incompatible","englishEquivalents":["like oil and water","chalk and cheese"],"shortGloss":"fundamentally incompatible","characters":[{"char":"冰","meaning":"ice"},{"char":"炭","meaning":"charcoal"},{"char":"不","meaning":"not"},{"char":"投","meaning":"fit together"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '冰炭不投' is based on the idea that ice and charcoal are fundamentally incompatible due to their opposing properties. Ice is cold and charcoal is hot, so they cannot coexist without one affecting the other. This concept is used metaphorically to describe people or things that are inherently unable to get along or work together.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"subject-predicate","register":"literary, but understood in ordinary speech","connotation":"negative","commonMistakes":"Learners might confuse this idiom with others that describe conflict rather than incompatibility. It's important to note that this idiom emphasizes the fundamental nature of the incompatibility, not just a temporary disagreement.","canStandAlone":false},"examples":[{"simplified":"他们俩就像冰炭不投，怎么也合不来。","english":"The two of them are like ice and charcoal; they just can't get along.","traditional":"他們倆就像冰炭不投，怎麼也合不來。"},{"simplified":"这两个部门的工作方式冰炭不投，导致了很多问题。","english":"The working styles of these two departments are fundamentally incompatible, leading to many problems.","traditional":"這兩個部門的工作方式冰炭不投，導致了很多問題。"}],"synonyms":[],"antonyms":[],"confusedWith":[{"id":"水火不容","note":"While both idioms describe incompatibility, '水火不容' emphasizes active conflict, whereas '冰炭不投' focuses on inherent incompatibility."}],"traditional":"冰炭不投","pinyinOverride":null},{"id":"bing-jing-liang-zu","simplified":"兵精粮足","literalMeaning":"soldiers are elite, provisions are sufficient","figurativeMeaning":"to be well-prepared and well-supplied for a task or challenge","englishEquivalents":["ready and well-prepared","fully equipped"],"shortGloss":"well-prepared and well-supplied","characters":[{"char":"兵","meaning":"soldiers"},{"char":"精","meaning":"elite, excellent"},{"char":"粮","meaning":"provisions, food supplies"},{"char":"足","meaning":"sufficient, ample"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '兵精粮足' describes a situation where an army is not only composed of elite soldiers but is also well-supplied with provisions. This ensures that the army is fully prepared for any military engagement. Over time, the idiom has come to be used more broadly to describe any situation where one is well-prepared and well-equipped to handle a challenge.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"coordinate","register":"literary, but can be used in formal speech and writing","connotation":"positive","commonMistakes":"Learners might confuse this idiom with others that involve military terms but do not imply readiness or preparation. It's important to note that this idiom emphasizes both quality and sufficiency.","canStandAlone":false},"examples":[{"simplified":"为了这次比赛，我们已经兵精粮足，准备充分。","english":"For this competition, we are well-prepared and well-supplied.","traditional":"為了這次比賽，我們已經兵精糧足，準備充分。"},{"simplified":"公司在新产品发布前，确保兵精粮足，以应对市场需求。","english":"Before launching the new product, the company ensured it was well-prepared and well-supplied to meet market demands.","traditional":"公司在新產品發佈前，確保兵精糧足，以應對市場需求。"}],"synonyms":["万事俱备"],"antonyms":["措手不及"],"confusedWith":[{"id":"兵荒马乱","note":"While '兵荒马乱' describes chaos and disorder, '兵精粮足' emphasizes readiness and preparation."}],"traditional":"兵精糧足","pinyinOverride":null},{"id":"bing-wu-chang-shi","simplified":"兵无常势","literalMeaning":"troops have no constant formation","figurativeMeaning":"there is no fixed strategy; be adaptable to changing circumstances","englishEquivalents":["adapt to circumstances","no fixed strategy"],"shortGloss":"adapt to changing circumstances","characters":[{"char":"兵","meaning":"troops; military"},{"char":"无","meaning":"no; not have"},{"char":"常","meaning":"constant; unchanging"},{"char":"势","meaning":"formation; situation"}],"origin":{"period":"Warring States period (475–221 BCE)","sourceText":"《孙子兵法·虚实篇》","sourceTextEnglish":"Sun Tzu's Art of War, Chapter on Weaknesses and Strengths","originalExcerpt":"故兵无常势，水无常形，能因敌变化而取胜者，谓之神。","storyEnglish":"This idiom comes from Sun Tzu's 'Art of War,' where it is emphasized that military strategies should not be rigid. Just as water takes the shape of its container, military tactics should adapt to the enemy's movements and the changing battlefield conditions. The ability to be flexible and adapt is seen as a mark of a skilled commander.","historicalFigures":["Sun Tzu"],"relatedIdiomsFromSameSource":["知己知彼","以逸待劳"]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"subject-predicate","register":"literary, but widely understood and used in strategic contexts","connotation":"neutral","commonMistakes":"Learners often confuse this idiom with others that emphasize flexibility, such as '见机行事', which focuses more on acting according to the situation rather than strategic adaptability.","canStandAlone":false},"examples":[{"simplified":"在商业竞争中，我们必须记住兵无常势，灵活应对市场变化。","english":"In business competition, we must remember that there is no fixed strategy and adapt flexibly to market changes.","traditional":"在商業競爭中，我們必須記住兵無常勢，靈活應對市場變化。"},{"simplified":"成功的领导者懂得兵无常势，根据实际情况调整计划。","english":"A successful leader understands that there is no fixed strategy and adjusts plans according to the actual situation.","traditional":"成功的領導者懂得兵無常勢，根據實際情況調整計劃。"}],"synonyms":["见机行事"],"antonyms":[],"confusedWith":[{"id":"见机行事","note":"While both emphasize adaptability, '见机行事' focuses on acting according to the situation, not necessarily in a strategic context."}],"traditional":"兵無常勢","pinyinOverride":null},{"id":"bing-bi-zhi-shu","simplified":"秉笔直书","literalMeaning":"hold pen and write straightforwardly","figurativeMeaning":"to write or record events truthfully and without embellishment","englishEquivalents":["tell it like it is","call a spade a spade"],"shortGloss":"write truthfully and directly","characters":[{"char":"秉","meaning":"hold"},{"char":"笔","meaning":"pen"},{"char":"直","meaning":"straightforward"},{"char":"书","meaning":"write"}],"origin":{"period":"Tang dynasty (618–907)","sourceText":"《旧唐书·魏征传》","sourceTextEnglish":"Old Book of Tang, Biography of Wei Zheng","originalExcerpt":"魏征秉笔直书，不隐恶，不讳过。","storyEnglish":"The idiom comes from the biography of Wei Zheng, a famous chancellor during the Tang dynasty. Known for his honesty and integrity, Wei Zheng was praised for his ability to record events and the actions of officials truthfully, without hiding their faults or mistakes. This phrase highlights the importance of honesty and straightforwardness in writing and recording history.","historicalFigures":["Wei Zheng"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"literary, but understood in educated speech and writing","connotation":"positive","commonMistakes":"Learners might confuse this idiom with others that imply embellishment or exaggeration. It specifically emphasizes truthfulness and directness, not just any kind of writing.","canStandAlone":false},"examples":[{"simplified":"历史学家应该秉笔直书，记录真实的历史。","english":"Historians should write truthfully and record the true history.","traditional":"歷史學家應該秉筆直書，記錄真實的歷史。"},{"simplified":"他总是秉笔直书，从不夸大其词。","english":"He always writes truthfully and never exaggerates.","traditional":"他總是秉筆直書，從不誇大其詞。"}],"synonyms":["实事求是"],"antonyms":["添油加醋"],"confusedWith":[{"id":"添油加醋","note":"添油加醋 means to add embellishments or exaggerate, which is the opposite of writing truthfully."}],"traditional":"秉筆直書","pinyinOverride":null},{"id":"bing-gong-mie-si","simplified":"秉公灭私","literalMeaning":"uphold justice, eliminate selfishness","figurativeMeaning":"to act with impartiality and fairness, putting aside personal interests","englishEquivalents":["act impartially","fair and just","without bias"],"shortGloss":"act impartially and fairly","characters":[{"char":"秉","meaning":"uphold; hold"},{"char":"公","meaning":"public; justice"},{"char":"灭","meaning":"eliminate; destroy"},{"char":"私","meaning":"selfishness; personal interest"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '秉公灭私' emphasizes the importance of acting with fairness and impartiality, especially in situations where personal interests might conflict with public duty. It encourages individuals to prioritize justice and the common good over personal gain.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["adverbial","predicate"],"structure":"verb-object","register":"formal written Chinese, but can be used in speech to emphasize fairness","connotation":"positive","commonMistakes":"Learners might confuse this idiom with those that emphasize personal gain or selfishness. It is important to remember that '秉公灭私' specifically refers to acting without bias or personal interest.","canStandAlone":false},"examples":[{"simplified":"在处理纠纷时，法官必须秉公灭私。","english":"When handling disputes, a judge must act impartially and without personal bias.","traditional":"在處理糾紛時，法官必須秉公滅私。"},{"simplified":"领导者应该秉公灭私，以赢得员工的信任。","english":"Leaders should act fairly and impartially to earn the trust of their employees.","traditional":"領導者應該秉公滅私，以贏得員工的信任。"}],"synonyms":["公正无私","大公无私"],"antonyms":["徇私舞弊"],"confusedWith":[{"id":"徇私舞弊","note":"徇私舞弊 means to act with favoritism and corruption, which is the opposite of acting impartially."}],"traditional":"秉公滅私","pinyinOverride":null},{"id":"bai-hua-zheng-yan","simplified":"百花争艳","literalMeaning":"a hundred flowers compete in beauty","figurativeMeaning":"a scene where many different things or people are flourishing and showing their best qualities","englishEquivalents":["a hundred flowers bloom","a flourishing scene"],"shortGloss":"a flourishing scene with diverse beauty","characters":[{"char":"百","meaning":"hundred"},{"char":"花","meaning":"flowers"},{"char":"争","meaning":"compete"},{"char":"艳","meaning":"beauty"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '百花争艳' is often used to describe a vibrant and lively scene where many different flowers bloom simultaneously, each showcasing its unique beauty. It is a metaphor for a situation where various talents or elements are flourishing together, creating a rich and diverse environment.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["subject","predicate","adverbial"],"structure":"subject-predicate","register":"commonly used in both literary and spoken Chinese to describe vibrant, flourishing scenes","connotation":"positive","commonMistakes":"Learners might confuse this idiom with others that involve flowers, such as '百花齐放', which emphasizes diversity rather than competition. '百花争艳' specifically highlights the competitive aspect of beauty.","canStandAlone":false},"examples":[{"simplified":"春天到了，公园里百花争艳，景色十分迷人。","english":"Spring has arrived, and the park is filled with flowers competing in beauty, creating a captivating scene.","traditional":"春天到了，公園裡百花爭豔，景色十分迷人。"},{"simplified":"在这次艺术展上，各种风格的作品百花争艳，令人目不暇接。","english":"At this art exhibition, works of various styles are flourishing, leaving viewers dazzled.","traditional":"在這次藝術展上，各種風格的作品百花爭豔，令人目不暇接。"}],"synonyms":[],"antonyms":[],"confusedWith":[],"traditional":"百花爭豔","pinyinOverride":null},{"id":"bai-nian-zhi-hou","simplified":"百年之后","literalMeaning":"a hundred years later","figurativeMeaning":"after one's death","englishEquivalents":["after one's passing","in the afterlife"],"shortGloss":"after one's death","characters":[{"char":"百","meaning":"hundred"},{"char":"年","meaning":"years"},{"char":"之","meaning":"after"},{"char":"后","meaning":"later"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '百年之后' is often used euphemistically to refer to the time after someone has passed away. The phrase implies a long duration, symbolizing the end of one's life and what comes after. It is commonly used in contexts discussing wills, legacies, or matters that will be relevant after a person's death.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["adverbial"],"structure":"modifier-head","register":"common in both formal and informal contexts, often used in legal or ceremonial language","connotation":"neutral","commonMistakes":"Learners might mistakenly use this idiom to refer to a literal hundred years later, but it specifically refers to the time after someone's death.","canStandAlone":false},"examples":[{"simplified":"他在遗嘱中说明了百年之后财产的分配。","english":"He specified the distribution of his assets after his death in the will.","traditional":"他在遺囑中說明了百年之後財產的分配。"},{"simplified":"百年之后，他的作品仍然被人们所铭记。","english":"After his death, his works are still remembered by people.","traditional":"百年之後，他的作品仍然被人們所銘記。"}],"synonyms":[],"antonyms":[],"confusedWith":[{"id":"百年之后 (literal)","note":"The literal meaning of '百年之后' as 'a hundred years later' can cause confusion, but the idiom specifically refers to the time after one's death."}],"traditional":"百年之後","pinyinOverride":null},{"id":"bai-shi-zhi-shi","simplified":"百世之师","literalMeaning":"teacher of a hundred generations","figurativeMeaning":"a teacher whose influence endures for generations; a great and respected teacher","englishEquivalents":["a teacher for the ages","an eternal mentor"],"shortGloss":"a teacher whose influence lasts for generations","characters":[{"char":"百","meaning":"hundred"},{"char":"世","meaning":"generations"},{"char":"之","meaning":"of"},{"char":"师","meaning":"teacher"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom 百世之师 refers to a teacher whose wisdom and teachings are so profound that they continue to influence and inspire people for many generations. It is often used to describe educators or philosophers who have made a lasting impact on society.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["attributive","subject"],"structure":"modifier-head","register":"literary, but can be used in formal speech to praise influential educators","connotation":"positive","commonMistakes":"Learners might confuse this idiom with similar-sounding phrases that do not carry the same sense of enduring influence. It's important to use it specifically to highlight long-lasting impact.","canStandAlone":false},"examples":[{"simplified":"孔子被认为是百世之师，他的思想影响了无数代人。","english":"Confucius is considered a teacher for the ages; his thoughts have influenced countless generations.","traditional":"孔子被認為是百世之師，他的思想影響了無數代人。"},{"simplified":"这位教授的研究成果使他成为百世之师。","english":"The professor's research achievements have made him a teacher whose influence will last for generations.","traditional":"這位教授的研究成果使他成為百世之師。"}],"synonyms":["万世师表"],"antonyms":[],"confusedWith":[],"traditional":"百世之師","pinyinOverride":null},{"id":"bai-si-mo-jie","simplified":"百思莫解","literalMeaning":"a hundred thoughts cannot solve","figurativeMeaning":"to remain puzzled after much thought; to be unable to make sense of something despite deep contemplation","englishEquivalents":["baffled","at a loss","can't make heads or tails of it"],"shortGloss":"puzzled despite much thought","characters":[{"char":"百","meaning":"a hundred; many"},{"char":"思","meaning":"thought; to think"},{"char":"莫","meaning":"cannot; not"},{"char":"解","meaning":"solve; understand"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '百思莫解' describes a situation where someone has thought deeply about a problem or mystery but remains unable to find a solution or understanding. It emphasizes the feeling of being perplexed despite making significant mental effort.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","complement"],"structure":"modifier-head","register":"commonly used in both written and spoken Chinese","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with others that suggest confusion but not necessarily after deep thought. It's important to note that '百思莫解' implies significant effort has been made to understand the issue.","canStandAlone":false},"examples":[{"simplified":"这个问题让我百思莫解。","english":"This problem leaves me puzzled despite much thought.","traditional":"這個問題讓我百思莫解。"},{"simplified":"他对那件事情百思莫解，最后只好放弃。","english":"He was baffled by that matter and eventually had to give up.","traditional":"他對那件事情百思莫解，最後只好放棄。"}],"synonyms":["百思不得其解"],"antonyms":[],"confusedWith":[{"id":"丈二和尚摸不着头脑","note":"This idiom also means being puzzled, but it doesn't imply deep thought or effort."}],"traditional":"百思莫解","pinyinOverride":null},{"id":"bai-sui-zhi-hao","simplified":"百岁之好","literalMeaning":"hundred years of good","figurativeMeaning":"a long and harmonious marriage","englishEquivalents":["a match made in heaven"],"shortGloss":"a long and happy marriage","characters":[{"char":"百","meaning":"hundred"},{"char":"岁","meaning":"years"},{"char":"之","meaning":"of"},{"char":"好","meaning":"good; harmonious"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '百岁之好' is used to wish for a long-lasting and harmonious marriage. It is often used in the context of weddings or when discussing the ideal of a perfect marriage. The phrase suggests a union that will last a hundred years, symbolizing longevity and happiness together.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["attributive"],"structure":"modifier-head","register":"commonly used in both formal and informal contexts, especially in wedding speeches or blessings","connotation":"positive","commonMistakes":"Learners may confuse this idiom with general expressions of longevity, but it specifically refers to the context of marriage. It should not be used to describe other types of long-lasting relationships.","canStandAlone":false},"examples":[{"simplified":"他们的婚姻真是百岁之好，令人羡慕。","english":"Their marriage is truly a long and harmonious one, something to be envied.","traditional":"他們的婚姻真是百歲之好，令人羨慕。"},{"simplified":"祝你们百岁之好，永结同心。","english":"Wishing you a long and harmonious marriage, united forever.","traditional":"祝你們百歲之好，永結同心。"}],"synonyms":["白头偕老"],"antonyms":[],"confusedWith":[{"id":"白头偕老","note":"Both refer to long-lasting marriages, but '白头偕老' emphasizes growing old together."}],"traditional":"百歲之好","pinyinOverride":null},{"id":"bai-wu-yi-cheng","simplified":"百无一成","literalMeaning":"a hundred without one success","figurativeMeaning":"to achieve nothing despite making many attempts","englishEquivalents":["nothing to show for it","all for naught"],"shortGloss":"achieve nothing despite efforts","characters":[{"char":"百","meaning":"hundred"},{"char":"无","meaning":"without"},{"char":"一","meaning":"one"},{"char":"成","meaning":"success"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '百无一成' is used to describe a situation where someone has made numerous attempts but has not succeeded in achieving any of their goals. It emphasizes the futility of the efforts and the lack of tangible results.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"modifier-head","register":"commonly used in both written and spoken Chinese","connotation":"negative","commonMistakes":"Learners might confuse this idiom with others that involve numbers, such as '九牛一毛', which has a different meaning related to insignificance. '百无一成' specifically highlights the lack of success despite many efforts.","canStandAlone":false},"examples":[{"simplified":"他努力了很久，但最终还是百无一成。","english":"He worked hard for a long time, but in the end, he achieved nothing.","traditional":"他努力了很久，但最終還是百無一成。"},{"simplified":"这些计划看似宏伟，但最后却百无一成。","english":"These plans seemed grand, but ultimately, they achieved nothing.","traditional":"這些計劃看似宏偉，但最後卻百無一成。"}],"synonyms":["徒劳无功"],"antonyms":["功成名就"],"confusedWith":[{"id":"九牛一毛","note":"九牛一毛 refers to something being insignificant or trivial, while 百无一成 emphasizes lack of success."}],"traditional":"百無一成","pinyinOverride":null},{"id":"bai-wu-yi-shi","simplified":"百无一失","literalMeaning":"a hundred without one mistake","figurativeMeaning":"absolutely certain; without a single error","englishEquivalents":["surefire","foolproof","can't go wrong"],"shortGloss":"absolutely certain","characters":[{"char":"百","meaning":"hundred"},{"char":"无","meaning":"without"},{"char":"一","meaning":"one"},{"char":"失","meaning":"mistake"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom suggests a scenario where out of a hundred attempts, not a single one results in failure. It is used to describe plans or actions that are considered to be completely reliable and without risk of error.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"modifier-head","register":"commonly used in both formal and informal contexts","connotation":"positive","commonMistakes":"Learners might confuse this idiom with similar ones that imply high probability but not absolute certainty. It's important to note that 百无一失 implies complete certainty with no chance of failure.","canStandAlone":false},"examples":[{"simplified":"他的方法百无一失，我们可以放心使用。","english":"His method is foolproof; we can use it with confidence.","traditional":"他的方法百無一失，我們可以放心使用。"},{"simplified":"这次的计划经过多次验证，已经是百无一失的了。","english":"This plan has been tested multiple times and is now absolutely certain to succeed.","traditional":"這次的計劃經過多次驗證，已經是百無一失的了。"}],"synonyms":["万无一失"],"antonyms":["百发百中"],"confusedWith":[{"id":"万无一失","note":"Both imply certainty, but 万无一失 suggests an even higher degree of assurance."}],"traditional":"百無一失","pinyinOverride":null},{"id":"bai-yi-bai-cong","simplified":"百依百从","literalMeaning":"hundred comply hundred follow","figurativeMeaning":"to comply with every request; to be completely obedient","englishEquivalents":["bend over backwards","at someone's beck and call"],"shortGloss":"comply with every request","characters":[{"char":"百","meaning":"hundred; completely"},{"char":"依","meaning":"comply"},{"char":"百","meaning":"hundred; completely"},{"char":"从","meaning":"follow"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom 百依百从 describes a person who is extremely compliant and willing to follow every request or command. It is often used to describe someone who is very accommodating or submissive, often to the point of being overly so.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"coordinate","register":"commonly used in both spoken and written Chinese","connotation":"neutral","commonMistakes":"Learners often confuse 百依百从 with 百发百中, which means 'to hit the target every time'. The former is about compliance, while the latter is about accuracy.","canStandAlone":false},"examples":[{"simplified":"她对孩子总是百依百从，从不拒绝他们的要求。","english":"She is always at her children's beck and call, never refusing their requests.","traditional":"她對孩子總是百依百從，從不拒絕他們的要求。"},{"simplified":"他对老板百依百从，希望能得到升职。","english":"He complies with every request from his boss, hoping to get a promotion.","traditional":"他對老闆百依百從，希望能得到升職。"}],"synonyms":["唯命是从"],"antonyms":["我行我素"],"confusedWith":[{"id":"百发百中","note":"百发百中 means 'to hit the target every time', focusing on accuracy rather than compliance."}],"traditional":"百依百從","pinyinOverride":null},{"id":"ban-jin-ba-liang","simplified":"半斤八两","literalMeaning":"half a jin, eight liang","figurativeMeaning":"two things are essentially the same; not much difference between them","englishEquivalents":["six of one, half a dozen of the other","not much to choose between them"],"shortGloss":"no real difference","characters":[{"char":"半","meaning":"half"},{"char":"斤","meaning":"a unit of weight (jin)"},{"char":"八","meaning":"eight"},{"char":"两","meaning":"a unit of weight (liang)"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '半斤八两' comes from the traditional Chinese units of measurement, where one jin is equal to ten liang. Therefore, half a jin (五两) is equivalent to five liang, and eight liang is only slightly more. The phrase is used to describe situations where two things are so similar that the difference between them is negligible.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"coordinate","register":"commonly used in both spoken and written Chinese","connotation":"neutral","commonMistakes":"Learners might mistakenly think the idiom refers to a literal comparison of weights, rather than its figurative meaning of similarity. It should not be used when there is a significant difference between the two things being compared.","canStandAlone":false},"examples":[{"simplified":"这两家公司在产品质量上半斤八两，没有太大区别。","english":"These two companies are half a dozen of one and six of the other in terms of product quality; there's not much difference.","traditional":"這兩家公司在產品質量上半斤八兩，沒有太大區別。"},{"simplified":"他们的能力半斤八两，谁来做这个项目都一样。","english":"Their abilities are essentially the same, so it doesn't matter who takes on this project.","traditional":"他們的能力半斤八兩，誰來做這個項目都一樣。"}],"synonyms":[],"antonyms":[],"confusedWith":[],"traditional":"半斤八兩","pinyinOverride":null},{"id":"ban-lu-chu-jia","simplified":"半路出家","literalMeaning":"halfway start monastic life","figurativeMeaning":"to start a new profession or activity halfway through life, often implying a lack of formal training or background","englishEquivalents":["a late bloomer","to change horses midstream"],"shortGloss":"start a new career late","characters":[{"char":"半","meaning":"half"},{"char":"路","meaning":"road; way"},{"char":"出","meaning":"to leave; to start"},{"char":"家","meaning":"home; family; monastic life"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '半路出家' originally refers to someone who decides to become a monk or nun later in life, after having lived as a layperson for many years. Over time, it has come to describe anyone who starts a new career or activity without the typical background or training, often implying that they might face challenges due to their late start.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"commonly used in both spoken and written Chinese","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with those that imply a complete change of identity or lifestyle, but it specifically refers to starting a new career or activity without prior background.","canStandAlone":false},"examples":[{"simplified":"他四十岁才开始学画画，真是半路出家。","english":"He only started learning to paint at forty, truly a late bloomer.","traditional":"他四十歲才開始學畫畫，真是半路出家。"},{"simplified":"她半路出家，成为了一名程序员。","english":"She changed careers midway and became a programmer.","traditional":"她半路出家，成為了一名程序員。"}],"synonyms":[],"antonyms":[],"confusedWith":[],"traditional":"半路出家","pinyinOverride":null},{"id":"ban-mian-bu-wang","simplified":"半面不忘","literalMeaning":"half face not forget","figurativeMeaning":"to have a deep impression of someone after only a brief meeting","englishEquivalents":["leave a lasting impression","unforgettable encounter"],"shortGloss":"unforgettable after a brief meeting","characters":[{"char":"半","meaning":"half"},{"char":"面","meaning":"face"},{"char":"不","meaning":"not"},{"char":"忘","meaning":"forget"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '半面不忘' describes the phenomenon of remembering someone vividly after only a brief encounter. It suggests that even a partial or fleeting interaction can leave a lasting impression on someone, making them unforgettable.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"modifier-head","register":"literary, but can be used in both formal and informal contexts","connotation":"positive","commonMistakes":"Learners might confuse this idiom with others that involve memory or recognition, but this idiom specifically emphasizes the depth of impression from a brief meeting.","canStandAlone":false},"examples":[{"simplified":"他是个半面不忘的人，第一次见面就让人印象深刻。","english":"He is someone unforgettable after just a brief meeting; he leaves a deep impression the first time you meet him.","traditional":"他是個半面不忘的人，第一次見面就讓人印象深刻。"},{"simplified":"她的微笑让人半面不忘，久久难以忘怀。","english":"Her smile is unforgettable, leaving a lasting impression for a long time.","traditional":"她的微笑讓人半面不忘，久久難以忘懷。"}],"synonyms":[],"antonyms":[],"confusedWith":[],"traditional":"半面不忘","pinyinOverride":null},{"id":"ban-mian-zhi-jiu","simplified":"半面之旧","literalMeaning":"half face of old","figurativeMeaning":"an acquaintance or someone known only superficially","englishEquivalents":["a passing acquaintance","a nodding acquaintance"],"shortGloss":"a superficial acquaintance","characters":[{"char":"半","meaning":"half"},{"char":"面","meaning":"face"},{"char":"之","meaning":"of"},{"char":"旧","meaning":"old (acquaintance)"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '半面之旧' refers to someone who is only an acquaintance, someone you have met but do not know well. The term 'half face' suggests that you have only seen or interacted with the person briefly or superficially, not enough to know them fully.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["object","attributive"],"structure":"modifier-head","register":"literary, but can be used in formal speech","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with those implying a deeper relationship. It specifically denotes a superficial or slight acquaintance, not a close friend.","canStandAlone":false},"examples":[{"simplified":"他只是我的半面之旧，我们并不熟悉。","english":"He is just a passing acquaintance of mine; we are not familiar with each other.","traditional":"他只是我的半面之舊，我們並不熟悉。"},{"simplified":"在这个城市，我有很多半面之旧，但没有真正的朋友。","english":"In this city, I have many superficial acquaintances but no real friends.","traditional":"在這個城市，我有很多半面之舊，但沒有真正的朋友。"}],"synonyms":[],"antonyms":["知己之交"],"confusedWith":[{"id":"泛泛之交","note":"Both refer to superficial relationships, but '泛泛之交' emphasizes a general lack of depth in friendship, while '半面之旧' focuses on minimal acquaintance."}],"traditional":"半面之舊","pinyinOverride":null},{"id":"ban-sheng-bu-shu","simplified":"半生不熟","literalMeaning":"half raw, not cooked","figurativeMeaning":"not fully developed or mature; lacking experience or skill","englishEquivalents":["half-baked","not fully cooked"],"shortGloss":"inexperienced or immature","characters":[{"char":"半","meaning":"half"},{"char":"生","meaning":"raw"},{"char":"不","meaning":"not"},{"char":"熟","meaning":"cooked"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '半生不熟' is often used to describe something or someone that is not fully developed or lacks the necessary experience or skill. The imagery of something being 'half raw, not cooked' conveys the idea of incompleteness or immaturity.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"modifier-head","register":"colloquial, commonly used in everyday speech","connotation":"negative","commonMistakes":"Learners often confuse this idiom with '半途而废' (to give up halfway), but '半生不熟' specifically refers to lack of maturity or experience, not the act of giving up.","canStandAlone":false},"examples":[{"simplified":"他的技术还半生不熟，需要多加练习。","english":"His skills are still half-baked and need more practice.","traditional":"他的技術還半生不熟，需要多加練習。"},{"simplified":"这道菜半生不熟，不能吃。","english":"This dish is half-cooked and can't be eaten.","traditional":"這道菜半生不熟，不能吃。"}],"synonyms":["半路出家"],"antonyms":["成熟"],"confusedWith":[{"id":"半途而废","note":"半途而废 means to give up halfway, while 半生不熟 refers to lack of maturity or experience."}],"traditional":"半生不熟","pinyinOverride":null},{"id":"ban-xin-bu-jiu","simplified":"半新不旧","literalMeaning":"half new, not old","figurativeMeaning":"neither new nor old; something that is in between being new and old, often implying mediocrity or lack of distinctiveness","englishEquivalents":["neither here nor there","betwixt and between"],"shortGloss":"neither new nor old","characters":[{"char":"半","meaning":"half"},{"char":"新","meaning":"new"},{"char":"不","meaning":"not"},{"char":"旧","meaning":"old"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '半新不旧' describes something that is neither completely new nor completely old. It is often used to describe objects, ideas, or situations that are in a transitional state or lack a clear identity. The phrase suggests a sense of mediocrity or indecisiveness, as it does not fully belong to either category.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["attributive","predicate"],"structure":"coordinate","register":"commonly used in everyday speech to describe objects or situations","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with '半途而废', which means to give up halfway. '半新不旧' specifically refers to the state of being neither new nor old, not about giving up.","canStandAlone":false},"examples":[{"simplified":"这件衣服看起来半新不旧的，不知道该不该扔掉。","english":"This piece of clothing looks neither new nor old; I'm not sure if I should throw it away.","traditional":"這件衣服看起來半新不舊的，不知道該不該扔掉。"},{"simplified":"他的想法总是半新不旧，没有什么特别的创新。","english":"His ideas are always neither new nor old, lacking any particular innovation.","traditional":"他的想法總是半新不舊，沒有什麼特別的創新。"}],"synonyms":[],"antonyms":[],"confusedWith":[{"id":"半途而废","note":"半途而废 means to give up halfway, while 半新不旧 refers to something being neither new nor old."}],"traditional":"半新不舊","pinyinOverride":null},{"id":"ban-zhen-ban-jia","simplified":"半真半假","literalMeaning":"half true half false","figurativeMeaning":"a mix of truth and falsehood; something that is partly true and partly false","englishEquivalents":["half-truth","mixed truth","partly true"],"shortGloss":"partly true, partly false","characters":[{"char":"半","meaning":"half"},{"char":"真","meaning":"true"},{"char":"半","meaning":"half"},{"char":"假","meaning":"false"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '半真半假' is used to describe situations or statements that contain both truth and falsehood. It reflects the complexity of certain scenarios where not everything is as it seems, and discerning the truth requires careful consideration.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["attributive","adverbial"],"structure":"coordinate","register":"commonly used in both spoken and written Chinese","connotation":"neutral","commonMistakes":"Learners often confuse '半真半假' with '似是而非' (seemingly true but actually false). '半真半假' indicates a genuine mix of truth and falsehood, while '似是而非' suggests something that appears true but is misleading.","canStandAlone":false},"examples":[{"simplified":"他的故事听起来半真半假，很难判断。","english":"His story sounds half true and half false, making it hard to judge.","traditional":"他的故事聽起來半真半假，很難判斷。"},{"simplified":"她的回答总是半真半假，让人摸不着头脑。","english":"Her answers are always partly true and partly false, leaving people puzzled.","traditional":"她的回答總是半真半假，讓人摸不著頭腦。"}],"synonyms":["似是而非"],"antonyms":[],"confusedWith":[{"id":"似是而非","note":"似是而非 means something that appears true but is actually false, while 半真半假 indicates a genuine mix of truth and falsehood."}],"traditional":"半真半假","pinyinOverride":null},{"id":"bao-ban-dai-ti","simplified":"包办代替","literalMeaning":"take over and replace","figurativeMeaning":"to take over everything and replace others, often implying doing so inappropriately or without consultation","englishEquivalents":["take over","do everything oneself"],"shortGloss":"take over and replace others","characters":[{"char":"包","meaning":"to wrap, to take charge of"},{"char":"办","meaning":"to handle, to manage"},{"char":"代","meaning":"to substitute, to replace"},{"char":"替","meaning":"to replace, to substitute"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '包办代替' refers to situations where someone takes over tasks or responsibilities that should be shared or handled by others, often without their consent or input. It implies an overbearing or controlling approach, where one person assumes all roles and responsibilities, potentially leading to resentment or inefficiency.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","object"],"structure":"verb-object","register":"commonly used in both formal and informal contexts to criticize overbearing behavior","connotation":"negative","commonMistakes":"Learners often confuse '包办代替' with simply taking responsibility, but it specifically implies doing so in a way that excludes others who should be involved.","canStandAlone":false},"examples":[{"simplified":"他总是包办代替，结果大家都不愿意和他合作。","english":"He always takes over everything, so no one wants to work with him.","traditional":"他總是包辦代替，結果大家都不願意和他合作。"},{"simplified":"在团队项目中，包办代替会导致其他成员失去积极性。","english":"In a team project, taking over everything can cause other members to lose motivation.","traditional":"在團隊項目中，包辦代替會導致其他成員失去積極性。"}],"synonyms":["大包大揽"],"antonyms":["分工合作"],"confusedWith":[{"id":"包罗万象","note":"包罗万象 means 'all-encompassing' and is not about taking over tasks."}],"traditional":"包辦代替","pinyinOverride":null},{"id":"bao-lan-ci-song","simplified":"包揽词讼","literalMeaning":"undertake litigation","figurativeMeaning":"to take on all legal cases; to monopolize legal representation","englishEquivalents":["ambulance chasing","legal monopoly"],"shortGloss":"monopolize legal cases","characters":[{"char":"包","meaning":"to undertake; to monopolize"},{"char":"揽","meaning":"to take on; to assume responsibility"},{"char":"词","meaning":"words; in this context, legal arguments"},{"char":"讼","meaning":"litigation; lawsuits"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom 包揽词讼 refers to someone who takes on all legal cases, often implying a monopolistic or unethical approach to legal representation. It suggests a person or entity that seeks to control or dominate the field of legal advocacy, sometimes with negative connotations of exploiting legal loopholes or engaging in aggressive litigation tactics.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","object"],"structure":"verb-object","register":"formal written Chinese, often used in legal contexts","connotation":"negative","commonMistakes":"Learners often confuse this idiom with general legal terms, but it specifically implies monopolizing or aggressively taking on legal cases, often with a negative connotation.","canStandAlone":false},"examples":[{"simplified":"这家律师事务所被指控包揽词讼，扰乱了法律市场。","english":"The law firm was accused of monopolizing legal cases, disrupting the legal market.","traditional":"這家律師事務所被指控包攬詞訟，擾亂了法律市場。"},{"simplified":"他因包揽词讼而被法律协会调查。","english":"He was investigated by the legal association for monopolizing litigation.","traditional":"他因包攬詞訟而被法律協會調查。"}],"synonyms":[],"antonyms":[],"confusedWith":[],"traditional":"包攬詞訟","pinyinOverride":null},{"id":"bao-dao-wei-lao","simplified":"宝刀未老","literalMeaning":"the treasured sword is not old","figurativeMeaning":"someone who is still capable and vigorous despite their age","englishEquivalents":["still going strong","not past one's prime"],"shortGloss":"still capable despite age","characters":[{"char":"宝","meaning":"treasured"},{"char":"刀","meaning":"sword"},{"char":"未","meaning":"not yet"},{"char":"老","meaning":"old"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '宝刀未老' is often used to describe someone who, despite their age, retains their skills and vigor. The imagery of a treasured sword that remains sharp and effective symbolizes the enduring capability of a person who has not lost their edge over time.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"subject-predicate","register":"commonly used in both spoken and written Chinese to compliment someone's enduring abilities","connotation":"positive","commonMistakes":"Learners might confuse this idiom with others that involve age, but '宝刀未老' specifically emphasizes continued capability and vigor, not just age or experience.","canStandAlone":false},"examples":[{"simplified":"虽然他已经退休多年，但在音乐会上演奏时，依然宝刀未老。","english":"Even though he has been retired for many years, he still plays at concerts with undiminished skill.","traditional":"雖然他已經退休多年，但在音樂會上演奏時，依然寶刀未老。"},{"simplified":"这位老将军在战场上依然宝刀未老，指挥若定。","english":"The veteran general still commands with confidence on the battlefield, proving he's not past his prime.","traditional":"這位老將軍在戰場上依然寶刀未老，指揮若定。"}],"synonyms":["老当益壮"],"antonyms":[],"confusedWith":[{"id":"老当益壮","note":"While both idioms praise the abilities of older individuals, '老当益壮' emphasizes becoming stronger with age, whereas '宝刀未老' highlights retaining one's original capability."}],"traditional":"寶刀未老","pinyinOverride":null},{"id":"bei-bi-wu-chi","simplified":"卑鄙无耻","literalMeaning":"base and shameless","figurativeMeaning":"extremely despicable and shameless","englishEquivalents":["low and shameless","utterly despicable"],"shortGloss":"utterly despicable and shameless","characters":[{"char":"卑","meaning":"base, low"},{"char":"鄙","meaning":"vulgar, despicable"},{"char":"无","meaning":"without"},{"char":"耻","meaning":"shame"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '卑鄙无耻' is used to describe someone who is extremely despicable and shameless. It is often used to criticize people who act in a morally reprehensible way without any sense of shame. The exact origin of the idiom is unclear, but it has been used in Chinese literature and speech to convey strong disapproval of someone's character.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"coordinate","register":"common in both written and spoken Chinese, often used in strong criticism","connotation":"negative","commonMistakes":"Learners might confuse this idiom with others that describe negative traits, but '卑鄙无耻' specifically emphasizes both despicability and shamelessness. It is stronger than simply calling someone 'bad' or 'dishonest'.","canStandAlone":false},"examples":[{"simplified":"他的行为真是卑鄙无耻，让人无法忍受。","english":"His behavior is truly despicable and shameless, making it unbearable.","traditional":"他的行為真是卑鄙無恥，讓人無法忍受。"},{"simplified":"在商业竞争中，他使用卑鄙无耻的手段来打击对手。","english":"In business competition, he uses despicable and shameless tactics to undermine his opponents.","traditional":"在商業競爭中，他使用卑鄙無恥的手段來打擊對手。"}],"synonyms":["厚颜无耻","无耻之徒"],"antonyms":["光明磊落"],"confusedWith":[{"id":"厚颜无耻","note":"While both idioms describe shamelessness, '厚颜无耻' focuses more on the shameless aspect, whereas '卑鄙无耻' emphasizes both despicability and shamelessness."}],"traditional":"卑鄙無恥","pinyinOverride":null},{"id":"bei-bu-zu-dao","simplified":"卑不足道","literalMeaning":"humble not worth mentioning","figurativeMeaning":"too insignificant to be worth mentioning","englishEquivalents":["not worth mentioning","insignificant","trivial"],"shortGloss":"too trivial to mention","characters":[{"char":"卑","meaning":"humble, lowly"},{"char":"不","meaning":"not"},{"char":"足","meaning":"enough, sufficient"},{"char":"道","meaning":"to speak, to mention"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '卑不足道' is used to describe something or someone that is considered too trivial or insignificant to be worth mentioning. It emphasizes the low status or minor importance of the subject in question.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"modifier-head","register":"neutral, used in both formal and informal contexts","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with similar expressions that emphasize humility, but '卑不足道' specifically conveys insignificance rather than modesty.","canStandAlone":false},"examples":[{"simplified":"他的贡献卑不足道，不值得一提。","english":"His contribution is too insignificant to be worth mentioning.","traditional":"他的貢獻卑不足道，不值得一提。"},{"simplified":"这些小问题卑不足道，不必担心。","english":"These minor issues are too trivial to worry about.","traditional":"這些小問題卑不足道，不必擔心。"}],"synonyms":["微不足道"],"antonyms":[],"confusedWith":[{"id":"微不足道","note":"Both idioms convey insignificance, but '微不足道' is more commonly used."}],"traditional":"卑不足道","pinyinOverride":null},{"id":"bei-gong-qu-jie","simplified":"卑躬屈节","literalMeaning":"low bow bent principles","figurativeMeaning":"to act obsequiously and compromise one's principles","englishEquivalents":["bend over backwards","grovel","kowtow"],"shortGloss":"to grovel and compromise principles","characters":[{"char":"卑","meaning":"low, humble"},{"char":"躬","meaning":"bow, body"},{"char":"屈","meaning":"bend, yield"},{"char":"节","meaning":"principles, integrity"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '卑躬屈节' describes the act of lowering oneself in a servile manner and compromising one's integrity or principles. It is often used to criticize someone who behaves obsequiously to gain favor or avoid trouble. The exact origin of this idiom is unclear, but it has been used in various historical texts to describe individuals who forsake their dignity for personal gain.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"coordinate","register":"literary, but understood in modern contexts to describe servile behavior","connotation":"negative","commonMistakes":"Learners often confuse this idiom with others that involve humility or modesty, but '卑躬屈节' specifically implies a negative sense of compromising one's principles for gain.","canStandAlone":false},"examples":[{"simplified":"他为了升职，不惜卑躬屈节。","english":"He didn't hesitate to grovel and compromise his principles for a promotion.","traditional":"他為了升職，不惜卑躬屈節。"},{"simplified":"在权力面前，他总是卑躬屈节。","english":"In the face of power, he always behaves obsequiously and compromises his integrity.","traditional":"在權力面前，他總是卑躬屈節。"}],"synonyms":["奴颜婢膝"],"antonyms":["刚正不阿"],"confusedWith":[{"id":"谦虚谨慎","note":"While '谦虚谨慎' means being modest and prudent, '卑躬屈节' implies a negative sense of compromising principles."}],"traditional":"卑躬屈節","pinyinOverride":null},{"id":"bei-jiu-jie-yuan","simplified":"杯酒解怨","literalMeaning":"cup of wine resolves resentment","figurativeMeaning":"to resolve conflicts or grudges over a drink","englishEquivalents":["bury the hatchet","make peace over a drink"],"shortGloss":"resolve grudges over a drink","characters":[{"char":"杯","meaning":"cup"},{"char":"酒","meaning":"wine"},{"char":"解","meaning":"resolve"},{"char":"怨","meaning":"resentment"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom suggests that sharing a drink can help people put aside their differences and resolve any grudges or resentments they may have. It's a metaphor for reconciliation and making peace in a social setting.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"common in both spoken and written Chinese, often used in social contexts","connotation":"positive","commonMistakes":"Learners might confuse this idiom with others that involve drinking but do not imply reconciliation. It's important to remember that this idiom specifically involves resolving conflicts.","canStandAlone":false},"examples":[{"simplified":"他们在聚会上杯酒解怨，终于和好了。","english":"They resolved their differences over a drink at the party and finally reconciled.","traditional":"他們在聚會上杯酒解怨，終於和好了。"},{"simplified":"经过一番杯酒解怨，两个朋友又恢复了往日的友谊。","english":"After resolving their grudges over a drink, the two friends restored their old friendship.","traditional":"經過一番杯酒解怨，兩個朋友又恢復了往日的友誼。"}],"synonyms":["化干戈为玉帛"],"antonyms":["反目成仇"],"confusedWith":[{"id":"一醉解千愁","note":"This idiom means to drink away one's worries, not to resolve conflicts with others."}],"traditional":"杯酒解怨","pinyinOverride":null},{"id":"bei-shui-zhi-xie","simplified":"杯水之谢","literalMeaning":"a cup of water's thanks","figurativeMeaning":"a small token of gratitude; a modest gesture of thanks","englishEquivalents":["a token of appreciation","a small gesture of thanks"],"shortGloss":"a small token of gratitude","characters":[{"char":"杯","meaning":"cup"},{"char":"水","meaning":"water"},{"char":"之","meaning":"of"},{"char":"谢","meaning":"thanks"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '杯水之谢' is believed to originate from the idea of offering a cup of water as a humble but sincere gesture of gratitude. It emphasizes the value of the thought behind the gesture rather than the material worth of the gift.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["object","attributive"],"structure":"modifier-head","register":"commonly used in both spoken and written Chinese to express modest gratitude","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with expressions that imply a larger or more significant gesture of thanks. It's important to remember that this idiom specifically conveys modesty and sincerity.","canStandAlone":false},"examples":[{"simplified":"他送了一本书作为杯水之谢。","english":"He gave a book as a small token of gratitude.","traditional":"他送了一本書作為杯水之謝。"},{"simplified":"请接受这点心，作为杯水之谢。","english":"Please accept these snacks as a small gesture of thanks.","traditional":"請接受這點心，作為杯水之謝。"}],"synonyms":[],"antonyms":[],"confusedWith":[],"traditional":"杯水之謝","pinyinOverride":null},{"id":"bei-cong-zhong-lai","simplified":"悲从中来","literalMeaning":"sorrow comes from within","figurativeMeaning":"to be overwhelmed by sorrow","englishEquivalents":["overcome with grief","sorrow wells up from within"],"shortGloss":"overwhelmed by sorrow","characters":[{"char":"悲","meaning":"sorrow"},{"char":"从","meaning":"from"},{"char":"中","meaning":"within"},{"char":"来","meaning":"come"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '悲从中来' describes a feeling of deep sorrow that seems to arise spontaneously from within oneself. It captures the experience of being suddenly overwhelmed by grief, often without an obvious external cause. This expression is used to convey a profound emotional response that is deeply personal and internal.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","complement"],"structure":"subject-predicate","register":"commonly used in both written and spoken Chinese to express deep personal sorrow","connotation":"negative","commonMistakes":"Learners might confuse this idiom with expressions that describe external causes of sadness. '悲从中来' specifically emphasizes an internal, spontaneous feeling of sorrow.","canStandAlone":false},"examples":[{"simplified":"听到这个消息，我不禁悲从中来。","english":"Upon hearing the news, I couldn't help but be overwhelmed by sorrow.","traditional":"聽到這個消息，我不禁悲從中來。"},{"simplified":"每当想起过去的事情，他总是悲从中来。","english":"Whenever he thinks of the past, he is always overcome with grief.","traditional":"每當想起過去的事情，他總是悲從中來。"}],"synonyms":["心如刀割","痛不欲生"],"antonyms":["喜出望外"],"confusedWith":[{"id":"痛不欲生","note":"While both express intense sorrow, '痛不欲生' implies a level of despair so deep that one does not wish to live, whereas '悲从中来' focuses on the spontaneous emergence of sorrow."}],"traditional":"悲從中來","pinyinOverride":null},{"id":"bei-ge-kang-kai","simplified":"悲歌慷慨","literalMeaning":"sad song, generous spirit","figurativeMeaning":"to express one's sorrow and noble aspirations passionately","englishEquivalents":["sing a mournful tune with a generous heart","lament with a magnanimous spirit"],"shortGloss":"express sorrow and noble aspirations","characters":[{"char":"悲","meaning":"sad, sorrowful"},{"char":"歌","meaning":"song"},{"char":"慷","meaning":"generous, fervent"},{"char":"慨","meaning":"indignant, impassioned"}],"origin":{"period":"Han Dynasty (206 BCE – 220 CE)","sourceText":"《史记·项羽本纪》","sourceTextEnglish":"Records of the Grand Historian, Biography of Xiang Yu","originalExcerpt":"项王则悲歌慷慨，自为诗曰：“力拔山兮气盖世，时不利兮骓不逝。”","storyEnglish":"The idiom originates from the story of Xiang Yu, a prominent warlord during the late Qin Dynasty. As he faced defeat, Xiang Yu sang a mournful song expressing his sorrow and unyielding spirit. Despite the dire situation, he remained passionate and noble, lamenting the unfavorable times and his loyal horse's inability to escape.","historicalFigures":["Xiang Yu"],"relatedIdiomsFromSameSource":["力拔山兮气盖世"]},"usage":{"grammaticalRole":["subject","predicate","object","attributive"],"structure":"coordinate","register":"literary, often used in formal writing and speeches","connotation":"neutral","commonMistakes":"Learners sometimes confuse this idiom with expressions that only convey sadness, missing the element of noble aspirations and passion. It is not just about being sad, but also about having a generous and spirited response to adversity.","canStandAlone":false},"examples":[{"simplified":"在这场灾难中，他悲歌慷慨，鼓舞了许多人。","english":"In the face of this disaster, he expressed his sorrow and noble aspirations passionately, inspiring many people.","traditional":"在這場災難中，他悲歌慷慨，鼓舞了許多人。"},{"simplified":"她用悲歌慷慨的诗句表达了对祖国的热爱。","english":"She used passionate and sorrowful verses to express her love for the motherland.","traditional":"她用悲歌慷慨的詩句表達了對祖國的熱愛。"}],"synonyms":[],"antonyms":[],"confusedWith":[{"id":"悲痛欲绝","note":"悲痛欲绝 focuses solely on deep sorrow, lacking the element of noble aspirations and passion."}],"traditional":"悲歌慷慨","pinyinOverride":null},{"id":"beiguan-yanshi","simplified":"悲观厌世","literalMeaning":"pessimistic, loathe the world","figurativeMeaning":"to be pessimistic and have a world-weary attitude","englishEquivalents":["world-weary","cynical","disillusioned"],"shortGloss":"pessimistic and world-weary","characters":[{"char":"悲","meaning":"sad; sorrowful"},{"char":"观","meaning":"view; outlook"},{"char":"厌","meaning":"detest; loathe"},{"char":"世","meaning":"world; life"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '悲观厌世' describes a mindset where an individual feels deeply pessimistic about life and harbors a sense of disillusionment with the world. This attitude can arise from personal experiences or broader societal issues that lead one to feel detached and weary of the world's challenges.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"coordinate","register":"commonly used in both written and spoken Chinese to describe a negative outlook on life","connotation":"negative","commonMistakes":"Learners often confuse this idiom with similar expressions that describe temporary sadness, but '悲观厌世' implies a deeper, more persistent worldview. It is not used for fleeting emotions.","canStandAlone":false},"examples":[{"simplified":"他最近变得悲观厌世，对什么事情都提不起兴趣。","english":"He has recently become pessimistic and world-weary, showing no interest in anything.","traditional":"他最近變得悲觀厭世，對什麼事情都提不起興趣。"},{"simplified":"她的悲观厌世态度让朋友们很担心。","english":"Her pessimistic and world-weary attitude worries her friends.","traditional":"她的悲觀厭世態度讓朋友們很擔心。"}],"synonyms":["消极避世"],"antonyms":["乐观向上"],"confusedWith":[{"id":"消极避世","note":"While both describe negative outlooks, '消极避世' emphasizes withdrawal from society, whereas '悲观厌世' focuses on a pessimistic worldview."}],"traditional":"悲觀厭世","pinyinOverride":null},{"id":"beitong-yujue","simplified":"悲痛欲绝","literalMeaning":"grief and pain to the extreme","figurativeMeaning":"overwhelmed with grief; heartbroken","englishEquivalents":["heartbroken","grief-stricken","devastated"],"shortGloss":"overwhelmed with grief","characters":[{"char":"悲","meaning":"sorrow"},{"char":"痛","meaning":"pain"},{"char":"欲","meaning":"about to"},{"char":"绝","meaning":"end; extreme"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '悲痛欲绝' is used to describe a state of being overwhelmed by grief to the point where one feels they cannot endure it any longer. It is often used in contexts of mourning or personal loss, conveying a deep emotional pain.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"modifier-head","register":"widely used in both literary and spoken Chinese to express deep sorrow","connotation":"negative","commonMistakes":"Learners might confuse this idiom with similar expressions of sadness, but '悲痛欲绝' specifically conveys an extreme level of grief. It should not be used for mild sadness or disappointment.","canStandAlone":false},"examples":[{"simplified":"听到他去世的消息，她悲痛欲绝。","english":"Upon hearing the news of his death, she was overwhelmed with grief.","traditional":"聽到他去世的消息，她悲痛欲絕。"},{"simplified":"失去爱犬后，他悲痛欲绝，几天都无法振作起来。","english":"After losing his beloved dog, he was heartbroken and couldn't pull himself together for days.","traditional":"失去愛犬後，他悲痛欲絕，幾天都無法振作起來。"}],"synonyms":["痛不欲生","肝肠寸断"],"antonyms":["喜出望外"],"confusedWith":[{"id":"痛不欲生","note":"While both express extreme sorrow, '痛不欲生' implies a desire not to live due to the pain, whereas '悲痛欲绝' focuses on the overwhelming grief itself."}],"traditional":"悲痛欲絕","pinyinOverride":null},{"id":"bei-an-tou-ming","simplified":"背暗投明","literalMeaning":"turn away from darkness and cast towards light","figurativeMeaning":"to abandon a wrong path and choose a better one; to defect from an unjust cause to a just one","englishEquivalents":["see the light","turn over a new leaf"],"shortGloss":"abandon darkness for light","characters":[{"char":"背","meaning":"turn one's back on"},{"char":"暗","meaning":"darkness"},{"char":"投","meaning":"cast towards"},{"char":"明","meaning":"light"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '背暗投明' describes the act of leaving a negative or unjust situation in favor of a positive or just one. It is often used to describe someone who has realized their previous path was wrong and has decided to follow a better, more righteous path. The imagery of moving from darkness to light symbolizes enlightenment and moral awakening.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"literary, but can be used in formal speech and writing","connotation":"positive","commonMistakes":"Learners might confuse this idiom with similar ones that involve change or transformation, but '背暗投明' specifically emphasizes a moral or ethical improvement.","canStandAlone":false},"examples":[{"simplified":"他终于决定背暗投明，加入了正义的事业。","english":"He finally decided to abandon darkness for light and joined the righteous cause.","traditional":"他終於決定背暗投明，加入了正義的事業。"},{"simplified":"在朋友的劝说下，她背暗投明，开始了新的生活。","english":"With her friend's persuasion, she turned over a new leaf and started a new life.","traditional":"在朋友的勸說下，她背暗投明，開始了新的生活。"}],"synonyms":["弃暗投明"],"antonyms":[],"confusedWith":[{"id":"改邪归正","note":"While both involve moral change, '改邪归正' emphasizes correcting one's behavior, whereas '背暗投明' emphasizes choosing a just cause over an unjust one."}],"traditional":"背暗投明","pinyinOverride":null},{"id":"bei-dao-jian-jin","simplified":"倍道兼进","literalMeaning":"double the road, advance together","figurativeMeaning":"to make rapid progress; to advance at double speed","englishEquivalents":["make rapid progress","forge ahead","move forward at full speed"],"shortGloss":"make rapid progress","characters":[{"char":"倍","meaning":"double"},{"char":"道","meaning":"road; path"},{"char":"兼","meaning":"together; simultaneously"},{"char":"进","meaning":"advance; move forward"}],"origin":{"period":"Warring States period (475–221 BCE)","sourceText":"《战国策·齐策四》","sourceTextEnglish":"Strategies of the Warring States, Strategies of Qi, Chapter 4","originalExcerpt":"倍道而进，兼行者三十日。","storyEnglish":"During the Warring States period, the state of Qi was in a hurry to send reinforcements to aid an ally. To ensure the troops arrived quickly, they traveled day and night, effectively doubling their pace. This strategy of rapid advancement was crucial in reaching their destination in time.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["adverbial","complement"],"structure":"verb-object","register":"literary, but can be used in formal speech and writing","connotation":"positive","commonMistakes":"Learners might confuse this idiom with similar expressions that imply haste but not necessarily progress. It's important to note that this idiom emphasizes both speed and effective advancement.","canStandAlone":false},"examples":[{"simplified":"为了赶上进度，我们必须倍道兼进。","english":"To catch up with the schedule, we must make rapid progress.","traditional":"為了趕上進度，我們必須倍道兼進。"},{"simplified":"项目进入关键阶段，团队决定倍道兼进。","english":"As the project entered a critical phase, the team decided to forge ahead at full speed.","traditional":"項目進入關鍵階段，團隊決定倍道兼進。"}],"synonyms":["加速前进","快马加鞭"],"antonyms":["缓慢前行"],"confusedWith":[{"id":"事半功倍","note":"事半功倍 means achieving more with less effort, whereas 倍道兼进 emphasizes speed and progress."}],"traditional":"倍道兼進","pinyinOverride":null},{"id":"bei-dao-jian-xing","simplified":"倍道兼行","literalMeaning":"double the road, simultaneously travel","figurativeMeaning":"to travel at double speed; to make haste","englishEquivalents":["make haste","double time","hurry up"],"shortGloss":"travel at double speed","characters":[{"char":"倍","meaning":"double"},{"char":"道","meaning":"road; path"},{"char":"兼","meaning":"simultaneously; concurrently"},{"char":"行","meaning":"travel; move"}],"origin":{"period":"Warring States period (475–221 BCE)","sourceText":"《孙子兵法·军争篇》","sourceTextEnglish":"The Art of War by Sun Tzu, Chapter on Military Maneuvers","originalExcerpt":"故其疾如风，其徐如林，侵掠如火，不动如山，难知如阴，动如雷震。故倍道而兼行，千里而不劳者，行也。","storyEnglish":"In 'The Art of War' by Sun Tzu, the phrase '倍道而兼行' is used to describe the strategy of moving troops at double speed to gain a tactical advantage. It emphasizes the importance of speed and efficiency in military maneuvers, allowing an army to cover great distances without becoming fatigued.","historicalFigures":["Sun Tzu"],"relatedIdiomsFromSameSource":["疾如风","不动如山"]},"usage":{"grammaticalRole":["adverbial"],"structure":"verb-object","register":"literary, but understood in modern contexts to imply urgency or haste","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with others that imply speed but not necessarily urgency or effort, such as '一日千里'. '倍道兼行' specifically implies making an extra effort to move faster.","canStandAlone":false},"examples":[{"simplified":"为了赶上会议，我们必须倍道兼行。","english":"To make it to the meeting on time, we must travel at double speed.","traditional":"為了趕上會議，我們必須倍道兼行。"},{"simplified":"敌军倍道兼行，迅速接近我们的防线。","english":"The enemy troops are advancing rapidly, approaching our defenses at double speed.","traditional":"敵軍倍道兼行，迅速接近我們的防線。"}],"synonyms":["马不停蹄"],"antonyms":["慢条斯理"],"confusedWith":[{"id":"一日千里","note":"While '一日千里' describes rapid progress, it does not imply the same urgency or effort as '倍道兼行'."}],"traditional":"倍道兼行","pinyinOverride":null},{"id":"bi-jun-san-she","simplified":"避君三舍","literalMeaning":"avoid you three she","figurativeMeaning":"to avoid confrontation; to give way to someone out of respect or strategy","englishEquivalents":["give way","step aside","yield"],"shortGloss":"avoid confrontation","characters":[{"char":"避","meaning":"avoid"},{"char":"君","meaning":"you; a respectful term for a ruler or superior"},{"char":"三","meaning":"three"},{"char":"舍","meaning":"she; a unit of distance, approximately 30 miles"}],"origin":{"period":"Spring and Autumn period (770–476 BCE)","sourceText":"《左传·僖公二十三年》","sourceTextEnglish":"Zuo Zhuan, Duke Xi, Year 23","originalExcerpt":"晋文公曰：‘避君三舍。’","storyEnglish":"The idiom originates from a story during the Spring and Autumn period. Duke Wen of Jin, who had previously been helped by Duke Mu of Qin, decided to avoid a direct confrontation with Qin out of gratitude. He ordered his troops to retreat three she (a unit of distance) to show respect and avoid conflict. This act of yielding became known as '避君三舍'.","historicalFigures":["Duke Wen of Jin","Duke Mu of Qin"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"literary, but can be used in formal speech","connotation":"neutral","commonMistakes":"Learners sometimes confuse this idiom with expressions that imply cowardice or fear, but it actually conveys respect or strategic retreat.","canStandAlone":false},"examples":[{"simplified":"在争论中，他选择避君三舍，以免冲突升级。","english":"In the argument, he chose to step aside to prevent the conflict from escalating.","traditional":"在爭論中，他選擇避君三舍，以免衝突升級。"},{"simplified":"为了保持友好关系，公司决定避君三舍，不与对方竞争。","english":"To maintain a friendly relationship, the company decided to yield and not compete with the other party.","traditional":"為了保持友好關係，公司決定避君三舍，不與對方競爭。"}],"synonyms":["退避三舍"],"antonyms":[],"confusedWith":[{"id":"退避三舍","note":"退避三舍 is a more common variant with the same meaning, often used interchangeably."}],"traditional":"避君三舍","pinyinOverride":null},{"id":"bi-nan-jiu-yi","simplified":"避难就易","literalMeaning":"avoid difficulty, approach ease","figurativeMeaning":"to take the easy way out; to choose the path of least resistance","englishEquivalents":["take the easy way out","choose the path of least resistance"],"shortGloss":"take the easy way out","characters":[{"char":"避","meaning":"avoid"},{"char":"难","meaning":"difficulty"},{"char":"就","meaning":"approach"},{"char":"易","meaning":"ease"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '避难就易' is used to describe a situation where someone chooses the easier option rather than facing a more challenging task. It reflects a tendency to avoid difficulties and opt for a simpler, less demanding path.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"coordinate","register":"commonly used in both spoken and written Chinese","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with others that involve 'difficult' and 'easy', but this idiom specifically emphasizes the choice of an easier path over a difficult one.","canStandAlone":false},"examples":[{"simplified":"在工作中，他总是避难就易，从不愿意接受挑战。","english":"At work, he always takes the easy way out and never wants to accept challenges.","traditional":"在工作中，他總是避難就易，從不願意接受挑戰。"},{"simplified":"如果你总是避难就易，你可能会错过许多成长的机会。","english":"If you always choose the path of least resistance, you might miss many opportunities for growth.","traditional":"如果你總是避難就易，你可能會錯過許多成長的機會。"}],"synonyms":[],"antonyms":["迎难而上"],"confusedWith":[{"id":"迎难而上","note":"While '避难就易' means avoiding difficulty, '迎难而上' means to face difficulties head-on."}],"traditional":"避難就易","pinyinOverride":null},{"id":"bi-qiang-ji-ruo","simplified":"避强击弱","literalMeaning":"avoid the strong, attack the weak","figurativeMeaning":"to avoid direct confrontation with strong opponents and instead target weaker ones","englishEquivalents":["pick on the weak","hit where it hurts","choose battles wisely"],"shortGloss":"target the weak, avoid the strong","characters":[{"char":"避","meaning":"avoid"},{"char":"强","meaning":"strong"},{"char":"击","meaning":"attack"},{"char":"弱","meaning":"weak"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '避强击弱' is often used in military strategy and competitive contexts. It suggests a tactical approach where one avoids engaging with stronger opponents and instead focuses on defeating weaker ones. This strategy can be applied in various situations, from warfare to business, where it is wise to conserve resources and increase chances of success by choosing battles carefully.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["adverbial","complement"],"structure":"verb-object + verb-object","register":"commonly used in both formal and informal contexts, especially in discussions of strategy","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with '以弱胜强' (using weakness to overcome strength), which has a different meaning. '避强击弱' emphasizes avoiding strong opponents, while '以弱胜强' focuses on overcoming them despite being weaker.","canStandAlone":false},"examples":[{"simplified":"在竞争激烈的市场中，我们应该避强击弱，选择合适的目标客户。","english":"In a highly competitive market, we should avoid the strong and attack the weak by choosing suitable target customers.","traditional":"在競爭激烈的市場中，我們應該避強擊弱，選擇合適的目標客戶。"},{"simplified":"他的战术是避强击弱，专门攻击对方的薄弱环节。","english":"His tactic is to avoid the strong and attack the weak, specifically targeting the opponent's weak points.","traditional":"他的戰術是避強擊弱，專門攻擊對方的薄弱環節。"}],"synonyms":[],"antonyms":["以弱胜强"],"confusedWith":[{"id":"以弱胜强","note":"以弱胜强 means to overcome a stronger opponent with a weaker force, whereas 避强击弱 means to avoid strong opponents and target weaker ones."}],"traditional":"避強擊弱","pinyinOverride":null},{"id":"bi-shi-ji-xu","simplified":"避实击虚","literalMeaning":"avoid the solid, strike the weak","figurativeMeaning":"to avoid the strong points and attack the weak points; to choose one's battles wisely","englishEquivalents":["hit where it hurts","pick your battles"],"shortGloss":"attack the weak points","characters":[{"char":"避","meaning":"avoid"},{"char":"实","meaning":"solid; strong"},{"char":"击","meaning":"strike; attack"},{"char":"虚","meaning":"weak; empty"}],"origin":{"period":"Warring States period (475–221 BCE)","sourceText":"《孙子兵法·虚实》","sourceTextEnglish":"Sun Tzu's Art of War, Chapter on Weaknesses and Strengths","originalExcerpt":"故形人而我无形，则我专而敌分。我专为一，敌分为十，是以十攻其一也。则我众而敌寡。能以众击寡者，则吾之所与战者约矣。故善战者，求之于势，不责于人，故能择人而任势。击其无备，出其不意。","storyEnglish":"This idiom comes from Sun Tzu's 'Art of War,' where he discusses the strategy of avoiding the enemy's strong points and attacking their weak points. The idea is to be flexible and adaptable, focusing on exploiting the enemy's vulnerabilities rather than confronting their strengths directly.","historicalFigures":["Sun Tzu"],"relatedIdiomsFromSameSource":["知己知彼","以逸待劳"]},"usage":{"grammaticalRole":["adverbial","attributive"],"structure":"verb-object","register":"literary, but often used in strategic or business contexts","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with '以弱胜强', which means 'to use weakness to overcome strength,' a different concept. '避实击虚' focuses on strategic choice rather than inherent strength or weakness.","canStandAlone":false},"examples":[{"simplified":"在商业竞争中，我们应该避实击虚，寻找对手的弱点。","english":"In business competition, we should avoid the strong points and strike at the weak ones, finding our opponent's weaknesses.","traditional":"在商業競爭中，我們應該避實擊虛，尋找對手的弱點。"},{"simplified":"他在谈判中总是避实击虚，成功地达成了协议。","english":"He always avoids the strong points and strikes at the weak ones in negotiations, successfully reaching an agreement.","traditional":"他在談判中總是避實擊虛，成功地達成了協議。"}],"synonyms":["声东击西"],"antonyms":[],"confusedWith":[{"id":"以弱胜强","note":"以弱胜强 means 'to use weakness to overcome strength,' focusing on the inherent strength of the weaker party, unlike 避实击虚 which is about strategic choice."}],"traditional":"避實擊虛","pinyinOverride":null},{"id":"bi-shi-jiu-xu","simplified":"避实就虚","literalMeaning":"avoid the solid, approach the void","figurativeMeaning":"to avoid direct confrontation and instead focus on attacking weaknesses or vulnerabilities","englishEquivalents":["hit where it hurts","attack the weak points"],"shortGloss":"attack the weak points","characters":[{"char":"避","meaning":"avoid"},{"char":"实","meaning":"solid; strong"},{"char":"就","meaning":"approach; go to"},{"char":"虚","meaning":"void; weak"}],"origin":{"period":"Warring States period (475–221 BCE)","sourceText":"《孙子兵法·虚实》","sourceTextEnglish":"Sun Tzu's Art of War, Chapter on Weaknesses and Strengths","originalExcerpt":"避实而击虚。","storyEnglish":"This idiom comes from Sun Tzu's 'The Art of War', a classic military treatise. In the chapter on weaknesses and strengths, Sun Tzu advises military strategists to avoid engaging the enemy's strong points and instead focus on attacking their weaknesses. This strategy emphasizes the importance of flexibility and adaptability in warfare.","historicalFigures":["Sun Tzu"],"relatedIdiomsFromSameSource":["知己知彼","百战不殆"]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"literary, but widely understood and used in strategic contexts","connotation":"neutral","commonMistakes":"Learners often confuse this idiom with general avoidance strategies, but it specifically refers to a tactical approach of targeting weaknesses rather than avoiding conflict altogether.","canStandAlone":false},"examples":[{"simplified":"在谈判中，我们应该避实就虚，找出对方的弱点。","english":"In negotiations, we should avoid direct confrontation and find the opponent's weaknesses.","traditional":"在談判中，我們應該避實就虛，找出對方的弱點。"},{"simplified":"他在比赛中避实就虚，最终赢得了胜利。","english":"He attacked the weak points in the match and eventually won.","traditional":"他在比賽中避實就虛，最終贏得了勝利。"}],"synonyms":["攻其不备"],"antonyms":[],"confusedWith":[{"id":"避重就轻","note":"避重就轻 refers to avoiding difficult tasks and choosing easier ones, not specifically about strategic attacks."}],"traditional":"避實就虛","pinyinOverride":null},{"id":"bi-su-qu-xin","simplified":"避俗趋新","literalMeaning":"avoid the old customs and pursue the new","figurativeMeaning":"to abandon old conventions in favor of new trends or ideas","englishEquivalents":["out with the old, in with the new"],"shortGloss":"abandon old customs for new trends","characters":[{"char":"避","meaning":"avoid"},{"char":"俗","meaning":"customs; conventions"},{"char":"趋","meaning":"pursue; move towards"},{"char":"新","meaning":"new"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '避俗趋新' reflects a mindset of moving away from traditional customs and embracing new ideas or trends. It is often used to describe people or societies that are eager to innovate and adapt to changing times, leaving behind outdated practices.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["adverbial","attributive"],"structure":"coordinate","register":"commonly used in both written and spoken Chinese to describe a progressive attitude","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with similar expressions that emphasize rejecting traditions entirely, but '避俗趋新' does not necessarily imply a negative view of old customs, just a preference for new ones.","canStandAlone":false},"examples":[{"simplified":"年轻人往往避俗趋新，喜欢尝试新的事物。","english":"Young people often abandon old customs in favor of new ones and like to try new things.","traditional":"年輕人往往避俗趨新，喜歡嘗試新的事物。"},{"simplified":"在这个快速变化的时代，企业必须避俗趋新才能保持竞争力。","english":"In this rapidly changing era, companies must abandon old customs and embrace new trends to remain competitive.","traditional":"在這個快速變化的時代，企業必須避俗趨新才能保持競爭力。"}],"synonyms":[],"antonyms":[],"confusedWith":[],"traditional":"避俗趨新","pinyinOverride":null},{"id":"bi-xiong-qu-ji","simplified":"避凶趋吉","literalMeaning":"avoid misfortune, pursue fortune","figurativeMeaning":"to avoid danger and seek safety or good fortune","englishEquivalents":["steer clear of trouble","seek the good and avoid the bad"],"shortGloss":"avoid danger, seek fortune","characters":[{"char":"避","meaning":"avoid"},{"char":"凶","meaning":"misfortune, danger"},{"char":"趋","meaning":"pursue, move towards"},{"char":"吉","meaning":"good fortune, auspiciousness"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '避凶趋吉' reflects a common human desire to avoid danger and seek out favorable circumstances. It is often used to describe actions or strategies that aim to minimize risk and maximize positive outcomes. The phrase is not attributed to a specific historical text but is a concept that has been prevalent in Chinese culture and philosophy.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"coordinate","register":"commonly used in both formal and informal contexts","connotation":"positive","commonMistakes":"Learners might confuse this idiom with similar expressions that involve risk management, but '避凶趋吉' specifically emphasizes the dual action of avoiding danger and seeking fortune, not just risk avoidance.","canStandAlone":false},"examples":[{"simplified":"在投资时，我们应该避凶趋吉，选择风险较小的项目。","english":"When investing, we should avoid danger and seek fortune by choosing projects with lower risks.","traditional":"在投資時，我們應該避凶趨吉，選擇風險較小的項目。"},{"simplified":"他总是避凶趋吉，避免参与有争议的活动。","english":"He always avoids danger and seeks fortune by steering clear of controversial activities.","traditional":"他總是避凶趨吉，避免參與有爭議的活動。"}],"synonyms":[],"antonyms":[],"confusedWith":[],"traditional":"避凶趨吉","pinyinOverride":null},{"id":"bi-he-zhu-lian","simplified":"璧合珠连","literalMeaning":"jade joined, pearls linked","figurativeMeaning":"a perfect match or harmonious union","englishEquivalents":["a match made in heaven","perfectly matched","a harmonious union"],"shortGloss":"a perfect match","characters":[{"char":"璧","meaning":"jade"},{"char":"合","meaning":"join"},{"char":"珠","meaning":"pearls"},{"char":"连","meaning":"link"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom 璧合珠连 is often used to describe a perfect match or harmonious union, especially in the context of marriage or partnerships. The imagery of jade and pearls, both precious and beautiful, symbolizes the idea of two valuable elements coming together seamlessly.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["attributive","predicate"],"structure":"coordinate","register":"literary, but can be used in formal speech and writing","connotation":"positive","commonMistakes":"Learners might confuse this idiom with others that involve '合' or '连', but this idiom specifically emphasizes the idea of a perfect match or union, often in a positive and harmonious context.","canStandAlone":false},"examples":[{"simplified":"他们俩真是璧合珠连，天生一对。","english":"They are truly a perfect match, a pair made in heaven.","traditional":"他們倆真是璧合珠連，天生一對。"},{"simplified":"这两家公司合作得非常好，简直是璧合珠连。","english":"These two companies work together so well, they are a perfect match.","traditional":"這兩家公司合作得非常好，簡直是璧合珠連。"}],"synonyms":["天作之合","珠联璧合"],"antonyms":[],"confusedWith":[{"id":"珠联璧合","note":"Both idioms describe a perfect match, but 璧合珠连 is less commonly used."}],"traditional":"璧合珠連","pinyinOverride":null},{"id":"bian-bu-ji-fu","simplified":"鞭不及腹","literalMeaning":"whip does not reach the belly","figurativeMeaning":"unable to reach or affect the core issue","englishEquivalents":["can't hit the mark","miss the point"],"shortGloss":"unable to reach the core issue","characters":[{"char":"鞭","meaning":"whip"},{"char":"不","meaning":"not"},{"char":"及","meaning":"reach"},{"char":"腹","meaning":"belly"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '鞭不及腹' is used to describe a situation where efforts or actions fail to address the most important or central part of a problem. The imagery of a whip not reaching the belly suggests that the action is ineffective or misdirected, unable to impact the core issue.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"literary, but can be used in formal speech or writing","connotation":"negative","commonMistakes":"Learners might confuse this idiom with others that imply ineffectiveness, but '鞭不及腹' specifically emphasizes the failure to address the core issue, not just general ineffectiveness.","canStandAlone":false},"examples":[{"simplified":"他的建议鞭不及腹，无法解决真正的问题。","english":"His suggestion fails to address the core issue and cannot solve the real problem.","traditional":"他的建議鞭不及腹，無法解決真正的問題。"},{"simplified":"如果不深入分析，这些措施可能鞭不及腹。","english":"Without in-depth analysis, these measures might miss the core issue.","traditional":"如果不深入分析，這些措施可能鞭不及腹。"}],"synonyms":[],"antonyms":[],"confusedWith":[],"traditional":"鞭不及腹","pinyinOverride":null},{"id":"bian-chang-bu-ji","simplified":"鞭长不及","literalMeaning":"the whip is long but doesn't reach","figurativeMeaning":"unable to exert influence or control due to distance or limitations","englishEquivalents":["out of reach","beyond one's grasp"],"shortGloss":"unable to reach or control","characters":[{"char":"鞭","meaning":"whip"},{"char":"长","meaning":"long"},{"char":"不","meaning":"not"},{"char":"及","meaning":"reach"}],"origin":{"period":"Han Dynasty (202 BCE – 220 CE)","sourceText":"《汉书·王莽传》","sourceTextEnglish":"Book of Han, Biography of Wang Mang","originalExcerpt":"鞭长不及，势不能也。","storyEnglish":"The phrase comes from a passage in the 'Book of Han', describing a situation where despite having resources or power, one is unable to exert influence due to distance or other limitations. It metaphorically compares the situation to having a long whip that still cannot reach the target.","historicalFigures":["Wang Mang"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"subject-predicate","register":"literary, but can be used in formal speech","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with others that imply lack of ability or power, rather than the specific idea of limitations due to distance or reach.","canStandAlone":false},"examples":[{"simplified":"虽然他在公司有很高的职位，但在这个问题上鞭长不及。","english":"Although he holds a high position in the company, he is unable to influence this issue.","traditional":"雖然他在公司有很高的職位，但在這個問題上鞭長不及。"},{"simplified":"他们想帮助远方的朋友，但鞭长不及。","english":"They wanted to help their friend far away, but it was beyond their reach.","traditional":"他們想幫助遠方的朋友，但鞭長不及。"}],"synonyms":[],"antonyms":[],"confusedWith":[{"id":"力不从心","note":"力不从心 refers to having the desire but not the ability to act, while 鞭长不及 specifically involves limitations due to distance or reach."}],"traditional":"鞭長不及","pinyinOverride":null},{"id":"biao-li-bu-yi","simplified":"表里不一","literalMeaning":"outside and inside not the same","figurativeMeaning":"to be hypocritical or insincere; to say one thing and do another","englishEquivalents":["two-faced","hypocritical","not what it seems"],"shortGloss":"hypocritical or insincere","characters":[{"char":"表","meaning":"outside; surface"},{"char":"里","meaning":"inside; inner"},{"char":"不","meaning":"not"},{"char":"一","meaning":"one; the same"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '表里不一' describes a situation where someone's outward appearance or statements do not match their true intentions or feelings. It is often used to criticize someone who is deceitful or hypocritical, presenting a false front to others.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"modifier-head","register":"commonly used in both formal and informal contexts","connotation":"negative","commonMistakes":"Learners often confuse this idiom with 表里如一, which means being consistent inside and out, the opposite of 表里不一. It's important to note the negative connotation of 表里不一.","canStandAlone":false},"examples":[{"simplified":"他这个人表里不一，不能轻信他的话。","english":"He is a person who is hypocritical; you can't trust what he says.","traditional":"他這個人表裡不一，不能輕信他的話。"},{"simplified":"这家公司表里不一，表面上说要环保，实际上却在污染环境。","english":"This company is hypocritical; they claim to be environmentally friendly, but in reality, they are polluting the environment.","traditional":"這家公司表裡不一，表面上說要環保，實際上卻在汙染環境。"}],"synonyms":["口是心非"],"antonyms":["表里如一"],"confusedWith":[{"id":"表里如一","note":"表里如一 means being consistent inside and out, which is the opposite of 表里不一."}],"traditional":"表裡不一","pinyinOverride":null},{"id":"biao-li-xiang-fu","simplified":"表里相符","literalMeaning":"exterior and interior match","figurativeMeaning":"to be consistent inside and out; to be genuine and sincere","englishEquivalents":["what you see is what you get","true to oneself"],"shortGloss":"consistent inside and out","characters":[{"char":"表","meaning":"exterior, surface"},{"char":"里","meaning":"interior, inside"},{"char":"相","meaning":"mutually, each other"},{"char":"符","meaning":"match, correspond"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '表里相符' emphasizes the importance of consistency between one's outward appearance and inner character. It is often used to describe people who are genuine and sincere, with no hidden agendas or deceit. The phrase suggests that what is visible on the outside should accurately reflect what is on the inside.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"modifier-head","register":"commonly used in both written and spoken Chinese to describe sincerity and genuineness","connotation":"positive","commonMistakes":"Learners might confuse this idiom with others that involve appearance, such as '表里不一', which means the exterior and interior do not match. It's important to note that '表里相符' has a positive connotation of sincerity.","canStandAlone":false},"examples":[{"simplified":"他是一个表里相符的人，值得信任。","english":"He is a person who is consistent inside and out, and is worthy of trust.","traditional":"他是一個表裡相符的人，值得信任。"},{"simplified":"在这个公司，表里相符的员工很受欢迎。","english":"In this company, employees who are genuine and sincere are very popular.","traditional":"在這個公司，表裡相符的員工很受歡迎。"}],"synonyms":["言行一致"],"antonyms":["表里不一"],"confusedWith":[{"id":"表里不一","note":"表里不一 means the exterior and interior do not match, implying deceit or inconsistency."}],"traditional":"表裡相符","pinyinOverride":null},{"id":"biao-li-yi-zhi","simplified":"表里一致","literalMeaning":"exterior and interior are consistent","figurativeMeaning":"to be consistent in one's words and actions; to be genuine and sincere","englishEquivalents":["what you see is what you get","true to one's word"],"shortGloss":"consistent inside and out","characters":[{"char":"表","meaning":"exterior; outward appearance"},{"char":"里","meaning":"interior; inner self"},{"char":"一","meaning":"one; consistent"},{"char":"致","meaning":"consistent; in agreement"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom 表里一致 is used to describe someone whose external actions and internal beliefs are in harmony. It emphasizes the importance of sincerity and integrity, suggesting that a person's outward behavior should reflect their true inner feelings and intentions.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"modifier-head","register":"commonly used in both formal and informal contexts","connotation":"positive","commonMistakes":"Learners might confuse 表里一致 with 表面功夫 (superficial effort), which has a negative connotation. 表里一致 implies genuine consistency, not just a facade.","canStandAlone":false},"examples":[{"simplified":"他是一个表里一致的人，值得信任。","english":"He is a person who is consistent inside and out, worthy of trust.","traditional":"他是一個表裡一致的人，值得信任。"},{"simplified":"在商业中，表里一致的公司更容易赢得客户的信任。","english":"In business, companies that are consistent inside and out are more likely to earn customers' trust.","traditional":"在商業中，表裡一致的公司更容易贏得客戶的信任。"}],"synonyms":["言行一致"],"antonyms":["口是心非"],"confusedWith":[{"id":"表面功夫","note":"表面功夫 refers to superficial effort, which is the opposite of genuine consistency."}],"traditional":"表裡一致","pinyinOverride":null},{"id":"bie-chu-xin-yi","simplified":"别出新意","literalMeaning":"depart to create new ideas","figurativeMeaning":"to come up with original ideas; to be creative and innovative","englishEquivalents":["think outside the box","break new ground"],"shortGloss":"to be creative and innovative","characters":[{"char":"别","meaning":"depart; different"},{"char":"出","meaning":"come up with; produce"},{"char":"新","meaning":"new"},{"char":"意","meaning":"idea; meaning"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '别出新意' is used to describe someone who is able to think creatively and come up with new ideas. It is often used to praise individuals who break away from conventional thinking and introduce innovative concepts. The phrase emphasizes the value of originality and the courage to be different.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"commonly used in both written and spoken Chinese to praise creativity","connotation":"positive","commonMistakes":"Learners might confuse this idiom with '标新立异', which also means to be different but often implies doing so for the sake of being different, sometimes with a negative connotation.","canStandAlone":false},"examples":[{"simplified":"他的设计总是别出新意，让人耳目一新。","english":"His designs always come up with new ideas, making people feel refreshed.","traditional":"他的設計總是別出新意，讓人耳目一新。"},{"simplified":"在这次比赛中，她别出新意，赢得了评委的赞赏。","english":"In this competition, she came up with original ideas and won the judges' praise.","traditional":"在這次比賽中，她別出新意，贏得了評委的讚賞。"}],"synonyms":["标新立异"],"antonyms":[],"confusedWith":[{"id":"标新立异","note":"While both idioms involve being different, '标新立异' can imply being different for the sake of it, sometimes negatively."}],"traditional":"別出新意","pinyinOverride":null},{"id":"bie-ju-hui-yan","simplified":"别具慧眼","literalMeaning":"possess unique discerning eyes","figurativeMeaning":"to have a keen eye; to have a unique insight or perspective","englishEquivalents":["to have an eye for something","to see what others do not"],"shortGloss":"have a keen eye for detail","characters":[{"char":"别","meaning":"unique; different"},{"char":"具","meaning":"possess; have"},{"char":"慧","meaning":"wisdom; intelligence"},{"char":"眼","meaning":"eye"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom 别具慧眼 is believed to have originated from the idea that some people possess a unique ability to see things that others might overlook. This keen insight or perspective allows them to notice details or understand situations in a way that is not common. The phrase is often used to praise someone's perceptiveness or ability to discern important aspects in complex situations.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"modifier-head","register":"commonly used in both written and spoken Chinese to praise someone's insight or perceptiveness","connotation":"positive","commonMistakes":"Learners might confuse 别具慧眼 with similar idioms that involve wisdom or insight, but this idiom specifically emphasizes having a unique or keen perspective. It's important to use it in contexts where someone's ability to see or understand something is notably different from the norm.","canStandAlone":false},"examples":[{"simplified":"他在艺术品鉴赏方面别具慧眼。","english":"He has a keen eye for appreciating art.","traditional":"他在藝術品鑑賞方面別具慧眼。"},{"simplified":"她对市场趋势的分析总是别具慧眼。","english":"Her analysis of market trends always shows unique insight.","traditional":"她對市場趨勢的分析總是別具慧眼。"}],"synonyms":["独具慧眼"],"antonyms":[],"confusedWith":[{"id":"独具匠心","note":"独具匠心 emphasizes unique creativity or craftsmanship, while 别具慧眼 focuses on insight or perception."}],"traditional":"別具慧眼","pinyinOverride":null},{"id":"bie-lai-wu-yang","simplified":"别来无恙","literalMeaning":"since parting, no ailments","figurativeMeaning":"I hope you have been well since we last met","englishEquivalents":["I hope you are well","I trust you have been well"],"shortGloss":"hope you've been well","characters":[{"char":"别","meaning":"parting"},{"char":"来","meaning":"since"},{"char":"无","meaning":"no"},{"char":"恙","meaning":"ailments"}],"origin":{"period":"Han Dynasty (206 BCE – 220 CE)","sourceText":"《汉书·苏武传》","sourceTextEnglish":"Book of Han, Biography of Su Wu","originalExcerpt":"子卿尚复为汉使，久别离无恙。","storyEnglish":"The idiom originates from the 'Book of Han', specifically the biography of Su Wu, a Han dynasty diplomat. Su Wu was sent on a mission to the Xiongnu and was detained for many years. Upon his return, he was greeted with the phrase, expressing the hope that he had remained in good health despite the long separation.","historicalFigures":["Su Wu"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","standalone-exclamation"],"structure":"subject-predicate","register":"literary, but commonly used in both written and spoken Chinese as a polite inquiry","connotation":"positive","commonMistakes":"Learners might confuse this idiom with expressions of farewell, but it is actually used to inquire about someone's well-being after a separation. It is not used when saying goodbye.","canStandAlone":true},"examples":[{"simplified":"好久不见，别来无恙？","english":"Long time no see, have you been well?","traditional":"好久不見，別來無恙？"},{"simplified":"信中写道：“别来无恙，盼复。”","english":"The letter read: 'I hope you have been well since we last met, looking forward to your reply.'","traditional":"信中寫道：“別來無恙，盼復。”"}],"synonyms":[],"antonyms":[],"confusedWith":[],"traditional":"別來無恙","pinyinOverride":null},{"id":"bie-shu-yi-zhi","simplified":"别树一帜","literalMeaning":"another tree, one banner","figurativeMeaning":"to develop a style of one's own; to create a unique path or approach","englishEquivalents":["carve out a niche","blaze a new trail"],"shortGloss":"create a unique style or path","characters":[{"char":"别","meaning":"another, different"},{"char":"树","meaning":"tree"},{"char":"一","meaning":"one"},{"char":"帜","meaning":"banner, flag"}],"origin":{"period":"Southern and Northern Dynasties (420–589)","sourceText":"《南齐书·王敬则传》","sourceTextEnglish":"Book of Southern Qi, Biography of Wang Jingze","originalExcerpt":"王敬则曰：“我虽不才，亦足以别树一帜。”","storyEnglish":"The phrase comes from a statement by Wang Jingze, a general during the Southern Qi dynasty. He expressed his confidence in his ability to establish a unique and independent position or style, despite not being particularly talented. The idiom has since come to mean creating a distinct path or style that sets one apart from others.","historicalFigures":["Wang Jingze"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"literary, but widely used in both formal and informal contexts","connotation":"positive","commonMistakes":"Learners often confuse this idiom with those that mean 'to stand out' in a more general sense. 别树一帜 specifically emphasizes creating a unique style or path, not just being different.","canStandAlone":false},"examples":[{"simplified":"这位艺术家在现代画坛上别树一帜。","english":"This artist has carved out a niche in the modern art world.","traditional":"這位藝術家在現代畫壇上別樹一幟。"},{"simplified":"他在音乐创作上别树一帜，形成了独特的风格。","english":"He has blazed a new trail in music composition, forming a unique style.","traditional":"他在音樂創作上別樹一幟，形成了獨特的風格。"}],"synonyms":["独树一帜"],"antonyms":[],"confusedWith":[{"id":"与众不同","note":"与众不同 means 'to be different from others' in a general sense, without the specific connotation of creating a unique style."}],"traditional":"別樹一幟","pinyinOverride":null},{"id":"bie-wu-er-zhi","simplified":"别无二致","literalMeaning":"no second difference","figurativeMeaning":"exactly the same; no different","englishEquivalents":["no different","exactly the same"],"shortGloss":"exactly the same","characters":[{"char":"别","meaning":"other"},{"char":"无","meaning":"no"},{"char":"二","meaning":"two; second"},{"char":"致","meaning":"difference"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '别无二致' is used to express that two things are exactly the same, with no differences between them. The phrase is often used in contexts where comparisons are made, emphasizing that the items being compared are indistinguishable in terms of quality, appearance, or other attributes.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"modifier-head","register":"commonly used in both written and spoken Chinese","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with expressions that imply minor differences. '别无二致' means there are no differences at all, not even minor ones.","canStandAlone":false},"examples":[{"simplified":"这两幅画看起来别无二致。","english":"These two paintings look exactly the same.","traditional":"這兩幅畫看起來別無二致。"},{"simplified":"虽然是不同品牌的产品，但质量上别无二致。","english":"Although they are products from different brands, there is no difference in quality.","traditional":"雖然是不同品牌的產品，但質量上別無二致。"}],"synonyms":["一模一样"],"antonyms":["截然不同"],"confusedWith":[{"id":"大同小异","note":"大同小异 means 'largely the same with minor differences', whereas 别无二致 means 'exactly the same'."}],"traditional":"別無二致","pinyinOverride":null},{"id":"bie-you-xin-chang","simplified":"别有心肠","literalMeaning":"have another heart","figurativeMeaning":"to have ulterior motives or hidden intentions","englishEquivalents":["have an axe to grind","have a hidden agenda"],"shortGloss":"ulterior motives","characters":[{"char":"别","meaning":"other; different"},{"char":"有","meaning":"have; possess"},{"char":"心","meaning":"heart; intention"},{"char":"肠","meaning":"intestines; metaphorically refers to feelings or intentions"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '别有心肠' is used to describe someone who harbors hidden intentions or ulterior motives. It suggests that the person's true feelings or plans are not openly expressed, and they may have a secret agenda. The phrase is often used in contexts where trust is questioned, or where someone's sincerity is doubted.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"modifier-head","register":"commonly used in both written and spoken Chinese, often in contexts involving suspicion or caution","connotation":"negative","commonMistakes":"Learners might confuse '别有心肠' with '别有用心', which also means having ulterior motives but is more commonly used. '别有心肠' specifically emphasizes the emotional or heartfelt aspect of hidden intentions.","canStandAlone":false},"examples":[{"simplified":"他看起来很友好，但我觉得他别有心肠。","english":"He seems very friendly, but I think he has ulterior motives.","traditional":"他看起來很友好，但我覺得他別有心腸。"},{"simplified":"在这个项目中，我们必须小心那些别有心肠的人。","english":"In this project, we must be cautious of those with hidden intentions.","traditional":"在這個項目中，我們必須小心那些別有心腸的人。"}],"synonyms":["别有用心"],"antonyms":[],"confusedWith":[{"id":"别有用心","note":"Both idioms refer to having ulterior motives, but '别有用心' is more commonly used and focuses on the intention rather than the emotional aspect."}],"traditional":"別有心腸","pinyinOverride":null},{"id":"bing-gong-wu-si","simplified":"秉公无私","literalMeaning":"uphold fairness without selfishness","figurativeMeaning":"to act impartially and selflessly","englishEquivalents":["fair and just","impartial and selfless"],"shortGloss":"impartial and selfless","characters":[{"char":"秉","meaning":"uphold; maintain"},{"char":"公","meaning":"fairness; justice"},{"char":"无","meaning":"without"},{"char":"私","meaning":"selfishness; personal interest"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '秉公无私' emphasizes the importance of acting with fairness and without personal bias. It is often used to describe someone who makes decisions based on justice and the common good, rather than personal gain. The phrase likely developed over time to encapsulate the ideal of impartiality in governance and personal conduct.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"coordinate","register":"formal written Chinese, but also used in speech to praise someone's fairness","connotation":"positive","commonMistakes":"Learners might confuse this idiom with similar phrases that imply fairness but do not emphasize the absence of selfishness. It's important to note that '无私' specifically highlights the lack of personal interest.","canStandAlone":false},"examples":[{"simplified":"他在处理这件事情时，秉公无私，得到了大家的赞赏。","english":"He handled the matter impartially and selflessly, earning everyone's praise.","traditional":"他在處理這件事情時，秉公無私，得到了大家的讚賞。"},{"simplified":"作为法官，他必须秉公无私地做出判决。","english":"As a judge, he must make decisions impartially and selflessly.","traditional":"作為法官，他必須秉公無私地做出判決。"}],"synonyms":["公正无私","铁面无私"],"antonyms":["徇私舞弊","偏袒"],"confusedWith":[{"id":"公正无私","note":"While both idioms emphasize fairness, '秉公无私' specifically highlights the act of upholding justice without personal interest."}],"traditional":"秉公無私","pinyinOverride":null},{"id":"bo-zui-liao-ya","simplified":"拨嘴撩牙","literalMeaning":"poke mouth tease teeth","figurativeMeaning":"to be argumentative or quarrelsome","englishEquivalents":["to pick a fight","to be argumentative"],"shortGloss":"to be quarrelsome","characters":[{"char":"拨","meaning":"poke"},{"char":"嘴","meaning":"mouth"},{"char":"撩","meaning":"tease"},{"char":"牙","meaning":"teeth"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '拨嘴撩牙' is believed to have originated from a folk expression describing someone who is unnecessarily argumentative, as if they are poking at someone's mouth and teasing their teeth to provoke a reaction.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"coordinate","register":"informal, commonly used in spoken Chinese","connotation":"negative","commonMistakes":"Learners often confuse this idiom with others that imply being talkative rather than specifically argumentative. It's important to note that this idiom carries a negative connotation of provoking disputes.","canStandAlone":false},"examples":[{"simplified":"他总是拨嘴撩牙，大家都不愿意和他争论。","english":"He is always argumentative, so no one wants to debate with him.","traditional":"他總是撥嘴撩牙，大家都不願意和他爭論。"},{"simplified":"在会议上，她不应该拨嘴撩牙，这只会让事情更复杂。","english":"She shouldn't be quarrelsome at the meeting; it will only complicate matters.","traditional":"在會議上，她不應該撥嘴撩牙，這隻會讓事情更復雜。"}],"synonyms":["斤斤计较"],"antonyms":["和颜悦色"],"confusedWith":[{"id":"多嘴多舌","note":"多嘴多舌 means to be talkative or to speak out of turn, without the argumentative aspect of 拨嘴撩牙."}],"traditional":"撥嘴撩牙","pinyinOverride":null},{"id":"bo-jian-chou-si","simplified":"剥茧抽丝","literalMeaning":"peel cocoon, draw silk","figurativeMeaning":"to unravel a complex problem step by step","englishEquivalents":["unravel a mystery","get to the bottom of it"],"shortGloss":"unravel a complex problem","characters":[{"char":"剥","meaning":"peel"},{"char":"茧","meaning":"cocoon"},{"char":"抽","meaning":"draw"},{"char":"丝","meaning":"silk"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '剥茧抽丝' likens the process of solving a complex problem to the careful and methodical process of peeling away a cocoon to draw out the silk thread. Just as one must be patient and precise to avoid breaking the silk, one must also approach complex problems with a step-by-step method to reach a solution.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["adverbial","attributive"],"structure":"verb-object","register":"commonly used in both written and spoken Chinese, especially in contexts involving problem-solving or analysis","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with those that imply quick or easy solutions, but '剥茧抽丝' emphasizes a methodical and patient approach. It is not suitable for situations where a quick fix is possible.","canStandAlone":false},"examples":[{"simplified":"解决这个复杂的问题需要剥茧抽丝的耐心。","english":"Solving this complex problem requires the patience of unraveling a cocoon.","traditional":"解決這個複雜的問題需要剝繭抽絲的耐心。"},{"simplified":"在调查过程中，我们必须剥茧抽丝，一步步分析每个细节。","english":"During the investigation, we must unravel the details step by step.","traditional":"在調查過程中，我們必須剝繭抽絲，一步步分析每個細節。"}],"synonyms":["抽丝剥茧"],"antonyms":[],"confusedWith":[],"traditional":"剝繭抽絲","pinyinOverride":null},{"id":"bo-pi-chou-jin","simplified":"剥皮抽筋","literalMeaning":"skin peeled, tendons pulled","figurativeMeaning":"to ruthlessly exploit or torment someone","englishEquivalents":["to skin alive","to bleed someone dry"],"shortGloss":"ruthlessly exploit or torment","characters":[{"char":"剥","meaning":"peel"},{"char":"皮","meaning":"skin"},{"char":"抽","meaning":"pull"},{"char":"筋","meaning":"tendons"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '剥皮抽筋' is often used to describe situations where someone is subjected to extreme exploitation or torment, akin to the literal and gruesome imagery of having one's skin peeled and tendons pulled. It is not tied to a specific historical story but rather conveys the severity of such actions metaphorically.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","object"],"structure":"verb-object","register":"informal, often used in speech to express strong disapproval","connotation":"negative","commonMistakes":"Learners might confuse this idiom with similar expressions involving punishment or suffering, but it specifically implies extreme and ruthless exploitation. It's important not to use it lightly, as it carries a strong negative connotation.","canStandAlone":false},"examples":[{"simplified":"他对员工剥皮抽筋，完全不顾他们的感受。","english":"He ruthlessly exploits his employees, completely disregarding their feelings.","traditional":"他對員工剝皮抽筋，完全不顧他們的感受。"},{"simplified":"这种公司只会剥皮抽筋，根本不关心员工的福利。","english":"This kind of company only exploits its employees and doesn't care about their welfare at all.","traditional":"這種公司只會剝皮抽筋，根本不關心員工的福利。"}],"synonyms":[],"antonyms":[],"confusedWith":[],"traditional":"剝皮抽筋","pinyinOverride":null},{"id":"bo-zhong-shu-ji","simplified":"伯仲叔季","literalMeaning":"eldest, second, third, youngest","figurativeMeaning":"ranking or order of siblings, often used to describe things or people of similar status or quality","englishEquivalents":["first among equals","rank and file"],"shortGloss":"order of siblings or equals","characters":[{"char":"伯","meaning":"eldest brother"},{"char":"仲","meaning":"second brother"},{"char":"叔","meaning":"third brother"},{"char":"季","meaning":"youngest brother"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '伯仲叔季' refers to the traditional order of brothers in a family, from the eldest to the youngest. In ancient Chinese society, this order was significant in determining responsibilities and inheritance. Over time, the idiom has come to be used more broadly to describe the ranking or order of things or people that are of similar status or quality.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["attributive"],"structure":"coordinate","register":"literary, but understood in educated speech","connotation":"neutral","commonMistakes":"Learners might mistakenly use this idiom to imply a strict hierarchy rather than a general order or ranking among equals. It is often confused with idioms that imply superiority or inferiority.","canStandAlone":false},"examples":[{"simplified":"在这次比赛中，他们的表现不相上下，真是伯仲叔季。","english":"In this competition, their performances were equally matched, truly first among equals.","traditional":"在這次比賽中，他們的表現不相上下，真是伯仲叔季。"},{"simplified":"这几位作家的作品水平相当，可以说是伯仲叔季。","english":"The works of these writers are of similar quality, you could say they are first among equals.","traditional":"這幾位作家的作品水平相當，可以說是伯仲叔季。"}],"synonyms":[],"antonyms":[],"confusedWith":[{"id":"不相上下","note":"While both idioms imply equality, '不相上下' more directly means 'equally matched' without the connotation of order or ranking."}],"traditional":"伯仲叔季","pinyinOverride":null},{"id":"bo-zhong-zhi-jian","simplified":"伯仲之间","literalMeaning":"between elder and younger brothers","figurativeMeaning":"to be almost equal; to be on par with each other","englishEquivalents":["neck and neck","on par","almost equal"],"shortGloss":"almost equal in ability or status","characters":[{"char":"伯","meaning":"elder brother"},{"char":"仲","meaning":"younger brother"},{"char":"之","meaning":"of; between"},{"char":"间","meaning":"between; among"}],"origin":{"period":"Warring States period (475–221 BCE)","sourceText":"《庄子·齐物论》","sourceTextEnglish":"Zhuangzi, Chapter Qi Wu Lun","originalExcerpt":"且夫水之积也不厚，则其负大舟也无力。覆杯水于坳堂之上，则芥为之舟；置杯焉则胶，水浅而舟大也。风之积也不厚，则其负大翼也无力。故九万里，则风斯在下矣，而后乃今培风；背负青天而莫之夭阏者，而后乃今将图南。且适南冥者，三餐而反，腹犹果然。彼其于世，伯仲之间也。","storyEnglish":"The phrase originates from the 'Zhuangzi', where it is used to describe things that are so close in comparison that they are like elder and younger brothers. In the text, it is used to illustrate the idea that some things are so similar in their essence that they are indistinguishable in terms of superiority or inferiority.","historicalFigures":["Zhuangzi"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["adverbial","attributive"],"structure":"modifier-head","register":"literary, but understood and used in formal contexts","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with expressions that imply a clear winner or superior, but 伯仲之间 specifically emphasizes equality or near equality.","canStandAlone":false},"examples":[{"simplified":"这两位选手的实力伯仲之间，很难预测谁会赢。","english":"The abilities of these two competitors are almost equal, making it difficult to predict who will win.","traditional":"這兩位選手的實力伯仲之間，很難預測誰會贏。"},{"simplified":"他们的作品质量伯仲之间，评委们很难做出决定。","english":"The quality of their works is almost equal, making it hard for the judges to decide.","traditional":"他們的作品質量伯仲之間，評委們很難做出決定。"}],"synonyms":["不相上下"],"antonyms":["天壤之别"],"confusedWith":[{"id":"不分上下","note":"Both idioms imply equality, but 不分上下 is more commonly used in everyday language to describe situations where there is no clear superior."}],"traditional":"伯仲之間","pinyinOverride":null},{"id":"bo-cai-zhong-yi","simplified":"博采众议","literalMeaning":"extensively gather various opinions","figurativeMeaning":"to consider a wide range of opinions or suggestions","englishEquivalents":["take counsel from all quarters","consider all viewpoints"],"shortGloss":"consider diverse opinions","characters":[{"char":"博","meaning":"extensively, broadly"},{"char":"采","meaning":"gather, collect"},{"char":"众","meaning":"many, various"},{"char":"议","meaning":"opinions, discussions"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '博采众议' emphasizes the importance of considering a wide range of opinions and suggestions before making a decision. It reflects a democratic approach to decision-making, where diverse perspectives are valued and taken into account.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["object","adverbial"],"structure":"verb-object","register":"commonly used in both formal and informal contexts","connotation":"positive","commonMistakes":"Learners might confuse this idiom with those that imply indecisiveness, but '博采众议' specifically suggests a thorough and thoughtful consideration of various opinions, not a lack of decision.","canStandAlone":false},"examples":[{"simplified":"在制定新政策之前，我们应该博采众议。","english":"Before formulating new policies, we should consider a wide range of opinions.","traditional":"在制定新政策之前，我們應該博採眾議。"},{"simplified":"他总是博采众议，以确保做出最好的决定。","english":"He always considers diverse opinions to ensure he makes the best decision.","traditional":"他總是博採眾議，以確保做出最好的決定。"}],"synonyms":["集思广益"],"antonyms":[],"confusedWith":[{"id":"优柔寡断","note":"优柔寡断 means indecisive or hesitant, whereas 博采众议 emphasizes thorough consideration of opinions."}],"traditional":"博採眾議","pinyinOverride":null},{"id":"bo-lan-gu-jin","simplified":"博览古今","literalMeaning":"extensively read ancient and modern","figurativeMeaning":"well-read and knowledgeable about both ancient and modern subjects","englishEquivalents":["well-read","erudite","versed in history"],"shortGloss":"well-read and knowledgeable","characters":[{"char":"博","meaning":"extensive; broad"},{"char":"览","meaning":"read; peruse"},{"char":"古","meaning":"ancient; old"},{"char":"今","meaning":"modern; present"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '博览古今' is used to describe someone who is extensively read and knowledgeable about both ancient and modern subjects. It emphasizes a breadth of knowledge across different time periods, suggesting that the person has a deep understanding of history and contemporary matters.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["attributive","predicate"],"structure":"modifier-head","register":"formal, often used in written contexts to describe scholars or intellectuals","connotation":"positive","commonMistakes":"Learners might confuse this idiom with others that emphasize depth over breadth of knowledge. It's important to use it when highlighting someone's wide-ranging knowledge across time periods.","canStandAlone":false},"examples":[{"simplified":"他是一位博览古今的学者，对历史和现代科学都有深入的研究。","english":"He is a scholar well-read in both ancient and modern subjects, with deep research in history and modern science.","traditional":"他是一位博覽古今的學者，對歷史和現代科學都有深入的研究。"},{"simplified":"要成为博览古今的人，需要不断地学习和积累知识。","english":"To become a person well-read in ancient and modern subjects, one needs to continuously learn and accumulate knowledge.","traditional":"要成為博覽古今的人，需要不斷地學習和積累知識。"}],"synonyms":["博学多才","学贯中西"],"antonyms":[],"confusedWith":[],"traditional":"博覽古今","pinyinOverride":null},{"id":"bu-cha-shang-xia","simplified":"不差上下","literalMeaning":"not differ up or down","figurativeMeaning":"almost identical; not much difference","englishEquivalents":["neck and neck","almost equal","on par"],"shortGloss":"almost identical","characters":[{"char":"不","meaning":"not"},{"char":"差","meaning":"differ"},{"char":"上","meaning":"up"},{"char":"下","meaning":"down"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '不差上下' is used to describe situations where two things or people are almost identical in quality, ability, or status. The phrase suggests that there is no significant difference between the two, whether looking from above or below.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"modifier-head","register":"commonly used in both written and spoken Chinese","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with others that imply a more significant difference or inequality. It's important to note that '不差上下' specifically conveys a sense of near equality.","canStandAlone":false},"examples":[{"simplified":"这两支球队的实力不差上下，比赛结果很难预测。","english":"The strength of these two teams is almost identical, making the outcome of the match hard to predict.","traditional":"這兩支球隊的實力不差上下，比賽結果很難預測。"},{"simplified":"他们的工作经验不差上下，所以在面试中都表现得很好。","english":"Their work experience is almost identical, so they both performed well in the interview.","traditional":"他們的工作經驗不差上下，所以在面試中都表現得很好。"}],"synonyms":["旗鼓相当","不相上下"],"antonyms":[],"confusedWith":[{"id":"天壤之别","note":"While '不差上下' means almost identical, '天壤之别' indicates a vast difference."}],"traditional":"不差上下","pinyinOverride":null},{"id":"bu-da-zi-zhao","simplified":"不打自招","literalMeaning":"without being hit, confess oneself","figurativeMeaning":"to confess without being pressed; to reveal one's own guilt or secrets unwittingly","englishEquivalents":["give oneself away","spill the beans"],"shortGloss":"confess unwittingly","characters":[{"char":"不","meaning":"not"},{"char":"打","meaning":"hit or beat"},{"char":"自","meaning":"oneself"},{"char":"招","meaning":"confess or reveal"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '不打自招' is believed to have originated from the idea that a guilty person might confess to their wrongdoing without any external pressure or interrogation. The phrase suggests that sometimes people inadvertently reveal their own secrets or guilt through their actions or words, even when no one is actively trying to extract a confession from them.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"modifier-head","register":"commonly used in both spoken and written Chinese","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with others that involve confession or revelation, but '不打自招' specifically implies an unwitting or unintentional confession without external pressure.","canStandAlone":false},"examples":[{"simplified":"他一紧张就不打自招，说出了真相。","english":"He got nervous and unwittingly confessed, revealing the truth.","traditional":"他一緊張就不打自招，說出了真相。"},{"simplified":"在警方的询问下，他不打自招，承认了自己的罪行。","english":"Under police questioning, he confessed without being pressed, admitting his crime.","traditional":"在警方的詢問下，他不打自招，承認了自己的罪行。"}],"synonyms":["自曝其短"],"antonyms":[],"confusedWith":[{"id":"自曝其短","note":"While both involve revealing something about oneself, '自曝其短' focuses on revealing one's own shortcomings, whereas '不打自招' involves an unintentional confession."}],"traditional":"不打自招","pinyinOverride":null},{"id":"bu-de-ren-xin","simplified":"不得人心","literalMeaning":"not obtain people's hearts","figurativeMeaning":"to be unpopular or not win people's support","englishEquivalents":["unpopular","out of favor"],"shortGloss":"unpopular, not winning support","characters":[{"char":"不","meaning":"not"},{"char":"得","meaning":"obtain"},{"char":"人","meaning":"people's"},{"char":"心","meaning":"hearts"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '不得人心' is used to describe someone or something that fails to gain the approval or support of others. It suggests a lack of popularity or acceptance, often due to actions or characteristics that are not in line with what people desire or expect.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"verb-object","register":"commonly used in both written and spoken Chinese","connotation":"negative","commonMistakes":"Learners might confuse this idiom with similar expressions that imply active dislike, but '不得人心' specifically refers to a lack of popularity or support, not necessarily active opposition.","canStandAlone":false},"examples":[{"simplified":"他的政策不得人心，很快就被废除了。","english":"His policies were unpopular and were quickly abolished.","traditional":"他的政策不得人心，很快就被廢除了。"},{"simplified":"这个计划因为不得人心而失败了。","english":"The plan failed because it did not win people's support.","traditional":"這個計劃因為不得人心而失敗了。"}],"synonyms":["众叛亲离","不受欢迎"],"antonyms":["深入人心","大受欢迎"],"confusedWith":[{"id":"不受欢迎","note":"Both imply unpopularity, but '不受欢迎' is more about being unwelcome, while '不得人心' emphasizes failing to gain support."}],"traditional":"不得人心","pinyinOverride":null},{"id":"bu-dong-zhuang-dong","simplified":"不懂装懂","literalMeaning":"not understand, pretend to understand","figurativeMeaning":"to pretend to understand something when one actually does not","englishEquivalents":["to feign understanding","to bluff one's way through","to pretend to know"],"shortGloss":"pretend to understand","characters":[{"char":"不","meaning":"not"},{"char":"懂","meaning":"understand"},{"char":"装","meaning":"pretend"},{"char":"懂","meaning":"understand"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '不懂装懂' describes the behavior of someone who pretends to understand something they do not. It reflects a common human tendency to avoid admitting ignorance, often to maintain face or avoid embarrassment. This behavior can lead to misunderstandings or mistakes, as the person may make decisions or give advice based on their false pretense of knowledge.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"colloquial and widely used in both spoken and written Chinese","connotation":"negative","commonMistakes":"Learners often confuse this idiom with similar expressions that involve genuine understanding. Unlike '假装明白' (to pretend to understand), '不懂装懂' specifically highlights the lack of understanding.","canStandAlone":false},"examples":[{"simplified":"他不懂装懂，结果在会议上闹了笑话。","english":"He pretended to understand, and ended up making a fool of himself at the meeting.","traditional":"他不懂裝懂，結果在會議上鬧了笑話。"},{"simplified":"在学习中，不要不懂装懂，这样会影响你的进步。","english":"In learning, don't pretend to understand what you don't, as it will hinder your progress.","traditional":"在學習中，不要不懂裝懂，這樣會影響你的進步。"}],"synonyms":["假装明白"],"antonyms":["实事求是"],"confusedWith":[{"id":"假装明白","note":"While both involve pretending, '假装明白' can be used when someone pretends to understand for a specific purpose, not necessarily due to actual ignorance."}],"traditional":"不懂裝懂","pinyinOverride":null},{"id":"bu-gan-bu-jing","simplified":"不干不净","literalMeaning":"not clean, not pure","figurativeMeaning":"unclean or impure; often used to describe something dirty or unhygienic","englishEquivalents":["unclean","dirty","impure"],"shortGloss":"unclean or impure","characters":[{"char":"不","meaning":"not"},{"char":"干","meaning":"clean"},{"char":"不","meaning":"not"},{"char":"净","meaning":"pure"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '不干不净' is often used in everyday language to describe something that is dirty or unhygienic. Its origin is not tied to a specific classical text, but it has been used in Chinese culture for a long time to emphasize the importance of cleanliness.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"coordinate","register":"colloquial, commonly used in everyday speech","connotation":"negative","commonMistakes":"Learners might confuse this idiom with expressions that imply moral impurity, but it primarily refers to physical cleanliness. It is not typically used to describe a person's character.","canStandAlone":false},"examples":[{"simplified":"他的房间总是乱七八糟，不干不净。","english":"His room is always a mess, unclean and untidy.","traditional":"他的房間總是亂七八糟，不乾不淨。"},{"simplified":"吃东西前要洗手，不然不干不净。","english":"You should wash your hands before eating, otherwise it's not clean.","traditional":"吃東西前要洗手，不然不乾不淨。"}],"synonyms":["脏乱差"],"antonyms":["干干净净"],"confusedWith":[{"id":"不三不四","note":"不三不四 refers to something or someone dubious or improper, not related to cleanliness."}],"traditional":"不乾不淨","pinyinOverride":null},{"id":"bu-gan-bu-ga","simplified":"不尴不尬","literalMeaning":"neither awkward nor embarrassed","figurativeMeaning":"in an awkward or embarrassing situation; neither one thing nor the other","englishEquivalents":["neither fish nor fowl","in a pickle"],"shortGloss":"in an awkward situation","characters":[{"char":"不","meaning":"not"},{"char":"尴","meaning":"awkward"},{"char":"不","meaning":"not"},{"char":"尬","meaning":"embarrassed"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '不尴不尬' is used to describe situations that are awkward or embarrassing, where things do not fit neatly into any category or expectation. It is often used when someone finds themselves in a situation that is neither here nor there, causing discomfort or embarrassment.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"coordinate","register":"informal, commonly used in everyday speech","connotation":"negative","commonMistakes":"Learners might confuse this idiom with more neutral expressions of uncertainty or indecision. It's important to remember that '不尴不尬' specifically implies awkwardness or embarrassment.","canStandAlone":false},"examples":[{"simplified":"他站在那儿，不尴不尬，不知道该往哪儿走。","english":"He stood there, feeling awkward and unsure of where to go.","traditional":"他站在那兒，不尷不尬，不知道該往哪兒走。"},{"simplified":"这件衣服的颜色不尴不尬，不太好搭配。","english":"The color of this clothing is awkward and doesn't match well with anything.","traditional":"這件衣服的顏色不尷不尬，不太好搭配。"}],"synonyms":["左右为难"],"antonyms":[],"confusedWith":[{"id":"左右为难","note":"While both idioms describe difficult situations, '左右为难' emphasizes being caught between two choices, whereas '不尴不尬' highlights awkwardness."}],"traditional":"不尷不尬","pinyinOverride":null},{"id":"bu-gan-gao-pan","simplified":"不敢高攀","literalMeaning":"not dare to climb high","figurativeMeaning":"to feel unworthy of associating with someone of higher status","englishEquivalents":["out of one's league","not in the same league"],"shortGloss":"feel unworthy of associating","characters":[{"char":"不","meaning":"not"},{"char":"敢","meaning":"dare"},{"char":"高","meaning":"high"},{"char":"攀","meaning":"climb"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '不敢高攀' is often used to express humility or modesty, indicating that one feels unworthy of associating with someone of higher status or prestige. It reflects a cultural value of recognizing one's own position and showing respect to those perceived as superior.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","complement"],"structure":"verb-object","register":"commonly used in both formal and informal contexts","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with expressions that imply literal climbing or physical elevation. It's important to remember that it refers to social status or relationships.","canStandAlone":false},"examples":[{"simplified":"他是个大企业家，我不敢高攀。","english":"He is a big entrepreneur; I feel unworthy of associating with him.","traditional":"他是個大企業家，我不敢高攀。"},{"simplified":"她的家庭背景太好了，我不敢高攀。","english":"Her family background is too prestigious; I feel unworthy of associating with her.","traditional":"她的家庭背景太好了，我不敢高攀。"}],"synonyms":[],"antonyms":[],"confusedWith":[{"id":"高不可攀","note":"高不可攀 means 'unreachable' or 'unattainable', often referring to goals or standards, not social relationships."}],"traditional":"不敢高攀","pinyinOverride":null},{"id":"bu-gan-hou-ren","simplified":"不甘后人","literalMeaning":"not willing to be behind others","figurativeMeaning":"unwilling to be outdone; striving to excel","englishEquivalents":["not willing to be left behind","strive to be the best"],"shortGloss":"unwilling to be outdone","characters":[{"char":"不","meaning":"not"},{"char":"甘","meaning":"willing"},{"char":"后","meaning":"behind"},{"char":"人","meaning":"others"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom 不甘后人 expresses the idea of not wanting to fall behind others and striving to excel. It is commonly used to describe someone who is competitive and ambitious, always seeking to improve and achieve more than their peers.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"modifier-head","register":"commonly used in both spoken and written Chinese","connotation":"positive","commonMistakes":"Learners might confuse this idiom with expressions that mean 'jealous of others' success,' but 不甘后人 has a positive connotation of self-improvement and ambition.","canStandAlone":false},"examples":[{"simplified":"他在工作中总是不甘后人，努力争取每一次提升的机会。","english":"He is always unwilling to be outdone at work, striving for every opportunity for advancement.","traditional":"他在工作中總是不甘後人，努力爭取每一次提升的機會。"},{"simplified":"在学术研究上，她不甘后人，总是追求新的突破。","english":"In academic research, she is unwilling to be outdone and always seeks new breakthroughs.","traditional":"在學術研究上，她不甘後人，總是追求新的突破。"}],"synonyms":["争先恐后","力争上游"],"antonyms":["甘拜下风"],"confusedWith":[{"id":"嫉妒心","note":"嫉妒心 refers to jealousy, whereas 不甘后人 is about striving to excel."}],"traditional":"不甘後人","pinyinOverride":null},{"id":"bu-gan-zao-ci","simplified":"不敢造次","literalMeaning":"not dare act rashly","figurativeMeaning":"to not dare to act carelessly or rashly","englishEquivalents":["tread carefully","proceed with caution"],"shortGloss":"proceed cautiously","characters":[{"char":"不","meaning":"not"},{"char":"敢","meaning":"dare"},{"char":"造","meaning":"act"},{"char":"次","meaning":"rashly"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '不敢造次' is used to express a sense of caution and carefulness in one's actions. It reflects the idea of not daring to act hastily or without due consideration. The exact origin of this idiom is not well-documented, but it has been used in Chinese literature and speech to convey the importance of prudence.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"modifier-head","register":"commonly used in both formal and informal contexts","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with others that emphasize fear rather than caution. It's important to note that '不敢造次' implies a deliberate choice to be careful, not necessarily out of fear.","canStandAlone":false},"examples":[{"simplified":"在这个重要的会议上，我们不敢造次。","english":"At this important meeting, we dare not act rashly.","traditional":"在這個重要的會議上，我們不敢造次。"},{"simplified":"面对如此复杂的情况，他不敢造次。","english":"Faced with such a complex situation, he dared not act carelessly.","traditional":"面對如此複雜的情況，他不敢造次。"}],"synonyms":[],"antonyms":[],"confusedWith":[],"traditional":"不敢造次","pinyinOverride":null},{"id":"bu-gu-si-huo","simplified":"不顾死活","literalMeaning":"disregard life or death","figurativeMeaning":"to act recklessly without regard for consequences","englishEquivalents":["reckless abandon","devil-may-care attitude"],"shortGloss":"reckless disregard for consequences","characters":[{"char":"不","meaning":"not"},{"char":"顾","meaning":"care for"},{"char":"死","meaning":"death"},{"char":"活","meaning":"life"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '不顾死活' describes someone who acts without considering the potential dangers or consequences of their actions, essentially ignoring whether they live or die. It is often used to criticize someone for being overly reckless or irresponsible.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["adverbial","attributive"],"structure":"modifier-head","register":"commonly used in both spoken and written Chinese to describe reckless behavior","connotation":"negative","commonMistakes":"Learners might confuse this idiom with others that imply bravery or courage, but '不顾死活' specifically emphasizes recklessness and a lack of consideration for consequences.","canStandAlone":false},"examples":[{"simplified":"他不顾死活地冲进了火场。","english":"He recklessly rushed into the fire.","traditional":"他不顧死活地衝進了火場。"},{"simplified":"她总是做事不顾死活，结果常常惹麻烦。","english":"She always acts recklessly, and as a result, often gets into trouble.","traditional":"她總是做事不顧死活，結果常常惹麻煩。"}],"synonyms":["鲁莽行事","冒险犯难"],"antonyms":["深思熟虑","谨小慎微"],"confusedWith":[{"id":"奋不顾身","note":"While both idioms involve disregard for personal safety, '奋不顾身' implies bravery and selflessness, whereas '不顾死活' implies recklessness."}],"traditional":"不顧死活","pinyinOverride":null},{"id":"bu-gu-yi-qie","simplified":"不顾一切","literalMeaning":"disregard everything","figurativeMeaning":"to act recklessly or without considering the consequences","englishEquivalents":["reckless abandon","at all costs"],"shortGloss":"reckless disregard for consequences","characters":[{"char":"不","meaning":"not"},{"char":"顾","meaning":"consider"},{"char":"一","meaning":"one"},{"char":"切","meaning":"all; everything"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '不顾一切' describes someone who acts without regard for the consequences, often driven by a strong desire or emotion. It suggests a willingness to ignore potential risks or dangers in pursuit of a goal.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["adverbial","complement"],"structure":"modifier-head","register":"common in both spoken and written Chinese, used in both formal and informal contexts","connotation":"negative","commonMistakes":"Learners may confuse this idiom with similar expressions that imply determination, but '不顾一切' specifically suggests recklessness and a lack of consideration for consequences.","canStandAlone":false},"examples":[{"simplified":"他不顾一切地冲进火场救人。","english":"He rushed into the fire to save people, disregarding everything.","traditional":"他不顧一切地衝進火場救人。"},{"simplified":"为了成功，她不顾一切地工作。","english":"She worked with reckless abandon for success.","traditional":"為了成功，她不顧一切地工作。"}],"synonyms":["奋不顾身"],"antonyms":["谨小慎微"],"confusedWith":[{"id":"奋不顾身","note":"While both imply disregard for personal safety, '奋不顾身' often carries a more positive connotation of selflessness."}],"traditional":"不顧一切","pinyinOverride":null},{"id":"bu-huang-bu-mang","simplified":"不慌不忙","literalMeaning":"not flustered, not hurried","figurativeMeaning":"calm and unhurried; composed","englishEquivalents":["calm and collected","cool as a cucumber"],"shortGloss":"calm and unhurried","characters":[{"char":"不","meaning":"not"},{"char":"慌","meaning":"flustered"},{"char":"不","meaning":"not"},{"char":"忙","meaning":"hurried"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '不慌不忙' is used to describe a person who remains calm and composed, even in situations that might cause others to panic or rush. It emphasizes the importance of maintaining one's composure and taking things at a steady pace.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["adverbial","predicate"],"structure":"coordinate","register":"commonly used in both spoken and written Chinese","connotation":"positive","commonMistakes":"Learners might confuse this idiom with similar expressions that imply slowness or laziness, but '不慌不忙' specifically conveys a sense of calmness and control, not procrastination.","canStandAlone":false},"examples":[{"simplified":"他在紧急情况下仍然不慌不忙，令人佩服。","english":"He remained calm and composed in the emergency, which was admirable.","traditional":"他在緊急情況下仍然不慌不忙，令人佩服。"},{"simplified":"她不慌不忙地完成了所有的工作。","english":"She completed all the work calmly and unhurriedly.","traditional":"她不慌不忙地完成了所有的工作。"}],"synonyms":["从容不迫"],"antonyms":["惊慌失措"],"confusedWith":[{"id":"慢条斯理","note":"While '慢条斯理' also implies slowness, it lacks the composure aspect of '不慌不忙'."}],"traditional":"不慌不忙","pinyinOverride":null},{"id":"bu-ji-zhi-min","simplified":"不羁之民","literalMeaning":"unbridled people","figurativeMeaning":"people who are difficult to control or govern","englishEquivalents":["unruly crowd","uncontrollable populace"],"shortGloss":"unruly or uncontrollable people","characters":[{"char":"不","meaning":"not"},{"char":"羁","meaning":"bridled, restrained"},{"char":"之","meaning":"of"},{"char":"民","meaning":"people, populace"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '不羁之民' describes people who are difficult to control or govern. It is often used to refer to groups or communities that resist authority or are hard to manage. The origins of this idiom are not clearly traceable to a specific classical text, and it likely developed over time as a descriptive phrase.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["attributive"],"structure":"modifier-head","register":"literary, but can be used in formal speech and writing","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with similar expressions that describe rebellious or revolutionary groups, but '不羁之民' does not necessarily imply active rebellion, just a lack of control.","canStandAlone":false},"examples":[{"simplified":"政府对这些不羁之民感到无奈。","english":"The government feels helpless against these unruly people.","traditional":"政府對這些不羈之民感到無奈。"},{"simplified":"不羁之民常常给社会带来挑战。","english":"Unruly people often pose challenges to society.","traditional":"不羈之民常常給社會帶來挑戰。"}],"synonyms":["桀骜不驯"],"antonyms":["循规蹈矩"],"confusedWith":[{"id":"桀骜不驯","note":"While both describe unruly behavior, '桀骜不驯' often refers to individuals, whereas '不羁之民' refers to groups."}],"traditional":"不羈之民","pinyinOverride":null},{"id":"bu-ji-qi-shu","simplified":"不计其数","literalMeaning":"not count their number","figurativeMeaning":"countless; too many to count","englishEquivalents":["countless","innumerable","beyond counting"],"shortGloss":"countless; innumerable","characters":[{"char":"不","meaning":"not"},{"char":"计","meaning":"count"},{"char":"其","meaning":"their"},{"char":"数","meaning":"number"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '不计其数' is used to describe a quantity so large that it cannot be counted. It is often used in contexts where something is abundant or occurs frequently, emphasizing the overwhelming number or frequency of the items or events in question.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"modifier-head","register":"widely used in both written and spoken Chinese","connotation":"neutral","commonMistakes":"Learners sometimes use this idiom to describe things that are simply large in size rather than numerous in quantity. It specifically refers to the number of items, not their size.","canStandAlone":false},"examples":[{"simplified":"在沙漠中，沙粒的数量不计其数。","english":"In the desert, the number of sand grains is countless.","traditional":"在沙漠中，沙粒的數量不計其數。"},{"simplified":"他收藏的邮票不计其数。","english":"The stamps in his collection are countless.","traditional":"他收藏的郵票不計其數。"}],"synonyms":["数不胜数","不可胜数"],"antonyms":["屈指可数"],"confusedWith":[{"id":"数不胜数","note":"Both mean 'countless', but 数不胜数 emphasizes the inability to count due to overwhelming numbers."}],"traditional":"不計其數","pinyinOverride":null},{"id":"bu-ji-qian-chou","simplified":"不记前仇","literalMeaning":"not remember past grudges","figurativeMeaning":"to forgive and forget past grievances","englishEquivalents":["forgive and forget","let bygones be bygones"],"shortGloss":"forgive past grievances","characters":[{"char":"不","meaning":"not"},{"char":"记","meaning":"remember"},{"char":"前","meaning":"past"},{"char":"仇","meaning":"grudges"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '不记前仇' is commonly used to describe someone who chooses not to hold onto past grievances or grudges. It encourages a mindset of forgiveness and moving forward, rather than dwelling on past conflicts.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"modifier-head","register":"commonly used in both formal and informal contexts","connotation":"positive","commonMistakes":"Learners might confuse this idiom with similar expressions that imply simply forgetting rather than actively forgiving. It's important to note that this idiom emphasizes the act of forgiveness.","canStandAlone":false},"examples":[{"simplified":"他是一个不记前仇的人，总是愿意给别人第二次机会。","english":"He is someone who forgives and forgets, always willing to give others a second chance.","traditional":"他是一個不記前仇的人，總是願意給別人第二次機會。"},{"simplified":"在工作中，我们应该不记前仇，专注于未来的合作。","english":"In the workplace, we should forgive past grievances and focus on future collaboration.","traditional":"在工作中，我們應該不記前仇，專注於未來的合作。"}],"synonyms":["既往不咎"],"antonyms":["睚眦必报"],"confusedWith":[{"id":"不念旧恶","note":"Both idioms involve forgiving past wrongs, but '不念旧恶' specifically emphasizes not dwelling on past evils or wrongdoings."}],"traditional":"不記前仇","pinyinOverride":null},{"id":"bu-jia-bu-se","simplified":"不稼不穑","literalMeaning":"not sowing, not reaping","figurativeMeaning":"to not engage in productive work; to live off the labor of others","englishEquivalents":["live off the fat of the land","freeload","sponging off others"],"shortGloss":"not engaging in productive work","characters":[{"char":"不","meaning":"not"},{"char":"稼","meaning":"sow"},{"char":"不","meaning":"not"},{"char":"穑","meaning":"reap"}],"origin":{"period":"Warring States period (475–221 BCE)","sourceText":"《孟子·滕文公上》","sourceTextEnglish":"Mencius, Teng Wen Gong I","originalExcerpt":"不稼不穑，胡取禾三百廛兮？","storyEnglish":"This idiom comes from a passage in the 'Mencius,' where Mencius criticizes those who do not engage in agricultural work yet expect to benefit from the harvest. It highlights the unfairness of enjoying the fruits of labor without contributing to the effort.","historicalFigures":["Mencius"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"coordinate","register":"literary, but understood in educated speech","connotation":"negative","commonMistakes":"Learners often confuse this idiom with general laziness, but it specifically refers to benefiting from others' work without contributing. It is not just about being idle.","canStandAlone":false},"examples":[{"simplified":"他总是依靠父母，不稼不穑。","english":"He always relies on his parents, not engaging in any productive work.","traditional":"他總是依靠父母，不稼不穡。"},{"simplified":"在这个团队中，没人能不稼不穑地享受成果。","english":"In this team, no one can enjoy the results without contributing.","traditional":"在這個團隊中，沒人能不稼不穡地享受成果。"}],"synonyms":["坐享其成"],"antonyms":["自食其力"],"confusedWith":[{"id":"游手好闲","note":"游手好闲 refers to idleness and laziness in general, not specifically living off others' work."}],"traditional":"不稼不穡","pinyinOverride":null},{"id":"bo-lan-wu-che","simplified":"博览五车","literalMeaning":"extensively read five cartloads","figurativeMeaning":"to be very knowledgeable or well-read","englishEquivalents":["well-read","a walking encyclopedia"],"shortGloss":"extensively knowledgeable","characters":[{"char":"博","meaning":"extensive"},{"char":"览","meaning":"to read"},{"char":"五","meaning":"five"},{"char":"车","meaning":"cartloads"}],"origin":{"period":"Warring States period (475–221 BCE)","sourceText":"《庄子·天下》","sourceTextEnglish":"Zhuangzi, Chapter Tianxia","originalExcerpt":"惠施多方，其书五车。","storyEnglish":"The idiom originates from the story of Hui Shi, a famous scholar during the Warring States period, who was known for his extensive knowledge. It was said that he had so many books that they could fill five cartloads. This expression came to symbolize someone who is very well-read or knowledgeable.","historicalFigures":["Hui Shi"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"modifier-head","register":"literary, but can be used in formal speech and writing","connotation":"positive","commonMistakes":"Learners may confuse this idiom with others that imply wisdom rather than extensive reading. It specifically refers to being well-read, not necessarily wise or intelligent.","canStandAlone":false},"examples":[{"simplified":"他是一个博览五车的学者。","english":"He is a scholar who is very well-read.","traditional":"他是一個博覽五車的學者。"},{"simplified":"在图书馆工作多年后，她已经博览五车。","english":"After working in the library for many years, she has become very well-read.","traditional":"在圖書館工作多年後，她已經博覽五車。"}],"synonyms":["学富五车"],"antonyms":[],"confusedWith":[{"id":"学富五车","note":"Both idioms refer to being well-read, but 学富五车 emphasizes the richness of knowledge, while 博览五车 emphasizes the breadth of reading."}],"traditional":"博覽五車","pinyinOverride":null},{"id":"bo-shou-wu-ce","simplified":"搏手无策","literalMeaning":"clasp hands, no plan","figurativeMeaning":"to be at a loss; to be unable to find a solution","englishEquivalents":["at one's wits' end","at a loss","out of ideas"],"shortGloss":"at a loss for a solution","characters":[{"char":"搏","meaning":"clasp"},{"char":"手","meaning":"hands"},{"char":"无","meaning":"no"},{"char":"策","meaning":"plan"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom 搏手无策 describes a situation where someone is so perplexed or overwhelmed that they clasp their hands together, signifying that they have no plan or strategy to deal with the problem at hand. This expression captures the feeling of being completely at a loss and unable to find a way forward.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"commonly used in both written and spoken Chinese to describe situations of helplessness or confusion","connotation":"negative","commonMistakes":"Learners might confuse 搏手无策 with 手足无措, which also means being at a loss but emphasizes confusion and lack of composure rather than just the absence of a plan.","canStandAlone":false},"examples":[{"simplified":"面对突如其来的危机，他感到搏手无策。","english":"Faced with the sudden crisis, he felt at a loss for a solution.","traditional":"面對突如其來的危機，他感到搏手無策。"},{"simplified":"在这个复杂的问题上，专家们也搏手无策。","english":"Even the experts were at a loss with this complex issue.","traditional":"在這個複雜的問題上，專家們也搏手無策。"}],"synonyms":["手足无措"],"antonyms":[],"confusedWith":[{"id":"手足无措","note":"手足无措 emphasizes confusion and lack of composure, while 搏手无策 focuses on the lack of a plan."}],"traditional":"搏手無策","pinyinOverride":null},{"id":"bo-mu-ming-ming","simplified":"薄暮冥冥","literalMeaning":"twilight darkening","figurativeMeaning":"a situation or atmosphere that is becoming increasingly unclear or uncertain","englishEquivalents":["dusk and gloom","twilight zone"],"shortGloss":"twilight and uncertainty","characters":[{"char":"薄","meaning":"thin, slight; here, it refers to the onset of evening"},{"char":"暮","meaning":"evening, dusk"},{"char":"冥","meaning":"dark, obscure"},{"char":"冥","meaning":"dark, obscure"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '薄暮冥冥' is used to describe the time of day when evening is setting in and darkness begins to fall. It metaphorically represents situations where clarity is fading and things become uncertain or obscure, much like the transition from day to night.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["adverbial","attributive"],"structure":"modifier-head","register":"literary, but can be used in poetic or descriptive contexts in modern language","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with expressions that imply complete darkness or hopelessness. However, '薄暮冥冥' specifically refers to the onset of darkness and the accompanying uncertainty, not total darkness.","canStandAlone":false},"examples":[{"simplified":"在薄暮冥冥的森林中，探险队迷失了方向。","english":"In the twilight-darkened forest, the expedition team lost their way.","traditional":"在薄暮冥冥的森林中，探險隊迷失了方向。"},{"simplified":"他的心情如同薄暮冥冥，充满了不确定性。","english":"His mood was like the twilight, filled with uncertainty.","traditional":"他的心情如同薄暮冥冥，充滿了不確定性。"}],"synonyms":[],"antonyms":[],"confusedWith":[],"traditional":"薄暮冥冥","pinyinOverride":null},{"id":"bu-guo-shi-fei","simplified":"补过饰非","literalMeaning":"patch up mistakes, decorate faults","figurativeMeaning":"to cover up one's mistakes or faults instead of correcting them","englishEquivalents":["sweep under the rug","whitewash","cover up"],"shortGloss":"cover up mistakes","characters":[{"char":"补","meaning":"to patch up; to mend"},{"char":"过","meaning":"mistakes; faults"},{"char":"饰","meaning":"to decorate; to embellish"},{"char":"非","meaning":"wrong; fault"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '补过饰非' describes the act of trying to cover up one's mistakes or faults rather than addressing and correcting them. It suggests a superficial attempt to hide errors, akin to putting a fresh coat of paint over a cracked wall. The phrase is often used to criticize someone who is more concerned with appearances than with genuine improvement.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"coordinate","register":"formal written Chinese, but also used in critical speech","connotation":"negative","commonMistakes":"Learners might confuse this idiom with ones that imply genuine correction of mistakes, such as 改过自新. 补过饰非 specifically implies a superficial or deceptive action.","canStandAlone":false},"examples":[{"simplified":"他总是补过饰非，从不真正解决问题。","english":"He always covers up his mistakes and never truly solves the problems.","traditional":"他總是補過飾非，從不真正解決問題。"},{"simplified":"与其补过饰非，不如诚实面对自己的错误。","english":"Instead of covering up mistakes, it's better to honestly face your errors.","traditional":"與其補過飾非，不如誠實面對自己的錯誤。"}],"synonyms":["掩耳盗铃"],"antonyms":["改过自新"],"confusedWith":[{"id":"改过自新","note":"改过自新 means to genuinely correct one's mistakes and start anew, unlike 补过饰非 which implies superficial cover-up."}],"traditional":"補過飾非","pinyinOverride":null},{"id":"bu-feng-zhuo-ying","simplified":"捕风捉影","literalMeaning":"catch the wind and seize the shadow","figurativeMeaning":"to make groundless accusations or pursue illusory goals","englishEquivalents":["chase shadows","grasp at straws"],"shortGloss":"pursue illusions or groundless claims","characters":[{"char":"捕","meaning":"catch"},{"char":"风","meaning":"wind"},{"char":"捉","meaning":"seize"},{"char":"影","meaning":"shadow"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '捕风捉影' is often used to describe actions that are as futile as trying to catch the wind or seize a shadow. It conveys the idea of pursuing something that is insubstantial or making claims without evidence. The origin of this idiom is not tied to a specific classical text, but it has been used in Chinese literature to criticize baseless accusations or efforts.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"coordinate","register":"literary, but commonly used in both formal and informal contexts","connotation":"negative","commonMistakes":"Learners often confuse this idiom with phrases that imply actual pursuit of something tangible. It specifically refers to actions or accusations that lack substance or evidence.","canStandAlone":false},"examples":[{"simplified":"他总是捕风捉影，毫无根据地指责别人。","english":"He is always chasing shadows, making baseless accusations against others.","traditional":"他總是捕風捉影，毫無根據地指責別人。"},{"simplified":"在没有证据的情况下，不要捕风捉影地猜测。","english":"Without evidence, don't make groundless guesses.","traditional":"在沒有證據的情況下，不要捕風捉影地猜測。"}],"synonyms":["无中生有","空穴来风"],"antonyms":["实事求是"],"confusedWith":[{"id":"无中生有","note":"Both involve creating something from nothing, but '无中生有' emphasizes fabrication, while '捕风捉影' focuses on the futility of the pursuit."}],"traditional":"捕風捉影","pinyinOverride":null},{"id":"bu-ba-yi-mao","simplified":"不拔一毛","literalMeaning":"not pluck a single hair","figurativeMeaning":"extremely stingy or unwilling to help others","englishEquivalents":["not lift a finger","tight-fisted"],"shortGloss":"extremely stingy","characters":[{"char":"不","meaning":"not"},{"char":"拔","meaning":"pluck"},{"char":"一","meaning":"one, a single"},{"char":"毛","meaning":"hair"}],"origin":{"period":"Eastern Han Dynasty (25–220 CE)","sourceText":"《后汉书·杨震传》","sourceTextEnglish":"Book of the Later Han, Biography of Yang Zhen","originalExcerpt":"人之为善，百不为多；为恶，一不为少。故君子不拔一毛以利人，亦不为也。","storyEnglish":"The idiom originates from a story about Yang Zhen, a renowned official during the Eastern Han Dynasty. Known for his integrity, Yang Zhen once explained that a gentleman would not pluck even a single hair to benefit others if it meant compromising his principles. This expression came to describe someone who is extremely stingy or unwilling to help others, even in the smallest way.","historicalFigures":["Yang Zhen"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"modifier-head","register":"literary, but understood in modern speech","connotation":"negative","commonMistakes":"Learners might confuse this idiom with expressions about being careful or frugal, but it specifically implies a negative judgment about stinginess or selfishness.","canStandAlone":false},"examples":[{"simplified":"他对朋友从来不拔一毛，大家都不愿意和他交往。","english":"He never lifts a finger to help his friends, so nobody wants to associate with him.","traditional":"他對朋友從來不拔一毛，大家都不願意和他交往。"},{"simplified":"在慈善活动中，他不拔一毛，令人失望。","english":"During the charity event, he was extremely stingy, which was disappointing.","traditional":"在慈善活動中，他不拔一毛，令人失望。"}],"synonyms":["一毛不拔"],"antonyms":["慷慨解囊"],"confusedWith":[{"id":"一毛不拔","note":"Both idioms describe stinginess, but 一毛不拔 is more commonly used in modern contexts."}],"traditional":"不拔一毛","pinyinOverride":null},{"id":"bu-bai-zhi-di","simplified":"不败之地","literalMeaning":"undefeatable place","figurativeMeaning":"a position of invincibility or unassailable advantage","englishEquivalents":["an unassailable position","a position of strength"],"shortGloss":"a position of invincibility","characters":[{"char":"不","meaning":"not"},{"char":"败","meaning":"defeated"},{"char":"之","meaning":"of"},{"char":"地","meaning":"place"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom 不败之地 is often used to describe a situation where someone or something is in a position that cannot be easily overcome or defeated. It conveys the idea of having a strong, unassailable advantage or being in a secure position.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["object","attributive"],"structure":"modifier-head","register":"commonly used in both formal and informal contexts","connotation":"positive","commonMistakes":"Learners might confuse 不败之地 with idioms that imply temporary advantage rather than a secure and lasting position. It's important to note that 不败之地 suggests a more permanent state of invincibility.","canStandAlone":false},"examples":[{"simplified":"他的公司在市场上占据了不败之地。","english":"His company has secured an unassailable position in the market.","traditional":"他的公司在市場上佔據了不敗之地。"},{"simplified":"经过多年的努力，他终于在行业中立于不败之地。","english":"After years of effort, he finally stands in an invincible position in the industry.","traditional":"經過多年的努力，他終於在行業中立於不敗之地。"}],"synonyms":[],"antonyms":[],"confusedWith":[],"traditional":"不敗之地","pinyinOverride":null},{"id":"bu-ce-zhi-huo","simplified":"不测之祸","literalMeaning":"unpredictable disaster","figurativeMeaning":"an unforeseen disaster or calamity","englishEquivalents":["bolt from the blue","unexpected misfortune"],"shortGloss":"unforeseen disaster","characters":[{"char":"不","meaning":"not"},{"char":"测","meaning":"predict"},{"char":"之","meaning":"of"},{"char":"祸","meaning":"disaster"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '不测之祸' refers to disasters or misfortunes that occur unexpectedly, without any prior warning. It emphasizes the suddenness and unpredictability of such events, often used to describe situations where people are caught off guard by unfortunate occurrences.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["attributive","object"],"structure":"modifier-head","register":"widely used in both formal and informal contexts","connotation":"negative","commonMistakes":"Learners might confuse this idiom with other phrases that describe predictable or expected events. It's important to remember that '不测之祸' specifically refers to unforeseen disasters.","canStandAlone":false},"examples":[{"simplified":"这次地震是个不测之祸，让大家措手不及。","english":"The earthquake was an unforeseen disaster that caught everyone off guard.","traditional":"這次地震是個不測之禍，讓大家措手不及。"},{"simplified":"他在旅途中遭遇了不测之祸，令人惋惜。","english":"He encountered an unforeseen disaster during his journey, which was regrettable.","traditional":"他在旅途中遭遇了不測之禍，令人惋惜。"}],"synonyms":["飞来横祸"],"antonyms":[],"confusedWith":[{"id":"意料之中","note":"意料之中 refers to something that is expected or anticipated, unlike 不测之祸 which is unforeseen."}],"traditional":"不測之禍","pinyinOverride":null},{"id":"bu-jie-zhi-yuan","simplified":"不解之缘","literalMeaning":"not untie of bond","figurativeMeaning":"an inseparable bond or connection","englishEquivalents":["inseparable bond","unbreakable tie"],"shortGloss":"inseparable bond","characters":[{"char":"不","meaning":"not"},{"char":"解","meaning":"untie; loosen"},{"char":"之","meaning":"of"},{"char":"缘","meaning":"bond; fate"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '不解之缘' describes a relationship or connection that cannot be easily broken or dissolved. It is often used to describe deep friendships, familial bonds, or a strong affinity between people, places, or things. The idea is that the bond is so strong that it cannot be untied or undone.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["attributive","predicate"],"structure":"modifier-head","register":"widely used in both formal and informal contexts","connotation":"positive","commonMistakes":"Learners might confuse '不解之缘' with '不解之谜', which means 'an unsolved mystery'. The key difference is that '缘' refers to a bond or connection, while '谜' refers to a mystery.","canStandAlone":false},"examples":[{"simplified":"他们之间有一种不解之缘。","english":"There is an inseparable bond between them.","traditional":"他們之間有一種不解之緣。"},{"simplified":"这座城市与我有着不解之缘。","english":"I have an inseparable bond with this city.","traditional":"這座城市與我有著不解之緣。"}],"synonyms":["密不可分","情同手足"],"antonyms":[],"confusedWith":[{"id":"不解之谜","note":"不解之谜 means 'an unsolved mystery', focusing on something puzzling rather than a bond."}],"traditional":"不解之緣","pinyinOverride":null},{"id":"bu-jing-shi-gu","simplified":"不经世故","literalMeaning":"not experienced in worldly affairs","figurativeMeaning":"naive or inexperienced in dealing with the complexities of life","englishEquivalents":["wet behind the ears","green","naive"],"shortGloss":"naive, inexperienced","characters":[{"char":"不","meaning":"not"},{"char":"经","meaning":"experienced"},{"char":"世","meaning":"worldly"},{"char":"故","meaning":"affairs"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '不经世故' describes someone who is naive or inexperienced in dealing with the complexities and realities of life. It is often used to refer to young people or those who have not yet encountered the harsh or intricate aspects of the world.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["attributive","predicate"],"structure":"modifier-head","register":"commonly used in both spoken and written Chinese to describe someone's lack of experience","connotation":"negative","commonMistakes":"Learners might confuse this idiom with '不识时务', which means not recognizing the times or trends, but '不经世故' specifically refers to a lack of experience in worldly affairs.","canStandAlone":false},"examples":[{"simplified":"他刚从学校毕业，还不经世故。","english":"He just graduated from school and is still inexperienced in worldly matters.","traditional":"他剛從學校畢業，還不經世故。"},{"simplified":"年轻人不经世故，容易上当受骗。","english":"Young people, being naive, are easily deceived.","traditional":"年輕人不經世故，容易上當受騙。"}],"synonyms":["乳臭未干","初出茅庐"],"antonyms":["老于世故"],"confusedWith":[{"id":"不识时务","note":"While '不识时务' means not recognizing the times or trends, '不经世故' refers to a lack of experience in worldly affairs."}],"traditional":"不經世故","pinyinOverride":null},{"id":"bu-jing-er-zou","simplified":"不胫而走","literalMeaning":"without legs but still runs","figurativeMeaning":"news, rumors, or information spreading quickly","englishEquivalents":["spread like wildfire","travel fast"],"shortGloss":"spread quickly (news or rumors)","characters":[{"char":"不","meaning":"not"},{"char":"胫","meaning":"shins, legs"},{"char":"而","meaning":"but, yet"},{"char":"走","meaning":"to run, to go"}],"origin":{"period":"Warring States period (475–221 BCE)","sourceText":"《韩非子·五蠹》","sourceTextEnglish":"Han Feizi, Chapter Five Vermin","originalExcerpt":"故善者因而成之，恶者不胫而走。","storyEnglish":"The idiom originates from the 'Han Feizi', a work by the philosopher Han Fei during the Warring States period. In the text, it is mentioned that bad news or rumors tend to spread quickly, even without any deliberate effort to disseminate them, as if they have legs of their own.","historicalFigures":["Han Fei"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"modifier-head","register":"literary, but widely understood and used in both written and spoken Chinese","connotation":"neutral","commonMistakes":"Learners might mistakenly use this idiom to describe physical movement rather than the spread of information. It specifically refers to the rapid dissemination of news or rumors.","canStandAlone":false},"examples":[{"simplified":"这个消息不胫而走，大家都知道了。","english":"This news spread quickly, and now everyone knows about it.","traditional":"這個消息不脛而走，大家都知道了。"},{"simplified":"谣言不胫而走，很快传遍了整个城市。","english":"The rumor spread rapidly and soon circulated throughout the entire city.","traditional":"謠言不脛而走，很快傳遍了整個城市。"}],"synonyms":["不翼而飞"],"antonyms":[],"confusedWith":[{"id":"不翼而飞","note":"While both idioms describe something spreading quickly, 不翼而飞 often implies disappearance or loss, whereas 不胫而走 focuses on the spread of information."}],"traditional":"不脛而走","pinyinOverride":null},{"id":"bu-ju-yi-ge","simplified":"不拘一格","literalMeaning":"not limited to one pattern","figurativeMeaning":"not sticking to one particular method or style; being flexible and open-minded","englishEquivalents":["think outside the box","break the mold"],"shortGloss":"be flexible and open-minded","characters":[{"char":"不","meaning":"not"},{"char":"拘","meaning":"confined"},{"char":"一","meaning":"one"},{"char":"格","meaning":"pattern; standard"}],"origin":{"period":"Qing Dynasty (1644–1912)","sourceText":"《龚自珍全集》","sourceTextEnglish":"Complete Works of Gong Zizhen","originalExcerpt":"不拘一格降人才。","storyEnglish":"The idiom originates from a poem by Gong Zizhen, a Qing Dynasty scholar and poet. In his poem, Gong Zizhen advocates for the idea that talent should not be constrained by rigid standards or traditional methods. He believed that society should embrace diverse talents and allow them to flourish without being confined to a single mold.","historicalFigures":["Gong Zizhen"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["adverbial","attributive"],"structure":"modifier-head","register":"literary, but commonly used in both formal and informal contexts","connotation":"positive","commonMistakes":"Learners often confuse this idiom with those that suggest chaos or lack of standards. However, it specifically refers to flexibility in methods and approaches, not a lack of organization or discipline.","canStandAlone":false},"examples":[{"simplified":"公司鼓励员工不拘一格地提出创新想法。","english":"The company encourages employees to propose innovative ideas without being constrained by traditional methods.","traditional":"公司鼓勵員工不拘一格地提出創新想法。"},{"simplified":"教育应该不拘一格，因材施教。","english":"Education should be flexible and tailored to the needs of each student.","traditional":"教育應該不拘一格，因材施教。"}],"synonyms":["灵活变通","随机应变"],"antonyms":["墨守成规"],"confusedWith":[{"id":"随心所欲","note":"随心所欲 means doing as one pleases without any restrictions, which can imply a lack of discipline, unlike 不拘一格 which emphasizes flexibility within a framework."}],"traditional":"不拘一格","pinyinOverride":null},{"id":"bu-jue-ru-xian","simplified":"不绝如线","literalMeaning":"unbroken like a thread","figurativeMeaning":"barely surviving; hanging by a thread","englishEquivalents":["hanging by a thread","on the brink of collapse"],"shortGloss":"barely surviving","characters":[{"char":"不","meaning":"not"},{"char":"绝","meaning":"cut off; end"},{"char":"如","meaning":"like; as if"},{"char":"线","meaning":"thread; line"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '不绝如线' is often used to describe a situation that is extremely precarious, as if it is hanging by a single, thin thread. The imagery suggests something that is barely holding on, and could easily fall apart at any moment.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"modifier-head","register":"commonly used in both written and spoken Chinese","connotation":"negative","commonMistakes":"Learners might confuse this idiom with others that involve threads or lines, but '不绝如线' specifically conveys a sense of imminent danger or collapse. It's not used for situations that are simply tenuous but stable.","canStandAlone":false},"examples":[{"simplified":"他的生意现在不绝如线，随时可能倒闭。","english":"His business is hanging by a thread and could collapse at any time.","traditional":"他的生意現在不絕如線，隨時可能倒閉。"},{"simplified":"在敌人的猛烈攻击下，他们的防线不绝如线。","english":"Under the enemy's fierce attack, their defense line was barely holding on.","traditional":"在敵人的猛烈攻擊下，他們的防線不絕如線。"}],"synonyms":["岌岌可危"],"antonyms":["安如泰山"],"confusedWith":[{"id":"千钧一发","note":"千钧一发 also conveys a sense of extreme danger, but it emphasizes the suddenness and critical nature of the situation."}],"traditional":"不絕如線","pinyinOverride":null},{"id":"bu-ke-mei-ju","simplified":"不可枚举","literalMeaning":"cannot be enumerated","figurativeMeaning":"too numerous to count","englishEquivalents":["countless","innumerable"],"shortGloss":"too many to count","characters":[{"char":"不","meaning":"not"},{"char":"可","meaning":"can, able to"},{"char":"枚","meaning":"enumerate, count"},{"char":"举","meaning":"list, enumerate"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '不可枚举' is used to describe situations where the quantity of something is so large that it cannot be counted or listed. It is often used in contexts where the sheer number of items, people, or occurrences is overwhelming.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"modifier-head","register":"commonly used in both formal and informal contexts","connotation":"neutral","commonMistakes":"Learners might confuse '不可枚举' with '数不胜数', which also means 'too many to count'. However, '不可枚举' emphasizes the inability to list each item, while '数不胜数' emphasizes the overwhelming number.","canStandAlone":false},"examples":[{"simplified":"这座城市的美食种类不可枚举。","english":"The variety of delicacies in this city is too numerous to count.","traditional":"這座城市的美食種類不可枚舉。"},{"simplified":"他的贡献不可枚举，对社会产生了深远的影响。","english":"His contributions are countless and have had a profound impact on society.","traditional":"他的貢獻不可枚舉，對社會產生了深遠的影響。"}],"synonyms":["数不胜数","不计其数"],"antonyms":["屈指可数"],"confusedWith":[{"id":"数不胜数","note":"Both idioms mean 'too many to count', but '不可枚举' emphasizes the inability to list each item, while '数不胜数' emphasizes the overwhelming number."}],"traditional":"不可枚舉","pinyinOverride":null},{"id":"bu-ke-mo-mie","simplified":"不可磨灭","literalMeaning":"cannot be erased","figurativeMeaning":"indelible; unforgettable; something that cannot be erased or forgotten","englishEquivalents":["etched in stone","unforgettable"],"shortGloss":"indelible, unforgettable","characters":[{"char":"不","meaning":"not"},{"char":"可","meaning":"can, able to"},{"char":"磨","meaning":"grind, erase"},{"char":"灭","meaning":"extinguish, destroy"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '不可磨灭' is used to describe something that is so significant or impactful that it cannot be erased or forgotten. It is often used to refer to memories, achievements, or influences that leave a lasting impression.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["attributive","predicate"],"structure":"modifier-head","register":"widely used in both formal and informal contexts","connotation":"positive","commonMistakes":"Learners might confuse this idiom with similar expressions that imply something is difficult to remove but not impossible. '不可磨灭' implies a stronger sense of permanence.","canStandAlone":false},"examples":[{"simplified":"他的贡献在历史上是不可磨灭的。","english":"His contributions are indelible in history.","traditional":"他的貢獻在歷史上是不可磨滅的。"},{"simplified":"这段经历给我留下了不可磨灭的印象。","english":"This experience left an indelible impression on me.","traditional":"這段經歷給我留下了不可磨滅的印象。"}],"synonyms":["刻骨铭心"],"antonyms":[],"confusedWith":[{"id":"难以忘怀","note":"While both imply something memorable, '难以忘怀' suggests difficulty in forgetting, not necessarily permanence."}],"traditional":"不可磨滅","pinyinOverride":null},{"id":"bu-ke-nai-he","simplified":"不可奈何","literalMeaning":"cannot do anything about it","figurativeMeaning":"to be helpless or have no choice; to be unable to do anything about a situation","englishEquivalents":["at one's wits' end","hands are tied"],"shortGloss":"helpless; no choice","characters":[{"char":"不","meaning":"not"},{"char":"可","meaning":"can; able to"},{"char":"奈","meaning":"to deal with; to cope with"},{"char":"何","meaning":"what; how"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '不可奈何' is used to describe a situation where someone feels helpless or unable to change the circumstances. It conveys a sense of resignation and acceptance that nothing can be done to alter the outcome.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"modifier-head","register":"widely used in both spoken and written Chinese","connotation":"neutral","commonMistakes":"Learners might confuse '不可奈何' with similar expressions like '无能为力' (powerless), but '不可奈何' emphasizes the inevitability and acceptance of the situation, whereas '无能为力' focuses on the lack of ability to change it.","canStandAlone":false},"examples":[{"simplified":"他对这个结果感到不可奈何。","english":"He felt helpless about the result.","traditional":"他對這個結果感到不可奈何。"},{"simplified":"面对突如其来的变化，我们也只能不可奈何地接受。","english":"Faced with sudden changes, we can only accept them helplessly.","traditional":"面對突如其來的變化，我們也只能不可奈何地接受。"}],"synonyms":["无能为力"],"antonyms":[],"confusedWith":[{"id":"无能为力","note":"'无能为力' emphasizes the lack of ability to change something, while '不可奈何' stresses the inevitability and acceptance of the situation."}],"traditional":"不可奈何","pinyinOverride":null},{"id":"bu-neng-zi-ba","simplified":"不能自拔","literalMeaning":"cannot extricate oneself","figurativeMeaning":"to be unable to free oneself from a difficult situation or emotional entanglement","englishEquivalents":["stuck in a rut","in over one's head"],"shortGloss":"unable to extricate oneself","characters":[{"char":"不","meaning":"not"},{"char":"能","meaning":"able"},{"char":"自","meaning":"self"},{"char":"拔","meaning":"pull out, extricate"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '不能自拔' is often used to describe someone who is deeply entangled in a situation, emotion, or habit from which they cannot easily free themselves. It conveys a sense of being trapped or overwhelmed, whether by circumstances or one's own feelings.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","complement"],"structure":"verb-object","register":"widely used in both formal and informal contexts","connotation":"negative","commonMistakes":"Learners often confuse this idiom with similar expressions that imply physical entrapment, but '不能自拔' is more about emotional or situational entanglement. It should not be used to describe literal physical situations.","canStandAlone":false},"examples":[{"simplified":"他对游戏上瘾，已经不能自拔。","english":"He is addicted to video games and cannot extricate himself.","traditional":"他對遊戲上癮，已經不能自拔。"},{"simplified":"她陷入了感情的漩涡，不能自拔。","english":"She is caught in a whirlpool of emotions and cannot free herself.","traditional":"她陷入了感情的漩渦，不能自拔。"}],"synonyms":["泥足深陷"],"antonyms":[],"confusedWith":[{"id":"束手无策","note":"束手无策 means to be at a loss or helpless, but it doesn't imply being trapped or entangled like 不能自拔."}],"traditional":"不能自拔","pinyinOverride":null},{"id":"bu-qi-er-hui","simplified":"不期而会","literalMeaning":"not planned yet meet","figurativeMeaning":"to meet by chance; an unexpected encounter","englishEquivalents":["a chance meeting","bump into someone"],"shortGloss":"an unexpected encounter","characters":[{"char":"不","meaning":"not"},{"char":"期","meaning":"plan"},{"char":"而","meaning":"yet"},{"char":"会","meaning":"meet"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '不期而会' describes a situation where two people meet unexpectedly without prior arrangement. It captures the idea of a serendipitous encounter, often leading to pleasant surprises or significant events.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"commonly used in both written and spoken Chinese","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with similar ones that imply intentional meetings. It's important to remember that '不期而会' specifically refers to unplanned encounters.","canStandAlone":false},"examples":[{"simplified":"我们在公园里不期而会，真是太巧了。","english":"We met by chance in the park; it was such a coincidence.","traditional":"我們在公園裡不期而會，真是太巧了。"},{"simplified":"在旅行中，我和老朋友不期而会，感到非常惊喜。","english":"During the trip, I unexpectedly met an old friend and felt very surprised.","traditional":"在旅行中，我和老朋友不期而會，感到非常驚喜。"}],"synonyms":["不期而遇"],"antonyms":[],"confusedWith":[{"id":"不期而遇","note":"Both idioms mean to meet unexpectedly, but '不期而遇' is more commonly used in modern Chinese."}],"traditional":"不期而會","pinyinOverride":null},{"id":"bu-qi-er-tong","simplified":"不期而同","literalMeaning":"not planned but same","figurativeMeaning":"to coincide by chance; to happen to agree or occur simultaneously without prior arrangement","englishEquivalents":["great minds think alike","coincidentally","by sheer coincidence"],"shortGloss":"coincide by chance","characters":[{"char":"不","meaning":"not"},{"char":"期","meaning":"expect; plan"},{"char":"而","meaning":"and; but"},{"char":"同","meaning":"same; together"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '不期而同' describes a situation where two or more people or events coincide or agree without prior planning or arrangement. It suggests a surprising or unexpected alignment of thoughts, actions, or occurrences.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"modifier-head","register":"widely used in both written and spoken Chinese","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with expressions that imply intentional agreement or planning. '不期而同' specifically refers to unplanned coincidences.","canStandAlone":false},"examples":[{"simplified":"他们不期而同地选择了同一家餐厅。","english":"They coincidentally chose the same restaurant.","traditional":"他們不期而同地選擇了同一家餐廳。"},{"simplified":"尽管没有商量，他们的意见不期而同。","english":"Even though they hadn't discussed it, their opinions coincided by chance.","traditional":"儘管沒有商量，他們的意見不期而同。"}],"synonyms":["不谋而合"],"antonyms":[],"confusedWith":[{"id":"不谋而合","note":"Both idioms describe coincidental agreement, but '不谋而合' emphasizes agreement in opinions or ideas, while '不期而同' can apply to actions and events as well."}],"traditional":"不期而同","pinyinOverride":null},{"id":"bu-ren-bu-yi","simplified":"不仁不义","literalMeaning":"not benevolent, not righteous","figurativeMeaning":"lacking in humanity and justice; cruel and unscrupulous","englishEquivalents":["heartless and unjust","cruel and unscrupulous"],"shortGloss":"cruel and unjust","characters":[{"char":"不","meaning":"not"},{"char":"仁","meaning":"benevolent"},{"char":"不","meaning":"not"},{"char":"义","meaning":"righteous"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '不仁不义' is used to describe actions or behaviors that are considered both inhumane and unjust. It is often used to criticize someone who acts with cruelty and without regard for moral principles.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"coordinate","register":"widely used in both written and spoken Chinese, often in moral or ethical contexts","connotation":"negative","commonMistakes":"Learners might confuse this idiom with similar phrases that only imply a lack of kindness or justice, but this idiom specifically conveys a strong negative judgment of both qualities.","canStandAlone":false},"examples":[{"simplified":"他的行为真是太不仁不义了。","english":"His actions are truly heartless and unjust.","traditional":"他的行為真是太不仁不義了。"},{"simplified":"在这种情况下，做出不仁不义的决定是不可接受的。","english":"In such circumstances, making a cruel and unjust decision is unacceptable.","traditional":"在這種情況下，做出不仁不義的決定是不可接受的。"}],"synonyms":["无情无义"],"antonyms":["仁义道德"],"confusedWith":[{"id":"无情无义","note":"Both imply a lack of compassion and justice, but '无情无义' emphasizes emotional coldness more than moral judgment."}],"traditional":"不仁不義","pinyinOverride":null},{"id":"bu-rong-fen-shuo","simplified":"不容分说","literalMeaning":"not allow to explain","figurativeMeaning":"to not allow any explanation or argument; to be adamant or peremptory","englishEquivalents":["no ifs, ands, or buts","no room for argument"],"shortGloss":"not allow any argument","characters":[{"char":"不","meaning":"not"},{"char":"容","meaning":"allow"},{"char":"分","meaning":"divide; here implies 'to explain'"},{"char":"说","meaning":"speak; explain"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '不容分说' is used to describe situations where no explanation or argument is allowed. It conveys a sense of finality and decisiveness, often used when someone is determined to proceed without entertaining objections or discussions.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"modifier-head","register":"commonly used in both written and spoken Chinese","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with others that involve explanation, such as '无可奈何'. However, '不容分说' specifically implies not allowing any explanation or argument, while '无可奈何' means having no choice or being helpless.","canStandAlone":false},"examples":[{"simplified":"他不容分说地拒绝了我们的请求。","english":"He refused our request without allowing any argument.","traditional":"他不容分說地拒絕了我們的請求。"},{"simplified":"经理不容分说地决定了项目的方向。","english":"The manager decided the direction of the project without allowing any discussion.","traditional":"經理不容分說地決定了項目的方向。"}],"synonyms":["不容置辩"],"antonyms":[],"confusedWith":[{"id":"无可奈何","note":"无可奈何 means having no choice or being helpless, not about refusing to allow discussion."}],"traditional":"不容分說","pinyinOverride":null},{"id":"bu-ru-shi-ming","simplified":"不辱使命","literalMeaning":"not disgrace the mission","figurativeMeaning":"to successfully fulfill a mission or task","englishEquivalents":["carry out one's duty","complete the mission"],"shortGloss":"successfully fulfill a mission","characters":[{"char":"不","meaning":"not"},{"char":"辱","meaning":"disgrace"},{"char":"使","meaning":"mission"},{"char":"命","meaning":"order; command"}],"origin":{"period":"Han Dynasty (206 BCE – 220 CE)","sourceText":"《后汉书·冯异传》","sourceTextEnglish":"Book of the Later Han, Biography of Feng Yi","originalExcerpt":"臣不敢辱使命。","storyEnglish":"The idiom originates from the story of Feng Yi, a general during the Han Dynasty. When tasked with a difficult mission, he declared that he would not disgrace the mission, implying his determination to succeed. This phrase has since been used to express the successful completion of a task or mission.","historicalFigures":["Feng Yi"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","object"],"structure":"verb-object","register":"formal written Chinese, but also used in speeches and formal contexts","connotation":"positive","commonMistakes":"Learners might confuse this idiom with similar expressions that imply failure, such as '辱使命'. It's important to note the positive connotation of '不辱'.","canStandAlone":false},"examples":[{"simplified":"他在这次任务中表现出色，不辱使命。","english":"He performed excellently in this mission and did not disgrace the mission.","traditional":"他在這次任務中表現出色，不辱使命。"},{"simplified":"经过多年的努力，团队终于不辱使命，完成了项目。","english":"After years of effort, the team finally fulfilled the mission and completed the project.","traditional":"經過多年的努力，團隊終於不辱使命，完成了項目。"}],"synonyms":["功成名就","大功告成"],"antonyms":["功败垂成"],"confusedWith":[{"id":"辱使命","note":"This phrase implies failure or disgrace in carrying out a mission, opposite to '不辱使命'."}],"traditional":"不辱使命","pinyinOverride":null},{"id":"bu-san-bu-si","simplified":"不三不四","literalMeaning":"not three not four","figurativeMeaning":"dubious; shady; neither one thing nor the other","englishEquivalents":["neither fish nor fowl","shady character"],"shortGloss":"dubious or shady","characters":[{"char":"不","meaning":"not"},{"char":"三","meaning":"three"},{"char":"不","meaning":"not"},{"char":"四","meaning":"four"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '不三不四' is believed to have originated from a folk saying that describes something or someone as not fitting into any recognized category or standard. It conveys a sense of being dubious or not respectable, as if the person or thing is neither here nor there, neither three nor four.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["attributive","predicate"],"structure":"coordinate","register":"informal, commonly used in both spoken and written Chinese","connotation":"negative","commonMistakes":"Learners often misinterpret this idiom as simply meaning 'ambiguous' without the negative connotation of being disreputable or shady. It is important to recognize the negative judgment implied in its use.","canStandAlone":false},"examples":[{"simplified":"他总是和一些不三不四的人混在一起。","english":"He always hangs out with some dubious characters.","traditional":"他總是和一些不三不四的人混在一起。"},{"simplified":"这家店的东西看起来不三不四，我不敢买。","english":"The items in this shop look shady; I don't dare to buy them.","traditional":"這家店的東西看起來不三不四，我不敢買。"}],"synonyms":["不伦不类"],"antonyms":[],"confusedWith":[{"id":"不伦不类","note":"While both idioms suggest something doesn't fit into a category, '不三不四' implies a negative, shady connotation, whereas '不伦不类' is more about being mismatched or incongruous without the negative judgment."}],"traditional":"不三不四","pinyinOverride":null},{"id":"bu-seng-bu-su","simplified":"不僧不俗","literalMeaning":"neither monk nor layman","figurativeMeaning":"to be in an ambiguous or undefined state; neither one thing nor another","englishEquivalents":["neither fish nor fowl","betwixt and between"],"shortGloss":"neither one thing nor another","characters":[{"char":"不","meaning":"not"},{"char":"僧","meaning":"monk"},{"char":"不","meaning":"not"},{"char":"俗","meaning":"layman"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '不僧不俗' describes a person or situation that doesn't fit neatly into a defined category. It suggests a state of being that is neither fully one thing nor another, similar to being caught between two worlds. The phrase uses the imagery of a monk (僧) and a layperson (俗) to illustrate this ambiguity.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"coordinate","register":"commonly used in both spoken and written Chinese","connotation":"neutral","commonMistakes":"Learners might mistakenly use this idiom to describe someone who is indecisive, but it specifically refers to being in an ambiguous state rather than indecision.","canStandAlone":false},"examples":[{"simplified":"他的穿着不僧不俗，让人看不出他的身份。","english":"His attire was neither monk-like nor layman-like, making it hard to discern his identity.","traditional":"他的穿著不僧不俗，讓人看不出他的身份。"},{"simplified":"这部电影的风格不僧不俗，吸引了很多观众。","english":"The movie's style was neither conventional nor unconventional, attracting a wide audience.","traditional":"這部電影的風格不僧不俗，吸引了很多觀眾。"}],"synonyms":[],"antonyms":[],"confusedWith":[{"id":"不伦不类","note":"While both idioms describe something that doesn't fit neatly into a category, '不伦不类' often carries a negative connotation of being awkward or inappropriate."}],"traditional":"不僧不俗","pinyinOverride":null},{"id":"bu-shang-pi-wei","simplified":"不伤脾胃","literalMeaning":"not harm the spleen and stomach","figurativeMeaning":"to not cause harm or offense; to be harmless or innocuous","englishEquivalents":["harmless","innocuous"],"shortGloss":"harmless, innocuous","characters":[{"char":"不","meaning":"not"},{"char":"伤","meaning":"harm"},{"char":"脾","meaning":"spleen"},{"char":"胃","meaning":"stomach"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom 不伤脾胃 is believed to have originated from traditional Chinese medicine, where the spleen and stomach are considered vital for digestion and overall health. The phrase metaphorically suggests that something is harmless or does not cause discomfort, much like food that is gentle on the digestive system.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"modifier-head","register":"commonly used in both spoken and written Chinese to describe something as harmless or inoffensive","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with expressions that describe physical health rather than metaphorical harmlessness. It's important to use it in contexts where the meaning is metaphorical.","canStandAlone":false},"examples":[{"simplified":"他的玩笑很幽默，不伤脾胃。","english":"His jokes are very humorous and harmless.","traditional":"他的玩笑很幽默，不傷脾胃。"},{"simplified":"这部电影轻松有趣，不伤脾胃。","english":"This movie is light-hearted and fun, without causing any offense.","traditional":"這部電影輕鬆有趣，不傷脾胃。"}],"synonyms":[],"antonyms":[],"confusedWith":[],"traditional":"不傷脾胃","pinyinOverride":null},{"id":"bu-sheng-bu-mie","simplified":"不生不灭","literalMeaning":"neither born nor destroyed","figurativeMeaning":"eternal and unchanging; beyond birth and death","englishEquivalents":["eternal","unchanging","immutable"],"shortGloss":"eternal and unchanging","characters":[{"char":"不","meaning":"not"},{"char":"生","meaning":"born; arise"},{"char":"不","meaning":"not"},{"char":"灭","meaning":"destroyed; extinguished"}],"origin":{"period":"Buddhist texts","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '不生不灭' is often associated with Buddhist philosophy, where it describes the nature of ultimate reality or Nirvana, which is beyond the cycles of birth and death. It suggests a state of permanence and constancy, unaffected by the transient nature of the world.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"coordinate","register":"literary, often used in philosophical or religious contexts","connotation":"neutral","commonMistakes":"Learners may confuse this idiom with similar expressions that describe impermanence. It's important to note that '不生不灭' refers to something eternal and unchanging, unlike idioms that describe transient states.","canStandAlone":false},"examples":[{"simplified":"佛教认为涅槃是不生不灭的境界。","english":"Buddhism considers Nirvana as a state that is eternal and unchanging.","traditional":"佛教認為涅槃是不生不滅的境界。"},{"simplified":"他的信念如同不生不灭的真理，坚定不移。","english":"His belief is like an eternal truth, unwavering and constant.","traditional":"他的信念如同不生不滅的真理，堅定不移。"}],"synonyms":[],"antonyms":[],"confusedWith":[],"traditional":"不生不滅","pinyinOverride":null},{"id":"bu-sheng-bu-keng","simplified":"不声不吭","literalMeaning":"not a sound, not a word","figurativeMeaning":"to remain silent; to not say a word","englishEquivalents":["silent as the grave","not a peep"],"shortGloss":"remain silent","characters":[{"char":"不","meaning":"not"},{"char":"声","meaning":"sound"},{"char":"不","meaning":"not"},{"char":"吭","meaning":"utter a word"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '不声不吭' describes a situation where someone remains completely silent, not making any noise or uttering any words. It is often used to describe a person who chooses not to speak or react in a situation where others might expect them to.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["adverbial","predicate"],"structure":"coordinate","register":"commonly used in both spoken and written Chinese","connotation":"neutral","commonMistakes":"Learners might confuse '不声不吭' with '默不作声', which also means to remain silent but can imply a more deliberate choice to not speak. '不声不吭' is more about the absence of sound or speech rather than a deliberate choice.","canStandAlone":false},"examples":[{"simplified":"他整晚都不声不吭，让人觉得很奇怪。","english":"He remained silent the whole evening, which made people feel strange.","traditional":"他整晚都不聲不吭，讓人覺得很奇怪。"},{"simplified":"会议上，他一直不声不吭，似乎心不在焉。","english":"During the meeting, he didn't say a word, seeming absent-minded.","traditional":"會議上，他一直不聲不吭，似乎心不在焉。"}],"synonyms":["默不作声"],"antonyms":[],"confusedWith":[{"id":"默不作声","note":"Both mean to remain silent, but '默不作声' can imply a more deliberate choice to stay silent."}],"traditional":"不聲不吭","pinyinOverride":null},{"id":"bu-wei-yi-shen","simplified":"不为已甚","literalMeaning":"not do excessively","figurativeMeaning":"to not overdo it; to stop before going too far","englishEquivalents":["don't overdo it","know when to stop"],"shortGloss":"don't overdo it","characters":[{"char":"不","meaning":"not"},{"char":"为","meaning":"do"},{"char":"已","meaning":"already"},{"char":"甚","meaning":"excessively"}],"origin":{"period":"Warring States period (475–221 BCE)","sourceText":"《论语·先进》","sourceTextEnglish":"Analects of Confucius, Chapter Xianjin","originalExcerpt":"子曰：“君子和而不同，小人同而不和。君子不为已甚。”","storyEnglish":"This idiom comes from the Analects of Confucius, where Confucius discusses the behavior of a gentleman (junzi). He advises that a gentleman should be harmonious but not blindly conforming, and should not go to extremes. The phrase '不为已甚' suggests that one should exercise restraint and moderation.","historicalFigures":["Confucius"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"modifier-head","register":"literary, but can be used in formal spoken contexts","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with similar-sounding phrases that imply doing something excessively, rather than avoiding excess. It's important to remember that this idiom advises moderation.","canStandAlone":false},"examples":[{"simplified":"在批评别人时，我们应该不为已甚。","english":"When criticizing others, we should not overdo it.","traditional":"在批評別人時，我們應該不為已甚。"},{"simplified":"他知道什么时候该不为已甚，适可而止。","english":"He knows when to stop and not overdo it.","traditional":"他知道什麼時候該不為已甚，適可而止。"}],"synonyms":["适可而止"],"antonyms":[],"confusedWith":[{"id":"得寸进尺","note":"得寸进尺 means to take advantage and push for more, while 不为已甚 means to exercise restraint."}],"traditional":"不為已甚","pinyinOverride":null},{"id":"bu-wen-bu-wen","simplified":"不闻不问","literalMeaning":"not hear, not ask","figurativeMeaning":"to be indifferent or unconcerned; to ignore something","englishEquivalents":["turn a blind eye","bury one's head in the sand"],"shortGloss":"indifferent or unconcerned","characters":[{"char":"不","meaning":"not"},{"char":"闻","meaning":"hear"},{"char":"不","meaning":"not"},{"char":"问","meaning":"ask"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '不闻不问' describes a situation where someone deliberately chooses not to listen or inquire about something, often implying a lack of concern or responsibility. It suggests a willful ignorance or avoidance of involvement.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"coordinate","register":"commonly used in both spoken and written Chinese","connotation":"negative","commonMistakes":"Learners often confuse this idiom with '置之不理' (ignore deliberately), but '不闻不问' emphasizes a passive indifference rather than an active decision to ignore.","canStandAlone":false},"examples":[{"simplified":"对于这些问题，他总是不闻不问。","english":"He always turns a blind eye to these issues.","traditional":"對於這些問題，他總是不聞不問。"},{"simplified":"面对朋友的困难，她选择不闻不问。","english":"She chose to ignore her friend's difficulties.","traditional":"面對朋友的困難，她選擇不聞不問。"}],"synonyms":["置若罔闻","漠不关心"],"antonyms":["关心则乱","刨根问底"],"confusedWith":[{"id":"置之不理","note":"不闻不问 implies passive indifference, while 置之不理 suggests an active decision to ignore."}],"traditional":"不聞不問","pinyinOverride":null},{"id":"bu-xiao-zi-sun","simplified":"不肖子孙","literalMeaning":"unworthy descendants","figurativeMeaning":"unworthy or disappointing descendants who fail to live up to their ancestors' legacy","englishEquivalents":["black sheep","disgrace to the family"],"shortGloss":"unworthy descendants","characters":[{"char":"不","meaning":"not"},{"char":"肖","meaning":"resemble; worthy"},{"char":"子","meaning":"child"},{"char":"孙","meaning":"grandchild; descendant"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '不肖子孙' refers to descendants who do not live up to the virtues or achievements of their ancestors. It is often used to express disappointment in younger generations who fail to carry on the family legacy or bring shame to their family name.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["subject","predicate","object","attributive"],"structure":"modifier-head","register":"commonly used in both written and spoken Chinese, often in a critical or disapproving context","connotation":"negative","commonMistakes":"Learners might confuse '不肖子孙' with '孝顺' (filial piety), which has a positive connotation. It's important to remember that '不肖' indicates a lack of worthiness or resemblance to virtuous ancestors.","canStandAlone":false},"examples":[{"simplified":"他被认为是不肖子孙，因为他没有继承家族的优良传统。","english":"He is considered an unworthy descendant because he did not carry on the family's fine traditions.","traditional":"他被認為是不肖子孫，因為他沒有繼承家族的優良傳統。"},{"simplified":"这些不肖子孙让祖先蒙羞。","english":"These unworthy descendants bring shame to their ancestors.","traditional":"這些不肖子孫讓祖先蒙羞。"}],"synonyms":["败家子"],"antonyms":["孝子贤孙"],"confusedWith":[{"id":"孝顺","note":"While '不肖子孙' refers to unworthy descendants, '孝顺' means filial piety and respect towards one's parents."}],"traditional":"不肖子孫","pinyinOverride":null},{"id":"bu-yan-bu-yu","simplified":"不言不语","literalMeaning":"not speaking, not talking","figurativeMeaning":"keeping silent; not saying a word","englishEquivalents":["silent as the grave","tight-lipped"],"shortGloss":"keeping silent","characters":[{"char":"不","meaning":"not"},{"char":"言","meaning":"speak"},{"char":"不","meaning":"not"},{"char":"语","meaning":"talk"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '不言不语' is used to describe someone who remains silent and does not engage in conversation. It is often used to depict a person who is either deliberately choosing not to speak or is in a situation where they prefer to remain quiet. The exact origin of the idiom is unclear, but it has been widely used in Chinese literature and conversation to convey the idea of silence.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"coordinate","register":"commonly used in both spoken and written Chinese","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with others that imply refusal to speak due to anger or stubbornness, but '不言不语' is neutral and doesn't imply a specific reason for the silence.","canStandAlone":false},"examples":[{"simplified":"他整晚不言不语，似乎有心事。","english":"He was silent all night, seemingly preoccupied with something.","traditional":"他整晚不言不語，似乎有心事。"},{"simplified":"在会议上，她不言不语，只是认真地听。","english":"During the meeting, she kept silent and just listened attentively.","traditional":"在會議上，她不言不語，只是認真地聽。"}],"synonyms":["默不作声","沉默寡言"],"antonyms":["滔滔不绝"],"confusedWith":[{"id":"默不作声","note":"Both mean keeping silent, but '默不作声' emphasizes not making any sound at all."}],"traditional":"不言不語","pinyinOverride":null},{"id":"bu-yan-qi-xiang","simplified":"不厌其详","literalMeaning":"not tire of its details","figurativeMeaning":"to be willing to go into great detail; to not mind explaining something thoroughly","englishEquivalents":["go into detail","leave no stone unturned"],"shortGloss":"willing to explain in detail","characters":[{"char":"不","meaning":"not"},{"char":"厌","meaning":"tire of"},{"char":"其","meaning":"its"},{"char":"详","meaning":"details"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom 不厌其详 is used to describe someone who is willing to provide a thorough and detailed explanation or description, without becoming impatient or bored. It reflects an attitude of patience and thoroughness, often in contexts where understanding or clarity is important.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"modifier-head","register":"commonly used in both spoken and written Chinese, especially in formal contexts","connotation":"positive","commonMistakes":"Learners might confuse 不厌其详 with similar expressions that imply verbosity without purpose. This idiom specifically conveys thoroughness with a positive connotation.","canStandAlone":false},"examples":[{"simplified":"他在报告中不厌其详地解释了每一个步骤。","english":"He explained each step in detail in his report.","traditional":"他在報告中不厭其詳地解釋了每一個步驟。"},{"simplified":"她总是愿意不厌其详地回答学生的问题。","english":"She is always willing to answer students' questions in detail.","traditional":"她總是願意不厭其詳地回答學生的問題。"}],"synonyms":["详详细细","事无巨细"],"antonyms":["一笔带过"],"confusedWith":[{"id":"长篇大论","note":"长篇大论 implies lengthy and possibly tedious discourse, while 不厌其详 emphasizes thoroughness and clarity."}],"traditional":"不厭其詳","pinyinOverride":null},{"id":"bu-yao-er-yu","simplified":"不药而愈","literalMeaning":"without medicine yet healed","figurativeMeaning":"to recover naturally without intervention; to resolve a problem on its own","englishEquivalents":["heal on its own","self-correcting"],"shortGloss":"recover without treatment","characters":[{"char":"不","meaning":"not"},{"char":"药","meaning":"medicine"},{"char":"而","meaning":"yet; but"},{"char":"愈","meaning":"heal; recover"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '不药而愈' describes a situation where an illness or problem resolves itself without the need for medicine or intervention. It is often used metaphorically to describe situations where issues resolve on their own without external help.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","complement"],"structure":"cause-effect","register":"commonly used in both spoken and written Chinese","connotation":"positive","commonMistakes":"Learners might confuse this idiom with others that involve healing or medicine, but '不药而愈' specifically emphasizes the absence of intervention. It should not be used for situations where treatment or action was necessary.","canStandAlone":false},"examples":[{"simplified":"他的感冒不药而愈，真是幸运。","english":"His cold healed on its own, which was really fortunate.","traditional":"他的感冒不藥而癒，真是幸運。"},{"simplified":"有些小问题会不药而愈，不需要太担心。","english":"Some minor issues will resolve themselves, so there's no need to worry too much.","traditional":"有些小問題會不藥而癒，不需要太擔心。"}],"synonyms":[],"antonyms":[],"confusedWith":[{"id":"药到病除","note":"药到病除 means 'the medicine works immediately', emphasizing effective treatment, unlike 不药而愈 which implies no treatment was needed."}],"traditional":"不藥而癒","pinyinOverride":null},{"id":"bu-yi-zhi-lun","simplified":"不易之论","literalMeaning":"not easy of discussion","figurativeMeaning":"an unassailable argument or irrefutable statement","englishEquivalents":["an irrefutable argument","a sound argument","an unassailable point"],"shortGloss":"an irrefutable argument","characters":[{"char":"不","meaning":"not"},{"char":"易","meaning":"easy"},{"char":"之","meaning":"of"},{"char":"论","meaning":"discussion, argument"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '不易之论' is used to describe an argument or statement that is so well-founded and logical that it cannot be easily refuted or disputed. The phrase emphasizes the strength and soundness of the argument being made.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["subject","object","attributive"],"structure":"modifier-head","register":"literary, but can be used in formal speech and writing","connotation":"positive","commonMistakes":"Learners might confuse this idiom with others that involve '论' (discussion) but lack the emphasis on irrefutability. It's important to use it only when the argument is truly strong and well-supported.","canStandAlone":false},"examples":[{"simplified":"他的观点是一个不易之论，令人信服。","english":"His viewpoint is an irrefutable argument, convincing to all.","traditional":"他的觀點是一個不易之論，令人信服。"},{"simplified":"在辩论中，她提出了一个不易之论，赢得了大家的赞同。","english":"In the debate, she presented an unassailable point that won everyone's approval.","traditional":"在辯論中，她提出了一個不易之論，贏得了大家的贊同。"}],"synonyms":["无懈可击"],"antonyms":[],"confusedWith":[{"id":"无可辩驳","note":"While both imply strong arguments, '无可辩驳' emphasizes that there is no room for counterargument, whereas '不易之论' highlights the difficulty in refuting the argument."}],"traditional":"不易之論","pinyinOverride":null},{"id":"bu-zu-wei-fa","simplified":"不足为法","literalMeaning":"not enough to be a model","figurativeMeaning":"not worth following as an example; not a good role model","englishEquivalents":["not worth emulating","not a good example to follow"],"shortGloss":"not worth following as a model","characters":[{"char":"不","meaning":"not"},{"char":"足","meaning":"sufficient"},{"char":"为","meaning":"to be"},{"char":"法","meaning":"a model or example"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom 不足为法 is used to express that something or someone is not worthy of being used as a model or example. It suggests that the actions or qualities in question are insufficient or inappropriate to be emulated.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"commonly used in both written and spoken Chinese","connotation":"negative","commonMistakes":"Learners might confuse this idiom with similar-sounding phrases that have positive connotations. It's important to remember that 不足为法 carries a negative judgment about the suitability of something as a model.","canStandAlone":false},"examples":[{"simplified":"他的行为不足为法，我们应该另找榜样。","english":"His behavior is not worth emulating; we should look for another role model.","traditional":"他的行為不足為法，我們應該另找榜樣。"},{"simplified":"这种做法在现代社会中已经不足为法。","english":"This method is no longer worth following in modern society.","traditional":"這種做法在現代社會中已經不足為法。"}],"synonyms":[],"antonyms":[],"confusedWith":[],"traditional":"不足為法","pinyinOverride":null},{"id":"bu-zu-wei-lu","simplified":"不足为虑","literalMeaning":"not enough to be a concern","figurativeMeaning":"not worth worrying about; insignificant","englishEquivalents":["not worth worrying about","no cause for concern"],"shortGloss":"not worth worrying about","characters":[{"char":"不","meaning":"not"},{"char":"足","meaning":"enough"},{"char":"为","meaning":"to be"},{"char":"虑","meaning":"concern"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom 不足为虑 is used to express that something is too trivial or minor to be worth worrying about. It is often used to reassure someone that a problem or issue is not significant enough to cause concern.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","complement"],"structure":"modifier-head","register":"common in both written and spoken Chinese","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with similar expressions that imply a more positive reassurance, but 不足为虑 is more neutral, simply stating that something is not worth worrying about.","canStandAlone":false},"examples":[{"simplified":"这个小问题不足为虑，我们可以很快解决。","english":"This small problem is not worth worrying about; we can solve it quickly.","traditional":"這個小問題不足為慮，我們可以很快解決。"},{"simplified":"虽然有些困难，但都不足为虑。","english":"Although there are some difficulties, they are not worth worrying about.","traditional":"雖然有些困難，但都不足為慮。"}],"synonyms":["无关紧要","微不足道"],"antonyms":["迫在眉睫","刻不容缓"],"confusedWith":[{"id":"无关紧要","note":"无关紧要 means something is irrelevant or insignificant, while 不足为虑 specifically means not worth worrying about."}],"traditional":"不足為慮","pinyinOverride":null},{"id":"bu-zu-wei-yi","simplified":"不足为意","literalMeaning":"not worth considering","figurativeMeaning":"not worth mentioning; insignificant","englishEquivalents":["not worth mentioning","nothing to write home about"],"shortGloss":"insignificant, not worth mentioning","characters":[{"char":"不","meaning":"not"},{"char":"足","meaning":"sufficient"},{"char":"为","meaning":"to be"},{"char":"意","meaning":"consideration"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '不足为意' is used to express that something is too trivial or insignificant to be worth considering or mentioning. It is often used to downplay an achievement or a compliment, suggesting that it is not a big deal.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","complement"],"structure":"modifier-head","register":"widely used in both formal and informal contexts","connotation":"neutral","commonMistakes":"Learners often confuse '不足为意' with '不足挂齿', which also means 'not worth mentioning' but is more often used to modestly downplay one's own achievements.","canStandAlone":false},"examples":[{"simplified":"这点小事，不足为意。","english":"This small matter is not worth mentioning.","traditional":"這點小事，不足為意。"},{"simplified":"他的贡献虽然不大，但也不能说不足为意。","english":"Although his contribution is not large, it cannot be said to be insignificant.","traditional":"他的貢獻雖然不大，但也不能說不足為意。"}],"synonyms":["不足挂齿"],"antonyms":[],"confusedWith":[{"id":"不足挂齿","note":"Both mean 'not worth mentioning', but '不足挂齿' is often used to modestly downplay one's own achievements."}],"traditional":"不足為意","pinyinOverride":null},{"id":"bu-bu-gao-sheng","simplified":"步步高升","literalMeaning":"step by step, rise high","figurativeMeaning":"to rise steadily in position or rank","englishEquivalents":["rise through the ranks","climb the ladder","advance step by step"],"shortGloss":"rise steadily in rank","characters":[{"char":"步","meaning":"step"},{"char":"步","meaning":"step"},{"char":"高","meaning":"high"},{"char":"升","meaning":"rise"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom 步步高升 is commonly used to wish someone success in their career, implying a steady and continuous rise in rank or position. It reflects the idea of progressing step by step towards a higher status, often used in contexts such as promotions or career advancements.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"commonly used in both formal and informal contexts, especially in congratulatory messages","connotation":"positive","commonMistakes":"Learners might confuse this idiom with those that imply sudden success, but 步步高升 emphasizes gradual progress. It should not be used to describe immediate or unexpected success.","canStandAlone":false},"examples":[{"simplified":"祝你在新的一年里步步高升。","english":"I wish you steady advancement in the new year.","traditional":"祝你在新的一年裡步步高昇。"},{"simplified":"他在公司里步步高升，已经成为部门经理。","english":"He has steadily risen through the ranks in the company and has become the department manager.","traditional":"他在公司裡步步高昇，已經成為部門經理。"}],"synonyms":["节节高升"],"antonyms":["原地踏步"],"confusedWith":[{"id":"一飞冲天","note":"一飞冲天 implies a sudden rise or success, unlike the gradual progress of 步步高升."}],"traditional":"步步高昇","pinyinOverride":null},{"id":"bu-diao-yi-zhi","simplified":"步调一致","literalMeaning":"step rhythm identical","figurativeMeaning":"to act in unison or to be in sync","englishEquivalents":["in step","in sync","on the same page"],"shortGloss":"acting in unison","characters":[{"char":"步","meaning":"step"},{"char":"调","meaning":"rhythm"},{"char":"一","meaning":"one; identical"},{"char":"致","meaning":"consistent; in agreement"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '步调一致' likely originates from military contexts where soldiers are required to march in step to maintain order and cohesion. Over time, it has come to be used more broadly to describe any situation where people or groups are working together harmoniously and with a shared purpose.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"modifier-head","register":"common in both written and spoken Chinese, used in formal and informal contexts","connotation":"positive","commonMistakes":"Learners might confuse this idiom with similar expressions that imply mere agreement rather than coordinated action. It's important to note that '步调一致' emphasizes synchronization and harmony in action, not just agreement in opinion.","canStandAlone":false},"examples":[{"simplified":"团队成员之间步调一致，项目进展得很顺利。","english":"The team members were in sync, and the project progressed smoothly.","traditional":"團隊成員之間步調一致，項目進展得很順利。"},{"simplified":"在这个关键时刻，我们必须步调一致，共同面对挑战。","english":"At this critical moment, we must act in unison to face the challenges together.","traditional":"在這個關鍵時刻，我們必須步調一致，共同面對挑戰。"}],"synonyms":["齐心协力","同心协力"],"antonyms":["各行其是"],"confusedWith":[{"id":"步步为营","note":"While '步步为营' emphasizes cautious progress, '步调一致' focuses on synchronized action."}],"traditional":"步調一致","pinyinOverride":null},{"id":"bu-lv-wei-jian","simplified":"步履维艰","literalMeaning":"steps are difficult","figurativeMeaning":"to struggle or face difficulties in progress","englishEquivalents":["to walk on thin ice","to be in a tight spot"],"shortGloss":"struggling to progress","characters":[{"char":"步","meaning":"step"},{"char":"履","meaning":"walk"},{"char":"维","meaning":"maintain"},{"char":"艰","meaning":"difficult"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom 步履维艰 is used to describe a situation where someone is finding it difficult to make progress, whether physically or metaphorically. It evokes the image of someone struggling to walk, with each step being a challenge. This can apply to various contexts, such as a business facing tough times or an individual dealing with personal challenges.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"modifier-head","register":"commonly used in both written and spoken Chinese to describe challenging situations","connotation":"negative","commonMistakes":"Learners might confuse this idiom with ones that imply physical difficulty only, but it is often used metaphorically to describe any difficult situation. It should not be used to describe situations that are merely inconvenient or slightly challenging.","canStandAlone":false},"examples":[{"simplified":"在经济不景气的情况下，公司步履维艰。","english":"In the face of an economic downturn, the company is struggling to make progress.","traditional":"在經濟不景氣的情況下，公司步履維艱。"},{"simplified":"他在学习新语言时步履维艰，但从未放弃。","english":"He struggled to make progress while learning a new language, but he never gave up.","traditional":"他在學習新語言時步履維艱，但從未放棄。"}],"synonyms":["举步维艰"],"antonyms":[],"confusedWith":[{"id":"举步维艰","note":"Both idioms describe difficulty in making progress, but 步履维艰 is more commonly used."}],"traditional":"步履維艱","pinyinOverride":null},{"id":"bu-ke-shou-shi","simplified":"不可收拾","literalMeaning":"cannot be tidied up","figurativeMeaning":"beyond repair or control; in a hopeless mess","englishEquivalents":["beyond redemption","irreparable","in shambles"],"shortGloss":"beyond repair or control","characters":[{"char":"不","meaning":"not"},{"char":"可","meaning":"can, able to"},{"char":"收","meaning":"gather, collect"},{"char":"拾","meaning":"tidy up, put in order"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '不可收拾' is used to describe a situation that has become so chaotic or problematic that it cannot be easily resolved or fixed. It is often used in contexts where things have spiraled out of control, whether in personal relationships, business, or other scenarios.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","complement"],"structure":"modifier-head","register":"commonly used in both spoken and written Chinese","connotation":"negative","commonMistakes":"Learners might confuse this idiom with positive expressions due to misunderstanding the context. It is important to remember that it always carries a negative connotation, indicating a situation that is out of control.","canStandAlone":false},"examples":[{"simplified":"他的公司因为管理不善，最终变得不可收拾。","english":"His company became beyond repair due to poor management.","traditional":"他的公司因為管理不善，最終變得不可收拾。"},{"simplified":"如果不及时解决这个问题，情况可能会变得不可收拾。","english":"If this issue is not resolved in time, the situation might become irreparable.","traditional":"如果不及時解決這個問題，情況可能會變得不可收拾。"}],"synonyms":["无可救药","不可救药"],"antonyms":[],"confusedWith":[{"id":"不可救药","note":"Both imply a hopeless situation, but '不可救药' often refers to people or things that are beyond saving, whereas '不可收拾' is more about situations or messes."}],"traditional":"不可收拾","pinyinOverride":null},{"id":"bu-ke-yu-yue","simplified":"不可逾越","literalMeaning":"cannot be surpassed","figurativeMeaning":"insurmountable; impossible to overcome","englishEquivalents":["insurmountable","beyond reach"],"shortGloss":"insurmountable obstacle","characters":[{"char":"不","meaning":"not"},{"char":"可","meaning":"can, able to"},{"char":"逾","meaning":"exceed, surpass"},{"char":"越","meaning":"cross over, go beyond"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '不可逾越' is used to describe obstacles or challenges that are extremely difficult or impossible to overcome. It emphasizes the idea of a boundary or limit that cannot be crossed or surpassed.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"modifier-head","register":"commonly used in both formal and informal contexts","connotation":"neutral","commonMistakes":"Learners might confuse '不可逾越' with similar expressions that imply difficulty but not impossibility. It's important to note that '不可逾越' suggests an absolute barrier, not just a challenging one.","canStandAlone":false},"examples":[{"simplified":"这座山对他们来说是不可逾越的障碍。","english":"This mountain is an insurmountable obstacle for them.","traditional":"這座山對他們來說是不可逾越的障礙。"},{"simplified":"在他的职业生涯中，这个问题似乎是一个不可逾越的难题。","english":"In his career, this issue seems to be an insurmountable problem.","traditional":"在他的職業生涯中，這個問題似乎是一個不可逾越的難題。"}],"synonyms":["难以逾越"],"antonyms":[],"confusedWith":[{"id":"难以克服","note":"While '难以克服' means difficult to overcome, '不可逾越' implies an absolute impossibility."}],"traditional":"不可逾越","pinyinOverride":null},{"id":"bu-lin-ci-jiao","simplified":"不吝赐教","literalMeaning":"not stingy in granting instruction","figurativeMeaning":"to kindly give advice or instruction; often used as a polite request for guidance","englishEquivalents":["Please enlighten me","I would appreciate your guidance"],"shortGloss":"kindly give advice","characters":[{"char":"不","meaning":"not"},{"char":"吝","meaning":"stingy"},{"char":"赐","meaning":"grant"},{"char":"教","meaning":"instruction"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '不吝赐教' is often used in a humble context, where someone is asking for advice or instruction from someone more knowledgeable. It conveys a sense of respect and willingness to learn.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","standalone-exclamation"],"structure":"verb-object","register":"polite and formal, often used in written communication or respectful speech","connotation":"positive","commonMistakes":"Learners might use this idiom in casual contexts where it can sound overly formal or deferential. It is best used when genuinely seeking advice from someone respected.","canStandAlone":true},"examples":[{"simplified":"如果您有时间，希望您不吝赐教。","english":"If you have time, I hope you will kindly give your advice.","traditional":"如果您有時間，希望您不吝賜教。"},{"simplified":"在这个项目上，我需要您的帮助，请不吝赐教。","english":"I need your help on this project, please kindly give your guidance.","traditional":"在這個項目上，我需要您的幫助，請不吝賜教。"}],"synonyms":[],"antonyms":[],"confusedWith":[{"id":"请多指教","note":"Both are polite requests for guidance, but '请多指教' is more commonly used in introductions or when starting a new relationship, while '不吝赐教' is more formal and used in specific contexts of seeking advice."}],"traditional":"不吝賜教","pinyinOverride":null},{"id":"bu-lun-bu-lei","simplified":"不伦不类","literalMeaning":"neither kind nor type","figurativeMeaning":"neither fish nor fowl; neither one thing nor the other","englishEquivalents":["neither fish nor fowl","neither here nor there"],"shortGloss":"neither one thing nor another","characters":[{"char":"不","meaning":"not"},{"char":"伦","meaning":"kind; type"},{"char":"不","meaning":"not"},{"char":"类","meaning":"category; type"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom 不伦不类 is used to describe something that does not fit neatly into any recognized category or type. It is often applied to things that are awkwardly or poorly matched, or that fail to conform to expectations or norms. The origin of this idiom is not clearly traceable to a specific classical text, suggesting it may have evolved through common usage over time.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"coordinate","register":"commonly used in both spoken and written Chinese","connotation":"negative","commonMistakes":"Learners often confuse 不伦不类 with idioms that imply uniqueness or originality, but it actually carries a negative connotation of awkwardness or lack of conformity. It should not be used to praise creativity.","canStandAlone":false},"examples":[{"simplified":"他的设计风格不伦不类，难以让人接受。","english":"His design style is neither fish nor fowl, making it hard for people to accept.","traditional":"他的設計風格不倫不類，難以讓人接受。"},{"simplified":"这篇文章写得不伦不类，不知道作者想表达什么。","english":"This article is written in a way that is neither here nor there; it's unclear what the author is trying to convey.","traditional":"這篇文章寫得不倫不類，不知道作者想表達什麼。"}],"synonyms":["四不像"],"antonyms":[],"confusedWith":[{"id":"别具一格","note":"别具一格 means having a unique style, which is positive, unlike the negative connotation of 不伦不类."}],"traditional":"不倫不類","pinyinOverride":null},{"id":"bu-luo-su-tao","simplified":"不落俗套","literalMeaning":"not fall into conventional patterns","figurativeMeaning":"to be unconventional or original","englishEquivalents":["break the mold","think outside the box"],"shortGloss":"unconventional or original","characters":[{"char":"不","meaning":"not"},{"char":"落","meaning":"fall into"},{"char":"俗","meaning":"common, conventional"},{"char":"套","meaning":"pattern, mold"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '不落俗套' is used to describe someone or something that does not conform to traditional or conventional ways. It emphasizes originality and uniqueness, suggesting a departure from the ordinary or expected patterns.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"modifier-head","register":"commonly used in both spoken and written Chinese to praise creativity or originality","connotation":"positive","commonMistakes":"Learners might confuse this idiom with '标新立异', which also means to be unconventional but often implies a deliberate attempt to be different, sometimes with a negative connotation.","canStandAlone":false},"examples":[{"simplified":"他的设计风格不落俗套，令人耳目一新。","english":"His design style is unconventional and refreshing.","traditional":"他的設計風格不落俗套，令人耳目一新。"},{"simplified":"这部电影的剧情不落俗套，给观众带来了惊喜。","english":"The plot of this movie is unconventional, bringing a pleasant surprise to the audience.","traditional":"這部電影的劇情不落俗套，給觀眾帶來了驚喜。"}],"synonyms":["标新立异"],"antonyms":["循规蹈矩"],"confusedWith":[{"id":"标新立异","note":"While both idioms praise originality, '标新立异' can imply a negative sense of being different for the sake of it."}],"traditional":"不落俗套","pinyinOverride":null},{"id":"bu-sheng-bu-xiang","simplified":"不声不响","literalMeaning":"no sound, no noise","figurativeMeaning":"quietly; without making a fuss or attracting attention","englishEquivalents":["quiet as a mouse","without a peep"],"shortGloss":"quietly, without fuss","characters":[{"char":"不","meaning":"not"},{"char":"声","meaning":"sound, voice"},{"char":"不","meaning":"not"},{"char":"响","meaning":"noise, sound"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '不声不响' describes someone or something that acts quietly or without drawing attention. It is often used to describe actions done discreetly or without public notice.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["adverbial"],"structure":"coordinate","register":"commonly used in both written and spoken Chinese","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with similar expressions that imply silence but have different connotations, such as '默默无闻', which suggests being unknown or unnoticed rather than simply quiet.","canStandAlone":false},"examples":[{"simplified":"他不声不响地完成了所有工作。","english":"He quietly completed all the work.","traditional":"他不聲不響地完成了所有工作。"},{"simplified":"她不声不响地离开了房间，没有人注意到。","english":"She left the room quietly, and no one noticed.","traditional":"她不聲不響地離開了房間，沒有人注意到。"}],"synonyms":["默默无闻"],"antonyms":["大张旗鼓"],"confusedWith":[{"id":"默默无闻","note":"不声不响 means acting quietly, while 默默无闻 implies being unknown or unnoticed."}],"traditional":"不聲不響","pinyinOverride":null},{"id":"bu-sheng-qi-ku","simplified":"不胜其苦","literalMeaning":"cannot bear its suffering","figurativeMeaning":"to be unable to endure the hardship or suffering","englishEquivalents":["can't take it anymore","at the end of one's rope"],"shortGloss":"unable to endure hardship","characters":[{"char":"不","meaning":"not"},{"char":"胜","meaning":"bear; endure"},{"char":"其","meaning":"its"},{"char":"苦","meaning":"suffering; hardship"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '不胜其苦' is often used to describe situations where someone is overwhelmed by difficulties or suffering. It is not tied to a specific historical story but rather reflects a common human experience of reaching one's limit in the face of adversity.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","complement"],"structure":"modifier-head","register":"commonly used in both written and spoken Chinese to express extreme difficulty or suffering","connotation":"negative","commonMistakes":"Learners might confuse this idiom with others that express general difficulty, but '不胜其苦' specifically emphasizes an inability to endure the hardship. It should not be used for minor inconveniences.","canStandAlone":false},"examples":[{"simplified":"他在工作中不胜其苦，决定辞职。","english":"He couldn't endure the suffering at work and decided to quit.","traditional":"他在工作中不勝其苦，決定辭職。"},{"simplified":"面对生活的种种困难，她感到不胜其苦。","english":"Faced with various difficulties in life, she felt unable to endure the suffering.","traditional":"面對生活的種種困難，她感到不勝其苦。"}],"synonyms":["苦不堪言"],"antonyms":[],"confusedWith":[{"id":"苦不堪言","note":"While both express suffering, '苦不堪言' emphasizes the indescribable nature of the suffering, not necessarily the inability to endure it."}],"traditional":"不勝其苦","pinyinOverride":null},{"id":"bu-shi-zhi-xu","simplified":"不时之需","literalMeaning":"unexpected time's need","figurativeMeaning":"a need that arises unexpectedly; a contingency","englishEquivalents":["for a rainy day","emergency fund"],"shortGloss":"unexpected need","characters":[{"char":"不","meaning":"not"},{"char":"时","meaning":"time"},{"char":"之","meaning":"of"},{"char":"需","meaning":"need"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom 不时之需 refers to the concept of preparing for needs that might arise unexpectedly. It emphasizes the importance of being prepared for unforeseen circumstances, similar to the idea of saving money or resources for a 'rainy day'. The phrase is often used to encourage prudence and foresight.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["object","attributive"],"structure":"modifier-head","register":"commonly used in both formal and informal contexts","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with others that involve preparation, but 不时之需 specifically emphasizes unexpected needs, not regular or predictable ones.","canStandAlone":false},"examples":[{"simplified":"我们应该存一些钱，以备不时之需。","english":"We should save some money for a rainy day.","traditional":"我們應該存一些錢，以備不時之需。"},{"simplified":"他总是准备一些额外的食物，以防不时之需。","english":"He always prepares some extra food just in case of an unexpected need.","traditional":"他總是準備一些額外的食物，以防不時之需。"}],"synonyms":["未雨绸缪"],"antonyms":[],"confusedWith":[{"id":"未雨绸缪","note":"未雨绸缪 focuses on preparing before a problem arises, while 不时之需 emphasizes the need that arises unexpectedly."}],"traditional":"不時之需","pinyinOverride":null},{"id":"bu-shi-da-ti","simplified":"不识大体","literalMeaning":"not recognize the big picture","figurativeMeaning":"to lack a sense of priorities or the overall situation; to be unable to see the bigger picture","englishEquivalents":["can't see the forest for the trees","missing the big picture"],"shortGloss":"lacking a sense of priorities","characters":[{"char":"不","meaning":"not"},{"char":"识","meaning":"recognize"},{"char":"大","meaning":"big"},{"char":"体","meaning":"body; here, it means 'overall situation'"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '不识大体' is used to describe someone who is unable to understand or prioritize the most important aspects of a situation. It suggests a lack of awareness or understanding of the broader context, focusing instead on minor details.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"modifier-head","register":"commonly used in both spoken and written Chinese","connotation":"negative","commonMistakes":"Learners often confuse this idiom with similar expressions that emphasize ignorance, but '不识大体' specifically refers to a lack of understanding of priorities or the overall situation, not general ignorance.","canStandAlone":false},"examples":[{"simplified":"他总是关注细节，而不识大体。","english":"He always focuses on the details and fails to see the bigger picture.","traditional":"他總是關注細節，而不識大體。"},{"simplified":"在这种情况下，不识大体会导致严重后果。","english":"In this situation, failing to see the bigger picture can lead to serious consequences.","traditional":"在這種情況下，不識大體會導致嚴重後果。"}],"synonyms":[],"antonyms":["识大体"],"confusedWith":[{"id":"目光短浅","note":"While both idioms suggest a lack of foresight, '目光短浅' specifically refers to shortsightedness, whereas '不识大体' emphasizes not understanding the overall situation."}],"traditional":"不識大體","pinyinOverride":null},{"id":"bu-shi-gao-di","simplified":"不识高低","literalMeaning":"not recognize high and low","figurativeMeaning":"to be unable to judge the situation; to lack judgment or discernment","englishEquivalents":["not know one's place","lack discernment"],"shortGloss":"lack judgment or discernment","characters":[{"char":"不","meaning":"not"},{"char":"识","meaning":"recognize"},{"char":"高","meaning":"high"},{"char":"低","meaning":"low"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '不识高低' is believed to have originated from folk expressions and is used to describe someone who cannot assess a situation properly or lacks the ability to discern the importance or seriousness of a matter. It implies a lack of awareness or understanding of one's own position or the circumstances.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","object","attributive"],"structure":"modifier-head","register":"colloquial and widely used in both spoken and written Chinese","connotation":"negative","commonMistakes":"Learners often confuse this idiom with similar expressions that involve judgment, such as '不知好歹'. While both imply a lack of discernment, '不识高低' specifically refers to not recognizing one's own position or the situation's gravity.","canStandAlone":false},"examples":[{"simplified":"他总是自以为是，真是不识高低。","english":"He always thinks he's right, truly lacking in judgment.","traditional":"他總是自以為是，真是不識高低。"},{"simplified":"在这种情况下说这样的话，简直是不识高低。","english":"Saying something like that in this situation shows a complete lack of discernment.","traditional":"在這種情況下說這樣的話，簡直是不識高低。"}],"synonyms":["不知好歹"],"antonyms":[],"confusedWith":[{"id":"不知好歹","note":"Both idioms imply a lack of discernment, but '不知好歹' focuses more on not knowing what's good or bad for oneself."}],"traditional":"不識高低","pinyinOverride":null},{"id":"bu-shi-hao-dai","simplified":"不识好歹","literalMeaning":"not recognize good or bad","figurativeMeaning":"unable to distinguish right from wrong; ungrateful or lacking judgment","englishEquivalents":["can't tell right from wrong","ungrateful"],"shortGloss":"unable to distinguish right from wrong","characters":[{"char":"不","meaning":"not"},{"char":"识","meaning":"recognize"},{"char":"好","meaning":"good"},{"char":"歹","meaning":"bad"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '不识好歹' is used to describe someone who cannot differentiate between good and bad, or who is ungrateful for the kindness shown to them. It is often used to criticize someone for their lack of judgment or appreciation.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"modifier-head","register":"commonly used in both spoken and written Chinese","connotation":"negative","commonMistakes":"Learners often confuse this idiom with similar expressions that mean 'ignorant' or 'naive'. However, '不识好歹' specifically implies a lack of judgment or appreciation, not just ignorance.","canStandAlone":false},"examples":[{"simplified":"他对帮助他的人不识好歹，真让人失望。","english":"He is ungrateful to those who helped him, which is truly disappointing.","traditional":"他對幫助他的人不識好歹，真讓人失望。"},{"simplified":"她总是不识好歹，分不清谁是真心对她好。","english":"She always fails to distinguish right from wrong and cannot tell who genuinely cares for her.","traditional":"她總是不識好歹，分不清誰是真心對她好。"}],"synonyms":["恩将仇报"],"antonyms":["知恩图报"],"confusedWith":[{"id":"愚昧无知","note":"While '愚昧无知' means ignorant or uneducated, '不识好歹' emphasizes a lack of judgment or appreciation."}],"traditional":"不識好歹","pinyinOverride":null},{"id":"bu-shi-shi-wu","simplified":"不识时务","literalMeaning":"not recognize the times","figurativeMeaning":"to be unable to adapt to the current circumstances or trends; to lack awareness of the situation","englishEquivalents":["out of touch","behind the times"],"shortGloss":"out of touch with reality","characters":[{"char":"不","meaning":"not"},{"char":"识","meaning":"recognize"},{"char":"时","meaning":"time; current"},{"char":"务","meaning":"affairs; matters"}],"origin":{"period":"Three Kingdoms period (220–280 CE)","sourceText":"《三国志·蜀书·诸葛亮传》","sourceTextEnglish":"Records of the Three Kingdoms, Book of Shu, Biography of Zhuge Liang","originalExcerpt":"亮曰：\\"孝直不识时务，非英雄也。\\"","storyEnglish":"The idiom originates from a story about Zhuge Liang, a famous strategist during the Three Kingdoms period. When someone criticized Zhuge Liang's decision to ally with Sun Quan, Zhuge Liang remarked that the critic 'did not recognize the times,' implying that the critic failed to understand the strategic necessity of adapting to the current political situation.","historicalFigures":["Zhuge Liang"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"modifier-head","register":"literary, but used in both formal and informal contexts","connotation":"negative","commonMistakes":"Learners often confuse this idiom with ones that suggest ignorance in general, but it specifically refers to a lack of awareness of current circumstances or trends.","canStandAlone":false},"examples":[{"simplified":"他总是坚持自己的老办法，真是有点不识时务。","english":"He always insists on his old ways, truly a bit out of touch with the times.","traditional":"他總是堅持自己的老辦法，真是有點不識時務。"},{"simplified":"在这个快速变化的时代，不识时务的人很难成功。","english":"In this rapidly changing era, people who are out of touch with reality find it hard to succeed.","traditional":"在這個快速變化的時代，不識時務的人很難成功。"}],"synonyms":["墨守成规"],"antonyms":["识时务者为俊杰"],"confusedWith":[{"id":"不知所措","note":"While 不识时务 refers to being out of touch with current trends, 不知所措 means being at a loss or not knowing what to do."}],"traditional":"不識時務","pinyinOverride":null},{"id":"bu-zhi-qing-zhong","simplified":"不知轻重","literalMeaning":"not know light heavy","figurativeMeaning":"to not know the importance or severity of a situation; to lack judgment or discernment","englishEquivalents":["not know one's own strength","lack of judgment"],"shortGloss":"lack discernment","characters":[{"char":"不","meaning":"not"},{"char":"知","meaning":"know"},{"char":"轻","meaning":"light; of little importance"},{"char":"重","meaning":"heavy; important"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '不知轻重' is used to describe someone who lacks the ability to assess the importance or severity of a situation. It implies a lack of judgment or discernment, often leading to inappropriate actions or decisions. The origin of this idiom is not tied to a specific classical text, and it is likely a folk expression that evolved over time.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"modifier-head","register":"commonly used in both written and spoken Chinese","connotation":"negative","commonMistakes":"Learners might confuse this idiom with others that involve judgment or decision-making, such as '不知所措'. However, '不知轻重' specifically refers to not understanding the importance or severity of a situation.","canStandAlone":false},"examples":[{"simplified":"他总是不知轻重，常常在重要场合开玩笑。","english":"He often lacks judgment and makes jokes in important situations.","traditional":"他總是不知輕重，常常在重要場合開玩笑。"},{"simplified":"在做决定时，我们不能不知轻重。","english":"When making decisions, we must not ignore the importance of the situation.","traditional":"在做決定時，我們不能不知輕重。"}],"synonyms":["不知所措"],"antonyms":["明辨是非"],"confusedWith":[{"id":"不知所措","note":"While both involve a lack of understanding, '不知所措' means not knowing what to do, whereas '不知轻重' refers to not understanding the importance or severity of a situation."}],"traditional":"不知輕重","pinyinOverride":null},{"id":"bu-zhi-qu-xiang","simplified":"不知去向","literalMeaning":"not know where gone","figurativeMeaning":"to disappear without a trace; to vanish","englishEquivalents":["vanish into thin air","disappear without a trace"],"shortGloss":"disappear without a trace","characters":[{"char":"不","meaning":"not"},{"char":"知","meaning":"know"},{"char":"去","meaning":"go"},{"char":"向","meaning":"direction"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '不知去向' is used to describe a situation where someone or something has disappeared, and their whereabouts are completely unknown. It is often used in literature and conversation to convey the sudden and complete disappearance of a person or object.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","complement"],"structure":"verb-object","register":"widely used in both written and spoken Chinese","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with others that involve disappearance, but '不知去向' specifically emphasizes the unknown whereabouts, not just the act of leaving.","canStandAlone":false},"examples":[{"simplified":"他昨天离开后就不知去向。","english":"He left yesterday and has been missing since.","traditional":"他昨天離開後就不知去向。"},{"simplified":"那只猫已经不知去向好几天了。","english":"The cat has been missing for several days.","traditional":"那隻貓已經不知去向好幾天了。"}],"synonyms":["杳无音信"],"antonyms":[],"confusedWith":[{"id":"销声匿迹","note":"While both idioms involve disappearance, '销声匿迹' implies deliberately hiding or going silent, whereas '不知去向' emphasizes unknown whereabouts."}],"traditional":"不知去向","pinyinOverride":null},{"id":"bu-zhi-suo-yun","simplified":"不知所云","literalMeaning":"not know what is being said","figurativeMeaning":"to not understand what someone is talking about; to be unintelligible or incoherent","englishEquivalents":["incomprehensible","doesn't make sense","gibberish"],"shortGloss":"incomprehensible speech","characters":[{"char":"不","meaning":"not"},{"char":"知","meaning":"know"},{"char":"所","meaning":"what"},{"char":"云","meaning":"say"}],"origin":{"period":"Three Kingdoms period (220–280 CE)","sourceText":"《三国志·吴书·周瑜传》","sourceTextEnglish":"Records of the Three Kingdoms, Book of Wu, Biography of Zhou Yu","originalExcerpt":"瑜大笑曰：“樊将军不知所云。”","storyEnglish":"The idiom comes from the 'Records of the Three Kingdoms', where Zhou Yu, a famous general, laughed and remarked that another general's words were incomprehensible. This phrase has since been used to describe speech or writing that is difficult to understand.","historicalFigures":["Zhou Yu"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","complement"],"structure":"verb-object","register":"commonly used in both formal and informal contexts to describe unclear speech or writing","connotation":"negative","commonMistakes":"Learners might mistakenly use this idiom to describe situations rather than speech or writing. It specifically refers to language that is hard to understand.","canStandAlone":false},"examples":[{"simplified":"他的报告让人不知所云。","english":"His report was incomprehensible.","traditional":"他的報告讓人不知所云。"},{"simplified":"这篇文章写得不知所云，读者很难理解。","english":"This article is written in a way that makes it incomprehensible, and readers find it hard to understand.","traditional":"這篇文章寫得不知所云，讀者很難理解。"}],"synonyms":["莫名其妙","语无伦次"],"antonyms":["一目了然"],"confusedWith":[{"id":"莫名其妙","note":"While both can describe something confusing, '莫名其妙' can refer to situations or actions, not just speech or writing."}],"traditional":"不知所云","pinyinOverride":null},{"id":"bu-zhi-tong-yang","simplified":"不知痛痒","literalMeaning":"not know pain or itch","figurativeMeaning":"to be indifferent or unconcerned about something; to be unaffected by the suffering or discomfort of others","englishEquivalents":["turn a blind eye","be indifferent","not bat an eye"],"shortGloss":"indifferent or unconcerned","characters":[{"char":"不","meaning":"not"},{"char":"知","meaning":"know"},{"char":"痛","meaning":"pain"},{"char":"痒","meaning":"itch"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '不知痛痒' is used to describe someone who is indifferent or unconcerned about something, especially the discomfort or suffering of others. It conveys a sense of emotional detachment, as if the person does not feel the 'pain' or 'itch' that others might be experiencing.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"modifier-head","register":"commonly used in both spoken and written Chinese","connotation":"negative","commonMistakes":"Learners might confuse this idiom with others that involve '不知', but this idiom specifically conveys indifference to discomfort or suffering, not general ignorance.","canStandAlone":false},"examples":[{"simplified":"他对别人的困难总是不知痛痒。","english":"He is always indifferent to other people's difficulties.","traditional":"他對別人的困難總是不知痛癢。"},{"simplified":"在这种情况下，不知痛痒的人是无法理解的。","english":"In such situations, it's hard to understand people who are indifferent.","traditional":"在這種情況下，不知痛癢的人是無法理解的。"}],"synonyms":["漠不关心","无动于衷"],"antonyms":["感同身受"],"confusedWith":[{"id":"不知所措","note":"While '不知所措' means not knowing what to do, '不知痛痒' specifically refers to being indifferent or unconcerned."}],"traditional":"不知痛癢","pinyinOverride":null},{"id":"bu-zhi-zhi-zheng","simplified":"不治之症","literalMeaning":"incurable disease","figurativeMeaning":"a problem or situation that cannot be resolved or remedied","englishEquivalents":["incurable condition","beyond cure"],"shortGloss":"incurable disease or problem","characters":[{"char":"不","meaning":"not"},{"char":"治","meaning":"cure"},{"char":"之","meaning":"of"},{"char":"症","meaning":"disease"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '不治之症' is used to describe a disease that cannot be cured. Over time, it has come to be used metaphorically to describe any problem or situation that seems impossible to resolve or fix. The phrase emphasizes the severity and hopelessness of the situation.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["subject","object","attributive"],"structure":"modifier-head","register":"commonly used in both formal and informal contexts","connotation":"negative","commonMistakes":"Learners might mistakenly use this idiom to describe minor problems, but it should be reserved for serious, unsolvable issues.","canStandAlone":false},"examples":[{"simplified":"他的病被医生诊断为不治之症。","english":"His illness was diagnosed by the doctor as an incurable disease.","traditional":"他的病被醫生診斷為不治之症。"},{"simplified":"腐败在这个国家已经成为不治之症。","english":"Corruption has become an incurable problem in this country.","traditional":"腐敗在這個國家已經成為不治之症。"}],"synonyms":["无药可救"],"antonyms":[],"confusedWith":[{"id":"无药可救","note":"Both describe incurable conditions, but '无药可救' is more often used metaphorically for people or situations beyond help."}],"traditional":"不治之症","pinyinOverride":null},{"id":"bu-zhuo-bian-ji","simplified":"不着边际","literalMeaning":"not touching the edge","figurativeMeaning":"irrelevant or off-topic; lacking focus or substance","englishEquivalents":["beside the point","off on a tangent"],"shortGloss":"irrelevant or off-topic","characters":[{"char":"不","meaning":"not"},{"char":"着","meaning":"touching"},{"char":"边","meaning":"edge"},{"char":"际","meaning":"boundary"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '不着边际' is used to describe speech or writing that is irrelevant or lacks focus. It suggests that the content is not grounded or connected to the main topic, much like something that does not touch the edge or boundary of a defined area.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"modifier-head","register":"commonly used in both spoken and written Chinese to describe irrelevant or unfocused discourse","connotation":"negative","commonMistakes":"Learners often confuse '不着边际' with idioms that mean 'unbelievable' or 'fantastical', but it specifically refers to irrelevance or lack of focus, not exaggeration.","canStandAlone":false},"examples":[{"simplified":"他的发言总是不着边际，让人很难理解他的重点。","english":"His speeches are always off-topic, making it hard to understand his main points.","traditional":"他的發言總是不著邊際，讓人很難理解他的重點。"},{"simplified":"这篇文章不着边际，没有提供任何有用的信息。","english":"This article is irrelevant and doesn't provide any useful information.","traditional":"這篇文章不著邊際，沒有提供任何有用的信息。"}],"synonyms":["离题万里"],"antonyms":["切中要害"],"confusedWith":[{"id":"天马行空","note":"While '天马行空' suggests imaginative or fantastical thinking, '不着边际' specifically refers to irrelevance or lack of focus."}],"traditional":"不著邊際","pinyinOverride":null},{"id":"bu-zu-gua-chi","simplified":"不足挂齿","literalMeaning":"not enough to hang on the teeth","figurativeMeaning":"not worth mentioning; too trivial to mention","englishEquivalents":["not worth mentioning","nothing to write home about"],"shortGloss":"not worth mentioning","characters":[{"char":"不","meaning":"not"},{"char":"足","meaning":"enough"},{"char":"挂","meaning":"to hang"},{"char":"齿","meaning":"teeth"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '不足挂齿' is often used to express humility or modesty, indicating that something is too insignificant to be worth mentioning. It suggests that the matter is so trivial that it doesn't deserve to be 'hung on the teeth,' metaphorically speaking.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"modifier-head","register":"commonly used in both spoken and written Chinese to express modesty or downplay one's achievements","connotation":"neutral","commonMistakes":"Learners might mistakenly use this idiom to describe something that is genuinely insignificant, rather than as a modest way to downplay one's own contributions or achievements.","canStandAlone":false},"examples":[{"simplified":"这点小事，不足挂齿。","english":"This small matter is not worth mentioning.","traditional":"這點小事，不足掛齒。"},{"simplified":"你的帮助对我来说意义重大，而我的回报不足挂齿。","english":"Your help means a lot to me, while my return is not worth mentioning.","traditional":"你的幫助對我來說意義重大，而我的回報不足掛齒。"}],"synonyms":["微不足道"],"antonyms":[],"confusedWith":[{"id":"微不足道","note":"Both express insignificance, but '微不足道' is more often used to describe things objectively small or trivial, rather than as a modest expression."}],"traditional":"不足掛齒","pinyinOverride":null},{"id":"ba-bai-zhi-jiao","simplified":"八拜之交","literalMeaning":"eight bows of friendship","figurativeMeaning":"a deep and formal friendship, akin to sworn brothers","englishEquivalents":["sworn brothers","bosom friends"],"shortGloss":"deep, formal friendship","characters":[{"char":"八","meaning":"eight"},{"char":"拜","meaning":"bow, as in a formal gesture of respect"},{"char":"之","meaning":"of, indicating possession"},{"char":"交","meaning":"friendship or relationship"}],"origin":{"period":"Eastern Han Dynasty (25–220 CE)","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '八拜之交' refers to a deep and formal friendship that is established through a series of ritual bows, symbolizing a commitment akin to becoming sworn brothers. This concept is rooted in ancient Chinese customs where friends would perform a series of eight bows to formalize their bond, signifying mutual respect and loyalty.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["subject","object","attributive"],"structure":"modifier-head","register":"literary, but can be used in formal speech to describe close friendships","connotation":"positive","commonMistakes":"Learners might confuse this idiom with general terms for friendship, but it specifically implies a formal and deep bond, not just casual friendship.","canStandAlone":false},"examples":[{"simplified":"他们是八拜之交，彼此非常信任。","english":"They are sworn brothers, and trust each other deeply.","traditional":"他們是八拜之交，彼此非常信任。"},{"simplified":"在古代，八拜之交是一种非常庄重的友谊仪式。","english":"In ancient times, the 'eight bows of friendship' was a very solemn friendship ceremony.","traditional":"在古代，八拜之交是一種非常莊重的友誼儀式。"}],"synonyms":["生死之交"],"antonyms":[],"confusedWith":[{"id":"莫逆之交","note":"While both refer to deep friendships, '莫逆之交' emphasizes a natural, harmonious friendship without formal rituals."}],"traditional":"八拜之交","pinyinOverride":null},{"id":"ba-dou-zhi-cai","simplified":"八斗之才","literalMeaning":"talent of eight dou","figurativeMeaning":"exceptionally talented or gifted, especially in literary or artistic fields","englishEquivalents":["a towering talent","a genius","an extraordinary talent"],"shortGloss":"exceptionally talented","characters":[{"char":"八","meaning":"eight"},{"char":"斗","meaning":"dou (a unit of volume)"},{"char":"之","meaning":"of"},{"char":"才","meaning":"talent"}],"origin":{"period":"Eastern Jin dynasty (317–420 CE)","sourceText":"《世说新语·文学》","sourceTextEnglish":"A New Account of the Tales of the World, Literature section","originalExcerpt":"天下才有一石，曹子建独占八斗。","storyEnglish":"The idiom originates from a story about the famous poet Cao Zhi, also known as Cao Zijian, from the Eastern Jin dynasty. It was said that the world's talent amounted to one 'shi' (an ancient Chinese unit of measurement), and Cao Zhi alone possessed eight 'dou' of it. This metaphor was used to emphasize his extraordinary literary talent.","historicalFigures":["Cao Zhi"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["attributive","predicate"],"structure":"modifier-head","register":"literary, but can be used in formal speech to praise someone's exceptional talent","connotation":"positive","commonMistakes":"Learners might confuse this idiom with others that use '才' (talent) but do not convey the same level of exceptional ability. It specifically implies a very high degree of talent, not just competence.","canStandAlone":false},"examples":[{"simplified":"他真是个八斗之才，写的诗让人赞叹不已。","english":"He truly is a towering talent; his poetry leaves people in awe.","traditional":"他真是個八斗之才，寫的詩讓人讚歎不已。"},{"simplified":"在音乐方面，她被认为是八斗之才。","english":"In the field of music, she is considered an extraordinary talent.","traditional":"在音樂方面，她被認為是八斗之才。"}],"synonyms":["才高八斗"],"antonyms":[],"confusedWith":[{"id":"才高八斗","note":"Both idioms praise exceptional talent, but '才高八斗' is more commonly used and emphasizes the height of talent."}],"traditional":"八斗之才","pinyinOverride":null},{"id":"ba-mian-ling-long","simplified":"八面玲珑","literalMeaning":"eight sides exquisite","figurativeMeaning":"to be smooth and tactful; able to please all parties","englishEquivalents":["smooth operator","people pleaser"],"shortGloss":"tactful and smooth in dealing with people","characters":[{"char":"八","meaning":"eight"},{"char":"面","meaning":"sides"},{"char":"玲","meaning":"exquisite"},{"char":"珑","meaning":"bright"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '八面玲珑' is often used to describe someone who is very tactful and able to handle different people and situations with ease. The phrase suggests a person who can present themselves well from all angles, like a finely cut gemstone that sparkles from every side. This quality is often seen as advantageous in social and professional settings.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["attributive","adverbial"],"structure":"modifier-head","register":"commonly used in both spoken and written Chinese","connotation":"neutral","commonMistakes":"Learners might mistakenly use this idiom to describe physical objects rather than people or their behavior. It's important to remember it refers to a person's ability to handle social situations smoothly.","canStandAlone":false},"examples":[{"simplified":"他在公司里八面玲珑，和每个人都相处得很好。","english":"He is very tactful in the company and gets along well with everyone.","traditional":"他在公司裡八面玲瓏，和每個人都相處得很好。"},{"simplified":"她总是八面玲珑，能够化解任何紧张的局面。","english":"She is always smooth and tactful, able to defuse any tense situation.","traditional":"她總是八面玲瓏，能夠化解任何緊張的局面。"}],"synonyms":["左右逢源"],"antonyms":["一意孤行"],"confusedWith":[{"id":"八面威风","note":"八面威风 refers to someone who is impressive and commanding in all directions, not necessarily tactful."}],"traditional":"八面玲瓏","pinyinOverride":null},{"id":"ba-qian-suan-hou","simplified":"巴前算后","literalMeaning":"cling to the front, calculate the back","figurativeMeaning":"to be overly cautious and calculating, considering every possibility before acting","englishEquivalents":["look before you leap","overthink things","hedge one's bets"],"shortGloss":"overly cautious and calculating","characters":[{"char":"巴","meaning":"cling to"},{"char":"前","meaning":"front"},{"char":"算","meaning":"calculate"},{"char":"后","meaning":"back"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '巴前算后' describes someone who is excessively cautious, always considering and calculating every possible outcome before making a decision. It reflects a mindset of being overly concerned with potential risks and benefits, often leading to indecision or delayed action.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["adverbial","attributive"],"structure":"coordinate","register":"commonly used in both spoken and written Chinese to describe cautious behavior","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with others that imply careful planning, but '巴前算后' specifically suggests an excessive or overly cautious approach, rather than just careful planning.","canStandAlone":false},"examples":[{"simplified":"他做事总是巴前算后，生怕出错。","english":"He always acts with excessive caution, fearing to make mistakes.","traditional":"他做事總是巴前算後，生怕出錯。"},{"simplified":"在这种情况下，巴前算后可能会错失良机。","english":"In this situation, being overly cautious might cause you to miss a good opportunity.","traditional":"在這種情況下，巴前算後可能會錯失良機。"}],"synonyms":["瞻前顾后"],"antonyms":["一意孤行"],"confusedWith":[{"id":"瞻前顾后","note":"Both idioms imply cautiousness, but '瞻前顾后' is more about being prudent and considering all sides, while '巴前算后' suggests excessive caution."}],"traditional":"巴前算後","pinyinOverride":null},{"id":"ba-dao-xiang-zhu","simplified":"拔刀相助","literalMeaning":"draw sword to help","figurativeMeaning":"to come to someone's aid in a time of need, often involving bravery or chivalry","englishEquivalents":["come to the rescue","lend a helping hand"],"shortGloss":"come to someone's aid","characters":[{"char":"拔","meaning":"draw (a sword)"},{"char":"刀","meaning":"sword"},{"char":"相","meaning":"mutually"},{"char":"助","meaning":"help"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '拔刀相助' is believed to have originated from stories of knights or martial heroes in ancient China who would draw their swords to help those in distress. It reflects the chivalrous spirit of coming to someone's aid, especially in dangerous situations.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"commonly used in both formal and informal contexts, often in storytelling or describing acts of bravery","connotation":"positive","commonMistakes":"Learners might confuse this idiom with more general terms for helping, but it specifically implies a heroic or brave action, often in a physical or metaphorical sense of 'drawing a sword.'","canStandAlone":false},"examples":[{"simplified":"他在危急时刻拔刀相助，救了那位老人。","english":"He came to the rescue in a critical moment and saved the elderly man.","traditional":"他在危急時刻拔刀相助，救了那位老人。"},{"simplified":"看到有人被欺负，他毫不犹豫地拔刀相助。","english":"Seeing someone being bullied, he didn't hesitate to come to their aid.","traditional":"看到有人被欺負，他毫不猶豫地拔刀相助。"}],"synonyms":["见义勇为","仗义执言"],"antonyms":[],"confusedWith":[{"id":"助人为乐","note":"助人为乐 means to take pleasure in helping others, which is more general and doesn't imply the bravery or urgency of 拔刀相助."}],"traditional":"拔刀相助","pinyinOverride":null},{"id":"ba-chi-bu-ding","simplified":"把持不定","literalMeaning":"grasp hold not certain","figurativeMeaning":"to be indecisive or unable to make up one's mind","englishEquivalents":["sit on the fence","be of two minds"],"shortGloss":"indecisive, unable to decide","characters":[{"char":"把","meaning":"grasp, hold"},{"char":"持","meaning":"maintain, hold"},{"char":"不","meaning":"not"},{"char":"定","meaning":"certain, fixed"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '把持不定' is used to describe someone who is unable to make a decision or is wavering between different choices. It reflects a state of indecision and hesitation, often leading to a lack of progress or resolution.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","complement"],"structure":"verb-object","register":"commonly used in both spoken and written Chinese to describe indecisiveness","connotation":"negative","commonMistakes":"Learners might confuse '把持不定' with '犹豫不决', which also means indecisive but is more commonly used. '把持不定' emphasizes the inability to hold a firm decision.","canStandAlone":false},"examples":[{"simplified":"他在工作和家庭之间把持不定。","english":"He is indecisive between work and family.","traditional":"他在工作和家庭之間把持不定。"},{"simplified":"面对这么多选择，她一时把持不定。","english":"Faced with so many choices, she couldn't make up her mind.","traditional":"面對這麼多選擇，她一時把持不定。"}],"synonyms":["犹豫不决"],"antonyms":["果断决策"],"confusedWith":[{"id":"犹豫不决","note":"Both mean indecisive, but '犹豫不决' is more common and doesn't emphasize the aspect of 'holding' or 'grasping' a decision."}],"traditional":"把持不定","pinyinOverride":null},{"id":"ba-wang-bie-ji","simplified":"霸王别姬","literalMeaning":"overlord bids farewell to concubine","figurativeMeaning":"a tragic farewell between lovers, often with a sense of inevitable separation due to circumstances","englishEquivalents":["parting is such sweet sorrow","a heartbreaking farewell"],"shortGloss":"tragic lovers' farewell","characters":[{"char":"霸","meaning":"overlord, referring to Xiang Yu"},{"char":"王","meaning":"king, referring to Xiang Yu"},{"char":"别","meaning":"to bid farewell"},{"char":"姬","meaning":"concubine, referring to Consort Yu"}],"origin":{"period":"Han Dynasty (202 BCE – 220 CE)","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '霸王别姬' refers to the poignant story of Xiang Yu, a prominent warlord during the late Qin Dynasty, and his beloved concubine, Consort Yu. Facing defeat in battle, Xiang Yu was surrounded by enemy forces. In a moment of despair, Consort Yu performed a farewell dance and then took her own life to relieve Xiang Yu of his emotional burden. This story has been immortalized in various operas and films, symbolizing a tragic and heroic farewell.","historicalFigures":["Xiang Yu","Consort Yu"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["subject","predicate","object"],"structure":"subject-predicate","register":"literary, but known and sometimes used in modern contexts, especially in artistic or dramatic settings","connotation":"negative","commonMistakes":"Learners often misinterpret this idiom as simply referring to any kind of farewell, but it specifically implies a tragic and emotionally charged parting, often with historical or dramatic connotations.","canStandAlone":false},"examples":[{"simplified":"在电影中，那场霸王别姬的戏份让观众潸然泪下。","english":"In the movie, the scene of '霸王别姬' moved the audience to tears.","traditional":"在電影中，那場霸王別姬的戲份讓觀眾潸然淚下。"},{"simplified":"他们的分手就像霸王别姬，令人心碎。","english":"Their breakup was like '霸王别姬', heartbreaking and tragic.","traditional":"他們的分手就像霸王別姬，令人心碎。"}],"synonyms":[],"antonyms":[],"confusedWith":[],"traditional":"霸王別姬","pinyinOverride":null},{"id":"bai-bi-wei-xia","simplified":"白璧微瑕","literalMeaning":"white jade with a slight flaw","figurativeMeaning":"a minor flaw in an otherwise perfect person or thing","englishEquivalents":["a fly in the ointment","a blemish on an otherwise perfect record"],"shortGloss":"a minor flaw in perfection","characters":[{"char":"白","meaning":"white"},{"char":"璧","meaning":"jade"},{"char":"微","meaning":"slight"},{"char":"瑕","meaning":"flaw"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '白璧微瑕' uses the metaphor of a piece of white jade, which is highly valued for its purity and beauty, having a small flaw. This suggests that even something or someone nearly perfect can have minor imperfections. The idiom emphasizes that the flaw is minor and does not significantly detract from the overall value or beauty.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["attributive","adverbial"],"structure":"modifier-head","register":"literary, but can be used in both formal and informal contexts","connotation":"neutral","commonMistakes":"Learners might mistakenly use this idiom to describe major flaws, but it specifically refers to minor imperfections. It is also sometimes confused with idioms that imply more serious defects.","canStandAlone":false},"examples":[{"simplified":"他的作品几乎完美，只是有些白璧微瑕。","english":"His work is almost perfect, with only a few minor flaws.","traditional":"他的作品幾乎完美，只是有些白璧微瑕。"},{"simplified":"虽然他在这次比赛中表现出色，但仍有白璧微瑕之处。","english":"Although he performed excellently in the competition, there were still minor imperfections.","traditional":"雖然他在這次比賽中表現出色，但仍有白璧微瑕之處。"}],"synonyms":[],"antonyms":[],"confusedWith":[{"id":"瑕不掩瑜","note":"While '白璧微瑕' emphasizes the presence of a minor flaw, '瑕不掩瑜' suggests that the flaw does not overshadow the overall excellence."}],"traditional":"白璧微瑕","pinyinOverride":null},{"id":"bai-ju-guo-xi","simplified":"白驹过隙","literalMeaning":"white colt passes through a crack","figurativeMeaning":"time flies like an arrow; life is fleeting","englishEquivalents":["time flies","life is short"],"shortGloss":"time flies quickly","characters":[{"char":"白","meaning":"white"},{"char":"驹","meaning":"colt, young horse"},{"char":"过","meaning":"pass through"},{"char":"隙","meaning":"crack, gap"}],"origin":{"period":"Han Dynasty (202 BCE – 220 CE)","sourceText":"《庄子·知北游》","sourceTextEnglish":"Zhuangzi, Chapter 'Zhi Bei You'","originalExcerpt":"人生天地之间，若白驹之过隙，忽然而已。","storyEnglish":"The idiom comes from the Daoist text 'Zhuangzi', where it describes the fleeting nature of life. It compares life to a white colt that swiftly passes through a crack, emphasizing how quickly time passes and how transient life is.","historicalFigures":["Zhuangzi"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["subject","predicate","adverbial"],"structure":"subject-predicate","register":"literary, but widely understood and used in both speech and writing","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with others that describe speed or swiftness, but it specifically refers to the passage of time, not physical speed.","canStandAlone":false},"examples":[{"simplified":"他感叹道，时间如白驹过隙，转眼就过去了。","english":"He lamented that time flies like a white colt passing through a crack, gone in the blink of an eye.","traditional":"他感嘆道，時間如白駒過隙，轉眼就過去了。"},{"simplified":"我们应该珍惜每一天，因为白驹过隙，岁月不待人。","english":"We should cherish every day, for time flies and waits for no one.","traditional":"我們應該珍惜每一天，因為白駒過隙，歲月不待人。"}],"synonyms":["光阴似箭","日月如梭"],"antonyms":[],"confusedWith":[{"id":"光阴似箭","note":"Both describe the swift passage of time, but '光阴似箭' uses the metaphor of an arrow, while '白驹过隙' uses a colt."}],"traditional":"白駒過隙","pinyinOverride":null},{"id":"bai-mian-shu-sheng","simplified":"白面书生","literalMeaning":"white-faced scholar","figurativeMeaning":"a young, inexperienced scholar or intellectual","englishEquivalents":["greenhorn","novice","rookie"],"shortGloss":"inexperienced scholar","characters":[{"char":"白","meaning":"white"},{"char":"面","meaning":"face"},{"char":"书","meaning":"book"},{"char":"生","meaning":"student; scholar"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '白面书生' likely originates from the traditional Chinese view that scholars, who spent much of their time indoors studying, had pale complexions. The term came to describe young scholars who, despite their academic knowledge, lacked practical experience in the real world.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["subject","object","attributive"],"structure":"modifier-head","register":"commonly used in both written and spoken Chinese, often with a slightly derogatory tone","connotation":"neutral","commonMistakes":"Learners might mistakenly use this idiom to refer to any scholar, but it specifically implies inexperience or naivety. It is not a compliment.","canStandAlone":false},"examples":[{"simplified":"他不过是个白面书生，没有实际经验。","english":"He is just an inexperienced scholar without any practical experience.","traditional":"他不過是個白面書生，沒有實際經驗。"},{"simplified":"公司不想雇用白面书生，他们更需要有经验的人。","english":"The company doesn't want to hire inexperienced scholars; they need people with experience.","traditional":"公司不想僱用白面書生，他們更需要有經驗的人。"}],"synonyms":["乳臭未干"],"antonyms":[],"confusedWith":[{"id":"书呆子","note":"While both refer to scholars, '书呆子' emphasizes being bookish or pedantic, not necessarily inexperienced."}],"traditional":"白面書生","pinyinOverride":null},{"id":"bai-ri-zuo-meng","simplified":"白日做梦","literalMeaning":"daytime dreaming","figurativeMeaning":"to indulge in unrealistic fantasies or daydreams","englishEquivalents":["daydreaming","building castles in the air"],"shortGloss":"indulging in unrealistic fantasies","characters":[{"char":"白","meaning":"daytime"},{"char":"日","meaning":"day"},{"char":"做","meaning":"do; make"},{"char":"梦","meaning":"dream"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '白日做梦' refers to the act of daydreaming or indulging in unrealistic fantasies. It is used to describe someone who is not grounded in reality and is instead lost in their own imagination, much like dreaming during the day.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","object"],"structure":"verb-object","register":"commonly used in both spoken and written Chinese to describe unrealistic thinking","connotation":"negative","commonMistakes":"Learners often confuse this idiom with positive expressions of creativity. However, '白日做梦' carries a negative connotation, implying impracticality or lack of realism.","canStandAlone":false},"examples":[{"simplified":"他总是白日做梦，想一夜之间变成富翁。","english":"He is always daydreaming, thinking he can become a millionaire overnight.","traditional":"他總是白日做夢，想一夜之間變成富翁。"},{"simplified":"如果你不努力工作，光是白日做梦是没有用的。","english":"If you don't work hard, just daydreaming is useless.","traditional":"如果你不努力工作，光是白日做夢是沒有用的。"}],"synonyms":[],"antonyms":["脚踏实地"],"confusedWith":[{"id":"异想天开","note":"While both involve imagination, '异想天开' can imply creative thinking, whereas '白日做梦' is more about unrealistic fantasies."}],"traditional":"白日做夢","pinyinOverride":null},{"id":"bai-shou-qi-jia","simplified":"白手起家","literalMeaning":"bare hands start family","figurativeMeaning":"to start from scratch; to build up from nothing","englishEquivalents":["start from scratch","build from the ground up"],"shortGloss":"to start from scratch","characters":[{"char":"白","meaning":"bare; empty-handed"},{"char":"手","meaning":"hand"},{"char":"起","meaning":"to start; to rise"},{"char":"家","meaning":"family; home; business"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '白手起家' describes the act of building a business, career, or life from nothing, relying solely on one's own efforts and resources. It emphasizes the idea of starting without any external help or initial capital, highlighting the individual's determination and hard work.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"commonly used in both formal and informal contexts","connotation":"positive","commonMistakes":"Learners might confuse this idiom with others that imply inheritance or external help, but '白手起家' specifically emphasizes self-reliance and starting from nothing.","canStandAlone":false},"examples":[{"simplified":"他白手起家，最终建立了自己的公司。","english":"He started from scratch and eventually established his own company.","traditional":"他白手起家，最終建立了自己的公司。"},{"simplified":"许多成功的企业家都是白手起家的。","english":"Many successful entrepreneurs started from scratch.","traditional":"許多成功的企業家都是白手起家的。"}],"synonyms":["自力更生"],"antonyms":["坐享其成"],"confusedWith":[{"id":"坐享其成","note":"坐享其成 implies benefiting from others' efforts, while 白手起家 emphasizes self-made success."}],"traditional":"白手起家","pinyinOverride":null},{"id":"bai-tou-xie-lao","simplified":"白头偕老","literalMeaning":"white head together old","figurativeMeaning":"to live together until old age; to remain a devoted couple for life","englishEquivalents":["grow old together","till death do us part"],"shortGloss":"grow old together","characters":[{"char":"白","meaning":"white"},{"char":"头","meaning":"head"},{"char":"偕","meaning":"together"},{"char":"老","meaning":"old"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '白头偕老' is often used in the context of weddings and anniversaries to express the wish for a couple to remain together happily into old age. The imagery of 'white head' suggests aging together, while 'together old' emphasizes companionship throughout life.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"modifier-head","register":"commonly used in both formal and informal contexts, especially in well-wishing scenarios","connotation":"positive","commonMistakes":"Learners might confuse this idiom with others that involve aging or longevity but lack the specific connotation of companionship. It specifically refers to a couple growing old together, not just individual longevity.","canStandAlone":false},"examples":[{"simplified":"他们希望能白头偕老，共度余生。","english":"They hope to grow old together and spend the rest of their lives with each other.","traditional":"他們希望能白頭偕老，共度餘生。"},{"simplified":"在婚礼上，大家都祝福新人白头偕老。","english":"At the wedding, everyone wished the newlyweds a lifetime of happiness together.","traditional":"在婚禮上，大家都祝福新人白頭偕老。"}],"synonyms":["长相厮守"],"antonyms":["分道扬镳"],"confusedWith":[{"id":"白头到老","note":"While similar, 白头到老 focuses more on the passage of time rather than the companionship aspect."}],"traditional":"白頭偕老","pinyinOverride":null},{"id":"bai-yun-cang-gou","simplified":"白云苍狗","literalMeaning":"white clouds, grey dogs","figurativeMeaning":"the ever-changing nature of things; the transience of life","englishEquivalents":["the vicissitudes of life","here today, gone tomorrow"],"shortGloss":"the transience of life","characters":[{"char":"白","meaning":"white"},{"char":"云","meaning":"clouds"},{"char":"苍","meaning":"grey"},{"char":"狗","meaning":"dogs"}],"origin":{"period":"Tang Dynasty (618–907)","sourceText":"《杜甫诗集·可叹》","sourceTextEnglish":"Du Fu's Poetry Collection, 'Ke Tan'","originalExcerpt":"天上浮云似白衣，斯须改变如苍狗。","storyEnglish":"The idiom comes from a poem by the famous Tang Dynasty poet Du Fu. In the poem, Du Fu observes the clouds in the sky, noting how they resemble white clothes but quickly change to look like grey dogs. This imagery captures the idea of constant change and the fleeting nature of life.","historicalFigures":["Du Fu"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["subject","predicate","object"],"structure":"coordinate","register":"literary, but understood in educated speech","connotation":"neutral","commonMistakes":"Learners might mistakenly use this idiom to describe literal clouds or dogs, but it metaphorically refers to the changeable nature of life and events.","canStandAlone":false},"examples":[{"simplified":"人生如白云苍狗，变化无常。","english":"Life is like white clouds and grey dogs, ever-changing and unpredictable.","traditional":"人生如白雲蒼狗，變化無常。"},{"simplified":"历史的变迁就像白云苍狗，令人感慨。","english":"The changes in history are like white clouds and grey dogs, evoking deep emotions.","traditional":"歷史的變遷就像白雲蒼狗，令人感慨。"}],"synonyms":["沧海桑田"],"antonyms":[],"confusedWith":[{"id":"白驹过隙","note":"Both idioms describe the passage of time, but 白驹过隙 emphasizes the swiftness of time passing."}],"traditional":"白雲蒼狗","pinyinOverride":null},{"id":"bai-zhi-hei-zi","simplified":"白纸黑字","literalMeaning":"white paper, black characters","figurativeMeaning":"something clearly documented or written down; undeniable proof","englishEquivalents":["black and white","in writing"],"shortGloss":"clearly documented","characters":[{"char":"白","meaning":"white"},{"char":"纸","meaning":"paper"},{"char":"黑","meaning":"black"},{"char":"字","meaning":"characters"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '白纸黑字' refers to the clarity and undeniability of something that is written down. The phrase emphasizes the contrast between black ink and white paper, symbolizing that once something is documented, it is clear and cannot be easily refuted or denied.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["attributive","adverbial"],"structure":"modifier-head","register":"widely used in both formal and informal contexts","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with similar expressions that imply certainty or proof but lack the emphasis on written documentation. It specifically refers to things that are documented in writing.","canStandAlone":false},"examples":[{"simplified":"合同上白纸黑字写得清清楚楚。","english":"The contract clearly states everything in black and white.","traditional":"合同上白紙黑字寫得清清楚楚。"},{"simplified":"他不相信口头承诺，只相信白纸黑字的协议。","english":"He doesn't trust verbal promises, only agreements that are in writing.","traditional":"他不相信口頭承諾，只相信白紙黑字的協議。"}],"synonyms":[],"antonyms":[],"confusedWith":[],"traditional":"白紙黑字","pinyinOverride":null},{"id":"bai-ban-diao-nan","simplified":"百般刁难","literalMeaning":"hundred kinds of tricky difficulties","figurativeMeaning":"to make things difficult in every possible way","englishEquivalents":["give someone a hard time","put through the wringer"],"shortGloss":"make things difficult in every way","characters":[{"char":"百","meaning":"hundred; many"},{"char":"般","meaning":"kinds; types"},{"char":"刁","meaning":"tricky; cunning"},{"char":"难","meaning":"difficult; hardship"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '百般刁难' describes a situation where someone deliberately makes things difficult for another person in every conceivable way. It is often used to describe bureaucratic or personal obstacles that are intentionally created to frustrate or hinder progress.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","object","attributive"],"structure":"verb-object","register":"commonly used in both spoken and written Chinese","connotation":"negative","commonMistakes":"Learners might confuse this idiom with similar expressions that imply difficulty but without the intentional malice. It's important to note the deliberate and cunning aspect of the difficulties described by this idiom.","canStandAlone":false},"examples":[{"simplified":"他总是对新员工百般刁难。","english":"He always gives the new employees a hard time.","traditional":"他總是對新員工百般刁難。"},{"simplified":"在申请过程中，他们遇到了百般刁难。","english":"They faced all sorts of difficulties during the application process.","traditional":"在申請過程中，他們遇到了百般刁難。"}],"synonyms":["处处为难"],"antonyms":[],"confusedWith":[{"id":"故意刁难","note":"Both involve making things difficult, but '故意刁难' explicitly emphasizes the intentional aspect."}],"traditional":"百般刁難","pinyinOverride":null},{"id":"bai-ban-feng-cheng","simplified":"百般奉承","literalMeaning":"hundred kinds of flattery","figurativeMeaning":"to flatter in every possible way; to ingratiate oneself with someone through excessive praise","englishEquivalents":["butter someone up","kiss up to someone"],"shortGloss":"flatter excessively","characters":[{"char":"百","meaning":"hundred; many"},{"char":"般","meaning":"kinds; sorts"},{"char":"奉","meaning":"offer; present"},{"char":"承","meaning":"receive; continue"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '百般奉承' describes the act of using every possible method to flatter or ingratiate oneself with someone. It suggests a sense of insincerity and exaggeration in praise, often used to gain favor or advantage.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["adverbial","predicate"],"structure":"modifier-head","register":"commonly used in both spoken and written Chinese, often with a negative connotation","connotation":"negative","commonMistakes":"Learners might confuse this idiom with similar expressions of praise without realizing its negative connotation of insincerity. It specifically implies excessive and often insincere flattery.","canStandAlone":false},"examples":[{"simplified":"他为了得到晋升，对老板百般奉承。","english":"He flattered the boss in every possible way to get a promotion.","traditional":"他為了得到晉升，對老闆百般奉承。"},{"simplified":"她总是百般奉承那些有权势的人。","english":"She always flatters those in power in every possible way.","traditional":"她總是百般奉承那些有權勢的人。"}],"synonyms":["阿谀奉承","溜须拍马"],"antonyms":["直言不讳"],"confusedWith":[{"id":"阿谀奉承","note":"Both idioms mean to flatter excessively, but '阿谀奉承' is more formal and literary."}],"traditional":"百般奉承","pinyinOverride":null},{"id":"bai-bi-cong-sheng","simplified":"百弊丛生","literalMeaning":"a hundred evils arise together","figurativeMeaning":"numerous problems or abuses arise simultaneously","englishEquivalents":["a host of evils","a multitude of problems"],"shortGloss":"numerous problems arise","characters":[{"char":"百","meaning":"hundred"},{"char":"弊","meaning":"evils; abuses"},{"char":"丛","meaning":"cluster; arise together"},{"char":"生","meaning":"arise; grow"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '百弊丛生' is used to describe a situation where numerous problems or abuses arise simultaneously, often due to neglect or mismanagement. It emphasizes the overwhelming nature of the issues, suggesting that they are numerous and difficult to address all at once.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"subject-predicate","register":"commonly used in both formal and informal contexts to describe situations with many problems","connotation":"negative","commonMistakes":"Learners might confuse this idiom with others that describe singular problems rather than a multitude. It's important to use it when referring to numerous issues arising together, not just one or two problems.","canStandAlone":false},"examples":[{"simplified":"如果不及时改革，社会将会百弊丛生。","english":"If reforms are not implemented in time, society will face a multitude of problems.","traditional":"如果不及時改革，社會將會百弊叢生。"},{"simplified":"管理不善导致公司百弊丛生。","english":"Poor management led to a host of problems within the company.","traditional":"管理不善導致公司百弊叢生。"}],"synonyms":["弊病丛生"],"antonyms":[],"confusedWith":[],"traditional":"百弊叢生","pinyinOverride":null},{"id":"bai-bu-chuan-yang","simplified":"百步穿杨","literalMeaning":"hundred steps pierce poplar","figurativeMeaning":"to have great precision in archery or marksmanship; to be extremely accurate","englishEquivalents":["hit the bullseye","dead on target"],"shortGloss":"extreme accuracy","characters":[{"char":"百","meaning":"hundred"},{"char":"步","meaning":"steps"},{"char":"穿","meaning":"pierce"},{"char":"杨","meaning":"poplar"}],"origin":{"period":"Warring States period (475–221 BCE)","sourceText":"《史记·周本纪》","sourceTextEnglish":"Records of the Grand Historian, Annals of Zhou","originalExcerpt":"养由基善射，去柳叶百步而射之，百发百中。","storyEnglish":"The idiom originates from a story about Yang Youji, a legendary archer during the Warring States period. It is said that he was so skilled that he could shoot an arrow through a leaf of a poplar tree from a hundred paces away, never missing his target. This story is recorded in the 'Records of the Grand Historian'.","historicalFigures":["Yang Youji"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["adverbial","attributive"],"structure":"verb-object","register":"literary, but can be used in both formal and informal contexts to describe precision","connotation":"positive","commonMistakes":"Learners might use this idiom to describe general skill rather than specific accuracy. It is important to note that it emphasizes precision rather than general proficiency.","canStandAlone":false},"examples":[{"simplified":"他的射箭技术真是百步穿杨。","english":"His archery skills are truly precise, like hitting the bullseye from a hundred paces.","traditional":"他的射箭技術真是百步穿楊。"},{"simplified":"这个狙击手的枪法可以说是百步穿杨。","english":"The sniper's marksmanship can be described as hitting the bullseye from a hundred paces.","traditional":"這個狙擊手的槍法可以說是百步穿楊。"}],"synonyms":["百发百中"],"antonyms":[],"confusedWith":[{"id":"百发百中","note":"While both idioms emphasize accuracy, 百发百中 highlights consistent success, whereas 百步穿杨 emphasizes precision over distance."}],"traditional":"百步穿楊","pinyinOverride":null},{"id":"bai-chuan-gui-hai","simplified":"百川归海","literalMeaning":"all rivers flow to the sea","figurativeMeaning":"all things ultimately have a common destination or goal","englishEquivalents":["All roads lead to Rome"],"shortGloss":"all things lead to a common goal","characters":[{"char":"百","meaning":"hundred; many"},{"char":"川","meaning":"rivers"},{"char":"归","meaning":"return; flow back"},{"char":"海","meaning":"sea"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '百川归海' is often used to describe how various paths or efforts ultimately converge towards a single goal or outcome, much like how all rivers, regardless of their origin, eventually flow into the sea. This imagery emphasizes unity and the inevitability of certain outcomes.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"subject-predicate","register":"literary, but commonly used in both formal and informal contexts","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with others that involve water or flow, but this idiom specifically emphasizes the convergence of many paths to one destination. It's not about the journey but the common endpoint.","canStandAlone":false},"examples":[{"simplified":"无论选择哪条路，最终都是百川归海。","english":"No matter which path you choose, ultimately all roads lead to the same destination.","traditional":"無論選擇哪條路，最終都是百川歸海。"},{"simplified":"各个部门的努力就像百川归海，最终都会为公司的成功做出贡献。","english":"The efforts of each department are like rivers flowing into the sea, ultimately contributing to the company's success.","traditional":"各個部門的努力就像百川歸海，最終都會為公司的成功做出貢獻。"}],"synonyms":[],"antonyms":[],"confusedWith":[],"traditional":"百川歸海","pinyinOverride":null},{"id":"bai-du-bu-yan","simplified":"百读不厌","literalMeaning":"hundred read not weary","figurativeMeaning":"something so interesting or valuable that it can be read or enjoyed repeatedly without losing appeal","englishEquivalents":["never gets old","timeless classic"],"shortGloss":"never gets old","characters":[{"char":"百","meaning":"hundred, many times"},{"char":"读","meaning":"read"},{"char":"不","meaning":"not"},{"char":"厌","meaning":"weary, tired of"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom 百读不厌 is used to describe books, stories, or other works that are so captivating or valuable that one can read them over and over again without losing interest. It highlights the enduring appeal of certain works that continue to engage and inspire readers no matter how many times they are revisited.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"modifier-head","register":"commonly used in both written and spoken Chinese, often in literary contexts","connotation":"positive","commonMistakes":"Learners might confuse this idiom with others that involve reading or repetition, such as 书不释手 (unable to put a book down), which emphasizes being engrossed in reading rather than the timeless quality of the material.","canStandAlone":false},"examples":[{"simplified":"这本小说真是百读不厌，每次读都有新的收获。","english":"This novel is truly timeless; every time I read it, I gain new insights.","traditional":"這本小說真是百讀不厭，每次讀都有新的收穫。"},{"simplified":"他的诗歌百读不厌，总能引发深思。","english":"His poetry never gets old and always provokes deep thought.","traditional":"他的詩歌百讀不厭，總能引發深思。"}],"synonyms":["百看不厌"],"antonyms":[],"confusedWith":[{"id":"书不释手","note":"书不释手 emphasizes being engrossed in reading, not the timeless quality of the material."}],"traditional":"百讀不厭","pinyinOverride":null},{"id":"bai-duan-dai-ju","simplified":"百端待举","literalMeaning":"a hundred tasks await action","figurativeMeaning":"many tasks or issues need to be addressed","englishEquivalents":["a lot on one's plate","many irons in the fire"],"shortGloss":"many tasks need attention","characters":[{"char":"百","meaning":"hundred"},{"char":"端","meaning":"tasks; issues"},{"char":"待","meaning":"await"},{"char":"举","meaning":"action; implementation"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '百端待举' is used to describe a situation where there are numerous tasks or issues that need to be addressed or resolved. It emphasizes the urgency and multiplicity of tasks awaiting action.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"modifier-head","register":"literary, but can be used in formal speech and writing","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with others that involve '百' (hundred) but do not convey the sense of urgency or multiplicity of tasks. It's important to use it in contexts where multiple tasks are pending.","canStandAlone":false},"examples":[{"simplified":"项目刚开始，百端待举，我们需要制定一个详细的计划。","english":"The project has just started, and many tasks need to be addressed. We need to come up with a detailed plan.","traditional":"項目剛開始，百端待舉，我們需要制定一個詳細的計劃。"},{"simplified":"新官上任，百端待举，他感到压力很大。","english":"As a new official takes office, many tasks await action, and he feels a lot of pressure.","traditional":"新官上任，百端待舉，他感到壓力很大。"}],"synonyms":[],"antonyms":[],"confusedWith":[],"traditional":"百端待舉","pinyinOverride":null},{"id":"bai-fei-dai-ju","simplified":"百废待举","literalMeaning":"a hundred neglected tasks await action","figurativeMeaning":"many neglected tasks or projects need to be started or addressed","englishEquivalents":["a lot of work to be done","many tasks awaiting attention"],"shortGloss":"many tasks awaiting action","characters":[{"char":"百","meaning":"hundred; many"},{"char":"废","meaning":"neglected; abandoned"},{"char":"待","meaning":"await; need"},{"char":"举","meaning":"to start; to initiate"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '百废待举' describes a situation where many tasks or projects have been neglected and now require attention. It is often used to describe the aftermath of a period of neglect or disruption, where there is a need to restart or rebuild.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"modifier-head","register":"commonly used in both written and spoken Chinese to describe situations of neglect or disrepair","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with ones that imply tasks are already in progress, rather than awaiting initiation. It's important to note that '待举' emphasizes the need to start or initiate action.","canStandAlone":false},"examples":[{"simplified":"新官上任，百废待举，他感到压力很大。","english":"The new official took office, and with many tasks awaiting action, he felt a lot of pressure.","traditional":"新官上任，百廢待舉，他感到壓力很大。"},{"simplified":"经过多年战乱，这个国家百废待举。","english":"After years of war, this country has many tasks awaiting action.","traditional":"經過多年戰亂，這個國家百廢待舉。"}],"synonyms":["百废俱兴"],"antonyms":[],"confusedWith":[{"id":"百废俱兴","note":"While '百废俱兴' implies that neglected tasks are being revived or flourishing, '百废待举' emphasizes that they are still awaiting initiation."}],"traditional":"百廢待舉","pinyinOverride":null},{"id":"bai-fei-ju-xing","simplified":"百废俱兴","literalMeaning":"a hundred abandoned things all flourish","figurativeMeaning":"all neglected affairs are being revived; everything is being restored","englishEquivalents":["everything is flourishing again","revival of all neglected matters"],"shortGloss":"revival of all neglected matters","characters":[{"char":"百","meaning":"hundred, many"},{"char":"废","meaning":"abandoned, neglected"},{"char":"俱","meaning":"all, together"},{"char":"兴","meaning":"flourish, revive"}],"origin":{"period":"Tang dynasty (618–907)","sourceText":"《旧唐书·李密传》","sourceTextEnglish":"Old Book of Tang, Biography of Li Mi","originalExcerpt":"百废俱兴，庶绩其繁。","storyEnglish":"The idiom originates from the 'Old Book of Tang', where it describes a period during the Tang dynasty when many neglected or abandoned state affairs were being revived and restored to prosperity. It reflects a time of renewal and reconstruction after a period of decline or neglect.","historicalFigures":["Li Mi"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"coordinate","register":"literary, but can be used in formal speech and writing","connotation":"positive","commonMistakes":"Learners often confuse it with idioms that simply mean 'everything is flourishing' without the nuance of revival from neglect. It specifically implies a restoration process.","canStandAlone":false},"examples":[{"simplified":"经过几年的努力，这个城市终于百废俱兴。","english":"After several years of effort, the city is finally seeing the revival of all neglected matters.","traditional":"經過幾年的努力，這個城市終於百廢俱興。"},{"simplified":"新政府上台后，百废俱兴，人民对未来充满希望。","english":"After the new government took office, everything neglected was revived, and the people were full of hope for the future.","traditional":"新政府上臺後，百廢俱興，人民對未來充滿希望。"}],"synonyms":[],"antonyms":[],"confusedWith":[{"id":"欣欣向荣","note":"欣欣向荣 means 'thriving and prosperous', but lacks the implication of revival from neglect."}],"traditional":"百廢俱興","pinyinOverride":null},{"id":"bai-gan-jiao-ji","simplified":"百感交集","literalMeaning":"a hundred feelings intertwined","figurativeMeaning":"to be overwhelmed by a mixture of emotions","englishEquivalents":["mixed emotions","overcome with emotion"],"shortGloss":"overwhelmed by mixed emotions","characters":[{"char":"百","meaning":"hundred; many"},{"char":"感","meaning":"feelings; emotions"},{"char":"交","meaning":"intertwined; mixed"},{"char":"集","meaning":"gathered; collected"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '百感交集' describes a state where a person experiences many different emotions at once, often due to a significant event or moment. The phrase conveys the complexity of human emotions, suggesting that they can be intertwined and overwhelming.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","complement"],"structure":"modifier-head","register":"widely used in both written and spoken Chinese","connotation":"neutral","commonMistakes":"Learners often confuse this idiom with others that describe singular emotions. '百感交集' specifically refers to a mix of emotions, not just one.","canStandAlone":false},"examples":[{"simplified":"听到这个消息，他百感交集，不知道该说什么好。","english":"Upon hearing the news, he was overwhelmed by mixed emotions and didn't know what to say.","traditional":"聽到這個消息，他百感交集，不知道該說什麼好。"},{"simplified":"毕业典礼上，她百感交集，既高兴又不舍。","english":"At the graduation ceremony, she was filled with mixed emotions, feeling both happy and reluctant to leave.","traditional":"畢業典禮上，她百感交集，既高興又不捨。"}],"synonyms":["感慨万千"],"antonyms":[],"confusedWith":[{"id":"感慨万千","note":"While both idioms involve strong emotions, '感慨万千' emphasizes deep feelings and reflections, often with a sense of nostalgia or sentimentality, rather than a mixture of emotions."}],"traditional":"百感交集","pinyinOverride":null},{"id":"bai-hui-qian-pa","simplified":"百卉千葩","literalMeaning":"a hundred flowers, a thousand blossoms","figurativeMeaning":"a great variety of beautiful things or talents flourishing together","englishEquivalents":["a riot of color","a profusion of blooms"],"shortGloss":"a profusion of beautiful things","characters":[{"char":"百","meaning":"hundred"},{"char":"卉","meaning":"flowers"},{"char":"千","meaning":"thousand"},{"char":"葩","meaning":"blossoms"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '百卉千葩' is often used to describe a scene where many different kinds of beautiful things or talents are flourishing together, much like a garden full of diverse and colorful flowers. The phrase emphasizes variety and abundance.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["attributive","adverbial"],"structure":"coordinate","register":"literary, often used in poetic or formal contexts","connotation":"positive","commonMistakes":"Learners might confuse this idiom with others that involve flowers but do not emphasize variety and abundance. It specifically highlights a profusion of diverse and beautiful elements.","canStandAlone":false},"examples":[{"simplified":"春天到了，公园里百卉千葩，美不胜收。","english":"Spring has arrived, and the park is a riot of color, with a profusion of blooms.","traditional":"春天到了，公園裡百卉千葩，美不勝收。"},{"simplified":"艺术节上，百卉千葩的作品让人目不暇接。","english":"At the art festival, the wide variety of beautiful works dazzled the eye.","traditional":"藝術節上，百卉千葩的作品讓人目不暇接。"}],"synonyms":[],"antonyms":[],"confusedWith":[],"traditional":"百卉千葩","pinyinOverride":null},{"id":"bai-jia-zheng-ming","simplified":"百家争鸣","literalMeaning":"a hundred schools contend and sing","figurativeMeaning":"a situation where various ideas and opinions are freely expressed and compete with each other","englishEquivalents":["let a hundred flowers bloom","marketplace of ideas"],"shortGloss":"free expression of competing ideas","characters":[{"char":"百","meaning":"hundred"},{"char":"家","meaning":"schools or families"},{"char":"争","meaning":"contend"},{"char":"鸣","meaning":"sing or express"}],"origin":{"period":"Warring States period (475–221 BCE)","sourceText":"《史记·百家争鸣》","sourceTextEnglish":"Records of the Grand Historian, Hundred Schools of Thought","originalExcerpt":"百家争鸣，诸子百家，皆有所长。","storyEnglish":"The phrase '百家争鸣' originates from the Warring States period, a time of great intellectual development in ancient China. During this era, various schools of thought, such as Confucianism, Daoism, and Legalism, emerged and competed for influence. The phrase captures the vibrant intellectual environment where different philosophers and thinkers expressed their ideas and debated with one another, contributing to the rich tapestry of Chinese philosophy.","historicalFigures":["Confucius","Laozi","Han Feizi"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["subject","predicate","object"],"structure":"subject-predicate","register":"literary, but very widely understood and used in ordinary speech","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with '百花齐放' (let a hundred flowers bloom), which emphasizes diversity and flourishing rather than competition. '百家争鸣' specifically refers to the contention and debate among different schools of thought.","canStandAlone":false},"examples":[{"simplified":"在这个学术会议上，真是百家争鸣，各种观点都有。","english":"At this academic conference, it was truly a case of '百家争鸣', with a variety of viewpoints being expressed.","traditional":"在這個學術會議上，真是百家爭鳴，各種觀點都有。"},{"simplified":"互联网时代的信息传播让百家争鸣成为可能。","english":"The spread of information in the internet age makes '百家争鸣' possible.","traditional":"互聯網時代的信息傳播讓百家爭鳴成為可能。"}],"synonyms":[],"antonyms":[],"confusedWith":[],"traditional":"百家爭鳴","pinyinOverride":null},{"id":"bai-kong-qian-chuang","simplified":"百孔千疮","literalMeaning":"hundred holes, thousand wounds","figurativeMeaning":"in a state of extreme disrepair or damage; riddled with problems","englishEquivalents":["riddled with holes","falling apart","in shambles"],"shortGloss":"in a state of disrepair","characters":[{"char":"百","meaning":"hundred"},{"char":"孔","meaning":"holes"},{"char":"千","meaning":"thousand"},{"char":"疮","meaning":"wounds"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '百孔千疮' is used to describe something that is severely damaged or in a state of disrepair. It conjures the image of an object or situation that is so full of holes and wounds that it is barely holding together. This vivid imagery is often applied to physical objects, systems, or situations that are failing or deteriorating.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"coordinate","register":"widely used in both written and spoken Chinese","connotation":"negative","commonMistakes":"Learners might confuse this idiom with others that describe damage or deterioration, but '百孔千疮' specifically emphasizes the extent and severity of the damage. It is not used for minor issues.","canStandAlone":false},"examples":[{"simplified":"这座老房子已经百孔千疮，住起来很不安全。","english":"This old house is riddled with holes and is very unsafe to live in.","traditional":"這座老房子已經百孔千瘡，住起來很不安全。"},{"simplified":"经过多年的战争，这个国家的基础设施百孔千疮。","english":"After years of war, the country's infrastructure is in shambles.","traditional":"經過多年的戰爭，這個國家的基礎設施百孔千瘡。"}],"synonyms":["千疮百孔"],"antonyms":[],"confusedWith":[{"id":"千疮百孔","note":"This is essentially a synonym with the same meaning, but learners might not realize they are interchangeable."}],"traditional":"百孔千瘡","pinyinOverride":null},{"id":"bai-kou-mo-bian","simplified":"百口莫辩","literalMeaning":"a hundred mouths cannot argue","figurativeMeaning":"unable to defend oneself despite being innocent","englishEquivalents":["speechless in defense","unable to justify oneself"],"shortGloss":"unable to defend oneself","characters":[{"char":"百","meaning":"hundred"},{"char":"口","meaning":"mouths"},{"char":"莫","meaning":"cannot"},{"char":"辩","meaning":"argue; defend"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '百口莫辩' describes a situation where someone is unable to defend themselves against accusations, even if they are innocent. The imagery of 'a hundred mouths' suggests that even with numerous people speaking on one's behalf, it is impossible to clear one's name. This reflects the frustration and helplessness of being wrongly accused.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","complement"],"structure":"subject-predicate","register":"commonly used in both written and spoken Chinese","connotation":"negative","commonMistakes":"Learners often confuse this idiom with similar expressions that imply guilt, but '百口莫辩' specifically refers to being unable to defend oneself despite being innocent.","canStandAlone":false},"examples":[{"simplified":"他被误会偷了东西，虽然百口莫辩，但他仍然保持冷静。","english":"He was misunderstood as having stolen something, and although he was unable to defend himself, he remained calm.","traditional":"他被誤會偷了東西，雖然百口莫辯，但他仍然保持冷靜。"},{"simplified":"在这样的情况下，即使是百口莫辩，也要相信真相终会大白。","english":"In such situations, even if you cannot defend yourself, you must believe that the truth will eventually come to light.","traditional":"在這樣的情況下，即使是百口莫辯，也要相信真相終會大白。"}],"synonyms":[],"antonyms":[],"confusedWith":[{"id":"哑口无言","note":"While both imply being speechless, '哑口无言' often suggests being at a loss for words due to surprise or defeat, not necessarily innocence."}],"traditional":"百口莫辯","pinyinOverride":null},{"id":"bai-li-tiao-yi","simplified":"百里挑一","literalMeaning":"one selected from a hundred","figurativeMeaning":"outstanding; one in a hundred; cream of the crop","englishEquivalents":["one in a million","cream of the crop"],"shortGloss":"outstanding; one in a hundred","characters":[{"char":"百","meaning":"hundred"},{"char":"里","meaning":"unit of distance; here used as a metaphor for quantity"},{"char":"挑","meaning":"select; choose"},{"char":"一","meaning":"one"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '百里挑一' is used to describe someone or something that is exceptionally outstanding, akin to being the best out of a hundred choices. It is often used to praise individuals who stand out in their field or context, emphasizing their rarity and excellence.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["attributive","predicate"],"structure":"verb-object","register":"commonly used in both spoken and written Chinese","connotation":"positive","commonMistakes":"Learners might confuse this idiom with '万里挑一', which means 'one in ten thousand' and implies an even rarer occurrence. '百里挑一' is less extreme but still denotes high quality.","canStandAlone":false},"examples":[{"simplified":"她的才华在公司里是百里挑一的。","english":"Her talent is one in a hundred in the company.","traditional":"她的才華在公司裡是百裡挑一的。"},{"simplified":"这款手机的性能在市场上是百里挑一。","english":"The performance of this phone is outstanding in the market.","traditional":"這款手機的性能在市場上是百裡挑一。"}],"synonyms":["出类拔萃","鹤立鸡群"],"antonyms":["平平无奇"],"confusedWith":[{"id":"万里挑一","note":"万里挑一 means 'one in ten thousand', indicating an even rarer occurrence than 百里挑一."}],"traditional":"百裡挑一","pinyinOverride":null},{"id":"bai-lian-cheng-gang","simplified":"百炼成钢","literalMeaning":"hundred refinements become steel","figurativeMeaning":"to become strong and resilient through trials and tribulations","englishEquivalents":["what doesn't kill you makes you stronger","tempered by fire","forged in the heat of battle"],"shortGloss":"strength through trials","characters":[{"char":"百","meaning":"hundred"},{"char":"炼","meaning":"refine; smelt"},{"char":"成","meaning":"become; turn into"},{"char":"钢","meaning":"steel"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '百炼成钢' is often used to describe someone who has become strong and resilient after undergoing numerous challenges and hardships. The metaphor compares a person to steel, which becomes stronger and more durable after being repeatedly heated and forged. This reflects the idea that enduring difficulties can lead to personal growth and strength.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","complement"],"structure":"verb-object","register":"commonly used in both written and spoken Chinese, often in motivational contexts","connotation":"positive","commonMistakes":"Learners might confuse this idiom with others that involve 'steel' or 'refinement,' but it's specifically about becoming strong through repeated challenges, not just any kind of improvement or refinement.","canStandAlone":false},"examples":[{"simplified":"经过多年的磨练，他终于百炼成钢。","english":"After years of trials, he finally became strong and resilient.","traditional":"經過多年的磨練，他終於百鍊成鋼。"},{"simplified":"在逆境中成长的人，往往能够百炼成钢。","english":"People who grow up in adversity often emerge strong and resilient.","traditional":"在逆境中成長的人，往往能夠百鍊成鋼。"}],"synonyms":["磨砺成钢"],"antonyms":[],"confusedWith":[{"id":"百折不挠","note":"While '百折不挠' emphasizes persistence despite setbacks, '百炼成钢' focuses on the strength gained through enduring hardships."}],"traditional":"百鍊成鋼","pinyinOverride":null},{"id":"bai-nian-bu-yu","simplified":"百年不遇","literalMeaning":"a hundred years not encountered","figurativeMeaning":"an extremely rare event","englishEquivalents":["once in a century","once in a lifetime"],"shortGloss":"extremely rare event","characters":[{"char":"百","meaning":"hundred"},{"char":"年","meaning":"years"},{"char":"不","meaning":"not"},{"char":"遇","meaning":"encountered"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '百年不遇' is used to describe an event or occurrence that is extremely rare, something that might happen only once in a hundred years. It emphasizes the rarity and uniqueness of the situation, often used in contexts where something extraordinary or unprecedented has occurred.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"modifier-head","register":"commonly used in both formal and informal contexts to emphasize rarity","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with similar expressions that denote rarity but differ in degree, such as '千载难逢' which implies an even rarer occurrence. It's important to use '百年不遇' when describing something rare but not necessarily unique in a millennium.","canStandAlone":false},"examples":[{"simplified":"这场暴风雪是百年不遇的自然灾害。","english":"This snowstorm is a once-in-a-century natural disaster.","traditional":"這場暴風雪是百年不遇的自然災害。"},{"simplified":"这样的机会真是百年不遇，我们一定要好好把握。","english":"Such an opportunity is extremely rare, we must seize it.","traditional":"這樣的機會真是百年不遇，我們一定要好好把握。"}],"synonyms":["千载难逢","凤毛麟角"],"antonyms":[],"confusedWith":[{"id":"千载难逢","note":"千载难逢 implies an even rarer occurrence, suggesting something that happens once in a thousand years."}],"traditional":"百年不遇","pinyinOverride":null},{"id":"bai-nian-da-ji","simplified":"百年大计","literalMeaning":"hundred-year great plan","figurativeMeaning":"a long-term plan of great importance","englishEquivalents":["a long-term strategy","a century-long plan"],"shortGloss":"a long-term important plan","characters":[{"char":"百","meaning":"hundred"},{"char":"年","meaning":"year"},{"char":"大","meaning":"great; significant"},{"char":"计","meaning":"plan; strategy"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '百年大计' is used to emphasize the importance of making plans that are meant to last for a very long time, often spanning generations. It is frequently used in contexts such as education, infrastructure, or national development, where the outcomes are expected to have enduring impacts.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["subject","object","attributive"],"structure":"modifier-head","register":"formal written and spoken Chinese, often used in official or serious contexts","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with shorter-term plans or strategies. It specifically implies a plan with long-term significance and impact.","canStandAlone":false},"examples":[{"simplified":"教育是国家的百年大计。","english":"Education is a long-term plan of great importance for the nation.","traditional":"教育是國家的百年大計。"},{"simplified":"这项工程是百年大计，必须认真规划。","english":"This project is a long-term plan of great importance and must be carefully planned.","traditional":"這項工程是百年大計，必須認真規劃。"}],"synonyms":["长远规划"],"antonyms":[],"confusedWith":[],"traditional":"百年大計","pinyinOverride":null},{"id":"bai-si-bu-jie","simplified":"百思不解","literalMeaning":"a hundred thoughts, not understand","figurativeMeaning":"to remain puzzled despite much thought; to be unable to make sense of something","englishEquivalents":["baffled","at a loss","can't make heads or tails of it"],"shortGloss":"unable to understand despite much thought","characters":[{"char":"百","meaning":"hundred; many"},{"char":"思","meaning":"think; ponder"},{"char":"不","meaning":"not"},{"char":"解","meaning":"understand; solve"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '百思不解' is used to describe a situation where someone has thought long and hard about something but still cannot understand or solve it. It reflects the frustration of being unable to comprehend a problem despite considerable effort.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","complement"],"structure":"subject-predicate","register":"commonly used in both written and spoken Chinese","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with others that involve thinking or pondering, such as '冥思苦想', which implies deep and painful thinking, whereas '百思不解' emphasizes the inability to understand despite much thought.","canStandAlone":false},"examples":[{"simplified":"他对这个问题百思不解，最后还是放弃了。","english":"He was baffled by the problem and eventually gave up.","traditional":"他對這個問題百思不解，最後還是放棄了。"},{"simplified":"这个谜题让我百思不解，真不知道答案是什么。","english":"This riddle has me completely puzzled; I really don't know what the answer is.","traditional":"這個謎題讓我百思不解，真不知道答案是什麼。"}],"synonyms":["百思莫解"],"antonyms":[],"confusedWith":[{"id":"冥思苦想","note":"While '冥思苦想' implies deep and painful thinking, '百思不解' emphasizes the inability to understand despite much thought."}],"traditional":"百思不解","pinyinOverride":null},{"id":"bai-wu-jin-ji","simplified":"百无禁忌","literalMeaning":"hundred no prohibitions","figurativeMeaning":"to be free from all restrictions; to do as one pleases","englishEquivalents":["free as a bird","no holds barred"],"shortGloss":"free from restrictions","characters":[{"char":"百","meaning":"hundred; all kinds of"},{"char":"无","meaning":"without; no"},{"char":"禁","meaning":"prohibit; forbid"},{"char":"忌","meaning":"taboo; avoid"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '百无禁忌' is often used to describe a situation where someone feels completely free to act without any restrictions or taboos. The phrase suggests a sense of liberation and the ability to do as one pleases without fear of repercussions. Its exact origin is unclear, but it is widely used in modern Chinese to convey a sense of freedom and lack of constraint.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"modifier-head","register":"commonly used in both spoken and written Chinese","connotation":"positive","commonMistakes":"Learners might confuse this idiom with similar-sounding ones that imply recklessness or lack of caution. '百无禁忌' specifically conveys a positive sense of freedom rather than carelessness.","canStandAlone":false},"examples":[{"simplified":"在这个自由的国家，人们可以百无禁忌地表达自己的意见。","english":"In this free country, people can express their opinions without any restrictions.","traditional":"在這個自由的國家，人們可以百無禁忌地表達自己的意見。"},{"simplified":"他在派对上百无禁忌地跳舞，完全不在乎别人的看法。","english":"He danced freely at the party, completely unconcerned with what others thought.","traditional":"他在派對上百無禁忌地跳舞，完全不在乎別人的看法。"}],"synonyms":["无拘无束","随心所欲"],"antonyms":["束手束脚"],"confusedWith":[{"id":"肆无忌惮","note":"While '肆无忌惮' implies acting recklessly without regard for rules or consequences, '百无禁忌' suggests freedom from restrictions in a positive sense."}],"traditional":"百無禁忌","pinyinOverride":null},{"id":"bai-wu-liao-lai","simplified":"百无聊赖","literalMeaning":"hundred without interest and reliance","figurativeMeaning":"extremely bored or feeling listless","englishEquivalents":["bored to death","bored stiff"],"shortGloss":"extremely bored","characters":[{"char":"百","meaning":"hundred; very"},{"char":"无","meaning":"without"},{"char":"聊","meaning":"interest; to rely on"},{"char":"赖","meaning":"rely on; depend on"}],"origin":{"period":"Eastern Jin Dynasty (317–420)","sourceText":"《世说新语·排调》","sourceTextEnglish":"A New Account of the Tales of the World, Chapter on Ridicule","originalExcerpt":"阮籍每当百无聊赖，辄登东山以舒啸。","storyEnglish":"The idiom originates from the Eastern Jin Dynasty, where the scholar Ruan Ji, feeling extremely bored and listless, would often climb the Eastern Mountain to express his feelings through long, drawn-out sighs. This behavior was noted in the text 'A New Account of the Tales of the World'.","historicalFigures":["Ruan Ji"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"modifier-head","register":"literary, but very widely understood and used in ordinary speech","connotation":"neutral","commonMistakes":"Learners often confuse this idiom with expressions that mean 'lazy' due to the character '赖', but it specifically refers to a state of boredom or listlessness, not laziness.","canStandAlone":false},"examples":[{"simplified":"他在家里百无聊赖，只好看电视打发时间。","english":"He was extremely bored at home, so he had no choice but to watch TV to pass the time.","traditional":"他在家裡百無聊賴，只好看電視打發時間。"},{"simplified":"百无聊赖的时候，我喜欢去公园散步。","english":"When I'm feeling extremely bored, I like to take a walk in the park.","traditional":"百無聊賴的時候，我喜歡去公園散步。"}],"synonyms":["无聊至极","无所事事"],"antonyms":["忙得不可开交"],"confusedWith":[{"id":"无所事事","note":"While both idioms relate to inactivity, '无所事事' emphasizes having nothing to do, whereas '百无聊赖' emphasizes the feeling of boredom."}],"traditional":"百無聊賴","pinyinOverride":null},{"id":"bai-zhan-bai-sheng","simplified":"百战百胜","literalMeaning":"hundred battles, hundred victories","figurativeMeaning":"to be invincible; to win every battle","englishEquivalents":["undefeated","invincible","always victorious"],"shortGloss":"invincible; always victorious","characters":[{"char":"百","meaning":"hundred"},{"char":"战","meaning":"battle"},{"char":"百","meaning":"hundred"},{"char":"胜","meaning":"victory"}],"origin":{"period":"Warring States period (475–221 BCE)","sourceText":"《孙子兵法·谋攻》","sourceTextEnglish":"The Art of War by Sun Tzu, Chapter on Attack by Stratagem","originalExcerpt":"故善战者，百战百胜，非善之善者也。","storyEnglish":"This idiom originates from Sun Tzu's 'The Art of War', where he discusses the qualities of a good general. He suggests that while winning every battle is impressive, it is not the ultimate form of excellence. True excellence lies in winning without fighting, by outsmarting the enemy before the battle even begins.","historicalFigures":["Sun Tzu"],"relatedIdiomsFromSameSource":["知己知彼，百战不殆"]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"coordinate","register":"literary, but widely used in both formal and informal contexts","connotation":"positive","commonMistakes":"Learners sometimes confuse this idiom with '百战不殆', which emphasizes being prepared and avoiding danger, rather than guaranteed victory.","canStandAlone":false},"examples":[{"simplified":"这支球队在比赛中百战百胜，令人敬佩。","english":"This team is invincible in matches, earning admiration from everyone.","traditional":"這支球隊在比賽中百戰百勝，令人敬佩。"},{"simplified":"他在商场上百战百胜，成为了行业的传奇。","english":"He is invincible in the business world, becoming a legend in the industry.","traditional":"他在商場上百戰百勝，成為了行業的傳奇。"}],"synonyms":["战无不胜"],"antonyms":["屡战屡败"],"confusedWith":[{"id":"百战不殆","note":"百战不殆 focuses on being prepared and avoiding danger, not necessarily winning every battle."}],"traditional":"百戰百勝","pinyinOverride":null},{"id":"bai-zhan-bu-dai","simplified":"百战不殆","literalMeaning":"hundred battles, not endangered","figurativeMeaning":"to be ever-victorious; to emerge unscathed from many battles","englishEquivalents":["invincible","unbeatable","always victorious"],"shortGloss":"invincible in battle","characters":[{"char":"百","meaning":"hundred"},{"char":"战","meaning":"battles"},{"char":"不","meaning":"not"},{"char":"殆","meaning":"endangered"}],"origin":{"period":"Spring and Autumn period (770–476 BCE)","sourceText":"《孙子兵法·谋攻》","sourceTextEnglish":"Sun Tzu's The Art of War, Chapter 3: Strategic Attack","originalExcerpt":"故善战者，立于不败之地，而不失敌之败也。是故胜兵先胜而后求战，败兵先战而后求胜。善用兵者，修道而保法，故能为胜败之政。故百战百胜，非善之善者也；不战而屈人之兵，善之善者也。","storyEnglish":"The idiom comes from Sun Tzu's 'The Art of War,' where he discusses the principles of warfare. Sun Tzu emphasizes that a truly skilled general is one who can achieve victory without risking his forces. The phrase '百战不殆' suggests that through careful planning and strategy, one can engage in numerous battles without ever being in danger of defeat.","historicalFigures":["Sun Tzu"],"relatedIdiomsFromSameSource":["不战而屈人之兵"]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"subject-predicate","register":"literary, but widely used in both written and spoken Chinese","connotation":"positive","commonMistakes":"Learners might confuse this idiom with '百战百胜' (to win every battle), which emphasizes winning rather than avoiding danger. '百战不殆' focuses on the strategic aspect of not being endangered.","canStandAlone":false},"examples":[{"simplified":"这位将军以其百战不殆的战绩而闻名。","english":"This general is famous for his record of emerging unscathed from countless battles.","traditional":"這位將軍以其百戰不殆的戰績而聞名。"},{"simplified":"他的策略让公司在竞争中百战不殆。","english":"His strategy allowed the company to remain invincible in the competition.","traditional":"他的策略讓公司在競爭中百戰不殆。"}],"synonyms":["百战百胜"],"antonyms":[],"confusedWith":[{"id":"百战百胜","note":"百战百胜 means winning every battle, while 百战不殆 focuses on not being in danger."}],"traditional":"百戰不殆","pinyinOverride":null},{"id":"bai-zhe-bu-hui","simplified":"百折不回","literalMeaning":"hundred setbacks not retreat","figurativeMeaning":"to persevere despite numerous setbacks; to remain unyielding","englishEquivalents":["persevere against all odds","never give up","unyielding spirit"],"shortGloss":"persevere despite setbacks","characters":[{"char":"百","meaning":"hundred; many"},{"char":"折","meaning":"setbacks; failures"},{"char":"不","meaning":"not"},{"char":"回","meaning":"retreat; yield"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '百折不回' is believed to have originated from the idea of enduring numerous challenges or setbacks without giving up. It emphasizes the importance of perseverance and resilience in the face of difficulties. The exact origin of the phrase is not tied to a specific historical text, but it has been used in Chinese literature and speech to inspire determination.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"modifier-head","register":"literary, but widely used in both formal and informal contexts","connotation":"positive","commonMistakes":"Learners might confuse this idiom with '半途而废' (give up halfway), which has an opposite meaning. It's important to remember that '百折不回' emphasizes perseverance, while '半途而废' emphasizes giving up.","canStandAlone":false},"examples":[{"simplified":"他在创业过程中百折不回，最终取得了成功。","english":"He persevered through countless setbacks in his entrepreneurial journey and eventually succeeded.","traditional":"他在創業過程中百折不回，最終取得了成功。"},{"simplified":"面对困难，我们要有百折不回的精神。","english":"In the face of difficulties, we must have an unyielding spirit.","traditional":"面對困難，我們要有百折不回的精神。"}],"synonyms":["锲而不舍","坚持不懈"],"antonyms":["半途而废"],"confusedWith":[{"id":"半途而废","note":"While '百折不回' means to persevere, '半途而废' means to give up halfway."}],"traditional":"百折不回","pinyinOverride":null},{"id":"bai-liu-can-hua","simplified":"败柳残花","literalMeaning":"withered willow, fallen flowers","figurativeMeaning":"a woman who has lost her beauty or fallen into disgrace","englishEquivalents":["faded beauty","fallen woman"],"shortGloss":"a woman past her prime or disgraced","characters":[{"char":"败","meaning":"withered, defeated"},{"char":"柳","meaning":"willow"},{"char":"残","meaning":"fallen, ruined"},{"char":"花","meaning":"flower"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '败柳残花' is often used to describe a woman who has lost her youthful beauty or has fallen from grace. The imagery of withered willows and fallen flowers evokes a sense of beauty that has faded or been tarnished. This expression is commonly used in literature and poetry to convey a sense of nostalgia or lament over lost beauty.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["attributive","predicate"],"structure":"coordinate","register":"literary, often used in poetic or formal contexts","connotation":"negative","commonMistakes":"Learners might confuse this idiom with positive expressions about nature due to the characters for 'willow' and 'flower'. However, it carries a negative connotation about lost beauty or disgrace.","canStandAlone":false},"examples":[{"simplified":"她曾是个美人，如今却成了败柳残花。","english":"She was once a beauty, but now she is like a withered willow and fallen flowers.","traditional":"她曾是個美人，如今卻成了敗柳殘花。"},{"simplified":"在旧社会，许多女子因命运不济而沦为败柳残花。","english":"In the old society, many women became faded beauties due to unfortunate circumstances.","traditional":"在舊社會，許多女子因命運不濟而淪為敗柳殘花。"}],"synonyms":["人老珠黄"],"antonyms":[],"confusedWith":[{"id":"花容月貌","note":"While '花容月貌' describes someone with exceptional beauty, '败柳残花' refers to someone who has lost their beauty."}],"traditional":"敗柳殘花","pinyinOverride":null},{"id":"ban-bo-lu-li","simplified":"斑驳陆离","literalMeaning":"mottled and variegated","figurativeMeaning":"colorful and varied; dazzling and diverse","englishEquivalents":["kaleidoscopic","a riot of colors"],"shortGloss":"colorful and varied","characters":[{"char":"斑","meaning":"mottled; speckled"},{"char":"驳","meaning":"variegated; mixed"},{"char":"陆","meaning":"land; here used in an archaic sense to mean 'varied'"},{"char":"离","meaning":"separated; here used in an archaic sense to mean 'variegated'"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '斑驳陆离' describes something that is colorful and varied, often used to depict scenes that are visually striking due to their diversity of colors and patterns. It is frequently used in literature to describe landscapes, artworks, or any scene that is rich in color and variety.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["attributive","adverbial"],"structure":"coordinate","register":"literary, but can be used in descriptive writing or speech","connotation":"positive","commonMistakes":"Learners might confuse this idiom with others that describe color, but '斑驳陆离' specifically emphasizes a striking, varied appearance. It should not be used to describe something that is simply colorful without the aspect of variety.","canStandAlone":false},"examples":[{"simplified":"秋天的森林斑驳陆离，令人目不暇接。","english":"The autumn forest is colorful and varied, leaving one dazzled.","traditional":"秋天的森林斑駁陸離，令人目不暇接。"},{"simplified":"她穿着一件斑驳陆离的连衣裙，吸引了所有人的目光。","english":"She wore a colorful and varied dress that caught everyone's attention.","traditional":"她穿著一件斑駁陸離的連衣裙，吸引了所有人的目光。"}],"synonyms":["五光十色","绚丽多彩"],"antonyms":["单调乏味"],"confusedWith":[{"id":"五光十色","note":"Both describe colorful scenes, but '五光十色' focuses more on the brilliance and shine, while '斑驳陆离' emphasizes variety and pattern."}],"traditional":"斑駁陸離","pinyinOverride":null},{"id":"ban-chun-di-she","simplified":"搬唇递舌","literalMeaning":"move lips pass tongue","figurativeMeaning":"to spread gossip or rumors; to sow discord by spreading tales","englishEquivalents":["stir the pot","spread rumors","gossip"],"shortGloss":"spread gossip or rumors","characters":[{"char":"搬","meaning":"move, shift"},{"char":"唇","meaning":"lips"},{"char":"递","meaning":"pass, deliver"},{"char":"舌","meaning":"tongue"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom 搬唇递舌 describes the act of spreading rumors or gossip, often with the intent of causing trouble or discord. The imagery of moving lips and passing the tongue suggests the act of speaking and spreading tales from one person to another.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"commonly used in both spoken and written Chinese, often with a negative connotation","connotation":"negative","commonMistakes":"Learners might confuse 搬唇递舌 with similar idioms that involve speaking, but this idiom specifically implies spreading gossip or rumors with a negative intent.","canStandAlone":false},"examples":[{"simplified":"他总是喜欢搬唇递舌，挑拨离间。","english":"He always likes to spread gossip and sow discord.","traditional":"他總是喜歡搬唇遞舌，挑撥離間。"},{"simplified":"在办公室里搬唇递舌只会导致更多的误解。","english":"Spreading gossip in the office will only lead to more misunderstandings.","traditional":"在辦公室裡搬唇遞舌只會導致更多的誤解。"}],"synonyms":["挑拨离间","造谣生事"],"antonyms":["和睦相处"],"confusedWith":[{"id":"挑拨离间","note":"Both involve causing discord, but 搬唇递舌 specifically emphasizes spreading gossip."}],"traditional":"搬唇遞舌","pinyinOverride":null},{"id":"ban-nong-shi-fei","simplified":"搬弄是非","literalMeaning":"stir up right and wrong","figurativeMeaning":"to sow discord by spreading rumors or gossip","englishEquivalents":["stir the pot","sow discord","spread rumors"],"shortGloss":"sow discord through gossip","characters":[{"char":"搬","meaning":"to move; to stir"},{"char":"弄","meaning":"to play with; to manipulate"},{"char":"是","meaning":"right; correct"},{"char":"非","meaning":"wrong; incorrect"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom 搬弄是非 describes the act of causing trouble by spreading rumors or gossip. The phrase suggests manipulating or stirring up matters of right and wrong to create conflict or discord among people. It is commonly used to describe someone who enjoys creating drama or tension by talking behind others' backs.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","object","adverbial"],"structure":"verb-object","register":"commonly used in both spoken and written Chinese, often in informal contexts","connotation":"negative","commonMistakes":"Learners might confuse this idiom with ones that simply mean 'to gossip' without the connotation of causing conflict. 搬弄是非 specifically implies malicious intent to create discord.","canStandAlone":false},"examples":[{"simplified":"他总是喜欢搬弄是非，搞得大家不和。","english":"He always likes to sow discord, causing everyone to be at odds.","traditional":"他總是喜歡搬弄是非，搞得大家不和。"},{"simplified":"小心那些喜欢搬弄是非的人，他们会破坏你的关系。","english":"Be careful of those who like to spread rumors; they can ruin your relationships.","traditional":"小心那些喜歡搬弄是非的人，他們會破壞你的關係。"}],"synonyms":["挑拨离间"],"antonyms":["和睦相处"],"confusedWith":[{"id":"流言蜚语","note":"流言蜚语 refers to gossip or rumors in general, without the specific intent to cause discord."}],"traditional":"搬弄是非","pinyinOverride":null},{"id":"ban-shang-ding-ding","simplified":"板上钉钉","literalMeaning":"nail on the board","figurativeMeaning":"something that is settled and cannot be changed","englishEquivalents":["set in stone","a done deal"],"shortGloss":"settled matter","characters":[{"char":"板","meaning":"board"},{"char":"上","meaning":"on"},{"char":"钉","meaning":"nail"},{"char":"钉","meaning":"nail"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '板上钉钉' comes from the idea of nailing something onto a board, which makes it fixed and difficult to change. It metaphorically describes a situation or decision that is finalized and cannot be altered.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"modifier-head","register":"commonly used in both spoken and written Chinese","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with similar expressions that imply certainty but do not necessarily mean something is unchangeable. It's important to use it specifically for situations that are finalized.","canStandAlone":false},"examples":[{"simplified":"合同已经签了，这件事就是板上钉钉了。","english":"The contract has been signed, so this matter is set in stone.","traditional":"合同已經簽了，這件事就是板上釘釘了。"},{"simplified":"他的升职是板上钉钉的事情。","english":"His promotion is a done deal.","traditional":"他的升職是板上釘釘的事情。"}],"synonyms":["铁板钉钉"],"antonyms":[],"confusedWith":[{"id":"铁板钉钉","note":"Both idioms imply certainty, but '铁板钉钉' emphasizes the firmness and unchangeability even more."}],"traditional":"板上釘釘","pinyinOverride":null},{"id":"ban-bi-jiang-shan","simplified":"半壁江山","literalMeaning":"half of the country's rivers and mountains","figurativeMeaning":"a significant portion of territory or power","englishEquivalents":["a large share","a significant portion"],"shortGloss":"a significant portion of territory or power","characters":[{"char":"半","meaning":"half"},{"char":"壁","meaning":"wall; here implies a division or part"},{"char":"江","meaning":"river"},{"char":"山","meaning":"mountain"}],"origin":{"period":"Southern Song dynasty (1127–1279)","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '半壁江山' is believed to have originated during the Southern Song dynasty, a period when the Song court controlled only the southern half of China after losing the northern territories to the Jin dynasty. The phrase metaphorically described the remaining territory under Song control as 'half of the country's rivers and mountains.' Over time, it came to refer more generally to any significant portion of territory or power.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["subject","object"],"structure":"modifier-head","register":"literary, but understood in formal contexts","connotation":"neutral","commonMistakes":"Learners might mistakenly use this idiom to refer to a literal half of any object or concept, but it specifically refers to a significant portion of territory or power. It should not be used for trivial or non-geographical divisions.","canStandAlone":false},"examples":[{"simplified":"在这场战争中，他失去了半壁江山。","english":"In this war, he lost a significant portion of his territory.","traditional":"在這場戰爭中，他失去了半壁江山。"},{"simplified":"公司重组后，他掌握了半壁江山。","english":"After the company's restructuring, he controlled a large share of the power.","traditional":"公司重組後，他掌握了半壁江山。"}],"synonyms":[],"antonyms":[],"confusedWith":[],"traditional":"半壁江山","pinyinOverride":null},{"id":"ban-shen-bu-sui","simplified":"半身不遂","literalMeaning":"half body not functioning","figurativeMeaning":"paralysis of half the body; hemiplegia","englishEquivalents":["paralyzed on one side","hemiplegic"],"shortGloss":"hemiplegia; paralysis of half the body","characters":[{"char":"半","meaning":"half"},{"char":"身","meaning":"body"},{"char":"不","meaning":"not"},{"char":"遂","meaning":"functioning; moving"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '半身不遂' describes a condition where one side of the body is paralyzed, commonly known as hemiplegia. This condition can result from various medical issues, such as a stroke. The phrase is used both in medical contexts and metaphorically to describe situations where something is only partially functional.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"modifier-head","register":"commonly used in both medical and metaphorical contexts","connotation":"neutral","commonMistakes":"Learners might confuse '半身不遂' with idioms that describe full paralysis or other medical conditions. It specifically refers to paralysis affecting only one side of the body.","canStandAlone":false},"examples":[{"simplified":"他因为中风而半身不遂。","english":"He became hemiplegic due to a stroke.","traditional":"他因為中風而半身不遂。"},{"simplified":"医生说他的半身不遂可能需要长期的康复治疗。","english":"The doctor said his hemiplegia might require long-term rehabilitation.","traditional":"醫生說他的半身不遂可能需要長期的康復治療。"}],"synonyms":[],"antonyms":[],"confusedWith":[{"id":"全身瘫痪","note":"全身瘫痪 refers to full body paralysis, whereas 半身不遂 refers to paralysis of only one side of the body."}],"traditional":"半身不遂","pinyinOverride":null},{"id":"ban-tui-ban-jiu","simplified":"半推半就","literalMeaning":"half push, half yield","figurativeMeaning":"to agree reluctantly; to yield after some initial resistance","englishEquivalents":["to give in grudgingly","to acquiesce reluctantly"],"shortGloss":"reluctantly agree","characters":[{"char":"半","meaning":"half"},{"char":"推","meaning":"push"},{"char":"半","meaning":"half"},{"char":"就","meaning":"yield"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '半推半就' describes a situation where someone initially resists or hesitates but eventually gives in or agrees, often reluctantly. It is commonly used in social contexts where a person is persuaded to accept an offer or proposal after some initial hesitation.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"coordinate","register":"common in both spoken and written Chinese, often used in informal contexts","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with others that imply complete agreement or enthusiasm, but '半推半就' specifically involves reluctance or hesitation before agreeing.","canStandAlone":false},"examples":[{"simplified":"他半推半就地接受了邀请。","english":"He reluctantly accepted the invitation.","traditional":"他半推半就地接受了邀請。"},{"simplified":"经过一番劝说，她半推半就地同意了。","english":"After some persuasion, she agreed reluctantly.","traditional":"經過一番勸說，她半推半就地同意了。"}],"synonyms":[],"antonyms":[],"confusedWith":[{"id":"心甘情愿","note":"心甘情愿 means to do something willingly and happily, without reluctance."}],"traditional":"半推半就","pinyinOverride":null},{"id":"ban-ye-san-geng","simplified":"半夜三更","literalMeaning":"midnight third watch","figurativeMeaning":"in the middle of the night","englishEquivalents":["the dead of night","the middle of the night"],"shortGloss":"in the middle of the night","characters":[{"char":"半","meaning":"half"},{"char":"夜","meaning":"night"},{"char":"三","meaning":"three"},{"char":"更","meaning":"watch (a period of time in the night)"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"In ancient China, the night was divided into five 'watches' (更), each lasting about two hours. The third watch, or 三更, was from 11 PM to 1 AM, considered the middle of the night. The idiom 半夜三更 thus refers to this time, emphasizing the late, quiet, and often mysterious or eerie nature of the hour.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["adverbial"],"structure":"modifier-head","register":"commonly used in both written and spoken Chinese","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with expressions that mean 'late at night' or 'early morning'. It specifically refers to the middle of the night, not just any late hour.","canStandAlone":false},"examples":[{"simplified":"他半夜三更才回家。","english":"He didn't come home until the middle of the night.","traditional":"他半夜三更才回家。"},{"simplified":"半夜三更，街上一个人也没有。","english":"In the middle of the night, there wasn't a single person on the street.","traditional":"半夜三更，街上一個人也沒有。"}],"synonyms":[],"antonyms":[],"confusedWith":[],"traditional":"半夜三更","pinyinOverride":null},{"id":"bang-ren-li-bi","simplified":"傍人篱壁","literalMeaning":"lean on someone's fence","figurativeMeaning":"to rely on others for support or to live off others","englishEquivalents":["live off others","rely on others"],"shortGloss":"rely on others for support","characters":[{"char":"傍","meaning":"lean on"},{"char":"人","meaning":"person, others"},{"char":"篱","meaning":"fence"},{"char":"壁","meaning":"wall"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '傍人篱壁' is believed to have originated from the idea of physically leaning on someone else's fence or wall for support. This imagery is used metaphorically to describe a person who depends on others for their livelihood or support, rather than being self-reliant.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","object"],"structure":"verb-object","register":"literary, but can be used in everyday speech to describe dependency","connotation":"negative","commonMistakes":"Learners often confuse this idiom with positive expressions of collaboration or teamwork. However, '傍人篱壁' specifically implies a negative dependency, not mutual support.","canStandAlone":false},"examples":[{"simplified":"他总是傍人篱壁，从来不自己努力。","english":"He always relies on others and never makes an effort himself.","traditional":"他總是傍人籬壁，從來不自己努力。"},{"simplified":"如果你继续傍人篱壁，你永远不会独立。","english":"If you continue to rely on others, you will never be independent.","traditional":"如果你繼續傍人籬壁，你永遠不會獨立。"}],"synonyms":["寄人篱下"],"antonyms":["自力更生"],"confusedWith":[{"id":"合作共赢","note":"While '傍人篱壁' implies negative dependency, '合作共赢' refers to positive collaboration and mutual benefit."}],"traditional":"傍人籬壁","pinyinOverride":null},{"id":"bang-ren-men-hu","simplified":"傍人门户","literalMeaning":"rely on others' door","figurativeMeaning":"to rely on others for support or protection","englishEquivalents":["lean on others","rely on others' support"],"shortGloss":"rely on others for support","characters":[{"char":"傍","meaning":"rely on"},{"char":"人","meaning":"others"},{"char":"门","meaning":"door"},{"char":"户","meaning":"household"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '傍人门户' describes the act of relying on someone else's household or resources for support. It is often used to describe someone who cannot stand on their own and depends on others for their livelihood or protection.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","object"],"structure":"verb-object","register":"neutral, used in both written and spoken Chinese","connotation":"negative","commonMistakes":"Learners often confuse this idiom with '依赖他人' (rely on others), which is more neutral. '傍人门户' carries a slightly negative connotation, implying dependency due to lack of self-sufficiency.","canStandAlone":false},"examples":[{"simplified":"他总是傍人门户，自己从来不努力。","english":"He always relies on others for support and never makes an effort himself.","traditional":"他總是傍人門戶，自己從來不努力。"},{"simplified":"在职场上，不能总是傍人门户，要学会独立。","english":"In the workplace, you can't always rely on others; you need to learn to be independent.","traditional":"在職場上，不能總是傍人門戶，要學會獨立。"}],"synonyms":["依赖他人"],"antonyms":["自力更生"],"confusedWith":[{"id":"依赖他人","note":"While both mean relying on others, '傍人门户' suggests a lack of self-sufficiency and has a negative connotation."}],"traditional":"傍人門戶","pinyinOverride":null},{"id":"bang-da-yuan-yang","simplified":"棒打鸳鸯","literalMeaning":"beat the mandarin ducks with a stick","figurativeMeaning":"to forcibly separate a loving couple","englishEquivalents":["break up a couple","come between lovers"],"shortGloss":"forcibly separate lovers","characters":[{"char":"棒","meaning":"stick"},{"char":"打","meaning":"hit"},{"char":"鸳","meaning":"male mandarin duck"},{"char":"鸯","meaning":"female mandarin duck"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '棒打鸳鸯' refers to the act of forcibly separating a loving couple, much like using a stick to drive apart a pair of mandarin ducks, which are known for their strong pair bonds. The phrase is often used to describe situations where external forces, such as family or societal pressures, interfere with a romantic relationship.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["object","attributive"],"structure":"verb-object","register":"commonly used in both spoken and written Chinese","connotation":"negative","commonMistakes":"Learners might confuse this idiom with others that involve separation or conflict, but it specifically implies an external force breaking up a romantic relationship. It should not be used for separations due to mutual consent or internal conflicts.","canStandAlone":false},"examples":[{"simplified":"他们的父母不同意这段恋情，硬是棒打鸳鸯。","english":"Their parents disapproved of the relationship and forcibly separated the couple.","traditional":"他們的父母不同意這段戀情，硬是棒打鴛鴦。"},{"simplified":"在这个故事中，恶毒的皇后试图棒打鸳鸯。","english":"In this story, the wicked queen tries to break up the loving couple.","traditional":"在這個故事中，惡毒的皇后試圖棒打鴛鴦。"}],"synonyms":["拆散鸳鸯"],"antonyms":[],"confusedWith":[{"id":"拆散鸳鸯","note":"Both idioms mean to separate a couple, but 棒打鸳鸯 emphasizes the forceful nature of the separation."}],"traditional":"棒打鴛鴦","pinyinOverride":null},{"id":"bao-cang-huo-xin","simplified":"包藏祸心","literalMeaning":"harbor disaster heart","figurativeMeaning":"to harbor evil intentions","englishEquivalents":["to have a hidden agenda","to harbor ill will"],"shortGloss":"harbor evil intentions","characters":[{"char":"包","meaning":"to harbor"},{"char":"藏","meaning":"to conceal"},{"char":"祸","meaning":"disaster"},{"char":"心","meaning":"heart"}],"origin":{"period":"Han Dynasty (206 BCE – 220 CE)","sourceText":"《汉书·王莽传》","sourceTextEnglish":"Book of Han, Biography of Wang Mang","originalExcerpt":"包藏祸心，窥觊神器。","storyEnglish":"The idiom originates from the 'Book of Han', where it describes Wang Mang, a Han Dynasty official who was accused of harboring evil intentions and plotting to usurp the throne. The phrase was used to describe his concealed ambitions and treacherous plans.","historicalFigures":["Wang Mang"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"verb-object","register":"formal written Chinese, but understood in spoken language","connotation":"negative","commonMistakes":"Learners may confuse this idiom with expressions that simply mean 'to have a plan' without the negative connotation of malice or deceit. It's important to note the negative intent implied in this idiom.","canStandAlone":false},"examples":[{"simplified":"他看似友好，实际上包藏祸心。","english":"He seems friendly, but in reality, he harbors evil intentions.","traditional":"他看似友好，實際上包藏禍心。"},{"simplified":"这个人包藏祸心，我们要小心提防。","english":"This person harbors evil intentions, we must be cautious and vigilant.","traditional":"這個人包藏禍心，我們要小心提防。"}],"synonyms":["居心叵测"],"antonyms":["光明磊落"],"confusedWith":[{"id":"居心叵测","note":"Both imply hidden intentions, but 居心叵测 emphasizes unpredictability, while 包藏祸心 emphasizes malicious intent."}],"traditional":"包藏禍心","pinyinOverride":null},{"id":"bao-dao-bu-lao","simplified":"宝刀不老","literalMeaning":"treasured sword not old","figurativeMeaning":"a person who remains skillful and vigorous despite aging","englishEquivalents":["still going strong","not past one's prime"],"shortGloss":"still skillful despite age","characters":[{"char":"宝","meaning":"treasured"},{"char":"刀","meaning":"sword"},{"char":"不","meaning":"not"},{"char":"老","meaning":"old"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '宝刀不老' is often used to describe someone who, despite their age, still retains their skills and abilities. It likens a person's enduring capabilities to a treasured sword that remains sharp and effective over time. The exact origin of the phrase is not well-documented, but it is commonly used in modern Chinese to compliment older individuals who continue to excel in their fields.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"subject-predicate","register":"commonly used in both spoken and written Chinese","connotation":"positive","commonMistakes":"Learners might confuse this idiom with expressions that imply aging or decline. It's important to remember that '宝刀不老' specifically highlights continued strength and skill, not just age.","canStandAlone":false},"examples":[{"simplified":"虽然他已经退休多年，但在象棋比赛中，他依然宝刀不老。","english":"Even though he has been retired for many years, he is still going strong in chess competitions.","traditional":"雖然他已經退休多年，但在象棋比賽中，他依然寶刀不老。"},{"simplified":"这位老将军在战场上依然宝刀不老，指挥若定。","english":"The veteran general is still going strong on the battlefield, commanding with confidence.","traditional":"這位老將軍在戰場上依然寶刀不老，指揮若定。"}],"synonyms":["老当益壮"],"antonyms":["江郎才尽"],"confusedWith":[{"id":"老当益壮","note":"While both idioms praise the abilities of older individuals, '老当益壮' emphasizes growing stronger with age, whereas '宝刀不老' focuses on retaining one's original strength."}],"traditional":"寶刀不老","pinyinOverride":null},{"id":"bao-ma-xiang-che","simplified":"宝马香车","literalMeaning":"precious horse, fragrant carriage","figurativeMeaning":"luxurious and extravagant lifestyle","englishEquivalents":["living in the lap of luxury","high on the hog"],"shortGloss":"luxurious lifestyle","characters":[{"char":"宝","meaning":"precious"},{"char":"马","meaning":"horse"},{"char":"香","meaning":"fragrant"},{"char":"车","meaning":"carriage"}],"origin":{"period":"Tang dynasty (618–907 CE)","sourceText":"《李白诗选》","sourceTextEnglish":"Selected Poems of Li Bai","originalExcerpt":"宝马雕车香满路。","storyEnglish":"This idiom originates from a poem by the famous Tang dynasty poet Li Bai. In his poem, he describes a scene of opulence and grandeur, where precious horses and fragrant carriages fill the road, symbolizing a life of luxury and extravagance.","historicalFigures":["Li Bai"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["attributive","object"],"structure":"coordinate","register":"literary, but understood in modern contexts to describe wealth and luxury","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with others that involve horses or carriages, but it specifically refers to luxury and opulence, not just transportation.","canStandAlone":false},"examples":[{"simplified":"他过着宝马香车的生活，令人羡慕。","english":"He lives a life of luxury and extravagance, which makes others envious.","traditional":"他過著寶馬香車的生活，令人羨慕。"},{"simplified":"在这次宴会上，宾客们都乘坐着宝马香车。","english":"At this banquet, the guests all arrived in luxurious carriages.","traditional":"在這次宴會上，賓客們都乘坐著寶馬香車。"}],"synonyms":["锦衣玉食"],"antonyms":["粗茶淡饭"],"confusedWith":[{"id":"千里马","note":"千里马 refers to a talented or capable person, not luxury or wealth."}],"traditional":"寶馬香車","pinyinOverride":null},{"id":"bao-jing-feng-shuang","simplified":"饱经风霜","literalMeaning":"fully experienced wind and frost","figurativeMeaning":"to have experienced many hardships and difficulties in life","englishEquivalents":["weathered many storms","been through the mill"],"shortGloss":"experienced many hardships","characters":[{"char":"饱","meaning":"fully"},{"char":"经","meaning":"experienced"},{"char":"风","meaning":"wind"},{"char":"霜","meaning":"frost"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '饱经风霜' is used to describe someone who has gone through many trials and tribulations in life, akin to enduring harsh weather conditions like wind and frost. It conveys the idea of resilience and the wisdom gained from overcoming difficulties.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"verb-object","register":"commonly used in both written and spoken Chinese","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with those that describe physical endurance rather than life experiences. It specifically refers to enduring life's hardships, not just physical challenges.","canStandAlone":false},"examples":[{"simplified":"他是一个饱经风霜的老人，经历了许多困难。","english":"He is an old man who has weathered many storms and gone through numerous hardships.","traditional":"他是一個飽經風霜的老人，經歷了許多困難。"},{"simplified":"饱经风霜的她，总是能给年轻人提供宝贵的建议。","english":"Having experienced many hardships, she is always able to offer valuable advice to young people.","traditional":"飽經風霜的她，總是能給年輕人提供寶貴的建議。"}],"synonyms":["历经沧桑","饱经沧桑"],"antonyms":[],"confusedWith":[{"id":"历尽艰辛","note":"Both idioms describe experiencing hardships, but 历尽艰辛 emphasizes the difficulty and suffering endured, while 饱经风霜 suggests a broader range of life experiences."}],"traditional":"飽經風霜","pinyinOverride":null},{"id":"bao-shi-zhong-ri","simplified":"饱食终日","literalMeaning":"eat one's fill all day","figurativeMeaning":"to lead an idle life, doing nothing productive","englishEquivalents":["idle away one's time","live a life of ease","do nothing all day"],"shortGloss":"idle away one's time","characters":[{"char":"饱","meaning":"full, satisfied"},{"char":"食","meaning":"eat, food"},{"char":"终","meaning":"end, throughout"},{"char":"日","meaning":"day"}],"origin":{"period":"Warring States period (475–221 BCE)","sourceText":"《论语·阳货》","sourceTextEnglish":"Analects of Confucius, Yang Huo","originalExcerpt":"饱食终日，无所用心，难矣哉。","storyEnglish":"In the Analects of Confucius, Confucius criticizes those who spend their days eating and doing nothing productive. He emphasizes the importance of using one's time wisely and engaging in meaningful activities. This idiom is derived from his teachings on the value of diligence and purposeful living.","historicalFigures":["Confucius"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"literary, but understood in modern contexts to describe idleness","connotation":"negative","commonMistakes":"Learners might confuse this idiom with positive expressions about enjoying life, but it actually criticizes laziness and lack of productivity.","canStandAlone":false},"examples":[{"simplified":"他每天饱食终日，从不考虑未来。","english":"He idles away his time every day, never thinking about the future.","traditional":"他每天飽食終日，從不考慮未來。"},{"simplified":"饱食终日的人往往会错过许多机会。","english":"Those who idle away their time often miss many opportunities.","traditional":"飽食終日的人往往會錯過許多機會。"}],"synonyms":["游手好闲"],"antonyms":["勤奋工作"],"confusedWith":[{"id":"享乐主义","note":"While '享乐主义' refers to hedonism or the pursuit of pleasure, '饱食终日' criticizes idleness and lack of productivity."}],"traditional":"飽食終日","pinyinOverride":null},{"id":"bao-chou-xue-hen","simplified":"报仇雪恨","literalMeaning":"avenge revenge clear hatred","figurativeMeaning":"to avenge a wrong and wipe out a grudge","englishEquivalents":["settle the score","get even","take revenge"],"shortGloss":"avenge a wrong and clear a grudge","characters":[{"char":"报","meaning":"avenge"},{"char":"仇","meaning":"revenge"},{"char":"雪","meaning":"clear away"},{"char":"恨","meaning":"hatred"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '报仇雪恨' is used to describe the act of taking revenge to settle a deep-seated grudge or hatred. It conveys the idea of not only avenging a wrong but also clearing away the emotional burden of hatred. The phrase reflects the cultural importance placed on justice and personal honor in traditional Chinese society.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","object"],"structure":"verb-object + verb-object","register":"commonly used in both formal and informal contexts","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with ones that simply mean 'to take revenge' without the nuance of clearing a grudge. It's important to note the dual aspect of avenging and clearing hatred.","canStandAlone":false},"examples":[{"simplified":"他发誓要报仇雪恨，为父亲讨回公道。","english":"He vowed to avenge and clear the grudge, seeking justice for his father.","traditional":"他發誓要報仇雪恨，為父親討回公道。"},{"simplified":"经过多年努力，他终于报仇雪恨，心中释然。","english":"After years of effort, he finally avenged and cleared the grudge, feeling relieved.","traditional":"經過多年努力，他終於報仇雪恨，心中釋然。"}],"synonyms":["以牙还牙","复仇"],"antonyms":["宽宏大量"],"confusedWith":[{"id":"以牙还牙","note":"While both involve revenge, '以牙还牙' emphasizes retaliation in kind, not necessarily clearing a grudge."}],"traditional":"報仇雪恨","pinyinOverride":null},{"id":"bao-can-shou-que","simplified":"抱残守缺","literalMeaning":"embrace the old, guard the broken","figurativeMeaning":"to cling to outdated traditions or ideas, resisting change","englishEquivalents":["stick to old ways","resist change","cling to outdated ideas"],"shortGloss":"cling to outdated traditions","characters":[{"char":"抱","meaning":"embrace, hold"},{"char":"残","meaning":"remnants, leftovers"},{"char":"守","meaning":"guard, maintain"},{"char":"缺","meaning":"deficiencies, broken parts"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '抱残守缺' describes the behavior of people who stubbornly hold on to outdated or broken ideas and resist any form of change or innovation. It criticizes those who are unwilling to adapt to new circumstances and prefer to stick with what is familiar, even if it is no longer effective or relevant.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"verb-object","register":"literary, but can be used in formal speech and writing","connotation":"negative","commonMistakes":"Learners might confuse this idiom with others that involve preservation or protection, but '抱残守缺' specifically implies a negative judgment about resisting necessary change.","canStandAlone":false},"examples":[{"simplified":"在快速发展的时代，抱残守缺只会让我们落后。","english":"In a rapidly developing era, clinging to outdated traditions will only make us fall behind.","traditional":"在快速發展的時代，抱殘守缺只會讓我們落後。"},{"simplified":"他总是抱残守缺，不愿意接受新的观念。","english":"He always clings to outdated ideas and is unwilling to accept new concepts.","traditional":"他總是抱殘守缺，不願意接受新的觀念。"}],"synonyms":["因循守旧","墨守成规"],"antonyms":["推陈出新","与时俱进"],"confusedWith":[{"id":"墨守成规","note":"Both idioms describe resistance to change, but '墨守成规' emphasizes sticking to rules, while '抱残守缺' highlights clinging to outdated ideas."}],"traditional":"抱殘守缺","pinyinOverride":null},{"id":"bao-hen-zhong-tian","simplified":"抱恨终天","literalMeaning":"harbor regret until the end of one's days","figurativeMeaning":"to carry a deep regret or grievance to one's grave","englishEquivalents":["die with a grievance","carry regret to the grave"],"shortGloss":"carry regret to one's grave","characters":[{"char":"抱","meaning":"harbor, hold"},{"char":"恨","meaning":"regret, grievance"},{"char":"终","meaning":"end, until the end"},{"char":"天","meaning":"heaven, one's life"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '抱恨终天' describes the feeling of carrying a deep regret or grievance throughout one's life, until death. It reflects the idea that some regrets or grievances are so profound that they remain unresolved and continue to weigh on a person until their dying day.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","complement"],"structure":"verb-object","register":"commonly used in both written and spoken Chinese","connotation":"negative","commonMistakes":"Learners might confuse this idiom with others that express regret but do not imply carrying it until death. It specifically conveys a sense of unresolved regret lasting a lifetime.","canStandAlone":false},"examples":[{"simplified":"他因为年轻时的错误而抱恨终天。","english":"He carried the regret of his youthful mistakes to his grave.","traditional":"他因為年輕時的錯誤而抱恨終天。"},{"simplified":"如果不及时解决这个问题，他可能会抱恨终天。","english":"If this issue isn't resolved in time, he might carry the regret to his grave.","traditional":"如果不及時解決這個問題，他可能會抱恨終天。"}],"synonyms":["遗憾终生"],"antonyms":[],"confusedWith":[{"id":"遗憾终生","note":"While both express lasting regret, '遗憾终生' focuses more on lifelong regret without the implication of taking it to the grave."}],"traditional":"抱恨終天","pinyinOverride":null},{"id":"bao-tou-shu-cuan","simplified":"抱头鼠窜","literalMeaning":"cover head and flee like a rat","figurativeMeaning":"to flee in panic and disorder","englishEquivalents":["run for one's life","scatter like rats"],"shortGloss":"flee in panic","characters":[{"char":"抱","meaning":"cover"},{"char":"头","meaning":"head"},{"char":"鼠","meaning":"rat"},{"char":"窜","meaning":"flee"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '抱头鼠窜' describes a scene where someone is so panicked that they cover their head and run away like a rat trying to escape danger. This vivid imagery conveys a sense of chaos and fear, often used to describe a hasty retreat in the face of overwhelming threat or defeat.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"commonly used in both written and spoken Chinese to describe chaotic retreats","connotation":"negative","commonMistakes":"Learners might confuse this idiom with others that describe fleeing or retreating, but '抱头鼠窜' specifically emphasizes panic and disorder. It should not be used for orderly or strategic retreats.","canStandAlone":false},"examples":[{"simplified":"敌军遭到猛烈攻击，只好抱头鼠窜。","english":"The enemy troops were fiercely attacked and had to flee in panic.","traditional":"敵軍遭到猛烈攻擊，只好抱頭鼠竄。"},{"simplified":"小偷被发现后，抱头鼠窜地逃跑了。","english":"The thief, once discovered, fled in panic.","traditional":"小偷被發現後，抱頭鼠竄地逃跑了。"}],"synonyms":["狼狈而逃"],"antonyms":["镇定自若"],"confusedWith":[{"id":"狼狈而逃","note":"While both idioms describe fleeing, '抱头鼠窜' emphasizes panic and disorder, whereas '狼狈而逃' focuses on the awkwardness and embarrassment of the escape."}],"traditional":"抱頭鼠竄","pinyinOverride":null},{"id":"bao-xin-jiu-huo","simplified":"抱薪救火","literalMeaning":"embrace firewood to put out a fire","figurativeMeaning":"to take measures that worsen a problem; to make matters worse","englishEquivalents":["add fuel to the fire","make matters worse"],"shortGloss":"make matters worse","characters":[{"char":"抱","meaning":"embrace, hold"},{"char":"薪","meaning":"firewood"},{"char":"救","meaning":"rescue, save"},{"char":"火","meaning":"fire"}],"origin":{"period":"Warring States period (475–221 BCE)","sourceText":"《史记·魏公子列传》","sourceTextEnglish":"Records of the Grand Historian, Biography of Prince Wei","originalExcerpt":"抱薪救火，薪不尽，火不灭。","storyEnglish":"The idiom originates from the 'Records of the Grand Historian' by Sima Qian. In the story, a person is described as trying to put out a fire by adding firewood to it, which is obviously counterproductive. This metaphor is used to illustrate the folly of attempting to solve a problem with actions that only exacerbate it.","historicalFigures":["Sima Qian"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","object"],"structure":"verb-object","register":"literary, but very widely understood and used in ordinary speech","connotation":"negative","commonMistakes":"Learners often confuse this idiom with phrases that imply helping or solving a problem, but it specifically means making a situation worse. It should not be used when referring to effective solutions.","canStandAlone":false},"examples":[{"simplified":"他试图通过提高税收来解决经济问题，但这只是抱薪救火。","english":"He tried to solve the economic problem by raising taxes, but it was just making matters worse.","traditional":"他試圖通過提高稅收來解決經濟問題，但這只是抱薪救火。"},{"simplified":"在这种情况下，增加投资就像抱薪救火。","english":"In this situation, increasing investment is like adding fuel to the fire.","traditional":"在這種情況下，增加投資就像抱薪救火。"}],"synonyms":["火上浇油"],"antonyms":["釜底抽薪"],"confusedWith":[{"id":"火上浇油","note":"Both idioms involve worsening a situation, but 抱薪救火 emphasizes futile efforts, while 火上浇油 emphasizes intensifying a problem."}],"traditional":"抱薪救火","pinyinOverride":null},{"id":"bao-li-zi-sui","simplified":"暴戾恣睢","literalMeaning":"violent and unrestrained","figurativeMeaning":"brutal and tyrannical behavior","englishEquivalents":["tyrannical","brutal","savage"],"shortGloss":"brutal and tyrannical","characters":[{"char":"暴","meaning":"violent"},{"char":"戾","meaning":"cruel"},{"char":"恣","meaning":"unrestrained"},{"char":"睢","meaning":"arrogant"}],"origin":{"period":"Warring States period (475–221 BCE)","sourceText":"《左传·襄公二十六年》","sourceTextEnglish":"Zuo Zhuan, Duke Xiang, Year 26","originalExcerpt":"暴戾恣睢，民怨神怒。","storyEnglish":"The idiom originates from the historical text 'Zuo Zhuan', which is a commentary on the 'Spring and Autumn Annals'. In the 26th year of Duke Xiang, it describes a situation where the ruler's violent and unrestrained behavior led to the people's resentment and the gods' anger.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["attributive","predicate"],"structure":"coordinate","register":"formal written Chinese, often used in historical or literary contexts","connotation":"negative","commonMistakes":"Learners often confuse this idiom with more general terms for anger or violence, but it specifically implies a tyrannical and oppressive behavior. It is not used for everyday anger or aggression.","canStandAlone":false},"examples":[{"simplified":"他的统治被描述为暴戾恣睢，百姓苦不堪言。","english":"His rule was described as brutal and tyrannical, causing the people to suffer immensely.","traditional":"他的統治被描述為暴戾恣睢，百姓苦不堪言。"},{"simplified":"历史上有许多暴戾恣睢的君主，他们的统治往往以失败告终。","english":"History has seen many tyrannical rulers, and their reigns often ended in failure.","traditional":"歷史上有許多暴戾恣睢的君主，他們的統治往往以失敗告終。"}],"synonyms":["残暴不仁","凶神恶煞"],"antonyms":["仁慈宽厚"],"confusedWith":[{"id":"凶神恶煞","note":"While both imply brutality, 凶神恶煞 often refers to fierce and evil spirits or people, not necessarily rulers."}],"traditional":"暴戾恣睢","pinyinOverride":null},{"id":"bao-lu-wu-yi","simplified":"暴露无遗","literalMeaning":"expose without remainder","figurativeMeaning":"to be completely exposed; to reveal everything without any concealment","englishEquivalents":["leave nothing to the imagination","lay bare","expose everything"],"shortGloss":"completely exposed","characters":[{"char":"暴","meaning":"to expose"},{"char":"露","meaning":"to reveal"},{"char":"无","meaning":"without"},{"char":"遗","meaning":"remainder"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom 暴露无遗 is used to describe a situation where everything is revealed without anything being hidden. It is often used in contexts where secrets are uncovered or when something is laid bare for all to see.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"modifier-head","register":"commonly used in both written and spoken Chinese","connotation":"neutral","commonMistakes":"Learners might confuse 暴露无遗 with similar idioms that imply partial exposure. This idiom specifically means that nothing is left hidden.","canStandAlone":false},"examples":[{"simplified":"他的谎言被揭穿后，真相暴露无遗。","english":"After his lies were exposed, the truth was completely laid bare.","traditional":"他的謊言被揭穿後，真相暴露無遺。"},{"simplified":"在调查中，公司的财务问题暴露无遗。","english":"During the investigation, the company's financial problems were fully exposed.","traditional":"在調查中，公司的財務問題暴露無遺。"}],"synonyms":["一览无余","彻底揭露"],"antonyms":["隐瞒不报"],"confusedWith":[{"id":"一览无余","note":"一览无余 means everything can be seen at a glance, often used for physical visibility, while 暴露无遗 emphasizes the exposure of hidden truths."}],"traditional":"暴露無遺","pinyinOverride":null},{"id":"bao-nue-wu-dao","simplified":"暴虐无道","literalMeaning":"tyrannical and without principle","figurativeMeaning":"cruel and oppressive, lacking moral principles","englishEquivalents":["tyranny and lawlessness","despotic and unjust","brutal and immoral"],"shortGloss":"tyrannical and unjust","characters":[{"char":"暴","meaning":"violent, brutal"},{"char":"虐","meaning":"tyrannical, oppressive"},{"char":"无","meaning":"without, lacking"},{"char":"道","meaning":"principle, morality"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom 暴虐无道 is used to describe a ruler or government that is excessively cruel and lacks any moral or ethical principles. It is often used in historical contexts to criticize tyrannical leaders who oppress their people without regard for justice or righteousness.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"coordinate","register":"formal written Chinese, often used in historical or political contexts","connotation":"negative","commonMistakes":"Learners might confuse 暴虐无道 with similar idioms that describe general lawlessness or chaos, but this idiom specifically emphasizes the cruelty and moral corruption of a ruler or authority.","canStandAlone":false},"examples":[{"simplified":"那个国王以暴虐无道而闻名。","english":"That king was notorious for being tyrannical and unjust.","traditional":"那個國王以暴虐無道而聞名。"},{"simplified":"历史上有许多暴虐无道的统治者。","english":"History has seen many tyrannical and unjust rulers.","traditional":"歷史上有許多暴虐無道的統治者。"}],"synonyms":["残暴不仁","横征暴敛"],"antonyms":["仁政爱民"],"confusedWith":[{"id":"无法无天","note":"无法无天 refers to lawlessness and disorder in general, not specifically to the cruelty of a ruler."}],"traditional":"暴虐無道","pinyinOverride":null},{"id":"bao-tian-tian-wu","simplified":"暴殄天物","literalMeaning":"wastefully destroy heaven's creations","figurativeMeaning":"to recklessly waste natural resources or valuable things","englishEquivalents":["waste not, want not","don't kill the goose that lays the golden eggs"],"shortGloss":"recklessly waste resources","characters":[{"char":"暴","meaning":"recklessly"},{"char":"殄","meaning":"destroy"},{"char":"天","meaning":"heaven's"},{"char":"物","meaning":"creations; resources"}],"origin":{"period":"Warring States period (475–221 BCE)","sourceText":"《尚书·武成》","sourceTextEnglish":"Book of Documents, Chapter 'Wu Cheng'","originalExcerpt":"今商王受无道，暴殄天物，害虐烝民。","storyEnglish":"The idiom originates from the 'Book of Documents', where it criticizes the last king of the Shang dynasty, King Zhou, for his tyrannical rule and reckless waste of resources. The text describes how King Zhou's actions led to the suffering of his people and the destruction of valuable resources, ultimately contributing to the downfall of his dynasty.","historicalFigures":["King Zhou of Shang"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"verb-object","register":"literary, but widely understood and used in both formal and informal contexts","connotation":"negative","commonMistakes":"Learners might confuse this idiom with expressions that simply mean 'to waste' without the connotation of recklessness or destruction. It's important to note the severity implied by '暴殄天物'.","canStandAlone":false},"examples":[{"simplified":"他每天浪费食物，真是暴殄天物。","english":"He wastes food every day; it's truly a reckless waste of resources.","traditional":"他每天浪費食物，真是暴殄天物。"},{"simplified":"在这个资源匮乏的时代，我们不能暴殄天物。","english":"In this era of scarce resources, we cannot afford to recklessly waste them.","traditional":"在這個資源匱乏的時代，我們不能暴殄天物。"}],"synonyms":["挥霍无度","奢侈浪费"],"antonyms":["节衣缩食","精打细算"],"confusedWith":[{"id":"浪费","note":"While '浪费' means to waste, it lacks the connotation of recklessness and destruction inherent in '暴殄天物'."}],"traditional":"暴殄天物","pinyinOverride":null},{"id":"bao-tiao-ru-lei","simplified":"暴跳如雷","literalMeaning":"jump violently like thunder","figurativeMeaning":"to be extremely angry; to fly into a rage","englishEquivalents":["hit the roof","fly off the handle"],"shortGloss":"extremely angry","characters":[{"char":"暴","meaning":"violently"},{"char":"跳","meaning":"jump"},{"char":"如","meaning":"like; as if"},{"char":"雷","meaning":"thunder"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom 暴跳如雷 describes someone who is so angry that they jump around violently, as if they were thunder. This vivid imagery captures the intensity of the person's rage, likening it to the sudden and powerful nature of a thunderstorm.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"modifier-head","register":"commonly used in both written and spoken Chinese","connotation":"negative","commonMistakes":"Learners might confuse 暴跳如雷 with similar expressions of anger, but this idiom specifically emphasizes the physical manifestation of anger, like jumping or stomping. It is not used for mild irritation.","canStandAlone":false},"examples":[{"simplified":"听到这个消息，他气得暴跳如雷。","english":"Upon hearing the news, he flew into a rage.","traditional":"聽到這個消息，他氣得暴跳如雷。"},{"simplified":"她总是因为小事而暴跳如雷。","english":"She always flies off the handle over trivial matters.","traditional":"她總是因為小事而暴跳如雷。"}],"synonyms":["怒火中烧","大发雷霆"],"antonyms":["心平气和"],"confusedWith":[{"id":"大发雷霆","note":"Both describe extreme anger, but 暴跳如雷 emphasizes physical actions like jumping, while 大发雷霆 focuses on the loudness and intensity of the anger."}],"traditional":"暴跳如雷","pinyinOverride":null},{"id":"bei-bi-wo-chuo","simplified":"卑鄙龌龊","literalMeaning":"base and filthy","figurativeMeaning":"despicable and morally repugnant","englishEquivalents":["vile and contemptible","low and dirty"],"shortGloss":"despicable and morally repugnant","characters":[{"char":"卑","meaning":"base, low"},{"char":"鄙","meaning":"vile, contemptible"},{"char":"龌","meaning":"filthy, dirty"},{"char":"龊","meaning":"squalid, mean"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '卑鄙龌龊' is used to describe someone or something that is morally repugnant and despicable. It conveys a strong sense of contempt and disdain for actions or behavior that are considered base and filthy. The exact origin of this idiom is unclear, but it has been used in Chinese literature and speech to criticize unethical or dishonorable conduct.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"coordinate","register":"used in both formal and informal contexts to express strong disapproval","connotation":"negative","commonMistakes":"Learners might confuse this idiom with others that describe negative traits, but '卑鄙龌龊' specifically emphasizes moral repugnance and despicability. It should not be used lightly, as it conveys strong condemnation.","canStandAlone":false},"examples":[{"simplified":"他的行为真是卑鄙龌龊，令人不齿。","english":"His actions are truly despicable and morally repugnant, making him contemptible.","traditional":"他的行為真是卑鄙齷齪，令人不齒。"},{"simplified":"在商业竞争中使用卑鄙龌龊的手段是不可接受的。","english":"Using despicable and morally repugnant tactics in business competition is unacceptable.","traditional":"在商業競爭中使用卑鄙齷齪的手段是不可接受的。"}],"synonyms":["卑鄙无耻","无耻下流"],"antonyms":["光明磊落"],"confusedWith":[{"id":"卑鄙无耻","note":"While both idioms describe contemptible behavior, '卑鄙无耻' focuses more on shamelessness."}],"traditional":"卑鄙齷齪","pinyinOverride":null},{"id":"bei-gong-qu-xi","simplified":"卑躬屈膝","literalMeaning":"low bow bent knee","figurativeMeaning":"to act in a servile or obsequious manner","englishEquivalents":["to kowtow","to grovel"],"shortGloss":"to act servilely or obsequiously","characters":[{"char":"卑","meaning":"lowly, humble"},{"char":"躬","meaning":"to bow"},{"char":"屈","meaning":"to bend"},{"char":"膝","meaning":"knee"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '卑躬屈膝' describes a person who is excessively humble and submissive, often to the point of losing self-respect. The phrase paints a vivid image of someone bowing low and bending their knees, symbolizing a complete lack of dignity in their eagerness to please or appease others.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"coordinate","register":"commonly used in both written and spoken Chinese to describe servile behavior","connotation":"negative","commonMistakes":"Learners might confuse this idiom with expressions that simply mean 'to be polite' or 'to show respect'. However, '卑躬屈膝' implies a loss of dignity and self-respect, not just politeness.","canStandAlone":false},"examples":[{"simplified":"他在老板面前总是卑躬屈膝，毫无自尊。","english":"He always acts obsequiously in front of the boss, with no self-respect.","traditional":"他在老闆面前總是卑躬屈膝，毫無自尊。"},{"simplified":"为了得到那份工作，他不得不卑躬屈膝。","english":"In order to get that job, he had to grovel.","traditional":"為了得到那份工作，他不得不卑躬屈膝。"}],"synonyms":["奴颜婢膝"],"antonyms":["顶天立地"],"confusedWith":[{"id":"点头哈腰","note":"While both idioms describe submissive behavior, '点头哈腰' is more about showing excessive politeness, whereas '卑躬屈膝' implies a loss of dignity."}],"traditional":"卑躬屈膝","pinyinOverride":null},{"id":"bei-pan-lang-ji","simplified":"杯盘狼藉","literalMeaning":"cups and plates in disarray","figurativeMeaning":"a scene of disorder and mess, often after a meal or event","englishEquivalents":["a complete mess","in shambles"],"shortGloss":"a scene of disorder","characters":[{"char":"杯","meaning":"cup"},{"char":"盘","meaning":"plate"},{"char":"狼","meaning":"wolf; here, chaotic or messy"},{"char":"藉","meaning":"disorderly; in disarray"}],"origin":{"period":"Eastern Han Dynasty (25–220 CE)","sourceText":"《后汉书·杜密传》","sourceTextEnglish":"Book of the Later Han, Biography of Du Mi","originalExcerpt":"杯盘狼藉，酒肉臭败。","storyEnglish":"The idiom originates from a passage in the 'Book of the Later Han', where it describes a scene after a feast, with cups and plates scattered in disarray and the smell of spoiled food and drink. It vividly depicts the aftermath of a banquet where everything is left in a chaotic state.","historicalFigures":["Du Mi"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"modifier-head","register":"commonly used in both written and spoken Chinese to describe messy situations","connotation":"negative","commonMistakes":"Learners might mistakenly use this idiom to describe personal disarray or chaos in non-physical contexts, but it specifically refers to physical messes, often after meals or events.","canStandAlone":false},"examples":[{"simplified":"宴会结束后，房间里杯盘狼藉，让人无从下手清理。","english":"After the banquet ended, the room was a complete mess, making it hard to start cleaning.","traditional":"宴會結束後，房間裡杯盤狼藉，讓人無從下手清理。"},{"simplified":"他看到厨房杯盘狼藉，立刻开始收拾。","english":"He saw the kitchen in disarray and immediately started tidying up.","traditional":"他看到廚房杯盤狼藉，立刻開始收拾。"}],"synonyms":["狼藉不堪"],"antonyms":["井井有条"],"confusedWith":[{"id":"狼狈不堪","note":"狼狈不堪 refers to being in a difficult or embarrassing situation, not physical mess."}],"traditional":"杯盤狼藉","pinyinOverride":null},{"id":"bei-bu-zi-sheng","simplified":"悲不自胜","literalMeaning":"sorrow cannot self overcome","figurativeMeaning":"overwhelmed with sorrow","englishEquivalents":["overcome with grief","heartbroken"],"shortGloss":"overwhelmed with sorrow","characters":[{"char":"悲","meaning":"sorrow"},{"char":"不","meaning":"cannot"},{"char":"自","meaning":"oneself"},{"char":"胜","meaning":"overcome"}],"origin":{"period":"Eastern Jin Dynasty (317–420)","sourceText":"《世说新语·言语》","sourceTextEnglish":"A New Account of the Tales of the World, Section on Speech","originalExcerpt":"桓温闻之，悲不自胜。","storyEnglish":"The idiom originates from a story in 'A New Account of the Tales of the World'. When Huan Wen, a prominent general and statesman of the Eastern Jin Dynasty, heard of the death of a close friend, he was so overwhelmed with grief that he could not contain his sorrow.","historicalFigures":["Huan Wen"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","complement"],"structure":"subject-predicate","register":"literary, but understood and occasionally used in formal speech","connotation":"negative","commonMistakes":"Learners may confuse this idiom with similar expressions of sorrow, but it specifically implies being overwhelmed by grief to the point of losing self-control.","canStandAlone":false},"examples":[{"simplified":"听到这个消息后，他悲不自胜，泪流满面。","english":"Upon hearing the news, he was overwhelmed with sorrow and tears streamed down his face.","traditional":"聽到這個消息後，他悲不自勝，淚流滿面。"},{"simplified":"她对父亲的去世感到悲不自胜，久久不能平复。","english":"She was overwhelmed with grief over her father's death and could not calm down for a long time.","traditional":"她對父親的去世感到悲不自勝，久久不能平復。"}],"synonyms":["痛不欲生","心如刀割"],"antonyms":[],"confusedWith":[{"id":"痛不欲生","note":"痛不欲生 implies a desire to die from pain, while 悲不自胜 focuses on being overwhelmed by sorrow."}],"traditional":"悲不自勝","pinyinOverride":null},{"id":"bei-tian-min-ren","simplified":"悲天悯人","literalMeaning":"lament heaven, pity people","figurativeMeaning":"to bemoan the state of the universe and pity the fate of mankind; to feel deep compassion for the world","englishEquivalents":["to have a heart full of compassion","to lament the state of the world"],"shortGloss":"deep compassion for the world","characters":[{"char":"悲","meaning":"lament"},{"char":"天","meaning":"heaven"},{"char":"悯","meaning":"pity"},{"char":"人","meaning":"people"}],"origin":{"period":"Northern and Southern Dynasties (420–589 CE)","sourceText":"《南史·陈纪下》","sourceTextEnglish":"History of the Southern Dynasties, Annals of Chen","originalExcerpt":"悲天悯人，怀抱不平。","storyEnglish":"The phrase '悲天悯人' comes from the 'History of the Southern Dynasties', where it describes a person who is deeply moved by the suffering and injustices of the world. This person laments the state of the universe and feels compassion for the plight of humanity, embodying a profound empathy and concern for others.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"coordinate","register":"literary, but widely understood and used in both formal and informal contexts","connotation":"positive","commonMistakes":"Learners often confuse this idiom with more general expressions of sadness or pity. It specifically conveys a broader, more philosophical compassion for humanity and the world, not just individual sorrow.","canStandAlone":false},"examples":[{"simplified":"他总是悲天悯人，关心社会上的弱势群体。","english":"He always shows deep compassion for the world, caring about the disadvantaged groups in society.","traditional":"他總是悲天憫人，關心社會上的弱勢群體。"},{"simplified":"她有一种悲天悯人的情怀，总是为他人的不幸而感到难过。","english":"She has a heart full of compassion, always feeling sad for the misfortunes of others.","traditional":"她有一種悲天憫人的情懷，總是為他人的不幸而感到難過。"}],"synonyms":["慈悲为怀","仁者爱人"],"antonyms":[],"confusedWith":[{"id":"同情心","note":"悲天悯人 implies a broader, philosophical compassion, while 同情心 refers to sympathy or empathy on a more personal level."}],"traditional":"悲天憫人","pinyinOverride":null},{"id":"bei-xi-jiao-ji","simplified":"悲喜交集","literalMeaning":"sorrow and joy intermingled","figurativeMeaning":"to experience mixed emotions; to feel both happy and sad at the same time","englishEquivalents":["bittersweet","mixed emotions"],"shortGloss":"mixed emotions","characters":[{"char":"悲","meaning":"sorrow"},{"char":"喜","meaning":"joy"},{"char":"交","meaning":"intermingle"},{"char":"集","meaning":"gather"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '悲喜交集' describes a situation where a person experiences both happiness and sadness simultaneously. This can occur in various life situations, such as when a person achieves a long-sought goal but also faces a personal loss. The idiom captures the complexity of human emotions, acknowledging that feelings are not always straightforward.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"coordinate","register":"widely used in both written and spoken Chinese","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with '喜怒哀乐' which refers to a broader range of emotions. '悲喜交集' specifically emphasizes the simultaneous experience of happiness and sadness.","canStandAlone":false},"examples":[{"simplified":"听到这个消息，他心中悲喜交集。","english":"Upon hearing the news, he felt a mix of happiness and sadness.","traditional":"聽到這個消息，他心中悲喜交集。"},{"simplified":"毕业典礼上，学生们悲喜交集，既高兴又不舍。","english":"At the graduation ceremony, the students felt mixed emotions, both happy and reluctant to leave.","traditional":"畢業典禮上，學生們悲喜交集，既高興又不捨。"}],"synonyms":["五味杂陈"],"antonyms":[],"confusedWith":[{"id":"喜怒哀乐","note":"While '喜怒哀乐' refers to a full range of emotions, '悲喜交集' specifically focuses on the simultaneous experience of joy and sorrow."}],"traditional":"悲喜交集","pinyinOverride":null},{"id":"bei-chang-jian-ku","simplified":"备尝艰苦","literalMeaning":"fully experience hardships","figurativeMeaning":"to endure many hardships or difficulties","englishEquivalents":["go through trials and tribulations","endure hardships","weather the storm"],"shortGloss":"endure many hardships","characters":[{"char":"备","meaning":"fully, completely"},{"char":"尝","meaning":"experience, taste"},{"char":"艰","meaning":"difficult, hardship"},{"char":"苦","meaning":"bitter, suffering"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '备尝艰苦' describes the experience of enduring numerous hardships or difficulties. It conveys the idea of someone who has faced and overcome significant challenges, often used to highlight perseverance and resilience.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"commonly used in both written and spoken Chinese to describe enduring hardships","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with others that describe hardship but do not emphasize the aspect of enduring or experiencing them fully. It's important to use it when highlighting the extent of the hardships faced.","canStandAlone":false},"examples":[{"simplified":"他在创业过程中备尝艰苦，但从未放弃。","english":"He endured many hardships during the startup process but never gave up.","traditional":"他在創業過程中備嘗艱苦，但從未放棄。"},{"simplified":"经过多年备尝艰苦，他们终于成功了。","english":"After many years of enduring hardships, they finally succeeded.","traditional":"經過多年備嘗艱苦，他們終於成功了。"}],"synonyms":["历尽艰辛","饱经风霜"],"antonyms":[],"confusedWith":[{"id":"历尽艰辛","note":"Both idioms describe enduring hardships, but '历尽艰辛' emphasizes the process of going through them, while '备尝艰苦' emphasizes the extent of the hardships experienced."}],"traditional":"備嘗艱苦","pinyinOverride":null},{"id":"bei-chang-xin-ku","simplified":"备尝辛苦","literalMeaning":"fully experience hardships","figurativeMeaning":"to endure many hardships or to go through a lot of difficulties","englishEquivalents":["go through the mill","bear the brunt","weather the storm"],"shortGloss":"endure many hardships","characters":[{"char":"备","meaning":"fully"},{"char":"尝","meaning":"experience"},{"char":"辛","meaning":"hard"},{"char":"苦","meaning":"suffering"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '备尝辛苦' is used to describe someone who has gone through significant difficulties or hardships. It emphasizes the comprehensive nature of the hardships experienced, suggesting that the person has faced and endured a wide range of challenges.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"commonly used in both written and spoken Chinese","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with similar expressions that imply hardship but do not emphasize the comprehensive nature of the experience. It's important to use it when referring to enduring a wide range of difficulties.","canStandAlone":false},"examples":[{"simplified":"他在创业的过程中备尝辛苦，最终取得了成功。","english":"He endured many hardships during the process of starting his business and eventually succeeded.","traditional":"他在創業的過程中備嘗辛苦，最終取得了成功。"},{"simplified":"为了实现梦想，她备尝辛苦，从未放弃。","english":"To achieve her dreams, she endured many hardships and never gave up.","traditional":"為了實現夢想，她備嘗辛苦，從未放棄。"}],"synonyms":["历尽艰辛","饱经风霜"],"antonyms":[],"confusedWith":[{"id":"历尽艰辛","note":"Both idioms describe enduring hardships, but '历尽艰辛' emphasizes the process of going through specific difficulties, while '备尝辛苦' highlights the comprehensive nature of the hardships."}],"traditional":"備嘗辛苦","pinyinOverride":null},{"id":"bei-er-bu-yong","simplified":"备而不用","literalMeaning":"prepare but not use","figurativeMeaning":"to be prepared for something but not use it unless necessary","englishEquivalents":["better safe than sorry","be prepared"],"shortGloss":"prepared but not used","characters":[{"char":"备","meaning":"prepare"},{"char":"而","meaning":"but"},{"char":"不","meaning":"not"},{"char":"用","meaning":"use"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '备而不用' emphasizes the importance of being prepared for any situation, even if the preparations are never actually needed. It reflects a mindset of caution and readiness, ensuring that one is equipped to handle unexpected events or emergencies.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"widely used in both formal and informal contexts","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with '未雨绸缪', which also involves preparation but specifically refers to taking precautions before problems arise. '备而不用' emphasizes having preparations ready, even if they are not immediately needed.","canStandAlone":false},"examples":[{"simplified":"我们应该备而不用，以防万一。","english":"We should be prepared but not use it, just in case.","traditional":"我們應該備而不用，以防萬一。"},{"simplified":"虽然这次没有用上，但备而不用总是好的。","english":"Although we didn't use it this time, it's always good to be prepared but not use it.","traditional":"雖然這次沒有用上，但備而不用總是好的。"}],"synonyms":["未雨绸缪"],"antonyms":[],"confusedWith":[{"id":"未雨绸缪","note":"While both involve preparation, '未雨绸缪' focuses on taking precautions before problems arise, whereas '备而不用' emphasizes having preparations ready even if not used."}],"traditional":"備而不用","pinyinOverride":null},{"id":"bei-dao-er-chi","simplified":"背道而驰","literalMeaning":"go against the road and gallop","figurativeMeaning":"to run counter to; to go in the opposite direction","englishEquivalents":["go against the grain","run counter to","go in the opposite direction"],"shortGloss":"run counter to","characters":[{"char":"背","meaning":"go against"},{"char":"道","meaning":"road; path"},{"char":"而","meaning":"and; yet"},{"char":"驰","meaning":"gallop"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '背道而驰' describes a situation where two parties or ideas are moving in completely opposite directions, metaphorically or literally. It is often used to highlight a contradiction or a fundamental disagreement between two approaches or viewpoints.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"widely used in both formal and informal contexts","connotation":"negative","commonMistakes":"Learners sometimes confuse this idiom with similar expressions that suggest mere difference rather than direct opposition. It specifically implies going in opposite directions, not just diverging paths.","canStandAlone":false},"examples":[{"simplified":"他们的计划和我们的目标背道而驰。","english":"Their plan runs counter to our goals.","traditional":"他們的計劃和我們的目標背道而馳。"},{"simplified":"如果继续这样做，你的行动将与公司的政策背道而驰。","english":"If you continue like this, your actions will go against the company's policies.","traditional":"如果繼續這樣做，你的行動將與公司的政策背道而馳。"}],"synonyms":["南辕北辙"],"antonyms":[],"confusedWith":[{"id":"南辕北辙","note":"Both idioms suggest opposite directions, but 南辕北辙 emphasizes the futility of actions due to contradictory intentions."}],"traditional":"背道而馳","pinyinOverride":null},{"id":"bei-jing-li-xiang","simplified":"背井离乡","literalMeaning":"leave one's well and depart from one's village","figurativeMeaning":"to leave one's hometown; to be far away from home","englishEquivalents":["leave one's hometown","far from home"],"shortGloss":"to leave one's hometown","characters":[{"char":"背","meaning":"to leave"},{"char":"井","meaning":"well (as in water well)"},{"char":"离","meaning":"to depart"},{"char":"乡","meaning":"hometown"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '背井离乡' describes the experience of leaving one's hometown, often for work or other obligations. The imagery of leaving behind the village well and departing from one's familiar surroundings evokes a sense of nostalgia and the challenges of being away from home.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["object","adverbial"],"structure":"verb-object","register":"commonly used in both written and spoken Chinese","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with others that involve travel or departure, but it specifically emphasizes the emotional aspect of leaving one's hometown.","canStandAlone":false},"examples":[{"simplified":"他为了工作不得不背井离乡。","english":"He had to leave his hometown for work.","traditional":"他為了工作不得不背井離鄉。"},{"simplified":"背井离乡多年，他对故乡的思念越来越深。","english":"Having been away from home for many years, his longing for his hometown grew stronger.","traditional":"背井離鄉多年，他對故鄉的思念越來越深。"}],"synonyms":["离乡背井"],"antonyms":[],"confusedWith":[{"id":"离乡背井","note":"This is essentially the same idiom with the characters in a different order, meaning the same thing."}],"traditional":"背井離鄉","pinyinOverride":null},{"id":"bei-shui-yi-zhan","simplified":"背水一战","literalMeaning":"back to the water, one battle","figurativeMeaning":"to fight with one's back to the wall; to fight a battle with no way to retreat","englishEquivalents":["fight with one's back to the wall","burn one's bridges"],"shortGloss":"fight with no retreat","characters":[{"char":"背","meaning":"back"},{"char":"水","meaning":"water"},{"char":"一","meaning":"one"},{"char":"战","meaning":"battle"}],"origin":{"period":"Han dynasty (206 BCE–220 CE)","sourceText":"《史记·淮阴侯列传》","sourceTextEnglish":"Records of the Grand Historian, Biography of Marquis of Huaiyin","originalExcerpt":"信乃使万人先行，出，背水陈。赵军望见而大笑。","storyEnglish":"The idiom originates from a story about Han Xin, a famous general during the Han dynasty. In a battle against the Zhao army, Han Xin ordered his troops to set up camp with their backs to a river. This seemingly reckless move left them no option but to fight to the death, which motivated them to fight fiercely and ultimately win the battle. The Zhao army underestimated Han Xin's strategy, thinking it was foolish, but it turned out to be a brilliant tactic.","historicalFigures":["Han Xin"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["adverbial","complement"],"structure":"verb-object","register":"literary, but very widely understood and used in ordinary speech","connotation":"neutral","commonMistakes":"Learners sometimes confuse this idiom with '破釜沉舟', which also implies a desperate fight but emphasizes destroying one's means of retreat. '背水一战' specifically refers to having no retreat due to the physical setting.","canStandAlone":false},"examples":[{"simplified":"在这次比赛中，我们必须背水一战，全力以赴。","english":"In this match, we must fight with our backs to the wall and give it our all.","traditional":"在這次比賽中，我們必須背水一戰，全力以赴。"},{"simplified":"他决定背水一战，把所有的积蓄都投入到新公司中。","english":"He decided to burn his bridges and invest all his savings into the new company.","traditional":"他決定背水一戰，把所有的積蓄都投入到新公司中。"}],"synonyms":["破釜沉舟"],"antonyms":[],"confusedWith":[{"id":"破釜沉舟","note":"While both idioms imply a desperate fight, '破釜沉舟' emphasizes destroying one's means of retreat, whereas '背水一战' refers to having no retreat due to the physical setting."}],"traditional":"背水一戰","pinyinOverride":null},{"id":"bei-xin-qi-yi","simplified":"背信弃义","literalMeaning":"betray trust, abandon righteousness","figurativeMeaning":"to betray trust and abandon moral principles","englishEquivalents":["betray trust","act in bad faith","break faith"],"shortGloss":"betray trust and principles","characters":[{"char":"背","meaning":"betray"},{"char":"信","meaning":"trust"},{"char":"弃","meaning":"abandon"},{"char":"义","meaning":"righteousness"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom 背信弃义 describes someone who betrays trust and abandons moral principles. It is often used to criticize someone who acts in a deceitful or untrustworthy manner, especially when they have broken promises or failed to uphold ethical standards.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"coordinate","register":"widely used in both formal and informal contexts","connotation":"negative","commonMistakes":"Learners often confuse 背信弃义 with 见利忘义, which means 'to forget righteousness in the pursuit of profit'. While both involve abandoning principles, 背信弃义 specifically emphasizes betrayal of trust.","canStandAlone":false},"examples":[{"simplified":"他为了钱背信弃义，抛弃了多年的朋友。","english":"He betrayed trust for money and abandoned his friends of many years.","traditional":"他為了錢背信棄義，拋棄了多年的朋友。"},{"simplified":"这种背信弃义的行为让人无法再相信他。","english":"Such a betrayal of trust makes it impossible for people to trust him again.","traditional":"這種背信棄義的行為讓人無法再相信他。"}],"synonyms":["背信忘义","见利忘义"],"antonyms":["信守承诺","忠诚不渝"],"confusedWith":[{"id":"见利忘义","note":"见利忘义 focuses on abandoning principles for profit, while 背信弃义 emphasizes betrayal of trust."}],"traditional":"背信棄義","pinyinOverride":null},{"id":"ben-zou-xiang-gao","simplified":"奔走相告","literalMeaning":"run around mutually inform","figurativeMeaning":"to spread news quickly; to run around telling everyone","englishEquivalents":["spread the word","pass the news","shout it from the rooftops"],"shortGloss":"spread news quickly","characters":[{"char":"奔","meaning":"run"},{"char":"走","meaning":"walk; move"},{"char":"相","meaning":"mutually"},{"char":"告","meaning":"inform; tell"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '奔走相告' describes the action of people running around to inform others of important news or events. It conveys the urgency and excitement with which news is spread among a community. The phrase captures the image of people eagerly sharing information with one another.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"commonly used in both written and spoken Chinese","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with expressions that imply secrecy or slow communication. It specifically refers to the rapid and open spreading of news.","canStandAlone":false},"examples":[{"simplified":"消息传来后，村民们奔走相告。","english":"After the news arrived, the villagers spread it quickly among themselves.","traditional":"消息傳來後，村民們奔走相告。"},{"simplified":"他一知道这个好消息，就奔走相告。","english":"As soon as he heard the good news, he ran around telling everyone.","traditional":"他一知道這個好消息，就奔走相告。"}],"synonyms":["广而告之"],"antonyms":["秘而不宣"],"confusedWith":[{"id":"秘而不宣","note":"While '奔走相告' means to spread news quickly, '秘而不宣' means to keep something secret and not announce it."}],"traditional":"奔走相告","pinyinOverride":null},{"id":"ben-lai-mian-mu","simplified":"本来面目","literalMeaning":"original face","figurativeMeaning":"true nature; original appearance","englishEquivalents":["true colors","real self"],"shortGloss":"true nature","characters":[{"char":"本","meaning":"original"},{"char":"来","meaning":"come"},{"char":"面","meaning":"face"},{"char":"目","meaning":"appearance"}],"origin":{"period":"Tang dynasty (618–907)","sourceText":"《景德传灯录》","sourceTextEnglish":"Jingde Record of the Transmission of the Lamp","originalExcerpt":"云：“不识本来面目。”","storyEnglish":"The phrase '本来面目' comes from a Zen Buddhist story recorded in the 'Jingde Record of the Transmission of the Lamp.' In the story, a monk asks a Zen master, 'What is my original face before my parents were born?' This question is meant to provoke deep introspection about one's true nature beyond superficial identities.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["subject","object","attributive"],"structure":"modifier-head","register":"literary, but commonly used in both written and spoken Chinese","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with phrases that mean 'appearance' in a superficial sense. However, 本来面目 refers to the deeper, true nature of something or someone.","canStandAlone":false},"examples":[{"simplified":"经过调查，事情的本来面目终于被揭露出来。","english":"After the investigation, the true nature of the matter was finally revealed.","traditional":"經過調查，事情的本來面目終於被揭露出來。"},{"simplified":"他在朋友面前总是表现出他的本来面目。","english":"He always shows his true self in front of his friends.","traditional":"他在朋友面前總是表現出他的本來面目。"}],"synonyms":["真相大白"],"antonyms":["掩人耳目"],"confusedWith":[{"id":"面目全非","note":"面目全非 means 'completely changed beyond recognition,' which is different from revealing one's true nature."}],"traditional":"本來面目","pinyinOverride":null},{"id":"ben-mo-dao-zhi","simplified":"本末倒置","literalMeaning":"root and branch inverted","figurativeMeaning":"to confuse the primary with the secondary; to put the cart before the horse","englishEquivalents":["put the cart before the horse","miss the forest for the trees"],"shortGloss":"confuse primary with secondary","characters":[{"char":"本","meaning":"root; origin; primary"},{"char":"末","meaning":"end; tip; secondary"},{"char":"倒","meaning":"invert; reverse"},{"char":"置","meaning":"place; set"}],"origin":{"period":"Han Dynasty (206 BCE – 220 CE)","sourceText":"《汉书·食货志》","sourceTextEnglish":"Book of Han, Treatise on Food and Money","originalExcerpt":"治国者，务在本末而不在末本，今本末倒置，故民不安。","storyEnglish":"The idiom originates from the 'Book of Han', where it was used to criticize those who focus on trivial matters while neglecting the essential ones. The text emphasizes the importance of prioritizing the fundamental aspects of governance over minor details, warning that reversing these priorities leads to unrest among the people.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"commonly used in both formal and informal contexts","connotation":"negative","commonMistakes":"Learners often confuse this idiom with similar expressions that emphasize disorder, but 本末倒置 specifically refers to misplacing priorities, not general chaos.","canStandAlone":false},"examples":[{"simplified":"在这个项目中，我们不能本末倒置，应该先解决最重要的问题。","english":"In this project, we shouldn't confuse the primary with the secondary; we should address the most important issues first.","traditional":"在這個項目中，我們不能本末倒置，應該先解決最重要的問題。"},{"simplified":"他总是本末倒置，花太多时间在细节上，而忽略了整体目标。","english":"He always puts the cart before the horse, spending too much time on details while neglecting the overall goals.","traditional":"他總是本末倒置，花太多時間在細節上，而忽略了整體目標。"}],"synonyms":["舍本逐末"],"antonyms":[],"confusedWith":[{"id":"舍本逐末","note":"While both idioms involve misplaced priorities, 舍本逐末 emphasizes abandoning the essential for the trivial, whereas 本末倒置 highlights reversing the order of importance."}],"traditional":"本末倒置","pinyinOverride":null},{"id":"ben-xiao-li-wei","simplified":"本小利微","literalMeaning":"capital small, profit slight","figurativeMeaning":"small capital and slight profit; a business with small scale and low profit margins","englishEquivalents":["small-scale business","low-margin business"],"shortGloss":"small-scale, low-profit business","characters":[{"char":"本","meaning":"capital"},{"char":"小","meaning":"small"},{"char":"利","meaning":"profit"},{"char":"微","meaning":"slight"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '本小利微' is used to describe a business or venture that operates on a small scale with limited capital and generates only modest profits. It highlights the challenges of running a small business where resources are limited and profit margins are thin.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"modifier-head","register":"common in both spoken and written Chinese, particularly in business contexts","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with those that imply a lack of ambition or effort, but it specifically refers to the scale and profit of a business, not the owner's intentions.","canStandAlone":false},"examples":[{"simplified":"这家店本小利微，但老板很努力。","english":"This shop has small capital and slight profit, but the owner works very hard.","traditional":"這家店本小利微，但老闆很努力。"},{"simplified":"虽然本小利微，但我们会继续坚持下去。","english":"Although the capital is small and the profit is slight, we will continue to persevere.","traditional":"雖然本小利微，但我們會繼續堅持下去。"}],"synonyms":[],"antonyms":[],"confusedWith":[],"traditional":"本小利微","pinyinOverride":null},{"id":"ben-xing-nan-yi","simplified":"本性难移","literalMeaning":"inherent nature hard to change","figurativeMeaning":"it's hard to change one's inherent nature or habits","englishEquivalents":["A leopard can't change its spots","Old habits die hard"],"shortGloss":"hard to change one's nature","characters":[{"char":"本","meaning":"inherent"},{"char":"性","meaning":"nature"},{"char":"难","meaning":"hard"},{"char":"移","meaning":"change"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom suggests that a person's inherent nature or deep-seated habits are difficult to change. It is often used to describe someone who continues to exhibit the same behavior despite efforts to change.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"subject-predicate","register":"commonly used in both spoken and written Chinese","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with others that imply change is impossible in all aspects, but 本性难移 specifically refers to inherent nature or habits, not all types of change.","canStandAlone":false},"examples":[{"simplified":"他虽然努力改正，但本性难移，还是老样子。","english":"Although he tried hard to change, his inherent nature was hard to change, and he remained the same.","traditional":"他雖然努力改正，但本性難移，還是老樣子。"},{"simplified":"本性难移，他总是忍不住发脾气。","english":"It's hard to change one's nature, and he always can't help losing his temper.","traditional":"本性難移，他總是忍不住發脾氣。"}],"synonyms":["江山易改，本性难移"],"antonyms":[],"confusedWith":[{"id":"江山易改，本性难移","note":"This is a longer version of the same idiom, emphasizing that while external circumstances can change, one's nature is hard to change."}],"traditional":"本性難移","pinyinOverride":null},{"id":"ben-zui-zhuo-she","simplified":"笨嘴拙舌","literalMeaning":"clumsy mouth, awkward tongue","figurativeMeaning":"inarticulate or tongue-tied; unable to express oneself clearly","englishEquivalents":["tongue-tied","at a loss for words"],"shortGloss":"inarticulate or tongue-tied","characters":[{"char":"笨","meaning":"clumsy"},{"char":"嘴","meaning":"mouth"},{"char":"拙","meaning":"awkward"},{"char":"舌","meaning":"tongue"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '笨嘴拙舌' is used to describe someone who struggles to express themselves clearly, often due to nervousness or lack of eloquence. It paints a vivid picture of someone whose mouth and tongue seem clumsy and awkward, making it difficult for them to articulate their thoughts.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"coordinate","register":"commonly used in both spoken and written Chinese to describe someone who is not eloquent","connotation":"negative","commonMistakes":"Learners might confuse this idiom with others that describe being speechless due to surprise or shock, but '笨嘴拙舌' specifically refers to a lack of eloquence or verbal clumsiness.","canStandAlone":false},"examples":[{"simplified":"他在面试中因为紧张而笨嘴拙舌。","english":"He was tongue-tied during the interview because he was nervous.","traditional":"他在面試中因為緊張而笨嘴拙舌。"},{"simplified":"尽管他笨嘴拙舌，但他的想法很有深度。","english":"Although he is inarticulate, his ideas are very profound.","traditional":"儘管他笨嘴拙舌，但他的想法很有深度。"}],"synonyms":["口拙"],"antonyms":["口若悬河"],"confusedWith":[{"id":"哑口无言","note":"哑口无言 refers to being speechless due to shock or having no response, while 笨嘴拙舌 refers to being inarticulate or lacking eloquence."}],"traditional":"笨嘴拙舌","pinyinOverride":null},{"id":"bi-yi-qi-fei","simplified":"比翼齐飞","literalMeaning":"fly wing to wing","figurativeMeaning":"to work together harmoniously towards a common goal, often used to describe a couple or partners","englishEquivalents":["fly side by side","work hand in hand"],"shortGloss":"work together harmoniously","characters":[{"char":"比","meaning":"side by side"},{"char":"翼","meaning":"wing"},{"char":"齐","meaning":"together"},{"char":"飞","meaning":"fly"}],"origin":{"period":"Tang Dynasty (618–907 CE)","sourceText":"《长恨歌》","sourceTextEnglish":"Song of Everlasting Regret","originalExcerpt":"在天愿作比翼鸟，在地愿为连理枝。","storyEnglish":"The idiom originates from the famous poem 'Song of Everlasting Regret' by Bai Juyi, which tells the tragic love story of Emperor Xuanzong of Tang and his beloved consort Yang Guifei. The poem expresses the wish that the lovers could be together forever, like birds flying wing to wing in the sky.","historicalFigures":["Emperor Xuanzong","Yang Guifei"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"literary, but used in both formal and informal contexts to express partnership or teamwork","connotation":"positive","commonMistakes":"Learners sometimes confuse this idiom with '齐头并进', which also means to advance together but lacks the romantic or harmonious connotation. '比翼齐飞' often implies a deeper, more personal connection.","canStandAlone":false},"examples":[{"simplified":"他们在事业上比翼齐飞，取得了巨大的成功。","english":"They worked together harmoniously in their careers and achieved great success.","traditional":"他們在事業上比翼齊飛，取得了巨大的成功。"},{"simplified":"这对夫妻在生活中比翼齐飞，令人羡慕。","english":"This couple lives harmoniously together, making others envious.","traditional":"這對夫妻在生活中比翼齊飛，令人羨慕。"}],"synonyms":["齐头并进"],"antonyms":[],"confusedWith":[{"id":"齐头并进","note":"While both idioms imply working together, '齐头并进' lacks the romantic or harmonious connotation of '比翼齐飞'."}],"traditional":"比翼齊飛","pinyinOverride":null},{"id":"bi-yi-shuang-fei","simplified":"比翼双飞","literalMeaning":"fly together with wings aligned","figurativeMeaning":"to be inseparable and harmonious, often used to describe a loving couple","englishEquivalents":["joined at the hip","two peas in a pod"],"shortGloss":"inseparable couple","characters":[{"char":"比","meaning":"side by side"},{"char":"翼","meaning":"wing"},{"char":"双","meaning":"pair, double"},{"char":"飞","meaning":"fly"}],"origin":{"period":"Tang dynasty (618–907 CE)","sourceText":"《长恨歌》","sourceTextEnglish":"Song of Everlasting Regret","originalExcerpt":"在天愿作比翼鸟，在地愿为连理枝。","storyEnglish":"The idiom comes from the famous Tang dynasty poem 'Song of Everlasting Regret' by Bai Juyi. The poem tells the tragic love story of Emperor Xuanzong of Tang and his beloved consort Yang Guifei. The line 'In heaven we wish to be two birds flying wing to wing' expresses their desire to be together eternally, whether in life or death.","historicalFigures":["Emperor Xuanzong","Yang Guifei"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["attributive","predicate"],"structure":"modifier-head","register":"literary, but often used in modern contexts to describe romantic relationships","connotation":"positive","commonMistakes":"Learners might confuse this idiom with others that describe friendship rather than romantic relationships. It specifically implies a romantic or deeply affectionate bond.","canStandAlone":false},"examples":[{"simplified":"他们俩真是比翼双飞，形影不离。","english":"The two of them are truly inseparable, like two birds flying wing to wing.","traditional":"他們倆真是比翼雙飛，形影不離。"},{"simplified":"这对夫妻一直以来都是比翼双飞，令人羡慕。","english":"This couple has always been inseparable, making others envious.","traditional":"這對夫妻一直以來都是比翼雙飛，令人羨慕。"}],"synonyms":["形影不离"],"antonyms":[],"confusedWith":[{"id":"形影不离","note":"While both idioms describe closeness, '形影不离' is more general and can refer to friends or companions, not just romantic partners."}],"traditional":"比翼雙飛","pinyinOverride":null},{"id":"bi-xia-sheng-hua","simplified":"笔下生花","literalMeaning":"under the pen, flowers bloom","figurativeMeaning":"to write beautifully and eloquently","englishEquivalents":["words flow like a river","eloquent writing","a silver tongue"],"shortGloss":"to write beautifully and eloquently","characters":[{"char":"笔","meaning":"pen"},{"char":"下","meaning":"under"},{"char":"生","meaning":"to give rise to"},{"char":"花","meaning":"flowers"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '笔下生花' is often attributed to the idea that a talented writer can create vivid and beautiful imagery with their words, as if flowers are blooming from their pen. It highlights the skill of writing in a way that captivates and enchants readers.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive","complement"],"structure":"subject-predicate","register":"literary, but widely understood and used in both formal and informal contexts","connotation":"positive","commonMistakes":"Learners might confuse this idiom with those that describe verbal eloquence rather than written skill. It's important to note that '笔下生花' specifically refers to writing, not speaking.","canStandAlone":false},"examples":[{"simplified":"他的文章真是笔下生花，让人读后回味无穷。","english":"His writing is truly eloquent, leaving readers with a lasting impression.","traditional":"他的文章真是筆下生花，讓人讀後回味無窮。"},{"simplified":"她的小说笔下生花，情节引人入胜。","english":"Her novel is beautifully written, with an engaging plot.","traditional":"她的小說筆下生花，情節引人入勝。"}],"synonyms":["妙笔生花"],"antonyms":[],"confusedWith":[{"id":"口若悬河","note":"口若悬河 refers to eloquence in speaking, not writing."}],"traditional":"筆下生花","pinyinOverride":null},{"id":"bi-you-zhi-lu","simplified":"必由之路","literalMeaning":"must pass through road","figurativeMeaning":"the only way; an unavoidable path or process","englishEquivalents":["the only way","the road one must take"],"shortGloss":"the only way forward","characters":[{"char":"必","meaning":"must"},{"char":"由","meaning":"pass through"},{"char":"之","meaning":"of; this"},{"char":"路","meaning":"road; path"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '必由之路' is often used to describe a path or process that is unavoidable or necessary to achieve a certain goal. It suggests that there is no alternative route, and one must follow this particular path to reach the desired outcome.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["subject","predicate","object","attributive"],"structure":"modifier-head","register":"widely used in both formal and informal contexts","connotation":"neutral","commonMistakes":"Learners might confuse it with idioms that imply choice or multiple options. '必由之路' specifically indicates a lack of alternatives.","canStandAlone":false},"examples":[{"simplified":"学习是成功的必由之路。","english":"Studying is the only way to success.","traditional":"學習是成功的必由之路。"},{"simplified":"在这个项目中，合作是我们必由之路。","english":"In this project, cooperation is the path we must take.","traditional":"在這個項目中，合作是我們必由之路。"}],"synonyms":[],"antonyms":[],"confusedWith":[],"traditional":"必由之路","pinyinOverride":null},{"id":"bi-guan-suo-guo","simplified":"闭关锁国","literalMeaning":"close the passes and lock the country","figurativeMeaning":"to isolate a country from outside influences; to close off from the world","englishEquivalents":["isolationism","closed-door policy"],"shortGloss":"national isolation policy","characters":[{"char":"闭","meaning":"close"},{"char":"关","meaning":"pass; checkpoint"},{"char":"锁","meaning":"lock"},{"char":"国","meaning":"country"}],"origin":{"period":"Qing Dynasty (1644–1912)","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '闭关锁国' refers to the policy of national isolation practiced by several Chinese dynasties, most notably the Qing Dynasty, which restricted foreign trade and cultural exchange. This policy aimed to preserve traditional culture and maintain control over foreign influences. However, it also led to technological and economic stagnation, contributing to the eventual decline of the Qing Dynasty.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["subject","predicate","object"],"structure":"verb-object","register":"commonly used in both formal and informal contexts to describe historical or modern isolationist policies","connotation":"negative","commonMistakes":"Learners might confuse this idiom with general terms for isolation or seclusion, but it specifically refers to a national policy of isolationism. It is not used for personal or small-scale isolation.","canStandAlone":false},"examples":[{"simplified":"清朝的闭关锁国政策导致了国家的落后。","english":"The Qing Dynasty's closed-door policy led to the country's backwardness.","traditional":"清朝的閉關鎖國政策導致了國家的落後。"},{"simplified":"在全球化的时代，闭关锁国已经不再可行。","english":"In the era of globalization, isolationism is no longer feasible.","traditional":"在全球化的時代，閉關鎖國已經不再可行。"}],"synonyms":[],"antonyms":["开放政策"],"confusedWith":[{"id":"自我封闭","note":"自我封闭 refers to personal or organizational self-isolation, not a national policy."}],"traditional":"閉關鎖國","pinyinOverride":null},{"id":"bi-guan-zi-shou","simplified":"闭关自守","literalMeaning":"close the pass and guard oneself","figurativeMeaning":"to isolate oneself from the outside world; to adopt a closed-door policy","englishEquivalents":["close oneself off","isolationism"],"shortGloss":"self-imposed isolation","characters":[{"char":"闭","meaning":"close"},{"char":"关","meaning":"pass; checkpoint"},{"char":"自","meaning":"self"},{"char":"守","meaning":"guard; defend"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '闭关自守' refers to the practice of isolating oneself or a country from external influences. Historically, it has been used to describe policies where a nation closes its borders and limits interaction with other countries, often to preserve its own culture or security. This approach can lead to stagnation and a lack of progress due to the absence of external ideas and trade.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"commonly used in both formal and informal contexts","connotation":"negative","commonMistakes":"Learners often confuse '闭关自守' with '闭门造车', which means to work behind closed doors without considering outside input. While both involve isolation, '闭关自守' emphasizes self-imposed isolation from the outside world, whereas '闭门造车' focuses on ignoring external feedback.","canStandAlone":false},"examples":[{"simplified":"在全球化的时代，闭关自守只会让国家落后。","english":"In an era of globalization, isolationism will only cause a country to fall behind.","traditional":"在全球化的時代，閉關自守只會讓國家落後。"},{"simplified":"他总是闭关自守，不愿与外界交流。","english":"He always isolates himself and is unwilling to communicate with the outside world.","traditional":"他總是閉關自守，不願與外界交流。"}],"synonyms":["自我封闭"],"antonyms":["开放包容"],"confusedWith":[{"id":"闭门造车","note":"闭门造车 means to work behind closed doors without considering outside input, while 闭关自守 refers to self-imposed isolation from the outside world."}],"traditional":"閉關自守","pinyinOverride":null},{"id":"bi-kou-bu-yan","simplified":"闭口不言","literalMeaning":"close mouth not speak","figurativeMeaning":"to remain silent; to keep one's mouth shut","englishEquivalents":["keep mum","hold one's tongue"],"shortGloss":"to remain silent","characters":[{"char":"闭","meaning":"close"},{"char":"口","meaning":"mouth"},{"char":"不","meaning":"not"},{"char":"言","meaning":"speak"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '闭口不言' is used to describe a situation where someone chooses to remain silent, often to avoid trouble or to keep a secret. It is a straightforward expression that emphasizes the act of not speaking.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"commonly used in both spoken and written Chinese","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with others that involve silence but imply different contexts, such as '三缄其口', which suggests being cautious with one's words. '闭口不言' is more about choosing not to speak at all.","canStandAlone":false},"examples":[{"simplified":"面对记者的提问，他闭口不言。","english":"Faced with the reporter's questions, he remained silent.","traditional":"面對記者的提問，他閉口不言。"},{"simplified":"在会议上，他对这个问题闭口不言。","english":"In the meeting, he kept silent on this issue.","traditional":"在會議上，他對這個問題閉口不言。"}],"synonyms":["缄口不言","三缄其口"],"antonyms":["口若悬河"],"confusedWith":[{"id":"三缄其口","note":"三缄其口 implies being cautious with words, whereas 闭口不言 is simply about not speaking."}],"traditional":"閉口不言","pinyinOverride":null},{"id":"bi-men-si-guo","simplified":"闭门思过","literalMeaning":"close the door and reflect on one's mistakes","figurativeMeaning":"to reflect on one's mistakes in private","englishEquivalents":["soul-searching","introspection"],"shortGloss":"reflect on one's mistakes","characters":[{"char":"闭","meaning":"close"},{"char":"门","meaning":"door"},{"char":"思","meaning":"reflect, think"},{"char":"过","meaning":"mistakes, faults"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '闭门思过' suggests the idea of closing oneself off from distractions to engage in deep reflection on one's past actions and mistakes. It emphasizes the importance of self-examination and personal growth through acknowledging and learning from one's errors.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"commonly used in both spoken and written Chinese, suitable for both formal and informal contexts","connotation":"neutral","commonMistakes":"Learners often confuse this idiom with those that imply punishment from others, but '闭门思过' emphasizes voluntary self-reflection rather than imposed consequences.","canStandAlone":false},"examples":[{"simplified":"他决定闭门思过，认真反省自己的错误。","english":"He decided to reflect on his mistakes in private and seriously examine his faults.","traditional":"他決定閉門思過，認真反省自己的錯誤。"},{"simplified":"经过这次失败，她选择闭门思过，寻找改进的方法。","english":"After this failure, she chose to reflect on her mistakes and find ways to improve.","traditional":"經過這次失敗，她選擇閉門思過，尋找改進的方法。"}],"synonyms":["反省自我"],"antonyms":[],"confusedWith":[{"id":"闭门羹","note":"闭门羹 refers to being refused entry or being ignored, not self-reflection."}],"traditional":"閉門思過","pinyinOverride":null},{"id":"bi-mu-sai-ting","simplified":"闭目塞听","literalMeaning":"close eyes and block ears","figurativeMeaning":"to ignore the truth or reality; to refuse to see or hear what is happening","englishEquivalents":["turn a blind eye","bury one's head in the sand"],"shortGloss":"ignore reality","characters":[{"char":"闭","meaning":"close"},{"char":"目","meaning":"eyes"},{"char":"塞","meaning":"block"},{"char":"听","meaning":"ears"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '闭目塞听' is used to describe someone who deliberately ignores reality by closing their eyes and blocking their ears, metaphorically speaking. It suggests a willful ignorance or refusal to acknowledge the truth of a situation.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"common in both written and spoken Chinese","connotation":"negative","commonMistakes":"Learners might confuse this idiom with similar expressions that involve physical blindness or deafness, but it specifically refers to a willful ignorance rather than a physical inability.","canStandAlone":false},"examples":[{"simplified":"他对公司的问题闭目塞听，最终导致了严重的后果。","english":"He ignored the company's problems, which eventually led to serious consequences.","traditional":"他對公司的問題閉目塞聽，最終導致了嚴重的後果。"},{"simplified":"在面对批评时，我们不能闭目塞听，而是要积极改进。","english":"When facing criticism, we shouldn't ignore it but actively work on improvements.","traditional":"在面對批評時，我們不能閉目塞聽，而是要積極改進。"}],"synonyms":["视而不见","充耳不闻"],"antonyms":["耳聪目明"],"confusedWith":[{"id":"视而不见","note":"Both idioms involve ignoring reality, but '视而不见' specifically means to look but not see, while '闭目塞听' means to actively shut out both sight and sound."}],"traditional":"閉目塞聽","pinyinOverride":null},{"id":"bi-yue-xiu-hua","simplified":"闭月羞花","literalMeaning":"hide the moon, shy the flowers","figurativeMeaning":"a woman of extraordinary beauty","englishEquivalents":["a face that could launch a thousand ships","drop-dead gorgeous"],"shortGloss":"extraordinarily beautiful woman","characters":[{"char":"闭","meaning":"hide"},{"char":"月","meaning":"moon"},{"char":"羞","meaning":"shy"},{"char":"花","meaning":"flowers"}],"origin":{"period":"Tang Dynasty (618–907 CE)","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '闭月羞花' is often associated with the legendary beauty of Diao Chan, one of the Four Beauties of ancient China. It is said that her beauty was so great that it could make the moon hide behind clouds out of shame and cause flowers to close in embarrassment. This chengyu is used to describe a woman whose beauty is so stunning that it surpasses even the wonders of nature.","historicalFigures":["Diao Chan"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["attributive","predicate"],"structure":"coordinate","register":"literary, but widely recognized in modern contexts","connotation":"positive","commonMistakes":"Learners often use this idiom without understanding its literary and historical connotations, which can make it sound overly formal or exaggerated in casual contexts.","canStandAlone":false},"examples":[{"simplified":"她的美貌真是闭月羞花，让人惊叹不已。","english":"Her beauty is truly extraordinary, leaving people in awe.","traditional":"她的美貌真是閉月羞花，讓人驚歎不已。"},{"simplified":"在这次选美比赛中，她以闭月羞花的姿态赢得了冠军。","english":"In this beauty pageant, she won the championship with her stunning beauty.","traditional":"在這次選美比賽中，她以閉月羞花的姿態贏得了冠軍。"}],"synonyms":["沉鱼落雁","倾国倾城"],"antonyms":[],"confusedWith":[{"id":"沉鱼落雁","note":"Both idioms describe exceptional beauty, but '沉鱼落雁' specifically refers to beauty that causes fish to sink and geese to fall."}],"traditional":"閉月羞花","pinyinOverride":null},{"id":"bi-zhou-qian-jin","simplified":"敝帚千金","literalMeaning":"a worn-out broom is worth a thousand gold pieces","figurativeMeaning":"something may be worthless to others but is precious to its owner","englishEquivalents":["One man's trash is another man's treasure"],"shortGloss":"valuing one's own possessions","characters":[{"char":"敝","meaning":"worn-out"},{"char":"帚","meaning":"broom"},{"char":"千","meaning":"thousand"},{"char":"金","meaning":"gold pieces"}],"origin":{"period":"Han Dynasty (202 BCE – 220 CE)","sourceText":"《史记·鲁仲连邹阳列传》","sourceTextEnglish":"Records of the Grand Historian, Biography of Lu Zhonglian and Zou Yang","originalExcerpt":"人皆以千金之子，敝帚自珍。","storyEnglish":"The idiom comes from a story in the 'Records of the Grand Historian' where it is mentioned that people value their own possessions, even if they seem worthless to others. The phrase '敝帚自珍' is used to illustrate how a worn-out broom, though seemingly worthless, is treasured by its owner.","historicalFigures":["Lu Zhonglian","Zou Yang"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","object"],"structure":"subject-predicate","register":"literary, but understood in modern contexts","connotation":"neutral","commonMistakes":"Learners often misunderstand this idiom to mean that the object itself is valuable, rather than understanding the subjective value placed on it by the owner.","canStandAlone":false},"examples":[{"simplified":"他对那辆旧车的感情就像敝帚千金。","english":"He treasures that old car as if it were worth a thousand gold pieces.","traditional":"他對那輛舊車的感情就像敝帚千金。"},{"simplified":"虽然这幅画在别人看来不值钱，但对他来说却是敝帚千金。","english":"Although this painting seems worthless to others, to him it is as precious as gold.","traditional":"雖然這幅畫在別人看來不值錢，但對他來說卻是敝帚千金。"}],"synonyms":[],"antonyms":[],"confusedWith":[],"traditional":"敝帚千金","pinyinOverride":null},{"id":"bi-zhou-zi-zhen","simplified":"敝帚自珍","literalMeaning":"worn-out broom, self-treasure","figurativeMeaning":"to value something simply because it is one's own, regardless of its actual worth","englishEquivalents":["One man's trash is another man's treasure","Every man thinks his own geese are swans"],"shortGloss":"treasuring one's own worthless things","characters":[{"char":"敝","meaning":"worn-out"},{"char":"帚","meaning":"broom"},{"char":"自","meaning":"self"},{"char":"珍","meaning":"treasure"}],"origin":{"period":"Han Dynasty (202 BCE – 220 CE)","sourceText":"《汉书·王吉传》","sourceTextEnglish":"Book of Han, Biography of Wang Ji","originalExcerpt":"家贫无可用，惟有敝帚自珍。","storyEnglish":"The idiom originates from a story about Wang Ji, a scholar during the Han Dynasty. Despite his poverty, he valued his old broom highly because it was his own. This story illustrates the idea that people often treasure their own possessions, no matter how worthless they may seem to others.","historicalFigures":["Wang Ji"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","object"],"structure":"verb-object","register":"literary, but can be used in everyday speech to humorously describe someone's attachment to their own possessions","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with others that emphasize the value of something, rather than the subjective attachment to it. It's important to note that the idiom highlights the personal value rather than intrinsic worth.","canStandAlone":false},"examples":[{"simplified":"他对那辆旧车敝帚自珍，谁也劝不动他卖掉。","english":"He treasures that old car of his, and no one can persuade him to sell it.","traditional":"他對那輛舊車敝帚自珍，誰也勸不動他賣掉。"},{"simplified":"虽然这幅画不值钱，但他敝帚自珍，挂在客厅里。","english":"Although the painting isn't worth much, he treasures it and hangs it in the living room.","traditional":"雖然這幅畫不值錢，但他敝帚自珍，掛在客廳裡。"}],"synonyms":[],"antonyms":[],"confusedWith":[],"traditional":"敝帚自珍","pinyinOverride":null},{"id":"bi-hai-qing-tian","simplified":"碧海青天","literalMeaning":"emerald sea, azure sky","figurativeMeaning":"a beautiful and serene scene; often used to describe a peaceful and picturesque environment","englishEquivalents":["clear skies and calm seas","a picture-perfect day"],"shortGloss":"a serene and picturesque scene","characters":[{"char":"碧","meaning":"emerald, greenish-blue"},{"char":"海","meaning":"sea, ocean"},{"char":"青","meaning":"azure, blue"},{"char":"天","meaning":"sky, heaven"}],"origin":{"period":"Tang Dynasty (618–907 CE)","sourceText":"《长恨歌》","sourceTextEnglish":"Song of Everlasting Regret","originalExcerpt":"此恨绵绵无绝期，长生殿上，碧海青天夜夜心。","storyEnglish":"The idiom originates from the famous Tang Dynasty poem 'Song of Everlasting Regret' by Bai Juyi. The poem tells the tragic love story of Emperor Xuanzong of Tang and his beloved consort Yang Guifei. In the poem, the phrase '碧海青天' is used to evoke the eternal and unchanging beauty of the natural world, contrasting with the fleeting nature of human emotions and life.","historicalFigures":["Emperor Xuanzong","Yang Guifei"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["attributive","adverbial"],"structure":"coordinate","register":"literary, but can be used in poetic or descriptive contexts in modern speech","connotation":"positive","commonMistakes":"Learners might confuse this idiom with others that describe natural beauty, but it specifically conveys a sense of serene and picturesque beauty, often with a poetic or nostalgic tone.","canStandAlone":false},"examples":[{"simplified":"在这个小岛上，你可以看到碧海青天的美景。","english":"On this small island, you can see the beautiful scene of emerald seas and azure skies.","traditional":"在這個小島上，你可以看到碧海青天的美景。"},{"simplified":"诗人用碧海青天来形容那段美好的时光。","english":"The poet used 'emerald seas and azure skies' to describe those beautiful times.","traditional":"詩人用碧海青天來形容那段美好的時光。"}],"synonyms":[],"antonyms":[],"confusedWith":[],"traditional":"碧海青天","pinyinOverride":null},{"id":"bi-lei-sen-yan","simplified":"壁垒森严","literalMeaning":"ramparts dense and strict","figurativeMeaning":"strict defenses; impenetrable barriers","englishEquivalents":["fortified defenses","impenetrable barriers"],"shortGloss":"strict defenses","characters":[{"char":"壁","meaning":"wall; rampart"},{"char":"垒","meaning":"rampart; fortification"},{"char":"森","meaning":"dense; strict"},{"char":"严","meaning":"strict; severe"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '壁垒森严' is used to describe a situation where defenses or barriers are very strict and difficult to penetrate. It evokes the image of a fortified place with dense and imposing ramparts, suggesting that it is well-protected and secure against intrusion.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["attributive","predicate"],"structure":"modifier-head","register":"commonly used in both formal and informal contexts to describe strict defenses or barriers","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with phrases that imply physical walls rather than metaphorical barriers. It is important to understand that it often refers to non-physical defenses, such as bureaucratic or social barriers.","canStandAlone":false},"examples":[{"simplified":"这家公司内部的壁垒森严，使得外人很难了解其运作。","english":"The company's internal defenses are so strict that outsiders find it difficult to understand its operations.","traditional":"這家公司內部的壁壘森嚴，使得外人很難了解其運作。"},{"simplified":"在这个行业中，壁垒森严的竞争环境让新企业很难进入。","english":"In this industry, the impenetrable competitive environment makes it difficult for new companies to enter.","traditional":"在這個行業中，壁壘森嚴的競爭環境讓新企業很難進入。"}],"synonyms":["固若金汤"],"antonyms":[],"confusedWith":[{"id":"铜墙铁壁","note":"While both idioms refer to strong defenses, '铜墙铁壁' emphasizes physical strength and invulnerability, often in a military context, whereas '壁垒森严' can refer to both physical and metaphorical barriers."}],"traditional":"壁壘森嚴","pinyinOverride":null},{"id":"bi-keng-luo-jing","simplified":"避坑落井","literalMeaning":"avoid a pit, fall into a well","figurativeMeaning":"to escape one problem only to fall into another; out of the frying pan into the fire","englishEquivalents":["out of the frying pan into the fire"],"shortGloss":"escape one problem, fall into another","characters":[{"char":"避","meaning":"avoid"},{"char":"坑","meaning":"pit"},{"char":"落","meaning":"fall"},{"char":"井","meaning":"well"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom describes a situation where someone tries to avoid a minor problem (a pit) only to end up in a worse situation (a well). It highlights the irony of escaping one danger only to encounter another, often more serious one.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"cause-effect","register":"commonly used in both written and spoken Chinese","connotation":"negative","commonMistakes":"Learners might confuse this idiom with others that involve avoiding or falling into traps, but it specifically emphasizes the irony of escaping one problem only to encounter a worse one.","canStandAlone":false},"examples":[{"simplified":"他想避免这次危机，结果却避坑落井，陷入了更大的麻烦。","english":"He tried to avoid this crisis, but ended up out of the frying pan into the fire, falling into even bigger trouble.","traditional":"他想避免這次危機，結果卻避坑落井，陷入了更大的麻煩。"},{"simplified":"小心你的选择，不要避坑落井。","english":"Be careful with your choices, don't escape one problem only to fall into another.","traditional":"小心你的選擇，不要避坑落井。"}],"synonyms":[],"antonyms":[],"confusedWith":[],"traditional":"避坑落井","pinyinOverride":null},{"id":"bi-zhong-jiu-qing","simplified":"避重就轻","literalMeaning":"avoid the heavy and go for the light","figurativeMeaning":"to evade important matters and focus on trivial ones; to shirk responsibility","englishEquivalents":["pass the buck","dodge the bullet"],"shortGloss":"evade important matters","characters":[{"char":"避","meaning":"avoid"},{"char":"重","meaning":"heavy; important"},{"char":"就","meaning":"go for; focus on"},{"char":"轻","meaning":"light; trivial"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '避重就轻' is often used to describe someone who evades important responsibilities or difficult tasks, choosing instead to focus on less significant or easier matters. The exact origin of this idiom is unclear, but it has been used in Chinese literature and speech to criticize those who avoid taking on challenging duties.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"commonly used in both formal and informal contexts","connotation":"negative","commonMistakes":"Learners sometimes confuse this idiom with similar-sounding ones that involve avoiding something, but it specifically refers to avoiding important tasks in favor of easier ones. It should not be used to describe evading physical danger.","canStandAlone":false},"examples":[{"simplified":"在工作中，我们不能避重就轻，应该勇敢面对挑战。","english":"In our work, we shouldn't evade important tasks; we should face challenges bravely.","traditional":"在工作中，我們不能避重就輕，應該勇敢面對挑戰。"},{"simplified":"他总是避重就轻，把困难的任务留给别人。","english":"He always evades the important tasks, leaving the difficult ones to others.","traditional":"他總是避重就輕，把困難的任務留給別人。"}],"synonyms":["推卸责任"],"antonyms":["勇挑重担"],"confusedWith":[{"id":"避难就易","note":"This idiom means to avoid difficulties and choose the easy way, which is similar but not specifically about responsibility."}],"traditional":"避重就輕","pinyinOverride":null},{"id":"bian-chang-mo-ji","simplified":"鞭长莫及","literalMeaning":"the whip is long but cannot reach","figurativeMeaning":"beyond one's reach or ability to help","englishEquivalents":["out of reach","beyond one's grasp"],"shortGloss":"beyond one's reach","characters":[{"char":"鞭","meaning":"whip"},{"char":"长","meaning":"long"},{"char":"莫","meaning":"cannot"},{"char":"及","meaning":"reach"}],"origin":{"period":"Han Dynasty (202 BCE – 220 CE)","sourceText":"《汉书·王吉传》","sourceTextEnglish":"Book of Han, Biography of Wang Ji","originalExcerpt":"鞭虽长，不及马腹。","storyEnglish":"The idiom originates from a passage in the 'Book of Han' where it is noted that even if a whip is long, it cannot reach the horse's belly. This metaphor was used to describe situations where one is unable to exert influence or provide help due to distance or limitations.","historicalFigures":["Wang Ji"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"subject-predicate","register":"literary, but commonly used in both written and spoken Chinese","connotation":"neutral","commonMistakes":"Learners may confuse this idiom with expressions that imply physical distance only, but it also refers to limitations in ability or influence.","canStandAlone":false},"examples":[{"simplified":"虽然他很想帮忙，但鞭长莫及。","english":"Although he really wanted to help, it was beyond his reach.","traditional":"雖然他很想幫忙，但鞭長莫及。"},{"simplified":"面对如此复杂的问题，我们也感到鞭长莫及。","english":"Faced with such a complex issue, we also felt it was beyond our reach.","traditional":"面對如此複雜的問題，我們也感到鞭長莫及。"}],"synonyms":["力不从心"],"antonyms":[],"confusedWith":[{"id":"心有余而力不足","note":"Both idioms describe limitations, but 心有余而力不足 emphasizes having the will but lacking the strength or means."}],"traditional":"鞭長莫及","pinyinOverride":null},{"id":"bian-hua-duo-duan","simplified":"变化多端","literalMeaning":"changes many ends","figurativeMeaning":"ever-changing; highly variable and unpredictable","englishEquivalents":["ever-changing","highly variable","unpredictable"],"shortGloss":"ever-changing and unpredictable","characters":[{"char":"变","meaning":"change"},{"char":"化","meaning":"transform"},{"char":"多","meaning":"many"},{"char":"端","meaning":"ends; aspects"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '变化多端' is used to describe situations, things, or people that are constantly changing and difficult to predict. It emphasizes the complexity and variability of the subject in question.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"modifier-head","register":"widely used in both formal and informal contexts","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with others that imply change, but '变化多端' specifically emphasizes unpredictability and complexity. It should not be used to describe simple or straightforward changes.","canStandAlone":false},"examples":[{"simplified":"天气变化多端，我们最好带把伞。","english":"The weather is ever-changing; we should bring an umbrella just in case.","traditional":"天氣變化多端，我們最好帶把傘。"},{"simplified":"他的计划变化多端，让人难以捉摸。","english":"His plans are highly variable, making them hard to grasp.","traditional":"他的計劃變化多端，讓人難以捉摸。"}],"synonyms":["千变万化"],"antonyms":["一成不变"],"confusedWith":[{"id":"千变万化","note":"Both describe changeability, but '千变万化' emphasizes a multitude of changes, while '变化多端' highlights unpredictability."}],"traditional":"變化多端","pinyinOverride":null},{"id":"bian-hua-mo-ce","simplified":"变化莫测","literalMeaning":"change cannot be predicted","figurativeMeaning":"unpredictable; constantly changing","englishEquivalents":["unpredictable","ever-changing","in a state of flux"],"shortGloss":"unpredictable; constantly changing","characters":[{"char":"变","meaning":"change"},{"char":"化","meaning":"transform"},{"char":"莫","meaning":"cannot"},{"char":"测","meaning":"predict; fathom"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '变化莫测' is used to describe situations, events, or even people that are unpredictable and constantly changing. The phrase suggests that the changes are so complex or rapid that they cannot be easily anticipated or understood.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"modifier-head","register":"commonly used in both formal and informal contexts","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with ones that imply chaos or disorder, but '变化莫测' specifically emphasizes unpredictability without a negative connotation.","canStandAlone":false},"examples":[{"simplified":"天气变化莫测，我们最好带上雨伞。","english":"The weather is unpredictable; we should bring an umbrella just in case.","traditional":"天氣變化莫測，我們最好帶上雨傘。"},{"simplified":"他的情绪变化莫测，让人捉摸不透。","english":"His mood is unpredictable, making it hard for people to understand him.","traditional":"他的情緒變化莫測，讓人捉摸不透。"}],"synonyms":["变幻无常","难以捉摸"],"antonyms":["一成不变"],"confusedWith":[{"id":"变幻无常","note":"Both idioms describe unpredictability, but '变幻无常' often implies more frequent or erratic changes."}],"traditional":"變化莫測","pinyinOverride":null},{"id":"bian-hua-wu-chang","simplified":"变化无常","literalMeaning":"change without constancy","figurativeMeaning":"to change frequently and unpredictably","englishEquivalents":["ever-changing","inconstant","unpredictable"],"shortGloss":"unpredictable change","characters":[{"char":"变","meaning":"change"},{"char":"化","meaning":"transform"},{"char":"无","meaning":"without"},{"char":"常","meaning":"constancy"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '变化无常' describes a situation or condition that changes frequently and without warning. It is often used to describe the unpredictable nature of things, such as the weather, a person's mood, or market conditions.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"modifier-head","register":"commonly used in both written and spoken Chinese","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with '千变万化', which emphasizes a wide variety of changes rather than unpredictability. '变化无常' specifically highlights the lack of consistency.","canStandAlone":false},"examples":[{"simplified":"这个城市的天气变化无常，让人很难适应。","english":"The weather in this city is unpredictable, making it hard for people to adapt.","traditional":"這個城市的天氣變化無常，讓人很難適應。"},{"simplified":"他的情绪变化无常，有时让人捉摸不透。","english":"His mood is unpredictable, sometimes making it hard to understand him.","traditional":"他的情緒變化無常，有時讓人捉摸不透。"}],"synonyms":["千变万化"],"antonyms":["一成不变"],"confusedWith":[{"id":"千变万化","note":"千变万化 emphasizes a wide variety of changes, while 变化无常 focuses on unpredictability."}],"traditional":"變化無常","pinyinOverride":null},{"id":"bian-di-kai-hua","simplified":"遍地开花","literalMeaning":"flowers bloom everywhere","figurativeMeaning":"to flourish everywhere; to spring up all over the place","englishEquivalents":["spring up like mushrooms","flourish everywhere"],"shortGloss":"flourish everywhere","characters":[{"char":"遍","meaning":"everywhere"},{"char":"地","meaning":"ground; place"},{"char":"开","meaning":"open; bloom"},{"char":"花","meaning":"flower"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '遍地开花' is often used to describe a situation where something positive, like a business or idea, spreads rapidly and successfully across a wide area, much like flowers blooming everywhere in a field. The phrase captures the sense of widespread growth and prosperity.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"common in both written and spoken Chinese, suitable for describing widespread success or proliferation","connotation":"positive","commonMistakes":"Learners sometimes use this idiom to describe negative situations, but it is typically used for positive or neutral contexts. It should not be confused with idioms that imply chaos or disorder.","canStandAlone":false},"examples":[{"simplified":"近年来，这种新型超市在城市里遍地开花。","english":"In recent years, this new type of supermarket has sprung up all over the city.","traditional":"近年來，這種新型超市在城市裡遍地開花。"},{"simplified":"他的音乐作品在全国遍地开花，受到广泛欢迎。","english":"His musical works have flourished everywhere in the country and are widely welcomed.","traditional":"他的音樂作品在全國遍地開花，受到廣泛歡迎。"}],"synonyms":["如雨后春笋"],"antonyms":[],"confusedWith":[{"id":"一败涂地","note":"While '遍地开花' implies success and proliferation, '一败涂地' means complete failure, often confused due to the shared character '地'."}],"traditional":"遍地開花","pinyinOverride":null},{"id":"bian-ti-lin-shang","simplified":"遍体鳞伤","literalMeaning":"whole body covered in scales and wounds","figurativeMeaning":"to be covered all over with cuts and bruises; severely beaten or injured","englishEquivalents":["beaten black and blue","covered in bruises"],"shortGloss":"covered in bruises","characters":[{"char":"遍","meaning":"all over; throughout"},{"char":"体","meaning":"body"},{"char":"鳞","meaning":"scales"},{"char":"伤","meaning":"wounds; injuries"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '遍体鳞伤' is often used to describe someone who has been severely beaten or injured, with their body covered in wounds and bruises. The imagery of 'scales' suggests a pattern of injuries all over the body, similar to how a fish's scales cover its body. This vivid description highlights the extent of the physical harm suffered.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"modifier-head","register":"commonly used in both written and spoken Chinese to describe severe physical injury","connotation":"negative","commonMistakes":"Learners might confuse this idiom with others that describe emotional or psychological harm, but '遍体鳞伤' specifically refers to physical injuries.","canStandAlone":false},"examples":[{"simplified":"他从战场回来时，遍体鳞伤。","english":"He returned from the battlefield covered in bruises.","traditional":"他從戰場回來時，遍體鱗傷。"},{"simplified":"经过那场车祸，他遍体鳞伤，需要住院治疗。","english":"After the car accident, he was covered in bruises and needed hospitalization.","traditional":"經過那場車禍，他遍體鱗傷，需要住院治療。"}],"synonyms":["伤痕累累"],"antonyms":[],"confusedWith":[{"id":"体无完肤","note":"While both describe severe injury, '体无完肤' emphasizes that there is no uninjured part of the body, whereas '遍体鳞伤' suggests being covered in bruises."}],"traditional":"遍體鱗傷","pinyinOverride":null},{"id":"biao-xing-da-han","simplified":"彪形大汉","literalMeaning":"tiger-shaped big man","figurativeMeaning":"a strong and muscular man","englishEquivalents":["a burly man","a hulking figure"],"shortGloss":"a strong, muscular man","characters":[{"char":"彪","meaning":"tiger-like, strong and robust"},{"char":"形","meaning":"shape, form"},{"char":"大","meaning":"big, large"},{"char":"汉","meaning":"man, fellow"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '彪形大汉' is used to describe a man who is physically large and strong, often with a muscular build. The term '彪' refers to the strength and robustness associated with a tiger, symbolizing power and might. This idiom is commonly used in everyday language to describe someone with an imposing physical presence.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["subject","object","attributive"],"structure":"modifier-head","register":"common in both spoken and written Chinese, used in informal and formal contexts","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with those describing bravery or fierceness due to the character '彪'. However, it specifically refers to physical size and strength, not personality traits.","canStandAlone":false},"examples":[{"simplified":"他是个彪形大汉，站在那里就像一座山。","english":"He is a burly man, standing there like a mountain.","traditional":"他是個彪形大漢，站在那裡就像一座山。"},{"simplified":"那个彪形大汉轻松地举起了重物。","english":"That hulking figure easily lifted the heavy object.","traditional":"那個彪形大漢輕鬆地舉起了重物。"}],"synonyms":[],"antonyms":[],"confusedWith":[{"id":"勇猛无比","note":"勇猛无比 refers to unparalleled bravery or fierceness, not physical size."}],"traditional":"彪形大漢","pinyinOverride":null},{"id":"biao-li-ru-yi","simplified":"表里如一","literalMeaning":"exterior and interior are the same","figurativeMeaning":"to be genuine and consistent; to be the same inside and out","englishEquivalents":["what you see is what you get","true to oneself"],"shortGloss":"genuine and consistent","characters":[{"char":"表","meaning":"exterior; outward appearance"},{"char":"里","meaning":"interior; inside"},{"char":"如","meaning":"like; as if"},{"char":"一","meaning":"one; the same"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom 表里如一 is used to describe someone whose outward appearance and inner character are consistent. It suggests that a person is genuine and does not pretend to be something they are not. The phrase likely developed as a moral ideal, emphasizing integrity and honesty.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"modifier-head","register":"commonly used in both formal and informal contexts","connotation":"positive","commonMistakes":"Learners might confuse 表里如一 with similar idioms that emphasize honesty, but this idiom specifically highlights consistency between appearance and reality, not just honesty.","canStandAlone":false},"examples":[{"simplified":"他这个人表里如一，值得信任。","english":"He is someone who is genuine and consistent, worthy of trust.","traditional":"他這個人表裡如一，值得信任。"},{"simplified":"她的性格表里如一，从不伪装。","english":"Her character is genuine and consistent; she never pretends.","traditional":"她的性格表裡如一，從不偽裝。"}],"synonyms":["言行一致"],"antonyms":["口是心非"],"confusedWith":[{"id":"口是心非","note":"口是心非 means saying one thing and meaning another, which is the opposite of 表里如一."}],"traditional":"表裡如一","pinyinOverride":null},{"id":"biao-mian-wen-zhang","simplified":"表面文章","literalMeaning":"surface article","figurativeMeaning":"superficial work; doing something for show without real substance","englishEquivalents":["window dressing","lip service"],"shortGloss":"superficial work","characters":[{"char":"表","meaning":"surface; outward appearance"},{"char":"面","meaning":"face; surface"},{"char":"文","meaning":"article; writing"},{"char":"章","meaning":"article; chapter"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '表面文章' refers to actions or work that are done only for appearances, without any real substance or depth. It is often used to criticize efforts that are focused on looking good rather than being effective or meaningful.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["attributive","object"],"structure":"modifier-head","register":"commonly used in both written and spoken Chinese to criticize superficial efforts","connotation":"negative","commonMistakes":"Learners might confuse '表面文章' with '表面功夫', which also refers to superficial efforts but is more focused on actions rather than written work.","canStandAlone":false},"examples":[{"simplified":"这份报告只是做做表面文章，没有实际内容。","english":"This report is just window dressing; it lacks any real content.","traditional":"這份報告只是做做表面文章，沒有實際內容。"},{"simplified":"他总是做表面文章，实际上什么也没做。","english":"He always puts on a show, but in reality, he does nothing.","traditional":"他總是做表面文章，實際上什麼也沒做。"}],"synonyms":["表面功夫"],"antonyms":[],"confusedWith":[{"id":"表面功夫","note":"表面功夫 refers more to superficial actions rather than written work."}],"traditional":"表面文章","pinyinOverride":null},{"id":"bie-ju-yi-ge","simplified":"别具一格","literalMeaning":"separately possess one style","figurativeMeaning":"to have a unique or distinctive style","englishEquivalents":["in a class of its own","one of a kind"],"shortGloss":"unique style","characters":[{"char":"别","meaning":"separate; different"},{"char":"具","meaning":"possess; have"},{"char":"一","meaning":"one; a"},{"char":"格","meaning":"style; pattern"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom 别具一格 is often used to describe something or someone that stands out due to a unique or distinctive style. It is commonly applied in contexts such as art, literature, fashion, or any field where creativity and individuality are valued. The phrase suggests that the subject has a style that is different from the norm, making it notable and memorable.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"verb-object","register":"widely used in both spoken and written Chinese, suitable for formal and informal contexts","connotation":"positive","commonMistakes":"Learners might confuse 别具一格 with similar expressions like 独树一帜, which also means having a unique style but often implies a pioneering or leading role. 别具一格 focuses more on distinctiveness rather than leadership.","canStandAlone":false},"examples":[{"simplified":"这位画家的作品别具一格，令人印象深刻。","english":"The artist's works have a unique style that leaves a deep impression.","traditional":"這位畫家的作品別具一格，令人印象深刻。"},{"simplified":"他的设计在展览中别具一格，吸引了很多观众。","english":"His design stood out at the exhibition with its distinctive style, attracting many visitors.","traditional":"他的設計在展覽中別具一格，吸引了很多觀眾。"}],"synonyms":["独树一帜"],"antonyms":[],"confusedWith":[{"id":"独树一帜","note":"独树一帜 emphasizes pioneering or leading a trend, while 别具一格 focuses on distinctiveness."}],"traditional":"別具一格","pinyinOverride":null},{"id":"bie-kai-sheng-mian","simplified":"别开生面","literalMeaning":"open up a new face","figurativeMeaning":"to create something new and original; to break new ground","englishEquivalents":["break new ground","pioneer","innovate"],"shortGloss":"create something new and original","characters":[{"char":"别","meaning":"separate; different"},{"char":"开","meaning":"open"},{"char":"生","meaning":"new; fresh"},{"char":"面","meaning":"face; aspect"}],"origin":{"period":"Tang dynasty (618–907 CE)","sourceText":"《新唐书·李泌传》","sourceTextEnglish":"New Book of Tang, Biography of Li Mi","originalExcerpt":"泌别开生面，不蹈袭前人之迹。","storyEnglish":"The idiom originates from a description of Li Mi, a Tang dynasty official, who was praised for his ability to innovate and create new approaches rather than following the footsteps of his predecessors. His work was described as '别开生面', meaning he opened up a new aspect or face, highlighting his originality and creativity.","historicalFigures":["Li Mi"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"verb-object","register":"literary, but widely understood and used in both formal and informal contexts","connotation":"positive","commonMistakes":"Learners might confuse this idiom with simply doing something differently, but it specifically implies innovation and originality, not just any change.","canStandAlone":false},"examples":[{"simplified":"这位艺术家的作品别开生面，令人耳目一新。","english":"The artist's work breaks new ground, offering a refreshing experience.","traditional":"這位藝術家的作品別開生面，令人耳目一新。"},{"simplified":"他的设计别开生面，获得了许多赞赏。","english":"His design was innovative and received much praise.","traditional":"他的設計別開生面，獲得了許多讚賞。"}],"synonyms":["独辟蹊径","标新立异"],"antonyms":["墨守成规"],"confusedWith":[{"id":"标新立异","note":"While both imply originality, 标新立异 often emphasizes being unconventional, whereas 别开生面 focuses on innovation and creating something new."}],"traditional":"別開生面","pinyinOverride":null},{"id":"bie-you-dong-tian","simplified":"别有洞天","literalMeaning":"another has cave heaven","figurativeMeaning":"a completely different world; a hidden paradise","englishEquivalents":["a hidden gem","a world of its own"],"shortGloss":"a hidden paradise","characters":[{"char":"别","meaning":"another; different"},{"char":"有","meaning":"have; there is"},{"char":"洞","meaning":"cave; hole"},{"char":"天","meaning":"heaven; sky"}],"origin":{"period":"Tang Dynasty (618–907)","sourceText":"《酉阳杂俎》","sourceTextEnglish":"Youyang Zazu","originalExcerpt":"别有洞天，不可具状。","storyEnglish":"The phrase '别有洞天' originates from the Tang Dynasty text 'Youyang Zazu' by Duan Chengshi. It describes a scene where a seemingly ordinary place reveals a hidden, breathtaking world, akin to a paradise. This expression has since been used to describe places or situations that are unexpectedly beautiful or extraordinary.","historicalFigures":["Duan Chengshi"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"modifier-head","register":"literary, but widely used in both written and spoken Chinese","connotation":"positive","commonMistakes":"Learners might confuse this idiom with similar expressions that describe beauty, but '别有洞天' specifically emphasizes the hidden or unexpected nature of the beauty.","canStandAlone":false},"examples":[{"simplified":"这座小岛真是别有洞天，风景如画。","english":"This small island is truly a hidden paradise, with picturesque scenery.","traditional":"這座小島真是別有洞天，風景如畫。"},{"simplified":"走进这个古老的庭院，仿佛进入了一个别有洞天的世界。","english":"Walking into this ancient courtyard feels like entering a world of its own.","traditional":"走進這個古老的庭院，彷彿進入了一個別有洞天的世界。"}],"synonyms":["柳暗花明","世外桃源"],"antonyms":[],"confusedWith":[{"id":"世外桃源","note":"While both describe idyllic places, '世外桃源' refers to an idealized utopia, whereas '别有洞天' emphasizes the hidden or unexpected nature of the beauty."}],"traditional":"別有洞天","pinyinOverride":null},{"id":"bie-you-tian-di","simplified":"别有天地","literalMeaning":"there is another world","figurativeMeaning":"a completely different world or realm; a unique or special place","englishEquivalents":["a world of its own","a different world"],"shortGloss":"a unique or special place","characters":[{"char":"别","meaning":"another, different"},{"char":"有","meaning":"have, there is"},{"char":"天","meaning":"heaven, sky, world"},{"char":"地","meaning":"earth, ground, place"}],"origin":{"period":"Tang Dynasty (618–907 CE)","sourceText":"《桃花源记》","sourceTextEnglish":"Record of the Peach Blossom Spring","originalExcerpt":"林尽水源，便得一山，山有小口，仿佛若有光。便舍船，从口入。初极狭，才通人。复行数十步，豁然开朗。土地平旷，屋舍俨然，有良田美池桑竹之属。阡陌交通，鸡犬相闻。其中往来种作，男女衣着，悉如外人。黄发垂髫，并怡然自乐。","storyEnglish":"The idiom originates from the famous fable 'Record of the Peach Blossom Spring' by Tao Yuanming. In the story, a fisherman accidentally discovers a hidden utopia where people live in harmony with nature, untouched by the outside world. This place is described as a completely different world, separate from the troubles of society.","historicalFigures":["Tao Yuanming"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","object","attributive"],"structure":"modifier-head","register":"literary, but used in both written and spoken Chinese to describe unique places","connotation":"positive","commonMistakes":"Learners may confuse this idiom with expressions meaning 'another world' in a more literal sense, but it specifically refers to a place that feels unique or special, often in a positive way.","canStandAlone":false},"examples":[{"simplified":"这座古老的花园真是别有天地，让人流连忘返。","english":"This ancient garden is truly a world of its own, making people reluctant to leave.","traditional":"這座古老的花園真是別有天地，讓人流連忘返。"},{"simplified":"他的新家布置得别有天地，充满了艺术气息。","english":"His new home is uniquely decorated, full of artistic flair.","traditional":"他的新家佈置得別有天地，充滿了藝術氣息。"}],"synonyms":["别有洞天"],"antonyms":[],"confusedWith":[{"id":"别有洞天","note":"Both idioms describe unique or special places, but 别有洞天 often emphasizes a hidden or unexpected aspect."}],"traditional":"別有天地","pinyinOverride":null},{"id":"bie-you-yong-xin","simplified":"别有用心","literalMeaning":"have a different intention","figurativeMeaning":"to have an ulterior motive","englishEquivalents":["have an axe to grind","hidden agenda"],"shortGloss":"ulterior motive","characters":[{"char":"别","meaning":"different"},{"char":"有","meaning":"have"},{"char":"用","meaning":"use"},{"char":"心","meaning":"heart; intention"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '别有用心' is often used to describe someone who appears to have a hidden agenda or ulterior motive. It suggests that the person's true intentions are not what they seem on the surface, and they may be acting with self-interest or deceit.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"modifier-head","register":"commonly used in both formal and informal contexts","connotation":"negative","commonMistakes":"Learners often confuse '别有用心' with neutral expressions of having a different opinion or approach. However, this idiom specifically implies deceit or hidden motives.","canStandAlone":false},"examples":[{"simplified":"他的话听起来很诚恳，但我觉得他别有用心。","english":"His words sounded sincere, but I think he has an ulterior motive.","traditional":"他的話聽起來很誠懇，但我覺得他別有用心。"},{"simplified":"在这次谈判中，他的行为让人怀疑他是否别有用心。","english":"During the negotiation, his behavior made people suspect he might have a hidden agenda.","traditional":"在這次談判中，他的行為讓人懷疑他是否別有用心。"}],"synonyms":["图谋不轨","心怀鬼胎"],"antonyms":["光明磊落"],"confusedWith":[{"id":"别具一格","note":"别具一格 means 'unique style' and does not carry the negative connotation of hidden motives."}],"traditional":"別有用心","pinyinOverride":null},{"id":"bing-qing-yu-jie","simplified":"冰清玉洁","literalMeaning":"ice clear jade pure","figurativeMeaning":"pure and noble; morally upright and untainted","englishEquivalents":["pure as the driven snow","spotless reputation"],"shortGloss":"pure and noble","characters":[{"char":"冰","meaning":"ice; symbolizes clarity and purity"},{"char":"清","meaning":"clear; denotes transparency and cleanliness"},{"char":"玉","meaning":"jade; represents purity and nobility"},{"char":"洁","meaning":"pure; indicates cleanliness and integrity"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom 冰清玉洁 is often used to describe someone with a pure and noble character, akin to the clarity of ice and the purity of jade. It is frequently applied to individuals who are morally upright and maintain a spotless reputation, free from corruption or moral blemish.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["attributive","predicate"],"structure":"coordinate","register":"literary, but widely understood and used in both formal and informal contexts","connotation":"positive","commonMistakes":"Learners might confuse 冰清玉洁 with idioms that describe physical cleanliness rather than moral purity. It's important to remember this idiom is about character, not physical attributes.","canStandAlone":false},"examples":[{"simplified":"她的品德冰清玉洁，令人敬佩。","english":"Her character is pure and noble, earning everyone's admiration.","traditional":"她的品德冰清玉潔，令人敬佩。"},{"simplified":"在这个腐败的时代，他依然保持着冰清玉洁的品质。","english":"In this corrupt era, he still maintains a pure and noble quality.","traditional":"在這個腐敗的時代，他依然保持著冰清玉潔的品質。"}],"synonyms":["洁身自好","清白无辜"],"antonyms":["卑鄙无耻"],"confusedWith":[{"id":"洁白无瑕","note":"洁白无瑕 focuses more on physical purity or flawlessness, while 冰清玉洁 emphasizes moral purity."}],"traditional":"冰清玉潔","pinyinOverride":null},{"id":"bing-xiao-wa-jie","simplified":"冰消瓦解","literalMeaning":"ice melts, tiles disintegrate","figurativeMeaning":"to collapse or disintegrate completely","englishEquivalents":["fall apart","come to nothing"],"shortGloss":"to disintegrate completely","characters":[{"char":"冰","meaning":"ice"},{"char":"消","meaning":"melt"},{"char":"瓦","meaning":"tiles"},{"char":"解","meaning":"disintegrate"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '冰消瓦解' is used to describe a situation where something collapses or disintegrates completely, much like how ice melts away and tiles crumble. It is often used to refer to the dissolution of organizations, plans, or structures.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"coordinate","register":"literary, but commonly used in both written and spoken Chinese","connotation":"negative","commonMistakes":"Learners often confuse this idiom with similar expressions that imply gradual change rather than complete collapse. It's important to note that '冰消瓦解' emphasizes a total disintegration.","canStandAlone":false},"examples":[{"simplified":"经过多次失败后，他们的计划终于冰消瓦解。","english":"After multiple failures, their plan finally fell apart.","traditional":"經過多次失敗後，他們的計劃終於冰消瓦解。"},{"simplified":"在强大的压力下，敌人的防线冰消瓦解。","english":"Under immense pressure, the enemy's defense line disintegrated completely.","traditional":"在強大的壓力下，敵人的防線冰消瓦解。"}],"synonyms":["土崩瓦解","烟消云散"],"antonyms":[],"confusedWith":[{"id":"烟消云散","note":"While both idioms describe disappearance, '烟消云散' often implies fading away like smoke or clouds, rather than a structural collapse."}],"traditional":"冰消瓦解","pinyinOverride":null},{"id":"bing-bu-xue-ren","simplified":"兵不血刃","literalMeaning":"troops do not stain blades with blood","figurativeMeaning":"to win a battle or achieve a victory without bloodshed; to achieve success effortlessly","englishEquivalents":["win without a fight","bloodless victory"],"shortGloss":"win without bloodshed","characters":[{"char":"兵","meaning":"troops, soldiers"},{"char":"不","meaning":"not"},{"char":"血","meaning":"blood"},{"char":"刃","meaning":"blade, edge"}],"origin":{"period":"Warring States period (475–221 BCE)","sourceText":"《战国策·齐策四》","sourceTextEnglish":"Strategies of the Warring States, Strategies of Qi, Chapter 4","originalExcerpt":"兵不接刃，齐师已败。","storyEnglish":"The phrase comes from a story in the 'Strategies of the Warring States', where a strategist describes a situation in which the Qi army was defeated without the need for direct combat. The enemy's strategic maneuvers and psychological tactics led to victory without any bloodshed, highlighting the power of strategy over brute force.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"modifier-head","register":"literary, but understood and sometimes used in formal speech","connotation":"positive","commonMistakes":"Learners sometimes confuse this idiom with those that imply a hard-fought victory. It specifically refers to achieving success without conflict or bloodshed.","canStandAlone":false},"examples":[{"simplified":"通过谈判，我们兵不血刃地解决了争端。","english":"Through negotiations, we resolved the dispute without bloodshed.","traditional":"通過談判，我們兵不血刃地解決了爭端。"},{"simplified":"他用巧妙的策略，让对手兵不血刃地认输。","english":"He used clever strategies to make his opponent concede without a fight.","traditional":"他用巧妙的策略，讓對手兵不血刃地認輸。"}],"synonyms":["不战而胜"],"antonyms":["血流成河"],"confusedWith":[{"id":"血流成河","note":"血流成河 describes a situation with heavy casualties, the opposite of 兵不血刃."}],"traditional":"兵不血刃","pinyinOverride":null},{"id":"bing-bu-yan-zha","simplified":"兵不厌诈","literalMeaning":"soldiers do not dislike deceit","figurativeMeaning":"in war, deception is acceptable; all's fair in love and war","englishEquivalents":["All's fair in love and war","By any means necessary"],"shortGloss":"deception is fair in war","characters":[{"char":"兵","meaning":"soldiers; military"},{"char":"不","meaning":"do not"},{"char":"厌","meaning":"dislike; detest"},{"char":"诈","meaning":"deceit; trickery"}],"origin":{"period":"Warring States period (475–221 BCE)","sourceText":"《韩非子·难一》","sourceTextEnglish":"Han Feizi, Difficulties, Part 1","originalExcerpt":"兵者，诡道也，故不厌诈。","storyEnglish":"The idiom originates from the teachings of Han Feizi, a philosopher during the Warring States period. In his writings, he emphasized the importance of strategy and deception in warfare. The phrase suggests that in the context of war, using deceitful tactics is not only acceptable but expected, as it can lead to victory.","historicalFigures":["Han Feizi"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"subject-predicate","register":"literary, but widely understood and used in ordinary speech","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with others that involve deceit but in non-warfare contexts, such as in personal relationships or business, where the connotation might be more negative.","canStandAlone":false},"examples":[{"simplified":"在战争中，兵不厌诈是常见的策略。","english":"In war, using deception is a common strategy.","traditional":"在戰爭中，兵不厭詐是常見的策略。"},{"simplified":"他在比赛中使用了兵不厌诈的策略，最终赢得了胜利。","english":"He used deceptive tactics in the competition and ultimately won.","traditional":"他在比賽中使用了兵不厭詐的策略，最終贏得了勝利。"}],"synonyms":[],"antonyms":[],"confusedWith":[{"id":"尔虞我诈","note":"尔虞我诈 refers to mutual deception, often in a negative context, while 兵不厌诈 is specific to warfare."}],"traditional":"兵不厭詐","pinyinOverride":null},{"id":"bing-gui-shen-su","simplified":"兵贵神速","literalMeaning":"troops value divine speed","figurativeMeaning":"in military operations, speed is of the essence","englishEquivalents":["strike while the iron is hot","time is of the essence"],"shortGloss":"speed is crucial in military action","characters":[{"char":"兵","meaning":"troops; military"},{"char":"贵","meaning":"value; emphasize"},{"char":"神","meaning":"divine; miraculous"},{"char":"速","meaning":"speed; quickness"}],"origin":{"period":"Han Dynasty (206 BCE – 220 CE)","sourceText":"《汉书·艺文志》","sourceTextEnglish":"Book of Han, Treatise on Literature","originalExcerpt":"兵贵神速者，谓其出奇制胜也。","storyEnglish":"The idiom originates from the 'Book of Han', which emphasizes the importance of speed in military strategy. The idea is that swift actions can surprise the enemy and lead to victory. In military contexts, being able to act quickly and decisively is often more valuable than sheer numbers or strength.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"subject-predicate","register":"formal written Chinese, but also used in speech to emphasize urgency","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with others that emphasize speed without the military context. It's important to note that this idiom specifically refers to the strategic advantage of speed in military operations.","canStandAlone":false},"examples":[{"simplified":"在战场上，兵贵神速，拖延只会导致失败。","english":"On the battlefield, speed is of the essence; delays will only lead to failure.","traditional":"在戰場上，兵貴神速，拖延只會導致失敗。"},{"simplified":"这次行动必须迅速完成，因为兵贵神速。","english":"This operation must be completed quickly because speed is crucial.","traditional":"這次行動必須迅速完成，因為兵貴神速。"}],"synonyms":["速战速决"],"antonyms":[],"confusedWith":[{"id":"速战速决","note":"While both emphasize speed, 速战速决 focuses on quickly resolving a conflict, not necessarily in a military context."}],"traditional":"兵貴神速","pinyinOverride":null},{"id":"bing-lin-cheng-xia","simplified":"兵临城下","literalMeaning":"troops approach the city walls","figurativeMeaning":"imminent danger or crisis; a situation where a threat is very close","englishEquivalents":["the enemy is at the gates","on the brink of disaster"],"shortGloss":"imminent danger or crisis","characters":[{"char":"兵","meaning":"troops"},{"char":"临","meaning":"approach"},{"char":"城","meaning":"city"},{"char":"下","meaning":"below; at the foot of"}],"origin":{"period":"Three Kingdoms period (220–280 CE)","sourceText":"《三国志·魏书·武帝纪》","sourceTextEnglish":"Records of the Three Kingdoms, Book of Wei, Annals of Emperor Wu","originalExcerpt":"兵临城下，城中人心惶惶。","storyEnglish":"During the Three Kingdoms period, the phrase '兵临城下' was used to describe situations where enemy forces were threateningly close to a city, causing panic among its inhabitants. This phrase vividly captures the urgency and fear of an impending attack.","historicalFigures":["Cao Cao"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"subject-predicate","register":"widely used in both formal and informal contexts","connotation":"negative","commonMistakes":"Learners often confuse this idiom with similar expressions that describe general danger, but '兵临城下' specifically implies an immediate and severe threat. It should not be used for minor or distant problems.","canStandAlone":false},"examples":[{"simplified":"随着敌军的逼近，城市已经是兵临城下。","english":"As the enemy forces approached, the city was already on the brink of disaster.","traditional":"隨著敵軍的逼近，城市已經是兵臨城下。"},{"simplified":"我们必须立即采取行动，因为现在是兵临城下的时刻。","english":"We must take immediate action because we are now at a critical moment of imminent danger.","traditional":"我們必須立即採取行動，因為現在是兵臨城下的時刻。"}],"synonyms":["危在旦夕"],"antonyms":[],"confusedWith":[{"id":"岌岌可危","note":"While both idioms imply danger, '岌岌可危' refers to a precarious situation that may not be immediate, whereas '兵临城下' suggests an imminent threat."}],"traditional":"兵臨城下","pinyinOverride":null},{"id":"bing-rong-xiang-jian","simplified":"兵戎相见","literalMeaning":"weapons meet each other","figurativeMeaning":"to meet on the battlefield; to engage in armed conflict","englishEquivalents":["to go to war","to clash in battle"],"shortGloss":"to engage in armed conflict","characters":[{"char":"兵","meaning":"soldiers; military"},{"char":"戎","meaning":"weapons; arms"},{"char":"相","meaning":"mutually; each other"},{"char":"见","meaning":"to meet; to encounter"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '兵戎相见' is used to describe a situation where two parties engage in armed conflict or war. It conveys the idea of meeting on the battlefield with weapons, signifying the start of hostilities. The phrase is often used in historical texts and discussions of war.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"formal written Chinese, often used in historical or military contexts","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with phrases that mean 'to argue' or 'to have a conflict' without physical confrontation. '兵戎相见' specifically implies armed conflict.","canStandAlone":false},"examples":[{"simplified":"两国关系紧张，最终兵戎相见。","english":"The relations between the two countries were tense, and they eventually went to war.","traditional":"兩國關係緊張，最終兵戎相見。"},{"simplified":"在谈判失败后，双方决定兵戎相见。","english":"After the negotiations failed, both sides decided to engage in armed conflict.","traditional":"在談判失敗後，雙方決定兵戎相見。"}],"synonyms":["刀光剑影"],"antonyms":["化干戈为玉帛"],"confusedWith":[{"id":"争论不休","note":"This idiom means 'to argue endlessly' and does not imply physical conflict, unlike '兵戎相见'."}],"traditional":"兵戎相見","pinyinOverride":null},{"id":"bing-huang-ma-luan","simplified":"兵荒马乱","literalMeaning":"soldiers in disarray, horses in chaos","figurativeMeaning":"a time of chaos and disorder, often due to war or conflict","englishEquivalents":["in turmoil","in chaos","in a state of upheaval"],"shortGloss":"chaotic and tumultuous times","characters":[{"char":"兵","meaning":"soldiers"},{"char":"荒","meaning":"in disarray"},{"char":"马","meaning":"horses"},{"char":"乱","meaning":"in chaos"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '兵荒马乱' describes a chaotic and tumultuous situation, often associated with times of war or conflict. The imagery of soldiers in disarray and horses in chaos vividly conveys the disorder and confusion that can arise during such periods. It is commonly used to describe any situation that is marked by turmoil and lack of order.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["adverbial","attributive"],"structure":"coordinate","register":"commonly used in both written and spoken Chinese to describe chaotic situations","connotation":"negative","commonMistakes":"Learners might confuse this idiom with similar expressions that describe chaos but lack the specific connotation of war or conflict-related disorder. It should not be used to describe minor or everyday chaos.","canStandAlone":false},"examples":[{"simplified":"在那个兵荒马乱的年代，人们的生活非常艰难。","english":"During those chaotic times, people's lives were very difficult.","traditional":"在那個兵荒馬亂的年代，人們的生活非常艱難。"},{"simplified":"战争结束后，城市逐渐从兵荒马乱中恢复过来。","english":"After the war ended, the city gradually recovered from the chaos.","traditional":"戰爭結束後，城市逐漸從兵荒馬亂中恢復過來。"}],"synonyms":["狼烟四起","动荡不安"],"antonyms":["安居乐业","风平浪静"],"confusedWith":[{"id":"狼烟四起","note":"Both describe chaotic situations, but '狼烟四起' specifically refers to the outbreak of war."}],"traditional":"兵荒馬亂","pinyinOverride":null},{"id":"bing-lian-huo-jie","simplified":"兵连祸结","literalMeaning":"wars continue, disasters accumulate","figurativeMeaning":"a continuous series of disasters or misfortunes","englishEquivalents":["one misfortune after another","trouble comes in threes"],"shortGloss":"continuous disasters and misfortunes","characters":[{"char":"兵","meaning":"war"},{"char":"连","meaning":"continue"},{"char":"祸","meaning":"disaster"},{"char":"结","meaning":"accumulate"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '兵连祸结' describes a situation where one disaster follows another, often in the context of wars or conflicts leading to further calamities. It is used to express the feeling of being overwhelmed by continuous misfortunes.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"coordinate","register":"formal written Chinese, but can appear in speech when discussing serious topics","connotation":"negative","commonMistakes":"Learners might confuse this idiom with others that describe a single disaster or event. It specifically refers to a series of ongoing troubles, not just one.","canStandAlone":false},"examples":[{"simplified":"最近几年，这个国家兵连祸结，人民生活十分艰难。","english":"In recent years, this country has faced continuous disasters, and the people's lives are very difficult.","traditional":"最近幾年，這個國家兵連禍結，人民生活十分艱難。"},{"simplified":"公司管理不善，导致兵连祸结，员工士气低落。","english":"Poor management in the company has led to a series of disasters, and employee morale is low.","traditional":"公司管理不善，導致兵連禍結，員工士氣低落。"}],"synonyms":["祸不单行"],"antonyms":[],"confusedWith":[{"id":"祸不单行","note":"Both describe multiple disasters, but '祸不单行' emphasizes that disasters do not come alone, while '兵连祸结' suggests a continuous series."}],"traditional":"兵連禍結","pinyinOverride":null},{"id":"bing-qiang-ma-zhuang","simplified":"兵强马壮","literalMeaning":"soldiers strong, horses robust","figurativeMeaning":"a powerful and well-equipped army","englishEquivalents":["a formidable force","a strong military presence"],"shortGloss":"a powerful and well-equipped army","characters":[{"char":"兵","meaning":"soldiers"},{"char":"强","meaning":"strong"},{"char":"马","meaning":"horses"},{"char":"壮","meaning":"robust"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '兵强马壮' describes a situation where an army is well-prepared, with strong soldiers and robust horses, indicating a formidable military force. It is often used to describe a powerful and well-equipped army ready for battle.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"coordinate","register":"commonly used in both formal and informal contexts","connotation":"positive","commonMistakes":"Learners might confuse this idiom with others that describe strength but do not specifically refer to military power. It is important to use it in contexts related to military or organizational strength.","canStandAlone":false},"examples":[{"simplified":"这支军队兵强马壮，敌人不敢轻易进攻。","english":"This army is powerful and well-equipped, so the enemy does not dare to attack easily.","traditional":"這支軍隊兵強馬壯，敵人不敢輕易進攻。"},{"simplified":"公司现在兵强马壮，能够应对任何挑战。","english":"The company is now strong and well-prepared, able to face any challenge.","traditional":"公司現在兵強馬壯，能夠應對任何挑戰。"}],"synonyms":["军威壮盛"],"antonyms":["兵微将寡"],"confusedWith":[{"id":"强兵富国","note":"While both idioms involve strength, '强兵富国' emphasizes national prosperity along with military strength."}],"traditional":"兵強馬壯","pinyinOverride":null},{"id":"bing-gong-ban-li","simplified":"秉公办理","literalMeaning":"handle impartially and justly","figurativeMeaning":"to handle affairs impartially and justly","englishEquivalents":["deal with fairly","act with impartiality"],"shortGloss":"handle impartially and justly","characters":[{"char":"秉","meaning":"hold"},{"char":"公","meaning":"impartiality; fairness"},{"char":"办","meaning":"handle; manage"},{"char":"理","meaning":"manage; handle"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '秉公办理' is used to describe the act of handling matters with fairness and impartiality. It emphasizes the importance of not letting personal biases or external influences affect one's judgment. The phrase is often used in contexts where justice and fairness are paramount, such as in legal or administrative settings.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"common in both formal and informal contexts, especially in discussions about fairness and justice","connotation":"positive","commonMistakes":"Learners might confuse this idiom with similar expressions that imply fairness but lack the emphasis on impartiality. It's important to note that '秉公办理' specifically stresses the absence of bias.","canStandAlone":false},"examples":[{"simplified":"法官在审理案件时必须秉公办理。","english":"A judge must handle cases impartially and justly.","traditional":"法官在審理案件時必須秉公辦理。"},{"simplified":"在处理公司内部纠纷时，管理层需要秉公办理。","english":"When dealing with internal company disputes, management needs to act impartially and justly.","traditional":"在處理公司內部糾紛時，管理層需要秉公辦理。"}],"synonyms":[],"antonyms":[],"confusedWith":[],"traditional":"秉公辦理","pinyinOverride":null},{"id":"bing-jia-qi-qu","simplified":"并驾齐驱","literalMeaning":"side by side, equal speed","figurativeMeaning":"to keep pace with; to be on par with","englishEquivalents":["neck and neck","on an equal footing"],"shortGloss":"to keep pace with","characters":[{"char":"并","meaning":"side by side"},{"char":"驾","meaning":"to drive (a carriage)"},{"char":"齐","meaning":"equal"},{"char":"驱","meaning":"to drive (a horse)"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '并驾齐驱' is believed to have originated from the imagery of two horses pulling a carriage side by side at the same speed, symbolizing two entities moving forward together at an equal pace. This imagery is often used to describe situations where two parties or competitors are equally matched in skill, ability, or progress.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"coordinate","register":"commonly used in both written and spoken Chinese","connotation":"neutral","commonMistakes":"Learners often confuse this idiom with '齐头并进', which also means to advance together but emphasizes simultaneous progress rather than equal ability or status.","canStandAlone":false},"examples":[{"simplified":"这两家公司在技术上并驾齐驱。","english":"These two companies are neck and neck in terms of technology.","traditional":"這兩家公司在技術上並駕齊驅。"},{"simplified":"在比赛中，他们一直并驾齐驱，直到最后一刻。","english":"In the race, they kept pace with each other until the very last moment.","traditional":"在比賽中，他們一直並駕齊驅，直到最後一刻。"}],"synonyms":["齐头并进"],"antonyms":[],"confusedWith":[{"id":"齐头并进","note":"齐头并进 emphasizes simultaneous progress, while 并驾齐驱 emphasizes equal ability or status."}],"traditional":"並駕齊驅","pinyinOverride":null},{"id":"bing-bing-wai-wai","simplified":"病病歪歪","literalMeaning":"sick sick crooked crooked","figurativeMeaning":"to be in poor health or appear weak and feeble","englishEquivalents":["sickly","frail","in poor health"],"shortGloss":"weak and feeble in health","characters":[{"char":"病","meaning":"sick"},{"char":"病","meaning":"sick"},{"char":"歪","meaning":"crooked"},{"char":"歪","meaning":"crooked"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom 病病歪歪 is used to describe someone who appears to be in poor health, often looking weak and feeble. It is a descriptive phrase that conveys the image of someone who is not only sick but also physically unsteady or frail.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"AABB","register":"informal, commonly used in spoken Chinese to describe someone's health condition","connotation":"negative","commonMistakes":"Learners might confuse this idiom with other expressions related to illness, but 病病歪歪 specifically emphasizes both sickness and physical frailty. It is not used for temporary conditions like a cold.","canStandAlone":false},"examples":[{"simplified":"他最近病病歪歪的，看起来很虚弱。","english":"He has been looking sickly and weak recently.","traditional":"他最近病病歪歪的，看起來很虛弱。"},{"simplified":"这个老人家病病歪歪的，需要人照顾。","english":"This elderly person is frail and needs care.","traditional":"這個老人家病病歪歪的，需要人照顧。"}],"synonyms":["体弱多病"],"antonyms":["身体健康"],"confusedWith":[{"id":"病怏怏","note":"病怏怏 also describes being sickly, but it emphasizes a lack of energy rather than physical frailty."}],"traditional":"病病歪歪","pinyinOverride":null},{"id":"bing-cong-kou-ru","simplified":"病从口入","literalMeaning":"illness enters through the mouth","figurativeMeaning":"disease often comes from what we eat or drink; be cautious about what you consume","englishEquivalents":["You are what you eat","An ounce of prevention is worth a pound of cure"],"shortGloss":"illness comes from what you consume","characters":[{"char":"病","meaning":"illness"},{"char":"从","meaning":"from"},{"char":"口","meaning":"mouth"},{"char":"入","meaning":"enter"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '病从口入' is a traditional saying that emphasizes the importance of being cautious about what one eats and drinks. It suggests that many illnesses are caused by consuming contaminated or unhealthy food and beverages. This saying is often used to remind people to maintain good hygiene and be mindful of their diet to prevent diseases.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["subject","predicate"],"structure":"subject-predicate","register":"commonly used in both spoken and written Chinese, often in health-related contexts","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with those that emphasize the importance of speech, due to the character '口' (mouth). However, this idiom specifically refers to the intake of food and drink, not speech.","canStandAlone":true},"examples":[{"simplified":"医生提醒我们，病从口入，所以要注意饮食卫生。","english":"The doctor reminded us that illness enters through the mouth, so we should pay attention to food hygiene.","traditional":"醫生提醒我們，病從口入，所以要注意飲食衛生。"},{"simplified":"为了避免疾病，我们应该牢记病从口入的道理。","english":"To avoid illness, we should remember the principle that disease enters through the mouth.","traditional":"為了避免疾病，我們應該牢記病從口入的道理。"}],"synonyms":[],"antonyms":[],"confusedWith":[{"id":"祸从口出","note":"While '病从口入' refers to illness from food, '祸从口出' means trouble comes from speaking carelessly."}],"traditional":"病從口入","pinyinOverride":null},{"id":"bo-luan-fan-zheng","simplified":"拨乱反正","literalMeaning":"rectify chaos and restore order","figurativeMeaning":"to bring order out of chaos; to set things right","englishEquivalents":["restore order","set things right"],"shortGloss":"restore order from chaos","characters":[{"char":"拨","meaning":"rectify"},{"char":"乱","meaning":"chaos"},{"char":"反","meaning":"return to"},{"char":"正","meaning":"order"}],"origin":{"period":"Han Dynasty (206 BCE – 220 CE)","sourceText":"《汉书·贾谊传》","sourceTextEnglish":"Book of Han, Biography of Jia Yi","originalExcerpt":"拨乱世，反诸正。","storyEnglish":"The idiom originates from the 'Book of Han', where it describes the efforts of Jia Yi, a prominent statesman and thinker, who advocated for policies to rectify the chaos and restore order during a tumultuous period in the Han Dynasty. Jia Yi's ideas were aimed at stabilizing the government and society by returning to proper governance and moral principles.","historicalFigures":["Jia Yi"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","object"],"structure":"verb-object","register":"literary, but can be used in formal speech and writing","connotation":"positive","commonMistakes":"Learners may confuse this idiom with ones that imply creating chaos rather than resolving it. It's important to remember that this idiom is about restoring order, not causing disorder.","canStandAlone":false},"examples":[{"simplified":"在经历了一段动荡时期后，国家需要拨乱反正。","english":"After a period of turmoil, the country needs to restore order.","traditional":"在經歷了一段動盪時期後，國家需要撥亂反正。"},{"simplified":"新的领导者上任后，立即采取措施拨乱反正。","english":"After the new leader took office, they immediately took measures to set things right.","traditional":"新的領導者上任後，立即採取措施撥亂反正。"}],"synonyms":["整顿乾坤"],"antonyms":["兴风作浪"],"confusedWith":[{"id":"兴风作浪","note":"兴风作浪 means to create chaos, which is the opposite of restoring order."}],"traditional":"撥亂反正","pinyinOverride":null},{"id":"bing-ru-gao-huang","simplified":"病入膏肓","literalMeaning":"illness enters the fat and diaphragm","figurativeMeaning":"a situation or condition that is beyond cure or remedy","englishEquivalents":["beyond cure","past the point of no return"],"shortGloss":"beyond cure or remedy","characters":[{"char":"病","meaning":"illness"},{"char":"入","meaning":"enters"},{"char":"膏","meaning":"fat"},{"char":"肓","meaning":"diaphragm"}],"origin":{"period":"Spring and Autumn period (770–476 BCE)","sourceText":"《左传·成公十年》","sourceTextEnglish":"Zuo Zhuan, 10th Year of Duke Cheng","originalExcerpt":"疾不可为也，已入膏肓。","storyEnglish":"The idiom originates from the 'Zuo Zhuan', an ancient Chinese historical text. It tells the story of Duke Jing of Jin, who fell seriously ill. His physician, after examining him, declared that the illness had reached the 'gao huang', a part of the body that was considered untreatable. This phrase came to symbolize situations that are beyond remedy.","historicalFigures":["Duke Jing of Jin"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","complement"],"structure":"subject-predicate","register":"literary, but widely understood and used in both formal and informal contexts","connotation":"negative","commonMistakes":"Learners often confuse this idiom with phrases that mean 'seriously ill' but not necessarily 'beyond cure'. It's important to note that this idiom implies a hopeless situation.","canStandAlone":false},"examples":[{"simplified":"他的病已经病入膏肓，医生们也无能为力。","english":"His illness has reached a point beyond cure, and even the doctors are helpless.","traditional":"他的病已經病入膏肓，醫生們也無能為力。"},{"simplified":"这个项目的失败已经病入膏肓，没有挽回的余地。","english":"The failure of this project is beyond remedy, with no chance of recovery.","traditional":"這個項目的失敗已經病入膏肓，沒有挽回的餘地。"}],"synonyms":["无可救药"],"antonyms":[],"confusedWith":[{"id":"病入骨髓","note":"While 病入骨髓 also describes a severe condition, it doesn't necessarily imply that it's beyond cure, unlike 病入膏肓."}],"traditional":"病入膏肓","pinyinOverride":null},{"id":"bo-yun-jian-ri","simplified":"拨云见日","literalMeaning":"part the clouds and see the sun","figurativeMeaning":"to see the light; to gain clarity after confusion","englishEquivalents":["see the light","clear the fog","a moment of clarity"],"shortGloss":"gain clarity after confusion","characters":[{"char":"拨","meaning":"part; push aside"},{"char":"云","meaning":"clouds"},{"char":"见","meaning":"see"},{"char":"日","meaning":"sun"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '拨云见日' is used to describe a situation where confusion or difficulties are cleared away, allowing one to see the truth or understand a situation clearly. It evokes the image of clouds parting to reveal the sun, symbolizing the dispelling of doubts or obstacles.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"commonly used in both spoken and written Chinese","connotation":"positive","commonMistakes":"Learners might confuse this idiom with similar expressions that involve clouds or clarity, but '拨云见日' specifically implies overcoming confusion to gain understanding, rather than simply clearing away physical obstacles.","canStandAlone":false},"examples":[{"simplified":"经过老师的解释，我终于拨云见日，明白了这个难题。","english":"After the teacher's explanation, I finally saw the light and understood the difficult problem.","traditional":"經過老師的解釋，我終於撥雲見日，明白了這個難題。"},{"simplified":"他的建议让我拨云见日，看清了事情的真相。","english":"His advice helped me see the light and understand the truth of the situation.","traditional":"他的建議讓我撥雲見日，看清了事情的真相。"}],"synonyms":["豁然开朗"],"antonyms":["迷雾重重"],"confusedWith":[{"id":"云开见日","note":"This phrase also means seeing clarity, but '拨云见日' emphasizes the action of actively clearing away confusion."}],"traditional":"撥雲見日","pinyinOverride":null},{"id":"bo-lan-zhuang-kuo","simplified":"波澜壮阔","literalMeaning":"waves vast and mighty","figurativeMeaning":"magnificent and impressive; grand and majestic","englishEquivalents":["grand and majestic","magnificent and impressive"],"shortGloss":"grand and majestic","characters":[{"char":"波","meaning":"waves"},{"char":"澜","meaning":"billows"},{"char":"壮","meaning":"magnificent"},{"char":"阔","meaning":"vast"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '波澜壮阔' is often used to describe scenes or events that are grand and majestic, much like the vast and powerful waves of the ocean. It is commonly used in literature and speeches to convey the grandeur of a movement or the magnificence of a landscape.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["attributive","predicate"],"structure":"coordinate","register":"literary, but widely used in both written and spoken Chinese","connotation":"positive","commonMistakes":"Learners often confuse this idiom with similar ones that describe grandeur but may not convey the same sense of dynamic power and movement. It's important to use it in contexts that truly reflect majesty and expansiveness.","canStandAlone":false},"examples":[{"simplified":"这部电影的场景波澜壮阔，让人叹为观止。","english":"The scenes in this movie are grand and majestic, leaving people in awe.","traditional":"這部電影的場景波瀾壯闊，讓人歎為觀止。"},{"simplified":"他的演讲波澜壮阔，激励了在场的每一个人。","english":"His speech was grand and majestic, inspiring everyone present.","traditional":"他的演講波瀾壯闊，激勵了在場的每一個人。"}],"synonyms":["气势磅礴"],"antonyms":["平淡无奇"],"confusedWith":[{"id":"气势磅礴","note":"Both describe grandeur, but '气势磅礴' emphasizes imposing momentum and force, while '波澜壮阔' suggests a majestic and expansive quality."}],"traditional":"波瀾壯闊","pinyinOverride":null},{"id":"bo-tao-xiong-yong","simplified":"波涛汹涌","literalMeaning":"waves and billows surge violently","figurativeMeaning":"a situation full of unrest or turmoil","englishEquivalents":["turbulent times","stormy seas","a rough patch"],"shortGloss":"turbulent and chaotic","characters":[{"char":"波","meaning":"waves"},{"char":"涛","meaning":"billows"},{"char":"汹","meaning":"fierce"},{"char":"涌","meaning":"surge"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '波涛汹涌' is often used to describe situations that are chaotic or full of turmoil, much like a stormy sea with high waves and billows. It is not tied to a specific classical text but rather has evolved in the language to capture the essence of turbulent circumstances.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"modifier-head","register":"commonly used in both written and spoken Chinese to describe chaotic or turbulent situations","connotation":"negative","commonMistakes":"Learners might confuse this idiom with ones that describe literal water conditions. It is important to remember that '波涛汹涌' is metaphorical and often used for non-literal, chaotic situations.","canStandAlone":false},"examples":[{"simplified":"最近的经济形势波涛汹涌，投资者都很谨慎。","english":"The recent economic situation is turbulent, and investors are very cautious.","traditional":"最近的經濟形勢波濤洶湧，投資者都很謹慎。"},{"simplified":"他的生活经历过波涛汹涌的时期，但最终他克服了困难。","english":"He went through turbulent times in his life, but eventually he overcame the difficulties.","traditional":"他的生活經歷過波濤洶湧的時期，但最終他克服了困難。"}],"synonyms":["风起云涌","动荡不安"],"antonyms":["风平浪静"],"confusedWith":[{"id":"风平浪静","note":"While '波涛汹涌' describes chaos and turbulence, '风平浪静' refers to calm and peaceful conditions."}],"traditional":"波濤洶湧","pinyinOverride":null},{"id":"bo-ran-bian-se","simplified":"勃然变色","literalMeaning":"suddenly change color","figurativeMeaning":"to suddenly become angry or agitated","englishEquivalents":["fly into a rage","see red"],"shortGloss":"suddenly become angry","characters":[{"char":"勃","meaning":"suddenly, vigorously"},{"char":"然","meaning":"suddenly, as in a change"},{"char":"变","meaning":"change"},{"char":"色","meaning":"color, expression"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '勃然变色' describes the sudden change in a person's facial expression, often due to anger or agitation. It paints a vivid picture of someone who, upon hearing or seeing something upsetting, immediately shows their displeasure through a noticeable change in their demeanor.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"literary, but can be used in both formal and informal contexts","connotation":"negative","commonMistakes":"Learners sometimes confuse this idiom with expressions that mean 'to blush' due to its literal meaning involving a change in color. However, '勃然变色' specifically refers to a change due to anger or agitation, not embarrassment.","canStandAlone":false},"examples":[{"simplified":"听到这个消息，他勃然变色，立刻要求一个解释。","english":"Upon hearing the news, he suddenly became angry and immediately demanded an explanation.","traditional":"聽到這個消息，他勃然變色，立刻要求一個解釋。"},{"simplified":"她勃然变色，显然对这个决定非常不满。","english":"She suddenly became agitated, clearly very unhappy with the decision.","traditional":"她勃然變色，顯然對這個決定非常不滿。"}],"synonyms":["怒发冲冠"],"antonyms":["心平气和"],"confusedWith":[{"id":"面红耳赤","note":"面红耳赤 refers to blushing or being embarrassed, not necessarily anger."}],"traditional":"勃然變色","pinyinOverride":null},{"id":"bo-ran-da-nu","simplified":"勃然大怒","literalMeaning":"suddenly greatly angry","figurativeMeaning":"to fly into a rage; to become furious","englishEquivalents":["fly off the handle","hit the roof","blow a fuse"],"shortGloss":"fly into a rage","characters":[{"char":"勃","meaning":"suddenly"},{"char":"然","meaning":"like; as if"},{"char":"大","meaning":"greatly; intensely"},{"char":"怒","meaning":"angry"}],"origin":{"period":"Eastern Han dynasty (25–220 CE)","sourceText":"《后汉书·周举传》","sourceTextEnglish":"Book of the Later Han, Biography of Zhou Ju","originalExcerpt":"举勃然大怒，曰：“君何以言之？”","storyEnglish":"The idiom originates from the 'Book of the Later Han', where it describes Zhou Ju's reaction to a situation that made him extremely angry. The phrase captures the sudden and intense nature of his anger.","historicalFigures":["Zhou Ju"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"modifier-head","register":"widely used in both formal and informal contexts","connotation":"negative","commonMistakes":"Learners often confuse this idiom with similar expressions of anger that imply a slower build-up rather than a sudden outburst. It's important to note the abruptness implied by '勃然'.","canStandAlone":false},"examples":[{"simplified":"听到这个消息，他勃然大怒。","english":"Upon hearing the news, he flew into a rage.","traditional":"聽到這個消息，他勃然大怒。"},{"simplified":"她勃然大怒，开始大声责骂。","english":"She became furious and started yelling loudly.","traditional":"她勃然大怒，開始大聲責罵。"}],"synonyms":["怒火中烧","大发雷霆"],"antonyms":["心平气和"],"confusedWith":[{"id":"怒不可遏","note":"While both idioms describe anger, '怒不可遏' emphasizes uncontrollable anger, whereas '勃然大怒' emphasizes the suddenness of the anger."}],"traditional":"勃然大怒","pinyinOverride":null},{"id":"bo-er-bu-jing","simplified":"博而不精","literalMeaning":"broad but not refined","figurativeMeaning":"having a wide range of knowledge but lacking depth in any particular area","englishEquivalents":["jack of all trades, master of none"],"shortGloss":"broad knowledge, lacks depth","characters":[{"char":"博","meaning":"broad, extensive"},{"char":"而","meaning":"but"},{"char":"不","meaning":"not"},{"char":"精","meaning":"refined, specialized"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '博而不精' describes someone who has acquired a wide range of knowledge but has not delved deeply into any particular subject. It highlights the contrast between breadth and depth in learning. The phrase is often used to caution against spreading oneself too thin in pursuit of knowledge.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"coordinate","register":"commonly used in both written and spoken Chinese","connotation":"neutral","commonMistakes":"Learners often confuse this idiom with '精益求精' (to constantly improve and refine), which has a positive connotation of striving for excellence. '博而不精' implies a lack of depth, while '精益求精' suggests continuous improvement.","canStandAlone":false},"examples":[{"simplified":"他学习了很多学科，但博而不精，没有一个特别擅长的领域。","english":"He has studied many subjects, but he is a jack of all trades and master of none, without any particular area of expertise.","traditional":"他學習了很多學科，但博而不精，沒有一個特別擅長的領域。"},{"simplified":"在现代社会，博而不精的人很难在某个领域取得突破。","english":"In modern society, it is difficult for someone who is broad but not refined to make breakthroughs in any specific field.","traditional":"在現代社會，博而不精的人很難在某個領域取得突破。"}],"synonyms":[],"antonyms":["精益求精"],"confusedWith":[{"id":"精益求精","note":"While '博而不精' suggests a lack of depth, '精益求精' means to continuously improve and refine one's skills."}],"traditional":"博而不精","pinyinOverride":null},{"id":"bo-gu-tong-jin","simplified":"博古通今","literalMeaning":"extensive knowledge of the past and present","figurativeMeaning":"having extensive knowledge of both ancient and modern times","englishEquivalents":["well-versed in history","knowledgeable about past and present"],"shortGloss":"knowledgeable about past and present","characters":[{"char":"博","meaning":"extensive, broad"},{"char":"古","meaning":"ancient, past"},{"char":"通","meaning":"to understand, to be proficient in"},{"char":"今","meaning":"modern, present"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '博古通今' is used to describe someone who has a deep understanding and knowledge of both ancient and contemporary matters. It is often used to praise scholars or individuals who are well-read and have a broad perspective on history and current affairs.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"modifier-head","register":"literary, but understood and used in educated speech","connotation":"positive","commonMistakes":"Learners might confuse this idiom with others that involve knowledge, such as '学富五车', which specifically emphasizes the vastness of one's learning rather than the breadth across time periods.","canStandAlone":false},"examples":[{"simplified":"他是一位博古通今的学者，对历史和现代文化都有深入的研究。","english":"He is a scholar well-versed in both ancient and modern times, with deep research into history and contemporary culture.","traditional":"他是一位博古通今的學者，對歷史和現代文化都有深入的研究。"},{"simplified":"为了成为博古通今的人，他每天都坚持阅读各种书籍。","english":"To become knowledgeable about the past and present, he insists on reading various books every day.","traditional":"為了成為博古通今的人，他每天都堅持閱讀各種書籍。"}],"synonyms":["学富五车"],"antonyms":[],"confusedWith":[{"id":"学富五车","note":"While both idioms relate to knowledge, '学富五车' emphasizes the vastness of one's learning, not necessarily across time periods."}],"traditional":"博古通今","pinyinOverride":null},{"id":"bo-wen-qiang-ji","simplified":"博闻强记","literalMeaning":"broad knowledge, strong memory","figurativeMeaning":"having extensive knowledge and a strong memory","englishEquivalents":["a walking encyclopedia","well-read and retentive"],"shortGloss":"extensively knowledgeable and retentive","characters":[{"char":"博","meaning":"broad, extensive"},{"char":"闻","meaning":"knowledge, to hear"},{"char":"强","meaning":"strong, powerful"},{"char":"记","meaning":"to remember, memory"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '博闻强记' is used to describe someone who is not only knowledgeable but also has the ability to remember what they have learned. It emphasizes both the breadth of one's knowledge and the strength of their memory. The phrase is often used to praise scholars or individuals who have a vast amount of information at their disposal and can recall it easily.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["attributive","predicate"],"structure":"coordinate","register":"commonly used in both formal and informal contexts","connotation":"positive","commonMistakes":"Learners might confuse this idiom with others that emphasize knowledge without the aspect of memory, such as '博学多才'. '博闻强记' specifically highlights both knowledge and memory.","canStandAlone":false},"examples":[{"simplified":"他是一个博闻强记的人，总是能回答各种问题。","english":"He is a person with extensive knowledge and a strong memory, always able to answer various questions.","traditional":"他是一個博聞強記的人，總是能回答各種問題。"},{"simplified":"在学术界，博闻强记是非常重要的素质。","english":"In academia, having extensive knowledge and a strong memory is a very important quality.","traditional":"在學術界，博聞強記是非常重要的素質。"}],"synonyms":["博学多才"],"antonyms":[],"confusedWith":[{"id":"博学多才","note":"While '博学多才' emphasizes being well-read and talented, '博闻强记' specifically highlights the strength of memory along with knowledge."}],"traditional":"博聞強記","pinyinOverride":null},{"id":"bo-wen-qiang-zhi","simplified":"博闻强识","literalMeaning":"broadly knowledgeable, strong memory","figurativeMeaning":"having extensive knowledge and a strong memory","englishEquivalents":["well-read and retentive","knowledgeable and perceptive"],"shortGloss":"knowledgeable and retentive","characters":[{"char":"博","meaning":"broad, extensive"},{"char":"闻","meaning":"to hear, knowledge"},{"char":"强","meaning":"strong, powerful"},{"char":"识","meaning":"to remember, knowledge"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '博闻强识' is often used to describe someone who is not only well-read but also has a strong ability to remember what they have learned. It emphasizes both the breadth of knowledge and the strength of memory, suggesting a person who is both knowledgeable and perceptive.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["attributive","predicate"],"structure":"coordinate","register":"literary, but can be used in formal speech and writing","connotation":"positive","commonMistakes":"Learners might confuse this idiom with others that emphasize knowledge alone, like '博学多才' (broadly learned and talented), but '博闻强识' specifically highlights the combination of knowledge and memory.","canStandAlone":false},"examples":[{"simplified":"他是一个博闻强识的学者，几乎没有他不知道的事情。","english":"He is a scholar with extensive knowledge and a strong memory; there is almost nothing he doesn't know.","traditional":"他是一個博聞強識的學者，幾乎沒有他不知道的事情。"},{"simplified":"在这个领域，他以博闻强识而闻名。","english":"In this field, he is known for his extensive knowledge and strong memory.","traditional":"在這個領域，他以博聞強識而聞名。"}],"synonyms":["博学多才"],"antonyms":[],"confusedWith":[{"id":"博学多才","note":"While both idioms describe knowledge, '博学多才' emphasizes being learned and talented, whereas '博闻强识' highlights memory strength."}],"traditional":"博聞強識","pinyinOverride":null},{"id":"bo-xue-duo-cai","simplified":"博学多才","literalMeaning":"broad learning, many talents","figurativeMeaning":"very knowledgeable and talented","englishEquivalents":["a person of wide learning","a polymath"],"shortGloss":"very knowledgeable and talented","characters":[{"char":"博","meaning":"broad, extensive"},{"char":"学","meaning":"learning, knowledge"},{"char":"多","meaning":"many, multiple"},{"char":"才","meaning":"talents, abilities"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom 博学多才 describes a person who possesses extensive knowledge and multiple talents. It is often used to praise someone who is well-educated and skilled in various fields. The exact origin of this idiom is not tied to a specific classical text, but it has been widely used in Chinese literature to describe scholars and polymaths.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["attributive","predicate"],"structure":"coordinate","register":"commonly used in both formal and informal contexts to describe someone with extensive knowledge and skills","connotation":"positive","commonMistakes":"Learners might confuse this idiom with others that describe intelligence or skill, but 博学多才 specifically emphasizes both breadth of knowledge and multiple talents. It should not be used to describe someone who is only skilled in one area.","canStandAlone":false},"examples":[{"simplified":"他是一个博学多才的教授，精通多种语言。","english":"He is a very knowledgeable and talented professor, fluent in multiple languages.","traditional":"他是一個博學多才的教授，精通多種語言。"},{"simplified":"在公司里，他以博学多才而闻名。","english":"In the company, he is known for being very knowledgeable and talented.","traditional":"在公司裡，他以博學多才而聞名。"}],"synonyms":["才高八斗","学富五车"],"antonyms":[],"confusedWith":[{"id":"才高八斗","note":"才高八斗 emphasizes exceptional talent, while 博学多才 emphasizes both broad knowledge and multiple talents."}],"traditional":"博學多才","pinyinOverride":null},{"id":"bu-bai-zhi-yuan","simplified":"不白之冤","literalMeaning":"injustice that cannot be cleared","figurativeMeaning":"an injustice or grievance that cannot be redressed or explained","englishEquivalents":["a wrong that cannot be righted","an unredressed grievance"],"shortGloss":"an unredressed injustice","characters":[{"char":"不","meaning":"not"},{"char":"白","meaning":"clear, explain"},{"char":"之","meaning":"of"},{"char":"冤","meaning":"injustice, grievance"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '不白之冤' refers to a situation where someone suffers an injustice or false accusation that cannot be cleared or explained away. The phrase highlights the frustration and helplessness of being wronged without the means to prove one's innocence or rectify the situation.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["object","attributive"],"structure":"modifier-head","register":"widely used in both formal and informal contexts","connotation":"negative","commonMistakes":"Learners often confuse this idiom with '冤屈' (injustice), but '不白之冤' specifically emphasizes the inability to clear one's name or explain the injustice.","canStandAlone":false},"examples":[{"simplified":"他背负着不白之冤，心中十分痛苦。","english":"He bears an unredressed grievance, feeling very distressed.","traditional":"他揹負著不白之冤，心中十分痛苦。"},{"simplified":"这件事情让她蒙受了不白之冤。","english":"This incident caused her to suffer an injustice that cannot be cleared.","traditional":"這件事情讓她蒙受了不白之冤。"}],"synonyms":["冤屈","含冤莫白"],"antonyms":[],"confusedWith":[{"id":"冤屈","note":"While both refer to injustice, '不白之冤' emphasizes the inability to clear one's name."}],"traditional":"不白之冤","pinyinOverride":null},{"id":"bu-bei-bu-kang","simplified":"不卑不亢","literalMeaning":"not servile, not arrogant","figurativeMeaning":"to remain humble yet dignified; neither overbearing nor subservient","englishEquivalents":["neither servile nor overbearing","maintain one's dignity"],"shortGloss":"maintain dignity and humility","characters":[{"char":"不","meaning":"not"},{"char":"卑","meaning":"servile"},{"char":"不","meaning":"not"},{"char":"亢","meaning":"arrogant"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '不卑不亢' describes a balanced attitude where a person maintains their dignity without being overly humble or arrogant. It encourages people to treat others with respect while also respecting themselves, avoiding extremes of behavior.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"coordinate","register":"commonly used in both formal and informal contexts","connotation":"positive","commonMistakes":"Learners might confuse this idiom with similar phrases that emphasize humility or arrogance alone. It's important to remember that this idiom stresses balance between the two.","canStandAlone":false},"examples":[{"simplified":"在谈判中，他始终保持不卑不亢的态度。","english":"During the negotiations, he consistently maintained a humble yet dignified attitude.","traditional":"在談判中，他始終保持不卑不亢的態度。"},{"simplified":"面对批评，她不卑不亢，冷静地回应。","english":"Facing criticism, she remained composed, neither servile nor arrogant, and responded calmly.","traditional":"面對批評，她不卑不亢，冷靜地回應。"}],"synonyms":["平易近人"],"antonyms":["盛气凌人","卑躬屈膝"],"confusedWith":[{"id":"谦虚","note":"谦虚 emphasizes humility, while 不卑不亢 stresses a balance between humility and dignity."}],"traditional":"不卑不亢","pinyinOverride":null},{"id":"bu-bian-shu-mai","simplified":"不辨菽麦","literalMeaning":"unable to distinguish between beans and wheat","figurativeMeaning":"unable to distinguish right from wrong; ignorant or lacking basic knowledge","englishEquivalents":["can't tell chalk from cheese","ignorant as a babe"],"shortGloss":"ignorant or lacking basic knowledge","characters":[{"char":"不","meaning":"not"},{"char":"辨","meaning":"distinguish"},{"char":"菽","meaning":"beans"},{"char":"麦","meaning":"wheat"}],"origin":{"period":"Eastern Han dynasty (25–220 CE)","sourceText":"《后汉书·孔融传》","sourceTextEnglish":"Book of the Later Han, Biography of Kong Rong","originalExcerpt":"融年四岁，尝与客坐，客问曰：“贤家君何在？”融应声答曰：“君在田，未知菽麦。”","storyEnglish":"The idiom originates from a story about Kong Rong, a famous scholar and official during the Eastern Han dynasty. When Kong Rong was just four years old, a guest asked him where his father was. Kong Rong replied that his father was in the fields, but he couldn't tell the difference between beans and wheat. This response was meant to humorously imply that his father was not knowledgeable about farming, highlighting Kong Rong's wit even at a young age.","historicalFigures":["Kong Rong"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"verb-object","register":"literary, but can be used in a humorous or critical context in speech","connotation":"negative","commonMistakes":"Learners might confuse this idiom with others that involve ignorance, but this specifically implies a lack of basic or fundamental knowledge. It is not used for complex or specialized ignorance.","canStandAlone":false},"examples":[{"simplified":"他对基本常识都不懂，简直是不辨菽麦。","english":"He doesn't even understand basic common sense; he truly can't tell beans from wheat.","traditional":"他對基本常識都不懂，簡直是不辨菽麥。"},{"simplified":"在这个领域，他完全是不辨菽麦。","english":"In this field, he is completely ignorant.","traditional":"在這個領域，他完全是不辨菽麥。"}],"synonyms":["目不识丁"],"antonyms":[],"confusedWith":[{"id":"目不识丁","note":"目不识丁 refers to being illiterate, while 不辨菽麦 implies a broader ignorance of basic facts."}],"traditional":"不辨菽麥","pinyinOverride":null},{"id":"bu-cheng-ti-tong","simplified":"不成体统","literalMeaning":"not form a system","figurativeMeaning":"to be improper or indecent; to not conform to accepted standards","englishEquivalents":["out of line","inappropriate","unseemly"],"shortGloss":"improper or indecent","characters":[{"char":"不","meaning":"not"},{"char":"成","meaning":"form"},{"char":"体","meaning":"body; system"},{"char":"统","meaning":"system; order"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '不成体统' is used to describe actions or behaviors that are considered improper or indecent, not conforming to accepted norms or standards. It is often used to criticize someone for behaving in a way that is socially unacceptable or embarrassing.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"modifier-head","register":"commonly used in both spoken and written Chinese to describe inappropriate behavior","connotation":"negative","commonMistakes":"Learners might confuse this idiom with others that involve '不成', but '不成体统' specifically refers to behavior that is socially unacceptable or improper. It is not used to describe failure in general.","canStandAlone":false},"examples":[{"simplified":"他的行为真是不成体统。","english":"His behavior is truly improper.","traditional":"他的行為真是不成體統。"},{"simplified":"在正式场合穿得太随便是不成体统的。","english":"Dressing too casually at a formal event is inappropriate.","traditional":"在正式場合穿得太隨便是不成體統的。"}],"synonyms":["不伦不类","不合时宜"],"antonyms":["合情合理","合乎规范"],"confusedWith":[{"id":"不成样子","note":"While '不成样子' refers to something being in bad shape or unsightly, '不成体统' specifically refers to behavior that is socially unacceptable."}],"traditional":"不成體統","pinyinOverride":null},{"id":"bu-cheng-zhi-tu","simplified":"不逞之徒","literalMeaning":"discontented people","figurativeMeaning":"troublemakers or lawbreakers; people who cause trouble out of dissatisfaction","englishEquivalents":["troublemakers","rabble-rousers"],"shortGloss":"troublemakers or lawbreakers","characters":[{"char":"不","meaning":"not"},{"char":"逞","meaning":"succeed; achieve one's aims"},{"char":"之","meaning":"of; possessive particle"},{"char":"徒","meaning":"followers; people"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '不逞之徒' refers to people who are dissatisfied and therefore engage in disruptive or unlawful behavior. It is often used to describe individuals who cause trouble or disturbances in society due to their discontentment.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["subject","object","attributive"],"structure":"modifier-head","register":"neutral, used in both formal and informal contexts","connotation":"negative","commonMistakes":"Learners might confuse this idiom with more neutral terms for dissatisfied people, but it specifically implies causing trouble or breaking the law.","canStandAlone":false},"examples":[{"simplified":"警方正在追捕那些不逞之徒。","english":"The police are pursuing those troublemakers.","traditional":"警方正在追捕那些不逞之徒。"},{"simplified":"这些不逞之徒常常在夜间活动。","english":"These troublemakers often operate at night.","traditional":"這些不逞之徒常常在夜間活動。"}],"synonyms":["捣乱分子"],"antonyms":[],"confusedWith":[{"id":"不满之人","note":"While '不满之人' refers to dissatisfied people, it does not imply they are causing trouble."}],"traditional":"不逞之徒","pinyinOverride":null},{"id":"bu-chu-suo-liao","simplified":"不出所料","literalMeaning":"not beyond what was expected","figurativeMeaning":"as expected; unsurprisingly","englishEquivalents":["as expected","no surprise","predictably"],"shortGloss":"as expected","characters":[{"char":"不","meaning":"not"},{"char":"出","meaning":"beyond"},{"char":"所","meaning":"what"},{"char":"料","meaning":"expected"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '不出所料' is commonly used in modern Chinese to express that something happened as anticipated. It does not have a specific classical origin but rather has evolved through common usage to convey the idea of events unfolding as predicted.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"modifier-head","register":"commonly used in both spoken and written Chinese","connotation":"neutral","commonMistakes":"Learners often confuse '不出所料' with '意料之外' which means 'unexpectedly'. '不出所料' should be used when something happens as predicted, whereas '意料之外' is used for surprises.","canStandAlone":false},"examples":[{"simplified":"他的成功不出所料，因为他一直很努力。","english":"His success was as expected because he has always worked hard.","traditional":"他的成功不出所料，因為他一直很努力。"},{"simplified":"不出所料，今天的会议又被推迟了。","english":"As expected, today's meeting was postponed again.","traditional":"不出所料，今天的會議又被推遲了。"}],"synonyms":["果然","意料之中"],"antonyms":["意料之外"],"confusedWith":[{"id":"意料之外","note":"意料之外 means 'unexpectedly', which is the opposite of 不出所料."}],"traditional":"不出所料","pinyinOverride":null},{"id":"bu-chuai-mao-mei","simplified":"不揣冒昧","literalMeaning":"not presume to be bold","figurativeMeaning":"to humbly request permission to speak or act, often used as a polite preface","englishEquivalents":["if I may be so bold","with your permission"],"shortGloss":"humbly request permission","characters":[{"char":"不","meaning":"not"},{"char":"揣","meaning":"presume"},{"char":"冒","meaning":"bold"},{"char":"昧","meaning":"ignorant"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '不揣冒昧' is often used as a humble preface when someone is about to make a request or offer an opinion, acknowledging that they may be overstepping or being presumptuous. It reflects a traditional value of modesty and respect in communication.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["adverbial"],"structure":"modifier-head","register":"formal written Chinese, often used in letters or speeches","connotation":"neutral","commonMistakes":"Learners might mistakenly use this idiom in casual conversation where it can sound overly formal or insincere. It is best reserved for formal contexts.","canStandAlone":false},"examples":[{"simplified":"不揣冒昧，我想提出一个建议。","english":"If I may be so bold, I would like to offer a suggestion.","traditional":"不揣冒昧，我想提出一個建議。"},{"simplified":"不揣冒昧，请允许我发表意见。","english":"With your permission, please allow me to express my opinion.","traditional":"不揣冒昧，請允許我發表意見。"}],"synonyms":[],"antonyms":[],"confusedWith":[],"traditional":"不揣冒昧","pinyinOverride":null},{"id":"bu-ci-lao-ku","simplified":"不辞劳苦","literalMeaning":"not refuse toil and hardship","figurativeMeaning":"to work tirelessly and endure hardship without complaint","englishEquivalents":["go the extra mile","work tirelessly","leave no stone unturned"],"shortGloss":"work tirelessly without complaint","characters":[{"char":"不","meaning":"not"},{"char":"辞","meaning":"refuse"},{"char":"劳","meaning":"toil"},{"char":"苦","meaning":"hardship"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '不辞劳苦' is used to describe someone who is willing to endure hardship and work tirelessly without complaining. It emphasizes a strong work ethic and dedication to a task or cause, often used to praise individuals who go above and beyond in their efforts.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"common in both written and spoken Chinese, used to praise diligence and dedication","connotation":"positive","commonMistakes":"Learners might confuse this idiom with similar expressions that imply working hard but with a negative connotation, such as '吃苦耐劳', which emphasizes enduring hardship rather than the willingness to do so without complaint.","canStandAlone":false},"examples":[{"simplified":"他为了完成这个项目，不辞劳苦地工作了好几个月。","english":"He worked tirelessly for several months to complete this project.","traditional":"他為了完成這個項目，不辭勞苦地工作了好幾個月。"},{"simplified":"志愿者们不辞劳苦地帮助受灾群众。","english":"The volunteers worked tirelessly to help the disaster victims.","traditional":"志願者們不辭勞苦地幫助受災群眾。"}],"synonyms":["吃苦耐劳"],"antonyms":[],"confusedWith":[{"id":"吃苦耐劳","note":"吃苦耐劳 emphasizes enduring hardship, while 不辞劳苦 emphasizes working without complaint."}],"traditional":"不辭勞苦","pinyinOverride":null},{"id":"bu-de-yao-ling","simplified":"不得要领","literalMeaning":"unable to grasp the main point","figurativeMeaning":"to fail to understand the key point; to miss the essence of something","englishEquivalents":["miss the point","bark up the wrong tree"],"shortGloss":"miss the main point","characters":[{"char":"不","meaning":"not"},{"char":"得","meaning":"obtain"},{"char":"要","meaning":"important"},{"char":"领","meaning":"understanding; grasp"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '不得要领' is used to describe a situation where someone fails to grasp the essential points or main ideas. It is often applied in contexts where understanding or comprehension is crucial, such as in learning or problem-solving. The phrase suggests a lack of focus on what truly matters.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","complement"],"structure":"verb-object","register":"commonly used in both written and spoken Chinese","connotation":"negative","commonMistakes":"Learners often confuse this idiom with similar expressions that imply a complete lack of understanding, but '不得要领' specifically refers to missing the main point rather than not understanding at all.","canStandAlone":false},"examples":[{"simplified":"他学习很努力，但总是不得要领。","english":"He studies hard, but he always misses the main point.","traditional":"他學習很努力，但總是不得要領。"},{"simplified":"如果你不得要领，就很难解决这个问题。","english":"If you miss the main point, it will be difficult to solve this problem.","traditional":"如果你不得要領，就很難解決這個問題。"}],"synonyms":["抓不住重点"],"antonyms":["一针见血"],"confusedWith":[{"id":"不知所云","note":"While '不知所云' means not understanding what is being said at all, '不得要领' specifically refers to missing the key point."}],"traditional":"不得要領","pinyinOverride":null},{"id":"bu-dong-sheng-se","simplified":"不动声色","literalMeaning":"not move voice color","figurativeMeaning":"to remain calm and collected; to not show emotions","englishEquivalents":["keep a straight face","remain unflappable"],"shortGloss":"remain calm and collected","characters":[{"char":"不","meaning":"not"},{"char":"动","meaning":"move"},{"char":"声","meaning":"voice"},{"char":"色","meaning":"color; expression"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '不动声色' describes someone who remains calm and composed, without showing any outward signs of emotion or reaction. It is often used to praise individuals who can maintain their composure in stressful or surprising situations.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"modifier-head","register":"commonly used in both spoken and written Chinese to describe a calm demeanor","connotation":"positive","commonMistakes":"Learners might confuse this idiom with others that involve silence or calmness, but '不动声色' specifically emphasizes the lack of visible emotional reaction.","canStandAlone":false},"examples":[{"simplified":"即使在紧急情况下，他也能不动声色地处理问题。","english":"Even in emergencies, he can handle problems calmly and without showing any emotion.","traditional":"即使在緊急情況下，他也能不動聲色地處理問題。"},{"simplified":"她面对批评时总是不动声色，让人佩服。","english":"She always remains calm and collected in the face of criticism, which earns her admiration.","traditional":"她面對批評時總是不動聲色，讓人佩服。"}],"synonyms":["泰然自若","镇定自若"],"antonyms":["惊慌失措"],"confusedWith":[{"id":"面不改色","note":"Both idioms describe calmness, but '面不改色' focuses more on not changing facial expression specifically."}],"traditional":"不動聲色","pinyinOverride":null},{"id":"bu-fen-bi-ci","simplified":"不分彼此","literalMeaning":"not distinguish between 'that' and 'this'","figurativeMeaning":"to treat everyone or everything equally without distinction","englishEquivalents":["treat everyone equally","no distinction between you and me"],"shortGloss":"treat equally without distinction","characters":[{"char":"不","meaning":"not"},{"char":"分","meaning":"distinguish"},{"char":"彼","meaning":"that"},{"char":"此","meaning":"this"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '不分彼此' is used to describe a situation where no distinction is made between different people or things, often implying a sense of unity or equality. It suggests treating everyone or everything the same, without bias or favoritism.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"commonly used in both spoken and written Chinese","connotation":"positive","commonMistakes":"Learners sometimes confuse this idiom with those that emphasize differences rather than equality. It's important to remember that '不分彼此' emphasizes unity and lack of distinction.","canStandAlone":false},"examples":[{"simplified":"在困难面前，我们应该不分彼此，团结一致。","english":"In the face of difficulties, we should treat everyone equally and unite as one.","traditional":"在困難面前，我們應該不分彼此，團結一致。"},{"simplified":"他们之间的关系非常好，几乎不分彼此。","english":"Their relationship is so good that they hardly distinguish between each other.","traditional":"他們之間的關係非常好，幾乎不分彼此。"}],"synonyms":["一视同仁","平等待人"],"antonyms":[],"confusedWith":[{"id":"泾渭分明","note":"泾渭分明 emphasizes clear distinctions, opposite to the unity implied by 不分彼此."}],"traditional":"不分彼此","pinyinOverride":null},{"id":"bu-fen-zao-bai","simplified":"不分皂白","literalMeaning":"not distinguish black white","figurativeMeaning":"to not distinguish right from wrong","englishEquivalents":["unable to tell right from wrong","indiscriminate","without discrimination"],"shortGloss":"indiscriminate; unable to tell right from wrong","characters":[{"char":"不","meaning":"not"},{"char":"分","meaning":"distinguish"},{"char":"皂","meaning":"black"},{"char":"白","meaning":"white"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '不分皂白' is used to describe a situation where someone does not distinguish between right and wrong, or between different sides of an argument. The characters '皂' (black) and '白' (white) are used metaphorically to represent opposing sides or ideas, similar to the English concept of 'black and white' thinking.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["adverbial","attributive"],"structure":"modifier-head","register":"commonly used in both spoken and written Chinese","connotation":"negative","commonMistakes":"Learners might confuse this idiom with others that involve colors or opposites, but it specifically refers to a lack of discernment between right and wrong, not just any two opposing concepts.","canStandAlone":false},"examples":[{"simplified":"他总是对事情不分皂白地做出判断。","english":"He always makes judgments about things without distinguishing right from wrong.","traditional":"他總是對事情不分皂白地做出判斷。"},{"simplified":"在不分皂白的情况下做决定是危险的。","english":"Making decisions without distinguishing right from wrong is dangerous.","traditional":"在不分皂白的情況下做決定是危險的。"}],"synonyms":["不辨是非"],"antonyms":["明辨是非"],"confusedWith":[{"id":"黑白不分","note":"Both idioms involve distinguishing right from wrong, but '黑白不分' emphasizes confusion or reversal of right and wrong."}],"traditional":"不分皂白","pinyinOverride":null},{"id":"bu-fu-shui-tu","simplified":"不服水土","literalMeaning":"not acclimated to water and soil","figurativeMeaning":"to be unaccustomed to a new environment or climate","englishEquivalents":["not acclimatized","not adjusted to the environment"],"shortGloss":"not acclimated to a new environment","characters":[{"char":"不","meaning":"not"},{"char":"服","meaning":"acclimated"},{"char":"水","meaning":"water"},{"char":"土","meaning":"soil"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '不服水土' is used to describe someone who is not accustomed to the local environment or climate, often resulting in discomfort or illness. It reflects the idea that different regions have distinct water and soil conditions that can affect people's health and well-being when they move from one place to another.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","complement"],"structure":"verb-object","register":"commonly used in both spoken and written Chinese","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with expressions related to cultural differences, but it specifically refers to physical acclimatization to a new environment.","canStandAlone":false},"examples":[{"simplified":"他刚到这个城市，还不服水土。","english":"He just arrived in this city and is not yet acclimated to the environment.","traditional":"他剛到這個城市，還不服水土。"},{"simplified":"很多人出国旅行时会不服水土。","english":"Many people experience discomfort when traveling abroad due to not being acclimated to the local environment.","traditional":"很多人出國旅行時會不服水土。"}],"synonyms":[],"antonyms":[],"confusedWith":[],"traditional":"不服水土","pinyinOverride":null},{"id":"bu-fu-zhong-wang","simplified":"不负众望","literalMeaning":"not disappoint the expectations of the masses","figurativeMeaning":"to live up to expectations; to meet the expectations of many","englishEquivalents":["live up to expectations","meet expectations"],"shortGloss":"live up to expectations","characters":[{"char":"不","meaning":"not"},{"char":"负","meaning":"disappoint"},{"char":"众","meaning":"the masses; many people"},{"char":"望","meaning":"expectations; hopes"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '不负众望' is used to describe someone who successfully meets the expectations placed upon them by a large group of people. It is often used in contexts where a person or group has achieved what others hoped they would, such as in leadership, performance, or fulfilling a promise.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"commonly used in both spoken and written Chinese, suitable for formal and informal contexts","connotation":"positive","commonMistakes":"Learners might confuse this idiom with '不负所望', which has a similar meaning but is less commonly used. '不负众望' specifically emphasizes the expectations of a large group.","canStandAlone":false},"examples":[{"simplified":"他在比赛中表现出色，不负众望。","english":"He performed excellently in the competition, living up to everyone's expectations.","traditional":"他在比賽中表現出色，不負眾望。"},{"simplified":"经过多年的努力，她终于不负众望，成为了一名医生。","english":"After many years of hard work, she finally lived up to expectations and became a doctor.","traditional":"經過多年的努力，她終於不負眾望，成為了一名醫生。"}],"synonyms":["不负所望"],"antonyms":["辜负众望"],"confusedWith":[{"id":"不负所望","note":"Both idioms mean to meet expectations, but '不负众望' emphasizes the expectations of a larger group."}],"traditional":"不負眾望","pinyinOverride":null},{"id":"bu-gan-ji-mo","simplified":"不甘寂寞","literalMeaning":"not willing to be lonely","figurativeMeaning":"unwilling to remain idle; eager to be active or involved","englishEquivalents":["itching for action","restless","eager to be involved"],"shortGloss":"eager to be involved","characters":[{"char":"不","meaning":"not"},{"char":"甘","meaning":"willing"},{"char":"寂","meaning":"silent"},{"char":"寞","meaning":"lonely"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '不甘寂寞' describes someone who is not content with being inactive or isolated. It is often used to characterize people who seek out activity or involvement, whether in social, professional, or personal contexts. The phrase captures a sense of restlessness and a desire to be part of the action.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"modifier-head","register":"commonly used in both spoken and written Chinese","connotation":"neutral","commonMistakes":"Learners often confuse this idiom with similar phrases that imply loneliness or solitude. However, '不甘寂寞' specifically conveys a desire to avoid idleness or inactivity, not just loneliness.","canStandAlone":false},"examples":[{"simplified":"他总是不甘寂寞，总是想找点事情做。","english":"He is always eager to keep busy and is constantly looking for something to do.","traditional":"他總是不甘寂寞，總是想找點事情做。"},{"simplified":"她不甘寂寞，加入了多个社团。","english":"She couldn't stand being idle, so she joined several clubs.","traditional":"她不甘寂寞，加入了多個社團。"}],"synonyms":["好动不安"],"antonyms":["甘于寂寞"],"confusedWith":[{"id":"孤芳自赏","note":"While '不甘寂寞' implies a desire for activity, '孤芳自赏' means to admire oneself in solitude, often with a sense of pride."}],"traditional":"不甘寂寞","pinyinOverride":null},{"id":"bu-gan-shi-ruo","simplified":"不甘示弱","literalMeaning":"not willing to show weakness","figurativeMeaning":"unwilling to concede or appear inferior; determined to hold one's own","englishEquivalents":["not to be outdone","refuse to be cowed","stand one's ground"],"shortGloss":"refuse to show weakness","characters":[{"char":"不","meaning":"not"},{"char":"甘","meaning":"willing"},{"char":"示","meaning":"show"},{"char":"弱","meaning":"weakness"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '不甘示弱' describes a situation where someone is unwilling to show weakness or concede to others. It is often used in contexts where individuals or groups are competing or trying to maintain their dignity and status.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"modifier-head","register":"commonly used in both spoken and written Chinese, suitable for everyday contexts","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with '示弱' (to show weakness), which has the opposite meaning. It's important to remember that '不甘' negates the willingness to show weakness.","canStandAlone":false},"examples":[{"simplified":"在比赛中，他不甘示弱，最终赢得了胜利。","english":"In the competition, he refused to be outdone and ultimately won the victory.","traditional":"在比賽中，他不甘示弱，最終贏得了勝利。"},{"simplified":"面对挑战，她不甘示弱，努力克服困难。","english":"Facing the challenge, she refused to show weakness and worked hard to overcome the difficulties.","traditional":"面對挑戰，她不甘示弱，努力克服困難。"}],"synonyms":["针锋相对","寸步不让"],"antonyms":["甘拜下风"],"confusedWith":[{"id":"示弱","note":"示弱 means to show weakness, the opposite of 不甘示弱."}],"traditional":"不甘示弱","pinyinOverride":null},{"id":"bu-gan-gou-tong","simplified":"不敢苟同","literalMeaning":"not dare to casually agree","figurativeMeaning":"to disagree; to not approve of something","englishEquivalents":["I beg to differ","I don't agree","I can't go along with that"],"shortGloss":"to disagree","characters":[{"char":"不","meaning":"not"},{"char":"敢","meaning":"dare"},{"char":"苟","meaning":"carelessly; casually"},{"char":"同","meaning":"agree"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '不敢苟同' is used to express a polite disagreement or dissent. It implies that one does not dare to agree with something casually or without careful consideration. The phrase is often used in discussions or debates to respectfully express a differing opinion.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","standalone-exclamation"],"structure":"verb-object","register":"formal written Chinese, but also used in polite spoken contexts","connotation":"neutral","commonMistakes":"Learners might mistakenly use this idiom in contexts where a stronger disagreement is intended. It is more polite and reserved than outright saying 'I disagree'.","canStandAlone":true},"examples":[{"simplified":"对于这个观点，我不敢苟同。","english":"I can't agree with this point of view.","traditional":"對於這個觀點，我不敢苟同。"},{"simplified":"虽然大家都支持这个计划，但我不敢苟同。","english":"Although everyone supports this plan, I beg to differ.","traditional":"雖然大家都支持這個計劃，但我不敢苟同。"}],"synonyms":["持不同意见"],"antonyms":["同意","赞同"],"confusedWith":[{"id":"不同意","note":"不敢苟同 is more formal and polite, while 不同意 is straightforward and direct."}],"traditional":"不敢苟同","pinyinOverride":null},{"id":"bu-gong-dai-tian","simplified":"不共戴天","literalMeaning":"not share the same sky","figurativeMeaning":"to have an irreconcilable enmity with someone; to be bitter enemies","englishEquivalents":["sworn enemies","mortal enemies"],"shortGloss":"irreconcilable enmity","characters":[{"char":"不","meaning":"not"},{"char":"共","meaning":"together"},{"char":"戴","meaning":"wear"},{"char":"天","meaning":"sky"}],"origin":{"period":"Warring States period (475–221 BCE)","sourceText":"《左传·僖公二十四年》","sourceTextEnglish":"Zuo Zhuan, Duke Xi, Year 24","originalExcerpt":"不共戴天之仇，必报。","storyEnglish":"The idiom originates from a passage in the 'Zuo Zhuan', an ancient Chinese historical text. It describes a situation where one party has such deep-seated hatred for another that they cannot coexist under the same sky. The phrase is often used to describe enemies who are determined to seek revenge or cannot reconcile their differences.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"modifier-head","register":"literary, but widely understood and used in both formal and informal contexts","connotation":"negative","commonMistakes":"Learners often confuse this idiom with less intense expressions of dislike. It specifically implies an intense, irreconcilable enmity, not just a simple disagreement or rivalry.","canStandAlone":false},"examples":[{"simplified":"他们之间有不共戴天的仇恨。","english":"There is an irreconcilable enmity between them.","traditional":"他們之間有不共戴天的仇恨。"},{"simplified":"他视敌人为不共戴天的仇人。","english":"He regards his enemy as a sworn enemy.","traditional":"他視敵人為不共戴天的仇人。"}],"synonyms":["势不两立"],"antonyms":[],"confusedWith":[{"id":"水火不容","note":"While both imply conflict, 水火不容 suggests incompatibility rather than personal enmity."}],"traditional":"不共戴天","pinyinOverride":null},{"id":"bu-guan-tong-yang","simplified":"不关痛痒","literalMeaning":"does not concern pain or itch","figurativeMeaning":"irrelevant or of no concern; having no effect on the situation","englishEquivalents":["of no consequence","irrelevant","beside the point"],"shortGloss":"irrelevant or inconsequential","characters":[{"char":"不","meaning":"not"},{"char":"关","meaning":"concern"},{"char":"痛","meaning":"pain"},{"char":"痒","meaning":"itch"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '不关痛痒' is used to describe something that is irrelevant or does not affect the situation. The phrase literally means something that neither causes pain nor itch, implying it has no impact or significance. It is often used to dismiss concerns or issues that are deemed unimportant.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive","adverbial"],"structure":"modifier-head","register":"commonly used in both spoken and written Chinese to indicate irrelevance","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with expressions that imply indifference or lack of care, but it specifically refers to irrelevance rather than emotional detachment.","canStandAlone":false},"examples":[{"simplified":"他提出的建议对我们的计划不关痛痒。","english":"His suggestion is irrelevant to our plan.","traditional":"他提出的建議對我們的計劃不關痛癢。"},{"simplified":"这些细节对最终结果不关痛痒。","english":"These details are irrelevant to the final outcome.","traditional":"這些細節對最終結果不關痛癢。"}],"synonyms":["无关紧要","无足轻重"],"antonyms":["息息相关"],"confusedWith":[{"id":"漠不关心","note":"漠不关心 means 'indifferent' or 'unconcerned', which implies a lack of care rather than irrelevance."}],"traditional":"不關痛癢","pinyinOverride":null},{"id":"bu-guo-er-er","simplified":"不过尔尔","literalMeaning":"nothing more than this","figurativeMeaning":"something is insignificant or mediocre","englishEquivalents":["nothing special","no big deal"],"shortGloss":"insignificant or mediocre","characters":[{"char":"不","meaning":"not"},{"char":"过","meaning":"more than"},{"char":"尔","meaning":"this; thus"},{"char":"尔","meaning":"this; thus"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '不过尔尔' is used to express that something is not particularly special or noteworthy. It suggests that the thing being described is just average or ordinary, and not worth making a fuss over.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"coordinate","register":"common in both spoken and written Chinese","connotation":"neutral","commonMistakes":"Learners might mistakenly use this idiom to describe something positively, but it actually conveys a sense of mediocrity or insignificance.","canStandAlone":false},"examples":[{"simplified":"他的表演不过尔尔，没有什么特别的。","english":"His performance was nothing special, nothing particularly remarkable.","traditional":"他的表演不過爾爾，沒有什麼特別的。"},{"simplified":"这次比赛不过尔尔，不值得太在意。","english":"This competition is nothing special, not worth paying too much attention to.","traditional":"這次比賽不過爾爾，不值得太在意。"}],"synonyms":["平平无奇","普普通通"],"antonyms":["出类拔萃","鹤立鸡群"],"confusedWith":[{"id":"不过如此","note":"Both express mediocrity, but '不过如此' often implies disappointment after high expectations."}],"traditional":"不過爾爾","pinyinOverride":null},{"id":"bu-han-er-li","simplified":"不寒而栗","literalMeaning":"not cold yet shivering","figurativeMeaning":"to tremble with fear or dread","englishEquivalents":["shiver with fear","shake in one's boots"],"shortGloss":"tremble with fear","characters":[{"char":"不","meaning":"not"},{"char":"寒","meaning":"cold"},{"char":"而","meaning":"yet"},{"char":"栗","meaning":"shiver"}],"origin":{"period":"Han Dynasty (202 BCE – 220 CE)","sourceText":"《汉书·蒯通传》","sourceTextEnglish":"Book of Han, Biography of Kuai Tong","originalExcerpt":"不寒而栗，言其惧也。","storyEnglish":"The idiom originates from the 'Book of Han', where it describes a situation in which someone trembles with fear despite not being cold. The phrase was used to emphasize the intensity of fear that could make someone shiver as if they were in cold weather.","historicalFigures":["Kuai Tong"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"modifier-head","register":"literary, but widely understood and used in both written and spoken Chinese","connotation":"negative","commonMistakes":"Learners often confuse this idiom with expressions related to physical coldness. It specifically refers to shivering due to fear, not temperature.","canStandAlone":false},"examples":[{"simplified":"听到那个恐怖的故事，他不寒而栗。","english":"Hearing that terrifying story, he shivered with fear.","traditional":"聽到那個恐怖的故事，他不寒而慄。"},{"simplified":"面对如此严厉的批评，她不寒而栗。","english":"Faced with such harsh criticism, she trembled with dread.","traditional":"面對如此嚴厲的批評，她不寒而慄。"}],"synonyms":["毛骨悚然"],"antonyms":[],"confusedWith":[{"id":"寒风刺骨","note":"寒风刺骨 refers to the physical sensation of cold wind piercing the bones, not fear."}],"traditional":"不寒而慄","pinyinOverride":null},{"id":"bu-he-shi-yi","simplified":"不合时宜","literalMeaning":"not fit the time and occasion","figurativeMeaning":"out of keeping with the times; inappropriate for the current situation","englishEquivalents":["out of place","behind the times"],"shortGloss":"out of keeping with the times","characters":[{"char":"不","meaning":"not"},{"char":"合","meaning":"fit; suit"},{"char":"时","meaning":"time; current"},{"char":"宜","meaning":"occasion; appropriate"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '不合时宜' is used to describe something that does not fit the current circumstances or trends. It suggests that an action, idea, or object is outdated or inappropriate for the present time.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"modifier-head","register":"commonly used in both written and spoken Chinese","connotation":"negative","commonMistakes":"Learners often confuse this idiom with '合时宜', which means 'appropriate for the time'. The key difference is the negation '不', which completely changes the meaning.","canStandAlone":false},"examples":[{"simplified":"他的穿着在这个场合显得不合时宜。","english":"His attire seemed out of place for the occasion.","traditional":"他的穿著在這個場合顯得不合時宜。"},{"simplified":"这个古老的观念在现代社会已经不合时宜了。","english":"This old concept is already out of keeping with modern society.","traditional":"這個古老的觀念在現代社會已經不合時宜了。"}],"synonyms":["过时"],"antonyms":["合时宜"],"confusedWith":[{"id":"合时宜","note":"‘合时宜’ means appropriate for the time, the opposite of '不合时宜'."}],"traditional":"不合時宜","pinyinOverride":null},{"id":"bu-huan-er-san","simplified":"不欢而散","literalMeaning":"not happy and disperse","figurativeMeaning":"to part on bad terms; to break up unhappily","englishEquivalents":["part on bad terms","leave in a huff"],"shortGloss":"part on bad terms","characters":[{"char":"不","meaning":"not"},{"char":"欢","meaning":"happy"},{"char":"而","meaning":"and"},{"char":"散","meaning":"disperse; break up"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '不欢而散' describes a situation where people part ways unhappily, often after a disagreement or argument. It reflects the idea that a meeting or gathering ended without joy, and the participants left with unresolved issues or negative feelings.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"modifier-head","register":"commonly used in both spoken and written Chinese","connotation":"negative","commonMistakes":"Learners may confuse this idiom with positive partings or misunderstand it as simply 'ending a meeting'. It specifically implies an unhappy or contentious ending.","canStandAlone":false},"examples":[{"simplified":"他们因为意见不合而不欢而散。","english":"They parted on bad terms because of their disagreement.","traditional":"他們因為意見不合而不歡而散。"},{"simplified":"会议结束时，大家不欢而散，气氛很尴尬。","english":"When the meeting ended, everyone parted on bad terms, and the atmosphere was awkward.","traditional":"會議結束時，大家不歡而散，氣氛很尷尬。"}],"synonyms":["不欢而别"],"antonyms":["皆大欢喜"],"confusedWith":[{"id":"皆大欢喜","note":"While '皆大欢喜' means everyone is happy, '不欢而散' means the opposite, with an unhappy parting."}],"traditional":"不歡而散","pinyinOverride":null},{"id":"bu-ji-zhi-wu","simplified":"不急之务","literalMeaning":"not urgent matters","figurativeMeaning":"matters or tasks that are not urgent and can be postponed","englishEquivalents":["not a priority","can wait","not pressing"],"shortGloss":"non-urgent matters","characters":[{"char":"不","meaning":"not"},{"char":"急","meaning":"urgent"},{"char":"之","meaning":"of"},{"char":"务","meaning":"matters"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '不急之务' refers to tasks or matters that are not immediately pressing and can be deferred. It is often used to prioritize tasks by focusing on what is urgent and important, while setting aside those that are not urgent.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["object","attributive"],"structure":"modifier-head","register":"commonly used in both spoken and written Chinese","connotation":"neutral","commonMistakes":"Learners sometimes confuse this idiom with '紧急之务' (urgent matters), which has the opposite meaning. It's important to note the presence of '不' which negates the urgency.","canStandAlone":false},"examples":[{"simplified":"我们应该先处理紧急的事情，而不是不急之务。","english":"We should first deal with urgent matters, not those that are not pressing.","traditional":"我們應該先處理緊急的事情，而不是不急之務。"},{"simplified":"在工作中，学会区分不急之务和紧急任务是很重要的。","english":"In work, it's important to learn to distinguish between non-urgent matters and urgent tasks.","traditional":"在工作中，學會區分不急之務和緊急任務是很重要的。"}],"synonyms":[],"antonyms":["紧急之务"],"confusedWith":[{"id":"紧急之务","note":"紧急之务 refers to urgent matters, which is the opposite of 不急之务."}],"traditional":"不急之務","pinyinOverride":null},{"id":"bu-ji-bu-xu","simplified":"不疾不徐","literalMeaning":"not fast not slow","figurativeMeaning":"to proceed at a steady, moderate pace; neither too fast nor too slow","englishEquivalents":["steady as she goes","at a measured pace"],"shortGloss":"steady, moderate pace","characters":[{"char":"不","meaning":"not"},{"char":"疾","meaning":"fast"},{"char":"不","meaning":"not"},{"char":"徐","meaning":"slow"}],"origin":{"period":"Han Dynasty (206 BCE – 220 CE)","sourceText":"《礼记·中庸》","sourceTextEnglish":"The Book of Rites, Doctrine of the Mean","originalExcerpt":"君子之道，淡而不厌，简而文，温而理，知远之近，知风之自，知不疾而速，不行而至。","storyEnglish":"The idiom comes from a passage in the 'Doctrine of the Mean' within the 'Book of Rites', which describes the ideal way of a gentleman as being moderate and balanced. The phrase '不疾而速' suggests achieving speed without haste, which is interpreted as maintaining a steady, moderate pace.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["adverbial","predicate"],"structure":"coordinate","register":"literary, but can be used in formal speech and writing","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with expressions that suggest slowness or laziness. It's important to remember that it implies a balanced pace, not a slow one.","canStandAlone":false},"examples":[{"simplified":"他做事总是不疾不徐，结果总是很好。","english":"He always works at a steady pace, and the results are always good.","traditional":"他做事總是不疾不徐，結果總是很好。"},{"simplified":"在这次比赛中，他不疾不徐地完成了整个过程。","english":"In this competition, he completed the entire process at a steady pace.","traditional":"在這次比賽中，他不疾不徐地完成了整個過程。"}],"synonyms":[],"antonyms":[],"confusedWith":[{"id":"慢条斯理","note":"While both suggest a measured pace, 慢条斯理 often implies a slower, more deliberate pace, sometimes with a negative connotation of being too slow."}],"traditional":"不疾不徐","pinyinOverride":null},{"id":"bu-jian-tian-ri","simplified":"不见天日","literalMeaning":"not see the light of day","figurativeMeaning":"to be in a dark, oppressive situation; to live in misery or confinement","englishEquivalents":["not see the light of day","in the dark","under a cloud"],"shortGloss":"in a dark, oppressive situation","characters":[{"char":"不","meaning":"not"},{"char":"见","meaning":"see"},{"char":"天","meaning":"sky; day"},{"char":"日","meaning":"sun; day"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '不见天日' is often used to describe situations where someone is trapped in a dark, oppressive environment, either literally or metaphorically. It conveys a sense of being cut off from hope or freedom, similar to being in a dungeon or a place devoid of light.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"commonly used in both written and spoken Chinese to describe oppressive or miserable conditions","connotation":"negative","commonMistakes":"Learners might confuse this idiom with phrases that simply mean 'hidden' or 'secret'. However, '不见天日' specifically emphasizes the oppressive or miserable nature of the situation.","canStandAlone":false},"examples":[{"simplified":"他在那家公司工作，感觉像是不见天日。","english":"He works at that company and feels like he's in a dark, oppressive situation.","traditional":"他在那家公司工作，感覺像是不見天日。"},{"simplified":"这些年来，她的生活一直不见天日。","english":"For years, her life has been shrouded in darkness and misery.","traditional":"這些年來，她的生活一直不見天日。"}],"synonyms":["暗无天日"],"antonyms":["阳光明媚"],"confusedWith":[{"id":"暗无天日","note":"Both idioms describe dark, oppressive situations, but '暗无天日' emphasizes the absence of light even more strongly."}],"traditional":"不見天日","pinyinOverride":null},{"id":"bu-jin-ren-qing","simplified":"不近人情","literalMeaning":"not close to human feelings","figurativeMeaning":"to be unreasonable or lacking in empathy","englishEquivalents":["cold-hearted","unfeeling"],"shortGloss":"unreasonable or lacking empathy","characters":[{"char":"不","meaning":"not"},{"char":"近","meaning":"close"},{"char":"人","meaning":"human"},{"char":"情","meaning":"feelings"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom 不近人情 describes someone who is perceived as cold or lacking in empathy. It is often used to criticize individuals who act in a way that seems detached from normal human emotions or social norms. The phrase suggests a lack of understanding or consideration for the feelings of others.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"modifier-head","register":"commonly used in both spoken and written Chinese to describe someone as unreasonable or lacking empathy","connotation":"negative","commonMistakes":"Learners might confuse 不近人情 with idioms that describe someone as simply being strict or disciplined, but 不近人情 specifically implies a lack of empathy or consideration for others' feelings.","canStandAlone":false},"examples":[{"simplified":"他的决定太不近人情了，完全没有考虑到员工的感受。","english":"His decision was too unreasonable, completely disregarding the employees' feelings.","traditional":"他的決定太不近人情了，完全沒有考慮到員工的感受。"},{"simplified":"她对待朋友的方式让人觉得不近人情。","english":"The way she treats her friends makes her seem unfeeling.","traditional":"她對待朋友的方式讓人覺得不近人情。"}],"synonyms":["冷酷无情"],"antonyms":["通情达理"],"confusedWith":[{"id":"冷酷无情","note":"Both describe a lack of empathy, but 冷酷无情 is more about being cold and ruthless, while 不近人情 emphasizes being unreasonable."}],"traditional":"不近人情","pinyinOverride":null},{"id":"bu-jiu-ji-wang","simplified":"不咎既往","literalMeaning":"not blame the past","figurativeMeaning":"to forgive past mistakes or let bygones be bygones","englishEquivalents":["let bygones be bygones","forgive and forget"],"shortGloss":"forgive past mistakes","characters":[{"char":"不","meaning":"not"},{"char":"咎","meaning":"blame"},{"char":"既","meaning":"already"},{"char":"往","meaning":"past"}],"origin":{"period":"Warring States period (475–221 BCE)","sourceText":"《左传·襄公二十四年》","sourceTextEnglish":"Zuo Zhuan, Duke Xiang, Year 24","originalExcerpt":"不以既往，咎人。","storyEnglish":"The idiom originates from the historical text 'Zuo Zhuan', where it is mentioned in the context of not blaming someone for past actions. The idea is to move forward without holding onto past grievances, promoting forgiveness and reconciliation.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"formal written Chinese, but also used in spoken language","connotation":"positive","commonMistakes":"Learners might confuse this idiom with similar ones that emphasize forgetting rather than forgiving. It's important to note that this idiom focuses on not blaming rather than erasing the memory of past events.","canStandAlone":false},"examples":[{"simplified":"我们应该不咎既往，重新开始。","english":"We should forgive past mistakes and start anew.","traditional":"我們應該不咎既往，重新開始。"},{"simplified":"他决定不咎既往，与对方和解。","english":"He decided to let bygones be bygones and reconcile with the other party.","traditional":"他決定不咎既往，與對方和解。"}],"synonyms":["既往不咎"],"antonyms":[],"confusedWith":[{"id":"既往不咎","note":"This is a variant with the same meaning but different word order."}],"traditional":"不咎既往","pinyinOverride":null},{"id":"bu-ju-xiao-jie","simplified":"不拘小节","literalMeaning":"not stick to small matters","figurativeMeaning":"to not be bothered by trivial details; to focus on the bigger picture","englishEquivalents":["Don't sweat the small stuff","Not nitpicky"],"shortGloss":"not bothered by trivial details","characters":[{"char":"不","meaning":"not"},{"char":"拘","meaning":"confined to; stick to"},{"char":"小","meaning":"small"},{"char":"节","meaning":"details; matters"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '不拘小节' is used to describe someone who does not concern themselves with minor details or trivial matters. It suggests a focus on more significant issues or the bigger picture, rather than getting bogged down by small, inconsequential details. The origin of this idiom is not tied to a specific classical text, and it has likely evolved from common usage over time.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"modifier-head","register":"commonly used in both spoken and written Chinese","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with others that imply carelessness or negligence. However, '不拘小节' does not imply a lack of attention to important matters, only to trivial ones.","canStandAlone":false},"examples":[{"simplified":"他是一个不拘小节的人，总是关注大局。","english":"He is someone who doesn't sweat the small stuff and always focuses on the bigger picture.","traditional":"他是一個不拘小節的人，總是關注大局。"},{"simplified":"在工作中，不拘小节有时是必要的，以便更好地完成任务。","english":"In work, sometimes not worrying about trivial details is necessary to better accomplish tasks.","traditional":"在工作中，不拘小節有時是必要的，以便更好地完成任務。"}],"synonyms":[],"antonyms":[],"confusedWith":[{"id":"粗心大意","note":"粗心大意 means careless and negligent, implying a lack of attention to important matters, unlike 不拘小节."}],"traditional":"不拘小節","pinyinOverride":null},{"id":"bu-jue-ru-lu","simplified":"不绝如缕","literalMeaning":"unbroken like a thread","figurativeMeaning":"hanging by a thread; in a very precarious situation","englishEquivalents":["hanging by a thread","on the brink","in dire straits"],"shortGloss":"in a precarious situation","characters":[{"char":"不","meaning":"not"},{"char":"绝","meaning":"break"},{"char":"如","meaning":"like"},{"char":"缕","meaning":"thread"}],"origin":{"period":"Han Dynasty (202 BCE – 220 CE)","sourceText":"《后汉书·张纲传》","sourceTextEnglish":"Book of the Later Han, Biography of Zhang Gang","originalExcerpt":"其声不绝如缕。","storyEnglish":"The idiom originates from a description in the 'Book of the Later Han' where the sound of a musical instrument is described as continuous but very faint, like a thin thread. This metaphor was later extended to describe situations that are barely holding on, much like a thread that is about to break.","historicalFigures":["Zhang Gang"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"modifier-head","register":"literary, but understood in educated speech","connotation":"negative","commonMistakes":"Learners often confuse this idiom with '千钧一发', which also means a precarious situation but emphasizes imminent danger. '不绝如缕' focuses more on the fragility and continuity aspect.","canStandAlone":false},"examples":[{"simplified":"他的生意现在不绝如缕，随时可能倒闭。","english":"His business is now hanging by a thread and could collapse at any moment.","traditional":"他的生意現在不絕如縷，隨時可能倒閉。"},{"simplified":"在战争的最后阶段，敌军的抵抗不绝如缕。","english":"In the final stages of the war, the enemy's resistance was hanging by a thread.","traditional":"在戰爭的最後階段，敵軍的抵抗不絕如縷。"}],"synonyms":["千钧一发"],"antonyms":[],"confusedWith":[{"id":"千钧一发","note":"While both idioms describe precarious situations, '千钧一发' emphasizes imminent danger, whereas '不绝如缕' highlights fragility and continuity."}],"traditional":"不絕如縷","pinyinOverride":null},{"id":"bu-kan-zhi-lun","simplified":"不刊之论","literalMeaning":"an uncorrectable statement","figurativeMeaning":"an irrefutable or unalterable truth","englishEquivalents":["an indisputable truth","a gospel truth"],"shortGloss":"an irrefutable truth","characters":[{"char":"不","meaning":"not"},{"char":"刊","meaning":"to amend; to correct"},{"char":"之","meaning":"of; possessive particle"},{"char":"论","meaning":"statement; opinion"}],"origin":{"period":"Eastern Jin dynasty (317–420 CE)","sourceText":"《世说新语·文学》","sourceTextEnglish":"A New Account of the Tales of the World, Literature","originalExcerpt":"王戎曰：“此不刊之论也。”","storyEnglish":"During the Eastern Jin dynasty, a scholar named Wang Rong praised a statement made by another scholar, saying it was 'an uncorrectable statement' (不刊之论), meaning it was so perfect and true that it needed no amendment. This phrase has since been used to describe statements or truths that are considered irrefutable.","historicalFigures":["Wang Rong"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["subject","object","attributive"],"structure":"modifier-head","register":"literary, but can be used in formal speech and writing","connotation":"positive","commonMistakes":"Learners might confuse this idiom with expressions that imply stubbornness or refusal to change, but it specifically refers to truths or statements that are inherently correct and need no alteration.","canStandAlone":false},"examples":[{"simplified":"他的观点被认为是不刊之论。","english":"His viewpoint is considered an irrefutable truth.","traditional":"他的觀點被認為是不刊之論。"},{"simplified":"这篇文章中有许多不刊之论。","english":"There are many irrefutable truths in this article.","traditional":"這篇文章中有許多不刊之論。"}],"synonyms":["铁证如山"],"antonyms":["无稽之谈"],"confusedWith":[{"id":"顽固不化","note":"顽固不化 refers to stubbornness and refusal to change, unlike 不刊之论 which refers to an irrefutable truth."}],"traditional":"不刊之論","pinyinOverride":null},{"id":"bu-kan-ru-mu","simplified":"不堪入目","literalMeaning":"cannot bear to enter the eyes","figurativeMeaning":"too offensive or unpleasant to look at","englishEquivalents":["an eyesore","too hideous to behold"],"shortGloss":"too unpleasant to look at","characters":[{"char":"不","meaning":"not"},{"char":"堪","meaning":"can bear"},{"char":"入","meaning":"enter"},{"char":"目","meaning":"eyes"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom describes something so offensive or ugly that it is unbearable to look at. The phrase is often used to criticize something that is visually displeasing or morally repugnant.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"modifier-head","register":"commonly used in both written and spoken Chinese to describe something unpleasant or offensive to the eyes","connotation":"negative","commonMistakes":"Learners might confuse this idiom with similar expressions that describe something unpleasant, but this idiom specifically emphasizes the visual aspect. It should not be used to describe something that is unpleasant in a non-visual sense.","canStandAlone":false},"examples":[{"simplified":"这幅画简直不堪入目，太难看了。","english":"This painting is simply an eyesore; it's so ugly.","traditional":"這幅畫簡直不堪入目，太難看了。"},{"simplified":"他的房间乱得不堪入目。","english":"His room is such a mess that it's unbearable to look at.","traditional":"他的房間亂得不堪入目。"}],"synonyms":["触目惊心"],"antonyms":["赏心悦目"],"confusedWith":[{"id":"触目惊心","note":"While both describe something shocking, 触目惊心 emphasizes the shock or horror, not just visual unpleasantness."}],"traditional":"不堪入目","pinyinOverride":null},{"id":"bu-kan-she-xiang","simplified":"不堪设想","literalMeaning":"cannot bear to imagine","figurativeMeaning":"too dreadful to contemplate; unimaginable consequences","englishEquivalents":["too horrible to imagine","unthinkable","beyond comprehension"],"shortGloss":"unimaginable consequences","characters":[{"char":"不","meaning":"not"},{"char":"堪","meaning":"can bear; can endure"},{"char":"设","meaning":"set up; establish; imagine"},{"char":"想","meaning":"think; imagine"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '不堪设想' is used to describe situations where the potential consequences are so dire or dreadful that one cannot bear to think about them. It emphasizes the severity and seriousness of a situation, suggesting that if certain actions are taken or if certain events occur, the outcomes would be disastrous.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","complement"],"structure":"modifier-head","register":"commonly used in both formal and informal contexts to emphasize the severity of potential outcomes","connotation":"negative","commonMistakes":"Learners often misuse this idiom by applying it to trivial situations. It should be reserved for scenarios with genuinely serious or disastrous potential outcomes.","canStandAlone":false},"examples":[{"simplified":"如果不采取措施，后果将不堪设想。","english":"If no measures are taken, the consequences will be unimaginable.","traditional":"如果不採取措施，後果將不堪設想。"},{"simplified":"这次事故的影响不堪设想。","english":"The impact of this accident is too dreadful to contemplate.","traditional":"這次事故的影響不堪設想。"}],"synonyms":["不可思议"],"antonyms":[],"confusedWith":[{"id":"不可思议","note":"While both express something unimaginable, 不可思议 can be used for both positive and negative situations, whereas 不堪设想 is strictly negative."}],"traditional":"不堪設想","pinyinOverride":null},{"id":"bu-kan-yi-ji","simplified":"不堪一击","literalMeaning":"cannot withstand a single blow","figurativeMeaning":"extremely weak and unable to withstand any challenge","englishEquivalents":["fall at the first hurdle","crumble at the first sign of pressure"],"shortGloss":"extremely weak, easily defeated","characters":[{"char":"不","meaning":"not"},{"char":"堪","meaning":"able to withstand"},{"char":"一","meaning":"one"},{"char":"击","meaning":"blow, strike"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '不堪一击' is used to describe something or someone that is so weak that they cannot withstand even a single blow. It is often used in a metaphorical sense to describe arguments, defenses, or plans that are easily defeated or disproven.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"modifier-head","register":"commonly used in both spoken and written Chinese","connotation":"negative","commonMistakes":"Learners often confuse this idiom with others that imply weakness but do not specifically mean 'easily defeated'. It should be used to describe something that fails immediately under pressure.","canStandAlone":false},"examples":[{"simplified":"他的辩论不堪一击，根本没有说服力。","english":"His argument was extremely weak and had no persuasive power.","traditional":"他的辯論不堪一擊，根本沒有說服力。"},{"simplified":"敌人的防线不堪一击，很快就被突破了。","english":"The enemy's defenses were extremely weak and were quickly breached.","traditional":"敵人的防線不堪一擊，很快就被突破了。"}],"synonyms":["不堪一战"],"antonyms":["坚不可摧"],"confusedWith":[{"id":"不堪重负","note":"While '不堪重负' means unable to bear a heavy burden, '不堪一击' specifically refers to being easily defeated."}],"traditional":"不堪一擊","pinyinOverride":null},{"id":"bu-kang-bu-bei","simplified":"不亢不卑","literalMeaning":"not arrogant not servile","figurativeMeaning":"to be neither arrogant nor servile; to maintain a balanced and respectful demeanor","englishEquivalents":["neither haughty nor humble","keep a level head"],"shortGloss":"neither arrogant nor servile","characters":[{"char":"不","meaning":"not"},{"char":"亢","meaning":"arrogant"},{"char":"不","meaning":"not"},{"char":"卑","meaning":"servile"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '不亢不卑' describes a person who maintains a balanced demeanor, neither looking down on others nor being overly submissive. It is often used to praise someone who handles themselves with grace and dignity, regardless of the situation.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["adverbial","attributive"],"structure":"coordinate","register":"commonly used in both written and spoken Chinese to describe a balanced attitude","connotation":"positive","commonMistakes":"Learners might confuse this idiom with similar expressions that imply neutrality but lack the positive connotation of dignity and respect. It is important to remember that this idiom specifically praises a balanced demeanor.","canStandAlone":false},"examples":[{"simplified":"他在会议上表现得不亢不卑，给大家留下了深刻的印象。","english":"He behaved neither arrogantly nor servilely at the meeting, leaving a deep impression on everyone.","traditional":"他在會議上表現得不亢不卑，給大家留下了深刻的印象。"},{"simplified":"在与客户的交谈中，她总是保持不亢不卑的态度。","english":"In conversations with clients, she always maintains a demeanor that is neither arrogant nor servile.","traditional":"在與客戶的交談中，她總是保持不亢不卑的態度。"}],"synonyms":["不卑不亢"],"antonyms":[],"confusedWith":[{"id":"不卑不亢","note":"These two idioms are often used interchangeably, but '不卑不亢' is more commonly used in modern Chinese."}],"traditional":"不亢不卑","pinyinOverride":null},{"id":"bu-ke-duo-de","simplified":"不可多得","literalMeaning":"not possible to obtain many","figurativeMeaning":"rare and valuable; hard to come by","englishEquivalents":["rare gem","one in a million"],"shortGloss":"rare and valuable","characters":[{"char":"不","meaning":"not"},{"char":"可","meaning":"possible"},{"char":"多","meaning":"many"},{"char":"得","meaning":"obtain"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '不可多得' is used to describe something or someone that is extremely rare and valuable, emphasizing the difficulty of finding such a thing or person. It highlights the uniqueness and worth of the subject in question.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"modifier-head","register":"widely used in both written and spoken Chinese","connotation":"positive","commonMistakes":"Learners might confuse this idiom with others that imply rarity but lack the positive connotation of value, such as '稀有' which means rare but not necessarily valuable.","canStandAlone":false},"examples":[{"simplified":"这位科学家是不可多得的人才。","english":"This scientist is a rare and valuable talent.","traditional":"這位科學家是不可多得的人才。"},{"simplified":"这样的机会不可多得，你一定要好好把握。","english":"Opportunities like this are rare and valuable, you must seize them.","traditional":"這樣的機會不可多得，你一定要好好把握。"}],"synonyms":["凤毛麟角","稀世之宝"],"antonyms":["比比皆是"],"confusedWith":[{"id":"稀有","note":"稀有 means rare but does not imply value, whereas 不可多得 emphasizes both rarity and value."}],"traditional":"不可多得","pinyinOverride":null},{"id":"bu-ke-gao-ren","simplified":"不可告人","literalMeaning":"cannot be told to others","figurativeMeaning":"something that must be kept secret or hidden; a shameful or embarrassing secret","englishEquivalents":["skeleton in the closet","dirty little secret"],"shortGloss":"a secret too shameful to reveal","characters":[{"char":"不","meaning":"not"},{"char":"可","meaning":"can, able to"},{"char":"告","meaning":"tell, inform"},{"char":"人","meaning":"people, others"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '不可告人' is used to describe something that is too embarrassing or shameful to be shared with others. It suggests that the matter is best kept hidden to avoid disgrace or trouble. The phrase is often used in contexts where someone is hiding a personal secret or a past mistake.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"modifier-head","register":"common in both written and spoken Chinese, suitable for informal contexts","connotation":"negative","commonMistakes":"Learners might confuse this idiom with general terms for secrets, but '不可告人' specifically implies a negative or shameful aspect that makes the secret particularly sensitive.","canStandAlone":false},"examples":[{"simplified":"他有一个不可告人的秘密。","english":"He has a secret that he cannot reveal to anyone.","traditional":"他有一個不可告人的秘密。"},{"simplified":"这些事情都是不可告人的，最好不要提起。","english":"These matters are best kept secret and should not be mentioned.","traditional":"這些事情都是不可告人的，最好不要提起。"}],"synonyms":["见不得人"],"antonyms":[],"confusedWith":[{"id":"秘密","note":"秘密 simply means 'secret' without the negative or shameful connotation."}],"traditional":"不可告人","pinyinOverride":null},{"id":"bu-ke-kai-jiao","simplified":"不可开交","literalMeaning":"cannot be untied","figurativeMeaning":"in a hopelessly tangled situation; extremely busy or embroiled","englishEquivalents":["in a bind","in a jam","up to one's ears"],"shortGloss":"hopelessly tangled or busy","characters":[{"char":"不","meaning":"not"},{"char":"可","meaning":"can; able to"},{"char":"开","meaning":"open; untie"},{"char":"交","meaning":"intersect; join"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '不可开交' is often used to describe situations where someone is extremely busy or entangled in a complex situation. The phrase suggests that the situation is so complicated that it cannot be easily resolved or 'untied'. It is commonly used in modern Chinese to describe being overwhelmed with tasks or problems.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["complement"],"structure":"modifier-head","register":"commonly used in both spoken and written Chinese","connotation":"neutral","commonMistakes":"Learners often misuse this idiom by trying to use it as a standalone phrase. It typically follows a verb to describe the extent of being busy or entangled, such as '忙得不可开交' (so busy that one cannot untie oneself).","canStandAlone":false},"examples":[{"simplified":"他最近工作忙得不可开交。","english":"He has been extremely busy with work lately.","traditional":"他最近工作忙得不可開交。"},{"simplified":"她的生活被各种琐事弄得不可开交。","english":"Her life is tangled up with all sorts of trivial matters.","traditional":"她的生活被各種瑣事弄得不可開交。"}],"synonyms":["忙得不可开交"],"antonyms":[],"confusedWith":[{"id":"不可收拾","note":"不可收拾 means 'beyond repair or control', often used for situations that have deteriorated, whereas 不可开交 emphasizes being busy or tangled."}],"traditional":"不可開交","pinyinOverride":null},{"id":"bu-ke-li-yu","simplified":"不可理喻","literalMeaning":"cannot be reasoned with","figurativeMeaning":"unreasonable; impervious to reason or persuasion","englishEquivalents":["beyond reasoning","unreasonable","impossible to talk sense into"],"shortGloss":"unreasonable; beyond reasoning","characters":[{"char":"不","meaning":"not"},{"char":"可","meaning":"can"},{"char":"理","meaning":"reason"},{"char":"喻","meaning":"persuade"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '不可理喻' is used to describe someone who is so unreasonable that they cannot be persuaded or reasoned with. It is often used in situations where someone is being stubborn or irrational, refusing to listen to logic or reason.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"modifier-head","register":"commonly used in both formal and informal contexts","connotation":"negative","commonMistakes":"Learners often confuse '不可理喻' with '不可思议', which means 'inconceivable' or 'unimaginable'. The former implies stubbornness or unreasonableness, while the latter refers to something beyond belief or comprehension.","canStandAlone":false},"examples":[{"simplified":"他的态度真是不可理喻，怎么说都听不进去。","english":"His attitude is truly unreasonable; he won't listen no matter what you say.","traditional":"他的態度真是不可理喻，怎麼說都聽不進去。"},{"simplified":"面对不可理喻的客户，我们只能耐心解释。","english":"When dealing with unreasonable customers, we can only explain patiently.","traditional":"面對不可理喻的客戶，我們只能耐心解釋。"}],"synonyms":["蛮不讲理","冥顽不灵"],"antonyms":["通情达理"],"confusedWith":[{"id":"不可思议","note":"不可思议 means 'inconceivable' or 'unimaginable', not 'unreasonable'."}],"traditional":"不可理喻","pinyinOverride":null},{"id":"bu-ke-ming-zhuang","simplified":"不可名状","literalMeaning":"cannot be described","figurativeMeaning":"indescribable; beyond words","englishEquivalents":["beyond description","indescribable"],"shortGloss":"indescribable","characters":[{"char":"不","meaning":"not"},{"char":"可","meaning":"can"},{"char":"名","meaning":"name, describe"},{"char":"状","meaning":"state, condition"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '不可名状' is often used to express feelings or situations that are so profound or complex that they cannot be adequately described with words. It emphasizes the limitations of language in capturing the full essence of certain experiences.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"modifier-head","register":"literary, but widely understood and used in both formal and informal contexts","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with others that imply a lack of understanding rather than a lack of words. It specifically refers to the inability to describe, not the inability to comprehend.","canStandAlone":false},"examples":[{"simplified":"他的表演让人感到一种不可名状的感动。","english":"His performance evoked an indescribable feeling of emotion.","traditional":"他的表演讓人感到一種不可名狀的感動。"},{"simplified":"那幅画带给我一种不可名状的宁静。","english":"The painting brought me an indescribable sense of peace.","traditional":"那幅畫帶給我一種不可名狀的寧靜。"}],"synonyms":["难以言喻"],"antonyms":[],"confusedWith":[{"id":"难以理解","note":"不可名状 refers to something indescribable, while 难以理解 refers to something difficult to understand."}],"traditional":"不可名狀","pinyinOverride":null},{"id":"bu-ke-sheng-shu","simplified":"不可胜数","literalMeaning":"cannot be counted","figurativeMeaning":"too many to count; countless","englishEquivalents":["countless","innumerable","too many to count"],"shortGloss":"countless; innumerable","characters":[{"char":"不","meaning":"not"},{"char":"可","meaning":"can, able to"},{"char":"胜","meaning":"to be able to bear"},{"char":"数","meaning":"count, number"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '不可胜数' is used to describe a quantity so large that it cannot be counted. It is often used to emphasize the vastness or abundance of something, such as stars in the sky or grains of sand on a beach.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"modifier-head","register":"commonly used in both written and spoken Chinese","connotation":"neutral","commonMistakes":"Learners might confuse it with similar idioms that also imply large quantities but have different nuances, such as '数不胜数'. '不可胜数' emphasizes the inability to count due to the sheer number.","canStandAlone":false},"examples":[{"simplified":"天上的星星不可胜数。","english":"The stars in the sky are countless.","traditional":"天上的星星不可勝數。"},{"simplified":"在这个城市里，餐馆的数量不可胜数。","english":"In this city, the number of restaurants is countless.","traditional":"在這個城市裡，餐館的數量不可勝數。"}],"synonyms":["数不胜数"],"antonyms":[],"confusedWith":[{"id":"数不胜数","note":"Both mean 'countless', but '数不胜数' is more commonly used in modern contexts."}],"traditional":"不可勝數","pinyinOverride":null},{"id":"bu-ke-yan-yu","simplified":"不可言喻","literalMeaning":"cannot be expressed in words","figurativeMeaning":"indescribable; beyond words","englishEquivalents":["beyond words","indescribable"],"shortGloss":"indescribable","characters":[{"char":"不","meaning":"not"},{"char":"可","meaning":"can; able to"},{"char":"言","meaning":"speak; say"},{"char":"喻","meaning":"describe; explain"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '不可言喻' is used to describe something that is so profound or complex that it cannot be adequately expressed or described in words. It is often used to convey the idea of emotions or experiences that are deeply felt but difficult to articulate.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adjectival"],"structure":"modifier-head","register":"common in both written and spoken Chinese","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with similar expressions that mean 'difficult to describe' but lack the connotation of being completely beyond words. It's important to use it when something truly cannot be captured by language.","canStandAlone":false},"examples":[{"simplified":"她的美丽是不可言喻的。","english":"Her beauty is indescribable.","traditional":"她的美麗是不可言喻的。"},{"simplified":"那种感动是不可言喻的。","english":"That kind of emotion is beyond words.","traditional":"那種感動是不可言喻的。"}],"synonyms":["难以形容"],"antonyms":[],"confusedWith":[{"id":"难以形容","note":"While both mean difficult to describe, '不可言喻' implies a complete inability to express in words, whereas '难以形容' suggests difficulty but not impossibility."}],"traditional":"不可言喻","pinyinOverride":null},{"id":"bu-ke-yi-shi","simplified":"不可一世","literalMeaning":"cannot match one generation","figurativeMeaning":"arrogant and conceited; considering oneself unrivaled","englishEquivalents":["full of oneself","high and mighty"],"shortGloss":"arrogant and conceited","characters":[{"char":"不","meaning":"not"},{"char":"可","meaning":"can"},{"char":"一","meaning":"one"},{"char":"世","meaning":"generation; world"}],"origin":{"period":"Three Kingdoms period (220–280 CE)","sourceText":"《三国志·魏书·袁绍传》","sourceTextEnglish":"Records of the Three Kingdoms, Book of Wei, Biography of Yuan Shao","originalExcerpt":"绍自以为不可一世，遂有骄矜之志。","storyEnglish":"The idiom originates from the 'Records of the Three Kingdoms', where it describes Yuan Shao, a warlord during the late Eastern Han dynasty. Yuan Shao was known for his arrogance and overconfidence, believing himself to be unmatched in his time. This attitude ultimately led to his downfall, as he underestimated his rivals and overestimated his own capabilities.","historicalFigures":["Yuan Shao"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"modifier-head","register":"commonly used in both written and spoken Chinese to describe arrogance","connotation":"negative","commonMistakes":"Learners often confuse this idiom with similar expressions of confidence, but it specifically implies an excessive and unjustified arrogance. It should not be used to describe justified pride or confidence.","canStandAlone":false},"examples":[{"simplified":"他在公司里总是不可一世，结果没人愿意和他合作。","english":"He is always so arrogant at the company that no one wants to work with him.","traditional":"他在公司裡總是不可一世，結果沒人願意和他合作。"},{"simplified":"这个年轻人不可一世，以为自己无所不能。","english":"This young man is so conceited, thinking he is capable of anything.","traditional":"這個年輕人不可一世，以為自己無所不能。"}],"synonyms":["目中无人","自高自大"],"antonyms":["谦虚谨慎"],"confusedWith":[{"id":"自命不凡","note":"自命不凡 means considering oneself extraordinary, which can be positive or neutral, while 不可一世 is negative and implies arrogance."}],"traditional":"不可一世","pinyinOverride":null},{"id":"bu-ke-zhong-ri","simplified":"不可终日","literalMeaning":"unable to last the day","figurativeMeaning":"to be in a state of panic or anxiety, unable to calm down","englishEquivalents":["on pins and needles","in a state of panic"],"shortGloss":"in a state of panic","characters":[{"char":"不","meaning":"not"},{"char":"可","meaning":"can, able to"},{"char":"终","meaning":"end, complete"},{"char":"日","meaning":"day"}],"origin":{"period":"Warring States period (475–221 BCE)","sourceText":"《左传·成公十三年》","sourceTextEnglish":"Zuo Zhuan, Duke Cheng, Year 13","originalExcerpt":"君子不可终日安之。","storyEnglish":"The idiom originates from the Zuo Zhuan, an ancient Chinese historical text. In a particular passage, it describes a situation where a nobleman is so anxious about the state of affairs that he cannot remain calm for even a single day. This reflects the idea of being in a constant state of worry or panic.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","complement"],"structure":"modifier-head","register":"literary, but can be used in formal speech","connotation":"negative","commonMistakes":"Learners often confuse this idiom with expressions that simply mean 'busy' or 'occupied'. However, 不可终日 specifically conveys a sense of panic or anxiety, not just busyness.","canStandAlone":false},"examples":[{"simplified":"他对公司的未来感到不可终日。","english":"He feels anxious about the company's future.","traditional":"他對公司的未來感到不可終日。"},{"simplified":"面对突如其来的危机，她感到不可终日。","english":"Faced with the sudden crisis, she felt on pins and needles.","traditional":"面對突如其來的危機，她感到不可終日。"}],"synonyms":["惶惶不可终日"],"antonyms":[],"confusedWith":[{"id":"忙忙碌碌","note":"忙忙碌碌 means 'busy and bustling', lacking the anxiety implied by 不可终日."}],"traditional":"不可終日","pinyinOverride":null},{"id":"bu-lang-bu-you","simplified":"不稂不莠","literalMeaning":"neither weed nor wild grass","figurativeMeaning":"mediocre; neither good nor bad","englishEquivalents":["neither fish nor fowl"],"shortGloss":"mediocre; neither good nor bad","characters":[{"char":"不","meaning":"not"},{"char":"稂","meaning":"weed"},{"char":"不","meaning":"not"},{"char":"莠","meaning":"wild grass"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '不稂不莠' describes something or someone that is neither particularly good nor particularly bad, akin to being mediocre. The characters '稂' and '莠' refer to types of weeds or wild grasses, suggesting something that is not cultivated or refined. The phrase implies a lack of distinguishing qualities, neither standing out positively nor negatively.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"coordinate","register":"literary, but understood in ordinary speech","connotation":"neutral","commonMistakes":"Learners often confuse this idiom with more negative expressions, but it is neutral, indicating mediocrity rather than poor quality.","canStandAlone":false},"examples":[{"simplified":"他在公司里表现得不稂不莠，没有特别出色的地方。","english":"He performs neither exceptionally well nor poorly in the company.","traditional":"他在公司裡表現得不稂不莠，沒有特別出色的地方。"},{"simplified":"这部电影不稂不莠，没有给我留下深刻印象。","english":"This movie was mediocre and didn't leave a strong impression on me.","traditional":"這部電影不稂不莠，沒有給我留下深刻印象。"}],"synonyms":[],"antonyms":["出类拔萃"],"confusedWith":[{"id":"平淡无奇","note":"While both suggest mediocrity, '平淡无奇' emphasizes plainness and lack of interest."}],"traditional":"不稂不莠","pinyinOverride":null},{"id":"bu-lin-zhu-yu","simplified":"不吝珠玉","literalMeaning":"not stingy with pearls and jade","figurativeMeaning":"to generously share one's valuable insights or advice","englishEquivalents":["share one's wisdom","offer valuable advice"],"shortGloss":"generously share wisdom","characters":[{"char":"不","meaning":"not"},{"char":"吝","meaning":"stingy"},{"char":"珠","meaning":"pearls"},{"char":"玉","meaning":"jade"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '不吝珠玉' is often used to encourage someone to share their valuable knowledge or advice. The pearls and jade symbolize precious insights, and the phrase implies that one should not be stingy in sharing them with others.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"modifier-head","register":"literary, but can be used in formal speech or writing","connotation":"positive","commonMistakes":"Learners might confuse this idiom with others involving '珠玉' (pearls and jade) but should note that this idiom specifically refers to sharing wisdom or advice, not material wealth.","canStandAlone":false},"examples":[{"simplified":"请您不吝珠玉，给我们一些建议。","english":"Please generously share your wisdom and give us some advice.","traditional":"請您不吝珠玉，給我們一些建議。"},{"simplified":"在会议上，他不吝珠玉，提出了许多有价值的想法。","english":"During the meeting, he generously shared his wisdom and offered many valuable ideas.","traditional":"在會議上，他不吝珠玉，提出了許多有價值的想法。"}],"synonyms":["畅所欲言"],"antonyms":[],"confusedWith":[{"id":"珠光宝气","note":"珠光宝气 refers to someone or something being richly adorned, focusing on material wealth rather than sharing wisdom."}],"traditional":"不吝珠玉","pinyinOverride":null},{"id":"bu-lu-sheng-se","simplified":"不露声色","literalMeaning":"not reveal sound or color","figurativeMeaning":"to hide one's emotions and intentions; to remain calm and composed","englishEquivalents":["keep a poker face","play it cool"],"shortGloss":"hide emotions and intentions","characters":[{"char":"不","meaning":"not"},{"char":"露","meaning":"reveal"},{"char":"声","meaning":"sound"},{"char":"色","meaning":"color; emotions"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom 不露声色 describes a person who is able to conceal their emotions and intentions, showing no outward sign of what they are thinking or feeling. This ability to maintain a calm and composed demeanor is often valued in strategic situations, where revealing one's true thoughts could be disadvantageous.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"modifier-head","register":"commonly used in both formal and informal contexts","connotation":"neutral","commonMistakes":"Learners often confuse this idiom with similar expressions that imply deception or dishonesty. However, 不露声色 focuses on emotional control rather than deceit.","canStandAlone":false},"examples":[{"simplified":"他在谈判中不露声色，让对方摸不清他的底牌。","english":"He kept a poker face during the negotiations, making it difficult for the other party to figure out his cards.","traditional":"他在談判中不露聲色，讓對方摸不清他的底牌。"},{"simplified":"即使遇到困难，她也总是不露声色，显得很镇定。","english":"Even when faced with difficulties, she always remains calm and composed.","traditional":"即使遇到困難，她也總是不露聲色，顯得很鎮定。"}],"synonyms":["泰然自若","面不改色"],"antonyms":["喜形于色"],"confusedWith":[{"id":"面不改色","note":"Both idioms involve maintaining composure, but 面不改色 emphasizes not showing fear or panic."}],"traditional":"不露聲色","pinyinOverride":null},{"id":"bu-luo-ke-jiu","simplified":"不落窠臼","literalMeaning":"not fall into the rut","figurativeMeaning":"to be original; to avoid clichés or conventional patterns","englishEquivalents":["think outside the box","break the mold"],"shortGloss":"be original, avoid clichés","characters":[{"char":"不","meaning":"not"},{"char":"落","meaning":"fall into"},{"char":"窠","meaning":"nest; rut"},{"char":"臼","meaning":"mortar; old pattern"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom 不落窠臼 is believed to have originated from the idea of not falling into a pre-made mold or pattern, like a bird not returning to its nest or a person not following conventional paths. It emphasizes originality and creativity, encouraging people to break away from traditional or clichéd ways of thinking.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"modifier-head","register":"literary, but understood in educated speech","connotation":"positive","commonMistakes":"Learners might confuse this idiom with similar expressions that suggest unconventionality but do not emphasize originality. It's important to note that 不落窠臼 specifically praises creativity and fresh thinking.","canStandAlone":false},"examples":[{"simplified":"他的设计风格独特，不落窠臼。","english":"His design style is unique and original, avoiding clichés.","traditional":"他的設計風格獨特，不落窠臼。"},{"simplified":"这位作家的作品总是不落窠臼，令人耳目一新。","english":"This writer's works are always original and refreshing, never falling into clichés.","traditional":"這位作家的作品總是不落窠臼，令人耳目一新。"}],"synonyms":["别出心裁"],"antonyms":["墨守成规"],"confusedWith":[{"id":"标新立异","note":"While both idioms emphasize originality, 标新立异 can sometimes imply being different for the sake of being different, whereas 不落窠臼 emphasizes genuine creativity."}],"traditional":"不落窠臼","pinyinOverride":null},{"id":"bu-mao-zhi-di","simplified":"不毛之地","literalMeaning":"land where nothing grows","figurativeMeaning":"a barren or unproductive place","englishEquivalents":["barren land","wasteland"],"shortGloss":"barren land","characters":[{"char":"不","meaning":"not"},{"char":"毛","meaning":"hair; vegetation"},{"char":"之","meaning":"of"},{"char":"地","meaning":"land; place"}],"origin":{"period":"Han Dynasty (206 BCE–220 CE)","sourceText":"《汉书·地理志》","sourceTextEnglish":"Book of Han, Treatise on Geography","originalExcerpt":"其地不生五谷，不毛之地也。","storyEnglish":"The idiom originates from the 'Book of Han', where it describes a region that was so barren that it could not produce the five grains, thus being referred to as 'land where nothing grows'. This phrase has since been used metaphorically to describe any unproductive or barren place.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["attributive","object"],"structure":"modifier-head","register":"literary, but understood in ordinary speech","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with phrases that imply desolation or ruin, but it specifically refers to lack of productivity or fertility, not destruction.","canStandAlone":false},"examples":[{"simplified":"这片沙漠是一片不毛之地。","english":"This desert is a barren land.","traditional":"這片沙漠是一片不毛之地。"},{"simplified":"他们在不毛之地上建造了一个繁荣的城市。","english":"They built a thriving city on barren land.","traditional":"他們在不毛之地上建造了一個繁榮的城市。"}],"synonyms":["荒无人烟"],"antonyms":["沃土千里"],"confusedWith":[{"id":"荒凉之地","note":"不毛之地 emphasizes lack of productivity, while 荒凉之地 emphasizes desolation."}],"traditional":"不毛之地","pinyinOverride":null},{"id":"bu-ming-yi-qian","simplified":"不名一钱","literalMeaning":"not name a single coin","figurativeMeaning":"to be penniless; to have no money at all","englishEquivalents":["penniless","broke"],"shortGloss":"penniless, broke","characters":[{"char":"不","meaning":"not"},{"char":"名","meaning":"name, possess"},{"char":"一","meaning":"one, a single"},{"char":"钱","meaning":"coin, money"}],"origin":{"period":"Han Dynasty (202 BCE – 220 CE)","sourceText":"《史记·平原君虞卿列传》","sourceTextEnglish":"Records of the Grand Historian, Biography of Lord Pingyuan and Yu Qing","originalExcerpt":"虞卿曰：“臣不名一钱。”","storyEnglish":"The idiom originates from a story in the 'Records of the Grand Historian' where Yu Qing, a scholar, was described as not possessing even a single coin. Despite his lack of wealth, he was respected for his wisdom and integrity.","historicalFigures":["Yu Qing"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"modifier-head","register":"literary, but can be used in both formal and informal contexts","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with others that describe poverty but have different nuances, such as '穷困潦倒' which implies being destitute and in a miserable state.","canStandAlone":false},"examples":[{"simplified":"他虽然不名一钱，但依然乐观面对生活。","english":"Although he is penniless, he still faces life with optimism.","traditional":"他雖然不名一錢，但依然樂觀面對生活。"},{"simplified":"在那段时间里，我几乎不名一钱。","english":"During that period, I was almost penniless.","traditional":"在那段時間裡，我幾乎不名一錢。"}],"synonyms":["身无分文"],"antonyms":["腰缠万贯"],"confusedWith":[{"id":"穷困潦倒","note":"This idiom implies being destitute and in a miserable state, not just penniless."}],"traditional":"不名一錢","pinyinOverride":null},{"id":"bu-ming-bu-bai","simplified":"不明不白","literalMeaning":"not clear not white","figurativeMeaning":"ambiguous or unclear; not clearly understood or explained","englishEquivalents":["neither here nor there","in the dark","vague"],"shortGloss":"ambiguous or unclear","characters":[{"char":"不","meaning":"not"},{"char":"明","meaning":"clear"},{"char":"不","meaning":"not"},{"char":"白","meaning":"white; clear"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '不明不白' is often used to describe situations or explanations that are unclear or lack transparency. It suggests a lack of clarity or certainty, leaving people confused or uncertain about the true nature or details of a matter.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","attributive"],"structure":"coordinate","register":"commonly used in both spoken and written Chinese","connotation":"negative","commonMistakes":"Learners might confuse this idiom with '不清不楚', which also means unclear but often emphasizes the lack of clarity in speech or writing specifically. '不明不白' is broader, covering any unclear situation.","canStandAlone":false},"examples":[{"simplified":"他的解释不明不白，让人很难理解。","english":"His explanation was ambiguous, making it hard to understand.","traditional":"他的解釋不明不白，讓人很難理解。"},{"simplified":"这件事情不明不白，我们需要更多的信息。","english":"This matter is unclear; we need more information.","traditional":"這件事情不明不白，我們需要更多的信息。"}],"synonyms":["模糊不清"],"antonyms":["一清二楚"],"confusedWith":[{"id":"不清不楚","note":"Both idioms mean unclear, but '不清不楚' often specifically refers to unclear speech or writing."}],"traditional":"不明不白","pinyinOverride":null},{"id":"bu-mou-er-he","simplified":"不谋而合","literalMeaning":"without planning yet agree","figurativeMeaning":"to agree without prior consultation; to coincide by chance","englishEquivalents":["great minds think alike","on the same wavelength"],"shortGloss":"agree without prior consultation","characters":[{"char":"不","meaning":"not"},{"char":"谋","meaning":"plan"},{"char":"而","meaning":"yet"},{"char":"合","meaning":"agree"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom '不谋而合' describes a situation where two or more people come to the same conclusion or agreement without having discussed it beforehand. It highlights a spontaneous or coincidental alignment of thoughts or opinions, often suggesting a deeper, intuitive understanding between the parties involved.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"modifier-head","register":"commonly used in both formal and informal contexts","connotation":"positive","commonMistakes":"Learners might confuse this idiom with '不约而同', which also means to do something simultaneously without prior arrangement, but '不谋而合' emphasizes agreement in thought or opinion rather than action.","canStandAlone":false},"examples":[{"simplified":"他们对这个问题的看法不谋而合。","english":"They coincidentally agreed on their views regarding this issue.","traditional":"他們對這個問題的看法不謀而合。"},{"simplified":"在讨论中，我们不谋而合地提出了相同的建议。","english":"During the discussion, we coincidentally proposed the same suggestion.","traditional":"在討論中，我們不謀而合地提出了相同的建議。"}],"synonyms":["不约而同"],"antonyms":[],"confusedWith":[{"id":"不约而同","note":"不约而同 emphasizes simultaneous action without prior arrangement, while 不谋而合 focuses on agreement in thought."}],"traditional":"不謀而合","pinyinOverride":null},{"id":"bu-neng-zi-yi","simplified":"不能自已","literalMeaning":"cannot control oneself","figurativeMeaning":"unable to control one's emotions or actions","englishEquivalents":["beside oneself","lose control","overcome with emotion"],"shortGloss":"unable to control oneself","characters":[{"char":"不","meaning":"cannot, not"},{"char":"能","meaning":"able to"},{"char":"自","meaning":"oneself"},{"char":"已","meaning":"control, stop"}],"origin":{"period":"Eastern Jin Dynasty (317–420)","sourceText":"《世说新语·任诞》","sourceTextEnglish":"A New Account of the Tales of the World, Chapter on Unrestrained","originalExcerpt":"王子猷居山阴，夜大雪，眠觉，开室，命酌酒，四望皎然，因起彷徨，咏左思《招隐》诗，忽忆戴安道，乘兴乘舟将往访之。既而日出，湖中人鸟声俱绝，意兴殊爽，便泛舟而归。未至家，不能自已。","storyEnglish":"Wang Ziyou, a man from the Eastern Jin Dynasty, once stayed in Shanyin. One night, he awoke to find heavy snow falling. He opened his door, ordered wine, and admired the bright landscape. Inspired, he recited poetry and suddenly thought of his friend Dai Andao. Impulsively, he decided to visit him by boat. As the sun rose and the sounds of nature ceased, he felt a great joy and returned home by boat. Before reaching home, he found himself unable to control his emotions.","historicalFigures":["Wang Ziyou","Dai Andao"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","complement"],"structure":"modifier-head","register":"literary, but understood in educated speech","connotation":"neutral","commonMistakes":"Learners often confuse this idiom with similar expressions that imply physical restraint, but it specifically refers to emotional or mental control.","canStandAlone":false},"examples":[{"simplified":"听到这个好消息，她高兴得不能自已。","english":"Upon hearing the good news, she was so happy that she couldn't control herself.","traditional":"聽到這個好消息，她高興得不能自已。"},{"simplified":"他对过去的回忆让他悲伤得不能自已。","english":"His memories of the past made him so sad that he couldn't control himself.","traditional":"他對過去的回憶讓他悲傷得不能自已。"}],"synonyms":["情不自禁"],"antonyms":["泰然自若"],"confusedWith":[{"id":"情不自禁","note":"Both refer to uncontrollable emotions, but 不能自已 is more about an inability to control oneself, while 情不自禁 emphasizes being overwhelmed by emotions."}],"traditional":"不能自已","pinyinOverride":null},{"id":"bu-nian-jiu-e","simplified":"不念旧恶","literalMeaning":"not remember past wrongs","figurativeMeaning":"to forgive past grievances or offenses; to not hold grudges","englishEquivalents":["forgive and forget","let bygones be bygones"],"shortGloss":"forgive past grievances","characters":[{"char":"不","meaning":"not"},{"char":"念","meaning":"remember"},{"char":"旧","meaning":"past"},{"char":"恶","meaning":"wrongs; offenses"}],"origin":{"period":"Three Kingdoms period (220–280 CE)","sourceText":"《三国志·蜀书·先主传》","sourceTextEnglish":"Records of the Three Kingdoms, Shu Book, Biography of Liu Bei","originalExcerpt":"先主不念旧恶，故能得人心。","storyEnglish":"The idiom originates from the 'Records of the Three Kingdoms', where it is said that Liu Bei, the founding emperor of the Shu Han state, was known for not holding grudges against those who had wronged him in the past. This quality helped him win the loyalty and support of many people, contributing to his success.","historicalFigures":["Liu Bei"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"literary, but understood and sometimes used in formal speech","connotation":"positive","commonMistakes":"Learners sometimes confuse this idiom with '不计前嫌', which also means to forgive past offenses but is more commonly used in modern contexts. '不念旧恶' has a more classical and literary tone.","canStandAlone":false},"examples":[{"simplified":"他是一个不念旧恶的人，所以朋友很多。","english":"He is someone who forgives past grievances, so he has many friends.","traditional":"他是一個不念舊惡的人，所以朋友很多。"},{"simplified":"在处理人际关系时，学会不念旧恶是很重要的。","english":"In handling interpersonal relationships, learning to forgive past wrongs is very important.","traditional":"在處理人際關係時，學會不念舊惡是很重要的。"}],"synonyms":["不计前嫌"],"antonyms":["记仇"],"confusedWith":[{"id":"不计前嫌","note":"Both idioms mean to forgive past offenses, but '不计前嫌' is more commonly used in modern contexts."}],"traditional":"不念舊惡","pinyinOverride":null},{"id":"bu-pian-bu-yi","simplified":"不偏不倚","literalMeaning":"not leaning, not slanting","figurativeMeaning":"impartial and unbiased","englishEquivalents":["fair and square","without bias","even-handed"],"shortGloss":"impartial and unbiased","characters":[{"char":"不","meaning":"not"},{"char":"偏","meaning":"leaning"},{"char":"不","meaning":"not"},{"char":"倚","meaning":"slanting"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom 不偏不倚 is used to describe a person or action that is fair and impartial, without any bias or favoritism. It is often used in contexts where neutrality and fairness are important, such as in judgments or decisions.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"coordinate","register":"common in both written and spoken Chinese, used in formal and informal contexts","connotation":"positive","commonMistakes":"Learners might confuse 不偏不倚 with similar idioms that imply indecisiveness, but this idiom specifically emphasizes fairness and neutrality, not a lack of decision.","canStandAlone":false},"examples":[{"simplified":"法官在审判时必须做到不偏不倚。","english":"A judge must be impartial and unbiased during a trial.","traditional":"法官在審判時必須做到不偏不倚。"},{"simplified":"他处理问题时总是不偏不倚，大家都很信任他。","english":"He is always fair and unbiased when handling issues, and everyone trusts him.","traditional":"他處理問題時總是不偏不倚，大家都很信任他。"}],"synonyms":["公正无私","公平公正"],"antonyms":["偏心偏袒"],"confusedWith":[{"id":"左右为难","note":"左右为难 means being in a dilemma, which is different from being impartial."}],"traditional":"不偏不倚","pinyinOverride":null},{"id":"bu-ping-ze-ming","simplified":"不平则鸣","literalMeaning":"not fair then cry out","figurativeMeaning":"injustice will provoke a reaction; people will speak out against unfairness","englishEquivalents":["where there's injustice, there's protest","speak out against injustice"],"shortGloss":"injustice provokes protest","characters":[{"char":"不","meaning":"not"},{"char":"平","meaning":"fair; even"},{"char":"则","meaning":"then; in that case"},{"char":"鸣","meaning":"cry out; protest"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom suggests that when people encounter unfairness or injustice, they will naturally express their dissatisfaction or protest. It reflects the human tendency to speak out against wrongs.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"cause-effect","register":"commonly used in both formal and informal contexts","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with others that involve 'speaking out', but this one specifically refers to reacting to injustice. It should not be used to describe general complaints or grievances.","canStandAlone":false},"examples":[{"simplified":"面对不公正的待遇，他不平则鸣，提出了抗议。","english":"Faced with unfair treatment, he spoke out in protest.","traditional":"面對不公正的待遇，他不平則鳴，提出了抗議。"},{"simplified":"在一个不平等的社会中，人们常常不平则鸣。","english":"In an unequal society, people often speak out against injustices.","traditional":"在一個不平等的社會中，人們常常不平則鳴。"}],"synonyms":[],"antonyms":[],"confusedWith":[{"id":"鸣不平","note":"鸣不平 specifically means to voice dissatisfaction or protest, but doesn't inherently imply a reaction to injustice."}],"traditional":"不平則鳴","pinyinOverride":null},{"id":"bu-po-bu-li","simplified":"不破不立","literalMeaning":"no destruction, no construction","figurativeMeaning":"Without breaking the old, the new cannot be established; sometimes destruction is necessary for creation","englishEquivalents":["You can't make an omelet without breaking eggs","Out with the old, in with the new"],"shortGloss":"destruction is necessary for creation","characters":[{"char":"不","meaning":"not"},{"char":"破","meaning":"break"},{"char":"不","meaning":"not"},{"char":"立","meaning":"establish"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom suggests that in order to create something new or improve a situation, one must first dismantle or remove the existing structures or ideas that are no longer effective. This concept is often applied in contexts of reform or innovation, where old practices must be abandoned to make way for progress.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"coordinate","register":"commonly used in both formal and informal contexts","connotation":"neutral","commonMistakes":"Learners might confuse this idiom with others that involve breaking or destruction, but it specifically emphasizes the necessity of breaking down the old to build something new.","canStandAlone":false},"examples":[{"simplified":"改革需要勇气，不破不立。","english":"Reform requires courage; without breaking the old, the new cannot be established.","traditional":"改革需要勇氣，不破不立。"},{"simplified":"在创新的过程中，不破不立是一个常见的原则。","english":"In the process of innovation, 'no destruction, no construction' is a common principle.","traditional":"在創新的過程中，不破不立是一個常見的原則。"}],"synonyms":[],"antonyms":[],"confusedWith":[],"traditional":"不破不立","pinyinOverride":null},{"id":"bu-qi-er-yu","simplified":"不期而遇","literalMeaning":"not planned but meet","figurativeMeaning":"to meet by chance; to have a chance encounter","englishEquivalents":["bump into","run into","happen upon"],"shortGloss":"meet by chance","characters":[{"char":"不","meaning":"not"},{"char":"期","meaning":"expect"},{"char":"而","meaning":"but"},{"char":"遇","meaning":"meet"}],"origin":{"period":"Han Dynasty (202 BCE–220 CE)","sourceText":"《史记·平原君虞卿列传》","sourceTextEnglish":"Records of the Grand Historian, Biography of Lord Pingyuan and Yu Qing","originalExcerpt":"不期修古，不期而遇。","storyEnglish":"The idiom originates from a story in the 'Records of the Grand Historian' where two people unexpectedly meet. The phrase '不期而遇' describes the unexpected nature of their encounter, emphasizing that it was not planned or anticipated.","historicalFigures":["Lord Pingyuan","Yu Qing"],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["predicate","adverbial"],"structure":"verb-object","register":"commonly used in both written and spoken Chinese","connotation":"neutral","commonMistakes":"Learners sometimes use this idiom to describe planned meetings, but it specifically refers to chance encounters. It should not be used for meetings that are scheduled or expected.","canStandAlone":false},"examples":[{"simplified":"在公园散步时，我和老朋友不期而遇。","english":"While walking in the park, I ran into an old friend by chance.","traditional":"在公園散步時，我和老朋友不期而遇。"},{"simplified":"我们在旅行中不期而遇，真是太巧了。","english":"We happened to meet during the trip; it was such a coincidence.","traditional":"我們在旅行中不期而遇，真是太巧了。"}],"synonyms":["邂逅"],"antonyms":[],"confusedWith":[{"id":"约定","note":"约定 means 'to arrange or agree on a meeting', which is planned, unlike 不期而遇 which is unplanned."}],"traditional":"不期而遇","pinyinOverride":null},{"id":"bu-qing-zhi-qing","simplified":"不情之请","literalMeaning":"an unreasonable request","figurativeMeaning":"a request that may be considered unreasonable or presumptuous","englishEquivalents":["a big ask","an imposition"],"shortGloss":"an unreasonable request","characters":[{"char":"不","meaning":"not"},{"char":"情","meaning":"reasonable"},{"char":"之","meaning":"of"},{"char":"请","meaning":"request"}],"origin":{"period":"Unknown / folk origin","sourceText":"","sourceTextEnglish":"Origin disputed / folk etymology","originalExcerpt":"","storyEnglish":"The idiom 不情之请 is used to preface a request that the speaker acknowledges might be seen as unreasonable or burdensome. It is often used as a polite way to introduce a favor or ask for help, softening the imposition by acknowledging its nature.","historicalFigures":[],"relatedIdiomsFromSameSource":[]},"usage":{"grammaticalRole":["attributive"],"structure":"modifier-head","register":"polite and formal, often used in written requests or formal speech","connotation":"neutral","commonMistakes":"Learners often mistake this idiom as having a negative connotation, but it is actually neutral and used to politely acknowledge the nature of a request.","canStandAlone":false},"examples":[{"simplified":"我有一个不情之请，希望您能帮我这个忙。","english":"I have an unreasonable request and hope you can do me this favor.","traditional":"我有一個不情之請，希望您能幫我這個忙。"},{"simplified":"对于他的不情之请，我感到很为难。","english":"I felt quite awkward about his unreasonable request.","traditional":"對於他的不情之請，我感到很為難。"}],"synonyms":[],"antonyms":[],"confusedWith":[{"id":"无理取闹","note":"无理取闹 means making trouble without reason, which carries a negative connotation, unlike the neutral tone of 不情之请."}],"traditional":"不情之請","pinyinOverride":null}]`),n=`Unknown / folk origin`,r=t,i=a(r);function a(e){let t=[...e];for(let e=t.length-1;e>0;e--){let n=Math.floor(Math.random()*(e+1));[t[e],t[n]]=[t[n],t[e]]}return t}function o(){return i}function s(e){return r.find(t=>t.id===e)??null}function c(e){return r.find(t=>t.simplified===e||t.traditional===e)??null}function l(e,t=r){let n=e.trim();if(!n)return t;let i=n.toLowerCase();return t.filter(e=>e.simplified.includes(n)||e.traditional.includes(n)||e.shortGloss.toLowerCase().includes(i)||e.figurativeMeaning.toLowerCase().includes(i)||e.literalMeaning.toLowerCase().includes(i)||e.englishEquivalents.some(e=>e.toLowerCase().includes(i)))}function u(t){if(t.pinyinOverride)return t.pinyinOverride;let n=e(t.simplified)??e(t.traditional);return n?n.pinyin:t.characters.map(t=>e(t.char)?.pinyin??``).join(` `)}export{u as a,c as i,o as n,l as o,s as r,n as t};